(86, 16, 5, 'Cessão de Bens, Mobiliários e Equipamentos para a AGC', 'mancat-modulo-22-capitulo-005.doc', 'C:\\Correios\\mancat\\mancat-modulo-22-capitulo-005.doc'),
(87, 16, 6, 'Distrato de Termos de Convênio e Acordos de Cooperação Técnica de AGC', 'mancat-modulo-22-capitulo-006.doc', 'C:\\Correios\\mancat\\mancat-modulo-22-capitulo-006.doc'),
(88, 17, 4, 'Execução Operacional de Serviços em Agência(s) de Correios Franqueada(s) - AGF', 'mancat-modulo-26-capitulo-004.doc', 'C:\\Correios\\mancat\\mancat-modulo-26-capitulo-004.doc'),
(89, 17, 5, 'Postagem Via Mídia Com Importação de Dados Pelo Sistema de Automação do Atendimento', 'mancat-modulo-26-capitulo-005.doc', 'C:\\Correios\\mancat\\mancat-modulo-26-capitulo-005.doc'),
(90, 17, 9, 'Áreas Acessórias', 'mancat-modulo-26-capitulo-009.doc', 'C:\\Correios\\mancat\\mancat-modulo-26-capitulo-009.doc'),
(91, 17, 10, 'Procedimentos para Solicitação e Análise de Liberação de Equipamento Backup em AGF', 'mancat-modulo-26-capitulo-010.doc', 'C:\\Correios\\mancat\\mancat-modulo-26-capitulo-010.doc'),
(92, 17, 12, 'Procedimentos para Liberação de Guichê de Expedição Adicional', 'mancat-modulo-26-capitulo-012.doc', 'C:\\Correios\\mancat\\mancat-modulo-26-capitulo-012.doc'),
(93, 17, 13, 'Rescisão Contratual Com a Pessoa Jurídica da Franqueada - (AGF) - Rescisão Unilateral', 'mancat-modulo-26-capitulo-013.docx', 'C:\\Correios\\mancat\\mancat-modulo-26-capitulo-013.docx'),
(94, 17, 15, 'Processo de Aplicação da Penalidade de Suspensão Temporária de Partic. em Licitação e Imped. de Contratar Com os Correios', 'mancat-modulo-26-capitulo-015.doc', 'C:\\Correios\\mancat\\mancat-modulo-26-capitulo-015.doc'),
(95, 18, 4, 'Realização de Encontro de Negócios', 'mancat-modulo-27-capitulo-004.doc', 'C:\\Correios\\mancat\\mancat-modulo-27-capitulo-004.doc'),
(96, 18, 6, 'Material de Relacionamento', 'mancat-modulo-27-capitulo-006.doc', 'C:\\Correios\\mancat\\mancat-modulo-27-capitulo-006.doc'),
(97, 18, 10, 'Processos de Vendas', 'mancat-modulo-27-capitulo-010.doc', 'C:\\Correios\\mancat\\mancat-modulo-27-capitulo-010.doc'),
(98, 18, 12, 'Processos Gerir Clientes', 'mancat-modulo-27-capitulo-012.doc', 'C:\\Correios\\mancat\\mancat-modulo-27-capitulo-012.doc'),
(99, 18, 13, 'Guia de Atuação Comercial', 'mancat-modulo-27-capitulo-013.doc', 'C:\\Correios\\mancat\\mancat-modulo-27-capitulo-013.doc'),
(100, 19, 1, 'Gestão dos Instrumentos Contratuais', 'mancat-modulo-28-capitulo-001.doc', 'C:\\Correios\\mancat\\mancat-modulo-28-capitulo-001.doc'),
(101, 20, 3, 'Realização de Encontros da Força de Vendas', 'mancat-modulo-29-capitulo-003.doc', 'C:\\Correios\\mancat\\mancat-modulo-29-capitulo-003.doc'),
(102, 21, 4, 'Indenização e Ressarcimento de Objetos Internacionais de Exportação e Importação', 'mancat-modulo-32-capitulo-004.doc', 'C:\\Correios\\mancat\\mancat-modulo-32-capitulo-004.doc'),
(103, 22, 2, 'Integração Sistêmica e Ativação de Serviços de Terceiros', 'mancat-modulo-36-capitulo-002.doc', 'C:\\Correios\\mancat\\mancat-modulo-36-capitulo-002.doc'),
(104, 23, 1, 'Correios Log+', 'mancat-modulo-37-capitulo-001.docx', 'C:\\Correios\\mancat\\mancat-modulo-37-capitulo-001.docx'),
(105, 23, 2, 'Correios Log Supri', 'mancat-modulo-37-capitulo-002.docx', 'C:\\Correios\\mancat\\mancat-modulo-37-capitulo-002.docx'),
(106, 24, 1, 'Implantação do Canal Correios Aqui - Unidade Modular (CMD)', 'mancat-modulo-38-capitulo-001.doc', 'C:\\Correios\\mancat\\mancat-modulo-38-capitulo-001.doc');
INSERT INTO `eixos` (`id`, `slug`, `nome`, `descricao`, `icone`, `cor`, `cor_bg`, `tags`, `ordem`, `ativo`, `criado_em`, `atualizado_em`) VALUES
(1, 'posicionamento', 'Posicionamento e Estratégia', 'Diretrizes estratégicas, segmentação de mercado, proposta de valor e posicionamento competitivo dos serviços comerciais dos Correios.', 'bi-bullseye', '#003F88', '#e8f0fe', 'Estratégia,Mercado,Segmentação', 1, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25'),
(2, 'estrutura-contratual', 'Estrutura Contratual', 'Tipos de contratos comerciais, cláusulas essenciais, vigência, renovação, aditivos e gestão do ciclo de vida contratual com clientes B2B.', 'bi-file-earmark-ruled', '#1565C0', '#e3f2fd', 'Contratos,B2B,Juridico', 2, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25'),
(3, 'precificacao', 'Precificação e Faturamento', 'Metodologias de precificação, tabelas tarifárias, descontos por volume, faturamento eletrônico e gestão de cobranças contratuais.', 'bi-calculator', '#2E7D32', '#e8f5e9', 'Tarifas,Faturamento,Descontos', 3, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25'),
(4, 'portfolio-b2b', 'Portfólio Central de Soluções B2B', 'Catálogo completo de produtos e serviços para clientes corporativos: SEDEX, PAC, Malote, Banco Postal, logística reversa e soluções integradas.', 'bi-grid-1x2', '#6A1B9A', '#f3e5f5', 'SEDEX,Logística,Produtos', 4, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25'),
(5, 'tecnologia', 'Tecnologia, Integração e Automação', 'APIs de rastreamento e postagem, integração com ERPs, automação de processos, EDI, WebService e plataformas digitais para clientes corporativos.', 'bi-cpu', '#00838F', '#e0f7fa', 'API,Integração,Digital', 5, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25'),
(6, 'pos-venda', 'Pós-Venda, Indenizações e Seguros', 'Gestão de reclamações, SLA de atendimento, processo de indenização por extravio/avaria, seguros opcionais e gestão de risco comercial.', 'bi-shield-check', '#B71C1C', '#fce4ec', 'SLA,Indenização,Risco', 6, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25'),
(7, 'credito-cobranca', 'Gestão de Crédito, Cobrança e Compliance', 'Análise de crédito para clientes PJ, limites de faturamento, régua de cobrança, inadimplência, compliance contratual e auditoria de contratos.', 'bi-bank', '#E65100', '#fff3e0', 'Crédito,Compliance,Cobrança', 7, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25'),
(8, 'solucoes-internacionais', 'Soluções Internacionais (Cross-Border)', 'Exportação e importação postal, Remessa Internacional, EMS, e-commerce transfronteiriço, alfandegamento, acordos bilaterais e UPU.', 'bi-globe-americas', '#0277BD', '#e1f5fe', 'Exportação,Cross-Border,UPU', 8, 1, '2026-06-22 16:43:25', '2026-06-22 16:43:25');
INSERT INTO `ideias` (`id`, `eixo_id`, `titulo`, `campos`, `status`, `tags`, `criado_em`, `atualizado_em`) VALUES
(1, 1, 'Volume e fidelização', '[{\"label\":\"Objetivo\",\"valor\":\"Pensar estratégias para vender mais e aproveitar a capacidade instalada\",\"tipo\":\"texto_curto\"},{\"label\":\"Hipótese\",\"valor\":\"Pulverizar produtos e serviços entre pequenos empresários\",\"tipo\":\"texto_longo\"},{\"label\":\"Premissa\",\"valor\":\"Na operação logística a rentabilidade está na otimização da capacidade instalada.\",\"tipo\":\"texto_curto\"},{\"label\":\"Premissa 2\",\"valor\":\"O aumento sistemático dos volumes dos clientes existentes preenchem a capacidade instalada.\",\"tipo\":\"texto_curto\"},{\"label\":\"Observação1\",\"valor\":\"A fidelização deve ser uma política corporativa e precisa ser um indicador.\",\"tipo\":\"texto_curto\"}]', 'rascunho', '', '2026-06-22 17:12:15', '2026-06-22 17:15:17');
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(3743, 'capitulo', 1, NULL, 1, '1', 'FINALIDADE DO MANUAL', '', 0),
(3744, 'capitulo', 1, 3743, 2, '1.1', 'Fornecer as informações necessárias e estabelecer os procedimentos operacionais e comerciais relativos aos serviços prestados e aos produtos comercializados pelos Correios.', '', 1),
(3745, 'capitulo', 1, NULL, 1, '2', 'GLOSSÁRIO DE CONCEITOS, TERMOS E SIGLAS', '', 2),
(3746, 'capitulo', 1, 3745, 2, '2.1', 'Aceitação das imagens: é o recebimento da imagem do cliente quanto ela estiver adequada às características do produto contratado.', '', 3),
(3747, 'capitulo', 1, 3745, 2, '2.2', 'Agente de registro - AGR: pessoa responsável pela execução das atividades inerentes à AR. É a pessoa que realiza a validação e verificação da solicitação de certificados digitais.', '', 4),
(3748, 'capitulo', 1, 3745, 2, '2.3', 'Aerograma: objeto de correspondência pré-pago, com caráter de mensagem atual e pessoal, apresentado em impresso específico dos Correios, sob a forma de única folha de papel que, convenientemente dobrada, adquire o formato de um envelope.', '', 5),
(3749, 'capitulo', 1, 3745, 2, '2.4', 'Aerograma comemorativo: é o aerograma que contém ilustrações e mensagens para remessa por ocasião de eventos sociais, como Natal, aniversários e outras datas comemorativas.', '', 6),
(3750, 'capitulo', 1, 3745, 2, '2.5', 'Aerograma internacional: documento prioritário pré-selado, apresenta-se em forma de uma folha de papel que, convenientemente dobrada, adquire a forma de um envelope. É destinado a outros países, podendo ser aceito no regime interno, se for do interesse do remetente.', '', 7),
(3751, 'capitulo', 1, 3745, 2, '2.6', 'Aerograma nacional: é o aerograma de uso exclusivo no território nacional.', '', 8),
(3752, 'capitulo', 1, 3745, 2, '2.7', 'Aerograma personalizado: é o aerograma impresso com arte definida pelo cliente.', '', 9),
(3753, 'capitulo', 1, 3745, 2, '2.8', 'Agência de Correios - AC: é a unidade de atendimento própria, destinada à venda de produtos e à prestação de serviços dos Correios, bem como de terceiros, a clientes dos segmentos de varejo, comercial e estratégico.', '', 10),
(3754, 'capitulo', 1, 3745, 2, '2.9', 'Agência de Correios - Segmento pequenos mercados: é a Agência de Correios voltada para a universalização dos serviços postais e do banco postal, a ser instalada em pequenos municípios ou em mercados que tenham finalidade essencialmente de universalizar o acesso aos serviços postais e bancários básicos. Para fins desse modelo de agência, pequeno município é aquele onde a vocação da agência é a de universalização dos serviços postais e do banco postal e a população do município seja de até 15.000 (quinze mil) habitantes.', '', 11),
(3755, 'capitulo', 1, 3745, 2, '2.10', 'Agência de Correios Comercial - ACC: é a unidade de atendimento destinada à prestação de serviços e à venda de produtos comercializados pelos Correios, a cliente do segmento de varejo.', '', 12),
(3756, 'capitulo', 1, 3745, 2, '2.11', 'Agência de Correios Comunitária - AGC: é a unidade de atendimento destinada a viabilizar, no mínimo, a prestação de serviços postais básicos, em pequenas localidades com população superior a quinhentos habitantes, bem como em áreas urbanas onde predomine o interesse social e a exploração econômica de serviços postais não se mostre viável.', '', 13),
(3757, 'capitulo', 1, 3745, 2, '2.12', 'Agência de Correios de Venda à Distância - ACVD: é a agência de correios especializada no atendimento e operação das transações comerciais realizadas pelos Correios On-Line e daquelas com os correntistas filatélicos.', '', 14),
(3758, 'capitulo', 1, 3745, 2, '2.13', 'Agência de Correios Franqueada - AGF: é a unidade de atendimento terceirizada, operada por pessoa jurídica de direito privado, selecionada em procedimento de licitação específico, contratada pelos Correios para a execução das atividades auxiliares relativas ao serviço postal.', '', 15),
(3759, 'capitulo', 1, 3745, 2, '2.14', 'Agência de Correios Franqueada centralizadora: é aquela que irá realizar a gestão das áreas acessórias.', '', 16),
(3760, 'capitulo', 1, 3745, 2, '2.15', 'Agência de Correios subordinadora: é uma unidade própria dos Correios responsável pelo controle e fiscalização das máquinas de franquear de autorizados, no âmbito de sua subordinação.', '', 17),
(3761, 'capitulo', 1, 3745, 2, '2.16', 'Agência de perfil comercial: agência na qual se prioriza vendas e negócios, objetivando o atingimento das metas comerciais da Empresa, com foco na geração de receita para a sustentabilidade do negócio postal.', '', 18),
(3762, 'capitulo', 1, 3745, 2, '2.17', 'Agência de perfil social: agência na qual se prioriza a universalização dos serviços postais e bancários básicos e se caracterizam como instrumento governamental de desenvolvimento social e econômico.', '', 19),
(3763, 'capitulo', 1, 3745, 2, '2.18', 'Agência de Relacionamento - AR: Agência do Banco parceiro, que se relaciona diretamente com a Agência do Banco Postal, dando-lhe o apoio necessário na prestação do serviço de correspondente.', '', 20),
(3764, 'capitulo', 1, 3745, 2, '2.19', 'Agência Filatélica - AF: é a unidade de atendimento própria dos Correios voltada, principalmente, a atender à demanda dos clientes da área de selos e produtos filatélicos.', '', 21),
(3765, 'capitulo', 1, 3745, 2, '2.20', 'Agência operada por terceiros: agência operada com recursos de terceiros, mediante contrato de franquia postal ou contrato de permissão ou termo de convênio com órgãos públicos. Compõem ainda a rede operada por terceiros os Postos de Vendas de Produtos - PVP, formalizados mediante termo de credenciamento.', '', 22),
(3766, 'capitulo', 1, 3745, 2, '2.21', 'Agência vinculadora: é a agência própria à qual uma agência terceirizada está vinculada.', '', 23),
(3767, 'capitulo', 1, 3745, 2, '2.22', 'Agências do Banco Postal: agências de Correios que operam o sistema Banco Postal.', '', 24),
(3768, 'capitulo', 1, 3745, 2, '2.23', 'Alteração da composição societária: inclusão, exclusão parcial ou substituição total ou parcial de sócios na empresa titular operadora da unidade de atendimento terceirizada dos Correios.', '', 25),
(3769, 'capitulo', 1, 3745, 2, '2.24', 'Amarrado: agrupamento de objetos postais FN e/ou FS, rotulados com etiqueta específica única (etiqueta de amarrado), para encaminhamento a uma unidade postal. Fonte: MANDIS 1/1.', '', 26),
(3770, 'capitulo', 1, 3745, 2, '2.25', 'Ambiente de desenvolvimento: ambiente tecnológico onde são desenvolvidas e testadas as atualizações solicitadas no Portal Correios. As informações disponíveis nesse ambiente são exclusivamente acessadas da rede interna, ou seja, não estão disponíveis aos usuários da internet.', '', 27),
(3771, 'capitulo', 1, 3745, 2, '2.26', 'Ambiente de produção: ambiente tecnológico onde está instalado o Portal Correios cujas informações podem ser acessadas pelos usuários da internet.', '', 28),
(3772, 'capitulo', 1, 3745, 2, '2.27', 'Amostra em marketing direto: geralmente é um produto de tamanho ou espessura reduzida, em relação ao produto comercializado e/ou produzido pela empresa, o qual é fornecido gratuitamente ao consumidor para experimentação.', '', 29),
(3773, 'capitulo', 1, 3745, 2, '2.28', 'Amostra FAC: objeto extraído de forma aleatória, de diversas partes da carga, considerando a quantidade informada pelo Sistema CIFWEB, correspondente a 2% do total de objetos postados, limitando-se o mínimo de 20 (vinte) objetos e ao máximo de 200 (duzentos), para conferência com as informações individuais constantes do Relatório de Postagem Eletrônico.', '', 30),
(3774, 'capitulo', 1, 3745, 2, '2.29', 'Análise de procedência da reclamação: é o procedimento de averiguação de possíveis erros na prestação de serviço, formalmente comunicados pelo cliente por intermédio de Pedido de Informação - PI (objetos registrados) ou por Manifestação Genérica - MG (objetos sem registro).', '', 31),
(3775, 'capitulo', 1, 3745, 2, '2.30', 'Anexo operacional do contrato: documento gerado no ERP que reúne todas as informações cadastradas para os percursos do contrato de Malote. É fornecido junto ao contrato do cliente.', '', 32),
(3776, 'capitulo', 1, 3745, 2, '2.31', 'Anuário: publicação anual, contendo informações científicas, literárias, artísticas, econômicas etc.', '', 33),
(3777, 'capitulo', 1, 3745, 2, '2.32', 'Apuração preliminar: constitui num procedimento investigativo elementar e tem como objetivo a identificação dos elementos necessários à avaliação das causas que motivaram a reclamação do cliente e que resultaram em pagamento de indenização.', '', 34),
(3778, 'capitulo', 1, 3745, 2, '2.33', 'Área acessória: é a área destinada à instalação de ponto de atendimento auxiliar ao que foi licitado. Esse ponto adicional deverá estar localizado em área excedente à utilizada para instalação da AGF ou em imóvel distinto, que atendam as especificações do normativo interno.', '', 35),
(3779, 'capitulo', 1, 3745, 2, '2.34', 'Área de precificação estadual: é o conjunto de municípios de um mesmo Estado, excluindo-se aqueles pertencentes a uma mesma área de precificação local, onde é cobrado o preço local. Para a área de precificação estadual é cobrado o preço estadual.', '', 36),
(3780, 'capitulo', 1, 3745, 2, '2.35', 'Área de precificação local: é o conjunto de municípios de um mesmo Estado, em cuja jurisdição o preço local é cobrado.', '', 37),
(3781, 'capitulo', 1, 3745, 2, '2.36', 'Área de precificação nacional: é o conjunto de todos os Estados, com exceção daquele em que é feita a postagem do objeto.', '', 38),
(3782, 'capitulo', 1, 3745, 2, '2.37', 'Arquivo com Informações de Não Entrega - POE: trata-se do padrão e do formato do arquivo eletrônico envio ao cliente do serviço Correios Entrega Direta, de dados relativos à não entrega de suas publicações periódicas. Constitui-se arquivo de entrega, gerado pelos Correios, via FTP.', '', 39),
(3783, 'capitulo', 1, 3745, 2, '2.38', 'Arquivo com Respostas as Reclamações Apresentadas pela Editora - RES: trata-se do padrão e formato do arquivo eletrônico envio ao cliente do serviço Correios Entrega Direta, de dados relativos à resposta das reclamações postadas mediante arquivo REM, relativo as suas publicações periódicas. Constitui-se arquivo de entrega, gerado pelos Correios, via FTP.', '', 40),
(3784, 'capitulo', 1, 3745, 2, '2.39', 'Arquivo de Etiquetas para Impressão - ETI: trata-se do padrão e formato do arquivo eletrônico para postagem de publicações periódicas no serviço Correios Entrega Direta, conforme padrões dos Correios. Constitui-se arquivo de entrega, gerado pelos Correios, via FTP.', '', 41),
(3785, 'capitulo', 1, 3745, 2, '2.40', 'Arquivo de Postagem - PTG: trata-se do padrão e formato do arquivo eletrônico para postagem de publicações periódicas no serviço Correios Entrega Direta, conforme padrões dos Correios. Constitui-se arquivo de busca, gerado pelo cliente, disponibilizado aos Correios, via FTP.', '', 42),
(3786, 'capitulo', 1, 3745, 2, '2.41', 'Arquivo de Postagem para confecção de Etiquetas Personalizadas - PTP: trata-se do padrão e formato do arquivo eletrônico para postagem de publicações periódicas personalizadas no serviço Correios Entrega Direta, conforme padrões dos Correios, o qual retornará um arquivo ETI. Constitui-se arquivo de busca, gerado pelo cliente, disponibilizado aos Correios, via FTP.', '', 43),
(3787, 'capitulo', 1, 3745, 2, '2.42', 'Arquivo de Reclamações - REM: trata-se do padrão e formato do arquivo eletrônico para postagem de reclamações relativas às publicações periódicas postadas no serviço Correios Entrega Direta, conforme padrões dos Correios. Constitui-se arquivo de busca, gerado pelo cliente, disponibilizado aos Correios, via FTP.', '', 44),
(3788, 'capitulo', 1, 3745, 2, '2.43', 'Atendimento: conjunto de atividades desenvolvidas junto aos clientes com o propósito de prestar informações e esclarecimentos e propiciar a prestação de serviços e a venda de produtos.', '', 45),
(3789, 'capitulo', 1, 3745, 2, '2.44', 'Atendimento conclusivo CPF: atendimento realizado exclusivamente pelos Correios, sem a necessidade de o cliente comparecer à unidade local da Secretaria Receita Federal do Brasil.', '', 46),
(3790, 'capitulo', 1, 3745, 2, '2.45', 'Atendimento impeditivo CPF: atendimento que não é conclusivo, nem não conclusivo, ou seja, atendimento que apresenta alguma inconsistência que não permite a finalização do atendimento.', '', 47),
(3791, 'capitulo', 1, 3745, 2, '2.46', 'Atendimento não conclusivo CPF: atendimento realizado inicialmente nos Correios e concluído pela Secretaria Receita Federal do Brasil. O cliente, após ser atendido pela Agência de Correios terá que se dirigir à unidade local da Secretaria da Receita Federal do Brasil para a conclusão do seu atendimento iniciado nos Correios. Após a finalização do atendimento pela Secretaria da Receita Federal do Brasil, não haverá mais nenhuma ação dos Correios.', '', 48),
(3792, 'capitulo', 1, 3745, 2, '2.47', 'Atividade de controle e gestão: é a atividade adaptada às características próprias de cada agência.', '', 49),
(3793, 'capitulo', 1, 3745, 2, '2.48', 'Auto de Irregularidade - AI: documento no qual são registradas não conformidades constatadas no encaminhamento postal interno, antes da entrega do objeto ao destinatário.', '', 50),
(3794, 'capitulo', 1, 3745, 2, '2.49', 'Autoridade Certificadora - AC: entidade responsável pela geração e emissão dos certificados digitais.', '', 51),
(3795, 'capitulo', 1, 3745, 2, '2.50', 'Autoridade Certificadora Raiz - AC Raiz: é a primeira autoridade da cadeia de certificação digital, executora das Políticas de Certificados e normas técnicas e operacionais aprovadas pelo Comitê Gestor da ICP-Brasil.', '', 52),
(3796, 'capitulo', 1, 3745, 2, '2.51', 'Autoridade Registradora - AR: entidade responsável pela interface entre o usuário e uma Autoridade Certificadora - AC. É sempre vinculada a uma AC e tem por objetivo o recebimento, a validação, a autorização e o encaminhamento de solicitações de emissão ou revogação de certificados digitais às AC e identificação, de forma presencial, de seu(s) solicitante(s). A AR Correios é vinculada à AC Serpro RFB.', '', 53),
(3797, 'capitulo', 1, 3745, 2, '2.52', 'Autorização de Postagem em Agência (e-ticket): número que permite ao remetente realizar a postagem de um objeto em uma Agência de Correios Própria, por meio do serviço de Logística Reversa.', '', 54),
(3798, 'capitulo', 1, 3745, 2, '2.53', 'Autorizado/permissionário: pessoa física ou jurídica, credenciada pelos Correios, por meio de termo específico para uso de Máquina de Franquear.', '', 55),
(3799, 'capitulo', 1, 3745, 2, '2.54', 'Avaliação Técnica Comercial - ATC: formulário padrão de avaliação das características físicas e geométricas do objeto postal, para fins de habilitação ao critério de desconto “Objeto Automatizável”.', '', 56),
(3800, 'capitulo', 1, 3745, 2, '2.55', 'Avaliação Técnica Operacional - ATO: formulário padrão de avaliação da performance da massa de teste submetida ao tratamento nos sistemas de triagem automatizada, para fins de habilitação ao critério de desconto “Impressão do CEPNET em objeto automatizável”.', '', 57),
(3801, 'capitulo', 1, 3745, 2, '2.56', 'Aviso de chegada: é o aviso emitido por uma unidade dos Correios e encaminhado ao destinatário de um objeto, onde é informado ao cliente que a encomenda se encontra disponível para retirada interna.', '', 58),
(3802, 'capitulo', 1, 3745, 2, '2.57', 'Aviso de Recebimento - AR: serviço que permite comprovar, junto ao remetente, a entrega de objeto postado sob registro, com ou sem declaração de valor.', '', 59),
(3803, 'capitulo', 1, 3745, 2, '2.58', 'Aviso de Recebimento Compacto: é o AR destinado para uso em objetos com dimensões de 90x145mm ou aproximadamente. É normalmente utilizado em embalagem para remessa de Compact Disc ou assemelhados.', '', 60),
(3804, 'capitulo', 1, 3745, 2, '2.59', 'Aviso de Recebimento Digital - AR Digital: é o AR que informa ao remetente, por meio eletrônico, os dados de entrega do objeto e restitui o AR de forma digital, ou seja, por meio de imagem via mídia eletrônica, em substituição ao formulário físico.', '', 61),
(3805, 'capitulo', 1, 3745, 2, '2.60', 'Aviso de Recebimento Integrado: é o AR normalmente utilizado para contratos de SEDEX Especial, podendo, no entanto, ser utilizado para os demais serviços tais como: Carta Registrada, SEDEX, Encomenda Normal etc., devendo ser colado na extremidade esquerda do anverso do objeto. Este AR é dividido em 2 (duas) partes frontais, contendo todas as informações pertinentes ao remetente e destinatário. Também se destina a atender a demanda específica dos clientes que desejam, quando do insucesso da entrega, o objeto retorne para o endereço “A” e o formulário de AR retorne para o endereço “B”.', '', 62),
(3806, 'capitulo', 1, 3745, 2, '2.61', 'Aviso de tentativa de entrega/coleta: é o aviso emitido por um empregado dos Correios e deixado no local da tentativa de entrega ou coleta de um objeto, visando comprovar que esteve no local e que retornará para uma nova tentativa.', '', 63),
(3807, 'capitulo', 1, 3745, 2, '2.62', 'Banco de dados (database): conjunto de informações relevantes sobre o cliente que permitem selecioná-lo da forma mais precisa possível para o envio de ofertas, prospecção e material de relacionamento em ações de marketing direto.', '', 64),
(3808, 'capitulo', 1, 3745, 2, '2.63', 'Banco de Dados Financeiro - BDF: sistema que incorpora diariamente todos os movimentos gerados nas agências dos Correios (próprias ou terceirizadas).', '', 65),
(3809, 'capitulo', 1, 3745, 2, '2.64', 'Banco Postal - BP: serviço financeiro postal especial instituído pelo Ministério das Comunicações, para que os Correios atuem na condição de Correspondente em sua rede de atendimento.', '', 66),
(3810, 'capitulo', 1, 3745, 2, '2.65', 'Banner: peça de divulgação institucional ou comercial produzida em material resistente.', '', 67),
(3811, 'capitulo', 1, 3745, 2, '2.66', 'Beneficiário da indenização ou do ressarcimento de Objeto Nacional Registrado: o cliente que pode receber o valor de indenização, após o processo de apuração da reclamação ou na indenização de ofício. Pode ser recebedor:', '', 68),
(3812, 'capitulo', 1, 3811, 4, 'a', 'remetente: quando ocorre extravio ou espoliação total;', '', 69),
(3813, 'capitulo', 1, 3811, 4, 'b', 'destinatário: quando ocorre avaria ou o objeto foi postado como Sedex a Cobrar, cujos preços postais foram pagos pelo próprio destinatário;', '', 70),
(3814, 'capitulo', 1, 3811, 4, 'c', 'contratante: quando o objeto for postado no serviço de Logística Reversa;', '', 71),
(3815, 'capitulo', 1, 3811, 4, 'd', 'autorizado: quando o remetente, o destinatário ou o contratante autoriza, por escrito, outra pessoa a receber a indenização que lhe é devida.', '', 72),
(3816, 'capitulo', 1, 3745, 2, '2.67', 'Boletim de Intervenção Técnica - BIT: documento exigido pela CESEP para executar intervenções no ambiente de produção.', '', 73),
(3817, 'capitulo', 1, 3745, 2, '2.68', 'Boletim de Ocorrência - BO: é o documento emitido por autoridade policial contendo relato das ocorrências de sinistro (assalto a carteiro, assalto a veículo, assalto a unidade etc.).', '', 74),
(3818, 'capitulo', 1, 3745, 2, '2.69', 'Boletim Técnico - BT: é um instrumento utilizado para publicar, internamente, informações relacionadas à Empresa.', '', 75),
(3819, 'capitulo', 1, 3745, 2, '2.70', 'Boletins: publicação periódica que em geral se constitui em objeto de divulgação de entidade oficial ou privada. Exemplo: Boletim Meteorológico', '', 76),
(3820, 'capitulo', 1, 3745, 2, '2.71', 'Brinde: é a mercadoria que, não se constituindo objeto de linha de comercialização ou produção da empresa contratante, tenha sido adquirida para a distribuição gratuita ao consumidor final em ações de marketing direto.', '', 77),
(3821, 'capitulo', 1, 3745, 2, '2.72', 'Cadastramento de usuários SIGMA: cadastro efetuado no sistema SIGMA que autoriza o empregado a trabalhar com a ferramenta, em perfis predefinidos.', '', 78),
(3822, 'capitulo', 1, 3745, 2, '2.73', 'Cadastro Nacional de Pessoa Física - CPF: é um banco de dados gerenciado pela Secretaria da Receita Federal do Brasil - RFB que armazena informações cadastrais de contribuintes obrigados à inscrição no CPF, ou de cidadãos que se inscreveram voluntariamente.', '', 79),
(3823, 'capitulo', 1, 3745, 2, '2.74', 'Cadastro de Pessoa Física eletrônico - e-CPF: Certificado digital criado pela Secretaria da Receita Federal para identificar o contribuinte pessoa física no ambiente virtual. É comercializado nas agências credenciadas dos Correios.', '', 80),
(3824, 'capitulo', 1, 3745, 2, '2.75', 'Cadastro Nacional de Pessoa Jurídica eletrônico - e-CNPJ: certificado digital criado pela Secretaria da Receita Federal para identificar o contribuinte pessoa jurídica no ambiente virtual. É comercializado nas agências credenciadas dos Correios.', '', 81),
(3825, 'capitulo', 1, 3745, 2, '2.76', 'Caixas Ativos: quantidade de empregados cadastrados no SARA/BP que possuam algum produto, operação do banco postal ou outro serviço vinculado à sua matrícula, e que tenha registrado alguma operação no dia.', '', 82),
(3826, 'capitulo', 1, 3745, 2, '2.77', 'Caixa de coleta: é o receptáculo instalado em logradouros públicos destinados ao atendimento do usuário por meio de depósito de correspondência previamente franqueada.', '', 83),
(3827, 'capitulo', 1, 3745, 2, '2.78', 'Caixa postal: serviço por meio do qual os objetos são depositados em receptáculos apropriados, para entrega mediante a utilização da respectiva chave, sem a interferência de empregado dos Correios.', '', 84),
(3828, 'capitulo', 1, 3745, 2, '2.79', 'Caixas previstos: Quantidade de posições definidas no sistema SGPA para as atividades de atendimento em guichê.', '', 85),
(3829, 'capitulo', 1, 3745, 2, '2.80', 'Caixas temporários da própria unidade: quantidade de empregados da própria unidade, com ou sem portaria para exercer a função de quebra de caixa na unidade, cadastrados no SARA/BP e que, por qualquer motivo, possuam algum produto, operação do banco postal ou outro serviço vinculado à sua matrícula, e que tenham registrado alguma operação no dia, enquadrando-se neste caso os empregados da própria unidade atuando na substituição no horário do almoço, férias e absenteísmo dos caixas titulares da própria unidade. Exemplos dos casos sem portaria são as situações de substituição pontual de quebras de caixa na unidade ou de vendas avulsas, pelo Gerente, Encarregado de Tesouraria ou Supervisor de Atendimento, em decorrência de horário de almoço ou ausência momentânea do titular, onde são realizadas vendas no SARA/BP por empregado sem função de quebra de caixa, habilitado no sistema.', '', 86),
(3830, 'capitulo', 1, 3745, 2, '2.81', 'Caixas temporários de outra unidade: quantidade de empregados lotados em outras unidades, com portaria para exercer a função de quebra de caixa na unidade, cadastrados no SARA/BP e que possuam algum produto, operação do banco postal ou outro serviço vinculado à sua matrícula, e que tenham registrado alguma operação no(s) dia(s) na unidade que o recebeu. Enquadra-se neste caso o efetivo reserva lotado em outra unidade e que atenderá às demandas decorrentes de férias, absenteísmo ou do fechamento provisório da unidade (por exemplo, em decorrência de arrombamentos e necessidade de reformas na unidade).', '', 87),
(3831, 'capitulo', 1, 3745, 2, '2.82', 'Caixas temporários para outra unidade: quantidade de empregados lotados na unidade, com portaria para exercer a função de quebra de caixa em outra unidade, cadastrados no SARA/BP e que possuam algum produto, operação do banco postal ou outro serviço vinculado à sua matrícula, e que tenham registrado alguma operação no(s) dia(s) na unidade que o recebeu. Enquadra-se nesse caso o efetivo reserva lotado na unidade e que atenderá às demandas decorrentes de férias, absenteísmo ou do fechamento provisório de outras unidades (por exemplo, em decorrência de arrombamentos e necessidade de reformas na unidade).', '', 88),
(3832, 'capitulo', 1, 3745, 2, '2.83', 'Caixas titulares: quantidade de empregados designados por portaria, vigente e sem término definido, para exercer a função de quebra de caixa na unidade.', '', 89),
(3833, 'capitulo', 1, 3745, 2, '2.84', 'Caixeta: unitizador de material resistente, com formato adequado ao empilhamento, destinado ao acondicionamento de objetos simples ou registrados, de formato normal ou semi-embaraçoso.', '', 90),
(3834, 'capitulo', 1, 3745, 2, '2.85', 'Campanha de incentivo a vendas: ação regional ou corporativa que, por meio de mecanismos de recompensa e reconhecimento, objetiva incrementar as receitas da Empresa.', '', 91),
(3835, 'capitulo', 1, 3745, 2, '2.86', 'Campanha de terceiros: campanha de incentivo às vendas em que os custos com a premiação e com produção do material promocional forem de responsabilidade exclusiva do(s) parceiro(s).', '', 92),
(3836, 'capitulo', 1, 3745, 2, '2.87', 'Campanha mista: campanha de incentivo às vendas em que os custos com a premiação e com produção do material promocional são compartilhados com outro(s) parceiro(s).', '', 93),
(3837, 'capitulo', 1, 3745, 2, '2.88', 'Campanha própria: campanha de incentivo às vendas em que os custos com a premiação e com produção do material promocional são de responsabilidade exclusiva da Empresa.', '', 94),
(3838, 'capitulo', 1, 3745, 2, '2.89', 'Canal de atendimento: estrutura oferecida para a captação centralizada de manifestações dos clientes: serviços comerciais como captação de telegramas e solicitação de coleta de objetos, informações sobre produtos e serviços, reclamações, sugestões, elogios, críticas e denúncias. É identificada segundo a forma de captação:', 'a) canal telefônico, como a CAC;\nb) canal via internet, como o Fale com os Correios;\nc) endereço para envio de carta;\nd) e-mail para envio de mensagem;\ne) fax;\nf) chat;\ng) blogue;\nh) instant messaging;\ni) Twitter;\nj) ouvidoria.', 95),
(3839, 'capitulo', 1, 3745, 2, '2.90', 'Capacidade Produtiva de um Empregado - CPE: é o tempo real de efetiva ocupação do empregado com seu trabalho, sendo considerada em condições normais uma ocupação real de 90% da jornada diária de 8 (oito) horas, o que equivale a 432 (quatrocentos e trinta e dois) minutos.', '', 96),
(3840, 'capitulo', 1, 3745, 2, '2.91', 'Carga consolidada FAC: carga composta por vários lotes de um mesmo cliente, para postagens através de um mesmo contrato.', '', 97),
(3841, 'capitulo', 1, 3745, 2, '2.92', 'Carga da máquina de franquear: é o valor que se aplica ao registrador descendente do medidor da máquina de franquear.', '', 98),
(3842, 'capitulo', 1, 3745, 2, '2.93', 'Carga de trabalho: é o tempo total médio diário consumido na execução das atividades em uma AC.', '', 99),
(3843, 'capitulo', 1, 3745, 2, '2.94', 'Carga de Trabalho Média Diária - CMD: é o tempo total médio diário consumido individualmente nos trabalhos de cada setor da agência.', '', 100),
(3844, 'capitulo', 1, 3745, 2, '2.95', 'Carga de trabalho média diária total - CMDT: é o somatório das cargas médias diárias de todos os setores da agência.', '', 101),
(3845, 'capitulo', 1, 3745, 2, '2.96', 'Carga Heterogênea: composta por objetos que apresentam dimensões diferentes.', '', 102),
(3846, 'capitulo', 1, 3745, 2, '2.97', 'Carga Homogênea: composta por objetos que apresentam as mesmas dimensões.', '', 103),
(3847, 'capitulo', 1, 3745, 2, '2.98', 'Carga Remota: procedimento computadorizado utilizado para realizar carga em medidor de Máquina de Franquear, mediante conexão desta à CCR, via modem.', '', 104),
(3848, 'capitulo', 1, 3745, 2, '2.99', 'Carta: objeto de correspondência, com ou sem envoltório, sob a forma de comunicação escrita, de natureza administrativa social, comercial, ou qualquer outra, que contenha informação de interesse específico do destinatário.', '', 105),
(3849, 'capitulo', 1, 3745, 2, '2.100', 'Carta comercial: é aquela cujo remetente é pessoa jurídica com ou sem fins lucrativos, com inscrição no CNPJ, e que recebe o tratamento de objeto urgente ou, ainda, a carta que apresente pelo menos um dos seguintes aspectos:', 'a) remetente anônimo;\nb) franqueamento por meio de contrato com os Correios.\nCarta não comercial: é aquela cujo remetente é pessoa física e que recebe o tratamento de objeto urgente, sendo vedado:\na) utilização de envelope tipo data-mailer,\nb) utilização de envelopes com timbre de pessoas jurídicas ou com inscrições promocionais impressas no envelope.', 106),
(3850, 'capitulo', 1, 3745, 2, '2.101', 'Carta registrada: é a carta com o serviço adicional de Registro.', '', 107),
(3851, 'capitulo', 1, 3745, 2, '2.102', 'Carta simples: é a carta sem nenhum serviço adicional.', '', 108),
(3852, 'capitulo', 1, 3745, 2, '2.103', 'Carta social: é a modalidade de Carta cuja postagem está vinculada ao Programa Bolsa Família, e que tem por finalidade contribuir para a inclusão social por meio dos serviços postais de pessoas em situação de pobreza ou de extrema pobreza.', '', 109),
(3853, 'capitulo', 1, 3745, 2, '2.104', 'Cartão de autógrafo: formulário de acolhimento de assinaturas, para efeito de validação da assinatura do cliente.', '', 110),
(3854, 'capitulo', 1, 3745, 2, '2.105', 'Cartão de autorização de postagem: cartão de identificação do cliente, onde constam os seguintes dados: Código Administrativo, nome do cliente, SE de origem, validade do cartão, unidades credenciadas e a especificação dos serviços que serão prestados. É obrigatória a sua apresentação quando da postagem da carga.', '', 111),
(3855, 'capitulo', 1, 3745, 2, '2.106', 'Cartão de crédito: é um produto disponibilizado pelo banco parceiro a ser contratado por meio do Banco Postal a clientes com crédito pré-aprovado pela instituição financeira.', '', 112),
(3856, 'capitulo', 1, 3745, 2, '2.107', 'Cartão operacional: cartão emitido no SIGMA para postagem do malote, impresso em 2 (duas) faces, contendo razão social e dados de endereçamento do cliente para a ida e a volta. Contempla ainda o código de barras com 35 (trinta e cinco) posições numéricas, apresentando respectivamente o CEP de destino, código do serviço, número de identificação do percurso, campo vago com 4 (quatro) posições, indicativo de ida (1) ou volta (8) e o número do malote.', '', 113),
(3857, 'capitulo', 1, 3745, 2, '2.108', 'Cartão-Postal: objeto de correspondência, de material consistente, sem envoltório, contendo mensagem e endereço.', '', 114),
(3858, 'capitulo', 1, 3745, 2, '2.109', 'Cartão-Resposta: cartão ou cupom, encartado em catálogo ou fazendo parte do inteiro de uma peça de propaganda, que possibilita, ao cliente, a remessa de seu pedido, reserva da mercadoria ou objeto do seu interesse.', '', 115),
(3859, 'capitulo', 1, 3745, 2, '2.110', 'Carta-Resposta - CR: é o envelope, que pode ser encartado em catálogo ou em outro material de propaganda impressa, que possibilita, ao cliente, a remessa do seu pedido, reserva da mercadoria ou objeto do seu interesse.', '', 116),
(3860, 'capitulo', 1, 3745, 2, '2.111', 'Carta-Resposta Convencional - CRC: é o tipo em que o conteúdo é inserido em envelope específico, previamente confeccionado pelo cliente autorizado, em âmbito nacional.', '', 117),
(3861, 'capitulo', 1, 3745, 2, '2.112', 'Carta-Resposta Internacional - CRI: é o tipo em que o conteúdo é inserido em envelope específico, previamente confeccionado pelo cliente autorizado, em âmbito internacional. Permite a remessa de pedidos e/ou informações, sob a forma de carta ou cartão, não previamente franqueados, à pessoa jurídica autorizada, que efetuará o pagamento correspondente no ato da retirada.', '', 118),
(3862, 'capitulo', 1, 3745, 2, '2.113', 'Carta-Resposta taxa paga: é o tipo no qual o remetente utiliza envelope comum para acondicionar o conteúdo.', '', 119),
(3863, 'capitulo', 1, 3745, 2, '2.114', 'Cartazes obrigatórios: são aqueles referentes às informações obrigatórias sobre a operacionalização dos serviços prestados pelos Correios.', '', 120),
(3864, 'capitulo', 1, 3745, 2, '2.115', 'Cartazes obrigatórios do Banco Postal: são aqueles referentes às informações obrigatórias do Banco Postal.', '', 121),
(3865, 'capitulo', 1, 3745, 2, '2.116', 'Cartazes sociais: são aqueles relacionados às campanhas do Governo Federal, Estadual ou Municipal (Ex: Desaparecimento de menores, vacinação etc.).', '', 122),
(3866, 'capitulo', 1, 3745, 2, '2.117', 'Carteira de clientes: conjunto de clientes (CNPJ) sob gestão de um vendedor responsável pelo relacionamento e vendas dos produtos e serviços.', '', 123),
(3867, 'capitulo', 1, 3745, 2, '2.118', 'Carteira Nacional de Habilitação - CNH: é o documento oficial que atesta a aptidão de um cidadão para conduzir veículos automotores terrestres.', '', 124),
(3868, 'capitulo', 1, 3745, 2, '2.119', 'Catálogo: objeto em formato brochura contendo ofertas de produtos ou serviços. À exceção da capa, cada face do objeto deve conter a imagem do produto/serviço ofertado. Os objetos classificados como catálogos devem ter as seguintes dimensões: no mínimo 190 mm (comprimento) x 135 mm (largura) x 1 mm (altura) e no máximo 275 mm (comprimento) x 205 mm (largura) x 40 mm (altura). Exemplos: catálogo de roupas, produtos, moda.', '', 125),
(3869, 'capitulo', 1, 3745, 2, '2.120', 'Categorias de localidade: segue a classificação adotada pelo Instituto Brasileiro de Geografia e Estatística - IBGE:', 'a) cidade - sede de município ou do 1º (primeiro) distrito;\nb) vila - sede de distrito, quando o município possuir, em sua composição político-administrativa, mais de um distrito;\nc) povoado - qualquer outra localidade, desde que não esteja enquadrada, oficialmente, nas categorias de cidade ou vila.', 126),
(3870, 'capitulo', 1, 3869, 3, '2.120.1', 'Serão consideradas como povoado as seguintes categorias de localidade: aglomerado rural, agrovila, aldeia, colônia, fazenda, lugarejo, povoado, reserva indígena, subdistrito etc. Será considerado como perímetro urbano, toda área da localidade, dentro dos limites estabelecidos, assim considerada pelos documentos federais, estaduais e municipais. Existem bairros e locais cuja denominação se inicia pela palavra \"vila\"; no entanto, não são considerados como sede de distrito. Somente serão consideradas como cidade ou vila, aquelas localidades cujos respectivos municípios e distritos estejam efetivamente instalados, de acordo com os procedimentos legais inerentes a cada Unidade da Federação. Até que seja efetivada sua instalação como município ou distrito, uma localidade, que esteja passando pelo processo de elevação de categoria, deverá ser enquadrada na categoria em que estava classificada, antes da vigência do documento legal. O município somente será considerado como instalado, após a efetiva posse de seus representantes eleitos (prefeito, vice-prefeito e vereadores). No caso de distrito, a sua instalação dependerá, ou não, de um ato de formalização, conforme estiver determinado na legislação vigente em cada Unidade da Federação.', '', 127),
(3871, 'capitulo', 1, 3745, 2, '2.121', 'Categorização de clientes: estratificação dos clientes em categorias que vão de “A” a “I”, de acordo com o valor que representam para a Empresa em PPCC/ano, conforme relação a seguir:', '', 128),
(3872, 'capitulo', 1, 3871, 4, 'a', 'A - acima de 200.000.000', '', 129),
(3873, 'capitulo', 1, 3871, 4, 'b', 'B - de 36.000.001 a 200.000.000', '', 130),
(3874, 'capitulo', 1, 3871, 4, 'c', 'C - de 5.400.001 a 36.000.000', '', 131),
(3875, 'capitulo', 1, 3871, 4, 'd', 'D - 1.000.001 a 5.400.000', '', 132),
(3876, 'capitulo', 1, 3871, 4, 'e', 'E - 300.001 a 1.000.000', '', 133),
(3877, 'capitulo', 1, 3871, 4, 'f', 'F - 100.001 a 300.000 (SE/SPM)', '', 134),
(3878, 'capitulo', 1, 3871, 4, 'g', 'F - 50.001 a 300.000 (Demais SEs)', '', 135),
(3879, 'capitulo', 1, 3871, 4, 'h', 'G - 30.001 a 100.000 (SE/SPM)', '', 136),
(3880, 'capitulo', 1, 3871, 4, 'i', 'G - 30.001 a 50.000 (Demais SEs)', '', 137),
(3881, 'capitulo', 1, 3871, 4, 'j', 'H - abaixo de 30.000', '', 138),
(3882, 'capitulo', 1, 3871, 4, 'k', 'I - qualquer valor à vista', '', 139),
(3883, 'capitulo', 1, 3745, 2, '2.122', 'Cecograma: objeto de correspondência impresso em relevo, para uso dos cegos. Considera-se também cecograma o material impresso para uso dos cegos. Disponível para envio nacional e internacional', '', 140),
(3884, 'capitulo', 1, 3745, 2, '2.123', 'Célula de mobiliários e equipamentos a compartilhar: é o espaço físico capaz de comportar móveis e equipamentos destinados ao suporte das atividades desenvolvidas no guichê de retaguarda, cuja utilização é opcional e pode ser partilhada com outros guichês de retaguarda e/ou para apoiar as atividades dos guichês de atendimento.', '', 141),
(3885, 'capitulo', 1, 3745, 2, '2.124', 'Célula mínima: é o espaço físico estimado para comportar móveis e equipamentos referentes à instalação de único guichê de retaguarda.', '', 142),
(3886, 'capitulo', 1, 3745, 2, '2.125', 'Central de Atendimento dos Correios - CAC: canal de atendimento responsável pela captação de manifestações dos clientes dos Correios por telefone, que atende por intermédio dos seguintes números:', 'a) 3003-0100: capitais, regiões metropolitanas e cidades-sedes de DDD;\nb) 0800-725-7282: demais localidades;\nc) 0800-725-0100: exclusivo para o registro de reclamações, elogios e sugestões.', 143),
(3887, 'capitulo', 1, 3745, 2, '2.126', 'Central de Carga Remota - CCR: unidade de processamento onde se executa e controla todo o processo de carga e gerenciamento de Máquinas de Franquear, mantendo a integridade e a inviolabilidade dos aplicativos e dos dados, emitindo relatórios gerenciais.', '', 144),
(3888, 'capitulo', 1, 3745, 2, '2.127', 'Central de Controle Físico - CCF: unidade de processamento responsável pela armazenagem e processamento das informações coletadas das amostras de objetos pesquisados, nos Locais de Recebimento e Tratamento. Também é responsável pelo cruzamento de dados com a Central de Carga Remota.', '', 145),
(3889, 'capitulo', 1, 3745, 2, '2.128', 'Centralizador: unidade operacional que concentra as atividades de recebimento e encaminhamento da carga postal de/para outras unidades. Fonte: MANENC 1/1.', '', 146),
(3890, 'capitulo', 1, 3745, 2, '2.129', 'Centro de Tratamento de Cartas - CTC: unidade operacional responsável pelo tratamento de cartas. Fonte: MANENC 1/1.', '', 147),
(3891, 'capitulo', 1, 3745, 2, '2.130', 'Centro de Tratamento de Cartas e Encomendas - CTCE: unidade operacional responsável pela execução integrada das atividades de coleta, recebimento, conferência, triagem e expedição de correspondências, malote e encomendas. Fonte: MANENC 1/1.', '', 148),
(3892, 'capitulo', 1, 3745, 2, '2.131', 'CEPNET: representação gráfica do CEP em código de barras, de forma “compreendida” pela máquina de triagem de correspondências. O código representa os 8 (oito) dígitos do Código de Endereçamento Postal - CEP e para cada número serão utilizadas 5 (cinco) barras. Ao final dos 8 (oito) dígitos, deverá ser acrescido mais um dígito, totalizando 9 (nove), que será denominado Dígito Verificador.', '', 149),
(3893, 'capitulo', 1, 3745, 2, '2.132', 'Central de Relacionamento com os Clientes - CEREL: órgão vinculado à Administração Central com a função de administrar, controlar, coordenar e operacionalizar os processos transacionais relativos aos serviços de gestão da CAC; gestão dos canais de relacionamento com o cliente; gestão do Sistema Fale Conosco; gestão das reclamações e indenizações.', '', 150),
(3894, 'capitulo', 1, 3745, 2, '2.133', 'Certificação digital: é um composto de serviços baseados na venda de certificados digitais em Agências dos Correios.', '', 151),
(3895, 'capitulo', 1, 3745, 2, '2.134', 'Certificado de homologação: documento emitido pelo DERAT atestando, com base nos relatórios das áreas, a homologação da máquina de franquear digital ou do ambiente do fornecedor.', '', 152),
(3896, 'capitulo', 1, 3745, 2, '2.135', 'Certificado de Registro de Veículos - CRV: é o documento de segurança que se destina a comprovar que o veículo com as características nele descritas está no cadastro de veículos do Detran.', '', 153),
(3897, 'capitulo', 1, 3745, 2, '2.136', 'Certificado de Registro e Licenciamento de Veículos - CRLV: é o documento de segurança que se destina a comprovar que o veículo com as características nele especificadas está com o licenciamento regular, após a quitação dos débitos especificados.', '', 154),
(3898, 'capitulo', 1, 3745, 2, '2.137', 'Certificado Digital - CD: é uma ferramenta de segurança que permite ao cidadão brasileiro realizar transações eletrônicas que necessitem de segurança, como assinar contratos, notas fiscais eletrônicas etc.', '', 155),
(3899, 'capitulo', 1, 3745, 2, '2.138', 'Cesta de serviços Banco Postal: pacote de produtos e serviços padronizados de acordo com perfil do cliente com valores de tarifas mensais específicas.', '', 156),
(3900, 'capitulo', 1, 3745, 2, '2.139', 'Chancela: forma de franqueamento para clientes de contrato.', '', 157),
(3901, 'capitulo', 1, 3745, 2, '2.140', 'Chancela-padrão de franqueamento: para os serviços prestados mediante contrato ficam estabelecidas, como formas de franqueamento, chancelas específicas, por serviço, as quais retratam a modalidade de entrega, conforme padronização, em símbolos, estabelecida pelos Correios.', '', 158),
(3902, 'capitulo', 1, 3745, 2, '2.141', 'Check-list ou lista de checagem: formulário no qual são discriminados todos os itens de verificação de prédios, equipamentos, objetos e processos da Empresa.', '', 159),
(3903, 'capitulo', 1, 3745, 2, '2.142', 'Cheque: é uma ordem de pagamento à vista, ao próprio emitente ou a terceiro.', '', 160),
(3904, 'capitulo', 1, 3745, 2, '2.143', 'Circuito de coleta: itinerário pré-definido para a coleta de objetos depositados em caixas de coleta, executado pelo coletor em frequência regular.', '', 161),
(3905, 'capitulo', 1, 3745, 2, '2.144', 'Classificação de objetos postais: é a atividade que define se o teor e a natureza do conteúdo da mensagem do objeto postal para comunicação dirigida são de interesse específico do destinatário ou de interesse geral ou de um grupo de pessoas.', '', 162),
(3906, 'capitulo', 1, 3745, 2, '2.145', 'Cliente: pessoa física ou jurídica que adquire produtos/serviços da Empresa.', '', 163),
(3907, 'capitulo', 1, 3745, 2, '2.146', 'Cliente avulso: cliente de Reembolso Postal sem contrato com os Correios.', '', 164),
(3908, 'capitulo', 1, 3745, 2, '2.147', 'Cliente CNS: lojas ou anunciantes, contratantes do ambiente do shopping para intermediação nas suas vendas ou para propaganda.', '', 165),
(3909, 'capitulo', 1, 3745, 2, '2.148', 'Cliente comercial: pessoa jurídica que possui contrato firmado com os Correios para a prestação de serviços e venda de produtos, cujo valor de categorização, em Primeiro Porte da Carta Comercial - PPCC, seja até:', 'a) 100.000 vezes para a Superintendência Estadual de SPM;\nb) 50.000 vezes para as Superintendências Estaduais da BA, MG, PR, RJ, RS e SPI;\nc) 30.000 vezes para as demais Superintendências Estaduais.', 166),
(3910, 'capitulo', 1, 3745, 2, '2.149', 'Cliente corporativo: pessoa jurídica que possui contrato firmado com os Correios para a prestação de serviços e venda de produtos, cujo valor de categorização seja de 300.001 a 5.400.000 vezes o PPCC.', '', 167),
(3911, 'capitulo', 1, 3745, 2, '2.150', 'Cliente empresarial: pessoa jurídica que possui contrato firmado com os Correios para a prestação de serviços e venda de produtos, cujo valor de categorização, em PPCC, seja de:', 'a) 100.001 a 300.000 vezes para a Superintendência Estadual de SPM;\nb) 50.001 a 300.000 vezes para as Superintendências Estaduais da BA, MG, PR, RJ, RS e SPI;\nc) 30.001 a 300.000 vezes para as demais Superintendências Estaduais.', 168),
(3912, 'capitulo', 1, 3745, 2, '2.151', 'Cliente estratégico: pessoa jurídica que possui contrato firmado com os Correios para a prestação de serviços e venda de produtos, cujo valor de categorização seja superior a 5.400.000 vezes o PPC', '', 169),
(3913, 'capitulo', 1, 3745, 2, '2.152', 'Cliente inscrito: cliente de reembolso postal com contrato com os Correios.', '', 170),
(3914, 'capitulo', 1, 3745, 2, '2.153', 'Cliente varejo: pessoa física ou jurídica que utiliza os serviços e adquire os produtos dos Correios com pagamento na modalidade à vista.', '', 171),
(3915, 'capitulo', 1, 3745, 2, '2.154', 'Código 128: código de barras padrão 128, com codificação de números e letras maiúsculas, sendo utilizado para a impressão do número do registro.', '', 172),
(3916, 'capitulo', 1, 3745, 2, '2.155', 'Código administrativo: código numérico gerado mediante o cadastramento de um contrato nos sistemas dos Correios. O código é o identificador do contrato.', '', 173),
(3917, 'capitulo', 1, 3745, 2, '2.156', 'Código de Endereçamento Postal - CEP: é um conjunto numérico constituído de 8 (oito) algarismos, cujo objetivo principal é orientar e acelerar o encaminhamento, o tratamento e a distribuição de objetos de correspondência, por meio da sua atribuição a localidades, logradouros, unidades dos Correios, serviços, órgãos públicos, empresas e edifícios.', '', 174),
(3918, 'capitulo', 1, 3745, 2, '2.157', 'Código de Informação de Franqueamento - CIF: código de barras expresso no padrão “Code 128”, devendo ser impresso em todos os objetos postados como FAC Simples. Pode ser aposto na parte interna da janela do envelope, na etiqueta de endereçamento ou no próprio envelope, frente ou verso, de acordo com as especificações técnicas constantes no seguinte endereço: \\\\sac0424\\SISTEMAS\\VINEG\\Novo_FAC', '', 175),
(3919, 'capitulo', 1, 3918, 3, '2.157.1', 'O código CIF contém as seguintes informações:', 'a) Código da DR de postagem: 2 dígitos;\nb) Código Administrativo do Contrato: 8 dígitos;\nc) Número do lote: 5 dígitos;\nd) Número sequencial do objeto (ID do objeto): 11 dígitos;\ne) Código de Destino: 1 dígito;\nf) Código Reserva (igual a o): 1 dígito;\ng) Data de Produção/Postagem: 6 dígitos.', 176),
(3920, 'capitulo', 1, 3745, 2, '2.158', 'Coeficiente de atividade: tempo médio de execução de cada atividade. Como cada atividade possui sua especificidade, cada uma tem o seu tempo médio de execução. O coeficiente é definido em minutos.', '', 177),
(3921, 'capitulo', 1, 3745, 2, '2.159', 'ColdAnalyzer: ferramenta utilizada para analisar códigos de programas de forma a evitar que sua execução degrade o ambiente onde o sistema será executado.', '', 178),
(3922, 'capitulo', 1, 3745, 2, '2.160', 'Coleta especial: termo utilizado, no serviço Disque Coleta, para as coletas realizadas entre 18h e 20h.', '', 179),
(3923, 'capitulo', 1, 3745, 2, '2.161', 'Coleta normal: termo utilizado, no serviço Disque Coleta, para as coletas realizadas entre 14h e 18h.', '', 180),
(3924, 'capitulo', 1, 3745, 2, '2.162', 'Coleta Programada - CP: Serviço de coleta domiciliar de objeto realizado de forma regular.', '', 181),
(3925, 'capitulo', 1, 3745, 2, '2.163', 'Coleta Programada Diurna - CPD: serviço adicional do Malote que oferece aos clientes a flexibilidade de horário de coleta, pagando valor específico previsto no verso da tarifa, por operação, acrescido ao serviço principal.', '', 182),
(3926, 'capitulo', 1, 3745, 2, '2.164', 'Coleta Programada Noturna - CPN: serviço adicional do Malote que oferece aos clientes a flexibilidade de horário de coleta entre 18h e 20h, pagando valor específico previsto no verso da tarifa, por operação, acrescido ao serviço principal.', '', 183),
(3927, 'capitulo', 1, 3745, 2, '2.165', 'Coleta vertical: coleta de malote efetuada em endereços localizados em edifícios comerciais.', '', 184),
(3928, 'capitulo', 1, 3745, 2, '2.166', 'Coletor de caixas de coleta: empregado responsável pela coleta das correspondências depositadas nas caixas de coleta.', '', 185),
(3929, 'capitulo', 1, 3745, 2, '2.167', 'Comercialização: é o processo por meio do qual se busca descobrir e interpretar as necessidades, desejos e expectativas dos clientes para então satisfazê-los por meio da concepção, da promoção, da venda e da distribuição de produtos e serviços.', '', 186),
(3930, 'capitulo', 1, 3745, 2, '2.168', 'Competências comerciais: conjunto das principais competências exigidas do profissional da área de vendas. São elas: visão sistêmica, visão estratégica, análise e crítica, relacionamento interpessoal, foco em resultados, comunicação, negociação, visão de processo, proatividade, conhecimento técnico, criatividade, comportamento ético, foco no cliente, poder de decisão, planejamento e liderança.', '', 187),
(3931, 'capitulo', 1, 3745, 2, '2.169', 'Composição societária: são as pessoas físicas que compõem a pessoa jurídica operadora da agência terceirizada.', '', 188),
(3932, 'capitulo', 1, 3745, 2, '2.170', 'Comprovante: é um formulário (recibo) a ser fornecido, quando da apresentação de mensagem telemática, e se destina a comprovar o pagamento da prestação do serviço no guichê da unidade operacional.', '', 189),
(3933, 'capitulo', 1, 3745, 2, '2.171', 'Comprovante de postagem: recibo emitido pelos Correios no momento do atendimento, contendo dados dos serviços prestados e os respectivos códigos de registro, contendo 13 dígitos, necessários para a identificação dos objetos em caso de abertura de Pedido de Informação - PI.', '', 190),
(3934, 'capitulo', 1, 3745, 2, '2.172', 'Comunicação dirigida: é toda mensagem escrita, na forma impressa ou eletrônica, destinada a uma pessoa ou grupo de pessoas.', '', 191),
(3935, 'capitulo', 1, 3745, 2, '2.173', 'Comunicação dirigida de interesse específico do destinatário: é aquela de teor e natureza pessoal, intransferível, com informações de caráter confidencial, comumente denominada Carta.', '', 192),
(3936, 'capitulo', 1, 3745, 2, '2.174', 'Comunicação dirigida de interesse geral ou de um grupo de pessoas: é aquela de teor e natureza pública, de interesse geral ou que interessa a um grupo de pessoas indistintamente, comumente denominado Impresso.', '', 193);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(3937, 'capitulo', 1, 3745, 2, '2.175', 'Comunicação Interna - CI: é um instrumento de correspondência utilizado para as comunicações entre os órgãos da Empresa, que requeiram o registro de assuntos formais com redação mais extensa.', '', 194),
(3938, 'capitulo', 1, 3745, 2, '2.176', 'Consignação: entrega de mercadorias por um fabricante ou consignador a um agente vendedor que as recebe, sem transferência de posse, responsabilizando-se apenas pelo pagamento da parte vendida, conservando a possibilidade de devolver o restante que não tiver sido vendido.', '', 195),
(3939, 'capitulo', 1, 3745, 2, '2.177', 'Consulta de extrato: é uma transação disponibilizada no Banco Postal que permite o correntista verificar a movimentação da sua conta.', '', 196),
(3940, 'capitulo', 1, 3745, 2, '2.178', 'Consulta de saldo: é uma transação disponibilizada no Banco Postal que permite o correntista verificar a posição do saldo de sua conta.', '', 197),
(3941, 'capitulo', 1, 3745, 2, '2.179', 'Conta conjunta não solidária: modalidade de conta com 2 (dois) ou 3 (três) titulares, cuja movimentação somente poderá ser feita com as assinaturas de todos os titulares. Nesse caso, não será fornecido cartão magnético e estará vedado o cadastramento da senha.', '', 198),
(3942, 'capitulo', 1, 3745, 2, '2.180', 'Conta conjunta solidária: modalidade de conta com 2 (dois) ou 3 (três) titulares, o quais podem movimentá-la em conjunto ou isoladamente', '', 199),
(3943, 'capitulo', 1, 3745, 2, '2.181', 'Conta corrente: é a forma de cobrança utilizada para os clientes que possuam acordo com os Correios, para esse tipo de débito.', '', 200),
(3944, 'capitulo', 1, 3745, 2, '2.182', 'Conta de consumo: documentos como contas de água, luz, telefone etc., apresentada em Agência do Banco Postal para fins de comprovação de endereço.', '', 201),
(3945, 'capitulo', 1, 3745, 2, '2.183', 'Conta espólio: conta corrente de titularidade de falecido e movimentada legalmente por inventariante (não disponível no Banco Postal).', '', 202),
(3946, 'capitulo', 1, 3745, 2, '2.184', 'Conta mais: é uma modalidade de conta de depósito à vista e poupança ofertada no Banco Postal, para pessoa física e jurídica.', '', 203),
(3947, 'capitulo', 1, 3745, 2, '2.185', 'Contas em condições especiais: são contas prioritariamente destinadas a menores, proponentes incapazes, não alfabetizados, contas abertas com procuração, deficientes visuais/auditivos e tituladas por falecidos (espólio).', '', 204),
(3948, 'capitulo', 1, 3745, 2, '2.186', 'Contêiner Aramado Fixo - CAF: unitizador desmontável, constituído por uma estrutura metálica dobrável, utilizado na unitização de carga postal. Fonte: MANENC 1/1.', '', 205),
(3949, 'capitulo', 1, 3745, 2, '2.187', 'Contêiner Desmontável Leve - CDL: tipo de recipiente desmontável, com base e tampa em plástico injetado e corpo em papelão, utilizado na unitização de carga postal. Fonte: MANENC 1/1.', '', 206),
(3950, 'capitulo', 1, 3745, 2, '2.188', 'Contestação de transferência intercompany: Procedimento que consiste na análise de procedência das transferências entre regionais de valores pagos a título de indenização.', '', 207),
(3951, 'capitulo', 1, 3745, 2, '2.189', 'Contratante: pessoa jurídica que contrata os Correios para prestar serviços a terceiros.', '', 208),
(3952, 'capitulo', 1, 3745, 2, '2.190', 'Contrato: acordo formal firmado entre os Correios e terceiros, cujas cláusulas e condições definem os direitos, obrigações e responsabilidades das partes.', '', 209),
(3953, 'capitulo', 1, 3745, 2, '2.191', 'Contrato de Franquia Postal - CFP: é o instrumento contratual firmado entre os Correios e a pessoa jurídica (operador) de direito privado, precedido de seleção através de licitação, e cujas cláusulas, referentes aos direitos e obrigações recíprocas, às condições para fornecimento de produtos ou de prestação de serviços pertinentes ao objeto contratado, assim como as condições gerais de remuneração e de pagamento, submetem-se ao regime de franquia postal.', '', 210),
(3954, 'capitulo', 1, 3745, 2, '2.192', 'Contrato de Permissão: é o instrumento contratual firmado entre os Correios e a pessoa jurídica (operador) de direito privado, precedido de seleção através de licitação, e cujas cláusulas, referentes aos direitos e obrigações recíprocas, às condições para fornecimento de produtos ou de prestação de serviços pertinentes ao objeto contratado, assim como as condições gerais de remuneração e de pagamento, submetem-se ao regime permissional de outorga de serviços públicos.', '', 211),
(3955, 'capitulo', 1, 3745, 2, '2.193', 'Contrato especial: é o contrato firmado entre os Correios e a pessoa jurídica (usuário) de direito público ou privado, cujas cláusulas, não se enquadram nos contratos padronizados.', '', 212),
(3956, 'capitulo', 1, 3745, 2, '2.194', 'Contrato múltiplo: é contrato firmado entre os Correios e pessoa jurídica (usuário) de direito público ou privado, de adesão aos serviços dos Correios. Este contrato resume em um único documento a coletânea de contratos comerciais referentes a cada serviço integrante do porta-fólio dos Correios. Constitui-se de 3 (três) partes: corpo, ficha técnica e anexo. O corpo contém cláusulas identificadoras da relação cliente e os Correios; a ficha técnica contempla as informações que tratam de especificidades do cliente com os Correios em cada serviço e o anexo abrange os procedimentos financeiros, operacionais e técnicos, relativo a cada serviço.', '', 213),
(3957, 'capitulo', 1, 3745, 2, '2.195', 'Contrato múltiplo simplificado: é o contrato que se constitui dos documentos relacionados abaixo:', 'a) corpo: apresenta apenas as cláusulas essenciais exigidas pela Lei nº 8.666/93;\nb) ficha resumo: ficha que contém os serviços escolhidos pelo cliente, dados específicos da contratação dos serviços a serem prestados, bem como a data de vigência dos serviços contratados;\nc) ficha técnica do serviço: ficha contendo os dados variáveis dos seguintes produtos e serviços: Carta comercial, Carta Cartão Resposta, Conta Certa, Correios Entrega Direta, DNE, Encomendas, FAC, Mala Direta Postal Domiciliária, órgãos de trânsito e recebimento de inscrições.\nd) termo de condições gerais de prestação de serviços e venda de produtos: contém o detalhamento da execução do contrato, incluindo os anexos de todos os produtos e serviços dos Correios. Esse termo está averbado no Cartório do 2º Ofício de Registro Civil, Títulos e Documentos e Pessoas Jurídica de Brasília, sob o registro n.º 984931 de 18/10/2010. A via física desse termo pode ser solicitada pelos clientes ao cartório, via site www.cartoriodebrasilia.com.br.', 214),
(3958, 'capitulo', 1, 3957, 3, '2.195.1', 'Os documentos constantes nas alíneas a, b e c formam o instrumento contratual a ser assinado pelas partes, sendo que uma das vias ficará arquivada nas Regionais, juntamente com as alterações ocorridas no decorrer da vigência contratual, tanto na ficha resumo como nas fichas técnicas.', '', 215),
(3959, 'capitulo', 1, 3957, 3, '2.195.2', 'A cada alteração necessária deverá ser assinada uma nova ficha resumo, sendo válida a mais recente, sem a necessidade de formalização de termo aditivo.', '', 216),
(3960, 'capitulo', 1, 3745, 2, '2.196', 'Cópia de Telegrama - CC: é um Serviço Adicional Taxado cuja solicitação é feita pelo remetente (expedidor), no ato da apresentação da mensagem telemática, bem como pelo destinatário no ato da postagem da mensagem telemática ou posteriormente (obedecido o prazo de arquivamento de telegrama) para que lhe seja fornecida uma cópia do telegrama transmitido no SGM.', '', 217),
(3961, 'capitulo', 1, 3745, 2, '2.197', 'Correios Entrega Direta - CED: serviço exclusivo para entrega, em âmbito nacional, de publicações periódicas, em domicílio. Destina-se ao cliente que precisa distribuir e gerenciar a entrega de suas publicações, da postagem à entrega. Por meio da web, são disponibilizadas informações da performance da entrega, motivos de não entrega e possibilidades de reenvio, de modo a que o cliente tenha respostas rápidas e confiáveis para os recebedores de suas publicações.', '', 218),
(3962, 'capitulo', 1, 3745, 2, '2.198', 'Correios online: loja virtual dos Correios que oferece produtos e serviços nacionais e internacionais pelo site www.correiosonline.com.br. A materialização de sua prestação de serviços ocorre por intermédio da Agência de Correios Vendas à Distância.', '', 219),
(3963, 'capitulo', 1, 3745, 2, '2.199', 'CorreiosNet Shopping - CNS: solução de comércio eletrônico dos Correios para hospedagem de loja virtual e realização segura de transações comerciais na internet.', '', 220),
(3964, 'capitulo', 1, 3745, 2, '2.200', 'CorreiosNet Shopping: canal, via internet, a ser utilizado para captação dos valores referentes ao pagamento de carga por terceiros.', '', 221),
(3965, 'capitulo', 1, 3745, 2, '2.201', 'Correspondência: toda comunicação de pessoa a pessoa, por meio de carta, via postal, ou por telegrama.', '', 222),
(3966, 'capitulo', 1, 3745, 2, '2.202', 'Correspondente: é uma empresa que atua nos mais diversos ramos de atividade, contratada por instituição financeira e outras autorizadas a funcionar pelo Banco Central do Brasil - Bacen, para prestação de serviços de atendimento a clientes e usuários da instituição contratante.', '', 223),
(3967, 'capitulo', 1, 3745, 2, '2.203', 'Criptografia de chave pública: método de criptografia para certificados digitais que utiliza um par de chaves: uma pública e outra privada. A chave pública é distribuída livremente para todos os correspondentes, enquanto a chave privada deve ser conhecida apenas pelo seu dono.', '', 224),
(3968, 'capitulo', 1, 3745, 2, '2.204', 'Criptographic Service Provider - CSP: provedor de serviços de criptografia.', '', 225),
(3969, 'capitulo', 1, 3745, 2, '2.205', 'Critérios de Descontos FAC: FAC simples:', 'a) volume;\nb) formato automatizável;\nc) impressão do CEP em código de barras (CEPNET), em objeto automatizável;\nd) unitização da carga; e\ne) postagem antecipada.\nFAC registrado:\na) volume;\nb) unitização da carga;\nc) postagem antecipada.', 226),
(3970, 'capitulo', 1, 3745, 2, '2.206', 'Cupom: para circulação postal, é a parte destacável do objeto ou do invólucro, com característica semelhante à carta-resposta, desde que possua indicação de local para porteamento do cupom, local para indicação do endereço do remetente e instrução para envio do referido cupom através dos Correios.', '', 227),
(3971, 'capitulo', 1, 3745, 2, '2.207', 'Cupom Resposta Internacional: Título de valor postal emitido pela UPU, que pode ser vendido ou trocado em outros países por selos postados ao valor de referência previamente estabelecido para cada país.', '', 228),
(3972, 'capitulo', 1, 3745, 2, '2.208', 'Custos: é qualquer desembolso financeiro relacionado à investimentos, instalação, operacionalização e manutenção de uma AGF/área acessória.', '', 229),
(3973, 'capitulo', 1, 3745, 2, '2.209', 'Data de produção: conceito aplicado somente em postagem de carga parcelada. É o último dia de produção de determinado lote de objetos e, também, a data limite para a postagem dos objetos junto aos Correios. Será considerada como a data de postagem efetiva, para fins de controle dos prazos de qualidade de entrega dos objetos.', '', 230),
(3974, 'capitulo', 1, 3745, 2, '2.210', 'Declaração de Práticas de Certificação - DPC: descreve as práticas e os procedimentos empregados pela AC SERPRO RFB, integrante da ICP-Brasil, na execução dos seus serviços.', '', 231),
(3975, 'capitulo', 1, 3745, 2, '2.211', 'Delegação de representação: faculdade que assiste à empresa titular da ACF, caracterizada pela possibilidade de constituição de preposto perante os Correios, mediante procuração com poderes para praticar atos relativos ao Contrato de Franquia Empresarial - CFE, vedado o substabelecimento com ou sem reservas de poderes e excluídos os relativos à transferência ou extinção da titularidade da ACF, a alteração da composição societária, a mudança de endereço da unidade, a acordo de parcelamento de débito e a celebração de Termo Aditivo ao CFE.', '', 232),
(3976, 'capitulo', 1, 3745, 2, '2.212', 'Depois do Horário - DH: carimbo aplicado na correspondência/encomenda postada após o horário limite de encaminhamento do dia.', '', 233),
(3977, 'capitulo', 1, 3745, 2, '2.213', 'Depósito: é a transação disponibilizada no Banco Postal referente à entrega de numerário, por parte do cliente, para guarda em conta.', '', 234),
(3978, 'capitulo', 1, 3745, 2, '2.214', 'Desempenho Geral da Venda DGV: avalia o desempenho da receita originada dos contratos celebrados pela Regional somada à sua receita à vista medindo de forma efetiva o seu esforço de vendas, até o mês corrente do exercício.', '', 235),
(3979, 'capitulo', 1, 3745, 2, '2.215', 'Despersonalização: é o ato de separar o Selo-Base da vinheta destinada ao cliente, por meio de corte manual nos picotes que unem as peças.', '', 236),
(3980, 'capitulo', 1, 3745, 2, '2.216', 'Destinatário: responsável pelo recebimento de encomenda ou objeto. Só detém a posse do objeto após a efetiva entrega.', '', 237),
(3981, 'capitulo', 1, 3745, 2, '2.217', 'Devolução de Documento - DD: serviço que permite o retorno de documento ou de via de Nota Fiscal, ao remetente da encomenda, após a entrega do objeto.', '', 238),
(3982, 'capitulo', 1, 3745, 2, '2.218', 'Devolução Garantida: é o serviço que assegura a restituição, opcional, ao remetente, de objetos postados por meio dos serviços de Impresso Normal, Impresso Especial e Mala Direta Postal cuja entrega ao destinatário, não tenha sido possível.', '', 239),
(3983, 'capitulo', 1, 3745, 2, '2.219', 'Dimensionamento do efetivo: determinação do número de profissionais necessários nos postos de trabalho, com base nos parâmetros “Carga de Trabalho”.', '', 240),
(3984, 'capitulo', 1, 3745, 2, '2.220', 'Direto: sistema utilizado para fazer a gestão da postagem e não entrega da Mala Direta Postal Especial, Básica, Expressa, Econômica e Porta a Porta.', '', 241),
(3985, 'capitulo', 1, 3745, 2, '2.221', 'Diretório Nacional de Endereços - e-DNE: banco de dados constituído de elementos de endereçamento até nível de secção de logradouro e Códigos de Endereçamento Postal - CEP. Possui aproximadamente 793.000 CEPs em aproximadamente 916.000 registros de elementos de endereçamento relativos a Continentes e Países, Unidades da Federação, Localidades, Bairros, Logradouros, Unidades dos Correios, Caixas Postais, Grandes Usuários, Eventos Promocionais e Caixas Postais Comunitárias.', '', 242),
(3986, 'capitulo', 1, 3745, 2, '2.222', 'Diretório Nacional de Endereços - Básico - e-DNE Básico: Modalidade do DNE destinada a qualquer pessoa física ou jurídica que na condição de usuária final trabalhe com as seguintes aplicações:', '', 243),
(3987, 'capitulo', 1, 3986, 4, 'a', 'validação, higienização e duplicação de registros de cadastros de endereços;', '', 244),
(3988, 'capitulo', 1, 3986, 4, 'b', 'mineração de dados (datamining);', '', 245),
(3989, 'capitulo', 1, 3986, 4, 'c', 'localização geográfica (geomarketing);', '', 246),
(3990, 'capitulo', 1, 3986, 4, 'd', 'atendimento call centers e/ou telemarketing;', '', 247),
(3991, 'capitulo', 1, 3986, 4, 'e', 'acesso à internet ou intranet;', '', 248),
(3992, 'capitulo', 1, 3986, 4, 'f', 'gerenciamento da relação com clientes;', '', 249),
(3993, 'capitulo', 1, 3986, 4, 'g', 'Customer Relationship Management (CRM);', '', 250),
(3994, 'capitulo', 1, 3986, 4, 'h', 'captação de endereços;', '', 251),
(3995, 'capitulo', 1, 3986, 4, 'i', 'Enterprise Resource Panning (ERP).', '', 252),
(3996, 'capitulo', 1, 3986, 4, 'j', 'base de dados fornecida em arquivo texto (.txt)', '', 253),
(3997, 'capitulo', 1, 3745, 2, '2.223', 'Diretório Nacional de Endereços - Master - e-DNE Master: modalidade do DNE destinada a qualquer pessoa física ou jurídica que trabalhe com as seguintes aplicações:', '', 254),
(3998, 'capitulo', 1, 3997, 4, 'a', 'desenvolvimento de software para tratamento de endereços e comercialização no mercado corporativo;', '', 255),
(3999, 'capitulo', 1, 3997, 4, 'b', 'prestação de serviços de higienização de cadastros de endereços (oneshot ou online);', '', 256),
(4000, 'capitulo', 1, 3997, 4, 'c', 'publicação de guias de endereços, catálogos telefônicos e assemelhados', '', 257),
(4001, 'capitulo', 1, 3997, 4, 'd', 'validação, higienização e deduplicação de registros de cadastros de endereços;', '', 258),
(4002, 'capitulo', 1, 3997, 4, 'e', 'mineração de dados (datamining);', '', 259),
(4003, 'capitulo', 1, 3997, 4, 'f', 'localização geográfica (geomarketing);', '', 260),
(4004, 'capitulo', 1, 3997, 4, 'g', 'atendimento call centers e/ou telemarketing;', '', 261),
(4005, 'capitulo', 1, 3997, 4, 'h', 'acesso à internet ou intranet;', '', 262),
(4006, 'capitulo', 1, 3997, 4, 'i', 'gerenciamento da relação com clientes;', '', 263),
(4007, 'capitulo', 1, 3997, 4, 'j', 'Customer Relationship Management (CRM);', '', 264),
(4008, 'capitulo', 1, 3997, 4, 'k', 'captação de endereços;', '', 265),
(4009, 'capitulo', 1, 3997, 4, 'l', 'Enterprise Resource Panning (ERP).', '', 266),
(4010, 'capitulo', 1, 3997, 4, 'm', 'base de dados fornecida em arquivos .mdb e .txt.', '', 267),
(4011, 'capitulo', 1, 3745, 2, '2.224', 'Disque Coleta - DC: serviço de coleta domiciliar de objeto, realizado de forma esporádica.', '', 268),
(4012, 'capitulo', 1, 3745, 2, '2.225', 'Distribuição aleatória: é aquela em que a Mala Direta Postal Domiciliária é entregue juntamente com a correspondência a ser distribuída, não causando alteração na percorrida do Carteiro.', '', 269),
(4013, 'capitulo', 1, 3745, 2, '2.226', 'Distribuição interna: é aquela realizada na rede de atendimento dos Correios, exclusivamente através das Caixas Postais, displays ou entregue pelos Atendentes Comerciais.', '', 270),
(4014, 'capitulo', 1, 3745, 2, '2.227', 'Distribuição seletiva: é aquela em que as condições de entrega são preestabelecidas, causando alteração na percorrida do Carteiro. Dessa forma, serão disponibilizados para o serviço as seguintes possibilidades de segmentação para a entrega das Malas Diretas Postais Domiciliárias:', '', 271),
(4015, 'capitulo', 1, 3745, 2, '2.228', 'Divergência de Peso: peso total líquido da carga diferente daquele informado no Relatório de Postagem Eletrônico, excedendo a margem de erro de 4% (quatro por cento), a maior ou a menor. Na hipótese de o peso total líquido da carga estar igual ao informado, ou dentro da margem de tolerância, não será considerada divergência de peso para fins de ajuste da postagem', '', 272),
(4016, 'capitulo', 1, 3745, 2, '2.229', 'Documento Internacional: serviço utilizado para envio de documentos do Brasil para o exterior. É classificado como documento o conteúdo que se refere à uma comunicação de caráter confidencial entre pessoas e ou empresas.', '', 273),
(4017, 'capitulo', 1, 3745, 2, '2.230', 'Dossiê da instalação técnica: é um conjunto de documentos devidamente organizados, que obrigatoriamente constam em uma instalação técnica e servem de auxílio para os agentes de registro dirimirem suas dúvidas.', '', 274),
(4018, 'capitulo', 1, 3745, 2, '2.231', 'DR de Origem do Contrato: Superintendência Estadual em que o contrato foi celebrado.', '', 275),
(4019, 'capitulo', 1, 3745, 2, '2.232', 'DR de Vinculação do Contrato (DR de Faturamento): Superintendência Estadual que presta os serviços contratados através de contrato celebrado por outra SE. Chamada também de SE de faturamento, por faturar os serviços por ela prestados.', '', 276),
(4020, 'capitulo', 1, 3745, 2, '2.233', 'DR Pagadora da Indenização: Superintendência Estadual que contabiliza o pagamento de indenizações.', '', 277),
(4021, 'capitulo', 1, 3745, 2, '2.234', 'DR Processamento da Indenização: SE que processa o pagamento de indenizações.', '', 278),
(4022, 'capitulo', 1, 3745, 2, '2.235', 'Efetivo existente: quantidade de empregados lotados na unidade, abatendo-se da informação aqueles empregados lotados na unidade e que prestam serviços temporários em outras unidades e incluindo-se aqueles empregados lotados em outras unidades que prestam serviços temporários na unidade.', '', 279),
(4023, 'capitulo', 1, 3745, 2, '2.236', 'O abatimento e a inclusão do pessoal que presta serviço temporário deve ser proporcional aos dias efetivamente trabalhados no mês, exemplos:', '', 280),
(4024, 'capitulo', 1, 4023, 4, 'a', 'unidade em que parte do efetivo atua em outras unidades:', 'I - efetivo previsto: 9 empregados;\nII - efetivo ativo lotado na unidade (CAD): 9 empregados;\nIII - efetivo atuando temporariamente em outra unidade: 1 empregado;\nIV - tempo de atuação temporária fora da unidade: 15 dias no mês.\nTem-se:\nEfetivo existente = 9 - (15/30) = 9 - 0,5 = 8,5 empregados', 281),
(4025, 'capitulo', 1, 4023, 4, 'b', 'unidade em que parte do efetivo vem de outras unidades:', 'I - efetivo Previsto: 9 empregados;\nII - efetivo ativo lotado na unidade (CAD): 7 empregados;\nIII - efetivo atuando temporariamente na unidade: 4 empregados;\nIV - tempo de atuação do temporário na unidade: 15 dias no mês.\nTem-se:\nEfetivo Existente: 7 + [(15×4)/30] = 7 + 2 = 9 empregados', 282),
(4026, 'capitulo', 1, 3745, 2, '2.237', 'Efetivo previsto: quantidade de empregados definidos no sistema SGPA para todos os setores (guichê, interno, administrativo e financeiro) da unidade, incluindo-se no cálculo o efetivo reserva.', '', 283),
(4027, 'capitulo', 1, 3745, 2, '2.238', 'E-mail: é um instrumento de correspondência interna e externa, utilizado por órgãos ou empregados para agilizar a circulação de informações.', '', 284),
(4028, 'capitulo', 1, 3745, 2, '2.239', 'Empréstimo: é um produto referente à liberação de crédito por Instituições Financeiras a clientes pessoa física ou jurídica.', '', 285),
(4029, 'capitulo', 1, 3745, 2, '2.240', 'Encabeçamento: disposição dos objetos colocados verticalmente nas caixetas com o endereçamento invertido para baixo. Fonte: MANENC 1/1.', '', 286),
(4030, 'capitulo', 1, 3745, 2, '2.241', 'Encontro da força de vendas: ação promovida pela área comercial que, periodicamente, reúne, num mesmo local, os profissionais da força de vendas. Pode ser em âmbito regional ou corporativo.', '', 287),
(4031, 'capitulo', 1, 3745, 2, '2.242', 'Encontro de Negócios: ação desenvolvida pela área comercial, com o objetivo de promover e ampliar o relacionamento com os clientes dos Correios, clientes potenciais, segmentos de mercado e clientes usuários de um mesmo segmento de negócios.', '', 288),
(4032, 'capitulo', 1, 3745, 2, '2.243', 'Endereçamento: compõe-se de nome completo, endereço completo (rua, quadra, conjunto, bloco, nº da casa ou apartamento etc) e o Código de Endereçamento Postal - CEP, que deverão ser indicados de forma legível.', '', 289),
(4033, 'capitulo', 1, 3745, 2, '2.244', 'Endosso de cheque: transferência da posse do cheque para outra pessoa física/jurídica.', '', 290),
(4034, 'capitulo', 1, 3745, 2, '2.245', 'Enterprise Resource Planning - ERP: são sistemas de informação que integram todos os dados e processos de uma organização em um único sistema, também conhecido como SIGE (Sistemas Integrados de Gestão Empresarial).', '', 291),
(4035, 'capitulo', 1, 3745, 2, '2.246', 'Entrega ao Portador: é o serviço cuja entrega de um objeto, ao destinatário, será de inteira responsabilidade do remetente, podendo o seu encaminhamento ser efetuado por terceiros, desde que esse transporte não se constitua em exploração econômica.', '', 292),
(4036, 'capitulo', 1, 3745, 2, '2.247', 'Entrega de Encarte Local: serviço acessório do serviço Correios Entrega Direta que constitui a entrega de um encarte, junto à publicação, sendo esse encarte disponibilizado pelo remetente ou parceiro diretamente no destino/local em que contrata a entrega local.', '', 293),
(4037, 'capitulo', 1, 3745, 2, '2.248', 'Entrega Programada Diurna - EPD: Serviço adicional do Malote que oferece aos clientes a flexibilidade de horário de entrega, pagando valor específico previsto no verso da tarifa, por operação, acrescido ao serviço principal.', '', 294),
(4038, 'capitulo', 1, 3745, 2, '2.249', 'Entrega Programada Noturna - EPN: Serviço adicional do Malote que oferece aos clientes a flexibilidade de horário de entrega entre 18 e 20 horas, pagando valor específico previsto no verso da tarifa, por operação, acrescido ao serviço principal.', '', 295),
(4039, 'capitulo', 1, 3745, 2, '2.250', 'Entrega Protocolada: Serviço acessório do serviço Correios Entrega Direta que constitui a entrega de publicação mediante comprovante de entrega a ser assinado pelo destinatário/assinante. Geralmente é uma forma de verificar o recebedor de publicações de alto valor agregado e/ou fruto de reclamações habituais do assinante.', '', 296),
(4040, 'capitulo', 1, 3745, 2, '2.251', 'Envelopamento: serviço acessório do serviço Correios Entrega Direta que constitui o envelopamento das publicações nas unidades dos Correios, geralmente no destino, com fornecimento de insumo pelo cliente contratante.', '', 297),
(4041, 'capitulo', 1, 3745, 2, '2.252', 'Envelope: invólucro achatado, de forma retangular, geralmente obtido mediante dobras de uma única folha de papel. Nesse caso as dobras são feitas de modo a apresentar a face anterior (anverso), inteiriça e lisa e a posterior (verso), com quatro abas de fechamento, três das quais coladas pelos seus bordos, uma sobre a outra, conservando-se a quarta livre para o fechamento final.', '', 298),
(4042, 'capitulo', 1, 4041, 4, 'a', 'a face anterior (anverso), poderá apresentar uma área transparente, de forma retangular (janela), através da qual podem ser lidos o nome e o endereço do destinatário, escritos no conteúdo.', '', 299),
(4043, 'capitulo', 1, 4041, 4, 'b', 'os envelopes poderão se constituir, também, de 2 (duas) folhas de papel coladas uma à outra, pelas suas bordas.', '', 300),
(4044, 'capitulo', 1, 3745, 2, '2.253', 'Envelope de janela: envelope de janela - é o envelope que apresenta na face anterior (anverso), uma área transparente (janela) de forma retangular, através da qual podem ser lidos o nome e o endereço do destinatário escritos no conteúdo.', '', 301),
(4045, 'capitulo', 1, 3745, 2, '2.254', 'Envelope Encomenda-Resposta: é o serviço que permite a remessa de objetos, sob a forma de envelope encomenda, à pessoa jurídica autorizada, que efetuará o pagamento correspondente no ato da retirada', '', 302),
(4046, 'capitulo', 1, 3745, 2, '2.255', 'Envelope ordinário: é o envelope que apresenta a face anterior (anverso) inteiriça.', '', 303),
(4047, 'capitulo', 1, 3745, 2, '2.256', 'Envelope pré-pago de 1º porte: é a sobrecarta comercializada pelos Correios para ser usada pelo público em geral, na remessa de carta simples de primeiro porte, em âmbito nacional.', '', 304),
(4048, 'capitulo', 1, 3745, 2, '2.257', 'Envelope SEDEX estadual pré-franqueado: envelope específico pré-franqueado, tipo saco, com ilustrações alusivas aos serviços dos Correios, destinado ao acondicionamento de objetos a serem postados na modalidade SEDEX Estadual Pré-Franqueado do Serviço de Encomenda Expressa.', '', 305),
(4049, 'capitulo', 1, 3745, 2, '2.258', 'Envelope SEDEX Nacional: são envelopes padronizados, tipo saco, com ilustrações alusivas aos serviços dos Correios, destinados à embalagem de objetos do Serviço de Encomenda Expressa - SEDEX.', '', 306),
(4050, 'capitulo', 1, 3745, 2, '2.259', 'Envelopes comuns: são os envelopes utilizados no âmbito nacional, padronizados segundo as normas da ABNT, sendo, por isso, designados Recomendado pelos Correios - RPC.', '', 307),
(4051, 'capitulo', 1, 3745, 2, '2.260', 'Escoamento: processo automatizado ou procedimentos manuais de geração do objeto telemático -impressão e envelopamento- para posterior entrega.', '', 308),
(4052, 'capitulo', 1, 3745, 2, '2.261', 'Escritório de Consultoria e Negócios em Marketing Direto - ECMKD: unidade dos Correios responsável por desenvolver e estimular o mercado de Marketing Direto, por meio de eventos, palestras e publicações, estimulando o uso das soluções postais para as ações de comunicação dirigida.', '', 309),
(4053, 'capitulo', 1, 3745, 2, '2.262', 'e-SEDEX: serviço de remessa expressa de mercadorias adquiridas por meio do comércio eletrônico.', '', 310),
(4054, 'capitulo', 1, 3745, 2, '2.263', 'Espaço de integração e apoio: é o local da agência composto de banheiros, sala para guarda de material de limpeza, copa, sala de reunião e espaço qualidade de vida.', '', 311),
(4055, 'capitulo', 1, 3745, 2, '2.264', 'Espaço Qualidade de Vida - EQV: É o local destinado a lazer, descanso, leitura e estudo dos empregados lotados nas agências.', '', 312),
(4056, 'capitulo', 1, 3745, 2, '2.265', 'Estampa da máquina de franquear: imagem produzida pela máquina de franquear e impressa nos envelopes e fitas, compreendendo, em conjunto, o carimbo, o selo e a legenda impressos.', '', 313),
(4057, 'capitulo', 1, 3745, 2, '2.266', 'Estorno: cancelamento de uma operação realizada no Banco Postal e em franqueamento em máquina de franquear.', '', 314),
(4058, 'capitulo', 1, 3745, 2, '2.267', 'Estratégia de Presença: é um conjunto de iniciativas que visam integrar a comunicação de uma marca na internet, dando-lhe personalidade, utilizando as ferramentas de interação, a fim de estreitar a relação com o usuário e criar um canal de comunicação bidirecional.', '', 315),
(4059, 'capitulo', 1, 3745, 2, '2.268', 'Etiqueta ou Rótulo de Endereçamento: etiqueta/rótulo afixado em unitizadores com informações referentes a unidade de destino. Nos objetos registrados, as etiquetas contêm os números de registro dos objetos com rastreamento parcial ou total do percurso.', '', 316),
(4060, 'capitulo', 1, 3745, 2, '2.269', 'Exporta Fácil: conjunto de serviços oferecidos pelos Correios que facilita a exportação de mercadorias por empresas e por pessoas físicas, como artesãos, pequenos produtores e agricultores, sendo possível o envio de produtos com ou sem valor comercial - como vendas, amostras e presentes.', '', 317),
(4061, 'capitulo', 1, 3745, 2, '2.270', 'Exporta Fácil Econômico: serviço econômico para envio de mercadorias para o exterior, com prazos de entrega mais estendidos e preços reduzidos, com rastreamento parcial.', '', 318),
(4062, 'capitulo', 1, 3745, 2, '2.271', 'Exporta Fácil Expresso: serviço expresso para envio de mercadorias para o exterior, que tem por principais atributos o prazo de entrega reduzido e rastreamento completo.', '', 319),
(4063, 'capitulo', 1, 3745, 2, '2.272', 'Exporta Fácil Standard: serviço não expresso para envio de mercadorias para o exterior, que concilia prazo de entrega e preço, com rastreamento completo.', '', 320),
(4064, 'capitulo', 1, 3745, 2, '2.273', 'Exporta Fácil +: Solução de logística de exportação para o envio de remessas de grandes volumes, com peso a partir de 30 kg ou com dimensões que extrapolem as dimensões aceitas pelo meio postal, para o exterior.', '', 321),
(4065, 'capitulo', 1, 3745, 2, '2.274', 'Exportação de Malote: operação realizada pelas unidades postais que consiste na leitura e pesagem dos malotes no sistema SIGMA.', '', 322),
(4066, 'capitulo', 1, 3745, 2, '2.275', 'Extensible Markup Language - XML: é um formato para criação de documentos com dados organizados de forma hierárquica.', '', 323),
(4067, 'capitulo', 1, 3745, 2, '2.276', 'Faceamento: ato de posicionar o objeto verticalmente com o endereçamento voltado para frente. Fonte: MANENC 1/1.', '', 324),
(4068, 'capitulo', 1, 3745, 2, '2.277', 'Faixa de volume do Entrega Direta: Refere-se às faixas de preço do serviço Correios Entrega Direta que variam em função do volume postado pelo cliente. As quais se dividem para a:', '', 325),
(4069, 'capitulo', 1, 4068, 4, 'a', 'operação B, em:', 'I - de 2.000 a 20.000 objetos/ano;\nII - acima de 20.000 a 59.999 objetos/ano;\nIII - de 60.000 a 600.000 objetos/ano;\nIV - acima de 600.000 a 1.200.000 objetos/ano;\nV - acima de 1.200.000 a 2.400.000 objetos/ano; ou\nVI - acima de 2.400.000 a 3.600.000 objetos/ano.', 326),
(4070, 'capitulo', 1, 4068, 4, 'b', 'operação A, em:', 'I - acima de 3,6 a 6 milhões de objetos/ano;\nII - de 6 a 12 milhões de objetos/ano;\nIII - de 12 a 24 milhões de objetos/ano;\nIV - de 24 a 48 milhões de objetos/ano;\nV - de 48 a 84 milhões de objetos/ano;\nVI - acima de 84 milhões de objetos/ano.', 327),
(4071, 'capitulo', 1, 3745, 2, '2.278', 'Fale com os Correios: canal de atendimento responsável pela captação de manifestações dos clientes dos Correios pela internet, que podem ser registradas no seguinte endereço: http://apps2.correios.com.br/faleconosco/app/index.php.', '', 328),
(4072, 'capitulo', 1, 3745, 2, '2.279', 'Fale Conosco: sistema utilizado para o registro das Manifestações Gerais e dos Pedidos de Informação apresentados pelos clientes dos Correios, possibilitando o direcionamento automático dos questionamentos para o representante responsável pela resposta.', '', 329),
(4073, 'capitulo', 1, 3745, 2, '2.280', 'Falta ou insuficiência de franqueamento: valor faltante para o correto franqueamento do objeto, de acordo com a modalidade de serviço escolhido pelo remetente, no momento da postagem ou encontrado no destino antes da sua entrega.', '', 330),
(4074, 'capitulo', 1, 3745, 2, '2.281', 'Fatores indicativos de responsabilização: relação de eventos que norteiam a análise de responsabilização ou não do órgão, empregado ou terceiro que concorreu para o pagamento de indenizações.', '', 331),
(4075, 'capitulo', 1, 3745, 2, '2.282', 'Fax Post Nacional: é o serviço de Correio Eletrônico que utiliza equipamento de Fac-Símile para a transmissão de fotos, documentos, mapas, plantas, texto ou qualquer outro tipo de material impresso, escrito ou desenhado, desde que seja flexível.', '', 332),
(4076, 'capitulo', 1, 3745, 2, '2.283', 'Ficha de Intenção de Compra - FIC: formulário que contém as informações de publicações, volume, frequência para fins de definição quanto à faixa de enquadramento em tabela de preços do serviço Correios Entrega Direta.', '', 333),
(4077, 'capitulo', 1, 3745, 2, '2.284', 'Ficha Técnica - FT: é o documento que contém as especificações de uma linha de transporte tais como o itinerário, horários, tempos de parada, tipos de serviços executados, distâncias entre os pontos de parada, tipo e características do meio de transporte a ser usado, frequência da execução do serviço, empresa responsável pela sua execução e outras informações julgadas relevantes. Fonte: MANENC 1/1.', '', 334),
(4078, 'capitulo', 1, 3745, 2, '2.285', 'Fidelizar em Marketing Direto: ação promocional/comercial direcionada a incentivar a fidelidade dos clientes e estreitar o relacionamento, criando facilidades com o propósito de torná-los fiéis, a longo prazo, ao produto, serviço ou marca.', '', 335),
(4079, 'capitulo', 1, 3745, 2, '2.286', 'File Transfer Protocol (Protocolo de Transferência de Arquivos) - FTP: é uma forma de transferir arquivos entre um computador chamado “cliente” e um servidor.', '', 336),
(4080, 'capitulo', 1, 3745, 2, '2.287', 'Firewall: sistema de proteção que isola redes confiáveis e redes perigosas, fazendo um controle de acesso aos recursos disponibilizados.', '', 337),
(4081, 'capitulo', 1, 3745, 2, '2.288', 'Flash: programa desenvolvido pela empresa Macromedia para criação de páginas e ou componentes gráficos e interativos para Web, como por exemplo, imagens e banners.', '', 338),
(4082, 'capitulo', 1, 3745, 2, '2.289', 'Força de Vendas - FV: Conjunto de vendedores responsáveis pelo relacionamento e fornecimento de soluções comerciais às necessidades dos clientes dos Correios. (Gerente de Contas Especiais, Assistentes Comerciais e Agentes de Correios - Atividade Atendente Comercial).', '', 339),
(4083, 'capitulo', 1, 3745, 2, '2.290', 'Formato automatizável: objetos que atendem uma série de características compatíveis com o processo de leitura das máquinas de triagem dos Correios. Essas máquinas possuem leitores óticos de caracteres que fazem uma varredura do bloco de endereços dos objetos postais para seu reconhecimento e impressão do CEP em código de barras.', '', 340),
(4084, 'capitulo', 1, 3745, 2, '2.291', 'Formato Embaraçoso - FE: Objeto com pelo menos uma dimensão superior à correspondente (largura, comprimento ou altura) no formato semi-embaraçoso, cujo peso e/ou volume dificultem o seu tratamento. Fonte: MANENC 1/1.', '', 341),
(4085, 'capitulo', 1, 3745, 2, '2.292', 'Formato Normal ou Formato Padrão - FN: objeto em dimensões não superiores a 240x162x6mm (largura, comprimento, altura). Fonte: MANENC 1/1.', '', 342),
(4086, 'capitulo', 1, 3745, 2, '2.293', 'Formato Semi-Embaraçoso ou Grande Formato - FS: objeto com pelo menos uma dimensão superior à correspondente no formato normal. Dimensões máximas: 355x250x20mm (largura, comprimento, altura). Fonte: MANENC 1/1.', '', 343),
(4087, 'capitulo', 1, 3745, 2, '2.294', 'Fórmula de franqueamento: representação material de pagamento de prestação de um serviço postal.', '', 344),
(4088, 'capitulo', 1, 3745, 2, '2.295', 'Formulário de Discriminação de Conteúdo: formulário utilizado em encomendas postadas com o serviço adicional de Valor Declarado - VD para discriminar os objetos que estão sendo enviados e seus valores, quando o remetente não possui Nota/Cupom Fiscal.', '', 345),
(4089, 'capitulo', 1, 3745, 2, '2.296', 'Formulários Pré-Taxados: é a forma de compra antecipada, pelo cliente, de formulários, para uso em qualquer época.', '', 346),
(4090, 'capitulo', 1, 3745, 2, '2.297', 'Fornecedor: pessoa física ou jurídica que vende produtos ou presta serviços à Empresa, ou mesmo aquelas que cedem seus produtos para venda, em consignação.', '', 347),
(4091, 'capitulo', 1, 3745, 2, '2.298', 'Franqueado: é a pessoa jurídica operadora de Agência de Correios Franqueada - AGF, signatária do Contrato de Franquia Postal com os Correios, submetida aos direitos e obrigações decorrentes da Franquia.', '', 348),
(4092, 'capitulo', 1, 3745, 2, '2.299', 'Franqueador: são os Correios, pessoa jurídica que concede a franquia.', '', 349),
(4093, 'capitulo', 1, 3745, 2, '2.300', 'Franqueamento: valor impresso pela Máquina de Franquear nos objetos de correspondência.', '', 350),
(4094, 'capitulo', 1, 3745, 2, '2.301', 'Franqueamento Autorizado de Cartas - FAC: serviço destinado à Pessoa Jurídica, prestado mediante Contrato, que permite o franqueamento prévio de cartas simples e registradas.', '', 351),
(4095, 'capitulo', 1, 3745, 2, '2.302', 'Franqueamento Postal: pagamento de tarifa e, quando for o caso, do prêmio, relativos a objeto postal. Diz-se também da representação da tarifa.', '', 352),
(4096, 'capitulo', 1, 3745, 2, '2.303', 'Franquia Postal: é:', '', 353),
(4097, 'capitulo', 1, 4096, 4, 'a', 'a execução das atividades auxiliares relativas ao serviço postal, cuja finalidade é verificar sua contribuição para os resultados da Empresa e para a consecução dos objetivos de universalização dos serviços postais por parte dos Correios, observando:', 'I - as diretrizes de qualidade no desempenho de atividades e no trato do cliente;\nII - otimização da rede de atendimento dos Correios;\nIII - a comodidade dos clientes; e\nIV - a avaliação sistêmica e periódica, pelos Correios, do desempenho da Agência de Correios Franqueada - AGF.', 354),
(4098, 'capitulo', 1, 4096, 4, 'b', 'o benefício, assegurado pela legislação postal brasileira ou por convenções internacionais devidamente ratificadas, de isenção do pagamento de preços e prêmios para a utilização dos serviços postais especificados nesses atos, em âmbito interno ou internacional.', '', 355),
(4099, 'capitulo', 1, 3745, 2, '2.304', 'Frequência: são os dias da semana escolhidos pelo cliente para coleta dos malotes no endereço de origem e destino do percurso, em iguais quantidades.', '', 356),
(4100, 'capitulo', 1, 3745, 2, '2.305', 'Fundrasing: termo em inglês que equivale a arrecadação de fundos. Empresas sem fins lucrativos, cuja missão é prestar algum tipo de assistência social, que desenvolvem uma série de atividades e procedimentos para angariar recursos financeiros junto a diversos públicos, de forma a permitir a sustentabilidade dos projetos da organização. Exemplo: Missão Vida, Doutores da Alegria, Pintores com a boca, entre outras.', '', 357),
(4101, 'capitulo', 1, 3745, 2, '2.306', 'Gerência de Atividade de Distribuição de Publicações Periódicos - GDIPE: unidade vinculada à área operacional responsável pela gestão dedicada do serviço Correios Entrega Direta, bem como do Sistema Periódicos - SISPER.', '', 358),
(4102, 'capitulo', 1, 3745, 2, '2.307', 'Gerenciador de Postagens dos Correios - SIGEP WEB: é o sistema que tem o objetivo de preparar e gerenciar as postagens de clientes dos Correios.', '', 359),
(4103, 'capitulo', 1, 3745, 2, '2.308', 'Gestor de Vendas - GV: gestores dos processos de relacionamento e comercialização dos produtos e serviços dos Correios, junto à força de vendas.', '', 360),
(4104, 'capitulo', 1, 3745, 2, '2.309', 'Guias de Expedição: são os instrumentos que disciplinam as trocas de expedições entre as Centralizadoras Nacionais de cada uma das Superintendências Estaduais. Fonte: MANENC 1/1.', '', 361),
(4105, 'capitulo', 1, 3745, 2, '2.310', 'Guichê avançado: é o ponto de atendimento adicional aos licitados, que pode ser instalado para atendimento a: demandas sazonais (feiras e eventos), contingenciais (substituição provisória de unidade de atendimento) ou demandas governamentais.', '', 362),
(4106, 'capitulo', 1, 3745, 2, '2.311', 'Guichê de atendimento: é o ponto de atendimento composto por mobiliário, computador e periféricos especificados nos Guias e Especificações Técnicas da Licitação - AGF, interligados a rede corporativa dos Correios, onde o operador/caixa realiza o lançamento de informações, referente às postagens captadas pelo canal de atendimento e venda de produtos, no sistema de automação da rede de atendimento.', '', 363),
(4107, 'capitulo', 1, 3745, 2, '2.312', 'Guichê de retaguarda: é o ponto de atendimento adicional aos licitados, que pode ser instalado na área operacional da AGF ou em imóvel distinto localizado conforme especificações dispostas no normativo interno.', '', 364),
(4108, 'capitulo', 1, 3745, 2, '2.313', 'Guichês existentes: mobiliário de atendimento existente, na agência e com o mix de equipamentos para a operação de atendimento por parte dos empregados da unidade, ainda que haja algum equipamento em manutenção. Deverão ser considerados como existentes os casos de falta, ou indisponibilidade temporária do mix de equipamentos.', '', 365),
(4109, 'capitulo', 1, 3745, 2, '2.314', 'Guichês ocupados: parcela do mobiliário de atendimento com o mix de equipamentos e disponibilidade de empregado, com ou sem quebra de caixa, para a realização da operação de atendimento no guichê no dia.', '', 366),
(4110, 'capitulo', 1, 3745, 2, '2.315', 'Guichês previstos: mobiliário definido para a unidade segundo a quantidade dimensionada no Sistema de Gestão de Pessoal das Agências - SGPA, observadas as orientações/restrições da engenharia e/ou da Área de Canais.', '', 367),
(4111, 'capitulo', 1, 3745, 2, '2.316', 'Hall de atendimento da Agência do Banco Postal: espaço físico no interior das Agências do Banco Postal destinado à circulação e atendimento aos clientes.', '', 368),
(4112, 'capitulo', 1, 3745, 2, '2.317', 'Higienização de Mailing: consiste em eliminar dados inválidos/inexistentes da sua base de dados, de modo a evitar o tráfego de dados/objetos desnecessários, otimizando o retorno de uma mala direta, por exemplo, bem com reduzindo custos para o remetente e operador.', '', 369),
(4113, 'capitulo', 1, 3745, 2, '2.318', 'Hipermídia: é a reunião de várias mídias num suporte computacional, suportado por sistemas eletrônicos de comunicação.', '', 370),
(4114, 'capitulo', 1, 3745, 2, '2.319', 'Homologação de solução de franqueamento: conjunto de testes e avaliações aplicados às novas soluções de franqueamento pelas diversas áreas dos Correios responsáveis pelas atividades de homologação, com objetivo de verificar se a solução de franqueamento atende aos requisitos definidos pelos Correios.', '', 371),
(4115, 'capitulo', 1, 3745, 2, '2.320', 'Homologação Operacional da solução de franqueamento: é a aprovação da solução apresentada pelo fornecedor, mediante aplicação de testes operacionais que validarão as funcionalidades e a integração da solução com os sistemas especificados pelos Correios.', '', 372),
(4116, 'capitulo', 1, 3745, 2, '2.321', 'Homologação Técnica da solução de franqueamento: é a aprovação da solução apresentada pelo fornecedor, mediante aplicação de testes que avaliarão a sua capacidade de resposta, considerando a especificação técnica apresentada pelo fabricante e os critérios definidos pelos Correios.', '', 373),
(4117, 'capitulo', 1, 3745, 2, '2.322', 'Horário Limite de Postagem: horário máximo permitido pelas unidades de tratamento para recebimento de carga das unidades centralizadoras, de forma a viabilizar o tratamento e o encaminhamento dos objetos no mesmo dia, em função da malha de transporte. Fonte: MANENC 1/1.', '', 374),
(4118, 'capitulo', 1, 3745, 2, '2.323', 'HyperText Markup Language (Linguagem de Marcação de Hipertexto) - HTML: é uma linguagem de marcação utilizada para produzir páginas na Web.', '', 375),
(4119, 'capitulo', 1, 3745, 2, '2.324', 'Imóvel distinto: é aquele não integrante da proposta apresentada na licitação para a instalação da AGF.', '', 376),
(4120, 'capitulo', 1, 3745, 2, '2.325', 'Importação de Malote: Operação realizada pelas unidades operacionais que consiste na leitura de todos os malotes recebidos (importados) no sistema SIGMA para emissão de LEM e gestão das não conformidades.', '', 377),
(4121, 'capitulo', 1, 3745, 2, '2.326', 'Importação provisória de máquina de franquear digital: modalidade utilizada quando da importação de máquinas de franquear por período pré-estabelecido, observados os prazos definidos pelos Correios. Nessa condição se enquadram as importações de caráter comercial envolvendo testes para homologação de novas soluções de franqueamento, participação em feiras e demonstrações de produto. Vide legislação da Secretaria da Receita Federal.', '', 378),
(4122, 'capitulo', 1, 3745, 2, '2.327', 'Imposto sobre a Propriedade Territorial Rural - ITR: imposto sobre a propriedade, o domínio útil ou a posse (inclusive por usufruto) de imóvel por natureza, localizado fora da zona urbana do município, em 1º de janeiro de cada ano.', '', 379),
(4123, 'capitulo', 1, 3745, 2, '2.328', 'Impressão não postal: é a ilustração e/ou dizeres aplicados no objeto postal mediante processo gráfico.', '', 380),
(4124, 'capitulo', 1, 3745, 2, '2.329', 'Impresso: reprodução obtida sobre material de uso corrente na imprensa, editado em vários exemplares idênticos, de acordo com a Lei Postal - n.º 538/78. Para efeitos postais, é ainda o objeto de cunho informativo com ou sem apelo publicitário.', '', 381),
(4125, 'capitulo', 1, 3745, 2, '2.330', 'Impresso Especial - IE: objeto obtido por meio de impressão gráfica, em vários exemplares idênticos, constituído de uma ou mais folhas, contendo anúncios, matérias pagas, matérias especiais e similares, destinado a promover a divulgação e o desenvolvimento das vendas de um determinado produto ou serviço, a prestar informações, a divulgar eventos culturais, políticos, religiosos, esportivos e assemelhados.', '', 382),
(4126, 'capitulo', 1, 3745, 2, '2.331', 'Impresso Normal: serviço de envio e distribuição de pequenas quantidades, avulsas (a partir de um objeto), de peças exclusivamente promocionais, personalizadas ou não, com pagamento à vista, sem necessidade de contrato, disponível em todas as Agências de Correios.', '', 383),
(4127, 'capitulo', 1, 3745, 2, '2.332', 'Impresso Urgente: impresso postado com preço superior para lhe garantir a remessa urgente, com tarifa igual aos objetos urgentes.', '', 384),
(4128, 'capitulo', 1, 3745, 2, '2.333', 'Indenização: procedimento de restituição, no todo ou em parte, dos preços postais, acrescido do valor correspondente ao seguro automático ou valor declarado em decorrência de inconformidades que comprometam a integridade do conteúdo do objeto, como avaria, espoliação, extravio, devolução ou entrega indevida, roubo, etc. É efetuado de ofício ou a pedido do remetente ou do destinatário, nas situações de comprovação, após consulta no SRO e apuração da reclamação realizada pelas unidades diretamente envolvidas no fluxo postal.', '', 385),
(4129, 'capitulo', 1, 3745, 2, '2.334', 'Indenização Automática: cobertura financeira em valor previamente definido e constante nas tabelas de preços dos serviços, para os casos de extravio ou avaria.', '', 386),
(4130, 'capitulo', 1, 3745, 2, '2.335', 'Indenização de Ofício de Objeto Registrado Nacional: é o procedimento de compensação financeira ao cliente decorrente de erros ou inconformidades na prestação do serviço. É efetuado, por iniciativa dos Correios, autorizado pelo órgão responsável pela apuração das irregularidades, mesmo sem a solicitação do remetente ou do destinatário, nas seguintes situações:', '', 387),
(4131, 'capitulo', 1, 4130, 4, 'a', 'extravio: quando, após a informação de postagem, não consta, no SRO, informação de entrega após o prazo previsto para o objeto e é possível identificar o remetente;', '', 388),
(4132, 'capitulo', 1, 4130, 4, 'b', 'telegrama com vícios ortográficos: quando é constatada, pela CAC, a ocorrência de erros ortográficos que descaracterizam a mensagem captada pelo canal de atendimento ou causam constrangimento ao remetente;', '', 389),
(4133, 'capitulo', 1, 4130, 4, 'c', 'irregularidade operacional: quando, durante os procedimentos de encaminhamento, tratamento e entrega do objeto postal registrado, é constatada a ocorrência de irregularidade operacional (atraso na entrega, avaria, espoliação, furto) na prestação do serviço.', '', 390),
(4134, 'capitulo', 1, 3745, 2, '2.336', 'Indenização Excepcional de Objeto Registrado Nacional: é o procedimento de compensação financeira ao cliente decorrente de erros ou inconformidades na prestação do serviço, quando não se tratar de objetos indenizáveis. É efetuado a pedido do remetente ou do destinatário, nas situações que não se enquadram na indenização pedida, desde que observados os seguintes aspectos:', '', 391);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(4135, 'capitulo', 1, 4134, 4, 'a', 'deverá ser solicitada pela SE do remetente, se o objeto ainda não tiver sido entregue, ou do destinatário, caso a entrega tenha ocorrido;', '', 392),
(4136, 'capitulo', 1, 4134, 4, 'b', 'deverá ser acompanhada de justificativa para o pedido de excepcionalidade, fundamentada em aspectos comerciais, operacionais, institucionais e jurídicos;', '', 393),
(4137, 'capitulo', 1, 4134, 4, 'c', 'o pedido de indenização excepcional deverá ser encaminhado à Ouvidoria, que poderá autorizar o pagamento, após a análise de procedência da reclamação.', '', 394),
(4138, 'capitulo', 1, 3745, 2, '2.337', 'Indenização não prevista: os Correios não efetuam o pagamento de indenização, conforme as situações descritas:', '', 395),
(4139, 'capitulo', 1, 4138, 4, 'a', 'objeto simples: sempre que o objeto é postado sem registro (carta simples, carta social, impresso)', '', 396),
(4140, 'capitulo', 1, 4138, 4, 'b', 'erro de endereçamento: quando o objeto registrado apresenta endereçamento incorreto ou insuficiente;', '', 397),
(4141, 'capitulo', 1, 4138, 4, 'c', 'valor sem declaração: quando ocorre a inclusão de valor sem a correspondente declaração e sem o respectivo pagamento;', '', 398),
(4142, 'capitulo', 1, 4138, 4, 'd', 'retenção por autoridade competente: quando ocorre a retenção por autoridade alfandegária ou policial de âmbito Federal ou Estadual (Polícia Federal, Receita Federal, Ministério da Agricultura, Receitas Estaduais, Secretarias Estaduais de Agricultura) que possui competência legal para reter o objeto registrado e, dessa forma, faz cessar a expectativa de prazo de entrega anteriormente prevista para o objeto. A entrega do objeto é feita pelo órgão responsável pela retenção;', '', 399),
(4143, 'capitulo', 1, 4138, 4, 'e', 'prejuízos indiretos e benefícios não realizados: quando a ocorrência de eventuais irregularidades poderia acarretar prejuízos ou benefícios não conquistados que apenas supostamente poderiam estar correlacionados às irregularidades verificadas;', '', 400),
(4144, 'capitulo', 1, 4138, 4, 'f', 'força maior: situação em que, apesar dos cuidados e procedimentos de segurança observados no âmbito dos Correios, acontecem inconformidades causadas por fatores externos que interferem nas condições de entrega pela empresa, tais como fechamento de aeroportos, enchentes, incêndios, deslizamentos de terra e queda de pontes que afetam as condições de entrega previstas na prestação do serviço.', '', 401),
(4145, 'capitulo', 1, 3745, 2, '2.338', 'Indenização por decurso de prazo: é o procedimento de baixa de PI decorrente do não cumprimento dos prazos de resposta ao cliente e consequente pagamento de indenização com imputação de responsabilidade ao empregado/unidade que deu causa à perda do prazo de resposta.', '', 402),
(4146, 'capitulo', 1, 3745, 2, '2.339', 'Indenização Pedida de Objeto Registrado Nacional: é o procedimento de compensação financeira ao cliente decorrente de erros ou inconformidades na prestação do serviço. É efetuado, a pedido do remetente ou do destinatário, nas situações de comprovação, após consulta no SRO, nos casos abaixo:', '', 403),
(4147, 'capitulo', 1, 4146, 4, 'a', 'atraso na entrega: situação em que o objeto, segundo informação do SRO, tem sua primeira tentativa de entrega realizada fora do prazo previsto conforme a modalidade do serviço;', '', 404),
(4148, 'capitulo', 1, 4146, 4, 'b', 'avaria: quando, no momento da entrega ao destinatário ou devolução ao remetente, o objeto apresenta comprometimento parcial ou total do seu conteúdo, podendo ser aceito ou recusado no ato do recebimento;', '', 405),
(4149, 'capitulo', 1, 4146, 4, 'c', 'devolução indevida: situação em que o objeto é devolvido ao remetente sem que haja, documentadas no SRO, as tentativas de entrega previstas;', '', 406),
(4150, 'capitulo', 1, 4146, 4, 'd', 'entrega indevida: quando o objeto é entregue em local diferente do constante no endereçamento ou a destinatário indevido e necessita ser devolvido ao carteiro para possibilitar a entrega correta;', '', 407),
(4151, 'capitulo', 1, 4146, 4, 'e', 'espoliação: quando, no momento da entrega ao destinatário ou devolução ao remetente, o objeto apresenta retirada de todo ou parte do conteúdo, ocasião em que deverão ser lavrados os documentos necessários para registro da não conformidade e posterior notificação aos canais de relacionamento;', '', 408),
(4152, 'capitulo', 1, 4146, 4, 'f', 'extravio: quando, após a informação de postagem do objeto, não consta, no SRO, informação de entrega após o prazo previsto de entrega do objeto;', '', 409),
(4153, 'capitulo', 1, 4146, 4, 'g', 'entrega de telegrama após o prazo previsto: quando, de acordo com o SRO, o telegrama não foi entregue no prazo previsto;', '', 410),
(4154, 'capitulo', 1, 4146, 4, 'h', 'não entrega de telegrama: quando o SRO não registra a data de entrega do telegrama ao destinatário;', '', 411),
(4155, 'capitulo', 1, 4146, 4, 'i', 'prestação indevida de serviços adicionais: quando é constatada a prestação indevida de quaisquer serviços adicionais, como a não entrega de AR;', '', 412),
(4156, 'capitulo', 1, 4146, 4, 'j', 'não pagamento de Vale Postal: quando, terminado o prazo previsto para o respectivo pagamento, constata-se que o Vale Postal não foi pago devido a erro operacional (não envio de Aviso de Chegada);', '', 413),
(4157, 'capitulo', 1, 4146, 4, 'k', 'roubo: situação onde o objeto postal é subtraído em decorrência de assalto a carteiro, unidade ou veículo dos Correios caracterizando delito externo;', '', 414),
(4158, 'capitulo', 1, 4146, 4, 'l', 'telegrama com vícios: quando, apesar da entrega no prazo, o telegrama apresenta erros de conteúdo com relação às normas gramaticais vigentes ou com a mensagem transmitida pelo remetente.', '', 415),
(4159, 'capitulo', 1, 3745, 2, '2.340', 'Índice Geral de Preços de Mercado - IGP-M: um dos índices de correção de valores utilizados pelos Correios para reajuste de preços.', '', 416),
(4160, 'capitulo', 1, 3745, 2, '2.341', 'Informação de Celebração e/ou Alteração de Contrato - ICC e/ou IACC: formulário específico do serviço Correios Entrega Direta por meio do qual as etapas do processo de venda, cadastro contratual e cadastros de unidades e tabelas de preços são ativadas no Sistema Periódicos.', '', 417),
(4161, 'capitulo', 1, 3745, 2, '2.342', 'Informações com vestígios: são aquelas cuja ocorrência fica formalmente registrada em algum documento ou sistema, possibilitando consulta posterior.', '', 418),
(4162, 'capitulo', 1, 3745, 2, '2.343', 'Informações complementares periódicas: informações operacionais da agência que não são captadas pelo sistema de forma automática.', '', 419),
(4163, 'capitulo', 1, 3745, 2, '2.344', 'Informações Sem vestígios: são aquelas cuja ocorrência não deixa registro anotado em algum formulário.', '', 420),
(4164, 'capitulo', 1, 3745, 2, '2.345', 'Infraestrutura de Chaves Públicas Brasileira - ICP-Brasil: é uma cadeia hierárquica e de confiança que viabiliza a emissão de certificados digitais para identificação do cidadão quando transacionando no meio virtual, como a internet.', '', 421),
(4165, 'capitulo', 1, 3745, 2, '2.346', 'Instrumento de Habilitação de Postagem - IHP: formulário que permite que o remetente realize a postagem de objetos em uma Agência de Correios Própria, por meio do serviço de Logística Reversa.', '', 422),
(4166, 'capitulo', 1, 3745, 2, '2.347', 'Internauta típico: visitante de sites de lojas virtuais, que não tem hábito, estímulo ou confiança de realizar compras virtuais.', '', 423),
(4167, 'capitulo', 1, 3745, 2, '2.348', 'Irregularidades em objetos FAC: identificadas quando da leitura ótica do código de barras CIF dos objetos que compõem a amostra, em comparação com as informações constantes no Relatório de Postagem Eletrônico:', '', 424),
(4168, 'capitulo', 1, 4167, 4, 'a', 'não existe lote de postagem para o objeto;', '', 425),
(4169, 'capitulo', 1, 4167, 4, 'b', 'objeto não encontrado no arquivo de postagem;', '', 426),
(4170, 'capitulo', 1, 4167, 4, 'c', 'objeto com peso real superior ao indicado no arquivo de postagem, desde que ultrapasse a faixa tarifária de peso correspondente;', '', 427),
(4171, 'capitulo', 1, 4167, 4, 'd', 'objeto duplicado na amostra;', '', 428),
(4172, 'capitulo', 1, 4167, 4, 'e', 'CEP de destino indicado no objeto, diferente do âmbito da entrega (1 Local; 2 Estadual; 3 Nacional).', '', 429),
(4173, 'capitulo', 1, 3745, 2, '2.349', 'Jornais segmentados: publicação periódica constituída por uma série de folhas grandes de papel, dobradas em caderno, onde foram impressas notícias, reportagens, crônicas, entrevistas, anúncios e outro tipo de informação de interesse público, destinado a um grupo de pessoas.', '', 430),
(4174, 'capitulo', 1, 3745, 2, '2.350', 'Lacres Plásticos de Segurança: produto adquirido no mercado pelo cliente para uso no fechamento do malote visando proporcionar maior segurança e inviolabilidade ao conteúdo.', '', 431),
(4175, 'capitulo', 1, 3745, 2, '2.351', 'Leiaute para fins de classificação postal: compreende avaliar a disposição das chancelas, o bloco de endereçamento do destinatário, bem como do remetente. E, quando for o caso, quadrícula de motivos de devolução, dimensões admitidas, menções de fechamento autorizado.', '', 432),
(4176, 'capitulo', 1, 3745, 2, '2.352', 'Limite de Carga da máquina de franquear: é o maior valor de saldo (registrador descendente) permitido por máquina, que corresponde ao valor apurado como limite de crédito, divido pelo número de máquinas existentes na agência.', '', 433),
(4177, 'capitulo', 1, 3745, 2, '2.353', 'Limite de Crédito da unidade: é o limite quinzenal máximo de crédito concedido a uma Agência, calculado com base na média do movimento de selos estampados verificados nas últimas seis quinzenas.', '', 434),
(4178, 'capitulo', 1, 3745, 2, '2.354', 'Limite Inferior: é a primeira faixa de pontuação do Critério 2 da Ficha de Avaliação Técnica do Edital de Licitação (varia em 4, 10 ou 20 pontos) relativa ao espaço físico de cada modelo de agência (A1 e A2), considerando o quantitativo de Guichês de Atendimento.', '', 435),
(4179, 'capitulo', 1, 3745, 2, '2.355', 'Linguagem Cifrada: é aquela em que a mensagem é entendida apenas pelo remetente (expedidor) e destinatário, sendo usadas, no texto e/ou assinatura, palavras artificiais ou reais, entretanto sem possuir os significados que lhes são atribuídos, normalmente, no idioma a que pertencem, bem como símbolos, em forma de código, constituídos por caracteres isolados ou em grupos convencionados entre correspondentes.', '', 436),
(4180, 'capitulo', 1, 3745, 2, '2.356', 'Linguagem Corrente: é aquela em cuja mensagem as palavras, algarismos, sinais e expressões empregadas na redação do texto e na assinatura têm o significado que, normalmente, lhes é atribuído, no idioma a que pertencem.', '', 437),
(4181, 'capitulo', 1, 3745, 2, '2.357', 'Linhas de Crédito: relação das modalidades e espécies de créditos disponibilizados aos tomadores/clientes.', '', 438),
(4182, 'capitulo', 1, 3745, 2, '2.358', 'Linha Tronco Nacional - LTN: linha de transporte de carga entre regionais, por via de superfície.', '', 439),
(4183, 'capitulo', 1, 3745, 2, '2.359', 'Link: é uma palavra, texto, expressão ou imagem que permite o acesso imediato à outra parte de um mesmo, ou outro documento ou site, bastando ser acionado pelo ponteiro do mouse.', '', 440),
(4184, 'capitulo', 1, 3745, 2, '2.360', 'Lista de Coleta de Malote - LCM: lista de coleta emitida diariamente pelas unidades operacionais com a relação de malotes a serem coletados, por ordem de endereços roteirizados.', '', 441),
(4185, 'capitulo', 1, 3745, 2, '2.361', 'Lista de Distribuição Interna - LDI: é a lista que relaciona os números de registro dos objetos de distribuição interna, retirados pelo cliente nas agências ou unidades distribuidoras.', '', 442),
(4186, 'capitulo', 1, 3745, 2, '2.362', 'Lista de Entrega de Malote - LEM: lista de entrega emitida diariamente pelas unidades operacionais com a relação de malotes lidos na operação de importação, por ordem de endereços roteirizados.', '', 443),
(4187, 'capitulo', 1, 3745, 2, '2.363', 'Lista de Objetos Entregues pelo Carteiro - LOEC: é a lista que relaciona os números de registro dos objetos de distribuição externa, entregues pelo carteiro no endereço do destinatário.', '', 444),
(4188, 'capitulo', 1, 3745, 2, '2.364', 'Listas Telefônicas: lista sumária de endereços e telefones de pessoas ou de estabelecimentos comerciais emitidas dentro de certa periodicidade.', '', 445),
(4189, 'capitulo', 1, 3745, 2, '2.365', 'Litígio de contestação de transferência intercompany: situações onde não há consenso quanto à responsabilidade das regionais envolvidas no fluxo do objeto indenizado.', '', 446),
(4190, 'capitulo', 1, 3745, 2, '2.366', 'Locais de Recebimento e Tratamento: unidades operacionais responsáveis pelo recebimento/coleta dos objetos franqueados pelas Máquinas de Franquear.', '', 447),
(4191, 'capitulo', 1, 3745, 2, '2.367', 'Localização da Ocorrência: procedimento de definição automática e manual das regionais/unidades que deram causa ao pagamento de indenização.', '', 448),
(4192, 'capitulo', 1, 3745, 2, '2.368', 'Logística Reversa - LR: processo logístico reverso onde o cliente de contrato autoriza o seu cliente a realizar a postagem de um objeto, de pós-venda ou pós-consumo, sem ônus, seja através de uma agência ou através de uma coleta. O serviço possui 4 modalidades: LRD, LRA, LRSD e LRSA.', '', 449),
(4193, 'capitulo', 1, 3745, 2, '2.369', 'Logística Reversa Domiciliar - LRD: processo logístico reverso, realizado no endereço do consumidor final, que consiste na coleta domiciliar do produto de retorno.', '', 450),
(4194, 'capitulo', 1, 3745, 2, '2.370', 'Loja hospedada: serviço de hospedagem de loja virtual dos Correios destinado a varejistas que desejam iniciar sua operação na internet. Utilizando a estrutura tecnológica fornecida pelo CorreiosNet Shopping para montagem e operacionalização de loja virtual. Disponibilizando diversas formas de pagamento, carrinho de compras e quantidade ilimitada de produtos cadastrados.', '', 451),
(4195, 'capitulo', 1, 3745, 2, '2.371', 'Loja hospedada Cooperativa: é o mesmo serviço de hospedagem de loja virtual, destinado às associações, cooperativas e Arranjos Produtos Locais do Sebrae que desejam iniciar suas operações na internet.', '', 452),
(4196, 'capitulo', 1, 3745, 2, '2.372', 'Loja vinculada: serviço de visibilidade para lojistas do varejo virtual que já operam no comércio eletrônico utilizando outras soluções de comércio eletrônico. Para esses clientes oferecemos visibilidade no CorreiosNet Shopping, ampliando assim a credibilidade da loja virtual, por meio da vinculação com a marca forte dos Correios.', '', 453),
(4197, 'capitulo', 1, 3745, 2, '2.373', 'Loja vinculada Âncora: é o mesmo serviço de vínculo de loja virtual, destinado aos clientes corporativos do serviço e-SEDEX de renome nacional no comércio eletrônico.', '', 454),
(4198, 'capitulo', 1, 3745, 2, '2.374', 'Loja Virtual: página na internet com um software de gerenciamento de pedidos (carrinho de compras) na qual empresas oferecem e vendem seus produtos. Os clientes acessam o site, escolhem os produtos para aquisição e recebem estes produtos em casa.', '', 455),
(4199, 'capitulo', 1, 3745, 2, '2.375', 'Lote de objetos FAC: Conjunto de objetos postais apresentados para postagem única ou parcelada, com as seguintes características:', '', 456),
(4200, 'capitulo', 1, 4199, 4, 'a', 'os números dos lotes devem seguir uma numeração sequencial, iniciando-se em 00001 a cada ciclo de postagem (semestre);', '', 457),
(4201, 'capitulo', 1, 4199, 4, 'b', 'é vedada a repetição do número do lote dentro de um mesmo ciclo de postagem;', '', 458),
(4202, 'capitulo', 1, 4199, 4, 'c', 'o número sequencial do objeto deve iniciar em 00000000001 para cada lote;', '', 459),
(4203, 'capitulo', 1, 4199, 4, 'd', 'quando se tratar de carga parcelada, todas as parcelas constituirão um único lote. As parcelas devem apresentar numeração única de lote, sequencial de parcelas e sequencial de objetos;', '', 460),
(4204, 'capitulo', 1, 4199, 4, 'e', 'cada lote, ou parcela deste, quando da postagem, deve ser acompanhado de um Relatório de Postagem Eletrônico e respectivo resumo impresso;', '', 461),
(4205, 'capitulo', 1, 4199, 4, 'f', 'pode haver em cada mídia mais de um arquivo. Cada arquivo deve corresponder a um lote, ou parcela, no caso de carga parcelada.', '', 462),
(4206, 'capitulo', 1, 4199, 3, '2.375.1', 'A carga deve ser apresentada para postagem separada em três lotes, por âmbito de entrega: local, estadual e nacional. Os objetos FAC Simples e FAC Registrado devem ser postados em lotes distintos.', '', 463),
(4207, 'capitulo', 1, 3745, 2, '2.376', 'Mailing: termo em inglês (abreviação de Mailing List) que equivale a banco de dados (nome, endereços, características do consumidor, entre outros) para serem utilizados em marketing direto, tais como mala direta, telemarketing e correio eletrônico, entre outras.', '', 464),
(4208, 'capitulo', 1, 3745, 2, '2.377', 'Mala Direta: é uma mensagem publicitária, com apelo promocional ou meramente informativa (propaganda), com o objetivo de venda, divulgação, informação, prospecção e/ou fidelização, encaminhada ao público interessado ou com potencial para resposta, a qual pode ser emitida em vários exemplares idênticos ou personalizados, com ou sem indicação de endereço do destinatário.', '', 465),
(4209, 'capitulo', 1, 3745, 2, '2.378', 'Mala Direta Postal - MDP: é o serviço de envio e distribuição em grande quantidade de peças exclusivamente promocionais, endereçadas, personalizadas ou não, que requer investimento mensal de valor fixo, atualmente em R$ 3.500,00/mês, segundo a tarifa comercial dos Correios, contempla o pagamento a faturar, por meio de contrato.', '', 466),
(4210, 'capitulo', 1, 3745, 2, '2.379', 'Mala Direta Postal Domiciliária - MDPD: é o serviço de envio e distribuição de peças exclusivamente promocionais, não endereçadas, de até 300g, com pagamento a faturar ou à vista, por meio de contrato.', '', 467),
(4211, 'capitulo', 1, 3745, 2, '2.380', 'Mala Direta Postal Urgente - MDPU: é o serviço de Mala Direta Postal, postado com preço superior para lhe garantir a remessa urgente, com tarifa igual aos objetos urgentes', '', 468),
(4212, 'capitulo', 1, 3745, 2, '2.381', 'Mala M: remessa internacional destinada ao envio de impressos de um único remetente, endereçados a um só destinatário.', '', 469),
(4213, 'capitulo', 1, 3745, 2, '2.382', 'Malote: designa a embalagem física usada no acondicionamento dos objetos.', '', 470),
(4214, 'capitulo', 1, 3745, 2, '2.383', 'Malote Correios: é a marca registrada ou denominação comercial do serviço de correspondência agrupada adotada pelos Correios e usada na comercialização do serviço.', '', 471),
(4215, 'capitulo', 1, 3745, 2, '2.384', 'Malote Web: ferramenta disponibilizada exclusivamente para os clientes do serviço Malote Correios na internet, no endereço www.correios.com.br/malote. Com acesso por meio de senha, permite ao cliente consultar a situação do malote, solicitar novos percursos, alterar percursos existentes, acompanhar as solicitações, obter a 2ª via da fatura e outras informações relativas à operacionalização do serviço.', '', 472),
(4216, 'capitulo', 1, 3745, 2, '2.385', 'Mandato de Curatela: é o encargo conferido por lei a alguém, para reger a pessoa e os bens, ou somente os bens, de pessoas menores, ou maiores, que por si não podem fazer, ou por ainda não terem nascido.', '', 473),
(4217, 'capitulo', 1, 3745, 2, '2.386', 'Mandato de Tutela: autorização dada por Juiz a outrem para que exerça o poder familiar sempre que os pais estiverem ausentes ou incapacitados de fazê-lo.', '', 474),
(4218, 'capitulo', 1, 3745, 2, '2.387', 'Manifestação Genérica - MG: é o procedimento formal de registro, em formulário eletrônico específico com número de protocolo individual, de elogios, críticas, reclamações, dúvidas ou sugestões sobre os produtos e serviços da empresa, desde que não se refiram a objetos registrados.', '', 475),
(4219, 'capitulo', 1, 3745, 2, '2.388', 'Manifesto de Irregularidade - MI - Consiste no registro de não conformidade na operação do malote no SIGMA, podendo ser extravio, lacre rompido, encaminhamento errado, etc., gerando uma mensagem automática para a unidade operacional reportar ao cliente, quando for o caso.', '', 476),
(4220, 'capitulo', 1, 3745, 2, '2.389', 'Mão Própria - MP: Serviço pelo qual o remetente recebe a garantia de que o objeto, por ele postado sob registro, será entregue, exclusivamente, ao destinatário.', '', 477),
(4221, 'capitulo', 1, 3745, 2, '2.390', 'Máquina de Franquear - MF: é o equipamento básico do sistema, instalado em unidades de atendimento próprias e terceirizadas e em estabelecimentos de terceiros, cuja função lógica é a de impressão de selos estampados em correspondências, realizando o registro dos franqueamentos efetuados. É composto, por base e medidor, possuindo as seguintes características:', '', 478),
(4222, 'capitulo', 1, 4221, 4, 'a', 'impressão de estampa única contendo identificação do nº da máquina, unidade de postagem, sequência de impressão, registrador ascendente, registrador descendente, data, DH automático, programado pelo horário limite de postagem;', '', 479),
(4223, 'capitulo', 1, 4221, 4, 'b', 'impressão por processo digital (jato-de-tinta, laser, transferência térmica, etc.);', '', 480),
(4224, 'capitulo', 1, 4221, 4, 'c', 'controle de registradores ascendente/descendente;', '', 481),
(4225, 'capitulo', 1, 4221, 4, 'd', 'contabilização por conta de operador/supervisor; e', '', 482),
(4226, 'capitulo', 1, 4221, 4, 'e', 'sistema de carga remota, via modem.', '', 483),
(4227, 'capitulo', 1, 3745, 2, '2.391', 'Marketing Direto: é o segmento de negócios dos Correios que concentra os serviços de comunicação dirigida de caráter publicitário, promocional e/ou informacional, conforme normas de classificação de objetos dos Correios.', '', 484),
(4228, 'capitulo', 1, 3745, 2, '2.392', 'Matriz de Risco das Regionais: composta pela Taxa de Risco da Regional - TRR e pelo Percentual de Participação na Despesa - PPD, a Matriz de Risco das Regionais é utilizada no processo de transferência intercompany com o objetivo de distribuir, de forma equalizada, o ônus de despesas com indenizações pagas, exclusivamente, por motivo de extravio, nas situações em que não é possível definir a responsabilidade das regionais envolvidas.', '', 485),
(4229, 'capitulo', 1, 3745, 2, '2.393', 'Medidor da máquina de franquear: é um componente da Máquina de Franquear que permite a carga somente por processo remoto, via modem. Armazena e gerencia créditos, controlando o uso da postagem. É o mecanismo de registro das operações da Máquina de Franquear.', '', 486),
(4230, 'capitulo', 1, 3745, 2, '2.394', 'Mensagem: é o segmento de negócios dos Correios que concentra os serviços de comunicação dirigida de caráter pessoal e de interesse específico do destinatário.', '', 487),
(4231, 'capitulo', 1, 3745, 2, '2.395', 'Mensagem de Alteração de Percurso - MAP: mensagem automática gerada pelo SIGMA, enviada diretamente para a unidade responsável pela ação de alteração, cancelamento ou suspensão, pedido de novos malotes, distritamento etc., para as providências dentro de prazo previamente definido.', '', 488),
(4232, 'capitulo', 1, 3745, 2, '2.396', 'Mídia Eletrônica: conjunto de meios de comunicação que necessita de recursos eletrônicos ou eletromecânicos para que o usuário final tenha acesso ao conteúdo.', '', 489),
(4233, 'capitulo', 1, 3745, 2, '2.397', 'Mídia Postal: é o termo utilizado para definir no mercado de marketing direto as soluções postais para comunicação dirigida e envios de materiais diversos.', '', 490),
(4234, 'capitulo', 1, 3745, 2, '2.398', 'Modalidades de Pagamento de Indenizações; o pagamento de indenizações de objetos postais registrados poderá ser feito por meio de conta corrente, conta poupança, conta conjunta ou conta salário, Vale Postal Nacional Eletrônico - VPNE, Guia de Recolhimento Único - GRU e crédito em fatura.', '', 491),
(4235, 'capitulo', 1, 4234, 3, '2.398.1', 'As definições e regras de uso de cada uma das modalidades de pagamento apresentadas são de competência da área financeira dos Correios.', '', 492),
(4236, 'capitulo', 1, 3745, 2, '2.399', 'Monopólio postal: concessão prevista na Constituição Federal que autoriza os Correios a prestar serviços postais, de telegrama e de correspondência agrupada com exclusividade.', '', 493),
(4237, 'capitulo', 1, 3745, 2, '2.400', 'Navegação: é a ação de percorrer as páginas de um site para localizar informações, produtos ou serviços.', '', 494),
(4238, 'capitulo', 1, 3745, 2, '2.401', 'Nota Fiscal - NF: é um documento autorizado e controlado pelo Estado ou pelo Município de emissão obrigatória quando das vendas de mercadoria ou da prestação de serviços, devendo ser preenchidos pelos comerciantes, industriais ou prestadores de serviços pelo valor correto da operação.', '', 495),
(4239, 'capitulo', 1, 3745, 2, '2.402', 'Notificação de Pagamento - NP: consiste no pagamento ao remetente do valor recebido do destinatário, referente a um objeto de Reembolso Postal postado e entregue pelos Correios.', '', 496),
(4240, 'capitulo', 1, 3745, 2, '2.403', 'Notificação de Trânsito - NIT: a Notificação de Autuação de Infração de Trânsito é o documento que informa ao proprietário que o seu veículo foi autuado, ou seja, que foi registrada uma infração de trânsito com o seu veículo.', '', 497),
(4241, 'capitulo', 1, 3745, 2, '2.404', 'Novos internautas: incluídos pelas soluções CorreiosNet.', '', 498),
(4242, 'capitulo', 1, 3745, 2, '2.405', 'Número do Cadastro Geral - AN8: código numérico que designa o registro de pessoas físicas e jurídicas (empregados, fornecedores, clientes, terceiros etc.) no ERP.', '', 499),
(4243, 'capitulo', 1, 3745, 2, '2.406', 'Número de Matrícula de máquina de franquear: é um número de registro da Máquina de Franquear junto aos Correios.', '', 500),
(4244, 'capitulo', 1, 3745, 2, '2.407', 'Objeto Postal: qualquer objeto de correspondência, valor ou encomenda encaminhado por via postal.', '', 501),
(4245, 'capitulo', 1, 3745, 2, '2.408', 'Objeto Simples - LC: objeto sem número de registro. Fonte: MANENC 1/1.', '', 502),
(4246, 'capitulo', 1, 3745, 2, '2.409', 'Objeto Telemático: é a mensagem apresentada nas unidades de atendimento através de telefone, da internet ou de equipamentos fac-símile e transmitida por meio eletroeletrônico.', '', 503),
(4247, 'capitulo', 1, 3745, 2, '2.410', 'Objetos de Correspondência: são objetos do tipo: carta, cartão-postal, impresso, cecograma ou pequena encomenda.', '', 504),
(4248, 'capitulo', 1, 3745, 2, '2.411', 'Objetos postados sob registro - FR: sigla identificadora dos objetos postados sob registro, com ou sem AR Convencional/Digital, que deve acompanhar o número individual de registro dos objetos no Relatório de Postagem Eletrônico.', '', 505),
(4249, 'capitulo', 1, 3745, 2, '2.412', 'Operação A: segmentação específica do serviço Correios Entrega Direta que caracteriza o cliente de publicações periódicas com volume mínimo acima de 3,6 milhões de objetos ano, cuja operação é totalmente customizada e tem preço individualizado por cliente.', '', 506),
(4250, 'capitulo', 1, 3745, 2, '2.413', 'Operação B: segmentação específica do serviço Correios Entrega Direta que caracteriza o cliente de publicações periódicas com volume mínimo entre 2 mil e 3,6 milhões de objetos ano, cuja operação é padronizada e os preços são definidos em função da faixa de volume dos clientes.', '', 507),
(4251, 'capitulo', 1, 3745, 2, '2.414', 'Ordem de Serviço - OS: documento emitido pelo gestor da unidade, pedindo a manutenção de equipamentos/prédios e pedir ao prestador de serviço de máquina de franquear a manutenção preventiva/corretiva do equipamento.', '', 508),
(4252, 'capitulo', 1, 3745, 2, '2.415', 'Organização da Expedição: serviço acessório customizado do serviço Correios Entrega Direta que constitui em realizar todas as etapas de preparação da carga para postagem, incluindo envio de arquivo de postagem, separação da carga, cumprimento do plano de reparte, até a apresentação e postagem da carga no prazo definido pelo cliente.', '', 509),
(4253, 'capitulo', 1, 3745, 2, '2.416', 'PAC: serviço de remessa econômica de mercadorias.', '', 510),
(4254, 'capitulo', 1, 3745, 2, '2.417', 'Padronização e Melhoria do Atendimento - PMA: é um conjunto de ações e orientações que, por meio das perspectivas Comportamental/Gerencial, Processos, Comercial, Organização e Certificação, abordam os processos internos, as pessoas e o ambiente das Agências dos Correios.', '', 511),
(4255, 'capitulo', 1, 3745, 2, '2.418', 'Pagamento de Benefício INSS: é uma transação disponibilizada no Banco Postal referente a pagamentos de aposentados e pensionistas.', '', 512),
(4256, 'capitulo', 1, 3745, 2, '2.419', 'Página Interna: páginas de lista de produtos e lojas e resultado da busca de produtos.', '', 513),
(4257, 'capitulo', 1, 3745, 2, '2.420', 'Página Principal do CNS: Página principal do CorreiosNet Shopping.', '', 514),
(4258, 'capitulo', 1, 3745, 2, '2.421', 'Painel de Controle Principal da máquina de franquear: Teclado e tela pelo qual ocorre a comunicação da Máquina de Franquear e o medidor.', '', 515),
(4259, 'capitulo', 1, 3745, 2, '2.422', 'Painel de Informações para Agências (Parede) - PINP: consiste em um quadro de parede destinado à colocação de avisos e informações em agências.', '', 516),
(4260, 'capitulo', 1, 3745, 2, '2.423', 'Painel de Informações para Agências (Totem) - PINT: consiste em painel do tipo totem destinado à colocação de avisos e informações em agências.', '', 517),
(4261, 'capitulo', 1, 3745, 2, '2.424', 'Peças de Divulgação: materiais promocionais utilizados para divulgação de informações institucionais ou comerciais (totem, filipeta, woobler, folder, cartaz, banner, entre outros).', '', 518),
(4262, 'capitulo', 1, 3745, 2, '2.425', 'Pedido de Confirmação de Entrega de Telegrama - PC: é um Serviço Adicional Taxado cuja solicitação é feita pelo remetente (expedidor), no ato da postagem da mensagem telemática ou posteriormente, limitado ao prazo de guarda do formulário Pré-pago, para que lhe sejam informados o dia, hora e nome da pessoa que firmou o recibo da mensagem.', '', 519),
(4263, 'capitulo', 1, 3745, 2, '2.426', 'Pedido de Informação - PI: procedimento formal de registro, em formulário eletrônico específico com número de protocolo individual, de solicitações de informação e reclamações que se refiram a objetos registrados.', '', 520),
(4264, 'capitulo', 1, 3745, 2, '2.427', 'Percentual de Participação na Despesa - PPD: define a parcela da despesa que caberá a cada uma das regionais envolvidas no rateio de indenizações pagas pelo motivo “extravio”, conforme a taxa de risco.', '', 521),
(4265, 'capitulo', 1, 3745, 2, '2.428', 'Percurso de Malote: é o trajeto definido pelo cliente do serviço Malote compreendendo a(s) localidade(s) e os endereços de origem e destino, bem como a frequência semanal em que a coleta deverá ser realizada.', '', 522),
(4266, 'capitulo', 1, 3745, 2, '2.429', 'Perfil de Senhas: níveis de acesso ao SIGMA que permite ao empregado um maior ou menor grau de atuação em nível Regional ou Nacional.', '', 523),
(4267, 'capitulo', 1, 3745, 2, '2.430', 'Periodicidade: período de tempo característico das publicações periódicas, o qual pode ser diário, semanal, quinzenal, mensal, bimestral, trimestral, semestral, anual etc., que tratam da frequência com que as publicações circulam ou são emitidas.', '', 524),
(4268, 'capitulo', 1, 3745, 2, '2.431', 'Permissão de Serviço Público: o Art. 175 da Constituição Federal dispõe que, em se tratando de serviços atribuídos ao Poder Público, categoria na qual se enquadra o serviço postal (art. 21, inciso X), tais serviços somente poderão ser executados diretamente pelo Estado, ou seja, pelos seus órgãos ou entes paraestatais, ou ainda, pela adoção do regime de concessão ou permissão, mediante delegação, nos termos da Lei.', '', 525),
(4269, 'capitulo', 1, 3745, 2, '2.432', 'Permissionária: no âmbito da Rede de Atendimento, é a pessoa jurídica operadora de ACC Terceirizada, signatária do contrato de permissão com os Correios, submetida aos direitos e obrigações decorrentes da Permissão.', '', 526),
(4270, 'capitulo', 1, 3745, 2, '2.433', 'Permitente: são os Correios, pessoa jurídica que concede a permissão.', '', 527),
(4271, 'capitulo', 1, 3745, 2, '2.434', 'Personalizar em Marketing Direto: consiste em adequar a peça com dados que, de forma generalizada, informam características, preferências e hábitos de consumo, sem contemplar informação confidencial do destinatário da correspondência. A personalização não deve expor a privacidade do destinatário, sob pena de ser classificada como Carta.', '', 528),
(4272, 'capitulo', 1, 3745, 2, '2.435', 'Peso Cúbico: é o peso obtido por meio de fórmula específica, que leva em consideração o volume do objeto e um fator de divisão.', '', 529),
(4273, 'capitulo', 1, 3745, 2, '2.436', 'Peso real: é o peso obtido por meio da pesagem do objeto.', '', 530),
(4274, 'capitulo', 1, 3745, 2, '2.437', 'Peso Tarifado: peso atribuído ao objeto para efeito de cobrança dos serviços, sendo obtido mediante a comparação entre o peso cúbico e o peso real, escolhendo-se o de maior valor.', '', 531),
(4275, 'capitulo', 1, 3745, 2, '2.438', 'Pessoa Física - PF: é a pessoa natural, isto é, todo indivíduo (homem ou mulher), desde o nascimento até a morte.', '', 532),
(4276, 'capitulo', 1, 3745, 2, '2.439', 'Pessoa Jurídica - PJ: é a entidade abstrata com existência e responsabilidades jurídicas legalmente autorizadas.', '', 533),
(4277, 'capitulo', 1, 3745, 2, '2.440', 'Pessoa Politicamente Exposta - PPE: agentes públicos que desempenham ou tenham desempenhado, nos últimos cinco anos, no Brasil ou em países, territórios e dependências estrangeiras, cargos, empregos ou funções públicas relevantes, assim como seus representantes, familiares e estreitos colaboradores.', '', 534),
(4278, 'capitulo', 1, 3745, 2, '2.441', 'Pixel - Picture e Element: elemento de imagem. É o menor ponto que forma uma imagem digital.', '', 535),
(4279, 'capitulo', 1, 3745, 2, '2.442', 'Plano de Continuidade de Negócios - PCN: são documentos que tem por objetivo identificar os riscos da IT e definir a(s) resposta(s) adequada(s), a fim de extinguir, mitigar ou prevenir essas ameaças para manter a continuidade do Serviço de Certificação Digital.', '', 536),
(4280, 'capitulo', 1, 3745, 2, '2.443', 'Plano de Triagem: é o conjunto de critérios estabelecidos pelas Unidades Operacionais para a separação das cargas, visando adequar às direções dos Guias de Expedição. Fonte: MANENC 1/1.', '', 537),
(4281, 'capitulo', 1, 3745, 2, '2.444', 'Plano de Triagem Padrão: é o plano de triagem utilizado quando todos os equipamentos de triagem previstos para um Centro estiverem disponibilizados e em pleno funcionamento. Fonte: MANENC 1/1.', '', 538),
(4282, 'capitulo', 1, 3745, 2, '2.445', 'Plano de Reparte: é o plano de organização da carga ou plano de triagem a ser seguido para unitizar e rotular a carga do serviço Correios Entrega Direto.', '', 539),
(4283, 'capitulo', 1, 3745, 2, '2.446', 'Plano Nacional de Promoções de Vendas - PNP: É o planejamento das ações promocionais de vendas, contendo produtos foco, períodos das campanhas de vendas, segmentos de clientes, metas de vendas, categorias de profissionais ou tipos de unidades participantes e orçamento de premiação para a força de vendas.', '', 540),
(4284, 'capitulo', 1, 3745, 2, '2.447', 'Plano Regional de Promoções de Vendas - PRP: é o desdobramento do PNP, com abrangência apenas regional, observados os elementos constantes do PNP e a necessidade de autorização pelo Departamento de Vendas.', '', 541),
(4285, 'capitulo', 1, 3745, 2, '2.448', 'Posta Restante Caída: serviço de entrega, em uma Agência dos Correios, de objeto endereçado a localidade onde não há distribuição domiciliar ou cuja entrega domiciliar não seja possível.', '', 542),
(4286, 'capitulo', 1, 3745, 2, '2.449', 'Posta Restante Pedida: serviço pelo qual o remetente de um objeto indica como endereço para entrega ou devolução uma Agência dos Correios.', '', 543),
(4287, 'capitulo', 1, 3745, 2, '2.450', 'Posto de Venda de Produtos - PVP: unidade de Atendimento terceirizada operada, mediante termo de autorização, por pessoa jurídica, destinada à venda de selos e de produtos comercializados pelas agências dos Correios, compartilhada com negócios enquadrados em ramos de atividade de interesse dos Correios e instalada em localidade atendida por agência de correios.', '', 544),
(4288, 'capitulo', 1, 3745, 2, '2.451', 'Prazo de aceitação da reclamação: é o prazo em que os Correios aceitam o registro de reclamação para identificar, corrigir ou reparar possíveis erros na prestação de serviços comunicados pelo cliente por intermédio de Pedido de Informação - PI (objetos registrados) ou Manifestação Geral - MG.', '', 545),
(4289, 'capitulo', 1, 4288, 3, '2.451.1', 'Atraso ou não entrega de objetos registrados:', '', 546),
(4290, 'capitulo', 1, 4289, 4, 'a', 'início:', 'I - no dia seguinte ao do prazo previsto de entrega do objeto, conforme modalidade de postagem;\nII - após prazo previsto de entrega somado ao tempo de pagamento do vale para Vale Postal;\nIII - após prazo previsto de entrega somado ao prazo de devolução para serviços adicionais.', 547),
(4291, 'capitulo', 1, 4289, 4, 'b', 'fim: até 90 (noventa) dias da postagem.', '', 548),
(4292, 'capitulo', 1, 4288, 3, '2.451.2', 'Situações que não envolvam objetos registrados:', '', 549),
(4293, 'capitulo', 1, 4292, 4, 'a', 'início: após a ocorrência do fato motivador da reclamação;', '', 550),
(4294, 'capitulo', 1, 4292, 4, 'b', 'fim: até 90 (noventa) dias da ocorrência do fato motivador da reclamação.', '', 551),
(4295, 'capitulo', 1, 3745, 2, '2.452', 'Prazo de apuração da reclamação de objeto nacional: é o prazo que as áreas possuem para fornecer a resposta final das reclamações (PI e MG) recebidas, conforme as prioridades definidas pela empresa:', '', 552),
(4296, 'capitulo', 1, 4295, 4, 'a', 'até 2 (dois) dias, para telegramas com vícios captados pela CAC;', '', 553),
(4297, 'capitulo', 1, 4295, 4, 'b', 'até 3 (três) dias úteis para as reclamações.', '', 554),
(4298, 'capitulo', 1, 3745, 2, '2.453', 'Prazo de guarda: prazo que um objeto ficará disponível em uma unidade dos Correios para retirada por parte do destinatário ou do remetente, em caso de devolução.', '', 555),
(4299, 'capitulo', 1, 3745, 2, '2.454', 'Prazo de pagamento de indenização ou ressarcimento de Objeto Nacional Registrado: o prazo para pagamento da indenização ou ressarcimento será de:', '', 556),
(4300, 'capitulo', 1, 4299, 4, 'a', '10 (dez) dias úteis: a pedido, sendo que a contagem do prazo para pagamento inicia-se a partir da conclusão pela procedência do Pedido de Informação e resposta conclusiva ao cliente;', '', 557),
(4301, 'capitulo', 1, 4299, 4, 'b', '30 (trinta) dias úteis: de ofício.', '', 558),
(4302, 'capitulo', 1, 3745, 2, '2.455', 'Preço: remuneração das atividades conotadas ao serviço postal ou ao serviço de telegrama. Representa um dos elementos constitutivos do produto na medida em que contribui para definir o seu caráter para o comprador, sendo na maioria das vezes o primeiro ponto de referência. Valor monetário atribuído a um produto para efeito de comercialização.', '', 559),
(4303, 'capitulo', 1, 3745, 2, '2.456', 'Preço estadual: é o preço cobrado na postagem de objeto quando a origem se encontra em um município e o destino em outro município do mesmo Estado, desde que os 2 municípios não pertençam à mesma área de precificação local.', '', 560),
(4304, 'capitulo', 1, 3745, 2, '2.457', 'Preço local: é o preço cobrado na postagem de objeto quando a origem e o destino se encontram dentro de um mesmo município/área de precificação local.', '', 561),
(4305, 'capitulo', 1, 3745, 2, '2.458', 'Preço nacional: é o preço cobrado na postagem de objeto quando a origem se encontra em um Estado e o destino em outro Estado.', '', 562),
(4306, 'capitulo', 1, 3745, 2, '2.459', 'Preço postal: é o valor estabelecido pelos Correios, em moeda nacional, pelo qual se determina a importância a ser paga pelo usuário de produtos e serviços postais prestados em regime concorrencial.', '', 563),
(4307, 'capitulo', 1, 3745, 2, '2.460', 'Prêmio: importância fixada percentualmente sobre o valor declarado dos objetos postais, a ser paga pelos usuários de determinados serviços para cobertura de riscos.', '', 564),
(4308, 'capitulo', 1, 3745, 2, '2.461', 'Pré-requisitos de postagem FAC: requisitos que devem ser, obrigatoriamente, cumpridos pela Contratante.', '', 565),
(4309, 'capitulo', 1, 4308, 4, 'a', 'FAC Simples:', 'I - impressão, em cada objeto, do Código de Informação de Franqueamento - CIF;\nII - execução dos serviços de pré-triagem conforme Plano de Triagem ou Sistema de Blocagem;\nIII - indicação do CEP e dos endereços corretos e completos do destinatário e do remetente;\nIV - aposição, no envelope, da Chancela de Franqueamento Padrão FAC;\nV - postagem da carga com o respectivo Relatório de Postagem Eletrônico e Resumo Impresso.', 566),
(4310, 'capitulo', 1, 4308, 4, 'b', 'FAC Registrado:', 'I - Execução dos serviços de pré-triagem conforme Plano de Triagem ou Sistema de Blocagem;\nII - Indicação do CEP e dos endereços corretos e completos do destinatário e do remetente;\nIII - Aposição, no envelope, da Chancela de Franqueamento Padrão FAC;\nIV - Postagem da carga com o respectivo Relatório de Postagem Eletrônico e Resumo Impresso.\nV - Impressão, no envelope, do número do registro;\nVI - Aposição da Data de Postagem ou Data de Produção junto ao bloco de endereçamento ou abaixo da Chancela de Franqueamento, precedida da expressão “Data de Postagem” ou “Data de Produção”, conforme o caso.', 567),
(4311, 'capitulo', 1, 3745, 2, '2.462', 'Prestação de Contas da agência terceirizada: apuração do valor arrecadado pela Agência Terceirizada ou verificação das transações realizadas no período.', '', 568),
(4312, 'capitulo', 1, 3745, 2, '2.463', 'Pré-triagem: separação preliminar de carga por área de tratamento/células ou direções de maior volume de carga. Fonte: MANENC 1/1.', '', 569),
(4313, 'capitulo', 1, 3745, 2, '2.464', 'Previsão de Postagem - AR Digital: arquivo com previsão de leiaute definido no MANCAT 7/13/4 que deverá ser transmitido aos Correios antes da postagem física dos objetos com AR Digital, para alimentar a base de dados do SGD - Sistema de Gerenciamento Eletrônico de Documentos dos Correios.', '', 570),
(4314, 'capitulo', 1, 3745, 2, '2.465', 'Primeiro Porte da Carta - PPC: unidade de valor referencial equivalente à tarifa aplicada ao primeiro porte da Carta.', '', 571),
(4315, 'capitulo', 1, 3745, 2, '2.466', 'Procurador: indivíduo que exerce um papel intermediário entre as partes interessadas, nomeado por meio de instrumento público.', '', 572),
(4316, 'capitulo', 1, 3745, 2, '2.467', 'Produção: serviço adicional que consiste na recepção de arquivos eletrônicos com processamento da informação, geração de objetos com AR Digital, por meio de montagem gráfica, impressão, envelopamento, fechamento e triagem.', '', 573),
(4317, 'capitulo', 1, 3745, 2, '2.468', 'Produto: é um conjunto de atributos, tangíveis ou intangíveis, constituído através do processo de produção, para atendimento de necessidades reais ou simbólicas, e que pode ser negociado no mercado, mediante um determinado valor de troca, quando então se converte em mercadoria.', '', 574),
(4318, 'capitulo', 1, 3745, 2, '2.469', 'Produtos adicionais: são produtos comercializados pelos Correios e quando adquiridos implicam custos adicionais ao cliente, como por exemplo, caixas, envelopes etc.', '', 575),
(4319, 'capitulo', 1, 3745, 2, '2.470', 'Produtos e serviços de terceiros: são os provenientes de contratos firmados entre os Correios e os parceiros comerciais administradores daqueles produtos e serviços.', '', 576),
(4320, 'capitulo', 1, 3745, 2, '2.471', 'Produtos Personalizados Empresariais: são produtos postais destinados à comunicação (aerogramas, cartões-postais, envelopes etc), que podem ser personalizados com marcas, imagens ou mensagens dos clientes.  De acordo com as necessidades de empresas e outras organizações, os produtos personalizados podem ser transformados em brindes exclusivos, criados e produzidos pelos Correios.', '', 577),
(4321, 'capitulo', 1, 3745, 2, '2.472', 'Profissional Liberal - PL: são considerados profissionais liberais, aqueles abrangidos por conselhos de classe (advogados, médicos, engenheiros, psicólogos etc). Também são considerados como profissionais liberais ou autônomos aqueles que exercem atividade econômica por meios próprios, de forma não assalariada, que para o exercício da atividade necessite de registro em prefeitura municipal e/ou junta comercial e que tenha sua atividade reconhecida pelo poder público, como por exemplo: leiloeiros, produtores rurais etc. Nessas condições não terá a emissão de CNPJ.', '', 578),
(4322, 'capitulo', 1, 3745, 2, '2.473', 'Projeto de instalação: é o conjunto de informações referentes às alterações arquitetônicas (estruturais, elétricas, de iluminação etc.) a serem realizadas no imóvel onde será instalada a área acessória, conforme designado no edital de licitação.', '', 579),
(4323, 'capitulo', 1, 3745, 2, '2.474', 'Propaganda web: espaços para veiculação de anúncios no CorreiosNet Shopping, nas seguintes opções de ambientes.', '', 580),
(4324, 'capitulo', 1, 3745, 2, '2.475', 'Proponente: no caso de Banco Postal, são pessoas físicas e jurídicas interessadas em adquirir produtos e/ou serviços no Banco Postal.', '', 581),
(4325, 'capitulo', 1, 3745, 2, '2.476', 'Proponente Incapaz: aquele que deve ser representado legalmente por outrem.', '', 582),
(4326, 'capitulo', 1, 3745, 2, '2.477', 'Proposta de Automação de Processo - PAP: documento exigido pela área de tecnologia dos Correios para a manutenção ou desenvolvimento de sistemas de informação.', '', 583),
(4327, 'capitulo', 1, 3745, 2, '2.478', 'Prospecção: atividade que consiste na busca de clientes em potencial, indicações e, no caso dos clientes estratégicos e corporativos, de novos negócios na carteira de clientes atuais.', '', 584),
(4328, 'capitulo', 1, 3745, 2, '2.479', 'Prospectar em marketing direto: ação promocional/comercial direcionada a alcançar, captar e conquistar potenciais consumidores.', '', 585),
(4329, 'capitulo', 1, 3745, 2, '2.480', 'Publicações periódicas: são aquelas normalmente editadas em intervalos prefixados (diário, semanal, quinzenal, mensal etc.) que se apresentam sob a forma de revistas, jornais segmentados, anuários, boletins, guias, catálogos, tabloides promocionais que têm edição ou período de circulação.', '', 586),
(4330, 'capitulo', 1, 3745, 2, '2.481', 'Rastreamento: acompanhamento do objeto via internet. O Rastreamento se dá por meio do SRO.', '', 587),
(4331, 'capitulo', 1, 3745, 2, '2.482', 'Rastreamento automático: acompanhamento do objeto passo a passo, desde a origem até o destino.', '', 588),
(4332, 'capitulo', 1, 3745, 2, '2.483', 'Recebimento: é uma transação disponibilizada no Banco Postal referente à quitação de contas de concessionárias, títulos e tributos.', '', 589),
(4333, 'capitulo', 1, 3745, 2, '2.484', 'Recebimento de contas: é o serviço que possibilita, mediante contrato de prestação de serviço de recebimento para terceiros, o recebimento de valores constantes nas contas ou carnês emitidos pela contratante.', '', 590),
(4334, 'capitulo', 1, 3745, 2, '2.485', 'Recebimento Parcial de Objeto Contestado - RPOC: documento no qual são registradas não conformidades constatadas após a entrega do objeto ao destinatário.', '', 591),
(4335, 'capitulo', 1, 3745, 2, '2.486', 'Receita contábil de vendas: é a composição da receita à vista mais a receita dos contratos advinda de postagens efetuadas no âmbito da Superintendência Estadual.', '', 592),
(4336, 'capitulo', 1, 3745, 2, '2.487', 'Receita gerencial de vendas: é a composição da receita à vista mais a receita dos contratos sob gestão da Superintendência Estadual, independentemente do local de postagem, representando o efetivo esforço de vendas.', '', 593),
(4337, 'capitulo', 1, 3745, 2, '2.488', 'Reclamação: serviço prestado pelos Correios para identificar, corrigir ou reparar possíveis erros na prestação de serviço formalmente comunicados pelo cliente. Quando envolve objeto registrado é feita por Pedido de Informação - PI, quando não envolve é feita por Manifestação Genérica - MG.', '', 594),
(4338, 'capitulo', 1, 3745, 2, '2.489', 'Recrutamento Interno - RI: método de seleção interna de profissionais para exercer função específica.', '', 595),
(4339, 'capitulo', 1, 3745, 2, '2.490', 'Recuperação de receita de objetos indenizados: conjunto de procedimentos a serem adotados com vistas à negociação com o cliente para devolução dos valores pagos a título de indenização nos casos de:', '', 596),
(4340, 'capitulo', 1, 4339, 4, 'a', 'erro por parte do cliente;', '', 597),
(4341, 'capitulo', 1, 4339, 4, 'b', 'reintegração de objetos registrados indenizados pelos motivos de extravio e roubo.', '', 598),
(4342, 'capitulo', 1, 3745, 2, '2.491', 'Rede Urgente - RU: é um instrumento utilizado para publicar, internamente, informações relacionadas à Empresa.', '', 599),
(4343, 'capitulo', 1, 3745, 2, '2.492', 'Reembolso Postal: serviço de remessa econômica de mercadorias em que o remetente estipula o valor a ser cobrado do destinatário.', '', 600),
(4344, 'capitulo', 1, 3745, 2, '2.493', 'Reenvio de publicações periódicas: serviço acessório do serviço Correios Entrega Direta, para nova entrega de publicação quando a primeira tentativa de entrega foi impossibilitada por informação incorreta do remetente. É também a nova entrega de publicação quando o cliente alega falha de entrega dos Correios e não houve alteração nos dados anteriormente informados, geralmente decorrente de uma reclamação do destinatário/assinante.', '', 601);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(4345, 'capitulo', 1, 3745, 2, '2.494', 'Refugo de Malote: destinação do conteúdo do malote após esgotar todas as tentativas de entrega ao cliente e prazo de guarda.', '', 602),
(4346, 'capitulo', 1, 3745, 2, '2.495', 'Registrador ascendente de máquina de franquear: dispositivo que registra o somatório dos franqueamentos realizados pela Máquina de Franquear.', '', 603),
(4347, 'capitulo', 1, 3745, 2, '2.496', 'Registrador descendente de máquina de franquear: dispositivo que registra o valor disponível no medidor da Máquina de Franquear.', '', 604),
(4348, 'capitulo', 1, 3745, 2, '2.497', 'Registro: serviço adicional por meio do qual o objeto é confiado aos Correios, contra a emissão de documento comprobatório da postagem. O objeto é identificado pela aplicação de numeração específica que possibilita acompanhar o seu trâmite desde a postagem até a entrega por meio do SRO.', '', 605),
(4349, 'capitulo', 1, 3745, 2, '2.498', 'Registro Automático: serviço no qual o objeto é confiado aos Correios, mediante certificado de registro.', '', 606),
(4350, 'capitulo', 1, 3745, 2, '2.499', 'Relações públicas: constituem um diálogo por meio de ações destinadas a obter reações favoráveis à atividade da empresa por parte dos seus diversos públicos, isto é, o público externo e o público interno.', '', 607),
(4351, 'capitulo', 1, 3745, 2, '2.500', 'Relatório Analítico de Transferência Intercompany: relatório emitido pelo SGTI, por regional, contendo a relação detalhada de indenizações, cuja responsabilidade foi definida para uma regional.', '', 608),
(4352, 'capitulo', 1, 3745, 2, '2.501', 'Relatório de Avaliação de Viabilidade Comercial - RAVC: relatório enviado aos órgãos formatadores de produtos e serviços para avaliação de viabilidade comercial composto das informações detalhadas do negócio.', '', 609),
(4353, 'capitulo', 1, 3745, 2, '2.502', 'Relatório de Postagem Eletrônico - RPE: descrição detalhada dos objetos que compõem a carga, com informações individualizadas de cada objeto. Pode ser apresentado por meio de disquete, CD-ROM, pendrive ou transferência eletrônica de dados. Deve seguir o leiaute estabelecido pelos Correios, disposto no seguinte endereço: \\\\sac0424\\SISTEMAS\\VINEG\\Novo_FAC.', '', 610),
(4354, 'capitulo', 1, 3745, 2, '2.503', 'Remessa Econômica de CRLV, CRV, CNH e Notificações: serviço destinado a pessoas jurídicas, prestado mediante contrato, para o envio de Certificado de Registro e Licenciamento de Veículos - CRLV, Certificado de Registro de Veículos - CRV, Carteira Nacional de Habilitação - CNH e Notificações.', '', 611),
(4355, 'capitulo', 1, 3745, 2, '2.504', 'Remessa Econômica de Talão de Cheques e Cartões Diversos: serviço destinado a Pessoas Jurídicas, prestado mediante contrato, para o envio de talões de cheques e cartões diversos.', '', 612),
(4356, 'capitulo', 1, 3745, 2, '2.505', 'Remessa Expressa Órgãos de Trânsito: serviço de remessa expressa de Certificado de Registro e Licenciamento de Veículos - CRLV, Certificado de Registro de Veículos - CRV, Carteira Nacional de Habilitação - CNH e Notificação de Trânsito - NIT.', '', 613),
(4357, 'capitulo', 1, 3745, 2, '2.506', 'Remessa Expressa Talão/Cartão: serviço de remessa expressa de talões de cheques e/ou cartões diversos.', '', 614),
(4358, 'capitulo', 1, 3745, 2, '2.507', 'Remessa Local com Comprovação de Entrega: serviço de correspondência prestado mediante contrato, para o envio exclusivo de Notificações, Citações, Intimações, Taxas/Contribuições e IPTU.', '', 615),
(4359, 'capitulo', 1, 3745, 2, '2.508', 'Remetente: cliente que faz a postagem de objetos postais/encomendas. Detém a posse e a responsabilidade do objeto até a efetivação da entrega.', '', 616),
(4360, 'capitulo', 1, 3745, 2, '2.509', 'Representante do Fale Conosco: funcionário dos Correios devidamente cadastrado para acessar o sistema Fale Conosco, apurar as reclamações e elaborar respostas aos questionamentos direcionados para a unidade em que trabalha.', '', 617),
(4361, 'capitulo', 1, 3745, 2, '2.510', 'Requerimento para Utilização de Máquina de Franquear: é o documento utilizado para requerer a utilização de Máquina de Franquear junto às Superintendências Estaduais.', '', 618),
(4362, 'capitulo', 1, 3745, 2, '2.511', 'Responsabilidade definida: quando o fato gerador da indenização possibilita a indicação de responsabilidade do órgão, empregado ou terceiro.', '', 619),
(4363, 'capitulo', 1, 3745, 2, '2.512', 'Responsabilidade indefinida: quando o fato gerador da indenização não possibilita a indicação de responsabilidade do órgão, empregado ou terceiro.', '', 620),
(4364, 'capitulo', 1, 3745, 2, '2.513', 'Ressarcimento: é o procedimento de restituição ao cliente, no todo ou em parte, dos preços postais, em decorrência de erros ou inconformidades na prestação dos serviços, inclusive serviços adicionais, como atraso na entrega, não devolução do AR, etc. É efetuado de ofício ou a pedido do remetente ou do destinatário, nas situações de comprovação, após consulta ao SRO e apuração da reclamação realizada pelas unidades diretamente envolvidas no fluxo postal.', '', 621),
(4365, 'capitulo', 1, 3745, 2, '2.514', 'Resumo de Postagem Impresso: resumo impresso do Relatório de Postagem Eletrônico que, por motivos de contingência, deve ser entregue junto ao respectivo RPE, com os seguintes dados: número do lote, quantidade de objetos por destino, peso total e unitário dos objetos, peso bruto da carga (incluindo peso de unitizadores), número do contrato e código administrativo, número do cartão de postagem e data de entrega aos Correios.', '', 622),
(4366, 'capitulo', 1, 3745, 2, '2.515', 'Resumo de Serviços Especiais - SER: documento referente aos detalhes de operacionalização de determinado serviço/produto.', '', 623),
(4367, 'capitulo', 1, 3745, 2, '2.516', 'Revista: publicação periódica que geralmente inclui artigos, entrevistas, reportagens, etc., de temas de interesse comum, científicos, históricos, entre outros.', '', 624),
(4368, 'capitulo', 1, 3745, 2, '2.517', 'Sala de AR: ambiente físico da instalação técnica para receber o solicitante do certificado digital.', '', 625),
(4369, 'capitulo', 1, 3745, 2, '2.518', 'Sambag: unitizador flexível, fabricado em tecido de polipropileno.', '', 626),
(4370, 'capitulo', 1, 3745, 2, '2.519', 'Saque: é a transação disponibilizada no Banco Postal referente à retirada de numerário, por parte do cliente, mediante a aposição de senha.', '', 627),
(4371, 'capitulo', 1, 3745, 2, '2.520', 'Scanner: equipamento utilizado para captura dos dados/imagem da estampa com conexão a coletor de dados, onde ficarão armazenadas as informações coletadas.', '', 628),
(4372, 'capitulo', 1, 4371, 3, '2.520.1', 'Esse equipamento será utilizado pelas equipes de supervisão e inspetores para leitura das informações contidas na estampa dos objetos franqueados pelas máquinas de franquear.', '', 629),
(4373, 'capitulo', 1, 3745, 2, '2.521', 'Secretaria da Receita Federal do Brasil - RFB: órgão específico, singular, subordinado ao Ministério da Fazenda, exercendo funções essenciais para que o Estado possa cumprir seus objetivos. É responsável pela administração dos tributos de competência da União, inclusive os previdenciários, e aqueles incidentes sobre o comércio exterior, abrangendo parte significativa das contribuições sociais do País.', '', 630),
(4374, 'capitulo', 1, 3745, 2, '2.522', 'SEDEX: serviço de remessa expressa de documentos e mercadorias.', '', 631),
(4375, 'capitulo', 1, 3745, 2, '2.523', 'SEDEX 10: serviço de remessa expressa de documentos e mercadorias com entrega garantida até às 10 horas do dia útil seguinte ao da postagem.', '', 632),
(4376, 'capitulo', 1, 3745, 2, '2.524', 'SEDEX a Cobrar: serviço de remessa expressa de documentos e mercadorias, no qual o remetente paga os preços postais no momento da postagem e estipula o valor a ser cobrado do destinatário.', '', 633),
(4377, 'capitulo', 1, 3745, 2, '2.525', 'SEDEX Hoje: serviço de remessa expressa de documentos e mercadorias com entrega garantida até às 18 horas do dia da postagem.', '', 634),
(4378, 'capitulo', 1, 3745, 2, '2.526', 'Segmentação de clientes: estratificação dos clientes em segmentos, de acordo com o valor que representam para a Empresa. São eles: Estratégico, Corporativo, Empresarial, Comercial e Varejo.', '', 635),
(4379, 'capitulo', 1, 3745, 2, '2.527', 'Segmentação de mercado: processo de análise e identificação de grupos de clientes, com necessidade e preferências homogêneas ou com algum grau de homogeneidade, permitindo que a empresa adapte melhor as políticas de marketing ao seu mercado-alvo.', '', 636),
(4380, 'capitulo', 1, 3745, 2, '2.528', 'Segmentação de negócios: estratificação dos negócios da Empresa em segmentos conforme suas características. São eles: Conveniência, Encomendas, Financeiro, Internacional, Logística, Marketing Direto e Mensagens.', '', 637),
(4381, 'capitulo', 1, 3745, 2, '2.529', 'Selo Base: é o selo que contém motivo temático e demais informações relacionadas ao valor de franquia e legendas. A ele, separada pelo picote, encontra-se a vinheta em branco destinada à impressão da imagem autorizada pelo cliente.', '', 638),
(4382, 'capitulo', 1, 3745, 2, '2.530', 'Selo não Postal: é a etiqueta com a mesma finalidade da vinheta.', '', 639),
(4383, 'capitulo', 1, 3745, 2, '2.531', 'Selo Personalizado: é um produto filatélico composto por um Selo Base focalizando um motivo temático do universo sociocultural, com valor facial vinculado à tarifa postal, acrescido de uma vinheta destinada à impressão de fotografia e/ou imagem pertencente ao cliente.', '', 640),
(4384, 'capitulo', 1, 3745, 2, '2.532', 'Selo Postal: estampilha postal, adesiva ou fixa, bem com a estampa produzida por meio de máquina de franquear correspondência, destinadas a comprovar o pagamento da prestação de um serviço postal.', '', 641),
(4385, 'capitulo', 1, 3745, 2, '2.533', 'Serviço: ações, processos e atuações, com características de intangibilidade, perecibilidade, heterogeneidade ou variabilidade, simultaneidade ou inseparabilidade e participação do cliente no processo.', '', 642),
(4386, 'capitulo', 1, 3745, 2, '2.534', 'Serviço adicional inerente: serviço adicional inerente - é aquele cujo preço já se encontra embutido na tarifa do serviço considerado e os procedimentos para sua prestação encontram-se mesclados aos procedimentos do serviço postal.', '', 643),
(4387, 'capitulo', 1, 3745, 2, '2.535', 'Serviço Atendimento Pessoal às TELES: consiste no atendimento pessoal aos usuários das TELES (Operadoras de Telefonia), mediante distribuição e captação, nas Agências de Correios Credenciadas, dos formulários “Solicitação de Serviços” devidamente preenchidos.', '', 644),
(4388, 'capitulo', 1, 3745, 2, '2.536', 'Serviço CPF: consiste na captação e tratamento de dados, via formulário eletrônico, para repasse de informações à Secretaria de Receita Federal do Brasil - RFB. Visa a inscrição, alteração, correção e pedido de regularização do Cadastro de Pessoa Física - CPF.', '', 645),
(4389, 'capitulo', 1, 3745, 2, '2.537', 'Serviço de Personalização: consiste na impressão de fotografia e/ou imagem pertencente ao cliente na vinheta associada ao Selo Base, destinada à personalização da imagem autorizada, observando-se as condições constantes do Termo de Solicitação do Serviço de Personalização de Selos Postais.', '', 646),
(4390, 'capitulo', 1, 3745, 2, '2.538', 'Serviço de Protocolo Postal - SPP: protocolo de petições, recursos e documentos destinados aos Tribunais de Justiça, Órgãos de Trânsito e outros segmentos semelhantes.', '', 647),
(4391, 'capitulo', 1, 3745, 2, '2.539', 'Serviço de Recarga Virtual: recarga de crédito virtual on-line de aparelhos telefônicos (fixos e/ou móveis) pré-pagos, nas Agências de Correios.', '', 648),
(4392, 'capitulo', 1, 3745, 2, '2.540', 'Serviço ITR: o Serviço consiste no recebimento das Declarações do Imposto Territorial Rural, apresentada em formulário impresso, que deve ser entregue por toda pessoa física ou jurídica que seja proprietária, titular do domínio útil ou possuidora, a qualquer título, de imóvel Rural. Serviço prestado, anualmente, geralmente nos meses de agosto e setembro.', '', 649),
(4393, 'capitulo', 1, 3745, 2, '2.541', 'Serviço Postal: constitui serviço postal o recebimento, expedição, transporte e entrega de objetos de correspondência, valores e encomendas, conforme definido em regulamento.', '', 650),
(4394, 'capitulo', 1, 3745, 2, '2.542', 'Serviço postal relativo a valores: recebimento de tributos, prestações, contribuições e obrigações pagáveis à vista, por via postal, sendo que para os serviços de conveniência será utilizado como venda de Cartões Virtuais, pré-pagos, na forma de PINs Personal Identificator Number (senha) virtuais, denominados Cartões Virtuais.', '', 651),
(4395, 'capitulo', 1, 3745, 2, '2.543', 'Serviços acessórios do serviço Correios Entrega Direta: são os serviços que poderão ser utilizados ou não pelo cliente do Correios Entrega Direta, os quais tem códigos específicos para contratação. São eles:', '', 652),
(4396, 'capitulo', 1, 4395, 4, 'a', 'Entrega de encarte local;', '', 653),
(4397, 'capitulo', 1, 4395, 4, 'b', 'Coleta;', '', 654),
(4398, 'capitulo', 1, 4395, 4, 'c', 'Inserção do primeiro encarte;', '', 655),
(4399, 'capitulo', 1, 4395, 4, 'd', 'Inserção dos demais encartes;', '', 656),
(4400, 'capitulo', 1, 4395, 4, 'e', 'Envelopamento;', '', 657),
(4401, 'capitulo', 1, 4395, 4, 'f', 'Entrega protocolada até 2% do volume; e', '', 658),
(4402, 'capitulo', 1, 4395, 4, 'g', 'Entrega protocolada que exceder 2% do volume.', '', 659),
(4403, 'capitulo', 1, 4395, 4, 'h', 'Custos adicionais;', '', 660),
(4404, 'capitulo', 1, 4395, 4, 'i', 'Complementação anual de volume;', '', 661),
(4405, 'capitulo', 1, 4395, 4, 'j', 'Reenvio por reclamação improcedente;', '', 662),
(4406, 'capitulo', 1, 4395, 4, 'k', 'Cancelamento de Etiquetas.', '', 663),
(4407, 'capitulo', 1, 3745, 2, '2.544', 'Serviços acessórios customizados do serviço Correios Entrega Direta: são os serviços que poderão ser desenvolvidos para os clientes do serviço Correios Entrega Direta, mediante demanda do mercado. São eles:', '', 664),
(4408, 'capitulo', 1, 4407, 4, 'a', 'organização da expedição;', '', 665),
(4409, 'capitulo', 1, 4407, 4, 'b', 'inserção de encartes personalizados, brindes e amostras;', '', 666),
(4410, 'capitulo', 1, 4407, 4, 'c', 'devolução de objetos não entregues;', '', 667),
(4411, 'capitulo', 1, 4407, 4, 'd', 'outros que poderão ser formatados de acordo com a necessidade do cliente, cujos preços serão definidos em função da customização efetuada.', '', 668),
(4412, 'capitulo', 1, 3745, 2, '2.545', 'Serviços adicionais: serviços que podem ser agregados ao serviço principal, mas quando adquiridos implicam custos adicionais ao cliente.', '', 669),
(4413, 'capitulo', 1, 3745, 2, '2.546', 'Serviços bancários básicos: são aqueles autorizados pelo Banco Central aos correspondentes bancários e deverão ser implantados prioritariamente nos municípios desassistidos de atendimento bancário, como instrumento de inserção social.', '', 670),
(4414, 'capitulo', 1, 4413, 3, '2.546.1', 'Os municípios desassistidos de atendimento bancário são aqueles que não possuem agência bancária, correspondente ou qualquer tipo de posto de atendimento que forneça serviços bancários.', '', 671),
(4415, 'capitulo', 1, 3745, 2, '2.547', 'Serviços Básicos do serviço Correios Entrega Direta: são os serviços que compõem a formatação padrão e que já estão inseridos no preço final definido para cada faixa de volume.', '', 672),
(4416, 'capitulo', 1, 4415, 4, 'a', 'na Operação B são os seguintes:', 'I - postagem na unidade definida pelos Correios;\nII - transferência e interiorização;\nIII - impressão das etiquetas de endereçamento;\nIV - etiquetagem no destino;\nV - entrega e informação de não entrega, via Sistema Periódicos.', 673),
(4417, 'capitulo', 1, 4415, 4, 'b', 'na Operação A podem ser:', 'I - captação na gráfica ou local definido pelo cliente;\nII - transferência e interiorização;\nIII - impressão das etiquetas de endereçamento;\nIV - etiquetagem no destino;\nV - entrega e informação de não entrega, via Sistema Periódicos.', 674),
(4418, 'capitulo', 1, 3745, 2, '2.548', 'Serviços concorrenciais: serviços prestados pelos Correios que não estão tutelados pelo Monopólio Postal.', '', 675),
(4419, 'capitulo', 1, 3745, 2, '2.549', 'Serviços de atacado: aqueles que possuem pelo menos uma das seguintes características em sua formatação:', '', 676),
(4420, 'capitulo', 1, 4419, 4, 'a', 'não é prevista a postagem em Agências;', '', 677),
(4421, 'capitulo', 1, 4419, 4, 'b', 'formatação operacional especial;', '', 678),
(4422, 'capitulo', 1, 4419, 4, 'c', 'preços customizados que implicam reduzidas margens de lucratividade.', '', 679),
(4423, 'capitulo', 1, 3745, 2, '2.550', 'Serviços de Recebimento de Inscrições: são os serviços que possibilitam o recebimento de inscrições, para Concursos (Públicos ou Privados), Vestibulares para Faculdades (Públicas e Particulares), Instituições ou Escolas que dependam de inscrições para realização de provas.', '', 680),
(4424, 'capitulo', 1, 3745, 2, '2.551', 'Serviços de Resposta: Carta e Cartão Resposta e Envelope Encomenda Resposta: objetos de correspondência, previamente chancelados, sob a forma de comunicação escrita, de natureza comercial a ser devolvido pelo respectivo destinatário. Permite a remessa de pedidos e/ou informações, em forma de carta, cartão ou envelope encomenda resposta, cujo destinatário efetua a postagem, porém o pagamento é responsabilidade do remetente quando da retirada do objeto na unidade definida para retorno.', '', 681),
(4425, 'capitulo', 1, 3745, 2, '2.552', 'Serviços inerentes: serviços agregados ao serviço principal e que não implicam custos adicionais ao cliente.', '', 682),
(4426, 'capitulo', 1, 3745, 2, '2.553', 'Serviços monopolizados: serviços prestados pelos Correios que estão sob a tutela do Monopólio Postal. São eles: Carta, Cartão Postal, Correspondência Agrupada e Telegrama.', '', 683),
(4427, 'capitulo', 1, 3745, 2, '2.554', 'Shopping virtual: site que permite ao usuário navegar entre várias lojas, fazer comparações entre produtos, acompanhar pedidos, solicitar atendimento, visualizar produtos e catálogos e receber ofertas.', '', 684),
(4428, 'capitulo', 1, 3745, 2, '2.555', 'Simulador de Preço de Percurso do Malote: ferramenta disponível no portal do serviço de Malote na internet (www.correios.com.br/malote) que oferece aos interessados e clientes a possibilidade de calcular o preço do percurso mensal.', '', 685),
(4429, 'capitulo', 1, 3745, 2, '2.556', 'Sistema CIFWEB: sistema desenvolvido exclusivamente para gerenciar a captação dos objetos FAC. Controla as etapas do processo de postagem: leitura do Relatório de Postagem Eletrônico, pesagem, amostragem, validação da amostra e geração dos dados de faturamento para importação pelo sistema de faturamento dos Correios. Somente pode ser operado por empregados dos Correios.', '', 686),
(4430, 'capitulo', 1, 3745, 2, '2.557', 'Sistema CPF Web Service - CPF WS: Sistema eletrônico corporativo no qual é executado o Serviço CPF via Web Service em unidades dos Correios.', '', 687),
(4431, 'capitulo', 1, 3745, 2, '2.558', 'Sistema de Acompanhamento da Padronização do Processo Produtivo - SAPPP: é o Sistema de Acompanhamento da Padronização do Processo Produtivo, que será utilizado como instrumento corporativo para certificação da PMA nas agências de Correios.', '', 688),
(4432, 'capitulo', 1, 3745, 2, '2.559', 'Sistema de Automação da Rede de Atendimento - SARA: sistema de automação do atendimento adotado pelos Correios.', '', 689),
(4433, 'capitulo', 1, 3745, 2, '2.560', 'Sistema de blocagem: triagem virtual dos objetos, na base de dados, para ser verificada a melhor forma de impressão e unitização.', '', 690),
(4434, 'capitulo', 1, 3745, 2, '2.561', 'Sistema de Cálculo de Preços e Prazos - SCPP: é o sistema que possibilita calcular os preços e prazos de entrega de produtos e serviços, bem como consultar a ocorrência de feriados nas localidades de destino, os quais devem ser considerados para efeito de previsão de prazos de entrega.', '', 691),
(4435, 'capitulo', 1, 3745, 2, '2.562', 'Sistema de Captação de Indenização - SCISPI: sistema utilizado pela área de relacionamento com o cliente para cadastrar PI procedentes de indenização, calcular os valores a serem pagos e registrar a responsabilidade da(s) regional (ais) que deu (ram) causa ao pagamento de indenização.', '', 692),
(4436, 'capitulo', 1, 3745, 2, '2.563', 'Sistema de Coleta - SCOL: sistema que gerencia as solicitações dos serviços Disque Coleta e Logística Reversa.', '', 693),
(4437, 'capitulo', 1, 3745, 2, '2.564', 'Sistema de Conferência de Carga Recebida - SCCR: é o sistema utilizado para captação das postagens de objetos dos serviços de remessa expressa e de remessa econômica.', '', 694),
(4438, 'capitulo', 1, 3745, 2, '2.565', 'Sistema de Comercio Exterior - Siscomex: sistema instituído para integrar as atividades afins do Departamento de Comércio Exterior (DECEX), da Secretaria da Receita Federal (SRF) e do Banco Central (BC) no registro, no acompanhamento e no controle das diferentes etapas das operações de exportação e importação.', '', 695),
(4439, 'capitulo', 1, 3745, 2, '2.566', 'Sistema de Faturamento Regional - Módulo Malote - SFR-M: módulo do Sistema de Faturamento Regional - SFR para calcular o Valor do Serviço Contratado - VSC dos percursos ativos e gerar o faturamento dos movimentos captados pelo SIGMA, de forma centralizada, para emissão das faturas no ERP e no SFR.', '', 696),
(4440, 'capitulo', 1, 3745, 2, '2.567', 'Sistema de Gerenciamento de Documentos Eletrônicos - SGD: é o sistema utilizado para gestão de documentos eletrônicos.', '', 697),
(4441, 'capitulo', 1, 3745, 2, '2.568', 'Sistema de Gerenciamento de Documentos Perdidos - SDP Web: sistema responsável pelo gerenciamento do serviço de Achados e Perdidos.', '', 698),
(4442, 'capitulo', 1, 3745, 2, '2.569', 'Sistema de Gerenciamento de Postagens - SIGEP VB: é um sistema com o propósito de preparar e gerenciar as postagens de clientes dos Correios.', '', 699),
(4443, 'capitulo', 1, 3745, 2, '2.570', 'Sistema de Gerenciamento do Atendimento (Gerenciamento de Filas) - SGEA: sistema utilizado para gerenciar a fila nas agências de Correios.', '', 700),
(4444, 'capitulo', 1, 3745, 2, '2.571', 'Sistema de Gerenciamento de Transferência Intercompany de Indenizações - SGTI: sistema desenvolvido em Access, utilizado pela CEREL para processar a transferência intercompany de indenizações cadastradas no SCISPI pelos órgãos regionais de indenização vinculados à área de clientes e operações.', '', 701),
(4445, 'capitulo', 1, 3745, 2, '2.572', 'Sistema de Gestão de Pessoal das Agências - SGPA: sistema que calcula a Carga de Trabalho e Dimensiona o Efetivo das Agências Próprias.', '', 702),
(4446, 'capitulo', 1, 3745, 2, '2.573', 'Sistema de Informações Locais de Tratamento - SILTE: é o sistema utilizado para gestão das informações e estatísticas de tratamento de encomendas e malotes, que possibilita recuperar informações como o peso dos objetos ao passar pelas unidades de encaminhamento.', '', 703),
(4447, 'capitulo', 1, 3745, 2, '2.574', 'Sistema INFOCONV: sistema do SERPRO para prestação do serviço CPF WS.', '', 704),
(4448, 'capitulo', 1, 3745, 2, '2.575', 'Sistema Integrado de Gerenciamento do Malote - SIGMA: é o sistema corporativo que executa a captação dos movimentos gerados nas unidades postais pela intranet no endereço http://sigma/sigma de forma centralizada, e gerencia todo o processo comercial/operacional do serviço Malote, além de gerar dados para o faturamento do serviço.', '', 705),
(4449, 'capitulo', 1, 3745, 2, '2.576', 'Sistema Periódico - SISPER: sistema de gestão do serviço Correios Entrega Direta.', '', 706),
(4450, 'capitulo', 1, 3745, 2, '2.577', 'Sistema Próprio de Postagem: sistema desenvolvido pelo cliente de contrato para realizar a pré-postagem de seus objetos.', '', 707),
(4451, 'capitulo', 1, 3745, 2, '2.578', 'Site: conjunto de páginas Web, imagens e outros conteúdos em formato digital, alojados num servidor Web e acessíveis por meio da internet ou de uma rede local.', '', 708),
(4452, 'capitulo', 1, 3745, 2, '2.579', 'Site para Unidades Terceirizadas - SUT: é um instrumento utilizado para publicar, para a rede de agências terceirizadas, informações relacionadas à Empresa.', '', 709),
(4453, 'capitulo', 1, 3745, 2, '2.580', 'Smart Sard: cartão inteligente que geralmente assemelha-se em forma e tamanho a um cartão de crédito convencional de plástico com tarja magnética. Serve para armazenar um certificado digital, oferecendo autenticação segura, verificação e serviços de criptografia de informações.', '', 710),
(4454, 'capitulo', 1, 3745, 2, '2.581', 'Solução de Organização de Filas - SOF: é um organizador de filas em agências com pelo menos 2 (dois) guichês ativos.', '', 711),
(4455, 'capitulo', 1, 3745, 2, '2.582', 'Solução Digital de Franqueamento: conjunto constituído por hardware e software que deverá se integrar de forma harmoniosa com outros sistemas utilizados pelos Correios.', '', 712),
(4456, 'capitulo', 1, 3745, 2, '2.583', 'Supervisão: atividade desempenhada pelo supervisor de atendimento com a finalidade de avaliar e prestar apoio técnico às rotinas dos serviços financeiro, administrativo, comercial e operacional executados pelas agências de correios, emitindo, periodicamente, relatórios gerenciais indicando os resultados dos processos analisados com as oportunidades de melhorias e as melhores práticas verificadas.', '', 713),
(4457, 'capitulo', 1, 3745, 2, '2.584', 'Suspensão Temporária de Percurso do Malote: solicitação de cliente visando a suspensão da coleta e da cobrança do VSC do percurso por período determinado, normalmente por motivo de férias coletivas.', '', 714),
(4458, 'capitulo', 1, 3745, 2, '2.585', 'Tabloides promocionais: são cadernos/brochuras que contêm ofertas promocionais com prazo de vigência, emitidos por estabelecimento.', '', 715),
(4459, 'capitulo', 1, 3745, 2, '2.586', 'Tabela de Motivos e Análise de Responsabilidades de Unidades: matriz que apresenta um conjunto de fatores indicativos ou não de responsabilização das unidades, de acordo com o motivo do pagamento de indenizações.', '', 716),
(4460, 'capitulo', 1, 3745, 2, '2.587', 'Tarifa: valor, fixado em base unitária, pelo qual se determina a importância a ser paga pelo usuário do serviço postal ou do serviço de telegramas.', '', 717),
(4461, 'capitulo', 1, 3745, 2, '2.588', 'Tarifa de divisa: tarifa especial previamente aprovada, equivalente ao preço de percurso estadual, que visa atender percursos entre localidades de estados limítrofes.', '', 718),
(4462, 'capitulo', 1, 3745, 2, '2.589', 'Tarifa postal: é o valor estabelecido pelo Poder Público, em moeda nacional, pelo qual se determina a importância máxima a ser paga pelo usuário de serviços postais prestados pelos Correios em regime de exclusividade.', '', 719),
(4463, 'capitulo', 1, 3745, 2, '2.590', 'Taxa de armazenagem: tarifa cobrada pela armazenagem de um objeto em uma unidade dos Correios.', '', 720),
(4464, 'capitulo', 1, 3745, 2, '2.591', 'Taxa de Risco das Regionais - TRR: representa o percentual de vulnerabilidade regional no tocante ao tratamento e entrega de objetos. A TRR é calculada com base na média ponderada entre o ICI e o ICP.', '', 721),
(4465, 'capitulo', 1, 3745, 2, '2.592', 'Telegrama - TLG: é a mensagem, transmitida por meios eletrônicos, a ser convertida em comunicação escrita, para entrega ao destinatário.', '', 722),
(4466, 'capitulo', 1, 3745, 2, '2.593', 'Telegrama de Balcão: é o serviço telegrama captado nos guichês de atendimento de toda a rede de agências próprias e terceirizadas.', '', 723),
(4467, 'capitulo', 1, 3745, 2, '2.594', 'Telegrama Fonado: é o serviço de telegrama captado por telefone, por meio da Central de Atendimento aos Clientes dos Correios - CAC, cujos números de atendimento e horários de funcionamento encontram-se divulgados no portal dos Correios na internet (www.correios.com.br).', '', 724),
(4468, 'capitulo', 1, 3745, 2, '2.595', 'Telegrama Pré-Datado: é o telegrama em que o remetente (expedidor) solicita que a entrega ocorra em uma data pré-determinada e posterior àquela em que o está apresentando aos Correios.', '', 725),
(4469, 'capitulo', 1, 3745, 2, '2.596', 'Telegrama via internet: é o serviço telegrama captado por meio da internet, pelo Sistema de Postagem Eletrônica - SPE, pela loja virtual (Correios Online) ou por arquivo magnético (mídia eletrônica).', '', 726),
(4470, 'capitulo', 1, 3745, 2, '2.597', 'Tempo de Constatação - TC: documento no qual são registradas não conformidades constatadas antes da entrega do objeto ao destinatário.', '', 727),
(4471, 'capitulo', 1, 3745, 2, '2.598', 'Tempo de Resposta ao Cliente do Fale Conosco - ETR FC: é o indicador utilizado para mensurar o tempo de resposta às manifestações dos clientes dos Correios registradas no sistema Fale Conosco e que considera as pendências de respostas de meses anteriores, de forma a possibilitar.', '', 728),
(4472, 'capitulo', 1, 3745, 2, '2.599', 'Terminais de acesso/usuários: são microcomputadores dos Correios utilizados como canal para troca de informações com o fornecedor de solução de franqueamento, por meio de acesso via web, com o propósito de viabilizar o gerenciamento do parque de máquinas de franquear.', '', 729),
(4473, 'capitulo', 1, 3745, 2, '2.600', 'Termo de acordo operacional: é o instrumento que estabelece as condições gerais de operacionalização e de comissionamento, para os casos em que se utiliza a média histórica.', '', 730),
(4474, 'capitulo', 1, 3745, 2, '2.601', 'Termo de Autorização de Uso de Máquina de Franquear - Agências Próprias: documento que estabelece as responsabilidades sobre a Máquina de Franquear de propriedade dos Correios.', '', 731),
(4475, 'capitulo', 1, 3745, 2, '2.602', 'Termo de Autorização de Uso de Máquina de Franquear - Cliente autorizado: documento que estabelece as responsabilidades sobre a Máquina de Franquear de propriedade de terceiros.', '', 732),
(4476, 'capitulo', 1, 3745, 2, '2.603', 'Termo de Autorização de Uso de Máquina de Franquear- Agências Terceirizadas: documento que define os direitos e obrigações das Agências Terceirizadas e dos Correios, no que tange ao uso de Máquina de Franquear de propriedade dos Correios.', '', 733),
(4477, 'capitulo', 1, 3745, 2, '2.604', 'Tipo de ônus: consiste na atribuição de responsabilidade das regionais diretamente envolvidas no fluxo postal, para efeito de transferência intercompany das despesas pagas com indenizações. Os tipos de ônus disponíveis são:', '', 734),
(4478, 'capitulo', 1, 4477, 4, 'a', 'De/Para a Própria DR: quando envolve, obrigatoriamente, uma ou mais unidades vinculadas à regional de origem da postagem, tendo o objeto como destino a mesma regional;', '', 735),
(4479, 'capitulo', 1, 4477, 4, 'b', 'DR destino: quando envolve, obrigatoriamente, uma ou mais unidades vinculadas à regional de destino do objeto, sendo essa diferente da regional de origem da postagem;', '', 736),
(4480, 'capitulo', 1, 4477, 4, 'c', 'DR intermediária: quando envolve, obrigatoriamente, uma ou mais unidades não vinculadas nem à regional de origem, nem à regional de destino do objeto;', '', 737),
(4481, 'capitulo', 1, 4477, 4, 'd', 'DR origem: quando envolve, obrigatoriamente, uma ou mais unidades vinculadas à regional de origem da postagem, sendo o objeto destinado a outra regional;', '', 738),
(4482, 'capitulo', 1, 4477, 4, 'e', 'rateio: quando envolve, obrigatoriamente, duas unidades de regionais distintas, sendo, pelo menos, uma delas vinculada à regional de origem ou destino do objeto.', '', 739),
(4483, 'capitulo', 1, 3745, 2, '2.605', 'Transferência Intercompany: consiste no procedimento financeiro de transferência integral ou parcial de valores pagos a título de indenização para a regional responsável pelo fato gerador da indenização. É realizado mensalmente e compreende as indenizações processadas no período de 26 a 25 de cada mês.', '', 740),
(4484, 'capitulo', 1, 3745, 2, '2.606', 'Tipo de unidade: para efeito de transferência intercompany e análise de contestações, será classificada como tipo de unidade de:', '', 741),
(4485, 'capitulo', 1, 4484, 4, 'a', 'atendimento: quando envolver, exclusivamente, unidades de atendimento (AC, ACF, AGF, AGC etc.) e o evento, no SRO, estiver relacionado com a fase de postagem de objetos registrados alvo de reclamações;', '', 742),
(4486, 'capitulo', 1, 4484, 4, 'b', 'operacional: quando envolver, exclusivamente, unidades operacionais (CDD, CEE, CTC, CTE, CTCE, CTO etc.) ou quando envolver, simultaneamente, unidades de atendimento e operacional e os eventos, no SRO, estiverem relacionados com as fases de coleta, encaminhamento, distribuição, tratamento de objetos registrados alvo de reclamações.', '', 743),
(4487, 'capitulo', 1, 3745, 2, '2.607', 'Unidade de Atendimento: unidade responsável pela venda de produtos e serviços postais e de produtos e serviços de outras instituições, conforme definido em contratos, acordos ou convênios. A unidade de atendimento pode ser própria ou operada por terceiros.', '', 744),
(4488, 'capitulo', 1, 3745, 2, '2.608', 'Unidade de Tratamento: responsável pelo recebimento, triagem, armazenamento e expedição de objetos postais e/ou mensagens telemáticas.', '', 745),
(4489, 'capitulo', 1, 3745, 2, '2.609', 'Unidade Distribuidora: são todas as unidades responsáveis pela entrega (CDD, CEE ou agências que efetuam distribuição).', '', 746),
(4490, 'capitulo', 1, 3745, 2, '2.610', 'Unidade Operacional: é a unidade que realiza atividades operacionais (coleta, tratamento, armazenamento, expedição distribuição de objetos postais, mensagens telemáticas e cargas unitizadas). São Unidades Operacionais: Agências, Centros de Tratamento, Centros de Distribuição Domiciliária, Centros de Entrega de Encomendas e Centros de Distribuição (Leste e Oeste).', '', 747),
(4491, 'capitulo', 1, 3745, 2, '2.611', 'Unidade Vinculada - UV: é uma Unidade de Correios vinculada a uma IT.', '', 748),
(4492, 'capitulo', 1, 3745, 2, '2.612', 'Unitização:  agrupamento de objetos homogêneos, embalados ou não, em uma unidade adequada à movimentação mecânica e ao transporte, mantido desde o expedidor até o destino da carga.', '', 749),
(4493, 'capitulo', 1, 3745, 2, '2.613', 'Unitizador: recipiente padronizado, destinado a conter e proteger aos objetos postais. Utilizado para agrupamento, movimentação e transporte de carga.', '', 750),
(4494, 'capitulo', 1, 3745, 2, '2.614', 'Usabilidade: é o grau de eficiência com que um usuário do site consegue realizar as tarefas desejadas.', '', 751),
(4495, 'capitulo', 1, 3745, 2, '2.615', 'Usuário: público em geral, potenciais internautas.', '', 752),
(4496, 'capitulo', 1, 3745, 2, '2.616', 'Vale Postal - VP: consiste no pagamento ao remetente do valor recebido do destinatário, referente a um objeto SEDEX a Cobrar postado e entregue pelos Correios.', '', 753),
(4497, 'capitulo', 1, 3745, 2, '2.617', 'Valor de carga adquirida para máquina de franquear: é entendido como sendo o crédito a ser concedido, em acréscimo ao saldo (registrador descendente) da Máquina de Franquear.', '', 754),
(4498, 'capitulo', 1, 3745, 2, '2.618', 'Valor Declarado: serviço adicional pelo qual o cliente declara, se assim o desejar, o valor de um objeto postado com registro, para eventual compensação em caso de extravio, avaria ou espoliação.', '', 755),
(4499, 'capitulo', 1, 4498, 3, '2.618.1', 'É obrigatório nas situações em que incluir um dos seguintes itens:', '', 756),
(4500, 'capitulo', 1, 4499, 4, 'a', 'ouro, platina, bronze ou níquel;', '', 757),
(4501, 'capitulo', 1, 4499, 4, 'b', 'quaisquer metais preciosos;', '', 758),
(4502, 'capitulo', 1, 4499, 4, 'c', 'joias ou artigos preciosos;', '', 759),
(4503, 'capitulo', 1, 4499, 4, 'd', 'cédulas e moedas fora de circulação;', '', 760),
(4504, 'capitulo', 1, 4499, 4, 'e', 'selos ou outras fórmulas de franquia;', '', 761),
(4505, 'capitulo', 1, 4499, 4, 'f', 'quaisquer papéis representativos de valor ao portador.', '', 762),
(4506, 'capitulo', 1, 3745, 2, '2.619', 'Valor do Serviço Contratado - VSC: é o valor mínimo cobrado por cada percurso contratado, em valor médio por remessa equivalente a 2 kg, com o objetivo de garantir a manutenção dos recursos alocados ao contrato. O valor do VSC varia mensalmente em função dos dias da frequência contratada que caírem dentro do ciclo de faturamento, inclusive feriado, e será calculado automaticamente, a cada mês, considerando-se a frequência semanal (ida e volta).', '', 763),
(4507, 'capitulo', 1, 3745, 2, '2.620', 'Venda: processo de persuasão e convencimento do cliente para que o mesmo compre um produto ou serviço da Empresa.', '', 764),
(4508, 'capitulo', 1, 3745, 2, '2.621', 'Vendedor: profissional a quem compete realizar o processo de relacionamento e venda dos produtos e serviços.', '', 765),
(4509, 'capitulo', 1, 3745, 2, '2.622', 'Vinculação de unidade: funcionalidade no SIGMA que permite a uma unidade assumir as operações de malote de outras unidades.', '', 766),
(4510, 'capitulo', 1, 3745, 2, '2.623', 'Vinculação do contrato: ato que estabelece quais unidades operacionais ou de atendimento, próprias ou terceirizadas, serão autorizadas a realizar a captação dos objetos pertinentes ao contrato, ou seja, a sua operacionalização.', '', 767),
(4511, 'capitulo', 1, 4510, 3, '2.623.1', 'O ato de vinculação será estabelecido conforme conveniência da contratante e respeitadas as restrições de natureza logística, financeira ou operacional dos Correios, bem como as normas que regem a comercialização do serviço ou produto.', '', 768),
(4512, 'capitulo', 1, 4510, 3, '2.623.2', 'O ato de vinculação será dispensado quando a operacionalização do contrato exigir a participação indiscriminada da rede de atendimento local, regional ou nacional, caracterizando, nesses casos, operações de guichê típicas de atendimento de varejo.', '', 769),
(4513, 'capitulo', 1, 3745, 2, '2.624', 'Vinculação exclusiva: é aquela em que apenas uma única unidade será autorizada a operacionalizar determinado contrato, por força de conveniência técnica dos Correios.', '', 770),
(4514, 'capitulo', 1, 3745, 2, '2.625', 'Vinheta: é a ilustração adesiva ou impressa mediante processo gráfico específico no objeto postal com a finalidade de promover a divulgação de eventos e campanhas de cunho sociocultural:', '', 771),
(4515, 'capitulo', 1, 4514, 4, 'a', 'não é prevista a postagem em Agências;', '', 772),
(4516, 'capitulo', 1, 4514, 4, 'b', 'formatação operacional especial;', '', 773),
(4517, 'capitulo', 1, 4514, 4, 'c', 'preços customizados que implicam reduzidas margens de lucratividade.', '', 774),
(4518, 'capitulo', 1, 3745, 2, '2.626', 'Visibilidade: exposição da loja nas páginas do CNS.', '', 775),
(4519, 'capitulo', 1, 3745, 2, '2.627', 'Vistoria de conformidade técnica: é a inspeção realizada pelas equipes técnicas de engenharia e de tecnologia à unidade ou a área acessória, com a finalidade de verificar, no todo ou em parte, a conformidade das instalações aos padrões estabelecidos no Projeto de Instalação de AGF/área acessória aprovado pelos Correios, Guias e Especificações Técnicas e proposta técnica.', '', 776),
(4520, 'capitulo', 1, 3745, 2, '2.628', 'Vistoria de conformidade técnica de engenharia: é a visita técnica na qual os profissionais designados pelo órgão regional de gestão de engenharia verificarão a conformidade da AGF/área acessória com os padrões estabelecidos no projeto de instalação (AGF/Área Acessória) aprovado pelos Correios, bem como as especificações constantes nos Guias e Especificações Técnicas correlatos.', '', 777),
(4521, 'capitulo', 1, 3745, 2, '2.629', 'Vistoria de conformidade técnica de TI: é a visita em que os profissionais designados pelo órgão regional de gestão dos recursos de tecnologia verificarão a conformidade da AGF/Área Acessória com os padrões estabelecidos no Guia de Especificações Técnicas, para os equipamentos de informática e para a infraestrutura de tecnologia da informação, necessária ao funcionamento de uma Agência de Correios Franqueada.', '', 778),
(4522, 'capitulo', 1, 3745, 2, '2.630', 'V-Post: solução que engloba o serviço Carta Comercial com os serviços adicionais Produção de Objetos, Registro e AR Digital. É comercializado com ou sem a inclusão de assinatura digital por meio de Certificado Digital.', '', 779),
(4523, 'capitulo', 1, 3745, 2, '2.631', 'A Remessa Expressa Talão de Cheques, Cartões Diversos e Carteira de Identidade Nacional - CIN é o serviço de envio de talões de cheques, cartões diversos e/ou CIN.', '', 780),
(4524, 'capitulo', 1, 3745, 2, '2.632', 'O uso fraudulento de cartão e/ou talão é caracterizado pela utilização por pessoa distinta do seu destinatário enquanto o objeto que encaminha esse conteúdo estiver sob posse dos Correios, sem que haja comunicação tempestiva ao cliente para o bloqueio em caso de sinistro ou comunicação em caso de devolução, no eventual retorno do objeto ao remetente.', '* * * * *', 781),
(4525, 'capitulo', 2, NULL, 1, '1', 'POLÍTICAS E DIRETRIZES', '1.1 Importância e objetivos do serviço postal e telemático\nO Serviço Postal e Telemático constitui-se em um dos mais importantes canais de comunicação, unindo os pontos mais distantes do país. Como fator de integração nacional e internacional, atua de forma decisiva para a aceleração do processo de desenvolvimento da nação. Os Serviços Postais e Telemáticos, explorados pela ECT em regime de monopólio da União, têm os seguintes objetivos:\n1.1.1 A política básica do serviço postal e telemático é promover a entrega dos objetos e mensagens confiados à Empresa, dentro dos padrões previamente estabelecidos, levando-se em conta os imperativos de Rapidez, Segurança e Regularidade.\n1.1.2 A política social do serviço postal é interligar os mais longínquos pontos do país, por meio de comunicação escrita.\n1.1.3 Políticas culturais\n1.1.3.1 Promover a difusão da cultura ao transportar objetos postais e publicações destinadas a abastecer postos de venda, garantindo o encaminhamento e a distribuição desses objetos aos destinatários.\n1.1.3.2 Encaminhar correspondência e publicações destinadas a outros países, assim como distribuir no território nacional esses objetos, quando postados em outros países.\n1.1.4 Políticas econômicas\n1.1.4.1 Estimular o comércio por meio de vendas pelo sistema de reembolso postal e pelo intercâmbio de encomendas, além de divulgar a venda de mercadorias por carta/cartão/envelope encomenda-resposta e do encaminhamento e distribuição de folhetos de propaganda.\n1.1.4.2 Promover a circulação de valores por meio de vales e de remessas com valor declarado de cartas, impressos e encomendas.\n1.2 Políticas e diretrizes quanto a proibições e restrições no serviço postal\n1.2.1 Para serem admitidos no ato da postagem, os objetos postais devem observar determinadas especificações de peso, dimensões, volume, acondicionamento, formato, endereçamento e franqueamento, de acordo com as instruções estabelecidas nas normas em vigor na ECT, previstas em convenções, acordos internacionais ou definidas por lei.\n1.2.2 Além das condições previstas no subitem 1.2.1, fica estabelecido que:\n1.2.2.1 Os objetos destinados a moradores e usuários de edifícios residenciais, comerciais, condomínios, ou qualquer outra coletividade, tais como hospitais, shopping centers, estabelecimentos prisionais, quartéis, associações, estabelecimentos religiosos, etc., não poderão ser aglutinados e endereçados ao porteiro, zelador, síndico ou a qualquer outra pessoa, a fim de que estas efetuem a redistribuição aos vários destinatários.\nExemplo: Envelope endereçado ao porteiro de um edifício contendo faturas para redistribuição aos respectivos moradores.\n1.2.2.1.1 Em caso de apresentação para postagem de objetos aglutinados, o cliente deve ser orientado a promover o desmembramento da carga e a postagem individualizada dos objetos.\n1.2.2.2 Os objetos destinados ao exterior, devem ser admitidos pelo país de destino, conforme orientações contidas na Lista de Objetos Proibidos (LOP), constantes do Mod 6, Cap 4, Item 4 do Manual do Correios Internacional (MANINT).\n1.2.3 Não serão aceitos nem entregues:\na) substância explosiva, radioativa, deteriorável, fétida, nauseante, corrosiva, nociva ou facilmente inflamável ou qualquer outra substância, cujo manuseio ou transporte constitua perigo ou possa causar danos;\nb) animal vivo, exceto os admitidos em acordo ou convenção internacional ratificada pelo Brasil, conforme subitem 1.2.4.4 deste capítulo;\nc) animal morto;\nd) planta viva;\ne) entorpecente e substâncias psicotrópicas, salvo em se tratando de remessa legalmente autorizada, conforme subitem 1.2.4.3 deste capítulo;\nf) objeto cujo conteúdo ou teor atente contra a segurança nacional;\ng) armação de arma de fogo, munições e explosivos de qualquer natureza;\nh) ossos humanos ou de animais;\ni) cinzas humanas ou de animais, exceto restos mortais humanos provenientes de incineração (cremação);\nj) objetos cuja circulação no País, exportação ou importação, estejam proibidas por ato de autoridade competente.\n1.2.4 Objetos aceitos com restrições\n1.2.4.1 Objetos contendo artigos de ouro, platina, prata, bronze, níquel ou qualquer outro metal de valor, cédula e moedas fora de circulação, selos ou qualquer outra fórmula de franqueamento, joias e artigos preciosos ou qualquer papel representativo de valor ao portador só podem ser aceitos mediante DECLARAÇÃO DE VALOR.\n1.2.4.2 A transferência de numerário só é admitida quando efetuada por meio do serviço Vale Postal.\n1.2.4.3 Entorpecentes e substâncias psicotrópicas, desde que com autorização legal ou expedido com finalidade médica ou científica.\n1.2.4.4 Abelhas, sanguessugas, bichos-da-seda, parasitas e predadores de insetos nocivos desde que destinados ao controle desses insetos só podem ser aceitos se estiverem sendo permutados entre instituições reconhecidas oficialmente e embalados em condições apropriadas, sob responsabilidade do cliente.\n1.2.4.5 Armas de fogo, de pressão e simulacros (imitação), suas peças e acessórios, mediante a utilização exclusiva do serviço de Encomenda SEDEX, com uso obrigatório do serviço adicional de Aviso de Recebimento – AR, acompanhadas da Guia de Tráfego expedida pela Diretoria de Fiscalização de Produtos Controlados – DFPC do Ministério da Defesa.\n1.2.4.5.1 A postagem dos objetos indicados no subitem 1.2.4.5 poderá ser realizada por fabricantes nacionais de armas, mediante celebração de contrato especial SEDEX e por clientes sem contrato para retorno ao fabricante em casos de devolução ou manutenção do produto.\n1.2.4.6 Amostras de material biológico humano ou animal, mediante celebração de Anexo Especial de Contrato Múltiplo - Remessa Expressa de Material Biológico e desde que atendam as condições previstas no anexo.\n* * * * *', 0),
