(4535, 'capitulo', 3, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Apresentação dos Objetos nas Unidades de Postagem\n2.1.1 Verificar se a indicação do franqueamento foi efetuada no ângulo superior direito do anverso do objeto.\n2.2 Formas de Franqueamento Postal', 9);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(4536, 'capitulo', 3, NULL, 3, '2.2.1', 'Considerar como formas de franqueamento postal:', 'a) selo postal;\nb) estampa por meio de máquina de franquear;\nc) etiqueta física de registro, a ser colada nos objetos sob registro;\nd) a impressão de marcas fosforescentes com os dizeres \"Correios\" e \"Pré-Franqueado\" utilizada no envelope Pré-Franqueado de Primeiro Porte;\ne) a impressão da expressão \"Pré-Franqueado\" na área central do anverso do envelope específico para encomendas da modalidade SEDEX Estadual Pré-Franqueado;\nf) chancela de franqueamento;\ng) código 2D, do tipo Datamatrix, constante no rótulo de endereçamento padrão ou reduzido, emitido pela Plataforma de Pré-Postagem, que pode ser impresso diretamente no envelope ou em etiqueta autocolante de boa qualidade que deverá ser fixada na correspondência.\nNota: não serão aceitos, para postagem, objetos sem o respectivo franqueamento.\n2.2.2 Considerar como nulo, para efeito de franqueamento:\na) selo obliterado;\nb) selo seccionado;\nc) selo que apresente caracteres ou sinais estranhos à emissão;\nd) selo sujo, desbotado ou lavado;\ne) selo coberto por qualquer substância;\nf) selo aposto de modo a impedir a correta obliteração;\ng) selo retirado de circulação;\nh) selo fixo ou estampado, quando retirado de fórmula de franqueamento;\ni) selo de outro país;\nj) selo não emitido pelos Correios;\nk) selo falso ou falsificado;\nl) selo coberto, em parte, por outro;\nm) estampa 2D inutilizada com sinalização escrita, como por exemplo um “X” aposto por cima da estampa.\n2.2.2.1 Circundar, à tinta, e anotar o numeral zero (0) ao lado do selo adesivo, da estampa de máquina de franquear e chancela que não forem válidos para o franqueamento.\n2.2.2.2 Reter e encaminhar à área de auditoria ou de inspeção, em face do disposto nos Artigos 36, 37, 45 e 46 da Lei nº 6.538/78, o objeto postal portando selos nulos refugado na origem, no caso de selo falso, falsificado ou reutilizado.\n2.2.2.3 Verificar nos objetos e orientar os clientes quanto as seguintes regras:\na) o selo deverá sempre ser colado, pelo próprio cliente, utilizando apenas quantidade suficiente de cola e quando se tratar de objeto simples;\nNota: quando o atendente for solicitado pelo cliente a colar os selos, observar o posicionamento correto: partindo do canto superior direito, em linha, para a esquerda. Havendo necessidade, deve-se iniciar uma segunda linha de selos, seguindo o mesmo sentido; de forma alguma os selos deverão ser sobrepostos no objeto.\nb) havendo mais de um selo, este deverá ser colocado ao lado esquerdo do selo anterior;\nc) a fixação do selo em qualquer outro local prejudica a triagem automática da carta;\nd) o franqueamento à máquina deverá estar contido na área reservada à fixação do selo;\ne) serão considerados como não franqueados:\nI - as cartas e cartões postais que apresentarem o franqueamento no verso;\nII - os objetos franqueados em máquina de franquear, quando a estampa estiver ilegível ou aplicada de forma parcial ou no verso do objeto;\nIII - os objetos sem uma das formas de franqueamento citadas no subitem 2.2.1 deste Capítulo;\nIV - o objeto que não possuir a chancela de franqueamento correspondente ao serviço, conforme descrito nos Anexos 2 e 3 deste Capítulo.\n2.2.3 Utilizar a Chancela de Franqueamento para os serviços prestados mediante contrato, levando em consideração o serviço e a modalidade de entrega, conforme padronização e modelos constantes nos Anexos 2 e 3 deste Capítulo, respectivamente.\nNota: a Mala Direta Básica e Mala Direta Domiciliária poderão utilizar a chancela como forma de franqueamento para postagens à vista.\n2.2.3.1 Franquear as encomendas postais nacionais, fixando a etiqueta autoadesiva do serviço solicitado, conforme especificado no MANCAT 1/2, Anexo 20, no canto superior direito do objeto.\n2.3 Postagem de Objetos por Órgãos dos Correios\n2.3.1 Solicitar, formalmente, à DINEG, autorização de postagem.\n2.3.1.1 Solicitar, ao respectivo departamento gestor do segmento de negócios a chancela para a postagem dos objetos, de acordo com o serviço a ser utilizado.\n2.3.1.1.1 Adotar a Chancela de Franqueamento, sendo necessária a inclusão da seguinte indicação: Postagem Autorizada - DINEG e abaixo a sigla do órgão dos Correios seguida de CS ou SE/XX, conforme disposto no Anexo 3 deste Capítulo.\n2.4 Vinhetas, Selos e Impressões não Postais\n2.4.1 Orientar, aos interessados, sobre os procedimentos a seguir, para a autorização por parte dos Correios:\na) solicitar, à Superintendência Estadual da jurisdição da autorização, com antecedência mínima de 15 (quinze) dias da postagem dos objetos, anexando quatro amostras do modelo, e informando o prazo de utilização;\nb) havendo postagem em localidades jurisdicionadas em mais de uma Superintendência Estadual, solicitar, a que der a autorização, para encaminhar amostras do modelo, para conhecimento das demais;\nc) a organização promotora de feiras de negócios ou festejos locais pode pedir uma autorização para que todas as firmas participantes utilizem vinhetas, selos ou impressões não postais alusivos ao evento;\nd) informar que são proibidas, nas vinhetas, selos e impressões não postais:\nI - reprodução de selos postais nacionais ou estrangeiros;\nII - a impressão da legenda Correios e do valor facial;\nIII - a impressão de desenhos, símbolos ou dizeres indecentes, injuriosos, ameaçadores, ofensivos à moral ou ainda, contrários à ordem pública e aos interesses do país;\nIV - a impressão de desenho ou fotografia de pessoas, assim como a reprodução de obra ou parte de obras dessas pessoas, a menos que o pedido de autorização tenha sido acompanhado de documento comprobatório da anuência delas ou de seus representantes legais;\nV - a impressão de outra estampa 2D na área reservada aos símbolos de franqueamento postal.\n2.4.2 Verificar se as vinhetas, os selos e as impressões e selos não postais foram aplicados no ângulo superior esquerdo do anverso do objeto na área livre para o remetente ou no verso, fora do respectivo fecho, para não serem confundidos com as impressões destinadas ao franqueamento.\n2.4.2.1 Verificar se a vinheta, o selo e a impressão não postal, que possam ser confundidos com os destinados ao franqueamento, foram previamente autorizados pelos Correios e, nesse caso, só podem ser aplicados no verso do objeto fora do respectivo fecho.\n* * * * *', 10),
(4537, 'capitulo', 4, NULL, 1, '1', 'ATRIBUTOS DOS SUBPROCESSOS', '1.1 Objetivo: prestar um serviço que permita a regularização do franqueamento de objetos, simples e registrados no regime nacional, insuficientemente franqueados possibilitando seu encaminhamento e distribuição aos respectivos destinatários.\n1.2 Abrangência: nacional e internacional.\n1.3 Gestor: DPOST/SUCOM.\n1.4 Fornecedores: áreas comercial, operacional e internacional.\n1.5 Clientes: pessoas físicas e jurídicas.\n1.6 Periodicidade: contínua.\n1.7 Duração: prazo indeterminado.', 0),
(4538, 'capitulo', 4, NULL, 1, '2', 'DESCRIÇÃO DOS SUBPROCESSOS', '2.1 Objetos Simples\n2.1.1 Agência de origem\n2.1.1.1 Verificar, no ato da postagem de Carta, Carta Social ou Cartão Postal, se o objeto está devidamente franqueado.\n2.1.1.1.1 Informar ao cliente a insuficiência do franqueamento.\n2.1.1.1.2 Solicitar ao cliente a complementação do valor para que o objeto seja encaminhado normalmente.\n2.1.2 Unidade operacional na origem\n2.1.2.1 Devolver ao remetente Cartas, Cartas Sociais e Cartões Postais, insuficientemente franqueadas e depositadas em caixa de coleta, com aplicação de carimbo indicando o motivo da devolução “outros” e complementando com a anotação “Insuficiência de Franquia”.\n2.1.2.1.1 Tratar os objetos de que trata este subitem como refugo, caso a devolução ao remetente não seja possível em virtude de falta de endereço.\n2.1.2.2 Tratar, como regra geral, o impresso normal insuficientemente franqueado como refugo.\n2.1.2.3 Contatar o remetente, no caso de impresso com devolução garantida ou de impresso urgente, bem como no caso de postagem agrupada de qualquer tipo de impressos simples normais, cuja insuficiência de franqueamento seja detectada ainda na localidade de origem, a fim de complementar o franqueamento.\n2.1.2.3.1 Refugar os objetos, caso o remetente se recuse a pagar o complemento.\n2.1.2.4 Responsabilizar o empregado dos Correios ou o permissionário pela complementação da tarifa de Impresso Simples, quando a insuficiência de franqueamento for constatada na origem e o franqueamento houver sido realizado por meio de máquina de franquear.\n2.1.3 Unidade Operacional no destino\n2.1.3.1 Providenciar o encaminhamento normal e entrega ao destinatário, nos casos de insuficiência de franqueamento de Cartas, Cartas Sociais e Cartões Postais, insuficientemente franqueadas.\n2.1.3.2 Envidar esforços para a reparação da diferença junto à Unidade de Postagem ou ao permissionário de máquina de franquear, sem prejuízo das demais providências administrativas previstas nos contratos de permissão de uso de máquina de franquear e do contrato de Franquia Empresarial.\n2.1.3.3 Emitir uma comunicação para a Unidade de Origem a fim de que observem o correto franqueamento durante a postagem.\n2.1.3.4 Solicitar à Unidade de Origem, nos casos de remetente pessoa jurídica, que entre em contato com o remetente e oriente sobre a correta tarifação do objeto.\n2.2 Objetos registrados\n2.2.1 Unidade operacional de origem\n2.2.1.1 Responsabilizar, como regra geral, pelo pagamento da parte complementar (tarifa menos valor pago) o empregado dos Correios que tiver efetuado o registro quando se verificar insuficiência no franqueamento de objeto registrado.\n2.2.1.2 Solicitar o recolhimento imediato da parte complementar, correspondente à diferença entre a tarifa correta e a que foi cobrada, mediante a aplicação de selos adesivos, estampas de máquina de franquear ou comprovante de franqueamento no próprio objeto, obliterando-os quando for o caso.\n2.2.1.3 Contatar o cliente para complementar a insuficiência de franqueamento, no caso de postagem de grandes clientes, cuja conferência pelo empregado dos Correios é realizada por amostragem.\n2.2.1.4 Adotar as providências, no caso de recebimento de CIE relativa a objeto registrado insuficientemente franqueado postado naquela unidade.\n2.2.1.4.1 Dar ciência ao empregado responsável pela postagem do objeto motivo da CIE.\n2.2.1.4.2 Solicitar ao empregado o recolhimento da diferença mediante a aplicação de selos adesivos, ou estampa de máquina de franquear ou comprovante de franqueamento, no verso da CIE, obliterando-os quando for o caso.\n2.2.2 Unidade de Tratamento\n2.2.2.1 Apor a menção \"T\" no centro da parte superior do anverso do objeto, quando constatada a insuficiência de franqueamento de objeto registrado, durante o encaminhamento do objeto.\n2.2.2.2 Expedir o objeto ao destino, com a menção “T” especificada.\n2.2.3 Unidade Operacional de Destino\n2.2.3.1 Adotar de imediato, nos casos de constatada a insuficiência de franqueamento de objeto registrado ou objeto com a menção “T”, as providências:\n2.2.3.1.1 Extrair Comunicação de Irregularidade na Expedição (CIE), onde anotará o peso real do objeto e a quantia complementar, calculada com base na tarifa em vigor na data da postagem, assinando em seguida.\n2.2.3.1.2 Dar curso normal ao objeto.\n2.2.3.1.3 Efetuar a entrega do objeto, solicitando ao destinatário a sobrecarta que será anexada à CIE, para comprovação junto à origem, da insuficiência.\n2.2.3.1.4 Encaminhar a CIE à Unidade de Origem (com ou sem a sobrecarta).\n* * * * *', 1),
(4539, 'capitulo', 5, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: acondicionar um determinado produto, conferindo segurança ao seu conteúdo e comodidade ao cliente.\n1.2 Abrangência: nacional.\n1.3 Gestor: Departamento de Negócios de Varejo - DEVAR/DINEG.\n1.4 Fornecedores: órgãos do Correios Sede - CS.\n1.5 Clientes: pessoas físicas e jurídicas.\n1.6 Periodicidade: diária.\n1.7 Duração: indeterminado.\n1.8 Vínculo com a Cadeia de Valor: N2 - gestão de produtos.', 0),
(4540, 'capitulo', 5, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO - AQUISIÇÃO NOVOS MODELOS', '2.1 Procedimentos da Área Gestora do Produto', 1),
(4541, 'capitulo', 5, NULL, 3, '2.1.1', 'Demandar a especificação técnica.', '', 2),
(4542, 'capitulo', 5, NULL, 3, '1.1.1', 'Criar arte.', '', 3),
(4543, 'capitulo', 5, NULL, 3, '2.1.2', 'Solicitar criação de código do produto.', '', 4),
(4544, 'capitulo', 5, NULL, 3, '2.1.3', 'Definir quantidade e modelo de aquisição.', '', 5),
(4545, 'capitulo', 5, NULL, 3, '2.1.5', 'Encaminhar à GSUP para produção.', '', 6),
(4546, 'capitulo', 5, NULL, 3, '2.1.6', 'Avaliar a prova de máquina.', '', 7),
(4547, 'capitulo', 5, NULL, 3, '2.1.7', 'Solicitar andamento na contratação.', '', 8),
(4548, 'capitulo', 5, NULL, 3, '2.1.8', 'Elaborar pauta inicial para a validação do Departamento de Atendimento.', '', 9),
(4549, 'capitulo', 5, NULL, 3, '2.1.9', 'Elaborar comunicado para divulgação à Rede.', '2.1.10 Encaminhar a pauta validada para a Central de Gestão de Contratos e Suprimentos.\n2.2 Procedimentos da Área de Cadastro\n2.2.1 Criar código do novo modelo no Enterprise Resource Planning - ERP.\n2.2.2 Encaminhar o código do novo modelo ao Gestor do Produto.\n2.3 Procedimentos da Central de Gestão de Contratos e Suprimentos\n2.3.1 Elaborar especificação técnica.\n2.3.2 Solicitar a entrega do exemplar.\n2.3.3 Receber o exemplar.\n2.3.4 Aprovar o exemplar, pelo seus laboratórios.\n2.3.5 Comunicar o fornecedor sobre a aprovação do exemplar.\n2.3.6 Solicitar a produção.\n2.3.7 Receber a prova de máquina e encaminhar ao gestor do produto.\n2.3.8 Comunicar o fornecedor sobre o resultado da análise da prova de máquina e solicitar entrega do pedido.\n2.3.9 Comunicar os Centros de Logística Integrada Leste e Oeste - CLI Leste/Oeste para a aceitação do material.\n2.3.10 Encaminhar a pauta para os Centros de Logística Integrada Leste e Oeste - CLI Leste/Oeste realizarem a distribuição.\n2.4 Procedimentos nos Centros de Logística Integrada - CLIs (Leste e Oeste)\n2.4.1 Receber a pauta inicial da CEGES.\n2.4.2 Receber a carga do fornecedor.\n2.4.3 Avaliar amostra.\n2.4.4 Incorporar ao estoque.\n2.4.5 Receber a pauta de distribuição inicial.\n2.4.6 Separar e encaminhar os produtos conforme pauta.\n2.5 Procedimentos do Departamento de Atendimento\n2.5.1 Validar a pauta de distribuição inicial.\n2.5.2 Publicar comunicado.\n2.6 Procedimentos das Agências\n2.6.1 Receber as embalagens da pauta inicial do Centros de Logística Integradas - CLI Leste e Oeste.\n2.6.2	Conferir a quantidade física das embalagens recebidas com a quantidade lançada na Pauta de Suprimento - PS.\n2.6.3 Dar aceite à Pauta de Suprimento no Sistema de Automação da Rede de Atendimento - SARA.\n2.6.4	Arquivar a pauta de suprimento na unidade.\n2.6.5 Suprir os guichês de atendimento.\n2.6.6 Realizar a venda.\n2.6.7 Gerir o estoque conforme demanda da unidade.\n2.6.8 Solicitar suprimento sempre que necessário, via SISCAP.\n* * * * *', 10),
(4550, 'capitulo', 6, NULL, 1, '1', 'ATRIBUTO DO SUBPROCESSO', '1.1 Objetivo: facilitar a comunicação entre pessoas, mediante a oferta de produtos com caráter de mensagem atual e pessoal.\n1.2 Abrangência: nacional.\n1.3 Gestor: Departamento de Varejo - DEVAR.\n1.4 Fornecedores: órgãos do Correios Sede – CS.\n1.5 Clientes: pessoas físicas e jurídicas.', 0),
(4551, 'capitulo', 6, 4550, 2, '1.6', 'Periodicidade: anual.', '1.7 Duração: 6 a 8 meses.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', 1),
(4552, 'capitulo', 6, NULL, 1, '2', 'DESCRIÇAO DO SUBPROCESSO', '2.1 Procedimentos para atendimento:', 2),
