(4554, 'capitulo', 6, 4552, 4, 'b', 'selecionar, no SARA, o produto para o qual se deseja realizar a venda;', '', 4),
(4555, 'capitulo', 6, 4552, 4, 'c', 'entregar o ticket ao cliente;', '', 5),
