(4557, 'capitulo', 6, 4552, 2, '2.2', 'Procedimentos do DEVAR/DINEG', '', 7),
(4558, 'capitulo', 6, 4557, 3, '2.2.1', 'Gerir o serviço conforme MANORG 8/6.', 'Nota: considerando a aprovação de descontinuidade dos produtos Aerograma Comemorativo/Nacional e Cartão Comemorativo, a comercialização se dará apenas até o dia 31 de dezembro de 2021.\n* * * * *', 8),
(4559, 'capitulo', 7, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(4560, 'capitulo', 7, 4559, 2, '1.1', 'Objetivo: firmar parceria com empresas a fim de comercializar seus produtos e/ou serviços na rede de atendimento dos Correios, conforme características descritas na nota 2 deste capítulo.', '', 1),
(4561, 'capitulo', 7, 4559, 2, '1.2', 'Abrangência: Nacional', '', 2),
(4562, 'capitulo', 7, 4559, 2, '1.3', 'Gestor: Departamento de Negócios de Varejo – DEVAR', '', 3),
(4563, 'capitulo', 7, 4559, 2, '1.4', 'Fornecedores: área de tecnologia, área de relacionamento com o cliente, área de precificação, área financeira, área de suprimento e área jurídica.', '', 4),
(4564, 'capitulo', 7, 4559, 2, '1.5', 'Clientes: pessoas físicas e jurídicas', '', 5),
(4565, 'capitulo', 7, 4559, 2, '1.6', 'Periodicidade: sob demanda', '', 6),
(4566, 'capitulo', 7, 4559, 2, '1.7', 'Duração: de acordo com o contrato', '', 7),
(4567, 'capitulo', 7, 4559, 2, '1.8', 'Vínculo com a Cadeia de Valor:  N2 - gerir produtos e serviços', '', 8),
(4568, 'capitulo', 7, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(4569, 'capitulo', 7, 4568, 2, '2.1', 'Procedimentos da área de tecnologia', '', 10),
(4570, 'capitulo', 7, 4569, 3, '2.1.1', 'Disponibilizar sistemas que permitam a integração entre os sistemas dos clientes e dos Correios.', '', 11),
(4571, 'capitulo', 7, 4569, 3, '2.1.2', 'Dar suporte no desenvolvimento e manutenção de sistemas que ofereçam a integração e   viabilizem a comercialização dos produtos/serviços de terceiros pelos Correios.', '', 12),
(4572, 'capitulo', 7, 4568, 2, '2.2', 'Procedimentos da área de relacionamento com o cliente', '', 13),
(4573, 'capitulo', 7, 4572, 3, '2.2.1', 'Identificar oportunidades de negócios com base nas necessidades do mercado e dos clientes, endereçando às áreas pertinentes nos Correios para avaliação de viabilidade da formatação e disponibilização do produto/serviço.', '', 14),
(4574, 'capitulo', 7, 4572, 3, '2.2.2', 'Realizar tratativas com o cliente para formalização do contrato e as atividades inerentes da gestão contratual e de relacionamento.', '', 15),
(4575, 'capitulo', 7, 4572, 3, '2.2.3', 'Gerir contratos comerciais de negócios no que se refere às comunicações necessárias (vigência, termos aditivos de renovações e reajustes, alteração de representante legal, endereço, etc).', '', 16),
(4576, 'capitulo', 7, 4572, 3, '2.2.4', 'Estabelecer com o parceiro comercial a pauta de distribuição de produtos e/ou insumos necessários à comercialização, de acordo com validação do departamento gestor da rede de atendimento.', '', 17),
(4577, 'capitulo', 7, 4572, 3, '2.2.5', 'Captar propostas para campanhas de vendas dos produtos e/ou serviços de terceiros sob sua gestão e enviar para área gestora do processo no departamento de vendas.', '', 18),
(4578, 'capitulo', 7, 4572, 3, '2.2.6', 'Analisar resultados de vendas e realizar reuniões com cliente para avaliação de performance e proposição de planos de ações.', '', 19),
(4579, 'capitulo', 7, 4572, 3, '2.2.7', 'Avaliar faturamento do cliente e realizar as tratativas para correções e ajustes, quando necessário.', '', 20),
(4580, 'capitulo', 7, 4568, 2, '2.3', 'Procedimentos da área de precificação', '', 21),
(4581, 'capitulo', 7, 4580, 3, '2.3.1', 'Apresentar hipóteses de preços e/ou comissões sobre os produtos/serviços comercializados.', '', 22),
(4582, 'capitulo', 7, 4580, 3, '2.3.2', 'Gerar os códigos dos produtos e cadastrá-los nos sistemas corporativos dos Correios.', '', 23),
(4583, 'capitulo', 7, 4568, 2, '2.4', 'Procedimentos da área financeira', '', 24),
(4584, 'capitulo', 7, 4583, 3, '2.4.1', 'Efetuar faturamento do parceiro.', '', 25),
(4585, 'capitulo', 7, 4583, 3, '2.4.2', 'Efetuar o repasse/pagamento ao terceiro/parceiro.', '', 26),
(4586, 'capitulo', 7, 4583, 3, '2.4.3', 'Registrar informações contábeis referente aos produtos.', '', 27),
(4587, 'capitulo', 7, 4568, 2, '2.5', 'Procedimentos da área de suprimento', '', 28),
(4588, 'capitulo', 7, 4587, 3, '2.5.1', 'Receber e conferir as quantidades dos produtos, observando o disposto no MANCAT 5/5/2.', '', 29),
(4589, 'capitulo', 7, 4587, 3, '2.5.2', 'Gerir os estoques de produtos e distribui-los às unidades de venda (Agências).', '', 30),
(4590, 'capitulo', 7, 4587, 3, '2.5.3', 'Manter o gestor do produto informado quanto aos níveis de estoque, quantitativo de produtos rejeitados e acerca de recusa no seu recebimento.', '', 31),
(4591, 'capitulo', 7, 4587, 3, '2.5.4', 'Orientar os procedimentos de recolhimento/devolução e/ou alijamento/destruição de produtos.', '', 32),
(4592, 'capitulo', 7, 4568, 2, '2.6', 'Procedimentos da área jurídica', '', 33),
(4593, 'capitulo', 7, 4592, 3, '2.6.1', 'Emitir parecer jurídico.', '', 34),
(4594, 'capitulo', 7, 4592, 3, '2.6.2', 'Chancelar documentos de instrumento contratual.', 'Nota 1: os produtos/serviços de terceiros não poderão ter preços superiores aos praticados pelo parceiro no mercado.\nNota 2: os produtos/serviços de terceiros a serem comercializados nas Agências de Correios terão como características os itens citados abaixo:', 35),
(4595, 'capitulo', 7, 4594, 4, 'a', 'qualidade compatível com exigências do mercado;', '', 36),
(4596, 'capitulo', 7, 4594, 4, 'b', 'respeito ao meio ambiente;', '', 37),
(4597, 'capitulo', 7, 4594, 4, 'c', 'incentivo às inciativas de promoção social;', '', 38),
(4598, 'capitulo', 7, 4594, 4, 'd', 'valorização da diversidade étnica e cultural brasileira;', '', 39),
(4599, 'capitulo', 7, 4594, 4, 'e', 'divulgação e intercâmbio da cultura regional brasileira;', '', 40),
(4600, 'capitulo', 7, 4594, 4, 'f', 'atualização: antecipação das tendências de consumo.', 'Nota: o detalhamento da operacionalização de cada produto/serviço de terceiros será especificado no Resumo de Serviços Especiais (RSE), publicado na intranet do Departamento de Varejo (DEVAR).\n* * * * *', 41),
(4601, 'capitulo', 8, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(4602, 'capitulo', 8, 4601, 2, '1.1', 'Objetivo: orientar as áreas comerciais e operacionais sobre os procedimentos gerais a serem realizados na prestação dos serviços postais de Mensagem e Marketing', '', 1),
(4603, 'capitulo', 8, 4601, 2, '1.2', 'Abrangência: nacional.', '', 2),
(4604, 'capitulo', 8, 4601, 2, '1.3', 'Gestor: Departamento de Gestão de Produtos Nacionais - DEPRO/SUPRO.', '', 3),
(4605, 'capitulo', 8, 4601, 2, '1.4', 'Fornecedores: Órgãos de gestão comercial e operacional.', '', 4),
(4606, 'capitulo', 8, 4601, 2, '1.5', 'Clientes: atendentes comerciais, força de vendas, operadores de distribuição.', '', 5),
(4607, 'capitulo', 8, 4601, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4608, 'capitulo', 8, 4601, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4609, 'capitulo', 8, 4601, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', '', 8),
(4610, 'capitulo', 8, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(4611, 'capitulo', 8, 4610, 2, '2.1', 'Procedimentos do Órgão Responsável pela Postagem', '', 10),
(4612, 'capitulo', 8, 4611, 3, '2.1.1', 'Realizar as verificações no ato da postagem:', '', 11),
(4613, 'capitulo', 8, 4612, 4, 'a', 'se o franqueamento dos objetos atende ao estabelecido no MANCAT 3/1;', '', 12),
(4614, 'capitulo', 8, 4612, 4, 'b', 'se as condições gerais de aceitação de objetos quanto ao peso, natureza do conteúdo, dimensões, formato, endereçamento e proibições estão sendo atendidas;', '', 13),
(4615, 'capitulo', 8, 4612, 4, 'c', 'se as regras de negócio estabelecidas para o serviço estão sendo atendidas;', '', 14),
(4616, 'capitulo', 8, 4612, 4, 'd', 'se o Cartão de Postagem do cliente está vigente e a unidade autorizada para receber a carga, no caso dos serviços prestados mediante contrato.', 'Nota 1: no caso de irregularidades, a postagem não deverá ser aceita.\nNota 2: quando os objetos em volume tiver as mesmas características, deverá realizar a verificação por amostragem, conforme prevista na regra do serviço postal.\nNota 3: no caso de serviço(s) adicional(is) não inerente(s) ao serviço postal, consultar os adicionais no MANCAT 7/1/2.', 15),
(4617, 'capitulo', 8, 4611, 3, '2.1.2', 'Lançar, obrigatoriamente, no sistema de postagem, no respectivo código de serviço, os objetos apresentados pré-franqueados por meio de selo, inclusive os oriundos de coleta.', '2.1.2.1 Obliterar os selos, no ato da postagem (agências), devendo abranger o maior número de selos possível.\nNota: não poderá haver sobreposição de obliteração sobre um mesmo selo.', 16),
(4618, 'capitulo', 8, 4611, 3, '2.1.3', 'Informar o horário limite de postagem da unidade para encaminhamento dos objetos no mesmo dia, o qual deverá ser rigorosamente obedecido.', '', 17),
(4619, 'capitulo', 8, 4611, 3, '2.1.4', 'Informar, ao cliente, as regras previstas para o serviço quando solicitado.', '', 18),
(4620, 'capitulo', 8, 4610, 2, '2.2', 'Prazos de Guarda', '', 19),
(4621, 'capitulo', 8, 4620, 3, '2.2.1', 'Observar os prazos de guarda previstos para cada serviço postal, estabelecido no MANCAT 6/1/2.', '', 20),
(4622, 'capitulo', 8, 4610, 2, '2.3', 'Prazos de Entrega', '', 21),
(4623, 'capitulo', 8, 4622, 3, '2.3.1', 'Observar as regras dos prazos de entrega constantes no MANNEG 6/3 - Gestão dos Prazos dos Produtos. ', '', 22),
(4624, 'capitulo', 8, 4610, 2, '2.4', 'Limites de Dimensões e de Peso, Embalagem e Acondicionamento, Padronização de Envelopes, Leiaute dos Objetos e Regras de Endereçamento - Mensagem e Marketing Direto', '', 23),
(4625, 'capitulo', 8, 4624, 3, '2.4.1', 'Observar as regras constantes no anexo 4 deste capítulo.', '', 24),
(4626, 'capitulo', 8, 4610, 2, '2.5', 'Premissas, Áreas de Precificação e Abrangência', '', 25),
(4627, 'capitulo', 8, 4626, 3, '2.5.1', 'Observar as regras de abrangência constantes no anexo 5 deste capítulo.', '* * * * *', 26),
(4628, 'capitulo', 9, NULL, 1, '1', 'ATRIBUTOS DOS SUBPROCESSOS', '', 0),
(4629, 'capitulo', 9, 4628, 2, '1.1', 'Objetivo: prestar o serviço de correspondência, sob a forma de comunicação escrita, de natureza administrativa, social, comercial ou qualquer outra, que contenha informação de interesse específico do destinatário.', '', 1),
(4630, 'capitulo', 9, 4628, 2, '1.2', 'Abrangência: nacional.', '', 2),
(4631, 'capitulo', 9, 4628, 2, '1.3', 'Gestor: DEPRO/DINEG', '', 3),
(4632, 'capitulo', 9, 4628, 2, '1.4', 'Fornecedores: área comercial e operacional.', '', 4),
(4633, 'capitulo', 9, 4628, 2, '1.5', 'Clientes: pessoas físicas e jurídicas.', '', 5),
(4634, 'capitulo', 9, 4628, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4635, 'capitulo', 9, 4628, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4636, 'capitulo', 9, 4628, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', '', 8),
(4637, 'capitulo', 9, NULL, 1, '2', 'DESCRIÇÃO DOS SUBPROCESSOS', '', 9),
(4638, 'capitulo', 9, NULL, 3, '2.1.1', 'Procedimentos Gerais da Rede de Atendimento e Área Comercial', '2.1.1.1 Orientar o cliente sobre as características dos tipos de Carta (Carta, Carta Comercial, Carta Mapa Quadra e Carta Social).\nNota: as características desses tipos de Carta constam do Anexo 2 ao 5 deste Capítulo.\n2.1.1.2 Orientar o cliente sobre as características do Cartão Postal constantes do Anexo 6 deste Capítulo.', 10),
(4639, 'capitulo', 9, 4637, 2, '2.2', 'Carta à Vista (sem contrato)', '', 11),
(4640, 'capitulo', 9, 4639, 3, '2.2.1', 'Procedimento da Rede de Atendimento', '2.2.1.1 Orientar o cliente sobre as características da Carta, constante do Anexo 2 deste Capítulo.', 12),
(4641, 'capitulo', 9, 4639, 3, '2.2.2', 'Procedimento da Área Operacional', '2.2.2.1 Providenciar, obrigatoriamente, o registro das cartas postadas sob registro no Sistema de Rastreamento de Objetos - SRO dos Correios.', 13),
(4642, 'capitulo', 9, 4637, 2, '2.3', 'Carta Comercial a Faturar (prestada mediante contrato)', '', 14),
(4643, 'capitulo', 9, 4642, 3, '2.3.1', 'Procedimento da Área Comercial', '2.3.1.1 Orientar o cliente sobre as características da Carta Comercial, constante do Anexo 3 deste Capítulo.', 15),
(4644, 'capitulo', 9, 4642, 3, '2.3.2', 'Procedimentos do Órgão de Contratação', '2.3.2.1 Observar o disposto no MANCAT 28.\n2.3.2.2 Firmar contrato exclusivamente com pessoa jurídica que, comprovadamente, mediante prévia validação do órgão de vendas da SE, tenha condições de atender aos critérios constante do Anexo 3 deste Capítulo.', 16),
(4645, 'capitulo', 9, 4637, 2, '2.4', 'Postagem - Carta Comercial', '', 17),
(4646, 'capitulo', 9, 4645, 3, '2.4.1', 'Procedimento da Área Operacional', '2.4.1.1 Observar as regras contidas no Anexo 3 para postagem da Carta Comercial.', 18),
(4647, 'capitulo', 9, 4637, 2, '2.5', 'Carta Social (sem contrato)', '', 19),
(4648, 'capitulo', 9, 4647, 3, '2.5.1', 'Procedimento da Rede de Atendimento', '2.5.1.1 Orientar o cliente sobre as características da Carta Social, constante do Anexo 5 deste Capítulo.', 20),
(4649, 'capitulo', 9, 4637, 2, '2.6', 'Prazo de Guarda', '', 21),
(4650, 'capitulo', 9, 4649, 3, '2.6.1', 'Procedimento da Área Operacional', '2.6.1.1 Observar o disposto no MANCAT 6/1, Anexo 2, para o prazo de guarda dos objetos.', 22),
(4651, 'capitulo', 9, 4637, 2, '2.7', 'Devolução de Objetos', '', 23),
(4652, 'capitulo', 9, 4651, 3, '2.7.1', 'Procedimentos da Área Operacional', '2.7.1.1 Restituir os objetos cujas entregas não tenham sido possíveis aos respectivos remetentes, com a informação do motivo da não entrega, conforme regras dispostas MANDIS 2/3.\n2.7.1.2 Admitir, para objetos registrados, a devolução imediata ao remetente, quando da eventual não entrega do objeto, observados os seguintes critérios descrito no Anexo 3.\n2.7.1.3 Enviar ao cliente, caso ele tenha optado pela Devolução Eletrônica da Carta Simples ou Registrada a faturar, a informação eletrônica dos motivos da não entrega, devendo os objetos ser refugados.\n* * * * *', 24),
(4653, 'capitulo', 10, NULL, 1, '1', 'ATRIBUTOS DOS SUBPROCESSOS', '1.1 Objetivo: prestar serviço que permita o encaminhamento e a distribuição de objetos contendo literatura para uso de deficientes visuais e instituições de cegos oficialmente reconhecidas, auxiliando os cegos a superarem suas limitações na comunicação.\n1.2 Abrangência: nacional e internacional.\n1.3 Gestor: Departamento de Gestão de Produtos Nacionais - DEPRO/DINEG.\n1.4 Fornecedores: áreas comercial, operacional e internacional.\n1.5 Clientes: deficientes visuais e instituições de cegos oficialmente reconhecidas.\n1.6 Periodicidade: contínua.\n1.7 Duração: prazo indeterminado.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços', 0),
(4654, 'capitulo', 10, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos da Área de Atendimento\n2.1.1 Receber os objetos abertos.\n2.1.2 Verificar se o objeto atende às condições para aceitação, previstas no Anexo 2, deste Capítulo.\n2.1.3 Fechar/lacrar os objetos.\n2.1.4 Apor a menção Cecograma, em caixa-alta, no canto inferior esquerdo do objeto.\n2.1.5 Apor o carimbo da Agência no invólucro.\n2.1.6 Tratar o Cecograma, obrigatoriamente, como objeto simples e não urgente.\n2.1.7 Permitir, caso solicitado, o uso do serviço adicional Transcrição - Braille, disposto no MANCAT 7/14, Anexo 2.\n2.1.8 Observar as orientações do MANCAT 12/1, Anexo 3, para os casos de postagem internacional.\n2.1.9 Isentar o cliente do pagamento do preço de franqueamento.\n2.1.9.1 Cobrar apenas o valor do adicional, caso o cliente opte pelo serviço adicional Transcrição - Braille.\n2.1.10 Encaminhar o Cecograma ao respectivo destinatário, conforme normas em vigor.\n* * * * *', 1),
(4655, 'capitulo', 11, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(4656, 'capitulo', 11, 4655, 2, '1.1', 'Objetivo: estabelecer padrão de atendimento às demandas dos clientes no que se refere à classificação de seus objetos, bem como os limites e prerrogativas de ação das Unidades dos Correios que, ao longo do fluxo postal, se deparam com objetos classificados como de interesse geral ou de um grupo de pessoas.', '', 1),
(4657, 'capitulo', 11, 4655, 2, '1.2', 'Abrangência: nacional.', '', 2),
(4658, 'capitulo', 11, 4655, 2, '1.3', 'Gestor: DPOST/SUCOM.', '', 3),
(4659, 'capitulo', 11, 4655, 2, '1.4', 'Fornecedores: Agências/Unidades de Atendimento (próprias e franqueadas), todas as posições de atendimento ao cliente da Força de Vendas e todas as Gerências de Atendimento, Vendas/Suporte e Relacionamento com o cliente, quando da classificação de objetos para postagem nos serviços Mala Direta Normal e Urgente, Mala Direta Básica, Mala Direta Domiciliária, Mala Direta Especial, Impresso Normal e Urgente.', '', 4),
(4660, 'capitulo', 11, 4655, 2, '1.5', 'Clientes: remetentes, unidades operacionais de captação e unidades de postagem.', '', 5),
(4661, 'capitulo', 11, 4655, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4662, 'capitulo', 11, 4655, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4663, 'capitulo', 11, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 8),
(4664, 'capitulo', 11, 4663, 2, '2.1', 'Procedimentos gerais de atendimento e classificação de Objetos Postais', '', 9),
(4665, 'capitulo', 11, 4664, 3, '2.1.1', 'Receber do cliente de carteira, corporativo, estratégico ou de varejo, o pedido de classificação de objeto para fins de postagem como comunicação dirigida de interesse geral, conforme definição do glossário deste manual, com dois modelos da peça a verificar.', '', 10),
(4666, 'capitulo', 11, 4664, 3, '2.1.2', 'Analisar e classificar os objetos na presença do cliente ou imediatamente após à solicitação, quer seja com a apresentação do objeto a ser postado quer seja imagem de arquivo eletrônico, com o suporte técnico, se preciso, da gerência de subordinação imediata da unidade de atendimento, da força de vendas ou área de suporte a vendas da Superintendência Estadual - SE.', '', 11),
(4667, 'capitulo', 11, 4664, 3, '2.1.3', 'Informar ao cliente da classificação de seus objetos até D+0 para os objetos que precisarem de apoio técnico e que foram apresentados até às 12h. Objetos apresentados após às 12h, que requeiram apoio técnico na classificação, o prazo será de D+1.', 'NOTA: as regras de classificação do impresso, da mala direta e suas modalidades são idênticas, com variação apenas das condições de aceitação, pagamento e faturamento das postagens.', 12),
(4668, 'capitulo', 11, 4664, 3, '2.1.4', 'Verificar se o objeto atende às todas as condições previstas nos Anexos deste Capítulo.', '2.1.5 Analisar apenas o texto do objeto quando da classificação.\nNOTA: as expressões, contidas no objeto, do tipo: carta, carta-circular, memorando, convite pessoal, confidencial, urgente etc., independente de estarem numeradas ou não, são aceitas como impresso/mala direta, desde que o respectivo conteúdo caracterize-se como impresso/mala direta, observadas as disposições contidas nos anexos deste Capítulo.\n2.1.6 Solicitar ao cliente, no caso de peças que apresentem texto em outro idioma, a tradução correspondente para fins de avaliação e classificação.\nNOTA: em se tratando de livros e revistas, os objetos serão aceitos com respaldo na previsão contratual que dispõe da não aceitação e entrega de objetos enquadrados no Art. 13 da Lei Postal nº 6.538/1978.', 13),
(4669, 'capitulo', 11, 4664, 3, '2.1.7', 'Verificar ainda se o objeto atende às condições específicas de cada serviço, conforme regras contratuais ou constantes nos capítulos específicos deste manual e orientar o cliente quanto à adequação se for o caso.', '', 14),
(4670, 'capitulo', 11, 4664, 3, '2.1.8', 'Verificar se o objeto atende aos padrões de apresentação, endereçamento, formato e dimensões admitidas nos objetos de comunicação dirigida, conforme MANCAT 1/12, Anexo 26, e orientar o cliente se for o caso.', 'NOTA: a avaliação dos padrões, dimensões e leiaute (disposição das chancelas, endereçamento, motivos de devolução), bem como das condições de aceitação, acondicionamento, brindes e amostras e impacto dos objetos no fluxo operacional, está contida no subprocesso de classificação de que trata este capítulo.', 15),
(4671, 'capitulo', 11, 4664, 3, '2.1.9', 'Verificar e informar, ao cliente, as condições de precificação e tarifa combinada, quando da classificação do conjunto (Impresso + Carta ou Mala Direta + Carta), de acordo com as especificações dos serviços envolvidos, se for o caso.', '', 16),
(4672, 'capitulo', 11, 4664, 3, '2.1.10', 'Verificar se os objetos contendo amostras ou brindes estejam de acordo com as condições de apresentação, acondicionamento, dimensões e permissões previstas e planejar junto à área operacional a melhor forma de escoar a carga, de modo a diminuir os impactos no processo produtivo operacional.', '', 17),
(4673, 'capitulo', 11, 4664, 3, '2.1.11', 'Aplicar carimbo de classificação/correção, conforme consta no Anexo 8 deste Capítulo, tanto no envelope quanto no conteúdo, em todas as páginas do objeto, exceto quando se tratar de publicações.', 'NOTA: no caso de peças, cuja resposta de classificação seja eletrônica, o e-mail de classificação, junto com o arquivo PDF da peça, substituirá o carimbo.', 18),
(4674, 'capitulo', 11, 4664, 3, '2.1.12', 'Reter um exemplar da peça classificada para arquivo local e entregar o outro ao cliente, orientando-o a apresentá-lo no momento da postagem, sempre que necessário.', '', 19),
(4675, 'capitulo', 11, 4664, 3, '2.1.13', 'Enviar solicitação ou pedido de classificação, em caso de dúvidas quanto à classificação do objeto, com imagem digitalizada, fundamentado, especificando o respectivo item deste documento que gerou dúvida, à área de subordinação imediata, conforme Anexo 2 deste Capítulo.', '', 20),
(4676, 'capitulo', 11, 4664, 3, '2.1.14', 'Receber retorno da classificação solicitada, com análise de teor.', '', 21),
(4677, 'capitulo', 11, 4664, 3, '2.1.15', 'Verificar a concordância ou não do cliente quanto à classificação da peça.', '2.1.16 Enviar e-mail com imagem ou fax, Anexo 9 deste Capítulo (modelo de e-mail alerta de classificação de objeto), somente das peças que geraram dúvidas na classificação, quando o agente de classificação não for unidade de postagem, informando a classificação de determinada peça para ciência da unidade de postagem/captação da carga.\n2.1.17 Arquivar somente as peças que geraram dúvidas na classificação, para eventuais consultas necessárias.', 22),
(4678, 'capitulo', 11, 4664, 3, '2.1.18', 'Encerrar o processo nos casos em que o cliente não concorde com a classificação atribuída ao objeto, informando-o de que a postagem de objetos classificados como carta é exclusividade dos Correios, por conta do monopólio postal da União.', '', 23),
(4679, 'capitulo', 11, 4664, 3, '2.1.19', 'Cumprir os subitens 2.1.6 e 2.1.7 deste capítulo para os casos em que a área de subordinação imediata classificou o teor do objeto em acordo com a solicitação do cliente, ou seja, como Impresso/Mala Direta.', '', 24),
(4680, 'capitulo', 11, 4664, 3, '2.1.20', 'Enviar e-mail com imagem ou fax para a unidade de postagem/captação da carga quando se tratar de objeto para o qual foi autorizado a inclusão de Serviço de Resposta de contratante diferente, conforme previsto na alínea “f” do item 2 do Anexo 4 deste Capítulo.', '', 25),
(4681, 'capitulo', 11, 4663, 2, '2.2', 'Procedimentos específicos de atendimento e classificação de Objetos Postais', '', 26),
(4682, 'capitulo', 11, 4681, 3, '2.2.1', 'A cargo da Unidade de Atendimento', '2.2.1.1 Efetuar a postagem, uma vez recebido o “de acordo” do cliente quanto à classificação efetuada, em casos de peças para as quais solicitou apoio na classificação.', 27),
(4683, 'capitulo', 11, 4681, 3, '2.2.1', 'A cargo da Força de Vendas/Área de Suporte a Vendas ou equivalente', '2.2.1.1 Avaliar a necessidade da emissão de Avaliação Técnica Comercial - ATC para a peça a ser classificada.\n2.2.1.2 Elaborar a Avaliação Técnica - ATC, se necessário, e encaminhar à centralizadora de vinculação operacional definida em contrato as amostras para validação das condições de mecanização e leitura do CEPNet, endereçamento e emissão da Avalição Técnica Operacional - ATO.\n2.2.1.3 Receber retorno quanto à emissão da Avaliação Técnica Operacional - ATO e demandar ajustes nos objetos, ao cliente, se for caso.', 28),
(4684, 'capitulo', 11, 4663, 2, '2.3', 'A Cargo da Área de Subordinação Imediata das Unidades de Atendimento, Força de Vendas e Suporte a Vendas ou Equivalente', '', 29),
(4685, 'capitulo', 11, 4684, 3, '2.3.1', 'Prestar suporte à classificação de objetos oriundos das unidades de atendimento e força de vendas e suporte a vendas, em caso de dúvidas desses agentes.', '', 30),
(4686, 'capitulo', 11, 4684, 3, '2.3.2', 'Enviar solicitação ou pedido de classificação, devidamente fundamentado à equipe de classificação de objetos, caso não consiga sanar as dúvidas quanto à classificação.', 'NOTA 1: a equipe de classificação é caracterizada pela ação eventual de um conjunto de empregados para deliberar sobre a classificação de objetos, atuando com órgão decisor para classificação.\nNOTA 2: essa equipe de classificação deve ser composta pela participação de representantes da força de vendas, área de suporte a vendas e atendimento aos clientes, coordenada pela gerência de subordinação imediata da área de vendas da unidade ou equivalente.', 31),
(4687, 'capitulo', 11, 4684, 3, '2.3.3', 'Devolver ao demandante a peça com a devida classificação.', '2.3.4 Para os serviços que permitem a celebração de contrato com profissional liberal, sua identificação na chancela deverá ser pelas iniciais de seu nome.\n2.3.5 Orientar o cliente que não serão aceitos, para postagem, objetos sem o devido franqueamento, bem como os motivos que os objetos serão considerados como não franqueados, conforme previsto no MANCAT 3/1.\n2.3.6 Assegurar que as solicitações de autorizações mencionadas no subitem 2.2.3.4 deste capítulo seja apresentada, pelo cliente, em papel timbrado, e que contenham a quantidade de objetos, o período de postagem, o tipo da não conformidade e o compromisso de adequação aos padrões do serviço contratado na próxima postagem, de modo a evitar retrabalhos e atrasos no processo de classificação e postagem dos objetos.\n2.3.7 Informar eventuais autorizações à área operacional, de modo a manter o fluxo das postagens, em especial às gerências de captação de carga de grandes clientes.', 32),
(4688, 'capitulo', 11, 4663, 2, '2.4', 'A Cargo da GCCAP, CTC ou Equivalente', '', 33),
(4689, 'capitulo', 11, 4688, 3, '2.4.1', 'Não recepcionar a carga sem o respectivo franqueamento estabelecido para o serviço.', '', 34),
(4690, 'capitulo', 11, 4688, 3, '2.4.2', 'Receber, conforme subitem 2.1.7 deste Capítulo, imagens dos objetos classificados.', '', 35),
(4691, 'capitulo', 11, 4688, 3, '2.4.3', 'Questionar eventuais divergências de critérios de classificação identificadas junto ao remetente da imagem, com base nos Anexos 3 a 7 deste Capítulo.', '', 36),
(4692, 'capitulo', 11, 4688, 3, '2.4.4', 'Solicitar, no ato da postagem, ao cliente e/ou ao representante comercial responsável pelo contrato na SE, em caso de dúvidas quanto à classificação, e caso não tenha histórico de postagens do cliente como Impresso/Mala Direta, o exemplar ou imagem com carimbo de aprovação para verificação.', '', 37),
(4693, 'capitulo', 11, 4688, 3, '2.4.5', 'Verificar se os objetos apresentados para postagem conferem com o exemplar ou imagem disponibilizada, caso haja dúvidas.', '', 38),
(4694, 'capitulo', 11, 4688, 3, '2.4.6', 'Contatar o responsável pelo contrato na SE, caso o objeto apresentado para postagem seja diferente do recebido pela unidade de postagem/captação.', '', 39),
(4695, 'capitulo', 11, 4688, 3, '2.4.7', 'Informar, ao responsável pelo contrato na SE, que deverá definir e informar as medidas de exceção/autorização em D+0, prazo em que a carga poderá ficar armazenada na unidade, para que sejam adotadas as medidas necessárias junto ao cliente.', 'NOTA 1: esse prazo é necessário face à inexistência de espaço para armazenagem nas unidades de captação, ao fato de o objeto pertencer ao remetente embora esteja nas dependências dos Correios, e por comprometer os prazos de entrega, com ônus para os Correios.\nNOTA 2: compete, exclusivamente, ao responsável pelo contrato na SE e gerências de subordinação imediata, autorizar medidas de exceção, como devolução da carga, bem como devem justificar às esferas superiores a decisão e critérios adotados, quer na autorização excepcional, quer na medida de exceção.\n2.4.8 Avaliar, com base nos Anexos 3 a 7 deste Capítulo, se o objeto está corretamente classificado, ainda que não exista divergência entre imagem/exemplar e objeto postado.', 40),
(4696, 'capitulo', 11, 4688, 3, '2.4.9', 'Informar e solicitar posicionamento ao responsável pelo contrato na SE, quanto a eventuais divergências de classificação identificadas, conforme previsto nos documentos mencionados no subitem 2.2.4.3.3 deste capítulo.', '', 41),
(4697, 'capitulo', 11, 4688, 3, '2.4.10', 'Avaliar a Avaliação Técnica Comercial - ATC, submeter amostras a teste conforme subitem 2.2.2.2 deste capítulo e emitir Avaliação Técnica Operacional - ATO e/ou orientar o demandante quanto aos ajustes necessários, se for o caso.', '', 42),
(4698, 'capitulo', 11, 4688, 3, '2.4.11', 'Efetuar o recebimento das postagens das respectivas peças promocionais, conforme processo específico.', '', 43),
(4699, 'capitulo', 11, 4663, 2, '2.5', 'Procedimentos a cargo da equipe de classificação de objetos', '2.5.1 Recepcionar demanda e peça oriunda da área, conforme subitem 2.2.3 deste capítulo.\n2.5.2 Analisar, emitir parecer acerca das dúvidas da área e informar classificação atribuída à peça.', 44),
(4700, 'capitulo', 11, 4699, 3, '2.5.3', 'Encaminhar o parecer ao DEVEN, por meio do e-mail geav@correios.com.br, para deliberação junto ao DPOST, em caso de dúvidas sobre a classificação do objeto.', '', 45),
(4701, 'capitulo', 11, 4663, 2, '2.6', 'Procedimentos DEVEN', '2.6.1 Receber demanda da equipe de classificação de objetos e encaminhar para o DPOST, conforme subitem 2.2.5.3 deste Capítulo.', 46),
(4702, 'capitulo', 11, 4663, 2, '2.7', 'Procedimentos DPOST', '2.7.1 Avaliar demanda sobre classificação, conforme subitem 2.2.6.1 deste Capítulo.\n* * * * *', 47),
(4703, 'capitulo', 12, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(4704, 'capitulo', 12, 4703, 2, '1.1', 'Objetivo: orientar quanto à prestação do serviço de distribuição de publicações periódicas em domicílio, de forma padronizada, a partir de volume mínimo anual e suportado por um sistema de informações operacionais gerenciais via web.', '', 1),
(4705, 'capitulo', 12, 4703, 2, '1.2', 'Abrangência: origem (com exceção das SEs AM, AP e RR) e destino (nacional).', '', 2),
(4706, 'capitulo', 12, 4703, 2, '1.3', 'Gestor Funcional: Departamento de Gestão de Serviços Nacionais - DEPRO/SUPRO/DINEG.', '', 3),
(4707, 'capitulo', 12, 4703, 2, '1.4', 'Fornecedores: áreas comercial, operacional, técnica e de suprimento.', '', 4),
(4708, 'capitulo', 12, 4703, 2, '1.5', 'Clientes: pessoas jurídicas.', '', 5),
(4709, 'capitulo', 12, 4703, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4710, 'capitulo', 12, 4703, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4711, 'capitulo', 12, 4703, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir portfólio de produtos.', '', 8),
(4712, 'capitulo', 12, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(4713, 'capitulo', 12, 4712, 2, '2.1', 'Procedimentos de Contratação (Força de Vendas)', '', 10),
(4714, 'capitulo', 12, 4713, 3, '2.1.1', 'Preencher a Ficha de Intenção de Compra - FIC, informando os serviços básicos e acessórios afetos ao contrato, conforme códigos abaixo.', '2.1.1.1 Serviços Básicos:', 11),
(4715, 'capitulo', 12, 4714, 4, 'a', 'Faixa 1 (Cód. Serv. 3128-3) - anual de 2.000 a 20.000;', '', 12),
(4716, 'capitulo', 12, 4714, 4, 'b', 'Faixa 2 (Cód. Serv. 3129-1) - anual acima de 20.000 a 59.999;', '', 13),
(4717, 'capitulo', 12, 4714, 4, 'c', 'Faixa 3 (Cód. Serv. 3110-0) - anual de 60.000 a 600.000;', '', 14),
(4718, 'capitulo', 12, 4714, 4, 'd', 'Faixa 4 (Cód. Serv. 3111-9) - anual acima de 600.000 a 1.200.000;', '', 15),
(4719, 'capitulo', 12, 4714, 4, 'e', 'Faixa 5 (Cód. Serv. 3112-7) - anual acima de 1.200.000 a 2.400.000;', '', 16),
(4720, 'capitulo', 12, 4714, 4, 'f', 'Faixa 6 (Cód. Serv. 3113-5) - anual acima de 2.400.000.', '2.1.1.2 Serviços Acessórios:', 17),
(4721, 'capitulo', 12, 4714, 4, 'a', 'Inserção do primeiro encarte simples (Cód. Serv. 3115-1);', '', 18),
(4722, 'capitulo', 12, 4714, 4, 'b', 'Inserção dos demais encartes simples (Cód. Serv. 3116-0);', '', 19),
(4723, 'capitulo', 12, 4714, 4, 'c', 'Envelopamento (Cód. Serv. 3117-8);', '', 20),
(4724, 'capitulo', 12, 4714, 4, 'd', 'Coleta (Cód. Serv. 3114-3);', '', 21),
(4725, 'capitulo', 12, 4714, 4, 'e', 'Entrega protocolada até 2% do volume (Cód. Serv. 3118-6);', '', 22),
(4726, 'capitulo', 12, 4714, 4, 'f', 'Cancelamento de etiquetas (Cód. Serv. 3132-1);', '', 23),
(4727, 'capitulo', 12, 4714, 4, 'g', 'Organização da expedição (Cód. Serv. 3102-0);', '', 24),
(4728, 'capitulo', 12, 4714, 4, 'h', 'Entrega de encarte local (Cód. Serv. 3106-2);', '', 25),
(4729, 'capitulo', 12, 4714, 4, 'i', 'Entrega protocolada que exceder 2% do volume (Cód. Serv. 3119-4).', '', 26),
(4730, 'capitulo', 12, 4713, 3, '2.1.2', 'Solicitar amostra do periódico ao cliente para confirmar os dados fornecidos na FIC.', '', 27),
(4731, 'capitulo', 12, 4713, 3, '2.1.3', 'Definir a unidade que operacionalizará o contrato, em conjunto com o cliente, verificando sua capacidade operacional (AC, AGF, CTC, CTE, CTCE), considerando a quantidade de publicações a ser manuseada e postada.', '2.1.3.1 Postar em AGF obedecendo ao disposto no MANCAT 26/4, Anexo 2.', 28),
(4732, 'capitulo', 12, 4713, 3, '2.1.4', 'Observar os procedimentos estabelecidos no MANFAC 6, para pessoa jurídica, quando da contratação do serviço.', '', 29);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(4733, 'capitulo', 12, 4713, 3, '2.1.5', 'Fornecer ao cliente o leiaute para o desenvolvimento do arquivo de postagem e o arquivo construtor, disponíveis na intranet da área de Negócios, e orientá-lo quando necessário.', '', 30),
(4734, 'capitulo', 12, 4713, 3, '2.1.6', 'Validar o arquivo encaminhado pelo cliente, por meio do validador, para a aprovação do leiaute, antes da assinatura do contrato.', '', 31),
(4735, 'capitulo', 12, 4713, 3, '2.1.7', 'Firmar contrato, conforme minuta de contratos e regras de serviço vigentes.', '', 32),
(4736, 'capitulo', 12, 4713, 3, '2.1.8', 'Fornecer ao cliente, em arquivo eletrônico, o modelo da chancela de franqueamento, quando solicitado.', '2.1.8.1 Observar para os seguintes dados fixos e informações no franqueamento:', 33),
(4737, 'capitulo', 12, 4736, 4, 'a', 'nome do serviço e marca Correios;', '', 34),
(4738, 'capitulo', 12, 4736, 4, 'b', 'campo para os dados variáveis:', 'I - número e ano de assinatura do contrato;\nII - Superintendências Estaduais - SEs de origem do contrato e de postagem;\nIII - nome ou sigla da contratante.', 35),
(4739, 'capitulo', 12, 4713, 3, '2.1.9', 'Fornecer ao cliente a tabela de preços vigente.', '', 36),
(4740, 'capitulo', 12, 4712, 2, '2.2', 'Procedimentos Após Assinatura do Contrato (Força de Vendas)', '', 37),
(4741, 'capitulo', 12, 4740, 3, '2.2.1', 'Criação da Pasta FTP', '2.2.1.1 Solicitar ao Help Desk, após a celebração do contrato, a criação de uma pasta FTP para o serviço de Correios Entrega Direta - CED, informando: nome do cliente, permissão de leitura e gravação de arquivos e SE de origem.\n2.2.1.1.1 Aguardar resposta da equipe do Help Desk em até um dia útil e ao fim deste prazo, em caso de não recebimento, contatar a equipe do Help Desk, de modo a ativar a prioridade na criação da pasta.\n2.2.1.1.2 Solicitar a criação de nova pasta File Transfer Protocol - FTP a cada Cadastro Nacional de Pessoa Jurídica - CNPJ e Internacional Standard Serial Number - ISSN diferentes.\n2.2.1.2 Testar o acesso à pasta FTP e inserir os dados na FIC para cadastro no SISPER.\n2.2.1.3 Contatar a equipe técnica na hipótese de o cliente não conseguir acessar a pasta.\n2.2.1.4 Cancelar, junto ao Help Desk, via ordem de serviço, a pasta FTP de cada cliente que tiver seu contrato cancelado, imediatamente após efetivação deste.', 38),
(4742, 'capitulo', 12, 4740, 3, '2.2.2', 'Cadastrar no Gerenciador de Solicitação de Cadastro - GSC, as informações do cliente observadas no contrato.', '', 39),
(4743, 'capitulo', 12, 4740, 3, '2.2.3', 'Acompanhar no GSC a inserção de informações do cliente no ERP, pela área de cadastro.', '', 40),
(4744, 'capitulo', 12, 4740, 3, '2.2.4', 'Cadastro dos Clientes (Força de Vendas)', '2.2.4.1 Fornecer ao cliente:', 41),
(4745, 'capitulo', 12, 4744, 4, 'a', 'dados necessários para acesso ao SISPER;', '', 42),
(4746, 'capitulo', 12, 4744, 4, 'b', 'manual de operacionalização do sistema e suporte ao primeiro acesso, disponível na intranet da área de Negócios;', '', 43),
(4747, 'capitulo', 12, 4744, 4, 'c', 'código e siglas gerados pelo SISPER, para inclusão no arquivo de postagem;', '', 44),
(4748, 'capitulo', 12, 4744, 4, 'd', 'número de contrato, código administrativo, número do cartão, código e especificação de serviço, código da unidade que prestará o serviço e demais dados necessários à operacionalização do contrato.', '2.2.4.1.1 Encaminhar todos os dados do item “c” e “d” ao cliente, para inclusão no arquivo eletrônico de postagem, para validação dos dados e processamento das devidas informações.\n2.2.4.2 Orientar o cliente quanto à postagem dos objetos com ou sem envelope. Caso o cliente apresente a necessidade da postagem sem invólucro, solicitar assinatura do Termo de Isenção de Responsabilidade em 2 vias, disponível na intranet da área de Negócios.\n2.2.4.2.1 Apresentar o termo a cada postagem, anexado às Lista de Postagens - LPs apresentadas, no centralizador que operacionalizará a postagem.\n2.2.4.3 Acompanhar a primeira postagem do cliente, na unidade que operacionalizará a postagem.\n2.2.4.4 Solicitar o cadastro ao gestor funcional do SISPER, sempre que houver alteração de usuários.\n2.2.4.5 Gerar o Formulário de Informação de Celebração e/ou Alteração de Contrato - ICC/IACC.\n2.2.4.6 Enviar o Formulário de Informação de Celebração e/ou Alteração de Contrato - ICC/IACC atualizado para o gestor funcional do SISPER.\n2.2.4.7 Solicitar, à área de cadastro a alteração do contrato, atualização no ERP, para que o gestor funcional do SISPER possa providenciar a alteração no sistema, com base nas informações do ICC atualizado.\n2.2.4.7.1 Comparar o exemplar com os dados preenchido nos formulários para o posterior envio ao gestor funcional do SISPER, no caso de inclusão de nova publicação no contrato do cliente.\n2.2.4.8 Providenciar atualização da ficha técnica.\n2.2.4.9  Encaminhar a ficha técnica para o gestor funcional do SISPER para as devidas atualizações no sistema, quando se tratar de:\na) mudança de faixa de volume contratada;\nb) alteração da SE Origem;\nc) alteração/inclusão de unidade que operacionalizará a postagem.\n2.2.4.9.1 Atentar-se para permissão de apenas 1 (uma) unidade cadastrada para operacionalização por SE.\n2.2.3.7.2 Atentar-se ao item 2.1.3 em caso de alteração de unidade de operacionalização da postagem.\n2.2.4.10 Encaminhar, via e-mail, o formulário Ficha de Intenção de Compra - FIC e ICC/IACC para o gestor funcional do SISPER, para que as informações sejam ajustadas no sistema.', 45),
(4749, 'capitulo', 12, 4712, 2, '2.3', 'Procedimentos de Alteração Contratual (Gerências de Apoio a Contratos Comerciais)', '', 46),
(4750, 'capitulo', 12, 4749, 3, '2.3.1', 'Solicitar à área de cadastro, o cancelamento do contrato e/ou substituição de tabela de preços no ERP, para que o gestor funcional do SISPER providencie as respectivas alterações no sistema, com base nas informações do ICC/IACC.', '', 47),
(4751, 'capitulo', 12, 4712, 2, '2.4', 'Procedimentos para Rescisão/Cancelamento do Contrato (Gerências de Apoio a Contratos Comerciais)', '', 48),
(4752, 'capitulo', 12, 4751, 3, '2.4.1', 'Solicitar, à área de cadastro, que inabilite as tabelas de preço no ERP.', '', 49),
(4753, 'capitulo', 12, 4712, 2, '2.5', 'Procedimentos do Gestor Funcional do Sistema de Periódicos - SISPER', '', 50),
(4754, 'capitulo', 12, 4753, 3, '2.5.1', 'Inserir no SISPER o cadastro do cliente, bem como a tabela de preços, usando as informações da FIC e ICC/IACC.', '2.5.1.1 Atentar-se para o prazo de cadastramento no SISPER de 2 (dois) dias úteis.', 51),
(4755, 'capitulo', 12, 4753, 3, '2.5.2', 'Cadastrar no Sistema de Periódicos - SISPER:', '', 52),
(4756, 'capitulo', 12, 4755, 4, 'a', 'cliente - utilizar dados do ERP;', '', 53),
(4757, 'capitulo', 12, 4755, 4, 'b', 'títulos dos periódicos;', '', 54),
(4758, 'capitulo', 12, 4755, 4, 'c', 'unidade de operacionalização da postagem;', '', 55),
(4759, 'capitulo', 12, 4755, 4, 'd', 'local de postagem;', '', 56),
(4760, 'capitulo', 12, 4755, 4, 'e', 'informações do usuário (login e senha para o cliente e Agência Franqueada –   AGF);', '', 57),
(4761, 'capitulo', 12, 4755, 4, 'f', 'pasta FTP;', '', 58),
(4762, 'capitulo', 12, 4755, 4, 'g', 'nível de serviço;', '', 59),
(4763, 'capitulo', 12, 4755, 4, 'h', 'contato do cliente;', '', 60),
(4764, 'capitulo', 12, 4755, 4, 'i', 'código de serviço;', '', 61),
(4765, 'capitulo', 12, 4755, 4, 'j', 'vincular tabelas de preços.', '2.5.2.1 Atentar-se para os dados incluídos no SISPER como largura, comprimento e espessura a cada nova inclusão de título.', 62),
(4766, 'capitulo', 12, 4753, 3, '2.5.3', 'Cancelar as tabelas de preços e o acesso ao SISPER, inabilitando o cliente.', '', 63),
(4767, 'capitulo', 12, 4712, 2, '2.6', 'Reajuste das Tabelas de Preço (Área de Precificação)', '', 64),
(4768, 'capitulo', 12, 4767, 3, '2.6.1', 'Reajustar tabelas de preços dos clientes do CED por meio do SISPER a partir da autorização para realizar as respectivas alterações.', 'Nota: essa atualização será feita por meio do sistema da área responsável pela precificação.', 65),
(4769, 'capitulo', 12, 4712, 2, '2.7', 'Procedimentos de Postagem do Arquivo de Reclamação', '', 66),
(4770, 'capitulo', 12, 4769, 3, '2.7.1', 'Orientar o cliente a depositar o arquivo eletrônico de reclamações na pasta FTP, conforme leiaute previsto, disponível na intranet da área de Negócios.', '2.7.1.1 Estar ciente que a reclamação apenas será permitida ao cliente que postou a reserva técnica referente à edição reclamada.', 67),
(4771, 'capitulo', 12, 4712, 2, '2.8', 'Procedimentos de Postagem dos Objetos CED para Contratos Celebrados até Fev/2020 - Política Comercial Antiga', '', 68),
(4772, 'capitulo', 12, 4771, 3, '2.8.1', 'Calcular o quantitativo mínimo de 1.000 (mil) objetos, considerando o somatório da quantidade de objetos em todas as Listas de Postagem - LPs apresentadas pelo cliente na data da postagem.', 'Nota 1: o Sistema de Periódicos - SISPER permite a consolidação de diversos arquivos em uma única LP ou a geração de LPs distintas para uma mesma edição/título a ser postada.\nNota 2: o cálculo será efetuado com base no preço do objeto de 100 gramas para a entrega local/metropolitana, definido na tabela prevista para este contrato e vigente na data da postagem. Este valor deverá ser multiplicado pela diferença entre a quantidade postada e o mínimo estabelecido por postagem.\nNota 3: a quantidade de objetos complementares ao volume mínimo não será contabilizada para efeito de composição da cota de postagem mínima anual indicada na tabela de preços dos serviços básicos.', 69),
(4773, 'capitulo', 12, 4712, 2, '2.9', 'Cobrar em fatura posterior uma complementação financeira caso seja efetuada postagem em quantidade inferior ao definido.', '', 70),
(4774, 'capitulo', 12, 4712, 2, '2.10', 'Realizar cálculos de quantidades mínimas de postagem separadamente por tabela de preços e também, proporcionalmente, ao período em que as tabelas estiveram ativas no ano civil, quando houver alteração de tabela de preços dos serviços básicos da Operação B para mudança de faixa de volume anual de postagem de objetos, durante a vigência do contrato.', '* * * * *', 71),
(4775, 'capitulo', 13, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(4776, 'capitulo', 13, 4775, 2, '1.1', 'Objetivo: prestar o serviço que permite a distribuição de peças promocionais sem a indicação de endereço, de forma seletiva ou aleatória, com o objetivo de se atingir o público alvo de determinada região, de interesse do cliente.', '', 1),
(4777, 'capitulo', 13, 4775, 2, '1.2', 'Abrangência: nacional.', '', 2),
(4778, 'capitulo', 13, 4775, 2, '1.3', 'Gestor: DPOST/SUCOM.', '', 3),
(4779, 'capitulo', 13, 4775, 2, '1.4', 'Fornecedores: áreas comercial, operacional e de atendimento.', '', 4),
(4780, 'capitulo', 13, 4775, 2, '1.5', 'Clientes: pessoas jurídicas, pessoas físicas, profissionais liberais e candidatos a cargos políticos.', '', 5),
(4781, 'capitulo', 13, 4775, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4782, 'capitulo', 13, 4775, 2, '1.7', 'Duração: prazo indeterminado.', '2. DESCRIÇÃO DOS SUBPROCESSOS\n2.1 Procedimentos de Contratação\n2.1.1 Firmar contrato, conforme modelos indicados nos endereços abaixo, levando em consideração as características do serviço constante do Anexo 2 deste Capítulo.\na) Contrato Múltiplo:\n\\\\sac0424\\CONTRATOS_COMERCIAIS\\DEPRO\\Marketing\\Anexos_do_Contrato_Múltiplo.\nb) Contrato Múltiplo Simplificado:\n\\\\Sac0424\\CONTRATOS_COMERCIAIS\\CONTRATO_MULTIPLO_SIMPLIFICADO\\ARQUIVOS_EM_PDF\\ANEXOS.\n2.1.2 Observar os procedimentos estabelecidos no MANFAC 1/2 e 5/1, para pessoa jurídica, quando da contratação do serviço.\n2.1.3 Distribuir as vias do contrato da seguinte forma:\na) 1ª. via – cliente;\nb) 2ª. via – área vendas/comercial.\n2.1.4 Verificar se os objetos apresentam as características que definem o Serviço de Mala Direta e se não se enquadram na relação de objetos proibidos, conforme definido no MANCAT 6/4, observando que:\na) devem ser apresentados abertos para verificação do conteúdo;\nb) caso sejam apresentados totalmente fechados, deve constar, obrigatoriamente, no invólucro do objeto a expressão “Fechamento Autorizado. Pode ser aberto pelos Correios”.\nNOTA: caso não atendida as condições dispostas neste item, o objeto não se classificará como Mala Direta.', 7),
(4783, 'capitulo', 13, 4775, 2, '2.2', 'Procedimentos de Atendimento', '', 8),
(4784, 'capitulo', 13, 4783, 3, '2.2.1', 'Aceitação dos Objetos (AC e AGF)', '', 9),
(4785, 'capitulo', 13, 4783, 3, '2.2.2', 'Identificar a modalidade de postagem: à vista ou a faturar.', '2.2.3 Verificar, no ato da postagem, a situação do contrato, no sentido de haver ou não impedimentos para a aceitação da postagem, caso a postagem seja a faturar.', 10),
(4786, 'capitulo', 13, 4785, 4, 'a', 'recusar a postagem de objetos nos casos do contrato ou cartão esteja suspenso ou cancelado;', '', 11),
(4787, 'capitulo', 13, 4785, 4, 'b', 'nesse caso, a carga deverá ser retirada no mesmo momento pelo cliente/preposto.', '', 12),
(4788, 'capitulo', 13, 4783, 3, '2.2.4', 'Verificar se os objetos possuem a chancela específica do serviço:', '', 13),
(4789, 'capitulo', 13, 4788, 4, 'a', 'na modalidade a faturar: contendo a chancela com o número do contrato;', '', 14),
(4790, 'capitulo', 13, 4788, 4, 'b', 'na modalidade à vista: contendo o nº. do CNPJ ou CPF do cliente.', '', 15),
(4791, 'capitulo', 13, 4783, 3, '2.2.5', 'Verificar se os objetos estão de acordo com os pesos e dimensões estabelecidos para o serviço.', '', 16),
(4792, 'capitulo', 13, 4783, 3, '2.2.6', 'Verificar se os objetos apresentados para postagem estão encabeçados e em amarrados, de no máximo 4 kg, conforme quantidade de objetos estabelecida pela Diretoria Regional para o amarrado, e separados por Centro de Distribuição Domiciliária – CDD / Unidade de Distribuição – UD / Agência de Correios - AC.', '', 17),
(4793, 'capitulo', 13, 4783, 3, '2.2.7', 'Verificar se os amarrados estão acompanhados do respectivo espelho MDD, conforme Anexo 4 deste Capítulo, devidamente preenchido.', '', 18),
(4794, 'capitulo', 13, 4775, 2, '2.3', 'Atividades de Recebimento de Objetos (AC e AGF)', '2.3.1 Pesar, no caso e objetos com chancela, uma amostra de dez objetos, dividindo o peso da amostra por dez, para cálculo do peso unitário médio.\n2.3.2 Inserir as informações obtidas na pesagem, peso unitário e quantidade, conforme cada abrangência, no respectivo código de serviço no Sistema SARA.\n2.3.3 Inserir no SARA obrigatoriamente, o nº. do CNPJ ou CPF do cliente, se postagem à vista.\n2.3.4 Emitir a segunda via do comprovante SARA.\n2.3.5 Preencher o “Formulário Instruções Para a Distribuição MDD”, conforme Anexo 3 deste Capítulo, em duas vias, procedendo conforme segue:', 19),
(4795, 'capitulo', 13, 4794, 4, 'a', 'arquivar uma via na agência;', 'b) encaminhar uma via junto à carga, com a 2ª via do comprovante SARA anexada.\n2.3.6 Acondicionar os amarrados em unitizador exclusivo, ou seja, fechar unitizadores contendo apenas Mala Direta Domiciliária e utilizar o rótulo MDD, conforme Anexo 3 deste Capítulo, devidamente preenchido.\nNOTA: recomenda-se a Unidade de Postagem, quando possível, enviar, por e-mail, à Unidade de Distribuição a imagem da peça e cópia eletrônica do formulário instruções para distribuição.\n2.4 Procedimentos Operacionais\n2.4.1 Procedimentos de Conferência – CTC/CTCE, CDD ou UD\n2.4.2 Verificar a existência do “Formulário Instruções Para a Distribuição MDD”, bem como o respectivo comprovante SARA, junto à carga de Mala Direta Domiciliária.\n2.4.3 Arquivar o “Formulário Instruções Para a Distribuição MDD”, juntamente ao comprovante SARA, para eventuais consultas das áreas de controle.\n2.4.4 Efetuar a conferência das cargas de Mala Direta Domiciliária, conforme a seguir:', 20),
(4796, 'capitulo', 13, 4794, 4, 'a', 'no caso do CTC/CTCE, conferir por amostragem (uma carga por dia, preferencialmente a mais volumosa), comparando a quantidade/peso dos objetos', '', 21),
(4797, 'capitulo', 13, 4794, 4, 'b', 'no caso de CDD ou UD, conferir, efetuando a contagem por gabarito, toda a carga de abrangência local que não trafega por Centro de Tratamento, comparando a quantidade/peso dos objetos informados no Formulário com a carga física, bem como com o respectivo lançamento no comprovante SARA.', '2.4.5 Comunicar as eventuais irregularidades à GETER, GERAT ou GENEG para regularização.\n2.5 Procedimentos de Distribuição\n2.5.1 Encaminhar e distribuir as Malas Diretas Domiciliárias, de acordo com os procedimentos operacionais estabelecidos para objetos não urgentes.\n2.5.2 Entregar os objetos conforme segmento de distribuição constante no “Formulário Instruções Para a Distribuição MDD” e os espelhos dos amarrados.\n2.5.3 Entregar os objetos juntamente com a correspondência a ser distribuída, no caso de distribuição aleatória. Não haverá alteração na percorrida do carteiro.\n2.5.4 Entregar os objetos em locais preestabelecidos, no caso de entrega seletiva, conforme a seguintes segmentações:\na) localidade;\nb) bairro;', 22),
(4798, 'capitulo', 13, 4794, 4, 'c', 'rua;', 'd) somente para o comércio;\ne) somente para o residencial.\n2.5.5 Entregar os objetos, por meio do atendente comercial, ao final de cada atendimento ou inserir nas caixas postais ou ainda disponibilizar nos displays, nos casos de entrega interna, somente em Agência Próprias, observando:\na) para a viabilidade da distribuição de Malas Diretas Domiciliárias em display nos balcões de Agências ou pelos atendentes comerciais, o ACOM/GCE deverá consultar a GERAT das SEs para a devida aprovação. Para a disponibilização/distribuição das peças deverão ser observados os seguintes critérios:\nI - prazo mínimo para a permanência de peças nas agências: a critério do cliente;\nII - prazo máximo para a permanência de peças nas agências: 3 meses, com reposição de peças.\nIII - o display deve ser confeccionado pelo cliente, conforme as dimensões estabelecidas no Anexo 2 - Quadro com as Características Principais do Serviço Mala Direta Domiciliária (Limites de Peso e Dimensões), deste Capítulo. O material de confecção do display deverá ser de papelão, acrílico ou outro que tenha apresentação satisfatória e resistência, mediante avaliação prévia.\nb) a distribuição por atendentes: entrega da peça pelos atendentes comerciais para o cliente de balcão, ao final de cada atendimento:\nI - quantidade de displays por agência categorias 1 e 2: Máximo de 2 displays;\nII - quantidade de displays por agências categorias 3, 4, 5 e 6: Máximo de 1 display;\nIII - quantidade de peças distribuídas pelo atendente, por agências categorias 1 a 6: Máximo de 2.\nc) quando houver novos clientes interessados em disponibilizar suas peças em determinada agência onde já exista a distribuição pelos atendentes comerciais ou por meio de display de outros clientes, deve-se aguardar o vencimento do prazo de qualquer uma das peças expostas, para incluir aquele que apresentou a solicitação em primeiro lugar, respeitando a quantidade máxima previstas nos incisos I e II da alínea \"b\";\nd) no caso de exposição de catálogos, pode-se dispensar o display em razão do volume, tendo em vista que o peso máximo admitido é de 300 gramas;\ne) a afixação de cartazes nas agências para apoio à promoção realizada nas peças deve obedecer aos critérios estabelecidos pela DERAT.\nf) o ressuprimento de peças deve ser solicitado pela agência à áreas comerciais/vendas ou de atendimento, com a informação da quantidade necessária.\n* * * * *', 23),
(4799, 'capitulo', 14, NULL, 1, '1', 'ATRIBUTOS DOS PROCESSOS', '', 0),
(4800, 'capitulo', 14, 4799, 2, '1.1', 'Objetivo: prestar um serviço que represente uma solução completa para o cliente, desde a captação e tratamento dos seus arquivos, transformando-os em objetos postais, até a entrega e devolução de informação constante no AR Digital.', '', 1),
(4801, 'capitulo', 14, 4799, 2, '1.2', 'Abrangência: local, estadual e nacional.', '', 2),
(4802, 'capitulo', 14, 4799, 2, '1.3', 'Gestor: DPOST/SUCOM.', '', 3),
(4803, 'capitulo', 14, 4799, 2, '1.4', 'Fornecedores: áreas Comercial, Operacional e Técnica.', '', 4),
(4804, 'capitulo', 14, 4799, 2, '1.5', 'Clientes: Órgãos Públicos.', '', 5),
(4805, 'capitulo', 14, 4799, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4806, 'capitulo', 14, 4799, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4807, 'capitulo', 14, NULL, 1, '2', 'DESCRIÇÕES DOS PROCESSOS', '2.1 Área Comercial\n2.1.1 Encaminhar Memorando assinado pelo SE às áreas envolvidas (operacional, atendimento, técnica, etc).\n2.1.2 Reunir áreas envolvidas para comunicar sobre a celebração do contrato e início da prestação do serviço.\n2.1.3 Apresentar o Guia Operacional V-Post ressaltando os principais pontos e informar endereço \\\\sac0424\\INSTITUCIONAL\\VINEG\\DEPRO\\PUBLICO\\Publico_GEDI\\V-Post, no qual o material estará disponível.\n2.1.4 Fazer gestão da prestação do serviço utilizando os sistemas V-Post e SGD.\n2.1.5 Acionar as áreas envolvidas visando resolução imediata das pendências identificadas.\n2.1.6 Cadastrar a sigla e o código do Cliente no SGD.\n2.1.7 Cadastrar os dados (contrato, contatos, endereço, etc.) do cliente no SGD.\n2.1.8 Cadastrar as faixas de etiquetas no SGD.\n2.1.9 Preencher os dados comerciais da planilha cadastro V-Post.\n2.2 Área Técnica\n2.2.1 Disponibilizar Matriz de Regras para o Cliente.\n2.2.2 Cadastrar o leiaute dos arquivos de Previsão de Postagem e Retorno no SGD.\n2.2.3 Cadastrar as especificações técnicas dos arquivos no SGD.\n2.2.4 Prestar suporte técnico relativo ao sistema ao cliente e à área comercial.\n2.2.5 Cadastrar os dados técnicos do cliente no sistema V-Post, com base nas informações prestadas pela área comercial contidas na planilha Cadastro V-Post.\n2.2.6 Informar aos CLIs de impressão e digitalização o novo contrato e arquivos envolvidos, bem como a data de início de testes e produção.\n2.2.7 Interagir com a área comercial da SE detentora do contrato para verificar as inconsistências de cadastramento entre os sistemas SGD e V-Post no que diz respeito aos dados do cliente.\n2.3 CLI de Produção\n2.3.1 Disponibilizar canal de comunicação para a transferência de arquivos entre as partes, que poderá ser realizada via FTP (File Transfer Protocol) corporativo ou software de transferência de arquivos, ambos providos pelos Correios.\n2.3.2 Capturar arquivos eletrônicos de postagem, contendo lotes de tamanho e quantidade de objetos acordados entre as partes, na faixa horária definida em Ficha Técnica.\n2.3.3 Encaminhar os arquivos eletrônicos, assinados digitalmente, contendo as imagens e metadados dos formulários AR Digital, na faixa horária definida em Ficha Técnica.\n2.3.4 Validar o arquivo por meio de notificação positiva ou negativa.\n2.3.5 Receber a resposta à notificação do cliente para início dos trabalhos de produção.\n2.3.6 Disponibilizar o arquivo para o site de impressão definido pelo sistema.\n2.3.7 Imprimir os objetos uni e multipaginados e os respectivos ARs.\n2.3.8 Proceder ao envelopamento dos objetos multipaginados e autoenvelopamento dos unipaginados.\n2.3.9 Confirmar impressão; ao confirmar a impressão, o sistema V-Post libera o arquivo para faturamento para incorporação no SARA.\n2.3.10 Proceder ao faturamento via SARA, que gera o evento “postagem” no SRO.\n2.3.11 Confirmar no sistema V-Post o faturamento; a confirmação do faturamento disponibiliza o arquivo de pré-postagem para o SGD.\n2.3.12 Disponibilizar os objetos postais para tratamento, encaminhamento e distribuição domiciliária.\n2.3.13 Emitir 2ª via dos objetos sem informação posterior ao evento “Postagem” desde que solicitado pelo cliente.\n2.3.13.1 Inserir os objetos no fluxo postal, utilizando o motivo de baixa “Reimpresso/Reenviado”, código 53 do SRO.\n2.4 Unidades de Tratamento\n2.4.1 Aplicar o mesmo tratamento, encaminhamento e prazo de entrega estabelecidos para a plataforma operacional do serviço de Carta Comercial Registrada com AR Digital, cujos procedimentos estão descritos no MANCAT 7/2 e 7/3.\n2.5 Unidades de Entrega (Agência e CDD)\n2.5.1 Aplicar os procedimentos relativos à distribuição dos objetos Carta Registrada com AR Digital constantes no MANDIS 10/6 - 3 e 4 e MANDIS 9/7 - 3.\n2.5.2 Aplicar os mesmos procedimentos relativos ao encaminhamento dos formulários de AR Digital, tanto entregues quanto os devolvidos.\n2.6 CLI de Digitalização\n2.6.1 Receber e conferir carga.\n2.6.2 Abrir, compactar e estimar carga.\n2.6.3 Classificar documentos por cliente.\n2.6.4 Liberar documentos para digitalização.\n2.6.5 Higienizar documentos.\n2.6.6 Devolver documentos para regularização.\n2.6.7 Configurar aplicativo para digitalização.\n2.6.8 Digitalizar documentos.\n2.6.9 Indexar documento.\n2.6.10 Verificar inconsistências/controle de qualidade.\n2.6.11 Tratar inconsistência da digitalização.\n2.6.12 Consolidar lotes.\n2.6.13 Exportar lotes de imagens.\n2.6.14 Verificar a incorporação da imagem no SGD.\n2.6.15 Tratar inconsistência de incorporação da imagem.\n2.6.16 Gerar capa de lote.\n2.6.17 Tratar inconsistência capa de lote.\n2.6.18 Organizar documentos digitalizados.\n2.6.19 Verificar lotes.\n2.6.20 Liberar documentos para armazenar.\n2.6.21 Emitir carta para devolução de documentos.\n2.6.22 Liberar documentos para devolução.\n2.6.23 Incorporar imagens.\n2.6.24 Obter informações de entrega no SRO.\n2.6.25 Conferir informações do SRO com as imagens.\n2.6.26 Digitar informações do documento.\n2.6.27 Assinar documentos digitalmente.\n2.6.28 Empacotar informação ao cliente.\n2.6.29 Assinar arquivo digitalmente.\n2.6.30 Autenticar usuário.\n2.6.31 Enviar arquivo pacotes.\n2.6.32 Receber notificação de rejeição.\n2.6.33 Receber notificação de recebimento.\n2.6.34 Regularizar a situação.\n* * * * *', 8),
(4808, 'capitulo', 15, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: prestar o serviço que permite a remessa de pedido e/ou informações, sob forma de carta ou cartão, não previamente franqueados, à pessoa jurídica autorizada, que efetuará o pagamento correspondente no ato da retirada.', 0),
(4809, 'capitulo', 15, 4808, 2, '1.2', 'Abrangência: nacional.', '', 1),
(4810, 'capitulo', 15, 4808, 2, '1.3', 'Gestor: DPOST/DINEG.', '', 2),
(4811, 'capitulo', 15, 4808, 2, '1.4', 'Fornecedores: áreas comercial e operacional.', '', 3),
(4812, 'capitulo', 15, 4808, 2, '1.5', 'Clientes: pessoas jurídicas.', '', 4),
(4813, 'capitulo', 15, 4808, 2, '1.6', 'Periodicidade: contínua.', '', 5),
(4814, 'capitulo', 15, 4808, 2, '1.7', 'Duração: prazo indeterminado.', '', 6),
(4815, 'capitulo', 15, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos da Área Comercial\n2.1.1 Analisar, em conjunto com a área operacional da SE se os objetos atendem as exigências dos Correios.\n2.1.2 Observar os procedimentos constantes do MANFAC 2/1, para pessoa jurídica, quando da contratação do serviço.\n2.1.3 Firmar contrato, conforme orientações constantes do MANCAT 28, levando em consideração as características do serviço constantes do Anexo 2, deste Capítulo.\nNota: a partir da revisão da política comercial de 2020, as minutas dos contratos para clientes EP - Empresa Privada e OP - Órgão Público, constam no endereço \\\\sac3144\\PROJETOS\\CONTRATOS_COMERCIAIS\\DEVEN\\Minutas_Contrato_Múltiplo\\REVISAO POLITICA COMERCIAL_2020\\MINUTAS CONTRATO MULTIPLO.\n2.1.4 Fornecer aos clientes, em arquivo eletrônico, os modelos de Carta-Resposta, disponíveis no Anexo 3, deste Capítulo, bem como os modelos das chancelas de franqueamento.\n2.1.5 Verificar junto à unidade de atendimento, viabilidade operacional para aceitação dos objetos em resposta.\n2.1.6 Validar o modelo do objeto produzido pelo cliente, observando se é compatível com os modelos previstos no Anexo 3, deste Capítulo.\n2.2 Procedimentos de Atendimento\n2.2.1 Procedimentos de Postagem\n2.2.1.1 Identificar se os objetos estão de acordo com os critérios definidos para franqueamento, constante do MANCAT 3/1.\n2.2.1.2 Verificar se o nome da unidade dos Correios responsável pela centralização e entrega dos objetos de resposta em retorno está indicado na parte inferior esquerda do objeto, acima do CEP e da localidade.\n2.2.1.3 Carimbar Carta-Resposta à esquerda da chancela de franqueamento do serviço ou da indicação do tipo, no caso do serviço de Carta-Resposta - tipo Taxa Paga.\n2.2.2 Procedimentos de Retirada dos Objetos\n2.2.2.1 Entregar ao cliente, em agência previamente definida, após análise de viabilidade, os objetos em retorno, observando que a entrega deverá ocorrer em dias acertados com os Correios.\nNota: não deverá haver um intervalo maior do que 10 (dez) dias entre duas retiradas consecutivas, exceto se nada houver a receber.\n2.2.2.2 Emitir comprovante de postagem e colher assinatura do cliente, quando da retirada dos objetos de resposta, para efeitos de faturamento ou tíquete quando do pagamento à vista.\n2.2.2.3 Observar os seguintes procedimentos, quando da não retirada dos objetos no prazo de 10 (dez) dias:\na) emitir comprovante de postagem e encaminhar para área financeira para que os valores sejam faturados, tanto na modalidade à vista como a faturar, independentemente de aviso prévio ao cliente;\nb) agrupar e encaminhar, por meio de Carta Registrada com Serviço Adicional Aviso de Recebimento - AR, os objetos não retirados no prazo, obedecendo aos seguintes procedimentos:\nI - inserir no campo “descrição de conteúdo” no formulário Aviso de Recebimento - AR os seguintes dizeres: “(xx - inserir a quantidade) Cartas-Resposta entregues ao remetente”;\nII - faturar, em nome do cliente, o envio desses objetos.\nc) efetuar a entrega dos objetos no endereço do cliente, indicado no contrato.\n* * * * *', 7),
(4816, 'capitulo', 16, NULL, 1, '1', 'ATRIBUTOS DOS SUBPROCESSOS', '1.1 Objetivo: prestar o serviço de correspondência registrada destinado aos Órgãos de Trânsito, para remessa exclusiva de Certificado de Registro e Licenciamento de Veículos - CRLV, Certificado de Registro de Veículos - CRV, Carteira Nacional de Habilitação - CNH e Notificações.\n1.2 Abrangência: nacional.\n1.3 Gestor: DPOST/SUCOM\n1.4 Fornecedores: área comercial e operacional.\n1.5 Clientes: órgãos do segmento de Trânsito (DENATRAN, CONTRAN, DETRAN, DER, PRE, DPRF, DNIT, Órgãos Municipais de Trânsito e Empresa/Órgão que, por delegação ou contrato com órgãos oficiais de trânsito, inclusive, prefeituras, quando for o caso, realize a postagem de CRLV, CRV, CNH e Notificações.\n1.6 Periodicidade: contínua.\n1.7 Duração: prazo indeterminado.', 0),
(4817, 'capitulo', 16, NULL, 1, '2', 'DESCRIÇÃO DOS SUBPROCESSOS', '2.1 Área Comercial\n2.1.1 Verificar e orientar o cliente as características principais do serviço Remessa Econômica de CRLV, CRV, CNH e Notificações dispostas no Anexo 2 deste Capítulo, bem como as demais informações constantes neste presente documento.\n2.1.2 Contratação\n2.1.2.1 Firmar contrato do serviço de Remessa Econômica de CRLV, CRV, CNH e Notificações exclusivamente com os órgãos do segmento de Trânsito dispostos no subitem 1.5 deste Capítulo.\n2.1.2.2 Não vincular o contrato de Remessa Econômica de CRLV, CRV, CNH e Notificações às unidades da Rede Terceirizada.\n2.1.2.3 Cadastrar, caso houver, com anuência dos Correios, para a utilização do serviço, a(s) Dependência(s) da Contratante, em âmbito nacional, conforme suas necessidades e independentemente da origem do Contrato.\n2.1.2.4 Seguir os procedimentos estabelecidos para contratação do serviço descritos no Manual de Faturamento e Cobrança – MANFAC para pessoa jurídica.\n2.1.2.5 Providenciar a celebração do contrato, após aprovação pelas áreas envolvidas, conforme modelos disponibilizados nos seguintes endereços:\na) anexo do Contrato Múltiplo:\n\\\\sac0424\\CONTRATOS_COMERCIAIS\\DEPRO\\Mensagem\\ANEXOS_CONTRATO_MÚLTIPLO\nb) anexo do Contrato Simplificado:\n\\\\sac0424\\CONTRATOS_COMERCIAIS\\CONTRATO_MULTIPLO_SIMPLIFICADO\n2.1.2.6 Fornecer aos clientes, após a formalização do contrato, os cartões de autorização de postagem para cada uma de suas Dependências credenciadas a efetuar postagem no contrato;\n2.1.2.7 Orientar os clientes que os objetos de Remessa Econômica de CRLV, CRV, CNH e Notificações devem ser apresentados para postagem nas Agências Próprias e/ou diretamente nos Centros de Tratamento.\n2.1.2.8 Providenciar a assinatura e a remessa à Diretoria de postagem, da(s) Ficha(s) Técnica(s), no caso de haver postagem em Diretoria Regional diferente daquela de origem, após aprovação das mesmas pela DR de origem do serviço, em conformidade com o subitem 2.2.2 deste Capítulo.\n2.1.2.9 Anexar ao contrato, para cada autorizada a utilizar o serviço, a(s) Ficha(s) Técnica(s), com a programação das respectivas coletas, de acordo com o modelo disponível no endereço:\nhttp://intranetac/presidencia/dplan/formularios-eletronicos/formularios-eletronicos, para o planejamento operacional.\n2.1.2.10 Providenciar a assinatura de nova(s) Ficha(s) Técnica(s) com as especificações acordadas, com antecedência mínima de 15 (quinze) dias da data de vigência das alterações, quando houver modificação do local, da quantidade de objetos e da frequência da coleta.\n2.1.2.11 Orientar ao cliente que, quando não houver viabilidade para realização da coleta, os objetos deverão ser entregues nas unidades de captação previamente definidas e nos horários acordados com a ECT, em conformidade com o subitem 2.2.4.4 deste Capítulo.\n2.1.2.12 Observar o disposto em contrato, no caso de rescisão contratual.\n2.2 Área Operacional\n2.2.1 Disponibilizar, à área comercial, para ser fornecido à Contratante:\na) plano de Triagem ou Sistema de Blocagem;\nb) plano de Expedição;\nc) modelo de etiquetas de amarrados.\n2.2.1.1 Fornecer os Planos de Triagem/Sistema de Blocagem correspondentes às Superintendências Estaduais - SE envolvidas na prestação do serviço, quando o contrato estabelecer postagem em mais de uma SE.\n2.2.2 Submeter, para aprovação da SE de prestação do serviço, a(s) Ficha(s) Técnica (s), quando houver postagem em SE diferente daquele de origem do contrato.\n2.2.3 Verificar, tanto na coleta quanto na postagem, se os objetos:\na) foram entregues previamente separados por localidade de destino, faceados e encabeçados por ordem crescente de CEP, de acordo com o Plano de Triagem/Sistema de Blocagem fornecido pelos Correios;\nb) foram entregues separados, levando-se em conta o tipo de objeto (com ou sem AR Digital), acompanhados da etiqueta de amarrado, com as indicações necessárias ao tratamento dos mesmos, conforme modelo fornecido pelos Correios;\nc) estão devidamente chancelados, conforme disposto no MANCAT 3/1;\nd) Foram entregues acompanhados da respectiva Lista de Postagem em meio eletrônico, através de CD-ROM, pen-drive ou transferência de dados, conforme leiaute dos arquivos fornecidos pelos Correios;\nNOTA 1: poderá ser adotado, pela Contratante, o Sistema de Gerenciamento de Postagens – SIGEP para fins de encaminhamento das informações relativas à postagem, ou aplicativo próprio, dependendo de validação prévia dos Correios. Neste caso, deverá ser observado o leiaute de arquivo utilizado pelo SIGEP para o envio das informações de postagem;\nNOTA 2: a título de contingência, a Contratante deverá entregar, também, Lista de Postagem impressa, conforme modelo estabelecido pelos Correios, disponível no endereço:\nhttp://intranetac/presidencia/dplan/formularios-eletronicos/formularios-eletronicos.\n2.2.4 Coleta\n2.2.4.1 Verificar o disposto no subitem 2.2.3 deste Capítulo.\n2.2.4.2 Definir, previamente, a frequência das coletas por cada SE bem como a quantidade de objetos a serem coletados em cada Dependência autorizada pela Contratante, se for o caso.\n2.2.4.3 Realizar as coletas no endereço indicado pela Contratante, podendo ser cadastrado um ou vários pontos de coleta, de acordo com a viabilidade operacional da SE, bem como considerando o disposto no subitem 2.1.2.9 deste Capítulo.\n2.2.4.4 Receber os objetos nas unidades de captação previamente definidas e nos horários acordados com os Correios, quando não houver viabilidade para realização da coleta, em conformidade com o subitem 2.1.2.11 deste Capítulo.\n2.2.5 Postagem\n2.2.5.1 Verificar o disposto no subitem 2.2.3 deste Capítulo.\n2.2.5.2 Receber os objetos de Remessa Econômica CRLV, CRV, CNH e Notificações para postagem nas Agências Próprias e/ou diretamente nas unidades operacionais devidamente vinculadas especificamente ao contrato, conforme subitem 2.1.2.7 deste Capítulo.\n2.2.5.3 Checar se a Contratante e a(s) respectiva(s) Dependência(s), apresentaram, no ato da postagem, o Cartão de Autorização de Postagem.\n2.2.5.4 Recusar a postagem de correspondências aglutinadas e endereçadas ao porteiro, zelador, síndico ou qualquer outra pessoa, a fim de que estas efetuem a redistribuição aos respectivos destinatários.\n2.2.5.4.1 Considerar por aglutinação o envio, de mais de uma correspondência, com destinatários diferentes, contidas em um mesmo envoltório.\n2.2.5.5 Observar o disposto no MANCAT 6/1, Anexo 1, para o prazo de guarda dos objetos.\n2.2.6 Distribuição\n2.2.6.1 Aplicar aos objetos da Remessa Econômica CRLV, CRV, CNH e Notificações o mesmo tratamento, encaminhamento e prazo de entrega estabelecidos para a plataforma operacional do serviço de Carta Comercial Registrada.\n2.2.7 Devolução de Objetos\n2.2.7.1 Restituir os objetos cuja entrega não tenha sido possível aos respectivos remetentes, conforme definido para o serviço de Carta Comercial Registrada, com a informação do motivo da não entrega. Neste caso, aplicam-se as regras dispostas no MANDIS.\n2.2.7.2 Atentar que o serviço de Remessa Econômica CRLV, CRV, CNH e Notificações admite a devolução imediata ao remetente, quando da eventual não entrega do objeto após as 3 (três) tentativa de entrega, observados os seguintes critérios:\na) a devolução imediata é opcional ao cliente;\nb) caso o cliente opte pela devolução imediata deverá apor, em cada envoltório, a mensagem abaixo indicada, de forma visível, por meio de impressão ou carimbo, com vistas a indicar, às unidades operacionais, o tratamento a ser dado ao objeto:\nI - objetos COM AR: apor, abaixo da assinatura do carteiro (abaixo dos motivos da não entrega), a mensagem “Devolução Imediata Após a Terceira Tentativa de Entrega”;\nII - objetos registrados sem AR: apor a mensagem “Devolução Imediata Após a Terceira Tentativa de Entrega” na área 3 do envoltório (área destinada ao bloco de endereço do destinatário), ao lado direito do bloco de endereçamento;\nc) os objetos destinados às localidades não atendidas pela distribuição domiciliária devem ser direcionados para entrega interna, conforme disposto no Manual de Distribuição e Coleta – MANDIS 9/2, mesmo que conste no envoltório a menção de devolução imediata;\nd) os objetos endereçados à Caixa Postal devem seguir o fluxo normal deste serviço, mesmo que conste no envoltório a menção de devolução imediata.\n2.3 Faturamento\n2.3.1 Considerar o período base de faturamento e data de vencimento da fatura, conforme disposto em contrato.\n2.3.2 Observar que para o serviço de Remessa Econômica CRLV, CRV, CNH e Notificações, o cliente é isento da cota mínima mensal de faturamento, conforme disposto na Tabela de Preços do serviço.\n* * * * *', 1),
(4818, 'capitulo', 17, NULL, 1, '1', 'ATRIBUTOS DOS SUBPROCESSOS', '', 0),
(4819, 'capitulo', 17, 4818, 2, '1.1', 'Objetivo: prestar o serviço de correspondência registrada destinado à pessoa jurídica, mediante contrato, especificamente para o envio de talões de cheques, cartões diversos e Carteira de Identidade Nacional - CIN.', '', 1),
(4820, 'capitulo', 17, 4818, 2, '1.2', 'Abrangência: nacional.', '', 2),
(4821, 'capitulo', 17, 4818, 2, '1.3', 'Gestor: Gerência de Desempenho de Comunicação Nacional - GDCO/DEPRO/SUPRO.', '', 3),
(4822, 'capitulo', 17, 4818, 2, '1.4', 'Fornecedores: área comercial e operacional.', '', 4),
(4823, 'capitulo', 17, 4818, 2, '1.5', 'Clientes: pessoas jurídicas que mantenham relacionamento com grandes carteiras de consumidores.', '', 5),
(4824, 'capitulo', 17, 4818, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4825, 'capitulo', 17, 4818, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4826, 'capitulo', 17, 4818, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', '', 8),
(4827, 'capitulo', 17, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(4828, 'capitulo', 17, 4827, 2, '2.1', 'Procedimentos da Área Comercial', '', 10),
(4829, 'capitulo', 17, 4828, 3, '2.1.1', 'Procedimentos Gerais', '2.1.1.1 Verificar as características principais do serviço Remessa Econômica de talão de cheques, cartões diversos e CIN, conforme disposto no Anexo 2 deste Capítulo.\n2.1.1.2 Informar aos clientes as características verificadas, bem como as demais informações constantes no presente documento.', 11),
(4830, 'capitulo', 17, 4828, 3, '2.1.2', 'Contratação', '2.1.2.1 Firmar contrato do serviço de Remessa Econômica de talão de cheques, cartões diversos e CIN.\n2.1.2.2 Atentar que não é permitida a vinculação do contrato de Remessa Econômica Talão/Cartão/CIN às unidades da Rede Terceirizada.\n2.1.2.3 Cadastrar, caso houver, com anuência dos Correios, filial, empresa coligada e/ou controlada da contratante, em âmbito nacional, para utilização do serviço, conforme suas necessidades e independentemente da origem do contrato.\n2.1.2.4 Seguir os procedimentos estabelecidos para contratação do serviço estabelecidos no MANFAC 6/1 para pessoa jurídica.\n2.1.2.5 Celebrar o contrato, após aprovação das áreas envolvidas, conforme modelos disponibilizados nos seguintes endereços:\na) anexo do Contrato Múltiplo:\n\\\\sac0424\\CONTRATOS_COMERCIAIS\\DEPRO\\Mensagem\\ANEXOS_CONTRATO_MULTIPLO\nb) anexo do Contrato Simplificado:\n\\\\sac0424\\CONTRATOS_COMERCIAIS\\CONTRATO_MULTIPLO_SIMPLIFICADO\n2.1.2.6 Fornecer aos clientes, após a formalização do contrato, os cartões de autorização de postagem para cada um de seus órgãos credenciados a efetuar postagem no contrato.\n2.1.2.7 Orientar os clientes que os objetos de Remessa Econômica Talão/Cartão/CIN devem ser apresentados para postagem nas agências próprias e/ou diretamente nos centros de tratamento.\n2.1.2.8 Providenciar a assinatura e a remessa à Superintendência Estadual - SE de postagem.\n2.1.2.9 A(s) ficha(s) técnica(s), no caso de haver postagem em SE diferente daquela de origem, após aprovação delas pela SE de origem do serviço, em conformidade com o subitem 2.2.1.3 deste Capítulo.\n2.1.2.10 Anexar a(s) ficha(s) técnica(s), com a programação das respectivas coletas, ao contrato de cada autorizada a utilizar o serviço, para fins de planejamento operacional.\n2.1.2.11 Providenciar a assinatura de nova(s) ficha(s) técnica(s) com as especificações acordadas, com antecedência mínima de 15 (quinze) dias da data de vigência das alterações, quando houver modificação do local, da quantidade de objetos e da frequência da coleta.\n2.1.2.12 Orientar o cliente que, quando não houver viabilidade para realização da coleta, os objetos deverão ser entregues nas unidades de captação previamente definidas e nos horários acordados com os Correios, em conformidade com o subitem 2.2.4.4 deste Capítulo.\n2.1.2.13 Observar o disposto em contrato, no caso de rescisão contratual.', 12),
(4831, 'capitulo', 17, 4827, 2, '2.2', 'Procedimentos da Área Operacional', '', 13),
(4832, 'capitulo', 17, 4831, 3, '2.2.1', 'Procedimentos Gerais', '2.2.1.1 Disponibilizar, à área comercial, para ser fornecido à contratante, o plano de triagem ou sistema de blocagem, o plano de expedição e o modelo de etiquetas de amarrados.\n2.2.1.2 Fornecer os planos de triagem/sistema de blocagem correspondentes às Superintendências Estaduais - SEs envolvidas na prestação do serviço quando o contrato estabelecer postagem em mais de uma SE.\n2.2.1.3 Submeter, para aprovação da SE de prestação do serviço, a(s) ficha(s) técnica(s), quando houver postagem em SE diferente daquele de origem do contrato.\n2.2.1.4 Apresentar a Lista de Postagem em meio eletrônico deve ser entregue/transmitida, aos Correios, com 1 (um) dia útil de antecedência em relação à postagem dos objetos.', 14),
(4833, 'capitulo', 17, 4831, 3, '2.2.2', 'Coleta', '2.2.2.1 Verificar o disposto no subitem 2.2.1.4 deste Capítulo.\n2.2.2.2 Definir, previamente, a frequência das coletas por cada SE, bem como a quantidade de objetos a serem coletados em cada dependência autorizada pela contratante, se for o caso.\n2.2.2.3 Realizar as coletas no endereço indicado pela contratante, podendo ser cadastrado um ou vários pontos de coleta, de acordo com a viabilidade operacional da SE, bem como considerando o disposto no subitem 2.1.2.10 deste Capítulo.\n2.2.2.4 Receber os objetos nas unidades de captação previamente definidas e nos horários acordados com os Correios, quando não houver viabilidade para realização da coleta, em conformidade com o subitem 2.1.2.12 deste Capítulo.', 15),
(4834, 'capitulo', 17, 4831, 3, '2.2.3', 'Postagem', '2.2.3.1 Verificar o disposto no subitem 2.2.1.4 deste Capítulo.\n2.2.3.2 Receber os objetos de Remessa Econômica Talão/Cartão/CIN para postagem nas agências próprias e/ou diretamente nas unidades operacionais devidamente vinculadas especificamente ao contrato, conforme subitem 2.1.2.7 deste Capítulo.\n2.2.3.3 Checar se a contratante e a respectiva filial, empresa coligada e ou controlada apresentaram, no ato da postagem, o Cartão de Autorização de Postagem.\n2.2.3.4 Recusar a postagem de correspondências aglutinadas e endereçadas ao porteiro, zelador, síndico ou qualquer outra pessoa, a fim de que estas efetuem a redistribuição aos respectivos destinatários.\n2.2.3.5 Observar o disposto no MANCAT 6/1/1, para o prazo de guarda dos objetos.', 16),
(4835, 'capitulo', 17, 4831, 3, '2.2.4', 'Distribuição', '2.2.4.1 Aplicar aos objetos da Remessa Econômica Talão/Cartão/CIN o mesmo tratamento, encaminhamento e prazo de entrega estabelecidos para a plataforma operacional do serviço de Carta Comercial Registrada.\n2.2.4.2 Atentar que para os objetos destinados às regiões Norte, Nordeste e Centro-Oeste (exceto Brasília), o prazo de entrega será acrescido em 1 (um) dia útil.', 17),
(4836, 'capitulo', 17, 4831, 3, '2.2.5', 'Devolução de Objetos', '2.2.5.1 Restituir os objetos cuja entrega não tenha sido possível aos respectivos remetentes, conforme definido para o serviço de Carta Comercial Registrada, com a informação do motivo da não entrega.\nNota: nesse caso, aplicam-se as regras dispostas no MANDIS.', 18),
(4837, 'capitulo', 17, 4831, 3, '2.2.6', 'Faturamento', '2.2.6.1 Considerar o período-base de faturamento e data de vencimento da fatura, conforme disposto em contrato.\n2.2.6.2 Estabelecer valor mínimo mensal de acordo as contrapartidas estabelecidas para o pacote de serviço contratado, sendo admitido para a Remessa Econômica Talão/Cartão/CIN os pacotes Platinum ou superiores, conforme Termos de Condições Comerciais dos Correios.\n2.2.6.3 Observar a cota mínima mensal de faturamento estabelecida para o serviço, conforme disposto na Tabela de Preços do serviço.\n2.2.6.4 Incluir, na fatura correspondente ao período, uma complementação financeira para que o montante a ser pago atinja a importância estipulada, na hipótese de o valor referente aos serviços prestados ser inferior à cota mínima estabelecida.\n2.2.6.5 Cobrar a conta mínima após o segundo período base (ciclo) de faturamento, contado a partir do ciclo inicial de faturamento, independentemente da data de assinatura e vigência do contrato, no caso de novos contratos.\n* * * * *', 19),
(4838, 'capitulo', 18, NULL, 1, '1', 'ATRIBUTOS DOS SUBPROCESSOS', '1.1 Objetivo: prestar um serviço que permita o franqueamento prévio de cartas simples e registradas, nas modalidades FAC Simples e FAC Registrado.\n1.2 Abrangência: nacional.\n1.3 Gestor: Departamento de Gestão de Serviços Nacionais - DEPRO/DINEG\n1.4 Fornecedores: áreas de vendas e operacional.\n1.5 Clientes: pessoas jurídicas, públicas e privadas que efetuam a postagem de grandes volumes de correspondências.\n1.6 Periodicidade: contínua.\n1.7 Duração: prazo indeterminado.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', 0);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(4839, 'capitulo', 18, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos do Órgão de Vendas\n2.1.1 Informar aos clientes as características principais do serviço FAC dispostas no Anexo 3 deste Capítulo, bem como as demais informações constantes neste documento.\n2.1.2 Orientar os clientes quanto ao cumprimento dos pré-requisitos de postagem estabelecidos para uso do serviço, especificados no Anexo 2 deste Capítulo.\n2.1.3 Negociar o FAC junto aos clientes que, comprovadamente, mediante validação prévia do órgãos de vendas da respectiva Superintendência Estadual - SE, tenham condições de atender aos pré-requisitos de postagem, especificados no Anexo 2 deste Capítulo.\n2.1.4 Orientar o cliente que não será aceita a carga para postagem sem a chancela de franqueamento e sem o arquivo de postagem.\n2.1.5 Disponibilizar a carga para retirada, caso não sejam apresentados a chancela de franqueamento e/ou o arquivo de postagem.\n2.1.6 Orientar os clientes a retirar, nas dependências dos Correios, a carga não postada em decorrência das situações previstas no MANCAT 6/13, Anexo 5.\n2.1.7 Providenciar, no que compete ao órgão de vendas, bem como orientar os clientes no que couber, os procedimentos estabelecidos:\na) no subitem 2.4 deste Capítulo, quanto ao processo de postagem do serviço FAC;\nb) no subitem 2.5 deste Capítulo, quanto à devolução de objetos não entregues;\nc) no subitem 2.6 deste Capítulo, sempre que houver atualização de plano de triagem ou sistemas de blocagem;\nd) no subitem 2.7 deste Capítulo, quanto ao faturamento dos objetos;\ne) no Anexo 2 deste Capítulo, quanto ao cumprimento dos pré-requisitos e validações de códigos e arquivo de postagem.\n2.1.8 Acompanhar o histórico dos contratos, por meio dos relatórios emitidos pelo sistema GPOST, a fim de avaliar as providências a serem adotadas com relação ao contrato, no caso de repetidas inconsistências constantes no MANCAT 6/13, Anexo 5.\n2.1.9 Orientar os clientes que o serviço admite coleta, considerando o disposto abaixo:\na) a(s) frequência(s) da(s) coleta(s) deve(m) ser definida(s) em cada SE, de acordo com a demanda dos respectivos clientes e viabilidade operacional dos Correios da respectiva SE;\nb) deve ser estabelecido e anexado ao contrato, para cada filial, empresa coligada e/ou controladora autorizada a efetuar a postagem, uma Ficha Técnica, conforme modelo estabelecido pelos Correios, com a programação das respectivas coletas, para o planejamento operacional;\nc) deve ser providenciada a assinatura e a remessa à SE de postagem da(s) Ficha(s) Técnica(s), no caso de haver postagem em SE diferente daquela de origem do contrato, após aprovação das mesmas pela SE de origem do serviço, em conformidade com o subitem 2.2.3 deste Capítulo.\n2.1.10 Solicitar ao cliente um objeto-teste (máscara) e realizar a Avaliação Técnica Comercial - ATC, de acordo com o tipo de objetos do cliente (envelope ou autoenvelope sem ou com o código 2D), por meio da qual são avaliadas as características físicas e geométricas que determinam se tal objeto:', 1),
(4840, 'capitulo', 18, 4839, 4, 'a', 'é formato automatizável com CEPNet (pré-requisito de postagem);', '', 2),
(4841, 'capitulo', 18, 4839, 4, 'b', 'contém o código Bidimensional Datamatrix 2D automatizável com CEPNet.', '2.1.10.1 Informar ao gestor comercial do contrato que na hipótese de a máscara ser considerada adequada (situação aprovada) em ATC, após preenchimento do formulário e inserção da imagem no sistema GPOST, deverá solicitar ao cliente, conforme opções a seguir:', 3),
(4842, 'capitulo', 18, 4839, 4, 'a', 'opção 1 - ATO Inicial:', 'I - apresentar no mínimo 500 (quinhentos) objetos (massa de teste) com endereços/CEPs válidos de várias localidades (âmbitos local, estadual e nacional), e com o CEPNet e Código Bidimensional Datamatrix 2D impresso;\nII - informar o número da ATC aprovada ao CTC/CTCE automatizado da respectiva SE ou da SE automatizada mais próxima no caso de SEs não automatizadas, para realização da Avaliação Técnica Operacional - ATO;\nIII - se a ATC/ATO for aprovada no GPOST e inserida a numeração no arquivo de postagem correspondente ao(s) objeto(s) da(s) máscara(s) aprovada(s), o pré-requisito “Objeto Formato Automatizável com CEPNet” será habilitado para a postagem de imediato no sistema.', 4),
(4843, 'capitulo', 18, 4839, 4, 'b', 'opção 2: ATO Inicial + ATO de Fluxo:', 'I - apresentar no mínimo 50 (cinquenta) objetos com endereços/CEPs válidos de várias localidades (âmbitos local, estadual e nacional) e com o CEPNet e Código Bidimensional Datamatrix 2D impresso;\nII - informar o número da ATC aprovada ao CTC/CTCE automatizado da respectiva SE ou da SE automatizada mais próxima no caso de SEs não automatizadas, para realização da Avaliação Técnica Operacional - ATO;\nIII - neste caso, o teste será realizado com a carga real (mínimo de 2.000 objetos) e o pré-requisito “Objeto Formato Automatizável com CEPNet” será habilitado para a postagem de imediato no sistema, se houver aprovação.\nNota 1: os formulários das avaliações técnicas (ATC e ATO) encontram-se disponíveis no menu Avaliação Técnica >>> Realização de Avaliação, do sistema GPOST.\nNota 2: recomenda-se a leitura do Guia Técnico CEPNet e Código Bidimensional Datamatrix 2D indicados no MANCAT 6/13, Anexo 2 - 1.6.\n2.1.11 Fornecer ao cliente, quando o contrato estabelecer postagem em mais de uma SE, os planos de triagem ou sistemas de blocagem correspondentes às SEs envolvidas na prestação do serviço.\n2.1.12 Orientar o cliente e a(s) respectiva(s) filial(is), empresa coligada e/ou controlada do cliente, caso houver, que é obrigatória no ato da postagem, a apresentação do Cartão de Autorização de Postagem.\n2.1.13 Orientar o cliente que não será aceita a postagem de objetos aglutinados e endereçados ao porteiro, zelador, síndico ou a qualquer outra pessoa, a fim de que estes efetuem a redistribuição aos respectivos destinatários.\n2.1.13.1 Considerar como aglutinação o envio de mais de um objeto, com destinatários diferentes, contidos em um mesmo envoltório.\n2.2 Contratação\n2.2.1 Firmar contrato exclusivamente com pessoa jurídica que, comprovadamente, mediante prévia validação do órgão de vendas da SE, tenha condições de atender aos critérios de postagem especificados no subitem 2.1.3 deste Capítulo.\nNota: o serviço está disponível nas modalidades FAC Simples e FAC Registrado.\n2.2.2 Demandar, à área de suporte comercial, o cadastro, caso houver, com anuência dos Correios, de filial, empresa coligada e/ou controlada do cliente, em âmbito nacional, para utilização do serviço FAC, conforme suas necessidades e independentemente da origem do contrato.\n2.2.3 Atentar para o fato de que é admitida a postagem de objetos de terceiros, com indicação do remetente distinta do cliente, por meio de um único termo contratual, desde que firmado exclusivamente com bancos, financeiras, administradoras de cartão de crédito, empresas de cobrança, Câmara\\Clube dos Dirigentes Lojistas - CDL e Associações Comerciais, considerando o descrito abaixo:', 5),
(4844, 'capitulo', 18, 4839, 4, 'a', 'a gestão das postagens efetuadas dispostas neste subitem e o relacionamento comercial e financeiro junto aos Correios serão de responsabilidade exclusiva do cliente;', '', 6),
(4845, 'capitulo', 18, 4839, 4, 'b', 'poderá constar no envoltório do objeto logomarca distinta do cliente;', '', 7),
(4846, 'capitulo', 18, 4839, 4, 'c', 'para as postagens de objetos de terceiros, deve ser considerada a atividade principal ou secundária do cliente.', '2.2.4 Seguir os procedimentos estabelecidos para celebração e cadastro de contratos previstos no MANCAT 28 e MANFAC 6 para pessoa jurídica.\n2.3 Procedimentos da Área Operacional\n2.3.1 Disponibilizar ao órgão de vendas, para ser fornecido ao cliente, o plano de triagem ou sistema de blocagem, bem como o plano de expedição para a unitização de carga, para a postagem de objetos simples e sob registro, no âmbito da respectiva SE.\n2.3.1.1 Fornecer aos clientes, o modelo da etiqueta de amarrados para a postagem dos objetos, a qual deverá conter as informações necessárias ao encaminhamento dos objetos, conforme normas em vigor.\n2.3.2 Estabelecer, juntamente com o órgão de vendas e clientes, as frequências das coletas a serem efetuadas para cada contrato, observando o disposto no subitem 2.1.7 deste Capítulo, bem como suas respectivas alíneas.\n2.3.3 Submeter, para aprovação da SE de prestação do serviço, a(s) ficha(s) técnica(s), quando houver postagem em Unidade Federativa diferente daquele de origem do contrato.\n2.3.4 Efetuar as coletas em domicílio, de acordo com o estabelecido em cada ficha técnica.\n2.3.5 Providenciar, no que compete à área operacional, os procedimentos estabelecidos:\na) no subitem 2.4 deste Capítulo, quanto ao processo de postagem do serviço FAC;\nb) no subitem 2.5 deste Capítulo, quanto à devolução de objetos não entregues;\nc) no subitem 2.6 deste Capítulo, sempre que houver atualização de plano de triagem ou sistemas de blocagem;\nd) no Anexo 2 deste Capítulo, quanto ao cumprimento dos pré-requisitos e validações de códigos e arquivo de postagem.\n2.3.6 Orientar as respectivas unidades de postagem quanto à operacionalização do serviço.\n2.3.6.1 Informar a Gerência de Operações da sua jurisdição, para que sejam tomadas as providências necessárias, caso as unidades operacionais constatem a existência de alguma desconformidade na execução do serviço.\n2.4 Postagem\n2.4.1 Observar os procedimentos para postagem dispostos no Processo de Postagem do Serviço FAC - Anexo 5 deste Capítulo, no MANENC 15/5 e nos passo a passos de postagem disponíveis no link: https://intranet.correios.com.br/cs/dineg/sucan/espaco-do-consultor-1/portfolio/portfolio-1.\nNota: na inobservância de pré-requisitos de postagem e/ou identificação de inconsistências previstas para o FAC que resulte em alteração no preço da postagem prevista, os objetos, mesmo que descaracterizados, só poderão ser apresentamos para postagem nas Unidades Operacionais autorizadas pelos Correios, sendo estritamente proibidas a sua postagem em Agências.\n2.5 Devolução de Objetos não Entregues\n2.5.1 Restituir os objetos cuja entrega ao destinatário não tenha sido possível, tanto na modalidade simples como registrada, aos respectivos remetentes, conforme definido para o serviço de carta, com a informação do motivo da não entrega.\n2.5.1.1 Utilizar, caso seja opção do cliente, a Devolução Eletrônica dos Objetos.\n2.5.2 Admitir, para objetos registrados quando não houver Devolução Eletrônica de Objetos, a devolução imediata ao remetente, quando da eventual não entrega do objeto, observado os seguintes critérios:\na) a devolução imediata ao cliente é opcional, que deverá apor, em cada envoltório, a mensagem abaixo indicada, de forma visível, por meio de impressão ou carimbo, com vistas a indicar, às unidades operacionais, o tratamento a ser dado ao objeto:\nI - objetos com AR: apor no envoltório, abaixo da assinatura do carteiro (abaixo dos motivos da não entrega), a mensagem “Devolução Imediata Após a Terceira Tentativa de Entrega”;\nII - objetos registrados sem AR: apor a mensagem “Devolução Imediata Após a Tentativa de Entrega” na área 3 do envoltório (área destinada ao bloco de endereço do destinatário), ao lado direito do bloco de endereçamento.\nb) os objetos destinados às localidades não atendidas pela distribuição domiciliária devem ser direcionados para entrega interna, conforme disposto no MANDIS 3/1, Anexo 2, mesmo que conste no envoltório a menção de devolução imediata;\nc) os objetos endereçados à Caixa Postal devem seguir o fluxo normal deste serviço, mesmo que conste no envoltório a menção de devolução imediata.\n2.6 Atualização do Plano de Triagem ou Sistema de Blocagem\n2.6.1 Observar o fluxo constante no Anexo 4 deste Capítulo e o disposto nas alíneas subsequentes, quando houver atualização do plano de triagem ou sistema de blocagem:\na) quando atualizado o plano de triagem ou sistema de blocagem, o Departamento de Tratamento - DTRAT disponibilizará o respectivo documento na intranet, em seu portal e providenciará as seguintes comunicações:\nI - aos órgãos da área operacional, em âmbito nacional, para implantação conforme datas pré-estabelecidas em cronograma disponibilizado no portal do DTRAT;\nII - ao Departamento de Vendas - DEVEN, que deverá repassar a informação às Gerências Regionais, em nível nacional, em até 3 (três) dias úteis, contados a partir do dia seguinte ao da comunicação do Departamento de Tratamento - DTRAT.', 8),
(4847, 'capitulo', 18, 4839, 4, 'b', 'o gestor comercial do contrato deve disponibilizar, ao respectivo cliente, o plano atualizado em até 3 (três) dias úteis, contados a partir do dia seguinte ao da comunicação do Departamento de Vendas;', 'Nota: a entrega do documento ao cliente deve ser protocolada. Uma cópia do protocolo deve ser encaminhada à unidade responsável pela captação da carga FAC do respectivo cliente até o dia seguinte, para fins de controle do prazo limite para adequação da carga ao novo plano.', 9),
(4848, 'capitulo', 18, 4839, 4, 'c', 'a partir do dia seguinte ao da entrega do plano, o cliente deve adequar a sua carga ao novo plano de triagem/sistema de blocagem em até 30 (trinta) dias corridos;', 'Nota: durante esse período de adequação do plano pelo cliente, a carga FAC postada com o plano desatualizado deve ser faturada normalmente, conforme Tabela de Preços e Tarifas estabelecida para o serviço. Não deve ser aplicado à carga o disposto no subitem 2.1.6 deste Capítulo.\nd) a partir do 31º dia, na hipótese de o cliente não ter se adequado ao novo plano, para fins de faturamento, a carga deve ser faturada conforme disposto no subitem 2.1.6 do presente Capítulo.\n2.7 Faturamento\n2.7.1 Seguir os procedimentos estabelecidos para a consolidação dos registros de postagens e para emissão de faturas, de acordo com as regras de negócios e tarifárias estabelecidas no contrato, conforme disposto no MANFAC 3/1.\n* * * * *', 10),
(4849, 'capitulo', 20, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(4850, 'capitulo', 20, 4849, 2, '1.1', 'Objetivo: prestar o serviço de postagem, encaminhamento e distribuição de peças promocionais, comumente denominadas Malas Diretas, com apelo para oferta e divulgação de produtos e serviços e/ou com a finalidade de prospectar ou fidelizar clientes.', '', 1),
(4851, 'capitulo', 20, 4849, 2, '1.2', 'Abrangência: nacional.', '', 2),
(4852, 'capitulo', 20, 4849, 2, '1.3', 'Gestor: Departamento de Gestão de Serviços Nacionais - DEPRO/DINEG', '', 3),
(4853, 'capitulo', 20, 4849, 2, '1.4', 'Fornecedores: áreas comercial, operacional e atendimento.', '', 4),
(4854, 'capitulo', 20, 4849, 2, '1.5', 'Clientes: pessoas físicas e jurídicas.', '', 5),
(4855, 'capitulo', 20, 4849, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4856, 'capitulo', 20, 4849, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4857, 'capitulo', 20, 4849, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', '', 8),
(4858, 'capitulo', 20, NULL, 1, '2', 'DESCRIÇÕES DO SUBPROCESSO', '', 9),
(4859, 'capitulo', 20, 4858, 2, '2.1', 'Área Comercial', '', 10),
(4860, 'capitulo', 20, 4859, 3, '2.1.2', 'Atividades de Contratação', '2.1.3 Firmar contrato, junto ao cliente, conforme modelos estabelecidos pelos Correios.\n2.1.4 Orientar o cliente sobre a cota mínima financeira estabelecida para o serviço, vigente na data da postagem quando se tratar de contratos assinados até fevereiro de 2020.\n2.1.5 Orientar o cliente sobre as formas de franqueamento dos objetos, conforme a seguir:', 11),
(4861, 'capitulo', 20, 4860, 4, 'a', 'Mala Direta Básica com franqueamento em máquina de franquear: disponível à vista e a faturar em AGF;', '', 12),
(4862, 'capitulo', 20, 4860, 4, 'b', 'Mala Direta Básica com franqueamento por meio de chancela: disponível à vista em Unidades Próprias e a faturar em Unidades Própria e Agência franqueada - AGF.', 'Nota: os objetos sem o devido franqueamento não serão recebidos, conforme estabelecido no MANCAT 3/1.\n2.1.6 Manter o cliente instruído sobre a importância de consultar os Correios, com antecedência, quando da necessidade de desenvolverem peças promocionais fora dos padrões usuais.', 13),
(4863, 'capitulo', 20, 4858, 2, '2.2', 'Unidade de Atendimento', '', 14),
(4864, 'capitulo', 20, 4863, 3, '2.2.2', 'Atividades de Aceitação de Objetos', '2.2.2.1 Identificar a modalidade de postagem: à vista ou a faturar.\n2.2.2.2 Identificar a forma de franqueamento.\n2.2.2.3 Verificar se os objetos estão devidamente franqueados.\nNota 1: os objetos sem o devido franqueamento não deverão ser recebidos, conforme estabelecido no MANCAT 3/1.\nNota 2: as regras quanto à classificação de objetos estão descritas no item 2.1 do MANCAT 6/4.\n2.2.2.4 Verificar a situação do contrato e do cartão de postagem, no caso da modalidade a faturar.\n2.2.2.5 Rejeitar a carga, caso o contrato ou cartão de postagem estejam suspensos ou cancelados.\n2.2.2.6 Verificar se os objetos apresentam as características que definem o Serviço Mala Direta Básica e se não se enquadram na relação de objetos proibidos, conforme definido no MANCAT 6/4, observando que:\na) devem ser apresentados (postados) abertos para verificação do conteúdo. Neste caso, após a verificação do conteúdo, os objetos seguem abertos no fluxo postal ex.: Folders;', 15),
(4865, 'capitulo', 20, 4864, 4, 'b', 'caso sejam apresentados (postados) totalmente fechados, deve constar, obrigatoriamente, no invólucro do objeto a expressão “Fechamento Autorizado. Pode ser aberto pelos Correios”. Nesta condição, a referida expressão deve fazer parte do objeto durante todo fluxo postal, caso o objeto seja um serviço de Mala Direta;', '', 16),
(4866, 'capitulo', 20, 4864, 4, 'c', 'para os objetos que forem apresentados (postados) parcialmente abertos, como por exemplo, utilização de invólucros transparentes e/ou de lacres, o atendimento deverá analisar se é possível a visualização e classificação do conteúdo na sua integralidade. Se não for possível identificar o conteúdo, o objeto deverá então seguir com a expressão “Fechamento Autorizado. Pode ser aberto pelos Correios”.', 'Nota: caso não atendida as condições dispostas nesse item, o objeto não se classificará como Mala Direta.\n2.2.2.6.1 Proceder conforme orientações a seguir, se apresentadas inconsistências nas especificações do subitem 2.2.2.6:', 17),
(4867, 'capitulo', 20, 4864, 4, 'a', 'reter a carga;', '', 18),
(4868, 'capitulo', 20, 4864, 4, 'b', 'comunicar de imediato à contratante/preposto;', '', 19),
(4869, 'capitulo', 20, 4864, 4, 'c', 'informar o ocorrido ao Gerente de Contas Especiais - GCE / Assistente Comercial -  ACOM, por e-mail;', '', 20),
(4870, 'capitulo', 20, 4864, 4, 'd', 'solicitar que seja realizada a correção da falha ou o aceite da postagem como Carta ou Encomenda, a depender da correta classificação, conforme conteúdo, até o horário de funcionamento da Unidade de Postagem, do dia útil posterior ao da solicitação, conforme item 2.7 deste Capítulo;', '', 21),
(4871, 'capitulo', 20, 4864, 4, 'e', 'disponibilizar a carga para retirada pela contratante/preposto, caso a carga não seja ajustada ou não haja aceite da postagem como Carta ou Encomenda.', '2.2.2.7 Verificar se o nome e endereçamento do remetente e destinatário estão completos.\n2.2.2.8 Verificar se os objetos estão de acordo com os pesos e dimensões estabelecidos para o serviço.\n2.2.2.9 Verificar se os objetos estão acondicionados corretamente, conforme as orientações de acondicionamento.\n2.2.2.10 Verificar se os objetos apresentados estão acompanhados da Lista de Postagem - LP, em abrangências distintas, considerando-se a distribuição local, estadual e nacional.\n2.2.2.11 Rejeitar a carga desacompanhada da LP.\n2.2.2.12 Verificar se os objetos estão organizados em amarrados dentro de unitizadores, devidamente etiquetados, levando-se em conta o descrito no MANENC 15/3, nos casos de postagem a faturar.\n2.2.2.13 Verificar se os objetos se apresentam encabeçados, faceados, triados e agrupados em amarrados, para postagem nos horários e locais acordados previamente com os Correios.\n2.2.2.14 Verificar se cada amarrado contém somente objetos idênticos, de mesmo formato, tamanho e peso.\n2.2.2.15 Observar se consta de cada amarrado um espelho, conforme modelo definido pela área operacional, contendo a data da postagem, o destino e o primeiro número de CEP relativo aos objetos nele incluídos, se possível, impresso em código de barras padrão 128.\nNota: a carga deverá atender ao plano de triagem de clientes com contrato Mala Direta Básica ou sistema de blocagem, conforme fornecido pelos Correios. No caso de postagem à vista, é exigido que a carga seja postada apenas com a triagem por abrangência.', 22),
(4872, 'capitulo', 20, 4858, 2, '2.3', 'Atividades de Recebimento de Objetos', '', 23),
(4873, 'capitulo', 20, 4872, 3, '2.3.1', 'Pesar, no caso de objetos com chancela, uma amostra de 10 (dez) objetos, dividindo o peso da amostra por 10 (dez), para cálculo do peso unitário médio, conforme detalhamento abaixo:', '', 24),
(4874, 'capitulo', 20, 4873, 4, 'a', 'pesar a carga;', '', 25),
(4875, 'capitulo', 20, 4873, 4, 'b', 'contar a quantidade de cada tipo de unitizador;', '', 26),
(4876, 'capitulo', 20, 4873, 4, 'c', 'verificar se a divergência entre o peso total líquido aferido pelos Correios e o informado na Lista de Postagem respeita a margem de tolerância de 2% (dois por cento).', '', 27),
(4877, 'capitulo', 20, 4872, 3, '2.3.2', 'Verificar se a quantidade e o peso indicados na lista de postagem conferem com os resultados obtidos na conferência efetuada. Nessa conferência, se os objetos estiverem dispostos em unitizadores, deve-se excluir os pesos dos unitizadores.', '', 28),
(4878, 'capitulo', 20, 4872, 3, '2.3.3', 'Inserir as informações obtidas na pesagem, peso unitário e quantidade, conforme cada abrangência, no respectivo código de serviço no sistema de postagem.', '', 29),
(4879, 'capitulo', 20, 4872, 3, '2.3.4', 'Franquear os objetos com estampa de máquina de franquear digital, para os casos de franqueamento por máquina de franquear, obrigatoriamente com a descrição do serviço na estampa digital.', '', 30),
(4880, 'capitulo', 20, 4872, 3, '2.3.5', 'Carimbar Depois do Horário - DH para as remessas efetuadas após o horário limite de postagem da agência.', '', 31),
(4881, 'capitulo', 20, 4872, 3, '2.3.6', 'Gerar dados para faturamento no sistema de postagem.', '', 32),
(4882, 'capitulo', 20, 4872, 3, '2.3.7', 'Entregar comprovante de postagem, emitido pelo sistema de postagem, ao cliente.', '', 33),
(4883, 'capitulo', 20, 4872, 3, '2.3.8', 'Encaminhar os objetos para tratamento.', '', 34),
(4884, 'capitulo', 20, 4858, 2, '2.4', 'Procedimentos de Encaminhamento - AGF para Objetos com Chancela', '', 35),
(4885, 'capitulo', 20, 4884, 3, '2.4.1', 'Encaminhar a carga unitizada e separada por cliente, para o respectivo centralizador, acompanhada do documento de postagem (Lista de Postagem e Comprovante de Postagem).', '', 36),
(4886, 'capitulo', 20, 4884, 3, '2.4.2', 'Rotular a carga conforme Anexo 3 deste Capítulo.', 'Nota: os rótulos deverão ser numerados, de acordo com o total de unitizadores que compõem a carga gerada para cada cliente.\nExemplo: 1/N, 2/N, 3/N, .... N/N.', 37),
(4887, 'capitulo', 20, 4884, 3, '2.4.3', 'Inserir o documento de postagem (Lista de Postagem e Comprovante de Postagem) no primeiro unitizador: 1/N.', '2.4.4 Seguir com a carga conforme coleta normal.', 38),
(4888, 'capitulo', 20, 4858, 2, '2.5', 'Área Operacional', '', 39),
(4889, 'capitulo', 20, 4888, 3, '2.5.1', 'Procedimentos de Conferência (Centralizador) para Objetos com Chancela - Carga oriunda de AGF', '2.5.1.1 Conferir a carga na Gerência de Controle e Captação - GCCAP dos Centros de Tratamento, no caso de postagens com mais de 5.000 (cinco mil) objetos.\n2.5.1.2 Receber a carga separada por âmbito (local, estadual e nacional) acompanhada da LP e comprovante de postagem emitido pelo sistema de postagem e executar, para cada âmbito, os seguintes procedimentos:', 40),
(4890, 'capitulo', 20, 4889, 4, 'a', 'pesar a carga;', '', 41),
(4891, 'capitulo', 20, 4889, 4, 'b', 'contar a quantidade de cada tipo de unitizador;', '', 42),
(4892, 'capitulo', 20, 4889, 4, 'c', 'pesar amostra de 10 (dez) objetos, para cálculo do peso médio unitário do objeto;', '', 43),
(4893, 'capitulo', 20, 4889, 4, 'd', 'lançar os dados aferidos nas alíneas “a” a “c” no “Relatório de Pesagem”;', '', 44),
(4894, 'capitulo', 20, 4889, 4, 'e', 'verificar se a divergência entre o peso total líquido aferido pelos Correios e o informado na Lista de Postagem respeita a margem de tolerância de 2% (dois por cento).', '2.5.1.3 Verificar se o franqueamento dos objetos está de acordo com o estabelecido para o serviço.\n2.5.1.4 Observar, aleatoriamente, se os amarrados contêm apenas objetos idênticos, de mesmo formato, tamanho e porte.\n2.5.1.5 Retirar de cada postagem, de cada âmbito (local, estadual, nacional), aleatoriamente, no mínimo uma amostra dos unitizadores primários e/ou secundários e posteriormente verificar se:', 45),
(4895, 'capitulo', 20, 4889, 4, 'a', 'foi cumprido o plano de triagem vigente;', '', 46),
(4896, 'capitulo', 20, 4889, 4, 'b', 'consta dos amarrados etiqueta contendo a data da postagem, o destino, a classificação do objeto e o CEP inicial da faixa correspondente ao destino;', '', 47),
(4897, 'capitulo', 20, 4889, 4, 'c', 'o conteúdo dos amarrados está de acordo com a identificação da etiqueta e corresponde à direção mencionada no rótulo dos unitizadores primários;', '', 48),
(4898, 'capitulo', 20, 4889, 4, 'd', 'os objetos estão faceados e encabeçados;', '', 49),
(4899, 'capitulo', 20, 4889, 4, 'e', 'os rótulos dos unitizadores primários possuem as informações de data, unidade de origem e destino, CEP inicial da faixa correspondente ao destino e categoria do objeto;', '', 50),
(4900, 'capitulo', 20, 4889, 4, 'f', 'os rótulos dos unitizadores secundários estão de acordo com padrão estabelecido no Anexo 3 deste Capítulo;', '', 51),
(4901, 'capitulo', 20, 4889, 4, 'g', 'a carga for oriunda de unidades de AGF, observar se os rótulos contêm o carimbo datador;', '', 52),
(4902, 'capitulo', 20, 4889, 4, 'h', 'o CEP de destino dos objetos corresponde aos rótulos dos unitizadores primários;', 'i) as informações do rótulo do unitizador primário estão de acordo com as informações do rótulo do unitizador secundário.\n2.5.1.6 Reter a carga e submeter o caso para a equipe de supervisão de receita, para os casos de divergência (quantidade de objetos e peso), para que a mesma proceda de acordo com o previsto no MANCAT 15/1.\n2.5.1.7 Conferir a carga pelo supervisor de atendimento, no caso de postagens com menos de 5.000 objetos, conforme previsto no MANCAT 15/1.\n2.5.1.8 Observar se as postagens dos objetos com chancela estão devidamente lançados no sistema de postagem, observando se a carga física está de acordo com as informações registradas no referido sistema.', 53),
(4903, 'capitulo', 20, 4858, 2, '2.6', 'Procedimentos de Distribuição', '', 54),
(4904, 'capitulo', 20, 4903, 3, '2.6.1', 'Encaminhar e efetuar a distribuição dos objetos de acordo com os procedimentos e normas operacionais estabelecidos pelos Correios, conforme consta no MANDIS e MANENC.', '', 55),
(4905, 'capitulo', 20, 4858, 2, '2.7', 'Procedimentos para Regularização de Cobrança por Divergência de Classificação', '2.7.1 Realizar conferência e correção de eventuais divergências de classificação de objeto, após a postagem ou a qualquer tempo, com prevalência de sua aferição, sendo cabível a restituição de valores no caso de diferença entre o valor faturado e o valor apurado.\n2.7.2 Reclassificar o objeto como Carta ou Encomendas, de acordo com o conteúdo do objeto, se confirmada a existência de objetos cobrados a menor devido a divergência de classificação. Porém, sempre que possível, reclassificar prioritariamente como Carta, caso o conteúdo seja em formato escrito, exceto se houver brindes.\n2.7.3 Alterar o faturamento do cliente, ajustado ao valor da reclassificação, manter o objeto na mesma plataforma postal e não realizar novo etiquetamento para o objeto, quando o serviço de Mala Direta for reclassificado para Encomenda ou Carta.\n2.7.4 Informar o ocorrido ao GCE/ACOM ou à Agência, por e-mail, para que possa entrar em contato com o cliente.\n2.7.5 Proceder o recolhimento da diferença (Unidade de Postagem) por meio do Sistema SARA, utilizando o código 55565.\n2.7.6 Devolver a carga para o cliente em caso de recusa à cobrança da diferença por motivo de reclassificação.\nNota 1: quando não houver possibilidade de identificar o cliente para regularização à vista e o ônus for incorporado pelos Correios, será responsabilizado como regra geral, pelo pagamento da parte complementar, o empregado dos Correios ou o permissionário que tiver efetuado a postagem.\nNota 2: na regularização da pendência a faturar, comunicar ao cliente, e efetuar o recolhimento da diferença no cartão do cliente que originou a postagem incorreta, utilizando como referência o mesmo número do documento e registrando a operação no código de serviço 55565.\n* * * * *', 56),
(4906, 'capitulo', 21, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: fornecer aos clientes banco de dados constituído de elementos de endereçamento brasileiro até nível de secção de logradouro e Códigos de Endereçamento Postal – CEP, disponível para venda na Loja Virtual dos Correios, por meio de download do arquivo da base de dados DNE e atualizações.\n1.2 Abrangência: nacional e internacional.\n1.3 Gestor:  DPOST/SUCOM.\n1.4 Fornecedores: áreas comercial e técnica;\n1.5 Clientes: pessoas jurídicas e profissionais liberais.\n1.6 Periodicidade: contínua.\n1.7 Duração: prazo indeterminado.', 0),
(4907, 'capitulo', 21, NULL, 1, '2', 'DESCRIÇÃO DOS SUBPROCESSOS', '2.1 Procedimentos para comercialização\n2.1.1 Adquirir o serviço mediante compra via Loja Virtual dos Correios, por meio de download do arquivo da base de dados DNE e atualizações.\nNOTA: a venda ocorrerá nos mesmos moldes da compra dos demais produtos/serviços disponíveis na nossa loja virtual.\n2.1.2 Efetuar cadastro na CorreiosOnline, criando login (e-mail) e senha, para acesso à loja virtual.\nNOTA: esses dados serão os mesmos para todas as aquisições de serviços/produtos realizados na Loja Correios Online.\n2.1.3 Concordar com as regras de negócio, mediante o aceite do Termo de Compromisso, conforme modelo do Anexo 3 deste capítulo.\n2.1.4 Efetuar pagamento.\nNOTA: o acesso ao download DNE/atualização será disponibilizado logo após a confirmação do pagamento pela Correios On Line.\n2.1.5 Realizar download do arquivo, que estará disponibilizado na pasta “Meus Downloads” somente após confirmação de pagamento.\n2.2 Procedimentos para Manutenção\n2.2.1 DEPLA\n2.2.1.1 Consolidar os dados da base DNE.\n2.2.1.2 Elaborar e emitir “Comunicados” para veiculação nas bases de dados comerciais.\n2.2.2 Área Técnica\n2.2.2.1 Gerar as matrizes da base DNE.\n2.2.2.2 Disponibilizar base DNE para as SEs e DPOST.\n2.2.3 Área Comercial – DPOST/SUCOM\n2.2.3.1 Abrir PAP de serviço para atualização da base DNE.\n2.2.3.2 Comunicar às Macrorregiões da disponibilização da base DNE e data de publicação no institucional.\n2.2.3.3 Comunicar ao DEENC/SUCOM\na) a data de publicação e comercialização da nova versão; e\nb) solicitar criação dos códigos para a nova versão e respectivos vínculos e atualização das informações na loja virtual.\n2.2.3.4 Expedir para o DPOST, CESAD e SEs comunicado sobre as alterações ocorridas na base DNE.\n2.2.4 Área Executante – DEENC/SUCOM\n2.2.4.1 Adequar o ambiente Correios Online para a comercialização do DNE de forma que as regras previamente definidas pelo DPOST/SUCOM sejam contempladas.\n2.2.4.2 Criar códigos da nova versão e respectivos vínculos.\n2.2.4.3 Atualizar informações da loja e comercializar o DNE.\n* * * * *', 1),
(4908, 'capitulo', 22, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(4909, 'capitulo', 22, 4908, 2, '1.1', 'Objetivo: prestar o serviço de recebimento, tratamento e distribuição de objetos promocionais em domicilio, denominados Mala Direta, personalizadas ou não, com ou sem Serviços Adicionais, postados com endereço, em âmbito nacional, com Devolução Eletrônica da informação dos motivos de não entrega.', '', 1),
(4910, 'capitulo', 22, 4908, 2, '1.2', 'Abrangência: nacional.', '', 2),
(4911, 'capitulo', 22, 4908, 2, '1.3', 'Gestor: DPOST/DINEG.', '', 3),
(4912, 'capitulo', 22, 4908, 2, '1.4', 'Fornecedores: áreas comercial, operacional e técnica.', '', 4),
(4913, 'capitulo', 22, 4908, 2, '1.5', 'Clientes: pessoas jurídicas.', '', 5),
(4914, 'capitulo', 22, 4908, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(4915, 'capitulo', 22, 4908, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(4916, 'capitulo', 22, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 8),
(4917, 'capitulo', 22, 4916, 2, '2.1', 'Área Comercial:', '', 9),
(4918, 'capitulo', 22, 4917, 3, '2.1.1', 'Atividades de contratação.', '', 10),
(4919, 'capitulo', 22, 4917, 3, '2.1.2', 'Firmar contrato, junto ao cliente, conforme modelos estabelecidos pelos Correios.', '2.1.3 Fornecer e orientar o cliente quanto às regras de negócio necessárias para utilização do serviço.', 11),
(4920, 'capitulo', 22, 4917, 3, '2.1.4', 'Avaliar os objetos previamente, em relação às regras de endereçamento, leiaute e leitura dos códigos de barras dos objetos (etiquetas e amarrados).', '', 12),
(4921, 'capitulo', 22, 4917, 3, '2.1.5', 'Manter o cliente instruído sobre a importância de consultar os Correios, com antecedência, quando da necessidade de desenvolverem peças promocionais fora dos padrões usuais.', '', 13),
(4922, 'capitulo', 22, 4917, 3, '2.1.6', 'Cadastrar o cliente no Sistema Direto.', '', 14),
(4923, 'capitulo', 22, 4916, 2, '2.2', 'Unidade de Atendimento', '', 15),
(4924, 'capitulo', 22, 4923, 3, '2.2.1', 'Atividades de aceitação de objetos.', '', 16),
(4925, 'capitulo', 22, 4923, 3, '2.2.2', 'Verificar, no ato da postagem, a situação do contrato e do cartão de postagem.', '2.2.3 Recusar a postagem caso o contrato ou cartão de postagem esteja suspenso ou cancelado.\n2.2.4 Recusar o recebimento da carga caso o contrato ou cartão de postagem estejam suspensos ou cancelados.', 17),
(4926, 'capitulo', 22, 4923, 3, '2.2.5', 'Verificar se o objeto apresenta as características que definem o serviço Mala Direta Especial e se não está enquadrado na relação de objetos proibidos, conforme definido no MANCAT 6/4, observando que:', '', 18),
(4927, 'capitulo', 22, 4926, 4, 'a', 'devem ser apresentados abertos para verificação do conteúdo;', 'b) caso sejam apresentados totalmente fechados, deve constar, obrigatoriamente, no invólucro do objeto a expressão “Fechamento Autorizado. Pode ser aberto pelos Correios”.\nNOTA: caso não sejam atendidas as condições dispostas neste item, o objeto não se classificará como Mala Direta.\n2.2.5.1 Proceder conforme orientações a seguir, se apresentadas inconsistências nas especificações do subitem 2.2.5', 19),
(4928, 'capitulo', 22, 4926, 4, 'a', 'reter a carga;', '', 20),
(4929, 'capitulo', 22, 4926, 4, 'b', 'comunicar de imediato à Contratante/preposto.', '', 21),
(4930, 'capitulo', 22, 4926, 4, 'c', 'informar o ocorrido ao GCE/ACOM, por e-mail;', '', 22),
(4931, 'capitulo', 22, 4926, 4, 'd', 'solicitar que seja realizada a correção da falha ou o aceite da postagem como Carta ou Encomenda, a depender da correta classificação, conforme conteúdo até o horário de funcionamento da Unidade de Postagem, do dia útil posterior ao da solicitação, conforme item 2.5 deste Capítulo;', 'd) disponibilizar a carga para retirada pela contratante/preposto, caso a carga não seja ajustada ou não haja aceite da postagem como Carta ou Encomenda.', 23),
(4932, 'capitulo', 22, 4923, 3, '2.2.6', 'Verificar se as regras de endereçamento estão sendo atendidas, bem como se os objetos estão de acordo com os pesos e dimensões estabelecidos para o serviço e se estão devidamente acondicionados.', '', 24),
(4933, 'capitulo', 22, 4923, 3, '2.2.7', 'Verificar se os objetos apresentados estão acompanhados da lista de postagem, em abrangências distintas, considerando-se a distribuição local, estadual e nacional.', '', 25),
(4934, 'capitulo', 22, 4923, 3, '2.2.8', 'Recusar o recebimento carga desacompanhada da lista de postagem.', '2.2.9 Verificar se os objetos estão organizados em amarrados dentro de unitizadores, devidamente etiquetados:', 26),
(4935, 'capitulo', 22, 4934, 4, 'a', 'Verificar se os objetos se apresentam encabeçados, faceados, triados e agrupados em amarrados, para postagem nos horários e locais acordados previamente com os Correios;', '', 27),
(4936, 'capitulo', 22, 4934, 4, 'b', 'Verificar se cada amarrado só contém objetos idênticos, de mesmo formato, tamanho e peso;', '', 28),
(4937, 'capitulo', 22, 4934, 4, 'c', 'Observar se consta de cada amarrado um espelho, conforme modelo definido pela área operacional, contendo a data da postagem, o destino e o primeiro número de CEP relativo aos objetos incluídos no mesmo, se possível, impresso em código de barras padrão 128.', 'NOTA: nas formas de postagem sem mídia no ato da postagem, a carga deverá atender ao Plano de Triagem de clientes com contrato, conforme estabelecido pelos Correios. No caso de mídia antecipada, a carga deverá respeitar a Unitização Virtual, efetuada pelo Sistema Direto e respectiva lista de conferência.', 29),
(4938, 'capitulo', 22, 4923, 3, '2.2.10', 'Atividades de Recebimento de Objetos', '', 30),
(4939, 'capitulo', 22, 4923, 3, '2.2.11', 'Pesar uma amostra de 10 (dez) objetos, dividindo o peso da amostra por 10 (dez), para cálculo do peso unitário médio.', '', 31),
(4940, 'capitulo', 22, 4923, 3, '2.2.12', 'Pesar a carga, encontrando o peso bruto e líquido por abrangência.', '', 32),
(4941, 'capitulo', 22, 4923, 3, '2.2.13', 'Inserir as informações obtidas na pesagem, peso unitário e quantidade, conforme cada abrangência, no Sistema Direto, inclusive, no campo “Observações”, registrar o nome e matrícula do recebedor.', '', 33),
(4942, 'capitulo', 22, 4923, 3, '2.2.14', 'Encaminhar a carga para tratamento, caso não sejam identificadas inconsistências na conferência.', '', 34),
(4943, 'capitulo', 22, 4923, 3, '2.2.15', 'Contatar o cliente imediatamente, a fim de que se posicione quanto à aceitação ou não da pesagem aferida pelos Correios, na hipótese de ser constatada divergência de peso ou de quantidade de objetos entre o aferido pelos Correios e o apresentado pelo cliente, que exceda a margem de tolerância de 2% (dois por cento), para mais ou para menos.', '', 35),
(4944, 'capitulo', 22, 4923, 3, '2.2.16', 'Realizar os demais procedimentos operacionais de recebimento da carga, caso o peso ou a quantidade de objetos aferidos pelos Correios sejam aceitos pelo cliente.', '', 36),
(4945, 'capitulo', 22, 4923, 3, '2.2.17', 'Solicitar, ao cliente, a retirada da carga (até o dia útil seguinte ao da tentativa de postagem) sob circunstância de refugo dos objetos, caso o peso ou a quantidade aferidos pelos Correios não sejam aceitos, após exauridas todas as tentativas de correção, e finalizar a postagem.', '', 37),
(4946, 'capitulo', 22, 4923, 3, '2.2.18', 'Observar no caso da rede terceirizada:', '', 38),
(4947, 'capitulo', 22, 4946, 4, 'a', 'O Sistema Direto liberará o prosseguimento da postagem somente se a correção da carga for realizada pelo cliente.', '', 39),
(4948, 'capitulo', 22, 4946, 4, 'b', 'A carga deverá ser encaminhada à unidade validadora, no mesmo dia da postagem, por meio da linha de coleta regular de transporte dos Correios.', '', 40),
(4949, 'capitulo', 22, 4946, 4, 'c', 'Encaminhar a carga unitizada e separada por cliente para o centralizador, acompanhada da respectiva lista de postagem.', '', 41),
(4950, 'capitulo', 22, 4923, 3, '2.2.19', 'Adotar os procedimentos a seguir, caso o Sistema Direto apresente impossibilidade de acesso ou instabilidade que impeçam o prosseguimento das ações de lançamentos de informações em qualquer fase do processo:', '', 42),
(4951, 'capitulo', 22, 4950, 4, 'a', 'Comunicar a área técnica competente;', '', 43),
(4952, 'capitulo', 22, 4950, 4, 'b', 'Preencher, de acordo com as informações da conferência, 2 (duas) vias da lista de postagem Mala Direta Especial simples ou registrados, conforme Anexos 3 e 4 deste Capítulo.', 'NOTA: no caso das unidades terceirizadas, emitir 3 (três) vias da lista de postagem (duas vias) atenderão o disposto nas letras “c” e “d” e a terceira deverá acompanhar a carga encaminhada à unidade centralizadora.', 44),
(4953, 'capitulo', 22, 4950, 4, 'c', 'Apor o carimbo datador e solicitar a assinatura do gestor da unidade de captação, ou seu eventual.', '', 45),
(4954, 'capitulo', 22, 4950, 4, 'd', 'Entregar 1 (uma) via da lista de postagem ao cliente, e manter 1 (uma) via arquivada na unidade.', '', 46),
(4955, 'capitulo', 22, 4950, 4, 'e', 'Assim que o sistema for restabelecido, efetuar os lançamentos devidos.', 'NOTA: inserir, no campo “Observações”, o seguinte texto: “Postagem realizada por meio de procedimento contingencial, conforme MANCAT 6/18”.', 47),
(4956, 'capitulo', 22, 4923, 3, '2.2.20', 'Atividades de Geração de Lista de Postagem (somente unidades de atendimento próprias)', '', 48),
(4957, 'capitulo', 22, 4923, 3, '2.2.21', 'Gerar a lista de postagem.', '', 49),
(4958, 'capitulo', 22, 4923, 3, '2.2.22', 'Emitir a lista de postagem, entregar o documento ao cliente colhendo as devidas assinaturas e apor o carimbo datador.', '', 50),
(4959, 'capitulo', 22, 4923, 3, '2.2.23', 'Registrar as informações no Sistema Direto.', '', 51),
(4960, 'capitulo', 22, 4923, 3, '2.2.24', 'Encaminhar a carga para tratamento, no mesmo dia da postagem, por meio de linha de coleta de transporte dos Correios.', '', 52),
(4961, 'capitulo', 22, 4923, 3, '2.2.25', 'Atividades de devolução física.', '', 53),
(4962, 'capitulo', 22, 4923, 3, '2.2.26', 'Realizar os procedimentos previstos no MANCAT 7/8.', '', 54),
(4963, 'capitulo', 22, 4916, 2, '2.3', 'Unidade Operacional', '', 55),
(4964, 'capitulo', 22, 4963, 3, '2.3.1', 'Procedimentos de Validação', '', 56),
(4965, 'capitulo', 22, 4963, 3, '2.3.2', 'Validar a postagem, quando oriundas da rede terceirizada, observando os procedimentos constantes dos subitens 2.2.2.1 ao 2.2.3.4 deste Capítulo.', '', 57),
(4966, 'capitulo', 22, 4963, 3, '2.3.3', 'Reter a carga e solicitar, à unidade de postagem, a correção da Lista de Postagem para a realização de nova conferência, na situação em que não seja possível realizar os devidos lançamentos no Sistema Direto por ordem técnica/intermitência, ou caso a carga apresente divergência.', '', 58),
(4967, 'capitulo', 22, 4963, 3, '2.3.4', 'Após a correção, conferir a lista de postagem e a carga. Caso não haja inconsistências, liberar a carga para tratamento.', 'NOTA 1: independentemente do tipo de postagem, com ou sem mídia, as informações inseridas sobre peso, quantidade e sequencial do amarrado e unitizadores são de uso exclusivo do cliente, não devendo, portanto, serem consideradas para efeito de validação da carga.\nNOTA 2: fica, ainda, dispensada a exigência da data da postagem constante nos rótulos supracitados ser a real da postagem do objeto, pois o controle é via Sistema Direto.', 59),
(4968, 'capitulo', 22, 4963, 3, '2.3.5', 'Solicitar a retirada da carga ao cliente até o dia útil seguinte, caso a correção não ocorra em função de o cliente não aceitar a aferição realizada.', '', 60),
(4969, 'capitulo', 22, 4916, 2, '2.4', 'Procedimentos de Tratamento/Distribuição', '', 61),
(4970, 'capitulo', 22, 4969, 3, '2.4.1', 'Encaminhar, efetuar a distribuição e devolução dos objetos de acordo com os procedimentos e normas estabelecidos pelos Correios.', '', 62),
(4971, 'capitulo', 22, 4969, 3, '2.4.2', 'Realizar a Devolução Eletrônica ou a Devolução Física, conforme o caso, em situações de insucesso na entrega do objeto.', '', 63),
(4972, 'capitulo', 22, 4916, 2, '2.5', 'Procedimentos para Regularização de Cobrança por Divergência de Classificação', '', 64),
(4973, 'capitulo', 22, 4972, 3, '2.5.1', 'Realizar conferência e correção de eventuais divergências de classificação de objeto, após a postagem ou a qualquer tempo, com prevalência de sua aferição, sendo cabível a restituição de valores no caso de diferença entre o valor faturado e o valor apurado.', '', 65),
(4974, 'capitulo', 22, 4972, 3, '2.5.2', 'Reclassificar o objeto como Carta ou Encomendas, de acordo com o conteúdo do objeto, se confirmada a existência de objetos cobrados a menor devido a divergência de classificação.', '', 66),
(4975, 'capitulo', 22, 4972, 3, '2.5.3', 'Informar o ocorrido ao GCE/ACOM ou Agência, por e-mail, para que possa entrar em contato com o cliente.', '', 67),
(4976, 'capitulo', 22, 4972, 3, '2.5.4', 'Proceder o recolhimento da diferença (Unidade de Postagem) por meio do Sistema SARA utilizando o código 55565.', 'NOTA: na regularização da pendência a faturar, comunicar ao cliente, e efetuar o recolhimento da diferença no cartão do cliente que originou a postagem incorreta, utilizando como referência o mesmo número do documento e registrando a operação no código de serviço 55565.\n* * * * *', 68),
(4977, 'capitulo', 23, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: realizar a assinatura de Caixa Postal para obter um domicílio postal e receber correspondências e encomendas com privacidade e comodidade.\n1.2 Abrangência: nacional.\nGestor: Departamento de Negócios de Varejo – DEVAR\\DINEG.\nFornecedores: GERAT ou GEOPE e GEVEN da SE.\nClientes: assinantes de Caixa Postal.\nPeriodicidade: diariamente, sempre que alguém procurar uma agência para utilização do serviço.\nDuração: de acordo com a modalidade de assinatura (semestral, anual e bianual).\nVínculo com a Cadeia de Valor: N2 - gerir produtos e serviços', 0),
(4978, 'capitulo', 23, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', 'Procedimentos na Agência para alugar uma Caixa Postal\nReceber do interessado o pedido de assinatura de caixa postal e a documentação exigida para a habilitação e abrir a tela principal do sistema para efetuar o atendimento;\nAcessar o Sistema de Atendimento da Rede de Agências - SARA - e clicar nas opções Atendimento e Tela Principal;\nNa tela seguinte, clicar em À Vista/ Identificado e em Cliente (para modalidade à vista), ou à faturar (para modalidade à faturar), digitar o CNPJ/CPF do cliente cadastrado no SARA ou o Número do Cartão de postagem e clicar no botão Pesquisar;\nClicar em OK assim que o sistema retorne os dados do interessado, então, surgirá a tela de atendimento;\nClicar em Serviços para pesquisar e selecionar aquele que corresponde ao prazo de assinatura de caixa postal escolhido;\nDigitar o código 3405-3 para vigência anual, 3406-1 para bianual ou 3404-5 para semestral;\nClicar em OK;\nSurgirá a tela com opções de Reendereçamento, Divulgação do Nome e do Endereço. Escolher sempre NÃO para esses itens;\nSelecionar o número da Caixa Postal que deseja alugar e clicar em OK;\nImprimir o Termo de Assinatura de Caixa Postal, disponibilizado a partir de janela aberta pelo Explorer. As agências terceirizadas deverão imprimir três vias do formulário, sendo uma via para o cliente, uma para o arquivo da agência e outra via para o balancete que segue para a Coordenadoria de Controle de Receitas;\nFinalizar o atendimento no SARA normalmente, assim que reaparecer a tela de atendimento;\nEm caso de falha na emissão do Termo de Assinatura diretamente no SARA, utilizar o formulário disponível no anexo 5 deste capítulo, fazendo os ajustes necessários manualmente;\nExplicar ao interessado que sua assinatura formaliza o conhecimento e a concordância com a regulamentação do serviço, a qual consta, de forma resumida, no TERMO DE ASSINATURA DE CAIXA POSTAL que ficará em seu poder;\nO assinante do Serviço de Caixa Postal deverá solicitar aos seus correspondentes que indiquem além do número de sua caixa postal, o CEP da agência onde a mesma está localizada.\nColher a assinatura do interessado e solicitar o respectivo valor em dinheiro, cartões de débito ou crédito, ou na modalidade a faturar por meio de cartão de postagem (cliente com contrato), conforme fixado na Tarifa Postal Interna vigente, para cada modalidade de assinatura (semestral, anual ou bienal);\nEntregar 01 (uma) chave do receptáculo e a 1ª via do TERMO DE ASSINATURA ao cliente;\nAnexar a 2ª via do TERMO aos documentos do caixa;\nFinalizar o atendimento.\nProcedimentos da área de atendimento\nManter controle atualizado, por unidade de atendimento, das caixas postais existentes na Superintendência Estadual - SE;\nIdentificar o nível de demanda de caixas postais, no âmbito da SE, no curto e médio prazo, para avaliar a necessidade de remanejar os módulos de Caixa Postal.\nAutorizar, quando necessário e possível, junto ao Órgão da Área de Administração da UF, o remanejamento de blocos ou módulos de caixas postais.\nDar publicidade ao serviço, pelos meios mais indicados, nos locais onde exista disponibilidade de caixas postais para alugar.\nPreparar orientação, a ser distribuída aos assinantes de caixas postais, especificando o uso das mesmas e procedimentos a serem seguidos.\nParticipar da preparação de cartas circulares e avisos, lembrando aos assinantes a necessidade da renovação das assinaturas, e informar prazo e preços fixados.\nNota: mais detalhes sobre a operacionalização completa do serviço estão disponíveis no Resumo de Serviços Especiais - RSE, disponível na página do Departamento gestor do serviço, na Intranet.\n* * * * *', 1),
(4979, 'capitulo', 24, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
