(4997, 'capitulo', 25, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimento da Agência para o fornecimento de cópia de chave:\n2.1.1 Modalidade “À Faturar”:\na) acessar o sistema e clicar no menu Atendimento e Tela Principal;\nb) escolher a modalidade “À FATURAR”;\nc) na tela seguinte, pesquisar o cartão de postagem do cliente e clicar OK;\nd) clicar no botão “Serviço”; abrirá uma tela de pesquisa de Serviço, selecionar o código 3411-8 Caixa Postal – Cópia de Chave e clicar OK;\ne) clicar OK na tela com o serviço Caixa Postal – Cópia de Chave. Clicar OK na tela seguinte que mostra o valor do serviço;\nf) clicar em finalizar quando aparecer a tela de atendimento;\ng) selecionar a opção Sim ou Não para a pergunta: Cliente apresentou o número do documento;\nh) clicar OK na tela de personalização se os dados do cliente estiverem corretos;\ni) escolher o formato de impressão do comprovante: Analítico ou Sintético;\nj) escolher a impressora.\n2.1.2 Modalidade “À VISTA”:\na) acessar o sistema e clicar no menu Atendimento e Tela Principal;\nb) escolher a modalidade: À Vista;\nc) clicar no botão “Serviço”; abrirá uma tela de pesquisa de Serviço, localizar o código 3411-8 Caixa Postal – Cópia de Chave e clicar Ok;\nd) clicar OK na tela com o serviço Caixa Postal – Cópia de Chave; Clicar OK na tela seguinte, que mostra o valor do serviço;\ne) clicar OK na tela de atendimento que mostra o serviço desejado e o valor. Clicar em finalizar;\nf) clicar na forma de pagamento escolhida pelo cliente e no botão OK;\ng) clicar em OK novamente para concluir o pagamento.\n2.1.3 Modalidade “À VISTA/IDENTIFICADO”:\na) acessar o sistema e clicar no menu Atendimento e Tela Principal;\nb) escolher a modalidade: à Vista /Identificado e identificação cliente;\nc) pesquisar o CNPJ/CPF ou cartão de postagem do cliente e clicar OK;\nd) clicar no botão “Serviço”; abrirá uma tela de pesquisa de Serviço, localizar o código 3411-8 Caixa Postal – Cópia de Chave e clicar OK;\ne) clicar OK na tela com o serviço Caixa Postal – Cópia de Chave. Clicar OK na tela seguinte, que mostra o valor do serviço;\nf) clicar em finalizar na tela de atendimento, que mostra os dados do cliente, serviço desejado e o valor;\ng) clicar na forma de pagamento escolhida pelo cliente e no botão OK;\nh) clicar em OK novamente para concluir o pagamento.\nNota: mais detalhes sobre a operacionalização completa do serviço estão disponíveis no Resumo de Serviços Especiais - RSE, disponível no ambiente de Negócios, na Intranet.\n* * * * *', 8),
(4998, 'capitulo', 26, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: substituir a fechadura de Caixa Postal alugada.\n1.2 Abrangência: nacional.', 0),
(4999, 'capitulo', 26, 4998, 2, '1.3', 'Gestor: Departamento de Negócios de Varejo – DEVAR\\DINEG.', '', 1),
(5000, 'capitulo', 26, 4998, 2, '1.4', 'Fornecedores: GERAT ou GEOPE e GEVEN da SE.', '', 2),
(5001, 'capitulo', 26, 4998, 2, '1.5', 'Clientes: assinantes de Caixa Postal.', '', 3),
(5002, 'capitulo', 26, 4998, 2, '1.6', 'Periodicidade: Realizar-se-á a substituição de fechadura do recipiente de Caixa Postal por força de rescisão do contrato de assinatura.', '1.7 Duração: providenciar a imediata troca de fechadura da caixa postal, liberando-a para nova assinatura, se o ex-assinante não se pronunciar até o 15° dia findo o prazo de vigência do contrato.\n1.8 Vínculo com a cadeia de valor: N2 - gerir produtos e serviços.', 4),
(5003, 'capitulo', 26, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimento da Agência para a troca de fechadura ou reparo do receptáculo\n2.1.1 Modalidade “À VISTA/IDENTIFICADO”:\na) acessar o sistema e clicar no menu Atendimento e Tela Principal;\nb) escolher a modalidade: à Vista /Identificado e identificação cliente;\nc) pesquisar o CNPJ/CPF ou cartão de postagem do cliente e clicar OK;\nd) clicar no botão “Serviço”; abrirá uma tela de pesquisa de Serviço, localizar o código 3410-0 Caixa Postal - manutenção (troca de fechadura) e clicar OK;\ne) clicar OK na tela do serviço Caixa Postal - Manutenção. Clicar OK na tela seguinte, que mostra o valor do serviço;\nf) solicitar o respectivo pagamento - conforme fixado na Tarifa Postal Interna vigente;\ng) clicar em finalizar na tela de atendimento, que mostra os dados do cliente, serviço desejado e o valor;\nh) clicar na forma de pagamento escolhida pelo cliente e no botão OK;\ni) clicar em OK novamente para concluir o pagamento;\nj) imprimir o ticket de caixa, entregar a 1ª via ao cliente e arquivar a outra via.\n2.1.2 Modalidade à Vista:\na) acessar o sistema e clicar no menu Atendimento e Tela Principal;\nb) escolher a modalidade: À Vista;\nc) clicar no botão “Serviços”; abrirá uma tela de pesquisa de Serviço, selecionar o código 3410-0 Caixa Postal - Manutenção e clicar Ok;\nd) o SARA apresentará a tela com o serviço Caixa Postal - Manutenção; clicar OK; a tela seguinte mostra o valor do serviço; clicar Ok;\ne) em seguida, aparecerá a tela de atendimento, com o serviço desejado e valor; clicar em finalizar;\nf) clicar na forma de pagamento escolhida pelo cliente e no botão Ok. Clicar em Ok novamente para concluir o pagamento.\n2.1.3 Modalidade à Faturar:\na) acessar o sistema e clicar no menu Atendimento e Tela Principal;\nb) escolher a modalidade: à faturar;\nc) na tela seguinte, pesquisar o cartão de postagem do cliente e clicar Ok;\nd) clicar no botão “Serviços”; abrirá uma tela de pesquisa de Serviço, selecionar o código 3410-0 Caixa Postal - Manutenção e clicar Ok;\ne) o SARA apresentará a tela com o serviço Caixa Postal - Manutenção; clicar Ok; a tela seguinte mostra o valor do serviço; clicar Ok;\nf) em seguida, aparecerá a tela de atendimento, com os dados do cliente, serviço desejado e valor; clicar em finalizar;\ng) selecionar a opção Sim ou Não para a pergunta: cliente apresentou o número do documento?\nh) aparecerá a tela de personalização, verificar os dados do cliente e, se estiver correto, clicar Ok;\ni) escolha o formato de impressão do comprovante: Analítico ou Sintético; escolha a impressora.\n2.1.4 Retorno do cliente à agência:\na) recepcionar o cliente;\nb) solicitar o documento de identificação pessoal e o recibo de pagamento do serviço de troca de fechadura;\nc) localizar o Termo de Assinatura, em arquivo da agência, e confirmar a existência de contrato com o interessado;\nd) entregar uma chave da caixa postal ao cliente.\nNota: mais detalhes sobre a operacionalização completa do serviço estão disponíveis no Resumo de Serviços Especiais - RSE, disponível no ambiente de Negócios, na Intranet.\n* * * * *', 5),
(5004, 'capitulo', 27, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: transferir a assinatura de Caixa Postal, por solicitação do assinante, de uma agência para outra, no âmbito da Superintendência Estadual.\n1.2 Abrangência: nacional', 0),
