(5544, 'capitulo', 54, 5540, 2, '1.4', 'Fornecedor: Cliente Contratante / Agência de Correios Franqueada', '', 4),
(5545, 'capitulo', 54, 5540, 2, '1.5', 'Cliente: Cliente Contratante / Agência de Correios Franqueada', '', 5),
(5546, 'capitulo', 54, 5540, 2, '1.6', 'Periodicidade: Por demanda.', '', 6),
(5547, 'capitulo', 54, 5540, 2, '1.7', 'Duração: A duração do subprocesso de Vinculação de Contratos de Franqueamento Autorizado de Cartas, Mala Direta Postal e Mala Direta Postal Domiciliária é variável, conforme o processo a ser analisado.', '', 7),
(5548, 'capitulo', 54, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 8),
(5549, 'capitulo', 54, 5548, 2, '2.1', 'Procedimentos do Cliente Contratante', '', 9),
(5550, 'capitulo', 54, 5549, 3, '2.1.1', 'Solicitar formalmente, à Diretoria Regional, mediante Carta, a vinculação do Contrato FAC, MDP ou MDPD para uma ou mais ACFs, podendo ainda, simultaneamente, manter o vínculo a uma unidade própria da ECT.', '', 10),
(5551, 'capitulo', 54, 5549, 3, '2.1.2', 'Declarar no corpo da Carta, estar ciente do conteúdo da Proposta de Vinculação Operacional de Contrato e de acordo com as informações nela prestadas pelo franqueado.', '', 11),
(5552, 'capitulo', 54, 5548, 2, '2.2', 'Procedimentos da Pessoa Jurídica detentora do Contrato de Franquia Empresarial da ECT', '', 12),
(5553, 'capitulo', 54, 5552, 3, '2.2.1', 'Anexar à Carta do cliente a PROPOSTA DE VINCULAÇÃO OPERACIONAL DE CONTRATO, conforme modelo no anexo 2 deste capítulo e encaminhar à ECT.', '', 13),
(5554, 'capitulo', 54, 5552, 3, '2.2.2', 'Assinar o Termo de Acordo Operacional a ser firmado com a ECT, nos casos em que houver aprovação técnica à vinculação, conforme o modelo constante no Anexo 3 ou 4 deste capítulo, conforme o caso.', '', 14),
(5555, 'capitulo', 54, 5548, 2, '2.3', 'Procedimentos da Área de Vendas, Área de Atendimento (GETER/GERAT) ou Órgãos equivalentes', '', 15),
(5556, 'capitulo', 54, 5555, 3, '2.3.1', 'Receber a solicitação de vinculação do Contrato FAC, MDP ou MDPD.', '', 16),
(5557, 'capitulo', 54, 5555, 3, '2.3.2', 'Verificar se junto a Carta do cliente está anexa a PROPOSTA DE VINCULAÇÃO OPERACIONAL DE CONTRATO, conforme modelo no anexo 2 deste capítulo.', '', 17),
(5558, 'capitulo', 54, 5555, 3, '2.3.3', 'Observar no MANCAT 1/2, o Anexo de Políticas e Diretrizes para Administração da Rede de Franquia Empresarial – ACF, o qual dispõe sobre as questões relativas a vinculação do Contrato FAC, MDP ou MDPD.', '', 18),
(5559, 'capitulo', 54, 5555, 3, '2.3.4', 'Solicitar ao Diretor Regional a instituição de Grupo de Trabalho para analisar a solicitação de vinculação do Contrato FAC, MDP ou MDPD.', '', 19),
(5560, 'capitulo', 54, 5555, 3, '2.3.5', 'Participar do Grupo de Trabalho que será instituído para analisar a solicitação de vinculação do Contrato FAC, MDP ou MDPD.', '', 20),
(5561, 'capitulo', 54, 5555, 3, '2.3.6', 'Assinar o Termo de Acordo Operacional em conjunto com o Diretor Regional e com o sócio gerente da Pessoa Jurídica detentora do Contrato de Franquia Empresarial da ECT e anexá-lo ao contrato correspondente, integrando-o ao mesmo.', 'Nota 1: Observar que as regras constantes neste capítulo, aplicam-se, complementarmente às normas e disposições do Capítulo 21, Módulo 8, deste Manual.\nNota 2: Observar as demais normas relativas a Vinculação de Contratos de Franqueamento Autorizado de Cartas, Mala Direta Postal e Mala Direta Postal Domiciliária em Políticas e Diretrizes da Administração da Rede de Franquia Empresarial – ACF, Anexo do MANCAT 1/2.', 21),
(5562, 'capitulo', 54, 5548, 2, '2.4', 'Procedimentos do Grupo de Trabalho', '', 22),
(5563, 'capitulo', 54, 5562, 3, '2.4.1', 'Analisar a PROPOSTA DE VINCULAÇÃO OPERACIONAL DE CONTRATO, a qual deverá constar obrigatoriamente as seguintes informações:', 'a) identificação da ACF;\nb) locais onde serão coletados e tratados os objetos captados do cliente;\nc) serviços não previstos no contrato FAC, MDP ou MDPD e que serão prestados pela ACF ao cliente.\nExemplo: impressão, geração de etiquetas, dobragem, preenchimento de formulários, inserção de brindes etc.;\nd) freqüência semanal de entrega da carga no Centro de Tratamento de Cartas da ECT;\ne) previsão de serviços postais adicionais: AR, MP, Registro etc;\nf) estimativa da quantidade de objetos por postagem;\ng) descrição e tipificação de objetos.\nExemplo: Boleto de 20g com AR, Revista de 200g, Catálogos de 200-500g etc.\n2.4.1.1 Certificar, nos casos em que há mais de uma ACF de vinculação, que cada franqueado emita a correspondente Proposta, a qual deverá contemplar todas as informações constantes no subitem anterior.', 23),
(5564, 'capitulo', 54, 5562, 3, '2.4.2', 'Analisar se os contratos foram firmados antes ou depois de 19/07/2001, para que sejam observadas as regras dispostas tanto neste capítulo quanto no Anexo de Políticas e Diretrizes para Administração da Rede de Franquia Empresarial – ACF no MANCAT1/2.', '', 24),
(5565, 'capitulo', 54, 5562, 3, '2.4.3', 'Adotar os seguintes procedimentos para os novos contratos firmados a partir de 20/07/2001', '2.4.3.1 Permitir, desde que cumpridas as presentes regras de vinculação em questão, que os novos contratos FAC, MDP e MDPD firmados a partir de 20/07/2001, sejam vinculados a unidades próprias ou franqueadas.\n2.4.3.1.1 É admitida a vinculação simultânea a duas ou mais unidades próprias e/ou franqueadas.\n2.4.3.2 Assegurar que não será enquadrado nas regras dos novos contratos firmados a partir de 20/07/2001, o contrato FAC, MDP ou MDPD com pessoa jurídica contratante que, por sua iniciativa, nos últimos 06 (seis meses) antecedentes à data do novo ajuste, tenha dado causa à rescisão de contrato comercial de mesmo objeto ou de autorização de postagem de mesmo segmento de serviço, que tinha vinculação exclusiva em unidade própria da ECT.\n2.4.3.2.1 Os novos contratos firmados a partir de 20/07/2001 serão submetidos às mesmas regras de vinculação e de comissionamento relativas aos contratos firmados até 19/07/2001, previstas neste capítulo.\n2.4.3.3  Remunerar a ACF ou conjunto de ACFs pela aplicação dos índices a seguir especificados:\na) FAC: 5%;\nb) MDP e MDPD: Tabela “A” de Comissão de ACF;\n2.4.3.3.1 Observar ainda as seguintes regras para o comissionamento de ACF aplicáveis aos contratos firmados a partir de 20/07/2001:', 25),
(5566, 'capitulo', 54, 5565, 4, 'a', 'quando a vinculação for exclusiva em ACF ou grupo de ACFs, a base de cálculo será o valor total da fatura paga pelo cliente contratante, devendo o resultado, na hipótese de haver mais de uma ACF, ser rateado proporcionalmente à participação de cada unidade no movimento faturado;', 'b) quando a vinculação for simultânea em unidades próprias e franqueadas, a base de cálculo será resultante da diferença entre o valor total da fatura paga pelo cliente contratante e o valor correspondente à participação das unidades da ECT no movimento faturado. Havendo mais de uma ACF a Comissão será rateada de acordo com a alínea anterior;\nc) nas hipóteses descritas nas alíneas “a” e “b” acima, quando tratar-se de contrato de Mala Direta com inserção de Carta/Cartão/Envelope-Encomenda Resposta Comercial, deverá ser expurgado do valor da fatura, o montante correspondente aos objetos devolvidos como Reposta Comercial, cujas tarifas de serviço foram incluídos na mesma fatura do MDP/MDPD.', 26),
(5567, 'capitulo', 54, 5562, 3, '2.4.4', 'Adotar os seguintes procedimentos para os Contratos Firmados até 19/07/2001:', '', 27),
(5568, 'capitulo', 54, 5567, 4, 'a', 'os pedidos de vinculação, a uma ou mais ACFs, de contratos FAC, MDP ou MDPD, em regular execução, pactuados até 19 de julho de 2001, e que foram, originalmente, vinculados exclusivamente em unidades próprias da ECT, poderão ser atendidos, desde que cumpridas as disposições deste capítulo e das Políticas e Diretrizes para a Administração da Rede de Franquia Empresarial – ACF, no MANCAT 1/2 ;', '', 28),
(5569, 'capitulo', 54, 5567, 4, 'b', 'o processo de mudança de vinculação de contrato enquadrado na alínea anterior será conduzido pelo Grupo de Trabalho da Regional constituído pelos Gerentes Regionais das áreas comercial, de finanças e de operações. O Diretor Regional poderá, a seu critério, designar outros representantes do corpo gerencial;', '', 29),
(5570, 'capitulo', 54, 5567, 4, 'c', 'o Grupo de Trabalho Regional submeterá sua decisão à ratificação do Diretor Regional.', '2.4.4.1  Verificar se há impedimentos de natureza técnica que inviabilizem o atendimento do pedido de vinculação à ACF.\n2.4.4.1.1 Na hipótese de não-aprovação, esta será necessariamente fundamentada.\n2.4.4.2  Comunicar no prazo máximo de 7 (sete) dias úteis, contados da data de recebimento da Carta-Pedido do cliente, o resultado da verificação da existência ou não de impedimentos de natureza técnica que inviabilizem o atendimento do pedido de vinculação à ACF.\n2.4.4.3  Emitir o Termo de Acordo Operacional a ser firmado com a ACF, nos casos em que houver aprovação técnica à vinculação, de acordo com os modelos constantes nos Anexos 3 ou 4 deste capítulo, conforme o caso. Havendo mais de uma ACF, será emitido um termo para cada.\n2.4.4.3.1 Certificar de que o Termo de Acordo Operacional, que é o instrumento que formaliza a vinculação do contrato à ACF e estabelece as condições de operacionalização e de comissionamento, contempla os seguintes aspectos:\na) identificação e endereço das partes;\nb) identificação do cliente contratante e do respectivo contrato;\nc) os preços e tarifas divulgados pela ECT para o serviço FAC, MDP ou MDPD, que não incluem a remuneração pela prestação de serviços de pré-postagem ou de qualquer outro serviço adicional, que venha a ser executado/prestado por iniciativa da ACF à contratante;\nd) identificação da unidade operacional da DR para entrega da carga;\ne) fixação da freqüência semanal e do horário-limite de entrega da carga à ECT;\nf) exigência de cumprimento dos pré-requisitos mínimos para apresentação dos objetos para postagem na ECT, de acordo com o estabelecido no contrato FAC, MDP ou MDPD;\ng) metodologia de cálculo do comissionamento, de acordo com o subitem 3 deste capítulo;\nh) atribuição à ACF de eventuais prejuízos causados ao cliente, enquanto os objetos estiverem sob responsabilidade da franquia.\nExemplo: perda de desconto pelo não-cumprimento do horário antecipado de postagem.', 30),
(5571, 'capitulo', 54, 5548, 2, '2.5', 'Encaminhar o Termo de Acordo Operacional para assinatura do Diretor Regional e do  Gerente da Área de Vendas, Área de Atendimento (GETER/GERAT) ou Órgãos equivalentes.', '', 31),
(5572, 'capitulo', 54, 5571, 3, '2.5.1', 'Calcular a comissão da ACF - Contrato FAC', '2.5.1.1  Calcular a Comissão da ACF com base no VALOR-REFERÊNCIA de cada contrato, conforme as instruções seguintes:\na) obter as faturas referentes aos últimos 6 (seis) meses de operação normal do contrato FAC, com vinculação exclusiva em unidade própria da ECT. Caso o contrato tenha menos de 6 (seis) meses de operação normal, utilizar a quantidade de meses disponíveis;\nb) o VALOR-REFERÊNCIA será expresso em quantidade de PPCC (Primeiro Porte Carta Comercial), por meio da divisão do valor de cada fatura pelo valor unitário do PPCC vigente na data de sua emissão;\nc) somar as faturas já transformadas em PPCC e extrair a média aritmética. O resultado final (média aritmética) corresponderá ao VALOR-REFERÊNCIA expresso em PPCC;\nd) no ato de cálculo da comissão da ACF, que o VALOR-REFERÊNCIA será convertido em moeda-corrente (Reais), mediante aplicação do valor do PPCC vigente na data do acerto de contas;\ne) a comissão da ACF corresponderá à aplicação do percentual único de 5% (cinco por cento), nas condições descritas no item 3.3 – Determinação das Bases de Cálculo da Comissão – deste capítulo.', 32),
(5573, 'capitulo', 54, 5571, 3, '2.5.2', 'Calcular a comissão da ACF  -  Contratos MDP e MDPD', '2.5.2.1 Calcular a comissão da ACF aplicando-se as regras previstas para os contratos FAC, descritos no subitem 2.5.1.1, porém, tratando-se de contratos MDP e MDPD, será utilizado o PRIMEIRO PORTE DA MALA DIRETA POSTAL NACIONAL, na modalidade NORMAL, em substituição ao PPCC, tanto na determinação do VALOR-REFERÊNCIA, quanto na sua conversão em moeda-corrente (Reais).\n2.5.2.1.1 Certificar de que a efetivação do pagamento da comissão seguirá a regra para o comissionamento de serviços prestados a faturar, ou seja, o pagamento está condicionado à prévia quitação da fatura pelo cliente, conforme a cláusula sexta, subitem 6.1.8 do Contrato de Franquia.', 33),
(5574, 'capitulo', 54, 5548, 2, '2.6', 'Determinar as Bases de Cálculo da Comissão - Cliente que opera Contrato FAC, MDP OU MDPD com Unidade Própria da ECT e quer vinculação exclusiva a uma ACF:', '', 34),
(5575, 'capitulo', 54, 5574, 3, '2.6.1', 'Adotar a aplicação dos procedimentos descritos nos subitens relativos às Comissões deste capítulo, a fim de obter-se o Valor-Referência.', '', 35),
(5576, 'capitulo', 54, 5574, 3, '2.6.2', 'Remunerar a ACF pelo valor correspondente à comissão de 5% (cinco por cento) para o FAC e pela Tabela “A” de comissão da ACF para a MDP e MDPD aplicada sobre o montante da fatura que exceder o Valor-referência.', '', 36),
(5577, 'capitulo', 54, 5548, 2, '2.7', 'Determinar as Bases de Cálculo da Comissão - Cliente que opera contrato FAC, MDP OU MDPD com Unidade Própria da ECT e quer vinculação simultânea com Unidade Própria e ACF', '', 37),
(5578, 'capitulo', 54, 5577, 3, '2.7.1', 'Aplicar os procedimentos descritos nos subitens relativos às Comissões deste capítulo, a fim de obter-se o Valor-Referência.', '', 38),
(5579, 'capitulo', 54, 5577, 3, '2.7.2', 'Calcular o valor da Comissão da ACF sobre o montante da fatura que exceder o Valor-referência, em combinação com o grau de participação da Unidade Própria no total faturado, conforme disposto a seguir:', 'a) se a participação da Unidade Própria no movimento financeiro faturado for igual ou menor do que o Valor-referência, a Comissão da ACF corresponderá à comissão de 5% (cinco por cento) para o FAC e à comissão estabelecida para a MDP e MDPD na Tabela “A” de comissão da ACF, do montante da fatura que exceder o Valor-referência;\nExemplo:\nVALORES EM REAIS\nFATURA	VALOR-REFERÊNCIA	MOVIMENTO DA Unidade Própria	MOVIMENTO DA ACF	BASE CÁLCULO DA COMISSÃO	COMISSÃO DA ACF\n250.000,00	150.000,00	100.000,00	150.000,00	100.000,00	5.000,00\nb) se a participação da Unidade Própria no movimento financeiro faturado for superior ao Valor-referência, a Comissão da ACF corresponderá à comissão de 5% (cinco por cento), para o FAC e à Comissão estabelecida para a MDP e MDPD na Tabela “A” de comissão de ACF, do montante equivalente à participação da ACF no movimento financeiro faturado;\nExemplo:\nVALORES EM REAIS\nFATURA	VALOR-REFERÊNCIA	MOVIMENTO DA UNIDADE PRÓPRIA	MOVIMENTO DA ACF	BASE CÁLCULO DA COMISSÃO	COMISSÃO DA ACF\n250.000,00	150.000,00	190.000,00	60.000,00	60.000,00	3.000,00\nc) caso o cliente utilize mais de uma unidade Unidade Própria, a participação da ECT será calculada pelo somatório das postagens em cada uma de suas dependências.', 39);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(5580, 'capitulo', 54, 5548, 2, '2.8', 'Determinar as Bases de Cálculo da Comissão - Cliente que opera contrato FAC, MDP ou MDPD com Unidade Própria da ECT e quer vinculação simultânea com a Unidade Própria e mais de uma ACF', '', 40),
(5581, 'capitulo', 54, 5580, 3, '2.8.1', 'Aplicar os procedimentos descritos no subitem 2.8 deste capítulo, a fim de obter-se o Valor-Referência.', '', 41),
(5582, 'capitulo', 54, 5580, 3, '2.8.2', 'Calcular o valor da Comissão das ACFs sobre o montante da fatura que exceder o Valor-referência, em combinação com o grau de participação da Unidade Própria no total faturado, conforme as disposições seguintes:', 'a) se a participação da Unidade Própria no movimento financeiro faturado for igual ou menor do que o Valor-referência, a Comissão do conjunto de ACFs corresponderá à comissão de 5% (cinco por cento) para o FAC e à Comissão estabelecida para a MDP e MDPD na Tabela “A” de comissão da ACF do montante da fatura que exceder o Valor-Referência. O resultado será rateado proporcionalmente à participação de cada franquia no movimento financeiro faturado;\nExemplo:\nVALORES EM REAIS\nFATURA	VALOR-REFERÊNCIA	MOVIMENTO DA UNIDADE PRÓPRIA	MOVIMENTO DA ACF	BASE CÁLCULO DA COMISSÃO	COMISSÃO DAS ACFs\n250.000,00	150.000,00	100.000,00	150.000,00	100.000,00	5.000,00\nRateio da Comissão entre as ACFs:						VALORES EM REAIS\nCOMISSÃO TOTAL	MOVIMENTO DA ACF #1	MOVIMENTO DA ACF #2	COMISSÃO DA ACF #1	COMISSÃO DA ACF #2\n5.000,00	90.000,00	60.000,00	3.000,00	2.000,00\nb) se a participação da Unidade Própria no movimento financeiro faturado for superior ao Valor-Referência, a Comissão da ACF corresponderá à comissão de 5% (cinco por cento) para o FAC e à Comissão estabelecida para a MDP e MDPD na Tabela “A” de comissão da ACF do montante equivalente à participação da ACF no movimento financeiro faturado;\nExemplo:\nVALORES EM REAIS\nFATURA	VALOR-REFERÊNCIA	MOVIMENTO DA UNIDADE PRÓPRIA	MOVIMENTO DA ACF	BASE CÁLCULO DA COMISSÃO	COMISSÃO DA ACF\n250.000,00	150.000,00	190.000,00	60.000,00	60.000,00	3.000,00\nRateio da Comissão entre as ACFs:						VALORES EM REAIS\nCOMISSÃO TOTAL	MOVIMENTO DA ACF #1	MOVIMENTO DA ACF #2	COMISSÃO DA ACF #1	COMISSÃO DA ACF #2\n3.000,00	40.000,00	20.000,00	2.000,00	1.000,00\nc) caso o cliente utilize mais de uma Unidade Própria, a participação da Empresa será calculada pelo somatório das postagens em cada dependência.', 42),
(5583, 'capitulo', 54, 5548, 2, '2.9', 'Determinar as Bases de Cálculo da Comissão - Cliente que opera contrato FAC, MDP OU MDPD com Unidade Própria da ECT e quer vinculação simultânea com duas ou mais ACFs', '', 43),
(5584, 'capitulo', 54, 5583, 3, '2.9.1', 'Aplicar os procedimentos descritos no item 2.8 deste capítulo, a fim de obter-se o Valor-Referência.', '', 44),
(5585, 'capitulo', 54, 5583, 3, '2.9.2', 'Calcular o valor da Comissão baseado na aplicação da comissão de 5% (cinco por cento) para o FAC e à comissão estabelecida para a MDP e MDPD na Tabela “A” de comissão da ACF sobre o montante da fatura que exceder o Valor-Referência, devendo o resultado ser rateado proporcionalmente à participação de cada ACF na composição do movimento financeiro faturado no contrato.', 'Exemplo:\nVALORES EM REAIS\nFATURA	VALOR-REFERÊNCIA	BASE CÁLCULO DA COMISSÃO	MOVIMENTO DA ACF #1	MOVIMENTO DA ACF#2	MOVIMENTO DA ACF#3\n250.000,00	150.000,00	100.000,00	110.000,00	90.000,00	50.000,00\nRateio da Comissão entre as ACFs:						VALORES EM REAIS\nCOMISSÃO TOTAL	COMISSÃO DA ACF #1	COMISSÃO DA ACF #2	COMISSÃO DA ACF #3\n5.000,00	2.200,00	1.800,00	1.000,00\n* * * * *', 45),
(5586, 'capitulo', 55, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5587, 'capitulo', 55, 5586, 2, '1.1', 'Objetivo: Formalização de parceria comercial visando à utilização da infraestrutura da rede de atendimento dos Correios, por meio de contrato comercial, para comercialização de produtos e prestação de serviços de terceiros, conforme portaria 210 de 13 de abril de 2012 do Ministério das Comunicações.', '', 1),
(5588, 'capitulo', 55, 5586, 2, '1.2', 'Abrangência: toda a empresa.', '', 2),
(5589, 'capitulo', 55, 5586, 2, '1.3', 'Gestor: DERAT.', '', 3),
(5590, 'capitulo', 55, 5586, 2, '1.4', 'Fornecedores: Órgãos Interessados em firmar Parceria com os Correios', '', 4),
(5591, 'capitulo', 55, 5586, 2, '1.5', 'Clientes: Todos os empregados da Empresa.', '', 5),
(5592, 'capitulo', 55, 5586, 2, '1.6', 'Periodicidade: Conforme a demanda.', '', 6),
(5593, 'capitulo', 55, 5586, 2, '1.7', 'Duração: Permanente.', '', 7),
(5594, 'capitulo', 55, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 8),
(5595, 'capitulo', 55, 5594, 2, '2.1', 'Procedimentos do Órgão Proponente para produtos e serviços.', '', 9),
(5596, 'capitulo', 55, 5595, 3, '2.1.1', 'Encaminhar proposta apresentando produtos e serviços de terceiros a serem comercializados na rede de Unidades de Atendimento considerando os parâmetros e critérios estabelecidos para os Correios.', 'NOTA 1: Toda e qualquer demanda de implantação de novos produtos, serviços, sistemas e processos na rede de atendimento, bem como a avaliação de impactos das alterações delas decorrentes, e ainda qualquer atividade a ser direcionada e/ou desenvolvida pelas Gerências de Atendimento e órgãos correspondentes (GENEGs), devem ser antecipadamente avaliadas pelo DERAT - Departamento de Administração da Rede de Atendimento, previamente e somente após aprovação do DERAT poderão vigorar.', 10),
(5597, 'capitulo', 55, 5595, 3, '2.1.2', 'Observar o segmento de atuação dos Correios, conforme apresentado a seguir:', '', 11),
(5598, 'capitulo', 55, 5597, 4, 'a', 'Segmentos de negócios:', 'I - Conveniência;\nII - Serviços de encomenda;\nIII - Serviços de logística;\nIV - Serviços financeiros;\nV - Serviços internacionais;', 12),
(5599, 'capitulo', 55, 5597, 4, 'b', 'Segmentos de Clientes:', 'NOTA 1: serão considerados os segmentos constantes do MANCAT 27.1.\nNOTA 2: Os segmentos referenciados não são limitadores para a contratação da venda de produtos e prestação de serviços de terceiros.', 13),
(5600, 'capitulo', 55, 5594, 2, '2.2', 'Procedimentos do Órgão Gestor da Rede de Unidades de Atendimento', '', 14),
(5601, 'capitulo', 55, 5600, 3, '2.2.1', 'Verificar se a proposta atende aos critérios descritos a seguir:', '', 15),
(5602, 'capitulo', 55, 5601, 4, 'a', 'Compatibilidade com as demais atividades desenvolvidas na rede de Atendimento dos Correios;', '', 16),
(5603, 'capitulo', 55, 5601, 4, 'b', 'Capacidade de absorção da infraestrutura de atendimento para a intermediação na venda de produtos e/ou prestação de serviços de terceiros;', '', 17),
(5604, 'capitulo', 55, 5594, 2, '2.3', 'Procedimentos dos Órgãos Formatadores de produtos/serviços de Terceiros', '', 18),
(5605, 'capitulo', 55, 5604, 4, 'a', 'Observar a política de precificação adotada pelos Correios, considerando o cálculo do retorno financeiro do negócio, a quantidade de agências credenciadas para a execução do serviço ou o valor global do contrato;', '', 19),
(5606, 'capitulo', 55, 5604, 4, 'b', 'Verificar a justa remuneração aos Correios pela utilização de sua infraestrutura para comercialização de produtos e serviços de terceiros;', '', 20),
(5607, 'capitulo', 55, 5604, 4, 'c', 'Atender aos princípios da administração pública;', '', 21),
(5608, 'capitulo', 55, 5604, 4, 'd', 'Manutenir a qualidade dos produtos e dos serviços oferecidos aos clientes;', '', 22),
(5609, 'capitulo', 55, 5604, 4, 'e', 'Alinhar aos objetivos estabelecidos no Planejamento Estratégicos dos Correios – Correios 2020', '', 23),
(5610, 'capitulo', 55, 5604, 4, 'f', 'Analisar a capacidade técnica-operacional-financeira e idoneidade do terceiro interessado em contratar com os Correios.', '', 24),
(5611, 'capitulo', 55, 5604, 4, 'g', 'Verificar se os novos serviços/atividades não configuram, ainda que indiretamente, ofensa ou ameaça aos consumidores (dignidade, integridade física e moral, igualdade, aos direitos humanos, trabalho escravo e outros valores constitucionalmente protegidos), aos costumes locais e ao meio-ambiente ou que cause poluição.', '2.3.1 Não poderão ser comercializados produtos e serviços enquadrados nas seguintes categorias:', 25),
(5612, 'capitulo', 55, 5604, 4, 'a', 'Bebidas alcoólicas e de outras substâncias que possam causar vício;', '', 26),
(5613, 'capitulo', 55, 5604, 4, 'b', 'Loterias, bingos e assemelhados não explorados por instituições públicas; e', '', 27),
(5614, 'capitulo', 55, 5604, 4, 'c', 'Não poderá ser exigida exclusividade dos Correios quanto à prestação do serviço, limitando o fechamento de outros contratos com parceiros diferentes.', '2.3.2 O órgão formatador do produto e/ou serviço deverá efetuar análises, verificando o atendimento aos parâmetros e requisitos estabelecidos, bem como o atendimento às demais condições, conforme itens abaixo:\na) Analisar a viabilidade comercial, operacional, tecnológica e econômico-financeira dos Correios e do produto ou serviço, baseada em informações apresentadas pelo parceiro.\nb) Verificar a adequação do conceito do produto/serviço a ser ofertado, em especial a compatibilidade da sua proposição de valor aos objetivos negociais dos Correios.\nc) Deverá ser observado o prazo previsto para análise das propostas comerciais, bem como o prazo de vigência dos contratos com terceiros, em conformidade com os normativos vigentes dos Correios e as normas externas que regulam a matéria.\nd) Verificar se a proposta não abrange a venda de produtos ou a prestação serviços que sejam concorrentes com aqueles comercializados pelos Correios.\ne) Acompanhar, em conjunto com a área de vendas e gestores regional proponente e/ou nacional, o desempenho dos negócios contratados em regime de parceria comercial com terceiros, de forma a assegurar a adequada contraprestação.\nf) Emitir à área de Vendas o resultado da avaliação da proposta emitida aos Correios.', 28),
(5615, 'capitulo', 55, 5594, 2, '2.4', 'Procedimentos do Órgão Gestor na Regional GERAT/CONEG', '', 29),
(5616, 'capitulo', 55, 5615, 3, '2.4.1', 'Preparar orientações para disseminação do novo processo para rede', '', 30),
(5617, 'capitulo', 55, 5616, 4, 'a', 'Informar a capacidade de absorção da infraestrutura de atendimento para a na venda de produtos e/ou prestação de serviços de terceiros quando solicitado;', '', 31),
(5618, 'capitulo', 55, 5616, 4, 'b', 'Entrar em contato com áreas meio de forma a subsidiar apoio às agências para execução das atividades disponibilizada para rede (suporte de treinamento, suporte de sistemas, área de Vendas e etc);', '', 32),
(5619, 'capitulo', 55, 5594, 2, '2.5', 'Procedimentos das Agências', '', 33),
(5620, 'capitulo', 55, 5619, 3, '2.5.1', 'Aplicar orientação necessária para execução do produto/serviço a exemplo de: TLT, liberação de pessoas para treinamento e etc;', '', 34),
(5621, 'capitulo', 55, 5620, 4, 'a', 'Informar quando necessário a GERAT de ajuste para melhor aplicabilidade no atendimento em relação ao produto/serviço; e', '', 35),
(5622, 'capitulo', 55, 5620, 4, 'b', 'Entrar em contato com áreas meio de forma a dar suporte necessário para execução dos produtos/serviços disponibilizados para Rede.', 'NOTA 1: Todas as demandas de parcerias comerciais deverão ser captadas ou intermediadas pela área de vendas, que as encaminhará à área formatadora;\nNOTA 2: Priorizar as demandas visando o maior retorno financeiro dos negócios e maior abrangência do produto ou serviço; e\nNOTA 3: As disposições deste capítulo não revogam nem modificam os contratos firmados entre os Correios e terceiros até a data de publicação deste Anexo.\n* * * * *', 36),
(5623, 'capitulo', 56, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5624, 'capitulo', 56, 5623, 2, '1.1', 'Objetivo: atender a necessidade do cliente com a prestação do serviço móvel pessoal por meio de rede virtual no modelo credenciado, com a comercialização de chip, Recarga e prestação de serviços de pós-venda.', '', 1),
(5625, 'capitulo', 56, 5623, 2, '1.2', 'Abrangência: nacional.', '', 2),
(5626, 'capitulo', 56, 5623, 2, '1.3', 'Gestor: Departamento de Negócios de Varejo - DEVAR.', '', 3),
(5627, 'capitulo', 56, 5623, 2, '1.4', 'Fornecedores: órgãos do Correios Sede - CS e das Superintendências Estaduais - SEs.', '', 4),
(5628, 'capitulo', 56, 5623, 2, '1.5', 'Clientes: pessoa física e jurídica.', '', 5),
(5629, 'capitulo', 56, 5623, 2, '1.6', 'Periodicidade: diária.', '', 6),
(5630, 'capitulo', 56, 5623, 2, '1.7', 'Duração: Indeterminada.', '', 7),
(5631, 'capitulo', 56, 5623, 2, '1.8', 'Macroprocesso: N2 - Gestão de produtos.', '', 8),
(5632, 'capitulo', 56, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(5633, 'capitulo', 56, 5632, 2, '2.1', 'Procedimentos de Comercialização do Chip na Rede de Atendimento dos Correios', '', 10),
(5634, 'capitulo', 56, 5633, 3, '2.1.1', 'Receber dos Centros de Logística Integradas - CLI Leste e Oeste os Chips destinados à venda.', '', 11),
(5635, 'capitulo', 56, 5633, 3, '2.1.2', 'Conferir a quantidade física de chips recebidos com a quantidade lançada na pauta de suprimento.', '', 12),
(5636, 'capitulo', 56, 5633, 3, '2.1.2', 'Registrar a entrada do produto (Chip Correios Celular) eletronicamente no Sistema de Automação da Rede de Atendimento - SARA.', '', 13),
(5637, 'capitulo', 56, 5633, 3, '2.1.3', 'Arquivar a pauta de suprimento na unidade.', '', 14),
(5638, 'capitulo', 56, 5633, 3, '2.1.4', 'Realizar o atendimento do cliente e a venda dos chips conforme Procedimento Operacional Padrão - POP.', '', 15),
(5639, 'capitulo', 56, 5633, 3, '2.1.5', 'Entregar o(s) chip(s) ao cliente, juntamente com o cupom do SARA.', '', 16),
(5640, 'capitulo', 56, 5632, 2, '2.2', 'Procedimentos de Comercialização do Chip fora da Rede de Atendimento dos Correios', '', 17),
(5641, 'capitulo', 56, 5640, 3, '2.2.1', 'Gestor do Produto', '2.2.1.1 Receber o relatório mensal contendo informação das vendas realizadas fora da rede de atendimento dos Correios.\n2.2.1.2 Validar as informações do relatório por meio dos pontos de controle disponíveis.\n2.2.1.3 Encaminhar o Relatório à Central Financeira - CEFIN.\n2.2.1.4 Receber informação da CEFIN sobre a fatura emitida e a data de vencimento.', 18),
(5642, 'capitulo', 56, 5640, 3, '2.2.2', 'Central Financeira - CEFIN', '2.2.2.1 Receber o relatório do gestor do produto com o valor e quantidade de Chips vendidos fora da Rede de Atendimento dos Correios.\n2.2.2.2 Emitir a fatura dos serviços prestados fora da rede de atendimento.\n2.2.2.3 Informar ao gestor do produto, via SEI, o valor e a data de vencimento da fatura.', 19),
(5643, 'capitulo', 56, 5632, 2, '2.3', 'Procedimentos de Comercialização da Recarga na Rede de Atendimento dos Correios', '', 20),
(5644, 'capitulo', 56, 5643, 3, '2.3.1', 'Nas Agências', '2.3.1.1 Realizar o atendimento do cliente e a venda dos chips conforme POP.\n2.3.1.2 Entregar o comprovante do SARA ao cliente.', 21),
(5645, 'capitulo', 56, 5643, 3, '2.3.2', 'Central Financeira - CEFIN', '2.3.2.1 Enviar à Surf Telecom, empresa parceira na venda de chips, todo dia útil, relatório de vendas de recargas virtuais, detalhando as vendas em espécie, em cartão de débito e de crédito do segundo dia útil anterior (D-1).\n2.3.2.2 Autorizar o depósito dos valores no Enterprise Resource Planning - ERP, deduzida sua remuneração e a taxa dos recebimentos com cartão, em conta corrente designada pela empresa parceira.\n2.4 Procedimentos de Comercialização da Recarga Fora da Rede de Atendimento dos Correios', 22),
(5646, 'capitulo', 56, 5643, 3, '2.4.1', 'Gestor do produto', '2.4.1.1 Receber o demonstrativo consolidado da receita referente às recargas vendidas fora da rede de atendimento dos Correios.\n2.4.1.2 Encaminhar o demonstrativo à CEFIN.\n2.4.1.3 Receber informação da CEFIN sobre a fatura emitida e a data de vencimento.', 23),
(5647, 'capitulo', 56, 5643, 3, '2.4.2', 'Central Financeira - CEFIN', '2.4.2.1 Emitir a fatura dos serviços prestados fora da rede de atendimento.\n2.4.2.2 Informar ao gestor do produto, via SEI, o valor e a data de vencimento da fatura.\n2.5 Procedimentos de Devolução dos Chips não Comercializados', 24),
(5648, 'capitulo', 56, 5643, 3, '2.5.1', 'Nas agências próprias', '2.5.1.1 Devolver os chips não comercializados (inválidos ou com defeito) ao órgão supridor CLI Leste CLI Oeste.\n2.5.1.2 Fazer pacotes com 25 (vinte e cinco) unidades, de forma somente o último pacote de chips avulsos contenha menos de 25 (vinte e cinco) unidades.\n2.5.1.3 Emitir a Guia de Remessa de Produtos - GRP.\n2.5.1.4 Rotular as encomendas.\n2.5.1.5 Preparar a expedição.', 25),
(5649, 'capitulo', 56, 5643, 3, '2.5.2', 'Nos Centros de Logística Integrada - CLIs (Leste e Oeste)', '2.5.2.1 Receber das agências os chips devolvidos.\n2.5.2.2 Lavrar auto de irregularidade, caso seja observado algum indício de violação do pacote.\n2.5.2.3 Lavrar termo de conferência e encaminhar à unidade para verificar o ocorrido, caso haja divergência na quantidade.\n2.5.2.4 Arquivar a 1ª via da Guia de Recolhimento de Produtos - GRP na área de suprimento.\n2.5.2.5 Conferir e separar os chips recebidos nos volumes.\n2.5.2.6 Lacrar e rotular o unitizador.\n2.5.2.7 Preparar a expedição à Surf Telecom.\n2.5.2.8 Encaminhar a carga para expedição.\n2.5.2.8 Devolver à Surf Telecom os chips não comercializados, devidamente separados por Superintendência Estadual - SE, acompanhados de relação totalizadora em 2 (duas) vias, passando recibo na 2ª via.', 26),
(5650, 'capitulo', 56, 5632, 2, '2.6', 'Procedimentos de Prestação de Contas dos Chips comercializados na Rede de Atendimento dos Correios', '', 27),
(5651, 'capitulo', 56, 5650, 3, '2.6.1', 'Central Financeira - CEFIN', '2.6.1.1 Apurar, após o fechamento da quinzena, as vendas por CLI, por taxa de recebimento com cartão e por comissão sobre as vendas para prestação de contas e repasse à Surf Telecom.\n2.6.1.2 Fazer o depósito dos valores em conta corrente designada pela Surf Telecom, deduzidas a remuneração dos Correios e as taxas inerentes ao recebimento por cartão de débito.\n2.6.1.3 Informar aos CLIs Leste e Oeste o quantitativo de venda do chip para a emissão da nota fiscal de devolução simbólica.\n2.6.1.4 Efetuar a conciliação financeira/contábil.', 28),
(5652, 'capitulo', 56, 5650, 3, '2.6.2', 'CLIs Leste e Oeste.', '2.6.2.1 Emitir a nota fiscal/Danfe relativa à devolução simbólica das mercadorias vendidas, sem tributação, de acordo com as vendas apuradas pela CEFIN.\n2.6.2.2 Escriturar a nota fiscal de devolução simbólica emitida pelos Correios no Livro de Registro de Entradas - LRE.\nNota: a Surf Telecom deverá emitir nota fiscal/Danfe de vendas em consignação para cada CLI (Leste e Oeste), contendo, além dos demais requisitos previstos na legislação tributária, as indicações da operação, CFOP 5114 (se operação interna), CFOP 6114 (se operação interestadual), valor da operação correspondente ao preço da mercadoria efetivamente vendida, neste incluído, quando for o caso, o valor relativo ao reajuste do preço.', 29),
(5653, 'capitulo', 56, 5632, 2, '2.7', 'Procedimentos de Atendimento aos Serviços de Pós-Venda', '', 30),
(5654, 'capitulo', 56, 5653, 3, '2.7.1', 'Demanda do Poder Judiciário e do Programa de Proteção e Defesa do Consumidor - Procon', '2.7.1.1 Superintendência Estadual - SE\n2.7.1.1.1 Receber a demanda e, imediatamente, abrir processo no Sistema Eletrônico de Informações - SEI, destinado ao gestor do produto (GPOV/DEVAR) e à Ouvidoria ou jurídico.\n2.7.1.1.2 Solicitar, ao gestor do produto, subsídios para resposta.\n2.7.1.1.3 Responder ao órgão demandante, após recebimento dos subsídios, e incluir o resultado no respectivo processo.\n2.7.1.2 Gestor do Produto\n2.7.1.2.1 Encaminhar a demanda à Surf Telecom, solicitando subsídios para auxiliar na resposta ao órgão.\n2.7.1.2.2 Receber os subsídios da Surf Telecom.\n2.7.1.2.3 Encaminhar os subsídios ao órgão demandante na SE ou ao Departamento Jurídico - DEJUR.', 31),
(5655, 'capitulo', 56, 5653, 3, '2.7.2', 'Portabilidade', '2.7.2.1 Agência\n2.7.2.1.1 Recepcionar o cliente com a demanda e conferir os documentos obrigatórios, conforme POP.\n2.7.2.1.2 Abrir chamado de portabilidade ou resolução de um problema relacionado a portabilidade, com indicação das informações necessárias.\n2.7.2.1.3 Orientar o cliente sobre ao prazo previsto pela Anatel para concretização da portabilidade.\nNota 1: para que a portabilidade seja executada dentro do prazo de 3 (três) dias, é necessário que o Cadastro de Pessoa Física - CPF cadastrado seja o mesmo nas duas operadoras (Correios Celular e Operadora Doadora).\nNota 2: se o CPF for divergente, a portabilidade não será executada devido a bloqueio na operadora doadora.\nNota 3: se o número da operadora doadora estiver inválido (número antigo ou que não se encontra mais ativo), a portabilidade não será executada.\nNota 4: se o número de telefone do cliente na operadora doadora foi conta pós-pago ou conta controle, a portabilidade pode não ser executada, dessa forma, é necessário que o cliente solicite, a sua operadora, a alteração para conta do tipo pré-pago.', 32),
(5656, 'capitulo', 56, 5653, 3, '2.7.3', 'Mudança de Titularidade', '2.7.3.1 Recepcionar o cliente com a demanda e conferir os documentos obrigatórios.\n2.7.3.2 Abrir chamado para mudança de titularidade com necessidade de indicação das informações necessárias, conforme POP.\n2.7.3.3 Informar ao cliente sobre o recebimento do Short Message Service - SMS de confirmação da titularidade.\nNota 1: para solicitar a troca de titularidade é necessário que o solicitante e o cedente da linha apresentem documento de identificação e que ambos devem estar presente no ato da solicitação.\nNota 2: para que a troca de titularidade seja executada, é enviado um SMS de confirmação, para isso, o Chip Correios Celular deve estar ativo e funcionando para que seja possível o recebimento do SMS.\nNota 3: nos casos de troca de titularidade para pessoas jurídicas, o processo será feito em até 5 (cinco) dias úteis e o titular da linha deverá abrir chamado no call center.\n* * * * *', 33),
(5657, 'capitulo', 57, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: disponibilizar consulta de informações existentes no cadastro de inadimplentes nas bases de dados da Serasa Experian S.A, mediante consulta individual e pagamento dos preços estipulados.\n1.2 Abrangência: nacional.\n1.3 Gestor: o serviço é gerenciado pela SE/Gestora do contrato e pelo Departamento de Varejo/DEVAR\n1.4 Fornecedores: órgãos do Correios Sede - CS e das Superintendências Estaduais - SEs.\n1.5 Clientes: usuários de telefones celulares nos planos pré-pagos.\n1.6 Periodicidade: por demanda.', 0),
(5658, 'capitulo', 57, 5657, 2, '1.7', 'Duração: vigência do contrato 9912410478 - 14/03/2022.', '', 1),
(5659, 'capitulo', 57, 5657, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - gerir produtos e serviços', '', 2),
(5660, 'capitulo', 57, NULL, 1, '2', 'DESCRIÇAO DO SUBPROCESSO', '2.1 Procedimentos para atendimento do serviço:', 3),
(5661, 'capitulo', 57, 5660, 4, 'a', 'receber a solicitação do cliente;', '', 4),
(5662, 'capitulo', 57, 5660, 4, 'b', 'solicitar documento de identificação com foto e CPF;', '', 5),
(5663, 'capitulo', 57, 5660, 4, 'c', 'selecionar, por meio do SARA, o serviço 34355 - Consulta de Proteção ao Crédito;', '', 6),
(5664, 'capitulo', 57, 5660, 4, 'd', 'proceder conforme Manual de Operacionalização - Serasa;', '', 7),
(5665, 'capitulo', 57, 5660, 4, 'e', 'entregar o ticket ao cliente;', '', 8),
(5666, 'capitulo', 57, 5660, 4, 'f', 'finalizar o atendimento.', 'Nota: detalhes sobre a operacionalização do Serviço estão contidos no Resumo de Serviços Especiais - RSE - Serasa, disponível na Intranet.\n2.2 Procedimentos de processamento do serviço:\nCEFIN/SUFIN/DIEFI', 9),
(5667, 'capitulo', 57, 5660, 4, 'a', 'realizar os procedimentos de arrecadação e importação do movimento das agencias diariamente para repasse ao cliente;', '', 10),
(5668, 'capitulo', 57, 5660, 4, 'b', 'efetuar a conciliação financeiro-contábil e, sendo apuradas divergências, efetuar os acertos financeiros pertinentes;', '', 11),
(5669, 'capitulo', 57, 5660, 4, 'c', 'gerar demonstrativo das vendas realizadas no mês anterior e enviar até o 7º (sétimo) dia útil ao cliente, via e-mail;', '', 12),
(5670, 'capitulo', 57, 5660, 4, 'd', 'período mensal: do 1º (primeiro) ao último dia de cada mês;', '', 13),
(5671, 'capitulo', 57, 5660, 4, 'e', 'efetuar o repasse no dia 23 do mês subsequente à prestação do serviço, mediante recebimento da nota débito a ser emitida pela Serasa Experian;', '', 14),
(5672, 'capitulo', 57, 5660, 4, 'f', 'após a realização do repasse financeiro, emitir carta à Serasa com o demonstrativo financeiro da prestação do serviço de disponibilização de Consultas Serasa nas Agências dos Correios no mês de referência;', '', 15),
(5673, 'capitulo', 57, 5660, 4, 'g', 'avaliar as demandas de acerto financeiro das agências, em função de impossibilidade de impressão do ticket de consulta ao cadastro SERASA por problemas técnicos exclusivos dos Correios, com base na conclusão da interação respondida pela área de suporte SARA.', 'Nota: À GPOV/DEVAR/DINEG, cabe gerir o serviço conforme atribuições previstas no MANORG 8/6.\n* * * * *', 16),
(5674, 'capitulo', 58, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5675, 'capitulo', 58, 5674, 2, '1.1', 'Objetivo: prestar o serviço Telegrama Nacional.', '', 1),
(5676, 'capitulo', 58, 5674, 2, '1.2', 'Abrangência: nacional.', '', 2),
(5677, 'capitulo', 58, 5674, 2, '1.3', 'Gestor: Funcional: Departamento de Gestão de Serviços Nacionais - DEPRO /SUPRO/DINEG.', '', 3),
(5678, 'capitulo', 58, 5674, 2, '1.4', 'Fornecedores: áreas comercial, operacional e técnica.', '', 4),
(5679, 'capitulo', 58, 5674, 2, '1.5', 'Clientes: pessoas físicas e jurídicas.', '', 5),
(5680, 'capitulo', 58, 5674, 2, '1.6', 'Periodicidade: contínua.', '', 6),
(5681, 'capitulo', 58, 5674, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(5682, 'capitulo', 58, 5674, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', '', 8),
(5683, 'capitulo', 58, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(5684, 'capitulo', 58, 5683, 2, '2.1', 'Procedimentos das Áreas de Atendimento/Captação', '', 10),
(5685, 'capitulo', 58, 5684, 3, '2.1.1', 'Telegrama de Balcão', '2.1.1.1 Realizar a venda do serviço de telegrama aos clientes em todas as Agências de Correios próprias e terceirizadas, conforme subitem 2.2 deste Capítulo.\n2.1.1.1.1 Registrar o valor informado pelos sistemas, que será calculado conforme a quantidade de páginas utilizadas.\n2.1.1.1.2 Oferecer os Serviços Adicionais: Pedido de Confirmação de Entrega - PC e Cópia de Telegrama - CC, conforme o subitem Serviços Telemáticos Adicionais deste Capítulo.\n2.1.1.2 Imprimir o arquivo formulário telegrama balcão, conforme modelo do Anexo 6 deste Capítulo, disponibilizado no endereço https://intranet.correios.com.br/correios-normas-1/formularios/t/telegrama_balcao_nova_marca.pdf/view.\n2.1.1.3 Requisitar ao respectivo Centro de Distribuição - CD (Leste ou Oeste) a quantidade suficiente de etiquetas telegramas (MB) para o atendimento conforme necessidade da unidade, levantada a partir do histórico de vendas e eventual estoque existente na unidade.\n2.1.1.4 Utilizar etiquetas telegrama (MB) numerada autoadesiva com código de barras em substituição ao registro pré-impresso nos formulários originais, cujo número será utilizado na transmissão do telegrama via sistemas.\n2.1.1.5 Receber o(s) formulário(s) telegrama balcão devidamente preenchido(s) pelo cliente, e verificar se atende(m) às condições de aceitação estabelecidas no Anexo 3 deste Capítulo.\n2.1.1.6 Negociar com o cliente a possibilidade de pré-datar os telegramas, programando a entrega em vários dias de acordo com a quantidade de mensagens, sempre que ocorrer a postagem de uma remessa/listagem.\n2.1.1.6.1 Aceitar a remessa/listagem mesmo que o cliente não concorde em pré-datar os telegramas.\n2.1.1.6.2 Alertar ao cliente que a transmissão e a entrega dos telegramas está condicionada à capacidade técnica e operacional dos Correios, e que desta forma não haverá condições de garantir a entrega em até 4 (quatro) horas ou até no mesmo dia.\n2.1.1.7 Validar o agendamento de entrega do telegrama pré-datado, quando solicitado pelo cliente.\n2.1.1.7.1 Verificar se a data de entrega é posterior à data da apresentação.\n2.1.1.7.2 Verificar se a data informada pelo expedidor recairá num sábado, domingo ou feriado, e se existe entrega nesses dias para a localidade indicada, por meio de consulta no Sistema Gerenciador de Mensagens - SGM, no campo “Consulta Serviço”.\n2.1.1.7.3 Indicar outra data, caso não haja entrega de telegrama para a localidade indicada pelo remetente (expedidor) na data escolhida, desde que esteja de acordo com a Tabela de Prazos de Telegrama, constante no endereço: https://www2.correios.com.br/sistemas/precosPrazos/.\n2.1.1.7.4 Fazer constar nos campos apropriados do formulário a indicação \"Telegrama Pré-Datado\" e a data da entrega ao destinatário.\n2.1.1.8 Validar os dados de cada telegrama quanto à linguagem.\n2.1.1.8.1 Aceitar os telegramas que estejam redigidos em linguagem corrente ou cifrada (conforme conceitos constantes do glossário).\n2.1.1.8.2 Solicitar esclarecimentos adicionais ao remetente (expedidor) sempre que houver dúvidas quanto ao significado de qualquer informação contida no telegrama.\n2.1.1.8.3 Recusar o telegrama sempre que o remetente (expedidor) não esclarecer as dúvidas.\n2.1.1.8.4 Aceitar os telegramas que contenham códigos especiais em suas redações, quando previstos 	em normas de conhecimento público, considerando-os como linguagem corrente.\n2.1.1.8.5 Aceitar os telegramas que contenham as informações conforme descritas no Anexo 3 deste Capítulo.\n2.1.1.8.6 Aceitar o telegrama redigido em linguagem cifrada somente se o endereço do destinatário, constante no telegrama, estiver escrito em linguagem corrente.\n2.1.1.9 Recusar o formulário telegrama balcão que não atenda aos requisitos conforme descritas no Anexo 3 deste Capítulo.\n2.1.1.10 Transmitir o(s) telegrama(s) no prazo máximo de até 30 (trinta) minutos após o horário do recebimento do formulário telegrama balcão, por meio dos sistemas, informando os dados de cobrança exigidos pelo sistema.\n2.1.1.11 Contatar os Centros de Serviços Telemáticos - CST ou órgão responsável na regional para verificar a possibilidade de transmissão, antes da confirmação da postagem de uma remessa/listagem (20 telegramas ou mais), caso a unidade constate que haverá dificuldades para transmissão no seu âmbito.', 11),
(5686, 'capitulo', 58, 5684, 3, '2.1.2', 'Telegrama Fonado', '2.1.2.1 Realizar a captação do(s) telegrama(s) por meio da Central de Atendimento dos Correios - CAC por telefone, limitado até 3 (três) postagens por ligação.\n2.1.2.1.1 Validar os dados do remetente, destinatário, contato, mensagem, serviços adicionais, formas de pagamento e opções de entrega desejados, incluindo data de entrega - em caso de pré-datado, conforme as orientações descritas nas ferramentas de informação da CAC.\n2.1.2.1.2 Validar o agendamento de entrega (telegrama pré-datado), quando solicitado pelo cliente, conforme disposto no subitem 2.1.1.7 e seus subitens, deste Capítulo.\n2.1.2.2 Transmitir o(s) telegrama(s) recebidos utilizando o SGM, informando os dados de cobrança exigidos pelo sistema.', 12),
(5687, 'capitulo', 58, 5684, 3, '2.1.3', 'Telegrama Via Internet', '2.1.3.1 Captar eletronicamente via internet os telegramas transmitidos pelos sistemas e loja online dos Correios, conforme características descritas no Anexo 2 deste Capítulo.\n2.1.3.2 Transmitir eletronicamente os telegramas captados pela internet para os sistemas, conforme características descritas no Anexo 2 deste Capítulo.', 13),
(5688, 'capitulo', 58, 5684, 3, '2.1.4', 'Mídia Eletrônica (Grandes Clientes)', '2.1.4.1 Receber os telegramas encaminhados em arquivo magnético para os CST, conforme orientações e leiautes constantes no Anexo 4 deste Capítulo.\n2.1.4.1.1 Subdividir cada arquivo recebido no leiaute Grandes Clientes, caso seja necessário, em arquivos com tamanhos máximos de 2MB ou 3000 (três mil) telegramas.\n2.1.4.1.2 Formatar os telegramas recebidos no leiaute Excel e gerar arquivo(s) no leiaute de Grandes Clientes aceitos pelo SGM.\n2.1.4.1.3 Devolver as remessas fora dos padrões, ou quando as condições e/ou quantidades não forem passíveis de tratamento, informando ao cliente os motivos da devolução.\n2.1.4.2 Submeter os arquivos com os telegramas para postagem em lote (Grandes Clientes) via SGM.\n2.1.4.3 Retornar aos clientes os arquivos de log resultantes da postagem do arquivo contendo os registros (telegramas) rejeitados pelo SGM e do arquivo de recibo dos registros (telegramas) postados com sucesso', 14),
(5689, 'capitulo', 58, 5684, 3, '2.1.5', 'Serviços Adicionais Telemáticos (PC/CC)', '2.1.5.1 Vender os serviços adicionais: PC e CC, em conjunto com a mensagem telemática, utilizando a tela do serviço Telegrama Nacional 4h (por página).\n2.1.5.2 Vender os serviços adicionais (PC/CC Posterior), quando o serviço principal telegrama já tenha sido vendido anteriormente, em até 365 dias após a postagem do telegrama, independente do canal utilizado na postagem original (balcão, fonado, internet), utilizando a opção “Pós Postagem” na tela do serviço telegrama do Sistema de Automação da Rede de Atendimento - SARA, caso utilize as Agências de Correios próprias e terceirizadas.\n2.1.5.2.1 Solicitar o número do telegrama para possibilitar a transmissão do serviço adicional PC/CC posterior no SGM.\n2.1.5.2.2 Avisar ao interessado que a resposta à sua solicitação será encaminhada conforme o endereço constante no telegrama original, como descrito no item de venda do PC/CC acima.\n2.1.5.3 Emitir um PC para cada telegrama, separadamente.\nNota: não emitir PC sem a data, hora e nome legível de quem recebeu o telegrama.\n2.1.5.4 Transmitir o telegrama com o PC obedecendo os mesmos prazos previstos para a natureza do telegrama que originou o PC.\n2.1.5.4.1 Atentar para o fato de que deverá constar nesse telegrama todos os dados que constarem nas linhas de endereçamento do destinatário, sem abreviar o nome e o número do protocolo que consta após ou abaixo do nome do destinatário. (Essa exigência normalmente é feita por Cartórios que mantém contrato com os Correios.', 15),
(5690, 'capitulo', 58, 5684, 3, '2.1.6', 'Pagamento e Preços', '2.1.6.1 Cobrar o serviço de acordo com as modalidades de pagamento e preços previstos na Tabela de Preços, de acordo com as características constantes no Anexo 2 deste Capítulo.', 16),
(5691, 'capitulo', 58, 5683, 2, '2.2', 'Procedimentos da Área de Distribuição', '', 17),
(5692, 'capitulo', 58, 5691, 3, '2.2.1', 'Escoamento e Entrega', '2.2.1.1 Escoar os telegramas no menor prazo possível, conforme definidos no MANDIS 2.', 18),
(5693, 'capitulo', 58, 5691, 3, '2.2.2', 'Entrega Externa ou Interna', '2.2.2.1 Realizar a entrega dos telegramas nos endereços dos destinatários, quando exigida a entrega domiciliária, conforme definido no MANDIS 3/1/2.\n2.2.2.2 Realizar o tratamento de objetos postais, destinados a entrega interna em uma unidade operacional ou de atendimento dos Correios, considerando-se os procedimentos definidos para a Entrega Interna conforme MANATE 4/1/2.\n2.2.2.3 Realizar a entrega da CC sempre que solicitada para entrega em domicílio.\n2.2.2.4 Realizar a entrega do PC, sempre que solicitado para entrega em domicílio.\n* * * * *', 19),
(5694, 'capitulo', 59, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5695, 'capitulo', 59, 5694, 2, '1.1', 'Objetivo: atender necessidade do cliente, por meio da prestação do serviço de entrega ao titular ou a devolução ao órgão emissor de documentos perdidos e/ou extraviados, quando entregues na Agência de Correios ou depositados em Caixas de Coleta.', '', 1),
(5696, 'capitulo', 59, 5694, 2, '1.2', 'Abrangência: no mínimo uma unidade de atendimento própria, por localidade, previamente selecionada pela Diretoria Regional, intitulada como Agência Centralizadora. A critério da Diretoria Regional, mais de uma unidade poderá ser cadastrada por localidade.', '', 2),
(5697, 'capitulo', 59, 5694, 2, '1.3', 'Gestor: Departamento de Filatelia e Produtos - DEFIP.', '', 3),
(5698, 'capitulo', 59, 5694, 2, '1.4', 'Fornecedores: órgãos da Administração Central e Diretorias Regionais.', '', 4),
(5699, 'capitulo', 59, 5694, 2, '1.5', 'Clientes: interessados na prestação do serviço.', '', 5),
(5700, 'capitulo', 59, 5694, 2, '1.6', 'Periodicidade: diária.', '', 6),
(5701, 'capitulo', 59, 5694, 2, '1.7', 'Duração: indeterminada.', '', 7),
(5702, 'capitulo', 59, 5694, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - gerir produtos e serviços', '', 8),
(5703, 'capitulo', 59, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(5704, 'capitulo', 59, 5703, 2, '2.1', 'Procedimentos na Agência para atendimento do Serviço Achados e Perdidos', 'Nota: os documentos perdidos podem ser depositados nas Caixas de Coleta ou entregues em qualquer Agência dos Correios. Caso sejam depositados ou entregues em unidades terceirizadas, estas deverão encaminhá-los às respectivas Agências subordinadoras, uma vez que não poderão, em hipótese alguma, efetuar a devolução dos documentos diretamente aos interessados.', 10),
(5705, 'capitulo', 59, 5704, 3, '2.1.1', 'Recepcionar o cliente e solicitar um documento que comprove sua titularidade, posto que eventuais documentos sob a guarda dos Correios só poderão ser entregues aos proprietários ou seus representantes legais devidamente reconhecidos:', '', 11),
(5706, 'capitulo', 59, 5705, 4, 'a', 'o documento de menores de 18 anos somente poderá ser retirado pelos pais ou responsáveis, necessitando, para isso, da apresentação de um documento de identidade para o registro da entrega;', '', 12),
(5707, 'capitulo', 59, 5705, 4, 'b', 'o menor de 18 anos não pode autorizar a retirada dos documentos por outras pessoas;', '', 13),
(5708, 'capitulo', 59, 5705, 4, 'c', 'quando da perda dos documentos que permitam a identificação por meio de foto, além do nome do titular, deve-se solicitar a identificação completa de filiação (pai e mãe);', '', 14),
(5709, 'capitulo', 59, 5705, 4, 'd', 'os documentos que poderão ser apresentados para retirada são:', 'I - original ou cópia do Boletim de Ocorrência, quando se tratar do próprio titular;\nII - autorização por escrito, simples, assinada pelo dono do documento;\nIII - identidade do representante ou outro documento oficial e Boletim de Ocorrência (original e cópia) relativo à perda do documento, quando se tratar de representante do titular.\nNota: os documento, quando apresentados, devem ser arquivados pela Unidade por 06 (seis) meses e, posteriormente, refugados na própria unidade.', 15),
(5710, 'capitulo', 59, 5704, 3, '2.1.2', 'Efetuar pesquisa no Sistema de Achados e Perdidos, de modo a localizar se o documento encontra-se na base de dados dos Correios.', '', 16),
(5711, 'capitulo', 59, 5704, 3, '2.1.3', 'Caso positivo, informar ao cliente que o documento está na base de dados dos Correios e a unidade em que o documento está sob guarda; seguir os procedimentos constantes no item 2.1.6.', '', 17),
(5712, 'capitulo', 59, 5704, 3, '2.1.4', 'Caso negativo, informar ao cliente que o documento não se encontra nos Correios, dispensando-o posteriormente.', '', 18),
(5713, 'capitulo', 59, 5704, 3, '2.1.5', 'Caso seja a unidade em que conste o documento:', '', 19),
(5714, 'capitulo', 59, 5713, 4, 'a', 'entregar o documento perdido ao cliente/titular;', '', 20),
(5715, 'capitulo', 59, 5713, 4, 'b', 'efetuar a baixa dos documentos no SDP, capturando os dados de endereço do titular do documento, a fim de manter a base de dados dos endereços dos respectivos titulares dos documentos, que serão mantidos na base de dados dos Correios;', '', 21),
(5716, 'capitulo', 59, 5713, 4, 'c', 'receber o valor estabelecido na Tabela de Preços e Tarifas Serviços Nacionais:', 'I - caso o cliente se recuse a efetuar o pagamento do valor estabelecido para o Serviço Achados e Perdidos, deverá ser explicado sobre os custos de desenvolvimento e manutenção do sistema. Persistindo a recusa, será emitida a declaração de não pagamento, disponível no sistema, a ser assinada pelo próprio recebedor, e a entrega do documento será efetuada normalmente sem a cobrança de qualquer valor;\nII - o pagamento dos valores relativos aos serviços prestados poderá ser efetuado em dinheiro, cheque ou por meio de cartão de crédito/débito, caso a unidade disponibilize esse meio de pagamento;', 22),
(5717, 'capitulo', 59, 5713, 4, 'd', 'lançar o serviço no sistema de atendimento, entregar o recibo e finalizar o atendimento.', '', 23),
(5718, 'capitulo', 59, 5704, 3, '2.1.6', 'Caso não seja a unidade em que conste o documento, informar ao titular que ele poderá optar pelo recebimento em Agência mais próxima do seu endereço ou local de trabalho, exceto Agência Franqueada. Para tanto, deverá formalizar o pedido na agência própria mais próxima:', '', 24),
(5719, 'capitulo', 59, 5718, 4, 'a', 'a solicitação para o envio do documento para a Agência mais próxima, deverá ser feita pelo titular ou representante legal, devidamente identificado, por escrito, e deverá conter, se possível, cópia do Boletim de Ocorrência – BO ou documento com foto;', '', 25),
(5720, 'capitulo', 59, 5718, 4, 'b', 'enviar e-mail à unidade responsável pela guarda do documento, solicitando a reexpedição dos documentos, em envelope vai e vem simples, para a unidade. O e-mail deverá conter:', 'I - nome completo do solicitante/titular e telefone de contato;\nII - endereço da unidade definida para entrega;\nIII - nome completo do solicitante/titular e telefone de contato;\nIV - endereço da unidade definida para entrega;\nV - nome do pai do titular;\nVI - nome da mãe do titular;\nVII - data de nascimento do titular;\nVIII - nº do boletim de ocorrência (BO) e data de emissão, se apresentado;\nIX - tipo e nº do(s) documento(s) solicitado(s), obrigatoriamente.', 26),
(5721, 'capitulo', 59, 5718, 4, 'c', 'solicitar para que o cliente comparecerá à agência indicada 10 dias úteis, após o pedido, para retirada da remessa.', '', 27),
(5722, 'capitulo', 59, 5703, 2, '2.2', 'Procedimentos na agência/unidade que receber solicitação de envio do documento', '', 28),
(5723, 'capitulo', 59, 5722, 3, '2.2.1', 'Receber a solicitação via e-mail, sendo que a comunicação (e-mail) deverá ficar arquivada, pelo prazo de 06 (seis) meses na unidade responsável pelo acolhimento da solicitação.', '', 29),
(5724, 'capitulo', 59, 5722, 3, '2.2.2', 'Efetuar a baixa dos documentos no SDP, na opção Entregue sem taxa;', '', 30),
(5725, 'capitulo', 59, 5722, 3, '2.2.3', 'Acondicioná-los em envelope de serviço vai e vem com o nome Reexpedição Achados e Perdidos;', '', 31),
(5726, 'capitulo', 59, 5722, 3, '2.2.4', 'Endereçá-lo à agência;', '', 32),
(5727, 'capitulo', 59, 5722, 3, '2.2.5', 'Expedir pelo malote da unidade o envelope vai e vem;', '', 33),
(5728, 'capitulo', 59, 5722, 3, '2.2.6', 'Anexar o formulário emitido pelo SDP da entrega sem taxa, com o e-mail de solicitação e arquivá-los com os documentos contábeis da unidade;', '', 34),
(5729, 'capitulo', 59, 5722, 3, '2.2.7', 'Informar, por e-mail, à unidade solicitante, a data de atendimento à solicitação e encaminhamento.', 'Nota: o documento é considerado entregue a partir da baixa efetuada no SDP. Em face da forma de envio ser simples e a prestação do serviço de reexpedição ser sem ônus para o cliente, não se admite reclamação em caso de extravio.', 35),
(5730, 'capitulo', 59, 5703, 2, '2.3', 'Procedimentos agência própria que receber o documento para entrega', '', 36),
(5731, 'capitulo', 59, 5730, 3, '2.3.1', 'Recepcionar o cliente e solicitar um documento que comprove sua titularidade, posto que eventuais documentos sob a guarda dos Correios só poderão ser entregues aos proprietários ou representantes legais devidamente identificados;', '', 37),
(5732, 'capitulo', 59, 5730, 3, '2.3.2', 'Entregar o documento ao cliente;', '', 38),
(5733, 'capitulo', 59, 5730, 3, '2.3.3', 'Receber o valor estabelecido na tabela de Preços e Tarifas Serviços Nacionais para o serviço Achados e Perdidos:', '', 39),
(5734, 'capitulo', 59, 5733, 4, 'a', 'caso o cliente se recuse a efetuar o pagamento do valor estabelecido para o Serviço Achados e Perdidos, deverá ser explicado sobre os custos de desenvolvimento e manutenção do sistema. Persistindo a recusa, será emitida a declaração de não pagamento, disponível no sistema, a ser assinada pelo próprio recebedor após o entrega do documento será efetuada normalmente, sem a cobrança de qualquer valor;', '', 40),
(5735, 'capitulo', 59, 5733, 4, 'b', 'o pagamento dos valores relativos aos serviços prestados poderá ser efetuado em dinheiro, cheque ou por meio de cartão de crédito/débito, caso a unidade disponibilize esse meio de pagamento;', '', 41),
(5736, 'capitulo', 59, 5733, 4, 'c', 'pela entrega de documentos na unidade mais próxima do endereço do titular deverá ser cobrado o valor fixado na Tabela de Preços e Tarifas, independentemente da quantidade de documentos restituída, sem qualquer acréscimo de preço correspondente ao serviço de Reexpedição dos documentos.', '', 42),
(5737, 'capitulo', 59, 5730, 3, '2.3.4', 'Lançar o serviço no sistema de atendimento, entregar o recibo e finalizar o atendimento;', '* * * * *', 43),
(5738, 'capitulo', 60, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5739, 'capitulo', 60, 5738, 2, '1.1', 'Objetivo: visa atender os clientes para o envio e recebimento de remessas financeiras em âmbito internacional.', '', 1),
(5740, 'capitulo', 60, 5738, 2, '1.2', 'Abrangência: agências de Correios (próprias e AGFs).', '', 2),
(5741, 'capitulo', 60, 5738, 2, '1.3', 'Gestor: Departamento de Gestão de Produtos Internacionais - DEINT/DINEG', '', 3),
(5742, 'capitulo', 60, 5738, 2, '1.4', 'Fornecedores: órgãos da Administração Central e Superintendências Estaduais.', '', 4),
(5743, 'capitulo', 60, 5738, 2, '1.5', 'Clientes: interessados na prestação do serviço.', '', 5),
(5744, 'capitulo', 60, 5738, 2, '1.6', 'Periodicidade: diária.', '', 6),
(5745, 'capitulo', 60, 5738, 2, '1.7', 'Duração: indeterminada.', '', 7),
(5746, 'capitulo', 60, 5738, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços', '', 8),
(5747, 'capitulo', 60, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(5748, 'capitulo', 60, 5747, 2, '2.1', 'Emissão de Vale Internacional Eletrônico', '', 10),
(5749, 'capitulo', 60, 5748, 3, '2.1.1', 'Receber a solicitação do cliente para emissão de Vale Internacional Eletrônico e informar o país de destino.', '', 11),
(5750, 'capitulo', 60, 5748, 3, '2.1.2', 'Verificar se o país informado pelo cliente possui convênio com os Correios para o envio de Vale Postal Internacional Eletrônico.', '', 12),
(5751, 'capitulo', 60, 5748, 3, '2.1.3', 'Selecionar o código correspondente à emissão de Vale Postal Internacional no sistema de atendimento.', '', 13),
(5752, 'capitulo', 60, 5748, 3, '2.1.4', 'Solicitar que o cliente informe o nome e endereço completo (inclusive CEP) do destinatário e valor da remessa.', '', 14),
(5753, 'capitulo', 60, 5748, 3, '2.1.5', 'Selecionar a finalidade da remessa, conforme exigido pelo “Regulamento do Mercado de Câmbio e Capitais Internacionais” do Banco Central do Brasil.', '', 15),
(5754, 'capitulo', 60, 5748, 3, '2.1.6', 'Selecionar o país de destino.', '', 16),
(5755, 'capitulo', 60, 5748, 3, '2.1.7', 'Preencher o campo “Valor” com o montante informado pelo remetente, em reais.', '', 17),
(5756, 'capitulo', 60, 5748, 3, '2.1.8', 'Acessar a guia “Cotações”, selecionar a moeda correspondente e efetuar a conversão.', '', 18),
(5757, 'capitulo', 60, 5748, 3, '2.1.9', 'Selecionar, na guia “Complementares” a finalidade da remessa.', '', 19),
(5758, 'capitulo', 60, 5748, 3, '2.1.10', 'Solicitar ao cliente para que apresente o CPF/CNPJ e documento de identificação ou passaporte e informar endereço do remetente. Os documentos de identificação válidos são:', '', 20),
(5759, 'capitulo', 60, 5758, 4, 'a', 'carteira de Identidade;', '', 21),
(5760, 'capitulo', 60, 5758, 4, 'b', 'carteira de Trabalho e Previdência Social;', '', 22),
(5761, 'capitulo', 60, 5758, 4, 'c', 'certificado de Alistamento Militar;', '', 23),
(5762, 'capitulo', 60, 5758, 4, 'd', 'certificado de Reservista;', '', 24),
(5763, 'capitulo', 60, 5758, 4, 'e', 'certificado de Dispensa de Incorporação;', '', 25),
(5764, 'capitulo', 60, 5758, 4, 'f', 'carteira de Conselho de Classe;', '', 26),
(5765, 'capitulo', 60, 5758, 4, 'g', 'carteira Funcional (somente para empregado do Correios;', '', 27),
(5766, 'capitulo', 60, 5758, 4, 'h', 'carteira de Identidade Postal; ou', '', 28),
(5767, 'capitulo', 60, 5758, 4, 'i', 'qualquer outro documento que tenha fé pública no território nacional, que contenha a fotografia do titular e possibilite comprovar a assinatura do favorecido ou remetente ou seus representantes legais.', '', 29),
(5768, 'capitulo', 60, 5748, 3, '2.1.11', 'Preencher os dados do remetente, com nome completo, endereço, telefone, CPF/CNPJ e documento de identidade ou passaporte.', '', 30),
(5769, 'capitulo', 60, 5748, 3, '2.1.12', 'Preencher os dados do destinatário, com nome completo, endereço e telefone.', '', 31),
(5770, 'capitulo', 60, 5748, 3, '2.1.13', 'Solicitar para o cliente que confira, no ticket de pré-conferência emitido pelo sistema de atendimento, se os dados do destinatário foram preenchidos corretamente pelo empregado da unidade.', '', 32),
(5771, 'capitulo', 60, 5748, 3, '2.1.14', 'Informar ao cliente o valor total do serviço, receber o dinheiro e finalizar o serviço no sistema de atendimento.', '', 33),
(5772, 'capitulo', 60, 5748, 3, '2.1.15', 'Solicitar a assinatura do cliente no comprovante emitido pelo sistema.', '', 34),
(5773, 'capitulo', 60, 5748, 3, '2.1.16', 'Informar ao cliente que, conforme legislação específica, os dados referentes às transações financeiras internacionais são transmitidos ao Banco Central do Brasil (Bacen e ao Conselho de Controle de Atividades Financeiras (COAF).', '', 35),
(5774, 'capitulo', 60, 5747, 2, '2.2', 'Pagamento de Vale Internacional Eletrônico', '', 36);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(5775, 'capitulo', 60, 5774, 3, '2.2.1', 'Solicitar que o cliente apresente CPF/CNPJ e documento de identificação (conforme subitem 2.1.10) ou Passaporte e informar o número da remessa.', '', 37),
(5776, 'capitulo', 60, 5774, 3, '2.2.2', 'Acessar, no sistema de atendimento, o código referente ao pagamento de Vale Postal Internacional Eletrônico.', '', 38),
(5777, 'capitulo', 60, 5774, 3, '2.2.3', 'Selecionar a opção Pagamento ao Destinatário.', '', 39),
(5778, 'capitulo', 60, 5774, 3, '2.2.4', 'Efetuar a leitura do código de barras constante no Aviso de Chegada ou digitar o número do Vale Postal.', '', 40),
(5779, 'capitulo', 60, 5774, 3, '2.2.5', 'Pesquisar, no sistema VIE, o número do Vale Postal Internacional, caso o destinatário não apresente o Aviso de Chegada.', '', 41),
(5780, 'capitulo', 60, 5774, 3, '2.2.6', 'Conferir os dados apresentados pelo sistema de atendimento com os documentos apresentados pelo cliente.', '', 42),
(5781, 'capitulo', 60, 5774, 3, '2.2.7', 'Preencher os dados do Preposto, caso o destinatário tenha indicado.', '', 43),
(5782, 'capitulo', 60, 5774, 3, '2.2.8', 'Finalizar o atendimento, solicitar assinatura no comprovante emitido pelo sistema de atendimento e entregar o dinheiro.', '', 44),
(5783, 'capitulo', 60, 5747, 2, '2.3', 'Pagamento em Devolução ao Remetente', '', 45),
(5784, 'capitulo', 60, 5783, 3, '2.3.1', 'Solicitar ao cliente que apresente CPF/CNPJ e documento de identificação (conforme subitem 2.1.10) ou passaporte, informar o número do Vale Postal Internacional ou apresentar Aviso de Devolução ao funcionário da unidade.', '', 46),
(5785, 'capitulo', 60, 5783, 3, '2.3.2', 'Acessar, no sistema de atendimento, o código referente ao pagamento de Vale Postal Internacional Eletrônico.', '', 47),
(5786, 'capitulo', 60, 5783, 3, '2.3.3', 'Selecionar o item referente ao “Pagamento em Devolução”.', '', 48),
(5787, 'capitulo', 60, 5783, 3, '2.3.4', 'Efetuar a leitura do código de barras constante no “Aviso de Devolução” ou inserir o número do vale no sistema de atendimento.', '', 49),
(5788, 'capitulo', 60, 5783, 3, '2.3.5', 'Preencher os dados do preposto, caso o cliente tenha indicado.', '', 50),
(5789, 'capitulo', 60, 5783, 3, '2.3.6', 'Finalizar o atendimento, solicitar assinatura no comprovante emitido pelo sistema de atendimento e entregar o dinheiro.', '', 51),
(5790, 'capitulo', 60, 5747, 2, '2.4', 'Pagamento de Vale Postal Internacional Prescrito', '', 52),
(5791, 'capitulo', 60, 5790, 3, '2.4.1', 'Solicitar ao cliente que apresente CPF/CNPJ e documento de identificação (conforme subitem 2.1.10) ou passaporte e informar o número do Vale Postal Internacional.', '', 53),
(5792, 'capitulo', 60, 5790, 3, '2.4.2', 'Selecionar a opção “Pagamento em Devolução” e inserir o número da remessa no sistema de atendimento.', 'Nota: caso a remessa tenha sido devolvida há mais de 365 (trezentos e sessenta e cinco) dias, o sistema de atendimento informará que não é possível efetuar o pagamento.', 54),
(5793, 'capitulo', 60, 5790, 3, '2.4.3', 'Solicitar, à Central Financeira - CEFIN, o pagamento do vale postal ao cliente, informando: número da remessa, CPF/CNPJ, endereço, banco, agência e conta corrente.', 'Nota: caso o cliente, Pessoa Física, não possua conta bancária, o pagamento poderá ser feito através da emissão de VPNE pela CEFIN. Tratando-se de Pessoa Jurídica, o pagamento é feito exclusivamente através de depósito em conta corrente.\n* * * * *', 55),
(5794, 'capitulo', 61, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: promover o recebimento, desembaraço aduaneiro, tratamento e distribuição dos serviços de documentos e encomendas postadas em outros países com destino ao Brasil.\n1.2 Abrangência: toda a Empresa.\n1.3 Gestor: órgão gestor dos produtos internacionais\n1.4 Fornecedores: operadores designados de outros países.\n1.5 Clientes: unidades operacionais.\n1.6 Periodicidade: por demanda.\n1.7 Duração: contínua.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir portfólio de produtos.', 0),
(5795, 'capitulo', 61, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos da Área de Operações\n2.1.1 Operacionalizar o recebimento e o despacho de importação dos objetos postais internacionais conforme regras constantes dos anexos deste Capítulo, seguindo as orientações do MANINT, Módulos 8 e 9.\n2.1.2 Proceder o tratamento e a distribuição dos objetos postais internacionais conforme regras constantes dos anexos deste Capítulo e orientações dos manuais operacionais.\n2.2 Tratamento e Distribuição\n2.2.1 Proceder conforme instruído no MANINT 8 - CAP 2 para orientações quanto ao tratamento e distribuição dos serviços internacionais de importação,\n2.3 Priorização\n2.3.1 Proceder com o tratamento operacional dos serviços postais internacionais conforme priorização a seguir:', 1),
(5796, 'capitulo', 61, 5795, 4, 'a', 'EMS;', '', 2),
(5797, 'capitulo', 61, 5795, 4, 'b', 'LC Registrado e Simples;', '', 3),
(5798, 'capitulo', 61, 5795, 4, 'c', 'Prime;', '', 4),
(5799, 'capitulo', 61, 5795, 4, 'd', 'Tracked;', '', 5),
(5800, 'capitulo', 61, 5795, 4, 'e', 'Colis Postaux;', '', 6),
(5801, 'capitulo', 61, 5795, 4, 'f', 'PPR;', '', 7),
(5802, 'capitulo', 61, 5795, 4, 'g', 'PPS.', '2.4 Prazos de Entrega\n2.4.1 Considerar que, para fins de distribuição, os objetos internacionais seguirão as regras das encomendas/serviços nacionais equivalentes, a saber:', 8),
(5803, 'capitulo', 61, 5795, 4, 'a', 'EMS: equivalente ao Sedex;', '', 9),
(5804, 'capitulo', 61, 5795, 4, 'b', 'Colis Postaux, Prime e Tracked: equivalente ao PAC;', '', 10),
(5805, 'capitulo', 61, 5795, 4, 'c', 'PPR: equivalente ao Impresso Registrado;', '', 11),
(5806, 'capitulo', 61, 5795, 4, 'd', 'PPS: equivalente ao Impresso Simples;', '', 12),
(5807, 'capitulo', 61, 5795, 4, 'e', 'LC Simples e Mala M sem registro: equivalente à Carta Simples;', '', 13),
(5808, 'capitulo', 61, 5795, 4, 'f', 'LC Registrado e Mala M com registro: equivalente à Carta Registrada.', 'Nota 1: o prazo previsto de entrega para os objetos das alíneas “a” e “b” começa a ser contado a partir da saída do objeto do Centro Internacional responsável pela sua nacionalização.\nNota 2: o prazo previsto de entrega para os objetos das alíneas “c” e “d” começa a ser contado a partir da confirmação dos pagamentos devidos.\nNota 3: o prazo previsto de entrega para os objetos das alíneas “e” e “f” começa a ser contado a partir da confirmação de recebimento no Brasil.\n2.5 Prazo de Guarda\n2.5.1 Proceder a guarda do objetos conforme o disposto no Anexo 9 deste Capítulo.\n* * * * *', 14),
(5809, 'capitulo', 62, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: prover serviço qualificado para entrega de encomendas no Brasil, com rastreamento completo, velocidade e integridade na troca de informações via Application Programming Interface - API, agilidade nos processos de desembaraço aduaneiro e entrega da última milha.\n1.2 Abrangência: toda a Empresa.\n1.3 Gestor: órgão gestor dos produtos internacionais\n1.4 Fornecedores: órgãos comercial e operacional.\n1.5 Clientes: gestores de relacionamento, gerente de contas especiais, assistente comercial, assistente de comércio exterior, gerente de agência ou outro empregado conforme modelo vigente.\n1.6 Periodicidade: por demanda.\n1.7 Duração: contínua.\n1.8 Vínculo com a Cadeia de Valor: N2 - Prospectar oportunidades de inovação.', 0),
(5810, 'capitulo', 62, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos da Força de Vendas\n2.1.1 Realizar a negociação com o cliente informando as características do serviço Correios Packet, as regras para a contratação e utilização do serviço.\n2.1.2 Auxiliar o cliente na integração dos sistemas.\n2.1.3 Acompanhar o teste-piloto antes do início das operações.\n2.1.4 Confirmar o depósito na conta dos Correios para contrato na modalidade pré-pago antes do envio dos dados eletrônicos e dos objetos ao Brasil monitorando o consumo do saldo e o limite de crédito nos sistemas interagindo com o cliente quando necessário.\n2.1.5 Orientar o cliente no processo de embarque e transmissão dos dados via API.\n2.2 Procedimentos do Órgão Responsável pelas Atividades de Carga Internacional\n2.2.1 Receber a carga no aeroporto designado.\n2.2.2 Encaminhar a carga para o Centro Internacional para tratamento.\n2.3 Procedimentos do Centro Internacional\n2.3.1 Registrar a presença de carga dos objetos no Sistema de Serviços Internacionais de Importação - SSII.\n2.3.2 Realizar a inspeção não invasiva.\n2.3.3 Apresentar os objetos para a Receita Federal do Brasil - RFB e demais órgãos anuentes se for o caso.\n2.3.4 Registrar a Declaração de Importação de Remessa - DIR.\n2.3.5 Expedir os objetos pagos e/ou liberados sem cobrança de impostos para a unidade de tratamento/distribuição.\n2.3.6 Armazenar objetos tributados e em análise.\n2.3.7 Devolver ao Contratante os objetos cuja importação não foi autorizada ou que não tiveram o pagamento dos impostos.\n* * * * *', 1),
(5811, 'capitulo', 63, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: atender o cliente para postagem de serviços internacionais de exportação.\n1.2 Abrangência: toda a Empresa.\n1.3 Gestor: Gerência de Relacionamento Aduaneiro e Exportação -	GREX/DEINT/DINEG.\n1.4 Fornecedores: áreas comercial e operacional, órgãos anuentes do comércio exterior.\n1.5 Clientes: agências próprias ou terceirizadas e unidades operacionais.\n1.6 Periodicidade: por demanda.\n1.7 Duração: contínua.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir portfólio de produtos.', 0),
(5812, 'capitulo', 63, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos do Atendente\n2.1.1 Postagem de Remessa Internacional de Exportação\n2.1.1.1 Recepcionar o cliente.\n2.1.1.2 Esclarecer as dúvidas do cliente quanto à escolha da modalidade de serviço, investigando qual melhor atende à sua necessidade de envio.\n2.1.1.3 Consultar as condições de aceitação do país de destino, principalmente no que se refere à disponibilidade do serviço para o destino solicitado e proibições e restrições do serviço postal para aquele destino.\n2.1.1.4 Aceitar os objetos fechados e adequadamente embalados.\n2.1.1.5 Verificar se o cliente tem conhecimento de restrições/proibições do conteúdo a ser enviado ao país de destino.\n2.1.1.6 Verificar se o cliente realizou pré-postagem no Portal Correios.\n2.1.1.6.1 Inserir o código de pré-postagem no sistema de atendimento, nos casos em que o cliente tenha realizado a pré-postagem no Portal Correios.\n2.1.1.6.2 Conferir os dados da remessa no sistema de atendimento.\n2.1.1.6.3 Corrigir os dados, caso seja necessário.\n2.1.1.6.4 Inserir os dados da remessa no sistema de atendimento, caso o cliente não tenha realizado pré-postagem, orientando sobre a disponibilidade da ferramenta no Portal Correios.\n2.1.1.7 Recomendar que seja inserido endereço do remetente e destinatário no interior da remessa.\n2.1.1.8 Recomendar que sejam incluídos número de telefone e/ou endereço eletrônico do remetente e destinatário no endereçamento do objeto, pois tais ações podem contribuir para agilizar a entrega e para eventuais contatos relativos à prestação do serviço.\n2.1.1.9 Solicitar ao cliente o preenchimento do Formulário CN 22 na postagem do Documento Internacional Standard.\n2.1.1.9.1 Oferecer o adicional de registro.\n2.1.1.10 Solicitar ao cliente as informações necessárias para preenchimento do Formulário de Postagem - AWB no sistema de atendimento, para postagem de todos os demais serviços, conforme regras do Anexo 2 deste Capítulo.\n2.1.1.10.1 Solicitar ao cliente pessoa jurídica a apresentação da nota fiscal relativa aos produtos a serem enviados.\n2.1.1.10.2 Informar que o cumprimento da legislação tributária vigente é de inteira responsabilidade do remetente.\n2.1.1.10.3 Oferecer serviços adicionais.\n2.1.1.10.4 Imprimir o formulário CP72/AWB para postagem de objetos com qualquer finalidade de envio (vias do remetente, destinatário, aduana de origem, aduana de destino).\n2.1.1.10.5 Imprimir a invoice (fatura comercial).\n2.1.1.10.6 Solicitar ao cliente a conferência dos dados impressos no formulário CP72/AWB e na fatura comercial antes de ele assinar em todas as vias.\n2.1.1.10.7 Providenciar correção dos dados cadastrados no sistema de atendimento, se houver alguma divergência.\n2.1.1.10.8 Imprimir novamente os formulários para assinatura do cliente.\n2.1.1.10.9 Coletar a assinatura do cliente em todas as vias do formulário.\n2.1.1.10.10 Apor o carimbo datador no campo específico em todas as vias do formulário CP72/AWB.\n2.1.1.10.11 Inserir as vias do formulário que seguirão com o objeto, fatura e demais documentos porventura fornecidos pelo cliente em envelope plástico adesivo, afixando-o ao objeto de modo a não obstruir o endereçamento aposto na embalagem.\n2.1.1.11 Informar ao cliente o valor a ser pago pela postagem.\n2.1.1.12 Receber do cliente o pagamento referente ao serviço.\n2.1.1.13 Imprimir o comprovante de postagem.\n2.1.1.14 Solicitar assinatura do cliente na via do comprovante de postagem da agência, no caso de postagem a faturar.\n2.1.1.15 Direcionar o objeto postado para expedição.\n2.1.2 Endereçamento de Objetos Destinados ao Exterior\n2.1.2.1 Recusar a postagem nos casos listados no subitem 3.3 do Anexo 2 desse Capítulo.\n2.1.2.2 Verificar se as informações de endereçamento estão dispostas na maior face e no sentido da maior dimensão da embalagem.\n2.1.2.2.1 Solicitar a mudança do local de aposição do endereçamento, se necessário.\n2.1.2.3 Informar ao cliente que as informações de endereçamento são de responsabilidade do remetente.\n2.1.2.4 Verificar se constam as informações suficientes para que a entrega seja realizada, conforme descritas no item 11 no Anexo 2.\n2.1.2.5 Aceitar, ocasionalmente, o modelo internacional de endereçamento, no qual é utilizado o canto superior esquerdo do anverso da embalagem para a identificação do remetente e seu endereço de forma suficientemente afastada do endereçamento do destinatário, a fim de se evitar qualquer engano.\n2.1.3 Postagem de Mercadorias: Vendas, Amostras ou Presentes\n2.1.3.1 Verificar se a remessa contém bens cujo tratamento administrativo indique a necessidade de autorização de órgãos anuentes, se possui valor de mercado acima de USD 1.000 (mil dólares) em moeda nacional e/ou tem destinação comercial.\n2.1.3.2 Anexar, junto ao AWB, certificados, atestados, faturas, notas fiscais e outros documentos que sejam necessários para o desembaraço aduaneiro de sua remessa, seja no momento de saída do Brasil, seja no momento de entrada no país de destino.\n2.1.3.3 Orientar o cliente quanto à necessidade da Declaração Única de Exportação - DU-E, caso a remessa se enquadre em algum dos casos do item 3 do Anexo 2.\n2.1.3.3.1 Verificar se o cliente emitiu a DU-E.\n2.1.3.3.2 Anotar o número no campo específico do AWB.\n2.1.3.3.3 Não assinalar a quadrícula “Sim”, no AWB, caso o remetente já tenha emitido uma DU-E para sua remessa antes de efetuar a postagem.\n2.1.3.3.4 Assinalar a quadrícula “Sim”, caso o remetente não tenha emitido a DU-E e queira que os Correios o façam.\n2.1.3.3.5 Informar ao cliente que a DU-E será emitida na unidade centralizadora dos envios internacionais (Gerência de Atividades de Exportação de Remessas Internacionais - GEEXP) do CEINT/SPM.\n2.1.3.4 Utilizar a folha suplementar do formulário, quando o campo “Informações para Alfândega” não possuir a quantidade de linhas suficientes para a descrição do conteúdo.\n2.1.3.5 Verificar as condições de aceitação (acondicionamento, embalagem, limites de peso e dimensão, proibições, restrições etc.) no fichário dos países ou em qualquer outro meio no qual as informações estejam disponíveis na agência, de acordo com as informações do AWB.\n2.1.3.6 Conferir o preenchimento dos campos.\n2.1.3.7 Solicitar a assinatura do remetente no campo específico em que ele assume a responsabilidade pela fidedignidade das informações prestadas.\n2.1.3.8 Solicitar ao cliente o preenchimento das instruções em caso de não entrega da encomenda.\n2.1.3.9 Informar ao cliente que a devolução ao remetente poderá implicar o pagamento das taxas de devolução incidentes quando da retirada do pacote.\n2.1.3.10 Fixar, na face de maior área plana do objeto, em posição centralizada, o envelope plástico transparente de uso obrigatório, no qual estará contido o formulário de postagem e demais documentos necessários.\n2.1.3.11 Apor carimbo datador no campo apropriado das 4 (quatro) vias do Formulário de Postagem que marcará a data de captação do objeto.\n2.1.4 Adicional de Valor Declarado\n2.1.4.1 Oferecer ao cliente a opção do adicional de Valor Declarado para envio de mercadorias, seja venda, amostra ou presente.\n2.1.4.2 Verificar a informação dos valores-limite aceitos em cada país de destino, disponíveis no sistema de atendimento.\n2.1.4.3 Informar ao cliente quanto à restrição do limite de cada país, com a opção de fracionar a remessa ou assumir o risco pela diferença, caso o limite máximo seja inferior ao valor declarado do item.\n2.1.4.4 Postar obrigatoriamente, mediante declaração de seu valor total, os objetos contendo artigos de ouro, platina, prata, bronze, níquel ou qualquer outro metal de valor, cédula e moeda fora de circulação, selos ou qualquer outra fórmula de franqueamento, papel representativo de valor ao portador, joia, pedra e artigos preciosos.\n2.1.4.5 Limitar o Valor Declarado ao valor máximo aceito para cada país de destino.\n2.1.4.5.1 Não aceitar declaração de valor superior ao valor total dos itens declarados.\n2.1.4.6 Preencher obrigatoriamente o campo correspondente no AWB.\n2.1.4.7 Esclarecer ao cliente que documentos com valor intrínseco serão considerados mercadorias e que, portanto, a remuneração e os procedimentos da postagem serão os mesmos aplicados às mercadorias.\n2.1.4.8 Certificar-se de que o cliente tem consciência das consequências, caso decida não fazer o serviço opcional de declaração de valor.\nNota: as orientações acerca do adicional de Valor Declarado estão disponíveis no Anexo 2 deste Capítulo.\n* * * * *', 1),
(5813, 'capitulo', 64, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: possibilitar a recuperação de valores pagos aos clientes a título de indenização por extravio e roubo de objetos postais nacionais, posteriormente reintegrados ao fluxo postal.', 0),
(5814, 'capitulo', 64, 5813, 2, '1.2', 'Abrangência: toda a empresa.', '', 1),
(5815, 'capitulo', 64, 5813, 2, '1.3', 'Gestor: órgão gestor do subprocesso de suporte a indenização.', '', 2),
(5816, 'capitulo', 64, 5813, 2, '1.4', 'Fornecedores: unidades de atendimento e operacionais.', '', 3),
(5817, 'capitulo', 64, 5813, 2, '1.5', 'Clientes: Superintendências Estaduais - SEs, clientes externos e internos.', '', 4),
(5818, 'capitulo', 64, 5813, 2, '1.6', 'Periodicidade: indeterminada.', '1.7 Duração: indeterminada.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir clientes.', 5),
(5819, 'capitulo', 64, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Objeto Indenizado Reintegrado ao Fluxo Postal e Entregue ao Destinatário\n2.1.1 Procedimentos da Área Executora do Processo de Recuperação de Receita\n2.1.1.1 Providenciar, por meio do Sistema de Recuperação de Receita - SRR, a negociação junto ao detentor do contrato, a fim de recuperar o valor indenizado, quando o objeto indenizado for reintegrado ao fluxo postal e entregue ao destinatário.\nNota: a recuperação de receita dos objetos que se enquadram no Item 2.1.1.1, somente será possível mediante concordância do cliente detentor do contrato, na realização das negociações.\n2.1.1.2 Realizar a recuperação, por meio de débito em fatura, quando houver aceite na negociação com cliente de contrato.\n2.1.1.3 Realizar a recuperação do valor por meio de transferência ou depósito na conta bancária dos Correios, informada na mensagem enviada pelo SRR, quando houver aceite na negociação com cliente de postagem à vista.\n2.1.1.4 Providenciar, junto ao órgão responsável pela execução dos serviços financeiros, a confirmação da devolução do valor indenizado e solicitar a contabilização do valor recuperado na conta “Recuperação de Receita”, quando o cliente à vista concordar com a devolução aos Correios do valor indenizado.\nNota: quando a recuperação de receita, por meio do SRR, tiver sido realizada, a informação poderá ser consultada no Sistema de Apoio ao ERP - SAERP.\n2.2 Objeto Indenizado Reintegrado ao Fluxo Postal e Devolvido ao Remetente\n2.2.1 Procedimentos da Área Executora do Processo de Recuperação de Receita\n2.2.1.1 Realizar, por meio do SRR, a recuperação automática (glosa em fatura) de parte do valor indenizado, referente ao Valor Declarado (se houver) ou o valor da indenização automática, quando o objeto for reintegrado ao fluxo postal e devolvido ao remetente, após o pagamento da indenização.\n2.2.1.2 Enviar, por meio do SRR, comunicação ao remetente ou detentor do contrato, informando que, em função da devolução do objeto, parte do valor já indenizado será recuperado pelos Correios, por meio de glosa em fatura, indicando os dados do objeto e valor a recuperar.\nNota 1: quando o objeto for reintegrado ao fluxo postal e devolvido ao remetente antes da aprovação do pagamento da indenização, o motivo do pagamento será alterado de “Extravio” para “Serviços Postais Não Prestados”.\nNota 2: o valor referente à recuperação de receita dos objetos que se enquadram na situação do item 2.2 será calculado pelo SRR e debitado na fatura do cliente. O valor recuperado não será igual ao mesmo que foi pago, ou seja, será correspondente à indenização automática ou Valor Declarado, se houver.\nNota 3: quando da recuperação de receita dos objetos que se enquadram na situação do Item 2.2, será deixado com o cliente detentor do contrato o valor referente ao preço postal, uma vez que o serviço não foi prestado. Entende-se por valor de serviço não prestado a soma dos valores correspondentes aos preços postais pagos e serviços adicionais, exceto “ad valorem”.\n2.3 Objeto Entregue ao Destinatário sem baixa no SRO com Indenização Paga\n2.3.1 Procedimentos da Área Executora do Processo de Recuperação de Receita\n2.3.1.1 Receber solicitação da área comercial, à partir da comunicação do remetente ou detentor do contrato, para regularizar a informação do Sistema de Rastreamento de Objetos - SRO quando o objeto for entregue ao destinatário e ainda constar no sistema de rastreamento a ausência do evento “Entregue”.\n2.3.1.1.1 Verificar se há eventos finalísticos, no SRO, que indiquem a entrega do objeto ao destinatário, para prosseguimento da recuperação da receita.\n2.3.1.1.2 Verificar no sistema ERP Indenização se houve pagamento de indenização ao remetente ou detentor do contrato.\n2.3.1.1.3 Solicitar o desbloqueio junto ao gestor nacional do SRO, informando o número do registro do objeto postal, a unidade operacional que deverá realizar a baixa e IP do concentrador do SRO da mesma.\n2.3.1.1.4 Confirmar no sistema de rastreamento de objetos se houve o desbloqueio e inserção do evento finalizador “Entregue”.\n2.3.1.1.5 Realizar o processo de negociação de recuperação de receita junto ao remetente ou detentor do contrato, por meio do SRR.\nNota 1: não haverá desbloqueio do SRO, com a finalidade de baixa corretiva para as situações apresentadas no item 2.3, salvo solicitação do remetente ou detentor do contrato à área comercial para regularizar a informação do SRO quando o objeto foi entregue ao destinatário e ainda consta ausência do evento “Entregue”.\nNota 2: não haverá cancelamento de indenização e nem será passível de negociação ou recuperação de receita as situações em que o objeto foi entregue ao destinatário mas, devido a erro operacional, não houve a devida baixa no sistema de rastreamento e em função disso houve resposta de procedência indenizatória por extravio no Fale Conosco, salvo solicitação do remetente ou detentor do contrato.\n* * * * *', 6),
(5820, 'capitulo', 65, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: fornecer subsídios para eventual apuração de irregularidade de conduta funcional por pagamento de indenização por extravio de objeto postal ocorrido internamente em Unidades Operacionais e de Atendimento onde há comprovação de responsabilidade definida.', 0),
(5821, 'capitulo', 65, 5820, 2, '1.2', 'Abrangência: Unidades Operacionais e de Atendimento, Gerências Operacionais e de Atendimento nas Superintendências Estaduais - SEs.', '1.3 Gestor: Departamento de Planejamento e Controle - DEPLA/SUPLO/DIOPE.\n1.4 Fornecedores: Órgão gestor do processo indenizatório.\n1.5 Clientes: Gerências Operacionais e de Atendimento; Unidades Operacionais e de Atendimento; Órgãos de Segurança Empresarial nas Superintendências Estaduais - SEs, Órgão gestor do processo indenizatório e Órgão de Segurança Empresarial no CS.\n1.6 Periodicidade: Diária.\n1.7 Duração: indeterminada.\n1.8 Vínculo na cadeia de valor: N2 - Planejar operação.', 1),
(5822, 'capitulo', 65, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 2),
(5823, 'capitulo', 65, 5822, 2, '2.1', 'Procedimentos da Área Gestora do Processo Indenizatório', '2.1.1 Disponibilizar os dados das indenizações por extravio, por meio de integração do ERP indenizações e Sistema de Recuperação de Receita - SRR com o Sistema de Acompanhamento Processual de Recuperação de Ativos - SAPRA, com exceção das indenizações por extravio onde houve rateio entre Superintendência Estaduais ou entre unidades da mesma SE.\nNota: a disponibilização de dados que trata o item 2.1.1 será realizada após o pagamento da indenização por extravio, conforme status do ERP Indenizações.\n2.2 Procedimentos a Cargo do Gestor das Unidades Definidas\n2.2.1 Acessar diariamente o SAPRA, para preencher as informações solicitadas para cada objeto indenizado por extravio.\nNota 1: o acesso ao SAPRA é realizado por meio de validação de login e senha na rede dos Correios, mediante prévia solicitação ao gestor do sistema.\nNota 2: os perfis Gestor Nacional, Consulta Nacional e Administrador de Acesso são concedidos pelo Gestor Funcional do SAPRA. Os perfis Gestor Regional e Operador são concedidos pelo Administrador de Acessos da SE.\nNota 3: a permissão de acesso para o perfil \"Administrador de Acesso\" será concedido pelo Gestor Funcional do SAPRA mediante solicitação da SE por processo SEI. No âmbito da SE, caberá ao órgão superior hierarquicamente enviar a solicitação ao Administrador de Acesso do SAPRA.\n2.2.2 Realizar a apuração dos objetos indenizados por extravio, relacionados à sua unidade, nos prazos estabelecidos, visando encontrar os elementos necessários à:\na) avaliação das causas que resultaram no extravio do objeto;\nb) identificação de empregado ou terceirizado ou unidade terceirizada que tenha dado causa à indenização do objeto.\nNota: para terceirizados, Mão-de-Obra Temporária - MOT, Execução Indireta de Serviços -EIS e Unidades Terceirizadas os procedimentos pós-indenizatórios de extravio de objetos com responsabilidade definida deverão seguir o previsto em contrato.\n2.2.3 Preencher todas as informações necessárias para atender os procedimentos pós-indenizatórios de apuração de extravios com unidade definida solicitadas pelo SAPRA em até 15 (quinze) dias úteis.\nNota: para os casos onde há possibilidade de definir a autoria do extravio, o formulário no SAPRA deve ser concluído com a inclusão dos dados do autor. Para os casos onde não há possibilidade de definir a autoria do extravio, o gestor deve concluir o preenchimento do formulário com a devida justificativa.\n2.2.4 Providenciar os procedimentos descritos no Manual de Controle Disciplinar - MANCOD quando há definição de autoria pelo extravio do objeto.\n2.3 Procedimentos das Áreas às Quais a Unidade Definida está Subordinada\n2.3.1 Acessar diariamente o SAPRA, para acompanhar se as unidades estão preenchendo as informações solicitadas para cada objeto indenizado por extravio, dentro do prazo estabelecido.\nNota: nas situações em que a unidade é unipessoal, a área hierarquicamente superior deve realizar as apurações do SAPRA.\n2.3.2 Manter a lista dos acessos concedidos sempre higienizada, excluindo perfis que, porventura, não necessitam de acesso.\n2.3.3 Dar andamento nos procedimentos sob sua responsabilidade quanto a apuração de conduta disciplinar descritos no MANCOD quando houver definição de autoria pelo extravio do objeto.\n2.3.4 Abrir processo no Sistema Eletrônico de Informação - SEI para apurar se houve omissão do gestor da unidade no dever de realizar os procedimentos pós-indenizatórios quanto ao extravio do objeto por meio do SAPRA.\nNota 1: os procedimentos sob responsabilidade do gestor da unidade operacional ou de atendimento devem ser adotados em até 15 (quinze) dias úteis a partir da disponibilização no SAPRA.\nNota 2: para os casos onde o prazo acima foi descumpridos, devem ser aplicados os procedimentos previstos no MANCOD.\n2.3.5 Avaliar os resultados gerais dos procedimentos pós-indenização de apuração de extravios com unidade definida e realizar ações nos processos sob sua coordenação visando identificar melhorias e correção de processos, para minimizar a incidência de novos extravios.\n2.4 Procedimentos dos Departamentos da Diretoria de Operações Quanto Ocorrência de Extravios com Responsabilidade Definida\n2.4.1 Consultar no SAPRA as unidades com maior incidência de extravios de objetos com responsabilidade definida e adotar ações para mitigar tais ocorrências nessas unidades.\n2.5 Disposições Gerais\n2.5.1 Adotar os procedimentos previstos na versão anterior desta norma para os objetos extraviados e indenizados com data anterior a 31/08/2021.\n* * * * *', 3),
(5824, 'capitulo', 66, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: disponibilizar orientações para a força de vendas realizar a negociação dos serviços de encomendas.\n1.2 Abrangência: geral.\n1.3 Gestor: Departamento de Gestão de Serviços Nacionais - DEPRO/DINEG.\n1.4 Fornecedores: Central de Infraestrutura/CEINF/DIRAD, Departamento de Desenvolvimento de Negócios e Vendas - DEVEN/DINEG, Departamento de Atendimento - DERAT/DIOPE e seus respectivos órgãos subordinados.\n1.5 Clientes: gestores de relacionamento, gerente de contas especiais, assistente comercial, gerente de agência ou outro empregado conforme modelo vigente.\n1.6 Periodicidade: por demanda.\n1.7 Duração: contínua.\n1.8	Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', 0),
(5825, 'capitulo', 66, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos do Gestor de Relacionamento para a Comercialização dos Serviços de Encomendas de Acordo com as Alçadas de Aprovação do MANCAT 16/1, Anexo 2\n2.1.1 Realizar o diagnóstico comercial para atendimento das necessidades do cliente, considerando:', 1),
(5826, 'capitulo', 66, 5825, 4, 'a', 'perfil da carga do cliente (tipo de objeto a ser transportado, origem e destino, peso e dimensão, se há volume e condições para postar em unidade de captação de grandes quantidades etc.);', '', 2),
(5827, 'capitulo', 66, 5825, 4, 'b', 'valor mínimo: valor de consumo mínimo, em reais, definidos para cada pacote de serviços de encomendas. Seu pagamento pode ser mensal, semestral ou anual, conforme benefício do pacote ou da categoria pela política comercial dos Correios:', 'I - na oferta dos pacotes de serviços de encomendas aos clientes, preferencialmente, devem ser considerados o valor mínimo mensal em consumo de encomendas nacionais.\nII - os outros produtos e serviços poderão contribuir para o atingimento do valor mínimo de encomendas. O valor mínimo em consumo de encomendas será o valor mínimo do contrato quando ele for o maior dentre os serviços contratados;\nIII - as instituições sujeitas ao regime de contratação pela Lei 8.666/93 e 13.303/16 somente terão cobrança de valor mínimo nos casos de previsão contratual.', 3),
(5828, 'capitulo', 66, 5825, 4, 'c', 'potencial de compra do cliente para os serviços de encomendas, inclusive o que é postado na concorrência;', 'Nota: poderá ser considerado o potencial de consumo de encomendas, para os próximos seis meses, mediante seu compromisso em aumentar a participação dos Correios em suas operações.', 4),
(5829, 'capitulo', 66, 5825, 4, 'd', 'fatores críticos de sucesso para a negociação como: mix de marketing, segurança na negociação, celeridade no processo contratual, comprometimento, capilaridade, dentre outros;', '', 5),
(5830, 'capitulo', 66, 5825, 4, 'e', 'demais contrapartidas previstas no Anexo 3 deste Capítulo.', '2.1.2 Propor a oferta do pacote de serviços de encomendas que atenda melhor às necessidades do cliente, mediante o cumprimento das contrapartidas previstas e que proporcione opções para negociações futuras.\n2.1.3 Avaliar, em conjunto com as gerências de suporte a vendas, operacional, financeira e de tecnologia, a necessidade de alocação de recursos para viabilizar os benefícios da categoria e do pacote a ser disponibilizado ao cliente.\n2.1.3.1 Prosseguir com a proposta comercial, após a viabilização dos recursos.\n2.1.4 Elaborar proposta comercial.\n2.1.5  Apresentar ao cliente as vantagens e as características das soluções de encomendas, bem como as contrapartidas e benefícios comuns de acordo com a política comercial e benefícios específicos, conforme MANCAT 16/1, Anexos 3 e 5.\n2.1.6 Realizar negociação com o cliente, apresentando os esclarecimentos necessários e contornando as objeções, se for o caso.\n2.1.7 Entregar a proposta comercial juntamente com as documentações contratuais necessárias (ex: minuta anexo, ficha resumo, ficha técnica, apenso...).\n2.1.8 Realizar a conferência dos documentos, os encaminhando após verificação aos órgãos de suporte para análise e posterior envio à área de cadastro de contratos, depois de concluída a negociação com o cliente.\n2.1.9 Monitorar a utilização dos serviços de encomendas, bem como o cumprimento das contrapartidas e das cláusulas contratuais negociadas, interagindo com o cliente e os órgãos envolvidos na solução dos problemas, esclarecimentos de dúvidas e melhoria do relacionamento.\n2.1.10 Acompanhar o cumprimento das contrapartidas negociadas com o cliente, considerando a vigência inicial de concessão do pacote de serviços de encomendas.\n2.1.11 Enviar, se necessário, a informação às áreas responsáveis para alteração dos registros nos sistemas de cadastro, ajustes nos procedimentos das gerências envolvidas e comunicação ao cliente.\n2.2 Procedimentos do Suporte a Vendas na Execução do Contrato\n2.2.1 Solicitar ao órgão responsável pelo cadastro:', 6),
(5831, 'capitulo', 66, 5825, 4, 'a', 'cadastro do pacote de serviços de encomendas;', '', 7),
(5832, 'capitulo', 66, 5825, 4, 'b', 'geração de cartão de postagem;', '', 8),
(5833, 'capitulo', 66, 5825, 4, 'c', 'cadastramento do valor mínimo mensal;', '', 9),
(5834, 'capitulo', 66, 5825, 4, 'd', 'cadastro dos períodos de isenção, dentre outros aspectos financeiros.', '2.2.1.1 Gerar, somente para os serviços de encomendas nacionais, o cartão de postagem denominado “Cartão de Postagem Destinatário Único” - DU, que permite ao seu portador ou ao portador do Instrumento de Habilitação de Postagem - IHP, a postagem de encomendas destinadas para um único endereço indicado pelo detentor do contrato, sendo vedado o cadastro dos códigos dos serviços Coleta Agendada e Coleta Programada.\nNota: já o cadastro de códigos de API em cartão do tipo DU, é permitido e as regras de utilização e guarda são as mesmas do cartão de postagem convencional.\n2.2.2 Solicitar aos órgãos gestores a concessão dos benefícios negociados com o cliente.\n2.2.3 Informar ao gestor de relacionamento as não conformidades na prestação dos serviços para regularização junto ao cliente e às áreas envolvidas.\n* * * * *', 10),
(5835, 'capitulo', 67, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: atender o cliente para postagem de encomenda nacional.\n1.2 Abrangência: toda a Empresa.\n1.3 Gestor: DEPRO/DINEG.\n1.4 Fornecedores: Superintendências Estaduais de Operações, DEVEN/DINEG.\n1.5 Clientes: Agências Próprias ou Franqueadas e unidades operacionais.\n1.6 Periodicidade: por demanda.\n1.7 Duração: contínua.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', 0),
(5836, 'capitulo', 67, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos do órgão de Atendimento\n2.2 Recepcionar o cliente.\n2.3 Receber a encomenda, perguntando pelo serviço desejado.\n2.3.1 Esclarecer as dúvidas do remetente quanto à escolha do serviço de encomendas.\n2.3.2 Investigar qual melhor serviço atende a necessidade de envio do remetente.\n2.3.3 Solicitar ao cliente a apresentação da nota fiscal.\n2.3.4 Informar que o cumprimento da legislação tributária vigente é de inteira responsabilidade do remetente da encomenda, quando se tratar de envio de bens com ou sem valor mercantil.\n2.3.5 Oferecer ao remetente o formulário de declaração de conteúdo, quando a encomenda estiver desprovida de nota fiscal.\n2.4 Consultar se o franqueamento da postagem será feito à vista ou a faturar.\n2.4.1 Seguir os procedimentos descritos no MANCAT 16/28, quando a encomenda for a faturar com etiqueta gerada a partir do aplicativo SIGEP WEB ou sistemas integrados com o Correios Web Services.\n2.5 Observar todas as condições de aceitação dos objetos constantes no Portal dos Correios, no MANCAT 16/3/2 e demais orientações, referentes ao peso, dimensões, formato, natureza do conteúdo, acondicionamento, embalagem, endereçamento e franqueamento.\n2.6 Posicionar a encomenda na balança.\n2.7 Aferir se está dentro do limite de peso aceito, conforme o serviço escolhido.\n2.8 Verificar os limites de peso e dimensões aceitáveis para cada serviço.\n2.8.1 Recusar a postagem se a encomenda estiver fora dos limites de peso ou dimensões aceitáveis pelos Correios.\n2.9 Oferecer os serviços adicionais.\n2.10 Colar a etiqueta do serviço de encomendas contratado.\n2.11 Anotar o peso aferido pela balança.\n2.12 Recusar a encomenda que após a verificação foi constatado que não resiste ao peso, à forma e à natureza do conteúdo ou às condições de transporte.\n2.12.1 Oferecer embalagem ao cliente se a encomenda não estiver embalada adequadamente ou no caso de o cliente não apresentar o conteúdo embalado.\n2.13 Verificar se a encomenda apresenta, em caracteres latinos e números arábicos, os respectivos endereços do remetente e do destinatário, considerando:', 1),
(5837, 'capitulo', 67, 5836, 4, 'a', 'o nome completo;', '', 2),
(5838, 'capitulo', 67, 5836, 4, 'b', 'o endereço completo (rua, quadra, conjunto, bloco, número da casa ou apartamento, cidade, estado);', '', 3),
(5839, 'capitulo', 67, 5836, 4, 'c', 'Código de Endereçamento Postal - CEP com o maior detalhamento;', '', 4),
(5840, 'capitulo', 67, 5836, 4, 'd', 'a qualidade da impressão das informações de endereçamento e do código de barras.', '2.13.1 Verificar se as informações de endereçamento estão dispostas na maior face e no sentido da maior dimensão da embalagem.\n2.13.2 Solicitar a mudança do local de aposição do endereçamento quando houver dobras, fita adesiva ou plástico sobre as informações.\n2.13.3 Cobrir indicações operacionais de outros operadores de entrega, quando for o caso, utilizando-se de papel, de fita adesiva ou de uma embalagem dos Correios, se houver concordância por parte do cliente.\n2.13.4 Orientar o cliente a informar os números de telefone do remetente e do destinatário, comunicando que esses números poderão ser utilizados pelos Correios exclusivamente para envio de informações eletrônicas e para eventuais contatos relativos à prestação do serviço.\n2.14 Verificar se o serviço pretendido ainda pode ser aceito no horário da postagem.\n2.14.1 Informar ao cliente que o prazo de entrega será acrescido em 1 (um) dia útil, caso tenha passado do horário limite de postagem para encaminhamento no mesmo dia.\n2.15 Realizar a postagem no sistema de atendimento.\n2.15.1 Prosseguir conforme definido no subitem 2.15.4 em diante, se o franqueamento for pago à vista.\n2.15.2 Solicitar a apresentação do cartão de postagem para os casos de postagem a faturar, exceto quando a encomenda for apresentada com Pré-Lista de Postagem - PLP.\n2.15.3 Fazer a leitura do código de barras do cartão de postagem ou digitar o número.\n2.15.4 Fazer a leitura do código de barras de registro da etiqueta do serviço contratado.\nNota: quando se tratar de objeto com etiqueta adicional de Radio Frequency Identification - RFID, proceder a leitura de ambas as etiquetas nele constantes.\n2.15.5 Preencher as informações operacionais necessárias quanto à prestação dos serviços adicionais.\n2.15.6 Registrar o peso aferido e as dimensões.\n2.15.7 Digitar o CEP de destino no sistema.\n2.15.7.1 Informar ao cliente sobre as restrições abaixo, caso retorne a informação de área com restrição de entrega:\n ', 5),
(5841, 'capitulo', 67, 5836, 4, 'a', 'a encomenda seguirá para entrega interna ou;', '', 6),
(5842, 'capitulo', 67, 5836, 4, 'b', 'haverá aumento de prazo em decorrência de medidas de segurança de entrega domiciliar no destino.', '2.15.8 Prosseguir com a postagem somente após o seu consentimento quanto às consequências da entrega em área com restrição.\n2.15.9 Registrar os serviços e os produtos adicionais, se adquiridos.\n2.15.10 Solicitar a apresentação do número do CPF/ CNPJ ou passaporte do remetente e destinatário, esclarecendo que o não fornecimento do número do documento no momento da postagem do objeto, ensejará na sua recusa.\n2.15.11  Oferecer o cadastro gratuito do número de celular do remetente e do destinatário.\n2.16 Concluir os procedimentos de atendimento ao cliente.\n2.16.1 Informar o valor total a ser pago pela postagem.\n2.16.2 Receber do cliente o pagamento referente aos serviços, quando o franqueamento for à vista.\n2.16.3 Imprimir o comprovante de postagem.\n2.16.4 Entregar a via do comprovante ao remetente.\n2.17 Direcionar a encomenda postada para expedição.\n* * * * *', 7),
(5843, 'capitulo', 68, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: instruir os procedimentos de atendimento da logística reversa na agência.\n1.2 Abrangência: toda Empresa.\n1.3 Gestor: Departamento de Gestão de Serviços Nacionais (DEPRO/DINEG).\n1.4 Fornecedores: Superintendências Estaduais - SEs de Operações e Departamento de Desenvolvimento de Negócios e Vendas (DEVEN/DINEG).\n1.5 Clientes: Unidades de Atendimento.\n1.6 Periodicidade: por demanda.\n1.7 Duração: contínua.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', 0),
(5844, 'capitulo', 68, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos da Agência\n2.1.1 Receber o cliente portando a encomenda de retorno e o documento de postagem, que pode ser:', 1),
(5845, 'capitulo', 68, 5844, 4, 'a', 'autorização de postagem eletrônica (e-ticket) impressa ou eletrônica;', '', 2),
(5846, 'capitulo', 68, 5844, 4, 'b', 'aviso de chegada de encomenda, quando houver entrega simultânea.', '2.1.2 Captar encomenda de Logística Reversa com Autorização de Postagem (e-ticket).\n2.1.3 Digitar o número da autorização de postagem no SARA para localizar os dados de postagem.\n2.1.4 Orientar o remetente para dirigir-se à unidade de atendimento designada no aviso de chegada, quando ele apresentar-se com a encomenda de retorno e autorização de postagem em unidade de atendimento distinta daquela em que a encomenda simultânea está em guarda.\n2.1.5 Verificar se o objeto a ser entregue já está em guarda na agência, se houver entrega simultânea de outra encomenda vinculada à autorização de postagem.\n2.1.6 Orientar o remetente para aguardar o aviso de chegada da encomenda, caso haja previsão de entrega simultânea sem que a encomenda já esteja em guarda na agência.\n2.1.7  Verificar a quantidade de encomendas inscritas para envio na autorização de postagem.\n2.1.8  Verificar se há previsão de preenchimento de Check-List para a autorização de postagem.\nNota: o atendente deve estar atento à eventual necessidade de instruções adicionais ao cliente no momento da captação da logística reversa.\n2.1.9  Identificar, dentre os disponíveis, qual Check-list deve ser preenchido, que são:', 3),
(5847, 'capitulo', 68, 5844, 4, 'a', 'Check-List Celular;', '', 4),
(5848, 'capitulo', 68, 5844, 4, 'b', 'Check-List Equipamento Eletrônico;', '', 5),
(5849, 'capitulo', 68, 5844, 4, 'c', 'Check-List Documento;', '', 6),
(5850, 'capitulo', 68, 5844, 4, 'd', 'Check-List Conteúdo.', 'Nota: poderá haver personalização de cada um dos check-list, conforme a necessidade do cliente.\n2.1.10 Conferir se as seguintes informações estão corretas para cada encomenda prevista na autorização de postagem o e-ticket:', 7),
(5851, 'capitulo', 68, 5844, 4, 'a', 'nome e endereço do destinatário;', '', 8),
(5852, 'capitulo', 68, 5844, 4, 'b', 'número da autorização de postagem;', '', 9),
(5853, 'capitulo', 68, 5844, 4, 'c', 'serviço de encomendas.', '2.1.11 Verificar se o e-ticket autoriza o fornecimento de embalagem, caso o cliente apresente o conteúdo da encomenda a descoberto.\n2.1.12 Fornecer embalagem ao cliente, caso a autorização de postagem indique seu fornecimento e o atendimento ocorrer em Agência Própria (AC).\n2.1.13 Orientar o cliente a se dirigir a uma AC, caso a autorização de postagem indique o fornecimento de embalagem e o atendimento tenha sido iniciador em uma Agência Franqueada - AGF.\n2.1.14  Realizar a postagem na própria AGF, caso o cliente concorde mediante pagamento da embalagem.\n2.1.15 Imprimir o rótulo de endereçamento da encomenda de Logística Reversa.\nNota: caso a embalagem apresentada pelo cliente tenha qualquer endereço ou etiqueta com código de barra rastreável pelo SRO tais informações deverão ser inutilizadas.\n2.1.16 Averiguar se a impressão corresponde ao rótulo que deve ser colado à encomenda, evitando indenizações por troca de rótulo na agência, principalmente nos casos em que a impressora é compartilhada.\n2.1.17 Colar o rótulo de endereçamento na encomenda de logística reversa.\n2.1.18 Colar a etiqueta de rastreamento do objeto conforme o serviço.\n2.1.19 Realizar a entrega simultânea de encomenda, se houver, vinculada à autorização de postagem, após a postagem da encomenda de retorno, proceder a entrega interna da outra encomenda, conforme procedimentos definidos no Manual de Distribuição e Coleta - MANDIS 5/3.\n2.1.20 Proceder a postagem conforme número de autorização de postagem que constará do aviso de chegada, quando o remetente apresentar o aviso de chegada de encomenda simultânea ao envio de logística reversa.\n2.1.21 Finalizar o atendimento.\nNota: após a finalização do atendimento, do serviço Logística Reversa, não é permitido o estorno da postagem.\n* * * * *', 10),
(5854, 'capitulo', 69, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5855, 'capitulo', 69, 5854, 2, '1.1', 'Objetivo: instruir os procedimentos de solicitação de coleta.', '', 1),
(5856, 'capitulo', 69, 5854, 2, '1.2', 'Abrangência: toda a Empresa.', '', 2),
(5857, 'capitulo', 69, 5854, 2, '1.3', 'Gestor: DEENC/SUCOM/DINEG.', '', 3),
(5858, 'capitulo', 69, 5854, 2, '1.4', 'Fornecedores: Superintendências Estaduais - SEs, DEVEN/SUCOM/DINEG.', '', 4),
(5859, 'capitulo', 69, 5854, 2, '1.5', 'Clientes: unidades operacionais.', '', 5),
(5860, 'capitulo', 69, 5854, 2, '1.6', 'Periodicidade: por demanda.', '', 6),
(5861, 'capitulo', 69, 5854, 2, '1.7', 'Duração: contínua.', '', 7),
(5862, 'capitulo', 69, 5854, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - gerir Produtos e Serviços.', '', 8),
(5863, 'capitulo', 69, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(5864, 'capitulo', 69, NULL, 3, '2.1.1', 'Procedimentos do Gestor Comercial', '2.1.1.1 Avaliar a solicitação de coleta apresentada pelo cliente.\n2.1.1.2 Enviar, por e-mail, solicitação ao gestor da unidade de captação.\n2.1.1.3 Informar ao cliente a viabilidade ou inviabilidade da coleta, conforme análise do gestor da unidade de captação e do gestor de coleta.\n2.1.1.4 Apresentar proposta alternativa de coleta, conforme análise do gestor de captação e do gestor de coleta.\n2.1.1.5 Confirmar junto ao cliente a aprovação de horários alternativos sugeridos pelo gestor de unidade de captação, caso tenha recebido deste uma proposta de frequência e horários alternativos.\n2.1.1.6 Informar ao gestor de unidade de captação e de unidade de coleta a aprovação ou recusa do cliente.\n2.1.1.7 Cadastrar demanda de coleta.', 10),
(5865, 'capitulo', 69, NULL, 3, '2.1.2', 'Procedimentos do Gestor de Unidade de Captação', '2.1.2.1 Avaliar viabilidade de captação, para a coleta, conforme os dados enviados por e-mail pelo gestor comercial, em até 4 (quatro) dias úteis, nos casos de programações com frequências regulares; e em até 1 (um) dia útil, para as coletas em dias pontuais.\n2.1.2.2 Solicitar avaliação de disponibilidade de veículo, mão de obra e equipamentos para o gestor de unidade de coleta (CEE, CTO ou GERAE), caso tenha capacidade disponível para captação.\n2.1.2.3 Enviar e-mail ao gestor comercial com as justificativas do indeferimento, cabendo a ele informar ao cliente o resultado, caso não tenha capacidade de captação.\n2.1.2.4 Informar deferimento ao gestor comercial via e-mail, caso o gestor de unidade de coleta aprove a proposta desejada pelo cliente.\n2.1.2.5 Verificar nova viabilidade de captação, caso o gestor de unidade de coleta apresente frequência ou horários alternativos à proposta desejada pelo cliente.\n2.1.2.6 Enviar ao gestor comercial a proposta alternativa para apresentação ao cliente de acordo com as informações repassadas pelo gestor de unidade de coleta.\n2.1.2.7 Indeferir solicitação caso não tenha viabilidade de captação.\n2.1.2.8 Informar o resultado da análise de viabilidade de captação, via e-mail, ao gestor comercial.\n2.1.2.9 Informar ao gestor comercial o indeferimento caso o gestor de unidade de coleta não tenha capacidade de coleta.', 11);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(5866, 'capitulo', 69, NULL, 3, '2.1.3', 'Procedimentos do Gestor de Unidade de Coleta', '2.1.3.1 Avaliar viabilidade de coleta quanto à disponibilidade de mão de obra, veículos e equipamentos necessários para atendimento à demanda.\n2.1.3.2 Aprovar viabilidade de coleta, caso tenha disponibilidade dos recursos.\n2.1.3.3 Informar viabilidade de coleta ao gestor da unidade de captação.\n2.1.3.4 Sugerir ao gestor da unidade de captação, horários ou volume alternativos de coleta caso tenha disponibilidade de coleta diferente daquela desejada pelo cliente.\n* * * * *', 12),
(5867, 'capitulo', 70, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5868, 'capitulo', 70, 5867, 2, '1.1', 'Objetivo: permitir ao remetente interagir com os Correios para suspender a entrega de um objeto postado ao destinatário.', '', 1),
(5869, 'capitulo', 70, 5867, 2, '1.2', 'Abrangência: nacional.', '', 2),
(5870, 'capitulo', 70, 5867, 2, '1.3', 'Gestor: Departamento de Gestão de Produtos Nacionais - DEPRO/SUPRO.', '', 3),
(5871, 'capitulo', 70, 5867, 2, '1.4', 'Fornecedores: órgãos do Correios Sede e unidades das superintendências regionais.', '', 4),
(5872, 'capitulo', 70, 5867, 2, '1.5', 'Clientes: unidades operacionais e de atendimento que utilizam o Sistema de Rastreamento de Objetos Operacional - SRO.', '', 5),
