(5973, 'capitulo', 80, 5969, 2, '1.4', 'Fornecedores: DEPRO, DEINT e DEDIG/DINEG, DELOG/DIOPE e DEGEC/DIRAD.', '', 4),
(5974, 'capitulo', 80, 5969, 2, '1.5', 'Clientes: unidades operacionais, atendimento e comercial.', '', 5),
(5975, 'capitulo', 80, 5969, 2, '1.6', 'Periodicidade: por demanda.', '', 6),
(5976, 'capitulo', 80, 5969, 2, '1.7', 'Duração: período indeterminado.', '', 7),
(5977, 'capitulo', 80, 5969, 2, '1.8', 'Vínculo com a Cadeia de Valor: Gerir produtos e serviços', '', 8),
(5978, 'capitulo', 80, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(5979, 'capitulo', 80, 5978, 2, '2.1', 'Adotar os procedimentos abaixo, conforme o caso:', '', 10),
(5980, 'capitulo', 80, 5979, 4, 'a', 'efetuar baixa nos casos de etiquetas danificadas, extraviadas, rasgadas, rasuradas, com vigência vencida ou que tenham sofrido algum dano físico, por utilização indevida (troca ou erro), onde haja a necessidade de ajuste no estoque;', '', 11),
(5981, 'capitulo', 80, 5979, 4, 'b', 'arquivar no balancete da unidade;', '', 12),
(5982, 'capitulo', 80, 5979, 4, 'c', 'acessar a opção de cancelamento das etiquetas no sistema SARA e regularizar o estoque;', '', 13),
(5983, 'capitulo', 80, 5979, 4, 'd', 'emitir termo de destruição e termo de constatação, assinado pelo gerente da agência e testemunhas;', '', 14),
(5984, 'capitulo', 80, 5979, 4, 'e', 'registrar a baixa/regularização do estoque da unidade por meio da Guia de Remessa de Produtos - GRP no Sistema de Automação da Rede de Atendimento - SARA;', '', 15),
(5985, 'capitulo', 80, 5979, 4, 'f', 'destruir as etiquetas vencidas ou sem condição de uso na própria Unidade, adotando os procedimentos constantes do Manual de Suprimento - MANSUP 3/5.', 'Nota 1: não é necessário encaminhar o balancete para a área financeira, devendo este ficar arquivado na Unidade.\nNota 2: os procedimentos acima devem ser adotados pelos órgãos locais de negócios, conforme o caso.\n* * * * *', 16),
(5986, 'capitulo', 81, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(5987, 'capitulo', 81, 5986, 2, '1.1', 'Objetivo: oferecer o serviço exclusivo de Malote, para atender às necessidades logísticas de pessoas jurídicas de direito público ou privado, a fim de enviar e receber objetos de suas agências, filiais ou representantes, conforme MANCAT 18/1/3 - 2.4.1. Executar os trâmites para contratação e cadastro, a fim de que seja operacionalizada a coleta, o transporte e a entrega de malote.', '', 1),
(5988, 'capitulo', 81, 5986, 2, '1.2', 'Abrangência: nacional.', '', 2),
(5989, 'capitulo', 81, 5986, 2, '1.3', 'Gestor: Departamento de Gestão de Serviços Nacionais - DEPRO/DINEG.', '', 3),
(5990, 'capitulo', 81, 5986, 2, '1.4', 'Fornecedores: órgão comercial, órgão de cadastro, órgão designada para suprimento de cartões e malotes, órgão operacional e órgão de faturamento.', '', 4),
(5991, 'capitulo', 81, 5986, 2, '1.5', 'Clientes: pessoas jurídicas, clientes do serviço.', '', 5),
(5992, 'capitulo', 81, 5986, 2, '1.6', 'Periodicidade: por demanda.', '', 6),
(5993, 'capitulo', 81, 5986, 2, '1.7', 'Duração: prazo indeterminado.', '', 7),
(5994, 'capitulo', 81, 5986, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir produtos e serviços.', '', 8),
(5995, 'capitulo', 81, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(5996, 'capitulo', 81, 5995, 2, '2.1', 'Procedimentos do Órgão Comercial na Superintendência Estadual - SE', '', 10),
(5997, 'capitulo', 81, 5996, 3, '2.1.1', 'Informar ao cliente as características do serviço.', '', 11),
(5998, 'capitulo', 81, 5996, 3, '2.1.2', 'Apresentar o cálculo simulado, a partir do endereço e frequência de coleta informados.', '', 12),
(5999, 'capitulo', 81, 5996, 3, '2.1.3', 'Proceder com trâmites comerciais de contratação e encaminhamento ao cadastro, conforme MANCAT 27/10/3.', 'Nota: As características do serviço de Malote constam no Anexo 2 deste Capítulo.', 13),
(6000, 'capitulo', 81, 5995, 2, '2.2', 'Procedimento do Órgão de Cadastro', '', 14),
(6001, 'capitulo', 81, 6000, 3, '2.2.1', 'Proceder com o cadastro do contrato e/ou percurso, referente às solicitações oriundas do Malote WEB ou registradas via SEI, conforme disposto no MANFAC 6/3.', '', 15),
(6002, 'capitulo', 81, 5995, 2, '2.3', 'Procedimentos do Órgão Responsável pelo Suprimento de Cartão Operacional e Malote ao Cliente na SE', '', 16),
(6003, 'capitulo', 81, 6002, 3, '2.3.1', 'Gerenciar as demandas de fornecimento.', '', 17),
(6004, 'capitulo', 81, 6002, 3, '2.3.2', 'Providenciar o fornecimento dos respectivos cartões e malotes até à data de vigência.', '', 18),
(6005, 'capitulo', 81, 6002, 3, '2.3.3', 'Baixar malotes devolvidos pelos clientes.', '', 19),
(6006, 'capitulo', 81, 5995, 2, '2.4', 'Procedimentos do Órgão Operacional', '', 20),
(6007, 'capitulo', 81, 6006, 3, '2.4.1', 'Executar todos os procedimentos internos e externos relacionados ao serviço de Malote, conforme previsto nos manuais MANENC 6/11 e MANDIS 2/4, 3/2 e 5/3, assegurando a coleta, tratamento, transporte e entrega dos malotes, bem como a qualidade das informações disponibilizadas para consulta e rastreamento.', '', 21),
(6008, 'capitulo', 81, 6006, 3, '2.4.2', 'Recolher malotes devolvidos pelos clientes em razão de cancelamento ou troca, mediante apresentação do documento de devolução contendo contrato, percurso e respectivo número do malote.', '', 22),
(6009, 'capitulo', 81, 6006, 3, '2.4.3', 'Comunicar a devolução ao órgão responsável pelo fornecimento de cartões e malotes na SE, para registro e baixa no sistema corporativo.', '', 23),
(6010, 'capitulo', 81, 6006, 3, '2.4.4', 'Classificar os malotes devolvidos, identificando aqueles em condições de reaproveitamento e os sem condições de uso.', '', 24),
(6011, 'capitulo', 81, 6006, 3, '2.4.5', 'Encaminhar os malotes reaproveitáveis à equipe responsável pelo fornecimento de cartões e malotes na SE, garantindo sua reintegração ao estoque operacional.', '', 25),
(6012, 'capitulo', 81, 6006, 3, '2.4.6', 'Destinar os malotes sem condições de uso de acordo com as diretrizes do Plano de Gestão de Resíduos Sólidos - PGRS, observando as regras previstas no MANSUP 4/5.', '', 26),
(6013, 'capitulo', 81, 5995, 2, '2.5', 'Procedimento do Órgão de faturamento.', '2.5.1.1 Seguir os procedimentos estabelecidos para reunir os registros de postagens e para emitir as faturas, de acordo com as regras de negócio e tarifárias estabelecidas no contrato, conforme disposto no MANFAC 3/1.\n* * * * *', 27),
(6014, 'capitulo', 82, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(6015, 'capitulo', 82, 6014, 2, '1.1', 'Objetivo: estabelecer os procedimentos para a celebração de instrumentos jurídicos para a instalação de Agências de Correios Comunitária - AGC.', '', 1),
(6016, 'capitulo', 82, 6014, 2, '1.2', 'Abrangência: toda a empresa.', '', 2),
(6017, 'capitulo', 82, 6014, 2, '1.3', 'Gestor: órgão de gestão corporativa dos instrumentos jurídicos dos canais de atendimento terceirizados.', '', 3),
(6018, 'capitulo', 82, 6014, 2, '1.4', 'Fornecedor: órgão de gestão operacional dos canais de atendimento; órgão regional de gestão dos canais de atendimento terceirizados; ente público ou privado operador do canal de atendimento AGC.', '', 4),
(6019, 'capitulo', 82, 6014, 2, '1.5', 'Cliente: órgão de gestão operacional dos canais de atendimento; órgão regional de gestão dos canais de atendimento terceirizados; ente público ou privado operador do canal de atendimento AGC.', '', 5),
(6020, 'capitulo', 82, 6014, 2, '1.6', 'Periodicidade: por demanda.', '', 6),
(6021, 'capitulo', 82, 6014, 2, '1.7', 'Duração: variável.', '', 7),
(6022, 'capitulo', 82, 6014, 2, '1.8', 'Vinculação à cadeia de valor: N2 - Gerir canais.', '', 8),
(6023, 'capitulo', 82, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(6024, 'capitulo', 82, 6023, 2, '2.1', 'Procedimentos do Órgão de Gestão Corporativa dos Canais de Atendimento Terceirizados', '', 10),
(6025, 'capitulo', 82, 6024, 3, '2.1.1', 'Elaborar minutas-padrão e documentos auxiliares pré-chancelados pela área jurídica para a celebração de parcerias com os entes municipais.', '', 11),
(6026, 'capitulo', 82, 6024, 3, '2.1.2', 'Manter atualizados os documentos, manuais, orientações e outros repositórios de informações relacionadas à gestão corporativa dos canais de atendimento terceirizados.', '', 12),
(6027, 'capitulo', 82, 6024, 3, '2.1.3', 'Instaurar processo administrativo no Sistema Eletrônico de Informações - SEI, para envio das minutas de instrumentos jurídicos e demais documentos auxiliares padronizados.', '', 13),
(6028, 'capitulo', 82, 6024, 3, '2.1.4', 'Encaminhar ao órgão de gestão operacional dos canais de atendimento e Superintendências Estaduais - SE, as minutas de instrumento jurídico pré-chanceladas e demais documentos auxiliares padronizados, devidamente acompanhados das orientações necessárias à celebração da parceria.', '', 14),
(6029, 'capitulo', 82, 6024, 3, '2.1.5', 'Acompanhar a execução das ações dos órgãos regionais de gestão dos canais de atendimento destinados à celebração de parcerias no âmbito das SE, quando for o caso.', '', 15),
(6030, 'capitulo', 82, 6024, 3, '2.1.6', 'Fornecer subsídios, prestar auxílio e fornecer informações complementares aos órgãos de gestão operacional e regional dos canais de atendimento terceirizados e às SE, quando necessário.', '', 16),
(6031, 'capitulo', 82, 6023, 2, '2.2', 'Procedimentos do Órgão Corporativo de Gestão Operacional dos Canais de Atendimento', '', 17),
(6032, 'capitulo', 82, 6031, 3, '2.2.1', 'Acompanhar a existência de municípios sob gestão das SE que estejam desprovidos de atendimento postal de qualquer natureza e integrem a meta de universalização do atendimento.', '', 18),
(6033, 'capitulo', 82, 6031, 3, '2.2.2', 'Fornecer subsídios e prestar apoio às SE com a finalidade de viabilizar a celebração de parcerias para instalação de AGC, quando necessário.', '', 19),
(6034, 'capitulo', 82, 6031, 3, '2.2.3', 'Recepcionar o processo administrativo contendo as minutas dos instrumentos jurídicos pré-chancelados e demais documentos auxiliares padronizados enviados pelo órgão de gestão corporativa dos canais de atendimento terceirizados.', '', 20),
(6035, 'capitulo', 82, 6031, 3, '2.2.4', 'Elaborar ou atualizar documentos, manuais, orientações e outros repositórios de informações relacionadas à gestão operacional dos canais de atendimento terceirizados.', '', 21),
(6036, 'capitulo', 82, 6031, 3, '2.2.5', 'Encaminhar o processo administrativo contendo as minutas de instrumento jurídico pré-chanceladas e demais documentos auxiliares padronizados ao órgão de gestão regional dos canais de atendimento terceirizados, devidamente acompanhados das orientações necessárias à celebração de parcerias para a instalação de AGC.', '', 22),
(6037, 'capitulo', 82, 6031, 3, '2.2.6', 'Monitorar a adoção dos procedimentos necessários à celebração de parcerias para a instalação de AGC pelos órgãos regionais de gestão dos canais de atendimento destinados, quando necessário.', '', 23),
(6038, 'capitulo', 82, 6031, 3, '2.2.7', 'Recepcionar as solicitações de cadastro ou atualização de informações das AGC enviadas pelos órgãos regionais de gestão dos canais de atendimento terceirizados.', '', 24),
(6039, 'capitulo', 82, 6031, 3, '2.2.8', 'Prestar auxílio e fornecer informações complementares aos órgãos regionais de gestão dos canais de atendimento terceirizados, quando necessário.', '', 25),
(6040, 'capitulo', 82, 6031, 3, '2.2.9', 'Propor atualizações relacionadas aos instrumentos jurídicos ao órgão de gestão corporativa dos canais de atendimento terceirizados.', '', 26),
(6041, 'capitulo', 82, 6031, 3, '2.2.10', 'Demandar às áreas competentes o esclarecimento das dúvidas apresentadas pelo ente municipal ou pelos órgãos regionais de gestão dos canais de atendimento terceirizados, quando necessário.', '', 27),
(6042, 'capitulo', 82, 6023, 2, '2.3', 'Procedimentos do Órgão Regional de Gestão dos Canais de Atendimento Terceirizados', '', 28),
(6043, 'capitulo', 82, 6042, 3, '2.3.1', 'Verificar a existência de municípios sob gestão da SE que estejam desprovidos de atendimento postal de qualquer natureza e que estejam inseridos na meta de universalização do atendimento dos serviços postais, conforme portaria específica editada pelo Ministério Supervisor.', '', 29),
(6044, 'capitulo', 82, 6042, 3, '2.3.2', 'Manter contato com os entes municipais das localidades que se encontram na situação descrita no subitem 2.3.1, com o objetivo de negociar a celebração de parceria para a instalação de AGC.', '', 30),
(6045, 'capitulo', 82, 6042, 3, '2.3.3', 'Instaurar processo administrativo no Sistema Eletrônico de Informações - SEI, destinado à formalização da parceria e gestão da unidade de atendimento.', '', 31),
(6046, 'capitulo', 82, 6042, 3, '2.3.4', 'Formalizar por meio de carta/ofício a intenção dos Correios na celebração da parceria para a instalação de AGC por meio da assinatura de Acordo de Cooperação Técnica - ACT.', '', 32),
(6047, 'capitulo', 82, 6042, 3, '2.3.5', 'Recepcionar a resposta do ente municipal, com indicativo de concordância ou discordância das condições apresentadas.', '', 33),
(6048, 'capitulo', 82, 6042, 3, '2.3.6', 'Verificar a possibilidade de celebração de Termo de Convênio - TC, caso haja discordância com a formalização da parceria por meio da celebração de ACT e o município integre a meta de universalização do atendimento, exclusivamente quando os custos para a realização do atendimento por meios próprios forem superiores ao da celebração da parceria.', 'Nota: para fins de análise de viabilidade, devem ser considerados todos os custos inerentes ao atendimento e prestação dos serviços postais por meios próprios, tais como: custos de pessoal, transporte, locação de espaço físico, aquisição de equipamentos e mobiliários, etc.', 34),
(6049, 'capitulo', 82, 6042, 3, '2.3.7', 'Verificar se o ente municipal apresentou proposta de condições especiais para a celebração da parceria que não estejam previstas no instrumento jurídico pré-chancelado, observando, se existirem, os seguintes procedimentos:', '', 35),
(6050, 'capitulo', 82, 6049, 4, 'a', 'elaborar relatório técnico para demonstrar se há viabilidade para a aceitação das condições pleiteadas pela prefeitura, considerando, no mínimo, os seguintes aspectos:', 'I - impactos financeiros decorrentes da implementação, inclusive os custos decorrentes da criação de linhas de transporte e deslocamento de efetivo próprio dos Correios;\nII - cumprimento da meta de universalização do atendimento;\nIII - existência de impedimento nos normativos vigentes para a aceitação das condições pelos Correios;\nIV - existência de alternativas de atendimento para manter a prestação dos serviços postais na localidade por meios próprios;\nV - existência de vantajosidade econômica para a celebração da parceria, mediante a comparação de custos entre a aceitação das condições propostas e a realização da atividade por meios próprios.', 36),
(6051, 'capitulo', 82, 6049, 4, 'b', 'submeter o referido relatório para aprovação da SE;', '', 37),
(6052, 'capitulo', 82, 6049, 4, 'c', 'elaborar cláusulas customizadas, observando as disposições constantes no Manual de Licitação e Gestão - MANLIG 5/6 e no Manual de Licitação e Contratação - MANLIC 5/13, assim como, na legislação vigente, no que couber, caso haja aprovação da SE para a continuidade do processo;', '', 38),
(6053, 'capitulo', 82, 6049, 4, 'd', 'emitir relatório técnico com a fundamentação para a revisão do texto das cláusulas que serão incluídas, excluídas, renumeradas ou modificadas, assim como do conteúdo dos anexos do instrumento jurídico a ser avaliado;', '', 39),
(6054, 'capitulo', 82, 6049, 4, 'e', 'submeter instrumento jurídico customizado para deliberação da SE;', '', 40),
(6055, 'capitulo', 82, 6049, 4, 'f', 'recepcionar aprovação ou reprovação da minuta de instrumento jurídico customizado;', '', 41),
(6056, 'capitulo', 82, 6049, 4, 'g', 'providenciar a chancela do instrumento jurídico customizado perante a Assessoria Jurídica Estadual - ASJUR, nos termos do Manual Jurídico - MANJUR 1/2, caso a proposta de customização seja aprovada pela SE;', '', 42),
(6057, 'capitulo', 82, 6049, 4, 'h', 'recepcionar a manifestação enviada pela área jurídica após a avaliação da minuta de instrumento jurídico customizada;', '', 43),
(6058, 'capitulo', 82, 6049, 4, 'i', 'providenciar ajustes nas cláusulas do instrumento jurídico customizado em conformidade com as recomendações e ressalvas apresentadas pela área jurídica.', 'Nota: a área jurídica não compõe, obrigatoriamente, o procedimento previsto neste Capítulo, devendo ser acionada somente para garantir a segurança da análise por parte do órgão regional de gestão dos canais de atendimento terceirizados ou pré-chancelar os instrumentos jurídicos customizados, quando necessário, em estrita observância às disposições contidas no MANJUR 1/2.', 44),
(6059, 'capitulo', 82, 6042, 3, '2.3.8', 'Inserir minuta de instrumento jurídico no processo administrativo destinado à celebração da parceria.', '', 45),
(6060, 'capitulo', 82, 6042, 3, '2.3.9', 'Preencher informações relacionadas à unidade de atendimento foco da parceria nos campos correspondentes do instrumento jurídico e anexos contratuais.', '', 46),
(6061, 'capitulo', 82, 6042, 3, '2.3.10', 'Assinar eletronicamente o instrumento jurídico correspondente.', '', 47),
(6062, 'capitulo', 82, 6042, 3, '2.3.11', 'Submeter o instrumento jurídico correspondente para assinatura da autoridade administrativa competente no âmbito da SE.', '', 48),
(6063, 'capitulo', 82, 6042, 3, '2.3.12', 'Encaminhar correspondência ao ente municipal devidamente acompanhado da minuta de instrumento jurídico e das orientações necessárias à assinatura dos documentos por meio da disponibilização de acesso externo do SEI.', '', 49),
(6064, 'capitulo', 82, 6042, 3, '2.3.13', 'Orientar a pessoa jurídica contratada/conveniada a instruir o processo administrativo eletrônico destinado à celebração da parceria com os documentos descritos no instrumento contratual, bem como:', '', 50),
(6065, 'capitulo', 82, 6064, 4, 'a', 'alvará de funcionamento do prédio, edifício ou espaço em que funcionará a unidade de atendimento;', '', 51),
(6066, 'capitulo', 82, 6064, 4, 'b', 'comprovante de vínculo jurídico da pessoa jurídica com o imóvel em que funcionará a unidade, conforme orientações contidas no Anexo 2 deste capítulo;', '', 52),
(6067, 'capitulo', 82, 6064, 4, 'c', 'certidões comprobatórias de regularidade tributária, trabalhista e fiscal.', '', 53),
(6068, 'capitulo', 82, 6042, 3, '2.3.14', 'Monitorar a assinatura do instrumento contratual e demais documentos auxiliares pelo ente municipal dentro do prazo pré-estabelecido, solicitando formalmente sua assinatura em caso de atraso.', '', 54),
(6069, 'capitulo', 82, 6042, 3, '2.3.15', 'Prestar subsídios e fornecer orientações ao ente municipal, quando necessário.', '', 55),
(6070, 'capitulo', 82, 6042, 3, '2.3.16', 'Demandar às áreas competentes o esclarecimento das dúvidas apresentadas pelo ente municipal, quando necessário.', '', 56);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(6071, 'capitulo', 82, 6042, 3, '2.3.17', 'Adotar as providências para efetivar as atualizações cadastrais requeridas nos sistemas corporativos, quando cabível.', '', 57),
(6072, 'capitulo', 82, 6042, 3, '2.3.18', 'Preencher o formulário específico para viabilizar o cadastro da unidade de atendimento nos sistemas dos Correios, conforme orientações encaminhadas pelo órgão corporativo de cadastro.', '2.3.18.1 Encaminhar o processo administrativo ao órgão corporativo de cadastro e aguardar conclusão das providências.', 58),
(6073, 'capitulo', 82, 6023, 2, '2.4', 'Procedimentos do Órgão Público Contratado/Conveniado', '', 59),
(6074, 'capitulo', 82, 6073, 3, '2.4.1', 'Receber o processo administrativo contendo a formalização do contato efetuado pelos Correios, com o objetivo de iniciar o processo de estabelecimento da parceria.', '', 60),
(6075, 'capitulo', 82, 6073, 3, '2.4.2', 'Observar as regras previstas nos instrumentos jurídicos, em especial aquelas destinadas à assinatura do documentos perante os Correios.', '', 61),
(6076, 'capitulo', 82, 6073, 3, '2.4.3', 'Encaminhar resposta formal aos Correios no prazo estabelecido na correspondência de orientação, considerando o primeiro dia útil após o seu recebimento como termo inicial do prazo de resposta.', '', 62),
(6077, 'capitulo', 82, 6073, 3, '2.4.4', 'Solicitar esclarecimentos, quando houver dúvidas sobre o conteúdo das cláusulas dos instrumentos jurídicos.', '', 63),
(6078, 'capitulo', 82, 6073, 3, '2.4.5', 'Instruir o processo administrativo eletrônico destinado à celebração da parceria com os documentos descritos no instrumento contratual, bem como:', '', 64),
(6079, 'capitulo', 82, 6078, 4, 'a', 'alvará de funcionamento do prédio, edifício ou espaço em que funcionará a unidade de atendimento;', '', 65),
(6080, 'capitulo', 82, 6078, 4, 'b', 'comprovante de vínculo jurídico da pessoa jurídica com o imóvel em que funcionará a unidade, conforme orientações contidas no Anexo 2 deste capítulo;', '', 66),
(6081, 'capitulo', 82, 6078, 4, 'c', 'certidões comprobatórias de regularidade tributária, trabalhista e fiscal.', '', 67),
(6082, 'capitulo', 82, 6073, 3, '2.4.6', 'Assinar eletronicamente o instrumento jurídico em caso de aceite da parceria com os Correios.', '', 68),
(6083, 'capitulo', 82, 6073, 3, '2.4.7', 'Assinar fisicamente o instrumento jurídico, quando não for possível a sua assinatura eletrônica.', '', 69),
(6084, 'capitulo', 82, 6073, 3, '2.4.8', 'Incluir os documentos necessários diretamente no processo administrativo destinado à celebração da parceria, conforme orientação dos Correios.', '', 70),
(6085, 'capitulo', 82, 6023, 2, '2.5', 'Procedimentos do Órgão Corporativo de Cadastro', '', 71),
(6086, 'capitulo', 82, 6085, 3, '2.5.1', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados o formulário com os dados para a realização do cadastro do canal de atendimento terceirizado, denominado AGC, nos sistemas corporativos dos Correios.', '', 72),
(6087, 'capitulo', 82, 6085, 3, '2.5.2', 'Providenciar a alteração do cadastro em até 5 (cinco) dias úteis, contados do recebimento da solicitação.', '* * * * *', 73),
