(6089, 'capitulo', 83, 6088, 2, '1.1', 'Objetivo: estabelecer os procedimentos para a implantação de Agência de Correios Comunitária (AGC).', '', 1),
(6090, 'capitulo', 83, 6088, 2, '1.2', 'Abrangência: toda a empresa.', '', 2),
(6091, 'capitulo', 83, 6088, 2, '1.3', 'Gestor: órgão de gestão corporativa dos instrumentos jurídicos dos canais de atendimento terceirizados.', '', 3),
(6092, 'capitulo', 83, 6088, 2, '1.4', 'Fornecedor: órgão de gestão operacional dos canais de atendimento; órgão regional de gestão dos canais de atendimento terceirizados; órgão de gestão da tecnologia da informação; órgão de gestão da infraestrutura; órgão de gestão do transporte; órgão de gestão do tratamento; pessoa jurídica contratada/conveniada.', '', 4),
(6093, 'capitulo', 83, 6088, 2, '1.5', 'Cliente: pessoa jurídica contratada/conveniada.', '', 5),
(6094, 'capitulo', 83, 6088, 2, '1.6', 'Periodicidade: por demanda.', '', 6),
