(6096, 'capitulo', 83, 6088, 2, '1.8', 'Vinculação à cadeia de valor: N2 - Gerir canais.', '', 8),
(6097, 'capitulo', 83, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(6098, 'capitulo', 83, 6097, 2, '2.1', 'Procedimentos da Pessoa Jurídica Contratada/Conveniada', '', 10),
(6099, 'capitulo', 83, 6098, 3, '2.1.1', 'Proceder com as orientações relacionadas à assinatura do instrumento contratual e demais documentos, conforme orientações dos Correios.', '', 11),
(6100, 'capitulo', 83, 6098, 3, '2.1.2', 'Cadastrar-se no Sistema Eletrônico de Informações - SEI, para acesso externo, por meio de link disponibilizado pelos Correios ou orientações encaminhadas pelo órgão regional de gestão dos canais de atendimento.', '', 12),
(6101, 'capitulo', 83, 6098, 3, '2.1.3', 'Solicitar ao órgão regional de gestão dos canais de atendimento terceirizados esclarecimentos relacionados ao instrumento jurídico e demais documentos relacionados à implantação da unidade de atendimento, quando necessário.', '', 13),
(6102, 'capitulo', 83, 6098, 3, '2.1.4', 'Instruir o processo administrativo eletrônico de gestão da unidade de atendimento, com os documentos descritos no instrumento contratual, bem como:', '', 14),
(6103, 'capitulo', 83, 6102, 4, 'a', 'formulário de solicitação de capacitação devidamente acompanhado das cópias dos documentos pessoais dos servidores, empregados ou prepostos que atuarão na unidade;', '', 15),
(6104, 'capitulo', 83, 6102, 4, 'b', 'alvará de funcionamento do prédio, edifício ou espaço em que funcionará a unidade de atendimento;', '', 16),
(6105, 'capitulo', 83, 6102, 4, 'c', 'comprovante de vínculo jurídico da pessoa jurídica com o imóvel em que funcionará a unidade, conforme orientações contidas no anexo 2 deste capítulo;', '', 17),
(6106, 'capitulo', 83, 6102, 4, 'd', 'comprovante de vínculo jurídico de todos os servidores, empregados ou prepostos que atuarão na unidade;', '', 18),
(6107, 'capitulo', 83, 6102, 4, 'e', 'comprovante de escolaridade mínima de todos os servidores, empregados ou prepostos que atuarão na unidade;', '', 19),
(6108, 'capitulo', 83, 6102, 4, 'f', 'certidões comprobatórias de regularidade tributária, trabalhista e fiscal.', '', 20),
(6109, 'capitulo', 83, 6098, 3, '2.1.5', 'Observar os instrumentos firmados, documentos, guias, normativos internos e orientações técnicas dos Correios durante a implantação da unidade de atendimento.', '', 21),
(6110, 'capitulo', 83, 6098, 3, '2.1.6', 'Viabilizar a participação dos servidores, empregados ou prepostos que atuarão na unidade de atendimento nas ações de capacitação, conforme orientações dos Correios.', '', 22),
(6111, 'capitulo', 83, 6098, 3, '2.1.7', 'Providenciar, quando cabível, adequações físicas no imóvel em que funcionará a unidade de atendimento, conforme disposto no instrumento contratual e orientações enviadas pelos Correios.', '', 23),
(6112, 'capitulo', 83, 6098, 3, '2.1.8', 'Adquirir ou solicitar aos Correios a cessão de uso de mobiliários, equipamentos de informática e periféricos, necessários ao funcionamento da unidade.', '', 24),
(6113, 'capitulo', 83, 6098, 3, '2.1.9', 'Observar as especificações técnicas mínimas necessárias para o funcionamento dos sistemas dos Correios, em caso de aquisição por meios próprios de equipamentos e periféricos de informática.', '', 25),
(6114, 'capitulo', 83, 6098, 3, '2.1.10', 'Observar, durante a instalação da unidade de atendimento, a legislação vigente e as orientações dos órgãos competentes relacionadas à ergonomia e segurança do trabalho.', '', 26),
(6115, 'capitulo', 83, 6098, 3, '2.1.11', 'Observar os padrões de marca e identidade visual estabelecidos pelos Correios nos itens de comunicação utilizados na unidade de atendimento, conforme orientações encaminhadas pelo órgão regional de gestão dos canais de atendimento terceirizados.', '', 27),
(6116, 'capitulo', 83, 6098, 3, '2.1.12', 'Instruir o processo administrativo eletrônico de gestão da unidade de atendimento com os comprovantes, fotos, arquivos ou documentos que comprovem o cumprimento das atividades de instalação da unidade, conforme orientações dos Correios.', '', 28),
(6117, 'capitulo', 83, 6098, 3, '2.1.13', 'Atentar-se aos prazos definidos no instrumento contratual ou documentos de orientações dos Correios para a conclusão das atividades de instalação da unidade de atendimento.', '', 29),
(6118, 'capitulo', 83, 6098, 3, '2.1.14', 'Definir em conjunto com o órgão regional de gestão dos canais de atendimento terceirizados os itens que irão compor o plano de trabalho da unidade de atendimento.', '', 30),
(6119, 'capitulo', 83, 6098, 3, '2.1.15', 'Solicitar ao órgão regional de gestão dos canais de atendimento terceirizados a disponibilização, com antecedência mínima de 15 (quinze) dias úteis para a data prevista para o início das operações da unidade:', '', 31),
(6120, 'capitulo', 83, 6119, 4, 'a', 'dos itens constantes no mix obrigatório e complementar do plano de trabalho, anexo do instrumento contratual;', '', 32),
(6121, 'capitulo', 83, 6119, 4, 'b', 'insumos e materiais de consumo personalizados com as marcas e patentes registradas ou licenciadas em nome dos Correios, que serão utilizadas exclusivamente na prestação dos serviços, tratamento dos objetos ou expedição da carga postal;', '', 33),
(6122, 'capitulo', 83, 6119, 4, 'c', 'insumos necessários para a execução das atividades incluídas no plano de trabalho de fornecimento exclusivo pelos Correios, tais como malas, caixetas e lacres;', '', 34),
(6123, 'capitulo', 83, 6119, 4, 'd', 'tabelas, pastas de tarifas e demais materiais necessários à prestação do atendimento postal na unidade;', '', 35),
(6124, 'capitulo', 83, 6119, 4, 'e', 'modelos de cartazes obrigatórios que deverão ser anexados em local visível ao público, conforme orientações dos Correios.', '', 36),
(6125, 'capitulo', 83, 6098, 3, '2.1.16', 'Receber os itens listados no subitem 2.1.15 e solicitados aos Correios, conferindo a quantidade, a qualidade e sua integridade, atentando-se para as orientações de guarda e inclusão nos sistemas de atendimento, quando cabível.', '', 37),
(6126, 'capitulo', 83, 6098, 3, '2.1.17', 'Requerer ao órgão regional de gestão dos canais de atendimento terceirizados os ajustes necessários no suprimento realizado, caso identificada divergência entre o requerido e o disponibilizado.', '', 38),
(6127, 'capitulo', 83, 6098, 3, '2.1.18', 'Receber e executar os procedimentos orientados pelos profissionais dos Correios que irão realizar os procedimentos de operação assistida, presencialmente ou de forma remota.', '', 39),
(6128, 'capitulo', 83, 6097, 2, '2.2', 'Procedimentos do Órgão Regional de Gestão dos Canais de Atendimento Terceirizados', '', 40),
(6129, 'capitulo', 83, 6128, 3, '2.2.1', 'Solicitar ao órgão corporativo de gestão dos canais de atendimento terceirizados esclarecimentos relacionados ao instrumento jurídico e demais documentos relacionados à implantação da unidade de atendimento, quando necessário.', '', 41),
(6130, 'capitulo', 83, 6128, 3, '2.2.2', 'Instruir o processo administrativo de gestão da unidade de atendimento com os documentos necessários à implantação da unidade.', '', 42),
(6131, 'capitulo', 83, 6128, 3, '2.2.3', 'Atribuir ao processo administrativo de gestão da unidade de atendimento a característica de processo restrito, observando a previsão do artigo 31 da Lei 12.527/2011 (Lei de Acesso à Informação).', '', 43),
(6132, 'capitulo', 83, 6128, 3, '2.2.4', 'Conceder acesso ao processo administrativo de gestão da unidade de atendimento aos órgãos de gestão corporativa e operacional do canal de atendimento terceirizado, quando solicitado.', '', 44),
(6133, 'capitulo', 83, 6128, 3, '2.2.5', 'Orientar a pessoa jurídica contratada/conveniada acerca dos procedimentos de cadastro de todos os representantes legais da unidade de atendimento no SEI.', '', 45),
(6134, 'capitulo', 83, 6128, 3, '2.2.6', 'Conceder acesso externo à pessoa jurídica contratada/conveniada, por meio do gerenciador de acesso para usuários externos do SEI, utilizando-se da modalidade “acompanhamento integral do processo”.', '', 46),
(6135, 'capitulo', 83, 6128, 3, '2.2.7', 'Encaminhar à pessoa jurídica contratada/conveniada correspondência eletrônica por meio do SEI, acompanhada das orientações para:', '', 47),
(6136, 'capitulo', 83, 6135, 4, 'a', 'assinatura dos respectivos documentos;', '', 48),
(6137, 'capitulo', 83, 6135, 4, 'b', 'adoção das providências para instalação da unidade de atendimento;', '', 49),
(6138, 'capitulo', 83, 6135, 4, 'c', 'envio dos formulários de solicitação para capacitação dos servidores, empregados ou prepostos que atuarão na unidade;', '', 50),
(6139, 'capitulo', 83, 6135, 4, 'd', 'envio dos formulários de solicitação da cessão de uso de equipamentos, mobiliários ou periféricos necessários ao funcionamento da unidade de atendimento;', '', 51),
(6140, 'capitulo', 83, 6135, 4, 'e', 'envio dos documentos comprobatórios de cumprimento das obrigações fiscais, trabalhistas e previdenciárias;', '', 52),
(6141, 'capitulo', 83, 6135, 4, 'f', 'envio dos comprovantes de vínculo jurídico do imóvel, conforme orientações constantes no anexo 2 do Manual de Comercialização e Atendimento - MANCAT 22/1;', '', 53),
(6142, 'capitulo', 83, 6135, 4, 'g', 'envio dos comprovantes de vínculo jurídico (CTPS, contrato  mantido com todos os servidores, empregados ou prepostos que atuarão na unidade);', '', 54),
(6143, 'capitulo', 83, 6135, 4, 'h', 'envio dos comprovantes de escolaridade mínima exigidas dos servidores, empregados ou prepostos que atuarão na unidade, conforme orientações constantes no anexo 2 deste manual;', '', 55),
(6144, 'capitulo', 83, 6135, 4, 'i', 'envio de cópias de documentos dos representantes legais da pessoa jurídica contratada/conveniada, para fins de cadastro nos sistemas dos Correios, quando ainda não tiverem sido fornecidas.', '', 56),
