(6154, 'capitulo', 83, 6152, 4, 'b', 'insumos e materiais de consumo personalizados com as marcas e patentes registradas ou licenciadas em nome dos Correios, que serão utilizadas exclusivamente na prestação dos serviços, tratamento dos objetos ou expedição da carga postal;', '', 66),
(6155, 'capitulo', 83, 6152, 4, 'c', 'insumos necessários para a execução das atividades incluídas no plano de trabalho de fornecimento exclusivo pelos Correios, tais como malas, caixetas e lacres;', '', 67),
(6156, 'capitulo', 83, 6152, 4, 'd', 'tabelas, pastas de tarifas e demais materiais necessários à prestação do atendimento postal na unidade;', '', 68),
(6157, 'capitulo', 83, 6152, 4, 'e', 'modelos de cartazes obrigatórios que deverão ser anexados em local visível ao público, conforme orientações dos Correios.', '', 69),
(6158, 'capitulo', 83, 6128, 3, '2.2.16', 'Providenciar os ajustes necessários, caso identificada divergência no suprimento inicial realizado à unidade de atendimento.', '', 70),
(6159, 'capitulo', 83, 6128, 3, '2.2.17', 'Conceder prazo adicional para a finalização das atividades preliminares de instalação da unidade de atendimento, caso necessário.', '', 71),
(6160, 'capitulo', 83, 6128, 3, '2.2.18', 'Solicitar ao órgão de gestão operacional dos canais de atendimento a formalização do cadastro da unidade de atendimento nos sistemas dos Correios.', '', 72),
(6161, 'capitulo', 83, 6128, 3, '2.2.19', 'Solicitar ao órgão regional de gestão do tratamento e distribuição a definição do plano de triagem e expedição da unidade de atendimento.', '', 73),
(6162, 'capitulo', 83, 6128, 3, '2.2.20', 'Orientar a pessoa jurídica contratada/conveniada sobre os procedimentos necessários à prestação de contas, cumprimento do plano de trabalho, triagem e expedição dos objetos postais, distribuição e acerto de contas, quando cabível.', '', 74),
(6163, 'capitulo', 83, 6128, 3, '2.2.21', 'Providenciar o cadastro dos servidores, empregados ou prepostos da pessoa jurídica contratada/conveniada nos sistemas dos Correios, inclusive naqueles destinados a viabilizar o acesso ao ambiente virtual de aprendizagem (Universidade Corporativa dos Correios).', '', 75),
(6164, 'capitulo', 83, 6128, 3, '2.2.22', 'Orientar a pessoa jurídica contratada/conveniada acerca dos procedimentos para acessar o ambiente virtual de aprendizagem, inclusive quanto aos cursos de capacitação obrigatórios para o funcionamento da unidade.', '', 76),
(6165, 'capitulo', 83, 6128, 3, '2.2.23', 'Definir a data de início das operações da unidade de atendimento em conjunto com a pessoa jurídica contratada/conveniada.', '', 77),
(6166, 'capitulo', 83, 6128, 3, '2.2.24', 'Fornecer informações complementares ao órgão de gestão operacional dos canais de atendimento, caso necessário.', '', 78),
