(6171, 'capitulo', 83, 6097, 2, '2.4', 'Procedimentos do Órgão Regional de Gestão de Infraestrutura', '', 83),
(6172, 'capitulo', 83, 6171, 3, '2.4.1', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados o pedido de apoio técnico ou disponibilização de profissional para a realização de visita técnica às instalações da pessoa jurídica contratada/conveniada, a fim de se constatar o cumprimento dos requisitos técnicos necessários ao funcionamento da unidade.', '', 84),
(6173, 'capitulo', 83, 6171, 3, '2.4.2', 'Viabilizar, caso necessário, o comparecimento de profissional técnico nas instalações da pessoa jurídica contratada/conveniada para a realização da visita técnica.', '', 85),
