(6175, 'capitulo', 83, 6171, 3, '2.4.4', 'Prestar informações e/ou orientações ao órgão regional de gestão dos canais de atendimento terceirizados e à pessoa jurídica contratada/conveniada, quando for o caso, relativas aos itens de estrutura e mobiliário necessários ao funcionamento da unidade.', '', 87),
(6176, 'capitulo', 83, 6097, 2, '2.5', 'Procedimentos do Órgão Regional de Gestão de Tratamento e Transporte', '', 88),
(6177, 'capitulo', 83, 6176, 3, '2.5.1', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados o pedido de elaboração do plano de triagem da unidade de atendimento.', '', 89),
(6178, 'capitulo', 83, 6176, 3, '2.5.2', 'Disponibilizar o plano de triagem solicitado, com as orientações necessárias para o seu cumprimento.', '', 90),
(6179, 'capitulo', 83, 6176, 3, '2.5.3', 'Informar periodicidade e disponibilidade de linhas para a realização da coleta/transporte dos objetos na unidade própria vinculadora.', '', 91),
