(6806, 'capitulo', 98, 6798, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir clientes.', '', 8),
(6807, 'capitulo', 98, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Processos de Gerir Clientes da Cadeia de Valor\n2.1.1 Descrever o processo de Gerir clientes (nível 2): identifica oportunidades de negócios e necessidades dos clientes, por meio da oferta de soluções que agreguem valor ao negócio do cliente. Compreende a gestão da informação dos clientes nos sistemas corporativos, garantindo informações confiáveis para tomada de decisão. Inclui atendimento e tratamento das demandas de pós-vendas dos clientes e apoio consultivo para potencialização dos negócios do cliente\n* * * * *', 9),
(6808, 'capitulo', 99, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(6809, 'capitulo', 99, 6808, 2, '1.1', 'Objetivo: definir guia de atuação comercial para atendimento aos clientes com contrato.', '', 1),
(6810, 'capitulo', 99, 6808, 2, '1.2', 'Abrangência: nacional.', '', 2),
(6811, 'capitulo', 99, 6808, 2, '1.3', 'Gestor: Departamento de Desenvolvimento de Negócios e Vendas - DEVEN.', '', 3),
(6812, 'capitulo', 99, 6808, 2, '1.4', 'Fornecedores: Departamento de Desenvolvimento de Negócios e Vendas - DEVEN.', '', 4),
(6813, 'capitulo', 99, 6808, 2, '1.5', 'Clientes: clientes externos.', '', 5),
(6814, 'capitulo', 99, 6808, 2, '1.6', 'Periodicidade: permanente.', '', 6),
(6815, 'capitulo', 99, 6808, 2, '1.7', 'Duração: perene.', '', 7),
(6816, 'capitulo', 99, 6808, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Executar vendas.', '', 8),
(6817, 'capitulo', 99, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Definir guia de atuação comercial norteador para a atuação dos gestores de relacionamento comercial, responsáveis pela gestão dos clientes que contrataram os pacotes Infinite, Diamante, Platinum, Ouro, Prata, Bronze e Clube Correios, e para o suporte tecnológico, conforme os seguintes detalhamentos:\na) descrever as atividades, a partir das atribuições e premissas contidas na Política Comercial dos Correios;\nb) indicar as funções preferenciais;\nc) definir lotação e localização;\nd) comunicar alterações da gestão de clientes.\n* * * * *', 9),
(6818, 'capitulo', 100, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(6819, 'capitulo', 100, 6818, 2, '1.1', 'Objetivo: gerir os requisitos, fundamentação legal e normativa dos instrumentos contratuais e de convênios para a formalização da prestação de serviços e venda de produtos dos Correios.', '', 1),
(6820, 'capitulo', 100, 6818, 2, '1.2', 'Abrangência: toda a Empresa.', '', 2),
(6821, 'capitulo', 100, 6818, 2, '1.3', 'Gestor: Departamento de Precificação e Política Comercial - DPREC.', '', 3),
(6822, 'capitulo', 100, 6818, 2, '1.4', 'Fornecedores: área de vendas e negócios, departamentos gestores/formatadores, área jurídica, superintendências executivas e áreas técnicas no âmbito local ou nacional.', '', 4),
(6823, 'capitulo', 100, 6818, 2, '1.5', 'Clientes: áreas de vendas e negócios, administrativa, financeira e operacional.', '', 5),
(6824, 'capitulo', 100, 6818, 2, '1.6', 'Periodicidade: conforme demanda.', '', 6),
(6825, 'capitulo', 100, 6818, 2, '1.7', 'Duração: indeterminada.', '', 7),
(6826, 'capitulo', 100, 6818, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir precificação.', '', 8),
(6827, 'capitulo', 100, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(6828, 'capitulo', 100, 6827, 2, '2.1', 'Área Gestora de Contratos Comerciais', '', 10),
(6829, 'capitulo', 100, 6828, 3, '2.1.1', 'Definir os modelos dos instrumentos que regem a contratação da prestação de serviços e venda de produtos dos Correios (nacionais, internacionais e negócios customizados) e de seus documentos congêneres, considerando as especificações descritas no Anexo 2.', '', 11),
(6830, 'capitulo', 100, 6828, 3, '2.1.2', 'Definir as regras para a formalização de contratação da prestação de serviços e venda de produtos na ferramenta Correios Fácil e no Sistema Eletrônico de Informações - SEI.', '', 12),
(6831, 'capitulo', 100, 6828, 3, '2.1.3', 'Coordenar, junto às gerências de suporte comercial, no âmbito das Superintendências Estaduais - SEs, a gestão técnica do processo de contratos comerciais, compreendida pelo controle e operacionalização das atividades de pactuação, alterações, notificações inerentes e rescisões, assim como seus registros nos sistemas da Empresa.', '', 13),
(6832, 'capitulo', 100, 6827, 2, '2.2', 'Área Formatadora de Produtos e Serviços', '', 14),
(6833, 'capitulo', 100, 6832, 3, '2.2.1', 'Avaliar e emitir posicionamento quanto às demandas de customização de produtos e serviços, assim como as regras a serem pactuadas entre os Correios e os clientes.', '', 15),
(6834, 'capitulo', 100, 6827, 2, '2.3', 'Área Gestora de Produtos e Serviços', '', 16),
(6835, 'capitulo', 100, 6834, 3, '2.3.1', 'Avaliar e emitir posicionamento quanto às demandas de análise do ciclo de vida do negócio customizado e/ou ratificação da continuidade da customização, de solicitação de reajuste de preços, de condições comerciais e operacionais e demais informações pertinentes às customizações em vigor, observando as regras constantes do Anexo 2.', '', 17),
(6836, 'capitulo', 100, 6827, 2, '2.4', 'Área Gestora de Clientes', '', 18),
(6837, 'capitulo', 100, 6836, 3, '2.4.1', 'Receber as demandas referentes à alteração de regras contratuais e/ou de produtos/serviços encaminhadas pelos clientes e emitir análise e parecer técnico quanto à viabilidade comercial das proposições apresentadas.', '2.4.1.1 Encaminhar posicionamento, à área de suporte comercial, quando se tratar de alteração contratual e, nos casos de customização de produtos/serviços, observar as orientações do Departamento Formatador quanto ao fluxo a ser seguido.', 19),
(6838, 'capitulo', 100, 6836, 3, '2.4.2', 'Verificar o interesse do cliente na manutenção e continuidade de customizações vigentes, visando o início do processo de prorrogação/renovação/reajuste contratual.', '', 20),
(6839, 'capitulo', 100, 6827, 2, '2.5', 'Área de Suporte Comercial', '', 21),
(6840, 'capitulo', 100, 6839, 3, '2.5.1', 'Realizar o atendimento das demandas de formalização da contratação da prestação de serviços e venda de produtos dos Correios, bem como os procedimentos inerentes à operacionalização e respectivos registros nos sistemas da Empresa (exemplo: alteração de pacotes de serviços; criação/cancelamento de cartões de postagem, inclusão/exclusão de anexos, etc.).', '', 22),
(6841, 'capitulo', 100, 6839, 3, '2.5.2', 'Priorizar o atendimento das categorias de clientes previstas na Matriz de Relacionamento - Clientes com Contrato, para o benefício de pós-venda da Política Comercial dos Correios.', '', 23),
(6842, 'capitulo', 100, 6839, 3, '2.5.3', 'Celebração de Instrumentos Padronizados para a Prestação de Serviços e Venda de Produtos dos Correios via Sistema Eletrônico de Informações - SEI', '2.5.3.1 Receber, no ambiente SEI, o processo para celebração do instrumento contratual; analisar a documentação, os procedimentos de concessão de crédito (observados os regramentos da área financeira); e preparar a minuta, em estrita conformidade com as orientações técnicas do órgão de gestão dos contratos comerciais.\n2.5.3.2 Incluir, nos instrumentos contratuais, caso necessário, anexos, fichas técnicas, apensos e demais documentos vinculados, desde que previamente aprovados pela área formatadora, órgão de gestão dos contratos comerciais e/ou pela área jurídica dos Correios.\n2.5.3.3 Interagir com o cliente e orientá-lo a encaminhar documentações pendentes e/ou complementares, caso a formalização do instrumento requeira informações/documentos adicionais.\n2.5.3.4 Informar ao gestor comercial do cliente, quando da ocorrência de qualquer fato que inviabilize o prosseguimento da celebração do instrumento contratual.\n2.5.3.5 Disponibilizar a minuta para assinatura dos representantes legais dos Correios, os quais deverão estar em acordo com os critérios definidos pelo Estatuto dos Correios e portarias de delegação de competência.\n2.5.3.6 Disponibilizar a minuta para assinatura do(s) representante(s) legal(is) do cliente, responsável(is) por contrair obrigações.\n2.5.3.7 Validar o instrumento contratual assinado pelo cliente, legalizado/consularizado ou apostilado, em caso de instrumento internacional, conforme as regras constantes do Anexo 2.', 24),
(6843, 'capitulo', 100, 6839, 3, '2.5.4', 'Celebração de Instrumentos Contratuais Customizados para a Prestação de Serviços e Venda de Produtos dos Correios', '2.5.4.1 Receber as demandas encaminhadas por meio de processo SEI, referente à alteração de instrumentos contratuais ou customização de produtos/serviços, contendo solicitação/justificativa do cliente e a análise e parecer técnico da área gestora de clientes.\n2.5.4.2 Avaliar se a alteração proposta foi objeto de análise pela área competente (jurídica, de gestão dos contratos comerciais e/ou departamento gestor/formatador) e proceder os encaminhamentos a seguir:', 25),
(6844, 'capitulo', 100, 6843, 4, 'a', 'se o parecer da área competente for favorável: enviar a minuta proposta para chancela da área jurídica local, com os documentos que fundamentam a alteração, a justificativa do cliente e o posicionamento da área requerente;', '', 26),
(6845, 'capitulo', 100, 6843, 4, 'b', 'se o parecer da área competente for desfavorável: informar a área de vendas local e solicitar que retome as negociações, fundamentando-se na nota jurídica/ofício para a adoção da minuta do contrato comercial padronizado;', '', 27),
(6846, 'capitulo', 100, 6843, 4, 'c', 'se a alteração proposta trouxer um tema inédito ou customização de produtos/serviços, encaminhar consulta quanto à viabilidade da alteração à área competente, indicando a cláusula padronizada (caso haja), a cláusula proposta pelo cliente e o parecer técnico da gerência de suporte comercial, realizando os procedimentos das alíneas “a” ou “b”, conforme parecer da área competente.', '2.5.4.3 Realizar os procedimentos descritos nos subitens 2.5.3.5 e 2.5.3.6, em caso de parecer favorável à alteração proposta nos termos dos subitens 2.5.4.1 e 2.5.4.2.', 28),
(6847, 'capitulo', 100, 6839, 3, '2.5.5', 'Prorrogação de Vigência, Renovação e Reajuste Contratual', '2.5.5.1 Verificar a data de vigência final do contrato e/ou da vigência final dos preços vigentes para o produto/serviço customizado.\n2.5.5.2 Elaborar a comunicação para os clientes conforme prazos definidos no Anexo 4 deste Capítulo, considerando a data de término da vigência do instrumento.\n2.5.5.3 Realizar os procedimentos administrativos para a renovação/repactuação/reajuste contratual e prorrogação de vigência, conforme estabelecido em contrato e no subitem 2.5.3, observadas as regras constantes no Anexo 2.\n2.5.5.4 Acionar a força de vendas responsável pela gestão do cliente, com antecedência mínima de 180 (cento e oitenta) dias do vencimento do contrato customizado ou tabela de preços, para verificação do interesse na manutenção e continuidade da customização, visando o início do processo de prorrogação/renovação contratual.\n2.5.5.5 Encaminhar, ao departamento gestor de produtos e serviços, com antecedência mínima de 120 (cento e vinte) dias antes do vencimento do contrato customizado, demanda para análise do ciclo de vida do negócio, ratificação da continuidade da customização, solicitação de reajuste de preços, condições comerciais e operacionais e demais informações pertinentes à solução desenvolvida.\n2.5.5.6 Acompanhar retorno do departamento gestor de produtos e serviços quanto à continuidade da customização e/ou reajuste a ser aplicado, se for o caso, e proceder com a formalização junto ao cliente, conforme previsão contratual (apostilamento ou termo aditivo).\n2.5.5.7 Demandar, ao departamento gestor de precificação, o cadastro do novo preço nos sistemas dos Correios.\n* * * * *', 29),
(6848, 'capitulo', 102, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(6849, 'capitulo', 102, 6848, 2, '1.1', 'Objetivo: orientar quanto aos procedimentos referentes às manifestações relativas aos serviços internacionais.', '', 1),
(6850, 'capitulo', 102, 6848, 2, '1.2', 'Abrangência: toda a empresa.', '', 2),
(6851, 'capitulo', 102, 6848, 2, '1.3', 'Gestores: Gerência de Relacionamento Aduaneiro e Exportação - GREX, Gerência de Produtos de Importação - GPIM e Gerência de Contas Internacionais e Importação Convencional - GCIC - DEINT/DINEG.', '', 3),
(6852, 'capitulo', 102, 6848, 2, '1.4', 'Fornecedores: unidades operacionais e de atendimento, operadores designados estrangeiros.', '', 4),
(6853, 'capitulo', 102, 6848, 2, '1.5', 'Clientes: clientes dos Correios, equipe de pós-venda, operadores designados estrangeiros e contratantes dos serviços.', '', 5),
(6854, 'capitulo', 102, 6848, 2, '1.6', 'Periodicidade: por demanda.', '', 6),
(6855, 'capitulo', 102, 6848, 2, '1.7', 'Duração: contínua.', '', 7),
(6856, 'capitulo', 102, 6848, 2, '1.8', 'Vínculo com a Cadeia de Valor: N2 - Gerir portfólio de produtos.', '', 8),
(6857, 'capitulo', 102, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 9),
(6858, 'capitulo', 102, 6857, 2, '2.1', 'Procedimentos da Equipe de Pós-Venda', '', 10),
(6859, 'capitulo', 102, 6858, 3, '2.1.1', 'Tratamento de Manifestação dos Serviços de Exportação', '2.1.1.1 Receber a manifestação via sistema Fale Conosco.\n2.1.1.2 Analisar a manifestação.\n2.1.1.3 Buscar informações nos sistemas, caso necessário.\n2.1.1.4 Confirmar no fluxo postal se o objeto já foi entregue para a companhia aérea para exportação.\n2.1.1.5 Objeto Não Entregue para Companhia Aérea\n2.1.1.5.1 Analisar a procedência de indenização ou ressarcimento parcial, conforme regras definidas no Anexo 2 deste Capítulo.\n2.1.1.6 Objeto Entregue para a Companhia Aérea\n2.1.1.6.1 Confirmar se o objeto de exportação saiu do Brasil.\nNota: Essa busca de informações será realizada no Sistema de Rastreamento - SRO, no International Postal System - IPS e/ou EMS Smart Tracking.\n2.1.1.6.2 Confirmar se o objeto de exportação foi recebido no país de destino.\n2.1.1.6.3 Verificar para qual país a mala foi encaminhada, quando o objeto não tiver sido recebido no destino.\n2.1.1.6.4 Consultar o operador designado para o qual o objeto tenha sido encaminhado.\n2.1.1.6.5 Solicitar o encaminhamento do objeto para o país de destino, caso tenha sido encaminhado para um país terceiro (trânsito ou mal encaminhado).\n2.1.1.6.6 Monitorar o encaminhamento, recebimento e entrega do objeto ao país de destino.\n2.1.1.6.7 Em caso de não entrega, consultar o operador designado de destino.\n2.1.1.6.8 Analisar a resposta do operador designado.\n2.1.1.7 Considerar a manifestação procedente, se não for respondida dentro dos prazos estipulados no Anexo 2 deste capítulo.\n2.1.1.8 Efetuar o cadastro das informações no Sistema de Reclamações Internacionais - SRI e Fale Conosco.\n2.1.1.9 Responder conclusivamente ao operador designado, se for o caso, e ao cliente.', 11),
(6860, 'capitulo', 102, 6858, 3, '2.1.2', 'Tratamento de Manifestação dos Serviços de Importação', '2.1.2.1 Receber a manifestação via sistema Fale Conosco ou do operador designado do país de origem.\n2.1.2.2 Analisar a manifestação.\n2.1.2.3 Buscar informações nos sistemas, caso necessário.\n2.1.2.4 Confirmar se o objeto de importação chegou no Brasil.\nNota: Essa busca de informações será realizada no Sistema de Rastreamento - SRO, Sistema de Monitoramento de Armazenagem e Triagem Internacional – SMARTI, International Postal System - IPS ou no Sistema de Serviços Internacionais de Importação - SSII se for objeto Correios Packet.\n2.1.2.4.1 Consultar o operador designado quando se tratar de Carta Registrada, EMS, Colis, Prime, Petit Paquet Registrado-PPR ou Petit Paquet Simples - PPS.\n2.1.2.4.2 Considerar a resposta recebida do operador designado ou as informações dos sistemas para definir se a manifestação é procedente para pagamento de indenização ou ressarcimento via contas internacionais.\n2.1.2.4.3 Efetuar o cadastro das informações recebidas no Sistema de Reclamações Internacionais - SRI e Fale Conosco.\n2.1.2.4.4 Responder conclusivamente ao operador designado, se for o caso, e ao cliente.\n2.1.2.5 Encaminhar a manifestação à unidade operacional, caso o objeto tenha chegado no Brasil.\n2.1.2.5.1 Analisar a resposta recebida da unidade operacional.\n2.1.2.5.2 Considerar a resposta recebida da unidade para definir se a manifestação é procedente para indenização ao destinatário, caso tenha pagamento de tributos ou Despacho Postal, ao Contratante se for encomenda Correios Packet ou ressarcimento ao operador designado via contas internacionais.\n2.1.2.5.3 Responder conclusivamente ao operador designado, se for o caso, e ao cliente.\n* * * * *', 12),
(6861, 'capitulo', 103, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '1.1 Objetivo: definir as especificações e critérios necessários a comercialização de serviços de terceiros, por meio de integração entre os sistemas parceiros dos CORREIOS e o Sistema de Serviços de Terceiros - STER.\n1.2 Abrangência: nacional.\n1.3 Gestor: órgão gestor dos canais digitais.\n1.4 Fornecedores: órgãos da empresa diretamente ligados ao desenvolvimento, gestão de produtos e serviços e gestão de contratos, que necessitam de integração sistêmica, bem como ativação de serviços.\n1.5 Clientes: clientes externos com contrato comercial.\n1.6 Periodicidade: por demanda.\n1.7 Duração: contínua.\n1.8 Vínculo com a Cadeia de Valor: N2 - Gerir canais.', 0),
(6862, 'capitulo', 103, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Atribuições da Área Demandante\n2.1.1 Avaliar a necessidade de ativação de serviços de terceiros e/ou integração sistêmica, assim conforme procedimentos previstos no MANCAT 8/1.\n2.1.2 Demandar à Gestão Funcional STER, via ofício, Formulário SEI: TIC Sistemas - Integração Sistêmica - STER, bem como Ficha Técnica STER, devidamente validada pela área competente.\n2.2 Atribuições da Gestão Funcional do Sistema de Serviços de Terceiros STER\n2.2.1 Receber do órgão solicitante a demanda de integração sistêmica e/ou ativação de serviço, via ofício, Formulário SEI: TIC Sistemas - Integração Sistêmica - STER, bem como Ficha Técnica STER, devidamente validada pela área competente.\n2.2.2 Avaliar a demanda verificando os dados apresentados no formulário, e a aderência às diretrizes de integração do sistema STER, conforme previsto no documento: Padrões Técnicos de Comunicação API - STER CORREIOS, disponibilizado na intranet (http://intranet/cs/dineg/sucan/canais-digitais/ster) e outros normativos.\n2.2.3 Interagir com o solicitante para revisão da demanda caso não esteja aderente às diretrizes de integração do sistema STER e outros normativos.\n2.2.4 Confirmar a forma de integração, bem como os tipos de solução que serão utilizados na demanda.\n2.2.5 Analisar a aderência da solução demandada e, se necessário, registrar demanda de melhoria para o sistema STER, conforme conveniência de serviço já existente, aproveitável para um conjunto de clientes, de forma padronizada.\n2.2.6 Realizar as demandas evolutivas solicitadas pelas áreas de desenvolvimento e/ou gestão do ciclo de vida do produto para adequação das soluções disponíveis a partir do sistema STER.\n2.2.7 Homologar demanda.\n* * * * *', 1),
(6863, 'capitulo', 106, NULL, 1, '1', 'ATRIBUTOS DO SUBPROCESSO', '', 0),
(6864, 'capitulo', 106, 6863, 2, '1.1', 'Objetivo: orientar as partes envolvidas nas atividades para a implantação do Canal de Atendimento Correios Aqui - Unidade Modular (CMD).', '', 1),
(6865, 'capitulo', 106, 6863, 2, '1.2', 'Abrangência: toda a empresa', '', 2),
(6866, 'capitulo', 106, 6863, 2, '1.3', 'Gestor: órgão corporativo de gestão dos instrumentos jurídicos dos canais de atendimento terceirizados.', '', 3),
(6867, 'capitulo', 106, 6863, 2, '1.4', 'Fornecedor: órgão corporativo de gestão dos instrumentos jurídicos dos canais de atendimento terceirizados; de gestão operacional dos canais de atendimento; de gestão da tecnologia da informação; de gestão da infraestrutura; órgão regional de gestão dos canais de atendimento terceirizados; de gestão da infraestrutura; de gestão da tecnologia da informação; órgão de gestão corporativa de operações financeiras; Canal de Atendimento Correios Aqui - Unidade Modular (CMD).', '', 4),
(6868, 'capitulo', 106, 6863, 2, '1.5', 'Cliente: pessoa jurídica detentora do contrato de permissão do Canal de Atendimento Correios Aqui – Unidade Modular (CMD).', '', 5),
(6869, 'capitulo', 106, 6863, 2, '1.6', 'Periodicidade: por demanda.', '', 6),
(6870, 'capitulo', 106, 6863, 2, '1.7', 'Duração: variável.', '', 7),
(6871, 'capitulo', 106, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 8),
(6872, 'capitulo', 106, 6871, 2, '2.1', 'Procedimentos da Pessoa Jurídica Permissionária - Canal Correios Aqui - Unidade Modular (CMD)', '', 9),
(6873, 'capitulo', 106, 6872, 3, '2.1.1', 'Atender a convocação dos Correios para assinatura do instrumento contratual.', '', 10),
(6874, 'capitulo', 106, 6872, 3, '2.1.2', 'Cadastrar-se no sistema eletrônico de informações na página dos Correios, por meio do hiperlink disponibilizado ou conforme procedimento definido pelos Correios.', '', 11),
(6875, 'capitulo', 106, 6872, 3, '2.1.3', 'Disponibilizar, conforme prazo definido pelos Correios:', '', 12),
(6876, 'capitulo', 106, 6875, 4, 'a', 'cópia da documentação de identificação dos sócios bem como a documentação exigida nos instrumentos de seleção para a assinatura do contrato; e', '', 13);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(6877, 'capitulo', 106, 6875, 4, 'b', 'o(s) formulário(s) de solicitação de capacitação devidamente preenchido(s), acompanhado das cópias dos documentos dos empregados para os quais está sendo solicitada a capacitação.', '', 14),
(6878, 'capitulo', 106, 6872, 3, '2.1.4', 'Assinar o instrumento contratual, conforme orientações repassadas pelos Correios:', '', 15),
(6879, 'capitulo', 106, 6878, 4, 'a', 'comparecendo na data, local e horário indicados no documento de convocação; ou', '', 16),
(6880, 'capitulo', 106, 6878, 4, 'b', 'por meio do sistema eletrônico de informações.', '2.1.4.1 Observar as disposições do instrumento jurídico constitutivo da pessoa jurídica quanto à representação legal da empresa para as respectivas assinaturas.\n2.1.4.2 Atentar-se às penalidades previstas caso o instrumento contratual não seja assinado sem a apresentação de justificativa comprovadamente aceitável, conforme previsto nos instrumentos editalícios e anexos.\nNOTA: caso o instrumento contratual deixe de ser assinado devido a procedimentos sob responsabilidade dos Correios, será devolvido à permissionária prazo na mesma proporção do atraso, mediante justificativa fundamentada nos autos do processo administrativo de acompanhamento e gestão do contrato.', 17),
(6881, 'capitulo', 106, 6872, 3, '2.1.5', 'Acompanhar e prestar os esclarecimentos necessários à equipe técnica de implantação, durante a etapa de realização das atividades preliminares.', '', 18),
(6882, 'capitulo', 106, 6872, 3, '2.1.6', 'Observar os instrumentos firmados, guias, normativos internos e orientações técnicas dos Correios na execução das atividades preliminares.', '', 19),
(6883, 'capitulo', 106, 6872, 3, '2.1.7', 'Viabilizar a participação dos profissionais que irão executar as atividades do CMD nas ações de capacitação, conforme orientações disponibilizadas pelos Correios.', '', 20),
(6884, 'capitulo', 106, 6872, 3, '2.1.8', 'Providenciar, quando cabível, as adequações físicas no imóvel e/ou o rearranjo do leiaute do estabelecimento comercial, conforme previsto nos instrumentos editalícios e respectivos anexos.', '', 21),
(6885, 'capitulo', 106, 6872, 3, '2.1.9', 'Adquirir e instalar o mobiliário, os itens de comunicação visual, os sistemas, os equipamentos e os periféricos, observando as definições dispostas nas diretrizes presentes no projeto básico do canal conforme abaixo:', '', 22),
(6886, 'capitulo', 106, 6885, 4, 'a', 'fica garantida à permissionária a flexibilidade de meios e o direito de adquirir os itens/equipamentos, incluindo os softwares, os hardwares, os periféricos e os mobiliários de quaisquer fabricantes e modelos, devendo atentar-se à legislação aplicável e às especificações técnicas mínimas de qualidade e desempenho dos itens adquiridos;', '', 23),
(6887, 'capitulo', 106, 6885, 4, 'b', 'de forma a evitar inadequações de padronização e marcas de propriedade dos Correios, os itens com exigência específica de modelo ou especificações técnicas não estão abrangidos pela liberalidade de que trata a alínea acima.', '', 24),
(6888, 'capitulo', 106, 6872, 3, '2.1.10', 'Solicitar ao órgão regional de gestão dos canais de atendimento terceirizados, no prazo definido no projeto básico ou contrato de permissão, a verificação de adequação aos requisitos do processo seletivo do CMD.', '', 25),
(6889, 'capitulo', 106, 6872, 3, '2.1.11', 'Encaminhar, com a devida justificativa, solicitação de postergação de prazo para finalização das atividades preliminares, cuja análise e decisão caberá ao órgão regional de gestão dos canais de atendimento terceirizados.', '2.1.11.1 Realizar o pagamento da sanção pecuniária correspondente, nas ocasiões em que a justificativa não for acatada pelos Correios, conforme itens e valores dispostos no projeto básico e/ou no contrato de permissão\n2.1.11.2 Disponibilizar, no Sistema Eletrônico de Informações (SEI), o comprovante do pagamento da sanção pecuniária relativa ao subitem 2.1.11.1 deste Capítulo, em até 5 (cinco) dias úteis ou conforme orientação dos Correios.', 26),
(6890, 'capitulo', 106, 6872, 3, '2.1.12', 'Atentar-se para o prazo limite para a conclusão das atividades preliminares, conforme etapas e procedimentos previstos nos instrumentos editalícios sob pena de revogação da permissão.', 'NOTA: excetuam-se dessa regra as situações em que, comprovadamente, a causa tenha ocorrido em função de fato superveniente intransponível ou caso fortuito ou de força maior, demonstrado documentalmente em processo administrativo específico, com decisão fundamentada da autoridade competente.', 27),
(6891, 'capitulo', 106, 6872, 3, '2.1.13', 'Providenciar a adequação e o registro, junto aos órgãos competentes, do documento constitutivo da pessoa jurídica, bem como o alvará de funcionamento quando cabível e demais exigências legais, de modo a incluir a execução das atividades inerentes ao contrato de permissão do CMD. Com esse objetivo deve-se providenciar:', 'a) as adequações referentes as exigências fiscais e/ou tributárias, sempre que cabível;\nb) fornecimento das informações de inscrição estadual aos Correios, de modo a possibilitar o suprimento do kit inicial e demais fornecimentos posteriores, tendo em vista que esses dados são essenciais para a emissão de Nota Fiscal Eletrônica (NF-e);\nc) fornecer, ao longo da execução contratual, documentos comprobatórios da regularidade tributária, trabalhista e fiscal, sempre que solicitado pelos Correios.', 28),
(6892, 'capitulo', 106, 6872, 3, '2.1.14', 'Interagir com o órgão regional de gestão dos canais de atendimento terceirizados para solicitação do kit inicial de suprimento, com no mínimo 20 (vinte) dias de antecedência da data prevista para verificação de adequação aos requisitos do processo seletivo ou em prazo definido pelos Correios.', '2.1.14.1 Receber o pedido de suprimento e conferir a quantidade, a qualidade e a integridade dos itens, atentando-se para as descrições apresentadas na Nota Fiscal Eletrônica (NF-e) de fornecimento e proceder à respectiva guarda e inclusão no sistema de atendimento, conforme orientação dos Correios.\nNOTA: no ato do recebimento do pedido, havendo divergência ou irregularidade no quantitativo, qualidade e/ou integridade dos itens recebidos, informar ao órgão regional de gestão dos canais de atendimento terceirizados e seguir as orientações fornecidas.', 29),
(6893, 'capitulo', 106, 6872, 3, '2.1.15', 'Obter junto ao órgão regional de gestão dos canais de atendimento terceirizados as informações de data e valor do pagamento do preço de entrada.', '', 30),
(6894, 'capitulo', 106, 6872, 3, '2.1.16', 'Realizar o pagamento relativo ao preço de entrada conforme estabelecido no instrumento contratual (Tabela de Valores e Taxas do Canal Correios Aqui - Unidade Modular - CMD) em até 5 (cinco) dias úteis anteriores a data marcada para a verificação de adequação aos requisitos do processo seletivo.', '2.1.16.1 Utilizar os dados registrados abaixo para o pagamento por meio de transferência eletrônica disponível (TED), operação de transferência/depósito identificado:', 31),
(6895, 'capitulo', 106, 6894, 4, 'a', 'favorecido: Empresa Brasileira de Correios e Telégrafos;', '', 32),
(6896, 'capitulo', 106, 6894, 4, 'b', 'CNPJ: 34.028.316/0001-03;', '', 33),
(6897, 'capitulo', 106, 6894, 4, 'c', 'banco: 001 - Banco do Brasil;', '', 34),
(6898, 'capitulo', 106, 6894, 4, 'd', 'agência: 3307-3 - Conta Corrente: 195.002-9; e', '', 35),
(6899, 'capitulo', 106, 6894, 4, 'e', 'código de identificação: CNPJ da pessoa jurídica da permissionária.', '', 36),
(6900, 'capitulo', 106, 6872, 3, '2.1.17', 'Disponibilizar no Sistema Eletrônico de Informações (SEI), cópia do recibo de transferência/depósito identificado, até 2 (dois) dias úteis anteriores da data agendada para a realização da verificação da adequação aos requisitos do processo seletivo.', '2.1.17.1 Havendo dificuldades de inserção do documento, informar ao órgão regional de gestão dos canais de atendimento terceirizados da situação, via e-mail, anexando o recibo do pagamento do preço de entrada do CMD.\nNOTA: o pagamento do preço de entrada do CMD não poderá ser realizado por meio de cheque ou documento de ordem de crédito (DOC) ou qualquer outro formato, exceto se autorizados formalmente pelos Correios.', 37),
(6901, 'capitulo', 106, 6872, 3, '2.1.18', 'Organizar os documentos complementares a serem disponibilizados à equipe técnica de implantação, a serem incluídos no processo administrativo de gestão do CMD relativo ao objeto do contrato de permissão, conforme lista a seguir:', '', 38),
(6902, 'capitulo', 106, 6901, 4, 'a', 'cópia do leiaute da loja após a instalação da estação de atendimento;', '', 39),
(6903, 'capitulo', 106, 6901, 4, 'b', 'cópia do leiaute da área reservada ao desenvolvimento das atividades internas/retaguarda;', '', 40),
(6904, 'capitulo', 106, 6901, 4, 'c', 'cópia do instrumento constitutivo da pessoa jurídica com as alterações do objeto social registrado no órgão competente, prevendo a prestação de serviços e venda de produtos pertinentes à operação do CMD;', '', 41),
(6905, 'capitulo', 106, 6901, 4, 'd', 'cópia do alvará de funcionamento atualizado com as adequações necessárias;', 'NOTA: será isenta a apresentação de alvará de funcionamento, quando a legislação dispensar sua emissão para a atividade varejista.', 42),
(6906, 'capitulo', 106, 6901, 4, 'e', 'cópia do comprovante do pagamento do preço de entrada, quando não inserida do prazo estabelecido no subitem 2.1.17 deste Capítulo;', '', 43),
(6907, 'capitulo', 106, 6901, 4, 'f', 'cópia de comprovante de quitação de eventuais débitos com os Correios relativos à operacionalização de outro tipo de Canal de Atendimento Terceirizado: Agência de Correios Comercial (ACC), Agência de Correios Franqueada (ACF ou AGF) da qual tenha sido ou seja signatária;', '', 44),
(6908, 'capitulo', 106, 6901, 4, 'g', 'cópia dos certificados de capacitação dos empregados/sócios envolvidos na operação do CMD; e', '', 45),
(6909, 'capitulo', 106, 6901, 4, 'h', 'levantamento fotográfico da unidade com qualidade mínima de 5 (cinco) megapixels (MP), tamanho 10x15 cm, sem edição ou qualquer manipulação de imagem (exemplo: photoshop ou software/aplicativo semelhante), com as imagens a seguir:', 'I - foto da fachada do imóvel (caso o imóvel possua mais de uma fachada, deverá ser disponibilizada uma foto de cada fachada onde houver a aplicação da comunicação visual com a marca dos Correios);\nII - foto do hall de atendimento da unidade, tirada da porta principal do imóvel com vista para o interior;\nIII - foto do interior do imóvel com vista para a porta principal;\nIV - foto de frente do módulo de atendimento abarcando a comunicação visual interna; e\nV - foto da área reservada ao desenvolvimento de atividades internas/retaguarda.\nNOTA: a apresentação dos documentos indicados nas alíneas “c” e “d” poderá ser prorrogada, mediante solicitação formal da permissionária aos Correios, desde que demonstrada e fundamentada a necessidade de prazo superior para que os órgãos competentes realizem os trâmites administrativos pertinentes à sua emissão.', 46),
(6910, 'capitulo', 106, 6872, 3, '2.1.19', 'Garantir a presença do representante legal da permissionária, ou pessoa designada por ele, para receber a equipe técnica de implantação do CMD, quando necessária a visita presencial, e acompanhar a verificação dos requisitos do processo seletivo e verificação da existência/manutenção dos critérios de habilitação foco da pontuação auferida no processo de seleção do CMD.', '', 47),
(6911, 'capitulo', 106, 6872, 3, '2.1.20', 'Receber dos Correios uma via do termo de verificação de adequação dos requisitos do processo seletivo da Unidade Modular e marcar, em comum acordo com os Correios, a data de início da operação do CMD.', '', 48),
(6912, 'capitulo', 106, 6872, 3, '2.1.21', 'Realizar a correção dos itens que não estão em conformidade e solicitar nova verificação de adequação aos requisitos do processo seletivo aos correios.', 'NOTA: a emissão do termo de verificação de adequação aos requisitos do processo seletivo com a aprovação ou aprovação com ressalva, que permitirá o início da operação do CMD, está condicionada à realização das atividades preliminares e apresentação dos documentos exigidos no edital.', 49),
(6913, 'capitulo', 106, 6872, 3, '2.1.22', 'Receber e executar os procedimentos orientados pelo(s) profissional(is) dos Correios que irão(á) realizar os procedimentos de operação assistida, seja presencialmente nas instalações do CMD ou on-line.', '', 50),
(6914, 'capitulo', 106, 6871, 2, '2.2', 'Procedimentos do Órgão Regional de Gestão dos Canais de Atendimento Terceirizados', '', 51),
(6915, 'capitulo', 106, 6914, 3, '2.2.1', 'Solicitar, quando necessário, ao órgão corporativo de gestão dos instrumentos dos canais de atendimento terceirizados, esclarecimentos relacionados ao edital, projeto básico e contrato de permissão do CMD, por meio do endereço eletrônico ou outro canal de comunicação fornecido.', '', 52),
(6916, 'capitulo', 106, 6914, 3, '2.2.2', 'Instruir, quando cabível, no Sistema Eletrônico de Informações (SEI), processo administrativo de acompanhamento e gestão do Canal de Atendimento - Correios Aqui - Unidade Modular.', '2.2.2.1 Atribuir ao processo administrativo de acompanhamento e gestão do Canal de Atendimento de que trata o subitem 2.2.2 deste Capítulo a característica de processo restrito, observando a previsão do artigo 31 da Lei 12.527/2011 (Lei de Acesso à Informação).\n2.2.2.2 Conceder acesso ao processo administrativo de acompanhamento e gestão do Canal de Atendimento de que trata o subitem 2.2.2 deste Capítulo aos órgãos corporativos de gestão operacional e administrativa dos canais de atendimento terceirizados.', 53),
(6917, 'capitulo', 106, 6914, 3, '2.2.3', 'Orientar a permissionária quanto aos procedimentos de cadastro de todos os sócios e do(s) representante(s) legal(is) no Sistema Eletrônico de Informação (SEI), para viabilizar a assinatura eletrônica no contrato de permissão do CMD.', 'NOTA: havendo dúvidas quanto a questionamentos relativos ao tema, consultar a área técnica gestora do sistema.', 54),
(6918, 'capitulo', 106, 6914, 3, '2.2.4', 'Providenciar a coleta de assinatura do superintendente estadual e do gerente de atendimento/operações no contrato de permissão.', '', 55),
(6919, 'capitulo', 106, 6914, 3, '2.2.5', 'Encaminhar à permissionária a convocação para assinatura do contrato de permissão do CMD, estabelecendo a data limite de até 5 (cinco) dias úteis, após a data de recebimento da convocação, e:', '', 56),
(6920, 'capitulo', 106, 6919, 4, 'a', 'solicitar a inclusão de cópias da documentação dos sócios, quando essa não tiver sido fornecida anteriormente;', '', 57),
(6921, 'capitulo', 106, 6919, 4, 'b', 'orientar sobre o encaminhamento do formulário de solicitação de capacitação dos empregados envolvidos na operação do CMD; e', '', 58),
(6922, 'capitulo', 106, 6919, 4, 'c', 'informar ao permissionário, considerando o estabelecido no edital do processo de seleção sobre:', 'I - o valor venal do preço de entrada, módulo simples ou duplo a ser recolhido aos Correios, conforme contrato de permissão do CMD; e\nII - a data limite para o pagamento do preço de entrada, sendo em até 5 (cinco) dias úteis antes da data definida para a verificação de adequação aos requisitos do processo seletivo.', 59),
(6923, 'capitulo', 106, 6914, 3, '2.2.6', 'Atentar-se para as disposições apresentadas no instrumento jurídico constitutivo da pessoa jurídica da permissionária quanto à representação legal da empresa, no que tange à assinatura de contratos e demais documentos legais, visando a validade do ato.', '', 60),
(6924, 'capitulo', 106, 6914, 3, '2.2.7', 'Observar os procedimentos relacionados à assinatura do contrato de permissão do CMD, conforme a seguir:', '', 61),
(6925, 'capitulo', 106, 6924, 4, 'a', 'de forma presencial - coletar a assinatura dos sócios da permissionária na ficha de assinatura autorizada das unidades terceirizadas (FW0192/17), disponível na intranet ou conforme procedimento estabelecido pela área técnica responsável;', '', 62),
(6926, 'capitulo', 106, 6924, 4, 'b', 'via sistema eletrônico de informação:', 'I - na ocorrência de assinatura do contrato de permissão do CMD eletronicamente, as assinaturas na ficha de assinatura autorizada das unidades terceirizadas (FW0192/17) deverão ser coletadas quando da verificação da adequação aos requisitos do processo seletivo;\nII - na impossibilidade da coleta de assinatura nos moldes disposto no inciso anterior, o representante legal e o procurador da permissionária deverão registrar sua firma no órgão regional de gestão dos canais de atendimento terceirizados em até 60 (sessenta) dias, sem prejuízo da confirmação da autenticidade pelo representante dos Correios, nos termos da legislação;\nIII - estando qualquer(quaisquer) dos sócios, representante(s) legal(is) em outro estado ou país, poderá registrar/autenticar sua firma em cartório ou órgão reconhecido para essa finalidade e acrescer o documento de reconhecimento no SEI.', 63),
(6927, 'capitulo', 106, 6914, 3, '2.2.8', 'Conceder acesso ao processo administrativo de acompanhamento e gestão de que trata o subitem 2.2.2 deste Capítulo à pessoa jurídica da permissionária.', '', 64),
(6928, 'capitulo', 106, 6914, 3, '2.2.9', 'Definir, em conjunto com as áreas técnicas, os integrantes da equipe técnica de Implantação, a qual deverá ser composta de profissionais que detenham conhecimento e habilidades para realizar as seguintes atribuições:', '', 65),
(6929, 'capitulo', 106, 6928, 4, 'a', 'coordenar a equipe técnica de implantação;', '', 66),
(6930, 'capitulo', 106, 6928, 4, 'b', 'realizar as atividades relativas a tecnologia da informação previstas no projeto básico e no contrato de permissão do CMD; e', '', 67),
(6931, 'capitulo', 106, 6928, 4, 'c', 'operacionalizar o(s) sistema(s) de automação do atendimento e outros necessários à execução operacional do objeto do contrato de permissão do CMD.', '', 68),
(6932, 'capitulo', 106, 6914, 3, '2.2.10', 'Informar ao permissionário os dados de contato (nome, e-mail e telefone), do profissional responsável pela coordenação da equipe técnica de implantação e do ponto focal nos Correios ao longo do processo de realização das atividades preliminares.', '', 69),
(6933, 'capitulo', 106, 6914, 3, '2.2.11', 'Realizar as comunicações com a permissionária por meio do sistema eletrônico de informações ou outro sistema que vier a substituí-lo.', '2.2.11.1 Digitalizar e inserir no processo administrativo de gestão do CMD as correspondências físicas e/ou e-mails, eventualmente, emitidos ou recebidos por outros meios que não o SEI.', 70),
(6934, 'capitulo', 106, 6914, 3, '2.2.12', 'Orientar ao(s) permissionário(s) em até 5 (cinco) dias úteis, contados a partir do recebimento da comunicação relativa a dúvidas ou pedido de informações. Cabendo prorrogação por igual período ou suspensão do prazo mediante justificativa técnica registrada no sistema eletrônico de informações.', '', 71),
(6935, 'capitulo', 106, 6914, 3, '2.2.13', 'Devolver o prazo ao permissionário nas situações previstas no contrato, no projeto básico, normativo interno ou legislação, desde que devidamente justificado nos autos do processo administrativo de gestão do CMD.', '', 72),
(6936, 'capitulo', 106, 6914, 3, '2.2.14', 'Receber da permissionária a solicitação da verificação de adequação dos requisitos do processo seletivo.', '', 73),
(6937, 'capitulo', 106, 6914, 3, '2.2.15', 'Viabilizar junto aos órgãos competentes as ações necessárias para o deslocamento e a hospedagem dos profissionais dos Correios que irão realizar a verificação da adequação aos requisitos do processo seletivo para instalação do CMD, quando não for possível realizar remotamente.', '', 74),
(6938, 'capitulo', 106, 6914, 3, '2.2.16', 'Definir, em conjunto com as áreas técnicas, os profissionais que irão realizar a operação assistida do CMD, conforme a seguir:', '', 75),
(6939, 'capitulo', 106, 6938, 4, 'a', 'operação assistida in loco - poderá ocorrer a partir do primeiro dia de funcionamento do CMD e se estender nos dias úteis subsequentes até o fechamento da semana em que ocorrer a inauguração; e', '', 76),
(6940, 'capitulo', 106, 6938, 4, 'b', 'operação assistida à distância - poderá ocorrer a partir do encerramento da operação assistida in loco até o encerramento do primeiro mês subsequente à inauguração da unidade, consistindo no acompanhamento da sua performance diária e na prestação de assistência à execução do objeto do contrato.', 'NOTA 1: o acompanhamento deverá ser realizado em consonância com os indicadores comerciais, de qualidade operacional e de gestão inerentes à execução contratual.\nNOTA 2: a operação assistida in loco poderá ser convertida em acompanhamento remoto, desde que a respectiva área técnica autorize, oriente e acompanhe a operacionalização da atividade.', 77),
(6941, 'capitulo', 106, 6914, 3, '2.2.17', 'Priorizar na escolha dos profissionais que participarão da equipe técnica de implantação, quando necessária a operação assistida in loco, observando obrigatoriamente, a proximidade entre o órgão de lotação do(s) empregado(s) e localidade onde estará instalado o CMD, de forma a minimizar custos com deslocamento, diárias e hospedagem.', '', 78),
(6942, 'capitulo', 106, 6914, 3, '2.2.18', 'Providenciar o cadastro da unidade no sistema de suprimento autorizado para o modelo.', '', 79),
(6943, 'capitulo', 106, 6914, 3, '2.2.19', 'Auxiliar o permissionário na realização da solicitação de suprimento inicial da unidade, conforme projeto básico do canal e observando o prazo mínimo para que a data de solicitação de suprimento seja suficiente para que os produtos e insumos previstos, sejam recebidos na unidade até a data anterior marcada para a verificação aos requisitos do processo seletivo.', '', 80),
(6944, 'capitulo', 106, 6914, 3, '2.2.20', 'Viabilizar, antes da data marcada para a verificação de adequação aos requisitos do processo seletivo, o cadastramento dos profissionais do CMD nos sistemas necessários para operacionalização da unidade, tais como:', '', 81),
(6945, 'capitulo', 106, 6944, 4, 'a', 'Helpdesk - habilitação do gestor da unidade no sistema;', '', 82),
(6946, 'capitulo', 106, 6944, 4, 'b', 'Sistema de Gerenciamento de Mensagem (SGM) - habilitação dos profissionais da unidade que irão realizar o atendimento; e', '', 83),
(6947, 'capitulo', 106, 6944, 4, 'c', 'Sistema de Automação do Atendimento - habilitação dos profissionais da unidade que irão realizar o atendimento, serviços internos, gestão financeira e administrativa.', 'NOTA: a lista acima é exemplificativa, devendo ser realizado o cadastro da unidade em todos os sistemas necessários para o funcionamento do CMD.', 84),
(6948, 'capitulo', 106, 6914, 3, '2.2.21', 'Informar à permissionária, com no mínimo 10 (dez) dias de antecedência, a data definida para a realização da verificação da adequação aos requisitos do processo seletivo e da verificação dos critérios de pontuação técnica do CMD, contemplando no conteúdo do documento:', '', 85),
(6949, 'capitulo', 106, 6948, 4, 'a', 'solicitação de acompanhamento do procedimento pelo representante legal da permissionária, ou pessoa por ele designada, para verificação dos itens que compõe o termo de adequação aos requisitos do processo seletivo, o termo de verificação da existência/manutenção dos critérios de pontuação técnica do CMD e assinatura dos respectivos documentos;', '', 86),
(6950, 'capitulo', 106, 6948, 4, 'b', 'ratificação da necessidade de disponibilização dos documentos relacionados no instrumento contratual; e', '', 87),
(6951, 'capitulo', 106, 6948, 4, 'c', 'orientação para que a permissionária realize uma autoavaliação, antes da data marcada para verificação de adequação aos requisitos do processo seletivo.', 'NOTA: a verificação aos requisitos do processo seletivo poderá ser feita presencialmente, remotamente ou semipresencial, a depender da orientação a ser emitida pelo órgão corporativo de gestão administrativa dos canais de atendimento terceirizados.', 88),
(6952, 'capitulo', 106, 6914, 3, '2.2.22', 'Receber do permissionário solicitação de postergação de prazo para finalização das atividades preliminares, conforme disposto no projeto básico do Canal Correios Aqui - Unidade Modular (CMD).', '2.2.22.1  Analisar a justificativa presente no documento.\n2.2.22.2  Adotar os seguintes procedimentos:', 89),
(6953, 'capitulo', 106, 6952, 4, 'a', 'sendo acatados os argumentos/justificativas e deferido o pedido de prorrogação:', 'I - postergar o prazo, consoante as disposições previstas no projeto básico e no contrato; e\nII - comunicar à permissionária a decisão tomada.', 90),
(6954, 'capitulo', 106, 6952, 4, 'b', 'não sendo acatados os argumentos/justificativas e não sendo deferido o pedido de prorrogação:', 'I - considerar o prazo inicial, consoante as disposições previstas no projeto básico e contrato;\nII - comunicar à permissionária a decisão tomada;\nIII - emitir a notificação pela perda de prazo de cumprimento das atividades preliminares, informando o valor da sanção pecuniária a ser recolhida em até 5 (cinco) dias úteis, contados a partir do recebimento da comunicação, considerando os procedimentos definidos no instrumento contratual;\nIV - o comprovante de depósito da sanção pecuniária deverá ser disponibilizado no sistema eletrônico de informações pela permissionária em até 5 (cinco) dias úteis, contados da data de seu pagamento, ou no mesmo prazo encaminhado ao endereço eletrônico definido pelo gestor regional dos canais de atendimento terceirizados;\nV - a ausência do pagamento da sanção pecuniária de que trata o item acima será impeditivo para a realização da verificação de adequação dos requisitos do processo seletivo.', 91),
(6955, 'capitulo', 106, 6914, 3, '2.2.23', 'Comunicar antecipadamente a permissionária quando houver qualquer infortúnio que impeça a realização da verificação de adequação aos requisitos do processo seletivo, definindo nova data para sua realização.', '', 92),
(6956, 'capitulo', 106, 6914, 3, '2.2.24', 'Solicitar, ao órgão corporativo financeiro, a informação relativa ao pagamento do preço de entrada do CMD na conta dos Correios, realizando, quando for o caso, os seguintes procedimentos:', '', 93),
(6957, 'capitulo', 106, 6956, 4, 'a', 'verificar junto à permissionária e solicitar cópia do comprovante de depósito, via sistema eletrônico de informação ou sistema informado, caso não seja identificado o crédito para os Correios;', '', 94),
(6958, 'capitulo', 106, 6956, 4, 'b', 'ratificar à permissionária de que não poderá ser autorizado o início da operação do CMD antes da comprovação do pagamento do preço de entrada, mesmo que as demais atividades preliminares estejam finalizadas.', '', 95),
(6959, 'capitulo', 106, 6914, 3, '2.2.25', 'Realizar a verificação de adequação aos requisitos do processo seletivo, coordenando:', '', 96),
(6960, 'capitulo', 106, 6959, 4, 'a', 'o preenchimento do termo de verificação de adequação aos requisitos do processo seletivo pelos profissionais que compõem a equipe técnica de Implantação ;', '', 97),
(6961, 'capitulo', 106, 6959, 4, 'b', 'a assinatura do termo pelos componentes da equipe técnica de implantação e pelos representantes da permissionária;', '', 98),
(6962, 'capitulo', 106, 6959, 4, 'c', 'a disponibilização de uma via dos termos supramencionados à permissionária;', '', 99),
(6963, 'capitulo', 106, 6959, 4, 'd', 'gerar documentação complementar ou notificações, quando cabível, relativa ao processo de implantação.', '', 100),
(6964, 'capitulo', 106, 6914, 3, '2.2.26', 'Receber a documentação apresentada pela permissionária à equipe técnica de implantação e realizar os seguintes procedimentos:', '', 101),
(6965, 'capitulo', 106, 6964, 4, 'a', 'conferir e verificar se constam todos os documentos dos sócios, solicitando os faltantes quando for o caso;', '', 102),
(6966, 'capitulo', 106, 6964, 4, 'b', 'adotar as providências necessárias para complementação do cadastro de órgãos;', '', 103),
(6967, 'capitulo', 106, 6964, 4, 'c', 'enviar ao polo de educação as informações dos profissionais do CMD que irão participar da capacitação (nome completo, CPF e o perfil de atuação indicado no anexo de solicitação de capacitação); e', '', 104),
(6968, 'capitulo', 106, 6964, 4, 'd', 'disponibilizar a documentação no Sistema Eletrônico de Informação (SEI).', '', 105),
(6969, 'capitulo', 106, 6871, 2, '2.3', 'Procedimentos do Órgão de Gestão Corporativa de Operações Financeiras', '', 106),
(6970, 'capitulo', 106, 6969, 3, '2.3.1', 'Receber consulta do órgão regional de gestão dos canais de atendimento terceirizados sobre o crédito na conta dos Correios relativo ao preço de entrada do CMD e/ou das sanções pecuniárias aplicadas na fase de cumprimento das atividades preliminares, respondendo formalmente aos termos da consulta.', '', 107),
(6971, 'capitulo', 106, 6969, 3, '2.3.2', 'Subsidiar o órgão regional de gestão dos canais de atendimento terceirizados nas respostas aos questionamentos realizados pela permissionária sobre procedimento sob gestão da área financeira.', '', 108),
(6972, 'capitulo', 106, 6871, 2, '2.4', 'Procedimentos do Órgão Regional de Tecnologia da Informação', '', 109),
(6973, 'capitulo', 106, 6972, 3, '2.4.1', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados solicitação de apoio técnico e/ou disponibilização de profissional para realização de orientações e/ou verificação à adequação aos requisitos do processo seletivo.', '', 110),
(6974, 'capitulo', 106, 6972, 3, '2.4.2', 'Viabilizar o comparecimento de profissional, quando assim definido, nas instalações do Canal de Atendimento Correios Aqui - Unidade Modular (CMD) na data e horário previstos.', '', 111),
(6975, 'capitulo', 106, 6972, 3, '2.4.3', 'Verificar os requisitos relativos a tecnologia da informação especificados no termo de verificação de adequação aos requisitos do processo seletivo, preenchendo e assinando o respectivo documento.', '', 112),
(6976, 'capitulo', 106, 6972, 3, '2.4.4', 'Prestar informações e/ou orientações ao órgão regional de gestão dos canais de atendimento terceirizados e ao permissionário, quando for o caso, relativas aos itens de tecnologia da informação que compõe as atividades preliminares.', '', 113),
(6977, 'capitulo', 106, 6871, 2, '2.5', 'Procedimentos do Órgão Corporativo de Gestão dos Instrumentos dos Canais de Atendimento Terceirizados', '', 114),
(6978, 'capitulo', 106, 6977, 3, '2.5.1', 'Orientar aos órgão regionais de gestão dos canais de atendimento terceirizados sobre o início do processo administrativo de acompanhamento e gestão do Canal de Atendimento Terceirizado - Correios Aqui - Unidade Modular.', '', 115),
(6979, 'capitulo', 106, 6977, 3, '2.5.2', 'Receber as solicitações de esclarecimentos do órgão regional de gestão dos canais de atendimento terceirizados, relacionados ao edital, projeto básico e contrato de permissão do CMD.', '', 116),
(6980, 'capitulo', 106, 6977, 3, '2.5.3', 'Responder aos questionamentos em até 5 (cinco) dias úteis, contados da data de recebimento da solicitação, podendo ser prorrogado diante da complexidade da análise.', '', 117),
(6981, 'capitulo', 106, 6871, 2, '2.6', 'Procedimentos do Órgão Regional de Educação', '', 118),
(6982, 'capitulo', 106, 6981, 3, '2.6.1', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados a solicitação de capacitação dos profissionais do CMD.', '', 119),
(6983, 'capitulo', 106, 6981, 3, '2.6.2', 'Informar que o acesso ao ambiente virtual de aprendizado será realizado por meio da conta da extranet (CPF e senha de rede).', '', 120),
(6984, 'capitulo', 106, 6981, 3, '2.6.3', 'Disponibilizar as capacitações necessárias à operação do CMD, em consonância com o objeto do contrato de permissão.', '', 121),
(6985, 'capitulo', 106, 6981, 3, '2.6.4', 'Disponibilizar relatórios de participação dos empregados do CMD, conforme demanda.', '', 122),
(6986, 'capitulo', 106, 6871, 2, '2.7', 'Procedimentos do Órgão Regional de Tratamento e Distribuição', '', 123),
(6987, 'capitulo', 106, 6986, 3, '2.7.1', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados a comunicação quanto à instalação e inauguração do CMD.', '', 124),
(6988, 'capitulo', 106, 6986, 3, '2.7.2', 'Estabelecer o plano de triagem a ser seguido pelo CMD, que para o modelo não ultrapasse 6 (seis) direções.', '', 125),
(6989, 'capitulo', 106, 6986, 3, '2.7.3', 'Adotar as providências cabíveis relativas à coleta/entrega de carga no CMD.', '', 126),
(6990, 'capitulo', 106, 6871, 2, '2.8', 'Procedimentos do Órgão Regional de Engenharia', '', 127),
(6991, 'capitulo', 106, 6990, 3, '2.8.1', 'Receber, do órgão regional de gestão dos canais de atendimento terceirizados, solicitação de apoio técnico e/ou disponibilização de profissional para realização de orientações e/ou verificação à adequação aos requisitos do processo seletivo.', '', 128),
(6992, 'capitulo', 106, 6990, 3, '2.8.2', 'Viabilizar o comparecimento de profissional, quando assim definido, nas instalações do Canal de Atendimento Correios Aqui - Unidade Modular (CMD) na data e horário previstos.', '', 129),
(6993, 'capitulo', 106, 6990, 3, '2.8.3', 'Analisar a conformidade dos itens relativos a infraestrutura especificados no termo de verificação de adequação aos requisitos do processo seletivo.', '', 130),
(6994, 'capitulo', 106, 6990, 3, '2.8.4', 'Prestar informações e/ou orientações ao órgão regional de gestão dos canais de atendimento terceirizados relativas às demandas de engenharia/infraestrutura.', '* * * * *', 131),
(6995, 'anexo', 1, NULL, 1, '2', 'DINEG	DIREX	DINEG', 'Anexo 7	DEFIS	DIOPE	DIOPE\nAnexo 9	DEFIS	DINEG	DINEG\nAnexo 13	DEPRO	DINEG	DINEG\nAnexos 15, 16 e 18	DEFIS	DINEG	DINEG\nAnexos 20 e 24	DEPRO	DINEG	DINEG\nAnexo 25	DEFIS	DINEG	DINEG\nAnexo 28	DEDIG	DINEG	DINEG\nAnexo 30	DECOM	DIGOE	DIGOE\n3	1	DEPRO	DINEG	DINEG', 0),
