(6997, 'anexo', 1, NULL, 1, '2', 'DEPRO	DINEG	DINEG', '', 2),
(6998, 'anexo', 1, NULL, 1, '5', 'DEPRO	DINEG	DINEG', '6	1	DEPRO	DINEG	DINEG\nAnexos 1 a 3	DEPRO	DINEG	DINEG\nAnexo 4	DPREC	DINEG	DINEG\nAnexo 5	DEPRO	DINEG	DINEG\n2 a 4, 6 a 11, 13, 14,\n16 a 29	DEPRO	DINEG	DINEG\n7	1, 2, 4, 5, 7 a 10,\n12 a 16	DEPRO	DINEG	DINEG\n8	1, 4, 5, 6, 9 e 12	DEPRO	DINEG	DINEG\n21 a 23	DEFIS	DINEG	DINEG\n24 e 25	DEPRO	DINEG	DINEG\n9	1	DEPRO	DINEG	DINEG\n10	2 	DEPRO	DINEG	DINEG', 3),
