(8287, 'anexo', 102, NULL, 1, '1', 'DEFINIÇÃO', '', 0),
(8288, 'anexo', 102, 8287, 2, '1.1', 'O e-Carta é uma solução de comunicação formal híbrida que une plataformas digitais para a captação, processamento e mesclagem de arquivos eletrônicos, e aspectos físicos, englobando a impressão, o acabamento, o tratamento, a distribuição e a entrega das mensagens. O serviço se desdobra em três modalidades, cada qual adaptada a diferentes necessidades: e-Carta Fácil, e-Carta Transmissão e e-Carta Integração.', '', 1),
(8289, 'anexo', 102, NULL, 1, '2', 'ARGUMENTO DE VENDA', '', 2),
(8290, 'anexo', 102, 8289, 2, '2.1', 'Apresentar o e-Carta como a opção ideal para órgãos governamentais, empresas privadas e setores diversos em busca de:', '', 3),
(8291, 'anexo', 102, 8290, 4, 'a', 'Eficiência e Modernização: utilização de plataformas digitais para captação, processamento e mesclagem de arquivos eletrônicos, proporcionando agilidade na comunicação formal;', '', 4),
(8292, 'anexo', 102, 8290, 4, 'b', 'Segurança da Informação: garantia da proteção adequada aos dados transmitidos, assegurando a confidencialidade das informações;', '', 5),
(8293, 'anexo', 102, 8290, 4, 'c', 'Alinhamento Digital: Adequação às expectativas do mercado na transformação digital, mantendo-se atualizado e competitivo;', '', 6),
(8294, 'anexo', 102, 8290, 4, 'd', 'Flexibilidade de Modelos: personalização de leiautes conforme necessidade da comunicação, oferecendo versatilidade no formato das mensagens;', '', 7),
(8295, 'anexo', 102, 8290, 4, 'e', 'Sustentabilidade: redução do consumo de papel, promovendo práticas sustentáveis e contribuindo para a preservação do meio ambiente;', '', 8),
(8296, 'anexo', 102, 8290, 4, 'f', 'Unificação de Fornecedores: utilização dos Correios como único fornecedor para impressão, envelopamento, postagem e distribuição de mensagens, simplificando o processo e proporcionando maior controle e eficiência.', '', 9),
(8297, 'anexo', 102, NULL, 1, '3', 'ESPECIFICAÇÕES E ATRIBUTOS', '', 10),
(8298, 'anexo', 102, 8297, 2, '3.1', 'Modalidades:', '', 11),
(8299, 'anexo', 102, 8298, 4, 'a', 'e-Carta Fácil: direcionado a pequenos e médios volumes, destaca-se pela simplicidade do processo de envio, utilizando o Sistema de Mensagens Telemáticas - SMT para integração via WebService ou uso simplificado via Web;', '', 12),
(8300, 'anexo', 102, 8298, 4, 'b', 'e-Carta Transmissão: voltado para médios volumes de postagem, oferece flexibilidade na personalização de leiautes sem a necessidade de sistemas, com envio dos arquivos para produção utilizando ferramenta segura de transferência de arquivos validada pelos Correios;', '', 13),
(8301, 'anexo', 102, 8298, 4, 'c', 'e-Carta Integração: destaca-se pela integração com sistemas internos dos clientes, personalização avançada de leiautes e eficiência para grandes volumes, utilizando o sistema e-Carta via ferramenta segura de transferência de arquivos validada pelos Correios.', '', 14),
(8302, 'anexo', 102, 8297, 2, '3.2', 'Atributos inerentes aos objetos Simples, Registrados e Registrados com AR:', '', 15),
(8303, 'anexo', 102, 8302, 4, 'a', 'captação eletrônica dos dados;', '', 16),
(8304, 'anexo', 102, 8302, 4, 'b', 'tratamento de dados;', '', 17),
(8305, 'anexo', 102, 8302, 4, 'c', 'impressão;', '', 18),
(8306, 'anexo', 102, 8302, 4, 'd', 'envelopamento;', '', 19),
(8307, 'anexo', 102, 8302, 4, 'e', 'franqueamento;', '', 20),
(8308, 'anexo', 102, 8302, 4, 'f', 'postagem;', '', 21),
(8309, 'anexo', 102, 8302, 4, 'g', 'encaminhamento e tratamento em âmbito nacional;', '', 22),
(8310, 'anexo', 102, 8302, 4, 'h', 'distribuição;', '', 23),
(8311, 'anexo', 102, 8302, 4, 'i', 'papel A4 e envelopes;', '', 24),
(8312, 'anexo', 102, 8302, 4, 'j', 'Entrega Digital via App Correios (funcionalidade “Minhas Mensagens”)¹.', '¹ exclusivo para a modalidade e-Carta Integração.', 25),
(8313, 'anexo', 102, 8297, 2, '3.3', 'Atributos inerentes específicos aos objetos Registrados: registro nNacional', '', 26),
(8314, 'anexo', 102, 8297, 2, '3.4', 'Atributos inerentes específicos aos objetos Registrados com AR:', '', 27),
(8315, 'anexo', 102, 8314, 4, 'a', 'Registro Nacional;', '', 28),
(8316, 'anexo', 102, 8314, 4, 'b', 'AR Eletrônico ou Convencional, para o e-Carta Fácil;', '', 29),
(8317, 'anexo', 102, 8314, 4, 'c', 'AR Digital, para e-Carta Integração ou e-Carta Transmissão.', '', 30),
(8318, 'anexo', 102, 8297, 2, '3.5', 'Serviços adicionais com ônus:', '', 31),
(8319, 'anexo', 102, 8318, 4, 'a', 'Mão Própria - MP (exceto para objetos Simples);', '', 32),
(8320, 'anexo', 102, 8318, 4, 'b', 'Interrupção do Tratamento Eletrônico¹;', '', 33),
(8321, 'anexo', 102, 8318, 4, 'c', 'Interrupção da Produção das Mensagens¹;', '', 34),
(8322, 'anexo', 102, 8318, 4, 'd', 'Armazenamento Lógico (mês adicional)²;', '', 35),
(8323, 'anexo', 102, 8318, 4, 'e', 'Armazenamento Físico (mês adicional)².', '¹ exclusivo para a modalidade e-Carta Integração e e-Carta Transmissão.\n² exclusivo para a modalidade e-Carta Integração e disponível apenas para Objetos Registrados com AR Digital e limitado a 5 (cinco) meses.', 36),
(8324, 'anexo', 102, NULL, 1, '4', 'PÚBLICO-ALVO', '', 37),
(8325, 'anexo', 102, 8324, 2, '4.1', 'Público-alvo por modalidade:', '', 38),
(8326, 'anexo', 102, 8325, 4, 'a', 'e-Carta Fácil - A faturar: empresas e órgãos governamentais que precisam enviar pequenos e médios lotes de postagem, priorizando a simplicidade do processo e necessitando de acesso fácil e direto para múltiplos usuários;', '', 39),
(8327, 'anexo', 102, 8325, 4, 'b', 'e-Carta Fácil - À vista: pessoas físicas, microempresas e pequenas empresas que buscam uma solução acessível e econômica para o envio de documentos e informações importantes, valorizando a segurança e a flexibilidade de realizar envios pontuais, sem a necessidade de formalizar contratos corporativos.', '', 40),
(8328, 'anexo', 102, 8325, 4, 'c', 'e-Carta Transmissão: empresas e órgãos governamentais que valorizam a flexibilidade na personalização de leiautes e processamento eficiente para médios e grandes volumes de postagem, mas que possuem alta sazonalidade de postagem e/ou dificuldades tecnológicas para integração de sistemas;', '', 41),
(8329, 'anexo', 102, 8325, 4, 'd', 'e-Carta Integração: empresas e órgãos governamentais que buscam agilidade no envio e controle de arquivos para produção, têm estrutura para suportar e usufruir de integrações sistêmicas e valorizam a flexibilidade na personalização de leiautes e processamento eficiente para grandes volumes de postagem.', '', 42),
(8330, 'anexo', 102, 8324, 2, '4.2', 'Principais Segmentos de Mercado:', '', 43),
(8331, 'anexo', 102, 8330, 4, 'a', 'Trânsito e Judiciário;', '', 44),
(8332, 'anexo', 102, 8330, 4, 'b', 'Governo Federal, Municipal e Estadual;', '', 45),
(8333, 'anexo', 102, 8330, 4, 'c', 'Serviços Técnicos Especializados;', '', 46),
(8334, 'anexo', 102, 8330, 4, 'd', 'Conselhos, Ordens de Classe e Associações Públicas;', '', 47),
(8335, 'anexo', 102, 8330, 4, 'e', 'Financeiras, Seguros, Cobrança e Previdência;', '', 48),
(8336, 'anexo', 102, 8330, 4, 'f', 'Prestação de Serviços de Saúde;', '', 49),
(8337, 'anexo', 102, 8330, 4, 'g', 'Bancos e Administradoras de Cartões.', '', 50),
(8338, 'anexo', 102, NULL, 1, '5', 'ABRANGÊNCIA', '', 51),
(8339, 'anexo', 102, 8338, 2, '5.1', 'A definição e comunicação da abrangência de Produção e Postagem dos objetos e-Carta, que será executada operacionalmente pelos CDIP/UP, é responsabilidade do Departamento de Gestão Técnica dos Centros e Unidades de Produção, que deve priorizar a descentralização, com base nos seguintes aspectos operacionais:', '', 52),
(8340, 'anexo', 102, 8339, 4, 'a', 'CEP de destino, somente para as modalidades que possuírem capacidade tecnológica para distribuição automática dos lotes/objetos;', '', 53),
(8341, 'anexo', 102, 8339, 4, 'b', 'linhas de transporte com menor prazo e custo de encaminhamento;', '', 54),
(8342, 'anexo', 102, 8339, 4, 'c', 'capacidade produtiva dos Centros/Unidades;', '', 55),
(8343, 'anexo', 102, 8339, 4, 'd', 'SE de Origem mais próxima do Centro/Unidade de Produção.', '', 56),
(8344, 'anexo', 102, 8338, 2, '5.2', 'Quanto à entrega, os objetos e-Carta tem abrangência Nacional.', '', 57),
(8345, 'anexo', 102, NULL, 1, '6', 'PREÇOS', '', 58),
(8346, 'anexo', 102, 8345, 2, '6.1', 'Para definição do preço do serviço contratado, consideram-se a quantidade de páginas a serem produzidas por mensagem e o volume de postagem negociado.', '', 59),
(8347, 'anexo', 102, 8345, 2, '6.2', 'Há diferenciação de preços de acordo com a modalidade utilizada e com o faturamento, alinhado às tabelas cadastradas no pacote correspondente, conforme Termo de Condições Comerciais vigente.', '', 60),
(8348, 'anexo', 102, NULL, 1, '7', 'PRAZOS', '', 61),
(8349, 'anexo', 102, 8348, 2, '7.1', 'Os prazos referentes ao produto estão disponíveis no MANNEG 6/3.', '', 62),
(8350, 'anexo', 102, NULL, 1, '8', 'ATENDIMENTO', '', 63),
(8351, 'anexo', 102, 8350, 2, '8.1', 'Condições de Aceitação:', '', 64),
(8352, 'anexo', 102, 8351, 4, 'a', 'mensagens monocromáticas impressas na cor preta e suas tonalidades (cinza, etc);', '', 65),
(8353, 'anexo', 102, 8351, 4, 'b', 'mensagens produzidas na folha tamanho A4;', '', 66),
(8354, 'anexo', 102, 8351, 4, 'c', 'quantidades mínimas e máximas, conforme itens 8.6, 8.7 e 8.8 deste documento;', '', 67),
(8355, 'anexo', 102, 8351, 4, 'd', 'auto envelopamento de objetos simplex (com até 2 páginas);', '', 68),
(8356, 'anexo', 102, 8351, 4, 'e', 'auto envelopamento de objetos Multiplex (de 3 a 10 páginas);', '', 69),
(8357, 'anexo', 102, 8351, 4, 'f', 'inserção manual em envelope de objetos que variam de 11 a 200 páginas.', '', 70),
(8358, 'anexo', 102, 8350, 2, '8.2', 'Modalidades de Pagamento e Canais de acesso:', '', 71),
(8359, 'anexo', 102, 8358, 4, 'a', 'e-Carta Integração: A faturar - Sistema e-Carta;', '', 72),
(8360, 'anexo', 102, 8358, 4, 'b', 'e-Carta Transmissão: A faturar - Ferramenta de Transferência de Arquivos (EDI);', '', 73),
(8361, 'anexo', 102, 8358, 4, 'c', 'e-Carta Fácil: A faturar - SMT Web (https://apps.correios.com.br/smt/#/home) e WS; À vista - App Correios e SMT À Vista (https://smt-avista.correios.com.br/).', '', 74),
(8362, 'anexo', 102, 8350, 2, '8.3', 'A configuração da operação para o cliente do e-Carta Integração e Transmissão, também denominada “Desenvolvimento de Formulários”, consiste na criação de layouts personalizados para atender às necessidades específicas dos clientes, que poderão utilizar as matrizes (formulários) desenvolvidas para impressão de suas mensagens.', '', 75),
(8363, 'anexo', 102, 8350, 2, '8.4', 'As regras técnicas para utilização do serviço (integrações sistêmicas, envio de arquivos eletrônicos para impressão, recebimento de arquivos de retorno e demais informações) estão detalhadas nas Matrizes de Regras, disponíveis na Intranet da Gestão do Produto (https://c.correios.com.br/deprocomunicacao-docs).', '', 76),
(8364, 'anexo', 102, 8350, 2, '8.5', 'Limites Mínimos de Objetos por Postagem:', '', 77),
(8365, 'anexo', 102, 8364, 4, 'a', 'e-Carta Fácil, Transmissão e Integração: Sem postagem mínima;', '', 78),
(8366, 'anexo', 102, 8364, 4, 'b', 'e-Carta Integração | Postagem Industrial Simples: Mínimo de 1.000 objetos;', '', 79),
(8367, 'anexo', 102, 8364, 4, 'c', 'e-Carta Integração | Postagem Industrial Registrados: Mínimo de 100 objetos.', '', 80),
(8368, 'anexo', 102, 8350, 2, '8.6', 'Limites Máximos de Folhas por Objeto:', '', 81),
(8369, 'anexo', 102, 8368, 4, 'a', 'e-Carta Fácil: Máximo de 5 folhas;', '', 82),
(8370, 'anexo', 102, 8368, 4, 'b', 'e-Carta Transmissão e e-Carta Integração Simples: Máximo de 5 folhas;', '', 83),
(8371, 'anexo', 102, 8368, 4, 'c', 'e-Carta Transmissão e e-Carta Integração Registrado: Máximo de 100 folhas;', '', 84),
(8372, 'anexo', 102, 8368, 4, 'd', 'e-Carta Transmissão e e-Carta Integração Registrado com AR: Máximo de 100 folhas.', '', 85),
(8373, 'anexo', 102, 8350, 2, '8.7', 'Limites Máximos de Objetos por Lote:', '', 86),
(8374, 'anexo', 102, 8373, 4, 'a', 'e-Carta Fácil Via Web: Máximo de 200 objetos por lote;', '', 87),
(8375, 'anexo', 102, 8373, 4, 'b', 'e-Carta Fácil Via WebServices: Máximo de 1.000 objetos por lote;', '', 88),
(8376, 'anexo', 102, 8373, 4, 'c', 'e-Carta Transmissão: Sem Postagem Mínima;', '', 89),
(8377, 'anexo', 102, 8373, 4, 'd', 'e-Carta Integração: Conforme Matriz de Regras.', '', 90),
(8378, 'anexo', 102, NULL, 1, '9', 'ENTREGA E DEVOLUÇÃO', '', 91),
(8379, 'anexo', 102, 8378, 2, '9.1', 'Para objetos registrados, o cliente tem a opção de solicitar a devolução imediata após a terceira tentativa de entrega. Para isso, é necessário informar da opção ao CDIP, durante o desenvolvimento da Matriz de impressão (e-Carta Integração e Transmissão), a fim de possibilitar a inclusão da menção à devolução imediata no objeto em local externo/visível.', '', 92),
(8380, 'anexo', 102, NULL, 1, '10', 'PÓS VENDAS', '', 93),
(8381, 'anexo', 102, 8380, 2, '10.1', 'Situações relacionadas ao processo de captação e tratamento de manifestação de clientes para objetos e-Carta Registrados devem seguir os procedimentos e diretrizes estabelecidos no MANCAN 7, além de orientações específicas para o suporte pós-vendas.', '', 94),
(8382, 'anexo', 102, 8380, 2, '10.2', 'Indenizações por extravio, espoliação, avaria (total ou parcial) e atraso na entrega (exceto na modalidade e-Carta Simples) estão previstas de acordo com as regras especificadas no MANCAT 6/1 - Anexo 6.', '', 95),
(8383, 'anexo', 102, 8380, 2, '10.3', 'Em situações que envolvam questões técnicas referentes à integração de sistemas, transmissão e recebimento de arquivos, modificações nas matrizes e compreensão/aplicação das regras, é necessário acionar a equipe de Suporte ao Negócio do CDIP correspondente para obter assistência em colaboração com a equipe comercial, que é responsável por intermediar as negociações.', '', 96),
(8384, 'anexo', 102, NULL, 1, '11', 'DOCUMENTAÇÃO TÉCNICA', '', 97),
(8385, 'anexo', 102, 8384, 2, '11.1', 'Regras técnicas não contempladas neste documento ou nas Matrizes de Regras das modalidades e demais documentos complementares estão sujeitas à análise da gestão do produto e/ou da gestão técnica-operacional dos centros e unidades responsáveis pela sua operacionalização.', '', 98),
(8386, 'anexo', 102, 8384, 2, '11.2', 'A ficha técnica do e-Carta, juntamente com as Matrizes de Regras e documentos técnicos complementares, estarão disponíveis na Intranet da Gestão do Produto, link https://c.correios.com.br/deprocomunicacao-docs, sujeitos a atualizações conforme necessidade do produto.', '', 99),
(8387, 'anexo', 102, 8384, 2, '11.3', 'Qualquer modificação sistêmica relacionada ao e-Carta que possa causar impactos operacionais e/ou comerciais deve ser previamente analisada pela gestão do produto e registrada nos documentos técnicos correspondentes, com comunicação prévia às áreas envolvidas.', '', 100),
(8388, 'anexo', 102, 8384, 2, '11.4', 'Quando possível, é necessário comunicar com antecedência mínima de 15 (quinze) dias úteis sobre ajustes que possam afetar a parametrização de sistemas e a operação interna dos clientes, antes da efetivação da alteração.', '* * * * *', 101),
(8389, 'anexo', 103, NULL, 1, '1', 'OBJETIVOS', '1.1 Fornecer diretrizes detalhadas para a execução dos procedimentos específicos relacionados à modalidade e-Carta Integração. Este anexo não substitui as definições estabelecidas em seu Capítulo principal, sendo um complemento deste.', 0);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(8390, 'anexo', 103, NULL, 1, '2', 'DESCRIÇÃO DOS PROCEDIMENTOS ESPECÍFICOS', '2.1 Prospecção, Comercialização e Suporte ao Cliente (Força de Vendas)\n2.1.1 Preencher a planilha de Solicitação de Viabilidade de Comercialização, antes de preencher a Ficha Técnica, e:\na) enviar por e-mail ao Centro de Digitalização e Produção de Objetos Postais - CDIP de abrangência para volumes diários entre 5.000 e 20.000 de objetos com até 2 (duas) páginas; ou\nb) enviar por e-mail ao CDIP de abrangência para volumes diários entre 2.000 e 10.000 de objetos com 3 (três) páginas ou mais.\nNota: a solicitação de análise de viabilidade deve ser enviada imediatamente após a conclusão do item 2.1.1.9 do Capítulo principal deste anexo. Essa solicitação será usada para definir e otimizar os recursos necessários para atender às necessidades do cliente.\n2.1.2 Solicitar ao CDIP de abrangência o cronograma do processo de Desenvolvimento de Formulários, bem como a lista de documentos e requisitos necessários para configurações do processo operacional, após a resposta à solicitação de análise de viabilidade.\n2.1.2.1 Apresentar ao cliente os documentos fornecidos pelo CDIP, juntamente com a Matriz de Regras da Modalidade e seus complementos, para que tenha ciência dos prazos, responsabilidades atribuídas a ele e requisitos da modalidade.\n2.1.3 Orientar o cliente sobre a necessidade de informar, no início do processo de Desenvolvimento de Formulários, os adicionais a serem incluídos em cada formulário/matriz.\nNota 1: os adicionais de interrupção de produção ou tratamento eletrônico não se aplicam a essa necessidade, visto que podem ser solicitados pelo cliente a qualquer momento, antes da postagem dos objetos do lote, conforme Matriz de Regras da modalidade.\nNota 2: observar, no anexo 2 deste documento, os procedimentos específicos para o caso de necessidade de devolução imediata, após a terceira tentativa de entrega.\n2.1.4 Solicitar ao cliente, se possível, o modelo do formulário a ser desenvolvido pelo CDIP e/ou especificações detalhadas das necessidades para cada formulário/matriz.\n2.1.5 Mediar a comunicação entre o cliente e o suporte técnico durante o desenvolvimento dos formulários, garantindo atenção às necessidades do cliente, requisitos técnico-operacionais, regras da modalidade e responsabilidades de cada participante do processo.\n2.1.5.1 Comunicar imediatamente ao cliente, caso haja atrasos por parte deste, sinalizados pelo CDIP, e informá-lo sobre as consequências decorrentes da falta de resposta às solicitações.\n2.1.5.2 Receber do CDIP as amostras e obter validação formal junto ao cliente, utilizando os documentos padronizados fornecidos pelo CDIP.\n2.1.5.3 Em caso de desaprovação da amostra, solicitar ao cliente especificações detalhadas dos ajustes necessários e encaminhá-las ao CDIP, observando e comunicando ao cliente os prazos de correção informados pelo CDIP.\n2.1.6 Orientar o cliente sobre a necessidade de atenção à Matriz de Regras da modalidade e aplicação de suas definições, além de esclarecer e/ou orientar sobre:\n2.1.6.1 A importância, a finalidade, os prazos e os layouts dos arquivos que devem ser enviados pelo cliente, tais como Arquivo de Serviço - SV, Resposta à Notificação do Cliente - RN, Arquivo de Cancelamento - CA e Resposta do Cliente à Devolução de ARs e Metadados - RD.\n2.1.6.3 As premissas para o envio de arquivos complementares ao SV.\n2.1.6.4 A relevância, a finalidade, os prazos e os layouts dos arquivos que devem ser enviados pelos Correios, incluindo:\na) Notificação de Recibo de Serviço - NR, Notificação de Inconsistência - NI, Arquivo de Resposta ao Cancelamento - RC, para objetos Simples, Registrados e Registrados com AR;\nb) Rastreamento Antecipado sobre Data de Postagem - RP e Rastreamento Antecipado sobre Tentativa Final de Entrega - RF, para objetos Registrados e Registrados com AR, mediante solicitação do cliente no momento do Desenvolvimento;\nc) Arquivo de Devolução de ARs e Metadados - AD e Arquivo de Notificação de Recusa da Resposta à Devolução de ARs e Metadados - RR, para objetos Registrados com AR.\n2.1.6.5 As definições, que levam em consideração a Lei Geral de Proteção de Dados - LGPD, para a transferência de arquivos, armazenamento, recuperação e responsabilização de arquivos enviados e recebidos.\n2.1.6.6 As regras e parâmetros para a geração do dígito verificador das etiquetas de registro, quando necessário.\n2.1.6.7 A importância de conhecer e entender os motivos que podem levar à rejeição de arquivos, bem como atuar na prevenção de inconsistências que podem impactar o processo de produção.\n2.1.6.8 A necessidade de atenção e de parametrização quanto aos motivos de baixa oriundos do SRO, considerando seu relacionamento com o sistema de processamento de arquivos.\n2.1.6.9 A necessidade de correção de leiautes, nomenclaturas e características dos arquivos em caso de rejeição e/ou de sinalização de inconsistências por parte do CDIP.\n2.1.6.10 A necessidade de indicação de textos reduzidos para os campos da Entrega Digital, uma vez que se trata de mensagem a ser apresentada em tela de dispositivos móveis (celular, tablet e etc).\n2.2 Desenvolvimento de Formulários e Suporte Técnico ao Negócio (CDIP)\n2.2.1 Analisar a Planilha de Viabilidade de Comercialização, conforme previsto no item 2.1.1 deste anexo, e emitir parecer à Força de Vendas acerca da viabilidade operacional de atendimento.\n2.2.1.1 Em caso de inviabilidade, recorrer imediatamente ao Departamento de Gestão Técnica dos Centros e Unidades de Produção para suporte técnico-operacional, análise de redistribuição do atendimento e eventuais necessidades que se façam necessárias.\n2.2.2 Realizar os procedimentos necessários para a configuração da operação para o cliente, bem como para eventuais necessidades de suporte técnico, sob mediação da Força de Vendas, conforme item 2.1.3 do Capítulo principal deste anexo.\n2.2.3 Desenvolver o(s) formulário(s) contendo dados fixos e variáveis, de acordo com as especificações delineadas pelo cliente e informadas pela Força de Vendas, respeitando as definições da Matriz de Regras da modalidade.\n2.2.4 Cumprir os prazos previstos para desenvolvimento dos formulários, conforme MANNEG 6/3 e procedimentos padronizados e disponibilizados pelo Departamento de Gestão Técnica dos CDIP, analisando as especificações solicitadas pelo cliente e as regras estabelecidas para os níveis de complexidade de desenvolvimento, bem como as definições para novos formulários ou para alterações de formulários já existentes.\nNota 1: a homologação da modalidade e-Carta Integração considera toda a cadeia de produção (desenvolvimento formulário e/ou leiaute de arquivos e-Carta, captação eletrônica, tratamento eletrônico, geração física da mensagem e-Carta, postagem, entrega, digitalização do AR, caso haja necessidade, e retorno de dados), aprovação de cada formulário, mediante uso de arquivos de teste do cliente, conforme Matriz de Regras e documentos correlatos.\nNota 2: quando necessária alteração no formulário e/ou leiaute de arquivos que venha ocorrer durante o período de testes da cadeia produtiva, pode ser necessário acrescentar os dias referente à alteração citada.\n2.2.5 Gerar amostra impressa do formulário desenvolvido e encaminhar à Força de Vendas, utilizando modelo validação de formulário de desenvolvimento e disponibilizado pelo Departamento de Gestão Técnica dos Centros e Unidades de Produção, para fins de aprovação.\n2.2.6 Armazenar, digitalmente, uma via do Formulário aprovado pelo cliente, juntamente com o formulário de aprovação devidamente preenchido e assinado pelo cliente.\n2.2.7 Disponibilizar recursos para desenvolvimento aos Centros indicados pelo Departamento de Gestão Técnica dos Centros e Unidades de Produção, a fim de que a matriz aprovada seja desenvolvida de forma idêntica.\n2.2.8 Realizar todas as trocas de arquivos durante o processo de desenvolvimento de formulários utilizando dados fictícios, conforme estabelecido no item 2.1.3.8 do Capítulo principal deste anexo e seus itens complementares.\n2.2.9 Garantir a possibilidade de início da produção do formulário aprovado pelo cliente, em toda cadeia de produção, em até 2 dias úteis após a aprovação de cada formulário, a partir da autorização para primeira produção e envio dos arquivos pelo cliente.\n2.2.10 Comunicar à Força de Vendas, por e-mail, da liberação para início da produção e os demais dados necessários para início da produção (dados relacionados à matriz desenvolvida, dados de acesso aos sistemas e informações complementares).\n2.2.11 Não realizar qualquer alteração nos arquivos enviados pelo cliente, mesmo que solicitado, comunicando-se com a Força de Vendas e o Cliente para cancelamentos e correções, se necessário.\n2.2.12 Comunicar à Força de Vendas, por e-mail, sobre eventuais ocorrências sinalizadas pela equipe gestora dos sistemas, conforme itens 2.1.3 do Capítulo principal deste anexo.\n2.2.13 Interromper o serviço por solicitação do cliente, desde que a postagem física de pelo menos um dos objetos do lote não tenha ocorrido.\nNota: o cliente receberá um arquivo de Resposta ao Cancelamento indicando a aceitação ou não do pedido de interrupção.\n2.2.14 Caso seja percebida a impossibilidade de cumprimento dos prazos previstos, atuar conforme definição do Departamento de Gestão Técnica dos Centros e Unidades de Produção e conforme MANLOG 4/14.\n2.3 Produção de Objetos Postais (CDIP/UP)\n2.3.1 Realizar os procedimentos de confirmação de produção e postagem, por meio do sistema correspondente, conforme MANLOG 4/14.\n2.3.2 Descartar material produzido, em caso de cancelamento da produção pelo cliente, conforme MANLOG 4/14.', 1),
(8391, 'anexo', 103, NULL, 1, '3', 'GENERALIDADES', '3.1 Acompanhar a atualização da Matriz de Regras do e-Carta Integração, bem como seus complementos e anexos, além dos demais documentos técnicos relacionados à execução da modalidade.\n* * * * *', 2),
(8392, 'anexo', 104, NULL, 1, '1', 'OBJETIVOS', '1.1 Fornecer diretrizes detalhadas para a execução dos procedimentos específicos relacionados à modalidade e-Carta Transmissão. Este anexo não substitui as definições estabelecidas em seu Capítulo principal, sendo um complemento destinado à orientação e definição de diretrizes específicas.', 0),
(8393, 'anexo', 104, NULL, 1, '2', 'DESCRIÇÃO DOS PROCEDIMENTOS ESPECÍFICOS', '2.1 Prospecção, Comercialização e Suporte ao Cliente (Força de Vendas)\n2.1.1 Atentar para as características dessa modalidade que atende a clientes com postagens sazonais, com volumes de postagens médios/altos e que necessitam de flexibilidade no leiaute de suas mensagens.\nNota: recomenda-se que o cliente utilize a modalidade e-Carta Transmissão de forma temporária, a fim de atender demandas específicas e pontuais, com posterior migração para a modalidade e-Carta Integração.\n2.1.2 Preencher a planilha de Solicitação de Viabilidade de Comercialização, antes de preencher a Ficha Técnica, e:\na) enviar por e-mail ao Centro de Digitalização e Produção de Objetos - CDIP de abrangência para volumes diários entre 5.000 e 20.000 de objetos com até 2 (duas) páginas; ou\nb) enviar por e-mail ao CDIP de abrangência para volumes diários entre 2.000 e 10.000 de objetos com 3 (três) páginas ou mais.\nNota 1: a solicitação de análise de viabilidade deve ser enviada imediatamente após a conclusão do item 2.1.1.9 do Capítulo principal deste anexo.\nNota 2: essa solicitação será usada para definir e otimizar os recursos necessários para atender às necessidades do cliente.\n2.1.3 Solicitar ao CDIP de abrangência o cronograma do processo de Desenvolvimento de Formulários, bem como a lista de documentos e requisitos necessários para configurações do processo operacional, após a resposta à solicitação de análise de viabilidade.\n2.1.3.1 Apresentar ao cliente os documentos fornecidos pelo CDIP, juntamente com a Matriz de Regras da Modalidade e seus complementos, para que tenha ciência dos prazos, responsabilidades atribuídas a ele e requisitos da modalidade.\n2.1.4 Orientar o cliente sobre a necessidade de informar, no início do processo de Desenvolvimento de Formulários, os adicionais a serem incluídos em cada formulário/matriz.\nNota: observar, no anexo 2 deste documento, os procedimentos específicos para o caso de necessidade de devolução imediata, após a terceira tentativa de entrega.\n2.1.5 Solicitar ao cliente, se possível, o modelo do formulário a ser desenvolvido pelo CDIP e/ou especificações detalhadas das necessidades para cada formulário/matriz.\n2.1.6 Mediar a comunicação entre o cliente e o suporte técnico durante o desenvolvimento dos formulários, garantindo atenção às necessidades do cliente, requisitos técnico-operacionais, regras da modalidade e responsabilidades de cada participante do processo.\n2.1.6.1 Comunicar imediatamente ao cliente, caso haja atrasos por parte deste, sinalizados pelo CDIP, e informá-lo sobre as consequências decorrentes da falta de resposta às solicitações.\n2.1.6.2 Receber do CDIP as amostras e obter validação formal junto ao cliente, utilizando os documentos padronizados fornecidos pelo CDIP.\n2.1.6.3 Em caso de desaprovação da amostra, solicitar ao cliente especificações detalhadas dos ajustes necessários e encaminhá-las ao CDIP, observando e comunicando ao cliente os prazos de correção informados pelo CDIP.\n2.1.7 Orientar o cliente sobre a necessidade de atenção à Matriz de Regras da modalidade e aplicação de suas definições, além de esclarecer e/ou orientar sobre:\n2.1.7.1 A necessidade de atenção às premissas de envio e nomenclatura de arquivos principais.\n2.1.7.2 As premissas para o envio de arquivos complementares ao arquivo principal.\n2.1.7.3 As definições, que levam em consideração a Lei Geral de Proteção de Dados - GPD, para a transferência de arquivos, armazenamento, recuperação e responsabilização de arquivos enviados e recebidos.\n2.1.7.4 As regras e parâmetros para a geração do dígito verificador das etiquetas de registro, quando necessário.\n2.1.7.5 A importância de conhecer e entender os motivos que podem levar à rejeição de arquivos, bem como atuar na prevenção de inconsistências que podem impactar o processo de produção.\n2.1.7.6 A necessidade de correção de leiautes, nomenclaturas e características dos arquivos em caso de rejeição e/ou de sinalização de inconsistências por parte do CDIP.\n2.1.7.7 A impossibilidade de realização de validação de endereçamento/CEP nos arquivos enviados para produção nesta modalidade, diferentemente do e-Carta Integração.\nNota: no caso do item 2.1.7.7, se as informações de endereçamento ou CEP forem enviadas de forma incorreta ou estiverem ausentes, os Correios não se responsabilizarão por eventuais impactos na qualidade da distribuição do(s) objeto(s) nesta situação.\n2.1.7.8 A aceitação de arquivos de serviço, principalmente no formato PDF, apenas se contiverem todos os dados exigidos pelos Correios, como CEPNet, chancela, dados do destinatário e do remetente, devidamente posicionados conforme especificações pré-definidas.\nNota: para a correta utilização do CEPNet, é essencial seguir as definições e parametrizações descritas no “Guia Técnico - CEPNet e Código 2D para Triagem e Endereçamento”, incluindo requisitos de tamanho, fonte, distância das bordas, entre outros.\n2.2 Desenvolvimento de Formulários e Suporte Técnico ao Negócio (CDIP)\n2.2.1 Analisar a Planilha de Viabilidade de Comercialização, conforme previsto no item 2.1.1 deste anexo, e emitir parecer à Força de Vendas acerca da viabilidade operacional de atendimento.\n2.2.1.1 Em caso de inviabilidade, recorrer imediatamente ao Departamento de Gestão Técnica dos Centros e Unidades de Produção para suporte técnico-operacional, análise de redistribuição do atendimento e eventuais necessidades que se façam necessárias.\n2.2.2 Realizar os procedimentos necessários para a configuração da operação para o cliente, bem como para eventuais necessidades de suporte técnico, sob mediação da Força de Vendas, conforme item 2.1.3 Capítulo principal deste anexo.\n2.2.3 Desenvolver o(s) formulário(s) contendo dados fixos e variáveis, de acordo com as especificações delineadas pelo cliente e informadas pela Força de Vendas, respeitando as definições da Matriz de Regras da modalidade.\n2.2.4 Cumprir os prazos previstos para desenvolvimento dos formulários, conforme MANNEG 6/3 e procedimentos padronizados e disponibilizados pelo Departamento de Gestão Técnica dos CDIP, analisando as especificações solicitadas pelo cliente e as regras estabelecidas para os níveis de complexidade de desenvolvimento, bem como as definições para novos formulários ou para alterações de formulários já existentes.\nNota 1: a homologação da modalidade e-Carta Transmissão considera toda a cadeia de produção (desenvolvimento formulário e/ou leiaute de arquivos e-Carta, captação eletrônica, tratamento eletrônico, geração física da mensagem e-Carta, postagem, entrega, digitalização do AR, caso haja necessidade, e retorno de dados), aprovação de cada formulário, mediante uso de arquivos de teste do cliente, conforme Matriz de Regras e documentos correlatos.\nNota 2: quando necessária alteração no formulário e/ou leiaute de arquivos que venha ocorrer durante o período de testes da cadeia produtiva, pode ser necessário acrescentar os dias referente à alteração citada.\n2.2.5 Gerar amostra impressa do formulário desenvolvido e encaminhar à Força de Vendas, utilizando modelo validação de formulário de desenvolvimento e disponibilizado pelo Departamento de Gestão Técnica dos Centros e Unidades de Produção, para fins de aprovação.\n2.2.6 Armazenar, digitalmente, uma via do Formulário aprovado pelo cliente, juntamente com o formulário de aprovação devidamente preenchido e assinado pelo cliente.\n2.2.7 Disponibilizar recursos para desenvolvimento aos Centros indicados pelo Departamento de Gestão Técnica dos Centros e Unidades de Produção, a fim de que a matriz aprovada seja desenvolvida de forma idêntica.\n2.2.8 Realizar todas as trocas de arquivos durante o processo de desenvolvimento de formulários utilizando dados fictícios, conforme estabelecido no item 2.1.3.8 do Capítulo principal deste anexo e seus itens complementares.\n2.2.9 Garantir a possibilidade de início da produção do formulário aprovado pelo cliente, em toda cadeia de produção, em até 2 dias úteis após a aprovação de cada formulário, a partir da autorização para primeira produção e envio dos arquivos pelo cliente.\n2.2.10 Comunicar à Força de Vendas, por e-mail, da liberação para início da produção e os demais dados necessários para início da produção (dados relacionados à formulário/matriz desenvolvido e informações complementares).\n2.2.11 Não realizar qualquer alteração nos arquivos enviados pelo cliente, mesmo que solicitado, comunicando-se com a Força de Vendas e o Cliente para cancelamentos e correções, se necessário.\n2.2.12 Comunicar à Força de Vendas, por e-mail, sobre eventuais ocorrências percebidas nos arquivos enviados pelo cliente, conforme itens 2.1.3.1 e 2.1.3.4 do Capítulo principal deste anexo.\n2.2.14 Caso seja percebida a impossibilidade de cumprimento dos prazos previstos, atuar conforme definição do Departamento de Gestão Técnica dos Centros e Unidades de Produção e conforme MANLOG 4/14.\n2.3 Produção dos Objetos (CDIP/UP)\n2.3.1 Agrupar as mensagens separadas com capa de lote, conforme plano do sistema de blocagem, após a saída do autoenvelopamento, acomodando-as em caixetas, conforme MANLOG 4/14.\n2.3.2 Encaminhar a carga produzida à GCCAP ou CEM, situada no mesmo prédio do CDIP/UP ou no Centro de Tratamento mais próximo, para realização dos procedimentos de faturamento, postagem e integração no fluxo postal.\n2.3.4 Descartar material produzido, em caso de cancelamento da produção pelo cliente, conforme MANLOG 4/14.\n2.3.3 Realizar os demais procedimentos específicos à modalidade, conforme MANLOG 4/14.\n2.4 Postagem dos Objetos (GCCAP/CEM)\n2.4.1 Receber os objetos produzidos pelo CDIP/UP e conferir a carga, conforme Lista de Postagem disponibilizada.\n2.4.1.1 Observar se a lista de postagem considera no campo “DR de Faturamento” o número da SE do contrato. Caso contrário, solicitar correção ao CDIP/UP.\n2.4.2 Faturar a carga no SARA usando o código de serviço correspondente à modalidade e ao tipo de objeto, conforme Anexo 2 deste Manual\n2.4.2.1 Analisar se houve a inclusão de adicionais e proceder com o faturamento correspondente, de acordo com o informado.\n2.4.3 Encaminhar as mensagens para tratamento, conforme MANENC e MANCAT.', 1),
(8394, 'anexo', 104, NULL, 1, '3', 'GENERALIDADES', '3.1 Acompanhar a atualização da Matriz de Regras do e-Carta Trasmissão, bem como seus complementos e anexos, além dos demais documentos técnicos relacionados à execução da modalidade.\n* * * * *', 2),
(8395, 'anexo', 105, NULL, 1, '1', 'OBJETIVOS', '1.1 Fornecer diretrizes detalhadas para a execução dos procedimentos específicos relacionados à modalidade e-Carta Fácil. Este anexo não substitui as definições estabelecidas em seu Capítulo principal, sendo um complemento destinado à orientação e definição de diretrizes específicas.', 0),
(8396, 'anexo', 105, NULL, 1, '2', 'DESCRIÇÃO DOS PROCEDIMENTOS ESPECÍFICOS', '2.1 Prospecção, Comercialização e Suporte ao Cliente Contrato (Força de Vendas)\n2.1.1 Atentar para as características dessa modalidade, que atende a clientes com postagens padronizadas, com volumes baixos de objetos e/ou que necessitam de acesso a diversos usuários (CPF) associados ao contrato/cartão de postagem.\n2.1.2 Avaliar a Matriz de Regras do e-Carta Fácil e seus anexos, disponíveis na Intranet do Departamento gestor do produto, quanto aos requisito necessários para utilização.\n2.1.2.1 Apresentar ao cliente a Matriz de Regras da Modalidade e seus anexos, para que tenha ciência dos prazos, responsabilidades atribuídas a ele e requisitos da modalidade.\n2.1.3 Mediar a comunicação entre o cliente e o suporte técnico durante a utilização do sistema SMT (Web WebServices), garantindo atenção às necessidades do cliente, requisitos técnico-operacionais, regras da modalidade e responsabilidades de cada participante do processo.\n2.1.4 Orientar o cliente sobre a necessidade de atenção à Matriz de Regras da modalidade e aplicação de suas definições, além de esclarecer e/ou orientar sobre:\n2.1.4.1 A necessidade de atenção às premissas relacionadas à troca de informações e de dados enviados.\n2.1.4.2 Aos fluxos, regras, requisitos e utilização de funcionalidades do SMT (Web ou WebServices).\n2.1.4.3 As definições, que levam em consideração a Lei Geral de Proteção de Dados (LGPD), para a transferência de arquivos, armazenamento, recuperação e responsabilização de arquivos enviados e recebidos.\n2.1.4.4 A importância de conhecer, entender, prevenir e corrigir a rejeição de arquivos pelo Centro/Unidade devido a inconsistências percebidas pelas equipes de Produção.\n2.1.4.5 A responsabilidade pelos usuários (CPF) autorizados pelos clientes contratantes (CNPJ) a utilizar o SMT, conforme atribuição de perfil, bem como suas especificidades e autorizações.', 1),
(8397, 'anexo', 105, NULL, 1, '3', 'GENERALIDADES', '3.1 Acompanhar a atualização da Matriz de Regras do e-Carta Fácil, bem como seus complementos e anexos, além dos demais documentos técnicos relacionados à execução da modalidade.\n* * * * *', 2),
