(8440, 'anexo', 112, NULL, 1, '1', 'CARACTERÍSTICAS', '', 0),
(8441, 'anexo', 112, 8440, 2, '1.1', 'Serviço adicional que garante a entrega do objeto postal, exclusivamente, ao próprio destinatário.', '', 1),
(8442, 'anexo', 112, 8440, 2, '1.2', 'O serviço adicional Mão Própria - MP poderá ser utilizado somente em objetos postados sob registro.', '', 2),
(8443, 'anexo', 112, 8440, 2, '1.3', 'O serviço adicional de MP poderá ser contratado com Aviso de Recebimento - AR, com ou sem declaração sumária do conteúdo, e/ou com Valor Declarado.', '', 3),
(8444, 'anexo', 112, 8440, 2, '1.4', 'Exclusivamente, para cliente a faturar, poderão ser indicados no objeto, pelo cliente, até 3 (três) destinatários, residentes no mesmo endereço. Caso seja utilizado o Aviso de Recebimento - AR, deve-se observar os requisitos a seguir:', 'a) os nomes dos destinatários deverão ser impressos em linhas distintas;\nb) os nomes dos destinatários deverão ser os mesmos daqueles constantes no objeto encaminhado;\nc) recusar a postagem caso haja nome(s) divergente(s) daquele(s) constante(s) do objeto.', 4),
(8445, 'anexo', 112, 8440, 2, '1.5', 'A menção “MP” deverá constar no campo inferior à direita do anverso do objeto, utilizando a quadrícula própria das etiquetas com códigos de barras, sempre que possível.', '', 5),
(8446, 'anexo', 112, 8440, 2, '1.6', 'Realizar o tratamento da postagem, encaminhamento e distribuição do objeto com adicional de Mão Própria - MP, conforme regra prevista para cada serviço postal.', '', 6),
