(8660, 'anexo', 134, 8644, 2, '1.4', 'Arquivo de Retorno do AR Digital - Campo ‘Motivo de devolução’, os códigos e as descrições são:', '', 16),
(8661, 'anexo', 134, 8660, 4, 'a', '05: suspensão da entrega solicitada pelo remetente;', '', 17),
