(8700, 'anexo', 139, NULL, 1, '01', 'Tipo do registro	A	1	1 - 1	1', '', 2),
(8701, 'anexo', 139, NULL, 1, '02', 'Data de geração do arquivo	N	8	2 - 9', '', 3),
