(8704, 'anexo', 139, NULL, 1, '01', 'Tipo do registro	N	1	1-1	2', '', 6),
(8705, 'anexo', 139, NULL, 1, '02', 'Identificação do objeto (código de barras)	A	34	2-35', '', 7),
(8706, 'anexo', 139, NULL, 1, '03', 'Código do motivo de devolução	N	2	36-37	01-Mudou-se', '02-Endereço insuficiente\n03-Não existe o nº. Indicado\n04-Falecido\n05-Desconhecido\n06-Recusado\n07-Ausente\n08-Não procurado\n09-Outros\n10-Objeto Danificado\n11-Endereço Desconhecido na Localidade\n12-Falta Complemento (Coletivo/GU)\n13-Caixa Postal Cancelada\n14-Entrega Controlada', 8),
(8707, 'anexo', 139, 8706, 4, 'c', 'Registro Rodapé (Trailler):', 'CAMPO	DESCRIÇÃO	TIPO	TAM	VALOR', 9),
(8708, 'anexo', 139, NULL, 1, '01', 'Tipo do registro	N	1	3', '', 10),
(8709, 'anexo', 139, NULL, 1, '02', 'Controle Correios	N	1	1', '', 11),
(8710, 'anexo', 139, NULL, 1, '03', 'Quantidade de registros no arquivo (preencher com zeros à esquerda para locar tamanho máximo do campo em 10 posições. Não incluir registros tipo 1 e tipo 3)	N	10', '', 12),
