INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(9052, 'anexo', 178, 9051, 4, 'a', 'documentos internacionais: Mala M e Cecograma Internacional postados no exterior seguirão as mesmas regras definidas para as Cartas Simples/Registradas nacionais;', '', 2),
(9053, 'anexo', 178, 9051, 4, 'b', 'prazo de 20 (vinte) dias corridos: Colis Postaux, Petit Paquet simples e registrado, Prime e Tracked;', '', 3),
(9054, 'anexo', 178, 9051, 4, 'c', 'prazo de 7 (sete) dias corridos: EMS;', '', 4),
(9055, 'anexo', 178, 9051, 4, 'd', 'prazo de 7 (sete) dias corridos: Correios Packet;', '', 5),
(9056, 'anexo', 178, 9051, 4, 'e', 'prazo de 30 (trinta) dias corridos: objeto endereçado a Caixa Postal.', 'Nota: exceto para encomenda Correios Packet nacionalizada em devolução que não pode ser endereçada para unidade dos Correios.\nExemplo: Caixa Postal ou Posta Restante Pedida.\n* * * * *', 6),
(9057, 'anexo', 180, NULL, 1, '1', 'DEFINIÇÃO', '1.1 Serviço de recebimento no Brasil, desembaraço aduaneiro, tratamento e distribuição em domicílio, em âmbito nacional, de encomendas internacionais destinadas à pessoa física ou jurídica. \n1.2 O contratante do serviço é o usuário que estabelece acordo contrato com os Correios. Sendo responsável pela preparação das encomendas de acordo com instruções dos Correios, pela contratação do frete internacional e pela entrega das encomendas nos aeroportos indicados pelos Correios no Brasil.\n1.3 O contratante deverá observar as exigências fiscais e tributárias relativas à remessa das encomendas, na forma da legislação aduaneira brasileira vigente, sendo responsável pelas informações contidas na Declaração Aduaneira. \n1.4 O contratante deve responsabilizar-se pela devolução à origem (inclusos transporte internacional e desembaraço aduaneiro no exterior) das encomendas não nacionalizadas ou cuja importação não foi autorizada, observando os prazos estabelecidos na legislação vigente ou determinados pela autoridade aduaneira responsável pela determinação de devolução. \n1.5 O serviço está distribuído em 02 modalidades de entrega:', 0),
(9058, 'anexo', 180, 9057, 4, 'a', 'Correios Packet Express com encaminhamento em território nacional das encomendas aos destinatários, por meio da distribuição expressa de acordo com as regras de tratamento e prazos estabelecidos para a entrega do serviço de encomenda nacional SEDEX; ', '', 1),
(9059, 'anexo', 180, 9057, 4, 'b', 'Correios Packet Standard com encaminhamento em território nacional das encomendas aos destinatários, por meio da distribuição não expressa de acordo com as regras de tratamento e prazos estabelecidos para a entrega do serviço de encomenda nacional PAC. ', 'Nota: o prazo previsto de entrega começa a ser contado a partir da conclusão do processo de nacionalização da encomenda pela autoridade aduaneira. ', 2),
(9060, 'anexo', 180, NULL, 1, '2', 'ABRANGÊNCIA', '2.1 O serviço Correios Packet tem abrangência nacional para distribuição.', 3),
(9061, 'anexo', 180, NULL, 1, '3', 'PÚBLICO-ALVO', '3.1 O público-alvo do serviço Correios Packet compreende os atuantes na cadeia de valor do comércio eletrônico internacional, pessoa jurídica (com contrato).', 4),
(9062, 'anexo', 180, NULL, 1, '4', 'SERVIÇOS INERENTES', '4.1 Os atributos inerentes ao serviço Correios Packet são:', 5),
(9063, 'anexo', 180, 9062, 4, 'a', 'devolução no Brasil;', '', 6),
(9064, 'anexo', 180, 9062, 4, 'b', 'devolução à origem de objeto não nacionalizado;', '', 7),
(9065, 'anexo', 180, 9062, 4, 'c', 'entrega domiciliar;', '', 8),
(9066, 'anexo', 180, 9062, 4, 'd', 'indenização automática;', '', 9),
(9067, 'anexo', 180, 9062, 4, 'e', 'rastreamento;', '', 10),
(9068, 'anexo', 180, 9062, 4, 'f', 'registro;', '', 11),
(9069, 'anexo', 180, 9062, 4, 'g', 'troca eletrônica de informações.', '4.1.1 A devolução de objetos não nacionalizados, desde que não sejam artigos perigosos, conforme classificação International Air Transport Association - IATA, está condicionada a:', 12),
(9070, 'anexo', 180, 9062, 4, 'a', 'opção do cliente pela devolução com a informação prestada via integração tecnológica;', '', 13),
(9071, 'anexo', 180, 9062, 4, 'b', 'autorização da Receita Federal do Brasil; e', '', 14),
(9072, 'anexo', 180, 9062, 4, 'c', 'contratação de transporte internacional dentro do prazo estabelecido pela autoridade aduaneira, bem como todos os custos decorrentes da devolução dos objetos ao exterior.', '', 15),
(9073, 'anexo', 180, NULL, 1, '5', 'SERVIÇOS ADICIONAIS', '5.1 Não há.', 16),
(9074, 'anexo', 180, NULL, 1, '6', 'LIMITES DE PESO', '6.1 Os limites máximos permitidos para o peso físico é de até 30kg para o Correios Packet Express e Standard.', 17),
(9075, 'anexo', 180, NULL, 1, '7', 'LIMITES DE DIMENSÕES', '7.1 Envelope:', 18),
(9076, 'anexo', 180, 9075, 4, 'a', 'comprimento mínimo é 14 cm e a largura mínima é de 9 cm;', '', 19),
(9077, 'anexo', 180, 9075, 4, 'b', 'maior dimensão (comprimento ou largura) não deve ultrapassar 60 cm e a segunda maior dimensão não pode ultrapassar 30 cm;', '', 20),
(9078, 'anexo', 180, 9075, 4, 'c', 'soma das dimensões não exceder 90 cm.', '7.2 Caixa/Pacote:', 21),
(9079, 'anexo', 180, 9075, 4, 'a', 'comprimento mínimo é 15 cm, a largura mínima é de 10 cm e a altura mínima é de 1 cm;', '', 22),
(9080, 'anexo', 180, 9075, 4, 'b', 'maior dimensão (comprimento, largura ou altura) não deve ultrapassar 100 cm e a segunda maior dimensão não pode ultrapassar 90 cm;', '', 23),
(9081, 'anexo', 180, 9075, 4, 'c', 'soma das dimensões não deve exceder 200 cm.', '7.3 Rolo:', 24),
(9082, 'anexo', 180, 9075, 4, 'a', 'dimensões mínimas (C x D): 10 cm x 5 cm;', '', 25),
(9083, 'anexo', 180, 9075, 4, 'b', 'dimensões máximas (C x D): 90 cm x 30 cm;', '', 26),
(9084, 'anexo', 180, 9075, 4, 'c', 'soma das dimensões não deve ultrapassar 104 cm.', '* * * * *', 27),
(9085, 'anexo', 181, NULL, 1, '1', 'DOCUMENTO INTERNACIONAL', '', 0),
(9086, 'anexo', 181, 9085, 2, '1.1', 'Podem ser enviados como Documento Internacional:', '', 1),
(9087, 'anexo', 181, 9086, 4, 'a', 'qualquer correspondência, mensagem, texto, informação ou dado de natureza pessoal ou jurídica, sem valor comercial intrínseco, gravado em papel ou outro meio físico, magnético ou eletromagnético. Incluem-se, jornais, revistas e assemelhados, desde que não sejam caracterizados como remessa comercial;', '', 2),
(9088, 'anexo', 181, 9086, 4, 'b', 'CD, fita cassete, fita de vídeo, DVD, além de outras mídias usadas para a comunicação, desde que não sejam caracterizados como remessa comercial.', '', 3),
(9089, 'anexo', 181, 9085, 2, '1.2', 'Os serviços estão distribuídos em duas modalidades de entrega:', '', 4),
(9090, 'anexo', 181, 9089, 4, 'a', 'Documento Internacional Expresso: serviço internacional expresso para envio de documentos. Ideal para quem quer velocidade na entrega;', '', 5),
(9091, 'anexo', 181, 9089, 4, 'b', 'Documento Internacional Standard: serviço internacional para envio de documentos. Pode ser enviado de forma simples ou registrado. Ideal para quem deseja conciliar o prazo de entrega com preços mais acessíveis.', '', 6),
(9092, 'anexo', 181, NULL, 1, '2', 'EXPORTA FÁCIL', '', 7),
(9093, 'anexo', 181, 9092, 2, '2.1', 'Podem ser enviados via Exporta Fácil:', '', 8),
(9094, 'anexo', 181, 9093, 4, 'a', 'presentes: remessas de bens em quantidade e valor que não permitam presumir destinação comercial;', '', 9),
(9095, 'anexo', 181, 9093, 4, 'b', 'amostras: fragmentos ou partes de qualquer mercadoria, em quantidade estritamente necessária para conhecimento de sua natureza, espécie e qualidade;', '', 10),
(9096, 'anexo', 181, 9093, 4, 'c', 'venda (de mercadorias): remessas compostas de bens destinados à operação de venda, cujo registro da exportação é obrigatório;', '', 11),
(9097, 'anexo', 181, 9093, 4, 'd', 'outros: exportação temporária e bagagem desacompanhada.', '', 12),
(9098, 'anexo', 181, 9093, 3, '2.1.1', 'O envio de mercadorias realizado por pessoa jurídica (com ou sem contrato) necessita obrigatoriamente da apresentação da nota fiscal.', '', 13),
(9099, 'anexo', 181, 9093, 3, '2.1.2', 'Notas fiscais de remessas ao exterior devem possuir Códigos Fiscais de Operações e Prestações - CFOP específicos de exportação, os quais podem ser consultados pelo cliente pessoa jurídica no site do Confaz, na internet.', '', 14),
(9100, 'anexo', 181, 9093, 3, '2.1.3', 'Remessas cujas notas fiscais possuam códigos CFOP com motivos divergentes de exportação são passíveis de devolução ou apreensão pela Receita Federal para que sejam corrigidas, gerando atraso no envio.', '2.1.3.1 Recomenda-se, portanto, que os clientes se atentem aos códigos e, observando alguma divergência, que ela seja corrigida antes da postagem.', 15),
(9101, 'anexo', 181, 9093, 3, '2.1.4', 'É vedado à pessoa jurídica, o envio de remessas enquadradas como presente, sendo permitido apenas a pessoas físicas. Para tanto, é permitido à pessoa jurídica o envio de brindes ou amostras, os quais devem ser acompanhados por nota fiscal para o devido encaminhamento ao destino.', '', 16),
(9102, 'anexo', 181, 9093, 3, '2.1.5', 'Os serviços estão distribuídos em 3 (três) modalidades de entrega:', '', 17),
(9103, 'anexo', 181, 9102, 4, 'a', 'Exporta Fácil Expresso;', '', 18),
(9104, 'anexo', 181, 9102, 4, 'b', 'Exporta Fácil Standard;', '', 19),
(9105, 'anexo', 181, 9102, 4, 'c', 'Exporta Fácil Econômico.', '', 20),
(9106, 'anexo', 181, NULL, 1, '3', 'ORIENTAÇÕES PARA POSTAGEM INTERNACIONAL NA UNIDADE', '', 21),
(9107, 'anexo', 181, 9106, 2, '3.1', 'Os formulários CN22 e AWB são obrigatórios para postagem de objetos internacionais de exportação.', '', 22),
(9108, 'anexo', 181, 9107, 3, '3.1.1', 'O CN22 deve ser utilizado para postagem de Documento Internacional Standard e preenchido pelo cliente.', '', 23),
(9109, 'anexo', 181, 9107, 3, '3.1.2', 'O AWB deve ser utilizado para a postagem de todos os demais serviços e preenchido pelo atendente no sistema de atendimento.', '3.1.2.1 O cliente tem a opção de repassar as informações ao atendente no ato da postagem ou preencher antecipadamente o AWB disponível no portal dos Correios e levá-lo impresso a uma agência. Nesse caso, permanece a necessidade de o atendente inserir os dados no sistema de atendimento, porém o processo de postagem pode ser agilizado se as informações já estiverem preenchidas no formulário.\n3.1.2.2 Nos casos de uso de folha suplementar do formulário, ela deve ser impressa em 4 (quatro) vias, pois deve ser anexada a cada via do formulário AWB.\n3.1.2.3 Para presente ou amostra, a moeda estrangeira a ser usada será dólar americano.\n3.1.2.4 Para mercadoria comercial (venda), a moeda estrangeira a ser usada será a moeda de negociação (dólares, euros etc.).\n3.1.2.5 A nota fiscal e a invoice (fatura comercial) deverão ser incluídas no envelope plástico adesivo na encomenda.', 24),
(9110, 'anexo', 181, 9107, 3, '3.1.3', 'A descrição do conteúdo deve ser preenchida em português e na língua inglesa.', '', 25),
(9111, 'anexo', 181, 9106, 2, '3.2', 'O registro da exportação será obrigatório para todos os envios de mercadorias.', '', 26),
(9112, 'anexo', 181, 9111, 3, '3.2.1', 'O registro deverá ser realizado obrigatoriamente por meio de Declaração Única de Exportação - DU-E nas seguintes hipóteses:', '', 27),
(9113, 'anexo', 181, 9112, 4, 'a', 'envio de mercadorias objeto de transação comercial, presentes ou amostras, cujo valor de mercado exceda ao equivalente a USD 1.000,00 (mil dólares americanos) em moeda nacional;', '', 28),
(9114, 'anexo', 181, 9112, 4, 'b', 'bagagem desacompanhada e exportação temporária, independentemente do valor.', '', 29),
(9115, 'anexo', 181, 9111, 3, '3.2.2', 'O registro poderá ser realizado por meio de DU-E ou Lista de Remessa para objetos com valor de mercado de até US$ 1.000,00 (mil dólares americanos), ainda que o envio seja inerente a uma transação comercial.', '', 30),
(9116, 'anexo', 181, 9106, 2, '3.3', 'A postagem deve ser recusada se:', '', 31),
(9117, 'anexo', 181, 9116, 4, 'a', 'o objeto estiver fora dos limites de peso e dimensões;', '', 32),
(9118, 'anexo', 181, 9116, 4, 'b', 'o destino não estiver sendo atendido;', '', 33),
(9119, 'anexo', 181, 9116, 4, 'c', 'a embalagem e acondicionamento não estiverem adequados;', '', 34),
(9120, 'anexo', 181, 9116, 4, 'd', 'o endereçamento no objeto não estiver completo;', '', 35),
(9121, 'anexo', 181, 9116, 4, 'e', 'não tiverem sido utilizados caracteres latinos e números arábicos.', '', 36),
(9122, 'anexo', 181, NULL, 1, '4', 'ABRANGÊNCIA', '', 37),
(9123, 'anexo', 181, 9122, 2, '4.1', 'Quando a abrangência e disponibilidade de determinado serviço estiver restrita, as localidades atendidas estarão disponíveis para consulta no portal Correios.', '', 38),
(9124, 'anexo', 181, 9123, 3, '4.1.1', 'De acordo com a viabilidade comercial e operacional de prestação do serviço, a restrição da abrangência poderá ocorrer por:', '', 39),
(9125, 'anexo', 181, 9124, 4, 'a', 'área geográfica: região, estados (UF), microrregião, cidade ou área urbana, em âmbito nacional e por país de destino, em âmbito internacional;', '', 40),
(9126, 'anexo', 181, 9124, 4, 'b', 'faixa de CEP;', '', 41),
(9127, 'anexo', 181, 9124, 4, 'c', 'índice de classificação da cidade.', '', 42),
(9128, 'anexo', 181, NULL, 1, '5', 'PÚBLICO-ALVO', '', 43),
(9129, 'anexo', 181, 9128, 2, '5.1', 'Os serviços de envio de documentos e encomendas internacionais podem ser utilizados por pessoa física e pessoa jurídica (com ou sem contrato).', '', 44),
(9130, 'anexo', 181, NULL, 1, '6', 'SERVIÇOS INERENTES', '', 45),
(9131, 'anexo', 181, 9130, 2, '6.1', 'São atributos do serviço Documento Internacional para envio de documentos:', '', 46),
(9132, 'anexo', 181, 9131, 4, 'a', 'devolução garantida: Expresso e Standard;', '', 47),
(9133, 'anexo', 181, 9131, 4, 'b', 'entrega domiciliar: Expresso e Standard. A depender das regras de distribuição do operador de destino;', '', 48),
(9134, 'anexo', 181, 9131, 4, 'c', 'indenização automática: Expresso e Standard;', '', 49),
(9135, 'anexo', 181, 9131, 4, 'd', 'rastreamento: Expresso, Standard (Parcial: postagem, chegada no permutante e saída do Brasil para objetos registrados e entrega ao destinatário);', '', 50),
(9136, 'anexo', 181, 9131, 4, 'e', 'registro: Expresso.', '', 51),
(9137, 'anexo', 181, 9130, 2, '6.2', 'São atributos do serviço Exporta Fácil para o envio de mercadoria:', '', 52),
(9138, 'anexo', 181, 9137, 4, 'a', 'entrega domiciliar: Expresso, Standard e Econômico. A depender das regras de distribuição do operador de destino;', '', 53),
(9139, 'anexo', 181, 9137, 4, 'b', 'indenização automática: Expresso, Standard e Econômico;', '', 54),
(9140, 'anexo', 181, 9137, 4, 'c', 'rastreamento: Expresso, Standard (completo no Brasil e na maior parte dos países de destino); Econômico (Parcial: postagem, saída da unidade de postagem, chegada no permutante, saída do Brasil e entrega ao destinatário);', '', 55),
(9141, 'anexo', 181, 9137, 4, 'd', 'registro: Expresso, Standard e Econômico.', '', 56),
(9142, 'anexo', 181, NULL, 1, '7', 'SERVIÇOS ADICIONAIS', '', 57),
(9143, 'anexo', 181, 9142, 2, '7.1', 'Serviços adicionais disponíveis:', '', 58),
(9144, 'anexo', 181, 9143, 4, 'a', 'para documento: Registro (Documento Internacional Standard);', '', 59),
(9145, 'anexo', 181, 9143, 4, 'b', 'para mercadoria: Valor Declarado (Exporta Fácil Expresso e Standard).', '', 60),
(9146, 'anexo', 181, 9142, 2, '7.2', 'Os serviços adicionais podem variar de acordo com o país de destino.', '', 61),
(9147, 'anexo', 181, 9142, 2, '7.3', 'Valor Declarado', '', 62),
(9148, 'anexo', 181, 9147, 3, '7.3.1', 'O serviço adicional Valor Declarado - VD pode ser contratado no momento no envio de mercadorias como forma de garantir a indenização do valor total do bem. Está disponível para os seguintes serviços:', '', 63),
(9149, 'anexo', 181, 9148, 4, 'a', 'Exporta Fácil Expresso, sendo:', 'I - limite de declaração de valor: US$ 10 mil;\nII - percentual de ad valorem: 1,5%.', 64),
(9150, 'anexo', 181, 9148, 4, 'b', 'Exporta Fácil Standard, sendo:', 'I - limite de declaração de valor: US$ 5 mil;\nII - percentual de ad valorem: 2%', 65),
(9151, 'anexo', 181, 9147, 3, '7.3.2', 'O valor declarado é limitado ao valor da mercadoria na nota fiscal, ao limite especificado por serviço e ao limite máximo aceito em cada país de destino.', '', 66),
(9152, 'anexo', 181, 9147, 3, '7.3.3', 'O percentual de ad valorem será cobrado sobre o valor que foi declarado, o qual varia conforme o serviço contratado.', '', 67),
(9153, 'anexo', 181, 9147, 3, '7.3.4', 'O cálculo do Valor Declarado deve ser efetuado em todas as postagens de mercadoria, amostra ou presente, exceto se o remetente expressar sua opção de não fazer opcional declaração de valor.', '', 68),
(9154, 'anexo', 181, NULL, 1, '8', 'LIMITES DE PESO', '', 69),
(9155, 'anexo', 181, 9154, 2, '8.1', 'O limite máximo de peso físico para o envio de documento, obtido da balança, é 2 kg para Documento Internacional Expresso e Standard.', '', 70),
(9156, 'anexo', 181, 9154, 2, '8.2', 'Os limites máximos de peso físico para o envio de mercadoria, obtidos da balança, são:', '', 71),
(9157, 'anexo', 181, 9156, 4, 'a', '30 kg para Exporta Fácil Expresso e Standard;', '', 72),
(9158, 'anexo', 181, 9156, 4, 'b', '2 kg para Exporta Fácil Econômico.', '', 73),
(9159, 'anexo', 181, 9154, 2, '8.3', 'O limite de peso pode variar de acordo com o país de destino, limitado aos pesos dispostos para documento e mercadoria neste item 8.', '', 74),
(9160, 'anexo', 181, 9159, 3, '8.3.1', 'A consulta pode ser realizada no portal dos Correios, em Fichário de Países.', '', 75),
(9161, 'anexo', 181, NULL, 1, '9', 'LIMITES DE DIMENSÕES', '', 76),
(9162, 'anexo', 181, 9161, 2, '9.1', 'Documento Internacional', '', 77),
(9163, 'anexo', 181, 9162, 3, '9.1.1', 'Documento Internacional Expresso e Standard', 'Formato	Dimensões Mínimas	Dimensões Máximas\nEnvelope P	Comprimento: 14 cm\nLargura: 9 cm	Comprimento: 24,5 cm\nLargura: 16,5 cm\nEspessura: 0,5 cm\nEnvelope G	Comprimento: 14 cm\nLargura: 9 cm	Comprimento: 38,1 cm\nLargura: 30,5 cm\nEspessura: 2 cm\nRolo	Comprimento: 10 cm\nDiâmetro: 5 cm	Comprimento: 90 cm\nDiâmetro: 30 cm\nSoma das dimensões\n[C+(2xD)]: 104 cm', 78),
(9164, 'anexo', 181, 9161, 2, '9.2', 'Exporta Fácil', '', 79),
(9165, 'anexo', 181, 9164, 3, '9.2.1', 'Exporta Fácil Expresso', 'Formato	Dimensões Mínimas	Dimensões Máximas\nEnvelope	Comprimento: 32,4 cm\nLargura: 22,9 cm	Comprimento: 60 cm\nLargura: 30 cm\nSoma das dimensões: 90 cm\nCaixa/Pacote	Comprimento: 16 cm\nLargura: 11 cm\nAltura: 5 cm\nSoma das dimensões: 32 cm	Comprimento: 150 cm\nLargura: 100 cm\nAltura: 100 cm\nSoma das dimensões: 300 cm1\nRolo	Comprimento: 10 cm\nDiâmetro: 5 cm\nSoma das dimensões\n[C+(2xD)]: 30 cm	Comprimento: 90 cm\nDiâmetro: 30 cm\nSoma das dimensões\n[C+(2xD)]: 104 cm\n1: soma de comprimento e da maior circunferência medida em uma direção diferente do comprimento.', 80),
(9166, 'anexo', 181, 9164, 3, '9.2.2', 'Exporta Fácil Standard', 'Formato	Dimensões Mínimas	Dimensões Máximas\nEnvelope	Comprimento: 14 cm\nLargura: 9 cm	Comprimento: 60 cm\nLargura: 30 cm\nSoma das Dimensões: 90 cm\nCaixa/Pacote	Comprimento: 16 cm\nLargura: 11 cm\nAltura: 5 cm\nSoma das Dimensões: 32 cm	Comprimento: 150 cm\nLargura: 100 cm\nAltura: 100 cm\nSoma das dimensões: 300 cm1\nRolo	Comprimento: 10 cm\nDiâmetro: 5 cm\nSoma das dimensões\n[C+(2xD)]: 30 cm	Comprimento: 90 cm\nDiâmetro: 30 cm\nSoma das dimensões\n[C+(2xD)]: 104 cm\n2: soma de comprimento e da maior circunferência medida em uma direção diferente do comprimento.', 81),
(9167, 'anexo', 181, 9164, 3, '9.2.3', 'Exporta Fácil Econômico', 'Formato	Dimensões Mínimas	Dimensões Máximas\nEnvelope	Comprimento: 14 cm\nLargura: 9 cm	Comprimento: 60 cm\nLargura: 30 cm\nSoma das Dimensões: 90 cm\nCaixa/Pacote	Comprimento: 16 cm\nLargura: 11 cm\nAltura: 5 cm\nSoma das Dimensões: 32 cm	Comprimento: 150 cm\nLargura: 100 cm\nAltura: 100 cm\nSoma das dimensões: 300 cm1\nRolo	Comprimento: 10 cm\nDiâmetro: 5 cm\nSoma das dimensões\n[C+(2xD)]: 30 cm	Comprimento: 90 cm\nDiâmetro: 30 cm\nSoma das dimensões\n[C+(2xD)]: 104 cm', 82),
(9168, 'anexo', 181, 9161, 2, '9.3', 'Os limites de dimensões podem variar de acordo com o país de destino.', '', 83),
(9169, 'anexo', 181, 9168, 3, '9.3.1', 'A consulta pode ser realizada no portal dos Correios em Fichário de Países.', '', 84),
(9170, 'anexo', 181, NULL, 1, '10', 'EMBALAGEM E ACONDICIONAMENTO', '', 85),
(9171, 'anexo', 181, 9170, 2, '10.1', 'Todo objeto deverá ser acondicionado e fechado pelo cliente, em embalagem que resista ao peso, à forma e à natureza do conteúdo, bem como às condições de transporte.', '', 86),
(9172, 'anexo', 181, 9170, 2, '10.2', 'Será admitida a postagem de documentos em envelopes ou caixas que atendam às condições de acondicionamento exigidas.', '', 87),
(9173, 'anexo', 181, 9170, 2, '10.3', 'Observar adicionalmente às orientações deste Anexo e o disposto no MANCAT 16/3/2.', '', 88),
(9174, 'anexo', 181, 9170, 2, '10.4', 'O objeto deverá ser acondicionado de forma a não colocar em risco a integridade física dos empregados, equipamentos postais e demais objetos postais.', '', 89),
(9175, 'anexo', 181, 9170, 2, '10.5', 'Os objetos internacionais são obrigatoriamente disponibilizados para fiscalização por parte da Receita Federal do Brasil e órgãos anuentes do comércio exterior.', '', 90),
(9176, 'anexo', 181, 9170, 2, '10.6', 'A constatação, em qualquer dependência dos Correios, da existência de remessa contendo objetos proibidos poderá determinar a devolução ao remetente ou sua apreensão.', '', 91),
(9177, 'anexo', 181, 9170, 2, '10.7', 'O material apreendido poderá, conforme sua natureza, ser confiscado ou destruído por autoridade competente ou ser encaminhado para refugo postal.', '', 92),
(9178, 'anexo', 181, 9177, 3, '10.7.1', 'Nos casos de confisco ou destruição de objetos, não caberá qualquer indenização ao cliente, devendo este, ser informado desta providência.', '', 93),
(9179, 'anexo', 181, 9170, 2, '10.8', 'Fechamento de Envelope', '', 94),
(9180, 'anexo', 181, 9179, 3, '10.8.1', 'Deverá ser feito com cola, evitando-se os excessos, e se possível, a formação de ondulações entre as partes.', '', 95),
(9181, 'anexo', 181, 9179, 3, '10.8.2', 'Não serão aceitos objetos cujo fechamento seja realizado com clipes ou grampos metálicos, nem deverão estar contidos em seu interior, onde possam oferecer riscos aos empregados dos Correios e ao transporte e tratamento dos demais objetos.', '', 96),
(9182, 'anexo', 181, 9170, 2, '10.9', 'Fechamento de Pacote', '', 97),
(9183, 'anexo', 181, 9182, 3, '10.9.1', 'Os objetos fechados adequadamente pelo remetente não deverão ser lacrados novamente com fita adesiva plástica dos Correios.', '', 98),
(9184, 'anexo', 181, 9182, 3, '10.9.2', 'Os objetos fechados inadequadamente pelo remetente deverão receber reforço de fita adesiva plástica dos Correios, de forma a garantir o devido fechamento do objeto.', '', 99),
(9185, 'anexo', 181, 9170, 2, '10.10', 'Consultar as instruções adicionais de embalagens e acondicionamento contidas no Guia Técnico de Embalagens Recomendadas pelos Correios - RPC, disponível no portal Correios.', '', 100),
(9186, 'anexo', 181, NULL, 1, '11', 'ENDEREÇAMENTO', '', 101),
(9187, 'anexo', 181, 9186, 2, '11.1', 'O objeto deverá ser apresentado com rótulos de endereçamento considerando apenas um remetente e um destinatário, preenchidos de forma correta e completa, em concordância com o regulamento interno dos Correios e a legislação pertinente.', '', 102),
(9188, 'anexo', 181, 9187, 3, '11.1.1', 'É proibido o envio de remessa em anonimato.', '', 103),
(9189, 'anexo', 181, 9186, 2, '11.2', 'Para que a entrega do objeto internacional seja realizada, o endereçamento deve conter, no mínimo, as informações abaixo:', '', 104),
(9190, 'anexo', 181, 9189, 4, 'a', 'nome do destinatário;', '', 105),
(9191, 'anexo', 181, 9189, 4, 'b', 'endereço completo;', '', 106),
(9192, 'anexo', 181, 9189, 4, 'c', 'código postal;', '', 107),
(9193, 'anexo', 181, 9189, 4, 'd', 'nome do país de destino na última linha.', 'Nota: o remetente poderá optar por também escrever os indicativos de endereço e o nome do destinatário no idioma local do destino.', 108),
(9194, 'anexo', 181, 9186, 2, '11.3', 'Recomenda-se verificar se o cliente possui o e-mail e telefone do destinatário, para facilitar o processo de desembaraço no destino.', '', 109),
(9195, 'anexo', 181, 9186, 2, '11.4', 'Os Correios não se responsabilizam pela demora na execução de qualquer serviço, resultante de omissão ou erro por parte do cliente.', '', 110),
(9196, 'anexo', 181, NULL, 1, '12', 'ENDEREÇAMENTO COM ETIQUETA LÓGICA', '', 111),
(9197, 'anexo', 181, 9196, 2, '12.1', 'Quando o cliente gerar suas próprias etiquetas de registro, por meio do Correios Web Service ou de sistemas próprios de postagem, não será necessário utilizar chancelas de franqueamento.', '', 112),
(9198, 'anexo', 181, 9197, 3, '12.1.1', 'Nesse caso, o rótulo de endereçamento deve incluir o número do contrato, ano em que foi celebrado, sigla da Superintendência Estadual - SE de origem do contrato, sigla e o nome completo da contratante.', '12.1.1.1 Os dados que sejam coincidentes com os dados do cliente não necessitam ser repetidos.', 113),
(9199, 'anexo', 181, 9197, 3, '12.1.2', 'Os símbolos da linha de remessa postal para o envio de Documento Internacional e Exporta Fácil também devem ser utilizados pelos clientes que geram etiquetas lógicas, sendo:', 'Expresso	Standard	Econômico', 114),
(9200, 'anexo', 181, NULL, 1, '13', 'PRAZO DE GUARDA DE OBJETOS INTERNACIONAIS DE EXPORTAÇÃO', '', 115),
(9201, 'anexo', 181, 9200, 2, '13.1', 'Na postagem internacional de exportação, o prazo de guarda é considerado quando há devolução ao remetente no Brasil.', '', 116),
(9202, 'anexo', 181, 9201, 3, '13.1.1', 'Nesses casos, o objeto fica disponível para ser retirado pelo cliente, na agência, após as tentativas de devolução ou quando endereçado para Caixa Postal, conforme prazos abaixo:', '', 117),
(9203, 'anexo', 181, 9202, 4, 'a', 'documentos internacionais (modalidade Standard, Mala M, Cecograma Internacional, Carta-Resposta Internacional postados no Brasil): seguirão as mesmas regras definidas para as Cartas Simples/Registradas nacionais;', '', 118),
(9204, 'anexo', 181, 9202, 4, 'b', 'Documento Internacional Expresso, Exporta Fácil Expresso: prazo de 7 (sete) dias corridos;', '', 119),
(9205, 'anexo', 181, 9202, 4, 'c', 'Exporta Fácil Standard e Exporta Fácil Econômico: prazo de 20 (vinte) dias corridos;', '', 120),
(9206, 'anexo', 181, 9202, 4, 'd', 'objeto endereçado a Caixa Postal: prazo de 30 (trinta) dias corridos.', '', 121),
(9207, 'anexo', 181, 9200, 2, '13.2', 'Objetos em devolução que possam ser mantidos na Caixa Postal permanecerão em guarda pelo tempo que durar a assinatura.', '', 122),
(9208, 'anexo', 181, 9200, 2, '13.3', 'Quando houver o vencimento dos prazos definidos, o objeto com origem no exterior será tratado conforme indicado pelo cliente (devolver, tratar como abandonado ou outros).', '', 123),
(9209, 'anexo', 181, NULL, 1, '14', 'DESISTÊNCIA DE POSTAGEM DE EXPORTAÇÃO PELO REMETENTE', '', 124),
(9210, 'anexo', 181, 9209, 2, '14.1', 'O cliente pode desistir da postagem da remessa internacional de exportação diretamente na unidade de origem, desde que o objeto não tenha sido expedido fisicamente para outra unidade.', '', 125),
(9211, 'anexo', 181, 9210, 3, '14.1.1', 'Se o sistema de atendimento permitir, o atendente deve proceder com o estorno da postagem, entregar o objeto ao cliente e providenciar ou solicitar a devolução do valor pago, conforme os procedimentos previstos para cada forma de pagamento.', '', 126),
(9212, 'anexo', 181, 9210, 3, '14.1.2', 'Se o sistema não permitir o estorno da postagem, o atendente deve devolver o objeto ao cliente e solicitar a devolução do valor pago, conforme os procedimentos previstos.', '', 127),
(9213, 'anexo', 181, 9210, 3, '14.1.3', 'Os procedimentos para retirada do objeto e devolução dos valores ao cliente devem ser executados conforme orientações dispostas no MANATE 2/2.', '', 128),
(9214, 'anexo', 181, 9210, 3, '14.1.4', 'O processo de devolução deve considerar a restituição integral dos valores pagos a título de ad valorem.', '', 129),
(9215, 'anexo', 181, 9210, 3, '14.1.5', 'Não serão restituídos valores relativos a embalagens, etiquetas de registro ou outros produtos dos Correios que tenham valor próprio.', '', 130),
(9216, 'anexo', 181, 9210, 3, '14.1.6', 'Para postagem franqueada com selo ou máquina de franquear não há ressarcimento do valor de postagem nem dos serviços adicionais inclusos.', '', 131),
(9217, 'anexo', 181, 9210, 3, '14.1.7', 'O cliente poderá desistir de postagem referente a qualquer serviço de exportação, desde que atendidos os critérios estabelecidos neste Anexo.', '', 132),
(9218, 'anexo', 181, 9209, 2, '14.2', 'Quando a remessa já tiver sido expedida fisicamente da unidade de origem, não poderá haver a desistência da postagem e o cliente deve ser orientado a acionar a funcionalidade de Suspensão de Entrega de Objetos, no portal dos Correios.', '', 133),
(9219, 'anexo', 181, NULL, 1, '15', 'SUSPENSÃO DE ENTREGA DE REMESSA DE EXPORTAÇÃO', '', 134),
(9220, 'anexo', 181, 9219, 2, '15.1', 'A suspensão da entrega da remessa de exportação pode ser solicitada pelo cliente, caso ele queira interromper seu envio e a remessa já tenha sido expedida fisicamente da unidade de postagem.', '', 135),
(9221, 'anexo', 181, 9220, 3, '15.1.1', 'Nesse caso, o atendente deve orientar o cliente a acionar a funcionalidade de Suspensão de Entrega de Objetos, no portal dos Correios.', '', 136),
(9222, 'anexo', 181, 9220, 3, '15.1.2', 'A efetividade da suspensão da entrega dependerá de viabilidade dos Correios e ocorrerá desde que o objeto não tenha sido expedido para o país de destino, ou seja, antes da apresentação da remessa de exportação à companhia aérea.', '', 137),
(9223, 'anexo', 181, 9220, 3, '15.1.3', 'Caso a suspensão seja efetivada, o cliente poderá solicitar o ressarcimento parcial da postagem, por meio de abertura de manifestação, conforme orientações dispostas no MANCAT 32/4/2.', '', 138),
(9224, 'anexo', 181, 9220, 3, '15.1.4', 'O processo de ressarcimento parcial deve considerar a restituição integral dos valores pagos a título de ad valorem.', '', 139),
(9225, 'anexo', 181, 9220, 3, '15.1.5', 'Não serão ressarcidos valores relativos a embalagens, etiquetas de registro ou outros produtos dos Correios que tenham valor próprio.', '', 140),
(9226, 'anexo', 181, 9219, 2, '15.2', 'A suspensão de entrega da remessa internacional de exportação pode ser realizada para os serviços registrados:', '', 141),
(9227, 'anexo', 181, 9226, 4, 'a', 'Exporta Fácil Expresso;', '', 142),
(9228, 'anexo', 181, 9226, 4, 'b', 'Exporta Fácil Standard;', '', 143),
(9229, 'anexo', 181, 9226, 4, 'c', 'Exporta Fácil Econômico;', '', 144),
(9230, 'anexo', 181, 9226, 4, 'd', 'Documento Internacional Expresso;', '', 145),
(9231, 'anexo', 181, 9226, 4, 'e', 'Documento Internacional Standard com adicional de registro.', '', 146),
(9232, 'anexo', 181, 9219, 2, '15.3', 'As regras para suspensão de entrega de objetos internacionais, via portal dos Correios, e para ressarcimento parcial da postagem estão descritas no presente Anexo e no MANCAT 32/4/2.', '', 147),
(9233, 'anexo', 181, NULL, 1, '16', 'CANCELAMENTO DA EXPORTAÇÃO', '', 148),
(9234, 'anexo', 181, 9233, 2, '16.1', 'O envio de uma remessa ao exterior pode ser cancelado por circunstâncias que inviabilizem sua exportação e estejam fora do controle dos Correios, conforme descritas abaixo:', '', 149),
(9235, 'anexo', 181, 9234, 4, 'a', 'caso fortuito ou de força maior, tais como: terremoto, ciclone, tempestade, inundação, guerra, queda de aeronave, embargo, condições climáticas inapropriadas, greves, atos ou omissões de autoridades públicas, ou similares que ocorrerem sem que haja culpa dos Correios;', '', 150),
(9236, 'anexo', 181, 9234, 4, 'b', 'qualquer ato ou omissão do cliente (declaração incorreta de conteúdo, mal acondicionamento ou endereço insuficiente), do destinatário, de um terceiro, de um profissional de alfândega e de outros oficiais governamentais;', '', 151),
(9237, 'anexo', 181, 9234, 4, 'c', 'danos de natureza elétrica, magnética ou por perda ou avaria de imagens, gravações eletrônicas, fotográficas ou de filmagens;', '', 152),
(9238, 'anexo', 181, 9234, 4, 'd', 'devolução do objeto que tenha sido ocasionada por erro do cliente ou por órgão de fiscalização;', '', 153),
(9239, 'anexo', 181, 9234, 4, 'e', 'envio de conteúdo proibido ou que apresentem indícios que as enquadrem em alguma restrição ao transporte.', '', 154),
(9240, 'anexo', 181, 9234, 3, '16.1.1', 'Nesses casos, o cliente poderá solicitar o ressarcimento parcial da postagem, por meio de abertura de manifestação, conforme orientações dispostas no MANCAT 32/4/2.', '', 155),
(9241, 'anexo', 181, 9234, 3, '16.1.2', 'O processo de ressarcimento parcial deve considerar a restituição integral dos valores pagos a título de ad valorem.', '', 156),
(9242, 'anexo', 181, 9234, 3, '16.1.3', 'Não serão ressarcidos valores relativos a embalagens, etiquetas de registro ou outros produtos dos Correios que tenham valor próprio.', '', 157),
(9243, 'anexo', 181, 9234, 3, '16.1.4', 'A análise do ressarcimento parcial de postagem de remessa internacional de exportação pode ser realizada para os serviços registrados:', 'a)	Exporta Fácil Expresso;\nb)	Exporta Fácil Standard;\nc)	Exporta Fácil Econômico;\nd)	Documento Internacional Expresso;\ne)	Documento Internacional Standard com adicional de registro.', 158),
(9244, 'anexo', 181, 9233, 2, '16.2', 'As regras envolvendo o cancelamento da exportação e ressarcimento parcial da postagem estão descritas no presente Anexo e no MANCAT 32/4/2.', '', 159),
(9245, 'anexo', 181, NULL, 1, '17', 'RESPONSABILIDADES', '', 160),
(9246, 'anexo', 181, 9245, 2, '17.1', 'Os Correios não se responsabilizam:', '', 161),
(9247, 'anexo', 181, 9246, 4, 'a', 'pelo conteúdo do documento ou da encomenda;', '', 162),
(9248, 'anexo', 181, 9246, 4, 'b', 'por valor incluído em objeto sem declaração de valor;', '', 163),
(9249, 'anexo', 181, 9246, 4, 'c', 'pela demora ou prejuízo resultante de omissão ou erro por parte do remetente;', '', 164),
(9250, 'anexo', 181, 9246, 4, 'd', 'por objeto apreendido, confiscado ou destruído por autoridade competente;', '', 165),
(9251, 'anexo', 181, 9246, 4, 'e', 'em caso fortuito ou de força maior;', '', 166),
(9252, 'anexo', 181, 9246, 4, 'f', 'por prejuízos indiretos e benefícios não realizados.', '', 167),
(9253, 'anexo', 181, 9245, 2, '17.2', 'O cliente é totalmente responsável:', '', 168),
(9254, 'anexo', 181, 9253, 4, 'a', 'pelas informações apresentadas no momento da postagem, não cabendo à agência a conferência do conteúdo;', '', 169),
(9255, 'anexo', 181, 9253, 4, 'b', 'pelo cumprimento da legislação tributária vigente.', '* * * * *', 170),
(9256, 'anexo', 182, NULL, 2, '1.1', 'Carta-Resposta Internacional', '1.1.1 Dimensões:', 0),
(9257, 'anexo', 182, 9256, 4, 'a', 'mínimas: 9 cm × 14 cm;', '', 1),
(9258, 'anexo', 182, 9256, 4, 'b', 'máximas: 11,4 cm × 22,9cm;', '', 2),
(9259, 'anexo', 182, 9256, 4, 'c', 'peso: 50 gramas.', '1.1.2 Modalidade: econômica.\n1.1.3 Forma de pagamento: à vista ou a faturar.\n1.1.4 Disponível somente mediante contrato conforme as demais regras previstas para o serviço nacional.\n1.1.5 Modelo de Carta-Resposta Internacional\n1.1.6 Inserir os dados da agência responsável no lado direito da Carta-Resposta Internacional: nome, CEP, cidade, Superintendência Estadual - SE e o número do contrato vigente.', 3),
(9260, 'anexo', 182, NULL, 2, '1.2', 'Cecograma Internacional', '1.2.1 Dimensões:', 4),
(9261, 'anexo', 182, 9260, 4, 'a', 'mínimas: 9 cm × 14 cm ou rolo: comprimento + 2× o diâmetro = 17 cm (maior dimensão não inferior a 10 cm);', '', 5),
(9262, 'anexo', 182, 9260, 4, 'b', 'máximas: comprimento + largura + espessura = 90 cm (maior dimensão exceder 60 cm) ou rolo: comprimento + 2× o diâmetro = 104 cm (maior dimensão não pode exceder 90 cm).', '1.2.2 Peso: até 7 kg.\n1.2.3 Modalidade: econômica.\n1.2.4 Serviços adicionais: não há.\n1.2.5 Forma de pagamento: serviço isento de taxas de postagem (gratuito).\n1.2.6 Outras considerações:', 6),
(9263, 'anexo', 182, 9260, 4, 'a', 'também são considerados cecogramas: clichês, registros sonoros e sinais cecográficos, desde que acondicionados e expedidos por instituições de cegos oficialmente reconhecidas ou endereçadas a elas;', '', 7),
(9264, 'anexo', 182, 9260, 4, 'b', 'os objetos deverão ser apresentados abertos e somente serão fechados após verificação das condições de aceitação.', '', 8),
(9265, 'anexo', 182, NULL, 2, '1.3', 'Mala M', '1.3.1 Dimensões:', 9),
(9266, 'anexo', 182, 9265, 4, 'a', 'mínimas: 9 cm × 14 cm ou rolo: comprimento + 2× o diâmetro = 17 cm (maior dimensão não inferior a 10 cm);', '', 10),
(9267, 'anexo', 182, 9265, 4, 'b', 'máximas: comprimento + largura + espessura = 90 cm (maior dimensão exceder 60 cm) ou rolo: comprimento + 2× o diâmetro = 104 cm (maior dimensão não pode exceder 90 cm).', '1.3.2 Peso: até 30 kg.\n1.3.3 Modalidade: econômica.\n1.3.4 Serviços adicionais: não oferece o registro para esse serviço.\n1.3.5 Forma de pagamento: a faturar.\n1.3.6 Outras considerações:', 11),
(9268, 'anexo', 182, 9265, 4, 'a', 'disponível apenas mediante contrato;', '', 12),
(9269, 'anexo', 182, 9265, 4, 'b', 'os objetos serão acondicionados, desde a sua postagem até a sua entrega, em única embalagem postal com peso máximo de 30 kg, conforme aceitação do país de destino;', '', 13),
(9270, 'anexo', 182, 9265, 4, 'c', 'cada Mala M será considerada como único objeto;', '', 14),
(9271, 'anexo', 182, 9265, 4, 'd', 'o conteúdo da Mala M deverá ser agrupado em malas distintas, da seguinte forma:', 'I - livros, revistas, jornais, papéis de música, mapas e cartas geográficas;\nII- demais impressos;', 15),
(9272, 'anexo', 182, 9265, 4, 'e', 'não é permitido o envio de qualquer bem ou mercadoria, com ou sem valor intrínseco (brindes, amostras, etc.), mesmo se integrante de peça publicitária;', '', 16),
(9273, 'anexo', 182, 9265, 4, 'f', 'o remetente deverá apresentar a Mala “M” fechada para postagem, conforme cláusulas constantes do contrato;', '', 17),
(9274, 'anexo', 182, 9265, 4, 'g', 'o remetente apresentará o cartão de habilitação para efetuar a postagem da Mala M, preencherá o Formulário de Postagem - AWB e a etiqueta-endereço, contendo, no anverso, todas as informações relativas ao destinatário;', '', 18),
(9275, 'anexo', 182, 9265, 4, 'h', 'no verso da etiqueta-endereço, deverão constar:', 'I - menção \"Taxe Perçue\";\nII - montante total pago;\nII - número do comprovante;\nIV - carimbo datador da unidade de postagem;\nV - número de registro (etiqueta com código de barras), se for o caso;\nVI - número do selo plástico, se for o caso;\nVII - a menção \"M\".', 19),
(9276, 'anexo', 182, NULL, 1, '2', 'PRODUTOS INTERNACIONAIS', '2.1 Cupom Resposta Internacional\n2.1.1 Dimensões:', 20),
(9277, 'anexo', 182, 9276, 4, 'a', 'mínimas: 9 cm × 14 cm;', '', 21),
(9278, 'anexo', 182, 9276, 4, 'b', 'máximas: 10,5 cm × 14,8 cm.', '2.1.2 Modalidade: prioritária.\n2.1.3 Serviço adicionais: não há.\n2.1.4 Forma de pagamento: à vista ou a faturar. Venda disponível somente na loja online.\n2.1.5 Outras considerações:', 22),
(9279, 'anexo', 182, 9276, 4, 'a', 'pode ser vendido ou trocado em outros países por selos postados ao valor de referência previamente estabelecido para cada país;', '', 23),
(9280, 'anexo', 182, 9276, 4, 'b', 'não rasurar, amassar nem dobrar o cupom, pois ele perderá validade;', '', 24),
(9281, 'anexo', 182, 9276, 4, 'c', 'na venda, o cupom deverá ser obliterado (carimbado) no campo “carimbo do correio de origem”;', '', 25),
(9282, 'anexo', 182, 9276, 4, 'd', 'na troca, o atendente não deverá aceitar cupom com prazo de validade expirado (validade impressa no cupom);', '', 26),
(9283, 'anexo', 182, 9276, 4, 'e', 'só serão trocados cupons vindos do exterior, o que pode ser indicado pelo carimbo de origem do cupom ou pelo nome do país impresso no cupom;', '', 27),
(9284, 'anexo', 182, 9276, 4, 'f', 'o valor base de troca do cupom corresponde ao 1º porte do Documento Internacional Standard do país de destino;', '', 28),
(9285, 'anexo', 182, 9276, 4, 'g', 'o cupom deverá ser guardado para prestação de contas no fechamento do dia;', '', 29),
(9286, 'anexo', 182, 9276, 4, 'h', 'todas as agências estão habilitadas a efetuar a troca do cupom;', '', 30),
(9287, 'anexo', 182, 9276, 4, 'i', 'caso o portador deseje trocar seu cupom por um ou mais selos específicos, o atendente deverá verificar se o valor base de troca é suficiente para a compra, devendo solicitar a complementação do valor ou devolver a diferença em selos postais;', '', 31),
(9288, 'anexo', 182, 9276, 4, 'j', 'os cupons de outros países trocados nas agências, devem ser enviados ao órgão responsável pelo acerto de contas do serviço.', '* * * * *', 32),
(9289, 'anexo', 183, NULL, 1, '1', 'ORIENTAÇÕES GERAIS', '1.1 Para serem admitidos no ato da postagem, os objetos devem atender a determinadas especificações de peso, dimensões, acondicionamento, formato, endereçamento e franqueamento, de acordo com as instruções estabelecidas nas normas em vigor nos Correios, previstas em convenções, acordos internacionais ou definidas por lei.\n1.2 São proibidas as postagens de objetos que contenham qualquer bem cuja exportação esteja suspensa ou vetada pelas autoridades brasileiras ou qualquer bem cuja importação esteja suspensa ou vetada pelas autoridades do país de destino.\n1.3 Conforme as normas vigentes, objetos postais contendo materiais proibidos serão devolvidos ao remetente, desde que não comprometam a segurança do fluxo postal.\n1.3.1 Nos demais casos, serão encaminhados às autoridades competentes para adoção das medidas necessárias.\n1.4 Se for constatada avaria ou vazamento em qualquer embalagem que contenha material perigoso deve-se:', 0),
(9290, 'anexo', 183, 9289, 4, 'a', 'evitar o manuseio da embalagem ou reduzi-lo ao mínimo;', '', 1),
(9291, 'anexo', 183, 9289, 4, 'b', 'inspecionar as embalagens adjacentes para verificar se foram avariadas devido ao vazamento;', '', 2),
(9292, 'anexo', 183, 9289, 4, 'c', 'separar as que possam ter sido contaminadas;', '', 3),
(9293, 'anexo', 183, 9289, 4, 'd', 'notificar o remetente.', '1.5 Conforme previsto na Convenção Postal Universal, na Lei nº 6.538, de 22 de junho de 1978 e no Decreto nº 9.358, de 30 de abril de 2018, o remetente de qualquer objeto postal é responsável pelos danos corporais sofridos pelos agentes dos correios e por quaisquer danos causados aos outros objetos postais e ao equipamento postal em consequência da expedição de objetos não admitidos para transporte ou da inobservância das condições de admissão em virtude de inobservância dos dispositivos legais e regulamentares, desde que não tenha havido erro ou negligência da empresa exploradora do serviço postal ou do transportador.\n1.6 Não é permitida a postagem de documento com declaração de valor.', 4),
(9294, 'anexo', 183, NULL, 1, '2', 'PROIBIÇÕES E RESTRIÇÕES', '2.1 As proibições e restrições para envio por objeto postal estão publicadas na página dos Correios.\n2.2 Além das proibições que constam das regras do MANCAT 12/1, é proibida ou restrita a postagem de:', 5),
(9295, 'anexo', 183, 9294, 4, 'a', 'medicamentos não controlados em forma sólida. Para que possam ser postados, tais medicamentos devem estar acompanhados de:', 'I -	receita médica contendo o nome do destinatário do objeto com data recente em duas vias, uma em português, outra em inglês;\nII -		1 (uma) via do comprovante de compra do medicamento (nota fiscal, cupom fiscal ou comprovante do Sistema Único de Saúde - SUS). É esse documento de compra ou aquisição que comprova que a medicação foi adquirida em instituição farmacêutica com devida regularidade fiscal;\nIII -	3 (três) vias da fatura comercial emitida pelos Correios no sistema de atendimento na agência ou pré-postagem para pessoa física;\nIV -	vias da Airway Bill - AWB emitidas pelos Correios no sistema de atendimento na agência ou pré-postagem.', 6),
(9296, 'anexo', 183, 9294, 4, 'b', 'medicamentos não controlados na forma líquida, creme, pomada ou gel somente podem ser postados por clientes de contrato conforme especificações do tipo (líquidos, cremes, pomadas, géis), de acordo com as normas vigentes. O envio é possível apenas se feito por pessoa jurídica com emissão de Ficha de Informações de Segurança de Produto Químico - FISQP preenchida e assinada pelo responsável técnico da fabricação do medicamento, com inclusão do registro do órgão de classe que o representa;', '', 7),
(9297, 'anexo', 183, 9294, 4, 'c', 'medicamentos controlados são proibidos conforme normas da Agência Nacional de Vigilância Sanitária - Anvisa;', 'Nota 1: as regras sobre medicamentos estão de acordo com Portaria SVS/MS nº 344/98, ANVISA RDC 430/2020 e RDC 653/2022.\nNota 2: todas as remessas estão sujeitas ao cumprimento das eventuais exigências do órgão sanitário do país de destino. Portanto, é de inteira responsabilidade tanto do remetente como do destinatário o conhecimento prévio dessas exigências. Os Correios não podem representar os clientes junto a esses órgãos. Sendo identificado conteúdo proibido, o objeto poderá ser devolvido, destruído ou apreendido.\nNota 3: o envio de medicamentos para Portugal é permitido, apenas, quando formalmente autorizado pelo órgão regulador português.', 8),
(9298, 'anexo', 183, 9294, 4, 'd', 'conteúdos líquidos e pastosos soomente são permitidos com contrato comercial e embalagem especificada com a frase \"Contém líquido não perigoso\", bem como, mediante comprovação de suas características químicas descritas na Ficha de Informações de Segurança de Produtos Químicos - FISPQ, conforme estabelecido na Norma Regulamentadora NR-26 do Ministério do Trabalho e Emprego - MTE;', '', 9),
(9299, 'anexo', 183, 9294, 4, 'e', 'joias e pedras preciosas: artigos de ouro, platina, prata, bronze, níquel ou qualquer outro metal de valor, cédula e moedas fora de circulação, selos ou qualquer outra fórmula de franqueamento, joias e artigos preciosos ou qualquer papel representativo de valor ao portador só podem ser aceitos acompanhados de documentação que comprove a origem da mercadoria e mediante contratação do serviço de Valor Declarado;', 'Nota 1: para envio de pedras preciosas e/ou joias destinadas ao exterior é necessário anexar documentação que comprove a origem da mercadoria, como nota fiscal eletrônica de aquisição ou nota fiscal de exportação ou Permissão de Lavra Garimpeira - PLG etc. e informar especificação técnica do tipo de material e sua respectiva gramatura no formulário de postagem AWB/CP72 (campos 3 e 7) ou no envelope plástico afixado na embalagem.\nNota 2: remessas declaradas como “presente”, mas que de acordo com avaliação dos auditores fiscais da Receita Federal possuam características comerciais, não serão expedidas para os países de destino, sendo devolvidas aos remetentes.', 10),
(9300, 'anexo', 183, 9294, 4, 'f', 'amostras de material biológico humano ou animal são permitidas apenas se exclusivamente recolhidas para fins de análise, pesquisa, investigação, diagnóstico, tratamento, transplante ou prevenção;', '', 11),
(9301, 'anexo', 183, 9294, 4, 'g', 'proibições e restrições por país de destino: as definições e exemplos citados neste Anexo não são exaustivos. Proibições e restrições específicas por país podem ser consultadas no site da União Postal Universal - UPU (www.upu.int) e podem ser alteradas a qualquer tempo, cabendo ao remetente certificar-se previamente da viabilidade e das condições de envio.', '2.2.1 Referente à alínea “f”, as amostras podem ser encaminhadas somente na modalidade Exporta Fácil Expresso, por meio de contrato celebrado com os Correios, desde que:', 12),
(9302, 'anexo', 183, 9294, 4, 'a', 'o material seja classificado como isento, ou seja, não deve conter agentes patogênicos ou que possam representar risco a saúde de seres humanos ou animais;', '', 13),
(9303, 'anexo', 183, 9294, 4, 'b', 'a classificação nessa categoria seja de responsabilidade do cliente. O objeto deve ser acompanhado de todos os documentos relativos ao embarque exigidos pelas autoridades locais e no destino, bem como de uma declaração (em português e inglês) contendo a descrição detalhada do produto e a finalidade do envio, mencionando que o remetente tem ciência de que o item será submetido ao equipamento de raio X e que o material e sua função não serão prejudicados;', '', 14),
(9304, 'anexo', 183, 9294, 4, 'c', 'o objeto seja acondicionado em embalagem adequada ao padrão International Air Transport Association - IATA (tríplice), incluindo as etiquetas em uma das superfícies da embalagem externa, contendo: \"Substância Biológica embalada em conformidade com a instrução de embalagem para isento exemplares-IATA, \"Exemplar humano\" ou \"Isento espécime animal\". O material não deve necessitar de refrigeração nem deve ser proibido no país de destino.', '* * * * *', 15);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(9305, 'anexo', 185, NULL, 1, '1', 'GENERALIDADES', '1.1 Acatar a vontade do cliente remetente, por meio da área executora do processo de recuperação de receita, quando for identificado no SRO que o objeto foi reintegrado ao fluxo postal e o cliente remetente se manifestou de forma proativa sobre a intenção de receber o objeto, seja em devolução ao remetente ou a entrega ao destinatário, mediante o cancelamento ou devolução do valor indenizado, tomando todas providências necessárias, desde que o objeto esteja em condições para entrega e não tenha sido encaminhado para refugo.\n1.2 Confirmar no ERP - Módulo de Indenização sobre a situação apresentada no subitem 3.1, por meio da área executora do processo de recuperação de receita, o status do pagamento da indenização e providenciar a recuperação do valor indenizado por meio do SRR, de forma automática para o caso de devolução ao remetente ou iniciar o processo de negociação de recuperação da indenização paga, por meio do SRR, se o objeto foi entregue ao destinatário.\nNota 1: para os objetos cujo tipo de serviço seja Remessa Expressa Cartão/Talão ou encomenda com etiqueta RFID (Radio Frequency Identification - Identificação por Radiofrequência) adquirida pelo cliente devidamente vinculada ao respectivo número de registro, não haverá recuperação de receita em nenhuma situação, conforme manual do formatador do serviço.\nNota 2: os objetos que estiverem com etiqueta RFID adquirida pelo cliente, devidamente vinculada ao respectivo número de registro, não serão submetidos a apuração de responsabilidade definida, conforme disciplinado no MANCOD 1/2, visto que o evento de baixa “Objeto em trânsito para a unidade” - OTU no Sistema de Rastreamento de Objetos - SRO é automática e decorrente de uma regra de negócio decidida pelo órgão formatador, para qual não há a possibilidade de definição da unidade ofensora.\nNota 3: para o serviço de Mensagem e Marketing, recuperar-se-á a receita apenas para casos em que o objeto for postado com Valor Declarado.\n1.3 Proceder com a recuperação do valor indenizado por extravio, referente ao Valor Declarado (se houver) ou indenização automática, mediante processo SEI e com a devida comunicação previa ao cliente, caso ocorra desistência da postagem pelo cliente, sem o devido lançamento tempestivo do evento “Desistência da Postagem” no sistema de rastreamento.\n1.4 Apurar o motivo da contestação, quando o cliente detentor do contrato contestar os valores recuperados, por meio da área responsável pela execução do processo de recuperação de receita, a qual deverá, juntamente com a área operacional, e, somente em casos procedentes, restituir ao cliente o valor recuperado.\n1.5 Solicitar, excepcionalmente e quando houver necessidade das unidades operacionais/força de vendas, à área executora do processo de recuperação de receita desbloqueio do objeto indenizado para que seja efetuada a entrega.\n1.5.1 Autorizar, por meio da área executora do processo de recuperação de receita, o desbloqueio somente mediante apresentação de autorização expressa do remetente ou detentor do contrato, por e-mail ou carta, concordando com o cancelamento ou recuperação da indenização.\n1.5.2. Solicitar, por meio da área executora do processo de recuperação de receita, o desbloqueio junto ao gestor nacional do SRO, informando o número do registro do objeto postal, a unidade operacional que deverá realizar a baixa e IP do concentrador do SRO da mesma.\nNota 1: o prazo para recuperar valores indenizados é de 5 (cinco) anos, contados a partir do pagamento da indenização, conforme art. 1º do Decreto 20.910, de 06 de janeiro de 1932.\nNota 2: a verificação do status do objeto indenizado no SRO deverá ser feita pelo SRR, até o limite de 5 (cinco) anos, contados da data de procedência da manifestação do cliente.\nNota 3: não haverá recuperação de receita para objetos que tiveram, por erro manual ou do sistema SRO, atribuição diferente do seu registro de letras e números de sequência AA111111111BR, que ocasionaram a procedência da reclamação e o pagamento de indenização.\n1.6 Restituir os valores a serem recuperados aos Correios das seguintes formas:', 0),
(9306, 'anexo', 185, 9305, 4, 'a', 'para cliente com contrato: débito em fatura;', '', 1),
(9307, 'anexo', 185, 9305, 4, 'b', 'para cliente sem contrato: crédito em conta bancária ou recolhimento em agência;', '', 2),
(9308, 'anexo', 185, 9305, 4, 'c', 'os dados bancários para recolhimento em agência serão informados ao cliente na mensagem enviada por meio do SRR;', '', 3),
(9309, 'anexo', 185, 9305, 4, 'd', 'para efetivação contábil da recuperação de receita deverá ser exclusivamente lançado na conta 01011.44411.030010.', '* * * * *', 4),
(9310, 'anexo', 188, NULL, 1, '1', 'CONCEITO', '', 0),
(9311, 'anexo', 188, 9310, 2, '1.1', 'Consiste em um conjunto de serviços de encomendas com benefícios a serem concedidos aos clientes em função de maior e melhor utilização das soluções de encomendas disponíveis.', '', 1),
(9312, 'anexo', 188, NULL, 1, '2', 'RELACIONAMENTO', '2.1 O relacionamento será realizado pela força de vendas que prestará consultoria comercial, esclarecendo dúvidas, fornecendo informações sobre os produtos e serviços e viabilizando a geração de novos negócios que atendam às necessidades dos clientes.', 2),
(9313, 'anexo', 188, NULL, 1, '3', 'CONTRAPARTIDAS', '', 3),
(9314, 'anexo', 188, 9313, 2, '3.1', 'Contrapartidas são condições a serem negociadas e cumpridas para acesso aos benefícios no âmbito da prestação dos serviços de encomendas.', '', 4),
(9315, 'anexo', 188, 9313, 2, '3.2', 'Independente da categoria do cliente na política comercial, o cliente só terá acesso ao pacote de serviços de encomendas com melhores benefícios se cumprir todas as contrapartidas previstas.', '', 5),
(9316, 'anexo', 188, NULL, 1, '4', 'BENEFÍCIOS', '', 6),
(9317, 'anexo', 188, 9316, 2, '4.1', 'São vantagens que podem ser obtidas com a utilização dos serviços de encomendas.', '', 7),
(9318, 'anexo', 188, 9316, 2, '4.2', 'Além dos benefícios comuns das categorias previstos no Termo de Categorização e Benefícios da Política Comercial, o cliente terá acesso a benefícios específicos dos pacotes de serviços de encomendas.', '', 8),
(9319, 'anexo', 188, 9316, 2, '4.3', 'Os benefícios específicos podem se sobrepor aos comuns.', '', 9),
(9320, 'anexo', 188, NULL, 1, '5', 'CONCESSÃO DOS PACOTES DE SERVIÇOS DE ENCOMENDAS', '', 10),
(9321, 'anexo', 188, 9320, 2, '5.1', 'Para a concessão dos pacotes de serviços deverá ser considerado o grau de relacionamento, partindo de clientes com postagem de pequeno volume de encomendas e baixo nível de relacionamento até os clientes com grande volume de encomendas e alto nível de relacionamento.', '', 11),
(9322, 'anexo', 188, 9320, 2, '5.2', 'O pacote será definido considerando o histórico da quantidade média de encomendas postadas ou potencial de novos negócios de encomendas nacionais com os Correios.', '', 12),
(9323, 'anexo', 188, 9322, 3, '5.2.1', 'Os pacotes de serviços, contrapartidas e benefícios específicos constam no Anexo 5 deste Capítulo.', '', 13),
(9324, 'anexo', 188, NULL, 1, '6', 'ALÇADAS DE APROVAÇÃO', '', 14),
(9325, 'anexo', 188, 9324, 2, '6.1', 'A competência para a concessão do pacote, bem como sua manutenção no contrato e periodicidade de revisão estão descritas abaixo:', 'PACOTES	ALÇADA	PERIODICIDADE DE REAVALIAÇÃO\nEncomenda Básico, Encomenda 1, 2 e 6	gestor de agência	anual\nEncomenda 3, 4, 5, 7, 8 e 9	ACOM, GCE, coordenadores ou gerente de vendas\nEncomenda 10, 11 e 12, 13, 14, 15 e 16	gerente corporativo ou chefe do Departamento de Vendas	semestral', 15),
(9326, 'anexo', 188, 9324, 2, '6.2', 'O empregado responsável pela concessão do pacote superior também poderá classificar para os inferiores.', '', 16),
(9327, 'anexo', 188, 9326, 3, '6.2.1', 'O gerente corporativo ou chefe do Departamento de Vendas poderá delegar alçada para empregados ocupantes de função distinta das descritas, desde que atuem com vendas ou relacionamento com o cliente.', '', 17),
(9328, 'anexo', 188, NULL, 1, '7', 'ALTERAÇÃO DE PACOTE', '', 18),
(9329, 'anexo', 188, 9328, 2, '7.1', 'A alteração de pacote e respectivos níveis poderá ocorrer a pedido do cliente ou a critério dos Correios:', '', 19),
(9330, 'anexo', 188, 9328, 2, '7.2', 'A solicitação de alteração por iniciativa do cliente para um pacote de serviços deverá ser formalizada por meio de carta ou ofício ou diretamente no Sistema Eletrônico de Informações (SEI) com no mínimo 15 (quinze) dias úteis antes do início da vigência do próximo ciclo de faturamento.', '', 20),
(9331, 'anexo', 188, 9330, 3, '7.2.1', 'Recebido o pedido de alteração de pacote com prazo inferior a quinze dias úteis para o próximo ciclo de faturamento, os Correios analisarão o pedido, que se for deferido, será autorizado para o ciclo de faturamento subsequente.', '', 21),
(9332, 'anexo', 188, 9328, 2, '7.3', 'A critério dos Correios, a alteração de pacote de serviços de encomendas poderá ocorrer a qualquer tempo, independente do período determinado se houver necessidade de ajuste para melhor performance comercial. A alteração deverá ser formalizada por meio de carta ou ofício juntamente com a justificativa da alteração.', '', 22),
(9333, 'anexo', 188, NULL, 1, '8', 'MECANISMOS DE CONTROLE', '', 23),
(9334, 'anexo', 188, 9333, 2, '8.1', 'A manutenção do pacote de serviços de encomendas está condicionada ao cumprimento das contrapartidas acordadas com os clientes, as quais serão monitoradas, com vistas à garantia do processo negocial e operacional, conforme tabela a seguir:', 'CONTRAPARTIDAS	MECANISMOS DE CONTROLE	RESPONSÁVEL\nComercial/\nOperacional	Valor mínimo	Faturamento ERP (Automático).	Gerência de Faturamento e Cobrança\nPostagem Industrial	Acompanhamento analítico da quantidade de postagens efetuadas, por meio dos relatórios dos sistemas de postagem, de captação e faturamento das encomendas (exemplo: SIGEP, SVP, ERP, ferramentas de análise...).\nVerificação manual nas unidades em que o sistema ainda não estiver parametrizado.	Unidade de captação\nPré-postagem eletrônica 	Checagem da encomenda no ato da postagem e amostral por meio de relatórios dos sistemas de pré-postagem e postagem.	Unidade de captação', 24),
(9335, 'anexo', 188, 9333, 2, '8.2', 'A verificação do cumprimento das contrapartidas deverá ser feita periodicamente com vistas a verificar a adequação do pacote de serviços do cliente ou promover a sua alteração.', '', 25),
(9336, 'anexo', 188, NULL, 1, '9', 'MATRIZ DE CONTRAPARTIDAS E BENEFÍCIOS ESPECÍFICOS', '', 26),
(9337, 'anexo', 188, 9336, 2, '9.1', 'A matriz constante do Anexo 5 deste capítulo associa os pacotes de serviços de encomendas, contrapartidas e benefícios, de forma padronizada.', '', 27),
(9338, 'anexo', 188, 9336, 2, '9.2', 'As contrapartidas, por sua vez, são condições determinantes para acesso às categorias e respectivos benefícios. Dessa forma, possibilitam a lucratividade na redução de preço associada, portanto, não podem ser dispensadas e precisarão ser monitoradas continuamente.', '', 28),
(9339, 'anexo', 188, 9338, 3, '9.2.1', 'Não será permitido a combinação de contrapartidas e benefícios diferentes dos definidos na matriz das contrapartidas e benefícios específicos dos pacotes de serviços de encomendas.', '* * * * *', 29),
(9340, 'anexo', 189, NULL, 1, '1', 'CONTRAPARTIDAS', '1.1 Valor mínimo mensal: valor mínimo de consumo a ser pago pelo cliente.\n1.2 Pré-postagem eletrônica: postagem por meio do aplicativo SIGEP WEB; integração com o Correios Web Services ou mídia eletrônica.\n1.2.1 SIGEP WEB: preparação da postagem por meio de aplicativo fornecido gratuitamente pelos Correios.\n1.2.2 Correios Web Services: integração entre o sistema proprietário do cliente e os sistemas dos Correios.\n1.2.2 Mídia eletrônica: apresentação, na postagem, de arquivo eletrônico no padrão definido pelos Correios, contendo os dados relativos às encomendas que estão sendo postadas.\n1.3 Postagem industrial: postagem de grandes quantidades realizadas em unidade habilitada dos Correios.', 0),
(9341, 'anexo', 189, NULL, 1, '2', 'BENEFÍCIOS ESPECÍFICOS', '2.1 Isenção de cobrança coleta programada: coleta programada de encomendas sem ônus para o cliente.\n2.2 Posto Coleta: posto dos Correios instalado em unidade do cliente onde ocorrem as atividades de recepção e conferência das encomendas.\n2.3 Posto Avançado: posto dos Correios instalado em unidade do cliente onde ocorrem as atividades de recepção, conferência e postagem das encomendas\n2.4 Assistente de pós-venda: atendimento realizado por profissional que atuará no esclarecimento de dúvidas, informações sobre produtos, serviços, faturamento e interação com as diversas áreas dos Correios para agilizar a apuração de reclamações.\n* * * * *', 1),
(9342, 'anexo', 192, NULL, 1, '1', 'SERVIÇOS PRINCIPAIS', '', 0),
(9343, 'anexo', 192, 9342, 2, '1.1', 'Os serviços de encomendas nacionais estão distribuídos em linhas de remessas postais, conforme definido no MANCAT 1/2/20.', '', 1),
(9344, 'anexo', 192, 9343, 3, '1.1.1', 'Serviços da Linha Premium:', '', 2),
(9345, 'anexo', 192, 9344, 4, 'a', 'SEDEX Hoje: permite a remessa de documentos e mercadorias com entrega garantida no mesmo dia de postagem;', '', 3),
(9346, 'anexo', 192, 9344, 4, 'b', 'SEDEX 10: permite a remessa de documentos e mercadorias com entrega garantida até as 10 horas do dia útil seguinte ao da postagem;', '', 4),
(9347, 'anexo', 192, 9344, 4, 'c', 'SEDEX 12: permite a remessa de documentos e mercadorias com entrega garantida até as 12 horas do dia útil seguinte ao da postagem.', '', 5),
(9348, 'anexo', 192, 9343, 3, '1.1.2', 'Serviço da Linha Expressa: SEDEX, o qual permite a remessa expressa de documentos e mercadorias.', '', 6),
(9349, 'anexo', 192, 9343, 3, '1.1.3', 'Serviço da Linha Standard: PAC, o qual permite a remessa não expressa apenas de mercadorias.', '1.1.3.1 Apostilas, calendários, catálogos, livros, materiais promocionais, processos administrativos, processos judiciais, publicações com fulcro informativo, revistas e provas corrigidas ou não, remetidas por escolas ou institutos de ensino à distância, podem ser enviados por meio do serviço PAC.\n1.1.3.2 documentos classificados como serviço de correspondência, conforme definido no MANCAT 6/2, não são permitidos para envio via PAC.', 7),
(9350, 'anexo', 192, 9343, 3, '1.1.4', 'Serviço da Linha Econômica: Correios Mini Envios, o qual permite a remessa de pequenos objetos e mercadorias de baixo valor comercial.', '', 8),
(9351, 'anexo', 192, NULL, 1, '2', 'SERVIÇOS INERENTES', '', 9),
(9352, 'anexo', 192, 9351, 2, '2.1', 'Os atributos inerentes aos serviços de encomendas nacionais são:', '', 10),
(9353, 'anexo', 192, 9352, 4, 'a', 'Devolução Garantida;', '', 11),
(9354, 'anexo', 192, 9352, 4, 'b', 'Entrega Domiciliar;', '', 12),
(9355, 'anexo', 192, 9352, 4, 'c', 'Indenização Automática;', '', 13),
(9356, 'anexo', 192, 9352, 4, 'd', 'Rastreamento;', '', 14),
(9357, 'anexo', 192, 9352, 4, 'e', 'Registro.', '', 15),
(9358, 'anexo', 192, NULL, 1, '3', 'SERVIÇOS ADICIONAIS E FUNCIONALIDADES', '', 16),
(9359, 'anexo', 192, 9358, 2, '3.1', 'Os serviços adicionais e as funcionalidades estão disponíveis para os serviços de encomendas nacionais conforme tabela abaixo:', 'SEDEX Hoje	SEDEX 10	SEDEX 12	SEDEX	PAC	Correios Mini Envios\nAviso de Recebimento Convencional - AR		X	X	X	X	X\nAviso de Recebimento Digital		X	X	X	X	X\nAviso de Recebimento Eletrônico	X	X	X	X	X	X\nCaixa de Correio Inteligente - CCI		X	X	X	X	X\nClique e Retire		X	X	X	X	X\nColeta Agendada (cliente com contrato)				X	X\nColeta Mesmo Dia (cliente com contrato)				X	X\nColeta Programada (cliente com contrato)	X	X	X	X	X	X\nComprovante Eletrônico de Entrega - CEE (cliente com contrato)	X	X	X	X	X\nDevolução de Documento - DD (cliente com contrato)				X	X\nEntrega no Vizinho	X	X	X	X	X\nGrandes Formatos - GF (cliente com contrato)				X	X\nLocker				X	X	X\nMão Própria - MP		X	X	X	X\nPagamento na Entrega				X	X\nValor Declarado - VD	X	X	X	X	X	X\nNota 1: o serviço adicional de Posta Restante Pedida está disponível apenas para a Logística Reversa, conforme MANCAT 16/4.\nNota 2: encomenda destinada ao Locker ou a Caixa de Correio Inteligente não é permitida a contratação de serviços adicionais que necessitam de assinatura do recebedor: Aviso de Recebimento, Devolução de Documento e Mão Própria.', 17),
(9360, 'anexo', 192, NULL, 1, '4', 'COBRANÇA ADICIONAL DE MANUSEIO ESPECIAL POR FORMATO OU DIMENSÃO', '', 18),
(9361, 'anexo', 192, 9360, 2, '4.1', 'A cobrança adicional é aplicada para encomenda que necessita de manuseio especial  devido ao seu formato ou dimensão.', '', 19),
(9362, 'anexo', 192, 9360, 2, '4.2', 'A cobrança é obrigatória nos seguintes casos:', '', 20),
(9363, 'anexo', 192, 9362, 4, 'a', 'na postagem de encomenda na qual a maior dimensão (comprimento, largura, altura ou diâmetro) é superior a 70 cm (de 71 cm a 100 cm):', '', 21),
(9364, 'anexo', 192, 9362, 4, 'b', 'na postagem de encomenda embalada em formato de rolo/cilindro ou esfera:', '', 22),
(9365, 'anexo', 192, 9362, 4, 'c', 'excepcionalmente, a cobrança não é aplicada se forem verificadas as seguintes condições, simultaneamente:', 'I -  diâmetro da encomenda em formato rolo/cilindro maior que o seu comprimento;\nII -  diâmetro menor ou igual a 70 cm;\nIII -  rótulo de endereçamento afixado na maior face da embalagem.', 23),
(9366, 'anexo', 192, 9362, 3, '4.2.1', 'As regras de cobrança adicional são aplicadas para todos os serviços de encomendas, nas modalidades à vista e a faturar, exceto Correios Mini Envios e Grandes Formatos - GF.', '', 24),
(9367, 'anexo', 192, 9360, 2, '4.3', 'Após a aferição do formato, das medidas e do peso do objeto a cobrança adicional é realizada de forma automática pelo sistema de atendimento.', '', 25),
(9368, 'anexo', 192, NULL, 1, '5', 'PÚBLICO-ALVO', '', 26),
(9369, 'anexo', 192, 9368, 2, '5.1', 'Pessoas físicas sem contrato e pessoas jurídicas com e sem contrato, para todos os serviços de encomendas nacionais, com exceção do Correios Mini Envios, que está disponível apenas para pessoas jurídicas com contrato.', '', 27),
(9370, 'anexo', 192, NULL, 1, '6', 'ABRANGÊNCIA', '', 28),
(9371, 'anexo', 192, 9370, 2, '6.1', 'Possuem abrangência nacional os serviços SEDEX, PAC e Correios Mini Envios.', '', 29),
(9372, 'anexo', 192, 9370, 2, '6.2', 'Os serviços da Linha Premium SEDEX Hoje, SEDEX 10 e SEDEX 12 possuem abrangência restrita às localidades com potencial comercial e viabilidade operacional para prestação, mediante habilitação prévia.', '', 30),
(9373, 'anexo', 192, 9372, 3, '6.2.1', 'A restrição da abrangência ocorre por:', '', 31),
(9374, 'anexo', 192, 9373, 4, 'a', 'área geográfica: região, estado (Unidade Federativa - UF), microrregião, cidade ou área urbana;', '', 32),
(9375, 'anexo', 192, 9373, 4, 'b', 'faixa de CEP;', '', 33),
(9376, 'anexo', 192, 9373, 4, 'c', 'sentido do fluxo postal: postagem ou distribuição;', '', 34),
(9377, 'anexo', 192, 9373, 4, 'd', 'índice de classificação da cidade;', '', 35),
(9378, 'anexo', 192, 9373, 4, 'e', 'preferencialmente, com prazo de entrega SEDEX definido em D+1.', '', 36),
(9379, 'anexo', 192, 9372, 3, '6.2.2', 'Quando a abrangência de um serviço for restrita, os trechos atendidos podem ser consultados no Portal Correios e/ou na intranet.', '', 37),
(9380, 'anexo', 192, 9372, 3, '6.2.3', 'A restrição de abrangência ocorre da seguinte forma:', '', 38),
(9381, 'anexo', 192, 9380, 4, 'a', 'SEDEX Hoje: cidades classificadas como A+, para distribuição apenas em âmbito local;', '', 39),
(9382, 'anexo', 192, 9380, 4, 'b', 'SEDEX 10: cidades de origem classificadas como A+, A e B, com destino a A+ e A;', '', 40),
(9383, 'anexo', 192, 9380, 4, 'c', 'SEDEX 12:', 'I -  cidades classificadas como A+ na região metropolitana, sem prestação de SEDEX 10;\nII -  cidades classificadas como A, para distribuição apenas em âmbito local;\nIII -  cidades classificadas como B.', 41),
(9384, 'anexo', 192, 9372, 3, '6.2.4', 'É admitida abrangência dos serviços da Linha Premium, exceto SEDEX Hoje, em cidades com classificações diferentes das relacionadas, desde que haja potencial comercial e viabilidade operacional.', '', 42),
(9385, 'anexo', 192, 9370, 2, '6.3', 'A alteração da abrangência dos serviços da Linha Premium observa as seguintes regras:', '', 43),
(9386, 'anexo', 192, 9385, 4, 'a', 'inclusão dos serviços SEDEX 10 e SEDEX 12, o demandante deve:', 'I - elaborar planilha (origem × destino), contendo os nomes das cidades, suas UFs e respectivas faixas de CEP;\nII - solicitar estimativa de demanda comercial (tráfego e faturamento), junto a área de vendas da Superintendência Estadual - SE;\nIII - providenciar parecer operacional quanto à disponibilidade de linhas de transporte, de recursos de tratamento e distribuição dos objetos para execução dos trechos, com validação final dos respectivos departamentos gestores dos processos;\nIV - encaminhar o parecer operacional ao DEPLA para validação final, via processo SEI, com posterior envio ao DEPRO.', 44),
(9387, 'anexo', 192, 9385, 4, 'b', 'ampliação de abrangência dos serviços SEDEX 10 e SEDEX 12, o demandante deve:', 'I - elaborar planilha (origem × destino), contendo os nomes das cidades, suas UFs e respectivas faixas de CEP;\nII - providenciar parecer operacional quanto à disponibilidade de linhas de transporte para execução dos trechos, com validação final do respectivo departamento gestor do processo;\nIII - encaminhar o parecer operacional ao DEPLA para validação final, via processo no Sistema Eletrônico de Informações - SEI, com posterior envio ao DEPRO.\nNota: a ampliação de abrangência é referente ao processo de expansão do serviço nas localidades onde já há prestação, motivo pelo qual é um processo mais simplificado do que o de inclusão de abrangência.', 45),
(9388, 'anexo', 192, 9385, 4, 'c', 'suspensão temporária ou exclusão definitiva dos serviços SEDEX Hoje, SEDEX 10 e SEDEX 12, o demandante deve:', 'I - elaborar planilha (origem × destino), contendo os nomes das cidades, suas UFs e respectivas faixas de CEP;\nII - elaborar justificativa, com definição de data de início e término quando da suspensão temporária ou de data de finalização quando da exclusão da abrangência, anexando a documentação relacionada ao pleito (Ex.: ficha técnica da linha cancelada etc.);\nIII - solicitar mapeamento da análise de impacto comercial, perda de tráfego e receita, junto a área de vendas da Superintendência Estadual - SE, apenas quando da exclusão definitiva;\nIV - solicitar parecer operacional ao DETRA, quando o problema estiver relacionado ao transporte, exceto SEDEX Hoje;\nV - solicitar parecer operacional ao DTRAT, quando o problema estiver relacionado ao tratamento, exceto SEDEX Hoje;\nVI - solicitar parecer operacional ao DEDIS, quando o problema estiver relacionado a distribuição;\nVII - encaminhar os pareceres operacionais ao DEPLA para validação final, via processo SEI, com posterior envio ao DEPRO;\nVIII - solicitar previamente, à execução dos ajustes, o parecer comercial ao DEPRO.', 46),
(9389, 'anexo', 192, 9385, 4, 'd', 'alteração da modalidade de serviço (SEDEX 10 × SEDEX 12 × SEDEX 10), o demandante deve:', 'I - elaborar planilha (origem × destino), contendo os nomes das cidades, suas UFs e respectivas faixas de CEP;\nII - solicitar mapeamento da análise de impacto comercial, redução de tráfego e receita, junto a área de vendas da Superintendência Estadual - SE;\nIII - elaborar nota técnica contendo a justificativa e o histórico acerca das ações adotadas, anteriores à solicitação de alteração da modalidade de serviço;\nIV - solicitar parecer operacional ao DETRA, quando o problema estiver relacionado ao transporte;\nV - solicitar parecer operacional ao DTRAT, quando o problema estiver relacionado ao tratamento;\nVI - solicitar parecer operacional ao DEDIS, quando o problema estiver relacionado a distribuição;\nVII - encaminhar os pareceres operacionais ao DEPLA para validação final, via processo SEI, com posterior envio ao DEPRO;\nVIII - solicitar previamente, à execução dos ajustes, o parecer comercial ao DEPRO.\nNota 1: a abrangência do SEDEX 12 deve abarcar distribuição nas cidades A+, A e B, quando as dificuldades operacionais inviabilizarem a distribuição de SEDEX 10, o que inclui também a falta de eficiência na mobilidade urbana.\nNota 2: o fluxo processual para alteração de serviço será tratado apenas em caráter excepcional e quando restar devidamente comprovado, de forma documental, que todas as alternativas possíveis foram adotadas e ainda assim não lograram êxito para a continuidade do serviço prioritário, SEDEX 10.', 47),
(9390, 'anexo', 192, 9385, 4, 'e', 'inclusão ou ampliação do serviço SEDEX Hoje, o demandante deve:', 'I - identificar os municípios classificados como A+, conforme metodologia dos corredores prioritários (MANCAT 16/2/2);\nII - elaborar estudo mercadológico, cujo conteúdo deve expor o potencial de incremento de receita, imediato e futuro, com a habilitação do serviço na SE, dentre outras informações que julgar importante consignar no relatório;\nIII - formalizar o pedido por meio de processo SEI, contendo as análises, a relação das faixas de CEP e as unidades operacionais e de atendimento, com os respectivos MCUs, em que a SE pretende habilitar o serviço.\nNota 1: a planilha Excel contendo os trechos (origem × destino) para habilitação do serviço deve seguir o padrão de cadastro do ERP, conforme exemplo abaixo:\nNota 2: as únicas colunas que devem ser preenchidas são: CEP Origem Inicial, CEP Origem Final, CEP Destino Inicial, CEP Destino Final e Início Vigência. Todas as demais colunas permanecem com os dados que constam no exemplo acima.\nNota 3: a planilha de abrangência vigente está disponível para consulta no seguinte endereço: http://snu0097.correiosnet.int/spcc/app/tabelas/abrangencia/', 48),
(9391, 'anexo', 192, 9370, 2, '6.4', 'Processos oriundos por motivos de caso fortuito ou força maior, classificados como situações emergenciais, ficam dispensados das análises prévias operacionais, em face da sua urgência.', '', 49),
(9392, 'anexo', 192, 9391, 3, '6.4.1', 'É enquadrado como caso fortuito o evento proveniente de ato humano, imprevisível e inevitável, que impede o cumprimento de uma obrigação, como: greves, guerras e afins.', '', 50),
(9393, 'anexo', 192, 9391, 3, '6.4.2', 'É enquadrado como força maior o evento proveniente das forças da natureza, previsível ou imprevisível, porém inevitável, como: raios, tempestades, deslizamentos e afins.', 'Nota: não são aceitas situações que não estejam enquadradas nos casos mencionados acima.', 51),
(9394, 'anexo', 192, 9391, 3, '6.4.3', 'Os serviços da Linha Premium são temporariamente descontinuados nas circunstâncias em que se configurem eventos de caso fortuito ou força maior, para as faixas de CEP que se encontrarem afetadas por tais eventualidades.', '', 52),
(9395, 'anexo', 192, 9391, 3, '6.4.4', 'Todos os processos devem ser tramitados via Sistema Eletrônico de Informações - SEI, independentemente de sua natureza.', '', 53),
(9396, 'anexo', 192, 9391, 3, '6.4.5', 'É responsabilidade da área demandante observar a necessidade de obtenção de pareceres regionais, além dos pareceres obrigatórios dos departamentos do Correios Sede -CS.', '', 54),
(9397, 'anexo', 192, 9391, 3, '6.4.6', 'Processos sem a documentação mencionada não são avaliados, sendo devolvidos à área demandante.', '', 55),
(9398, 'anexo', 192, NULL, 1, '7', 'LIMITES DE PESO', '', 56),
(9399, 'anexo', 192, 9398, 2, '7.1', 'Os limites máximos permitidos para peso físico (aferido em balança) são:', '', 57),
(9400, 'anexo', 192, 9399, 4, 'a', 'SEDEX Hoje: 10 kg;', '', 58),
(9401, 'anexo', 192, 9399, 4, 'b', 'SEDEX 10, SEDEX 12, SEDEX e PAC: 30 kg;', '', 59),
(9402, 'anexo', 192, 9399, 4, 'c', 'Correios Mini Envios: 300 g.', 'Nota: considerando os limites máximos de dimensões permitidos, o peso cubado obtido para o objeto pode chegar a 50 kg, exceto Correios Mini Envios.', 60),
(9403, 'anexo', 192, 9399, 3, '7.1.1', 'Para objeto PAC, o peso físico pode ser ampliado para 50 kg, quando se tratar de postagem em âmbito estadual, para clientes com contrato e mediante viabilidade operacional da SE.', '7.1.1.1 Postagem de objeto PAC destinado ao Locker deve seguir o peso físico padrão permitido para o serviço, ou seja, 30 kg.', 61),
(9404, 'anexo', 192, 9399, 3, '7.1.2', 'Objeto Correios Mini Envios com peso físico variando entre 301 g e 1 kg pode ser aceito, mas é precificado pela tabela do serviço PAC e seu encaminhamento ocorre pelo serviço contratado, ou seja, Correios Mini Envios.', '', 62),
(9405, 'anexo', 192, NULL, 1, '8', 'LIMITES DE DIMENSÕES', '', 63),
(9406, 'anexo', 192, 9405, 2, '8.1', 'São admitidas as seguintes dimensões para os serviços de encomendas:', 'Envelope	Pacote	Rolo\nSEDEX Hoje, SEDEX 10, SEDEX 12 e SEDEX:\nComprimento (C): de 16 cm a 60 cm\nLargura (L): de 11 cm a 60 cm\nSEDEX Hoje:\nComprimento (C): de 11 cm a 70 cm\nLargura (L): de 6 cm a 70 cm\nAltura (A): de 0,4 cm a 70 cm\nSoma das dimensões: de 17,4 cm a 200 cm\nSEDEX 10, SEDEX 12, SEDEX e PAC:\nComprimento (C): de 13 cm a 100 cm\nLargura (L): de 8 cm a 100 cm\nAltura (A): de 0,4 cm a 100 cm\nSoma das dimensões: de 21,4 cm a 200 cm\nCorreios Mini Envios:\nComprimento (C): de 13 cm a 24 cm\nLargura (L): de 8 cm a 16 cm\nAltura (A): de 0,4 cm a 4 cm\nSEDEX Hoje, SEDEX 10, SEDEX 12, SEDEX e PAC:\nComprimento (C): de 18 cm a 100 cm\nDiâmetro (D): de 5 cm a 91 cm\nSoma das dimensões [C + (2 × D)]: de 28 cm a 200 cm', 64),
(9407, 'anexo', 192, 9405, 2, '8.2', 'Envelope com altura superior a 2 cm é mensurado como pacote, exceto quando objeto Correios Mini Envios e PAC.', '', 65),
(9408, 'anexo', 192, 9405, 2, '8.3', 'Objeto Correios Mini Envios com comprimento acima de 24 cm até 36 cm e/ou largura acima de 16 cm até 24 cm pode ser aceito, mas é precificado pela tabela do serviço PAC e seu encaminhamento ocorre pelo serviço contratado, ou seja, Correios Mini Envios.', '', 66),
(9409, 'anexo', 192, 9405, 2, '8.4', 'Todo objeto destinado ao Locker deve observar os limites máximos de dimensões admitidos para o canal, quais sejam: 47 cm de comprimento, 31 cm de largura e 27 cm de altura.', '', 67),
(9410, 'anexo', 192, 9409, 3, '8.4.1', 'Objeto Correios Mini Envios deve observar o limite máximo permitido para o serviço e não para o canal.', '', 68),
(9411, 'anexo', 192, 9405, 2, '8.5', 'Para os objetos aferidos em cubômetros, com pelo menos uma das dimensões inferiores a 10 cm, são atribuídas as dimensões mínimas previstas para as encomendas nacionais.', '', 69),
(9412, 'anexo', 192, 9405, 2, '8.6', 'Envelope pode ser utilizado como invólucro de objeto postado por meio dos serviços PAC e Correios Mini Envios, desde que resista ao peso, à forma e à natureza do conteúdo, bem como às condições de transporte.', '', 70),
(9413, 'anexo', 192, 9405, 2, '8.7', 'Quando da utilização de envelope como embalagem de um determinado produto, o remetente deve assegurar o devido acondicionamento, de modo a preservar a integridade do item até a efetiva entrega ao destinatário.', '', 71),
(9414, 'anexo', 192, NULL, 1, '9', 'PESO CUBADO', '', 72),
(9415, 'anexo', 192, 9414, 2, '9.1', 'A precificação considerando a relação peso físico × peso cubado deve ser aplicada para todos os serviços de encomendas, com exceção de envelopes e de objetos Correios Mini Envios. Para a precificação desses serviços é considerado apenas o peso físico.', '', 73),
(9416, 'anexo', 192, 9415, 3, '9.1.1', 'A precificação de objeto processado em ponto de coleta ou pré-postado à vista nos canais digitais (aplicativo ou web) considera apenas o peso cubado do objeto, dispensando a aferição de peso físico, em balança.', '', 74),
(9417, 'anexo', 192, 9414, 2, '9.2', 'As regras de isenção para precificação cúbica constam nas respectivas tabelas de preços e podem ser consultadas no seguinte endereço: \\\\sac0424\\SISTEMAS\\PRECOS_TARIFAS', '', 75),
(9418, 'anexo', 192, 9414, 2, '9.3', 'Para a aferição do peso cubado, devem ser consideradas as dimensões, em centímetros, observando-se os seguintes critérios:', '', 76),
(9419, 'anexo', 192, 9418, 4, 'a', 'encomenda quadrada ou retangular: medir o comprimento, a largura e a altura;', '', 77),
(9420, 'anexo', 192, 9418, 4, 'b', 'encomenda cilíndrica ou rolo: medir o comprimento e o diâmetro;', '', 78),
(9421, 'anexo', 192, 9418, 4, 'c', 'encomenda esférica: medir o diâmetro e aplicar a mesma medida ao comprimento;', '', 79),
(9422, 'anexo', 192, 9418, 4, 'd', 'outros formatos de encomendas: medir o comprimento, a largura e a altura, considerando a parte mais representativa de cada dimensão.', '', 80),
(9423, 'anexo', 192, 9414, 2, '9.4', 'O peso cubado para caixa ou pacote é calculado da seguinte forma:', 'Comprimento × Largura × Altura\nFator Cubagem', 81),
(9424, 'anexo', 192, 9414, 2, '9.5', 'O peso cubado para rolo/cilindro e esfera é calculado da seguinte forma:', '? × Raio² × Altura\nFator Cubagem\nNota:  ? (Pi) equivale a 3,14\nRaio é a metade do diâmetro obtido\nAltura é o comprimento obtido', 82),
(9425, 'anexo', 192, 9414, 2, '9.6', 'Para os canais Locker, Ponto de Coleta e Aplicativo Correios, o fator cubagem é 7.000, para os demais canais o fator cubagem é 6.000.', '', 83),
(9426, 'anexo', 192, NULL, 1, '10', 'EMBALAGEM E ACONDICIONAMENTO', '', 84),
(9427, 'anexo', 192, 9426, 2, '10.1', 'A encomenda deve ser acondicionada e fechada pelo remetente em embalagem que resista ao peso, à forma e à natureza do conteúdo, bem como às condições de transporte.', '', 85),
(9428, 'anexo', 192, 9426, 2, '10.2', 'É admitida a postagem de encomenda em envelope ou caixa que atenda às condições de acondicionamento exigidas.', '', 86),
(9429, 'anexo', 192, 9426, 2, '10.3', 'Objeto PAC e Correios Mini Envios acondicionado em envelope é lançado no sistema de atendimento como formato de \"pacote”.', '', 87),
(9430, 'anexo', 192, 9426, 2, '10.4', 'A encomenda pode ser postada em embalagem reutilizada, desde que as condições descritas nos subitens anteriores sejam atendidas e ainda:', '', 88),
(9431, 'anexo', 192, 9430, 4, 'a', 'a estrutura e a integridade da embalagem estejam preservadas;', '', 89),
(9432, 'anexo', 192, 9430, 4, 'b', 'não haja indício de violação em manuseio anterior, como por exemplo rasgos e remendos;', '', 90),
(9433, 'anexo', 192, 9430, 4, 'c', 'esteja sem marcações de postagem anterior ou quaisquer outras indicações ou insígnias operacionais de logística de entrega;', '', 91),
(9434, 'anexo', 192, 9430, 4, 'd', 'indicações de serviço ou código de barras devem ser cobertos ou sobrepostos pelo novo rótulo de endereçamento e código de rastreamento dos Correios.', '', 92),
(9435, 'anexo', 192, 9430, 3, '10.4.1', 'A embalagem da encomenda pode, de maneira facultativa, ser reforçada com invólucros plásticos, papel liso ou ainda qualquer material que seja capaz de resistir às condições de transporte.', '', 93),
(9436, 'anexo', 192, 9430, 3, '10.4.2', 'São exemplos de embalagens íntegras que atendem as condições de postagem:', '', 94),
(9437, 'anexo', 192, 9430, 3, '10.4.3', 'São exemplos de embalagens danificadas e/ou com indícios de violação, pouco resistentes ao fluxo postal, que portanto não atendem as condições de postagem:', '', 95),
(9438, 'anexo', 192, 9426, 2, '10.5', 'O envio de determinados materiais exige um acondicionamento especial, conforme exemplos a seguir:', '', 96),
(9439, 'anexo', 192, 9438, 4, 'a', 'metais preciosos: a embalagem deve ser constituída de caixa de metal resistente ou madeira, com pelo menos um centímetro de espessura ou de sacos duplos sem costura;', 'Nota: caso seja usada caixa de madeira chapeada, sua espessura pode ser limitada a 5 mm, contanto que as arestas de tais caixas sejam reforçadas com cantoneiras.', 97),
(9440, 'anexo', 192, 9438, 4, 'b', 'objetos de vidro ou outros objetos frágeis: a embalagem deve ser constituída de caixa de metal, madeira ou papelão resistente, cheia de papel, palha ou outro material protetor similar, de forma a impedir choques ou atritos durante o transporte, quer entre os objetos ou entre os objetos e as paredes da caixa;', '', 98),
(9441, 'anexo', 192, 9438, 4, 'c', 'líquidos ou corpos facilmente liquidificáveis: devem ser colocados em recipientes hermeticamente fechados (garrafas, frascos, potes, caixas etc.), os quais são acondicionados em caixas especiais (metal, madeira, plástico ou papelão ondulado resistente);', '', 99),
(9442, 'anexo', 192, 9438, 4, 'd', 'corpos gordurosos dificilmente liquidificáveis (unguentos, sabão mole, resina etc.): devem ser acondicionados em uma primeira embalagem (caixa, saco de pano, matéria plástica etc.) e colocados dentro de caixa metálica, de madeira ou de qualquer outro material suficientemente resistente, para impedir o escoamento do conteúdo;', '', 100),
(9443, 'anexo', 192, 9438, 4, 'e', 'pós secos corantes (azul de anilina): devem, obrigatoriamente, estar contidos em caixas de metal resistente, colocadas por sua vez em caixa de madeira ou de papelão ondulado e de boa qualidade, com serragem ou outras substâncias absorventes e protetoras entre as 2 (duas) embalagens;', '', 101),
(9444, 'anexo', 192, 9438, 4, 'f', 'pós secos não corantes: esses produtos devem ser acondicionados em caixa de metal, madeira ou papelão;', '', 102),
(9445, 'anexo', 192, 9438, 4, 'g', 'objetos de uma só peça constituídos de metal, madeira, couro ou outra substância resistente: podem ser expedidos sem envoltório;', '', 103),
(9446, 'anexo', 192, 9438, 4, 'h', 'objetos pontiagudos ou cortantes: devem ter as pontas e os gumes convenientemente resguardados.', '', 104),
(9447, 'anexo', 192, 9438, 3, '10.5.1', 'Os espaços internos devem ser protegidos com papel picado, serragem, isopor ou outro tipo de material apropriado.', '', 105),
(9448, 'anexo', 192, 9426, 2, '10.6', 'O objeto deve ser acondicionado de forma a não colocar em risco a integridade física dos empregados, equipamentos e demais objetos postais.', '', 106),
(9449, 'anexo', 192, 9426, 2, '10.7', 'Os Correios se reservam o direito de proceder com a abertura da encomenda, para verificação de conteúdo, sempre que surgirem dúvidas em relação ao objeto transportado.', '10.7.1 No momento de abrir a encomenda e verificar seu conteúdo, deverá estar presente o remetente, o destinatário ou seus prepostos legais', 107),
(9450, 'anexo', 192, 9426, 2, '10.8', 'A constatação, em qualquer dependência dos Correios, da existência de encomenda contendo item proibido determina a sua apreensão.', '', 108),
(9451, 'anexo', 192, 9426, 2, '10.9', 'O material apreendido pode, conforme natureza, ser confiscado ou destruído por autoridade competente ou ser encaminhado para refugo pelos Correios.', '', 109),
(9452, 'anexo', 192, 9426, 2, '10.10', 'Nos casos de confisco ou destruição de objeto, não cabe qualquer indenização ao cliente, devendo ele ser informado dessa situação.', '', 110),
(9453, 'anexo', 192, 9426, 2, '10.11', 'Fechamento de envelope:', '', 111),
(9454, 'anexo', 192, 9453, 4, 'a', 'o fechamento do envelope deve ser feito com cola, evitando-se os excessos, e, se possível, a formação de ondulações entre as partes;', '', 112),
(9455, 'anexo', 192, 9453, 4, 'b', 'não pode ser aceito objeto cujo fechamento foi realizado com clips ou grampos metálicos, nem deve estar contidos em seu interior, onde possam oferecer riscos aos empregados dos Correios, ao transporte e ao tratamento dos demais objetos.', '', 113),
(9456, 'anexo', 192, 9426, 2, '10.12', 'Fechamento de pacote:', '', 114),
(9457, 'anexo', 192, 9456, 4, 'a', 'objeto fechado adequadamente pelo remetente não deve ser lacrado novamente com fita adesiva dos Correios;', '', 115),
(9458, 'anexo', 192, 9456, 4, 'b', 'objeto fechado inadequadamente pelo remetente deve receber reforço de fita adesiva dos Correios, de forma a garantir o devido fechamento do objeto.', '', 116),
(9459, 'anexo', 192, 9426, 2, '10.13', 'Consultar as instruções adicionais de embalagens e acondicionamento contidas no Guia Técnico de Embalagens Recomendadas pelos Correios - RPC, disponível no Portal Correios.', '', 117),
(9460, 'anexo', 192, NULL, 1, '11', 'ENDEREÇAMENTO', '', 118),
(9461, 'anexo', 192, 9460, 2, '11.1', 'A encomenda deve ser apresentada com o rótulo de endereçamento, considerando apenas um remetente e um destinatário, preenchidos de forma correta e completa, em concordância com o regulamento interno dos Correios e a legislação pertinente.', '', 119),
(9462, 'anexo', 192, 9461, 3, '11.1.1', 'É proibido o envio de encomenda em anonimato.', '11.1.2 Conforme legislação vigente, não é permitido apelido ou nome incompleto do destinatário.\nNota: a título de exemplo, utilizamos algumas variações do mesmo nome \"Jorge Leal Amado de Faria\", sendo que, embora em alguns casos abreviados, permitem a identificação por completo do destinatário ou remetente, já em outros, não, como nos “Exemplos 2”, abaixo:\nExemplos 1: Jorge Leal Amado de Faria\nJorge L. Amado de Faria\nJorge L. A. de Faria\nExemplos 2: J. Leal Amado de Faria\nJ. L. Amado de Faria\nJ. Leal A. de Faria\nJ. L. A. de F\nJ. Leal Amado de F\nJorge\nJorge Faria', 120),
(9463, 'anexo', 192, 9461, 3, '11.1.3', 'É vedada a utilização de endereço de agência como remetente, salvo nas situações em que estiver contratado o serviço de Caixa Postal.', '', 121),
(9464, 'anexo', 192, 9461, 3, '11.1.4', 'É permitido o endereçamento para mais de um destino, somente nos casos em que o remetente contratar um serviço adicional ou escolher uma funcionalidade que preveja essa opção.', '', 122),
(9465, 'anexo', 192, 9461, 3, '11.1.5', 'A encomenda não enquadrada no subitem 11.1.2 e que estiver com mais de um endereço de destinatário, deve ser recusada.', '', 123),
(9466, 'anexo', 192, 9461, 3, '11.1.6', 'A encomenda direcionada ao Locker deve conter, no campo “Complemento” do endereço, o número do CPF/CNPJ e/ou e-mail do destinatário.', '', 124),
(9467, 'anexo', 192, 9460, 2, '11.2', 'Os Correios não se responsabilizam pela demora na execução de qualquer serviço, resultante de omissão ou erro por parte do remetente.', '', 125),
(9468, 'anexo', 192, 9460, 2, '11.3', 'Para encomenda com a funcionalidade de Entrega no Vizinho, o rótulo de endereçamento deve conter a informação “Entrega no Vizinho Autorizada”, bem como a identificação do endereço vizinho autorizado, conforme padrão especificado no Guia Técnico de Endereçamento.', '', 126),
(9469, 'anexo', 192, 9460, 2, '11.4', 'O cliente pode optar pela devolução imediata da encomenda (SEDEX, PAC e Correios Mini Envios), quando todas as tentativas de entrega domiciliar forem frustradas.', 'Nota: no Rótulo de Endereçamento deve constar a seguinte mensagem: “DEVOLUÇÃO IMEDIATA APÓS AS TENTATIVAS DE ENTREGA DOMICILIAR”.', 127),
(9470, 'anexo', 192, 9460, 2, '11.5', 'Devem ser consultadas as instruções adicionais de endereçamento contidas no Guia Técnico de Endereçamento, disponível no Portal Correios.', '', 128),
(9471, 'anexo', 192, 9460, 2, '11.6', 'Os modelos de etiquetas físicas vigentes para os serviços de encomendas são:', '', 129),
(9472, 'anexo', 192, NULL, 1, '12', 'ENDEREÇAMENTO COM ETIQUETA LÓGICA', '', 130),
(9473, 'anexo', 192, 9472, 2, '12.1', 'Na etiqueta de registro lógica deve constar o número do contrato e a sigla da SE de origem, quando gerada por meio de sistema de pré-postagem próprio ou dos Correios.', '', 131),
(9474, 'anexo', 192, 9473, 3, '12.1.1', 'O símbolo da linha de remessa postal, de acordo com o serviço contratado, também deve ser utilizado pelo cliente que gera etiqueta lógica:', 'SEDEX Hoje\nSEDEX 10\nSEDEX 12	SEDEX	PAC	Correios Mini Envios', 132),
(9475, 'anexo', 192, 9472, 2, '12.2', 'O cliente que utiliza etiqueta física está dispensado do uso do símbolo da linha de remessa postal.', '', 133),
(9476, 'anexo', 192, 9472, 2, '12.3', 'Alternativamente ao uso da etiqueta de registro física, o cliente que gera o seu Rótulo de Endereçamento, recomenda-se a utilização das instruções contidas no Guia Técnico de Endereçamento de Encomendas.', '', 134),
(9477, 'anexo', 192, NULL, 1, '13', 'NOTA FISCAL E DECLARAÇÃO DE CONTEÚDO', '13.1 A obrigatoriedade de cumprimento da legislação tributária vigente, inclusive quanto à correta emissão e à veracidade das informações constantes dos documentos fiscais (Nota Fiscal Eletrônica - NF-e e Declaração de Conteúdo Eletrônica - DC-e), é de responsabilidade do remetente, competindo aos Correios exigir informações e documentos necessários à aceitação da postagem.', 135),
(9478, 'anexo', 192, NULL, 3, '13.1.1', 'Eventuais custos oriundos de autuações fiscais, por descumprimento de obrigações legais inerentes ao objeto transportado, são de inteira responsabilidade do remetente.', '', 136),
(9479, 'anexo', 192, NULL, 3, '13.1.2', 'Não compete aos Correios qualificar juridicamente a natureza da operação comercial ou não comercial realizada pelo remetente.', '', 137),
(9480, 'anexo', 192, 9477, 2, '13.2', 'A postagem de bens e mercadorias deve estar acompanhada de documento fiscal válido (Nota Fiscal Eletrônica - NF-e e Declaração de Conteúdo Eletrônica - DC-e), afixado na parte externa da embalagem, de forma a possibilitar a fiscalização tributária e reduzir a necessidade de abertura da encomenda.', '', 138),
(9481, 'anexo', 192, 9480, 3, '13.2.1', 'A Declaração de Conteúdo Eletrônica - DC-e deverá ser utilizada somente para o transporte de bens e mercadorias por pessoas físicas ou jurídicas não contribuintes ou dispensadas da emissão da nota fiscal eletrônica - NF-e/DANFE.', '', 139),
(9482, 'anexo', 192, 9480, 3, '13.2.2', 'A Declaração Auxiliar de Conteúdo Eletrônica - DACE deverá ser afixada na parte externa da embalagem, para que seja possível o procedimento da fiscalização tributária, reduzindo a possibilidade de abertura da encomenda.', 'Nota 1: caso alguma informação esteja rasurada, ilegível ou qualquer outra circunstância que não permita a leitura, deverá ser realizada a reimpressão da Declaração Auxiliar de Conteúdo Eletrônica - DACE ou a emissão de nova Declaração de Conteúdo Eletrônica - DC-e, antes de se concretizar a postagem.\nNota 2: quando o objeto for postado com o serviço adicional Valor Declarado - VD, o valor informado pelo cliente não poderá exceder o valor constante no formulário Declaração de Conteúdo e deverá respeitar o limite máximo estabelecido para o serviço contratado.\nNota 3: Caso o cliente opte por não declarar o valor total, será permitida a declaração de parte do valor, desde que observados os limites do serviço e os instrumentos normativos vigentes, com vistas a evitar indenizações indevidas.\n13.2.3 Para fins de aceitação, são considerados documentos fiscais admitidos aqueles previstos na legislação vigente, tais como:', 140),
(9483, 'anexo', 192, 9482, 4, 'a', 'Documento Auxiliar de Nota Fiscal Eletrônica - Danfe;', '', 141),
(9484, 'anexo', 192, 9482, 4, 'b', 'Documento Auxiliar de Nota Fiscal Eletrônica Simplificado - Danfe Simplificado;', '', 142),
(9485, 'anexo', 192, 9482, 4, 'c', 'Documento Auxiliar de Nota Fiscal Eletrônica Simplificado Etiqueta - Danfe Simplificado Etiqueta;', '', 143),
(9486, 'anexo', 192, 9482, 4, 'd', 'Declaração Auxiliar de Conteúdo Eletrônica - Dace.', '', 144),
(9487, 'anexo', 192, 9480, 3, '13.2.3', 'No ato da captação, o atendente deverá:', 'a) verificar a existência do documento auxiliar de documento fiscal, afixado externamente à encomenda;\nb) verificar a legibilidade das informações constantes do documento apresentado;\nc) confrontar a descrição do conteúdo constante do documento fiscal com as regras de aceitação de objetos, a fim de identificar eventual item proibido ou restrito.', 145),
(9488, 'anexo', 192, 9477, 2, '13.3', 'O documento fiscal deve ser afixado de forma em que os dados do remetente e destinatário fiquem visíveis ou de forma em que seja possível o acesso à estas informações.', '', 146),
(9489, 'anexo', 192, 9488, 3, '13.3.1', 'Objeto em devolução deve estar acompanhado de documento fiscal (Nota Fiscal ou Declaração de Conteúdo) válido.', 'Nota: o emissor da Logística Reversa deve orientar o seu cliente (remetente) a respeito do documento fiscal que acompanha o objeto em devolução, seja a Nota Fiscal Eletrônica (NF-e) válida para o trânsito de bens e mercadorias ou a Declaração de Conteúdo Eletrônica (DC-e).', 147),
(9490, 'anexo', 192, 9488, 3, '13.3.2', 'A verificação realizada pelo atendente possui caráter formal, não se configurando análise fiscal ou validação tributária da operação.', '', 148),
(9491, 'anexo', 192, 9477, 2, '13.4', 'As quantidades e/ou características dos itens transportados devem estar refletidas fielmente no documento fiscal que acompanha o objeto.', '', 149),
(9492, 'anexo', 192, 9477, 2, '13.5', 'Em todos os casos o cliente deve ser indagado sobre o conteúdo da encomenda a ser enviada, a fim de garantir que não haja item proibido em seu interior, independentemente do tipo de documento fiscal apresentado no momento da postagem.', '', 150),
(9493, 'anexo', 192, 9477, 2, '13.6', 'A postagem será recusada quando:', 'a) inexistir o documento fiscal exigível;\nb) o documento estiver ilegível, rasurado ou não afixado externamente;\nc) a descrição do conteúdo indicar item proibido ou restrito, nos termos das regras de aceitação.\n13.7 Para a postagem de encomenda com a contratação do serviço adicional de Valor Declarado, verificar o disposto no MANCAT 7/5.', 151),
(9494, 'anexo', 192, NULL, 1, '14', 'CPF/CNPJ/PASSAPORTE', '', 152),
(9495, 'anexo', 192, 9494, 2, '14.1', 'É obrigatória a informação do número de CPF, CNPJ, passaporte (estrangeiros) ou Identidade Civil (estrangeiros de países membros do Mercosul) do remetente e destinatário para o envio de encomendas nacionais, em conformidade com as regras definidas no item 13 deste anexo.', '', 153),
(9496, 'anexo', 192, 9495, 3, '14.1.1', 'O não fornecimento do número do documento do remetente no momento da postagem do objeto enseja sua recusa.', '', 154),
(9497, 'anexo', 192, 9495, 3, '14.1.2', 'A postagem de objeto destinado ao Locker ou Clique e Retire deve conter, além dos números dos respectivos documentos, o número do celular do destinatário, com DDD.', '', 155),
(9498, 'anexo', 192, NULL, 1, '15', 'PROIBIÇÕES E RESTRIÇÕES', '', 156);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(9499, 'anexo', 192, 9498, 2, '15.1', 'Para a postagem ser aceita, deverá ser observado se o objeto atende às especificações de peso, dimensões, volume, acondicionamento, formato, endereçamento e franqueamento, de acordo com as instruções estabelecidas nas normas em vigor nos Correios, previstas em convenções, acordos internacionais ou definidas por lei e decreto.', '', 157),
(9500, 'anexo', 192, 9498, 2, '15.2', 'As encomendas destinadas a moradores e usuários de edifícios residenciais, comerciais, condomínios ou qualquer outra coletividade, tais como hospitais, shopping centers, estabelecimentos prisionais, quartéis, associações, estabelecimentos religiosos etc. não podem ser aglutinadas e nem endereçadas ao porteiro, zelador, síndico ou a qualquer outra pessoa, a fim de que estas efetuem a redistribuição aos vários destinatários.', '', 158),
(9501, 'anexo', 192, 9500, 3, '15.2.1', 'Encomendas aglutinadas para um mesmo destinatário podem ser aceitas, desde que todas estejam devidamente acondicionadas em uma única embalagem externa para envio, de forma que resista ao peso, à natureza do conteúdo e as condições de transporte.', '15.2.1.1  A embalagem externa não pode ultrapassar as dimensões e o peso permitidos para o serviço de encomenda contratado.\n15.2.1.2  Não são admitidas encomendas aglutinadas e presas por fitas, papel bolha etc.', 159),
(9502, 'anexo', 192, 9498, 2, '15.3', 'Não são aceitos e nem entregues:', '', 160),
(9503, 'anexo', 192, 9502, 4, 'a', 'substância explosiva, radioativa, deteriorável, facilmente perecível em temperatura ambiente, fétida, nauseante, corrosiva, nociva, facilmente inflamável ou qualquer outra substância cujo manuseio ou transporte constitua perigo ou possa causar danos;', '', 161),
(9504, 'anexo', 192, 9502, 4, 'b', 'entorpecentes e substâncias psicotrópicas;', '', 162),
(9505, 'anexo', 192, 9502, 4, 'c', 'objeto com endereço, dizeres ou desenho injuriosos, ameaçadores ou ofensivos à ordem pública ou aos interesses do país;', '', 163),
(9506, 'anexo', 192, 9502, 4, 'd', 'objeto cuja circulação no Brasil, exportação ou importação, estejam proibidos por ato de autoridade competente;', '', 164),
(9507, 'anexo', 192, 9502, 4, 'e', 'moeda de valor corrente;', '', 165),
(9508, 'anexo', 192, 9502, 4, 'f', 'objeto que atente contra a segurança nacional;', '', 166),
(9509, 'anexo', 192, 9502, 4, 'g', 'cigarros, derivados do tabaco e produtos similares que não estejam no escopo dos objetos identificados pelas Leis nº 9.294/1996 e nº 10.167/2000 e que sejam destinados à comercialização;', '', 167),
(9510, 'anexo', 192, 9502, 4, 'h', 'quaisquer outros bens ou produtos proibidos pela lei brasileira ou protegidos pela legislação ambiental;', '', 168),
(9511, 'anexo', 192, 9502, 4, 'i', 'mercadorias com limite de valor declarado superior ao previsto nas tabelas de preços dos Correios;', '', 169),
(9512, 'anexo', 192, 9502, 4, 'j', 'aerossol, de qualquer tipo, é proibido para o modal aéreo, conforme normativo RBAC nº 175, emenda nº 4 - ANAC e IS nº 175-001 da ANAC;', '', 170),
(9513, 'anexo', 192, 9502, 4, 'k', 'artigos perigosos, consultar a relação dos artigos classificados como perigosos no Portal Correios, cujo transporte é proibido pelo modal aéreo e terrestre.', '', 171),
(9514, 'anexo', 192, 9498, 2, '15.4', 'Conteúdos aceitos com restrições:', '', 172),
(9515, 'anexo', 192, 9514, 4, 'a', 'objetos contendo artigos de ouro, prata, platina, bronze, níquel ou qualquer outro metal de valor, cédulas e moedas fora de circulação, selos ou qualquer outra forma de franqueamento, joias e artigos preciosos ou qualquer papel representativo de valor ao portador, somente são aceitos com a contratação de valor declarado;', '', 173),
(9516, 'anexo', 192, 9514, 4, 'b', 'cheques possuem regras específicas, conforme MANCAT 7/5/2;', '', 174),
(9517, 'anexo', 192, 9514, 4, 'c', 'animais permitidos por acordos ou convenções internacionais ratificadas pelo Brasil, mas não sendo permitida a contratação de valor declarado, conforme Decreto nº 9.358/2018:', 'I - abelhas, sanguessugas e bichos-da-seda;\nII - parasitas e destruidores de insetos nocivos destinados ao controle destes insetos e permutados entre instituições oficialmente reconhecidas;\nIII - moscas da família das Drosophila melanogaster utilizadas para a pesquisa biomédica, permutadas entre instituições oficialmente reconhecidas.', 175),
(9518, 'anexo', 192, 9514, 4, 'd', 'animais diversos, que não constam em acordos ou convenções internacionais ratificados pelo Brasil, somente são permitidos mediante celebração de contrato de operação customizada e conforme legislação específica,', '', 176),
(9519, 'anexo', 192, 9514, 4, 'e', 'armas e demais produtos controlados pelo Exército Brasileiro, conforme regras específicas estabelecidas no MANCAT 16/3/5;', '', 177),
(9520, 'anexo', 192, 9514, 4, 'f', 'amostras de material biológico, exclusivamente recolhidas para fins de análise, pesquisa, investigação, diagnóstico, tratamento, transplante ou prevenção, podem ser encaminhadas somente por meio de contrato celebrado com os Correios, conforme regras específicas estabelecidas no MANCAT 16/3/6;', '', 178),
(9521, 'anexo', 192, 9514, 4, 'g', 'ovos embrionados de aves, desde que apresentado pelo remetente, no momento da postagem, e afixado em local visível fora da embalagem, o Guia de Trânsito de Animal - GTA, conforme Instrução Normativa nº 18, de 18/07/2006, do Mapa;', '', 179),
(9522, 'anexo', 192, 9514, 4, 'h', 'chá ayahuasca, o remetente deve declarar que o envio do objeto não é fruto de atividade comercial, por meio do preenchimento do formulário Declaração de Conteúdo, e apresentar no ato da postagem os documentos de constituição do grupo religioso devidamente organizado juridicamente, o seu respectivo cadastro e do destinatário junto a essa entidade religiosa, bem como documento de avaliação psíquica do remetente e destinatário, emitidos pela entidade religiosa organizada juridicamente;', '', 180),
(9523, 'anexo', 192, 9514, 4, 'i', 'medicamentos sem controle especial, saneantes e cosméticos é permitido o envio por clientes com e sem contrato, por meio dos serviços SEDEX Hoje, SEDEX 10, SEDEX 12, SEDEX e PAC, desde que a embalagem e o acondicionamento assegurem a entrega íntegra do item transportado, considerando as variações de temperatura, umidade e pressão durante o fluxo postal;', '', 181),
(9524, 'anexo', 192, 9514, 4, 'j', 'medicamentos com controle especial e produtos para a saúde são aceitos apenas mediante celebração de contrato de operação customizada;', '', 182),
(9525, 'anexo', 192, 9514, 4, 'k', 'aerossol não inflamável é aceito apenas para o modal terrestre, conforme Resolução ANTT nº 5.998/2022 (Processos SEI nº 53180.049680/2023-50 e nº 53180.049650/2025-13);', '', 183),
(9526, 'anexo', 192, 9514, 4, 'l', 'sementes, plantas e suas partes é permitido o envio por clientes com e sem contrato, conforme regras estabelecidas no MANCAT 16/3/11;', '', 184),
(9527, 'anexo', 192, 9514, 4, 'm', 'líquidos não perigosos listados abaixo, desde que conste escrito, em pelo menos 3 (três) faces da embalagem, a frase \"Contém líquido não perigoso\":', 'I -  cosméticos e produtos de higiene pessoal (exceto acetona);\nII -  bebidas;\nIII -  medicamentos em geral (exceto formol, éter, álcool);\nIV -  líquidos alimentícios e suplementos;\nV -  tintas e tóneres de impressoras;\nVI -  essências;\nVII -  ceras, detergentes, amaciantes e sabão líquido;\nVIII -  produtos para manutenção de aquários;\nIX -  tintas para tatuagem;\nX -  lubrificantes automotivos, exclusivamente pelo modal terrestre (Processo SEI nº 53107.016956/2020-53).', 185),
(9528, 'anexo', 192, 9514, 4, 'n', 'cilindros novos e totalmente vazios, permitidos apenas para o modal terrestre;', '', 186),
(9529, 'anexo', 192, 9514, 4, 'o', 'cinzas provenientes de cremação podem ser admitidas, desde que devidamente embaladas em recipiente hermeticamente fechado e posteriormente acondicionado em caixa de papelão resistente;', '', 187),
(9530, 'anexo', 192, 9514, 4, 'p', 'artigos perigosos, consultar a relação dos artigos classificados como perigosos no Portal Correios, cujo transporte é permitido apenas pelo modal terrestre:', 'Nota: obrigatória a vinculação do código adicional 095 (Artigos Perigosos) ao objeto, sem custo adicional ao cliente, apenas para controles internos e externos.', 188),
(9531, 'anexo', 192, 9498, 2, '15.5', 'As encomendas nacionais devem ser postadas abertas nos seguintes casos:', '', 189),
(9532, 'anexo', 192, 9531, 4, 'a', 'na Zona Franca de Manaus para que se comprove o atendimento às exigências da Receita Federal (com ou sem valor declarado);', '', 190),
(9533, 'anexo', 192, 9531, 4, 'b', 'nas unidades situadas em municípios localizados na Faixa de Fronteira, conforme definido no art. 20, inciso II, da Constituição Federal e na Lei nº 6.634/1979, visando atender às exigências de controle aduaneiro e à segurança nacional (com ou sem valor declarado);', '', 191),
(9534, 'anexo', 192, 9531, 4, 'c', 'com o serviço adicional de valor declarado, conforme MANCAT 7/5;', '', 192),
(9535, 'anexo', 192, 9531, 4, 'd', 'com o serviço de Pagamento na Entrega, conforme MANCAT 16/3/3.', 'Nota 1: a conferência da encomenda deve ser realizada na presença do remetente, com registro formal da inspeção e observância dos direitos do usuário.\nNota 2: a não abertura da encomenda implica na sua recusa.\nNota 3: a relação dos municípios brasileiros que fazem parte da Faixa de Fronteira pode ser consultada no Portal Correios (Correios de A a Z - Municípios de Fronteira).', 193),
(9536, 'anexo', 192, 9498, 2, '15.6', 'Encomendas contendo materiais que não sejam permitidos no serviço postal não são encaminhadas ao destino, nem entregues ao destinatário e nem devolvidas ao remetente. As autoridades competentes são comunicadas para tomarem as providências necessárias.', '', 194),
(9537, 'anexo', 192, 9498, 2, '15.7', 'Se for constatada avaria ou vazamento em qualquer embalagem, deve-se:', '', 195),
(9538, 'anexo', 192, 9537, 4, 'a', 'evitar o manuseio ou reduzi-lo ao mínimo;', '', 196),
(9539, 'anexo', 192, 9537, 4, 'b', 'inspecionar as embalagens adjacentes para verificar se foram avariadas devido ao vazamento;', '', 197),
(9540, 'anexo', 192, 9537, 4, 'c', 'separar as que possam ter sido contaminadas;', '', 198),
(9541, 'anexo', 192, 9537, 4, 'd', 'notificar o remetente e o destinatário.', '', 199),
(9542, 'anexo', 192, 9498, 2, '15.8', 'Conforme previsto na Convenção Postal Universal e na Lei nº 6.538/1978, o remetente de qualquer objeto postal é responsável, perante a empresa exploradora do serviço postal, pela danificação produzida em outro objeto, em virtude de inobservância dos dispositivos legais e regulamentares, desde que não tenha havido erro ou negligência da empresa exploradora do serviço postal ou do transportador.', '', 200),
(9543, 'anexo', 192, NULL, 1, '16', 'HORÁRIO LIMITE DE POSTAGEM', '', 201),
(9544, 'anexo', 192, 9543, 2, '16.1', 'O horário limite de postagem para encaminhamento no mesmo dia varia de acordo com o serviço de encomenda contratado, a localidade de origem e a unidade de postagem, devendo sempre ser confirmado no momento da postagem.', '', 202),
(9545, 'anexo', 192, 9543, 2, '16.2', 'É acrescido um dia útil ao prazo padrão de entrega na postagem efetuada após o horário limite, sendo o remetente informado dessa alteração no prazo.', '', 203),
(9546, 'anexo', 192, NULL, 1, '17', 'POSTAGEM', '', 204),
(9547, 'anexo', 192, 9546, 2, '17.1', 'SEDEX Hoje', '', 205),
(9548, 'anexo', 192, 9547, 3, '17.1.1', 'Realizada de segunda-feira a sábado, somente nas localidades e nas Agências dos Correios habilitadas para prestar o serviço.', '', 206),
(9549, 'anexo', 192, 9547, 3, '17.1.2', 'Realizada de segunda a domingo, nas unidades operacionais habilitadas à captação do serviço.', '', 207),
(9550, 'anexo', 192, 9547, 3, '17.1.3', 'As unidades habilitadas para postagem podem ser consultadas no Portal Correios.', '', 208),
(9551, 'anexo', 192, 9547, 3, '17.1.4', 'O horário limite de postagem nas agências habilitadas, para que os objetos sejam entregues no mesmo dia, está definido conforme abaixo:', '', 209),
(9552, 'anexo', 192, 9551, 4, 'a', 'de segunda a sexta-feira: até as 15h;', '', 210),
(9553, 'anexo', 192, 9551, 4, 'b', 'aos sábados: até as 11h, nas unidades que funcionam neste dia.', 'Nota: após o horário limite do serviço, devem ser ofertados o SEDEX 10 ou SEDEX 12.', 211),
(9554, 'anexo', 192, 9547, 3, '17.1.5', 'A postagem nas unidades operacionais habilitadas pode ocorrer até as 20h, em qualquer dia da semana, observando-se as seguintes regras:', '', 212),
(9555, 'anexo', 192, 9554, 4, 'a', 'objetos recebidos/postados até as 19h são entregues no mesmo dia, até as 23h;', '', 213),
(9556, 'anexo', 192, 9554, 4, 'b', 'objetos recebidos/postados após as 19h são entregues até as 12h do dia seguinte.', '', 214),
(9557, 'anexo', 192, 9547, 3, '17.1.6', 'Não é permitida a postagem de SEDEX Hoje endereçado à Caixa Postal, Clique e Retire ou qualquer outra modalidade de entrega interna, sendo recomendado ofertar outro serviço de encomenda.', '', 215),
(9558, 'anexo', 192, 9546, 2, '17.2', 'SEDEX 10 e SEDEX 12', '', 216),
(9559, 'anexo', 192, 9558, 3, '17.2.1', 'Realizada de segunda a sexta-feira, apenas nas localidades e Agências dos Correios habilitadas para prestar os serviços.', '', 217),
(9560, 'anexo', 192, 9546, 2, '17.3', 'SEDEX, PAC e Correios Mini Envios', '', 218),
(9561, 'anexo', 192, 9560, 3, '17.3.1', 'Realizada de segunda-feira a sábado em qualquer Agência ou Ponto de Coleta dos Correios, de acordo com o horário de funcionamento dessas unidades.', '', 219),
(9562, 'anexo', 192, 9546, 2, '17.4', 'No momento da postagem são conferidos os dados de endereçamento, do serviço e as condições de aceitação.', '', 220),
(9563, 'anexo', 192, 9546, 2, '17.5', 'A conferência e correção de eventuais divergências de peso, dimensões e formato também é realizada após a postagem ou a qualquer tempo, com prevalência de sua aferição, sendo cabível a restituição de valores, no caso de diferença entre o valor faturado e o valor apurado.', '', 221),
(9564, 'anexo', 192, 9563, 3, '17.5.1', 'A aferição de objetos de encomendas nacionais, inclusive de Logística Reversa, em unidades de Ponto Coleta, dar-se-á apenas com a medição das dimensões (C × L × A), dispensando a aferição do peso físico, em balança.', '', 222),
(9565, 'anexo', 192, 9563, 3, '17.5.2', 'Não está disponível para postagem em unidades de Ponto de Coleta os serviços da Linha Premium dos Correios, o Correios Mini Envios, assim como os objetos de Logística Reversa com a contratação do adicional de checklist e/ou fornecimento de embalagens.', '', 223),
(9566, 'anexo', 192, 9546, 2, '17.6', 'A indicação da unidade de franqueamento define o local de postagem da encomenda, bem como os preços e prazos.', '', 224),
(9567, 'anexo', 192, 9546, 2, '17.7', 'A encomenda coletada pelos Correios é considerada postada após o franqueamento em uma unidade de atendimento ou de captação.', '', 225),
(9568, 'anexo', 192, 9546, 2, '17.8', 'Respeitados os limites e parâmetros previamente estabelecidos pelos Correios, o cliente pode solicitar a implementação de restrições sistêmicas, que visam inibir a postagem de encomendas considerando critérios como: limites de peso, dimensões e abrangência para aceitação ou recusa dos objetos.', 'Nota: a efetividade dessa verificação está condicionada à viabilidade dos Correios.', 226),
(9569, 'anexo', 192, 9546, 2, '17.9', 'Para utilizar o serviço Correios Mini Envios é obrigatória a pré-postagem do objeto, independentemente do canal de atendimento.', '', 227),
(9570, 'anexo', 192, NULL, 1, '18', 'POSTAGEM DE GRANDES VOLUMES EM AGÊNCIAS DE CORREIOS FRANQUEADAS - AGFs', '', 228),
(9571, 'anexo', 192, 9570, 2, '18.1', 'As postagens de grandes volumes (antigo perfil industrial) realizadas em AGFs, dos clientes das categorias Diamante e Infinite, devem observar as seguintes regras:', '', 229),
(9572, 'anexo', 192, 9571, 4, 'a', 'carga de um mesmo cliente de contrato captada em AGF, com concentração acima de 100 (cem) objetos no mesmo dia, deve ser entregue pela agência na unidade operacional dos Correios designada;', '', 230),
(9573, 'anexo', 192, 9571, 4, 'b', 'as AGFs devem realizar as seguintes atividades para a respectiva carga:', 'I - preparação;\nII - recebimento e conferência da carga;\nIII - coleta das encomendas nos clientes;\nIV - escolta, se necessário;\nV - postagem;\nVI - triagem;\nVII -  entrega da carga em unidade operacional designada.', 231),
(9574, 'anexo', 192, 9571, 4, 'c', 'as coletas das encomendas nos clientes devem ocorrer no território de atuação da agência e a carga entregue em uma unidade operacional definida pelo órgão gestor, conforme plano de triagem específico.', '', 232),
(9575, 'anexo', 192, NULL, 1, '19', 'RESPONSABILIDADE PECUNIÁRIA', '', 233),
(9576, 'anexo', 192, 9575, 2, '19.1', 'A prestação dos serviços de encomendas, seja na postagem, no tratamento, no transporte ou na distribuição, efetuada em desconformidade com as regras definidas em normativos internos, sujeita os responsáveis às normas definidas pela Empresa para a recuperação dos eventuais custos decorrentes de vício na sua prestação.', '', 234),
(9577, 'anexo', 192, NULL, 1, '20', 'POSTAGEM DE ENCOMENDA DE SERVIÇO', '', 235),
(9578, 'anexo', 192, 9577, 2, '20.1', 'A postagem administrativa é permitida somente no estrito cumprimento do interesse da Empresa, no que concerne às suas atividades.', '', 236),
(9579, 'anexo', 192, 9578, 3, '20.1.1', 'Em regra, a tramitação de documentos dar-se-á por meio do Sistema Eletrônico de Informações - SEI.', 'Exemplos: ofícios, notas técnicas, formulários etc.', 237),
(9580, 'anexo', 192, 9578, 3, '20.1.2', 'Para postagens administrativas em função de atividades inerentes e sob competência da unidade própria, gerência ou departamento, que não podem ser supridas integralmente pelo uso do SEI, dar-se-á preferência à utilização do serviço de Malote Administrativo, sob o código 4415-6.', '', 238),
(9581, 'anexo', 192, 9577, 2, '20.2', 'As postagens administrativas devem cumprir, obrigatoriamente, o requisito específico de criação de pré-postagem pelo aplicativo corporativo designado pela Empresa e a postagem no sistema de atendimento (SARA ou Correios Atende), com identificação do empregado no ato da postagem.', '', 239),
(9582, 'anexo', 192, 9581, 3, '20.2.1', 'O acesso e a instalação do aplicativo devem ser solicitados mediante interação com o Help Desk e as instruções de uso podem ser observadas por meio do Manual do Usuário Administrativo, disposto no ambiente www.corporativo.correios.com.br.', '', 240),
(9583, 'anexo', 192, 9581, 3, '20.2.2', 'As postagens administrativas devem ser realizadas, exclusivamente, por meio dos códigos de serviços relacionados abaixo:', '', 241),
(9584, 'anexo', 192, 9583, 4, 'a', 'Carta Simples Administrativa (código 1034-0) para remessa de documentos;', '', 242),
(9585, 'anexo', 192, 9583, 4, 'b', 'Telegrama Nacional 4h internet (código 6216-2) para remessa de mensagens com necessidade de urgência comprovada;', '', 243),
(9586, 'anexo', 192, 9583, 4, 'c', 'Carta via internet (código 6828-4) para remessa de mensagem com necessidade de impressão;', '', 244),
(9587, 'anexo', 192, 9583, 4, 'd', 'E-Carta Administrativo (código 1268-8) para remessa de mensagens com necessidade de urgência e impressão;', '', 245),
(9588, 'anexo', 192, 9583, 4, 'e', 'SEDEX Administrativo (código 4083-5) para remessa de mercadorias com urgência comprovada ou para utilização das assessorias jurídicas dos Correios, em conjunto com o serviço do Cidadão - Protocolo Administrativo (código 3552-1);', '', 246),
(9589, 'anexo', 192, 9583, 4, 'f', 'SEDEX Reverso (código 0324-7) de uso exclusivo da loja online;', '', 247),
(9590, 'anexo', 192, 9583, 4, 'g', 'PAC Administrativo (código 4128-9) para remessa de mercadorias;', '', 248),
(9591, 'anexo', 192, 9583, 4, 'h', 'PAC Reverso (código 0330-1) de uso exclusivo da loja online;', '', 249),
(9592, 'anexo', 192, 9583, 4, 'i', 'Documento internacional nas modalidades Expresso (código 4537-3) e Standard (código 4534-9);', '', 250),
(9593, 'anexo', 192, 9583, 4, 'j', 'Exporta Fácil nas modalidades Expresso (código 4536-5), Standard (código 4538-1) e Econômico (código 4535-7);', '', 251),
(9594, 'anexo', 192, 9583, 4, 'k', 'Malote Administrativo (código 4415-6) para tramitação rotineira de documentos ou pequenos objetos, cuja necessidade de envio físico não seja suprida pelo SEI;', '', 252),
(9595, 'anexo', 192, 9583, 4, 'l', 'Balcão do Cidadão, Protocolo Administrativo (código 3552-1), para utilização exclusiva das assessorias jurídicas dos Correios.', 'Nota 1: em nenhuma hipótese deve haver cadastro de código de serviço além dos mencionados no subitem anterior, nos cartões de postagem das unidades próprias, terceirizadas e operacionais para realização de postagem administrativa.\nNota 2: o serviço de Malote Administrativo não é extensivo às unidades de atendimento terceirizadas.\nNota 3: os códigos de serviço internacional administrativo devem ser utilizados para o envio de correspondência administrativa com operadores postais e reguladores de países-membros da União Postal Universal - UPU e para outros organismos internacionais, para o intercâmbio comercial ou institucional de filatelia e para a correspondência administrativa com os contratantes dos serviços de entrada direta de importação.', 253),
(9596, 'anexo', 192, 9581, 3, '20.2.3', 'Excepcionalmente, a pedido dos órgãos formatadores, podem ser cadastrados novos cartões de postagem, com a inclusão de códigos de serviços diversos dos dispostos anteriormente, exclusivamente para a realização de testes, nos ambientes de homologação e produção, dos sistemas internos dos Correios.', '', 254),
(9597, 'anexo', 192, 9577, 2, '20.3', 'Em caso de urgência comprovável e cujo prazo dos outros serviços não sejam adequados para a demanda, a unidade própria, terceirizada e operacional devem solicitar ao órgão ao qual esteja vinculada no âmbito da SE, via SEI, com a respectiva justificativa, a postagem dos serviços caracterizados como urgentes, utilizando, obrigatoriamente, o código de serviço administrativo correspondente.', '', 255),
(9598, 'anexo', 192, 9597, 3, '20.3.1', 'O órgão no âmbito da SE, cuja unidade vinculada tenha solicitado o uso de algum serviço administrativo caracterizado como urgente, deve avaliar o deferimento ou não do pleito e, caso deferido, seguir os mesmos procedimentos descritos no subitem 20.2 e responder à respectiva unidade via SEI, anexando rótulo de endereçamento emitido pelo sistema de pré-postagem, utilizando, obrigatoriamente, o código de serviço correspondente.', '', 256),
(9599, 'anexo', 192, 9577, 2, '20.4', 'Não é permitida a postagem administrativa por terceiros, nem para fornecimento de material a ser entregue nos Centros de Distribuição - CDs ou nas unidades dos Correios, nem material institucional destinado aos empregados da Empresa.', '', 257),
(9600, 'anexo', 192, 9577, 2, '20.5', 'Todas as unidades e áreas da Empresa que fazem postagens administrativas devem manter o controle do cartão que lhe for atribuído, bem como da senha do sistema de pré-postagem, sendo o responsável direto pela sua utilização, pelo que podem ser contatados, a qualquer tempo, pelos órgãos de controle, para comprovar a necessidade de uso dos respectivos serviços.', '', 258),
(9601, 'anexo', 192, 9577, 2, '20.6', 'As SEs e os departamentos do Correios Sede devem fazer o acompanhamento da utilização dos serviços administrativos das respectivas áreas de vinculação, com prestação de contas mensal à área responsável pelo controle dos custos envolvidos.', '', 259),
(9602, 'anexo', 192, NULL, 1, '21', 'PREÇOS', '', 260),
(9603, 'anexo', 192, 9602, 2, '21.1', 'Os preços relativos aos serviços de encomendas nacionais encontram-se nas tabelas de preços disponíveis para consulta no seguinte endereço: \\\\sac0424\\SISTEMAS\\PRECOS_TARIFAS', '', 261),
(9604, 'anexo', 192, NULL, 1, '22', 'PRAZOS DE ENTREGA', '', 262),
(9605, 'anexo', 192, 9604, 2, '22.1', 'O prazo de entrega varia conforme o serviço de encomenda contratado e as localidades de origem e destino.', '', 263),
(9606, 'anexo', 192, 9605, 3, '22.1.1', 'Para consultar os prazos de entrega de cada serviço é necessário acessar o Calculador de Preços e Prazos no Portal Correios.', '', 264),
(9607, 'anexo', 192, 9604, 2, '22.2', 'O prazo de entrega é contado a partir do dia útil seguinte ao da postagem.', '', 265),
(9608, 'anexo', 192, 9604, 2, '22.3', 'Sábados, domingos e feriados não são considerados dias úteis na contagem do prazo de entrega.', '', 266),
(9609, 'anexo', 192, 9608, 3, '22.3.1', 'Para o serviço SEDEX Hoje, sábados, domingos e feriados são considerados dias úteis para postagem e entrega.', '', 267),
(9610, 'anexo', 192, 9604, 2, '22.4', 'O prazo de entrega informado para os serviços é considerado apenas para a 1ª tentativa de entrega, ou seja, a 2ª e 3ª tentativas não estão contabilizadas no prazo, ocorrendo nos dias úteis subsequentes.', '', 268),
(9611, 'anexo', 192, 9604, 2, '22.5', 'Nos casos de entrega interna, o prazo é considerado quando da disponibilização da encomenda ao destinatário.', '', 269),
(9612, 'anexo', 192, NULL, 1, '23', 'NÍVEL DE SERVIÇO - NS', '', 270),
(9613, 'anexo', 192, 9612, 2, '23.1', 'O NS é utilizado para supervisionar a execução do percentual de entrega dentro do prazo, acordada entre os Correios e os clientes de contrato.', '', 271),
(9614, 'anexo', 192, 9612, 2, '23.2', 'O acompanhamento do NS é aplicado aos serviços de encomendas, quais sejam: SEDEX Hoje, SEDEX 10, SEDEX 12, SEDEX e PAC.', 'Nota: o NS não é aplicado ao serviço Correios Mini Envios, assim como não engloba as indenizações pelos demais motivos, que não o atraso.', 272),
(9615, 'anexo', 192, 9612, 2, '23.3', 'A aplicação do NS é realizada por ciclo, conforme o calendário civil.', '', 273),
(9616, 'anexo', 192, 9615, 3, '23.3.1', 'No último dia do mês, são consideradas como encomendas fora do prazo aquelas que não tiveram eventos que comprovem a entrega e tenham data máxima de entrega até aquela data.', '23.3.1.1 As demais encomendas postadas no mês, com previsão de entrega no mês subsequente, são consideradas no ciclo seguinte.', 274),
(9617, 'anexo', 192, 9612, 2, '23.4', 'Os prazos referenciais para mensuração e acompanhamento do NS são estáveis.', '', 275),
(9618, 'anexo', 192, 9617, 3, '23.4.1', 'As atualizações e revisões são realizadas em ciclos, ou ainda, nas ocorrências de casos fortuitos ou de força maior, devidamente detalhados no MANNEG 6/3.', '', 276),
(9619, 'anexo', 192, 9612, 2, '23.5', 'Para os serviços SEDEX e PAC, o não atingimento do NS enseja ônus a título de reparação ao cliente.', '', 277),
(9620, 'anexo', 192, 9619, 3, '23.5.1', 'A regra para contabilização do faturamento se dá do mesmo modo que a do NS, ou seja, as encomendas consideradas na apuração do desempenho são as mesmas utilizadas na contabilização do faturamento sobre o qual incidirá o ônus, se for o caso.', '', 278),
(9621, 'anexo', 192, 9612, 2, '23.6', 'Para os serviços SEDEX Hoje, SEDEX 10 e SEDEX 12, o NS é aplicado para fins de acompanhamento de performance de resultado, não havendo contabilização desses objetos no cálculo de ônus.', '', 279),
(9622, 'anexo', 192, 9621, 3, '23.6.1', 'Para os objetos postados por meio da contratação de um serviço da Linha Premium e não entregues dentro do prazo acordado, há abertura proativa de manifestação pelo NS, sendo considerados como procedentes para o pagamento de indenização por atraso na entrega, em índice equivalente a 100% do valor da postagem, exceto serviços adicionais contratados, inclusive Ad Valorem e embalagem (Decisão Judicial - Processo SEI 53107.002188/2017-55 - Ofício nº 15628511).', 'Nota: a não contabilização de objetos da Linha Premium no cálculo de ônus possui o objetivo de impedir a ocorrência de duplicidade na bonificação/ressarcimento, ou seja, pagamento de ônus e indenização para um mesmo objeto.', 280),
(9623, 'anexo', 192, 9612, 2, '23.7', 'Em caso de cumprimento ou superação do desempenho acordado, não há ônus para nenhuma das partes.', '', 281),
(9624, 'anexo', 192, 9623, 3, '23.7.1', 'Caso o desempenho não seja alcançado, estipula-se regras para o cálculo de ônus a ser pago pelos Correios, a título de indenização.', '', 282),
(9625, 'anexo', 192, 9612, 2, '23.8', 'O NS é estabelecido por região geográfica, conforme percentuais estabelecidos para trocas entre as regiões brasileiras:', '% de SLA para trocas entre regiões\nDe/Para	Sudeste	Sul	Nordeste	Centro-Oeste	Norte\nSudeste	96%	96%	93%	93%	90%\nSul	96%	96%	93%	93%	90%\nNordeste	93%	93%	93%	93%	90%\nCentro-Oeste	93%	93%	93%	93%	90%\nNorte	90%	90%	90%	90%	90%\n(Processo SEI 53180.012138/2021-80 - Nota Técnica 20992456)', 283),
(9626, 'anexo', 192, 9612, 2, '23.9', 'A tabela de ônus estabelece o escalonamento de percentuais, a depender do resultado obtido e do pacote de serviços contratado, que incidem sobre a receita de SEDEX e PAC, para definição do valor do ônus:', 'Tabela de Ônus\nDesvio em relação ao NS Nacional Ponderado\n(NS Ponderado - NS Realizado)	Platinum	Diamante	Infinite\nAté -0,5%	0,05%	-	-\nDe -0,5% a -1%	0,10%	0,05%	-\nDe -1% a -2%	0,15%	0,10%	0,05%\nDe -2% a -4%	0,30%	0,25%	0,20%\nDe -4% a -6%	0,45%	0,40%	0,35%\nDe -6% a -8%	0,60%	0,55%	0,50%\nDe -8% a -10%	0,75%	0,70%	0,65%\nMenor que -10%	1,50%	1,45%	1,40%\n(Processo SEI 53180.012138/2021-80 - Nota Técnica 25760874)', 284),
(9627, 'anexo', 192, NULL, 1, '24', 'RASTREAMENTO', '', 285),
(9628, 'anexo', 192, 9627, 2, '24.1', 'As informações do rastreamento do objeto podem ser consultadas no Portal Correios ou na intranet.', '', 286),
(9629, 'anexo', 192, NULL, 1, '25', 'ENTREGA DOMICILIAR', '', 287),
(9630, 'anexo', 192, 9629, 2, '25.1', 'A encomenda pertence ao remetente até sua entrega ao destinatário ou a quem possa receber em seu nome.', '', 288),
(9631, 'anexo', 192, 9629, 2, '25.2', 'A encomenda é entregue mediante recibo, a qualquer pessoa adulta, civilmente capaz e que se apresente no endereço indicado para recebê-la, com exceção de objeto do serviço Correios Mini Envios, que é entregue sem recibo, depositado em caixa de correios ou em local seguro.', '', 289),
(9632, 'anexo', 192, 9631, 3, '25.2.1', 'No recibo deve constar a assinatura do recebedor, assim como a indicação do número de documento de identificação.', '25.2.1.1 Se a assinatura não for legível, deve-se registrar o nome e sobrenome do recebedor.', 290),
(9633, 'anexo', 192, 9631, 3, '25.2.2', 'Todas as encomendas destinadas a edifícios são entregues nas suas respectivas portarias.', '25.2.2.1 A entrega com o serviço adicional de Mão Própria deve ocorrer apenas a um dos três destinatários previstos no formulário específico (entrega porta a porta).', 291),
(9634, 'anexo', 192, 9629, 2, '25.3', 'Quando expressamente autorizado pelo remetente, no rótulo de endereçamento, o objeto pode ser entregue mediante recibo a qualquer pessoa adulta, civilmente capaz e que se apresente no endereço vizinho indicado na autorização.', '', 292),
(9635, 'anexo', 192, 9629, 2, '25.4', 'Nenhuma encomenda pode ser aberta pelo destinatário antes do seu recebimento.', '', 293),
(9636, 'anexo', 192, 9629, 2, '25.5', 'Sempre que houver indício de violação ou avaria da encomenda, deve ser lavrado Auto de Irregularidade - AI ou Termo de Constatação - TC, de acordo com o regulamento constante no MANENC 6/7, na unidade em que a irregularidade for identificada.', '', 294),
(9637, 'anexo', 192, 9636, 3, '25.5.1', 'A encomenda acompanhada de AI ou TC deve ser encaminhada para entrega interna.', '', 295),
(9638, 'anexo', 192, 9629, 2, '25.6', 'A encomenda destinada à localidade com Medida Defensiva de Entrega - MDE é encaminhada para entrega interna, na unidade dos Correios habilitada e mais próxima do endereço do destinatário.', '', 296),
(9639, 'anexo', 192, 9629, 2, '25.7', 'São encaminhadas mensagens via SMS, informando os principais momentos da prestação do serviço de entrega de encomendas, para remetente e destinatário que cadastram o número do celular corretamente no momento da postagem ou a qualquer tempo no Portal Correios, em rastreamento.', 'Nota: os eventos de SMS somente são enviados a partir do momento de cadastramento do número de celular.', 297),
(9640, 'anexo', 192, 9629, 2, '25.8', 'A entrega dos serviços de encomendas é realizada da seguinte forma:', '', 298),
(9641, 'anexo', 192, 9640, 3, '25.8.1', 'SEDEX Hoje:', '', 299),
(9642, 'anexo', 192, 9641, 4, 'a', 'entrega domiciliar realizada de segunda-feira a domingo, inclusive feriados:', 'I -  1ª tentativa: até as 23h do dia da postagem, para objetos postados até as 19h nas unidades operacionais e até as 15h nas unidades de atendimento;\nNota: para objetos postados após as 19h nas unidades operacionais a entrega é realizada até as 12h do dia seguinte.\nII -  2ª tentativa: em janela de entrega distinta da janela da 1ª tentativa.\nNota: primeira janela de entrega (manhã): 7h-12h; segunda janela de entrega (tarde): 12h-19h; terceira janela de entrega (noite): 19h-23h.', 300),
(9643, 'anexo', 192, 9640, 3, '25.8.2', 'SEDEX 10:', '', 301),
(9644, 'anexo', 192, 9643, 4, 'a', 'entrega domiciliar realizada de segunda a sexta-feira, em dias úteis:', 'I - 1ª tentativa: até as 10h do dia útil seguinte ao da postagem;\nII - 2ª tentativa: no decorrer do mesmo dia da 1ª tentativa de entrega;\nIII - 3ª tentativa: até as 10h do dia útil seguinte a 2ª tentativa de entrega.', 302),
(9645, 'anexo', 192, 9643, 4, 'b', 'a entrega domiciliar aos sábados ocorre da seguinte forma:', 'I - 1ª tentativa: até as 10h do dia seguinte ao da postagem;\nII - 2ª tentativa: até as 10h do dia útil seguinte ao da 1ª tentativa;\nIII - 3ª tentativa: no decorrer do mesmo dia da 2ª tentativa de entrega.\nNota: a entrega aos sábados ocorre apenas nas localidades que preveem a distribuição de SEDEX nesse dia.', 303),
(9646, 'anexo', 192, 9643, 4, 'c', 'quando a 1ª ou 2ª tentativa de entrega são frustradas, é deixado no endereço um “Aviso de Tentativa de Entrega”, informando quando o carteiro retorna para uma nova tentativa. Se a 3ª tentativa for frustrada, o aviso comunica a devolução imediata ao remetente.', '', 304),
(9647, 'anexo', 192, 9640, 3, '25.8.3', 'SEDEX 12:', '', 305),
(9648, 'anexo', 192, 9647, 4, 'a', 'entrega domiciliar realizada de segunda a sexta-feira, em dias úteis:', 'I - 1ª tentativa: até as 12h do dia útil seguinte ao da postagem;\nII - 2ª tentativa: até as 12h do dia útil seguinte ao da 1ª tentativa;\nIII - 3ª tentativa: até as 12h do dia útil seguinte ao da 2ª tentativa.', 306),
(9649, 'anexo', 192, 9647, 4, 'b', 'a entrega domiciliar aos sábados ocorre da seguinte forma:', 'I - 1ª tentativa: até as 12h do dia seguinte da postagem;\nII - 2ª tentativa: até as 12h do dia útil seguinte ao da 1ª tentativa;\nIII - 3ª tentativa: até as 12h do dia útil seguinte ao da 2ª tentativa.\nNota: a entrega aos sábados ocorre apenas nas localidades que preveem a distribuição de SEDEX nesse dia.', 307),
(9650, 'anexo', 192, 9647, 4, 'c', 'quando a 1ª ou 2ª tentativa de entrega são frustradas, é deixado no endereço um “Aviso de Tentativa de Entrega”, informando quando o carteiro retorna para uma nova tentativa. Se a 3ª tentativa for frustrada, o aviso comunica a devolução imediata ao remetente.', '', 308),
(9651, 'anexo', 192, 9640, 3, '25.8.4', 'SEDEX:', '', 309),
(9652, 'anexo', 192, 9651, 4, 'a', 'entrega domiciliar realizada de segunda-feira a sábado, em dias úteis;', 'Nota: a entrega aos sábados, quando prevista, é realizada apenas nas localidades classificadas como A+ e A.', 310),
(9653, 'anexo', 192, 9651, 4, 'b', 'são realizadas 3 (três) tentativas de entrega em dias úteis consecutivos;', '', 311),
(9654, 'anexo', 192, 9651, 4, 'c', 'quando a 1ª ou 2ª tentativa de entrega são frustradas, é deixado no endereço um “Aviso de Tentativa de Entrega”, informando quando o carteiro retorna para uma nova tentativa. Se a 3ª tentativa for frustrada, o aviso comunica que a encomenda deve ser retirada internamente, na agência indicada, dentro do prazo de sete dias corridos. Após o prazo, ocorre a devolução imediata ao remetente.', '', 312),
(9655, 'anexo', 192, 9640, 3, '25.8.5', 'PAC:', '', 313),
(9656, 'anexo', 192, 9655, 4, 'a', 'entrega domiciliar realizada de segunda a sexta-feira, em dias úteis;', '', 314),
(9657, 'anexo', 192, 9655, 4, 'b', 'são realizadas 2 (duas) tentativas de entrega em dias úteis consecutivos;', '', 315),
(9658, 'anexo', 192, 9655, 4, 'c', 'quando a 1ª tentativa de entrega é frustrada, é deixado no endereço um “Aviso de Tentativa de Entrega”, informando quando o carteiro retorna para uma nova tentativa. Se a 2ª tentativa for frustrada, o aviso comunica que a encomenda deve ser retirada internamente, na agência indicada, dentro do prazo de sete dias corridos. Após o prazo, ocorre a devolução imediata ao remetente.', '', 316),
(9659, 'anexo', 192, 9640, 3, '25.8.6', 'Correios Mini Envios:', '', 317),
(9660, 'anexo', 192, 9659, 4, 'a', 'entrega domiciliar realizada de segunda a sexta-feira, em dias úteis;', '', 318),
(9661, 'anexo', 192, 9659, 4, 'b', 'é realizada 1 tentativa de entrega em dia útil;', 'Nota: quando há contratação do serviço adicional de Aviso de Recebimento são realizadas 2 (duas) tentativas de entrega em dias úteis consecutivos.', 319),
(9662, 'anexo', 192, 9659, 4, 'c', 'quando a última tentativa de entrega é frustrada, é deixado no endereço um “Aviso de Tentativa de Entrega”, informando que a encomenda deve ser retirada internamente, na agência indicada, dentro do prazo de sete dias corridos. Após o prazo, ocorre a devolução imediata ao remetente.', '', 320),
(9663, 'anexo', 192, 9629, 2, '25.9', 'A Caixa de Correio Inteligente do endereço de destino pode ser usada para a entrega de encomendas, conforme MANDIS 3/1/4.', '', 321),
(9664, 'anexo', 192, 9629, 2, '25.10', 'A funcionalidade de Entrega no Vizinho é realizada quando autorizada pelo remetente, que indica o endereço vizinho ao endereço do destinatário para a entrega da encomenda.', '', 322),
(9665, 'anexo', 192, NULL, 1, '26', 'ENTREGA INTERNA', '', 323),
(9666, 'anexo', 192, 9665, 2, '26.1', 'Há a entrega interna de uma encomenda quando:', '', 324),
(9667, 'anexo', 192, 9666, 4, 'a', 'destinada a Caixa Postal, Posta Restante Pedida e Clique e Retire;', '', 325),
(9668, 'anexo', 192, 9666, 4, 'b', 'frustradas todas as tentativas de entrega previstas para o serviço contratado, exceto os serviços da Linha Premium;', '', 326),
(9669, 'anexo', 192, 9666, 4, 'c', 'destinada a localidade ou zona rural onde não há unidade operacional ou entrega domiciliar;', '', 327),
(9670, 'anexo', 192, 9666, 4, 'd', 'destinada a localidade de acesso difícil, proibido ou com Medida Defensiva de Entrega - MDE;', '', 328),
(9671, 'anexo', 192, 9666, 4, 'e', 'acompanhada de AI ou TC;', '', 329),
(9672, 'anexo', 192, 9666, 4, 'f', 'destinada ao Locker, mas com o número do CPF/CNPJ e/ou e-mail em falta no endereçamento ou em caso de dimensões excedentes aos limites permitidos;', '', 330),
(9673, 'anexo', 192, 9666, 4, 'g', 'mal endereçada, não sendo possível realizar a entrega domiciliar por constar o endereço de destino de forma incompleta ou incorreta.', '', 331),
(9674, 'anexo', 192, 9665, 2, '26.2', 'O Aviso de Chegada deve ser emitido pela agência que efetuará a entrega, no mesmo dia do recebimento da encomenda na unidade e uma única vez, não sendo permitida nova emissão.', '', 332),
(9675, 'anexo', 192, 9674, 3, '26.2.1', 'Não é prevista a entrega de aviso de chegada para objetos destinados ao Locker e Clique e Retire ou que estejam mal endereçados.', '', 333),
(9676, 'anexo', 192, 9665, 2, '26.3', 'Para a entrega interna de SEDEX 10 e SEDEX 12, o objeto é disponibilizado para o cliente na agência de destino até às 10h ou às 12h, respectivamente, do dia útil seguinte ao da postagem, excluindo-se o sábado, sendo considerado como entregue no horário em que for disponibilizado.', '', 334),
(9677, 'anexo', 192, 9665, 2, '26.4', 'No momento da entrega interna de encomenda acompanhada de AI ou TC, o destinatário pode conferir o conteúdo, diante do empregado dos Correios, podendo receber totalmente, receber parcialmente ou até mesmo recusar.', '', 335),
(9678, 'anexo', 192, 9665, 2, '26.5', 'Os procedimentos de entrega interna estão regulamentados no MANATE 4.', '', 336),
(9679, 'anexo', 192, 9665, 2, '26.6', 'Após o prazo de guarda estipulado para o serviço contratado, a encomenda é devolvida imediatamente ao remetente.', '', 337),
(9680, 'anexo', 192, NULL, 1, '27', 'PONTO DE COLETA', '', 338),
(9681, 'anexo', 192, 9680, 2, '27.1', 'Há captação de encomenda pré-postada e também entrega de objeto com referência de CEP específico em unidade de Correios compartilhada, denominada Ponto de Coleta.', '', 339),
(9682, 'anexo', 192, 9680, 2, '27.2', 'A prestação está restrita aos serviços SEDEX e PAC, para clientes com e sem contrato.', '', 340),
(9683, 'anexo', 192, 9680, 2, '27.3', 'As unidades possuem CEP específico, com final 970, 971 ou 972, que deve ser utilizado pelo remetente no endereçamento da encomenda a ser retirada em um Ponto de Coleta.', '', 341),
(9684, 'anexo', 192, 9680, 2, '27.4', 'O endereçamento correto, para a entrega da encomenda em um Ponto de Coleta, deve conter as seguintes informações relacionadas ao destinatário:', '', 342),
(9685, 'anexo', 192, 9684, 4, 'a', 'nome e número do celular do destinatário, com DDD;', '', 343),
(9686, 'anexo', 192, 9684, 4, 'b', 'a expressão “Ponto de Coleta dos Correios”;', '', 344),
(9687, 'anexo', 192, 9684, 4, 'c', 'nome do estabelecimento que é Ponto de Coleta;', '', 345),
(9688, 'anexo', 192, 9684, 4, 'd', 'CEP do Ponto de Coleta;', '', 346),
(9689, 'anexo', 192, 9684, 4, 'e', 'município/UF;', '', 347),
(9690, 'anexo', 192, 9684, 4, 'f', 'CPF/CNPJ do destinatário.', '', 348),
(9691, 'anexo', 192, 9680, 2, '27.5', 'A encomenda encaminhada para entrega em Ponto de Coleta é disponibilizada para retirada durante 3 (três) dias corridos.', '', 349),
(9692, 'anexo', 192, 9691, 3, '27.5.1', 'Após o prazo, ocorre a devolução imediata ao remetente.', '', 350),
(9693, 'anexo', 192, 9691, 3, '27.5.2', 'Não há indenização por atraso ou qualquer tipo de ressarcimento ao remente/destinatário, em razão da devolução da encomenda.', '', 351),
(9694, 'anexo', 192, NULL, 1, '28', 'CLIQUE E RETIRE', '', 352),
(9695, 'anexo', 192, 9694, 2, '28.1', 'Com o Clique e Retire é possível enviar encomenda para retirada em uma unidade dos Correios, sem cobrança adicional na entrega.', '', 353),
(9696, 'anexo', 192, 9695, 3, '28.1.1', 'A funcionalidade está restrita aos serviços SEDEX 10, SEDEX 12, SEDEX, PAC e Correios Mini Envios, para clientes com e sem contrato.', '', 354),
(9697, 'anexo', 192, 9695, 3, '28.1.2', 'Encomenda postada por meio do serviço de Logística Reversa e destinada ao Clique e Retire são aplicadas as regras de cobrança estabelecidas para a Posta Restante Pedida.', '', 355),
(9698, 'anexo', 192, 9694, 2, '28.2', 'As unidades que possuem CEP específico, com final 959, que deve ser utilizado pelo remetente no endereçamento da encomenda a ser retirada em uma unidade dos Correios.', '', 356),
(9699, 'anexo', 192, 9694, 2, '28.3', 'O endereçamento correto, para a entrega da encomenda com Clique e Retire, deve conter as seguintes informações relacionadas ao destinatário:', '', 357),
(9700, 'anexo', 192, 9699, 4, 'a', 'nome e número do celular do destinatário, com DDD;', '', 358),
(9701, 'anexo', 192, 9699, 4, 'b', 'a expressão “Clique e Retire dos Correios”;', '', 359),
(9702, 'anexo', 192, 9699, 4, 'c', 'nome da agência de destino;', '', 360),
(9703, 'anexo', 192, 9699, 4, 'd', 'CEP do Clique e Retire da agência;', '', 361),
(9704, 'anexo', 192, 9699, 4, 'e', 'município/UF.', '', 362),
(9705, 'anexo', 192, 9694, 2, '28.4', 'A encomenda encaminhada para entrega em unidade dos Correios, via Clique e Retire, é disponibilizada para retirada durante sete dias corridos.', '', 363),
(9706, 'anexo', 192, 9705, 3, '28.4.1', 'Após o prazo, ocorre a devolução imediata ao remetente.', '', 364),
(9707, 'anexo', 192, NULL, 1, '29', 'COMPROVANTE ELETRÔNICO DE ENTREGA - CEE', '', 365),
(9708, 'anexo', 192, 9707, 2, '29.1', 'Com o CEE é possível disponibilizar, de forma gratuita, as informações de entrega da encomenda, a partir da captura de imagem da etiqueta preenchida e assinada pelo recebedor, de forma on-line, via website e/ou webservice, conforme viabilidade operacional.', '', 366),
(9709, 'anexo', 192, 9708, 3, '29.1.1', 'A funcionalidade está restrita aos serviços SEDEX Hoje, SEDEX 10, SEDEX 12, SEDEX e PAC, para clientes com contrato.', '', 367),
(9710, 'anexo', 192, 9707, 2, '29.2', 'Dentre os benefícios do CEE estão: acessibilidade, comodidade, confiabilidade, gratuidade, captura da imagem da assinatura do recebedor, eliminação de lista de entrega, informação em tempo real, sucesso nos casos de acareação e redução no tempo de atendimento no pós-venda.', '', 368),
(9711, 'anexo', 192, 9707, 2, '29.3', 'O cliente com contrato, remetente da encomenda ou seus autorizados, para ter acesso à imagem, deve acessar, mediante login, utilizando os dados do ID Correios, o seguinte link: https://cas.correios.com.br/login?service=https://apps3.correios.com.br/arc/bem-vindo', '', 369),
(9712, 'anexo', 192, 9707, 2, '29.4', 'O CEE utiliza o mesmo sistema do AR-e, que é disponibilizado apenas para clientes com contrato.', '', 370),
(9713, 'anexo', 192, NULL, 1, '30', 'ENTREGA NO VIZINHO', '', 371),
(9714, 'anexo', 192, 9713, 2, '30.1', 'Com a funcionalidade de Entrega no Vizinho o remetente pode autorizar a entrega da encomenda em endereço vizinho ao endereço do destinatário.', '', 372),
(9715, 'anexo', 192, 9714, 3, '30.1.1', 'A autorização de entrega no vizinho deve estar indicada expressamente no rótulo de endereçamento da encomenda, incluindo a identificação do endereço vizinho autorizado, conforme padrão especificado no Guia Técnico de Endereçamento.', '', 373),
(9716, 'anexo', 192, 9714, 3, '30.1.2', 'O endereço vizinho a ser indicado pode estar situado até 2 (duas) casas à direita ou à esquerda ou imediatamente à frente do endereço do destinatário.', '', 374),
(9717, 'anexo', 192, 9713, 2, '30.2', 'A funcionalidade está restrita aos serviços SEDEX Hoje, SEDEX 10, SEDEX 12, SEDEX e PAC, para clientes com e sem contrato.', '', 375),
(9718, 'anexo', 192, NULL, 1, '31', 'LOCKER', '', 376),
(9719, 'anexo', 192, 9718, 2, '31.1', 'É possível enviar e retirar encomenda por meio de um armário inteligente dos Correios, sem cobrança adicional, denominado Locker.', '', 377),
(9720, 'anexo', 192, 9718, 2, '31.2', 'O Locker permite o envio de encomenda por meio do serviço de Logística Reversa.', '', 378),
(9721, 'anexo', 192, 9720, 3, '31.2.1', 'Para o envio utilizando o serviço de Logística Reversa, é necessário que o pacote esteja embalado, com a identificação do número do e-ticket na embalagem, assim como o documento fiscal anexado externamente.', '', 379),
(9722, 'anexo', 192, 9720, 3, '31.2.2', 'O e-ticket que possuir o serviço adicional de Checklist e/ou múltiplos objetos não é elegível para o Locker.', '', 380),
(9723, 'anexo', 192, 9720, 3, '31.2.3', 'Após o depósito da encomenda no terminal, o evento “a coletar” é registrado no rastreamento, com prazo de coleta em D+1.', '', 381),
(9724, 'anexo', 192, 9720, 3, '31.2.4', 'O remetente é notificado por e-mail, quando do depósito no Locker.', '', 382),
(9725, 'anexo', 192, 9720, 3, '31.2.5', 'O registro das dimensões e do peso da encomenda é realizado na unidade operacional, após a coleta no terminal.', '', 383),
(9726, 'anexo', 192, 9718, 2, '31.3', 'A funcionalidade de retirada está restrita aos serviços nacionais SEDEX, PAC e Correios Mini Envios e internacionais Packet e Prime, para clientes com e sem contrato.', '', 384),
(9727, 'anexo', 192, 9718, 2, '31.4', 'Os Lockers possuem CEP específico, com final 988 ou 989, que deve ser utilizado pelo remetente no endereçamento da encomenda a ser retirada em um armário inteligente.', '', 385),
(9728, 'anexo', 192, 9718, 2, '31.5', 'O endereçamento correto, para a entrega da encomenda no Locker, deve conter as seguintes informações:', '', 386),
(9729, 'anexo', 192, 9728, 4, 'a', 'do remetente: CPF, CNPJ ou passaporte (estrangeiro);', '', 387),
(9730, 'anexo', 192, 9728, 4, 'b', 'do destinatário: nome, CPF/CNPJ e/ou e-mail (inserido no campo complemento) e número do celular do destinatário, com DDD;', '', 388),
(9731, 'anexo', 192, 9728, 4, 'c', 'do Locker: nome, endereço e CEP.', '', 389),
(9732, 'anexo', 192, 9728, 3, '31.5.1', 'O destinatário deve realizar ou atualizar o cadastro da conta no Meu Correios, para o recebimento de informações de retirada da encomenda.', '', 390),
(9733, 'anexo', 192, 9728, 3, '31.5.2', 'O destinatário é notificado por e-mail, SMS e/ou App Correios, quando a encomenda estiver disponível para retirada.', '', 391),
(9734, 'anexo', 192, 9718, 2, '31.6', 'O prazo de retirada é de 72h, após o envio da notificação de encomenda disponível em Locker.', '', 392),
(9735, 'anexo', 192, 9734, 3, '31.6.1', 'Após o prazo, ocorre a devolução imediata ao remetente.', '', 393),
(9736, 'anexo', 192, 9734, 3, '31.6.2', 'Não há indenização por atraso ou qualquer tipo de ressarcimento ao remente/destinatário, em razão da devolução da encomenda.', '', 394),
(9737, 'anexo', 192, 9718, 2, '31.7', 'Encomenda fora dos padrões de peso e dimensões para entrega em Locker é direcionada para entrega interna na Agência Própria mais próxima ao terminal escolhido, seguindo as regras definidas para entrega interna.', '', 395),
(9738, 'anexo', 192, 9718, 2, '31.8', 'Para encomenda destinada ao Locker não é fornecido recibo de entrega.', '', 396),
(9739, 'anexo', 192, NULL, 1, '32', 'PRAZO DE GUARDA', '', 397),
(9740, 'anexo', 192, 9739, 2, '32.1', 'Prazo de guarda dos serviços de encomendas nacionais:', '', 398),
(9741, 'anexo', 192, 9740, 4, 'a', 'na entrega ao destinatário:', 'I -  72h: encomenda destinada ao Locker, após o envio da notificação de disponibilidade;\nII -  7 (sete) dias corridos: encomenda para entrega interna, Posta Restante Caída ou Posta Restante Pedida;\nIII -  30 (trinta) dias corridos: encomenda endereçada a Caixa Postal.', 399);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(9742, 'anexo', 192, 9740, 4, 'b', 'na devolução ao remetente:', 'I -  7 (sete) dias corridos: encomenda em devolução interna, Posta Restante Caída ou Posta Restante Pedida;\nII -  30 (trinta) dias corridos: encomenda endereçada a Caixa Postal.\nNota: não há prazo de guarda para entrega de SEDEX Hoje, tendo em vista que o serviço não prevê entrega interna.', 400),
(9743, 'anexo', 192, NULL, 1, '33', 'DESCONFORMIDADES NA PRESTAÇÃO DOS SERVIÇOS', '', 401),
(9744, 'anexo', 192, 9743, 2, '33.1', 'O Pedido de Informação - PI poderá ser apresentado por clientes com e sem contrato, por meio da Central de Atendimento dos Correios - CAC ou do Portal Correios, a partir do dia seguinte ao vencimento do prazo de entrega previsto para o serviço contratado e até 90 (noventa) dias corridos a partir da entrega ou da expectativa de entrega do objeto.', '', 402),
(9745, 'anexo', 192, 9743, 2, '33.2', 'São passíveis de indenização o atraso, a avaria, o extravio, o roubo, o furto e o vício de qualidade (falha operacional).', '', 403),
(9746, 'anexo', 192, 9745, 3, '33.2.1', 'Considera-se em atraso a encomenda na qual a primeira tentativa de entrega ocorreu após o prazo previsto de entrega.', '', 404),
(9747, 'anexo', 192, 9745, 3, '33.2.2', 'A indenização por avaria é proporcional ao dano causado, exceto nos casos relacionados abaixo, sendo considerada como avaria total:', '', 405),
(9748, 'anexo', 192, 9747, 4, 'a', 'quando o conteúdo da encomenda se tornar impróprio para o consumo;', '', 406),
(9749, 'anexo', 192, 9747, 4, 'b', 'os casos de impossibilidade técnica de identificar ou classificar a proporcionalidade do dano causado.', '', 407),
(9750, 'anexo', 192, 9745, 3, '33.2.3', 'Considera-se extravio, roubo ou furto quando:', '', 408),
(9751, 'anexo', 192, 9750, 4, 'a', 'a entrega da encomenda ocorrer em local distinto do endereço do destinatário e não seja recuperada para a devida entrega no endereço correto;', '', 409),
(9752, 'anexo', 192, 9750, 4, 'b', 'ocorrer sinistro ou delito praticado contra a operação postal, capaz de inviabilizar a entrega íntegra da encomenda;', '', 410),
(9753, 'anexo', 192, 9750, 4, 'c', 'não ocorrer a devolução ao remetente.', '33.2.3.1 A encomenda a faturar extraviada, roubada ou furtada terá a entrega suspensa, cujos procedimentos estão regulamentados no MANCAT 16/31.', 411),
(9754, 'anexo', 192, 9745, 3, '33.2.4', 'O vício de qualidade (falha operacional) acontece quando não são realizadas as tentativas de entrega domiciliar previstas para o serviço contratado, sendo o objeto entregue internamente em uma unidade dos Correios, enquadrando-se como um vício de qualidade por disparidade entre o serviço efetivamente prestado ante a sua oferta.', '', 412),
(9755, 'anexo', 192, 9743, 2, '33.3', 'Há devolução dos valores pagos relativos aos serviços adicionais não prestados total ou parcialmente.', '', 413),
(9756, 'anexo', 192, NULL, 1, '34', 'PAGAMENTO DE INDENIZAÇÃO', '', 414),
(9757, 'anexo', 192, 9756, 2, '34.1', 'O titular do direito ao pagamento de indenização, quando a reclamação for procedente, está definido conforme abaixo:', '', 415),
(9758, 'anexo', 192, 9757, 4, 'a', 'ao remetente ou a terceiro indicado por ele:', 'I -  atraso na entrega, exceto para o serviço Pagamento na Entrega, quando os preços postais forem pagos pelo destinatário;\nII -  avaria parcial de Pagamento na Entrega ou quando entrega de objeto em devolução;\nIII -  extravio, roubo, furto, avaria total ou vício de qualidade (falha operacional);\nIV -  entrega de objeto Pagamento na Entrega sem o devido pagamento do Vale Postal pelo destinatário.', 416),
(9759, 'anexo', 192, 9757, 4, 'b', 'ao destinatário ou a terceiro indicado por ele:', 'I -  atraso na entrega de Pagamento na Entrega, quando os preços postais forem pagos pelo destinatário;\nII -  avaria parcial.', 417),
(9760, 'anexo', 192, 9757, 4, 'c', 'ao cliente detentor do contrato com os Correios ou a terceiro indicado por ele, quando se tratar:', 'I - do serviço de Logística Reversa;\nII - de permissão para utilização de produtos e serviços por seus autorizados.\nNota: o detentor do contrato deve receber a reclamação e se julgar procedente, registrá-la junto aos Correios, responsabilizando-se pelo ressarcimento dos valores relativos às indenizações pagas ao seu autorizado.', 418),
(9761, 'anexo', 192, 9756, 2, '34.2', 'Quando a reclamação referente à avaria total, extravio, roubo ou furto for procedente, a indenização ao titular do direito de recebê-la será paga como segue:', '', 419),
(9762, 'anexo', 192, 9761, 4, 'a', 'sem valor declarado: devolução dos valores de postagem do serviço principal, dos serviços e produtos adicionais, quando contratados, e do valor referente à indenização automática;', '', 420),
(9763, 'anexo', 192, 9761, 4, 'b', 'com valor declarado: devolução dos valores de postagem do serviço principal, dos serviços e produtos adicionais, quando contratados, exceto ad valorem, e do valor declarado.', '', 421),
(9764, 'anexo', 192, 9756, 2, '34.3', 'Quando a reclamação referente à avaria parcial for procedente, a indenização ao titular do direito de recebê-la será paga como segue:', '', 422),
(9765, 'anexo', 192, 9764, 4, 'a', 'sem valor declarado: devolução dos valores de postagem do serviço principal, dos serviços adicionais, quando contratados, exceto embalagem, e do valor parcial referente à indenização automática, proporcional ao peso faltante ou dano causado;', '', 423),
(9766, 'anexo', 192, 9764, 4, 'b', 'com valor declarado: devolução dos valores de postagem do serviço principal, dos serviços adicionais, quando contratados, exceto embalagem e Ad Valorem, e do valor parcial declarado, proporcional ao peso faltante ou dano causado.', '', 424),
(9767, 'anexo', 192, 9764, 3, '34.3.1', 'No caso de documentos ou objetos cuja utilização ou funcionamento só tenha sentido nas situações em que a integridade é preservada, como documentos pessoais, fotos ou equipamentos, os procedimentos de indenização devem ocorrer como se a avaria fosse total, ainda que apenas uma parte do objeto tenha sido avariado.', '', 425),
(9768, 'anexo', 192, 9756, 2, '34.4', 'Quando a reclamação referente ao atraso na entrega for procedente, a indenização ao titular do direito de recebê-la será paga como segue:', '', 426),
(9769, 'anexo', 192, 9768, 4, 'a', 'SEDEX Hoje postado até as 19h em unidade operacional ou até as 15h em unidade de atendimento e não entregue até as 23h do mesmo dia: 100% do valor da postagem (decisão judicial, Processo SEI 53107.002188/2017-55, Ofício nº 15628511);', '', 427),
(9770, 'anexo', 192, 9768, 4, 'b', 'SEDEX Hoje postado entre as 19h01 e 20h em unidade operacional e não entregue até as 12h do dia seguinte: 100% do valor da postagem (decisão judicial, Processo SEI 53107.002188/2017-55, Ofício nº 15628511);', '', 428),
(9771, 'anexo', 192, 9768, 4, 'c', 'SEDEX 10 entregue após as 10h do dia útil seguinte à postagem: 100% do valor da postagem (decisão judicial, Processo SEI 53107.002188/2017-55, Ofício nº 15628511);', '', 429),
(9772, 'anexo', 192, 9768, 4, 'd', 'SEDEX 12 entregue após as 12h do dia útil seguinte à postagem: 100% do valor da postagem (decisão judicial, Processo SEI 53107.002188/2017-55, Ofício nº 15628511);', '', 430),
(9773, 'anexo', 192, 9768, 4, 'e', 'SEDEX:', 'I -  de 1 (um) a 3 (três) dias úteis de atraso: 5% do valor da postagem;\nII -  de 4 (quatro) a 5 (cinco) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 5 (cinco) dias úteis de atraso: 15% do valor da postagem.', 431),
(9774, 'anexo', 192, 9768, 4, 'f', 'PAC:', 'I -  de 1 (um) a 5 (cinco) dias úteis de atraso: 5% do valor da postagem;\nII -  de 6 (seis) a 10 (dez) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 10 (dez) dias úteis de atraso: 15% do valor da postagem.', 432),
(9775, 'anexo', 192, 9768, 3, '34.4.1', 'Não há indenização por atraso na entrega do serviço Correios Mini Envios.', '', 433),
(9776, 'anexo', 192, 9768, 3, '34.4.2', 'Os valores referentes aos serviços adicionais, embalagem e Ad Valorem não são restituídos.', '', 434),
(9777, 'anexo', 192, 9768, 3, '34.4.3', 'Cabe indenização por atraso na entrega quando a 1ª tentativa não ocorrer dentro do prazo definido para o serviço contratado.', '', 435),
(9778, 'anexo', 192, 9768, 3, '34.4.4', 'Não cabe indenização por atraso na devolução ao remetente de qualquer encomenda.', '', 436),
(9779, 'anexo', 192, 9756, 2, '34.5', 'Quando a reclamação referente ao vício de qualidade (falha operacional) for procedente, a indenização ao titular do direito de recebê-la será paga como segue:', '', 437),
(9780, 'anexo', 192, 9779, 4, 'a', 'devolução equivalente a 15% do valor total pago na postagem, exceto serviços adicionais e embalagens, quando as tentativas de entrega domiciliar previstas para o serviço contratado não forem realizadas conforme previsto em normativos, salvo em casos fortuitos ou de força maior, devidamente regulados;', '', 438),
(9781, 'anexo', 192, 9779, 4, 'b', 'a devolução se aplica para o caso em que, no momento da postagem, o serviço contratado previa a entrega domiciliar do objeto no destino, conforme informação constante no comprovante do Sistema de Atendimento ou no Calculador de Prazos e Preços do Portal Correios, mas foi encaminhado diretamente para a entrega interna em uma unidade dos Correios, sem ocorrer as tentativas de entrega em domicílio;', '', 439),
(9782, 'anexo', 192, 9779, 4, 'c', 'para o objeto reclamado, sem a tentativa de entrega domiciliar e destinado a município com CEP único, deve existir consulta junto a unidade responsável pela distribuição de encomendas, para identificação de atendimento ao art. 11 da Portaria nº 15.441/2024 do Ministério das Comunicações.', 'Nota: para os endereços em conformidade com a referida legislação, cabe indenização pela não tentativa de entrega domiciliar. Para os endereços desconformes, não cabe indenização, restando esclarecer ao reclamante.', 440),
(9783, 'anexo', 192, 9756, 2, '34.6', 'Quando o serviço adicional de Mão Própria não for adequadamente prestado, restituir os valores pagos a título de postagem e do referido serviço adicional.', '', 441),
(9784, 'anexo', 192, 9756, 2, '34.7', 'Ocorrendo a devolução da encomenda sem motivo justificável, previsto nos manuais da Empresa, o remetente pode requerer a devolução dos valores pagos pela postagem e pelos serviços adicionais adquiridos, exceto Ad Valorem e embalagem.', '', 442),
(9785, 'anexo', 192, 9756, 2, '34.8', 'O detalhamento das normas sobre indenização e Pedido de Informação estão disponíveis no MANCAN 7 e no Termo de Uso do Sistema Fale Conosco.', '', 443),
(9786, 'anexo', 192, NULL, 1, '35', 'DESISTÊNCIA DE POSTAGEM PELO REMETENTE', '', 444),
(9787, 'anexo', 192, 9786, 2, '35.1', 'O remetente pode desistir da postagem da encomenda, desde que o objeto ainda esteja fisicamente na unidade de origem, sendo devolvido o valor pago pela postagem, exceto por embalagem adquirida em conjunto com o serviço principal.', '', 445),
(9788, 'anexo', 192, 9787, 3, '35.1.1', 'A regra também se aplica para objeto postado com DH – depois do horário, ou seja, para a encomenda que ainda se encontra fisicamente na unidade de origem no dia seguinte à postagem.', 'Nota 1: quando a encomenda estiver fisicamente na unidade de origem e ainda puder ser estornada, devolver o objeto e os respectivos valores ao cliente, conforme procedimentos previstos no MANATE 2/2 para cada forma de pagamento.\nNota 2: quando a encomenda estiver fisicamente na unidade de origem e não puder mais ser estornada, devolver o objeto e solicitar a devolução dos valores ao cliente, conforme procedimentos previstos no MANATE 2/2.', 446),
(9789, 'anexo', 192, 9787, 3, '35.1.2', 'A desistência de postagem pelo remetente não está autorizada para o serviço de Logística Reversa, em nenhuma situação.', '', 447),
(9790, 'anexo', 192, 9786, 2, '35.2', 'Para a encomenda já expedida fisicamente da unidade de origem para uma unidade operacional, o cliente deve ser orientado a acionar a funcionalidade de Suspensão de Entrega do objeto, conforme definido no MANCAT 16/6/5, não havendo devolução de valores pagos.', '', 448),
(9791, 'anexo', 192, 9786, 2, '35.3', 'Os procedimentos operacionais a serem executados pela unidade de origem, relacionados à desistência de postagem, inclusive quanto à devolução de valores, devem ser consultados no MANATE 2/2.', '', 449),
(9792, 'anexo', 192, NULL, 1, '36', 'RESPONSABILIDADE', '', 450),
(9793, 'anexo', 192, 9792, 2, '36.1', 'Os Correios não se responsabilizam:', '', 451),
(9794, 'anexo', 192, 9793, 4, 'a', 'pelo conteúdo da encomenda;', '', 452),
(9795, 'anexo', 192, 9793, 4, 'b', 'por valor incluído em objeto sem declaração de valor;', '', 453),
(9796, 'anexo', 192, 9793, 4, 'c', 'pela demora ou pelo prejuízo resultante de omissão ou erro por parte do remetente;', '', 454),
(9797, 'anexo', 192, 9793, 4, 'd', 'por objeto apreendido, confiscado ou destruído por autoridade competente;', '', 455),
(9798, 'anexo', 192, 9793, 4, 'e', 'por caso fortuito ou de força maior;', '', 456),
(9799, 'anexo', 192, 9793, 4, 'f', 'por prejuízos indiretos e benefícios não realizados.', '* * * * *', 457),
(9800, 'anexo', 193, NULL, 1, '1', 'SERVIÇOS DISPONÍVEIS', '', 0),
(9801, 'anexo', 193, 9800, 2, '1.1', 'SEDEX e PAC.', '', 1),
(9802, 'anexo', 193, NULL, 1, '2', 'PÚBLICO-ALVO', '', 2),
(9803, 'anexo', 193, 9802, 2, '2.1', 'Pessoas físicas sem contrato e pessoas jurídicas com e sem contrato.', '', 3),
(9804, 'anexo', 193, NULL, 1, '3', 'SERVIÇOS INERENTES', '', 4),
(9805, 'anexo', 193, 9804, 2, '3.1', 'Serviços que não implicam custos adicionais ao cliente:', 'a) devolução garantida;\nb) rastreamento do objeto;\nc) registro automático.', 5),
(9806, 'anexo', 193, NULL, 1, '4', 'SERVIÇOS ADICIONAIS', '', 6),
(9807, 'anexo', 193, 9806, 2, '4.1', 'Serviços que implicam custos adicionais ao cliente:', 'a) Aviso de Recebimento - AR;\nb) Coleta Programada (apenas clientes com contrato);\nc) Mão Própria - MP;\nd) Posta Restante Pedida;\ne) Valor Declarado - VD (serviço obrigatório).', 7),
(9808, 'anexo', 193, NULL, 1, '5', 'POSTAGEM', '', 8),
(9809, 'anexo', 193, 9808, 2, '5.1', 'O remetente do objeto deve pagar os preços postais no momento da postagem, podendo incluí-los no valor a ser cobrado do destinatário.', '', 9),
(9810, 'anexo', 193, 9808, 2, '5.2', 'O valor mínimo do Vale Postal Eletrônico para o envio de encomendas com pagamento na entrega é o valor total da postagem.', '', 10),
(9811, 'anexo', 193, 9810, 3, '5.2.1', 'O valor máximo está definido na tabela de preços do serviço contratado.', '', 11),
(9812, 'anexo', 193, 9808, 2, '5.3', 'A encomenda Pagamento na Entrega não tem Indenização Automática e somente deve ser aceita com Valor Declarado - VD.', '', 12),
(9813, 'anexo', 193, 9812, 3, '5.3.1', 'A encomenda deve ser apresentada aberta, para que o atendente verifique a conformidade entre o conteúdo com a informação constante da nota fiscal, do cupom fiscal ou do Formulário de Discriminação de Conteúdo (caso não se trate de produto tributável).', '', 13),
(9814, 'anexo', 193, 9812, 3, '5.3.2', 'Para os clientes com contrato, é dispensada a apresentação da encomenda aberta.', '', 14),
(9815, 'anexo', 193, 9808, 2, '5.4', 'A nota fiscal, o cupom fiscal ou o Formulário de Discriminação de Conteúdo deve ser acondicionada em envelope plástico transparente autoadesivo para remessa de documentos, código 76500060-1.', '', 15),
(9816, 'anexo', 193, 9815, 3, '5.4.1', 'O envelope deve ser afixado na parte externa da encomenda, de maneira a suportar o tráfego postal e facilitar a verificação por parte dos órgãos de fiscalização tributária.', '', 16),
(9817, 'anexo', 193, 9815, 3, '5.4.2', 'Na falta do envelope citado acima, deve ser utilizado o envelope do tipo comum, padronizado para uso nos serviços postais.', '', 17),
(9818, 'anexo', 193, 9808, 2, '5.5', 'Ao emitir o Vale Postal Nacional eletrônico (VPNe) de Pagamento na Entrega, a agência de postagem deve observar os seguintes passos:', 'a) o pré-VPNe deve ser preenchido no sistema da agência de origem, no momento da postagem, com:\nI - os dados do remetente: nome, endereço, cidade, CEP, CPF/CNPJ, RG ou documento de identificação com foto;\nII - os dados do destinatário: nome, endereço, cidade e CEP;\nIII - o valor do VPNe; e\nIV - o número de registro do objeto Pagamento na Entrega.\nb) na agência de destino, devem ser completadas as informações do destinatário: CPF/CNPJ, RG ou documento de identificação com foto;\nc) o campo Valor Nominal deve ser preenchido com o valor a cobrar do destinatário;\nd) o campo Valor Declarado deve ser preenchido com o valor especificado em nota fiscal para efeito de indenização ao cliente;\ne) o campo “Agência de Destino”, deve ser preenchido com seu respectivo MCU pela unidade operacional no destino;\nf) o VPNe deve ser emitido em moeda nacional e complementado o preenchimento na agência de destino, no ato da entrega do objeto, sendo obrigatória a apresentação do RG e do CPF/CNPJ do destinatário.', 18),
(9819, 'anexo', 193, NULL, 1, '6', 'PREÇOS', '', 19),
(9820, 'anexo', 193, 9819, 2, '6.1', 'O Pagamento na Entrega é precificado da seguinte forma:', '', 20),
(9821, 'anexo', 193, 9820, 4, 'a', 'clientes sem contrato: precificar utilizando a tabela SEDEX ou PAC à vista, mais o valor do Vale Postal Nacional Eletrônico, modalidade à vista;', '', 21),
(9822, 'anexo', 193, 9820, 4, 'b', 'clientes com contrato: precificar utilizando a tabela SEDEX ou PAC a faturar, conforme contrato do cliente, mais o valor do Vale Postal Nacional Eletrônico, modalidade a faturar.', '', 22),
(9823, 'anexo', 193, NULL, 1, '7', 'PRAZO DE ENTREGA', '', 23),
(9824, 'anexo', 193, 9823, 2, '7.1', 'O prazo de entrega é considerado quando da chegada do objeto na agência que efetuará a entrega.', '', 24),
(9825, 'anexo', 193, NULL, 1, '8', 'ENTREGA', '', 25),
(9826, 'anexo', 193, 9825, 2, '8.1', 'A entrega interna deve ser realizada nas Agência dos Correios (AC ou AGF) mais próxima do endereço do destinatário.', '', 26),
(9827, 'anexo', 193, 9825, 2, '8.2', 'O objeto deve permanecer disponível para ser retirado na agência por até 7 (sete) dias corridos, sendo devolvido ao remetente após esse prazo.', '', 27),
(9828, 'anexo', 193, 9825, 2, '8.3', 'Colaborador da agência deve:', '', 28),
(9829, 'anexo', 193, 9828, 4, 'a', 'receber, conferir e lançar o objeto no SRO;', '', 29),
(9830, 'anexo', 193, 9828, 4, 'b', 'cadastrar a encomenda no SARA como objeto interno, indicando o valor nominal a ser cobrado do destinatário, conforme consta do VPNe;', '', 30),
(9831, 'anexo', 193, 9828, 4, 'c', 'emitir LDI para entrega interna da encomenda;', '', 31),
(9832, 'anexo', 193, 9828, 4, 'd', 'obter o código da agência de origem para preencher o Aviso de Chegada;', '', 32),
(9833, 'anexo', 193, 9828, 4, 'e', 'emitir o Aviso de Chegada do objeto para o destinatário da encomenda; e', '', 33),
(9834, 'anexo', 193, 9828, 4, 'f', 'encaminhar o objeto para a seção de guarda da agência.', '', 34),
(9835, 'anexo', 193, 9825, 2, '8.4', 'Para entregar o objeto ao destinatário, o atendente da agência de destino deve conferir:', '', 35),
(9836, 'anexo', 193, 9835, 4, 'a', 'o documento com RG e CPF/CNPJ do destinatário; e', '', 36),
(9837, 'anexo', 193, 9835, 4, 'b', 'o comprovante de pagamento do valor nominal previsto no VPNe.', 'Nota 1: a encomenda pode ser retirada mesmo sem a apresentação do Aviso de Chegada, desde que o próprio destinatário a retire, após apresentar um documento de identificação com foto.\nNota 2: quando se tratar de entrega com o serviço adicional de Mão Própria - MP, o destinatário deve apresentar documento de identificação com foto, mesmo que apresente o Aviso de Chegada.', 37),
(9838, 'anexo', 193, 9835, 4, 'c', 'receber o valor do Vale Postal preferencialmente via Pix. Na impossibilidade dessa modalidade de pagamento, pode ser realizado em dinheiro e em moeda nacional;', '', 38),
(9839, 'anexo', 193, 9835, 4, 'd', 'após recebimento do valor do Vale Postal é necessário completar o preenchimento do Vale Postal no sistema;', 'Nota: VPNe deve estar disponível no SARA para o remetente da encomenda assim que for efetuada a baixa do objeto na agência de destino.', 39),
(9840, 'anexo', 193, 9835, 4, 'e', 'efetuar baixa no SARA.', 'Nota: não será aceito cheque nem cartão de crédito/débito para efetuar o pagamento do serviço Pagamento na Entrega a ser retirado na agência de destino.', 40),
(9841, 'anexo', 193, 9825, 2, '8.5', 'Recomendações especiais de entrega:', '', 41),
(9842, 'anexo', 193, 9841, 4, 'a', 'antes da entrega, deve-se perguntar ao destinatário se ele realmente solicitou a encomenda na modalidade a pagar;', '', 42),
(9843, 'anexo', 193, 9841, 4, 'b', 'o destinatário não pode abrir a encomenda antes da realização do pagamento;', '', 43),
(9844, 'anexo', 193, 9841, 4, 'c', 'a responsabilidade dos Correios restringe-se aos casos de avaria ou violação, cuja ocorrência enseja a lavratura de auto de irregularidade;', '', 44),
(9845, 'anexo', 193, 9841, 4, 'd', 'após a entrega, se o destinatário se sentir lesado, deve receber a seguinte orientação:', 'I - registrar Boletim de Ocorrência - BO - na delegacia de polícia;\nII - entregar uma cópia do BO à unidade que efetuou a entrega da encomenda;\nIII - ser informado de que a restituição do valor pago somente ocorre mediante ordem judicial, exarada em processo que discuta a lesão alegada, se de fato ocorrida;\nIV - o processo judicial é instaurado entre o remetente e o destinatário.', 45),
(9846, 'anexo', 193, 9841, 4, 'e', 'a cópia do BO deve ser arquivada na agência de entrega da encomenda;', '', 46),
(9847, 'anexo', 193, 9841, 4, 'f', 'o vale postal tem seu trâmites administrativos normalmente; e', '', 47),
(9848, 'anexo', 193, 9841, 4, 'g', 'o VPNe deve ser encaminhado ao remetente.', '', 48),
(9849, 'anexo', 193, NULL, 1, '9', 'PRAZO DE GUARDA', '', 49),
(9850, 'anexo', 193, 9849, 2, '9.1', 'O prazo de guarda no destino é contado a partir do dia seguinte ao da disponibilidade do objeto ao destinatário, de acordo com a seguinte ordem de prioridade:', 'a) de entrega do Aviso de Chegada;\nb) de lançamento no caderno ou lista de entrega interna da Agência;\nc) do carimbo datador no verso da encomenda, quando esta não for protocolada.', 50),
(9851, 'anexo', 193, NULL, 1, '10', 'VALE POSTAL', '', 51),
(9852, 'anexo', 193, 9851, 2, '10.1', 'O valor pago pelo destinatário deve ser devolvido ao remetente por intermédio do serviço Vale Postal Nacional Eletrônico -  VPNe e deve constar as seguintes informações:', 'a) o valor do Vale Postal;\nb) a forma de pagamento da operação (dinheiro);\nc) a data da transação;\nd) a finalidade da remessa;\ne) a localidade de origem e destino dos recursos;\nf) o nome, CPF ou CNPJ, se for o caso, e o documento de identificação do remetente e do destinatário dos recursos.', 52),
(9853, 'anexo', 193, NULL, 1, '11', 'REEMBOLSO DO VALOR AO REMETENTE', '', 53),
(9854, 'anexo', 193, 9853, 2, '11.1', 'O reembolso do valor pago pelo destinatário ao remetente deve ser online para os clientes à vista e em D+2 para clientes com contrato, a contar da data de entrega da encomenda e pagamento do VPNe.', '', 54),
(9855, 'anexo', 193, 9853, 2, '11.2', 'A agência de origem do objeto deve:', '', 55),
(9856, 'anexo', 193, 9855, 4, 'a', 'receber o Vale Postal encaminhado pela agência que efetuou a entrega do objeto no destino;', '', 56),
(9857, 'anexo', 193, 9855, 4, 'b', 'emitir o Aviso de Chegada para o destinatário do Vale Postal;', 'Nota 1: somente o destinatário do Vale Postal ou seu representante legal podem retirar o pagamento do VPNe e mediante apresentação do RG e CPF/CNPJ;\nNota 2: caso o pagamento seja retirado pelo representante legal do destinatário do Vale Postal, deve ser autorizado o pagamento no verso do Aviso de Chegada e anexada cópia do documento que comprove a representação (procuração).', 57),
(9858, 'anexo', 193, 9855, 4, 'c', 'pagar o vale, em dinheiro e em moeda nacional, quando o cliente comparecer à agência, mediante apresentação de documento de identificação (com foto) e CPF/CNPJ.', '', 58),
(9859, 'anexo', 193, NULL, 1, '12', 'GENERALIDADES', '', 59),
(9860, 'anexo', 193, 9859, 2, '12.1', 'Todas as demais regras do Pagamento na Entrega, que não se encontram neste Anexo, como limites de peso e dimensões, cubagem, embalagem, acondicionamento etc., seguem as mesmas regras do SEDEX ou do PAC, conforme serviço contratado.', '* * * * *', 60),
(9861, 'anexo', 194, NULL, 1, '1', 'DEFINIÇÃO', '1.1 Transporte de Armas - Produto Controlado pelo Comando do Exército - PCE é o serviço na modalidade expressa (SEDEX, SEDEX 10 ou SEDEX 12), de armas de fogo ou de pressão, suas peças e acessórios e seus simulacros e imitações, regulamentado pelo Decreto Nº 10.627, de 12 de fevereiro de 2021.', 0),
(9862, 'anexo', 194, NULL, 1, '2', 'PÚBLICO ALVO', '2.1 Pessoas jurídicas com contrato de encomendas nacionais (fabricante nacional ou comércio especializado), conforme especificado nos itens 6.2.1, 6.2.2 e 6.2.3.', 1),
(9863, 'anexo', 194, NULL, 1, '3', 'SERVIÇOS INERENTES', '3.1 Serviços que não implicam em custos adicionais ao cliente:', 2),
(9864, 'anexo', 194, 9863, 4, 'a', 'devolução garantida;', '', 3),
(9865, 'anexo', 194, 9863, 4, 'b', 'rastreamento do objeto;', '', 4),
(9866, 'anexo', 194, 9863, 4, 'c', 'registro automático.', '', 5),
(9867, 'anexo', 194, NULL, 1, '4', 'SERVIÇOS ADICIONAIS OBRIGATÓRIOS', '4.1 Serviços com contratação obrigatória e que podem implicar ou não em custos adicionais ao cliente:', 6),
(9868, 'anexo', 194, 9867, 4, 'a', 'Aviso de Recebimento - AR (custo adicional);', '', 7),
(9869, 'anexo', 194, 9867, 4, 'b', 'Valor Declarado - VD (custo adicional);', '', 8),
(9870, 'anexo', 194, 9867, 4, 'c', 'Produto Controlado - EE (sem custo adicional).', 'Nota: o serviço adicional “Produto Controlado - EE”, código 036, foi criado apenas para ser utilizado quando do transporte de armas via SEDEX, linhas convencional e Premium, com objetivo de controle, não sendo permitida sua utilização para qualquer outro tipo de transporte.', 9),
(9871, 'anexo', 194, NULL, 1, '5', 'SERVIÇOS ADICIONAIS OPCIONAIS', '5.1 Serviços que implicam em custos adicionais ao cliente:', 10),
(9872, 'anexo', 194, 9871, 4, 'a', 'Devolução de Documento - DD;', '', 11),
(9873, 'anexo', 194, 9871, 4, 'b', 'Mão Própria - MP.', '', 12),
(9874, 'anexo', 194, NULL, 1, '6', 'POSTAGEM', '6.1 Postagem permitida apenas por meio de celebração de contrato de encomendas nacionais, na modalidade expressa (SEDEX, SEDEX 10 ou SEDEX 12) e com os serviços adicionais obrigatórios de Valor Declarado - VD, Aviso de Recebimento - AR e EE - produto controlado.\n6.2 Estão autorizados os seguintes tipos de remessas.\n6.2.1 De fabricantes nacionais para:', 13),
(9875, 'anexo', 194, 9874, 4, 'a', 'organizações militares das Forças Armadas;', '', 14),
(9876, 'anexo', 194, 9874, 4, 'b', 'órgãos de segurança pública listados no Artigo 144 da Constituição Federal - CF (Polícia Federal - PF, Polícia Rodoviária Federal - PRF, Polícia Ferroviária Federal, Polícia Civil - PC, Polícia Militar - PM e Corpo de Bombeiro Militar - CBM);', '', 15),
(9877, 'anexo', 194, 9874, 4, 'c', 'órgãos públicos e instituições expressamente autorizadas;', '', 16),
(9878, 'anexo', 194, 9874, 4, 'd', 'lojista do comércio especializado, detentor de registro junto ao Exército.', '', 17),
(9879, 'anexo', 194, NULL, 3, '6.2.2', 'Do lojista do comércio especializado para os destinatários citados nas alíneas “a”, “b” e “c”.', '', 18),
(9880, 'anexo', 194, NULL, 3, '6.2.3', 'Dos órgãos, instituições e pessoas jurídicas citadas nos subitens 6.2.1 e 6.2.2 para o fabricante ou lojista do comércio especializado em devolução, somente pelo serviço de Logística Reversa em Agência.', '', 19),
(9881, 'anexo', 194, NULL, 3, '6.2.4', 'Após o desembaraço alfandegário de produto controlado pelo Exército.', 'Nota: o serviço de importação efetuado pelos Correios será somente de peças de arma de fogo, por pessoas físicas e jurídicas autorizadas pelo Comando da Região Militar.\n6.3 A encomenda deverá ser postada fechada, em embalagem resistente, com total responsabilidade do remetente e sem qualquer indicação externa de conteúdo.\n6.4 É limitada a postagem de 2 (duas) unidades por encomenda, sendo ainda vedada mais de uma postagem no fluxo postal, no mesmo dia.\n6.5 É proibida a Remessa Agrupada.\n6.6 No interior da embalagem deverão constar:', 20),
(9882, 'anexo', 194, 9881, 4, 'a', 'Guia de Tráfego - GT, emitida pelo Exército, ou declaração da fiscalização militar, quando houver exigência específica por parte do Exército;', '', 21),
(9883, 'anexo', 194, 9881, 4, 'b', 'Nota Fiscal - NF ou documento de liberação da alfândega.', '6.7 A postagem de retorno ao fabricante ou comércio especializado somente poderá ser realizada através do serviço de Logística Reversa em Agência.\n6.8 Na etiqueta de endereçamento deverão constar os serviços adicionais de Aviso de Recebimento - AR e Produto Controlado - EE. No caso do serviço adicional EE, não é possível sua solicitação via Logística Reversa em Agência, não sendo possível sua indicação na etiqueta de endereçamento, por isso, ao emitir a Autorização de Postagem, o cliente deverá preencher o campo “Controle do Cliente” com as letras “EE”.\n6.9 Não é permitida a postagem de munições, explosivos, armações e chassis de arma de fogo, produtos químicos de interesse militar e fogos de artificio, entre outros, conforme restrições previstas na Norma Reguladora do Tráfego de Produtos Controlados pelos Correios, constante da Portaria Nº 015-COLOG, de 05 de outubro de 2009, do Comando Logístico do Exército Brasileiro, Capítulo III - Disposições Gerais, Art. 3º.\n6.10 O descumprimento de qualquer exigência implicará na retenção da encomenda e o acionamento da organização do Exército mais próxima, que enviará preposto à nossa unidade para verificação e decisão sobre o destino da remessa, que poderá ser apreendida ou liberada para tramitação normal.', 22),
(9884, 'anexo', 194, NULL, 1, '7', 'MODELO DE GUIA DE TRÁFEGO - GT', '', 23),
(9885, 'anexo', 194, NULL, 1, '8', 'PREÇOS', '8.1 Conforme tabela de preços da modalidade contratada.', 24),
(9886, 'anexo', 194, NULL, 1, '9', 'ENTREGA', '9.1 A entrega interna é realizada em dias úteis, de segunda-feira a sábado, na Agência dos Correios mais próxima do endereço do destinatário.\n9.2 O objeto ficará disponível na agência, para retirada por parte do destinatário, pelo prazo máximo de 7 (sete) dias corridos. Após este prazo o objeto será devolvido imediatamente ao remetente.\n9.3 Quando da chegada do objeto, a agência deverá emitir o Aviso de Chegada ao destinatário da encomenda.\n9.4 A encomenda poderá ser retirada mesmo sem a apresentação do Aviso de Chegada, desde que o próprio destinatário a retire, mediante apresentação de documento de identificação com foto.\n9.5 Quando se tratar de entrega com o serviço adicional de Mão Própria - MP, o destinatário deverá apresentar documento de identificação com foto, mesmo que apresente o Aviso de Chegada.', 25),
(9887, 'anexo', 194, NULL, 1, '10', 'GENERALIDADES', '10.1 As regras não mencionadas neste anexo são as mesmas definidas para o serviço Sedex.\n* * * * *', 26),
(9888, 'anexo', 196, NULL, 1, '1', 'DEFINIÇÃO', '', 0),
(9889, 'anexo', 196, 9888, 2, '1.1', 'Devolução de Documento – DD é o serviço adicional de devolução de canhoto de Nota Fiscal ou documento equivalente, assinados, sem conferência de conteúdo por parte do destinatário, ao remetente.', '', 1),
(9890, 'anexo', 196, NULL, 1, '2', 'PÚBLICO ALVO', '', 2),
(9891, 'anexo', 196, 9890, 2, '2.1', 'Pessoas jurídicas com contrato SEDEX ou PAC.', '', 3),
(9892, 'anexo', 196, NULL, 1, '3', 'MODALIDADES', '', 4),
(9893, 'anexo', 196, 9892, 2, '3.1', 'O serviço possui duas modalidades para retorno do documento:', '', 5),
(9894, 'anexo', 196, 9893, 4, 'a', 'devolução expressa: através do serviço SEDEX;', '', 6),
(9895, 'anexo', 196, 9893, 4, 'b', 'devolução econômica: através do serviço de Carta Registrada.', '', 7),
(9896, 'anexo', 196, NULL, 1, '4', 'CONTRATANTE', '', 8),
(9897, 'anexo', 196, 9896, 2, '4.1', 'A contratante deverá:', '', 9),
(9898, 'anexo', 196, 9897, 4, 'a', 'utilizar o sistema SIGEP fornecido pelos Correios ou sistema próprio de postagem, desde que o leiaute de postagem de seu sistema seja compatível com o do sistema dos Correios;', '', 10),
(9899, 'anexo', 196, 9897, 4, 'b', 'emitir o Rótulo de Endereçamento da encomenda de acordo com o padrão definido pelos Correios;', '', 11),
(9900, 'anexo', 196, 9897, 4, 'c', 'apresentar os dados de postagem do objeto em mídia eletrônica;', '', 12),
(9901, 'anexo', 196, 9897, 4, 'd', 'postar a encomenda acompanhada do envelope que será utilizado na devolução do documento, do canhoto ou da via de Nota Fiscal, o qual deverá ter o leiaute também definido pelos Correios:', 'I -  o envelope a ser utilizado deverá ser, preferencialmente, o do tipo comum, nas seguintes medidas: 114 mm x 162 mm ou 114 mm x 229 mm (Recomendado Pelos Correios – RPC), padronizados segundo as normas da Associação Brasileira de Normas Técnicas – ABNT.', 13),
(9902, 'anexo', 196, NULL, 1, '5', 'POSTAGEM', '', 14),
(9903, 'anexo', 196, 9902, 2, '5.1', 'O serviço será prestado, exclusivamente, se os dados de postagem do objeto forem apresentados de forma eletrônica.', '', 15),
(9904, 'anexo', 196, NULL, 1, '6', 'PREÇOS', '', 16),
(9905, 'anexo', 196, 9904, 2, '6.1', 'Os valores relativos à prestação do serviço encontram-se disponíveis para consulta na tabela de preços do serviço contratado.', '', 17),
(9906, 'anexo', 196, NULL, 1, '7', 'ENTREGA', '', 18),
(9907, 'anexo', 196, 9906, 2, '7.1', 'A entrega da encomenda ocorrerá mediante recibo, com assinatura legível do recebedor no documento, no canhoto ou na via de Nota Fiscal, não estando prevista, exceto em contratos especiais, a conferência do conteúdo por parte do destinatário.', '', 19),
(9908, 'anexo', 196, NULL, 1, '8', 'GENERALIDADES', '', 20),
(9909, 'anexo', 196, 9908, 2, '8.1', 'Os Correios deverão fornecer a contratante o leiaute da Etiqueta de Endereçamento e outros formulários utilizados para o serviço de Devolução de Documento – DD.', '* * * * *', 21),
(9910, 'anexo', 197, NULL, 1, '1', 'O serviço permite a remessa expressa ou não expressa de mercadorias com dimensões superiores às convencionais.', '', 0),
(9911, 'anexo', 197, NULL, 1, '2', 'SERVIÇOS DISPONIVEIS', '', 1),
(9912, 'anexo', 197, 9911, 2, '2.1', 'O GF está disponível para os serviços de encomendas da seguinte forma:', '', 2),
(9913, 'anexo', 197, 9912, 4, 'a', 'SEDEX GF: âmbito nacional, transportado apenas pelo modal terrestre, e nas localidades habilitadas;', '', 3),
(9914, 'anexo', 197, 9912, 4, 'b', 'PAC GF: âmbito estadual e interestadual e nas localidades habilitadas.', '', 4),
(9915, 'anexo', 197, NULL, 1, '3', 'PÚBLICO-ALVO', '', 5),
(9916, 'anexo', 197, 9915, 2, '3.1', 'Pessoas Jurídicas com contrato.', '', 6),
(9917, 'anexo', 197, NULL, 1, '4', 'ABRANGÊNCIA', '', 7),
(9918, 'anexo', 197, 9917, 2, '4.1', 'A área de cobertura do serviço é restrita às localidades atendidas por Centro de Entrega de Encomendas - CEE, e em alguns casos, por Centro de Distribuição Domiciliar - CDD, desde que atestada a viabilidade operacional por parte da Superintendência Estadual - SE.', '', 8),
(9919, 'anexo', 197, 9918, 3, '4.1.1', 'Eventualmente, as localidades que não possuem CEE ou CDD, mas possuem Agências com Distribuição, podem ser incluídas na abrangência do GF, com exceção das Agências Unipessoais. Contudo, há obrigatoriedade de análise de viabilidade por parte das SEs, sobretudo em relação à capacidade de transporte, à infraestrutura das unidades, em termos de espaço físico para recebimento, tratamento, distribuição e eventual guarda de objetos.', '', 9),
(9920, 'anexo', 197, 9917, 2, '4.2', 'As localidades habilitadas para prestar o serviço estão disponíveis para consulta no seguinte endereço: \\\\sac0424\\SISTEMAS\\PRECOS_TARIFAS\\Abrangência de Serviços de Encomendas.', '', 10),
(9921, 'anexo', 197, 9917, 2, '4.3', 'A inclusão de novas localidades ocorre mediante solicitação da SE ao departamento gestor do serviço e parecer favorável da área operacional do Correios Sede - CS.', '', 11),
(9922, 'anexo', 197, 9921, 3, '4.3.1', 'Na solicitação encaminhada deve constar a localidade e sua respectiva faixa de CEP, assim como o parecer favorável da área operacional da SE.', '', 12),
(9923, 'anexo', 197, 9917, 2, '4.4', 'Quando aprovada a demanda de nova localidade para prestação do serviço, é realizada a inclusão para postagem/entrega de SEDEX GF e PAC GF.', '', 13),
(9924, 'anexo', 197, 9923, 3, '4.4.1', 'As unidades dos Correios cujo CEP faça parte da área de cobertura do GF são automaticamente cadastradas para prestar o serviço.', '', 14),
(9925, 'anexo', 197, NULL, 1, '5', 'SERVIÇOS ADICIONAIS', '', 15),
(9926, 'anexo', 197, 9925, 2, '5.1', 'São admitidos os seguintes serviços adicionais:', '', 16),
(9927, 'anexo', 197, 9926, 4, 'a', 'Aviso de Recebimento - AR;', '', 17),
(9928, 'anexo', 197, 9926, 4, 'b', 'Coleta Programada;', '', 18),
(9929, 'anexo', 197, 9926, 4, 'c', 'Devolução de Documentos - DD;', '', 19),
(9930, 'anexo', 197, 9926, 4, 'd', 'Grandes Formatos - GF (obrigatório);', '', 20),
(9931, 'anexo', 197, 9926, 4, 'e', 'Mão Própria - MP;', '', 21),
(9932, 'anexo', 197, 9926, 4, 'f', 'Valor Declarado - VD.', '', 22),
(9933, 'anexo', 197, NULL, 1, '6', 'LIMITES DE DIMENSÕES', '', 23),
(9934, 'anexo', 197, 9933, 2, '6.1', 'A encomenda enquadrada como GF deve possuir as seguintes dimensões:', '', 24),
(9935, 'anexo', 197, 9934, 4, 'a', 'maior dimensão (C ou L ou A): entre 101 cm e 150 cm;', '', 25),
(9936, 'anexo', 197, 9934, 4, 'b', 'soma máxima das dimensões (C + L + A): entre 201 cm e 300 cm.', '', 26),
(9937, 'anexo', 197, NULL, 1, '7', 'POSTAGEM', '', 27),
(9938, 'anexo', 197, 9937, 2, '7.1', 'O cliente deve realizar, obrigatoriamente, a pré-postagem da encomenda via Plataforma de Pré-Postagem Nacional - PPN ou sistema próprio.', '', 28),
(9939, 'anexo', 197, 9937, 2, '7.2', 'A postagem na unidade é realizada conforme regras definidas no MANCAT 16/28.', '', 29),
(9940, 'anexo', 197, 9937, 2, '7.3', 'As unidades de atendimento habilitadas para captação das encomendas são:', 'a) Agências de Correios Franqueadas - AGFs;\nb) Agências de Correios Próprias - ACs;\nc) Correios Empresas - CEMs;\nd) Correios Essencial - CEL;\ne) Correios Modular - CMD;\nf) Correios Móvel - CMV;\ng) Gerências de Atividades de Controle e Captação - GCCAPs;\nh) Lojas de Correios Franqueadas - LCFs.', 30),
(9941, 'anexo', 197, 9940, 3, '7.3.1', 'Para estar habilitada nos sistemas de captação, o CEP da unidade de postagem deve pertencer a área de cobertura do serviço.', '', 31),
(9942, 'anexo', 197, 9937, 2, '7.4', 'Na postagem da encomenda deve ser utilizado o código do serviço contratado:', '', 32),
(9943, 'anexo', 197, 9942, 4, 'a', 'SEDEX GF: 0413-8, 0453-7, 0321-2, 0388-3 ou 0304-2;', '', 33),
(9944, 'anexo', 197, 9942, 4, 'b', 'PAC GF: 0469-3, 0461-8, 0332-8, 0394-8 ou 0310-7.', '', 34),
(9945, 'anexo', 197, 9942, 3, '7.4.1', 'Ao serviço principal contratado é incluído, automaticamente, o código 057, referente ao serviço adicional de GF.', '', 35),
(9946, 'anexo', 197, NULL, 1, '8', 'PREÇOS', '', 36),
(9947, 'anexo', 197, 9946, 2, '8.1', 'O preço do serviço é composto pelo valor do serviço principal contratado (SEDEX ou PAC) somado ao valor do serviço adicional GF.', '', 37),
(9948, 'anexo', 197, NULL, 1, '9', 'PRAZOS DE ENTREGA', '', 38),
(9949, 'anexo', 197, 9948, 2, '9.1', 'O prazo de entrega previsto para o serviço contratado é definido conforme abaixo:', '', 39),
(9950, 'anexo', 197, 9949, 4, 'a', 'SEDEX GF: prazo do serviço SEDEX acrescido de 2 dias úteis;', '', 40),
(9951, 'anexo', 197, 9949, 4, 'b', 'PAC GF: prazo do serviço PAC acrescido de 3 dias úteis.', '', 41),
(9952, 'anexo', 197, NULL, 1, '10', 'ENTREGA DOMICILIAR', '', 42),
(9953, 'anexo', 197, 9952, 2, '10.1', 'A entrega da encomenda é exclusiva em domicilio, não sendo possível a entrega interna.', '', 43),
(9954, 'anexo', 197, 9953, 3, '10.1.1', 'A encomenda é devolvida imediatamente ao remetente quando frustradas todas as tentativas de entrega previstas para o serviço contratado.', '', 44),
(9955, 'anexo', 197, 9952, 2, '10.2', 'Os procedimentos operacionais de entrega das encomendas são os mesmos definidos para o serviço principal contratado, constantes no MANDIS 3.', '', 45),
(9956, 'anexo', 197, NULL, 1, '11', 'GENERALIDADES', '', 46),
(9957, 'anexo', 197, 9956, 2, '11.1', 'As demais regras do SEDEX GF e PAC GF, que não constam neste anexo, são as mesmas definidas para o serviço de encomenda contratado, conforme MANCAT 16/3/2.', '* * * * *', 47),
(9958, 'anexo', 198, NULL, 1, '1', 'FINALIDADE', '', 0),
(9959, 'anexo', 198, 9958, 2, '1.1', 'Estabelecer as regras específicas do produto Transfer LOG.', '', 1),
(9960, 'anexo', 198, NULL, 1, '2', 'DEFINIÇÃO', '', 2),
(9961, 'anexo', 198, 9960, 2, '2.1', 'Transfer LOG consiste no transporte de carga unitizada em formato de palete ou similar ao Container Desmontável Leve - CDL, no fluxo postal regular dos Correios.', '', 3),
(9962, 'anexo', 198, 9960, 2, '2.2', 'O produto possibilita o transporte de mercadorias agrupadas em uma única unidade de carga padronizada, ou seja, reunir diferentes mercadorias em um só volume, dentro das especificações informadas pelos Correios.', '', 4),
(9963, 'anexo', 198, NULL, 1, '3', 'PUBLICO ALVO', '', 5),
(9964, 'anexo', 198, 9963, 2, '3.1', 'Pessoas jurídicas e órgãos públicos com contrato junto aos Correios.', '', 6),
(9965, 'anexo', 198, 9963, 2, '3.2', 'O serviço está disponível para clientes com contrato e será habilitado no contrato após realização de análise de viabilidade comercial, atendidas às exigências da Política Comercial vigente, especialmente no que se refere à contrapartida atual, na qual a revenda de serviços dos Correios não deve constituir a principal atividade do contratante.', '', 7),
(9966, 'anexo', 198, 9963, 2, '3.3', 'O produto pode ser ofertado aos clientes de todos os pacotes comerciais, entretanto a força de vendas só pode disponibilizar aos clientes que estejam em conformidade com os critérios não financeiros estabelecidos para acesso aos pacotes Diamante e Infinite, ou seja, as contrapartidas financeiras estipuladas para acesso aos pacotes permanecem as mesmas, entretanto, é necessário que o cliente esteja em conformidade com os demais critérios.', 'Nota: a análise do subitem 3.3 é necessária para mitigar eventual risco de canibalização do serviço de encomenda ou de desequilíbrio financeiro para os Correios e deve ser realizada enquanto os critérios de acesso aos pacotes Diamante e Infinite estiverem vigentes.', 8),
(9967, 'anexo', 198, 9963, 2, '3.4', 'O produto Transfer Log deverá ser desabilitado do contrato caso seja constatada irregularidade que resulte na diminuição do ticket médio sem um aumento real no volume de carga nova para os Correios.', '', 9),
(9968, 'anexo', 198, NULL, 1, '4', 'ABRANGÊNCIA', '', 10),
(9969, 'anexo', 198, 9968, 2, '4.1', 'Estadual e Nacional.', '4.1.1 O produto não possui âmbito local, pois para estes casos é indicado o uso do portfólio de Coleta dos Correios.', 11),
(9970, 'anexo', 198, NULL, 1, '5', 'MODAIS DE TRANSPORTE E PLATAFORMA DE OPERAÇÃO', '', 12),
(9971, 'anexo', 198, 9970, 2, '5.1', 'O produto pode ser transportado conforme a viabilidade operacional, a título exemplificativo, pelos modais aéreo, terrestre e plataformas operacionais dos produtos PAC e SEDEX.', '', 13),
(9972, 'anexo', 198, NULL, 1, '6', 'PRODUTOS ADICIONAIS', '', 14),
(9973, 'anexo', 198, 9972, 2, '6.1', 'Os produtos adicionais permitidos são:', 'a) Aviso de Recebimento - AR;\nb) Coleta Programada;\nc) Valor Declarado - VD.', 15),
(9974, 'anexo', 198, NULL, 1, '7', 'AD VALOREM, VALOR MÁXIMO DECLARADO E INDENIZAÇÃO', '', 16),
(9975, 'anexo', 198, 9974, 2, '7.1', 'O percentual de Ad Valorem está definido na tabela de preços do produto.', '', 17),
(9976, 'anexo', 198, 9974, 2, '7.2', 'O valor máximo permitido para declaração de valor está definido na tabela de preços do produto e seguirá os reajustes de preços previstos para o segmento de encomendas, estratégias comerciais de relacionamento com o cliente e mercadológica.', '', 18),
(9977, 'anexo', 198, 9974, 2, '7.3', 'O valor de indenização automática está definido na tabela de preços do produto e seguirá os reajustes de preços previstos para o segmento de encomendas, estratégias comerciais de relacionamento com o cliente e mercadológica.', '', 19),
(9978, 'anexo', 198, NULL, 1, '8', 'PRAZOS', '', 20),
(9979, 'anexo', 198, 9978, 2, '8.1', 'Prazo para embarque da carga pelos Correios: D+2.', '', 21),
(9980, 'anexo', 198, 9978, 2, '8.2', 'Prazo ofertado de entrega após a postagem: igual ao prazo do PAC para o respectivo trecho.', '', 22),
(9981, 'anexo', 198, 9978, 2, '8.3', 'O prazo máximo para retirada da carga é de 7 (sete) dias úteis, contabilizados a partir da disponibilidade da carga pela unidade operacional de destino, em dias úteis e respectivo horário de atendimento ao público.', '', 23),
(9982, 'anexo', 198, 9981, 3, '8.3.1', 'Após o prazo máximo para retirada da carga, a unidade operacional providenciará os lançamentos no sistema e as atividades inerentes à devolução da carga à origem, de forma similar ao que ocorre com os objetos de encomenda.', '', 24),
(9983, 'anexo', 198, 9981, 3, '8.3.2', 'Caso o cliente não retire a carga após o prazo estipulado e, por consequência, ocorra a devolução da carga à origem, será cobrado o mesmo valor (R$) de postagem da carga.', 'Nota: o Sistema de Proteção de Receita Nacional (SPN) - PROTER está parametrizado para identificar as cargas postadas com o código do produto (ERP), somando os eventos de devolução do objeto contidos no Sistema de Rastreamento do Objeto Postal - SRO e providenciar o lançamento da cobrança na fatura do cliente.', 25),
(9984, 'anexo', 198, 9981, 3, '8.3.3', 'Não há indenização por atraso ou nenhum tipo de ressarcimento ao remente/destinatário, em razão da devolução da carga não retirada no prazo previsto.', '', 26),
(9985, 'anexo', 198, 9981, 3, '8.3.4', 'A carga em devolução terá o prazo máximo para retirada de 7 (sete) dias úteis.', '8.3.4.1 Após este prazo, a unidade operacional de destino classificará a carga como refugo e irá providenciar os tramites previstos no MANDIS 9/3.', 27),
(9986, 'anexo', 198, NULL, 1, '9', 'NÍVEL DE SERVIÇO - NS', '', 28),
(9987, 'anexo', 198, 9986, 2, '9.1', 'É a solução utilizada para supervisionar a execução do percentual de entrega da carga dentro do prazo, acordada entre os Correios e os clientes de contrato.', '', 29),
(9988, 'anexo', 198, 9987, 3, '9.1.1', 'O produto seguirá as regras de nível de serviço estabelecidas para o segmento de encomenda e produto.', '', 30),
(9989, 'anexo', 198, NULL, 1, '10', 'UNIDADES DE POSTAGEM E DESTINO', '', 31),
(9990, 'anexo', 198, 9989, 2, '10.1', 'Considerando as dimensões e o peso estabelecidos para o produto, as unidades de postagem são: Centros de Logística Integrada - CLI, Gerência de Controle e Capitação de Postagens - GCCAP e Unidade Correios Empresa - CEM.', 'Nota: as postagens realizadas pelos CLIs são destinadas aos clientes que possuem estoque junto aos Correios (ex.: Correios Log+ e Correios Log Supri) e necessitam realizar a transferência de carga entre as unidades.', 32),
(9991, 'anexo', 198, 9989, 2, '10.2', 'As unidades de destino são: Centros de Logística Integrada - CLI e centros de tratamentos.', '', 33),
(9992, 'anexo', 198, 9989, 2, '10.3', 'O cliente deverá realizar a retirada da carga na unidade operacional.', '', 34),
(9993, 'anexo', 198, 9992, 3, '10.3.1', 'Os clientes que possuírem operações de Correios Log+ e/ou Correios Log Supri e enviarem a carga aos CLIs (estoques iniciais, reposição e transferência) poderão solicitar a incorporação dos produtos enviados aos respectivos estoques.', '', 35),
(9994, 'anexo', 198, NULL, 1, '11', 'POSTAGEM', '', 36),
(9995, 'anexo', 198, 9994, 2, '11.1', 'A carga unitizada deverá ser obrigatoriamente pré-postada, rotulada, endereçada e identificada como um único volume, igualmente aos produtos de encomenda (ex.: PAC e SEDEX).', '', 37),
(9996, 'anexo', 198, 9994, 2, '11.2', 'A carga deverá ser apresentada com rótulos de endereçamento em concordância com o regulamento interno dos Correios e a legislação pertinente, preenchidos de forma correta e completa.', '', 38),
(9997, 'anexo', 198, NULL, 1, '12', 'LIMITES DE DIMENSÕES, PESO E ACONDICIONAMENTO', '', 39),
(9998, 'anexo', 198, 9997, 2, '12.1', 'A carga deve ser apresentada, preferencialmente, em formato de palete ou CDL, em conformidade com as características e limites descritos a seguir:', '', 40),
(9999, 'anexo', 198, 9998, 4, 'a', 'dimensões máximas da carga unitizada: 1,20m (comprimento) x 1,10m (altura) x 1,00m (largura). Soma das dimensões (C + A + L): 3,30m;', '', 41),
(10000, 'anexo', 198, 9998, 4, 'b', 'peso máximo: até 350kg;', '', 42),
(10001, 'anexo', 198, 9998, 4, 'c', 'quando a carga unitizada estiver em formato de paletes, estes deverão apresentar a tábua inferior na maior dimensão, suportar o peso dos itens acondicionados, sem apresentar deformação/ruptura, prover acesso pelos quatro lados, para uso de empilhadeiras, e envoltos por filme de polietileno esticável (stretch);', '', 43),
(10002, 'anexo', 198, 9998, 4, 'd', 'para fins de controle quantitativo e faturamento, estas especificações denominam o volume unitário e estabelecem o conceito de “posições-palete”.', '', 44),
(10003, 'anexo', 198, 9997, 2, '12.2', 'Em casos excepcionais e desde que não haja aumento de recursos para a execução do produto, a Superintendência Estadual - SE e o Departamento de Vendas - DEVEN poderão negociar e autorizar o transporte do palete ou CDL excepcional, garantindo as viabilidades operacionais e comerciais necessárias para cada situação, sem incremento de recursos para a execução do produto.', 'Nota: a excepcionalidade mencionada deverá ser fundamentada pela SE e/ou DEVEN em fatores estratégicos, tais como: manutenção de uma boa relação comercial, a preservação da receita dos Correios, a otimização de recursos, a redução de custos e o foco no cliente. Não poderá ocorrer incremento de recursos para a execução do produto.', 45),
(10004, 'anexo', 198, NULL, 1, '13', 'FATURAMENTO', '', 46);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(10005, 'anexo', 198, 10004, 2, '13.1', 'O produto é faturado como volume unitário (palete/CDL), considerando a origem e o destino da carga.', '', 47),
(10006, 'anexo', 198, 10004, 2, '13.2', 'Os casos excepcionais deverão ser avaliados pela SE, desde que haja viabilidade operacional para manuseio e transporte sem incremento de recursos, a carga apresentada em desconformidade com as especificações de dimensão e acondicionamento deste manual poderá ser faturada conforme a quantidade de posições-palete ocupadas.', '', 48),
(10007, 'anexo', 198, 10004, 2, '13.3', 'As tabelas de preço do produto ficarão em repositório definido pelo Departamento competente, para acesso e respectivas consultas.', '', 49),
(10008, 'anexo', 198, 10004, 2, '13.4', 'O processo de faturamento dar-se-á em conformidade com as regras estabelecidas para clientes a faturar.', '', 50),
(10009, 'anexo', 198, NULL, 1, '14', 'DOCUMENTAÇÃO', '', 51),
(10010, 'anexo', 198, 10009, 2, '14.1', 'A carga deverá ser acompanhada da respectiva nota fiscal ou Formulário de Declaração de Conteúdo, conforme a classificação do cliente junto ao órgão de fiscalização tributária.', '', 52),
(10011, 'anexo', 198, 10009, 2, '14.2', 'O documento fiscal deverá ser afixado na parte externa da carga unitizada, para que seja possível o procedimento da fiscalização tributária, reduzindo a possibilidade de abertura do palete/CDL.', '', 53),
(10012, 'anexo', 198, 10009, 2, '14.3', 'Quando a solicitação for para transferência de carga entre CLIs dos Correios, deverão ser observadas as regras descritas neste manual.', '', 54),
(10013, 'anexo', 198, NULL, 1, '15', 'TRANSFERÊNCIA DE CARGA ENTRE CENTROS DE LOGÍSTICA INTEGRADOS - CLI', '', 55),
(10014, 'anexo', 198, 10013, 2, '15.1', 'O cliente deverá solicitar a retirada da carga no CLI por meio de um pedido de retirada com o código de distribuição do serviço Transfer Log (essa etapa será faturada como etapa do serviço Correios Log+ e/ou Correios Log Supri).', '', 56),
(10015, 'anexo', 198, 10013, 2, '15.2', 'O CLI preparará a carga e realizará os procedimentos de postagem.', '', 57),
(10016, 'anexo', 198, 10013, 2, '15.3', 'O CLI afixará o código de registro nos objetos, conforme modelo padrão dos Correios, para fins de viabilizar o rastreamento total do processo (da postagem até a entrega) através do Sistema de Rastreamento de Objetos - SRO.', '', 58),
(10017, 'anexo', 198, 10013, 2, '15.4', 'O CLI de origem endereçará a carga para o CLI de destino que operacionalize os serviços Correios Log+ e/ou Correios Log Supri.', '', 59),
(10018, 'anexo', 198, 10013, 2, '15.5', 'O CLI acondicionará os objetos em unitizador adequado, observando as dimensões máximas, peso e acondicionamento estipulados para o produto.', '', 60),
(10019, 'anexo', 198, 10013, 2, '15.6', 'O CLI disponibilizará a Nota Fiscal - NF do conteúdo junto ao unitizador (CDL/palete) e a NF-e de transferência - documento fiscal para a movimentação de mercadorias entre empresas sob a mesma titularidade.', '', 61),
(10020, 'anexo', 198, 10019, 3, '15.6.1', 'As notas fiscais a serem emitidas na operação de transferência de objetos de cliente que se encontram depositados no CLI dos Correios, são:', '', 62),
(10021, 'anexo', 198, 10020, 4, 'a', 'emissão de nota fiscal pelo cliente para o cliente (filial de outra UF) para registro da transferência (indicação nas informações complementares como local de entrega os dados do armazém de destino);', '', 63),
(10022, 'anexo', 198, 10020, 4, 'b', 'emissão de nota fiscal pelo armazém de origem da carga para o cliente, para registro do retorno simbólico de mercadoria depositada em armazém geral (indicação nas informações complementares da Nota Fiscal de transferência emitida pelo cliente);', '', 64),
(10023, 'anexo', 198, 10020, 4, 'c', 'emissão de nota fiscal pelo cliente (filial de outra UF) para o armazém de destino, para registro da remessa simbólica de mercadoria depositada em armazém geral.', '', 65),
(10024, 'anexo', 198, 10019, 3, '15.6.2', 'Detalhamento do fluxo fiscal:', '', 66),
(10025, 'anexo', 198, 10024, 4, 'a', 'CFOP 5.905: remessa para depósito em armazém geral, emitida pelo cliente para o armazém;', '', 67),
(10026, 'anexo', 198, 10024, 4, 'b', 'CFOP 5.907: retorno simbólico de mercadoria depositada em armazém geral, emitida pelo armazém para o cliente;', '', 68),
(10027, 'anexo', 198, 10024, 4, 'c', 'CFOP 6.155: transferência de produção do estabelecimento, que não deve por ele transitar (classificam-se neste código as transferências para outro estabelecimento da mesma empresa de produtos industrializados no estabelecimento, que tenham sido remetidos para o armazém geral, depósito fechado ou outro, sem que haja retorno ao estabelecimento depositante);', '', 69),
(10028, 'anexo', 198, 10024, 4, 'd', 'CFOP 6.156: transferência de mercadoria adquirida ou recebida de terceiros, que não deve por ele transitar (classificam-se neste código as transferências para outro estabelecimento da mesma empresa de mercadorias adquiridas ou recebidas de terceiros para industrialização ou comercialização, que não tenham sido objeto de qualquer processo industrial, remetidas para armazém geral, depósito fechado ou outro, sem que haja retorno ao estabelecimento depositante);', '', 70),
(10029, 'anexo', 198, 10024, 4, 'e', 'CFOP 5.934: remessa simbólica de mercadoria depositada em armazém geral, emitida pelo cliente na filial da outra UF para o armazém geral.', '', 71),
(10030, 'anexo', 198, NULL, 1, '16', 'APROVEITAMENTO DAS CAPACIDADES DISPONÍVEIS DAS LINHAS DE TRANSPORTE DO FLUXO POSTAL PARA PROMOÇÃO DE ESTRATÉGIAS COMERCIAIS', '', 72),
(10031, 'anexo', 198, 10030, 2, '16.1', 'O presente produto pode se beneficiar do aproveitamento das capacidades disponíveis das linhas de transporte do fluxo postal para promoção de estratégias comerciais.', '', 73),
(10032, 'anexo', 198, 10030, 2, '16.2', 'O órgão gestor do produto deverá consultar a área de operações quanto à existência de disponibilidade de espaços nas linhas de transporte convencionais do fluxo postal, em especial a disponibilidade de posições paletes nas linhas de transporte de retorno.', '', 74),
(10033, 'anexo', 198, 10032, 3, '16.2.1', 'A linha de transporte de retorno refere-se ao uso de veículos e aeronaves (dentre outros) que retornam com capacidade disponível, após a entrega, ao ponto de origem ou outro destino.', '', 75),
(10034, 'anexo', 198, 10032, 3, '16.2.2', 'Os possíveis benefícios de utilizar essas linhas incluem a redução de custos operacionais, pois maximiza a utilização dos veículos, aumenta a eficiência logística, aproveita melhor os recursos disponíveis e melhora a gestão de tempo e espaço.', '', 76),
(10035, 'anexo', 198, 10030, 2, '16.3', 'Para aplicação de estratégia comercial diferenciada serão consideradas as linhas que historicamente possuem dados estatísticos de disponibilidade igual ou superior a:', 'a) 65% de disponibilidade para os casos de linhas de transporte terrestres, ou seja, cujo indicador OLTN < 35%;\nb) 40% de disponibilidade para os casos de linha de transporte aéreo, ou seja, cujo indicador ORPN < 60%.', 77),
(10036, 'anexo', 198, 10030, 2, '16.4', 'A implantação de estratégias comerciais, como por exemplo de preços promocionais, seguirá o mesmo calendário definido para o ciclo de ajustes de prazos (MANNEG 6/3/2), excluindo apenas o último ciclo:', '', 78),
(10037, 'anexo', 198, 10036, 4, 'a', 'primeiro dia útil do mês de janeiro;', '', 79),
(10038, 'anexo', 198, 10036, 4, 'b', 'primeiro dia útil do mês de abril;', '', 80),
(10039, 'anexo', 198, 10036, 4, 'c', 'primeiro dia útil do mês de julho.', '', 81),
(10040, 'anexo', 198, NULL, 1, '17', 'CANAIS DE PÓS-VENDA, RECLAMAÇÕES E INDENIZAÇÕES', '', 82),
(10041, 'anexo', 198, 10040, 2, '17.1', 'Os canais de pós-venda, reclamações, solicitações de indenização e respectivos processos são os mesmos estabelecidos para objeto registrado nacional.', '', 83),
(10042, 'anexo', 198, 10040, 2, '17.2', 'Os valores devidos pelos Correios em caso de indenização deverão ser compensados por meio de crédito em fatura.', '', 84),
(10043, 'anexo', 198, NULL, 1, '18', 'GENERALIDADES', '', 85),
(10044, 'anexo', 198, 10043, 2, '18.1', 'Aplicar-se-á subsidiariamente as regras gerais de encomendas nacionais (MANCAT 16/3/2), para as demais regras do produto que não constam neste anexo.', '', 86),
(10045, 'anexo', 198, 10043, 2, '18.2', 'Não será aplicado ao produto cobrança adicional de manuseio especial por formato ou dimensão, em face da finalidade do produto no transporte de carga unitizada.', '', 87),
(10046, 'anexo', 198, 10043, 2, '18.3', 'O processo de rastreamento da carga é o mesmo dos produtos de encomendas (ex.: PAC e SEDEX), realizado pelo Sistema de Rastreamento de Objetos - SRO dos Correios.', '* * * * *', 88),
(10047, 'anexo', 199, NULL, 1, '1', 'A remessa de plantas e suas partes pode ser realizada por meio dos serviços SEDEX, SEDEX Hoje, SEDEX 10 e SEDEX 12.', '', 0),
(10048, 'anexo', 199, NULL, 1, '2', 'A remessa de sementes pode ser realizada por meio dos serviços SEDEX, SEDEX Hoje, SEDEX 10, SEDEX 12, PAC e Correios Mini Envios.', '', 1),
(10049, 'anexo', 199, NULL, 1, '3', 'PÚBLICO-ALVO', '', 2),
(10050, 'anexo', 199, 10049, 2, '3.1', 'Pessoas físicas sem contrato e pessoas jurídicas com e sem contrato e atuação no mercado em foco.', '', 3),
(10051, 'anexo', 199, NULL, 1, '4', 'SERVIÇOS ADICIONAIS', '', 4),
(10052, 'anexo', 199, 10051, 2, '4.1', 'Os serviços adicionais estão disponíveis conforme o serviço de encomenda contratado e podem ser consultados no MANCAT 16/3/2.', '', 5),
(10053, 'anexo', 199, NULL, 1, '5', 'EMBALAGEM E ACONDICIONAMENTO', '', 6),
(10054, 'anexo', 199, 10053, 2, '5.1', 'O cliente deve garantir a correta preparação dos volumes, de modo que cheguem ao destino em boas condições e que, durante o transporte, não apresentem risco para pessoas, animais, equipamentos e outros objetos postais.', '', 7),
(10055, 'anexo', 199, 10053, 2, '5.2', 'Para encomenda contendo sementes, estas devem estar acondicionadas em uma embalagem primária inviolada, identificada e original do produtor ou do reembalador, além de uma embalagem secundária resistente, que suporte o transporte e preserve as condições necessárias de proteção, evitando vazamentos e danos a outros objetos do fluxo postal.', '', 8),
(10056, 'anexo', 199, 10053, 2, '5.3', 'Para encomenda contendo plantas, é obrigatório o correto acondicionamento e a embalagem adequada, de acordo com o material a ser enviado, capaz de proteger o conteúdo e prevenir qualquer vazamento.', 'Exemplos:', 9),
(10057, 'anexo', 199, 10056, 3, '5.3.1', 'Vasos e demais recipientes devem ser enviados sem água e o solo deve estar devidamente coberto, para evitar derramamento durante o transporte.', '', 10),
(10058, 'anexo', 199, 10053, 2, '5.4', 'Plantas e sementes devem ser embaladas de forma a suportar o prazo máximo previsto de entrega e resistir a variações de temperatura, especialmente o calor excessivo, umidade e pressão.', '', 11),
(10059, 'anexo', 199, 10053, 2, '5.5', 'Para o adequado tratamento e transporte de plantas é recomendável a inserção de todas as etiquetas sinalizadoras que o cliente julgar como necessárias, em pelo menos duas faces da embalagem, e o rótulo de endereçamento deve ser afixado na parte superior da caixa.', 'Exemplos:', 12),
(10060, 'anexo', 199, 10053, 2, '5.6', 'Na remessa de plantas, o remetente deve apor na embalagem, abaixo da identificação do destinatário, a seguinte instrução:', '', 13),
(10061, 'anexo', 199, 10053, 2, '5.7', 'O remetente do objeto é o responsável por cumprir todas as exigências legais, nos âmbitos municipal, estadual e federal, relacionadas ao transporte de plantas e sementes.', '', 14),
(10062, 'anexo', 199, 10053, 2, '5.8', 'Os documentos obrigatórios para o transporte devem ser afixados externamente à embalagem, protegidos por envoltório plástico, de forma que fiquem acessíveis para os agentes fiscalizadores.', '', 15),
(10063, 'anexo', 199, NULL, 1, '6', 'DOCUMENTAÇÃO', '', 16),
(10064, 'anexo', 199, 10063, 2, '6.1', 'Para transportar sementes, plantas e suas partes, a seguinte documentação deve acompanhar a remessa:', '', 17),
(10065, 'anexo', 199, 10064, 4, 'a', 'Registro Nacional de Sementes e Mudas - Renasem do remetente, salvo exceções previstas;', 'Nota: o Renasem serve para registrar e habilitar pessoas físicas e jurídicas que atuam na produção, no beneficiamento, no comércio e em outras atividades relacionadas a sementes e mudas, assegurando a conformidade legal e o controle de qualidade desses materiais em todo o território brasileiro.', 18),
(10066, 'anexo', 199, 10064, 4, 'b', 'nota fiscal ou declaração de conteúdo, conforme MANCAT 16/3/2;', '', 19),
(10067, 'anexo', 199, 10064, 4, 'c', 'Permissão de Trânsito Vegetal - PTV, apenas quando do transporte interestadual, conforme exigências regulamentares.', 'Nota: a PTV serve como documento oficial que acompanha a movimentação de plantas, mudas, sementes e outros produtos de origem vegetal, atestando que a partida atende às normas de defesa sanitária vegetal do Brasil.', 20),
(10068, 'anexo', 199, 10063, 2, '6.2', 'Para transportar material de propagação, a seguinte documentação deve acompanhar a remessa:', '', 21),
(10069, 'anexo', 199, 10068, 4, 'a', 'Renasem do remetente, salvo exceções previstas;', '', 22),
(10070, 'anexo', 199, 10068, 4, 'b', 'nota fiscal, conforme MANCAT 16/3/2;', '', 23),
(10071, 'anexo', 199, 10068, 4, 'c', 'atestado de origem genética, certificado de sementes e mudas ou termo de conformidade, conforme o caso;', 'Nota 1: o atestado de origem genética serve para garantir a identidade e a qualidade do material genético, assegurando que o produto seja da cultivar correta, livre de contaminantes e isento de pragas e doenças.\nNota 2: o certificado de sementes e mudas serve para garantir a qualidade, a rastreabilidade e a identidade genética de um lote, assegurando que o material cumpre os padrões estabelecidos pelo Ministério da Agricultura e Pecuária - Mapa para o mercado.\nNota 3: o termo de conformidade serve para atestar que os lotes de sementes ou mudas foram produzidos em conformidade com a legislação, garantindo sua qualidade e identidade para o comércio e utilização.', 24),
(10072, 'anexo', 199, 10068, 4, 'd', 'termo aditivo, se houver;', 'Nota: o documento serve para registrar a origem, a qualidade e a segurança do material de propagação, assegurando que ele atende aos padrões estabelecidos.', 25),
(10073, 'anexo', 199, 10068, 4, 'e', 'PTV, apenas quando do transporte interestadual, conforme exigências regulamentares.', 'Nota: as consultas das exigências de documentação e regulamentação podem ser realizadas no site https://sistemasweb.agricultura.gov.br/cefiti/', 26),
(10074, 'anexo', 199, 10063, 2, '6.3', 'Para transportar produtos de origem florestal, a encomenda também deve estar acompanhada do Documento de Origem Florestal - DOF, salvo nos casos dispensados por lei.', 'Nota 1: o DOF serve como licença eletrônica obrigatória, controlando o transporte e armazenamento de produtos florestais de origem nativa (como madeira e carvão vegetal) no Brasil, contendo informações sobre a sua procedência, destino e tipo de material.\nNota 2: as consultas de produtos que possuem exigência de DOF podem ser realizadas no site: https://www.gov.br/ibama/pt-br/assuntos/biodiversidade/flora-e-madeira/documento-de-origem-florestal-dof', 27),
(10075, 'anexo', 199, 10074, 3, '6.3.1', 'Conforme previsto no § 5º do art. 36 da Lei nº 12.651/2012 e no art. 49 da Instrução Normativa Ibama nº 21/2014, estão fora do escopo do controle de fluxo florestal e, portanto, dispensados da emissão de DOF para transporte, salvo legislação mais restritiva no âmbito estadual ou municipal, os seguintes casos:', '', 28),
(10076, 'anexo', 199, 10075, 4, 'a', 'material lenhoso proveniente de erradicação de culturas, pomares ou poda de arborização urbana;', '', 29),
(10077, 'anexo', 199, 10075, 4, 'b', 'produtos que, por sua natureza, já se apresentam acabados, embalados, manufaturados e para consumo final, tais como: porta almofadada ou compensada, janela, móveis, pisos compostos industrializados, cabos de madeira para diversos fins e caixas, chapas aglomeradas, prensadas, compensadas e de fibras, ou outros objetos similares com denominações regionais;', '', 30),
(10078, 'anexo', 199, 10075, 4, 'c', 'celulose, goma-resina e demais pastas de madeira;', '', 31),
(10079, 'anexo', 199, 10075, 4, 'd', 'serragem, paletes e briquetes de madeira, folhas de essências plantadas, folhas, palhas e fibras de palmáceas, casca e carvão produzido da casca de coco, moinha e briquetes de carvão vegetal, madeira usada em geral e reaproveitamento de madeira de cercas, currais e casas, exceto de espécies constantes dos anexos da convenção sobre o Comércio Internacional das Espécies da Flora e Fauna Selvagens em Perigo de Extinção - Cites;', '', 32),
(10080, 'anexo', 199, 10075, 4, 'e', 'carvão vegetal empacotado, exceto na fase de saída do local da exploração florestal e/ou produção;', '', 33),
(10081, 'anexo', 199, 10075, 4, 'f', 'bambu (bambusa vulgaris) e espécies afins;', '', 34),
(10082, 'anexo', 199, 10075, 4, 'g', 'vegetação arbustiva de origem plantada para qualquer finalidade;', '', 35),
(10083, 'anexo', 199, 10075, 4, 'h', 'plantas vivas coletadas na natureza e óleos essenciais da flora nativa brasileira não constantes em lista federal de espécies ameaçadas de extinção e nem nos anexos da Cites, bem como demais produtos florestais não madeireiros;', '', 36),
(10084, 'anexo', 199, 10075, 4, 'i', 'exsicata para pesquisa científica.', '', 37),
(10085, 'anexo', 199, 10063, 2, '6.4', 'A inscrição no Renasem é obrigatória para todas as pessoas físicas ou jurídicas que exercem as atividades de produção, beneficiamento, reembalagem, armazenamento, análise ou comércio de sementes ou mudas e as atividades de responsabilidade técnica, certificação, amostragem, coleta ou análise de sementes ou mudas, previstas na Lei nº 10.711/2003, no Decreto nº 10.586/2020 e em norma complementar.', '', 38),
(10086, 'anexo', 199, 10085, 3, '6.4.1', 'Os casos que se enquadram para isenção de inscrição no Renasem estão previstos no § 1º, art. 4º do Decreto nº 10.586/2020 e nos § 2º e § 3º, art. 8º da Lei nº 10.711/2003.', '', 39),
(10087, 'anexo', 199, 10063, 2, '6.5', 'A consulta ao Renasem está disponível no site do Mapa, por meio do link: https://sistemasweb.agricultura.gov.br/renasem/', 'Exemplo:', 40),
(10088, 'anexo', 199, 10063, 2, '6.6', 'Cliente com contrato pode informar o número do Renasem na Nota Fiscal que acompanha a encomenda, no campo “Informações Complementares”, estando isento de apresentar o respectivo documento em apartado, nos casos de obrigatoriedade previstos em legislações.', '', 41),
(10089, 'anexo', 199, 10063, 2, '6.7', 'Os Correios não possuem competência técnica para avaliar se um determinado cliente se enquadra nos casos previstos de isenção do Renasem, conforme regulamentos vigentes. Cabe ao cliente assegurar e indicar que está isento da referida obrigação, apontando o seu enquadramento na legislação aplicável, tendo em vista que o Mapa não emite documento específico de isenção.', 'Exemplo: pessoa jurídica que vende, exclusivamente, sementes destinadas ao uso doméstico. Enquadramento de isenção: Decreto nº 10.586/2020, art. 4º, § 1º, III.', 42),
(10090, 'anexo', 199, 10089, 3, '6.7.1', 'O cliente deve informar, o seu respectivo enquadramento de isenção, na Nota Fiscal que acompanha a encomenda, no campo “Informações Complementares”, ou no Formulário Declaração de Conteúdo, no campo “Conteúdo”.', 'Exemplo: isenção Renasem - Decreto nº 10.586/2020, art. 4º, § 1º, III.', 43),
(10091, 'anexo', 199, 10063, 2, '6.8', 'O cliente é o único responsável por providenciar a documentação obrigatória completa e correta que acompanha a remessa.', '', 44),
(10092, 'anexo', 199, 10091, 3, '6.8.1', 'Em caso de omissão ou de informações incorretas, em desacordo com as disposições legais vigentes, os Correios não se responsabilizam pela retenção e/ou apreensão da encomenda por parte dos agentes fiscalizadores.', '', 45),
(10093, 'anexo', 199, NULL, 1, '7', 'PREÇOS', '', 46),
(10094, 'anexo', 199, 10093, 2, '7.1', 'Conforme tabela de preços do serviço de encomenda contratado.', '', 47),
(10095, 'anexo', 199, NULL, 1, '8', 'POSTAGEM', '', 48),
(10096, 'anexo', 199, 10095, 2, '8.1', 'Podem ser enviados os seguintes materiais: mudas, galhos, estacas, bacelos, frutos, sementes, raízes, tubérculos, bulbos, rizomas, folhas, flores, dentre outros da mesma natureza.', '', 49),
(10097, 'anexo', 199, 10095, 2, '8.2', 'Na postagem de qualquer encomenda deve ser vinculado o código de serviço adicional específico para o produto, para fins de controles internos e/ou externos dos órgãos reguladores competentes:', '', 50),
(10098, 'anexo', 199, 10097, 4, 'a', 'remessa de plantas: código 043;', '', 51),
(10099, 'anexo', 199, 10097, 4, 'b', 'remessa de sementes: código 071.', '', 52),
(10100, 'anexo', 199, 10095, 2, '8.3', 'Não são aceitas as seguintes postagens:', '', 53),
(10101, 'anexo', 199, 10100, 4, 'a', 'plantas destinadas às localidades que não realizam entrega domiciliar;', '', 54),
(10102, 'anexo', 199, 10100, 4, 'b', 'plantas destinadas à qualquer forma de entrega interna;', '', 55),
(10103, 'anexo', 199, 10100, 4, 'c', 'itens que constam na Lista Oficial de Espécies da Flora Brasileira Ameaçadas de Extinção, publicada pelo Ministério do Meio Ambiente e Mudança do Clima, por meio da Portaria MMA nº 443, de 17 de dezembro de 2014;', '', 56),
(10104, 'anexo', 199, 10100, 4, 'd', 'sementes classificadas como nocivas e proibidas, conforme Instrução Normativa Mapa nº 46, de 24 de setembro de 2013.', '', 57),
(10105, 'anexo', 199, 10100, 3, '8.3.1', 'Não há restrições para a entrega interna de encomenda contendo sementes, o objeto segue o fluxo previsto para o serviço contratado.', '', 58),
(10106, 'anexo', 199, 10095, 2, '8.4', 'Os Correios se reservam ao direito de recusar a postagem de qualquer encomenda que não esteja adequadamente embalada, etiquetada e acompanhada da documentação necessária para o transporte.', '', 59),
(10107, 'anexo', 199, NULL, 1, '9', 'PRAZO DE ENTREGA', '', 60),
(10108, 'anexo', 199, 10107, 2, '9.1', 'O remetente deve verificar se o prazo de entrega previsto para o serviço contratado atende suas necessidades, no que diz respeito à conservação e integridade do item transportado.', '', 61),
(10109, 'anexo', 199, NULL, 1, '10', 'ENTREGA', '', 62),
(10110, 'anexo', 199, 10109, 2, '10.1', 'A encomenda contendo plantas é devolvida imediatamente ao remetente, após frustradas todas as tentativas de entrega previstas para o serviço contratado.', '', 63),
(10111, 'anexo', 199, 10110, 3, '10.1.1', 'Não há previsão de nenhum tipo de entrega interna, apenas em domicílio.', '', 64),
(10112, 'anexo', 199, 10109, 2, '10.2', 'A encomenda contendo sementes segue os procedimentos convencionais de entrega previstos para o serviço contratado, inclusive de entrega interna.', '', 65),
(10113, 'anexo', 199, NULL, 1, '11', 'GENERALIDADES', '', 66),
(10114, 'anexo', 199, 10113, 2, '11.1', 'Os regulamentos aplicáveis para as remessas de plantas e sementes são:', '', 67),
(10115, 'anexo', 199, 10114, 4, 'a', 'Decreto nº 12.464/2025: dispõe sobre a prestação de serviços postais e de telegrama no território nacional e para o exterior;', '', 68),
(10116, 'anexo', 199, 10114, 4, 'b', 'Lei nº 10.711/2003: dispõe sobre o Sistema Nacional de Sementes e Mudas e dá outras providências;', '', 69),
(10117, 'anexo', 199, 10114, 4, 'c', 'Decreto nº 10.586/2020: regulamenta a Lei nº 10.711, de 5 de agosto de 2003, que dispõe sobre o Sistema Nacional de Sementes e Mudas;', '', 70),
(10118, 'anexo', 199, 10114, 4, 'd', 'Lei nº 12.651/2012: dispõe sobre a proteção da vegetação nativa e dá outras providências;', '', 71),
(10119, 'anexo', 199, 10114, 4, 'e', 'Instrução Normativa Ibama nº 21/2014: institui o Sistema Nacional de Controle da Origem dos Produtos Florestais - Sinaflor;', '', 72),
(10120, 'anexo', 199, 10114, 4, 'f', 'Instrução Normativa Ibama nº 9/2016: altera a Instrução Normativa nº 21, de 24 de dezembro de 2014;', '', 73),
(10121, 'anexo', 199, 10114, 4, 'g', 'Instrução Normativa Mapa nº 17/2017: regulamenta a produção, comercialização e utilização de sementes e mudas de espécies florestais ou de interesse ambiental ou medicinal, nativas e exóticas, visando garantir sua procedência, identidade e qualidade;', '', 74),
(10122, 'anexo', 199, 10114, 4, 'h', 'Instrução Normativa Mapa nº 46/2013: estabelece a relação de espécies de sementes nocivas toleradas e proibidas na produção, na comercialização e no transporte;', '', 75),
(10123, 'anexo', 199, 10114, 4, 'i', 'Instrução Normativa Mapa nº 28/2016: aprova a norma técnica para a utilização da PTV;', '', 76),
(10124, 'anexo', 199, 10114, 4, 'j', 'Portaria MMA nº 443/2014: reconhece como espécies da flora brasileira ameaçadas de extinção aquelas constantes da Lista Nacional Oficial de Espécies da Flora Ameaçadas de Extinção.', 'Nota: a legislação específica de sementes e mudas pode ser consultada no site do Mapa.', 77),
(10125, 'anexo', 199, 10113, 2, '11.2', 'As demais regras para as remessas de encomendas nacionais, não especificadas neste anexo, estão disponíveis para consulta no MANCAT 16/3/2.', '* * * * *', 78),
(10126, 'anexo', 201, NULL, 1, '1', 'LOGÍSTICA REVERSA', '', 0),
(10127, 'anexo', 201, 10126, 2, '1.1', 'Objetivo', '', 1),
(10128, 'anexo', 201, 10127, 3, '1.1.1', 'O atendimento à demanda de postagem autorizada pelo destinatário para o retorno de encomenda, podendo haver, simultaneamente, entrega de outra encomenda ao remetente, no momento da postagem ou da coleta.', '', 2),
(10129, 'anexo', 201, 10126, 2, '1.2', 'Modalidades da Logística Reversa:', '', 3),
(10130, 'anexo', 201, 10129, 4, 'a', 'Logística Reversa em Agência - LRA: quando a postagem da encomenda em devolução é realizada pelo consumidor na rede de agência, mediante apresentação do código de autorização de postagem (e-ticket);', '', 4),
(10131, 'anexo', 201, 10129, 4, 'b', 'Logística Reversa Domiciliar - LRD: quando a encomenda em devolução é coletada no endereço indicado pelo autorizador da coleta;', '', 5),
(10132, 'anexo', 201, 10129, 4, 'c', 'Logística Reversa Simultânea em Agência - LRSA: quando a postagem da encomenda em devolução é realizada simultaneamente à entrega de uma encomenda substituta em uma agência;', '', 6),
(10133, 'anexo', 201, 10129, 4, 'd', 'Logística Reversa Simultânea Domiciliar - LRSD: quando a coleta da encomenda em devolução é realizada simultaneamente à entrega de uma encomenda substituta no endereço indicado pelo autorizador da coleta.', '', 7),
(10134, 'anexo', 201, 10129, 4, 'e', 'Logística Reversa em Lockers - LRLCK: quando o envio de encomenda é realizado pelo consumidor nos armários inteligentes, mediante a apresentação do e-ticket ou o código do objeto para devolução.', '', 8),
(10135, 'anexo', 201, 10126, 2, '1.3', 'Serviços adicionais da Logística Reversa:', '', 9),
(10136, 'anexo', 201, 10135, 4, 'a', 'Aviso de Recebimento - AR, apenas na modalidade LRA;', '', 10),
(10137, 'anexo', 201, 10135, 4, 'b', 'Preenchimento de check-list;', '', 11),
(10138, 'anexo', 201, 10135, 4, 'c', 'Valor Declarado - VD;', '', 12),
(10139, 'anexo', 201, 10135, 4, 'd', 'Posta Restante Pedida (cobrada automaticamente quando o objeto for endereçado à uma unidade dos Correios, incluindo Caixa Postal).', '', 13),
(10140, 'anexo', 201, 10126, 2, '1.4', 'Embalagens podem ser adquiridas no momento da emissão da autorização de postagem.', '', 14),
(10141, 'anexo', 201, NULL, 1, '2', 'PÚBLICO-ALVO', '', 15),
(10142, 'anexo', 201, 10141, 2, '2.1', 'Pessoas jurídicas com contrato.', '', 16),
(10143, 'anexo', 201, NULL, 1, '3', 'ÁREA DE COBERTURA', '', 17),
(10144, 'anexo', 201, 10143, 2, '3.1', 'O serviço adicional posta restante pedida será automaticamente incluído pelo sistema quando, no endereçamento de encomendas de Logística Reversa, o CEP de destino for o de uma unidade dos Correios, inclusive quando constar o CEP de destino referente ao Clique e Retire.', '', 18),
(10145, 'anexo', 201, 10143, 2, '3.2', 'A área de cobertura do serviço de logística reversa seguirá a mesma do serviço de encomenda definido na autorização de postagem.', '', 19),
(10146, 'anexo', 201, 10143, 2, '3.3', 'A logística reversa em agência pode ser autorizada com os serviços SEDE Hoje, SEDEX 10, SEDEX 12, SEDEX, PAC, Correios Mini Envios e Grandes Formatos.', '', 20),
(10147, 'anexo', 201, 10143, 2, '3.4', 'A logística reversa com coleta pode ser autorizada com os serviços SEDEX e PAC.', '', 21),
(10148, 'anexo', 201, 10143, 2, '3.5', 'A logística reversa com coleta tem abrangência restrita às localidades que possuem viabilidade comercial e operacional para realizar a prestação do serviço, cuja área de cobertura está disponível para consulta:', '', 22),
(10149, 'anexo', 201, 10148, 4, 'a', 'na intranet: http://scol/scol/default.cfm;', '', 23),
(10150, 'anexo', 201, 10148, 4, 'b', 'na internet: http://www.corporativo.correios.com.br/encomendas/servicosonline/.', '', 24),
(10151, 'anexo', 201, 10143, 2, '3.6', 'A logística reversa em Lockers pode ser autorizada com os serviços SEDEX, PAC e Correios Mini Envios.', '', 25),
(10152, 'anexo', 201, NULL, 1, '4', 'PREÇOS', '', 26),
(10153, 'anexo', 201, 10152, 2, '4.1', 'O serviço Logística Reversa é prestado somente por contrato, sendo, em todos os casos, um serviço a faturar.', '', 27),
(10154, 'anexo', 201, 10152, 2, '4.2', 'O preço total a ser pago consiste no valor do serviço principal pago pelo cliente, adicionados de todos os produtos e serviços adicionais vendidos conforme autorização de postagem.', '', 28),
(10155, 'anexo', 201, 10152, 2, '4.3', 'Quando for o caso, além dos serviços principal e adicionais e da embalagem, o destinatário da logística reversa pagará pela coleta domiciliar, conforme autorização de postagem.', '', 29),
(10156, 'anexo', 201, 10152, 2, '4.4', 'Quando houver entrega simultânea, o contratante do serviço deverá pagar previamente pela postagem da encomenda a ser entregue juntamente com a postagem da encomenda de retorno, conforme faturamento para envio normal de encomendas a faturar.', '', 30),
(10157, 'anexo', 201, 10152, 2, '4.5', 'As tabelas de preços relativas aos serviços de encomendas nacionais encontram-se disponíveis no SAC0424.', '', 31),
(10158, 'anexo', 201, NULL, 1, '5', 'VALOR DECLARADO', '', 32),
(10159, 'anexo', 201, 10158, 2, '5.1', 'O valor declarado é definido por quem emitiu a autorização de postagem.', '', 33),
(10160, 'anexo', 201, 10158, 2, '5.2', 'O valor declarado deve estar disponível na autorização de postagem portada pelo remetente, não sendo obrigado coincidir com o valor constante da Nota Fiscal - NF.', '', 34),
(10161, 'anexo', 201, 10158, 2, '5.3', 'Havendo divergência entre o valor constante no Sistema de Coleta - SCOL e o valor constante na Nota Fiscal - NF, preencher o Formulário de Declaração de Conteúdo com o valor informado no SCOL', '', 35),
(10162, 'anexo', 201, 10158, 2, '5.4', 'O formulário preenchido deverá ser anexado à cópia da NF e encaminhado junto ao objeto de retorno.', '', 36),
(10163, 'anexo', 201, NULL, 1, '6', 'CHECK-LIST', '', 37),
(10164, 'anexo', 201, 10163, 2, '6.1', 'Os Correios somente efetuam a conferência do objeto de retorno quando o serviço adicional de preenchimento do check-list é contratado.', '', 38),
(10165, 'anexo', 201, 10163, 2, '6.2', 'Não será aceito o envio de objetos com serviço adicional de checklist para a Logística Reversa em Locker.', '', 39),
(10166, 'anexo', 201, 10163, 2, '6.3', 'Quando da contratação do serviço adicional de Preenchimento de check-list, o remente deverá, obrigatoriamente, apresentar a NF/cupom fiscal ou cópia de um desses comprovantes.', '', 40),
(10167, 'anexo', 201, 10166, 3, '6.3.1', 'Caso o remetente não apresente, deverá ser preenchido o formulário de declaração de conteúdo, conforme MANCAT 16/3/2 - 14, o que deverá ser anexado ao objeto de retorno.', '', 41),
(10168, 'anexo', 201, 10163, 2, '6.4', 'Nos casos em que o check-list for encaminhado em branco, com preenchimento incompleto ou não for encaminhado, a contratante terá direito a restituição do valor pago pelo serviço que não foi prestado ou que foi prestado incorretamente.', '', 42),
(10169, 'anexo', 201, 10168, 3, '6.4.1', 'Para solicitar essa restituição, a contratante deverá formalizar o ocorrido por meio de abertura de Pedido de Informação - PI.', '', 43),
(10170, 'anexo', 201, 10163, 2, '6.5', 'Na apuração de reclamação por avaria (total ou parcial) em encomendas postadas com lista de checagem, deverá ser considerado:', '', 44),
(10171, 'anexo', 201, 10170, 4, 'a', 'se havia embalagem adequada na autorização de postagem para envio da encomenda, considerando que:', 'I - se a embalagem utilizada não estiver adequada para a conservação do objeto, conforme orientação do guia de embalagem, não caberá indenização;\nII - as embalagens adequadas para envio de aparelhos telefônicos ou eletrônicos em geral são caixas, com adequado acondicionamento do conteúdo de modo a protegê-lo do atrito decorrente do trâmite postal.\nNota: envelopes ou envelopes plástico bolha não são adequados para o envio de aparelhos telefônicos ou eletrônicos em geral.', 45),
(10172, 'anexo', 201, 10170, 4, 'b', 'se o atendente registrou a avaria no preenchimento do check list.', 'Nota: o registro de avaria no check-list afasta a possibilidade de indenização pela avaria identificada.', 46),
(10173, 'anexo', 201, 10163, 2, '6.6', 'Cabe indenizar por aquela encomenda avariada, com check-list, em conformidade com as regras para encomendas, quando:', '', 47),
(10174, 'anexo', 201, 10173, 4, 'c', 'no preenchimento do check-list não houver sido registrada a avaria; ou', '', 48),
(10175, 'anexo', 201, 10173, 4, 'd', 'encomenda for aceita sem o acondicionamento adequado.', '', 49),
(10176, 'anexo', 201, NULL, 1, '7', 'COLETA - LOGÍSTICA REVERSA', '', 50),
(10177, 'anexo', 201, 10176, 2, '7.1', 'Logística Reversa Domiciliar', '', 51),
(10178, 'anexo', 201, 10177, 3, '7.1.1', 'A coleta da encomenda de logística reversa será realizada em dias úteis, de segunda a sexta-feira, no endereço indicado pela contratante, exceto nos casos em que for vedado o acesso do carteiro ao local.', '', 52),
(10179, 'anexo', 201, 10177, 3, '7.1.2', 'A prestação do serviço de coleta é obrigatória para as cidades A+, A, B e C do índice de classificação de cidades, constante do MANNEG 2/6/3.', '', 53),
(10180, 'anexo', 201, 10177, 3, '7.1.3', 'Serão realizadas até 2 (duas) tentativas de coleta em dias úteis consecutivos, de segunda-feira a sexta-feira, entre 8 e as 18 horas.', '7.1.3.1 Caso a 1ª tentativa de coleta seja frustrada, será deixado no endereço do cliente um Aviso de Tentativa de Coleta, informando quando o carteiro retornará para realizar a 2ª tentativa de coleta.\n7.1.3.2 Caso a 2ª tentativa de coleta também seja frustrada, será deixado um novo aviso informando o cancelamento da coleta.', 54),
(10181, 'anexo', 201, 10177, 3, '7.1.4', 'O prazo para a realização da 1º tentativa de coleta é o 1º dia útil seguinte ao da data de solicitação, porém a contratante poderá agendar seu pedido de coleta para até 30 (trinta) dias corridos da data de solicitação.', '', 55),
(10182, 'anexo', 201, 10177, 3, '7.1.5', 'Quando o pedido de coleta envolver aquisição de embalagem, ao prazo de coleta será acrescido 1 (um) dia útil.', '', 56),
(10183, 'anexo', 201, 10177, 3, '7.1.6', 'A contratante poderá solicitar a coleta de até 10 (dez) encomendas em um único pedido.', '', 57),
(10184, 'anexo', 201, 10177, 3, '7.1.7', 'A contratante poderá acompanhar ou cancelar seus pedidos de coleta via site corporativo dos Correios ou web services.', '7.1.7.1 A contratante somente poderá cancelar seu pedido de coleta quando o seu status no sistema estiver como “ACO” (A Coletar).', 58),
(10185, 'anexo', 201, 10177, 3, '7.1.8', 'Não serão coletadas encomendas em quantidade maior do que a prevista no pedido de coleta.', '', 59),
(10186, 'anexo', 201, 10177, 3, '7.1.9', 'As coletas serão realizadas mediante assinatura do remetente e anotação do motivo no Certificado de Postagem.', '', 60),
(10187, 'anexo', 201, 10177, 3, '7.1.10', 'Os dados para faturamento das encomendas coletadas deverão ser registrados no SCOL, de acordo com as informações fornecidas pelo próprio sistema.', '', 61),
(10188, 'anexo', 201, 10176, 2, '7.2', 'Logística Reversa Simultânea Domiciliar', '', 62),
(10189, 'anexo', 201, 10188, 3, '7.2.1', 'A coleta simultânea será realizada quando da chegada da encomenda de ida ao seu destino.', '', 63),
(10190, 'anexo', 201, 10188, 3, '7.2.2', 'Serão realizadas até 2 (duas) tentativas de coleta em dias úteis consecutivos, de segunda-feira a sexta-feira, entre 8 e as 18 horas.', '', 64),
(10191, 'anexo', 201, 10188, 3, '7.2.3', 'Caso a 1ª tentativa de coleta seja frustrada, será deixado no endereço do cliente um Aviso de Tentativa de Coleta, informando quando o carteiro retornará para realizar a 2ª tentativa de coleta.', '', 65),
(10192, 'anexo', 201, 10188, 3, '7.2.4', 'Caso a 2ª tentativa de coleta também seja frustrada, será deixado um novo aviso informando do cancelamento da coleta e a encomenda de ida será devolvida a contratante.', '', 66),
(10193, 'anexo', 201, 10188, 3, '7.2.5', 'A contratante poderá solicitar a coleta simultânea de 1 (uma) encomenda por pedido.', '', 67),
(10194, 'anexo', 201, 10188, 3, '7.2.6', 'A contratante somente poderá cancelar seu pedido de coleta quando o seu status no sistema estiver como “ACO” (A Coletar).', '', 68),
(10195, 'anexo', 201, 10188, 3, '7.2.7', 'Neste caso, a encomenda de ida será devolvida imediatamente ao remetente.', '', 69),
(10196, 'anexo', 201, 10188, 3, '7.2.8', 'O carteiro deverá obrigatoriamente cumprir os 2 (dois) atos, entregar e recolher os objetos, simultaneamente.', '* * * * *', 70),
(10197, 'anexo', 202, NULL, 2, '1.1', 'Check-list Celular é o documento que comprova o estado de um celular no momento da coleta ou da postagem.', '2. PROCEDIMENTOS DO ATENDENTE OU CARTEIRO', 0),
(10198, 'anexo', 202, NULL, 2, '2.1', 'O check-list deverá ser preenchido apenas pelo empregado dos Correios.', '', 1),
(10199, 'anexo', 202, NULL, 2, '2.2', 'No momento da postagem/coleta o empregado deverá:', '', 2),
(10200, 'anexo', 202, 10199, 4, 'a', 'solicitar a Nota/Cupom Fiscal ou cópia, que acompanhará o celular ou preencher o Formulário de Declaração de Conteúdo, conforme MANCAT, MOD 16, CAP 03, Anexo 02, Subitem 14;', '', 3),
(10201, 'anexo', 202, 10199, 4, 'b', 'verificar o estado do celular, informando se há algum defeito aparente;', '', 4),
(10202, 'anexo', 202, 10199, 4, 'c', 'informar os acessórios que seguirão com o celular;', '', 5),
(10203, 'anexo', 202, 10199, 4, 'd', 'solicitar os dados do remetente, sendo obrigatório informar o Nome e o CPF ou RG.', '', 6),
(10204, 'anexo', 202, NULL, 2, '2.3', 'O chip nunca deverá ser encaminhado junto ao celular, devendo permanecer com o remetente do objeto.', '', 7),
(10205, 'anexo', 202, NULL, 2, '2.4', 'É de responsabilidade do remetente o envio de todos os acessórios solicitados pelo fabricante, cabendo aos Correios apenas a correta verificação e marcação no check-list dos itens que irão acompanhar o celular.', '', 8),
(10206, 'anexo', 202, NULL, 2, '2.5', 'As informações contidas no check-list são essenciais aos clientes e as assistências técnicas, o que exige bastante atenção na verificação do celular e o correto preenchimento do formulário.', '', 9),
(10207, 'anexo', 202, NULL, 2, '2.6', 'A postagem/coleta deverá ser recusada caso o remetente:', '', 10),
(10208, 'anexo', 202, 10207, 4, 'a', 'discorde de qualquer informação constante no documento;', '', 11),
(10209, 'anexo', 202, 10207, 4, 'b', 'recuse assinar o check-list;', '', 12),
(10210, 'anexo', 202, 10207, 4, 'c', 'não possua a Nota/Cupom Fiscal ou cópia e não preencha o Formulário de Declaração de Conteúdo.', '', 13),
(10211, 'anexo', 202, NULL, 2, '2.7', 'O atendente ou carteiro deverá assinalar as condições de cada componente, conforme abaixo:', '', 14),
(10212, 'anexo', 202, 10211, 4, 'a', 'ok: em perfeito estado;', '', 15),
(10213, 'anexo', 202, 10211, 4, 'b', 'arranhado: apresenta riscos, mesmo que pequenos;', '', 16),
(10214, 'anexo', 202, 10211, 4, 'c', 'quebrado: apresenta trincas ou falta de pedaços (lascas);', '', 17),
(10215, 'anexo', 202, 10211, 4, 'd', 'amassado: apresenta deformidade (afundamento) em alguma parte;', '', 18),
(10216, 'anexo', 202, 10211, 4, 'e', 'faltando: está faltando ou está em separado (solto).', '', 19),
(10217, 'anexo', 202, NULL, 2, '2.8', 'Observações gerais:', '', 20),
(10218, 'anexo', 202, 10217, 4, 'a', 'se a tampa da bateria estiver presente, deverá ser marcada como parte integrante da carcaça, caso não, deverá ser marcada como “faltando”;', '', 21),
(10219, 'anexo', 202, 10217, 4, 'b', 'cada autorização de postagem ou pedido de coleta poderá conter até 10 encomendas e cada encomenda corresponde a uma postagem;', '', 22),
(10220, 'anexo', 202, 10217, 4, 'c', 'cada postagem contém apenas 1 (um) check-list que verifica apenas um celular;', '', 23),
(10221, 'anexo', 202, 10217, 4, 'd', 'o check-list é emitido em 2 vias: a 1ª via deverá ser assinada pelo remetente e inserida na embalagem junto ao celular, a 2ª via deverá ser entregue ao remetente;', '', 24),
(10222, 'anexo', 202, 10217, 4, 'e', 'é obrigatório o envio da Nota/Cupom Fiscal ou cópia, ou do Formulário de Declaração de Conteúdo.', '3. MODELO DO FORMULÁRIO CHECK-LIST CELULAR NO SARA\n4. MODELO DO FORMULÁRIO CHECK-LIST CELULAR NA COLETA\n* * * * *', 25),
(10223, 'anexo', 203, NULL, 1, '1', 'DEFINIÇÃO', '', 0),
(10224, 'anexo', 203, 10223, 2, '1.1', 'Check-list Eletrônico é o documento que comprova o estado de um equipamento eletrônico no momento da coleta ou da postagem.', '', 1),
(10225, 'anexo', 203, NULL, 1, '2', 'PROCEDIMENTOS DO ATENDENTE OU CARTEIRO', 'a. O check-list deverá ser preenchido apenas pelo empregado dos Correios.\nb. No momento da postagem/coleta o empregado deverá:', 2),
(10226, 'anexo', 203, 10225, 4, 'a', 'Solicitar a nota/cupom fiscal ou cópia que acompanhará o equipamento eletrônico ou preencher o Formulário de Declaração de Conteúdo, conforme MANCAT 16/3, Anexo 2, Subitem 14;', '', 3),
(10227, 'anexo', 203, 10225, 4, 'b', 'verificar o estado do equipamento eletrônico, informando se há algum defeito aparente;', '', 4),
(10228, 'anexo', 203, 10225, 4, 'c', 'informar os acessórios que seguirão com o equipamento eletrônico;', '', 5),
(10229, 'anexo', 203, 10225, 4, 'd', 'solicitar os dados do remetente, sendo obrigatório informar o Nome e o CPF ou RG.', 'c. O chip nunca deverá ser encaminhado junto ao equipamento eletrônico, devendo permanecer com o remetente do objeto.\nd. É de responsabilidade do remetente o envio de todos os acessórios solicitados pelo fabricante, cabendo aos Correios apenas a correta verificação e marcação no check-list dos itens que irão acompanhar o equipamento eletrônico.\ne. As informações contidas no check-list são essenciais aos clientes e as assistências técnicas, o que exige bastante atenção na verificação do equipamento eletrônico e o correto preenchimento do formulário.\nf. A postagem/coleta deverá ser recusada caso o remetente:', 6),
(10230, 'anexo', 203, 10225, 4, 'a', 'discorde de qualquer informação constante no documento;', '', 7),
(10231, 'anexo', 203, 10225, 4, 'b', 'recuse assinar o check-list;', '', 8),
(10232, 'anexo', 203, 10225, 4, 'c', 'não possua nota/cupom fiscal ou cópia e não preencha o Formulário de Declaração de Conteúdo.', 'g. O atendente ou carteiro deverá assinalar as condições de cada componente, conforme abaixo:', 9),
(10233, 'anexo', 203, 10225, 4, 'a', 'ok: em perfeito estado;', '', 10),
(10234, 'anexo', 203, 10225, 4, 'b', 'arranhado: apresenta riscos, mesmo que pequenos;', '', 11),
(10235, 'anexo', 203, 10225, 4, 'c', 'quebrado: apresenta trincas ou falta de pedaços (lascas);', '', 12),
(10236, 'anexo', 203, 10225, 4, 'd', 'amassado: apresenta deformidade (afundamento) em alguma parte;', '', 13),
(10237, 'anexo', 203, 10225, 4, 'e', 'faltando: está faltando ou está em separado (solto).', 'h. Observações gerais:', 14),
(10238, 'anexo', 203, 10225, 4, 'a', 'se a tampa da bateria estiver presente, deverá ser marcada como parte integrante da carcaça, caso não, deverá ser marcada como “faltando”;', '', 15),
(10239, 'anexo', 203, 10225, 4, 'b', 'cada autorização de postagem ou pedido de coleta poderá conter até 10 encomendas e cada encomenda corresponde a uma postagem;', '', 16),
(10240, 'anexo', 203, 10225, 4, 'c', 'cada postagem contém apenas 1 (um) check-List que verifica apenas um equipamento eletrônico;', '', 17),
(10241, 'anexo', 203, 10225, 4, 'd', 'o check-List é emitido em 2 vias: a 1ª via deverá ser assinada pelo remetente e inserida na embalagem junto ao equipamento eletrônico, a 2ª via deverá ser entregue ao remetente;', '', 18),
(10242, 'anexo', 203, 10225, 4, 'e', 'é obrigatório o envio da nota/cupom fiscal ou cópia, ou do Formulário de Declaração de Conteúdo.', '', 19),
(10243, 'anexo', 203, NULL, 1, '3', 'MODELO DO FORMULÁRIO CHECK-LIST EQUIPAMENTO ELETRÔNICO NO SARA', '', 20),
(10244, 'anexo', 203, NULL, 1, '4', 'MODELO DO FORMULÁRIO CHECK-LIST EQUIPAMENTO ELETRÔNICO NA COLETA', '* * * * *', 21),
(10245, 'anexo', 204, NULL, 2, '1.1', 'O Check-List documento consiste em uma lista de até 8 documentos a serem verificados no momento da postagem ou coleta a pedido do cliente de contrato. A postagem ou coleta somente serão aceitas se todos os documentos listados estiverem presentes no momento da postagem.', '', 0),
(10246, 'anexo', 204, NULL, 1, '2', 'LISTA DE DOCUMENTOS', '2.1 A seguir a lista de todos os documentos cadastrados, possíveis de serem verificados no momento da postagem ou coleta:', 1),
(10247, 'anexo', 204, 10246, 4, 'a', 'Atestado de Antecedentes Criminais;', '', 2),
(10248, 'anexo', 204, 10246, 4, 'b', 'Cadastro de Pessoas Físicas (CPF);', '', 3),
(10249, 'anexo', 204, 10246, 4, 'c', 'Cadastro Nacional de Pessoa Jurídica (CNPJ);', '', 4),
(10250, 'anexo', 204, 10246, 4, 'd', 'Carteira de Identidade (RG);', '', 5),
(10251, 'anexo', 204, 10246, 4, 'e', 'Carteira de Identidade Profissional (Ex: CRA, CRM, OAB);', '', 6),
(10252, 'anexo', 204, 10246, 4, 'f', 'Carteira de Trabalho e Previdência Social (CTPS);', '', 7),
(10253, 'anexo', 204, 10246, 4, 'g', 'Carteira do Aposentado;', '', 8),
(10254, 'anexo', 204, 10246, 4, 'h', 'Carteira Nacional de Habilitação (CNH);', '', 9),
(10255, 'anexo', 204, 10246, 4, 'i', 'Cartão do Programa de Formação do Patrimônio do Servidor Público (PASEP);', '', 10),
(10256, 'anexo', 204, 10246, 4, 'j', 'Cartão do Programa de Integração Social (PIS);', '', 11),
(10257, 'anexo', 204, 10246, 4, 'k', 'Certidão de Batismo;', '', 12),
(10258, 'anexo', 204, 10246, 4, 'l', 'Certidão de Casamento;', '', 13),
(10259, 'anexo', 204, 10246, 4, 'm', 'Certidão de Nascimento;', '', 14),
(10260, 'anexo', 204, 10246, 4, 'n', 'Certidão de Óbito;', '', 15),
(10261, 'anexo', 204, 10246, 4, 'o', 'Certidão Negativa de Débitos;', '', 16),
(10262, 'anexo', 204, 10246, 4, 'p', 'Certificado de Registro e Licenciamento de Veículo (CRLV);', '', 17),
(10263, 'anexo', 204, 10246, 4, 'q', 'Certificado de Reservista;', '', 18),
(10264, 'anexo', 204, 10246, 4, 'r', 'Comprovante de Matrícula;', '', 19),
(10265, 'anexo', 204, 10246, 4, 's', 'Comprovante de Pagamento de Boleto/Fatura;', '', 20),
(10266, 'anexo', 204, 10246, 4, 't', 'Comprovante de Pagamento de Anuidade/Mensalidade;', '', 21),
(10267, 'anexo', 204, 10246, 4, 'u', 'Conta de Água;', '', 22),
(10268, 'anexo', 204, 10246, 4, 'v', 'Conta de Gás;', '', 23),
(10269, 'anexo', 204, 10246, 4, 'w', 'Conta de Luz;', '', 24),
(10270, 'anexo', 204, 10246, 4, 'x', 'Conta de Telefone;', '', 25),
(10271, 'anexo', 204, 10246, 4, 'y', 'Contrato Assinado;', '', 26),
(10272, 'anexo', 204, 10246, 4, 'z', 'Escritura;', 'aa) Extrato Bancário;\nbb) Extrato de Benefícios;\ncc) Extrato de Fundo de Garantia (FGTS);\ndd) Fatura de Cartão de Crédito;\nee) Holerite (Contracheque);\nff) Nota / Cupom Fiscal;\ngg) Passaporte;\nhh) Procuração;\nii) Proposta Assinada;\njj) Recibo de Aluguel;\nkk) Recibo de Entrega da Declaração de Imposto de Renda;\nll) Título de Eleitor.', 27),
(10273, 'anexo', 204, NULL, 1, '3', 'PROCEDIMENTOS DO ATENDENTE OU CARTEIRO', '', 28),
(10274, 'anexo', 204, 10273, 2, '3.1', 'O Check-List deverá ser preenchido apenas pelo empregado dos Correios.', '', 29),
(10275, 'anexo', 204, 10273, 2, '3.2', 'No momento da postagem ou coleta o empregado deverá verificar:', '', 30),
(10276, 'anexo', 204, 10275, 4, 'a', 'se todos os documentos relacionados no formulário estão presentes no momento da postagem;', '', 31),
(10277, 'anexo', 204, 10275, 4, 'b', 'os dados do remetente: solicitar os dados pessoais do remetente (dados obrigatórios do remetente: nome e CPF ou RG).', '', 32),
(10278, 'anexo', 204, 10273, 2, '3.3', 'A postagem deverá ser recusada caso o remetente:', '', 33),
(10279, 'anexo', 204, 10278, 4, 'a', 'discorde da checagem do empregado dos Correios;', '', 34),
(10280, 'anexo', 204, 10278, 4, 'b', 'não tenha todos os documentos exigidos no Check-List;', '', 35),
(10281, 'anexo', 204, 10278, 4, 'c', 'recuse assinar o Check-List.', '', 36),
(10282, 'anexo', 204, 10273, 2, '3.4', 'É de responsabilidade única do destinatário (contratante) a lista dos documentos que deseja receber, não cabendo aos Correios ou ao consumidor qualquer interferência.', 'NOTA: a marcação significa que o documento foi checado e consta na relação de documentos solicitados.', 37),
(10283, 'anexo', 204, 10273, 2, '3.5', 'Observações Gerais:', '', 38),
(10284, 'anexo', 204, 10283, 4, 'a', 'cada autorização de postagem ou pedido de coleta poderá conter até 10 encomendas e cada encomenda corresponde a uma postagem;', '', 39),
(10285, 'anexo', 204, 10283, 4, 'b', 'cada postagem contém apenas 1 (um) Check-List documento, que poderá ter até 8 documentos;', '', 40),
(10286, 'anexo', 204, 10283, 4, 'c', 'o Check-List é emitido em 2 vias: a 1ª via deverá ser assinada pelo remetente e inserida na embalagem junto ao equipamento eletrônico, a 2ª via deverá ser entregue ao remetente.', '', 41),
(10287, 'anexo', 204, NULL, 1, '4', 'MODELO DO FORMULÁRIO CHECK-LIST DOCUMENTO NO SARA', '', 42);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(10288, 'anexo', 204, NULL, 1, '5', 'MODELO DO FORMULÁRIO CHECK-LIST DOCUMENTO NA COLETA', '* * * * *', 43),
(10289, 'anexo', 205, NULL, 2, '1.1', 'O check-list Conteúdo é a identificação do objeto que está sendo postado e sua respectiva quantidade. Consiste em informar basicamente e de forma resumida o conteúdo que está sendo postado e sua respectiva quantidade.', '2. PROCEDIMENTOS DO ATENDENTE OU CARTEIRO', 0),
(10290, 'anexo', 205, NULL, 2, '2.1', 'O check-list deverá ser preenchido apenas pelo empregado dos Correios.', '', 1),
(10291, 'anexo', 205, NULL, 2, '2.2', 'No momento da postagem ou coleta o empregado deverá:', '', 2),
(10292, 'anexo', 205, 10291, 4, 'a', 'solicitar a cópia da nota/cupom fiscal que acompanhará o produto ou preencher o Formulário de Declaração de Conteúdo, conforme MANCAT 16/3, Anexo 2 - Subitem 14;', '', 3),
(10293, 'anexo', 205, 10291, 4, 'b', 'informar a categoria e descrever o objeto (o conteúdo);', '', 4),
(10294, 'anexo', 205, 10291, 4, 'c', 'informar a quantidade do(s) objeto(s);', '', 5),
(10295, 'anexo', 205, 10291, 4, 'd', 'solicitar os dados do remetente, sendo obrigatório informar o Nome e o CPF ou RG.', '', 6),
(10296, 'anexo', 205, NULL, 2, '2.3', 'Para o check-list conteúdo não há marcação de defeito, somente a descrição do produto e quantidade.', '', 7),
(10297, 'anexo', 205, NULL, 2, '2.4', 'A solicitação do check-list conteúdo está condicionada a postagem de itens ou objetos que sejam facilmente reconhecidos pelo público em geral (expressões usuais de mercado como tênis, caneta, mouse, teclado, lanterna, tablete, calça jeans, bola etc).', '', 8),
(10298, 'anexo', 205, NULL, 2, '2.5', 'A postagem/coleta deverá ser recusada caso o remetente:', '', 9),
(10299, 'anexo', 205, 10298, 4, 'a', 'discorde de qualquer informação constante no documento;', '', 10),
(10300, 'anexo', 205, 10298, 4, 'b', 'recuse assinar o check-list;', '', 11),
(10301, 'anexo', 205, 10298, 4, 'c', 'não possua Nota/Cupom Fiscal ou cópia e não preencha o Formulário de Declaração de Conteúdo.', '', 12),
(10302, 'anexo', 205, NULL, 2, '2.6', 'Observações gerais:', '', 13),
(10303, 'anexo', 205, 10302, 4, 'a', 'cada autorização de postagem ou pedido de coleta poderá conter até 10 encomendas e cada encomenda corresponde a uma postagem;', '', 14),
(10304, 'anexo', 205, 10302, 4, 'b', 'cada postagem contém apenas 1 (um) check-list conteúdo que poderá ser informado 1 (um ou mais objetos;', '', 15),
(10305, 'anexo', 205, 10302, 4, 'c', 'o check-list é emitido em 2 vias: a 1ª via deverá ser assinada pelo remetente e inserida na embalagem junto ao celular, a 2ª via deverá ser entregue ao remetente;', '', 16),
(10306, 'anexo', 205, 10302, 4, 'd', 'é obrigatório o envio da nota/cupom fiscal ou cópia, ou do Formulário de Declaração de Conteúdo.', '3. MODELO DO FORMULÁRIO CHECK-LIST CONTEÚDO NO SARA\n4. MODELO DO FORMULÁRIO CHECK-LIST CONTEÚDO NA COLETA\n* * * * *', 17),
(10307, 'anexo', 206, NULL, 4, 'a', 'site corporativo (http://www2.correios.com.br/encomendas/servicosonline/);', '', 0),
(10308, 'anexo', 206, NULL, 4, 'b', 'processamento de arquivo XML via pasta FTP;', '', 1),
(10309, 'anexo', 206, NULL, 4, 'c', 'integração Web Services.', '1.2 Site Corporativo\n1.2.1 Para realizar o primeiro acesso, o cliente deverá preencher e entregar ao representante comercial dos Correios um formulário ou carta assinada, contendo os dados de contrato e um endereço de e-mail válido, para recebimento automático da senha de acesso, com perfil administrador.\n1.2.2 O representante comercial entregará ao responsável, na área de suporte a vendas da Superintendência Estadual - SE, a carta assinada, contendo no mínimo o código administrativo, nome e e-mail do cliente para cadastro.\n1.2.3 O responsável na área de suporte realizará o cadastro do e-mail no sistema checando as informações de contrato e assinatura, arquivando o formulário ou carta assinada na pasta do cliente para futuras consultas.\n1.2.4 O cliente realizará o acesso ao sistema mediante informação do código administrativo, e-mail e senha.\n1.2.5 O cliente, perfil Administrador, poderá criar outros perfis, conforme hierarquia de acesso.\n1.2.6 Para utilizar o serviço, o cliente deverá clicar na opção “Logística Reversa” e depois na opção “Solicitação de Autorização de Postagem em Agência” ou “Solicitação de Coleta Domiciliar”.\n1.2.7 Os dados do pedido deverão ser preenchidos (CEP de origem e de destino, nome do remetente e destinatário e serviços adicionais) e clicar em “Enviar Solicitação”.\n1.2.8 O número do e-ticket ou do pedido de coleta deverá ser informado ao consumidor.\n1.3 Processamento de Arquivo XML Via Pasta FTP\n1.3.1 O representante comercial dos Correios deverá encaminhar ao cliente as instruções e o leiaute XML de Processamento de Pedidos.\n1.3.2 O cliente deverá encaminhar por e-mail, ao representante comercial dos Correios, o arquivo XML formatado, de acordo com as instruções, para análise e aprovação.\n1.3.3 O representante comercial dos Correios deverá encaminhar o arquivo XML para a área técnica para aprovação.\n1.3.4 Quando o arquivo for aprovado, será fornecido ao contratante o endereço do servidor FTP, login e senha.\n1.3.5 Para solicitar logística reversa, o cliente deverá elaborar arquivo XML informando todos os dados do pedido (ex: nome e endereço do remetente e destinatário, serviço contratado etc).\n1.3.6 O cliente deverá:', 2),
(10310, 'anexo', 206, NULL, 4, 'a', 'acessar o servidor FTP, mediante login e senha;', '', 3),
(10311, 'anexo', 206, NULL, 4, 'b', 'disponibilizar arquivo XML na pasta “Entrada” do servidor FTP e aguardar o processamento do arquivo.', '1.3.7 Após o processamento, o arquivo de resposta constará na pasta “Retorno” do servidor FTP dos Correios.\n1.3.8 Todo arquivo de resposta será precedido por “RET” (arquivo processado) ou “ERR” (arquivo recusado).\n1.3.9 O cliente deverá informar ao seu cliente o número do e-ticket ou o pedido de coleta.\nNota: o processamento do arquivo ocorrerá de hora em hora, de segunda a sexta-feira, das 06h às 23h.\n1.4 Integração Webservice\n1.4.1 Para realizar a integração Web Services, é necessário seguir as regras descritas no manual de implementação disponibilizado nos seguintes endereços:', 4),
(10312, 'anexo', 206, NULL, 4, 'a', 'na internet: https://www2.correios.com.br/encomendas/servicosonline/;', 'b) no servidor :\n\\\\sac3063\\INSTITUCIONAL\\DINEG\\SUCOM\\DEENC\\PUBLICO\\N_INTRANET\\GESTAO_DE_PORTFOLIO\\SERV_COMPLEMENTARES\\LOG_REVERSA\\INF_GERAIS\\Web_Service_LR.\n1.4.2 Antes de entrar em produção, o cliente deverá realizar a homologação do sistema com os dados informados no manual de integração WebService da Logística Reversa.\n1.4.3 Após a homologação, cliente e área de suporte a vendas da Superintendência Estadual - SE deverão realizar os seguintes passos para acessar o ambiente produção:', 5),
(10313, 'anexo', 206, NULL, 4, 'a', 'cadastro no IDCorreios - Responsável: Cliente;', '', 6),
(10314, 'anexo', 206, NULL, 4, 'b', 'autorização para acesso ao componente da logística reversa no IDCorreios. O cliente deverá preencher e entregar ao representante comercial dos Correios um formulário ou carta assinada;', '', 7),
(10315, 'anexo', 206, NULL, 4, 'c', 'o representante comercial dos Correios entregará ao responsável, na área de suporte a vendas da Superintendência Estadual - SE , a carta assinada, contendo no mínimo o código administrativo, contrato, nome e ID Correios do cliente para conceder o acesso;', '', 8),
(10316, 'anexo', 206, NULL, 4, 'd', 'o responsável na gerência comercial concederá acesso ao “componente de logística reversa no ID Correios” checando as informações de contrato e assinatura, arquivando o formulário ou carta assinada na pasta do cliente para futuras consultas - Responsável: Gerência Comercial;', '', 9),
(10317, 'anexo', 206, NULL, 4, 'e', 'cadastro de senha de acesso ao Web Services no componente da Logistica Reversa no IDCorreios - Responsável: Cliente;', '', 10),
(10318, 'anexo', 206, NULL, 4, 'f', 'a autenticação no Web Services, ambiente produção, se dá utilizando o login de acesso do IDCorreios e a senha gravada no componente da Logística Reversa do IDCorreios, por meio do link de produção do Webservice informado no manual - Responsável: Cliente.', '', 11),
(10319, 'anexo', 206, NULL, 1, '2', 'REGRAS PARA SOLICITAÇÃO DA LOGISTICA REVERSA SIMULTÂNEA', '2.1 O cliente poderá realizar seus pedidos de logística reversa simultânea via:', 12),
(10320, 'anexo', 206, 10319, 4, 'a', 'processamento de arquivo XML + SIGEPVB;', '', 13),
(10321, 'anexo', 206, 10319, 4, 'b', 'SIGEPWEB;', '', 14),
(10322, 'anexo', 206, 10319, 4, 'c', 'integração webservice.', '2.2 Processamento de Arquivo XML + SIGEPVB\n2.2.1 O cliente deverá realizar os procedimentos do item 1.3 e os seguintes:', 15),
(10323, 'anexo', 206, 10319, 4, 'a', 'utilizando o SIGEPVB, realizar a pré-postagem do objeto de ida, vinculando-o à autorização de postagem ou coleta reversa;', '', 16),
(10324, 'anexo', 206, 10319, 4, 'b', 'o Rótulo de Endereçamento da logística Reversa Simultânea - LRS deverá ser emitido e  afixado no objeto de ida;', '', 17),
(10325, 'anexo', 206, 10319, 4, 'c', 'a etiqueta verde da logística reversa simultânea deverá ser afixada ao lado do Rótulo de Endereçamento do objeto de ida;', '', 18),
(10326, 'anexo', 206, 10319, 4, 'd', 'a postagem do objeto de ida deverá ser realizada em até 10 dias a contar da emissão.', '2.3 SIGEPWEB\n2.3.1 Conforme manual do SIGEPWEB, realizar a pré-postagem do objeto de ida com simultânea, vinculando a autorização de postagem ou a coleta reversa.\n2.3.2 O Rótulo de endereçamento da Logística Reversa Simultânea - LRS deverá ser emitido e afixado no objeto de ida.\n2.3.3 A etiqueta verde da logística reversa simultânea deverá ser afixada ao lado do Rótulo de Endereçamento do objeto de ida.\n2.3.4 A postagem do objeto de ida deverá ser realizada em até 10 (dez) dias a contar da emissão.\n2.4 Integração Web Service\n2.4.1 Conforme manual de implementação, realizar a integração WEBSERVICE.\n2.4.2 O Rótulo de Endereçamento da Logística Reversa Simultânea - LRS deverá ser emitido e afixado no objeto de ida.\n2.4.3 A etiqueta verde da logística reversa simultânea deverá ser afixada ao lado do Rótulo de Endereçamento do objeto de ida.\n2.4.4 A postagem do objeto de ida deverá ser realizada em até 10 (dez) dias a contar da emissão.', 19),
(10327, 'anexo', 206, NULL, 1, '3', 'RÓTULO DE ENDEREÇAMENTO DA LOGÍSTICA REVERSA SIMULTÂNEA EM AGÊNCIA E DA LOGÍSTICA REVERSA SIMULTÂNEA COM COLETA', '3.1 O Rótulo de Endereçamento possui as dimensões 10,1 cm de largura x 13,2 cm de altura, podendo ser realizada a impressão de 4 etiquetas por papel tamanho letter (carta).', 20),
(10328, 'anexo', 206, NULL, 1, '4', 'ETIQUETA VERDE IDENTIFICADORA DA LOGÍSTICA REVERSA SIMULTÂNEA', '4.1 A etiqueta da Logística Reversa Simultânea possui cor verde, dimensões 40 mm x 40 mm e código 752402897.\nNota: essa etiqueta na cor verde deverá ser colada ao lado do rótulo de endereçamento.\n* * * * *', 21),
(10329, 'anexo', 207, NULL, 1, '1', 'MODELO DE E-MAIL DA LOGÍSTICA REVERSA EM AGÊNCIA AO CONSUMIDOR', 'Logística Reversa\nEsta é uma mensagem automática, favor não responder.\nSr(a)\n- Você está recebendo uma Autorização de Postagem de Encomenda conforme dados abaixo:\nCódigo da Autorização de Postagem: 123456789\nAutorizador da Postagem: EMPRESA\nData de Emissão: xx/xx/xxxx\nData de Validade: xx/xx/xxxx\nQuantidade de objetos: 1\n- Para utilizá-la, você deverá se dirigir a uma Agência Própria ou Franqueada dos Correios, levando consigo, obrigatoriamente, o Código de Autorização e o objeto para postagem.\nServiços Autorizados:\n· SEDEX Reverso\nDestinatário:\nEMPRESA\nEndereço\nCEP - Cidade - UF\nRemetente:\nNome\nEndereço\nCEP - Cidade - UF\nInformações Importantes\nPara efetuar sua remessa com tranquilidade:', 0),
(10330, 'anexo', 207, NULL, 1, '1', 'Para sua maior comodidade e agilidade no processo de atendimento, imprima este e-mail com o rótulo de endereçamento.', '', 1),
(10331, 'anexo', 207, NULL, 1, '2', 'Você deverá observar as orientações do emissor da autorização, quanto ao envio de nota fiscal, utilização de embalagem adequada e a eventual necessidade de verificação do produto no ato da postagem (checklist).', '', 2),
(10332, 'anexo', 207, NULL, 1, '3', 'A autorização de postagem poderá ser utilizada em qualquer Agência Própria - AC ou Franqueada - AGF, porém, caso esta autorização contemple o Fornecimento de Embalagem, a postagem somente poderá ser realizada em Agência de Correios Própria - AC.', '', 3),
(10333, 'anexo', 207, NULL, 1, '4', 'Você poderá consultar o endereço das ACs e AGFs da sua cidade clicando no link https://mais.correios.com.br/app/index.php', '', 4),
(10334, 'anexo', 207, NULL, 1, '5', 'O serviço contratado está sujeito às condições de aceitação de encomendas, que se encontram disponíveis nas agências de Correios e no nosso site https://www.correios.com.br/enviar/precisa-de-ajuda/arquivos/contratos-formalizados-ate-fevereiro-de-2020/termo-de-condicoes-de-prestacao-de-servicos-de-encomendas-nacionais/view', '- Proibições e restrições:\nhttps://www.correios.com.br/enviar/proibicoes-e-restricoes/proibicoes-e-restricoes\n- Como embalar sua encomenda:\nhttps://www.correios.com.br/enviar/encomendas/arquivo/nacional/guia-tecnico-embalagens-rpc_v1-1.pdf\nCentral de Atendimento * 3003 0100 - Destinado a capitais e regiões metropolitanas. ** 0800 725 7282 - Demais localidades.', 5),
(10335, 'anexo', 207, NULL, 1, '2', 'MODELO DE E-MAIL DA LOGÍSTICA REVERSA COM COLETA AO CONSUMIDOR', '   					Logística Reversa\nEsta é uma mensagem automática, favor não responder.\nSr(a) ____________________________________\n- Você será visitado(a) por um funcionário dos Correios, devidamente uniformizado e portando o crachá de identificação, que efetuará a Coleta de Encomendas em seu endereço, conforme dados abaixo:\nNúmero do Pedido de Coleta: 123456789\nAutorizador da Coleta: Empresa\nQuantidade de objetos: x\nData da Coleta: xx/xx/xx\nConteúdo:\nEndereço de coleta:\nNome\nEndereço\nCEP - Cidade - UF\nEndereço do Destinatário:\nEmpresa\nEndereço\nCEP - Cidade - UF\nInformações Importantes\nPara efetuar sua remessa com tranquilidade:', 6),
(10336, 'anexo', 207, NULL, 1, '1', 'Para sua maior comodidade e agilidade no processo de coleta, sua encomenda deverá estar disponível para ser entregue ao carteiro acompanhada da nota fiscal, adequadamente embalada e fechada.', '', 7),
(10337, 'anexo', 207, NULL, 1, '2', 'Você deverá observar as orientações do autorizador da coleta quanto ao envio de nota fiscal, utilização de embalagem adequada e a eventual necessidade de verificação do produto no ato da postagem (checklist).', '', 8),
(10338, 'anexo', 207, NULL, 1, '3', 'O serviço contratado está sujeito às condições de aceitação de encomendas, que se encontram disponíveis nas agências de Correios e no nosso site https://www.correios.com.br/enviar/precisa-de-ajuda/arquivos/contratos-formalizados-ate-fevereiro-de-2020/termo-de-condicoes-de-prestacao-de-servicos-de-encomendas-nacionais/view', 'Proibições e Restrições:\nhttps://www.correios.com.br/enviar/proibicoes-e-restricoes/proibicoes-e-restricoes\nComo embalar sua encomenda:\nhttps://www.correios.com.br/enviar/encomendas/arquivo/nacional/guia-tecnico-embalagens-rpc_v1-1.pdf\nCentral de Atendimento * 3003 0100 - Destinado a capitais e regiões metropolitanas. ** 0800 725 7282 - Demais localidades.\nEste e-mail é automático e não é necessário respondê-lo', 9),
(10339, 'anexo', 207, NULL, 1, '3', 'MODELO DO E-MAIL DE LOGISTICA REVERSA SIMULTÂNEA COM COLETA AO CONSUMIDOR', 'Logística Reversa\nEsta é uma mensagem automática, favor não responder.\nSr(a) ____________________________________\n- Você será visitado(a) por um funcionário dos Correios devidamente uniformizado e portando o crachá de identificação, que simultaneamente efetuará a entrega de uma encomenda e coleta de outra em seu endereço, conforme dados abaixo:\nNúmero do Pedido de Coleta: 123456789\nData da Coleta: xx/xx/xxxx\nNúmero do objeto a ser coletado: XX123456789BR\nAutorizador da Coleta: Empresa\nConteúdo da encomenda a ser coletada:\nNúmero da encomenda a ser entregue: XX123456789BR\nEndereço de coleta:\nNome\nEndereço\nCEP  - Cidade -UF\nEndereço do Destinatário:\nEmpresa\nEndereço\nCEP  - Cidade – UF\nInformações Importantes\nPara efetuar sua remessa com tranquilidade:', 10),
(10340, 'anexo', 207, NULL, 1, '1', 'Para sua maior comodidade e agilidade no processo de coleta, sua encomenda deverá estar disponível para ser entregue ao carteiro acompanhada da nota fiscal, adequadamente embalada e fechada.', '', 11),
(10341, 'anexo', 207, NULL, 1, '2', 'Você deverá observar as orientações do autorizador da coleta quanto ao envio de nota fiscal, utilização de embalagem adequada e a eventual necessidade de verificação do produto no ato da postagem (checklist).', '', 12),
(10342, 'anexo', 207, NULL, 1, '3', 'O serviço contratado está sujeito às condições de aceitação de encomendas, que se encontram disponíveis nas agências de Correios e no nosso site https://www.correios.com.br/enviar/precisa-de-ajuda/arquivos/contratos-formalizados-ate-fevereiro-de-2020/termo-de-condicoes-de-prestacao-de-servicos-de-encomendas-nacionais/view', '- Proibições e restrições:\nhttps://www.correios.com.br/enviar/proibicoes-e-restricoes/proibicoes-e-restricoes\n- Como embalar sua encomenda:\nhttps://www.correios.com.br/enviar/encomendas/arquivo/nacional/guia-tecnico-embalagens-rpc_v1-1.pdf\nCentral de Atendimento * 3003 0100 - Destinado a capitais e regiões metropolitanas. ** 0800 725 7282 - Demais localidades.\nEste e-mail é automático e não é necessário respondê-lo', 13),
(10343, 'anexo', 207, NULL, 1, '4', 'MODELO DO PRIMEIRO AVISO POR E-MAIL AO CONSUMIDOR: POSTAGEM DO OBJETO DE ENTREGA (IDA) DA LOGISTICA REVERSA SIMULTÂNEA EM AGÊNCIA.', '   					Logística Reversa\nEsta é uma mensagem automática, favor não responder.\nÀ Sua Senhoria,\nPrezado Senhor(a),\nInformamos que a encomenda XX123456789BR será encaminhada à V.Sa. para retirada em uma agência mediante postagem de outra encomenda sob sua posse.\nTão logo ela esteja disponível, será enviada nova comunicação com os dados de retirada e as devidas instruções.\nO encaminhamento da encomenda pode ser acompanhado no portal dos correios, pelo número de registro da encomenda:\nREGISTRO DA ENCOMENDA: XX123456789BR\nclique aqui para acessar o rastreamento.\nImportante:', 14),
(10344, 'anexo', 207, NULL, 1, '1', 'Também será entregue, no seu endereço, Aviso de Chegada, para avisá-lo da disponibilidade da encomenda para retirada na Agência de Correios a ser indicada.', '', 15),
(10345, 'anexo', 207, NULL, 1, '2', 'Para retirar a encomenda, comparecer à Agencia portando o Objeto a Devolver e o Aviso de Chegada.', '', 16),
(10346, 'anexo', 207, NULL, 1, '3', 'A retirada da encomenda na Agência designada está condicionada à postagem do objeto que está em sua posse.', 'Este e-mail é automático. Favor não respondê-lo.\nEm caso de dúvida, contate os Correios por meio do Fale Conosco, para acessar, clique\naqui[inserir link para o fale conosco]', 17),
(10347, 'anexo', 207, NULL, 1, '5', 'MODELO DO SEGUNDO AVISO POR E-MAIL AO CONSUMIDOR:  CHEGADA DO OBJETO NA AGÊNCIA PARA TROCA SIMULTÂNEA. LOGISTICA REVERSA SIMULTÂNEA EM AGÊNCIA.', '   					Logística Reversa\nEsta é uma mensagem automática, favor não responder.\nÀ Sua Senhoria,\nPrezado Senhor(a),\nInformamos que sua encomenda está disponível na Agência de Correios informada a seguir, para retirada no prazo de 7 (sete) dias úteis, mediante entrega dos itens a serem devolvidos com as informações da Autorização de Postagem constantes dessa mensagem:\nAgência de Correios:\nNome da agência\nEndereço da agência\nCEP - Cidade - UF\nRegistro da Encomenda: XX123456789BR\nPrazo Máximo Para Retirada: DD/MM/AAAA\nCódigo da Autorização de Postagem: 123456789\nAutorizador da Postagem: EMPRESA\nData de Emissão: xx/xx/xxxx\nData de Validade: xx/xx/xxxx\nQuantidade de objetos: x\nServiços Autorizados:\nInformações Importantes\na) também será entregue, no seu endereço, Aviso de Chegada, para avisá-lo da disponibilidade da encomenda para retirada na Agência de Correios indicada acima.\nb) para retirar a encomenda, comparecer à Agencia portando o Objeto a Devolver e com o Aviso de Chegada.\nc) em substituição ao Aviso de Chegada também será aceita cópia dessa mensagem eletrônica.\nd) a retirada da encomenda na agência designada está condicionada à postagem do objeto que está em sua posse.\ne) você deverá observar as orientações do emissor da autorização, quanto ao envio de nota fiscal, utilização de embalagem adequada e a eventual necessidade de verificação do produto no ato da postagem (checklist).\nf) o serviço contratado está sujeito às condições de aceitação de encomendas. Clique aqui https://www.correios.com.br/enviar/precisa-de-ajuda/arquivos/contratos-formalizados-ate-fevereiro-de-2020/termo-de-condicoes-de-prestacao-de-servicos-de-encomendas-nacionais/view ou consulte as agências de Correios.\ng) clique aqui https://www.correios.com.br/enviar/proibicoes-e-restricoes/proibicoes-e-restricoespara consultar as proibições e restrições de envio de encomendas.\nh) clique aqui https://www.correios.com.br/enviar/encomendas/arquivo/nacional/guia-tecnico-embalagens-rpc_v1-1.pdf para conhecer as dicas de como embalar sua encomenda.\ni) caso a pessoa que comparecerá à agencia para retirada não for o destinatário, o formulário de autorização a seguir deverá ser preenchido:  \nAUTORIZO A PESSOA INDICADA ABAIXO A REALIZAR A TROCA DE OBJETOS\nNome do Representante:\nRG:\nAssinatura do destinatário:\nRG:\nDocumentos necessários para a retirada de objetos por representantes:', 18),
(10348, 'anexo', 207, NULL, 1, '1', 'Pessoas Físicas: Documento de identidade do representante e do destinatário, e este aviso preenchido e assinado pelo destinatário ou uma procuração simples', '', 19),
(10349, 'anexo', 207, NULL, 1, '2', 'Pessoas Jurídicas: Documento de identidade do representante e de um dos Sócios ou Diretores com atribuições gerenciais. Contrato Social da Empresa ou Ata de Assembleia que elegeu a Diretoria (Sociedades Anônimas) e este aviso preenchido e assinado pelo destinatário ou uma procuração simples.', 'j) para maior agilidade no atendimento, imprima as etiquetas de endereçamento abaixo, recorte e afixe na encomenda a ser devolvida:\n  \nDestinatário:\nEmpresa\nEndereço\nCEP  - Cidade - UF\n  \nRemetente:\nNome\nEndereço\nCEP  - Cidade - UF\nEste e-mail é automático. Favor não respondê-lo.\nEm caso de dúvida, contate os Correios por meio do Fale Conosco, para acessar, clique aqui[inserir link para o fale conosco]', 20),
(10350, 'anexo', 207, NULL, 1, '6', 'MODELO DO AVISO DE CHEGADA EMITIDO PELO SARA PARA A ENCOMENDA COM LOGISTICA REVERSA SIMULTÂNEA EM AGÊNCIA.', '* * * * *', 21),
(10351, 'anexo', 209, NULL, 1, '1', 'OBJETIVO', '', 0),
(10352, 'anexo', 209, 10351, 2, '1.1', 'O atendimento à necessidade de coleta em que o dia e o horário de coleta são definidos com antecedência da data de coleta, mas não há recorrência do agendamento, destinada a atender a demanda sazonal de coletas para clientes com contrato.', '', 1),
(10353, 'anexo', 209, NULL, 1, '2', 'PÚBLICO ALVO', '', 2),
(10354, 'anexo', 209, 10353, 2, '2.1', 'Pessoa Jurídica com contrato.', '', 3),
(10355, 'anexo', 209, NULL, 1, '3', 'SERVIÇOS INERENTES', '', 4),
(10356, 'anexo', 209, 10355, 2, '3.1', 'SEDEX, PAC, Correios Mini Envios.', '', 5),
(10357, 'anexo', 209, NULL, 1, '4', 'ÁREA DE COBERTURA', '', 6),
(10358, 'anexo', 209, 10357, 2, '4.1', 'Restrita às localidades que possuem viabilidade comercial e operacional para realizar a prestação do serviço.', '', 7),
(10359, 'anexo', 209, 10357, 2, '4.2', 'A cobertura deve priorizar as cidades A+, A, B e C do índice de classificação de cidades.', '', 8),
(10360, 'anexo', 209, 10357, 2, '4.3', 'A área de cobertura está disponível para consulta nos seguintes locais:', '', 9),
(10361, 'anexo', 209, 10360, 4, 'a', 'SCOL internet: https://www2.correios.com.br/encomendas/servicosonline/;', '', 10),
(10362, 'anexo', 209, 10360, 4, 'b', 'SCOL intranet: http://scol/scol/default.cfm.', '', 11),
(10363, 'anexo', 209, NULL, 1, '5', 'SOLICITAÇÃO DA COLETA', '', 12),
(10364, 'anexo', 209, 10363, 2, '5.1', 'Para clientes com contrato o pedido de coleta poderá ser realizado acessando o Sistema de Coleta - SCOL por meio do site dos Correios em qualquer horário e dia da semana.', '', 13),
(10365, 'anexo', 209, 10363, 2, '5.2', 'A coleta também poderá ser solicitada mediante cadastro no Sistema Coleta Interativa -  SCI, por intermédio do gestor comercial, ou mediante integração por API (Aplication Programming Interface).', '', 14),
(10366, 'anexo', 209, 10363, 2, '5.3', 'A coleta poderá ser cancelada ou reagendada enquanto seu status estiver “a coletar”.', '', 15),
(10367, 'anexo', 209, 10363, 2, '5.4', 'O pedido pode ser atendido no mesmo dia ou até 4 (quatro) dias úteis depois da solicitação.', '', 16),
(10368, 'anexo', 209, NULL, 1, '6', 'VIABILIDADE OPERACIONAL', '', 17),
(10369, 'anexo', 209, 10368, 2, '6.1', 'A viabilidade de captação deverá ocorrer no mesmo dia da entrada da demanda de coleta na unidade de captação.', '', 18),
(10370, 'anexo', 209, 10368, 2, '6.2', 'A viabilidade de coleta deverá ocorrer no mesmo dia da entrada da demanda de coleta na unidade de coleta.', '', 19),
(10371, 'anexo', 209, 10368, 2, '6.3', 'Caso a unidade de coleta seja a mesma unidade de captação, a viabilidade de coleta deverá ocorrer conjuntamente com a viabilidade de captação.', '', 20),
(10372, 'anexo', 209, 10368, 2, '6.4', 'Caso a unidade de coleta seja distinta da unidade de captação, a viabilidade de coleta deverá ocorrer imediatamente à viabilidade de captação.', '', 21),
(10373, 'anexo', 209, 10368, 2, '6.5', 'Demandas de coleta que não tiverem suas viabilidades realizadas no prazo estabelecido serão canceladas automaticamente pelo SCI, na primeira hora do dia seguinte ao prazo para viabilidade.', '', 22),
(10374, 'anexo', 209, 10368, 2, '6.6', 'Coletas liberadas no sistema e não realizadas na data estabelecida serão canceladas, automaticamente no SCI, na primeira hora do dia seguinte ao prazo para viabilidade.', '', 23),
(10375, 'anexo', 209, 10368, 2, '6.7', 'A coletas canceladas automaticamente, serão registradas no relatório de gestão de coletas do SCI, para controle.', '', 24),
(10376, 'anexo', 209, NULL, 1, '7', 'REALIZAÇÃO DA COLETA', '', 25),
(10377, 'anexo', 209, 10376, 2, '7.1', 'As coletas serão realizadas em dias úteis, de segunda a sexta-feira, no andar térreo do endereço indicado pelo cliente, exceto nos casos em que for vedado o acesso do carteiro ao local.', '', 26),
(10378, 'anexo', 209, 10376, 2, '7.2', 'Os objetos coletados deverão ser expedidos no mesmo dia para o seu respectivo destino, seguindo o plano de triagem específico para cada modalidade de serviço.', '', 27),
(10379, 'anexo', 209, 10378, 3, '7.2.1', 'Excepcionalmente, nas localidades que não houver viabilidade operacional de expedição no mesmo dia, o(s) objeto(s) deverão ser encaminhados no dia útil seguinte.', '', 28),
(10380, 'anexo', 209, 10376, 2, '7.3', 'No momento da coleta a encomenda deverá estar pré-postada, embalada e fechada, com rótulo padrão e etiqueta lógica dos Correios afixados, e nota fiscal ou formulário de declaração de conteúdo afixados na parte externa da encomenda.', '', 29),
(10381, 'anexo', 209, 10376, 2, '7.4', 'Para a coleta de carga LOG+, o cliente deverá apresentar a carga considerando o seguinte:', '', 30),
(10382, 'anexo', 209, 10381, 4, 'a', 'os itens de mesmo Stock Keeping Unit - SKU em grande quantidade e/ou volume deverão ser entregues e armazenados de forma unitizada em paletes e envoltos por filme de polietileno esticável (stretch), para garantir o transporte e manuseio por empilhadeiras e armazenamento em estrutura porta-paletes, com sua(s) respectiva(s) nota(s) fiscal/fiscais;', '', 31),
(10383, 'anexo', 209, 10381, 4, 'b', 'os paletes utilizados para entrega e armazenagem dos itens deverão ter dimensões padronizadas: largura máxima até 100cm, altura máxima até 110cm, sem considerar a altura do palete, profundidade máxima até 120cm; apresentar tábua inferior na maior dimensão; suportar o peso dos itens acondicionados, sem apresentar deformação/ruptura e prover acesso pelos quatro lados para uso de empilhadeiras;', '', 32),
(10384, 'anexo', 209, 10381, 4, 'c', 'os paletes utilizados para entrega e armazenagem não serão devolvidos à contratante ou transportador após a entrega dos itens à contratada;', '', 33),
(10385, 'anexo', 209, 10381, 4, 'd', 'os paletes utilizados para entrega e armazenagem deverão conter espelho (identificação) SKU de modo a distinguir o seu conteúdo.', '', 34),
(10386, 'anexo', 209, 10376, 2, '7.5', 'A coleta de qualquer mercadoria sujeita a tributação deverá ser acompanhada da respectiva nota fiscal afixada na parte externa da embalagem para que seja possível o procedimento da fiscalização tributária, reduzindo a possibilidade de abertura da encomenda.', '', 35),
(10387, 'anexo', 209, 10376, 2, '7.6', 'O representante comercial deverá consultar a viabilidade operacional, conforme demanda do cliente, junto ao gestor de unidade de captação, conforme preconiza MANCAT 16/5.', '', 36),
(10388, 'anexo', 209, 10376, 2, '7.7', 'Haverá apenas uma tentativa de coleta.', '', 37),
(10389, 'anexo', 209, NULL, 1, '8', 'FORMA DE PAGAMENTO', '', 38),
(10390, 'anexo', 209, 10389, 2, '8.1', 'O pagamento da coleta e o valor da postagem do objeto será realizado por meio de fatura.', '', 39),
(10391, 'anexo', 209, 10389, 2, '8.2', 'Para visitas que coletem até 10 (dez) objetos será cobrado um valor fixo.', '', 40),
(10392, 'anexo', 209, 10389, 2, '8.3', 'Para visitas que coletem a partir de 11 (onze) objetos será isenta de cobrança ao cliente, modalidade exclusiva para clientes com contrato.', '', 41),
(10393, 'anexo', 209, 10389, 2, '8.4', 'A tabela de preços encontra-se disponível para consulta no seguinte endereço: \\\\sac0424\\SISTEMAS\\PRECOS_TARIFAS\\Contratos formalizados a partir de março_2020.', '', 42),
(10394, 'anexo', 209, 10389, 2, '8.5', 'A visita da Coleta Agendada, cadastrada no SCI, é faturada a partir do seu registro no APP Operacional - Módulo Realizar Coletas, considerando a quantidade de objetos coletados, não devendo ocorrer lançamento para faturamento via SARA ou Correios Atende.', '', 43),
(10395, 'anexo', 209, NULL, 1, '9', 'ASPECTOS OPERACIONAIS', '', 44),
(10396, 'anexo', 209, 10395, 2, '9.1', 'Consulta aos Pedidos de Coleta Registrados no SCOL', '', 45),
(10397, 'anexo', 209, 10396, 3, '9.1.1', 'O supervisor da unidade ou o responsável designado pelo serviço Coleta Agendada, deverá:', '', 46),
(10398, 'anexo', 209, 10397, 4, 'a', 'acessar diariamente o Sistema de Coleta - SCOL às 9h;', '', 47),
(10399, 'anexo', 209, 10397, 4, 'b', 'verificar os pedidos existentes para realização das coletas;', '', 48),
(10400, 'anexo', 209, 10397, 4, 'c', 'gerar e imprimir a lista e documentos de coleta;', '', 49),
(10401, 'anexo', 209, 10397, 4, 'd', 'ordenar os pedidos de coleta constantes na lista de coleta, indicando à caneta, a ordem sequencial de atendimento, conforme o itinerário da linha;', '', 50),
(10402, 'anexo', 209, 10397, 4, 'e', 'distribuir aos carteiros a lista e documentos de coleta.', '', 51),
(10403, 'anexo', 209, 10395, 2, '9.2', 'Realização da Coleta', '', 52),
(10404, 'anexo', 209, 10403, 3, '9.2.1', 'Para coletas cadastradas no SCOL, o carteiro responsável pela coleta, deverá:', '', 53),
(10405, 'anexo', 209, 10404, 4, 'a', 'apresentar-se no endereço indicado na lista de coleta;', '', 54),
(10406, 'anexo', 209, 10404, 4, 'b', 'indicar na lista e nos documentos de coleta o horário de realização da coleta, ou quando for o caso, o motivo da não coleta e o horário da tentativa;', '', 55),
(10407, 'anexo', 209, 10404, 4, 'c', 'verificar e anotar na lista e/ou nos documentos de coleta a quantidade de objetos coletados;', '', 56),
(10408, 'anexo', 209, 10404, 4, 'd', 'o carteiro poderá coletar quantidade diferente do que foi registrado no pedido, observando sempre a capacidade de acondicionamento no veículo;', '', 57),
(10409, 'anexo', 209, 10404, 4, 'e', 'assinar de forma legível o nome e a matrícula no recibo do usuário e entrega-lo ao cliente;', '', 58),
(10410, 'anexo', 209, 10404, 4, 'f', 'assinar a lista de coleta.', '', 59),
(10411, 'anexo', 209, 10403, 3, '9.2.2', 'Para coletas cadastradas no SCI, o carteiro responsável pela coleta, deverá:', '', 60),
(10412, 'anexo', 209, 10411, 4, 'a', 'carregar as coletas no smartphone;', '', 61),
(10413, 'anexo', 209, 10411, 4, 'b', 'apresentar-se no endereço indicado na lista lógica disponibilizada no APP Operacional - Módulo Realizar Coleta;', '', 62),
(10414, 'anexo', 209, 10411, 4, 'c', 'indicar no APP Operacional - Modulo Realizar Coleta o horário de realização da coleta, ou quando for o caso, o motivo da não coleta e o horário da tentativa;', '', 63),
(10415, 'anexo', 209, 10411, 4, 'd', 'ler os objetos no APP Operacional - Modulo Realizar Coleta e gerar o evento coletado;', '', 64),
(10416, 'anexo', 209, 10411, 4, 'e', 'utilizar lista impressa para coletar e anotar a quantidade coletada, nos casos de falta de smartphone;', '', 65),
(10417, 'anexo', 209, 10411, 4, 'f', 'o carteiro poderá coletar quantidade diferente do que foi registrado no pedido, observando sempre a capacidade de acondicionamento no veículo.', '', 66),
(10418, 'anexo', 209, 10395, 2, '9.3', 'Recebimento e Postagem dos Objetos Coletados em Agência', '', 67),
(10419, 'anexo', 209, 10418, 3, '9.3.1', 'Quando previamente acordado entre a unidade operacional e agência própria dos Correios, o gerente da agência ou atendente designado receberá os objetos coletados pelo carteiro, para faturamento da coleta e postagem dos objetos utilizando o SARA ou Correios Atende.', '', 68),
(10420, 'anexo', 209, 10418, 3, '9.3.2', 'A agência deverá efetuar, no mesmo dia do recebimento, a postagem dos objetos no SARA, a expedição de todos os objetos coletados, de acordo com o plano de triagem específico para cada modalidade de serviço.', '9.3.2.1 Excepcionalmente, nas localidades que não houver viabilidade operacional de encaminhamento no mesmo dia, o(s) objeto(s) deverão ser encaminhados no dia útil seguinte.', 69),
(10421, 'anexo', 209, 10418, 3, '9.3.3', 'A unidade de coleta deverá entregar na agência de postagem os objetos demandados pelo SCOL e pelo SCI, com exceção dos objetos coletados em ponto de coleta que são destinados à unidade operacional específica.', 'Nota: no caso dos objetos do SCOL, coletar a assinatura do atendente no recibo do carteiro.', 70),
(10422, 'anexo', 209, 10418, 3, '9.3.4', 'O atendente deverá:', '', 71),
(10423, 'anexo', 209, 10422, 4, 'a', 'conferir a quantidade de objetos coletados;', '', 72),
(10424, 'anexo', 209, 10422, 4, 'b', 'conferir, assinar e carimbar o recibo do carteiro;', '', 73),
(10425, 'anexo', 209, 10422, 4, 'c', 'realizar a postagem dos objetos utilizando o SARA ou o Correios Atende, conforme caso.', '', 74),
(10426, 'anexo', 209, 10395, 2, '9.4', 'Prestação de Contas e Expedição dos Objetos Coletados', '', 75),
(10427, 'anexo', 209, 10426, 3, '9.4.1', 'O carteiro que realizou a coleta agendada no SCOL deverá entregar ao supervisor da unidade ou à equipe interna designada a lista e documentos de coleta preenchidos:', '', 76),
(10428, 'anexo', 209, 10427, 4, 'a', 'os objetos coletados, para que sejam direcionados a uma agência de postagem, quando não entregues na agência de postagem, no retorno da coleta/distribuição;', 'b) o recibo do carteiro preenchido, assinado e carimbado pela agência, caso os objetos sejam postados em agência própria dos Correios.', 77),
(10429, 'anexo', 209, 10426, 3, '9.4.2', 'Para as coletas realizadas via SCI, na prestação de contas apresentar as informações contidas no APP ao agente designado pela unidade.', '9.4.3 Os objetos coletados contingencialmente devem ser lidos no SCI e gerar o evento coletado antes de encaminhar para uma agência de postagem;\n9.4.4 Os objetos coletados de ponto de coleta, deverão ser expedidos no mesmo dia da coleta de acordo com o plano de triagem específico para cada modalidade de serviço.\n9.4.5 Excepcionalmente, nas localidades que não houver viabilidade operacional de encaminhamento no mesmo dia, o(s) objeto(s) deverá(ão) ser encaminhado(s) no dia útil seguinte.\n9.4.6 O supervisor ou equipe interna da unidade deverá:', 78),
(10430, 'anexo', 209, 10429, 4, 'a', 'conferir a lista, os documentos de coleta (recibos e certificado de postagem) preenchidos ou as informações contidas no APP Operacional e SCI;', '', 79),
(10431, 'anexo', 209, 10429, 4, 'b', 'efetuar, no SCOL, a baixa da coleta impreterivelmente no mesmo dia, após o retorno do carteiro à unidade, como também as baixas das coletas cadastrada no SCI e realizadas de forma contingencial;', '', 80),
(10432, 'anexo', 209, 10429, 4, 'c', 'encaminhar os objetos coletados para a agência mais próxima para o faturamento da coleta e a postagem dos objetos utilizando o SARA Operacional (modalidade a faturar) ou o Sistema Correios Atende (modalidade a vista), nos casos de objeto(s) não entregue(s) na agência;', '', 81),
(10433, 'anexo', 209, 10429, 4, 'd', 'no caso de pedidos não coletados, selecionar o motivo no campo “Situação do Pedido de Coleta” e anotar as observações que se fizerem necessárias;', '', 82),
(10434, 'anexo', 209, 10429, 4, 'e', 'arquivar os documentos para consulta futura.', '', 83),
(10435, 'anexo', 209, 10395, 2, '9.5', 'Procedimentos em Caso de Roubo dos Objetos Coletados', '9.5.1 Efetuar o registro do Boletim de Ocorrência - BO:', 84),
(10436, 'anexo', 209, 10435, 4, 'a', 'efetuar normalmente, no SCOL, a baixa da operação de coleta;', '', 85),
(10437, 'anexo', 209, 10435, 4, 'b', 'informar os dados de postagem para o atendente da agência e solicitar a postagem dos objetos no SARA (a faturar) ou Correios Atende (a vista) tomando por base os dados existentes no SCOL e no certificado ou lista de postagem;', '', 86),
(10438, 'anexo', 209, 10435, 4, 'c', 'efetuar, após o registro de postagem, a baixa no SRO lançando o respectivo evento (Roubo a Carteiro, Roubo a Unidade ou Roubo a Veículo).', 'Nota: caso a unidade não disponha do(s) número(s) do(s) objeto(s) roubado(s), esta informação deverá ser solicitada ao próprio cliente, sendo-lhe informado sobre o ocorrido e o prazo previsto para indenização.', 87),
(10439, 'anexo', 209, 10395, 2, '9.6', 'Procedimentos de Controle dos Objetos Roubados', '', 88),
(10440, 'anexo', 209, 10439, 3, '9.6.1', 'Visando possibilitar o acompanhamento dos casos e a identificação de possíveis simulações, deverão ser catalogados, pelas respectivas gerências de operações, e encaminhados à gerência responsável pelo pagamento de indenizações mensalmente, os casos de roubo dos objetos coletados, registrando:', '', 89),
(10441, 'anexo', 209, 10440, 4, 'a', 'data e a hora da ocorrência;', '', 90),
(10442, 'anexo', 209, 10440, 4, 'b', 'unidade de lotação e o nome completo do carteiro;', '', 91),
(10443, 'anexo', 209, 10440, 4, 'c', 'local do roubo;', '', 92),
(10444, 'anexo', 209, 10440, 4, 'd', 'dados do objeto roubado (número e estimativa de peso);', '', 93),
(10445, 'anexo', 209, 10440, 4, 'e', 'dados do cliente (nome, endereço e CPF);', '', 94),
(10446, 'anexo', 209, 10440, 4, 'f', 'valor roubado (coletas pagas à vista);', '', 95),
(10447, 'anexo', 209, 10440, 4, 'g', 'circunstâncias da ocorrência;', 'h) quantidade de roubos de objetos coletados envolvendo o carteiro.', 96),
(10448, 'anexo', 209, NULL, 1, '10', 'GENERALIDADES', '', 97),
(10449, 'anexo', 209, 10448, 2, '10.1', 'O gestor comercial deverá registrar a solicitação de coleta no SCI.', '', 98),
(10450, 'anexo', 209, 10448, 2, '10.2', 'A solicitação, alteração e manutenção das informações serão realizadas pelo representante comercial, conforme demanda do cliente.', '', 99),
(10451, 'anexo', 209, 10448, 2, '10.3', 'A unidade de coleta deverá realizar a baixa contingencial das coletas no SCI, mediante a leitura dos objetos coletados para geração do evento “Coletado”, quando da impossibilidade de baixa pelo carteiro, via APP Operacional - Módulo Realizar Coletas, além de baixar as coletas canceladas.', '* * * * *', 100),
(10452, 'anexo', 210, NULL, 1, '1', 'OBJETIVO', '', 0),
(10453, 'anexo', 210, 10452, 2, '1.1', 'O atendimento à necessidade de coleta em que os dias e horários da coleta são definidos previamente, com recorrência programada, destinada ao atendimento da demanda regular dos clientes com contrato.', '', 1),
(10454, 'anexo', 210, NULL, 1, '2', 'PÚBLICO ALVO', '', 2),
(10455, 'anexo', 210, 10454, 2, '2.1', 'Pessoas Jurídicas com contrato.', '', 3),
(10456, 'anexo', 210, NULL, 1, '3', 'SERVIÇOS INERENTES', '', 4),
(10457, 'anexo', 210, 10456, 2, '3.1', 'SEDEX, SEDEX 10, SEDEX 12, SEDEX HOJE, PAC e Correios Mini Envios.', '', 5),
(10458, 'anexo', 210, NULL, 1, '4', 'ÀREA DE COBERTURA', '', 6),
(10459, 'anexo', 210, 10458, 2, '4.1', 'Restrita às localidades que possuem viabilidade comercial e operacional para realizar a prestação do serviço.', '', 7),
(10460, 'anexo', 210, NULL, 1, '5', 'PROGRAMAÇÃO DA COLETA', '', 8),
(10461, 'anexo', 210, 10460, 2, '5.1', 'O representante comercial deverá consultar a viabilidade operacional, conforme demanda do cliente.', '', 9),
(10462, 'anexo', 210, 10461, 3, '5.1.1', 'Poderão ser cadastrados um ou vários pontos de coleta, conforme disponibilidade da unidade operacional dos Correios.', '', 10),
(10463, 'anexo', 210, 10461, 3, '5.1.2', 'Comunicar ao cliente quando o horário de postagem não permitir a expedição no mesmo dia.', '', 11),
(10464, 'anexo', 210, NULL, 1, '6', 'VIABILIDADE OPERACIONAL', '', 12),
(10465, 'anexo', 210, 10464, 2, '6.1', 'A viabilidade de captação deverá acontecer em D+1 a contar da entrada da demanda de coleta na unidade de captação.', '', 13),
(10466, 'anexo', 210, 10464, 2, '6.2', 'A viabilidade de coleta deverá acontecer em D+1 a contar da entrada da demanda de coleta na unidade de coleta.', '', 14),
(10467, 'anexo', 210, 10464, 2, '6.3', 'Caso a unidade de coleta seja a mesma unidade de captação, a viabilidade de coleta deverá ocorrer conjuntamente com a viabilidade de captação.', '', 15),
(10468, 'anexo', 210, 10464, 2, '6.4', 'Caso a unidade de coleta seja distinta da unidade de captação, a viabilidade de coleta deverá ocorrer imediatamente à viabilidade de captação.', '', 16),
