(10483, 'anexo', 210, NULL, 1, '8', 'FORMA DE PAGAMENTO', '', 31),
(10484, 'anexo', 210, 10483, 2, '8.1', 'O pagamento da coleta e o valor da postagem do objeto será realizado por meio de fatura.', '', 32),
(10485, 'anexo', 210, 10483, 2, '8.2', 'Para visitas que coletem até 10 (dez) objetos será cobrado um valor fixo.', '', 33),
(10486, 'anexo', 210, 10483, 2, '8.3', 'Para visitas que coletem a partir de 11 (onze) objetos, a coleta será isenta de cobrança ao cliente, modalidade exclusiva para clientes com contrato.', '', 34),
(10487, 'anexo', 210, 10483, 2, '8.4', 'A tabela de preços encontra-se disponível para consulta no seguinte endereço:\\\\sac0424\\SISTEMAS\\PRECOS_TARIFAS\\Contratos formalizados a partir de março_2020', '', 35),
(10488, 'anexo', 210, 10483, 2, '8.5', 'A visita da Coleta Programada é faturada a partir do seu registro no APP Operacional - Módulo Realizar Coletas, considerando a quantidade de objetos coletados, não devendo ocorrer lançamento para faturamento via SARA ou Correios Atende.', '', 36),
(10489, 'anexo', 210, NULL, 1, '9', 'ASPECTOS OPERACIONAIS', '', 37),
(10490, 'anexo', 210, 10489, 2, '9.1', 'Registro de programação no SCI:', '', 38),
(10491, 'anexo', 210, 10490, 4, 'a', 'a programação, alteração e manutenção das informações serão demandadas pelo cliente ou representante comercial, conforme demanda do cliente;', '', 39),
(10492, 'anexo', 210, 10490, 4, 'b', 'o gestor da unidade de coleta deverá verificar se todas as demandas de coleta do dia estão vinculadas ao carteiro que irá realizar o atendimento;', '', 40),
(10493, 'anexo', 210, 10490, 4, 'c', 'o gestor da unidade de coleta deverá disponibilizar os smartphones para os carteiros com aplicativo APP Operacional - Módulo Realizar Coletas instalado;', '', 41),
(10494, 'anexo', 210, 10490, 4, 'd', 'a unidade de coleta deverá gerenciar a baixa das coletas, inclusive as canceladas; e realizar a baixa em situações contingenciais primando pela fidelidade das informações contidas no sistema.', '', 42),
(10495, 'anexo', 210, 10489, 2, '9.2', 'Realização da Coleta - Unidade de Coleta', '', 43),
(10496, 'anexo', 210, 10495, 3, '9.2.1', 'O carteiro responsável pela coleta, deverá:', '', 44),
(10497, 'anexo', 210, 10496, 4, 'a', 'apresentar-se no endereço indicado no APP Operacional - Módulo Realizar coletas ou na lista de coleta, sendo para esse último em caso de contingência;', '', 45),
(10498, 'anexo', 210, 10496, 4, 'b', 'indicar na lista e nos documentos de coleta o horário de realização da coleta, ou quando for o caso, o motivo da não coleta e o horário da tentativa, quando da contingência;', '', 46),
(10499, 'anexo', 210, 10496, 4, 'c', 'verificar e registrar no App operacional - Módulo Realizar Coletas a quantidade de unitizadores, se carga unitizada ou realizar a leitura do código 2D se a encomenda estiver avulsa;', '', 47),
(10500, 'anexo', 210, 10496, 4, 'd', 'para as coletas realizadas de forma contingencial (lista impressa), verificar e registrar a quantidade de unitizadores, se carga unitizada, e a quantidade de objetos se a encomenda estiver avulsa;', '', 48),
(10501, 'anexo', 210, 10496, 4, 'e', 'o carteiro poderá coletar quantidade diferente do que foi registrado no pedido, observando sempre a capacidade de acondicionamento no veículo;', '', 49),
(10502, 'anexo', 210, 10496, 4, 'f', 'solicitar ao cliente que assine a lista diária de coleta, quando a coleta for realizada de forma contingencial;', '', 50),
(10503, 'anexo', 210, 10496, 4, 'g', 'assinar de forma legível o nome e a matrícula na via do cliente e entregá-lo ao mesmo;', '', 51),
(10504, 'anexo', 210, 10496, 4, 'h', 'realizar baixa, dos pedidos não coletados, via APP Operacional ou de forma contingencial no SCI;', '', 52),
(10505, 'anexo', 210, 10496, 4, 'i', 'arquivar os documentos para consulta futura, quando da baixa de forma contingencial;', '', 53),
(10506, 'anexo', 210, 10496, 4, 'j', 'realizar leitura dos objetos de coletas contingenciais, antes de serem encaminhados para a agência de postagem, no retorno do carteiro, conforme rotina do SCI de modo a gerar o evento coletado.', '', 54),
(10507, 'anexo', 210, 10489, 2, '9.3', 'Realização da Coleta - Agência de Postagem', '', 55),
(10508, 'anexo', 210, 10507, 4, 'a', 'realizar a postagem dos objetos utilizando o SARA Operacional, nos casos de objeto(s) não entregue(s) na agência;', '', 56),
(10509, 'anexo', 210, 10507, 4, 'b', 'efetuar, no mesmo dia, a expedição de todos os objetos coletados, de acordo com o plano de triagem específico para cada modalidade de serviço.', '', 57),
(10510, 'anexo', 210, 10489, 2, '9.4', 'Procedimentos em Caso de Roubo dos Objetos Coletados', '', 58);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(10511, 'anexo', 210, 10510, 3, '9.4.1', 'Efetuar o registro do Boletim de Ocorrência - BO: efetuar a baixa no SRO lançando o respectivo evento (Roubo a Carteiro, Roubo a Unidade ou Roubo a Veículo).', 'Nota: caso a unidade não disponha do(s) número(s) do(s) objeto(s) roubado(s), esta informação deverá ser solicitada ao próprio cliente, sendo-lhe informado sobre o ocorrido e o prazo previsto para indenização.', 59),
(10512, 'anexo', 210, 10489, 2, '9.5', 'Procedimentos de Controle dos Objetos Roubados', '', 60),
(10513, 'anexo', 210, 10512, 3, '9.5.1', 'Visando possibilitar o acompanhamento dos casos e a identificação de possíveis simulações, deverão ser catalogados, pelas respectivas gerências de operações, e encaminhados a gerência responsável pelo pagamento de indenizações mensalmente, os casos de roubo dos objetos coletados, registrando:', '', 61),
(10514, 'anexo', 210, 10513, 4, 'a', 'data e a hora da ocorrência;', '', 62),
(10515, 'anexo', 210, 10513, 4, 'b', 'unidade de lotação e o nome completo do carteiro;', '', 63),
(10516, 'anexo', 210, 10513, 4, 'c', 'local do roubo;', '', 64),
(10517, 'anexo', 210, 10513, 4, 'd', 'dados do objeto roubado (número e estimativa de peso);', '', 65),
(10518, 'anexo', 210, 10513, 4, 'e', 'dados do cliente (nome, endereço e CPF);', '', 66),
(10519, 'anexo', 210, 10513, 4, 'f', 'valor roubado (coletas pagas à vista);', '', 67),
(10520, 'anexo', 210, 10513, 4, 'g', 'circunstâncias da ocorrência;', '', 68),
(10521, 'anexo', 210, 10513, 4, 'h', 'quantidade de roubos de objetos coletados envolvendo o carteiro.', '', 69),
(10522, 'anexo', 210, NULL, 1, '10', 'GENERALIDADES', '', 70),
(10523, 'anexo', 210, 10522, 2, '10.1', 'O gestor comercial deverá registrar a programação de coletas no SCI.', '', 71),
(10524, 'anexo', 210, 10522, 2, '10.2', 'A solicitação, alteração e manutenção das informações serão realizadas pelo representante comercial, conforme demanda do cliente.', '', 72),
(10525, 'anexo', 210, 10522, 2, '10.3', 'A unidade de coleta deverá realizar a baixa contingencial das coletas, mediante a leitura dos objetos gerando o evento “Coletado” no SCI, quando da impossibilidade de baixa pelo carteiro, via APP Operacional Módulo - Realizar Coletas, além de baixar as coletas canceladas.', '* * * * *', 73),
(10526, 'anexo', 211, NULL, 1, '1', 'OBJETIVO', '', 0),
(10527, 'anexo', 211, 10526, 2, '1.1', 'O atendimento à necessidade de coleta em que o dia de coleta coincide com o dia da solicitação não havendo recorrência do agendamento, destinada a atender demanda pontual e urgente dos clientes com contrato.', '', 1),
(10528, 'anexo', 211, NULL, 1, '2', 'PÚBLICO ALVO', '', 2),
(10529, 'anexo', 211, 10528, 2, '2.1', 'Pessoas Jurídicas com contrato.', '', 3),
(10530, 'anexo', 211, NULL, 1, '3', 'SERVIÇOS INERENTES', '', 4),
(10531, 'anexo', 211, 10530, 2, '3.1', 'SEDEX, PAC e Correios Mini Envios.', '', 5),
(10532, 'anexo', 211, NULL, 1, '4', 'ÀREA DE COBERTURA', '', 6),
(10533, 'anexo', 211, 10532, 2, '4.1', 'Restrita às localidades que possuem viabilidade comercial e operacional para realizar a prestação do serviço.', '', 7),
(10534, 'anexo', 211, NULL, 1, '5', 'SOLICITAÇÃO DA COLETA', '', 8),
(10535, 'anexo', 211, 10534, 2, '5.1', 'O pedido deve ser solicitado até as 11hrs.', '', 9),
(10536, 'anexo', 211, 10534, 2, '5.2', 'Apenas pedidos aceitos serão coletados.', '', 10),
(10537, 'anexo', 211, 10534, 2, '5.3', 'O representante comercial deverá consultar a viabilidade operacional, conforme demanda do cliente.', '', 11),
(10538, 'anexo', 211, 10537, 3, '5.3.1', 'Poderão ser cadastrados um ou vários pontos de coleta, conforme disponibilidade da unidade operacional dos Correios.', '', 12),
(10539, 'anexo', 211, 10537, 3, '5.3.2', 'Comunicar ao cliente quando o horário de postagem não permitir a expedição no mesmo dia.', '', 13),
(10540, 'anexo', 211, NULL, 1, '6', 'VIABILIDADE OPERACIONAL', '', 14),
(10541, 'anexo', 211, 10540, 2, '6.1', 'A viabilidade de captação e de coleta deverão ocorrer no mesmo dia da entrada da demanda de coleta na unidade de captação/coleta.', '', 15),
(10542, 'anexo', 211, 10540, 2, '6.2', 'Caso a unidade de coleta seja a mesma unidade de captação, a viabilidade de coleta deverá ocorrer conjuntamente com a viabilidade de captação.', '', 16),
(10543, 'anexo', 211, 10540, 2, '6.3', 'Caso a unidade de coleta seja distinta da unidade de captação, a viabilidade de coleta deverá ocorrer imediatamente à viabilidade de captação.', '', 17),
(10544, 'anexo', 211, 10540, 2, '6.4', 'Demandas de coleta que não tiverem suas viabilidades realizadas no prazo estabelecido serão canceladas automaticamente pelo Sistema Coleta Interativa - SCI, na primeira hora do dia seguinte ao prazo para viabilidade.', '', 18),
(10545, 'anexo', 211, 10540, 2, '6.5', 'Coletas liberadas no sistema e não realizadas na data estabelecida serão canceladas, automaticamente no SCI, na primeira hora do dia seguinte ao prazo para viabilidade.', '', 19),
(10546, 'anexo', 211, 10540, 2, '6.6', 'A coletas canceladas automaticamente, serão registradas no relatório de gestão de coletas do SCI, para controle.', '', 20),
(10547, 'anexo', 211, NULL, 1, '7', 'REALIZAÇÃO DA COLETA', '', 21),
(10548, 'anexo', 211, 10547, 2, '7.1', 'As coletas Mesmo Dia serão realizadas conforme datas e horários definidos.', '', 22),
(10549, 'anexo', 211, 10547, 2, '7.2', 'As encomendas coletadas serão expedidas para o destino, conforme o plano de triagem específico para cada modalidade de serviço.', '', 23),
(10550, 'anexo', 211, 10547, 2, '7.3', 'O representante comercial deverá consultar a viabilidade operacional, conforme demanda do cliente, junto ao gestor de unidade de captação, conforme preconiza MANCAT 16/5.', '', 24),
(10551, 'anexo', 211, 10547, 2, '7.4', 'Haverá apenas uma tentativa de coleta.', '', 25),
(10552, 'anexo', 211, NULL, 1, '8', 'FORMA DE PAGAMENTO', '', 26),
(10553, 'anexo', 211, 10552, 2, '8.1', 'O pagamento da coleta e o valor da postagem do objeto será realizado por meio de fatura.', '', 27),
(10554, 'anexo', 211, 10552, 2, '8.2', 'Limite mínimo superior a 10 (dez) objetos por pedido.', '', 28),
(10555, 'anexo', 211, 10552, 2, '8.3', 'Para a coleta de unitizador, não há limite mínimo ou máximo.', '', 29),
(10556, 'anexo', 211, 10552, 2, '8.4', 'A tabela de preços encontra-se disponível para consulta no seguinte endereço:\\\\sac0424\\SISTEMAS\\PRECOS_TARIFAS\\Contratos formalizados a partir de março_2020', '', 30),
(10557, 'anexo', 211, 10552, 2, '8.5', 'A coleta Mesmo Dia é faturada a partir do registro de sua realização no APP Operacional - Módulo Realizar Coletas, não devendo ocorrer lançamento para faturamento via SARA ou Correios Atende.', '', 31),
(10558, 'anexo', 211, NULL, 1, '9', 'ASPECTOS OPERACIONAIS', '', 32),
(10559, 'anexo', 211, 10558, 2, '9.1', 'Registro de demanda de coleta no Sistema Coleta Interativa:', '', 33),
(10560, 'anexo', 211, 10559, 4, 'a', 'a solicitação, alteração e manutenção das informações serão demandadas pelo cliente ou representante comercial, conforme demanda do cliente;', '', 34),
(10561, 'anexo', 211, 10559, 4, 'b', 'o gestor da unidade de coleta deverá verificar se todas as demandas de coleta do dia estão vinculadas ao carteiro que irá realizar o atendimento;', '', 35),
(10562, 'anexo', 211, 10559, 4, 'c', 'o gestor da unidade de coleta deverá disponibilizar os smartphones para os carteiros com aplicativo APP Operacional - Módulo Realizar Coletas instalado;', '', 36),
(10563, 'anexo', 211, 10559, 4, 'd', 'a unidade de coleta deverá gerenciar a baixa das coletas, inclusive as canceladas; e realizar a baixa em situações contingenciais primando pela fidelidade das informações contidas no sistema.', '', 37),
(10564, 'anexo', 211, 10558, 2, '9.2', 'Em caso de viabilidade, a unidade de coleta deverá encaminhar imediatamente o pedido de coleta ao carteiro mais adequado.', '', 38),
(10565, 'anexo', 211, 10558, 2, '9.3', 'Realização da Coleta', '', 39),
(10566, 'anexo', 211, 10565, 3, '9.3.1', 'O carteiro responsável pela coleta, deverá:', '', 40),
(10567, 'anexo', 211, 10566, 4, 'a', 'apresentar-se no endereço indicado no APP Operacional - Módulo Realizar Coletas ou na lista de coleta, sendo para esse último em caso de contingência;', '', 41),
(10568, 'anexo', 211, 10566, 4, 'b', 'indicar na lista e nos documentos de coleta o horário de realização da coleta, ou quando for o caso, o motivo da não coleta e o horário da tentativa, quando da contingência;', '', 42),
(10569, 'anexo', 211, 10566, 4, 'c', 'verificar e registrar no APP operacional - Módulo Realizar Coletas a quantidade de unitizadores, se carga unitizada ou realizar a leitura do código 2D se a encomenda estiver avulsa;', '', 43),
(10570, 'anexo', 211, 10566, 4, 'd', 'para a coleta realizadas de forma contingencial (lista impressa), verificar e registrar a quantidade de unitizadores, se carga unitizada, e a quantidade de objetos se a encomenda estiver avulsa;', '', 44),
(10571, 'anexo', 211, 10566, 4, 'e', 'o carteiro poderá coletar quantidade diferente do que foi registrado no pedido, não menos que 10 (dez) objetos, observando sempre a capacidade de acondicionamento no veículo;', '', 45),
(10572, 'anexo', 211, 10566, 4, 'f', 'solicitar ao cliente que assine a lista diária de coleta, quando a coleta for realizada de forma contingencial;', '', 46),
(10573, 'anexo', 211, 10566, 4, 'g', 'assinar de forma legível o nome e a matrícula na via do cliente e entregá-lo ao mesmo;', '', 47),
(10574, 'anexo', 211, 10566, 4, 'h', 'realizar a postagem dos objetos utilizando o SARA Operacional, nos casos de objeto(s) não entregue(s) na agência;', 'i) efetuar, no mesmo dia, a expedição de todos os objetos coletados, de acordo com o plano de triagem específico para cada modalidade de serviço;\nj) no caso de pedidos não coletados, realizar baixa via APP Operacional ou de forma contingencial no SCI;\nNota: objetos coletados de forma contingencial deverão ser lidos no APP para gerar o evento coletado.', 48),
(10575, 'anexo', 211, 10566, 4, 'k', 'arquivar os documentos para consulta futura, quando da baixa de forma contingencial.', '', 49),
(10576, 'anexo', 211, 10558, 2, '9.4', 'Procedimentos em Caso de Roubo dos Objetos Coletados', '9.4.1 Efetuar o registro do Boletim de Ocorrência - BO, efetuar a baixa no SRO lançando o respectivo evento (Roubo a Carteiro, Roubo a Unidade ou Roubo a Veículo).\nNota: caso a unidade não disponha do(s) número(s) do(s) objeto(s) roubado(s), esta informação deverá ser solicitada ao próprio cliente, sendo-lhe informado sobre o ocorrido e o prazo previsto para indenização.', 50),
(10577, 'anexo', 211, 10558, 2, '9.5', 'Procedimentos de Controle dos Objetos Roubados', '', 51),
(10578, 'anexo', 211, 10577, 3, '9.5.1', 'Visando possibilitar o acompanhamento dos casos e a identificação de possíveis simulações, deverão ser catalogados, pelas respectivas gerências de operações, e encaminhados a gerência responsável pelo pagamento de indenizações mensalmente, os casos de roubo dos objetos coletados, registrando:', '', 52),
(10579, 'anexo', 211, 10578, 4, 'a', 'data e a hora da ocorrência;', '', 53),
(10580, 'anexo', 211, 10578, 4, 'b', 'unidade de lotação e o nome completo do carteiro;', '', 54),
(10581, 'anexo', 211, 10578, 4, 'c', 'local do roubo;', '', 55),
(10582, 'anexo', 211, 10578, 4, 'd', 'dados do objeto roubado (número e estimativa de peso);', '', 56),
(10583, 'anexo', 211, 10578, 4, 'e', 'dados do cliente (nome, endereço e CPF);', '', 57),
(10584, 'anexo', 211, 10578, 4, 'f', 'valor roubado (coletas pagas à vista);', '', 58),
(10585, 'anexo', 211, 10578, 4, 'g', 'circunstâncias da ocorrência;', '', 59),
(10586, 'anexo', 211, 10578, 4, 'h', 'quantidade de roubos de objetos coletados envolvendo o carteiro.', '', 60),
(10587, 'anexo', 211, NULL, 1, '10', 'GENERALIDADES', '', 61),
(10588, 'anexo', 211, 10587, 2, '10.1', 'O gestor comercial deverá registrar a programação de coletas no SCI, se na unidade já estiver ativa ou em planilha.', '', 62),
(10589, 'anexo', 211, 10587, 2, '10.2', 'A solicitação, alteração e manutenção das informações serão realizadas pelo representante comercial, conforme demanda do cliente.', '', 63),
(10590, 'anexo', 211, 10587, 2, '10.3', 'A unidade de coleta deverá realizar a baixa contingencial das coletas no SCI, quando da impossibilidade de baixa pelo carteiro, via APP Operacional - Módulo Realizar Coletas, além de baixar as coletas canceladas.', '* * * * *', 64),
(10591, 'anexo', 212, NULL, 1, '1', 'OBJETIVO', '', 0),
(10592, 'anexo', 212, 10591, 2, '1.1', 'O atendimento à necessidade de coleta de carga unitizada em que o dia da coleta coincide conforme modalidade solicitada (Agendada, Programada, Mesmo Dia), destinada a atender demanda pontual e urgente dos clientes com contrato.', '', 1),
(10593, 'anexo', 212, NULL, 1, '2', 'PÚBLICO ALVO', '', 2),
(10594, 'anexo', 212, 10593, 2, '2.1', 'Pessoa Jurídica com contrato.', '', 3),
(10595, 'anexo', 212, NULL, 1, '3', 'SERVIÇO DE VINCULAÇÃO', '', 4),
(10596, 'anexo', 212, 10595, 2, '3.1', 'Transfer Log', '', 5),
(10597, 'anexo', 212, NULL, 1, '4', 'ÁREA DE COBERTURA', '', 6),
(10598, 'anexo', 212, 10597, 2, '4.1', 'Restrita às localidades que possuem viabilidade comercial e operacional para realizar a prestação do serviço.', '', 7),
(10599, 'anexo', 212, NULL, 1, '5', 'SOLICITAÇÃO DA COLETA', '', 8),
(10600, 'anexo', 212, 10599, 2, '5.1', 'A coleta também deverá ser solicitada mediante cadastro no Sistema Coleta Interativa -  SCI, por intermédio do gestor comercial, ou mediante integração por API (Aplication Programming Interface), conforme regras e modalidade que melhor atenda ao cliente: Agendada, Programada ou Mesmo Dia.', '', 9),
(10601, 'anexo', 212, NULL, 1, '6', 'VIABILIDADE OPERACIONAL', '', 10),
(10602, 'anexo', 212, 10601, 2, '6.1', 'A viabilidade de captação deverá acontecer em D+1 a contar da entrada da demanda de coleta na unidade de captação.', '', 11),
(10603, 'anexo', 212, 10601, 2, '6.2', 'A viabilidade de coleta deverá acontecer em D+1 a contar da entrada da demanda de coleta na unidade de coleta.', '', 12),
(10604, 'anexo', 212, 10601, 2, '6.3', 'Caso a unidade de coleta seja a mesma unidade de captação, a viabilidade de coleta deverá ocorrer conjuntamente com a viabilidade de captação.', '', 13),
(10605, 'anexo', 212, 10601, 2, '6.4', 'Caso a unidade de coleta seja distinta da unidade de captação, a viabilidade de coleta deverá ocorrer imediatamente à viabilidade de captação.', '', 14),
(10606, 'anexo', 212, 10601, 2, '6.5', 'Demandas de coleta que não tiverem suas viabilidades realizadas no prazo estabelecido serão canceladas automaticamente pelo SCI, na primeira hora do dia seguinte ao prazo para viabilidade.', '', 15),
(10607, 'anexo', 212, 10601, 2, '6.6', 'Coletas liberadas no sistema e não realizadas na data estabelecida serão canceladas, automaticamente no SCI, na primeira hora do dia seguinte ao prazo para viabilidade.', '', 16),
(10608, 'anexo', 212, 10601, 2, '6.7', 'A coletas canceladas automaticamente, serão registradas no relatório de gestão de coletas do SCI, para controle.', '', 17),
(10609, 'anexo', 212, NULL, 1, '7', 'REALIZAÇÃO DA COLETA', '', 18),
(10610, 'anexo', 212, 10609, 2, '7.1', 'As coletas serão realizadas em dias úteis, de segunda a sexta-feira, no endereço indicado pelo cliente.', '', 19),
(10611, 'anexo', 212, 10609, 2, '7.2', 'Para a coleta de carga unitizada, o cliente deverá apresentar a carga considerando o seguinte:', '', 20),
(10612, 'anexo', 212, 10611, 4, 'a', 'a carga deverá estar acondicionada em paletes envoltos por filme de polietileno esticável (stretch) para garantir o transporte e manuseio por equipamentos de movimentação, acompanhados de sua(s) respectiva(s) nota(s) fiscal/fiscais;', '', 21),
(10613, 'anexo', 212, 10611, 4, 'b', 'os paletes deverão ter dimensões padronizadas: largura máxima até 100cm, altura máxima até 110cm, sem considerar a altura do palete, profundidade máxima até 120cm (soma das dimensões (C+A+L = 330cm) e peso máximo de 350kg; apresentar tábua inferior na maior dimensão; suportar o peso dos itens acondicionados, sem apresentar deformação/ruptura e prover acesso pelos quatro lados para uso de equipamentos de movimentação;', 'Nota: para fins de controle quantitativo e faturamento, estas especificações denominam o volume unitário estabelecido pelo conceito “posições-palete”.', 22),
(10614, 'anexo', 212, 10611, 4, 'c', 'em casos excepcionais e desde que não haja aumento de recursos para a execução do produto, a Superintendência Estadual - SE e o Departamento de Vendas poderão negociar e autorizar o transporte do palete ou CDL de forma diversa ao definido na presente norma, garantindo as viabilidades operacionais e comerciais necessárias para cada situação.', 'd) a carga apresentada em desconformidade com as especificações de dimensão e acondicionamento deste Manual deverá ser faturada conforme a quantidade de posições-palete ocupadas no veículo.\nNota: a excepcionalidade mencionada deverá ser fundamentada pela SE e/ou Departamento de Vendas em fatores estratégicos, tais como: a manutenção de uma boa relação comercial, a preservação da receita dos Correios, a otimização de recursos, a redução de custos e o foco no cliente. Sem a necessidade de incremento de recursos para a execução do produto. ', 23),
(10615, 'anexo', 212, 10611, 4, 'e', 'a carga unitizada deverá ser obrigatoriamente pré-postada como objeto TransferLog (código 03972), rotulada, endereçada e identificada como um único volume, similarmente como os produtos de encomenda (ex.: PAC e SEDEX). ', '', 24),
(10616, 'anexo', 212, 10611, 4, 'f', 'a carga deverá ser apresentada com rótulos de endereçamento em concordância com o regulamento interno dos Correios e a legislação pertinente, preenchidos de forma correta e completa. ', 'Nota: a cobrança da coleta ocorrerá conforme regras estabelecidas para a modalidade Coleta de Carga Unitizada.', 25),
(10617, 'anexo', 212, 10609, 2, '7.3', 'O representante comercial deverá consultar a viabilidade operacional, conforme demanda do cliente, junto ao gestor de unidade de captação, conforme preconiza MANCAT 16/5.', '', 26),
(10618, 'anexo', 212, 10609, 2, '7.4', 'Haverá apenas uma tentativa de coleta.', '', 27),
(10619, 'anexo', 212, NULL, 1, '8', 'AD VALOREM, VALOR MÁXIMO DECLARADO E INDENIZAÇÃO', '', 28),
(10620, 'anexo', 212, 10619, 2, '8.1', 'A coleta unitizada utilizará os parâmetros definidos para o produto TransferLog, nas questões relativas ao Ad Valorem, Valor Máximo Declarado e Indenização.', '', 29),
(10621, 'anexo', 212, 10619, 2, '8.2', 'O percentual de Ad Valorem está definido na tabela de preços do produto.', '', 30),
(10622, 'anexo', 212, 10619, 2, '8.3', 'O valor máximo permitido para declaração de valor está definido na tabela de preços do produto e seguirá os reajustes de preços previstos para o segmento de encomendas, estratégias comerciais de relacionamento com o cliente e mercadológica.', '', 31),
(10623, 'anexo', 212, 10619, 2, '8.4', 'O valor de indenização automática está definido na tabela de preços do produto e seguirá os reajustes de preços previstos para o segmento de encomendas, estratégias comerciais de relacionamento com o cliente e mercadológica.', '', 32),
(10624, 'anexo', 212, NULL, 1, '9', 'ASPECTOS OPERACIONAIS', '', 33),
(10625, 'anexo', 212, 10624, 2, '9.1', 'Realização da Coleta', '', 34),
(10626, 'anexo', 212, 10625, 3, '9.1.1', 'O agente responsável pela coleta, deverá:', '', 35),
(10627, 'anexo', 212, 10626, 4, 'a', 'carregar as coletas no smartphone;', '', 36),
(10628, 'anexo', 212, 10626, 4, 'b', 'apresentar-se no endereço indicado na lista lógica disponibilizada no APP Operacional - Módulo Realizar Coleta;', '', 37),
(10629, 'anexo', 212, 10626, 4, 'c', 'indicar no APP Operacional - Modulo Realizar Coleta o horário de realização da coleta, ou quando for o caso, o motivo da não coleta e o horário da tentativa;', '', 38),
(10630, 'anexo', 212, 10626, 4, 'd', 'ler os unitizadores no APP Operacional - Modulo Realizar Coleta e gerar o evento coletado;', '', 39),
(10631, 'anexo', 212, 10626, 4, 'e', 'utilizar lista impressa para coletar e anotar a quantidade coletada, nos casos de falta de smartphone;', 'Nota 1: o agente de coleta poderá coletar quantidade diferente do que foi registrado no pedido, observando sempre a capacidade de acondicionamento no veículo.\nNota 2: a carga de coleta unitizada deve ser entregue em uma das seguintes unidades: Centro de Logística Integrada - CLI, Correios Empresa - CEM ou Gerência de Controle e Captação - GCCAP, conforme solicitação de coleta.', 40),
(10632, 'anexo', 212, 10624, 2, '9.2', 'Prestação de Contas dos Unitizadores Coletados', '', 41),
(10633, 'anexo', 212, 10632, 3, '9.2.1', 'O agente de coleta deverá apresentar as informações contidas no APP ao agente designado pela unidade.', '', 42),
(10634, 'anexo', 212, 10632, 3, '9.2.2', 'Os unitizadores coletados contingencialmente devem ser lidos no SCI e gerar o evento coletado antes de encaminhar para uma unidade operacional de postagem;', '', 43),
(10635, 'anexo', 212, 10632, 3, '9.2.3', 'Excepcionalmente, nas localidades que não houver viabilidade operacional de encaminhamento no mesmo dia, o(s) unitizadores(s) deverá(ão) ser encaminhado(s) no dia útil seguinte.', '', 44),
(10636, 'anexo', 212, 10632, 3, '9.2.4', 'O supervisor ou equipe interna da unidade deverá:', '', 45),
(10637, 'anexo', 212, 10636, 4, 'a', 'conferir a lista, os documentos de coleta (recibos e certificado de postagem) preenchidos ou as informações contidas no APP Operacional e SCI;', '', 46),
(10638, 'anexo', 212, 10636, 4, 'b', 'arquivar os documentos para consulta futura.', '', 47),
(10639, 'anexo', 212, 10624, 2, '9.3', 'Casos de Roubo dos Objetos Coletados', '', 48),
(10640, 'anexo', 212, 10639, 3, '9.3.1', 'Em casos de roubo de objetos coletados, a unidade de coleta deverá:', '', 49),
(10641, 'anexo', 212, 10640, 4, 'a', 'efetuar o registro do Boletim de Ocorrência - BO;', '', 50),
(10642, 'anexo', 212, 10640, 4, 'b', 'efetuar normalmente a baixa da operação de coleta no SCI;', '', 51),
(10643, 'anexo', 212, 10640, 4, 'c', 'efetuar, após a baixa da coleta no SCI, a baixa no SRO lançando o respectivo evento (Roubo a Carteiro, Roubo a Unidade ou Roubo a Veículo).', '', 52),
(10644, 'anexo', 212, 10624, 2, '9.4', 'Controle dos Unitizadores Roubados', '', 53),
(10645, 'anexo', 212, 10644, 3, '9.4.1', 'As gerências de operações responsáveis pelos unitizadores roubados devem registrar seus respectivos catálogos considerando as seguintes informações:', '', 54),
(10646, 'anexo', 212, 10645, 4, 'a', 'data e a hora da ocorrência;', '', 55),
(10647, 'anexo', 212, 10645, 4, 'b', 'unidade de lotação e o nome completo do agente de coleta;', '', 56),
(10648, 'anexo', 212, 10645, 4, 'c', 'local do roubo;', '', 57),
(10649, 'anexo', 212, 10645, 4, 'd', 'dados do unitizador roubado (número e estimativa de peso);', '', 58),
(10650, 'anexo', 212, 10645, 4, 'e', 'dados do cliente (nome, endereço e CPF);', '', 59),
(10651, 'anexo', 212, 10645, 4, 'f', 'valor roubado;', '', 60),
(10652, 'anexo', 212, 10645, 4, 'g', 'circunstâncias da ocorrência;', 'h) quantidade de roubos de unitizadores envolvendo o agente de coleta.', 61),
(10653, 'anexo', 212, 10644, 3, '9.4.2', 'As gerências de operações devem encaminhar, mensalmente, a relação catalogada à gerência responsável pelo pagamento de indenizações.', '9.4.2.1 O ato de catalogar esses casos de roubo visa possibilitar o acompanhamento e a identificação de possíveis simulações.', 62),
(10654, 'anexo', 212, NULL, 1, '10', 'GENERALIDADES', '', 63),
(10655, 'anexo', 212, 10654, 2, '10.1', 'O gestor comercial deverá registrar a solicitação de coleta no SCI.', '', 64),
(10656, 'anexo', 212, 10654, 2, '10.2', 'A solicitação, alteração e manutenção das informações serão realizadas pelo representante comercial, conforme demanda do cliente.', '', 65),
(10657, 'anexo', 212, 10654, 2, '10.3', 'A unidade de coleta deverá realizar a baixa contingencial das coletas no SCI, mediante a leitura dos unitizadores para geração do evento “Coletado”, quando da impossibilidade de baixa pelo agente de coleta, via APP Operacional - Módulo Realizar Coletas, além de baixar as coletas canceladas.', '* * * * *', 66),
(10658, 'anexo', 213, NULL, 2, '1.1', 'Procedimentos Automatizados Realizados por Web Service do SIGEP WEB', '', 0),
(10659, 'anexo', 213, NULL, 2, '1.2', 'Procedimentos Automatizados Realizados pela API SRO Interatividade', '', 1),
(10660, 'anexo', 213, NULL, 2, '1.3', 'Procedimentos Automatizados Realizados pelo Portal Correios, Super App e Correios Empresas', '', 2),
(10661, 'anexo', 213, NULL, 2, '1.4', 'Procedimentos Realizados por Usuário Interno SEIN e Procedimentos Automatizadas pelo SEIN', '* * * * *', 3),
(10662, 'anexo', 214, NULL, 1, '1', 'SERVIÇO', '1.1 Funcionalidade que permite ao remetente (postagens à vista) ou ao detentor do contrato no qual ocorreu a postagem (postagens a faturar) solicitar a suspensão da entrega ao destinatário de um objeto já inserido no fluxo postal, resultando na sua devolução ao remetente.', 0),
(10663, 'anexo', 214, NULL, 1, '2', 'SERVIÇOS VINCULADOS', '2.1 São vinculados à Entrega Interativa, os seguintes serviços:', 1),
(10664, 'anexo', 214, 10663, 4, 'a', 'SEDEX Hoje;', '', 2),
(10665, 'anexo', 214, 10663, 4, 'b', 'SEDEX 10;', '', 3),
(10666, 'anexo', 214, 10663, 4, 'c', 'SEDEX 12;', '', 4),
(10667, 'anexo', 214, 10663, 4, 'd', 'SEDEX;', '', 5),
(10668, 'anexo', 214, 10663, 4, 'e', 'PAC;', '', 6),
(10669, 'anexo', 214, 10663, 4, 'f', 'Carta Registrada;', '', 7),
(10670, 'anexo', 214, 10663, 4, 'g', 'Remessa Econômica e Expressa Talão e Cartões Diversos;', '', 8),
(10671, 'anexo', 214, 10663, 4, 'h', 'Remessa Econômica e Expressa Órgãos de Trânsito;', '', 9),
(10672, 'anexo', 214, 10663, 4, 'i', 'e-Carta;', '', 10),
(10673, 'anexo', 214, 10663, 4, 'j', 'Mini Envios.', '', 11),
(10674, 'anexo', 214, NULL, 1, '3', 'PÚBLICO-ALVO', '3.1 Todos os remetentes dos serviços relacionados no item 2.', 12),
(10675, 'anexo', 214, NULL, 1, '4', 'SUSPENSÃO DA ENTREGA', '4.1 Poderá comandar a suspensão da entrega:', 13),
(10676, 'anexo', 214, 10675, 4, 'a', 'nas solicitações via webservice do Sistema de Gerenciamento de Postagens - SIGEP WEB: qualquer cliente remetente que possua contrato com os Correios e realize integração via webservices para a pré-postagem por meio do SIGEP WEB;', '', 14),
(10677, 'anexo', 214, 10675, 4, 'b', 'nas solicitações via Portal Correios ou SuperApp dos Correios: qualquer cliente remetente, desde que esteja autenticado com o idCorreios, dono do contrato em que o objeto foi postado, para objetos postados a faturar; ou informe o idtiquete (SARA) ou o idAtendimento (Correios Atende) correspondente ao objeto, para objetos à vista;', '', 15),
(10678, 'anexo', 214, 10675, 4, 'c', 'nas solicitações via Interface de Programação de Aplicação do Sistema de Rastreamento de Objetos - API SRO Interatividade, do Correios Web Service - CWS: qualquer cliente remetente, que possua contrato com os Correios e realize integração;', '', 16),
(10679, 'anexo', 214, 10675, 4, 'd', 'nas solicitações via Usuário Sistema de Entrega Interna - SEIN: via gestor de relacionamento, seguindo critérios de benefícios estabelecido na Política Comercial, conforme matriz de relacionamento;', '', 17),
(10680, 'anexo', 214, 10675, 4, 'e', 'Correios Empresas: o cliente poderá realizar a suspensão dos objetos que foram faturados em seu contrato.', '', 18),
(10681, 'anexo', 214, NULL, 1, '5', 'RECLAMAÇÕES POR DEVOLUÇÃO INDEVIDA', '5.1 Não são aceitas:\na) reclamações por devolução indevida realizadas pelo destinatário com solicitação de suspensão de entrega, uma vez que o objeto pertence ao remetente até sua entrega;\nb) reclamações por devolução indevida realizadas pelo remetente com solicitação de suspensão de entrega cuja postagem tenha sido realizada em contrato de terceiros, pois, nas postagens a faturar, a solicitação de suspensão de entrega é realizada exclusivamente pelo detentor do contrato no qual ocorreu a postagem.', 19),
(10682, 'anexo', 214, NULL, 1, '6', 'CANCELAMENTO DA SOLICITAÇÃO', '6.1 Não são aceitas solicitações para o cancelamento do comando de suspensão da entrega ao destinatário.', 20),
(10683, 'anexo', 214, NULL, 1, '7', 'INDENIZAÇÃO POR NÃO PRESTAÇÃO DOS SERVIÇOS', '7.1 Não haverá devolução de valores por:\na) serviços não prestados para objeto cuja suspensão da entrega tenha sido solicitada pelo remetente;\nb) objeto entregue ao destinatário após o registro da solicitação de suspensão de entrega, pois a efetividade da suspensão não é garantida. O atendimento à solicitação depende de viabilidade técnica e operacional dos Correios.', 21),
(10684, 'anexo', 214, NULL, 1, '8', 'RECLAMAÇÃO POR ATRASO', '8.1 Não serão aceitas reclamações por atraso cuja suspensão da entrega tenha sido solicitada pelo contratante.', 22),
(10685, 'anexo', 214, NULL, 1, '9', 'REGISTRO DE LEITURA', '9.1 O Sistema de Rastreamento de Objetos - SRO registrará automaticamente no histórico do objeto, o status “Objeto será devolvido por solicitação do contratante/remetente” ou o status de “conferido” pela unidade, mesmo que o objeto não tenha sido incluído em Lista de Objetos Entregues ao Carteiro - LOEC ou na Lista de Distribuição Interna - LDI.', 23),
(10686, 'anexo', 214, NULL, 1, '10', 'EXIBIÇÃO DO STATUS NO SRO INTRANET', '10.1 Quando um objeto recebe uma solicitação de suspensão de entrega, a solicitação é registrada no rastreamento do objeto, de acordo com a interface realizada para registro, conforme exemplos abaixo no SRO Intranet (interno, para os Correios).\n10.2 Solicitação de suspensão de entrega registrada diretamente pelo cliente por meio de web service do SIGEP WEB, exibida como na figura abaixo:\n10.3 Solicitação de suspensão de entrega registrada diretamente pelo cliente por meio do Portal Correios, exibida como na figura abaixo:\n10.4 Solicitação de suspensão de entrega registrada pelo usuário interno, via SEIN, exibida como na figura abaixo:\n10.5 Solicitação de suspensão de entrega registrada pelo Fale Conosco (MANCAT 16/31), exibida como na figura abaixo:\n* * * * *', 24),
(10687, 'anexo', 216, NULL, 1, '1', 'PROCEDIMENTOS DA UNIDADE DE DISTRIBUIÇÃO', '', 0),
(10688, 'anexo', 216, 10687, 2, '1.1', 'Ler o código do objeto para lançamento na Lista de Objetos Entregues ao Carteiro - LOEC ou na Lista de Distribuição Interna - LDI;', '', 1),
(10689, 'anexo', 216, 10688, 3, '1.1.1', 'Identificar tela de questionamento exibida no computador, com a pergunta: “Entrega bloqueada ao destinatário. O objeto será distribuído ao remetente por esta unidade?”, conforme imagem abaixo:', '', 2),
(10690, 'anexo', 216, 10688, 3, '1.1.2', 'Observar no pacote a existência ou não de marcação que sinalize se o objeto está em devolução.', '', 3),
(10691, 'anexo', 216, 10688, 3, '1.1.3', 'Identificar que há sinalização de devolução:', 'a) selecionar a opção “SIM” na tela;\nb) lançar objeto na LOEC ou na LDI;', 4),
(10692, 'anexo', 216, 10688, 3, '1.1.4', 'Identificar que não há sinalização de devolução:', 'a) selecionar a opção “NÃO” na tela;\nb) identificar tela de orientação exibida no computador, conforme imagem abaixo:\nc) selecionar a opção “OK”;\nd) realizar o processo de devolução ao remetente, conforme descrito no Manual de Distribuição e Coleta -  MANDIS 2/6.\nNota 1: a existência de marcação que sinalize que o objeto está ou não em devolução é o principal indicativo a ser observado no item 2.4.2, mas não exclui outras avaliações. Nos casos em que, por diversos motivos, não houver sinalização no objeto, mas a unidade certificar-se pelo rótulo de endereçamento que ela é a responsável pela devolução do objeto ao remetente, o objeto poderá ser lançado na LOEC/LDI.\nNota 2: a unidade deve realizar normalmente as demais atividades do processo de abertura, triagem e ordenamento de objetos, conforme descrito no MANDIS 2/2\n* * * * *', 5),
(10693, 'anexo', 218, NULL, 1, '1', 'DIMENSÃO', 'a) Altura: 5 cm\nb) Comprimento: 10 cm\n* * * * *', 0),
(10694, 'anexo', 220, NULL, 1, '1', 'FINALIDADE', '1.1 Estabelecer as regras específicas de aceitação dos objetos postados em unidades de atendimento via pré-lista de postagem (PLP) geradas por terceiros.\n1.2 As validações acontecem no Sistema Validador de Postagens (SVP), Sistema de Automação da Rede de Atendimento (SARA) e deverão ser feitas com base nas informações apresentadas de valor, CEP de origem e destino e a unidade em que está havendo a postagem.', 0),
(10695, 'anexo', 220, NULL, 1, '2', 'PÚBLICO ALVO', '2.1 Empresa que atua como intermediadora de comércio eletrônico, que tenha optado pelas regras (ex: limites de peso, dimensões, CEP de origem etc), para aceitação ou recusa de encomendas durante a postagem.', 1),
(10696, 'anexo', 220, NULL, 1, '3', 'CRITÉRIOS', '3.1 Quanto ao CEP de origem e unidade de postagem.\n3.1.1 O objeto será recusado, durante o procedimento operacional de atendimento, se o preço informado pelo Sistema de Gestão de Preços e Benefícios (SGPB), considerando CEP da unidade de postagem para CEP de destino informado na PLP for maior, se comparado às informações de preço, considerando CEP origem e o CEP destino informados na PLP.\nNOTA: durante o procedimento operacional de atendimento, a postagem será aceita, se constatado durante a aplicação da regra descrita no item 3.1.1 que o preço do serviço informado é menor ou igual ao exposto na PLP.\n3.1.2 Caso exista divergência de informação do CEP de origem informado na PLP se comparado à informação do rótulo de endereçamento aposto no objeto e enseje majoração de preço do serviço, a etiqueta deverá continuar válida, para postagem do objeto na área de abrangência da localidade informada na PLP.\n3.1.3 No caso descrito no item 3.1.2, o SVP apresentará a seguinte mensagem em tela de validação: “Atenção (33): A encomenda está em desacordo com as regras de prestação do serviço. O remetente deverá entrar em contato com o emissor da pré-postagem.”\nExemplo: PLP gerada onde consta objeto PAC com CEP de origem 71070-640 e CEP de destino 43840-000, valor: R$ 31,00. A postagem aconteceria em uma unidade cujo CEP de origem é 74899-899. Ao verificar o valor da postagem no SGPB, o atendente identifica o valor: R$ 37,10. Portanto, como o valor é superior ao que foi considerado na emissão da PLP, o atendente deverá recusar o objeto, sem invalidar a etiqueta de postagem.\n3.2 Quanto ao CEP de destino.\n3.2.1 Durante o procedimento operacional de atendimento, o objeto será recusado, se houver divergência de informação relativa ao CEP de destino informada no rótulo de endereçamento aposto no objeto àquele inserido PLP.\n3.2.2 Quando for realizada a leitura do código de barras do CEP de destino, o SARA fará a comparação entre as informações da etiqueta de postagem e a que foi gravada no SIGEP WEB.\n3.2.3 No caso de divergências entre os CEP’s, constatada durante o procedimento operacional de atendimento, o SARA informará a seguinte mensagem: “Houve divergência entre o CEP de destino constante no rótulo de endereçamento e o CEP de destino gravado na PLP. Confirma a informação?”\n3.2.3.1 O SARA permitirá ao Colaborador duas opções de respostas “SIM” e “NÃO”, para que o atendente verifique se ocorreu procedimento operacional de atendimento inadequado (ex: leitura/digitação do SRO no campo CEP).\n3.2.3.2 Se selecionado a opção “NÃO”, será permitida a alteração do CEP. Caso seja selecionada a opção “SIM”, a etiqueta será cancelada.\n3.2.4 No caso da etiqueta cancelada, a mensagem na tela no SVP será: “Atenção (55): CEP Destino no Rótulo de Endereçamento é divergente do constante no sistema!”.\nExemplo: PLP gerada para objeto SEDEX com CEP de origem 71070-640 e CEP de destino 43840-000. No ato da postagem, o atendente faz a leitura do código de barras do CEP de destino impresso na etiqueta e o SARA retorna mensagem de que o CEP é divergente daquele informado na PLP. Com a mensagem de inconsistência em tela, o atendente responde que NÃO, ajusta o CEP de destino e efetua a postagem.\n3.3 Quanto ao peso e medidas\n3.3.1 Recusar objetos que o peso real e as medidas estejam fora das regras de aceitação de peso e medidas, disponíveis no endereço: http://www.correios.com.br/para-voce/correios-de-a-a-z/limites-de-dimensoes-e-peso\n3.3.2 A etiqueta continuará válida, pois se o cliente retornar como objeto em consonâncias com as regras de aceitação poderá ser postado.\n3.3.3 O objeto será recusado se a diferença do peso real aferido pelo atendente, durante o procedimento operacional de atendimento, for maior, que o peso (kg) informado na PLP somado à “Variação de Peso” (XX kg) permitida, definida pelo cliente.\nOBS: O campo “Variação de Peso” (XX kg) deverá estar parametrizado no cadastro do contrato/cliente.\n3.3.4 Os casos de divergências de peso real aferido pelo atendente, durante o procedimento operacional de atendimento, serão alertados por meio do SVP, que apresentará a seguinte mensagem: “Atenção (99): A encomenda está em desacordo com as regras de prestação do serviço. O remetente deverá entrar em contato com o emissor da pré-postagem.”\n3.3.5 O objeto será recusado se a diferença do peso cubado, aferido pelo atendente durante o procedimento operacional de atendimento, for maior que que 5 kg e maior que o peso (kg) informado na PLP somado à “Variação de Peso” (XX kg) permitida, definida pelo cliente.\n3.3.6 Os casos de divergências de peso cubado, serão alertados por meio do SVP, que apresentará a seguinte mensagem: “Atenção (88): A encomenda está em desacordo com as regras de prestação do serviço. O remetente deverá entrar em contato com o emissor da pré-postagem.”\nExemplos:\nVariação de Peso a pedido do contratante (5 kg);\nPeso indicado na PLP = 6000 gramas;\nPostagem de uma encomenda\nPeso real (aferido pelo atendente) = 6,4 kg;\nPeso cubado (aferido pelo atendente) = (L = 35 x C = 35 x A = 35) / 6000 = 7,15 kg.\nPara a regra do peso real aferido pelo atendente:\n(6000 + 5000) > 6400?\n(11000) > 6400? Sim! Postagem liberada.\nPara a regra do peso cubado aferido pelo atendente:\nCondição 1: 7150 é maior que 5000? Sim! então deve-se comparar entre os dois pesos aferidos (real e cubado).\nCondição 2: 7150 é maior que 6400? Sim! peso de referência será 7150 e será cobrado pelo peso cubado.\nCondição 1 e Condição 2 são positivos? Sim\nVerificar a regra de peso cubado no sistema:\n(6000 + 5000) > 7150?\n(11000) > 7150? Sim! Postagem liberada.\nRecusa de uma encomenda com peso real aferido\nPeso real (aferido pelo atendente) = 13,4 kg;\nPeso cubado (aferido pelo atendente) = (L = 35 x C = 35 x A = 35) / 6000 = 7,15 kg.\nPara a regra do peso real:\n(6000 + 5000) > 13400?\n(11000) > 13400? Não! Alerta (99).\nNão verifica a regra de peso cubado, já que houve a impossibilidade de postagem pelo peso real aferido.\nRecusa de uma encomenda com peso cubado aferido\nPeso real (aferido pelo atendente) = 10,4 kg;\nPeso cubado (aferido pelo atendente) = (L = 40 x C = 50 x A = 35) / 6000 = 11,67 kg.\nPara a regra do peso real:\n(6000 + 5000) > 10400?\n(11000) > 10400? Sim! Postagem Liberada.\nPara a regra do peso cubado aferido pelo atendente:\nCondição 1: 11670 é maior que 5000? Sim! então deve-se comparar entre os dois pesos aferidos (real e cubado).\nCondição 2: 11670 é maior que 10400? Sim! peso de referência será 11670 e será cobrado pelo peso cubado.\nCondição 1 e Condição 2 são positivos? Sim\nVerificar a regra de peso cubado no sistema:\n(6000 + 5000) > 11670?\n(11000) > 11670? Não! Alerta (88).\n* * * * *', 2),
(10697, 'anexo', 222, NULL, 1, '1', 'Funcionalidade do Sistema de Rastreamento de Objetos - SRO que impede a entrega da encomenda ao destinatário, quando já indenizada por extravio.', '', 0),
(10698, 'anexo', 222, NULL, 1, '2', 'SERVIÇOS VINCULADOS', '2.1 Todos os serviços de encomendas nacionais: SEDEX Hoje, SEDEX 10, SEDEX 12, SEDEX, PAC e Correios Mini Envios, incluindo também a Logística Reversa.', 1),
(10699, 'anexo', 222, NULL, 1, '3', 'PÚBLICO-ALVO', '3.1 Pessoas físicas sem contrato e pessoas jurídicas com e sem contrato.', 2),
(10700, 'anexo', 222, NULL, 1, '4', 'BLOQUEIO DO OBJETO', '4.1 A solicitação de bloqueio é realizada pela equipe do Fale Conosco, conforme segue:', 3),
(10701, 'anexo', 222, 10700, 4, 'a', 'ao SRO, quando confirmado o sinistro de objeto postado em contrato;', '', 4),
(10702, 'anexo', 222, 10700, 4, 'b', 'ao ERP - módulo indenizações, no ato da aprovação da indenização, para objeto postado à vista ou de Logística Reversa.', '', 5),
(10703, 'anexo', 222, NULL, 1, '5', 'DESBLOQUEIO DO OBJETO', '5.1 Não há desbloqueio do SRO para lançamento de baixa corretiva, após a efetivação do bloqueio pela interface do Fale Conosco, exceto se houver solicitação do remetente/contratante.', 6),
(10704, 'anexo', 222, NULL, 1, '6', 'INDENIZAÇÃO POR EXTRAVIO', '6.1 É assegurada indenização em caso de extravio de objeto, mediante pedido por parte do remetente/contratante, por meio de registro de “Solicitação de Ressarcimento” no Fale Conosco.\n6.1.1 As regras de indenização por extravio estão definidas no MANCAT 16/3/2.', 7),
(10705, 'anexo', 222, NULL, 3, '6.1.2', 'O valor relativo à indenização por extravio é pago da seguinte forma:', '', 8),
(10706, 'anexo', 222, 10705, 4, 'a', 'crédito em fatura: cliente pessoa jurídica com contrato;', '', 9),
(10707, 'anexo', 222, 10705, 4, 'b', 'crédito em conta corrente ou poupança: cliente pessoa física e jurídica sem contrato, que indica uma agência e conta bancária quando do registro da solicitação de ressarcimento, ou para cliente pessoa jurídica com contrato, desde que haja previsão contratual.', 'Nota: o prazo de liberação do pagamento de indenização por extravio é de 30 (trinta) dias, contados a partir da resposta procedente.', 10),
(10708, 'anexo', 222, NULL, 1, '7', 'INDENIZAÇÃO POR NÃO PRESTAÇÃO DE SERVIÇO', '7.1 É assegurada indenização por não prestação de serviço, mediante constatação de devolução ao remetente de objeto indenizado por extravio, composta pelo valor da remessa e dos serviços adicionais eventualmente adquiridos na postagem.\n7.2 O valor relativo à indenização por não prestação de serviço é pago com crédito em fatura, ao mesmo tempo em que é realizado o débito do valor pago pela indenização por extravio, quando cliente com contrato.', 11),
(10709, 'anexo', 222, NULL, 1, '8', 'RECUPERAÇÃO DA RECEITA DE INDENIZAÇÃO POR EXTRAVIO DE OBJETO DEVOLVIDO AO REMETENTE', '8.1 A recuperação da receita de objeto indenizado por extravio e devolvido ao remetente só acontece para cliente com contrato, cuja postagem tenha sido realizada a faturar.\n8.2 Confirmada a devolução ao remetente de objeto indenizado por extravio, é realizado o débito em fatura do valor referente à Indenização Automática - IA ou ao Valor Declarado - VD, caso contratado, mantendo apenas o valor da indenização paga pelo serviço postal que não foi prestado, conforme MANCAT 14/2.\n8.3 Cliente com postagem de encomenda à vista ou de Logística Reversa, o ressarcimento e bloqueio de entrega do objeto ocorre em 30 (trinta) dias, após o cadastramento da indenização. Caso o objeto seja localizado, é encaminhado diretamente para refugo.\n* * * * *', 12),
(10710, 'anexo', 224, NULL, 1, '1', 'ORIENTAÇÕES', '1.1 As medidas preventivas contra as violações do regime de privilégio postal devem ter as características de alerta e de orientação quanto às atividades exercidas pelas empresas suspeitas de infração, configuradas como de reserva legal dos Correios, à luz da legislação vigente.\n1.2 As reuniões realizadas com empresa suspeitas de infração, tanto as que prestam serviços de entrega de objetos sujeitos ao regime de exclusividade, quanto as que utilizam desses serviços, deverão ser realizadas pela força de vendas e, sempre que possível com a presença dos respectivos gerentes e as negociações consignadas através de atas.\n1.3 A força de vendas deverá elaborar relatório técnico com todas as informações relacionadas ao processo de apuração e negociação com o cliente, incluindo o pedido de informações sobre os serviços contratados por concorrência em caso de editais públicos de licitação.\n* * * * *', 0),
(10711, 'anexo', 225, NULL, 1, '1', 'FINALIDADE', '1.1 Proporcionar informações aos órgãos envolvidos a respeito da fundamentação legal do regime de exclusividade do serviço postal dos Correios, de forma a uniformizar os procedimentos a serem adotados nos casos com indícios e/ou naqueles onde, de fato, esteja ocorrendo violação do privilégio do serviço postal.', 0);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(10712, 'anexo', 225, NULL, 1, '2', 'BASE LEGAL', '2.1 Fundamentação Legal do Regime de Exclusividade do Serviço Postal dos Correios\n2.1.1 Os serviços Postais e de Telegramas foram outorgados aos Correios em regime de exclusividade mediante o Decreto-lei 509, de 20/03/69, artigo 2 (inciso I) e estão regulados pela Lei 6.538, de 22/06/78.\n2.1.2 Os serviços Postais e de Telegramas, em sendo públicos e de competência da União, conforme se entende dos artigos 21 (inciso X) e 22 (inciso V) da Constituição Federal, só podem ser executados por outras pessoas jurídicas, que não a União, se forem descentralizados, ou seja, se transferida a execução por outorga (mediante lei) ou delegação, mediante concessão ou permissão segundo o Art. 175 da Constituição Federal, nos casos das AGFs e por convênios nas demais unidades operadas por terceiros, se for o caso.\n2.2 Serviços Postais Prestados pelos Correios em Regime de Exclusividade\n2.2.1 A Lei nº 6.538/1978 (Lei Postal), artigo 9º prevê que são exploradas pela União, em regime de monopólio, as seguintes atividades postais:\na) recebimento, transporte e entrega, no território nacional, e a expedição, para o exterior, de cartão e cartão-postal;\nb) recebimento, transporte e entrega, no território nacional, e a expedição, para o exterior, de correspondência agrupada;\nc) fabricação, emissão de selos e de outras fórmulas de franqueamento postal.\n2.2.2 Dependem de prévia e expressa autorização da empresa exploradora do serviço postal:\na) venda de selos e outras fórmulas de franqueamento postal;\nb) fabricação, importação e utilização de máquinas de franquear correspondência, bem como de matrizes para estampagem de selo ou carimbo postal.\n2.2.3 Não se incluem no regime de monopólio:\na) transporte de carta ou cartão-postal, efetuado entre dependências da mesma pessoa jurídica, em negócios de sua economia, por meios próprios, sem intermediação comercial;\nb) transporte e entrega de carta e cartão-postal; executados eventualmente e sem fins lucrativos, na forma definida em regulamento.\"\n2.2.4 A Lei 6.538/1978 (Lei Postal), artigo 27º, prevê que o serviço público de telegrama é explorado pela União em regime de monopólio.\n2.3 Definição dos Serviços Considerados como Integrantes do Regime de Exclusividade do Serviço Postal dos Correios\n2.3.1 A Lei nº 6.538/1978 (Lei Postal), artigo 47º apresenta a definição dos serviços integrantes do regime de exclusividade do serviço postal dos Correios, conforme a seguir:\na) carta - objeto de correspondência, com ou sem envoltório, sob a forma de comunicação escrita, de natureza administrativa, social, comercial, ou qualquer outra, que contenha informação de interesse específico do destinatário;\nb) cartão-postal - objeto de correspondência, de material consistente, sem envoltório, contendo mensagem e endereço;\nc) cecograma - objeto de correspondência impresso em relevo, para uso dos cegos.\nNota: considera-se também cecograma, o material impresso para uso dos cegos.\nd) correspondência - toda comunicação de pessoa a pessoa, por meio de carta, através da via postal, ou por telegrama;\ne) correspondência agrupada - reunião, em volume, de objetos da mesma ou de diversas naturezas, quando, pelo menos um deles, for sujeito ao monopólio postal, remetidos a pessoas jurídicas de direito público ou privado e/ou suas agências, filiais ou representantes;\nf) franqueamento postal - pagamento de tarifa e, quando for o caso, do prêmio, relativos a objeto postal. diz-se também da representação da tarifa;\ng) selo - estampilha postal, adesiva ou fixa, bem com a estampa produzida por meio de máquina de franquear correspondência, destinadas a comprovar o pagamento da prestação de um serviço postal;\nh) telegrama - mensagem transmitida por sinalização elétrica ou radioelétrica, ou qualquer outra forma equivalente, a ser convertida em comunicação escrita, para entrega ao destinatário.\n2.4 Objetos Incluídos nos Conceitos dos Serviços Prestados em Regime de Exclusividade pelos Correios\n2.4.1 Segundo art. 47 da Lei nº 6.538/1978 (Lei Postal), carta é definida como objeto de correspondência, com ou sem envoltório, sob a forma de comunicação escrita, de natureza administrativa, social, comercial, ou qualquer outra, que contenha informações de interesse específico do destinatário. Por conseguinte, os seguintes objetos podem ser incluídos nos conceitos dos serviços prestados em regime de exclusividade pelos Correios:\na) qualquer documento ou mensagem, escrita à mão ou por meio mecanizado, de qualquer natureza, que contenha informação de interesse específico do destinatário, independentemente de envoltório;\nb) boletos, faturas, carnês, contas, notas fiscais ou quaisquer outros documentos relacionados a cobranças, sejam elas realizadas por entes públicos ou privados;\nc) notificações administrativas, tais como tributos, multas ou quaisquer outras modalidades de comunicação entre a Administração Pública de qualquer ente federativo e os administrados ou mesmo de entidades públicas distintas entre si;\nd) documentos bancários, tais como cartões magnéticos, talões de cheque e posições bancárias;\ne) títulos de crédito, como duplicatas e notas promissórias;\nf) contratos, pareceres e outros instrumentos de natureza jurídica;\ng) certificados de aprovação ou conclusão e certificados de regularidade em geral;\nh) cartão de programa de fidelidade, cartão de plano de seguro, cartão de título de turismo, cartão de plano de saúde, cartão alimentação/refeição e similares;\ni) extratos diversos de interesse exclusivo do destinatário;\nj) telegramas: mensagem transmitida por sinalização elétrica ou radioelétrica, ou qualquer outra forma equivalente, a ser convertida em comunicação escrita, para entrega ao destinatário (art. 47 da Lei Postal);\nk) malotes ou serviço de envio de correspondências agrupadas - “reunião, em volume, de objetos da mesma ou de diversas naturezas, quando, pelo menos um deles, for sujeito ao monopólio postal, remetidos a pessoas jurídicas de direito público ou privado e/ou suas agências, filiais ou representantes” (art. 47 da Lei Postal).\nNota: importante considerar que as condições de realização da entrega, incluindo meios de transporte utilizado e prazos não alteram a natureza do objeto e não podem ser utilizadas como parâmetro para definição dos limites do privilégio postal.\n* * * * *', 1),
(10713, 'anexo', 227, NULL, 1, '1', 'FORMATADORES', '1.1 A criação de um novo tipo postal, é de responsabilidade dos Órgãos Formatadores, conforme a seguir:\nDepartamento de Gestão de Serviços Nacionais - DEPRO da Diretoria de Negócios - DINEG: Encomendas, Mensagem, Marketing Direto, Serviços Telemáticos e Físicos Digitais e Remessa Expressa;\nDepartamento de Gestão de Produtos Internacionais - DEINT da Diretoria de Negócios - DINEG: Serviços internacionais;\nDepartamento de Logística - DELOG da Diretora de Operações - DIOPE:  Soluções Customizadas em Logística.\n1.2 Prefixos e tipos postais por formatador:\nEncomendas e Malote (A, D, O, P, Q, S, T, W, Z);\nMensagem, Marketing Direto, Serviços Telemáticos Físicos e Digitais e Remessa Expressa (B, F, G, J, M, Y);\nInternacional (C, E, K, L, N, R, U, V, X);\nSoluções Customizadas em Logística (H, I).\n1.3 Gestor Funcional: Departamento de Negócios e Plataformas Digitais - DEDIG/DINEG\n* * * * *', 0),
(10714, 'anexo', 228, NULL, 1, '4', 'SÍMBOLOS DE INÍCIO E TÉRMINO', 'O símbolo de término é sempre o mesmo, independentemente do tipo de código 128 usado.\nCÁLCULO DO DÍGITO VERIFICADOR DO CÓDIGO 128\nO cálculo caractere verificador é feito por meio do algoritmo Módulo 103, que é descrito a seguir:\ncada caractere a ser codificado recebe um valor, retirado da tabela ASCII;\né atribuído um peso para cada caractere, de acordo com a sua posição;\nmultiplica-se o valor de cada caractere pelo seu peso correspondente;\nsoma-se o resultado de todas as multiplicações do passo 3;\no resultado anterior é dividido por 103;\no resto da divisão feita no passo 5 é o dígito verificador.\nNota: não confundir dígito verificador do código 128 com o dígito verificador do número de registro e Código de Endereçamento Postal - CEP.\nDEFINIÇÃO\nA Etiqueta de Tipo Postal contém as informações que individualizam cada objeto postado nos Correios como registrado, constante no envoltório da mesma em algarismos e em código de barras padrão 128, o qual deverá ser lido pelos sistemas de triagem de objetos registrados e por todos os equipamentos que compõem o Sistema de Rastreamento de Objetos.\nFORMATAÇÃO\nA etiqueta possui dimensões apropriadas ao leiaute necessário, à acomodação dos campos com as informações específicas de cada tipo de registro e ao espaço necessário para a impressão do código de barras e de sua linha de equivalência, garantidas as zonas de silêncio do mesmo. Estas dimensões deverão, também, estar de acordo com a área definida para sua utilização nas encomendas dos Correios;\nQuanto ao código de barras, existem várias possibilidades de tamanho, em função da dimensão e dos subsets utilizados. Para cada caso específico, deve-se verificar se o tamanho do código a ser gerado é compatível com o tamanho definido para a Etiqueta. Estas dimensões deverão, também, estar de acordo com a área definida para sua utilização nas encomendas dos Correios.\nCOMPOSIÇÃO\nA Etiqueta Tipo Postal possui a seguinte estrutura:\ndois dígitos representados por letras indicando o tipo postal, família/segmento, ou modalidade de serviço;\noito dígitos numéricos sequenciais que individualizam os objetos;\num dígito verificador numérico;\ndois dígitos representados por letras para indicação do país de origem do objeto (no nosso caso, BR).\n8.2 A parte numérica é composta por duas partes:\na primeira é composta por 8 dígitos, referente a uma faixa numérica;\na segunda pelo dígito verificador.\nExemplo: FE 400 026 101 BR.\nCARACTERÍSTICA DE CONTRASTE DE IMPRESSÃO\nO código de barras 128 deverá ser impresso de modo a atender às seguintes características de contraste e qualidade de impressão:\nPrint Contrast Signal (PCS) deverá ser de no mínimo 70% (setenta por cento), medido mediante o uso de um campo amostral igual a um círculo de diâmetro 0,6L, onde “L” é a largura nominal das barras impressas;\nA Minimum ReflCorreiosive Difference (MRD) deverá ser 30% (trinta por cento).\nPOSICIONAMENTO DA ETIQUETA DO NÚMERO DE REGISTRO\n10.1 A etiqueta do número de registro deve ser posicionada na face de maior área da encomenda, onde deve constar todo o endereçamento, inclusive a etiqueta de Código de Endereçamento Postal - CEP.\n* * * * *', 0),
(10715, 'anexo', 234, NULL, 1, '1', 'SERVIÇO', '', 0),
(10716, 'anexo', 234, 10715, 2, '1.1', 'Ao contratar o serviço, o cliente informa os endereços desejados para origem e destino de cada trecho (percurso) e os respectivos dias a serem programados para a coleta semanal do malote (frequência).', '', 1),
(10717, 'anexo', 234, 10716, 3, '1.1.1', 'O serviço de Malote, no contrato múltiplo, pode conter diversos endereçamentos de origem entre os percursos contratados e operar dentro de uma mesma cidade ou entre localidades diferentes.', '', 2),
(10718, 'anexo', 234, 10716, 3, '1.1.2', 'A quantidade de coleta semanal deve ser igual para o endereço de origem e para o endereço de destino.', '', 3),
(10719, 'anexo', 234, 10716, 3, '1.1.3', 'Os dias da semana podem ser iguais ou diferentes para a coleta na origem e no destino.', '', 4),
(10720, 'anexo', 234, 10716, 3, '1.1.4', 'A previsão da entrega do malote corresponderá ao prazo estipulado para o trecho, que pode ser consultado no calculador de preços e prazos nacionais, no portal dos Correios.', 'Nota: O simulador de preços para o serviço de Malote está disponível no endereço: https://www2.correios.com.br/encomendas/malote/simular_preco.cfm.', 5),
(10721, 'anexo', 234, NULL, 1, '2', 'SERVIÇOS ADICIONAIS', '', 6),
(10722, 'anexo', 234, 10721, 2, '2.1', 'Os clientes poderão contratar serviços adicionais de coleta e entrega programada para atender situações especiais, nas quais o horário convencional não atenda à sua necessidade, mediante o pagamento de tarifas e preços correspondentes.', '', 7),
(10723, 'anexo', 234, 10721, 2, '2.2', 'Esses serviços adicionais são:', '', 8),
(10724, 'anexo', 234, 10723, 4, 'a', 'Coleta Programada Diurna: com faixas horárias entre 8h e 18h, conforme opção do cliente;', '', 9),
(10725, 'anexo', 234, 10723, 4, 'b', 'Coleta Programada Noturna: com faixas horárias entre 18h e 20h, desde que seja possível a expedição no mesmo dia;', '', 10),
(10726, 'anexo', 234, 10723, 4, 'c', 'Entrega Programada Diurna: com faixas horárias entre 8h e 18h, conforme opção do cliente;', '', 11),
(10727, 'anexo', 234, 10723, 4, 'd', 'Entrega Programada Noturna: com faixas horárias entre 18h e 20h.', '', 12),
(10728, 'anexo', 234, 10721, 2, '2.3', 'Os serviços adicionais serão oferecidos em local onde houver viabilidade operacional e desde que o malote possa ser encaminhado no mesmo dia da sua coleta.', '', 13),
(10729, 'anexo', 234, NULL, 1, '3', 'EMBALAGEM, CARTÃO OPERACIONAL E LACRE DE FECHAMENTO', '', 14),
(10730, 'anexo', 234, 10729, 2, '3.1', 'Embalagem', '', 15),
(10731, 'anexo', 234, 10730, 3, '3.1.1', 'Para acondicionar os documentos e objetos, deverão ser usados os modelos de malote fornecidos gratuitamente pelos Correios.', '', 16),
(10732, 'anexo', 234, 10730, 3, '3.1.2', 'Consonante o custo do insumo e a necessidade do cliente, os malotes são disponi-bilizados nos modelos: Grande (medidas 50x45x20cm, código 115100148) e Médio (medidas 41x35x14cm, código 115100130), com as especificações:', '', 17),
(10733, 'anexo', 234, 10732, 4, 'a', 'malote de náilon impermeável, na cor azul;', '', 18),
(10734, 'anexo', 234, 10732, 4, 'b', 'porta-cartão (visor), com fechamento em velcro e lingueta, para facilitar inserção e retirada do cartão operacional;', '', 19),
(10735, 'anexo', 234, 10732, 4, 'c', 'fechamento seguro e simplificado, que permite o uso de lacre plástico de segurança não reutilizável;', '', 20),
(10736, 'anexo', 234, 10732, 4, 'd', 'alça adicional para manuseio.', '', 21),
(10737, 'anexo', 234, 10730, 3, '3.1.3', 'Se no pedido de inclusão de percurso não houver menção de quantidade e tamanho de malote desejados, padronizadamente são cadastrados e fornecidos:', '', 22),
(10738, 'anexo', 234, 10737, 4, 'a', '4 (quatro) malotes, para 1 (uma) frequência semanal;', '', 23),
(10739, 'anexo', 234, 10737, 4, 'b', '6 (seis) malotes, para mais do que 1 (uma) frequência semanal.', '', 24),
(10740, 'anexo', 234, 10730, 3, '3.1.4', 'Os malotes devem ser restituídos aos Correios, em caso de substituição destes, cancelamento de percurso ou rescisão do contrato em até 5 (cinco) dias corridos, caso contrário, serão considerados como extraviados.', '3.1.4.1 Caso o malote seja extraviado ou perdido, em situação causada pelo detentor do contrato, poderá ser aplicada cobrança, conforme preços vigentes.', 25),
(10741, 'anexo', 234, 10729, 2, '3.2', 'Cartão Operacional', '', 26),
(10742, 'anexo', 234, 10741, 3, '3.2.1', 'O cartão operacional é fornecido gratuitamente pelos Correios, para endereçamento dos malotes, sendo frente e verso, medindo 14 x 14 cm.', '3.2.1.1 Em um lado constam impressos os dados referentes ao endereço de origem (volta) e no outro lado constam dados referentes ao endereço de destino (ida).', 27),
(10743, 'anexo', 234, 10741, 3, '3.2.2', 'Para conservar os dados, principalmente do código de barras, o cartão é fornecido plastificado, com os seguintes dados referentes a cada sentido (ida/volta) do referido lado do cartão:', '', 28),
(10744, 'anexo', 234, 10743, 4, 'a', 'nome fantasia;', '', 29),
(10745, 'anexo', 234, 10743, 4, 'b', 'endereço completo;', '', 30),
(10746, 'anexo', 234, 10743, 4, 'c', 'nome do serviço;', '', 31),
(10747, 'anexo', 234, 10743, 4, 'd', 'número do contrato e número de percurso separados por uma barra;', '', 32),
(10748, 'anexo', 234, 10743, 4, 'e', 'sentido 1 ida (remetente é a origem e o destinatário é o destino do percurso) ou 8 volta (remetente é o destino e destinatário é a origem do percurso);', '', 33),
(10749, 'anexo', 234, 10743, 4, 'f', 'número do malote;', '', 34),
(10750, 'anexo', 234, 10743, 4, 'g', 'tamanho do malote;', '', 35),
(10751, 'anexo', 234, 10743, 4, 'h', 'sentido: ida e volta;', '', 36),
(10752, 'anexo', 234, 10743, 4, 'i', 'distrito operacional de entrega, com seu respectivo tipo (segunda a sexta ou sábado);', '', 37),
(10753, 'anexo', 234, 10743, 4, 'j', 'sigla do centralizador de tratamento regional da unidade de coleta/entrega;', '', 38),
(10754, 'anexo', 234, 10743, 4, 'k', 'estação (representa o espaço físico, para manuseio de malotes na unidade operacional, o padrão é “B”);', '', 39),
(10755, 'anexo', 234, 10743, 4, 'l', 'CEP de origem (remetente);', '', 40),
(10756, 'anexo', 234, 10743, 4, 'm', 'código de barras;', '', 41),
(10757, 'anexo', 234, 10743, 4, 'n', 'código 2D com os mesmos dados do código de barras;', '', 42),
(10758, 'anexo', 234, 10743, 4, 'o', 'data de emissão do cartão;', '', 43),
(10759, 'anexo', 234, 10743, 4, 'p', 'data de validade do cartão (não deve ser considerada como prazo para substituição);', '', 44),
(10760, 'anexo', 234, 10743, 4, 'q', 'código de barras: da esquerda para direita, no total de 35 (trinta e cinco) dígitos, o código de barras é composto por:', 'I - 8 dígitos: CEP conforme o sentido (ida/volta);\nII - 5 dígitos: código do serviço;\nIII - 12 dígitos: compostos pelo número de percurso e zeros à esquerda;\nIV - 4 dígitos: 4 zeros;\nV - 1 dígito: 1/8, referente ao sentido 1 ida e 8 volta;\nVI - 5 dígitos: número de malote, com zeros à esquerda.', 45),
(10761, 'anexo', 234, 10729, 2, '3.3', 'Lacre de Fechamento', '', 46),
(10762, 'anexo', 234, 10761, 3, '3.3.1', 'Para fechar o malote, deverá ser usado lacre plástico descartável, adquirido no mercado, para garantir que o conteúdo permaneça seguro e inviolável.', '', 47),
(10763, 'anexo', 234, NULL, 1, '4', 'COLETA E ENTREGA', '', 48),
(10764, 'anexo', 234, 10763, 2, '4.1', 'A coleta poderá ocorrer no período de 14h as 18h e a entrega de 8h as 12h, do dia de chegada à localidade de destino.', '4.1.1 Os horários de coleta e de entrega estão sujeitos à adequação, em função de peculiaridades operacionais e de transporte nas localidades de prestação do serviço.\n4.1.2 O carteiro poderá esperar no máximo até 3 (três) minutos, para entregar o malote no endereço constante no respectivo cartão operacional e coletar o malote no local designado na lista de coleta.', 49),
(10765, 'anexo', 234, 10763, 2, '4.2', 'Em área não abrangida pela coleta e entrega domiciliária, o recebimento e a entrega do malote serão operacionalizados pelo cliente em unidade de vinculação própria, previamente definida pelos Correios, respeitado o respectivo horário limite de expedição.', '', 50),
(10766, 'anexo', 234, 10763, 2, '4.3', 'O cliente poderá aproveitar a presença do carteiro do serviço de Malote e postar de forma avulsa, o malote pertencente ao percurso ativo sem coleta prevista para aquele dia.', '', 51),
(10767, 'anexo', 234, 10763, 2, '4.4', 'O cliente poderá indicar outra unidade operacional da sua preferência, mesmo que o endereço não seja atendido pela coleta e entrega, exceto unidades que não sejam próprias dos Correios, em conformidade com o MANCAT 26/4/2.', '', 52),
(10768, 'anexo', 234, 10763, 2, '4.5', 'A coleta/entrega vertical está condicionada ao uso de elevador ou outros meios que permitam a elevação do malote.', '4.5.1 Se o local for desprovido de tal meio, o malote será entregue/retirado no térreo ou na portaria, com o porteiro, administrador, zelador ou com a pessoa indicada para esse fim.', 53),
(10769, 'anexo', 234, 10763, 2, '4.6', 'O malote que não puder ser entregue no endereço previsto em contrato permanecerá à disposição do cliente pelo prazo de 30 (trinta) dias corridos na unidade de vinculação do percurso.', '4.6.1 Esgotadas todas as possibilidades de contato com o cliente, o malote não procurado no referido prazo será encaminhado para refugo.', 54),
(10770, 'anexo', 234, NULL, 1, '5', 'PÚBLICO-ALVO', '', 55),
(10771, 'anexo', 234, 10770, 2, '5.1', 'O público-alvo do serviço de Malote são pessoas jurídicas, empresas privadas e órgãos públicos que postam correspondência agrupada.', '', 56),
(10772, 'anexo', 234, NULL, 1, '6', 'ABRANGÊNCIA', '', 57),
(10773, 'anexo', 234, 10772, 2, '6.1', 'Serviço disponível em todo território nacional, com coleta e entrega.', '', 58),
(10774, 'anexo', 234, NULL, 1, '7', 'PRAZO DE ENTREGA', '', 59),
(10775, 'anexo', 234, 10774, 2, '7.1', 'O prazo de entrega do Malote está disponível para consulta no MANNEG 6/3/2.', '', 60),
(10776, 'anexo', 234, NULL, 1, '8', 'LIMITE DE PESO', '', 61),
(10777, 'anexo', 234, 10776, 2, '8.1', 'O peso recomendado é de 20 kg, sendo admitido remessas com o máximo de 30 kg.', '', 62),
(10778, 'anexo', 234, 10776, 2, '8.2', 'Malote com peso acima de 30 kg deve ser devolvido ao cliente, para que o conteúdo seja dividido e armazenado em mais de um malote.', '', 63),
(10779, 'anexo', 234, NULL, 1, '9', 'RESTRIÇÕES', '', 64),
(10780, 'anexo', 234, 10779, 2, '9.1', 'Não serão coletados os malotes que apresentarem mau fechamento, excesso de peso, cartão operacional virado, lacre de segurança danificado ou ausente, rasgo ou danos que permitam o acesso ao conteúdo e em caso de percurso suspenso ou cancelado.', '', 65),
(10781, 'anexo', 234, 10779, 2, '9.2', 'O conteúdo inserido no malote deve estar em conformidade às restrições postais, de órgãos reguladores e leis vigentes.', '', 66),
(10782, 'anexo', 234, NULL, 1, '10', 'SISTEMA DE GERENCIAMENTO DO SERVIÇO', '', 67),
(10783, 'anexo', 234, 10782, 2, '10.1', 'O sistema corporativo para operacionalização e gestão do serviço é o Sistema Integrado de Gerenciamento de Malotes - SIGMA.', '', 68),
(10784, 'anexo', 234, 10782, 2, '10.2', 'A unidade responsável pela coleta imprime diariamente a lista emitida automaticamente pelo sistema, contendo os dados dos percursos com programação de coleta no dia.', '', 69),
(10785, 'anexo', 234, 10782, 2, '10.3', 'Essa lista impressa serve para coletar a assinatura do cliente e servirá como o comprovante da prestação do serviço.', '', 70),
(10786, 'anexo', 234, 10782, 2, '10.4', 'O código de barras do malote coletado é registrado no sistema pela sua respectiva unidade de sua coleta ou pelo seu Centro de Tratamento vinculado, para o faturamento da remessa.', '', 71),
(10787, 'anexo', 234, 10782, 2, '10.5', 'A unidade responsável pela entrega, registra no SIGMA o recebimento do malote e por meio da assinatura do cliente, na lista gerada pelo sistema, ela realiza a confirmação da entrega no mesmo sistema.', '', 72),
(10788, 'anexo', 234, NULL, 1, '11', 'PREÇOS E TARIFAS', '', 73),
(10789, 'anexo', 234, 10788, 2, '11.1', 'A tabela de precificação é única, no modelo “De/Para”: com o valor variando em função da origem, do destino e do peso, com visualização do preço diretamente na tabela.', '', 74),
(10790, 'anexo', 234, 10788, 2, '11.2', 'Os valores para serviços adicionais, indenização automática para perda e roubo, bem como os valores para cobrança de malotes não devolvidos estão localizados na guia Informações da referida tabela.', '', 75),
(10791, 'anexo', 234, 10788, 2, '11.3', 'A Tabela de preços está disponível no seguinte endereço eletrônico:', '\\\\SAC0424\\SISTEMAS\\PRECOS_TARIFAS', 76),
(10792, 'anexo', 234, NULL, 1, '12', 'FORMA DE PAGAMENTO', '', 77),
(10793, 'anexo', 234, 10792, 2, '12.1', 'O serviço será efetuado na modalidade de pagamento a faturar.', '', 78),
(10794, 'anexo', 234, NULL, 1, '13', 'FATURAMENTO', '', 79),
(10795, 'anexo', 234, 10794, 2, '13.1', 'Captação de Dados de Postagem e Cálculo da Fatura', '', 80),
(10796, 'anexo', 234, 10795, 3, '13.1.1', 'Os dados do Malote são captados no SIGMA, para serem faturados pelo seu módulo Sistema de Faturamento Regional do Malote - SFRM.', '', 81),
(10797, 'anexo', 234, 10795, 3, '13.1.2', 'Para cada percurso contratado é cobrado o Valor de Serviço Contratado - VSC, calculado considerando, no ciclo de faturamento, o somatório total de dias de coletas previstas, conforme a frequência cadastrada, para o endereço de origem e o endereço de destino do percurso, multiplicado à tarifa entre origem e destino do percurso, com remessa de 2 kg.', '', 82),
(10798, 'anexo', 234, 10795, 3, '13.1.3', 'Após o cálculo do VSC realizado, as informações são transferidas para o ERP, a fim de gerar o faturamento.', '', 83),
(10799, 'anexo', 234, 10795, 3, '13.1.4', 'Se o valor total de remessas do percurso, no ciclo de cobrança, não atingir o valor de serviço contratado previsto para o período, haverá cobrança de complementação financeira, ou seja, a diferença entre o VSC e o valor total de remessas no ciclo.', '13.1.4.1 Entretanto, se o valor de remessas exceder o VSC, o percurso será cobrado pelo valor faturado.', 84),
(10800, 'anexo', 234, 10795, 3, '13.1.5', 'O cálculo de faturamento pode ser representado pela expressão:', 'FC = (?FP + ?CF) + VSA\nNa qual:\nCF = complementação financeira dos percursos do contrato\nFC = faturamento do serviço de Malote para o contrato\nFP = faturamento dos percursos do contrato\nVSA = valor serviço adicional (coleta/entrega programada)', 85),
(10801, 'anexo', 234, 10794, 2, '13.2', 'Extrato Analítico de Fatura', '', 86),
(10802, 'anexo', 234, 10801, 3, '13.2.1', 'Além do boleto da fatura, o cliente pode consultar o extrato analítico, no qual é apresentado o detalhamento de remessas para cada percurso, ocorridas no ciclo de faturamento, contendo os seguintes campos:', '', 87),
(10803, 'anexo', 234, 10802, 4, 'a', 'a data de remessa;', '', 88),
(10804, 'anexo', 234, 10802, 4, 'b', 'a descrição do serviço;', '', 89),
(10805, 'anexo', 234, 10802, 4, 'c', 'o número do malote postado;', '', 90),
(10806, 'anexo', 234, 10802, 4, 'd', 'o CEP de destino;', '', 91),
(10807, 'anexo', 234, 10802, 4, 'e', 'a unidade de coleta; MANCAT 21/1 /2 - 10', '', 92),
(10808, 'anexo', 234, 10802, 4, 'f', 'o peso;', '', 93),
(10809, 'anexo', 234, 10802, 4, 'g', 'o valor da remessa.', '', 94),
(10810, 'anexo', 234, 10801, 3, '13.2.2', 'Os serviços adicionais e a complementação financeira, por percurso, lançamentos de débitos e créditos, quando for o caso, são discriminados no rodapé do extrato.', '', 95),
(10811, 'anexo', 234, NULL, 1, '14', 'INDENIZAÇÃO POR EXTRAVIO E/OU PERDA', '14.1 Em caso de extravio e/ou perda, a responsabilidade dos Correios limitar-se-á ao preço da remessa afetada mais o valor da indenização automática, prevista na Tabela de Preços e Tarifas do Serviço de Malote.\n14.2 A apuração e o pagamento de indenização ao cliente de Malote ocorrerá de forma centralizada, conforme previsto no MANCAN 7/5/2.', 96),
(10812, 'anexo', 234, NULL, 1, '15', 'ACESSO DO CLIENTE À PLATAFORMA DOS CORREIOS, VIA INTERNET', '', 97),
(10813, 'anexo', 234, 10812, 2, '15.1', 'O cliente solicita o acesso ao Portal Malote WEB (módulo de internet do SIGMA) ao gestor do seu contrato nos Correios, para realizar pedidos referentes ao serviço de Malote contratado.', '', 98),
(10814, 'anexo', 234, 10812, 2, '15.2', 'O gestor do contrato nos Correios realiza o pedido por meio do formulário de sistemas comerciais, disponível no Helpdesk.', '', 99),
(10815, 'anexo', 234, 10812, 2, '15.3', 'Após o cadastro, o cliente receberá e-mail do sistema contendo sua senha inicial, a qual deverá ser alterada logo após o primeiro acesso.', '', 100),
(10816, 'anexo', 234, 10815, 3, '15.3.1', 'O cadastro do usuário somente será possível após a inclusão de pelo menos um percurso no contrato, inclusive nos casos de renovação com alteração de número de contrato.', '', 101),
(10817, 'anexo', 234, 10812, 2, '15.4', 'Mediante o seu cadastro no Malote WEB, vinculado ao contrato ativo de sua gestão, o cliente poderá realizar:', '', 102),
(10818, 'anexo', 234, 10817, 4, 'a', 'cadastro e desativação de outros usuários e alteração da própria senha de usuário;', 'Nota: a senha é pessoal e intransferível. O usuário com perfil de administrador é responsável por cadastrar novos usuários e retirar acessos de usuários que não devam mais acessar as informações do contrato.', 103),
(10819, 'anexo', 234, 10817, 4, 'b', 'solicitação de novo percurso com ou sem serviço adicional de coleta/entrega programada;', '', 104),
(10820, 'anexo', 234, 10817, 4, 'c', 'solicitação de mudança dos dados de percursos ativos e de envio de malotes e/ou cartões operacionais atualizados, correspondentes ao pedido;', 'Nota: o prazo para o cadastro e fornecimento de cartões e malotes é de até 10 (dez) dias corridos.', 105),
(10821, 'anexo', 234, 10817, 4, 'd', 'pedido de cancelamento de percurso (exceto se for o único percurso ativo no contrato, o que deverá ser solicitado via gestor do contrato);', '', 106),
(10822, 'anexo', 234, 10817, 4, 'e', 'pedido de suspensão temporária de percurso ou contrato;', 'Nota: a suspensão terá duração mínima de 15 (quinze) dias e máxima de 30 (trinta) dias corridos. Para nova suspensão, observar o interstício mínimo de 6 (seis) meses, contados da data de retorno do serviço;', 107),
(10823, 'anexo', 234, 10817, 4, 'f', 'solicitação de acréscimo ou decréscimo de malote;', '', 108),
(10824, 'anexo', 234, 10817, 4, 'g', 'pedido de cartão extra, indicando acréscimo de quantidade de malotes e informando que deseja somente cartões;', '', 109),
(10825, 'anexo', 234, 10817, 4, 'h', 'consulta de segunda via de fatura;', '', 110),
(10826, 'anexo', 234, 10817, 4, 'i', 'consulta de dados cadastrados para a razão social (alterações de razão social, endereço de sede ou de cobrança, devem ser solicitadas via processo eletrônico);', '', 111),
(10827, 'anexo', 234, 10817, 4, 'j', 'acompanhamento do status de solicitações;', '', 112),
(10828, 'anexo', 234, 10817, 4, 'k', 'simulação de preço para o percurso, por quilograma;', '', 113),
(10829, 'anexo', 234, 10817, 4, 'l', 'simulação de prazo de entrega entre trechos.', '', 114),
(10830, 'anexo', 234, NULL, 1, '16', 'GENERALIDADES', '', 115),
(10831, 'anexo', 234, 10830, 2, '16.1', 'Os Correios não se responsabilizam:', '', 116),
(10832, 'anexo', 234, 10831, 4, 'a', 'pela inclusão no malote, de valor, objeto frágil ou de natureza diversa à de correspondência;', '', 117),
(10833, 'anexo', 234, 10831, 4, 'b', 'pela demora na execução dos serviços devido à omissão ou ao erro por parte do detentor do contrato;', '', 118),
(10834, 'anexo', 234, 10831, 4, 'c', 'por prejuízos indiretos e benefícios não realizados;', '', 119),
(10835, 'anexo', 234, 10831, 4, 'd', 'por objeto que, no todo ou em parte, seja confiscado ou destruído por autoridade competente, desde que haja comprovação documental;', '', 120),
(10836, 'anexo', 234, 10831, 4, 'e', 'por fraudes ou danos decorrentes do uso indevido da ferramenta de gestão disponibilizada pelos Correios;', '', 121),
(10837, 'anexo', 234, 10831, 4, 'f', 'por malote entregue, findo o prazo de 3 (três) meses para a reclamação, a contar da data da remessa;', '', 122),
(10838, 'anexo', 234, 10831, 4, 'g', 'pela falha na coleta/entrega de malote ocorrida em caso fortuito ou de força maior ou motivada pela paralisação da jornada de trabalho, independentemente de sua vontade.', '* * * * *', 123),
(10839, 'anexo', 235, NULL, 1, '1', 'ESQUEMA DE DOBRA DO CARTÃO OPERACIONAL', '1.1 Para ser plastificado, o cartão operacional apresenta o sistema de dobra, conforme gravuras abaixo:\n1.1.1 No lado ida do cartão operacional são apresentados os dados de destino cadastrados para o percurso.\n1.1.2 No lado origem do cartão operacional são apresentados os dados de origem cadastrados para o percurso.\n1.2 Detalhamento do cartão operacional de ida (destino):', 0),
(10840, 'anexo', 235, 10839, 4, 'a', 'campo 1: nome fantasia e endereço completo;', '', 1),
(10841, 'anexo', 235, 10839, 4, 'b', 'campo 2: data de impressão do cartão;', '', 2),
(10842, 'anexo', 235, 10839, 4, 'c', 'campo 3: dados do código de barras;', '', 3),
(10843, 'anexo', 235, 10839, 4, 'd', 'campo 4: data de validade (não considerar para substituição);', '', 4),
(10844, 'anexo', 235, 10839, 4, 'e', 'campo 5: nome do serviço;', '', 5),
(10845, 'anexo', 235, 10839, 4, 'f', 'campo 6: número do contrato e número do malote;', '', 6),
(10846, 'anexo', 235, 10839, 4, 'g', 'campo 7: CEP do remetente;', '', 7),
(10847, 'anexo', 235, 10839, 4, 'h', 'campo 8: código de ida 1 (endereço destino do percurso);', '', 8),
(10848, 'anexo', 235, 10839, 4, 'i', 'campo 9: número do malote;', '', 9),
(10849, 'anexo', 235, 10839, 4, 'j', 'campo 10: tamanho do malote;', '', 10),
(10850, 'anexo', 235, 10839, 4, 'k', 'campo 11: código de estação (representa o espaço físico destinado ao malote na unidade de entrega);', '', 11),
(10851, 'anexo', 235, 10839, 4, 'l', 'campo 12: código de distrito referente à entrega de segunda a sexta;', '', 12),
(10852, 'anexo', 235, 10839, 4, 'm', 'campo 13: código de distrito referente à entrega aos sábados;', '', 13),
(10853, 'anexo', 235, 10839, 4, 'n', 'campo 14: CEP do destinatário;', '', 14),
(10854, 'anexo', 235, 10839, 4, 'o', 'campo 15: sigla do centralizador de tratamento regional da unidade de entrega no endereço;', '', 15),
(10855, 'anexo', 235, 10839, 4, 'p', 'campo 16: código Data Matrix ou QR Code contendo os mesmos dados do código de barras.', '1.3 Detalhamento do cartão operacional de volta (origem):', 16),
(10856, 'anexo', 235, 10839, 4, 'a', 'campo 17: nome fantasia e endereço completo de origem;', '', 17),
(10857, 'anexo', 235, 10839, 4, 'b', 'campo 18: data de impressão do cartão;', '', 18),
(10858, 'anexo', 235, 10839, 4, 'c', 'campo 19: dados do código de barras;', '', 19),
(10859, 'anexo', 235, 10839, 4, 'd', 'campo 20: data de validade (não considerar para substituição);', '', 20),
(10860, 'anexo', 235, 10839, 4, 'e', 'campo 21: nome do serviço;', '', 21),
(10861, 'anexo', 235, 10839, 4, 'f', 'campo 22: número do contrato e número do malote;', '', 22),
(10862, 'anexo', 235, 10839, 4, 'g', 'campo 23: CEP do rementente;', '', 23),
(10863, 'anexo', 235, 10839, 4, 'h', 'campo 24: código de ida 8 (endereço origem do percurso);', '', 24),
(10864, 'anexo', 235, 10839, 4, 'i', 'campo 25: número do malote;', '', 25),
(10865, 'anexo', 235, 10839, 4, 'j', 'campo 26: tamanho do malote;', '', 26),
(10866, 'anexo', 235, 10839, 4, 'k', 'campo 27: código de estação (representa o espaço físico destinado ao malote na unidade de entrega);', '', 27),
(10867, 'anexo', 235, 10839, 4, 'l', 'campo 28: código de distrito referente à entrega de segunda a sexta;', '', 28),
(10868, 'anexo', 235, 10839, 4, 'm', 'campo 29: código de distrito referente à entrega aos sábados;', '', 29),
(10869, 'anexo', 235, 10839, 4, 'n', 'campo 30: CEP do destinatário;', '', 30),
(10870, 'anexo', 235, 10839, 4, 'o', 'campo 31: sigla do centralizador de tratamento regional da unidade de entrega no endereço;', '', 31),
(10871, 'anexo', 235, 10839, 4, 'p', 'campo 32: código Data Matrix ou QR Code contendo os mesmos dados do código de barras.', '* * * * *', 32),
(10872, 'anexo', 237, NULL, 2, '1.1', 'O estabelecimento de parcerias para a instalação e operação das unidades de atendimento operadas por meio de parceria se dará pela celebração de Acordo de Cooperação Técnica - ACT, ou Termo Convênio - TC, podendo ou não, a unidade ser instalada em ambiente compartilhado com a atividade principal da pessoa jurídica contratada/conveniada.', '', 0),
(10873, 'anexo', 237, NULL, 2, '1.2', 'O presente normativo aplica-se, no que couber, a todos os tipos de unidades de atendimento que vierem a ser criados pelos Correios para serem operados por meio de parceria com pessoas jurídicas de direito público ou privado e que tenham finalidade social, ou seja, voltados ao cumprimento da meta de universalização do atendimento definida pelo Ministério Supervisor.', '', 1),
(10874, 'anexo', 237, NULL, 2, '1.3', 'Prioritariamente, a negociação com as pessoas jurídicas municipais deve ser realizada sem ônus para os Correios.', '2.1\n3.1\n1.3.1.', 2),
(10875, 'anexo', 237, 10874, 3, '1.3.1', 'A restrição mencionada no subitem 1.3 alcança os custos com a implantação da unidade, criação de linhas de coleta/entrega dos objetos postais e deslocamento de efetivo próprio para a região.', '', 3),
(10876, 'anexo', 237, 10874, 3, '1.3.2', 'Excetuam-se da restrição mencionada no subitem 1.3 a cessão não onerosa de bens, equipamentos e mobiliários pelos Correios à pessoa jurídica contratada/conveniada, para fins de instalação e operação da unidade de atendimento.', '', 4),
(10877, 'anexo', 237, NULL, 2, '1.4', 'A oferta de parceria mediante a celebração de TC deverá ocorrer apenas quando o município estiver inserido na meta de universalização do atendimento e os custos decorrentes da operacionalização por meios próprios forem superiores ao valor correspondente ao repasse mensal.', '', 5),
(10878, 'anexo', 237, NULL, 2, '1.5', 'A aceitação de cláusulas customizadas no instrumento contratual a ser celebrado com a pessoa jurídica municipal depende de viabilidade econômico-financeira e chancela a ser emitida pela Assessoria Jurídica Estadual - ASJUR.', '', 6),
(10879, 'anexo', 237, 10878, 3, '1.5.1', 'Está vedada a criação de cláusulas customizadas que importem em majoração dos custos para os Correios com a prestação do serviço postal de atendimento na região em que se pretende instalar a unidade de atendimento.', '', 7),
(10880, 'anexo', 237, 10878, 3, '1.5.2', 'Excetuam-se da vedação de que se trata o subitem 1.5.1 os casos em que comprovadamente não seja possível a cumprimento da meta de universalização do atendimento sem a instalação da unidade de atendimento.', '', 8),
(10881, 'anexo', 237, 10878, 3, '1.5.3', 'A comprovação de que trata o subitem 1.5.2 deverá ser realizada por meio de relatório técnico circunstanciado aprovado pelo SE.', '', 9),
(10882, 'anexo', 237, NULL, 2, '1.6', 'Está vedada a criação de linhas adicionais de transporte que impliquem em aumento de custos para os Correios decorrentes da instalação de unidades de atendimento por meio de parceria.', '', 10),
(10883, 'anexo', 237, 10882, 3, '1.6.1', 'Excetuam-se da vedação mencionada no subitem 1.6 acima, os casos em que comprovadamente não seja possível a cumprimento da meta de universalização do atendimento sem a instalação da unidade de atendimento.', '', 11),
(10884, 'anexo', 237, 10882, 3, '1.6.2', 'A comprovação de que trata o subitem 1.6.1 deverá ser realizada por meio de relatório técnico circunstanciado aprovado pelo SE.', '', 12),
(10885, 'anexo', 237, NULL, 2, '1.7', 'A avaliação de viabilidade financeira é item indispensável para subsidiar a decisão pela celebração da parceria quando houver aumento de custos para os Correios, seja em razão da celebração de TC seja em decorrência da criação de obrigações contratuais tratadas na negociação, tais como, por exemplo, a criação de linhas de transporte não previstas para a localidade.', '', 13),
(10886, 'anexo', 237, 10885, 3, '1.7.1', 'Especificamente no caso de ser celebrado ACT, aplicam-se as orientações para a análise de viabilidade financeira sempre que se constatar a necessidade de criação de linhas de transporte adicionais às já existentes.', '', 14),
(10887, 'anexo', 237, NULL, 2, '1.8', 'Em decorrência da possibilidade de aumento de custos para os Correios, a criação das linhas para a realização de coletas ou entrega de objetos postais na unidade de atendimento somente poderá ser realizada se houver autorização expressa do órgão corporativo de gestão do transporte, ou conforme sua orientação técnica.', '', 15),
(10888, 'anexo', 237, NULL, 2, '1.9', 'A avaliação técnica de viabilidade para a celebração da parceria, quando necessária à continuidade do processo, deverá ser inserida no processo administrativo de gestão da unidade de atendimento por meio de relatório técnico circunstanciado que contenha, no mínimo, as seguintes informações:', '', 16),
(10889, 'anexo', 237, 10888, 4, 'a', 'impactos financeiros decorrentes da não celebração do TC ou ACT com condições especiais, inclusive considerando os custos para a criação de linhas de transporte e deslocamento de efetivo próprio dos Correios;', '', 17),
(10890, 'anexo', 237, 10888, 4, 'b', 'impactos para o cumprimento da meta de universalização do atendimento;', '', 18),
(10891, 'anexo', 237, 10888, 4, 'c', 'inexistência de alternativas de atendimento para manter a prestação dos serviços postais na localidade por meios próprios;', '', 19),
(10892, 'anexo', 237, 10888, 4, 'd', 'existência de vantajosidade econômica para a celebração da parceria, mediante a comparação de custos entre a celebração do convênio e a realização da atividade por meios próprios.', '', 20),
(10893, 'anexo', 237, NULL, 2, '1.10', 'A decisão da autoridade administrativa que autorizar a continuidade da celebração da parceria por meio da assinatura de TC ou ACT com condições especiais deverá ser devidamente fundamentada.', '', 21),
(10894, 'anexo', 237, 10893, 3, '1.10.1', 'Excepcionalmente, o órgão corporativo de gestão dos canais de atendimento terceirizados poderá avocar o processo administrativo em que foi celebrado TC ou ACT com condições especiais, para fins de avaliação de conformidade com as disposições existentes nos normativos internos dos Correios.', '', 22),
(10895, 'anexo', 237, NULL, 2, '1.11', 'Todos os documentos relacionados à celebração da parceria deverão, obrigatoriamente, tramitar por meio do Sistema Eletrônico de Informações - SEI.', '', 23),
(10896, 'anexo', 237, 10895, 3, '1.11.1', 'Em caso de tramitação de documentos físicos, estes devem ser digitalizados e inseridos no processo administrativo destinado à gestão da unidade de atendimento.', '', 24),
(10897, 'anexo', 237, NULL, 2, '1.12', 'Todas as certidões, documentos e formulários obrigatórios para a celebração da parceria e assinatura do instrumento jurídico correspondente devem ser inseridas no processo administrativo antes do início das operações da unidade de atendimento.', '', 25),
(10898, 'anexo', 237, 10897, 3, '1.12.1', 'Excepcionalmente poderá ser autorizada a juntada posterior dos documentos citados no subitem 1.10, mediante decisão fundamentada da autoridade administrativa responsável pela gestão do canal de atendimento no âmbito da SE.', '', 26),
(10899, 'anexo', 237, 10897, 3, '1.12.2', 'Caso haja autorização para juntada posterior, o órgão regional de gestão dos canais de atendimento terceirizados deverá acompanhar e fazer cumprir o prazo acordado com a pessoa jurídica contratada/conveniada, sob pena de acarretar a rescisão da parceria com fundamento na cláusula correspondente do instrumento jurídico firmado.', '', 27),
(10900, 'anexo', 237, NULL, 2, '1.13', 'Em caso de tramitação física de documentos, o órgão de gestão regional dos canais de atendimento de terceiros deverá manter arquivado cartão autógrafo com cópia da assinatura física do representante da unidade de atendimento, para fins de comparação com as assinaturas apresentadas nos documentos juntados ao processo administrativo.', '', 28),
(10901, 'anexo', 237, NULL, 2, '1.14', 'Todas as correspondências recebidas pelos Correios deverão ser respondidas, obrigatoriamente, em até 10 (dez) dias contados do seu recebimento, exceto situações em que seja necessário consultar outras áreas técnicas dos Correios.', '', 29),
(10902, 'anexo', 237, 10901, 3, '1.14.1', 'Sendo necessário consultar outras áreas técnicas dos Correios, os prazos de resposta permanecerão suspensos até a conclusão das tratativas necessárias, devendo o órgão regional de gestão dos canais terceirizados, sempre que necessário, informar sobre a tramitação à pessoa jurídica contratada/conveniada.', '', 30),
(10903, 'anexo', 237, 10901, 3, '1.14.2', 'Recomenda-se a inserção de expediente no processo administrativo sempre que for necessário formalizar pedido de informações a outras áreas da Empresa, com o objetivo de conferir maior transparência às atividades executadas pelas áreas envolvidas.', '', 31),
(10904, 'anexo', 237, NULL, 1, '2', 'ORIENTAÇÕES SOBRE OS DOCUMENTOS NECESSÁRIOS À CELEBRAÇÃO DA PARCERIA', '', 32),
(10905, 'anexo', 237, 10904, 2, '2.2', 'A pessoa jurídica contratada/conveniada deverá, obrigatoriamente, apresentar os comprovantes de cumprimento das obrigações exigidas no instrumento jurídico no momento da celebração da parceria com os Correios.', '', 33),
(10906, 'anexo', 237, 10904, 2, '2.3', 'Quando a entidade parceira for a prefeitura municipal, todos os documentos que tenham sido emitidos por ela para fins de comprovação do cumprimento de obrigações exigidas no instrumento contratual deverão ser aceitos como originais, a exemplo de:', '', 34),
(10907, 'anexo', 237, 10906, 4, 'a', 'alvará de funcionamento;', '', 35),
(10908, 'anexo', 237, 10906, 4, 'b', 'comprovante de atendimento aos requisitos de acessibilidade;', '', 36),
(10909, 'anexo', 237, 10906, 4, 'c', 'habite-se do imóvel em que a unidade será instalada;', '', 37),
(10910, 'anexo', 237, 10906, 4, 'd', 'certidões municipais negativas.', '', 38),
(10911, 'anexo', 237, 10904, 2, '2.4', 'O vínculo jurídico da pessoa jurídica com o imóvel em que a unidade será instalada poderá ser comprovado mediante a apresentação de declaração formal da pessoa jurídica contratada/conveniada, contendo as informações do imóvel quanto a sua propriedade, locação ou cessão, área construída, endereço e a finalidade a que se destina (instalação da unidade de atendimento).', '', 39),
(10912, 'anexo', 237, 10911, 3, '2.4.1', 'Devem ser anexados à declaração de vínculo jurídico o documento de propriedade do imóvel construído, contrato de locação, termo de cessão de uso ou outro documento que comprove a posse ou propriedade do imóvel, ou, em caso de inexistência de averbação em registro público, declaração de que o imóvel existe e é de sua propriedade e a respectiva área construída.', '', 40),
(10913, 'anexo', 237, 10911, 3, '2.4.2', 'Para os casos em que o imóvel é cedido por terceiros, deve haver um Termo de Cessão pelo proprietário contendo a finalidade da cessão (instalação de AGC) e os dados necessários, tais como: nome do proprietário, nacionalidade, profissão, RG, CPF, endereço de domicílio, nome a quem está sendo cedido o imóvel, formato do imóvel (prédio, loja, sala, dentre outros), metragem, endereço, inscrição do imóvel.', '', 41),
(10914, 'anexo', 237, 10904, 2, '2.5', 'Não haverá metragem mínima exigida para o funcionamento da unidade de atendimento, no entanto deve ser preservado o espaço físico destinado unicamente para as atividades de atendimento postal, local seguro para a guarda de produtos, materiais e objetos postais, assim como acessibilidade do público e a organização das atividades postais.', '', 42),
(10915, 'anexo', 237, 10914, 3, '2.5.1', 'O imóvel em que será instalada a unidade de atendimento deverá possuir infraestrutura mínima suficiente para garantir a segurança dos clientes, dos objetos postais e a acessibilidade para as pessoas com deficiência ou locomoção reduzida.', '', 43),
(10916, 'anexo', 237, 10914, 3, '2.5.2', 'É de competência da pessoa jurídica contratada/conveniada observar o cumprimento das normas de acessibilidade, não cabendo aos Correios estabelecer obrigações distintas da prevista na legislação federal e local.', '', 44),
(10917, 'anexo', 237, 10904, 2, '2.6', 'Caso a pessoa jurídica contratada/conveniada não apresente imóvel que atenda às condições exigidas e se recuse ou não possa apresentar outro em substituição, o órgão regional de gestão do instrumento contratual deverá informar ao representante da entidade parceira sobre a impossibilidade de celebração da parceria.', '', 45),
(10918, 'anexo', 237, 10904, 2, '2.7', 'A demonstração do cumprimento das obrigações civis, fiscais, trabalhistas, previdenciárias se dará mediante a apresentação dos seguintes documentos:', '', 46),
(10919, 'anexo', 237, 10918, 4, 'a', 'alvará de funcionamento;', '', 47),
(10920, 'anexo', 237, 10918, 4, 'b', 'comprovante de atendimento aos requisitos de acessibilidade;', '', 48),
(10921, 'anexo', 237, 10918, 4, 'c', 'habite-se do imóvel em que a unidade será instalada;', '', 49),
(10922, 'anexo', 237, 10918, 4, 'd', 'Certidão Negativa de Débitos Trabalhistas - CNDT, caso os servidores, empregados ou prepostos sejam contratados sob o regime da Consolidação das Leis do Trabalho - CLT;', '', 50),
(10923, 'anexo', 237, 10918, 4, 'e', 'certidão negativa de débitos trabalhistas ou documento equivalente emitida pela prefeitura municipal, caso os servidores, empregados ou prepostos sejam contratados sob o regime estatutário;', '', 51),
(10924, 'anexo', 237, 10918, 4, 'f', 'certidão negativa de débitos previdenciários - CND/INSS;', '', 52),
(10925, 'anexo', 237, 10918, 4, 'g', 'certidão de regularidade dos depósitos do FGTS, caso os servidores, empregados ou prepostos sejam contratados sob o regime da Consolidação das Leis do Trabalho - CLT;', '', 53),
(10926, 'anexo', 237, 10918, 4, 'h', 'certidão negativa de tributos estaduais;', '', 54),
(10927, 'anexo', 237, 10918, 4, 'i', 'certidão negativa de tributos federais.', '', 55),
(10928, 'anexo', 237, 10918, 3, '2.7.1', 'As certidões positivas com efeitos de negativa deverão ser consideradas como se negativa fossem para o cumprimento das respectivas obrigações previstas no instrumento contratual.', '', 56),
(10929, 'anexo', 237, 10904, 2, '2.8', 'Na inexistência de qualquer dos documentos citados no subitem 2.6, a prefeitura poderá emitir declaração atestando a regularidade do cumprimento das obrigações de natureza municipal, devendo indicar, neste caso, o reconhecimento quanto à ausência de responsabilidade dos Correios no cumprimento da obrigação perante os órgãos de fiscalização.', '', 57),
(10930, 'anexo', 237, NULL, 1, '3', 'DISPOSIÇÕES FINAIS', '', 58),
(10931, 'anexo', 237, 10930, 2, '3.1', 'O gestor regional dos canais de atendimento terceirizados deverá ainda:', '', 59),
(10932, 'anexo', 237, 10931, 4, 'a', 'até o quinto dia útil do mês subsequente ao das assinaturas dos instrumentos jurídicos, encaminhar à imprensa oficial os respectivos extratos para publicação no Diário Oficial da União;', '', 60);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(10933, 'anexo', 237, 10931, 4, 'b', 'encaminhar ao órgão de gestão operacional dos canais de atendimento no âmbito do Correios Sede, sempre que necessário, as informações atualizadas de cadastro da unidade de atendimento, de modo a manter os seus registros atualizados nos sistemas dos Correios;', '', 61),
(10934, 'anexo', 237, 10931, 4, 'c', 'reportar-se aos órgãos de gestão corporativa e gestão operacional dos canais de atendimento terceirizados, sempre que surgirem dúvidas sobre o cumprimento das obrigações previstas no instrumento jurídico que já não tenham sido esclarecidas pelos normativos vigentes.', '', 62),
(10935, 'anexo', 237, 10930, 2, '3.2', 'Caberá ainda ao órgão regional de gestão dos canais de atendimento terceirizados notificar a pessoa jurídica contratada/conveniada, após a assinatura do instrumento jurídico correspondente, acerca da exigibilidade de apresentação dos comprovantes de regularidade civil, fiscal, trabalhista e previdenciária sempre que solicitado pelos Correios.', '', 63),
(10936, 'anexo', 237, 10935, 3, '3.2.1', 'As referidas certidões deverão ser exigidas conforme estabelecido no subitem 2.1.3 do MANCAT 22/4.', '', 64),
(10937, 'anexo', 237, 10930, 2, '3.3', 'Em caso de impossibilidade ou não apresentação dos documentos exigidos para comprovação do cumprimento das obrigações legais, regulamentares e contratuais pela pessoa jurídica contratada/conveniada, o órgão regional de gestão dos canais de atendimento terceirizados deverá enviar correspondência formalizando a situação de pendência e irregularidade constatada, concedendo prazo de 90 (noventa) dias para a sua regularização.', '', 65),
(10938, 'anexo', 237, 10937, 3, '3.3.1', 'Permanecendo a situação de irregularidade após o término do prazo, o órgão regional de gestão dos canais de atendimento terceirizados deverá emitir nova correspondência à pessoa jurídica contratada/conveniada, com a informação relacionada ao papel dos Correios no acompanhamento da fiscalização da parceria e da necessidade de regularizar a situação com a maior brevidade possível, concedendo novo prazo de 90 (noventa) dias.', '', 66),
(10939, 'anexo', 237, 10937, 3, '3.3.2', 'Não sendo regularizada a situação após as comunicações realizadas, o órgão regional de gestão dos canais de atendimento terceirizados deverá emitir ofício aos órgãos públicos competentes pela fiscalização da respectiva obrigação, informando o fato e relatando os esforços empreendidos pelos Correios para a sua regularização.', '', 67),
(10940, 'anexo', 237, 10930, 2, '3.4', 'Todas as correspondências enviadas à pessoa jurídica conveniada/parceira deverão ser emitidas por meio do SEI e encaminhadas por e-mail, com confirmação de recebimento e leitura.', '', 68),
(10941, 'anexo', 237, 10940, 3, '3.4.1', 'Caso não seja possível a tramitação por meio eletrônico, as correspondências deverão ser enviadas com aviso de recebimento, mediante recibo na segunda via, e posteriormente digitalizados e inseridos no respectivo processo administrativo de gestão do canal de atendimento.', '', 69),
(10942, 'anexo', 237, 10930, 2, '3.5', 'Todas as informações sobre o cadastramento das unidades de atendimento deverão estar registradas no sistema ERP, devendo todos os campos estar devidamente preenchidos.', '', 70),
(10943, 'anexo', 237, 10930, 2, '3.6', 'Compete ao órgão regional de gestão dos canais de atendimento terceirizados monitorar e informar a necessidade de atualização em razão de eventuais mudanças nas informações referentes ao cadastro da unidade de atendimento terceirizadas nos sistemas dos Correios.', '* * * * *', 71),
(10944, 'anexo', 239, NULL, 1, '1', 'PROCEDIMENTOS PRELIMINARES', '', 0),
(10945, 'anexo', 239, 10944, 2, '1.1', 'O estabelecimento de parcerias para a instalação e operação da Agência de Correios Comunitária - AGC se dará por meio de Acordo de Cooperação Técnica - ACT ou Termo Convênio - TC, podendo ou não, a unidade, ser instalada em ambiente compartilhado com a atividade principal do parceiro.', '', 1),
(10946, 'anexo', 239, 10944, 2, '1.2', 'A juntada de documentos pela pessoa jurídica contratada/conveniada deverá ser realizada, prioritariamente, por meio de peticionamento intercorrente diretamente nos autos eletrônicos constantes no Sistema Eletrônico de Informações - SEI.', '', 2),
(10947, 'anexo', 239, 10946, 3, '1.2.1', 'Eventual apresentação física de documentos pela pessoa jurídica contratada/conveniada somente poderá ser aceita caso sejam devidamente assinadas pelo seu representante legal.', '', 3),
(10948, 'anexo', 239, 10946, 3, '1.2.2', 'A assinatura física de que trata o subitem 1.4.1 deverá ser conferida mediante comparação entre a assinatura apresentada e a constante no cartão de autógrafo arquivado junto ao órgão regional de gestão dos canais de atendimento terceirizados, conforme orientações do item 3 deste anexo.', '', 4),
(10949, 'anexo', 239, 10946, 3, '1.2.3', 'Cabe ao órgão regional de gestão dos canais de atendimento terceirizados assegurar a conformidade da assinatura dos documentos pela pessoa jurídica contratada/conveniada.', '', 5),
(10950, 'anexo', 239, 10944, 2, '1.3', 'O órgão regional de gestão dos canais de atendimento terceirizados deverá disponibilizar à pessoa jurídica contratada/conveniada, antes do início das operações da AGC, os seguintes itens:', '', 6),
(10951, 'anexo', 239, 10950, 4, 'a', 'cartazes informativos obrigatórios;', '', 7),
(10952, 'anexo', 239, 10950, 4, 'b', 'cartazes informativos complementares;', '', 8),
(10953, 'anexo', 239, 10950, 4, 'c', 'cópia do Código de Defesa do Consumidor;', '', 9),
(10954, 'anexo', 239, 10950, 4, 'd', 'material de propaganda desenvolvido pelos Correios;', '', 10),
(10955, 'anexo', 239, 10950, 4, 'e', 'cópias das tabelas de preços e tarifas nacionais e internacionais, a fim de compor a pasta de tarifas que será utilizada pela AGC durante o atendimento e/ou disponibilizada no hall de atendimento;', '', 11),
(10956, 'anexo', 239, 10950, 4, 'f', 'itens de comunicação visual;', '', 12),
(10957, 'anexo', 239, 10950, 4, 'g', 'plano de triagem da AGC;', '', 13),
(10958, 'anexo', 239, 10950, 4, 'h', 'demais itens, bens ou mobiliários cedidos por meio do Termo de Cessão de Uso, conforme estabelece o instrumento contratual.', '', 14),
(10959, 'anexo', 239, 10944, 2, '1.4', 'A capacitação dos servidores, empregados ou prepostos da AGC deverá ocorrer antes do início das operações da unidade, preferencialmente em ambiente virtual, ou conforme orientações da área técnica de capacitação e educação corporativa dos Correios.', '', 15),
(10960, 'anexo', 239, 10944, 2, '1.5', 'O órgão regional de gestão dos canais de atendimento terceirizados poderá negociar com a AGC a escolha de dia e período para que o servidor, empregado ou preposto que atuará na AGC possa acompanhar o funcionamento da Agência de Correios mais próxima da localidade, com o objetivo de melhor capacitá-lo acerca das rotinas diárias de funcionamento da unidade de atendimento.', '', 16),
(10961, 'anexo', 239, 10944, 2, '1.6', 'O comprovante de escolaridade mínima exigido dos servidores, empregados ou prepostos da AGC deverá ser apresentado em conjunto com a solicitação de capacitação, diretamente no processo eletrônico de gestão da unidade.', '', 17),
(10962, 'anexo', 239, 10961, 3, '1.6.1', 'Não sendo possível apresentar comprovação da escolaridade mínima exigida, a falta do documento poderá ser suprida mediante a apresentação de declaração, assinada pela pessoa jurídica contratada/conveniada, atestando que o servidor, empregado ou preposto atende aos requisitos mínimos necessários.', '', 18),
(10963, 'anexo', 239, NULL, 1, '2', 'VISITA TÉCNICA PARA AVALIAÇÃO DE CONFORMIDADE', '', 19),
(10964, 'anexo', 239, 10963, 2, '2.1', 'Antes do início das operações da unidade de atendimento, o órgão regional de gestão dos canais de atendimento terceirizados deverá assegurar que todos os itens estruturais (tecnologia, infraestrutura e comunicação) necessários ao funcionamento da AGC foram devidamente observados.', '', 20),
(10965, 'anexo', 239, 10963, 2, '2.2', 'De forma a otimizar a realização das atividades e diminuir os custos com transporte, estadia e diárias aos empregados responsáveis pela verificação técnica, esta poderá ser realizada de forma remota, por meio de transmissão online em vídeo ou registros fotográficos inseridos no processo administrativo de gestão da AGC.', '', 21),
(10966, 'anexo', 239, 10963, 2, '2.3', 'A verificação do cumprimento dos requisitos deverá ser realizada conforme estabelece o Manual de Comercialização e Atendimento - MANCAT 22/2, Anexo 05, denominado FORMULÁRIO DE VERIFICAÇÃO DE PREENCHIMENTO DOS REQUISITOS MÍNIMOS DE FUNCIONAMENTO DA AGC.', '', 22),
(10967, 'anexo', 239, 10963, 2, '2.4', 'Em caso de indisponibilidade de empregados dos Correios das áreas de tecnologia e infraestrutura, a Superintendência Estadual - SE, poderá designar empregado de outra área para a sua execução, devendo este ser instruído e acompanhado remotamente por empregados das áreas técnicas responsáveis.', '', 23),
(10968, 'anexo', 239, 10967, 3, '2.4.1', 'A delegação de competência prevista no subitem 2.4 acima poderá ser realizada ao fiscal do contrato lotado na Agência Vinculadora ou ao Gerente da Agência de Correios mais próxima da AGC.', '', 24),
(10969, 'anexo', 239, 10963, 2, '2.5', 'O cumprimento da legislação relacionada à infraestrutura, acessibilidade e ergonomia é de competência exclusiva da pessoa jurídica contratada/conveniada.', '', 25),
(10970, 'anexo', 239, 10969, 3, '2.5.1', 'Constatado o não preenchimento de quaisquer dos requisitos de acessibilidade e ergonomia pela pessoa jurídica contratada/conveniada, o órgão de gestão regional de canais de atendimento terceirizados deverá notificar a pessoa jurídica responsável pela operação da AGC, concedendo-lhe prazo para regularização, conforme estabelece o instrumento contratual.', '', 26),
(10971, 'anexo', 239, 10969, 3, '2.5.2', 'A não observância do prazo disponibilizado ou o não cumprimento das recomendações realizadas pela área de infraestrutura e ergonomia deverá ser formalizada pelos Correios aos órgãos públicos responsáveis pela sua fiscalização.', '', 27),
(10972, 'anexo', 239, 10969, 3, '2.5.3', 'Caso a unidade de atendimento não seja integrante da meta de universalização do atendimento dos serviços postais, nos termos definidos pelo Ministério Supervisor, a ausência de regularização dos itens informados na notificação de que trata o subitem 2.5.1 ensejará a instauração de processo administrativo destinado à rescisão do vínculo contratual entre os Correios e a pessoa jurídica contratada/conveniada.', '', 28),
(10973, 'anexo', 239, NULL, 1, '3', 'DA CONFERÊNCIA DE ASSINATURAS', '', 29),
(10974, 'anexo', 239, 10973, 2, '3.1', 'Para a recepção de documentos físicos relacionados à implantação e gestão da unidade de atendimento, os Correios deverão manter arquivo contendo cartão de autógrafos com cópia da assinatura do responsável legal pela pessoa jurídica contratada/conveniada.', '', 30),
(10975, 'anexo', 239, 10973, 2, '3.2', 'A depender da distância da unidade de atendimento em relação às instalações do órgão regional de gestão dos canais de atendimento terceirizados, ou ainda, de eventual impossibilidade de coleta de assinaturas de forma presencial, o responsável legal da pessoa jurídica contratada/conveniada poderá assinar a ficha autógrafo na Agência de Correios vinculadora ou na Agência de Correios mais próxima da AGC.', '', 31),
(10976, 'anexo', 239, 10973, 2, '3.3', 'A ficha de autógrafos de que trata o subitem anterior, deverá ser impressa em papel A4 conforme o modelo previsto no Anexo 6 - MODELO DE FICHA AUTÓGRAFO, devendo ser digitalizada e inserida no processo administrativo de gestão da unidade de atendimento.', '', 32),
(10977, 'anexo', 239, 10976, 3, '3.3.1', 'Incumbe ao órgão regional de gestão dos canais de atendimento manter a cópia digitalizada do cartão de autógrafos do representante legal da unidade de atendimento mais atualizada possível no processo administrativo de gestão da unidade de atendimento.', '', 33),
(10978, 'anexo', 239, NULL, 1, '4', 'DOS PRODUTOS CONSTANTES NO PLANO DE TRABALHO DA AGC', '', 34),
(10979, 'anexo', 239, 10978, 2, '4.1', 'O órgão regional de gestão dos canais de atendimento terceirizados deverá providenciar o suprimento dos itens inseridos no plano de trabalho da AGC antes do início de suas operações.', '', 35),
(10980, 'anexo', 239, 10978, 2, '4.2', 'Considera-se suprimento mínimo para fins de atendimento às disposições do Plano de Trabalho:', '', 36),
(10981, 'anexo', 239, 10980, 4, 'a', 'Os produtos constantes no subitem 3.3 - PORTFÓLIO AUTORIZADO, GRUPO 1 - MIX BÁSICO, alínea “a” - PRODUTOS;', '', 37),
(10982, 'anexo', 239, 10980, 4, 'b', 'Os produtos constantes no subitem 3.3 - PORTFÓLIO AUTORIZADO, GRUPO 2 - MIX COMPLEMENTAR, alínea “b” - PRODUTOS, quando sua comercialização for autorizada formalmente pelos Correios.', '', 38),
(10983, 'anexo', 239, 10978, 2, '4.3', 'Considerando eventuais particularidades da negociação para a celebração da parceria ou da localidade em que a AGC será instalada, o órgão de gestão regional dos canais de atendimento terceirizados poderá negociar a disponibilidade de outros produtos não previstos inicialmente no plano de trabalho.', '', 39),
(10984, 'anexo', 239, 10983, 3, '4.3.1', 'Para fins de disponibilização de outros produtos, conforme estabelecido no subitem 4.3 acima, o órgão regional de gestão dos canais de atendimento terceirizados deverá emitir posicionamento técnico que ateste a viabilidade para a sua comercialização por meio da AGC.', '', 40),
(10985, 'anexo', 239, 10983, 3, '4.3.2', 'A autorização de que trata o subitem 4.3 e 4.3.1 acima está restrita aos produtos próprios e/ou que possuem a marca dos Correios (selos comemorativos, produtos filatélicos, camisetas, cadernos, livros, etc).', '', 41),
(10986, 'anexo', 239, 10983, 3, '4.3.3', 'Não poderão ser objeto de negociação para comercialização por meio da AGC os produtos de terceiros que não sejam disponibilizados por meio de consignação e os serviços, próprios ou de terceiros, que demandem a utilização de sistemas de atendimento distintos dos oficialmente disponibilizados pelos Correios.', '', 42),
(10987, 'anexo', 239, 10983, 3, '4.3.4', 'Não poderão ainda ser disponibilizados para comercialização pela AGC os serviços que não estejam previstos para comercialização por este Canal de Atendimento, em conformidade com a estratégia de canais adotada pela empresa, ou aqueles que demandem custos adicionais não previstos para os Correios e/ou para a pessoa jurídica contratada/conveniada.', '4.3.4.1. Eventual pedido de comercialização de produtos ou serviços vedados pelo subitem 4.3.4 deverá, obrigatoriamente, ser avaliado pelo órgão corporativo de gestão dos canais de atendimento terceirizados.\n4.3.4.2. O pedido de avaliação de que trata o subitem 4.3.4.1 deverá ser enviado por meio de processo administrativo instaurado no SEI, devidamente instruído e acompanhado de todos os documentos necessários à avaliação do pedido.\n4.3.4.3. O órgão corporativo de gestão dos canais de atendimento poderá submeter consulta técnica aos órgãos corporativos de formatação e gestão de produtos e serviços no âmbito do Correios Sede.', 43),
(10988, 'anexo', 239, 10978, 2, '4.4', 'O acerto de contas relacionado à comercialização de produtos não previstos originalmente no plano de trabalho seguirá as regras específicas de cada instrumento contratual.', '* * * * *', 44),
(10989, 'anexo', 240, NULL, 1, '1', 'Anexar junto a solicitação:', '', 0),
(10990, 'anexo', 240, 10989, 4, 'a', 'cópia do documento de identificação e do CPF dos profissionais;', '', 1),
(10991, 'anexo', 240, 10989, 4, 'b', 'cópia do comprovante de vínculo jurídico entre o profissional e a pessoa jurídica contratada/conveniada (CTPS, nomeação ou documento equivalente);', '', 2),
(10992, 'anexo', 240, 10989, 4, 'c', 'cópia dos certificados emitidos pelos Correios, quando o profissional tiver experiência profissional em serviço postal;', '* * * * *', 3),
(10993, 'anexo', 241, NULL, 4, 'a', 'Os insumos obrigatórios e de fornecimento pelos Correios não poderão ser excluídos da presente solicitação;', '', 0),
(10994, 'anexo', 241, NULL, 4, 'b', 'Na ocorrência de ser necessário fornecer algum dos itens previstos no Plano de Trabalho como sendo de fornecimento pelo parceiro, estes deverão ser objeto de Termo de Cessão de bem ou mobiliário, conforme Anexo previsto no instrumento jurídico correspondente;', '', 1),
(10995, 'anexo', 241, NULL, 4, 'c', 'A presente solicitação tem como objetivo fornecer o kit inicial de suprimento para o funcionamento da Agência de Correios Comunitária;', '', 2),
(10996, 'anexo', 241, NULL, 4, 'd', 'O suprimento de novos produtos ou insumos deverá ocorrer conforme normativa interna específica dos Correios.', '* * * * *', 3),
(10997, 'anexo', 242, NULL, 1, '1', 'EQUIPAMENTOS INFORMÁTICOS', '', 0),
(10998, 'anexo', 242, 10997, 2, '1.1', 'Preencha na coluna “Atendido” com o termo “sim” ou “não” conforme a análise da vistoria de adequação aos requisitos mínimos.', '', 1),
(10999, 'anexo', 242, NULL, 1, '1', 'ESTAÇÃO DE ATENDIMENTO CONFIGURAÇÃO MÍNIMA	Atendido', 'Os microcomputadores atendem às configurações mínimas estabelecidas pelos Correios para o funcionamento da unidade?	 \nOs microcomputadores estão conectados à internet?\nTodos os periféricos necessários foram devidamente instalados e apresentam bom funcionamento (mouse, teclado, leitor de código de barras, impressora de tíquete de atendimento e balança)?', 2),
(11000, 'anexo', 242, NULL, 1, '2', 'COMUNICAÇÃO VISUAL', '', 3),
(11001, 'anexo', 242, 11000, 2, '2.1', 'Preencha na coluna “Atendido” com o termo “sim” ou “não” conforme a análise da vistoria de adequação aos requisitos mínimos.', '', 4),
(11002, 'anexo', 242, NULL, 1, '2', 'COMUNICAÇÃO VISUAL	Atendido', 'A unidade possui todos os cartazes obrigatórios?\nA unidade possui todos os cartazes complementares?\nO(s) Guichê(s) de Atendimento está(ão) devidamente identificado(s)?\nA(s) placa(s) de identificação da unidade está(ão) devidamente instalada(s)?', 5),
(11003, 'anexo', 242, NULL, 1, '3', 'INSTALAÇÕES INTERNAS', '', 6),
(11004, 'anexo', 242, 11003, 2, '3.1', 'Preencha na coluna “Atendido” com o termo “sim” ou “não” conforme a análise da vistoria de adequação aos requisitos mínimos.', 'EQUIPAMENTOS E MOBILIÁRIO	Atendido', 7),
(11005, 'anexo', 242, NULL, 1, '3', 'ÁREA DE ATENDIMENTO', 'O módulo de atendimento está instalado?\nO módulo de atendimento atende às especificações de ergonomia?\nO módulo de atendimento atende às especificações de acessibilidade?\nA área de atendimento é suficiente para o acolhimento do cliente e prestação do serviço postal?', 8),
(11006, 'anexo', 242, NULL, 1, '4', 'ÁREA DE APOIO', 'A área disponível permite o acondicionamento dos objetos postais em segurança?\nCaso a área de apoio seja compartilhada com as instalações da pessoa jurídica, ela permite a guarda ou acondicionamento dos objetos postais em segurança?\nA área de apoio permite a guarda ou acondicionamento dos objetos de forma protegida contra chuvas, exposição ao sol ou outros tipos de eventos naturais?', 9),
(11007, 'anexo', 242, NULL, 1, '5', 'ACESSO DOS CLIENTES', 'O imóvel permite o acesso irrestrito de pessoas em qualquer época do ano, sem exigências de cadastramento prévio, crachás ou outro procedimento ou sistema de controle de acesso?\nA área de acesso dos clientes atende aos requisitos de ergonomia e acessibilidade?', 10),
(11008, 'anexo', 242, NULL, 1, '4', 'RESULTADO DA VERIFICAÇÃO DE REQUISITOS TÉCNICOS', '', 11),
(11009, 'anexo', 242, 11008, 2, '4.1', 'Conforme verificado, nesta data, e consoante as informações registradas neste documento a AGC _____________ (colocar o nome da Unidade) foi ____________ (aprovada/reprovada) nos seguintes itens, para os quais será concedido prazo para regularização, conforme estabelece o instrumento contratual:', 'ITEM OU\nCRITÉRIO 	DESCRIÇÃO DO MOTIVO DA REPROVAÇÃO\n 	 \n 	 \n 	 \n*Preencher apenas se houver inconsistência em algum item ou critério, não havendo passar um risco.\nCidade - UF ......./........... de ......\nRepresentantes dos Correios\n_______________________________\nNome Completo\nMatrícula:\n_______________________________\nNome Completo\nMatrícula:\nRepresentante(s) Legal(is) da Pessoa Jurídica Contratada/Conveniada\n_______________________________\nNome Completo\nCPF:\n_______________________________\nNome Completo\nCPF:', 12),
(11010, 'anexo', 242, NULL, 1, '5', 'ORIENTAÇÕES GERAIS:', '', 13),
(11011, 'anexo', 242, 11010, 2, '5.1', 'A aprovação ou reprovação de algum dos critérios previstos neste formulário deverá ser objeto de avaliação pelo órgão regional de gestão dos canais de atendimento terceirizados, a fim de se constatar se há impedimento ou não para o funcionamento da unidade.', '', 14),
(11012, 'anexo', 242, 11010, 2, '5.2', 'É de competência exclusiva da pessoa jurídica conveniada/contratada observar os requisitos previstos na legislação local acerca de acessibilidade e ergonomia.', '', 15),
(11013, 'anexo', 242, 11010, 2, '5.3', 'Os Correios poderão autorizar o início do funcionamento da unidade, caso a pessoa jurídica contratada/conveniada se comprometa a regularizar a situação no prazo estabelecido, conforme disciplina o instrumento contratual.', '', 16),
(11014, 'anexo', 242, 11010, 2, '5.4', 'As páginas desse documento deverão ser rubricadas pelos representantes dos Correios e da pessoa jurídica contratada/conveniada.', '* * * * *', 17),
(11015, 'anexo', 246, NULL, 1, '1', 'PROCEDIMENTOS PRELIMINARES', '', 0),
(11016, 'anexo', 246, 11015, 2, '1.1', 'Constatada a ocorrência de descumprimento de qualquer das cláusulas do instrumento jurídico firmado com a pessoa jurídica contratada/conveniada, o órgão regional de gestão dos canais de atendimento terceirizadas deverá instaurar processo administrativo por meio do Sistema Eletrônico de Informações - SEI.', '', 1),
(11017, 'anexo', 246, 11015, 2, '1.2', 'O processo deverá ser instaurado com a atribuição de sigilo, conforme orientações a seguir:', '', 2),
(11018, 'anexo', 246, 11017, 4, 'a', 'tipo de processo: atendimento - gestão das unidades contratadas (AFG, ACC, AGC)', '', 3),
(11019, 'anexo', 246, 11017, 4, 'b', 'especificação: apuração de irregularidade contratual + nome da AGC;', '', 4),
(11020, 'anexo', 246, 11017, 4, 'c', 'interessados: Superintendência Estadual - SE, órgão corporativo de gestão dos canais de atendimento terceirizados e órgão de gestão operacional dos canais de atendimento;', '', 5),
(11021, 'anexo', 246, 11017, 4, 'd', 'nível de acesso: restrito;', '', 6),
(11022, 'anexo', 246, 11017, 4, 'e', 'hipótese legal: controle interno (art. 26, § 3º, da lei 10.180/2001).', '', 7),
(11023, 'anexo', 246, 11015, 2, '1.3', 'Todos os documentos, arquivos, planilhas, registros fotográficos que fundamentarem a constatação da ocorrência devem ser inseridos no processo administrativo destinado à apuração da irregularidade.', '', 8),
(11024, 'anexo', 246, NULL, 1, '2', 'PROCEDIMENTOS PROCESSUAIS', '', 9),
(11025, 'anexo', 246, 11024, 2, '2.1', 'Após a instauração e instrução do processo, o órgão regional de gestão dos canais de atendimento terceirizados deverá emitir notificação à pessoa jurídica contratada/conveniada com a adequada descrição do fato e da penalidade decorrente de sua confirmação.', '', 10),
(11026, 'anexo', 246, 11024, 2, '2.2', 'A notificação deve conter de forma clara qual é a conduta considerada irregular e a respectiva previsão contratual da penalidade.', '', 11),
(11027, 'anexo', 246, 11024, 2, '2.3', 'Após a notificação, a pessoa jurídica contratada/conveniada terá prazo de 5 (cinco) dias úteis para apresentar defesa, caso queira.', '', 12),
(11028, 'anexo', 246, 11027, 3, '2.3.1', 'Transcorrido o prazo sem manifestação da pessoa jurídica contratada/conveniada, os Correios darão prosseguimento à apuração, conforme previsão inserida no instrumento jurídico correspondente.', '', 13),
(11029, 'anexo', 246, 11027, 3, '2.3.2', 'Caso necessário para viabilizar sua manifestação, a pessoa jurídica contratada/conveniada poderá requerer prorrogação do prazo de defesa, uma única vez, por igual período.', '', 14),
(11030, 'anexo', 246, 11024, 2, '2.4', 'O órgão regional de gestão dos canais de atendimento terceirizados terá prazo de 5 (cinco) dias úteis para avaliar a peça de defesa, podendo:', '', 15),
(11031, 'anexo', 246, 11030, 4, 'a', 'solicitar a complementação dos documentos apresentados pela pessoa jurídica contratada/conveniada, caso necessário;', '', 16),
(11032, 'anexo', 246, 11030, 4, 'b', 'prorrogar o prazo de avaliação da defesa, mediante despacho fundamentado, em decorrência da complexidade dos fatos apurados e/ou dos argumentos de defesa ou outro critério considerado relevante;', '', 17),
(11033, 'anexo', 246, 11030, 4, 'c', 'decidir, mediante apresentação de relatório técnico circunstanciado devidamente fundamentado, acerca do acolhimento ou indeferimento dos argumentos de defesa apresentados pela pessoa jurídica contratada/conveniada.', '', 18),
(11034, 'anexo', 246, 11024, 2, '2.5', 'Julgada improcedente a defesa, a pessoa jurídica contratada/conveniada poderá interpor recurso administrativo ao SE, no prazo de até 5 (cinco) dias úteis improrrogáveis, contados da notificação sobre o julgamento.', '', 19),
(11035, 'anexo', 246, 11024, 2, '2.6', 'Caso não ocorra apresentação de recurso administrativo pela pessoa jurídica contratada/conveniada, o órgão regional de gestão dos canais de atendimento terceirizados deverá adotar as providências previstas no item 3 deste Anexo, referentes à aplicação de penalidades.', '', 20),
(11036, 'anexo', 246, 11024, 2, '2.7', 'Recebido o recurso administrativo dentro do prazo estabelecido, o órgão regional de gestão dos canais de atendimento terceirizados poderá reconsiderar da decisão que julgou improcedentes os argumentos de defesa no prazo de 5 (cinco) dias úteis, ou, no mesmo prazo, submeter o recurso para deliberação da SE.', '', 21),
(11037, 'anexo', 246, 11024, 2, '2.8', 'A SE terá prazo de 5 (cinco) dias úteis para deliberar sobre o recurso administrativo apresentado pela pessoa jurídica contratada/conveniada, podendo adotar as mesmas providências estabelecidas por meio do subitem 2.4 acima.', '', 22),
(11038, 'anexo', 246, 11037, 3, '2.8.1', 'Para fins de fundamentação do julgamento do recurso administrativo, a SE poderá requerer a elaboração de relatório técnico circunstanciado ao órgão regional de gestão dos canais de atendimento terceirizados.', '', 23),
(11039, 'anexo', 246, 11024, 2, '2.9', 'Esgotadas todas as fases de tramitação do processo administrativo de apuração de descumprimento contratual, o órgão regional dos canais de atendimento terceirizados deverá:', '', 24),
(11040, 'anexo', 246, 11039, 4, 'a', 'adotar as providências necessárias ao arquivamento do processo, caso a decisão administrativa tenha sido pelo acolhimento da defesa ou recurso administrativo;', '', 25),
(11041, 'anexo', 246, 11039, 4, 'b', 'adotar as providências necessárias à aplicação da penalidade, conforme procedimentos estabelecidos no item 3 deste anexo.', '', 26),
(11042, 'anexo', 246, 11024, 2, '2.10', 'Em caso de arquivamento, a pessoa jurídica contratada/conveniada deverá ser notificada formalmente sobre o julgamento e sobre os fundamentos que permitiram o acolhimento da defesa ou recurso.', '', 27),
(11043, 'anexo', 246, 11024, 2, '2.11', 'O encerramento do processo administrativo dar-se-á mediante a inclusão de termo de encerramento de tramitação diretamente nos autos do processo eletrônico, no qual se realizará um resumo das ações executadas e da conclusão da apuração.', '', 28),
(11044, 'anexo', 246, 11043, 3, '2.11.1', 'Finalizada a tramitação do processo, este deverá ser anexado ao processo de gestão da unidade de atendimento, por meio da opção “anexação de processos” do SEI.', '', 29),
(11045, 'anexo', 246, NULL, 1, '3', 'APLICAÇÃO DE PENALIDADES', '', 30),
(11046, 'anexo', 246, 11045, 2, '3.1', 'Finalizada a tramitação do processo e constatada a ocorrência da irregularidade, o órgão regional de gestão dos canais de atendimento deverá emitir notificação formal à pessoa jurídica contratada/conveniada acerca da conclusão da apuração e da decisão proferida pela autoridade competente.', '', 31),
(11047, 'anexo', 246, 11045, 2, '3.2', 'O órgão regional de gestão dos canais de atendimento terceirizados deverá adotar as providências previstas no Manual de Comercialização e Atendimento - MANCAT 22/05, caso a irregularidade apurada tenha como finalidade a rescisão do instrumento jurídico firmado com a pessoa jurídica contratada/conveniada.', '', 32),
(11048, 'anexo', 246, 11045, 2, '3.3', 'A carta de notificação da aplicação da penalidade deverá constar, no mínimo:', '', 33),
(11049, 'anexo', 246, 11048, 4, 'a', 'descrição da ocorrência apurada;', '', 34),
(11050, 'anexo', 246, 11048, 4, 'b', 'descrição da irregularidade e sua correspondência com as cláusulas do instrumento jurídico;', '', 35),
(11051, 'anexo', 246, 11048, 4, 'c', 'resumo da tramitação do processo administrativo;', '', 36),
(11052, 'anexo', 246, 11048, 4, 'd', 'motivação da decisão administrativa de indeferimento da defesa ou do recurso administrativo;', '', 37),
(11053, 'anexo', 246, 11048, 4, 'e', 'penalidade correspondente à conduta, conforme previsto no instrumento jurídico;', '', 38),
(11054, 'anexo', 246, 11048, 4, 'f', 'início da vigência da penalidade, nos casos de penalidade que não implique a rescisão do instrumento jurídico;', '', 39),
(11055, 'anexo', 246, 11048, 4, 'g', 'data prevista para o encerramento das atividades da AGC, caso a penalidade preveja a rescisão do instrumento jurídico.', '', 40),
(11056, 'anexo', 246, 11045, 2, '3.4', 'As ocorrências de descumprimento contratual serão contabilizadas conforme disposições específicas de cada instrumento jurídico destinado à instalação de AGC.', '', 41),
(11057, 'anexo', 246, 11045, 2, '3.5', 'Além das orientações previstas no MANCAT 22/05, o órgão regional de gestão dos canais de atendimento terceirizados deverá interagir com os demais órgãos, em nível estadual e corporativo, quanto às providências necessárias para o encerramento das atividades da unidade de atendimento, conforme estabelecido nos demais normativos internos.', '', 42),
(11058, 'anexo', 246, NULL, 1, '4', 'DISPOSIÇÕES GERAIS', '', 43),
(11059, 'anexo', 246, 11058, 2, '4.1', 'Identificados débitos de qualquer natureza decorrentes da operacionalização da AGC, a área jurídica deverá ser acionada para adotar os procedimentos destinados à recuperação dos valores por meio de ação judicial específica.', '', 44),
(11060, 'anexo', 246, 11059, 3, '4.1.1', 'A orientação acima se aplica, inclusive, à identificação de débitos ou prejuízos decorrentes da operacionalização da unidade de atendimento após o término ordinário da vigência do instrumento jurídico ou distrato do Termo de Convênio ou Acordo de Cooperação Técnica.', '', 45),
(11061, 'anexo', 246, 11058, 2, '4.2', 'O processo administrativo deverá tramitar de forma independente de eventual processo judicial de natureza cível ou criminal, ainda que relacionado ao mesmo ato/fato, respeitando-se, caso exista, decisão judicial em sentido contrário.', '', 46),
(11062, 'anexo', 246, 11058, 2, '4.3', 'A pessoa jurídica contratada/conveniada tem o direito de:', '', 47),
(11063, 'anexo', 246, 11062, 4, 'a', 'ter acesso aos autos do processo administrativo, de forma física ou eletrônica;', '', 48),
(11064, 'anexo', 246, 11062, 4, 'b', 'conhecer e fazer cópia de todo e qualquer documento inserido nos autos;', '', 49),
(11065, 'anexo', 246, 11062, 4, 'c', 'apresentar defesa em face de qualquer fato que lhe esteja sendo imputado como irregularidade prevista no instrumento jurídico;', '', 50),
(11066, 'anexo', 246, 11062, 4, 'd', 'apresentar recurso à SE, caso a pessoa jurídica contratada/conveniada entenda que a decisão administrativa que aplicar a penalidade lhe seja desfavorável ou lhe tenha atribuído penalidade que considere desproporcional;', '', 51),
(11067, 'anexo', 246, 11062, 4, 'e', 'peticionar nos autos do processo administrativo, a qualquer momento.', '', 52),
(11068, 'anexo', 246, 11058, 2, '4.4', 'Caso necessário para melhor fundamentar a decisão administrativa sobre a defesa ou recurso administrativo apresentado pela pessoa jurídica contratada/conveniada, o órgão regional de gestão dos canais de atendimento terceirizado poderá encaminhar pedido de emissão de parecer jurídico à Assessoria Jurídica Estadual - ASJUR, conforme diretrizes apresentadas no Manual Jurídico - MANJUR 01/02.', '', 53),
(11069, 'anexo', 246, 11058, 2, '4.5', 'Todas as atividades executadas pelo órgão regional de gestão dos canais de atendimento devem ser devidamente formalizadas por meio do processo administrativo de apuração da irregularidade.', '* * * * *', 54),
(11070, 'anexo', 251, NULL, 2, '1.1', 'Prestação de serviço: ocorre mediante a realização das atividades de atendimento aos clientes de varejo e com contrato da ECT, conferência da observância às regras específicas e presentes nos normativos internos, lançamento das informações em sistema de automação do atendimento autorizado pelos Correios e tratamento dos objetos para disponibilização à ECT.', '', 0),
(11071, 'anexo', 251, NULL, 2, '1.2', 'Canal de atendimento terceirizado: unidade de atendimento postal operacionalizada por pessoa jurídica de direito privado, mediante celebração de instrumento contratual com os Correios.', '', 1),
(11072, 'anexo', 251, NULL, 2, '1.3', 'Região de atendimento (território de atuação): área geopolítica de um município, região metropolitana ou região conurbada que pode conter um ou vários canais de atendimento próprios ou terceirizados, independentemente do modelo.', '', 2),
(11073, 'anexo', 251, NULL, 2, '1.4', 'Órgão regional de gestão dos canais de atendimento terceirizados: unidade da estrutura organizacional da Superintendência Estadual responsável pela gestão dos instrumentos contratuais celebrados entre os Correios e as pessoas jurídicas de direito privado, instalados na macro divisão estadual.', '', 3),
(11074, 'anexo', 251, NULL, 2, '1.5', 'Irregularidade: ação ou omissão realizada pelos sócios, representante legal e/ou empregado da franqueadas relativa à execução operacional do objeto do contrato, que contrarie as disposições presentes instrumento contratual, nos normativos internos, nas orientações específicas e/ou na legislação aplicável.', '', 4),
(11075, 'anexo', 251, NULL, 2, '1.6', 'Plano de triagem: é um conjunto de direções estabelecidas com base em critérios para a separação das cargas nas unidades e que determina a forma como os objetos devem ser separados e encaminhados as suas respectivas centralizadoras.', '', 5),
(11076, 'anexo', 251, NULL, 1, '2', 'ORIENTAÇÕES GERAIS DO SUBPROCESSO', '', 6),
(11077, 'anexo', 251, 11076, 2, '2.1', 'A comercialização dos produtos e serviços pelas agências de Correios franqueadas - AGF estará autorizada a partir da disponibilização desses no Anexo 3 do Contrato de Franquia Postal.', '', 7),
(11078, 'anexo', 251, 11077, 3, '2.1.1', 'As orientações gerais e específicas sobre a comercialização dos produtos e serviços que compõem o portfólio autorizados para os canais de atendimento terceirizados, inclusive no que diz respeito as modalidades de pagamento pelo cliente, são de observação obrigatória, bem como as disposições presentes no Contrato de Franquia Postal.', '', 8),
(11079, 'anexo', 251, 11077, 3, '2.1.2', 'É vedado às AGF a comercialização de produtos/serviços nas situações de:', '', 9),
(11080, 'anexo', 251, 11079, 4, 'a', 'vedações descritas no item 5, deste Anexo 2;', '', 10),
(11081, 'anexo', 251, 11079, 4, 'b', 'impedimentos descritos no item 6, deste Anexo 2;', '', 11),
(11082, 'anexo', 251, 11079, 4, 'c', 'quando se tratar de produtos:', 'I - a clientes de contrato que realizem pagamento na modalidade a faturar;\nII - fora do prazo de comercialização.', 12),
(11083, 'anexo', 251, 11076, 2, '2.2', 'Os clientes de varejo ou contrato comercial que se apresentem voluntariamente na unidade para aquisição de serviços, independentemente da Unidade da Federação de origem, são elegíveis para execução operacional dos serviços pela agência de Correios franqueada - AGF, desde que:', '', 13),
(11084, 'anexo', 251, 11083, 4, 'a', 'o serviço esteja incluso no Anexo 3 do Contrato de Franquia Postal;', '', 14),
(11085, 'anexo', 251, 11083, 4, 'b', 'os objetos postais observem as orientações específicas para aceitação da postagem, tais como: peso, medidas, conteúdo, invólucro etc.', '', 15),
(11086, 'anexo', 251, 11083, 4, 'c', 'no caso dos objetos postais para postagem a faturar, apresentar:', 'I - a pré-lista de postagem, conforme definições estabelecidas; ou\nII - quando aplicável, na ausência da lista, o cartão de postagem válido e ativo.\nNota: havendo dúvidas sobre a regularidade do cartão de postagem, a AGF deverá consultar o órgão regional de gestão de vendas, antes de realizar o atendimento.', 16),
(11087, 'anexo', 251, 11083, 3, '2.2.1', 'Quando se tratar de serviços, consoante as contrapartidas e benefícios, os caracterizem como postagem como industrial deverá ser observado, além das disposições deste Anexo 2, as especificações presentes no Anexo 3 deste Capítulo.', '', 17),
(11088, 'anexo', 251, 11083, 3, '2.2.2', 'O cliente tem a liberalidade de escolher o(s) canal(is) de atendimento que irão atendê-lo, bem como definir, a qualquer tempo, por não utilizar o serviço de uma unidade da rede de atendimento, própria ou terceirizada, que já tenha lhe prestado serviço, sem que isso ocasione:', '', 18),
(11089, 'anexo', 251, 11088, 4, 'a', 'necessidade de comunicação ou de anuência prévia, exceto nos casos em que houver área acessória instalada nas instalações do cliente;', '', 19),
(11090, 'anexo', 251, 11088, 4, 'b', 'direito de qualquer natureza, inclusive, de compensação financeira à Franqueada, mesmo que a unidade tenha realizado investimentos em estrutura instalada para atendimento ao cliente.', '2.2.2.1 Excetua-se a definição disposta no caput no item 2.2.2, as situações em que é necessário a adesão e/ou habilitação da agência de Correios franqueada para prestação de serviços escopo da alínea “d”, do item 5.5.1 deste Anexo 2.', 20),
(11091, 'anexo', 251, 11083, 3, '2.2.3', 'As Agências de Correios Franqueadas - AGF só poderão realizar a execução operacional de postagens classificadas como industriais de determinado cliente, após terem sido habilitadas para operacionalizar o respectivo contrato.', '2.2.3.1 A inobservância da disposição presente no subitem 2.2.3 ensejará no enquadramento em ocorrência de descumprimento contratual e na contabilização da pontuação pela irregularidade, nos termos do Anexo 4 do contrato de franquia postal.\n2.2.3.2 Os Correios poderão desabilitar a AGF para execução operacional de postagens classificadas como industriais, conforme previsão do item 2.7 deste anexo.', 21),
(11092, 'anexo', 251, 11083, 3, '2.2.4', 'A franqueada deverá comunicar, formalmente, aos Correios com no mínimo 15 (quinze) dias de antecedência, na ocorrência de optar por deixar realizar as postagens classificadas como industriais vinculadas a determinado contrato comercial de clientes dos Correios.', '', 22),
(11093, 'anexo', 251, 11076, 2, '2.3', 'A AGF é responsável pelas informações de postagens lançadas no sistema de atendimento, de forma que, antes de realizar a postagem, deverá:', '', 23),
(11094, 'anexo', 251, 11093, 4, 'a', 'realizar a conferência exaustiva dos dados da Pré-Lista de Postagem - PLP com os objetos físicos captados pela agência;', '', 24),
(11095, 'anexo', 251, 11093, 4, 'b', 'corrigir as informações divergentes quando identificadas ou devolver o objeto ao cliente, conforme orientações do formatador;', '', 25),
(11096, 'anexo', 251, 11093, 4, 'c', 'informar ao cliente os itens retificados ou que necessitem alteração nas Pré-Lista de Postagem - PLP ou de postagem.', '', 26),
(11097, 'anexo', 251, 11076, 2, '2.4', 'A AGF, a seu critério, poderá preparar a Pré-Lista de Postagem - PLP ou a mídia com o arquivo dos dados dos objetos que serão postados, em substituição ao cliente que atenda com regularidade. Registrando-se que:', '', 27),
(11098, 'anexo', 251, 11097, 4, 'a', 'essa ação não será considerada uma ocorrência de descumprimento contratual;', '', 28),
(11099, 'anexo', 251, 11097, 4, 'b', 'deve ser guardada a devida observância às orientações dos Correios, em relação ao quantitativo mínimo e máximo de objeto por PLP ou mídia, bem como a disponibilização das informações necessárias e fidedignas no formulário;', '', 29),
(11100, 'anexo', 251, 11097, 4, 'c', 'essa ação não exime a AGF da conferência via sistema dos objetos que compõem a PLP ou mídia;', '', 30),
(11101, 'anexo', 251, 11097, 4, 'd', 'a franqueada é responsável com exclusividade pelos objetos postais desde sua coleta nas instalações do cliente, ou de seu recebimento nas instalações da AGF, até a sua entrega ao Correios.', '', 31),
(11102, 'anexo', 251, 11097, 3, '2.4.1', 'Contudo, em caso de constatação de irregularidades ou glosa por parte do cliente em relação aos objetos constantes da PLP de que trata o item 2.4, essas situações serão tratadas conforme previsto no Contrato de Franquia Postal (CFP).', '', 32),
(11103, 'anexo', 251, 11076, 2, '2.5', 'A AGF será responsabilizada pecuniariamente, sem prejuízo das eventuais responsabilidades contratuais, civil e penal a serem apuradas, pelas postagens que tenha recebido e que posteriormente sejam refutadas/glosadas pelo cliente, quando:', '', 33),
(11104, 'anexo', 251, 11103, 4, 'a', 'comprovado que as postagens realizadas são relativas ao contrato comercial de outrem, e não seja possível reverter a cobrança relativa aos objetos postais postados erroneamente;', '', 34),
(11105, 'anexo', 251, 11103, 4, 'b', 'não houver verificação sobre a autorização do mensageiro para realizar postagens na modalidade a faturar e os objetos não estiverem acompanhados da respectiva PLP, autorização assinado por pessoa competente ou o cartão de postagem ativo e válido;', '', 35),
(11106, 'anexo', 251, 11103, 4, 'c', 'realizar postagens após orientação contraria dos Correios ou do cliente.', '', 36),
(11107, 'anexo', 251, 11076, 2, '2.6', 'A remuneração da AGF pela comercialização de produtos e serviços ocorrerá conforme tabelas, grupos e percentuais definidos no Anexo 3 do contrato de franquia postal (CFP).', '', 37),
(11108, 'anexo', 251, 11076, 2, '2.7', 'É vedado a AGF aceitar, oferecer ou conceder vantagens financeiras aos clientes ou quaisquer outros benefícios que não estejam previstos no contrato de franquia postal ou nos contratos comerciais dos Correios, em prol de obter exclusividade/ou preferência na comercialização de produtos ou serviços.', '', 38),
(11109, 'anexo', 251, 11108, 3, '2.7.1', 'Não será considerada concessão de vantagem financeira a utilização pela franqueada de boletos bancários para cobrança de serviços prestados à vista para os clientes que atenda com habitualidade. Contudo, registre-se que essa liberalidade não altera o prazo ou as definições relativas às obrigações financeiras previstas no contrato de franquia postal para a comercialização de produtos e serviços na modalidade à vista', '', 39),
(11110, 'anexo', 251, 11076, 2, '2.8', 'É vedada a vinculação exclusiva de serviços relativos a contratos comerciais de órgãos públicos e entidades que se submetem a Lei 13.303/2016, a uma única AGF, ainda que a pedido do cliente.', '', 40),
(11111, 'anexo', 251, 11076, 2, '2.9', 'É vedado à pessoa jurídica da franqueada ou a seus sócios participar de certames/licitações/processos seletivos que visem à celebração de contratos para prestação de serviços postais ou os definidos como concorrenciais no(s) edital(is) de licitação de AGF:', 'a) a órgãos públicos e entidades que se submetem a Lei 13.303/2016 e a Lei 8.666/93;\nb) à pessoas jurídicas de direito público e/ou de direito privado.', 41),
(11112, 'anexo', 251, 11111, 3, '2.9.1', 'A inobservância ao item 2.9 acarretará o enquadramento da irregularidade presente no Anexo 4 do contrato de franquia postal - quadro de ocorrências de descumprimento contratual.', '', 42),
(11113, 'anexo', 251, 11076, 2, '2.10', 'Não será acatada defesa interposta pela franqueada, que tenha como escopo alegação/argumentação de desconhecimento de norma, orientação e/ou parâmetros presente neste Capítulo ou seus anexos.', '', 43),
(11114, 'anexo', 251, NULL, 1, '3', 'TERRITÓRIO DE ATUAÇÃO E COLETA', '', 44),
(11115, 'anexo', 251, 11114, 2, '3.1', 'O território de atuação da AGF para prospecção de clientes e coleta não é exclusivo e está limitado à área geopolítica do município, região metropolitana ou área conurbada, o que for maior, em que se encontra instalada a AGF.', '', 45),
(11116, 'anexo', 251, 11115, 3, '3.1.1', 'Entende-se por área conurbada a aglomeração formada por uma cidade, seus subúrbios e satélites ou por unidades limítrofes, que constituem uma sequência, sem, contudo, se confundirem, e que têm as mesmas características.', '', 46),
(11117, 'anexo', 251, 11115, 3, '3.1.2', 'A utilização do conceito de área conurbada, no que tange a prospecção e coleta pela AGF, deverá estar limitada ao compartilhamento das tabelas de preço entre o município onde está instalada a AGF e a área onde está localizado o cliente.', '', 47),
(11118, 'anexo', 251, 11115, 3, '3.1.3', 'A análise do território de atuação e coleta da AGF está restrita aos limites geográficos da Superintendência Estadual onde a agência estiver instalada, bem como ao alcance das tabelas de preço.', '', 48),
(11119, 'anexo', 251, 11114, 2, '3.2', 'O órgão regional de gestão dos canais de atendimento terceirizado poderá rever os limites do território de atuação da AGF:', 'a) de modo a preservar a qualidade e continuidade dos serviços postais, primando pelo interesse público e guardando a isonomia com as demais unidades;\nb) observando o compartilhamento das tabelas de preços;\nc) observando os limites geográficos da Superintendência Estadual onde a AGF está instalada.', 49),
(11120, 'anexo', 251, 11114, 2, '3.3', 'Havendo mudança em relação à classificação do município onde a AGF está instalada no que diz respeito aos “Corredores de Negócios”, o órgão regional de gestão dos canais de atendimento terceirizado deverá reavaliar o território de atuação e coleta, com a finalidade de atender o disposto no item 3 e seus subitens.', '', 50),
(11121, 'anexo', 251, NULL, 1, '4', 'COLETA', '', 51),
(11122, 'anexo', 251, 11121, 2, '4.1', 'A seu critério, a franqueada poderá disponibilizar coleta de objetos nas instalações/endereços indicados pelos clientes, desde que esses estejam dentro de seu território de atuação, responsabilizando-se pelos respectivos custos e riscos da operação.', '', 52),
(11123, 'anexo', 251, 11121, 2, '4.2', 'As franqueadas habilitadas a atender clientes com postagem classificada como industrial deverão realizar as coletas nos locais pré-definidos, responsabilizando-se pelos respectivos custos e riscos da operação, conforme disposto no subitem 7.4.3.1 do contrato de franquia postal, quando a instalação área acessória nas instalações do cliente não for obrigatória ou possível.', '', 53),
(11124, 'anexo', 251, 11121, 2, '4.3', 'A AGF não poderá realizar prospecção de clientes e/ou coleta fora dos limites do seu território de atuação e coleta.', '', 54),
(11125, 'anexo', 251, 11124, 3, '4.3.1', 'A excepcionalização do disposto no subitem 4.3, poderá ocorrer, por tempo determinado, para atender às demandas interesse público, quando autorizado pelo órgão corporativo de gestão administrativa dos instrumentos contratuais.', '', 55),
(11126, 'anexo', 251, 11124, 3, '4.3.2', 'As autorizações de coleta fora do território de atuação da AGF que foram concedidas pelo órgão regional de gestão dos canais terceirizados, em razão de normas anteriormente vigentes, perderão sua validade em até 90 (noventa) dias, após a publicação deste Anexo 2.', '', 56),
(11127, 'anexo', 251, 11121, 2, '4.4', 'A realização de coleta, não autorizada, fora do seu território de atuação implicará à AGF:', '', 57),
(11128, 'anexo', 251, 11127, 4, 'a', 'acréscimo de pontos ao histórico de irregularidade da AGF, conforme disposto no quadro de ocorrências de descumprimento contratual do contrato de franquia postal;', '', 58),
(11129, 'anexo', 251, 11127, 4, 'b', 'débito integral da remuneração auferida pela AGF, bem como as atualizações monetárias previstas no contrato de franquia postal, sobre as postagens relativas aos contratos comerciais cujos objetos foram coletados irregularmente.', '', 59),
(11130, 'anexo', 251, 11121, 2, '4.5', 'Nas situações em que os Correios não puderem atender ao pedido de coleta extra na AGF, a seu critério a franqueada poderá interagir com o órgão regional de gestão operacional para definir em qual unidade operacional da estrutura dos Correios poderá entregar a carga excedente/sazonal.', '', 60),
(11131, 'anexo', 251, 11130, 3, '4.5.1', 'A realização de entrega de carga excedente em unidade operacional da estrutura dos Correios não ensejará remuneração complementar a franqueada.', '', 61),
(11132, 'anexo', 251, NULL, 1, '5', 'SITUAÇÕES DE VEDAÇÃO DE EXECUÇÃO OPERACIONAL DE SERVIÇOS POR AGF', '', 62),
(11133, 'anexo', 251, 11132, 2, '5.1', 'Serviços que não estejam autorizados para a prestação por AGF no Anexo 3 do contrato de franquia postal.', '', 63),
(11134, 'anexo', 251, 11132, 2, '5.2', 'Serviços decorrentes de contrato comercial celebrados pelos Correios com pessoa jurídica cujo proprietário e/ou sócio participe da composição societária da franqueada.', '', 64),
(11135, 'anexo', 251, 11132, 2, '5.3', 'Serviços que se caracterizam pela postagem descentralizada de encomendas para um único destinatário, exceto os serviços constantes no Anexo 3 deste Capítulo.', '', 65);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(11136, 'anexo', 251, 11132, 2, '5.4', 'Serviço que se caracterizam pela postagem de objetos com remetente diverso da pessoa jurídica contratante, exceto:', 'a) quando se tratar de instituições bancárias, administradoras de cartões de crédito, entregadores de encomendas, órgãos (setores específicos da mesma empresa contratante), filiais, ou, no caso de holding, dessa e suas subsidiárias e controladas, cuja utilização do contrato for autorizada pelos Correios, conforme previsto no instrumento contratual;\nb) quando se tratar dos serviços de mala direta em contratos celebrados com gráficas, agências de publicidade, agências promotoras de eventos e/ou de marketing direto, podendo ser indicado, no objeto, a razão social, marcas e similares, e o respectivo endereço do seu cliente como remetente;\nc) para os clientes com os pacotes de marketplace de encomendas, que é definido como: plataforma eletrônica onde vendedores e compradores podem anunciar, pesquisar, vender, comprar e realizar o pagamento dos produtos, com toda a infraestrutura necessária de uma loja virtual, incluindo seus fornecedores de soluções tecnológicas, desde que comprovado o vínculo relacionado ao negócio de marketplaces e que as encomendas sejam geradas exclusivamente via intermediação.', 66),
(11137, 'anexo', 251, 11132, 2, '5.5', 'Quando reportar-se à execução de atividades relativas aos produtos e serviços postais previstos no Art. 9º da Lei nº. 6.538/78, contratadas por instrumento próprio celebrado pelos Correios com seus clientes, cujas características de volume ou quantidade os classifiquem como industrial ou atacado.', '', 67),
(11138, 'anexo', 251, 11137, 3, '5.5.1', 'Serão assim considerados na situação acima, aqueles que possuem pelo menos uma das características indicadas a seguir:', '', 68),
(11139, 'anexo', 251, 11138, 4, 'a', 'quando sua formatação operacional não preveja a postagem em agência;', '', 69),
(11140, 'anexo', 251, 11138, 4, 'b', 'possuam formatação operacional especial, que exija investimentos não previstos inicialmente no edital de licitação, bem como a execução de atividades complementares, diversas do padrão dos serviços postais realizados em agências;', '', 70),
(11141, 'anexo', 251, 11138, 4, 'c', 'possuam preços customizados que impliquem em margem de lucros reduzidas;', '', 71),
(11142, 'anexo', 251, 11138, 4, 'd', 'quando necessitem de manifestação formal de adesão ou habilitação em razão das condições presentes nos alíneas “b” e/ou “c”, até que a Franqueada disponibilize o Termo de Adesão ou documento formal onde consigne o reconhecimento e aceitação das condições específicas para a prestação do serviço em pauta;', '', 72),
(11143, 'anexo', 251, 11138, 4, 'e', 'postagens dos serviços de Carta, na modalidade a faturar, para clientes órgãos públicos e entidades públicas, devem observar:', 'I - salvo para os objetos contendo o rótulo de endereçamento padronizado com a Estampa 2D, rótulo gerado na Plataforma de Pré-postarem (PPN), em AGF, devem ser, obrigatoriamente, franqueadas por Máquinas de Franquear Digital ou com etiqueta física de registro, quando aplicável, inclusive para clientes Pessoas Jurídicas de Direito Privado;\nII - o volume/quantidade de postagem de atacado são: limite de 27.500 (vinte e sete mil e quinhentos) objetos/mês, multiplicado pela unidade/indexador referente ao Primeiro Porte da Carta (PPC) por contrato e por AGF (MCU);\nIII - as AGFs que ultrapassarem o faturamento mensal estabelecido não serão remuneradas pelas postagens acima do limite excedidos, e em razão disso, não serão penalizadas pelas regras previstas no Anexo 4 do Contrato de Franquia Postal.', 73),
(11144, 'anexo', 251, 11132, 2, '5.6', 'Realizar a prestação de postagem classificada como industrial sem a devida habilitação da unidade pelos Correios, conforme disposto no item 7 deste Anexo 2.', '', 74),
(11145, 'anexo', 251, NULL, 1, '6', 'SITUAÇÕES DE IMPEDIMENTOS PARA EXECUÇÃO OPERACIONAL DE SERVIÇO PELA(S) AGF(S)', '', 75),
(11146, 'anexo', 251, 11145, 2, '6.1', 'A execução operacional de serviço pela AGF relativa a contratos comerciais dos Correios não poderá ser realizada quando:', '', 76),
(11147, 'anexo', 251, 11146, 4, 'a', 'se qualquer sócio da pessoa jurídica do cliente com contrato comercial com os Correios mantém vínculo societário com a pessoa jurídica de franqueada, conforme orientações deste Anexo 2;', '', 77),
(11148, 'anexo', 251, 11146, 4, 'b', 'existência da prática, pela AGF, de condutas ilícitas que causem comprovado prejuízo a imagem institucional, ao erário ou a terceiros, especificadas no quadro de ocorrências de descumprimento contratual do contrato de franquia postal, sem prejuízo da responsabilização civil e criminal da AGF e de seus representantes nos termos da legislação específica.', '', 78),
(11149, 'anexo', 251, 11146, 3, '6.1.1', 'Sócios comuns entre as pessoas jurídicas do cliente e da franqueada.', '6.1.1.1 A AGF não poderá prestar serviços relativos a contratos comerciais celebrados entre os Correios e pessoas jurídicas cujo(s) sócio(s) seja(m) proprietário(s) ou tenha participação acionária na pessoa jurídica da AGF.\n6.1.1.2 A não observância do item 6.1.1.1 acarretará, cumulativamente, à AGF:\na) débito integral da remuneração auferida pela AGF, bem como as atualizações monetárias previstas no contrato de franquia postal, sobre as postagens relativas a execução operacional dos serviços relativos a contratos comerciais celebrados com os Correios e pessoas jurídica, na qual existam sócios comuns com a franqueada;\nb) aplicação de irregularidade prevista no quadro de ocorrências de descumprimento contratual do contrato de franquia postal.', 79),
(11150, 'anexo', 251, NULL, 1, '7', 'ORIENTAÇÃO GERAL SOB O SUBPROCESSO DE HABILITAÇÃO/ADESÃO PARA EXECUÇÃO OPERACIONAL DE POSTAGENS CLASSIFICADAS COMO INDUSTRIAL PELAS AGF', '', 80),
(11151, 'anexo', 251, 11150, 2, '7.1', 'Tramitação do processo de habilitação', '', 81),
(11152, 'anexo', 251, 11151, 3, '7.1.1', 'A tramitação de todos os documentos e comunicações relacionados ao processo administrativo de habilitação para execução operacional de serviços de encomenda classificados como industrial deverá ocorrer, preferencialmente, por meio do Sistema Eletrônico de Informação (SEI), ou outro que vier a substituí-lo:', '', 82),
(11153, 'anexo', 251, 11152, 4, 'a', 'outros meios, físicos ou digitais, de comunicação com os atores do processo podem ser utilizados nas oportunidades em que o SEI não estiver disponível;', '', 83),
(11154, 'anexo', 251, 11152, 4, 'b', 'utilizando-se outros meios de comunicação:', 'I - os documentos gerados/recebidos deverão ser escaneados e anexados ao processo SEI, observando-se, para tanto, a ordem cronológica de emissão e encaminhamento/recebimento;\nII - deverão ser observado os mecanismos de comprovação de recebimento oferecido pelos Correios, os quais devem ser acrescidos ao processo de habilitação da unidade;\nIII - a contagem de prazo deve considerar as especificidades contratuais relativas ao recebimento das comunicações, quando aplicável.', 84),
(11155, 'anexo', 251, 11151, 3, '7.1.2', 'A descrição do fluxo procedimental descritos para habilitação da AGF para execução operacional das postagens classificadas como industriais estão dispostos no Anexo 3 deste Capítulo.', '', 85),
(11156, 'anexo', 251, 11150, 2, '7.2', 'Execução Operacional', '', 86),
(11157, 'anexo', 251, 11156, 3, '7.2.1', 'A adesão da Agência de Correios Franqueada à execução operacional das postagens classificadas como industriais implica do conhecimento e na obrigatoriedade de realizar as atividades inerentes às postagens dessa natureza, conforme consignado na categorização do(s) cliente(s) por ela atendido(s).', '', 87),
(11158, 'anexo', 251, 11156, 3, '7.2.2', 'A franqueada será remunerada pela execução do conjunto de atividades correlacionadas às postagens classificadas como industriais, cujo percentual está estabelecido na tabela R5, do Anexo 3 do contrato de franquia postal, ou outra que vier a substitui-la no instrumento contratual.', '', 88),
(11159, 'anexo', 251, 11156, 3, '7.2.3', 'A qualquer tempo, poderão ser incluídos ou excluídos serviços na(s) tabela(s) que agrupa(m) os itens classificados como postagens industriais no Anexo 3 do contrato de franquia postal, considerando para tanto a meta ou o potencial de volume carga postal de serviço atual ou novo que se enquadre nos conceitos estabelecidos pelos pela legislação aplicável e/ou pelos Correios e que sejam inclusos nos contratos comerciais dos clientes, conforme sua classificação.', '', 89),
(11160, 'anexo', 251, 11156, 3, '7.2.4', 'A inclusão de novos itens na(s) tabela(s) classificados como postagens industriais poderá implicar na inclusão ou exclusão de atividades/etapas da execução operacional padrão para os serviços dessa natureza.', '', 90),
(11161, 'anexo', 251, 11156, 3, '7.2.5', 'No que tange ao processo de habilitação, será considerado como endereço das instalação do cliente, para realização de coleta pela AGF:', 'I - o endereço da matriz e da filial;\nII - armazém ou assemelhado do cliente;\nIII - seller (vendedor); ou\nIV - preposto do cliente: armazém contratado ou assemelhados que realize parte ou toda a operação de Picking e Packing, gráficas etc.\n7.2.5.1 Não se aplica como ocorrência de descumprimento contratual as oportunidades em que, voluntariamente, o cliente ou seu representante/contratado comparece na AGF de sua escolha, para realização da postagem, independentemente, se o domicílio do cliente onde originou-se a carga postal seja fora do território de atuação da agência.', 91),
(11162, 'anexo', 251, 11156, 3, '7.2.6', 'O atendimento ao cliente com carga classificada como postagem industrial não é exclusivo, podendo um ou mais canais de atendimento próprios e/ou terceirizados atenderem ao mesmo cliente.', '', 92),
(11163, 'anexo', 251, 11156, 3, '7.2.7', 'O processo de execução operacional de postagens classificadas como industriais poderá ser foco de revisão e melhorias, e em decorrência de adequações de atividades ou etapas vigentes na publicação deste Anexo 2.', '', 93),
(11164, 'anexo', 251, 11150, 2, '7.3', 'Atividades Inerentes a Execução Operacional de Postagem Industrial', '', 94),
(11165, 'anexo', 251, 11164, 3, '7.3.1', 'As realização dos itens abaixo relacionados são de cunho obrigatório para a execução operacional da postagens classificados como industriais:', '', 95),
(11166, 'anexo', 251, 11165, 4, 'a', 'coleta programada no endereço definido pelo cliente ou recebimento dos objetos na agência;', '', 96),
(11167, 'anexo', 251, 11165, 4, 'b', 'conferência da Carga;', '', 97),
(11168, 'anexo', 251, 11165, 4, 'c', 'formalização de informação ao cliente quando da ocorrência de divergência na PLP, em consonância com os objetos físicos coletados ou recebidos;', '', 98),
(11169, 'anexo', 251, 11165, 4, 'd', 'realização da postagem no sistema de automação autorizado pelos Correios;', '', 99),
(11170, 'anexo', 251, 11165, 4, 'e', 'execução de plano de triagem específico para entrega da carga industrial aos Correios;', '', 100),
(11171, 'anexo', 251, 11165, 4, 'f', 'utilização de escolta para transporte da carga industrial até a agência/área acessória e à unidade operacional;', 'I - a contratação de escolta é recomendada e insumo para definição da remuneração;\nII - a contratação ou não de escolta é uma liberalidade da Franqueada, haja vista que os riscos e a responsabilidade sobre a carga postal até a entrega aos Correios é exclusivamente dessa.', 101),
(11172, 'anexo', 251, 11165, 4, 'g', 'entrega da carga industrial na unidade operacional de vinculação em horário pré-estabelecido ou em outra indicada previamente pelos Correios;', '', 102),
(11173, 'anexo', 251, 11165, 4, 'h', 'instalação de área acessória nas instalações do cliente;', 'I - da classificação do cliente e das disposições correlacionadas às contrapartidas e benefícios presentes na Matriz de Relacionamento;\nII - do interesse e estrutura instalada do cliente; e\nIII - de autorização prévia dos Correios, conforme requisitos e parâmetros presentes no normativo interno.\n7.3.1.1 A realização de atividades que não estiver contemplada na matriz de relacionamento, contrapartidas e benefícios comuns, pela franqueada ao cliente deverá ser informada aos Correios.', 103),
(11174, 'anexo', 251, 11164, 3, '7.3.2', 'A realização de coleta de carga de objetos postais que sejam classificados como postagem industrial fora do território de atuação da AGF, será enquadrada como ocorrência de descumprimento contratual, nos termos do Anexo 4 do contrato de franquia postal.', '', 104),
(11175, 'anexo', 251, 11164, 3, '7.3.3', 'Quando a realização de coleta não for diária e/ou rotineira, a solicitação de coleta pelo cliente deverá ser realizada preferencialmente no dia útil anterior a data de interesse, de forma a haver tempo hábil para que a AGF inclua o cliente na rota de coletas da unidade:', '', 105),
(11176, 'anexo', 251, 11175, 4, 'a', 'o quantitativo mínimo de objetos deverá ser de 100 (cem) ou mais objetos, para enquadrar-se em coleta para postagem industrial;', '', 106),
(11177, 'anexo', 251, 11175, 4, 'b', 'não há impedimento para que a AGF realize a coleta:', 'I - solicitada em interstício temporal inferior; ou\nII - de quantitativo menor que 100 (cem) objetos, mas nesse caso, a postagem deve ser realizada considerando a tabela de varejo, conforme orientações vigentes.', 107),
(11178, 'anexo', 251, 11164, 3, '7.3.4', 'A AGF poderá negociar com o cliente em relação a periodicidade, frequência e o horário mais adequado para realização da coleta, de forma a viabilizar o melhor custo-benefício para as partes.', '', 108),
(11179, 'anexo', 251, 11164, 3, '7.3.5', 'Havendo solicitação do cliente para realização de coleta com escolta ou ainda de um quantitativo elevado de objetos e a AGF não tiver condições de atender ao pleito devido incompatibilidade de sua estrutura instalada ou de recursos, deverá interagir com o órgão regional de gestão dos canais de atendimento sobre o caso concreto.', '7.3.5.1 As situações dispostas no subitem 7.3.5 não serão passíveis de enquadramento como recusa em atender ao cliente e/ou de recusa/inobservância do cumprimento das atividades inerentes a execução operacional da postagem industrial.', 109),
(11180, 'anexo', 251, 11150, 2, '7.4', 'Desabilitação da AGF para Execução Operacional de Postagens Classificadas como Industriais', '', 110),
(11181, 'anexo', 251, 11180, 3, '7.4.1', 'A recusa ou inobservância do cumprimento das atividades inerentes a execução operacional da postagem classificada como industrial por parte da franqueada após a assinatura do Termo de Adesão, poderá ocasionar:', '', 111),
(11182, 'anexo', 251, 11181, 4, 'a', 'a rescisão do Termo de Adesão/Habilitação e por consequente na desabilitação da AGF para realização dessa atividade, até que se ajuste o motiva da desabilitação;', '', 112),
(11183, 'anexo', 251, 11181, 4, 'b', 'a exclusão dos valores remuneratórios relativos a quaisquer postagens classificadas como industriais realizadas no período de desabilitação;', '', 113),
(11184, 'anexo', 251, 11181, 4, 'c', 'na solicitação aos clientes com carga dessa natureza para utilizarem outras agências na rede de atendimento;', '', 114),
(11185, 'anexo', 251, 11181, 4, 'd', 'no enquadramento em ocorrência de descumprimento contratual, e aplicação de penalidade conforme previsto no Anexo 4 do contrato de franquia postal.', '', 115),
(11186, 'anexo', 251, 11180, 3, '7.4.2', 'Por iniciativa da franqueada, que a qualquer tempo poderá optar por deixar de operacionalizar as postagens classificadas como industriais relativo ao contrato do cliente que:', '', 116),
(11187, 'anexo', 251, 11186, 4, 'a', 'atenda por meio de área acessória nas instalações desse, devendo informar formalmente aos Correios com no mínimo 30 (trinta) dias de antecedência da finalização da operação;', '', 117),
(11188, 'anexo', 251, 11186, 4, 'b', 'atenda por meio de coleta ou na própria agência, devendo formalizar aos Correios essa decisão com no mínimo 15 (quinze) dias de antecedência, para que seja possível informar aos clientes.', '', 118),
(11189, 'anexo', 251, 11180, 3, '7.4.3', 'A revogação do Termo de Adesão por parte da franqueada consiste na desistência de atendimento de postagens classificadas como industriais, não ensejando em enquadramento em ocorrência de descumprimento contratual, desde que observados os prazos estabelecidos no subitem 7.3.2 deste Anexo 2.', '', 119),
(11190, 'anexo', 251, 11180, 3, '7.4.4', 'Os Correios, a qualquer tempo, poderão realizar a desabilitação da AGF, sem necessidade de anuência da franqueada ou concessão de Interstício temporal para a aplicação da decisão:', '', 120),
(11191, 'anexo', 251, 11190, 4, 'a', 'quando houver a identificação de que a agência de Correios franqueada está realizando coleta de objetos para realizar postagens classificada como industrial, sem que tenha ocorrido a habilitação para atendimento ao cliente detentor do contrato comercial;', '', 121),
(11192, 'anexo', 251, 11190, 4, 'b', 'se restar comprovado, descumprimento pela franqueada das obrigações assumidas a partir da assinatura do Termo de Adesão/habilitação;', 'c) nas situações de eventual adequação de modelagem relativas às fases de execução operacional tornem as postagens industriais inadequadas ou inviáveis para captação por AGF, inclusive sob os aspectos estruturais e financeiros;\nd) quando as premissas do modelo de franquia, em relação ao custo da remuneração pela operação e vantajosidade para as partes, deixaram de ocorrer em relação à postagens classificadas como industriais;\ne) que a concessão para execução operacional de postagens classificadas como industriais pelas AGF, não atendam as diretrizes da estratégia de canais de atendimento.\n7.4.4.1 A suspensão da habilitação de que trata o subitem 7.4.4 será pelo período de 6 (seis) meses, sem prejuízo do enquadramento de ocorrência de descumprimento contratual Anexo 4 do contrato de franquia postal, sendo a mesma extensiva a todos os clientes.', 122),
(11193, 'anexo', 251, 11150, 2, '7.5', 'Situações de Impedimento', '', 123),
(11194, 'anexo', 251, 11193, 3, '7.5.1', 'São situações de impedimento para habilitação de AGF para execução operacional de postagens classificadas como industriais, a existência de:', '', 124),
(11195, 'anexo', 251, 11194, 4, 'a', 'processo administrativo em andamento para apuração de irregularidade(s) prevista(s) no instrumento contatual, que incidir à rescisão unilateral do contrato, para o qual já conste decisão emitida pelo Superintendente Estadual;', '', 125),
(11196, 'anexo', 251, 11194, 4, 'b', 'processo administrativo relativo à suspensão de execução de postagem classificada como industrial enquanto durar o período de suspensão;', '', 126),
(11197, 'anexo', 251, 11194, 4, 'c', 'a AGF tenha em seu histórico, na data do protocolo da solicitação, irregularidades que somadas, nos últimos 6 (seis) meses, representem mais de 70% da pontuação máxima do quadro de ocorrências de descumprimento contratual, considerando o disposto no Anexo 4 do contrato de franquia postal;', '', 127),
(11198, 'anexo', 251, 11194, 4, 'd', 'o cliente estiver localizado fora da região de atendimento/território de atuação da Agência de Correios Franqueada, foco da análise.', '', 128),
(11199, 'anexo', 251, 11150, 2, '7.6', 'Requisitos para Análise da Viabilidade de Habilitação de AGF para Execução Operacional de Postagem Classificada como Industriais Relativas à Contrato Comercial de Clientes com Histórico de Postagem em Unidades Operacionais', '', 129),
(11200, 'anexo', 251, 11199, 3, '7.6.1', 'Poderá ser autorizada a ampliação dos canais de atendimento, com inclusão de AGF, para atendimento de clientes com contrapartida e benefícios relacionados às postagens classificadas como industriais, que tenham histórico de postagem em unidades operacionais nos últimos 6 (seis) meses, desde que atendidos os requisitos presentes neste item:', ' ', 130),
(11201, 'anexo', 251, 11200, 4, 'a', 'preenchimento do Anexo 6 deste Capítulo no qual consta a solicitação formal do cliente ao órgão regional de gestão do contrato comercial (essencial incluir a motivação);', '', 131),
(11202, 'anexo', 251, 11200, 4, 'b', 'preenchimento do Anexo 7 deste Capítulo, no qual consta a comunicação do gestor regional de vendas para a área de operações (Gestor da Unidade Operacional e seu Gerente Regional de Operações imediato);', '', 132),
(11203, 'anexo', 251, 11200, 4, 'c', 'atendimento aos demais critérios estabelecidos neste capítulo e seus anexos.', '', 133),
(11204, 'anexo', 251, 11199, 3, '7.6.2', 'Caso não seja identificado histórico de postagem pelo clientes em unidades operacionais no período citado neste subitem, deverá ser ofertado ao cliente o cartão Correios fácil (desvinculado).', '* * * * *', 134),
(11205, 'anexo', 252, NULL, 1, '1', 'DESCRIÇÃO DO SUBPROCESSO', '', 0),
(11206, 'anexo', 252, 11205, 2, '1.1', 'Procedimentos do Cliente com postagem Industrial do segmento encomendas', '', 1),
(11207, 'anexo', 252, 11206, 3, '1.1.1', 'Apresentar ao órgão regional de gestão dos contratos comerciais solicitação, formal, quando desejar incluir o rol de unidades de captação onde pretenda realizar postagens classificadas como industriais, agências de Correios franqueadas (AGF).', '', 2),
(11208, 'anexo', 252, 11206, 3, '1.1.2', 'Preencher o Anexo 6 deste Capítulo solicitando habilitação de postagem em AGF, caso pretenda deixar de realizar postagem industrial em unidade operacional.', '', 3),
(11209, 'anexo', 252, 11206, 3, '1.1.3', 'Atender aos critérios para postagem industrial, devendo observar o volume mínimo de encomendas postados conforme o pacote de serviço contratado e as orientações estabelecidas, bem como a concentração de encomendas por cliente e ponto de coleta.', '', 4),
(11210, 'anexo', 252, 11206, 3, '1.1.4', 'Preparar a Pré-Lista de Postagem - PLP, nos moldes orientados pelos Correios e com no mínimo 100 (cem) objetos cada uma.', 'Nota: as PLP relativas as postagens classificadas como industriais que não observarem a concentração mínima de 100 (cem) encomendas terão os objetos faturados na tarifa normal de varejo, mesmo que posteriormente.', 5),
(11211, 'anexo', 252, 11205, 2, '1.2', 'Procedimentos do Pessoa Jurídica da Franqueada', '', 6),
(11212, 'anexo', 252, 11211, 3, '1.2.1', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados o formulário de habilitação para operacionalização da postagem industrial de encomenda, para análise da viabilidade de atendimento ao cliente foco da consulta.', '', 7),
(11213, 'anexo', 252, 11211, 3, '1.2.2', 'Encaminhar ao órgão regional de gestão dos canais de atendimento terceirizados o formulário de habilitação para operacionalização da postagem industrial de encomenda, devidamente assinado pelo representante legal da unidade ou manifestar-se quando não houver interesse em aderir, em até 2 (dois) dias úteis contados do recebimento do formulário.', '', 8),
(11214, 'anexo', 252, 11211, 3, '1.2.3', 'Sanar o impedimento, indicado que inviabilize a execução operacional de postagens classificadas como industrial e informar ao órgão regional de gestão dos canais de atendimento sobre o fato pedindo a efetivação do processo de habilitação, quando houver interesse.', '', 9),
(11215, 'anexo', 252, 11211, 3, '1.2.4', 'Realizar a execução operacional das postagens classificadas como industriais conforme orientações específicas da área de formatação e gestão dos serviços, bem como do normativo interno e deste documento, tais como:', '', 10),
(11216, 'anexo', 252, 11215, 4, 'a', 'coletar as encomendas no endereço definido pelo cliente;', '', 11),
(11217, 'anexo', 252, 11215, 4, 'b', 'viabilizar a escolta da carga, se necessário, conforme avaliação de risco da franqueada;', '', 12),
(11218, 'anexo', 252, 11215, 4, 'c', 'preparar da carga e a PLP, em substituição ao cliente, quando essa metodologia for pré-acordada;', '', 13),
(11219, 'anexo', 252, 11215, 4, 'd', 'recepção e conferência da carga;', '', 14),
(11220, 'anexo', 252, 11215, 4, 'e', 'utilizar, obrigatoriamente, o Sistema Validador de Postagem - SVP para realizar a postagem industrial de encomendas:', 'I - na postagem via SVP o controle é realizado de forma automática. Quando o quantitativo mínimo de encomendas por PLP ou mídia não for atingido, há possibilidade de utilização da mesma pré-lista de postagem, com a alteração dos códigos para as tabelas de varejo-contrato, desde que haja anuência do cliente. Caso o cliente não concorde com a alteração de códigos, ele poderá gerar um novo arquivo com o quantitativo ajustado;\nII - quando a postagem via SVP não for possível, por exceção, poderá ocorrer via SARA. No entanto, deve-se realizar o controle manual do quantitativo mínimo obrigatório para a postagem ser efetuada no código industrial.', 15),
(11221, 'anexo', 252, 11215, 4, 'f', 'Informar ao cliente quando a PLP ou mídia:', 'I - não houver o quantitativo mínimo exigido, quanto ao ajuste necessário do arquivo, com a alteração dos códigos para as tabelas de varejo-contrato ou com a inserção das encomendas faltantes, até completar o mínimo de encomendas exigido para a postagem industrial;\nII - houver excesso de objetos quando comparados ao descrito no arquivo, para identificar a providência a ser tomada, inclusão na PLP ou mídia, devolução ao cliente etc;', 16),
(11222, 'anexo', 252, 11215, 4, 'g', 'realizar a triagem, conforme plano definido pelos Correios;', '', 17),
(11223, 'anexo', 252, 11215, 4, 'h', 'entregar da carga em unidade operacional definida pelos Correios.', '', 18),
(11224, 'anexo', 252, 11205, 2, '1.3', 'Procedimentos do Órgão Regional de Gestão dos Canais de Atendimento Terceirizados', '', 19),
(11225, 'anexo', 252, 11224, 3, '1.3.1', 'Receber a solicitação da força de vendas com a indicação da(s) agência(s) para verificação da viabilidade de habilitação para execução operacional de postagem industrial, conforme solicitação do cliente, bem como os demais dados necessários para o preenchimento do formulário de habilitação para operacionalização da postagem industrial de encomendas.', '', 20),
(11226, 'anexo', 252, 11224, 3, '1.3.2', 'Analisar se a(s) unidade(s) atende(m) aos requisitos estabelecidos no item 7, Anexo 2 deste Capítulo e no contrato de franquia postal para captação de postagem industrial.', '', 21),
(11227, 'anexo', 252, 11224, 3, '1.3.3', 'Identificar a existência de pontuação da AGF pré-selecionada que seja impedimento para atendimento ao cliente com postagem industrial, conforme disposto no item 7, Anexo 2 deste Capítulo.', '', 22),
(11228, 'anexo', 252, 11224, 3, '1.3.4', 'Encaminhar à(s) unidade(s) pré-selecionada(s) solicitação para preenchimento do formulário de habilitação para operacionalização da postagem industrial de encomenda, Anexo 5 deste Capítulo.', '', 23),
(11229, 'anexo', 252, 11224, 3, '1.3.5', 'Receber da(s) AGF pré-selecionada(s) o formulário de habilitação para operacionalização da postagem industrial de encomenda, verificando se o mesmo foi corretamente preenchido.', '', 24),
(11230, 'anexo', 252, 11224, 3, '1.3.6', 'Devolver à AGF o formulário de habilitação para operacionalização da postagem industrial de encomenda, quando verificado algum equívoco no preenchimento ou na assinatura, para correção.', 'Nota: a falta de retorno do formulário de habilitação para operacionalização da postagem industrial de encomenda, no prazo de até 2 (dois) dias úteis após o recebimento do formulário, será considerado como desinteresse pela AGF em prestar o(s) serviços(s) ao cliente.', 25),
(11231, 'anexo', 252, 11224, 3, '1.3.7', 'Encaminhar formalmente à força de vendas a confirmação da(s) agência(s) apta(s) para a execução operacional de postagem industrial, anexando o formulário de habilitação para operacionalização da postagem industrial de encomenda, Anexo 5 deste Capítulo, completamente preenchido.', '', 26),
(11232, 'anexo', 252, 11224, 3, '1.3.8', 'Interagir com o Órgão Regional de Gestão das Unidades Operacionais para definição da unidade operacional que irá receber a carga industrial e informar à AGF.', '', 27),
(11233, 'anexo', 252, 11224, 3, '1.3.9', 'Dos prazos que envolvam habilitação de agência para postagem industrial do segmento de encomendas:', '', 28),
(11234, 'anexo', 252, 11233, 4, 'a', 'D+1: analisar se o pedido está de acordo com as regras estabelecidas no MANCAT 26/4;', '', 29),
(11235, 'anexo', 252, 11233, 4, 'b', 'D+1: analisar o posicionamento da AGF e comunicar a área de suporte a vendas e/ou solicitar o posicionamento do gestor da unidade operacional;', '', 30),
(11236, 'anexo', 252, 11233, 4, 'c', 'D+0: comunicar à AGF quanto a resposta do gestor da unidade operacional.', '', 31),
(11237, 'anexo', 252, 11205, 2, '1.4', 'Procedimentos do Órgão Regional de Gestão de Contratos Comerciais/Vendas', '', 32),
(11238, 'anexo', 252, 11237, 3, '1.4.1', 'Comunicar o gestor da unidade operacional que recebe a postagem do cliente e seu gerente regional de operações imediato, informando a quantidade de encomendas que deixará de ser postada e data prevista para a término da operação naquela unidade conforme o Anexo 7, deste capítulo.', '', 33),
(11239, 'anexo', 252, 11237, 3, '1.4.2', 'Disponibilizar ao cliente informações sobre o rol de unidades passíveis de habilitação para captação de postagem industrial, quando couber.', '', 34),
(11240, 'anexo', 252, 11237, 3, '1.4.3', 'Encaminhar ao órgão regional de gestão dos canais de atendimento terceirizados a indicação da(s) AGF(s) pré-selecionada(s) pelo cliente para verificação da viabilidade de habilitação, quando se tratar de postagem industrial.', '', 35),
(11241, 'anexo', 252, 11237, 3, '1.4.4', 'Receber do órgão regional de gestão dos canais de atendimento terceirizados a confirmação da(s) AGF(s) passível(is) de habilitação para atendimento ao cliente.', '', 36),
(11242, 'anexo', 252, 11237, 3, '1.4.5', 'Encaminhar ao órgão corporativo de gestão dos serviços cujas características de contrapartidas e benefícios viabilizem a postagem industrial a solicitação de habilitação da(s) AGF para uso das tabelas de preço de postagem industrial de encomendas.', '', 37),
(11243, 'anexo', 252, 11237, 3, '1.4.6', 'Comunicar ao cliente quando do término do processo de habilitação qual(is) a(s) AGF que já pode(m) realizar a operacionalização das postagens classificadas como industriais relativos ao seu contrato.', '', 38),
(11244, 'anexo', 252, 11237, 3, '1.4.7', 'Informar as AGFs habilitadas a data em que o cliente iniciará suas postagens na unidade.', '', 39),
(11245, 'anexo', 252, 11237, 3, '1.4.8', 'Dos prazos que envolvam habilitação de agência para postagem industrial do segmento de encomendas:', '', 40),
(11246, 'anexo', 252, 11245, 4, 'a', 'D+0: verificar se o cliente atende as regras da política comercial e encaminhar para a área de suporte a vendas;', '', 41),
(11247, 'anexo', 252, 11245, 4, 'b', 'D+0: comunicar o cliente;', '', 42),
(11248, 'anexo', 252, 11245, 4, 'c', 'D+1: analisar as regras do MANCAT 26/4 e preencher o formulário para envio a área de atendimento ou devolver para a Força de Vendas;', '', 43),
(11249, 'anexo', 252, 11245, 4, 'd', 'D+1: formalizar justificativa da impossibilidade para a área de vendas;', '', 44),
(11250, 'anexo', 252, 11245, 4, 'e', 'D+1: encaminhar o processo SEI ao Órgão Corporativo de gestão do segmento de encomendas solicitando a habilitação da AGF;', '', 45),
(11251, 'anexo', 252, 11245, 4, 'f', 'D+0: informar a Força de vendas quanto a efetivação da habilitação no ERP.', '', 46),
(11252, 'anexo', 252, 11237, 3, '1.4.9', 'Informar ao cliente sobre a desabilitação da AGF foco da informação e cientificá-lo sobre os demais canais de atendimento à disposição para captação das suas postagens.', '', 47),
(11253, 'anexo', 252, 11237, 3, '1.4.10', 'Informar, quando identificado, ao órgão regional de gestão dos canais de atendimento a identificação de postagem de clientes com carga classificada como industrial que fiquem fora do território de atuação das AGF, cujo(a):', '', 48),
(11254, 'anexo', 252, 11253, 4, 'a', 'contrato comercial seja originado de outra Superintendência Estadual;', '', 49),
(11255, 'anexo', 252, 11253, 4, 'b', 'tabela de precificação aplicável ao município domicilio das instalações do cliente seja divergente do local de postagem.', 'Nota: excetua-se dessa rotina clientes classificados na política comercial como marketplace, concentrador de carga e assemelhados.', 50),
(11256, 'anexo', 252, 11205, 2, '1.5', 'Procedimentos do Órgão Corporativo de gestão do segmento encomenda', '', 51),
(11257, 'anexo', 252, 11256, 3, '1.5.1', 'Receber do processo administrativo de habilitação/desabilitação do órgão regional de gestão dos canais de atendimento com solicitação para habilitar/desabilitar a AGF no ERP, nos códigos vigentes referentes à postagem industrial.', '', 52),
(11258, 'anexo', 252, 11256, 3, '1.5.2', 'Viabilizar a habilitação/desabilitação da AGF foco do processo no ERP, nos códigos vigentes referentes à postagem industrial.', '', 53),
(11259, 'anexo', 252, 11205, 2, '1.6', 'Procedimentos do Órgão Regional de Gestão Operacional', '', 54),
(11260, 'anexo', 252, 11259, 3, '1.6.1', 'Receber pedido de indicação de Centro de Tratamento ou unidade operacional para recepcionar a carga de postagem industrial captada pela AGF do órgão regional de gestão dos canais de atendimento.', '', 55),
(11261, 'anexo', 252, 11259, 3, '1.6.2', 'Indicar a unidade operacional para recebimento das postagens classificadas como industriais observando os limites da região de atuação da AGF, conforme conceito estabelecido no item 3 do Anexo 2 deste Capítulo.', '1.6.2.1 Consultar a franqueada sobre a possibilidade de entregar, excepcionalmente, a carga industrial em unidade operacional dos Correios fora do território de atuação e coleta da AGF, quando verificado a inexistência neste espaço geográfico de unidade operacional com estrutura instalada apta a receber/tratar as postagens classificados como industriais e para qual não se identificou, em curto prazo, perspectiva de adequação estrutural.\n1.6.2.1.1 Priorizar na definição de que trata o item 1.6.2.1 deste capítulo a unidade operacional, que tenha a capacidade adequada ao recebimento/tratamento da carga industrial, que seja mais próxima ao município onde está instalada a AGF.\n1.6.2.2 Receber a resposta da franqueada e assinar o termo de autorização/anuência para entrega de carga industrial em unidade operacional estabelecida que esteja localizada fora do território de atuação e coleta da AGF, quando houver aceitação da indicação pela terceirizada.\n1.6.2.2.1 Informar ao órgão regional de gestão dos canais de atendimento terceirizados sobre eventual impossibilidade de realizar o recebimento da carga classificada como industrial, quando da inexistência no espaço geográfico de unidade operacional com estrutura instalada apta para receber/tratar a carga classificada como industrial e não houver aceitação pela franqueada da unidade indicada fora do território de atuação da AGF.', 56),
(11262, 'anexo', 252, 11259, 3, '1.6.3', 'Disponibilizar à(s) AGF(s) habilitada(s) o plano triagem a ser executado para as encomendas classificadas como industrial captadas pela agência.', '', 57),
(11263, 'anexo', 252, 11259, 3, '1.6.4', 'Elaborar e executar o plano de desmobilização ou realocação dos recursos utilizados no atendimento aos clientes com carga classificada como industrial, que definirem a realização de postagem em outra unidade própria ou terceirizada, conforme a data prevista para o término da operação.', '', 58),
(11264, 'anexo', 252, 11259, 3, '1.6.5', 'Estabelecer, em até D+1, o horário de recebimento da carga conforme plano de triagem e comunicar ao órgão regional de gestão dos canais de atendimento terceirizados.', '* * * * *', 59),
(11265, 'anexo', 256, NULL, 2, '1.1', 'Formalização pela Pessoa Jurídica da Franqueada da adesão à habilitação da Agência de Correios Franqueada acima identificada para realizar a execução operacional de postagens classificadas como industriais pelos Correios.', '', 0),
(11266, 'anexo', 256, NULL, 2, '1.2', 'Estabelecer que o prazo de vigência da habilitação da Franqueada para a execução operacional de postagem industrial perdura enquanto:', 'I - Os serviços cuja postagem é classificada como industrial fizerem parte do Anexo 3 do Contrato de Franquia Postal;\nII – Persistir o interesse da Franqueada em realizar a execução operacional de postagens classificadas como industriais;\nIII - Não houver aplicação de penalidade de enseje na desabilitação da AGF ou a rescisão do Contrato de Franquia Postal.\n2. DA DESABILITAÇÃO DA AGF', 1),
(11267, 'anexo', 256, NULL, 2, '2.1', 'A recusa ou inobservância do cumprimento das atividades inerentes a execução operacional da postagem industrial por parte da Franqueada, após a assinatura do Termo de Adesão, poderá ocasionar:', 'I - A rescisão do Termo de Adesão e na desabilitação da AGF, por 6 meses;\nII - Exclusão dos valores remuneratórios relativos à quaisquer postagens classificadas industriais realizados no período de desabilitação;\nIII - Na solicitação aos clientes com carga dessa natureza para utilizarem outras agências na rede de atendimento;\nIV - No enquadramento em ocorrência de descumprimento contratual, e aplicação de penalidade conforme previsto no Anexo 4 do Contrato de Franquia Postal - Quadro de Ocorrência de Descumprimento Contratual.', 2),
(11268, 'anexo', 256, NULL, 2, '2.2', 'A Franqueada, a qualquer tempo, poderá optar por deixar de operacionalizar as postagens classificadas como industriais relativos ao contrato do cliente que atenda por meio de:', 'I - Área acessória nas instalações desse, devendo informar formalmente aos Correios com no mínimo 30 (trinta) dias de antecedência da finalização da operação;\nII - Coleta ou na própria agência, devendo formalizar aos Correios essa decisão com no mínimo 15 (quinze) dias de antecedência para que seja possível informar aos clientes.', 3),
(11269, 'anexo', 256, NULL, 2, '2.3', 'A revogação do Termo de Adesão por parte da Franqueada consiste na desistência de realização das postagens classificas como industriais, não sendo enquadrada em ocorrência de descumprimento contratual, desde que observados os prazos estabelecidos no item 4.2 deste documento.', '', 4),
(11270, 'anexo', 256, NULL, 2, '2.4', 'Os Correios, a qualquer tempo, poderão realizar a desabilitação da AGF, sem necessidade de anuência da Franqueada ou concessão de interstício temporal para a aplicação da decisão, considerando a identificação de:', 'I - Descumprimento pela Franqueada das obrigações assumidas a partir da assinatura deste documento;\nII - Que eventual adequação de modelagem relativas às fases de execução operacional tornem as postagens industriais inadequadas ou inviáveis para captação por AGF, inclusive sob os aspectos estruturais e financeiros;\nIII - Que as premissas do modelo de franquia, em relação ao custo da remuneração pela operação e vantajosidade para as partes, deixaram de ocorrer em relação às postagens classificadas como industrial;\nIV - Que a concessão para execução operacional das postagens classificadas como industrial pelas AGF, não atendam as diretrizes da estratégia de canais de atendimento.\n3. ATENDIMENTO AOS CLIENTES', 5),
(11271, 'anexo', 256, NULL, 2, '3.1', 'Não há vínculo de exclusividade de qualquer natureza entre a AGF e o cliente com carga classificada como industrial, podendo um ou mais canais de atendimento próprios ou terceirizados atenderem ao mesmo cliente.', '', 6),
(11272, 'anexo', 256, NULL, 2, '3.2', 'O cliente tem a liberalidade de escolher os canais de atendimento habilitados que irão atendê-lo, bem como definir, a qualquer tempo, por não utilizar o serviço de uma AGF que já tenha lhe prestado serviço, sem que isso ocasione:', 'I - Necessidade de comunicação ou de anuência prévia, exceto nos casos em que houver área acessória nas instalações do cliente;\nII - Direito de qualquer natureza, inclusive, de compensação financeira à Franqueada, mesmo que essa tenha realizado investimentos para atendimento ao cliente.', 7),
(11273, 'anexo', 256, NULL, 2, '3.3', 'Não é considerado irregularidade, após a assinatura deste Termo de Adesão, a aceitação e postagem de classificadas como industrial de clientes, ou seu representante, que se apresente pessoalmente e voluntariamente a AGF para realização de postagem, desde que cumpra os demais requisitos de carga dessa natureza.', '', 8),
(11274, 'anexo', 256, NULL, 2, '3.4', 'A Franqueada é responsável integralmente:', 'I - pelas informações/dados de postagens que vier a incluir/lançar na solução de automação do atendimento fornecido pelos Correios;\nII - pelos valores correlacionados à tarifa de objetos postais para os quais ocorra a inviabilização do faturamento dos valores, devido a ocorrência de glosa por parte do cliente pelo não reconhecimento dos objetos, em razão do direcionamento equivocado ao seu cartão/contrato e não seja possível identificar o cliente responsável pelas postagens;\nIII - pela conferência exaustiva dos dados da Pré-Lista de Postagem – PLP com os objetos físicos efetivamente captados pela agência.\nIV - por informar ao cliente sobre objetos faltantes ou excedentes em relação à PLP apresentada e/ou da necessidade de corrigir o documento ou a mídia com o arquivos dos dados dos objetos a serem postados.\nV - por realizar a postagem de objetos nos códigos de postagens industriais', 9),
(11275, 'anexo', 256, 11274, 4, 'a', 'Industrial - quando a PLP alcançar ou superar o número mínimo de objetos indicados nos resumos de serviços e regramento vigente; ou', '', 10),
(11276, 'anexo', 256, 11274, 4, 'b', 'de varejo – quando quantitativo de objetos for inferior ao número mínimo de objetos indicados nos resumos de serviço e regramento vigente, após anuência do cliente.', '4. DAS VEDAÇÕES', 11),
(11277, 'anexo', 256, NULL, 2, '4.1', 'É vedado à AGF iniciar o atendimento aos clientes antes da análise do órgão regional de gestão dos canais de atendimento relativa ao processo de habilitação e quanto à localização do cliente no território de atuação e coleta da unidade.', '', 12),
(11278, 'anexo', 256, NULL, 2, '4.2', 'A realização de coleta de carga industrial de cliente para o qual não houve o processo de habilitação ou que estejam fora do território de atuação e coleta da AGF, ou ainda em localidade com tabela de preço diferente do município onde a unidade está instalada será enquadrada como ocorrência de descumprimento contratual.', '5. DAS ATIVIDADES INERENTES A EXECUÇÃO OPERACIONAL DE POSTAGEM INDUSTRIAL', 13),
(11279, 'anexo', 256, NULL, 2, '5.1', 'A execução dos itens abaixo relacionados são de cunho obrigatório para a realização da execução operacional da postagem classificadas como industriais:', 'I - Coleta no endereço definido pelo cliente ou recebimento dos objetos na agência;\nII - Conferência da carga;\nIII - Formalização de informação ao cliente quando da ocorrência de divergência na PLP, em consonância com os objetos físicos coletados ou recebidos;\nIV - Realização da postagem no sistema de automação autorizado pelos Correios;\nV - Execução de plano de triagem específico para entrega da carga industrial aos Correios;\nVI - Utilização de escolta para transporte da carga industrial até a agência/área acessória e à unidade operacional;', 14),
(11280, 'anexo', 256, 11279, 4, 'a', 'a contratação de escolta é recomendada e insumo para definição da remuneração;', '', 15),
(11281, 'anexo', 256, 11279, 4, 'b', 'a contratação ou não de escolta é uma liberalidade da Franqueada, haja vista que os riscos e a responsabilidade sobre a carga postal até a entrega aos Correios é exclusivamente dessa.', 'VII - Entrega da carga industrial na unidade operacional de vinculação em horário pré-estabelecido ou em outra indicada previamente pelos Correios;\nVIII - Instalação de Área acessória nas instalações do cliente;', 16),
(11282, 'anexo', 256, 11279, 4, 'a', 'da classificação do cliente e das disposições correlacionadas às contrapartidas e benefícios presentes na Matriz de Relacionamento;', '', 17),
(11283, 'anexo', 256, 11279, 4, 'b', 'do interesse e estrutura instalada do cliente; e', '', 18),
(11284, 'anexo', 256, 11279, 4, 'c', 'de autorização prévia dos Correios, conforme requisitos e parâmetros presentes no normativo interno.', '', 19),
(11285, 'anexo', 256, 11279, 3, '5.1.1', 'A realização de atividades que não estiverem contempladas na Matriz de Relacionamento, contrapartidas e benefícios comuns, pela Franqueada ao cliente deverá ser informada aos Correios.', '', 20),
(11286, 'anexo', 256, NULL, 2, '5.2', 'A Franqueada é única e exclusivamente responsável pelos objetos por ela captados e postados até o momento da entrega desses na unidade operacional definida pelos Correios.', '6. DISPOSIÇÕES GERAIS', 21),
(11287, 'anexo', 256, NULL, 2, '6.1', 'A assinatura deste Termo de Adesão para execução operacional de postagens classificadas como industriais implica a aquiescência da obrigatoriedade de realizar as atividades inerentes às postagens dessa natureza, conforme consignado na categorização do(s) cliente(s) atendido(s) pela Agência de Correios Franqueada.', '', 22),
(11288, 'anexo', 256, NULL, 2, '6.2', 'A execução operacional de postagens de encomendas classificadas como industrial, não é obrigatória, cabendo à Franqueada definir se a AGF IRÁ prestar esse tipo de serviço ou não, podendo a qualquer tempo:', 'I -  aderir, enquanto o serviço constar no Anexo 3 do Contrato de Franquia Postal; ou\nII - solicitar a desabilitação, conforme os temos presentes neste documento.', 23),
(11289, 'anexo', 256, NULL, 2, '6.3', 'A Franqueada será remunerada pela execução do conjunto de atividades correlacionadas a postagem industrial, cujo percentual está estabelecido na Tabela R5, do Anexo 3, ou outra que vier a substitui-la no Contrato de Franquia Postal.', '', 24),
(11290, 'anexo', 256, NULL, 2, '6.4', 'A qualquer tempo, os Correios poderão incluir ou excluir itens na(s) tabela(s) que agrupa(m) os serviços classificados como industriais no Anexo 3 do Contrato de Franquia Postal, considerando para tanto a meta ou o potencial de volume carga postal de serviço atual ou novo que se enquadre nos conceitos estabelecidos pelos Correios e que sejam inclusos nos contratos comerciais dos clientes, conforme sua classificação.', '', 25),
(11291, 'anexo', 256, NULL, 2, '6.5', 'A adesão pela Franqueada e a autorização dos Correios para prestação de serviços classificados como de postagem industrial não extingue a observância obrigatória dos limites do território de atuação e coleta da AGF ou, ainda, a vedação de prospecção de clientes em localidades onde a tarifa de preços é divergente do município onde está instalada a AGF/área acessória.', '', 26),
(11292, 'anexo', 256, NULL, 2, '6.6', 'Na ausência de unidade operacional na região de atendimento com capacidade instalada para recebimento/tratamento da carga industrial onde a AGF estiver instalada, os Correios poderão indicar outra unidade operacional para entrega da carga.', '', 27),
(11293, 'anexo', 256, NULL, 2, '6.7', 'A eventual necessidade de investimentos para ampliação do quadro funcional, aquisição de equipamentos, veículos ou adaptações da estrutura instalada da agência/área acessória ocorrerá exclusivamente por conta e risco da Pessoa Jurídica de Direito Privado detentora do contrato de AGF, sem que isso implique em garantias dos Correios quanto ao retorno desses custos ou despesas.', '7. DAS DISPOSIÇÕES FINAIS E TRANSITÓRIAS', 28),
(11294, 'anexo', 256, NULL, 2, '7.1', 'O presente documento deverá ser assinado pelo(s) sócio(s) administrador(res) ou pelo representante legal da pessoa jurídica de direito privado detentora do Contrato de Franquia Postal.', '', 29),
(11295, 'anexo', 256, 11294, 3, '7.1.1', 'A assinatura por pessoa não autorizada implicará na não aceitação do documento como válido e na conclusão do processo de habilitação.', 'Cidade/UF, (dd) de (mês) de (aaaa).\n_______________________________________________________\nNome completo do sócio ou representante legal da Franqueada\nCargo:\nCPF:\nRG:\n* * * * *', 30),
(11296, 'anexo', 259, NULL, 1, '1', 'É essencial que todos os atores do processo de área acessória conheçam na integralidade o conteúdo:', '', 0),
(11297, 'anexo', 259, 11296, 4, 'a', 'deste Capítulo e dos anexos que o compõem; e', '', 1),
(11298, 'anexo', 259, 11296, 4, 'b', 'do Contrato de Franquia Postal - CFP.', '', 2),
(11299, 'anexo', 259, NULL, 1, '2', 'TIPOS DE ÁREAS ACESSÓRIAS DE AGÊNCIAS DE CORREIOS FRANQUEADAS - AGF', '', 3),
(11300, 'anexo', 259, 11299, 2, '2.1', 'Guichê de Retaguarda', '', 4),
(11301, 'anexo', 259, 11300, 3, '2.1.1', 'Guichê de Retaguarda nas instalações da Agência de Correios Franqueada - AGF (Imóvel principal - Modelo A1 e A2 ou Imóvel Complementar - Modelo A2).', '', 5),
(11302, 'anexo', 259, 11300, 3, '2.1.2', 'Guichê de Retaguarda em Imóvel Distinto - GRID.', '', 6),
(11303, 'anexo', 259, 11299, 2, '2.2', 'Guichê Avançado de Atendimento', '', 7),
(11304, 'anexo', 259, 11303, 3, '2.2.1', 'Guichê Avançado de Atendimento Sazonal - GAS.', '', 8),
(11305, 'anexo', 259, 11303, 3, '2.2.2', 'Guichê Avançado de Atendimento Contingencial - GAC.', '', 9),
(11306, 'anexo', 259, 11299, 2, '2.3', 'A área acessória é considerada como espaço de apoio para desenvolvimento do processo produtivo realizado pela pessoa jurídica contratada, ou seja, não é um nova unidade, não possui designação de Master Cost Unit - MCU próprio, sendo que todos os eventos realizados nesse espaço, mesmo que em endereço diverso, são vinculados a AGF.', '', 10),
(11307, 'anexo', 259, 11299, 2, '2.4', 'Havendo necessidade de abertura de filial por exigência do poder executivo municipal, para a concessão do alvará de funcionamento, esse novo Cadastro Nacional de Pessoa Jurídica - CNPJ não incidirá sobre o quantitativo definido no item 3.4 do Edital de Licitação (2011), uma vez que a área acessória estará vinculada em sua operacionalização a AGF Centralizadora, inclusive para as atividades financeiras.', '', 11);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(11308, 'anexo', 259, NULL, 1, '3', 'FINALIDADE DA ÁREA ACESSÓRIA', '', 12),
(11309, 'anexo', 259, 11308, 2, '3.1', 'São finalidades da área acessória:', '', 13),
(11310, 'anexo', 259, 11309, 4, 'a', 'atender de forma tempestiva aumentos de demanda por serviços postais em determinado município da Superintendência Estadual - SE;', '', 14),
(11311, 'anexo', 259, 11309, 4, 'b', 'atender demandas sazonais por serviços postais, por exíguo período, cujas características de execução operacional não demandem a instalação de estrutura definitiva e/ou complexa;', '', 15),
(11312, 'anexo', 259, 11309, 4, 'c', 'garantir a continuidade do atendimento postal em situação(ões) contingencial(is) de fechamento provisório ou definitivo de agência de Correios, própria ou terceirizada, por período pré-estabelecido, nos moldes estabelecidos neste documento;', '', 16),
(11313, 'anexo', 259, 11309, 4, 'd', 'atender demandas de interesse público (governamentais e serviços especiais), em localidades que não sejam contempladas com estrutura instalada dos Correios, ou quando existente(s), não seja(m) adequada(s) ou não dispunham de pontos de atendimento suficientes.', '', 17),
(11314, 'anexo', 259, 11308, 2, '3.2', 'O atendimento de demandas por serviço postal, com reconhecido potencial de captação de receita e de ocupação de mercado, deverá ser realizado por meio da instalação de um canal de atendimento definitivo na localidade, seja ele próprio ou terceirizado.', '', 18),
(11315, 'anexo', 259, 11308, 2, '3.3', 'Os Correios a qualquer tempo poderá viabilizar, a seu critério exclusivo, a instalação de canais de atendimento, próprio ou terceirizado, nas localidades onde estão instaladas as áreas acessórias, sem que seja necessário:', '', 19),
(11316, 'anexo', 259, 11315, 4, 'a', 'conhecimento ou anuência prévia da AGF detentora da área acessória;', '', 20),
(11317, 'anexo', 259, 11315, 4, 'b', 'resguardar distância entre a nova unidade/loja postal e a área acessória.', '', 21),
(11318, 'anexo', 259, NULL, 1, '4', 'VEDAÇÕES/IMPEDIMENTOS PARA AUTORIZAÇÃO DE INSTALAÇÃO DE ÁREA ACESSÓRIA', '', 22),
(11319, 'anexo', 259, 11318, 2, '4.1', 'É vedada a autorização de instalação de área acessória quando identificada quaisquer uma das situações abaixo listadas, em relação à AGF:', '', 23),
(11320, 'anexo', 259, 11319, 4, 'a', 'o município onde se propõe instalar a área acessória seja diverso daquele onde a AGF está instalada;', '', 24),
(11321, 'anexo', 259, 11319, 4, 'b', 'o imóvel apresentado para instalação e operação da área acessória não contempla as características e especificidades exigidas neste Capítulo;', '', 25),
(11322, 'anexo', 259, 11319, 4, 'c', 'a pessoa jurídica contratada esteja em situação de inadimplência financeira perante os Correios, correlacionados a ausência:', 'I - de repasses totais ou parciais;\nII - de pagamentos de faturas; ou\nIII - atraso de Termo de Reconhecimento e Parcelamento de Débitos - TRPD ou assemelhado.', 26),
(11323, 'anexo', 259, 11319, 4, 'd', 'a AGF seja parte em processo administrativo de rescisão unilateral do contrato, assim constituído, mediante emissão de notificação à pessoa jurídica contratada, respaldada em decisão da autoridade competente;', '', 27),
(11324, 'anexo', 259, 11319, 4, 'e', 'a pessoa jurídica contratada (matriz ou filial) seja parte de processo administrativo para apuração de ocorrência de descumprimento contratual cujo(s) evento(s) foco seja(m) originado(s) na:', 'I - comercialização, estoque, utilização de selo ou estampas falsas;\nII - disponibilização de documento falso para comprovação de cumprimento das condições de habilitação;\nIII - participação em evento com características de fraude;\nIV - associação com outras pessoas jurídicas, cujo desenvolvimento das ações, intencionalmente ou não, gerem lesão financeira, institucional ou administrativa aos Correios ou a terceiros, etc.', 28),
(11325, 'anexo', 259, 11319, 4, 'f', 'ausência de comprovação das condições de habilitação estabelecidas no edital de licitação;', '', 29),
(11326, 'anexo', 259, 11319, 4, 'g', 'existência de área acessória, de qualquer tipo, fechada por motivo de irregularidade nos 6 (seis) meses anteriores a solicitação, consignada em:', 'I - Termo de Distrato já assinado; ou\nII - fechamento provisório devido a processo administrativo de apuração em andamento, enquanto a decisão da autoridade competente sobre os fatos não for registrada; ou\nIII - processo administrativo em andamento ou finalizado para apuração de instalação ou mudança de endereço de área acessória, sem prévia autorização dos Correios;\nIV - processo administrativo de apuração de irregularidade finalizado, no qual conste decisão de autoridade competente pelo fechamento da unidade ou da área acessória.\nNota: o fechamento da área acessória não afasta a aplicação de penalidades administrativas previstas no instrumento contratual e/ou na legislação penal ou cível, no escopo da gravidade da irregularidade cometida.', 30),
(11327, 'anexo', 259, 11319, 4, 'h', 'não atendimento ao parâmetro de preservação do espaço designado como Limite Inferior, quando se tratar de instalação da área acessória em imóvel principal ou complementar;', '', 31),
(11328, 'anexo', 259, 11319, 4, 'i', 'comprovada a insuficiência do espaço físico no imóvel apresentado pela Pessoa jurídica contratada para instalação da área acessória para comportar, simultaneamente:', 'I - o número de guichês de retaguarda pretendido;\nII - mobiliário necessário ao tratamento da carga captada;\nIII - armazenamento temporário da carga postal até a transferência ou coleta da carga;\nIV - local adequado para carga e descarga.', 32),
(11329, 'anexo', 259, 11319, 3, '4.1.1', 'A verificação da situação financeira da pessoa jurídica contratada ocorrerá por meio de consulta a sistema automatizado dos Correios ou na sua indisponibilidade, o órgão regional de gestão dos canais de atendimento terceirizados irá solicitar ao órgão corporativo de prestação de contas da rede terceirizada, a informação da situação de adimplência, ou não, da pessoa jurídica contratada perante os Correios.', '', 33),
(11330, 'anexo', 259, NULL, 1, '5', 'REQUISITOS GERAIS DOS IMÓVEIS DESTINADOS À INSTALAÇÃO DAS ÁREAS ACESSÓRIAS', '', 34),
(11331, 'anexo', 259, 11330, 2, '5.1', 'Quando a área acessória for instalada em imóvel diverso daquele onde está localizada a AGF Centralizadora, a edificação deverá atender aos requisitos do edital descritos nos guias e especificações técnicas, no que diz respeito aos seguintes itens:', '', 35),
(11332, 'anexo', 259, 11331, 4, 'a', 'normas de acessibilidade - conforme previstas na legislação local;', '', 36),
(11333, 'anexo', 259, 11331, 4, 'b', 'instalações sanitárias;', '', 37),
(11334, 'anexo', 259, 11331, 4, 'c', 'instalações elétricas, de rede e de segurança;', '', 38),
(11335, 'anexo', 259, 11331, 4, 'd', 'conectividade;', '', 39),
(11336, 'anexo', 259, 11331, 4, 'e', 'aprovação do imóvel junto aos órgãos competentes para que seja possível a concessão do alvará de funcionamento;', '', 40),
(11337, 'anexo', 259, 11331, 4, 'f', 'alvará de funcionamento.', '', 41),
(11338, 'anexo', 259, 11330, 2, '5.2', 'A pessoa jurídica contratada deverá garantir que o espaço disponibilizado para a instalação da área acessória, quando em imóvel diverso ao de instalação da AGF, ofereça as condições mínimas de segurança e salubridade.', '', 42),
(11339, 'anexo', 259, 11338, 3, '5.2.1', 'É exigência que o imóvel seja uma construção em alvenaria, assim como a existência de laje.', '', 43),
(11340, 'anexo', 259, 11338, 3, '5.2.2', 'Excepcionalmente, poderá ser aceito o imóvel sem laje, desde que:', '', 44),
(11341, 'anexo', 259, 11340, 4, 'a', 'haja a possibilidade de instalação de grade horizontal sob o telhado. Nesse caso, a instalação deverá ser providenciada em até 30 (trinta) dias após o início das atividades;', '', 45),
(11342, 'anexo', 259, 11340, 4, 'b', 'considerando as características estruturais no imóvel ou de sua localização, seja mais adequada a instalação de outros requisitos, tais como: equipamentos tecnológicos e/ou monitoramento e/ou vigilância. Nesse caso, a área de segurança da Superintendência Estadual - SE deverá ser consultada antes da aprovação do imóvel.', '', 46),
(11343, 'anexo', 259, 11330, 2, '5.3', 'Além da observância de que trata o item 4.1, deste Anexo 2, o imóvel apresentado deve dispor de espaço suficiente para comportar o mobiliário, os equipamentos operacionais e os Guichês de Retaguarda/Avançado, imprescindíveis à:', 'a) postagem e vendas de produtos;\nb) triagem e tratamento da carga;\nc) acomodação da carga até o momento de sua transferência ou coleta.', 47),
(11344, 'anexo', 259, 11343, 3, '5.3.1', 'A autorização de instalação de guichê de retaguarda ou guichê avançado em condições excepcionais não poderá comprometer a operacionalização e a qualidade do serviço prestado pela AGF.', 'Nota: a autorização excepcional de que trata o subitem 4.3.1 deverá obrigatoriamente ser submetida para análise e aprovação da área regional de gestão de operações e do Superintendente Estadual.', 48),
(11345, 'anexo', 259, 11330, 2, '5.4', 'A pessoa jurídica contratada é responsável, com exclusividade, por garantir que o imóvel onde será instalada a área acessória, durante toda a vigência do termo aditivo, atenda às seguintes condições:', 'a) de acessibilidade, de ergonomia e de salubridade, conforme legislação vigente;', 49),
(11346, 'anexo', 259, 11345, 4, 'b', 'de estrutura (largura da porta, espaço de circulação etc.) apropriada à carga e descarga, da instalação da grade horizontal ou requisito(s) substituto(s) quando cabível;', 'c) de integridade e segurança das pessoas, bem como da carga postal.', 50),
(11347, 'anexo', 259, 11345, 3, '5.4.1', 'Verificada a não observância das condições listadas nas alíneas do subitem 4.4, o órgão regional de gestão dos canais de atendimento terceirizados deverá notificar à pessoa jurídica contratada sobre a desconformidade, dando-lhe prazo de até 30 (trinta) dias úteis para regularização.', '', 51),
(11348, 'anexo', 259, 11345, 3, '5.4.2', 'Não sendo regularizada a desconformidade verificada dentro do prazo estipulado, a área acessória deverá ser fechada, pelo interstício temporal necessário para a regularização.', '', 52),
(11349, 'anexo', 259, NULL, 1, '6', 'UTILIZAÇÃO DO SISTEMA ELETRÔNICO DE INFORMAÇÕES PARA TRAMITAÇÃO DE DOCUMENTOS', '', 53),
(11350, 'anexo', 259, 11349, 2, '6.1', 'Antes de instruir processo administrativo com vistas a solicitar autorização para instalação de área acessória, recomenda-se a pessoa jurídica contratada que realize uma pré-avaliação dos requisitos e exigências descritas neste Anexo 2, mitigando situação de indeferimento do pleito.', '', 54),
(11351, 'anexo', 259, 11349, 2, '6.2', 'Toda a tramitação dos documentos relativa à análise da viabilidade da instalação de área acessória deverá ocorrer por meio do Sistema Eletrônico de Informações - SEI.', '', 55),
(11352, 'anexo', 259, 11351, 3, '6.2.1', 'Na oportunidade em que a pessoa jurídica contratada, por qualquer motivação, forneça documento(s) físico(s) ao órgão regional de gestão dos canais de atendimento terceirizados, esses deverão ser:', 'a) foco de conferência com os respectivos originais;\nb) atestados, por meio da aposição de carimbo “confere com o original”;\nc) escaneados, e anexados ao processo correspondente, prioritariamente, em ordem cronológica, se houver.', 56),
(11353, 'anexo', 259, 11349, 2, '6.3', 'A pessoa jurídica contratada deve ter acesso total ao processo administrativo desde a sua instrução até o momento de sua conclusão, independentemente de quem tenha instruído o processo administrativo no SEI.', '', 57),
(11354, 'anexo', 259, 11349, 2, '6.4', 'Não haverá sanção ou taxa especifica nas situações em que a pessoa jurídica contratada desista do pleito de instalar área acessória. Contudo, também, não haverá devolução de valores que já tenham sido glosados/descontados no decorrer do processo administrativos, que já tenham sido realizados.', '', 58),
(11355, 'anexo', 259, 11349, 2, '6.5', 'O processo administrativo com vistas a instalação de área acessória, por padrão, será iniciado pela pessoa jurídica contratada. Todovia, caso não seja possível, o órgão regional de gestão dos canais de atendimento terceirizados deverá fazê-lo seguindo as orientações presentes neste Anexo 2.', '', 59),
(11356, 'anexo', 259, 11349, 2, '6.6', 'Iniciar o processo administrativo no SEI observando as orientações abaixo:', '', 60),
(11357, 'anexo', 259, 11356, 4, 'a', 'selecionar: “Peticionamento” > “Processo Novo”;', '', 61),
(11358, 'anexo', 259, 11356, 4, 'b', 'escolher o tipo de Processo: Atendimento Gestão das Unidades Contratadas (AGF, ACC, AGC);', '', 62),
(11359, 'anexo', 259, 11356, 4, 'c', 'descrever na especificação: solicitação de instalação de área acessória  - [escrever nome da unidade];', '', 63),
(11360, 'anexo', 259, 11356, 4, 'd', 'inserir no campo Documento Principal a Carta assinada (Informar no Complemento do Tipo de Documento: Carta);', '', 64),
(11361, 'anexo', 259, 11356, 4, 'e', 'informar o formato: “Digitalizado” e adicionar;', '', 65),
(11362, 'anexo', 259, 11356, 4, 'f', 'inserir no campo Documento Complementar os quantos forem necessários (Informar no Complemento do Tipo de Documento);', '', 66),
(11363, 'anexo', 259, 11356, 4, 'g', 'informar o formato “Digitalizado” e Adicionar poderá ser adicionados quantos documentos forem necessários); e', '', 67),
(11364, 'anexo', 259, 11356, 4, 'h', 'peticionar.', '', 68),
(11365, 'anexo', 259, 11349, 2, '6.7', 'Escolher dentre as opções de formatos de documento disponibilizados pelo SEI, o tipo “Carta”. O sistema devolverá um formulário pré-formatado, o qual contará com campos que deverão ser preenchidos da seguinte forma:', '', 69),
(11366, 'anexo', 259, 11365, 4, 'a', 'descrição: dispor o assunto a que se refere o pleito;', '', 70),
(11367, 'anexo', 259, 11365, 4, 'b', 'destinatário: GERAT/SE ou GEOPE/SE [Ex.: GERAT/BSB ou GEOPE/PI];', '', 71),
(11368, 'anexo', 259, 11365, 4, 'c', 'nível de acesso: público;', '', 72),
(11369, 'anexo', 259, 11365, 4, 'd', 'confirmar.', '', 73),
(11370, 'anexo', 259, 11349, 2, '6.8', 'Preencher o formulário pré-formatado “Carta” que o sistema devolverá, conforme segue:', '', 74),
(11371, 'anexo', 259, 11370, 4, 'a', 'nome do destinatário: nome do GERAT ou GEOPE da Superintendência Estadual;', '', 75),
(11372, 'anexo', 259, 11370, 4, 'b', 'cargo: Gerente Regional de [Atendimento/Operações];', '', 76),
(11373, 'anexo', 259, 11370, 4, 'c', 'assunto: “Solicitação de mudança endereço - [nome da unidade/SE/UF]”;', '', 77),
(11374, 'anexo', 259, 11370, 4, 'd', 'no texto que comporá o documento de solicitação descrever, no mínimo, a adequação pretendida e a justificativa correlata.', 'Nota: atentar para as orientações relativas à autenticação dos documentos antes de incluí-los no processo administrativo de solicitação de instalação de área acessória, para que a carta de solicitação seja assinada pelo(s) sócio(s) ou representante legal autorizado(s) em instrumento de outorga a fazê-lo.', 78),
(11375, 'anexo', 259, 11349, 2, '6.9', 'Incluir no processo SEI, em formato PDF, quando se pretenda realizar a instalação da área acessória em imóvel diverso, onde está instalada a AGF:', '', 79),
(11376, 'anexo', 259, 11375, 4, 'a', 'as mesmas declarações exigidas no processo de seleção em relação ao imóvel;', '', 80),
(11377, 'anexo', 259, 11375, 4, 'b', 'documento vinculatório com o imóvel foco da avaliação para instalação da área acessória, quando essa for ocorrer em imóvel diverso daquele onde está a AGF. Serão aceitos quaisquer dos documentos exemplificados abaixo, para suprir o item:', 'I - uma carta de intenção, assinada pelo proprietário do imóvel que será locado, quando o contrato de locação ainda estiver em negociação e só for ser assinado após a aprovação desse pelos Correios; ou\nII - documento de locação do imóvel/espaço; ou\nIII - documento de cessão do imóvel/espaço a ser utilizado; ou\nIV - escritura do imóvel em nome de um dos sócios, ou da pessoa jurídica da contratada etc.', 81),
(11378, 'anexo', 259, 11375, 4, 'c', 'apresentação de levantamento arquitetônico (planta baixa ou leiaute) do imóvel onde será instalada a área acessória ou do espaço da área operacional onde será(ão) instalado(s) o guichê de retaguarda.', 'Nota: o levantamento arquitetônico/leiaute não precisa ser assinado por profissional de engenharia ou de arquitetura, nessa fase da processo.', 82),
(11379, 'anexo', 259, 11349, 2, '6.10', 'Solicitação pelos Correios para Instalação de Área Acessória', '', 83),
(11380, 'anexo', 259, 11379, 3, '6.10.1', 'Nas situações em que os Correios considerarem pertinentes poderão realizar consulta formal a pessoa jurídica contratada sobre interesse em instalar e operacionalizar área acessória - guichê avançado de atendimento (contingencial ou sazonal), respectivamente no Anexo 5 e 6 deste Capítulo.', '', 84),
(11381, 'anexo', 259, 11379, 3, '6.10.2', 'Nessa hipótese o órgão regional de gestão dos canais de atendimento terceirizados irá instaurar o processo administrativo com essa finalidade.', '', 85),
(11382, 'anexo', 259, 11379, 3, '6.10.3', 'A pessoa jurídica contratada deverá responder, por meio do SEI, em até 5 (cinco) dias úteis a partir da data do recebimento do documento de consulta, sobre haver ou não interesse em instalar e operacionalizar a área acessória - guichê avançado de atendimento contingencial ou sazonal.', '', 86),
(11383, 'anexo', 259, 11379, 3, '6.10.4', 'Considerar-se-á como falta de interesse da pessoa jurídica contratada em instalar e operacionalizar a área acessória - guichê avançado de atendimento foco do questionamento, caso não haja manifestação relativa à consulta dentro do prazo estabelecido.', '', 87),
(11384, 'anexo', 259, NULL, 1, '7', 'PROJETO DE INSTALAÇÃO DE ÁREA ACESSÓRIA', '', 88),
(11385, 'anexo', 259, 11384, 2, '7.1', 'O Projeto de Instalação de AGF ou de área acessória deverá estar em consonância com:', '', 89),
(11386, 'anexo', 259, 11385, 4, 'a', 'os guias e especificações técnicas definidas pelos Correios;', '', 90),
(11387, 'anexo', 259, 11385, 4, 'b', 'o número de células mínimas e/ou do espaço necessário para comportar a operação da Área Acessória;', '', 91),
(11388, 'anexo', 259, 11385, 4, 'c', 'às leis e normas técnicas pertinentes à construção civil e à localidade da unidade;', '', 92),
(11389, 'anexo', 259, 11385, 4, 'd', 'a norma vigente sobre acessibilidade;', '', 93),
(11390, 'anexo', 259, 11385, 4, 'e', 'o espaço para área de guarda provisória de objetos tratados e a tratar, compatível com o volume postal da Área Acessória.', '', 94),
(11391, 'anexo', 259, 11384, 2, '7.2', 'Após a aprovação dos documentos e da solicitação da implantação da área acessória deverá ser encaminhado ao órgão regional de gestão dos canais de atendimento terceirizados o projeto de instalação do canal de atendimento terceirizado ou da área acessória.', '', 95),
(11392, 'anexo', 259, 11384, 2, '7.3', 'Não haverá a obrigatoriedade da apresentação do projeto de instalação de área acessória para avaliação e aprovação dos Correios nas seguintes hipóteses:', '', 96),
(11393, 'anexo', 259, 11392, 4, 'a', 'Guichê de Retaguarda nas instalações da AGF, quando houver a instalação de até 2 (dois) pontos de atendimento e não for necessário reorganizar a estruturação das demais áreas da agência;', '', 97),
(11394, 'anexo', 259, 11392, 4, 'b', 'Guichê de Retaguarda em Imóvel Distinto - GRID; e', '', 98),
(11395, 'anexo', 259, 11392, 4, 'c', 'Guichê Avançado de Atendimento Sazonal - GAS.', '', 99),
(11396, 'anexo', 259, 11392, 3, '7.3.1', 'Nas situações em que não é necessário a apresentação do projeto de instalação a pessoa jurídica contratada deverá apresentar o leiaute/planta baixa das instalação da área acessória.', '', 100),
(11397, 'anexo', 259, 11384, 2, '7.4', 'Haverá a obrigatoriedade da apresentação do projeto de instalação de área acessória para avaliação e aprovação dos Correios nas seguintes hipóteses:', '', 101),
(11398, 'anexo', 259, 11397, 4, 'a', 'Guichê de Retaguarda nas instalações da AGF, quando houver a instalação de mais 2 (dois) pontos de atendimento; e', '', 102),
(11399, 'anexo', 259, 11397, 4, 'b', 'Guichê Avançado de Atendimento Contingencial - GAC.', '', 103),
(11400, 'anexo', 259, 11384, 2, '7.5', 'Na análise de autorização da instalação das áreas acessórias, o órgão regional de gestão dos canais de atendimento terceirizados deverá verificar se o espaço físico a ser disponibilizado é compatível com a quantidade de guichês/pontos de atendimento a serem ativados, bem como com a operação que será realizada, principalmente nos casos de áreas acessória em que não há a obrigatoriedade da apresentação do Projeto de Instalação.', '', 104),
(11401, 'anexo', 259, 11384, 2, '7.6', 'A apresentação do Projeto de Instalação deverá ocorrer em até 90 (noventa) dias após a autorização para instalação e operação da área acessória pretendida.', '', 105),
(11402, 'anexo', 259, 11401, 3, '7.6.1', 'Não havendo a apresentação do projeto de instalação no prazo definido, o processo administrativo será arquivado por desinteresse da pessoa jurídica contratada.', '', 106),
(11403, 'anexo', 259, 11384, 2, '7.7', 'O profissional, responsável técnico, pela elaboração o projeto de instalação do canal de atendimento terceirizado ou da área acessória deverá ter participado de reunião de nivelamento técnico com a equipe regional de engenharia e/ou de tecnologia da informação.', '', 107),
(11404, 'anexo', 259, 11384, 2, '7.8', 'Deverá ser observado o fluxo similar ao presente no normativa de mudança de endereço para viabilizar a participação do responsável técnico na reunião de nivelamento técnico.', '', 108),
(11405, 'anexo', 259, 11384, 2, '7.9', 'Fluxo de Avaliação do Projeto de Instalação do Canal de Atendimento Terceirizado ou da Área Acessória', '', 109),
(11406, 'anexo', 259, 11405, 3, '7.9.1', 'Procedimentos do órgão regional de gestão dos canais de atendimento terceirizados.', '7.9.1.1 Receber da pessoa jurídica contratada solicitação de análise do leiaute ou do projeto de instalação da AGF ou da área acessória.\n7.9.1.2 Encaminhar solicitação de análise do novo projeto de instalação do canal de atendimento terceirizado e/ ou área acessória ao órgão regional de gestão de engenharia e ao órgão regional de gestão de tecnologia da informação.\n7.9.1.3 Receber o resultado da análise do projeto de instalação da AGF ou da área acessória, e:\na) notificar a pessoa jurídica contratada sobre o resultado;\nb) orientar sobre as providências a serem adotadas nos casos de aprovação ou reprovação do projeto.\n7.9.1.4 Encaminhar o Projeto de Instalação da AGF aos órgãos competentes para reavaliação quando houver reencaminhamento pela pessoa jurídica contratada do projeto já com os itens não conformes ajustados.', 110),
(11407, 'anexo', 259, 11405, 3, '7.9.2', 'Procedimentos do órgão regional de gestão de engenharia.', '7.9.2.1 Receber para análise o projeto de instalação da AGF/área acessória do órgão regional de gestão dos canais de atendimento terceirizados.\n7.9.2.2 Analisar o projeto de instalação em até 20 (vinte) dias contados do recebimento da solicitação.\n7.9.2.3 Informar ao órgão regional de gestão dos canais de atendimento terceirizados o resultado da análise, indicando, quando existente, os pontos que têm que ser ajustados, nas oportunidades em que o projeto de instalação for reprovado.', 111),
(11408, 'anexo', 259, 11405, 3, '7.9.3', 'Procedimentos do órgão regional de gestão de tecnologia da informação.', '7.9.3.1 Receber para análise o projeto de instalação da AGF/área acessória do órgão regional de gestão dos canais de atendimento terceirizados.\n7.9.3.2 Analisar o projeto de instalação no que diz respeito aos aspectos de tecnologia da informação, em até 20 (vinte) dias contados do recebimento da solicitação.\n7.9.3.3 Informar o resultado da análise ao órgão regional de gestão dos canais de atendimento terceirizados, indicando, quando existente, os pontos que têm que ser ajustados, nas oportunidades em que o projeto de instalação for reprovado.', 112),
(11409, 'anexo', 259, 11384, 2, '7.10', 'A pessoa jurídica contratada ao receber o resultado da análise do projeto de instalação de AGF ou da área acessória deverá proceder conforme o disposto neste Anexo 2:', '', 113),
(11410, 'anexo', 259, 11409, 4, 'a', 'se aprovado, adotar as providências listadas no subitem 7.11;', '', 114),
(11411, 'anexo', 259, 11409, 4, 'b', 'se reprovado, adotar as providências listadas no subitem 7.12.', '', 115),
(11412, 'anexo', 259, 11384, 2, '7.11', 'O Projeto sendo Aprovado', '', 116),
(11413, 'anexo', 259, 11412, 3, '7.11.1', 'O projeto será o Anexo 1 do documento de formalização da área acessória.', '', 117),
(11414, 'anexo', 259, 11412, 3, '7.11.2', 'A pessoa jurídica contratada deverá:', 'a) registrar o Projeto de Instalação junto ao Conselho Regional de Engenharia e Agronomia - Crea ou Conselho de Arquitetura e Urbanismo - CAU e encaminhar cópia da Anotação de Responsabilidade Técnica - ART ou Registro de Responsabilidade Técnica - RRT, devidamente quitada ao órgão regional de gestão dos canais de atendimento terceirizado.\nb) obter as licenças necessárias para permitir a realização das adequações no imóvel;\nc) submeter o Projeto de Instalação da AGF ou do GAC à aprovação das autoridades públicas competentes, visando obter o alvará pertinente, quando necessário.', 118),
(11415, 'anexo', 259, 11412, 3, '7.11.3', 'Anexar ao processo de instalação da área acessória as cópias dos registros do projeto de instalação no Crea/CAU e a Anotação de Responsabilidade Técnica - ART, em até 30 (trinta) dias após a aprovação do projeto de instalação da área acessória pelos Correios.', '', 119),
(11416, 'anexo', 259, 11384, 2, '7.12', 'O Projeto sendo Reprovado', '', 120),
(11417, 'anexo', 259, 11416, 3, '7.12.1', 'Pela primeira vez, a pessoa jurídica contratada deverá realizar os ajustes necessários para reapresentação do projeto de instalação, não sendo cobrada taxa de avaliação de projeto.', '', 121),
(11418, 'anexo', 259, 11416, 3, '7.12.2', 'A partir da segunda reprovação, a pessoa jurídica contratada deverá:', '', 122),
(11419, 'anexo', 259, 11418, 4, 'a', 'realizar os ajustes necessários para a reapresentação do projeto de instalação da AGF ou do GAC;', '', 123),
(11420, 'anexo', 259, 11418, 4, 'b', 'encaminhar o projeto de instalação de AGF ou do GAC ajustado para o órgão regional de gestão dos canais de atendimento terceirizado, acompanhado do comprovante do pagamento da Taxa de Avaliação de Projeto.', '', 124),
(11421, 'anexo', 259, 11416, 3, '7.12.3', 'O órgão regional de gestão dos canais de atendimento terceirizados viabilizará a glosa/desconto do valor correspondente à Taxa de Avaliação de Projeto definido no Anexo 2 do Contrato de Franquia Postal, a partir da segunda reprovação.', '', 125),
(11422, 'anexo', 259, NULL, 1, '8', 'CUSTOS/DESPESAS', '', 126),
(11423, 'anexo', 259, 11422, 2, '8.1', 'Todas as despesas relativas à instalação, manutenção, operacionalização e administração de área(s) acessória(s) são de responsabilidade integral da pessoa jurídica contrata', '', 127),
(11424, 'anexo', 259, 11422, 2, '8.2', 'Antes de viabilizar a realização da glosa/desconto de qualquer taxa relativa a instalação de área acessória deve ser verificado pelo órgão regional de gestão dos canais de atendimento os valores correlacionados a cada etapa do processo.', '', 128),
(11425, 'anexo', 259, 11422, 2, '8.3', 'O órgão regional de gestão dos canais de atendimento terceirizados será o responsável por lançar na ferramenta \"Comunicação de Débito - GCFA Direto\", ou outra que vier a substituí-la, as informações de valor e da motivação para a glosa/desconto da taxa correspondente a fase do processo de análise do pleito de instalação e operação de área acessória.', '', 129),
(11426, 'anexo', 259, 11422, 2, '8.4', 'O órgão de gestão de prestação de contas dos canais de atendimento terceirizados irá processar a glosa/desconto, conforme as informações apresentadas pelo órgão regional de gestão dos canais de atendimento terceirizados.', '', 130),
(11427, 'anexo', 259, 11422, 2, '8.5', 'Realizada a glosa o órgão regional de gestão dos canais de atendimento terceirizados deverá:', '', 131),
(11428, 'anexo', 259, 11427, 4, 'a', 'incluir o comprovante do desconto, ou documento correlato, no processo administrativo de mudança de endereço; e', '', 132),
(11429, 'anexo', 259, 11427, 4, 'b', 'notificar a pessoa jurídica contratada da providência adotada, do valor e da motivação.', '', 133),
(11430, 'anexo', 259, 11422, 2, '8.6', 'O valor da taxa de vistoria de conformidade técnica, quando houver definição nesse sentido no instrumento contratual, será reduzida em 50% nos casos em que a reprovação for apenas de Tecnologia da Informação - TI ou apenas de engenharia.', '', 134),
(11431, 'anexo', 259, NULL, 1, '9', 'MOBILIÁRIO', '', 135),
(11432, 'anexo', 259, 11431, 2, '9.1', 'Para as áreas acessórias dos tipos GRID e GAS será flexibilizada a utilização do mobiliário definido nos Guias e Especificações Técnicas.', '', 136),
(11433, 'anexo', 259, 11431, 2, '9.2', 'Para os GAC a aquisição do mobiliário é obrigatória e deve seguir a orientação dos Guias e Especificações Técnicas vigentes na época da instalação no que tange a área de atendimento ao público, contudo o quantitativo pode ser flexibilizado.', '', 137),
(11434, 'anexo', 259, 11433, 3, '9.2.1', 'No GAC só será necessária a aquisição de mobiliário para área de operações:', 'a) financeiras, se for ocorrer as atividades financeiras nesse local;\nc) serviços internos (retaguarda) se for ocorrer as operações de tratamento e expedição na unidade.', 138),
(11435, 'anexo', 259, 11431, 2, '9.3', 'Para todos os tipos de áreas acessórias, quando houver opção da pessoa jurídica contrata por mobiliário similar ao definido nos guias e especificações técnicas será exigida a manutenção do padrão de coloração e a observância da ergonomia do mobiliário, em cumprimento ao Termo de Ajustamento de Conduta - TAC assinado entre o Ministério do Trabalho e os Correios.', '', 139),
(11436, 'anexo', 259, 11435, 3, '9.3.1', 'A pessoa jurídica contratada deverá obter e conservar documentos e/ou laudos técnicos que comprovem a ergonomia do mobiliário para apresentação, quando solicitados, aos órgãos de controle/regulação/supervisão externos e internos.', '', 140),
(11437, 'anexo', 259, 11435, 3, '9.3.2', 'Quando não for possível manter o padrão de colorametria definido nos guias e especificações técnicas, as cores escolhidas para o mobiliário nas áreas financeira, de operações (retaguarda) devem ser as mais próximas encontradas no mercado.', '', 141),
(11438, 'anexo', 259, NULL, 1, '10', 'EQUIPAMENTOS DE INFORMÁTICA E PERIFÉRICOS RELACIONADOS', '', 142),
(11439, 'anexo', 259, 11438, 2, '10.1', 'É obrigatória a observância das especificações/configurações mínimas presentes nos Guias e Especificações Técnicas para os equipamentos de informática onde serão instalados a solução de automação do atendimento, bem como aos periféricos necessários para a execução das atividades postais nas áreas acessórias.', '', 143),
(11440, 'anexo', 259, NULL, 1, '11', 'VISTORIA DE CONFORMIDADE TÉCNICA', '', 144),
(11441, 'anexo', 259, 11440, 2, '11.1', 'A vistoria de conformidade técnica em relação a estrutura física do imóvel ocorrerá obrigatoriamente para as áreas acessórias nas instalações da AGF e/ou do GAC.', '', 145),
(11442, 'anexo', 259, 11440, 2, '11.2', 'A solicitação da vistoria de conformidade técnica deverá estar acompanhada dos seguintes documentos, em 1 (uma) via:', '', 146),
(11443, 'anexo', 259, 11442, 4, 'a', 'documento “as built”;', '', 147),
(11444, 'anexo', 259, 11442, 4, 'b', 'levantamento fotográfico do imóvel comprovando a execução da obra, com no mínimo 5 (cinco) tipos de fotos conforme indicado abaixo:', 'I - foto da fachada do imóvel (caso o imóvel possua mais de uma fachada, deverá ser apresentada uma foto de cada fachada);\nII - foto do futuro hall de atendimento da unidade, tirada da porta principal do imóvel com vista para o seu interior, quando houver atendimento ao público;\nIII - foto do interior do imóvel com vista para a porta principal;\nIV - foto da porta dos fundos do imóvel, tirada do interior do imóvel com vista para a porta dos fundos (caso o imóvel possua várias destas portas, deverá ser apresentada uma foto de cada);\nV - foto com a área destinada à retaguarda da agência.', 148),
(11445, 'anexo', 259, 11440, 2, '11.3', 'Caso a área acessória esteja em Conformidade:', '', 149),
(11446, 'anexo', 259, 11445, 4, 'a', 'será instalado o Sistema de Automação da Rede de Atendimento no(s) Guichês de Retaguarda/Avançado;', '', 150),
(11447, 'anexo', 259, 11445, 4, 'b', 'será elaborado pelas equipe(s) de engenharia e/ou tecnologia o termo de conformidade técnica e disponibilizado para assinatura dos técnicos que realizaram a vistoria;', '', 151),
(11448, 'anexo', 259, 11445, 4, 'c', 'quando necessário o órgão regional de gestão dos canais de atendimento terceirizados solicitará a pessoa jurídica contratada o fornecimento de uma cópia dos documentos “as built”.', '', 152),
(11449, 'anexo', 259, 11445, 3, '11.3.1', 'Após a emissão do Termo de Conformidade Técnica será marcada a data para assinatura do documento de formalização de autorização para instalação de área acessória pelo órgão regional de gestão dos canais de atendimento terceirizados.', '', 153),
(11450, 'anexo', 259, 11445, 3, '11.3.2', 'A AGF poderá iniciar as operações da área acessória a partir da data de vigência do documento de formalização.', '', 154),
(11451, 'anexo', 259, 11440, 2, '11.4', 'Caso a área acessória não esteja em conformidade:', '', 155),
(11452, 'anexo', 259, 11451, 4, 'a', 'a(s) equipe(s) de engenharia e/ou tecnologia emitirão, em conjunto, documento com as indicações de quais ajustes necessitam ser realizados;', '', 156),
(11453, 'anexo', 259, 11451, 4, 'b', 'a pessoa jurídica contratada realizará os ajustes necessários;', '', 157),
(11454, 'anexo', 259, 11451, 4, 'c', 'a pessoa jurídica contratada solicitará o agendamento de nova Visita de Conformidade Técnica ao órgão regional de gestão dos canais de atendimento terceirizados.', '', 158),
(11455, 'anexo', 259, 11451, 3, '11.4.1', 'O órgão regional de gestão dos canais de atendimento terceirizados agendará nova data para realização da Vistoria de Conformidade Técnica com os órgãos regionais de gestão de engenharia e/ou de tecnologia.', '', 159),
(11456, 'anexo', 259, 11440, 2, '11.5', 'No caso de reprovação, a pessoa jurídica contratada deverá apresentar nova cópia dos documentos relacionados no item 9.2, já com as modificações realizadas.', '', 160),
(11457, 'anexo', 259, 11440, 2, '11.6', 'Para as áreas acessórias dos tipos GRID ou GAS ocorrerá apenas vistoria de conformidade técnica de Tecnologia da Informação - TI.', '', 161),
(11458, 'anexo', 259, 11440, 2, '11.7', 'Quando houver reprovação incidirá Taxa de Vistoria de Conformidade Técnica de TI, conforme previsto no Anexo 2 do CFP.', '', 162),
(11459, 'anexo', 259, 11440, 2, '11.8', 'Fluxo da Vistoria de Conformidade Técnica', '', 163),
(11460, 'anexo', 259, 11459, 3, '11.8.1', 'Procedimentos do órgão regional de gestão dos canais de atendimento terceirizados.', '11.8.1.1 Encaminhar solicitação de agendamento da(s) visita(s) de vistoria de conformidade técnica ao órgão regional de gestão de engenharia e ao órgão regional de gestão de recursos de tecnologia.\n11.8.1.2 Receber do órgão regional de gestão de engenharia e do órgão regional de gestão de recursos de tecnologia informação sobre a data e o horário em que foi agendada a visita de vistoria de conformidade técnica.\n11.8.1.3 Informar a pessoa jurídica contratada, com até 5 (cinco) dias úteis de antecedência, a data agendada para a visita de vistoria de conformidade técnica.\n11.8.1.4 Receber os relatórios de vistoria técnica dos órgãos regionais de gestão de engenharia e de gestão de recursos de tecnologia.\n11.8.1.5 Informar a pessoa jurídica contratada o resultado da vistoria de conformidade técnica, em até 5 (cinco) dias úteis, após o seu recebimento.\n11.8.1.6 Receber da pessoa jurídica contratada solicitação de marcação de nova vistoria de conformidade técnica, no(s) caso(s) de reprovação anterior.', 164),
(11461, 'anexo', 259, 11459, 3, '11.8.2', 'Procedimentos do órgão regional de gestão de engenharia.', '11.8.2.1 Receber solicitação para a realização de vistoria de conformidade técnica de engenharia na área acessória (AGF ou em imóvel diverso) do órgão regional de gestão dos canais de atendimento terceirizados.\n11.8.2.2 Agendar de comum acordo com o órgão regional de gestão de recursos de tecnologia a data da vistoria de conformidade técnica para até 10 (dez) dias contados a partir da data do recebimento da solicitação.\n11.8.2.3 Realizar a vistoria de conformidade técnica de engenharia, na data previamente agendada, e avaliar a conformidade da área acessória quanto ao projeto de instalação anteriormente aprovado.\n11.8.2.4 Emitir, em caso de conformidade da obra, relatório técnico e o Termo de Conformidade Técnica, por meio do SEI:', 165),
(11462, 'anexo', 259, 11461, 4, 'a', 'providenciar a assinatura da equipe técnica que realizou a vistoria;', '', 166),
(11463, 'anexo', 259, 11461, 4, 'b', 'disponibilizar para assinatura do representante da pessoa jurídica contratada que acompanhou a vistoria de conformidade técnica; e', '', 167),
(11464, 'anexo', 259, 11461, 4, 'c', 'quando emitido conjuntamente para assinatura da equipe técnica de TI.', '11.8.2.5 Listar os ajustes que a pessoa jurídica contratada deverá realizar quando verificada a existência de não conformidade verificadas durante a vistoria de conformidade técnica, e informar ao órgão regional de gestão dos canais de atendimento terceirizados.', 168),
(11465, 'anexo', 259, 11459, 3, '11.8.3', 'Procedimentos do órgão regional de gestão de tecnologia da informação.', '11.8.3.1 Receber a solicitação de vistoria de conformidade técnica na estrutura de TI da área acessória.\n11.8.3.2 Agendar de comum acordo com o órgão regional de gestão de engenharia data da vistoria de conformidade técnica para até 10 (dez) dias contados a partir da data do recebimento da solicitação.\n11.8.3.3 Realizar a vistoria de conformidade técnica na estrutura de TI e avaliar a conformidade da Área Acessória quanto ao Projeto de Instalação anteriormente aprovado.\n11.8.3.4 Emitir, em caso de conformidade da estrutura de TI, relatório técnico e o Termo de Conformidade Técnica, por meio do SEI:', 169),
(11466, 'anexo', 259, 11465, 4, 'a', 'providenciar a assinatura da equipe técnica que realizou a vistoria;', '', 170),
(11467, 'anexo', 259, 11465, 4, 'b', 'disponibilizar para assinatura do representante da pessoa jurídica contratada que acompanhou a vistoria de conformidade técnica.', '11.8.3.5 Listar os ajustes que a pessoa jurídica contratada deverá realizar quando verificada a existência de não conformidade, e informar ao órgão regional de gestão dos canais de atendimento terceirizados.', 171),
(11468, 'anexo', 259, NULL, 1, '12', 'TERMO ADITIVO OU TERMO DE AUTORIZAÇÃO', '', 172),
(11469, 'anexo', 259, 11468, 2, '12.1', 'O termo aditivo ou termo de autorização será disponibilizado para assinatura após a formalização da autorização para instalação e operacionalização da área acessória.', '', 173),
(11470, 'anexo', 259, 11468, 2, '12.2', 'O termo aditivo ou termo de autorização deverá ser assinado pelo(a):', 'a) gerente regional de gestão dos canais de atendimento terceirizado;\nb) superintendente estadual; e\nc) representante legal e/ou sócio(s) da pessoa jurídica contratada, cujo instrumento de constituição da empresa outorgue competência para tanto.', 174),
(11471, 'anexo', 259, 11468, 2, '12.3', 'O órgão regional de gestão dos canais de atendimento terceirizados deve viabilizar a publicação do extrato de celebração do termo aditivo ou do termo aditivo de prorrogação no Diário Oficial da União - DOU e/ou do Estado, com vistas a dar publicidade ao fato administrativo.', '', 175),
(11472, 'anexo', 259, 11468, 2, '12.4', 'O órgão regional de gestão dos canais de atendimento terceirizados devem atentar-se para as especificidades abaixo no que diz respeito ao prazo de vigência do termo aditivo de instalação ou do termo aditivo de prorrogação, a saber:', '', 176),
(11473, 'anexo', 259, 11472, 4, 'a', 'os termos aditivos devem ter vigência equivalente ao estabelecida nos anexos de cada tipo de área acessória;', '', 177),
(11474, 'anexo', 259, 11472, 4, 'b', 'fará jus a cobrança da taxa correspondente ao guichê de retaguarda ou guichê avançado quando da celebração do termo aditivo de instalação ou do termo aditivo de prorrogação;', '', 178),
(11475, 'anexo', 259, 11472, 4, 'c', 'a cobrança de que trata a alínea “b” deste subitem, corresponderá ao quantitativo de Guichês (Retaguarda/Avançado) estão instalados na área acessória;', '', 179),
(11476, 'anexo', 259, 11472, 4, 'd', 'as prorrogações da autorização de operacionalização da área acessória estão condicionadas a comprovação da compatibilidade às exigências de instalação, assim como aderência à estratégia de ocupação de mercados dos Correios;', '', 180),
(11477, 'anexo', 259, 11472, 4, 'e', 'disponibilizar o processo administrativo para assinatura do superintendente estadual no termo de autorização ou termo aditivo;', '', 181),
(11478, 'anexo', 259, 11472, 4, 'f', 'informar a pessoa jurídica contratada da disponibilização do termo aditivo e sobre o prazo de 5 (cinco) dias úteis, contados do recebimento do documento, para assinatura do(s) sócio(s) e/ou representante legal;', '', 182),
(11479, 'anexo', 259, 11472, 4, 'g', 'arquivar o processo administrativo de mudança de endereço tendo como motivação: “Desistência do pleito pela pessoa jurídica contratada”, caso o termo aditivo não seja assinado no prazo pré-estabelecido, exceto se:', 'I - houver solicitação de postergação do prazo pela pessoa jurídica contratada, com a devida justificativa;\nII - for apresentada justificativa plausível pela pessoa jurídica contratada, posteriormente.', 183),
(11480, 'anexo', 259, NULL, 1, '13', 'TERMO DE DISTRATO', '', 184),
(11481, 'anexo', 259, 11480, 2, '13.1', 'O termo de distrato de área acessória antes do final da vigência poderá ocorrer quando houver a solicitação, formal pela pessoa jurídica contratada, em prazo não inferior a 30 (trinta) dias da data em que se estima o fim do termo aditivo/autorização ou das atividades de prestação de serviços especiais ou demanda governamental:', '', 185),
(11482, 'anexo', 259, 11481, 4, 'a', 'quando observado o prazo não ensejará multa ou taxa;', '', 186),
(11483, 'anexo', 259, 11481, 4, 'b', 'não ensejará na devolução da taxa de instalação da área acessória pelos Correios.', 'Nota: não se aplicará a restrição disposta na alínea “a” ou cobrança de multa, quando o fechamento imediato for decorrente da identificação de falta de segurança das instalações da edificação onde está instalada a área acessória ou nas situações de caso fortuito ou força maior.', 187),
(11484, 'anexo', 259, 11480, 2, '13.2', 'O distrato também poderá ocorrer antes do início da operação da área acessória, podendo ocorrer a devolução do valor relativo a taxa de instalação, mas sem correção monetária, e, quando cabível, com os descontos a seguir:', '', 188),
(11485, 'anexo', 259, 11484, 4, 'a', 'o montante pago para publicação do extrato de celebração do termo aditivo no Diário Oficial da União - DOU e/ou do Estado;', '', 189),
(11486, 'anexo', 259, 11484, 4, 'b', 'o montante a ser pago para publicação do extrato do termo distrato no Diário Oficial da União - DOU e/ou do Estado.', '', 190),
(11487, 'anexo', 259, 11480, 2, '13.3', 'Os Correios podem suspender a operação da área acessória, durante a vigência do termo aditivo, uma vez que identifique a necessidade de instauração de processo administrativo de apuração de irregularidade:', 'a)	disposta da Tabela 6 do Anexo 4 do Contrato de Franquia Postal - CFP;\nb)	sobre deslocamento da área acessória ou dos equipamentos e periféricos habilitados para postagem para endereço distinto do autorizado para seu funcionamento, sem comunicação e autorização prévia;\nc)	apontada em apuração externa e/ou houver decisão judicial ou demanda de órgão de controle externo ou de polícia que indique pela paralisação temporária ou definitiva da área acessória.', 191),
(11488, 'anexo', 259, 11487, 3, '13.3.1', 'Sendo arquivado o processo administrativo de apuração, sem aplicação de penalidade, sendo de interesse da pessoa jurídica contratada, a área acessória poderá continuar as atividades, ou reinstalar a área acessória sem cobrança de taxas.', '', 192),
(11489, 'anexo', 259, 11487, 3, '13.3.2', 'Sendo comprovado o cometimento da irregularidade, mas sem a aplicação de penalidade de rescisão unilateral do CFP:', 'a) será contabilizada a pontuação correspondente a ocorrência de descumprimento contratual verificada, e quando cabível a penalidade (advertência/sanção pecuniária) correlacionada;\nb) será celebrado o termo de distrato, quando a irregularidade:\nI - estiver relacionada a captação de postagem a faturar, quando não autorizada;\nII - seja do Grupo II - Tabela 3 - Irregularidade de Gestão, cuja pontuação seja igual ou superior a 50 (cinquenta) pontos;\nIII - seja do Grupo IV - Tabela 6 - Irregularidade que ensejam rescisão unilateral do Contrato de Franquia Postal.', 193),
(11490, 'anexo', 259, 11487, 3, '13.3.3', 'Exceto no que diz respeito ao inciso III, alínea “b” do subitem 13.3.2 ficará vedada a instalação e operacionalização pela pessoa jurídica contratada de nova área acessória, de qualquer tipo, ou da reinstalação, por mínimo 6 (seis) meses.', '', 194),
(11491, 'anexo', 259, NULL, 1, '14', 'ATIVAÇÃO DA ÁREA ACESSÓRIA', '', 195),
(11492, 'anexo', 259, 11491, 2, '14.1', 'A ativação da área acessória só poderá ocorrer após a assinatura do termo de autorização ou do termo aditivo.', '', 196),
(11493, 'anexo', 259, 11491, 2, '14.2', 'Fluxo do Processo de Ativação da Área Acessória', '', 197),
(11494, 'anexo', 259, 11493, 3, '14.2.1', 'Procedimentos do órgão regional de gestão dos canais de atendimento terceirizados.', '14.2.1.1 Solicitar ao órgão regional de gestão de tratamento e distribuição análise quanto a oportunidade, conveniência e viabilidade de coleta em área acessória quando esta estiver instalada em imóvel diverso da AGF.\n14.2.1.2 Receber do órgão regional de gestão de tratamento e distribuição o resultado da análise de que trata o subitem 14.2.1.1.\n14.2.1.3 Realizar a atualização do Anexo 1 do instrumento contratual, incluindo os dados da área acessória.\n14.2.1.4 Solicitar ao órgão corporativo de gestão de cadastros, em até 5 (cinco) dias úteis antes da instalação, que cadastre:', 198),
(11495, 'anexo', 259, 11494, 4, 'a', 'o endereço da área acessória quando se tratar de imóvel diverso da instalação da Agência Centralizadora e os Correios forem realizar coleta neste local;', '', 199),
(11496, 'anexo', 259, 11494, 4, 'b', 'a inclusão do guichê de retaguarda na AGF, quando se tratar do imóvel principal ou complementar.', '14.2.1.5 Solicitar ao órgão corporativo de cadastro a alteração da vigência da área acessórias, sempre que for celebrado Termo Aditivo de Prorrogação ou Termo de Distrato com antecipação do fim da vigência.\n14.2.1.6 Incluir a área acessória no cronograma de supervisão ordinária e/ou extraordinária, em prol de verificar a correta operacionalização das atividades auxiliares no ponto adicional de atendimento:', 200),
(11497, 'anexo', 259, 11494, 4, 'a', 'preferencialmente, sempre que se mostrar viável e oportuno, na mesma data e horário das supervisões na AGF Centralizadora;', '', 201),
(11498, 'anexo', 259, 11494, 4, 'b', 'quando se tratar de área acessória - guichê de retaguarda em imóvel distinto, que tenha volume expressivo de postagem, realizar visitas in loco e viabilizar supervisões da carga postal nos Centros de Tratamento de forma periódica e aleatória.', '14.2.1.7 Solicitar, quando necessário, ao órgão regional de gestão de tecnologia da informação que realize testes de conectividade dos equipamentos e periféricos do canal de atendimento terceirizado que serão utilizados para operação do sistema/solução de atendimento na área acessória.', 202),
(11499, 'anexo', 259, 11493, 3, '14.2.2', 'Procedimentos do órgão regional de gestão de tratamento e distribuição.', '14.2.2.1 Receber do órgão regional de gestão dos canais de atendimento terceirizados a solicitação de análise de conveniência, oportunidade e viabilidade de realizar coleta na área acessória, quando esta for instalada fora do imóvel principal, complementar.\n14.2.2.2 Encaminhar o resultado da análise ao órgão regional de gestão dos canais de atendimento terceirizados em até 3 (três) dias úteis após o recebimento da solicitação.', 203),
(11500, 'anexo', 259, 11493, 3, '14.2.3', 'Procedimentos do órgão corporativo de gestão do cadastro.', '14.2.3.1 Receber do órgão regional de gestão dos canais de atendimento terceirizados solicitação de cadastramento do endereço da área acessória ou de alteração de vigência por prorrogação ou distrato.\n14.2.3.2 Providenciar o cadastramento até a véspera da data marcada para o início ou no dia posterior ao definido para o fim das operações na área acessória.\n14.2.3.3 Receber do órgão regional de gestão dos canais de atendimento terceirizado a solicitação para ativação ou desativação do(s) guichê(s)/ponto(s) de atendimento.\n14.2.3.4 Viabilizar a ativação ou desativação do do(s) guichê(s)/ponto(s) de atendimento com a maior brevidade possível.', 204),
(11501, 'anexo', 259, NULL, 1, '15', 'SISTEMA', '', 205),
(11502, 'anexo', 259, 11501, 2, '15.1', 'A solução de automação da rede de atendimento fornecida pelos Correios, obrigatoriamente, deverá(ão) ser utilizado(s) para realização dos registros de comercialização dos produtos e serviços em todas as áreas acessórias.', '', 206);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(11503, 'anexo', 259, 11502, 3, '15.1.1', 'Fica excetuada dessa regra ao GAS, quando a pessoa jurídica contratada optar pelo atendimento de forma manual, conforme previsto no Anexo 6 deste capítulo.', '', 207),
(11504, 'anexo', 259, 11501, 2, '15.2', 'A utilização nas áreas acessórias de solução de atendimento não autorizada pelos Correios para essa finalidade acarretará no enquadramento do fato em ocorrência de descumprimento contratual, e quando couber na aplicação das penalidades previstas no CFP.', '', 208),
(11505, 'anexo', 259, NULL, 1, '16', 'COLETA', '', 209),
(11506, 'anexo', 259, 11505, 2, '16.1', 'É de responsabilidade da pessoa jurídica contratada os custos, a segurança, a integridade da carga postal captada e seu transporte para as instalações da AGF Centralizadora, observando o horário estabelecido para coleta na Agência Centralizadora.', '', 210),
(11507, 'anexo', 259, 11505, 2, '16.2', 'Excepcionalmente, os Correios poderão realizar a coleta diretamente na área acessória, instalada em imóvel distinto da Agência Centralizadora, quando o órgão regional de gestão operacional analisar e concluir ser oportuno e conveniente realizar a coleta.', 'Nota: os Correios não tem obrigatoriedade de realizar coleta de carga postal em áreas acessórias.', 211),
(11508, 'anexo', 259, 11507, 3, '16.2.1', 'Serão utilizados entre outros parâmetros para a análise da conveniência e a oportunidade, o que segue:', '', 212),
(11509, 'anexo', 259, 11508, 4, 'a', 'a existência de área destinada às operações de embarque da carga postal que possibilite o acesso dos veículos de coleta dos Correios adequados ao volume de carga;', '', 213),
(11510, 'anexo', 259, 11508, 4, 'b', 'a média diária do volume de carga postal captada na AGF Centralizadora e na área acessória;', '', 214),
(11511, 'anexo', 259, 11508, 4, 'c', 'a disponibilidade e o melhor aproveitamento da capacidade da frota.', '', 215),
(11512, 'anexo', 259, 11505, 2, '16.3', 'Poderá haver horário de coleta distintos entre a área acessória o estabelecido para a agência. Nessa circunstância é obrigação da pessoa jurídica contratada ficar atenta:', 'a) ao horário limite de aceitação de postagem da agência centralizadora, Depois do Horário - DH;\nb) a separação dos objetos que não devem ser encaminhados, em razão do DH.', 216),
(11513, 'anexo', 259, 11505, 2, '16.4', 'O órgão regional de gestão operacional poderá acordar com a pessoa jurídica contratada a entrega da carga postal originada na AGF e/ou na área acessória, nos Centros de Tratamento ou outra unidade operacional que for mais conveniente para as partes.', '', 217),
(11514, 'anexo', 259, 11505, 2, '16.5', 'Tanto a carga disponibilizada para coleta pelos Correios nas instalações da agência, como aquela entregue nos Centros de Tratamento pelas AGF, deve impreterivelmente ter sido precedida da(o):', '', 218),
(11515, 'anexo', 259, 11514, 4, 'a', 'postagem;', '', 219),
(11516, 'anexo', 259, 11514, 4, 'b', 'triagem conforme definido no plano de triagem;', '', 220),
(11517, 'anexo', 259, 11514, 4, 'c', 'consolidação;', '', 221),
(11518, 'anexo', 259, 11514, 4, 'd', 'unitização; e', '', 222),
(11519, 'anexo', 259, 11514, 4, 'e', 'encaminhamento eletrônico (expedição).', '', 223),
(11520, 'anexo', 259, 11514, 3, '16.5.1', 'A inobservância da disposição presente no subitem 15.5 ensejará:', 'a) no registro de comercialização do(s) objeto(s) na unidade própria dos Correios que verificou a irregularidade, quando o remetente se tratar de cliente com contrato comercial;\nb) no desconto/glosa do valor de comercialização devido pela postagem dos objetos na remuneração da pessoa jurídica contratada, quando o remetente não se tratar de cliente com contrato comercial;\nc) na impossibilidade de geração de remuneração da AGF que encaminhou o objeto sem registro da postagem, quando a contabilização ocorrer por meio de um MCU diverso para que seja possível realizar a entrega ao destinatário ou devolução ao remetente, conforme o caso;\nd) na apuração da ocorrência de descumprimento contratual e quando cabível na aplicação da penalidade correspondente.', 224),
(11521, 'anexo', 259, NULL, 1, '17', 'PRESTAÇÃO DE CONTAS', '', 225),
(11522, 'anexo', 259, 11521, 2, '17.1', 'A prestação de contas relativa à comercialização de serviços e venda de produtos em áreas acessórias vinculadas a uma AGF Centralizadora deverá ser realizada no MCU desta, dentro dos prazos estabelecidos no Contrato de Franquia Postal e nas orientações específicas.', '', 226),
(11523, 'anexo', 259, 11521, 2, '17.2', 'A não observância das orientações acarretarão na aplicação das disposições estabelecidas no instrumento contratual, podendo inclusive ensejar na desativação da área acessória.', '', 227),
(11524, 'anexo', 259, NULL, 1, '18', 'IRREGULARIDADES', '', 228),
(11525, 'anexo', 259, 11524, 2, '18.1', 'Serão consideradas irregularidades, passíveis de suspensão das atividades em área acessória pelo período em que transcorrer o Processo Administrativo de Apuração, a existência de indícios de quaisquer dos comportamentos descritos a seguir:', '', 229),
(11526, 'anexo', 259, 11525, 4, 'a', 'deslocamento de objetos postais captados em determinada área acessória destinados à Agências de Correios diversa da AGF Centralizadora ou outra áreas acessórias, sejam essas unidades pertencentes a mesma pessoa jurídica contratada ou não;', '', 230),
(11527, 'anexo', 259, 11525, 4, 'b', 'recebimento de objetos postais cuja captação seja originada em outra área acessória ou AGF com MCU diferente;', '', 231),
(11528, 'anexo', 259, 11525, 4, 'c', 'cometimento de irregularidade cuja penalidade seja de rescisão unilateral do Contrato de Franquia Postal.', '', 232),
(11529, 'anexo', 259, 11524, 2, '18.2', 'A possibilidade de ocorrência de descumprimento contratual deverá ensejar na instalação de processo administrativo de apuração de irregularidade, considerando o fluxo estabelecido no instrumento contratual e no normativo específico.', '', 233),
(11530, 'anexo', 259, 11524, 2, '18.3', 'Identificado que a pessoas jurídica contratada está atuando de forma irregular na área acessória que possa trazer prejuízos aos Correios e a Terceiros, nos termos dispostos na Tabela 6 do Anexo 4 do Contrato de Franquia Postal, poderá ser demandada a suspensão imediata das atividades auxiliares ao serviço postal na área acessória. Para tanto, o órgão regional de gestão dos canais de atendimento terceirizados, deverá:', 'a) solicitar ao órgão regional de tecnologia da informação a desinstalação/desabilitação da solução de atendimento fornecida pelos Correios Guichês/pontos de atendimento correlacionados, bem como acompanhar a realização dos procedimentos;\nb) afixar cartaz em local visível na área acessória, com informação à população sobre a necessidade de fechamento do ponto de atendimento por período indeterminado, relacionando as unidades mais próximas para prestação do serviço.', 234),
(11531, 'anexo', 259, 11530, 3, '18.3.1', 'A paralização imediata da operação da área acessória ou da própria Agência Centralizadora pode ser demandada por meio de:', 'b) decisão judicial;\nc)  documento oficial de órgão de controle externo, assinado por pessoa competente.', 235),
(11532, 'anexo', 259, 11524, 2, '18.4', 'Finalizado o Processo Administrativo de Apuração, a AGF Centralizadora deverá ser comunicada sobre a decisão proferida, sendo:', '', 236),
(11533, 'anexo', 259, 11532, 4, 'a', 'comprovada a irregularidade e não havendo a decisão pela extinção do Contrato de Franquia Postal:', 'I - a depender da gravidade dos fatos, a área acessória será fechada e a AGF ficará impedida de instalar qualquer tipo de Área Acessória pelo prazo de 6 (seis) meses; e\nII - será aplicada as regras estabelecidas no instrumento contratual;\nNota: o processo administrativo de apuração deverá ser concluído, após a finalização de todas as fases, inclusive a cobrança de sanção pecuniária, quando couber, e apensado no processo administrativo principal de gestão da Agência de Correios Franqueada - AGF.', 237),
(11534, 'anexo', 259, 11532, 4, 'b', 'não comprovada a irregularidade:', 'I - a AGF Centralizadora poderá, sendo de seu interesse, prosseguir ou reiniciar as atividades na Área Acessória;\nII - o processo administrativo de apuração deverá ser concluído e apensado no processo administrativo principal de gestão da Agência de Correios Franqueada.', 238),
(11535, 'anexo', 259, 11524, 2, '18.5', 'Além das irregularidades previstas no Anexo 4 do Contrato de Franquia Postal serão enquadrados como ocorrência de descumprimento contratual a verificação de:', '', 239),
(11536, 'anexo', 259, 11535, 4, 'a', 'houver atendimento presencial de clientes em área acessória instalada em imóvel distinto, sem a devida autorização dos Correios;', '', 240),
(11537, 'anexo', 259, 11535, 4, 'b', 'captação de objetos postais na modalidade a faturar em GAC, sem a devida autorização dos Correios.', '', 241),
(11538, 'anexo', 259, 11535, 3, '18.5.1', 'As irregularidades listadas no item 17.5 serão enquadradas no Grupo II - Irregularidades de Gestão, Assunto 8 - Comercialização de produtos e serviços, Item 3 - Adotar práticas comerciais não previstas, a exemplo de concessão de descontos ou prazos não autorizados pela ECT, com a finalidade de aliciar clientes, induzindo-os a trocar o atendimento recebido por outra unidade pelo seu próprio.', '', 242),
(11539, 'anexo', 259, NULL, 1, '19', 'DESMOBILIZAÇÃO DA ÁREA ACESSÓRIA', '', 243),
(11540, 'anexo', 259, 11539, 2, '19.1', 'A pessoa jurídica contratada deverá descaracterizar a área acessória, que tenha sido instalada em imóvel diverso das instalações da AGF Centralizadora:', 'a) em prazo não superior a 30 (trinta) dias após fim da vigência do Termo Aditivo de autorização e operacionalização ou da assinatura do Termo de Distrato;\nb) retirando quaisquer sinalização ou comunicação visual, que contenha marca ou referência aos Correios;\nc) afixando cartaz, aprovado pelo órgão regional de gestão dos canais de atendimento terceirizado, informando a população e/ou clientes sobre a finalização das atividades da área acessória/ponto de atendimento.', 244),
(11541, 'anexo', 259, 11539, 2, '19.2', 'É de responsabilidade exclusiva da pessoa jurídica contratada o cumprimento das obrigações assumidas com terceiros para a instalação, operação e desmobilização da área acessória.', '', 245),
(11542, 'anexo', 259, 11539, 2, '19.3', 'A desmobilização da área acessória não afasta as obrigações operacionais e financeiras da pessoa jurídica contratada decorrentes de sua operação, inclusive no que diz respeito ao ressarcimento de custos e valores indenizatórios pagos ou impostos aos Correios, para os quais a AGF tenha dado causa, durante a vigência do termo aditivo ou do termo de autorização.', '* * * * *', 246),
(11543, 'anexo', 260, NULL, 1, '1', 'ESPECIFICIDADES DE ÁREA ACESSÓRIA - GUICHÊ DE RETAGUARDA NO IMÓVEL PRINCIPAL OU IMÓVEL COMPLEMENTAR', '', 0),
(11544, 'anexo', 260, 11543, 2, '1.1', 'A instalação de área acessória - guichê de retaguarda no imóvel principal ou complementar é recomendada quando o volume de postagens captadas supera a capacidade instalada e a estrutura física da agência comporta a adequação estrutural para implantação de célula(s) mínimas e célula(s) compartilhada, conforme orientações dos itens 5, 6 e 7 deste Anexo 3.', '', 1),
(11545, 'anexo', 260, 11543, 2, '1.2', 'Não poderá haver cumulação de área acessória nas instalação da Agência de Correios Franqueada - AGF com área acessória instalada em imóvel distinto.', '', 2),
(11546, 'anexo', 260, 11543, 2, '1.3', 'Nas situações em que a AGF tenha área acessória instalada em imóvel principal ou complementar, a Franqueada poderá solicitar sua transferência para imóvel distinto.', '', 3),
(11547, 'anexo', 260, 11546, 3, '1.3.1', 'A autorização da transferência será precedida de análise e aprovação pelo órgão regional de gestão dos canais de atendimento terceirizados, que utilizará na análise os mesmos parâmetros para avaliação de instalação em imóvel distinto, presentes neste Capítulo.', '', 4),
(11548, 'anexo', 260, 11543, 2, '1.4', 'Modalidade de Atendimento', '', 5),
(11549, 'anexo', 260, 11548, 3, '1.4.1', 'Guichê de Retaguarda nas instalações da AGF - pode atender nas seguintes modalidades:', '', 6),
(11550, 'anexo', 260, 11549, 4, 'a', 'à vista - em razão de coleta ou de atendimento personalizado pelo volume de postagens;', 'b) a faturar.', 7),
(11551, 'anexo', 260, 11543, 2, '1.5', 'Taxas Específicas', '', 8),
(11552, 'anexo', 260, 11551, 3, '1.5.1', 'Será devida a taxa correspondente ao número de guichês de retaguarda a serem instalados.', '', 9),
(11553, 'anexo', 260, 11551, 3, '1.5.2', 'Taxa de alteração de projeto de instalação da AGF.', '', 10),
(11554, 'anexo', 260, 11551, 3, '1.5.3', 'Taxa de vistoria de conformidade técnica de TI e/ou de Engenharia, quando couber.', '', 11),
(11555, 'anexo', 260, 11551, 3, '1.5.4', 'A transferência do guichê de retaguarda do imóvel principal/complementar para o Guichê de Retaguarda em imóvel Distinto não incidirá taxa específica.', '', 12),
(11556, 'anexo', 260, 11551, 3, '1.5.5', 'Os procedimentos de desconto/glosa de taxas estão presentes no Anexo 2 deste Capítulo.', '', 13),
(11557, 'anexo', 260, 11543, 2, '1.6', 'Quantitativo de Guichês/Pontos de Atendimento', '', 14),
(11558, 'anexo', 260, 11557, 3, '1.6.1', 'Será permitida a instalação do quantitativo de guichês/pontos de atendimento acordado entre os Correios e a pessoa jurídica contratada.', '', 15),
(11559, 'anexo', 260, 11557, 3, '1.6.2', 'Recomenda-se considerar o volume de vendas a faturar da agência para definição do quantitativo de guichês/pontos de atendimento.', '', 16),
(11560, 'anexo', 260, 11557, 3, '1.6.3', 'A desativação de guichês/pontos de atendimento não ensejará devolução total ou parcial da taxa de guichê de retaguarda.', '1.6.3.1 A pessoa jurídica contratada tem até 90 (noventa) dias para solicitar a reinstalação de guichês/pontos de atendimento para o qual tenha solicitado desinstalação, sem que isso gere nova taxa.', 17),
(11561, 'anexo', 260, NULL, 1, '2', 'FORMALIZAÇÃO DA AUTORIZAÇÃO PARA INSTALAÇÃO DA ÁREA ACESSÓRIA', '', 18),
(11562, 'anexo', 260, 11561, 2, '2.1', 'A formalização de autorização para instalação da área acessória no imóvel principal ou complementar será realizada por meio de Termo Aditivo - TA.', '', 19),
(11563, 'anexo', 260, 11561, 2, '2.2', 'A assinatura do instrumento de formalização deverá ocorrer por meio do Sistema Eletrônico de Informações - SEI, com a disponibilização do documento para assinatura externa.', '', 20),
(11564, 'anexo', 260, NULL, 1, '3', 'VIGÊNCIA DO TERMO ADITIVO PARA INSTALAÇÃO E OPERAÇÃO DA ÁREA ACESSÓRIA', '', 21),
(11565, 'anexo', 260, 11564, 2, '3.1', 'A vigência do Termo Aditivo - TA está adstrita, a quaisquer das 2 (duas) hipóteses listadas a seguir, prevalecendo o que ocorrer primeiro:', '', 22),
(11566, 'anexo', 260, 11565, 4, 'a', 'ao prazo de 36 (trinta e seis meses); ou', '', 23),
(11567, 'anexo', 260, 11565, 4, 'b', 'ao fim da vigência do Contrato de Franquia Postal.', '', 24),
(11568, 'anexo', 260, 11565, 3, '3.1.1', 'A assinatura do Termo Aditivo - TA deverá ocorrer por meio do Sistema Eletrônico de Informações - SEI, após a emissão do Termo de Vistoria Técnica, o qual dê parecer positivo.', '', 25),
(11569, 'anexo', 260, 11564, 2, '3.2', 'A contagem de prazo de vigência se inicia a partir da data da assinatura do Termo Aditivo -TA de autorização para instalação e operação da área acessória.', '', 26),
(11570, 'anexo', 260, 11569, 3, '3.2.1', 'A data do final de vigência do Termo Aditivo - TA deverá ser limitada a 5 (cinco) dias úteis antes do advento do termo final do Contrato de Franquia Postal - CFP.', '', 27),
(11571, 'anexo', 260, 11564, 2, '3.3', 'A partir da assinatura do Termo Aditivo - TA a pessoa jurídica contratada estará autorizada a iniciar a operacionalização a área acessória.', '', 28),
(11572, 'anexo', 260, NULL, 1, '4', 'PRORROGAÇÃO DE VIGÊNCIA DA AUTORIZAÇÃO DE OPERACIONALIZAÇÃO DA ÁREA ACESSÓRIA NAS INSTALAÇÕES DA AGÊNCIA', '', 29),
(11573, 'anexo', 260, 11572, 2, '4.1', 'A prorrogação de vigência da autorização para operacionalização da área acessória não é obrigatória.', '', 30),
(11574, 'anexo', 260, 11572, 2, '4.2', 'A pessoa jurídica contratada deverá, até 60 (sessenta) dias antes do vencimento do TA, apresentar solicitação para prorrogação da autorização para operacionalização da área acessória nas instalações da agência.', '', 31),
(11575, 'anexo', 260, 11572, 2, '4.3', 'O órgão regional de gestão dos canais de atendimento terceirizados para autorizar a prorrogação da autorização para operacionalização da área acessória nas instalações da agência, deverá verificar se a AGF cumpre os requisitos dispostos no Anexo 2 e no Anexo 3 deste Capítulo.', '', 32),
(11576, 'anexo', 260, 11572, 2, '4.4', 'Nos casos de prorrogação do Contrato de Franquia Postal - CFP pode ser celebrado novo Termo Aditivo para o funcionamento da área acessória, desde que a AGF esteja aderente a todos os critérios exigidos neste Capítulo e seus anexos.', '', 33),
(11577, 'anexo', 260, 11576, 3, '4.4.1', 'Considerando os custos correlacionados a prorrogação contratual, nesse caso o desconto/glosa da taxa de prorrogação do Termo Aditivo - TA da área acessória poderá ocorrer em até 90 (noventa) dias após a assinatura do Termo Aditivo - TA.', 'a) o comprovante da glosa/desconto deve ser anexado pelo órgão regional de gestão dos canais de atendimento terceirizado no processo administrativo de prorrogação da área acessória;', 34),
(11578, 'anexo', 260, 11577, 4, 'b', 'a pessoa jurídica contratada poderá solicitar a antecipação do fim da vigência da área acessória sem que isso enseje em multa ou taxa.', '', 35),
(11579, 'anexo', 260, 11576, 3, '4.4.2', 'Identificada qualquer situação de impedimento, o Termo Aditivo - TA não poderá ser prorrogado.', '', 36),
(11580, 'anexo', 260, NULL, 1, '5', 'LIMITE INFERIOR', '', 37),
(11581, 'anexo', 260, 11580, 2, '5.1', 'A instalação de área acessória em imóvel principal ou complementar não poderá comprometer o espaço físico da área de atendimento ou a operacionalização da AGF, o qual corresponde ao Limite Inferior da área que proporcionou ao licitante o alcance da pontuação na análise da ficha de avaliação técnica do edital de licitação.', '', 38),
(11582, 'anexo', 260, 11580, 2, '5.2', 'Os Limites Inferiores de cada unidade deverão considerar o quantitativo de Guichês de Atendimento e a pontuação obtida na FICHA DE AVALIAÇÃO TÉCNICA da AGF vigentes.', '', 39),
(11583, 'anexo', 260, 11582, 3, '5.2.1', 'Os Limites Inferiores por pontuação estão identificados nas tabelas abaixo:', 'Modelo A1\nQuantidade de guichês	Limite inferior da Área Mínima - 4 pontos	Limite inferior da Área Mínima - 10 pontos	Limite inferior da Área Ideal - 20 pontos\n1 guichê	48m²	55,21	60m²\n2 guichês	83m²	95,46	103m²\n3 guichês	97m²	111,56	122m²\n4 guichês	128m²	147,21	160m²\n5 guichês	143m²	164,46	179m²\n6 guichês	164m²	188,61	205m²\nModelo A2\nQuantidade de guichês	Limite Inferior - Área de Atendimento	Limite Inferior - Área de Operação\nLimite inferior - Área Total\n1 guichê	35,36m²	19,50m²	54,86m²\n2 guichês	40,30m²	19,50m²	59,80m²\n3 guichês	53,40m²	19,50m²	72.90m²\n4 guichês	66,00m²	19,50m²	85,50m²', 40),
(11584, 'anexo', 260, 11580, 2, '5.3', 'O espaço a ser utilizado no Imóvel Principal (Modelos A1 e A2) ou complementar (Modelo A2) para instalação da área acessória deve ser calculado com base nas Fórmulas presentes no item 6 e seus subitens.', '', 41),
(11585, 'anexo', 260, NULL, 1, '6', 'FÓRMULAS PARA CALCULAR A QUANTIDADE MÁXIMA DE GUICHÊS DE RETAGUARDA - IMÓVEL PRINCIPAL OU COMPLEMENTAR', '', 42),
(11586, 'anexo', 260, 11585, 2, '6.1', 'As fórmulas de cálculo utilizadas para identificar a quantidade máxima de Guichês de Retaguarda a serem instalados no espaço excedente existente em imóvel principal/complementar ou atendimento estão dispostas a seguir:', 'a) primeira etapa: Fórmula ?\nOnde:\nX: área homologada\nY: área estabelecida no edital (limite inferior)\nAE: área que pode ser utilizada como área acessória\nb) segunda etapa: Fórmula ?\nOnde:\nAE: área que pode ser utilizada como área acessória\nCM: célula mínima (5,75m² por guichê de retaguarda)\nN: quantidade máxima de guichês de retaguarda', 43),
(11587, 'anexo', 260, 11585, 2, '6.2', 'Resultados', '', 44),
(11588, 'anexo', 260, 11587, 3, '6.2.1', 'Poderá ser autorizada a instalação de Guichês de Retaguarda equivalente ao valor de “N” desde que seja igual ou superior a 1(um).', '', 45),
(11589, 'anexo', 260, 11587, 3, '6.2.2', 'Não poderá haver autorização para instalação de Área Acessória, se o resultado de “N” for inferior a 1 (um).', '', 46),
(11590, 'anexo', 260, 11585, 2, '6.3', 'Exemplos de Aplicação das Fórmulas', '', 47),
(11591, 'anexo', 260, 11590, 3, '6.3.1', 'Área mínima: metragem indicada no edital de licitação de Agência de Correios Franqueada - AGF.', '', 48),
(11592, 'anexo', 260, 11590, 3, '6.3.2', 'Pontuação concedida na análise da ficha de avaliação técnica: 4 pontos considerando a Área ofertada pelo licitante e homologada pelos Correios.', 'Modelo A1	1 guichê	2 guichês	3 guichês	4 guichês	5 guichês	6 guichês\nÁrea homologada (m²) *	54	87	110	147	170	180\nÁrea Mínima - Edital (m²)	48	83	97	128	143	164\nEspaço passível de disponibilização (m²)	6	4	13	19	27	16\nCélula Mínima - 1 Guichê de Retaguarda (m²)	5,75	5,75	5,75	5,75	5,75	5,75\nQuantidade Máxima de Guichês de Retaguarda possíveis para instalação na Área Acessória	1	0	2	3	5	3\n* valores exemplificativos.', 49),
(11593, 'anexo', 260, NULL, 1, '7', 'CÉLULA MÍNIMA - DIMENSÕES DA ÁREA PARA INSTALAÇÃO DE GUICHÊ DE RETAGUARDA NA AGÊNCIA', '', 50),
(11594, 'anexo', 260, 11593, 2, '7.1', 'O espaço físico estimado para comportar uma célula mínima é de 5,75 m², cuja área será destinada ao mobiliário e aos equipamentos constantes na tabela a seguir:', 'Mobiliário e Equipamentos que Compõem a Célula Mínima\nDescrição	Uso\nMB-01 B ERG (Mesa para Balança)	Mobiliário opcional\nImpressora a laser	Equipamento opcional\nMesa para digitador para agência (conforme Descrição Técnica; MDI 02B ou similar)	Mobiliário obrigatório\nCAD-27B ERG (Cadeira de Espaldar Baixo para Agência)\nMicrocomputador	Equipamento obrigatório\nLeitor de Código de Barras\nMesa de uso múltiplo para Agência (conforme Descrição Técnica; MMU-03B ou similar)	Mobiliário obrigatório (pode ser exclusivo de 1 guichê de retaguarda ou pode ser compartilhado com os demais)\nBalança de 6Kg, acoplada ao micro\nBalança de 30Kg, acoplada ao micro', 51),
(11595, 'anexo', 260, 11594, 3, '7.1.1', 'O Projeto de Instalação deverá estar compatível com o número de Guichês de Retaguarda solicitados pela pessoa jurídica contratada.', '', 52),
(11596, 'anexo', 260, 11594, 3, '7.1.2', 'Área(s) mínima(s) para instalação de Guichê(s) de Retaguarda é composta pela estimativa mínima de espaço físico necessário para acomodar de 1 (um) a 12 (doze) células mínimas, conforme tabela a seguir:', 'Número Guichês de Retaguarda/Empresariais	Área para o conjunto de células mínimas (m2)\n1	5,75\n2	11,06\n3	16,35\n4	22,00\n5	25,90\n6	28,43\n7	35,40\n8	37,95\n9	45,00\n10	47,52\n11	54,44\n12	56,98', 53),
(11597, 'anexo', 260, 11593, 2, '7.2', 'Exceções', '', 54),
(11598, 'anexo', 260, 11597, 3, '7.2.1', 'As situações excepcionais em que a área excedente for até 10% menor que a célula mínima definida para instalar um Guichê de Retaguarda, correspondente a até 57cm², deverão ser analisadas individualmente pelos órgãos regionais de gestão dos canais de atendimento terceirizados, de forma a se estabelecer se a operacionalização das atividades postais realizadas na AGF não seria prejudicada.', '', 55),
(11599, 'anexo', 260, 11597, 3, '7.2.2', 'Deverá elaborado relatório circunstanciado, quando necessário, poderá ser consultada a área de engenharia, para subsidiar a apreciação e deliberação fundamentada do Superintendente Estadual - SE.', '', 56),
(11600, 'anexo', 260, NULL, 1, '8', 'CÉLULA COMPARTILHADA', '', 57),
(11601, 'anexo', 260, 11600, 2, '8.1', 'O espaço físico necessário para a instalação da célula compartilhada dependerá da quantidade de móveis e equipamentos que a AGF necessitará para apoiar a operacionalização dos serviços auxiliares.', '', 58),
(11602, 'anexo', 260, 11600, 2, '8.2', 'A célula compartilhada é de utilização opcional e poderá ser associada com as atividades dos Guichês de Atendimento e/ou com outros Guichês de Retaguarda.', '', 59),
(11603, 'anexo', 260, 11600, 2, '8.3', 'O conjunto de móveis e equipamentos, destinados ao suporte das atividades desenvolvidas no Guichê de Retaguarda, estão contidos de forma referencial na tabela a seguir:', 'MOBILIÁRIO A SER COMPARTILHADO NAS ÁREAS ACESSÓRIAS\nONDE SERÃO INSTALADOS OS GUICHÊS DE RETAGUARDA\nCódigo	Descrição\nMC - 02B ERG	Mesa de Carimbação\nCAD-04B ERG 	Cadeira Alta\nMIMP - 03B 	Mesa para Impressora para Agências\nEP - 03B	Estante para Pacotes\nCM - 03B ERG	Cabide de Malas\nSC - 01 ERG	Suporte para Caixetas\nMMU-01-ERG	Mesa múltiplo uso - pequena\nMMU-02-ERG	Mesa múltiplo uso - grande\nMMU-03B	Mesa de Múltiplo Uso para agências\nCTME-01-ERG	Carrinho para Transporte de Malotes e Encomendas\nCTME-02-ERG	Carrinho para Transporte de Malotes e Encomendas escamoteável\nCTO-01-ERG	Carrinho para Transporte de Objetos\nCTO-02-ERG	Carrinho para Transporte de Objetos para Expedição\nBalança de 6Kg\nBalança de 30Kg\nImpressora a laser', 60),
(11604, 'anexo', 260, 11600, 2, '8.4', 'A instalação de mobiliário destinado à execução das atividades auxiliares no Guichê de Retaguarda no Imóvel Principal (Modelos A1 e A2) ou complementar (Modelo A2), mas não previstos nos guias e especificações técnicas, deverá ser previamente solicitada aos Correios e por este aprovada.', '', 61),
(11605, 'anexo', 260, 11604, 3, '8.4.1', 'Os projetos de mobiliário para apreciação dos Correios deverão considerar, obrigatoriamente, as mesmas referências de ergonomia observadas nos atuais Guias e especificações técnicas, mesmo que a proposição inclua outros materiais a serem utilizados na estrutura e no acabamento do(s) móvel(is), o qual pode considerar, entre outros fatores, as características e o volume da carga tratada e/ou condições climáticas especificas das localidades.', '* * * * *', 62),
(11606, 'anexo', 261, NULL, 1, '1', 'ESPECIFICIDADES DE ÁREA ACESSÓRIA - GUICHÊ DE RETAGUARDA EM IMÓVEL DISTINTO - GRID', '', 0),
(11607, 'anexo', 261, 11606, 2, '1.1', 'A instalação de Área Acessória Guichê de Retaguarda em Imóvel Distinto - GRID é recomendada para situações em que o imóvel onde a Agência de Correios Franqueada - AGF não comporta ampliação e o quantitativo de objetos captados supera a capacidade de tratamento na estrutura física.', '', 1),
(11608, 'anexo', 261, 11606, 2, '1.2', 'Quantitativo de Áreas Acessórias do Tipo GRID', '', 2),
(11609, 'anexo', 261, 11608, 3, '1.2.1', 'Cada AGF Centralizadora poderá instalar apenas um GRID.', '', 3),
(11610, 'anexo', 261, 11608, 3, '1.2.2', 'É vedado a cumulação de GRID com área acessória nas instalações da agência (imóvel principal ou complementar).', '', 4),
(11611, 'anexo', 261, 11608, 3, '1.2.3', 'A pessoa jurídica contratada poderá, por oportunidade e conveniência, solicitar a transferência da estrutura do GRID para o imóvel principal ou complementar.', '1.2.3.1 A autorização da transferência será precedida de análise e aprovação pelo órgão regional de gestão dos canais de atendimento terceirizados, que utilizará na análise os mesmos parâmetros utilizados para avaliação de instalação em imóvel principal ou complementar.', 5),
(11612, 'anexo', 261, 11606, 2, '1.3', 'Modalidade de Atendimento', '', 6),
(11613, 'anexo', 261, 11612, 3, '1.3.1', 'No Guichê de Retaguarda em Imóvel Distinto - DRID os clientes poderão ser atendidos nas seguintes modalidades:', 'a) à vista - em razão de coleta;\nb) a faturar - em razão de coleta.', 7),
(11614, 'anexo', 261, 11612, 3, '1.3.2', 'Não poderá haver atendimento presencial de clientes de varejo ou com contrato, exceto quando formalmente autorizado pelos Correios.', '', 8),
(11615, 'anexo', 261, 11612, 3, '1.3.3', 'A autorização de que trata o item 1.3.2 só poderá ser concedida corporativamente, em situações excepcionais e de forma temporária:', 'a) para prestar serviços especiais e demandas governamentais;\nb) em prol de garantir a continuidade do atendimento postal à população na Região de Atendimento onde o GRID foi instalado, nas situações em que houver fechamento definitivo ou provisória de outro canal de atendimento.', 9),
(11616, 'anexo', 261, 11606, 2, '1.4', 'Localização', '', 10),
(11617, 'anexo', 261, 11616, 3, '1.4.1', 'Esse tipo de área acessória deverá ser instalado no mesmo município onde está instalada a AGF Centralizadora, em prol de atuar sob o mesmo regimento tributário municipal.', '', 11),
(11618, 'anexo', 261, 11606, 2, '1.5', 'Taxas Específicas do GRID', '', 12),
(11619, 'anexo', 261, 11618, 3, '1.5.1', 'Será necessário o pagamento das taxas relativas à vistoria de conformidade técnica, quando cabível.', '', 13),
(11620, 'anexo', 261, 11618, 3, '1.5.2', 'Será devida a taxa correspondente ao número de guichês de retaguarda a serem instalados no GRID.', '', 14),
(11621, 'anexo', 261, 11618, 3, '1.5.3', 'Na prorrogação da autorização da operacionalização do GRID será realizada nova cobrança da taxa de que trata o subitem 1.5.2.', '', 15),
(11622, 'anexo', 261, 11618, 3, '1.5.4', 'A transferência do GRID para o imóvel principal não incidirá taxa específica, exceto se houver ampliação do número de guichês de retaguarda/ponto de atendimento.', '', 16),
(11623, 'anexo', 261, 11618, 3, '1.5.5', 'As taxas correlacionadas ao GRID serão glosadas/recolhidas da remuneração da pessoa jurídica contratada, consoante aos valores presentes na tabela do Anexo 2 do instrumento contratual.', '', 17),
(11624, 'anexo', 261, 11618, 3, '1.5.6', 'Havendo solicitação de distrato do Termo Aditivo - TA, antes de iniciar a operacionalização do GRID poderá ocorrer a devolução do valor relativo ao pagamento da taxa de instalação de área acessória, sem correção, e, quando cabível, com os descontos a seguir:', 'a) o montante pago para publicação do extrato de celebração do TA no Diário Oficial da União - DOU/ou do Estado;\nb) o montante a ser pago para publicação do extrato do Termo Distrato - TD no Diário Oficial da União - DOU e/ou do Estado.', 18),
(11625, 'anexo', 261, 11606, 2, '1.6', 'Quantitativo de Guichês/Pontos de Atendimento', '', 19),
(11626, 'anexo', 261, 11625, 3, '1.6.1', 'Será permitida a instalação do quantitativo de guichês/pontos de atendimento acordado entre os Correios e a pessoa jurídica contratada.', '', 20),
(11627, 'anexo', 261, 11625, 3, '1.6.2', 'Para definição do quantitativo de guichês/pontos de atendimento recomenda-se considerar o volume de vendas a faturar da agência.', '', 21),
(11628, 'anexo', 261, 11606, 2, '1.7', 'Imóvel onde será Instalado o GRID', '', 22),
(11629, 'anexo', 261, 11628, 3, '1.7.1', 'É obrigatória a comprovação de vínculo jurídico da pessoa jurídica contratada com o imóvel antes do início da operação da área acessória.', '', 23),
(11630, 'anexo', 261, 11628, 3, '1.7.2', 'O documento comprobatório deve ser incluído no processo administrativo específico, até 5 (cinco) dias úteis antes da data definida para o começo das atividades do Guichê de retaguarda em imóvel distinto.', '', 24),
(11631, 'anexo', 261, 11628, 3, '1.7.3', 'A falta da comprovação do vínculo jurídico é fator de impedimento para o início da operação da Área Acessória.', '', 25),
(11632, 'anexo', 261, NULL, 1, '2', 'FORMALIZAÇÃO DA AUTORIZAÇÃO PARA INSTALAÇÃO DO GRID', '', 26),
(11633, 'anexo', 261, 11632, 2, '2.1', 'A formalização de autorização para instalação do GRID Será realizada por meio de TA.', '', 27),
(11634, 'anexo', 261, 11632, 2, '2.2', 'A assinatura do instrumento de formalização poderá ocorrer:', '', 28),
(11635, 'anexo', 261, 11634, 4, 'a', 'preferencialmente, por meio do Sistema Eletrônico de Informações - SEI, com a disponibilização do documento para assinatura externa;', '', 29),
(11636, 'anexo', 261, 11634, 4, 'b', 'de forma presencial, em local e data pré-agendada de comum acordo entre a pessoa jurídica contratada e o órgão regional de gestão dos canais de atendimento terceirizados.', '', 30),
(11637, 'anexo', 261, NULL, 1, '3', 'VIGÊNCIA DO TERMO ADITIVO PARA INSTALAÇÃO E OPERAÇÃO DO GRID', '', 31),
(11638, 'anexo', 261, 11637, 2, '3.1', 'A vigência do Termo Aditivo está adstrita, a quaisquer das 3 (três) hipóteses listadas a seguir, prevalecendo o que ocorrer primeiro:', '', 32),
(11639, 'anexo', 261, 11638, 4, 'a', 'a duração do vínculo jurídico da pessoa jurídica contratada com o imóvel onde será instalado o GRID; ou', '', 33),
(11640, 'anexo', 261, 11638, 4, 'b', 'ao prazo de 36 (trinta e seis meses); ou', '', 34),
(11641, 'anexo', 261, 11638, 4, 'c', 'ao fim da vigência do Contrato de Franquia Postal - CFP.', '', 35),
(11642, 'anexo', 261, 11637, 2, '3.2', 'A partir da data inicial de vigência do instrumento de formalização a pessoa jurídica contratada estará autorizada a iniciar a operacionalização do GRID.', '', 36),
(11643, 'anexo', 261, 11637, 2, '3.3', 'A pessoa jurídica contratada poderá solicitar a antecipação do fim da vigência do GRID sem que isso enseje em multa ou taxa.', '', 37),
(11644, 'anexo', 261, NULL, 1, '4', 'PRORROGAÇÃO DA AUTORIZAÇÃO DE OPERACIONALIZAÇÃO DO GRID', '', 38),
(11645, 'anexo', 261, 11644, 2, '4.1', 'Poderá haver prorrogação da autorização para operacionalização do GRID, para tanto deverá ser verificado(a):', '', 39),
(11646, 'anexo', 261, 11645, 4, 'a', 'se a AGF não está enquadrada nas situações de vedação;', '', 40),
(11647, 'anexo', 261, 11645, 4, 'b', 'a permanência ou renovação do prazo do vínculo jurídico da pessoa jurídica contratada com o imóvel onde estará/está instalada o GRID.', '', 41),
(11648, 'anexo', 261, NULL, 1, '5', 'TRANSFERÊNCIA DA ÁREA ACESSÓRIA', '', 42),
(11649, 'anexo', 261, 11648, 2, '5.1', 'Havendo a solicitação para reinstalação de área acessória em período não superior a 90 (noventa) dias não será cobrada nova Taxa de Instalação de Guichê de Retaguarda, quando for no:', 'a) mesmo imóvel ou não;\nb) imóvel principal (Modelos A1 ou A2); ou\nc) imóvel complementar (Modelo A2).', 43),
(11650, 'anexo', 261, 11648, 2, '5.2', 'Em situações de reinstalação deverá ser assinado um novo instrumento de formalização, no qual deverá constar a motivação para isenção da taxa de instalação de guichê de retaguarda.', '', 44),
(11651, 'anexo', 261, 11648, 2, '5.3', 'A solicitação de reinstalação ocorrendo em prazo superior a 90 (noventa) dias, incidirá a cobrança da taxa correspondente ao número de guichês a serem instalados.', '* * * * *', 45),
(11652, 'anexo', 262, NULL, 1, '1', 'ORIENTAÇÕES ESPECÍFICAS APLICÁVEIS A ÁREA ACESSÓRIA GUICHÊ AVANÇADO DE ATENDIMENTO CONTINGENCIAL - GAC', '', 0),
(11653, 'anexo', 262, 11652, 2, '1.1', 'A instalação de área acessória - Guichê Avançado de Atendimento Contingencial - GAC é aplicável, nas oportunidades em que não foi possível instalar, de imediato, uma solução definitiva de atendimento postal.', '', 1),
(11654, 'anexo', 262, 11652, 2, '1.2', 'Modalidade de Atendimento', '', 2),
(11655, 'anexo', 262, 11654, 3, '1.2.1', 'No GAC pode ocorrer atendimento nas seguintes modalidades:', 'a) à vista - varejo;', 3),
(11656, 'anexo', 262, 11655, 4, 'b', 'à faturar, em situações excepcionais, quando formalmente autorizado pelos Correios.', '', 4),
(11657, 'anexo', 262, 11654, 3, '1.2.2', 'A excepcionalidade de que trata a alínea “b” do subitem 1.2.1, só poderá ser concedida corporativamente e de forma temporária, devendo ser aplicada apenas nas situações em que:', '', 5),
(11658, 'anexo', 262, 11657, 4, 'a', 'não existam outros os canais de atendimento (próprio e terceirizado) instalados no município que tenham os serviços a faturar autorizados no portfólio;', '', 6),
(11659, 'anexo', 262, 11657, 4, 'b', 'quando houver no município canal de atendimento unipessoal ou cuja estrutura instalada não comporta(em) a operacionalização do volume dos serviços e não haja perspectiva de ampliar essa capacidade a curto prazo.', '1.2.2.1 A concessão da liberalidade de que trata o subitem 1.2.2 é eminentemente precária, não gerando obrigação, podendo ser interrompida a qualquer tempo, sem necessidade de anuência da pessoa jurídica contratada.\n1.2.2.2 Anualmente, na prorrogação do termo aditivo, deverá ser reavaliada pelo órgão regional de gestão dos canais de atendimento a necessidade da manutenção da excepcionalidade de que trata o subitem 1.2.2.', 7),
(11660, 'anexo', 262, 11652, 2, '1.3', 'Localização', '', 8),
(11661, 'anexo', 262, 11660, 3, '1.3.1', 'O GAC só poderá ser instalado no mesmo município onde está instalada a Agência de Correios Franqueada - AGF Centralizadora, em localidade desassistida.', '', 9),
(11662, 'anexo', 262, 11660, 3, '1.3.2', 'Será considerada desassistida de atendimento postal, quando se constatar na localidade:', '', 10),
(11663, 'anexo', 262, 11662, 4, 'a', 'o fechamento de unidade própria ou terceirizada, a menos de 12 (doze) meses, que ainda não tenham sido substituídas por meio de processo licitatório ou por unidade própria;', '', 11),
(11664, 'anexo', 262, 11662, 4, 'b', 'o fechamento temporário de unidade própria para fins de reforma ou relocalização, e esse processo se dará em prazo superior a 6 (seis) meses;', '', 12),
(11665, 'anexo', 262, 11662, 4, 'c', 'que o quantitativo de guichês/pontos de atendimento esteja inferior ao número calculado conforme metodologia estabelecida na legislação vigente e/ou nos normativos internos dos Correios e a localidade não estiver prevista para licitação.', '', 13),
(11666, 'anexo', 262, 11652, 2, '1.4', 'O órgão regional de gestão dos canais de atendimento terceirizados ao identificar a necessidade de instalação de ponto de atendimento, para o qual não esteja prevista a substituição por canal de atendimento definitivo, em até 12 (doze) meses, poderá propor a instalação de uma área acessória do tipo guichê avançado de atendimento contingencial na localidade desassistido.', '', 14),
(11667, 'anexo', 262, 11666, 3, '1.4.1', 'A proposta deverá ser submetida pelo órgão regional de gestão dos canais de atendimento terceirizados ao (a) Superintendente Estadual - SE, por meio de um relatório técnico especifico.', '1.4.1.1 O relatório técnico deverá contemplar no mínimo as informações abaixo:\na) o quantitativo populacional da localidade/município;\nb) relação das unidades de atendimento próprias ou terceirizadas instaladas no município e na circunvizinhança à Região de Atendimento, bem como as distâncias entre elas e a unidade fechada;\nc) o resultado/quantitativo, por período não inferior a 6 (seis) meses:\nI - do indicador do tempo de espera na fila das unidades da circunvizinhança;\nII - de multas ou notificações do Programa de Proteção e Defesa do Consumidor - Procon ou outros órgãos de fiscalização sobre demora no atendimento na unidade fechada e daquelas listadas na alínea “b” deste item;\nIII - do resultado da operação Receita sobre Despesa - R/D das agências próprias instaladas nas proximidades da unidade fechada;\nIV - do valor de receita auferido pela unidade fechada e daquelas listadas na alínea “b” deste item.', 15),
(11668, 'anexo', 262, 11652, 2, '1.5', 'Havendo deferimento pelo(a) Superintendente Estadual o processo deverá ser submetido ao órgão corporativo de gestão de canais de atendimento terceirizado para análise da viabilidade da instalação de área acessória.', '', 16),
(11669, 'anexo', 262, 11652, 2, '1.6', 'A avaliação da viabilidade pelo órgão corporativo de gestão estratégica de canais de atendimento terceirizados, entre outros fatores considerará:', '', 17),
(11670, 'anexo', 262, 11669, 4, 'a', 'a estratégia de ocupação de mercado definida pelos Correios; e', '', 18),
(11671, 'anexo', 262, 11669, 4, 'b', 'se o quantitativo de pontos de atendimento já instalados na localidade atendem ou não as diretrizes estabelecidas na legislação vigente.', '', 19),
(11672, 'anexo', 262, 11652, 2, '1.7', 'A resposta do órgão corporativo de gestão estratégica de canais de atendimento terceirizados, poderá ensejar no(a):', '', 20),
(11673, 'anexo', 262, 11672, 4, 'a', 'arquivamento do processo de instalação de guichê avançado de atendimento contingencial, quando não houver autorização;', '', 21),
(11674, 'anexo', 262, 11672, 4, 'b', 'fornecimento de informações complementares, quando solicitado e reencaminhar o processo para reavaliação;', '', 22),
(11675, 'anexo', 262, 11672, 4, 'c', 'consulta sobre o interesse em instalar e operar GAC a todas as agências terceirizadas elegíveis.', 'Nota: não pode ser iniciada nenhuma iniciativa regional para a instalação de GAC, em fase anterior a autorização formal do órgão corporativo de gestão de canais de atendimento terceirizado.', 23),
(11676, 'anexo', 262, NULL, 1, '2', 'PROCEDIMENTOS DO ÓRGÃO REGIONAL DE GESTÃO DOS CANAIS DE ATENDIMENTO TERCEIRIZADOS', '', 24),
(11677, 'anexo', 262, 11676, 2, '2.1', 'Realizar o chamamento amplo, por meio de carta circular, encaminhada a todas as unidades contratadas que atentam os requisitos exigíveis, instaladas no município, fazendo constar na correspondência:', '', 25),
(11678, 'anexo', 262, 11677, 4, 'a', 'o prazo de vigência do termo aditivo;', '', 26),
(11679, 'anexo', 262, 11677, 4, 'b', 'a localidade, faixa de endereço, onde faz-se necessária a instalação do GAC;', '', 27),
(11680, 'anexo', 262, 11677, 4, 'c', 'que a instalação do GAC não amplia ou altera a vigência contratual;', '', 28),
(11681, 'anexo', 262, 11677, 4, 'd', 'que não há obrigatoriedade de prorrogação do termo aditivo de instalação e operação do GAC;', '', 29),
(11682, 'anexo', 262, 11677, 4, 'e', 'critérios de desempate;', '', 30),
(11683, 'anexo', 262, 11677, 4, 'f', 'os requisitos para abertura e operacionalização do GAC.', '', 31),
(11684, 'anexo', 262, 11676, 2, '2.2', 'Existindo mais de uma unidade interessada, a escolha será feita com base na proximidade geográfica com a Região-Alvo que necessita de atendimento contingencial, considerando:', '', 32),
(11685, 'anexo', 262, 11684, 4, 'a', 'o critério de proximidade geográfica, será aquele mais próximo em percurso, por vias públicas, entre o endereço da agência e o local onde se pretende instalar o GAC;', '', 33),
(11686, 'anexo', 262, 11684, 4, 'b', 'ao percurso calculado não se aplica uma linha reta imaginária, aplica-se o percurso real por vias públicas;', '', 34),
(11687, 'anexo', 262, 11684, 4, 'c', 'independentemente da proximidade geográfica, é vedado a autorização para instalação de GAC à agência que esteja em outro município.', '', 35),
(11688, 'anexo', 262, 11684, 3, '2.2.1', 'Analisar as respostas positivas enviadas pelas unidades interessadas e selecionar a(s) melhor(es) posicionada(s), segundo os critérios do subitem 2.2.', '', 36),
(11689, 'anexo', 262, 11676, 2, '2.3', 'Na hipótese de empate no critério de proximidade, será considerado para desempate a seguinte ordem:', '', 37),
(11690, 'anexo', 262, 11689, 4, 'a', 'a menor pontuação no histórico de irregularidades, nos 6 (seis) meses anteriores; e', '', 38),
(11691, 'anexo', 262, 11689, 4, 'b', 'a unidade que não tenha outro GAC já instalado.', '', 39),
(11692, 'anexo', 262, 11676, 2, '2.4', 'Comunicar as pessoas jurídicas consultadas sobre o resultado da seleção.', '', 40),
(11693, 'anexo', 262, 11676, 2, '2.5', 'Acompanhar a instalação da área acessória, observando as disposições deste Capítulo, do instrumento contratual e dos demais regramentos internos.', '', 41),
(11694, 'anexo', 262, NULL, 1, '3', 'ESPECIFICIDADES DE ÁREA ACESSÓRIA - GUICHÊ AVANÇADO DE ATENDIMENTO CONTINGENCIAL', '', 42),
(11695, 'anexo', 262, 11694, 2, '3.1', 'Poderão ser instaladas até 2 (duas) áreas acessórias desse tipo sob gestão de uma mesma Agência Centralizadora.', '', 43),
(11696, 'anexo', 262, 11694, 2, '3.2', 'Será permitida a instalação em cada GAC do quantitativo de guichês/pontos de atendimento acordado entre os Correios e a pessoa jurídica contratada.', '', 44),
(11697, 'anexo', 262, 11696, 3, '3.2.1', 'Para definição do quantitativo de guichês/pontos de atendimento será considerado:', '', 45),
(11698, 'anexo', 262, 11697, 4, 'a', 'o quantitativo de pontos de atendimento calculados, conforme metodologia estabelecida na legislação vigente e/ou nos normativos internos dos Correios;', '', 46),
(11699, 'anexo', 262, 11697, 4, 'b', 'volume histórico de vendas à vista da unidade de atendimento anteriormente localizada na Região de Atendimento desassistida;', '', 47),
(11700, 'anexo', 262, 11697, 4, 'c', 'o limite de guichês de atendimento estabelecida originalmente para as unidades do modelo de canal de atendimento terceirizado.', '', 48),
(11701, 'anexo', 262, 11694, 2, '3.3', 'A prioridade para a instalação desse tipo de Área Acessória será da AGF que estiver localizada mais próxima da Região-Alvo que necessita da contingência.', '', 49),
(11702, 'anexo', 262, NULL, 1, '4', 'PROJETO DE INSTALAÇÃO DO GUICHÊ AVANÇADO DE ATENDIMENTO CONTINGENCIAL', '', 50),
(11703, 'anexo', 262, 11702, 2, '4.1', 'Considerando o caráter emergencial da instalação do guichê, o GAC poderá ser instalado de imediato, podendo os procedimentos relativos à apresentação e aprovação do projeto de instalação ocorrer no prazo de 90 (noventa) dias, contados a partir da assinatura do Termo Aditivo.', '', 51),
(11704, 'anexo', 262, 11703, 3, '4.1.1', 'O início das operações do GAC de que trata o subitem 8.1 poderá ocorrer desde que sejam atendidas as condições mínimas de instalação listadas a seguir:', '', 52),
(11705, 'anexo', 262, 11704, 4, 'a', 'apresentação do alvará de funcionamento;', '', 53),
(11706, 'anexo', 262, 11704, 4, 'b', 'disponibilização no local de instalação do GAC dos equipamentos e periféricos definidos no Guia de Especiações Técnicas;', '', 54),
(11707, 'anexo', 262, 11704, 4, 'c', 'instalações da rede de comunicação de dados, bem como dos equipamentos de TI;', '', 55),
(11708, 'anexo', 262, 11704, 4, 'd', 'instalação da solução de automação do atendimento fornecido pelos Correios e demais sistemas corporativos previstos para operação do canal de atendimento terceirizado;', '', 56),
(11709, 'anexo', 262, 11704, 4, 'e', 'condições mínimas estabelecidas para o imóvel, considerando-se a segurança das instalações, de tal forma que não comprometa o atendimento aos clientes, o tratamento, a guarda dos objetos postais e a integridade física das pessoas;', '', 57),
(11710, 'anexo', 262, 11704, 4, 'f', 'mobiliário e equipamentos classificados como obrigatórios e imprescindíveis.', '', 58),
(11711, 'anexo', 262, 11702, 2, '4.2', 'A verificação das condições mínimas de funcionamento é responsabilidade do órgão regional de gestão dos canais de atendimento terceirizados que fará a interação com áreas de suporte necessárias.', '', 59),
(11712, 'anexo', 262, 11702, 2, '4.3', 'O fluxo de apresentação do projeto de instalação do GAC está estabelecido no Anexo 2 deste Capítulo.', '', 60),
(11713, 'anexo', 262, NULL, 1, '5', 'FORMALIZAÇÃO', '', 61),
(11714, 'anexo', 262, 11713, 2, '5.1', 'A formalização da autorização para instalação e operação do GAC ocorrerá por meio de Termo Aditivo.', '', 62),
(11715, 'anexo', 262, 11713, 2, '5.2', 'O início da operação do GAC poderá ocorrer a partir da assinatura do Termo Aditivo.', '', 63),
(11716, 'anexo', 262, NULL, 1, '6', 'VIGÊNCIA DO TERMO ADITIVO', '', 64),
(11717, 'anexo', 262, 11716, 2, '6.1', 'A vigência do Termo Aditivo será até 12 (doze) meses.', '', 65),
(11718, 'anexo', 262, 11716, 2, '6.2', 'Poderá ser extinguida a vigência do Termo Aditivo, de imediato e sem necessária anuência prévia da pessoa jurídica contratada, quando:', 'a) houver a instauração de processo administrativo de apuração de irregularidade disposta da Tabela 6 do Anexo 4, relativa a ação ocorrida no GAC;\nb) iniciado processo administrativo de apuração de deslocamento da área acessória ou dos equipamentos e periféricos habilitados para postagem para endereço distinto do autorizado para seu funcionamento, sem comunicação e autorização prévia;\nc) houver decisão judicial ou demanda de órgão de controle externo ou de polícia, correlacionada à paralisação temporária ou definitiva da área acessória.', 66),
(11719, 'anexo', 262, NULL, 1, '7', 'PRORROGAÇÃO DA AUTORIZAÇÃO DE OPERAÇÃO DO GAC', '', 67),
(11720, 'anexo', 262, 11719, 2, '7.1', 'A prorrogação da vigência da autorização para operacionalizar o GAC, poderá ocorrer uma única vez pelo período de 12 (doze) meses, estando condicionada:', 'a) a manutenção do interesse público;\nb) a comprovação da impossibilidade de instalar o canal de atendimento definitivo na localidade e o cenário inicial de demanda persista;', 68),
(11721, 'anexo', 262, 11720, 4, 'c', 'a inexistência de registro de suspensão temporária de participar de licitação e impedimento de contratar com os Correios e/ou Administração Pública, em que seja parte a pessoa jurídica contratada (matriz/filial), seus sócios e/ou representantes legais;', '', 69),
(11722, 'anexo', 262, 11720, 4, 'd', 'a anuência formal da pessoa jurídica contratada;', '', 70),
(11723, 'anexo', 262, 11720, 4, 'e', 'a inexistência de situações de vedação dispostas no item 4 do Anexo 2 deste Capitulo, envolvendo a Agência Centralizadora;', '', 71),
(11724, 'anexo', 262, 11720, 4, 'f', 'a manifestação formal do(a) Superintendente Estadual embasada em Relatório Técnico consubstanciado.', '', 72),
(11725, 'anexo', 262, 11719, 2, '7.2', 'Os procedimentos para a prorrogação da autorização de operação do GAC deverão ser iniciados pelo órgão regional dos canais de atendimento terceirizados com no mínimo 3 (três) meses de antecedência do encerramento da vigência do termo aditivo.', '', 73),
(11726, 'anexo', 262, 11719, 2, '7.3', 'O órgão regional de gestão dos canais de atendimento terceirizados deverá interagir com a pessoa jurídica contratada e orientá-la a manifestar-se formalmente, no prazo de 5 (cinco) dias úteis a partir do recebimento da consulta, sobre interesse de prorrogar a vigência da autorização para operação do GAC.', '', 74);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(11727, 'anexo', 262, 11719, 2, '7.4', 'Havendo manifestação contraria à prorrogação da vigência pela pessoa jurídica contratada, deverão ser observadas as providências para viabilizar a desmobilização do GAC, nos termos previstos no Anexo 2 deste Capítulo.', '', 75),
(11728, 'anexo', 262, 11719, 2, '7.5', 'A prorrogação deverá ser realizada por meio de Termo Aditivo, com prévia avaliação e chancela da área jurídica regional.', '', 76),
(11729, 'anexo', 262, 11719, 2, '7.6', 'A prorrogação da vigência do GAC é uma decisão bilateral, não sendo obrigatória para quaisquer das partes, não gerando multas ou ônus, caso não seja formalizada.', '', 77),
(11730, 'anexo', 262, NULL, 1, '8', 'ENCERRAMENTO DAS ATIVIDADES', '', 78),
(11731, 'anexo', 262, 11730, 2, '8.1', 'O órgão regional de gestão dos canais de atendimento terceirizados deverá notificar formalmente a pessoa jurídica contratada, com antecedência mínima de 60 (sessenta) dias, sobre a extinção Termo Aditivo de autorização de instalação e operação do GAC.', '', 79),
(11732, 'anexo', 262, 11730, 2, '8.2', 'A extinção do Termo Aditivo de autorização para instalação e operação do GAC, ocorrerá quando houver:', 'a) a rescisão ou fim da vigência do instrumento contratual do canal de atendimento terceirizado;\nb) o advento final do Termo Aditivo e não ocorrer a prorrogação;\nc) o retorno das atividades de forma plena da unidade substituída temporariamente;\nd) a adequação da(s) estrutura(s) instalada(s) de(as) unidade(s) de atendimento localizados no município, de forma que a quantidade de guichês/pontos de atendimento, calculado nos termos da legislação/normativo vigente seja alcançado;\ne) indicação da necessidade de redução do número de canais de atendimento no município, em fase de estudos de estruturação/reorganização da rede de atendimento;\nf) mudança de endereço do GAC sem autorização prévia dos Correios;\ng) verificação de atendimento a clientes de contrato, sem autorização prévia dos Correios.', 80),
(11733, 'anexo', 262, 11730, 2, '8.3', 'Identificada a ocorrência das alíneas “f” e “g” do subitem 8.2, ensejará a suspensão imediata do atendimento do GAC, enquanto estiver sendo apurada a possível ocorrência de descumprimento contratual e o fechamento definitivo se os indícios forem comprovados.', '* * * * *', 81),
(11734, 'anexo', 263, NULL, 1, '1', 'ORIENTAÇÕES ESPECÍFICAS APLICÁVEIS A GUICHÊ AVANÇADO DE ATENDIMENTO SAZONAL - GAS', '', 0),
(11735, 'anexo', 263, 11734, 2, '1.1', 'A instalação de área acessória - Guichê Avançado de Atendimento Sazonal - GAS é aplicável nas oportunidades em que:', 'a) for ocorrer no município evento/feira de grandes dimensões - onde seja verificada a probabilidade de prospecção de novos negócios;\nb) houver desenvolvimento de serviços especiais ou demanda governamental, que contemple pelo menos uma das seguintes características:\nI - amplo público alvo, fazendo-se necessário alcançar o maior quantitativo populacional no menor tempo;\nII - pequeno interstício temporal para prestação, onde a melhor estratégia e oferecer a maior pulverização de pontos de atendimento, para viabilizar o cumprimento da meta de atendimento à população;\nIII - impossibilidade da(s) agência(s) própria(s) instalada(s) na localidade realizar(em) a execução operacional de serviço governamentais ou especiais na totalidade ou parcialmente;\nIV - inviabilidade de investimento de recursos ou exiguidade temporal para instalação, com meios próprios, de estrutura (física e/ou recursos humanos) exclusiva para prestação dos serviços governamentais ou especiais.', 1),
(11736, 'anexo', 263, 11734, 2, '1.2', 'Não será autorizada a instalação de GAS, quando a feira-evento estiver vinculado com a divulgação de itens/produtos que não guardem similaridade e sinergia com a atividade postal ou que promovam/estimulem práticas incompatíveis com a prestação do serviço público.', '', 2),
(11737, 'anexo', 263, 11736, 3, '1.2.1', 'Será considerado sazonal:', 'a) a feira e/ou evento, que ocorre a cada intervalo temporal (semestral, anual, bianual etc.) que descaracterize perenidade/continuidade e que tenha duração igual ou inferior a 30 (trinta) dias consecutivos;\nb) prestação de serviços especiais e/ou atendimento a demandas governamentais o prazo de vigência será estabelecido no Termo Aditivo, consoante as diretrizes estabelecidas pelo formatador do serviço:\nI - os serviços especiais e/ou demandas governamentais estão relacionados ao interesse público;\nII - prazo de execução não superior a 90 (noventa) dias, podendo ser prorrogada uma única vez, por até igual período.\nNota: os Correios sempre terão prioridade para participar de feira e/ou evento com estrutura própria, podendo a seu critério exclusivo convidar ou autorizar pessoa jurídica contratada para participar.', 3),
(11738, 'anexo', 263, 11734, 2, '1.3', 'Não há vedação para que mais de uma pessoa jurídica contratada participe da mesma feira e/ou evento simultaneamente ou alternadamente. Entretanto, cada uma deve:', '', 4),
(11739, 'anexo', 263, 11738, 4, 'a', 'ter seu espaço individual;', '', 5),
(11740, 'anexo', 263, 11738, 4, 'b', 'atuar com os profissionais da equipe da agência centralizadora.', '', 6),
(11741, 'anexo', 263, 11734, 2, '1.4', 'A pessoa jurídica contratada por iniciativa própria pode solicitar participação na feira evento, pedido que será avaliado, consoante as regras deste Capítulo e seus Anexos.', '', 7),
(11742, 'anexo', 263, 11734, 2, '1.5', 'Modalidade de Atendimento', '', 8),
(11743, 'anexo', 263, 11742, 3, '1.5.1', 'No GAS pode ocorrer atendimentos nas seguintes modalidades:', 'a) à vista - varejo;\nb) a faturar - no local onde estiver instalado, a fim de atender ao público foco do evento, ou dos serviços especiais e das demandas governamentais.', 9),
(11744, 'anexo', 263, 11742, 3, '1.5.2', 'A definição da caracterização do serviço como especial ou de demanda governamental ocorrerá corporativamente quando do apostilamento.', '', 10),
(11745, 'anexo', 263, NULL, 1, '2', 'PROCEDIMENTOS DOS CORREIOS - INSTALAÇÃO DO GAS', '', 11),
(11746, 'anexo', 263, 11745, 2, '2.1', 'Iniciar processo administrativo para instalação de área acessória - guichê avançado de atendimento sazonal.', '', 12),
(11747, 'anexo', 263, 11745, 2, '2.2', 'O órgão regional de gestão dos canais de atendimento terceirizado deverá elaborar relatório técnico para submissão ao Superintendente Estadual, com vistas a receber orientações sobre quais providências a serem adotadas para atender a demanda de atendimento sazonal.', '', 13),
(11748, 'anexo', 263, 11745, 2, '2.3', 'Realizar o chamamento amplo, por meio de carta circular, encaminhada a todas as unidades contratadas que atentam os requisitos exigíveis, instaladas no município, fazendo constar na correspondência:', '', 14),
(11749, 'anexo', 263, 11748, 4, 'a', 'período de realização da feira-evento;', '', 15),
(11750, 'anexo', 263, 11748, 4, 'b', 'endereço de realização do evento;', '', 16),
(11751, 'anexo', 263, 11748, 4, 'c', 'estrutura a ser instalada, quando obrigatória;', '', 17),
(11752, 'anexo', 263, 11748, 4, 'd', 'que, obrigatoriamente, devem obrigatoriamente ser lançados na solução de atendimento as informações de comercialização de produtos e serviços, no mesmo dia em que ocorreram;', '', 18),
(11753, 'anexo', 263, 11748, 4, 'e', 'que não há distinção, no que diz respeito ao processo de prestação de contas, entre os produtos e serviços comercializados do GAS ou na agência centralizadora.', '', 19),
(11754, 'anexo', 263, 11745, 2, '2.4', 'Processar e analisar as respostas enviadas pelas unidades interessadas.', '', 20),
(11755, 'anexo', 263, 11754, 3, '2.4.1', 'Informar aos formatadores do serviço ou as entidades organizadoras do evento/feira caso não haja agências interessadas e arquivar o processo.', '', 21),
(11756, 'anexo', 263, 11754, 3, '2.4.2', 'Selecionar a(s) unidade(s) interessada(s), segundo os critérios do Anexo 2 deste Capítulo.', '2.4.2.1 Comunicar às pessoas jurídicas contratadas participantes do chamamento, qual(is) foi(foram) a(s) unidade(s) selecionada(s).\n2.4.2.2 Solicitar à(s) agências(s) selecionada(s) o preenchimento do Formulário de Solicitação de Instalação de área acessória.', 22),
(11757, 'anexo', 263, 11745, 2, '2.5', 'Acompanhar a instalação da área acessória, observando os regramentos internos, o disposto no instrumento contratual e as orientações fornecidas pelo(s) formatador do serviço quando se tratar de serviços especiais ou demandas governamentais.', '', 23),
(11758, 'anexo', 263, 11745, 2, '2.6', 'Realizar a formalização do termo de autorização para viabilizar a instalação do GAS, em data anterior ao início das operações da área acessória.', '', 24),
(11759, 'anexo', 263, NULL, 1, '3', 'PROCEDIMENTOS INICIATIVA DA PESSOA JURÍDICA CONTRATADA - INSTALAÇÃO DO GAS', '', 25),
(11760, 'anexo', 263, 11759, 2, '3.1', 'A pessoa jurídica contratada poderá solicitar sua participação de feira/evento.', '', 26),
(11761, 'anexo', 263, 11759, 2, '3.2', 'O órgão regional de gestão dos canais de atendimento terceirizados ao receber a solicitação para instalação de GAS deverá:', 'a) verificar se os Correios já se comprometeram com a organização do evento/feira em participar com estrutura própria;\nb) analisar a viabilidade de os Correios participarem com recursos próprios, considerando a necessidade de investimento, os prazos para instalação e desinstalação e os recursos (materiais e humanos) necessários;\nc) analisar o potencial de captação de negócios e a vantajosidade não de coparticipação de pessoa jurídica contratada no evento/feira;\nd) se a unidade proponente está instalada no mesmo município onde ocorrerá a feira/evento;\ne) verificar a existência de vedação para a autorização da participação da pessoa jurídica contratada, nos termos no Anexo 2 deste Capítulo.', 27),
(11762, 'anexo', 263, 11761, 3, '3.2.1', 'Finalizadas as análises, o órgão regional de gestão dos canais de atendimento terceirizados deverá:', 'a) elaborar relatório técnico com o parecer da área;\nb)  submeter o relatório ao (à) Superintendente Estadual para conhecimento e tomada de decisão quanto ao pleito da pessoa jurídica contratada.', 28),
(11763, 'anexo', 263, 11759, 2, '3.3', 'O(A) Superintendente Estadual deverá analisar os fatos acostados ao relatório técnico e tomar decisão quanto ao deferimento ou deferimento da solicitação da pessoa jurídica contrata.', '', 29),
(11764, 'anexo', 263, 11759, 2, '3.4', 'O órgão regional de gestão dos canais de atendimento terceirizado deverá notificar à pessoa jurídica contratada sobre a tomada de decisão do Superintendente Estadual, em até 2 (dois) dias úteis.', '', 30),
(11765, 'anexo', 263, 11764, 3, '3.4.1', 'O órgão regional de gestão dos canais de atendimento terceirizados, nas oportunidades em que houver o pleito for:', '', 31),
(11766, 'anexo', 263, 11765, 4, 'a', 'deferimento -  deverá acompanhar a instalação do GAS;', '', 32),
(11767, 'anexo', 263, 11765, 4, 'b', 'indeferimento - deverá arquivar o processo, e quando for o caso adotar as providências necessárias para instalar o GAS com estrutura própria ou para realizar o chamamento amplo.', '', 33),
(11768, 'anexo', 263, NULL, 1, '4', 'ALVARÁ DE FUNCIONAMENTO', '', 34),
(11769, 'anexo', 263, 11768, 2, '4.1', 'Não será exigida a obtenção de alvará de funcionamento para GAS, considerando que o próprio organizador da feira/evento providencia a documentação de autorização de funcionamento junto aos órgãos competentes.', '', 35),
(11770, 'anexo', 263, 11769, 3, '4.1.1', 'Excetua-se ao disposto no subitem 4.1 quando o órgão público municipal correlato determine de forma diversa.', '', 36),
(11771, 'anexo', 263, 11768, 2, '4.2', 'Independentemente, da exigência ou não de alvará de funcionamento, registre-se que cabe a pessoa jurídica contratada, obrigatoriamente e exclusivamente, certificar-se que o imóvel garante a segurança e a integridade física das pessoas, dos equipamentos e dos insumos/materiais disponibilizados para a execução do serviço.', '', 37),
(11772, 'anexo', 263, NULL, 1, '5', 'ESPECIFICIDADES DE ÁREA ACESSÓRIA - GUICHÊ AVANÇADO DE ATENDIMENTO SAZONAL', '', 38),
(11773, 'anexo', 263, 11772, 2, '5.1', 'Não haverá limitação para o quantitativo desse tipo de área acessória, a ser instalada simultaneamente.', '', 39),
(11774, 'anexo', 263, 11772, 2, '5.2', 'Será permitida a instalação em cada GAS do quantitativo de guichês/pontos de atendimento acordado entre os Correios e a pessoa jurídica contatada.', '', 40),
(11775, 'anexo', 263, 11772, 2, '5.3', 'Nas situações de evento/feira com duração inferior a 15 (quinze) dias, a(s) AGF(s) poderá(ão) realizar as operações de forma manual e, posteriormente, lançá-las no Sistema de Automação da Rede de Atendimento - SARA, ou outro que vier a substituí-lo, da agência centralizadora.', '', 41),
(11776, 'anexo', 263, 11775, 3, '5.3.1', 'Excetua-se ao disposto no subitem anterior, os serviços cuja contabilização ou preenchimento dos formulários específicos tenham de ser realizados no momento do atendimento.', '', 42),
(11777, 'anexo', 263, 11775, 3, '5.3.2', 'A opção por trabalhar manualmente não desobriga a AGF de registrar no sistema de automação de atendimento as vendas de produtos e o registro das informações de captação dos serviços, no mesmo dia da realização da operação, bem como de realizar o encaminhamento dos objetos postais que forem captados antes do horário limite de aceitação de postagem no dia, Depois do Horário - DH.', '', 43),
(11778, 'anexo', 263, 11775, 3, '5.3.3', 'Os objetos captados após o horário do DH devem ser registrados no sistema de automação de atendimento no mesmo dia de sua captação e serem encaminhados aos Centros de Tratamento, conforme os prazos estabelecidos na norma vigente.', '', 44),
(11779, 'anexo', 263, 11772, 2, '5.4', 'Nas situações em que a instalação do GAS estiver correlacionada ao desenvolvimento de serviços especiais ou demanda governamental, o formatador do serviço poderá estabelecer critérios específicos para instalação desse tipo de área acessória, por exemplo:', '', 45),
(11780, 'anexo', 263, 11779, 4, 'a', 'instalação de estrutura diferenciada;', '', 46),
(11781, 'anexo', 263, 11779, 4, 'b', 'atendimento em horário diferenciado;', '', 47),
(11782, 'anexo', 263, 11779, 4, 'c', 'interstício temporal para atendimento.', '', 48),
(11783, 'anexo', 263, NULL, 1, '6', 'LOCALIZAÇÃO', '', 49),
(11784, 'anexo', 263, 11783, 2, '6.1', 'Só será autorizada a instalação de GAS no mesmo município onde está instalada a agência centralizadora.', '', 50),
(11785, 'anexo', 263, 11783, 2, '6.2', 'Não existindo no município canais de atendimento terceirizados interessados e/ou aptos a instalarem GAS para prestação de serviços especiais ou demanda governamental na localidade pretendida, o órgão corporativo de gestão dos canais de atendimento terceirizado, poderá, excepcionalmente, autorizar, por tempo determinado, a instalação do GAS em município da circunvizinhança, dentro da Região de Atendimento.', '', 51),
(11786, 'anexo', 263, NULL, 1, '7', 'CRITÉRIOS DE DESEMPATE', '', 52),
(11787, 'anexo', 263, 11786, 2, '7.1', 'Havendo mais de uma agência interessada e o evento não comportar a participação de todas elas, o critério de desempate é o de maior proximidade geográfica da pretendente ao local onde será realizado o evento, considerando:', '', 53),
(11788, 'anexo', 263, 11787, 4, 'a', 'o critério de proximidade geográfica em percurso, por vias públicas, entre o endereço da agência e o local onde se pretende instalar o GAS;', '', 54),
(11789, 'anexo', 263, 11787, 4, 'b', 'ao percurso calculado não se aplica uma linha reta imaginária, aplica-se o percurso real por vias públicas;', '', 55),
(11790, 'anexo', 263, 11787, 4, 'c', 'independentemente da proximidade geográfica, é vedado a autorização à agência para instalação de GAS em outro município diverso daquele onde está instalada.', '', 56),
(11791, 'anexo', 263, 11787, 3, '7.1.1', 'Havendo empate no critério de proximidade, será considerado para desempate a seguinte ordem:', '', 57),
(11792, 'anexo', 263, 11791, 4, 'a', 'a menor pontuação no histórico de irregularidades, nos 6 (seis) meses anteriores; e', '', 58),
(11793, 'anexo', 263, 11791, 4, 'b', 'a unidade que não tenha outro GAS já instalado.', '', 59),
(11794, 'anexo', 263, 11786, 2, '7.2', 'O órgão regional de gestão dos canais de atendimento terceirizado deverá comunicar às pessoas jurídicas contratadas o resultado da seleção.', '', 60),
(11795, 'anexo', 263, NULL, 1, '8', 'VIGÊNCIA DO TERMO DE AUTORIZAÇÃO', '', 61),
(11796, 'anexo', 263, 11795, 2, '8.1', 'A vigência final do termo de autorização será o último dia programado para o evento ou feira da qual a pessoa jurídica contratada esteja participando ou a data prevista para final da execução do serviço especial ou demanda governamental.', '', 62),
(11797, 'anexo', 263, NULL, 1, '9', 'PRORROGAÇÃO DA AUTORIZAÇÃO DE OPERAÇÃO DO GAC', '', 63),
(11798, 'anexo', 263, 11797, 2, '9.1', 'Poderá haver prorrogação do Termo de Autorização quando:', '', 64),
(11799, 'anexo', 263, 11798, 4, 'a', 'houver a postergação do evento/feira além da data inicialmente programada;', '', 65),
(11800, 'anexo', 263, 11798, 4, 'b', 'o formatador do serviço, em nome do cliente, solicitar a ampliação da disponibilização do serviço especial ou demanda governamental além da data inicialmente contratada;', '', 66),
(11801, 'anexo', 263, 11798, 4, 'c', 'a unidade não esteja enquadrada nas situações de vedação dispostas no Anexo 2 deste Capítulo.', 'Nota: a prorrogação do Temo de Autorização está relacionado a vigência do Contrato de Franquia Postal, devendo estar limitada a 15 (quinze) dias do advento do termo final do instrumento contratual.', 67),
(11802, 'anexo', 263, NULL, 1, '10', 'ENCERRAMENTO DAS ATIVIDADES', '', 68),
(11803, 'anexo', 263, 11802, 2, '10.1', 'A extinção do termo de autorização para instalação e operação do GAS, ocorrerá quando houver:', 'a) a rescisão ou fim da vigência do instrumento contratual do canal de atendimento terceirizado;\nb) o advento final do Termo de Autorização e não ocorrer a prorrogação;\nc) o adiamento ou a desistência de realizar a feira/evento pela organização;\nd) mudança de endereço do GAS sem autorização prévia dos Correios;\ne) verificação de atendimento a clientes fora das instalações da feira/evento, sem autorização prévia dos Correios.', 69),
(11804, 'anexo', 263, 11802, 2, '10.2', 'As obrigações adstritas à vigência do termo de autorização se esgotarão de pleno quando da desinstalação da Área Acessória pela pessoa jurídica contratada, exceto no que tange as obrigações financeira e/ou quitação de valores indenizatórios para os quais a agência terceirizada tenha dado causa enquanto o documento estava em vigor.', '* * * * *', 70),
(11805, 'anexo', 265, NULL, 1, '1', 'Equipamento backup é aquele adquirido pela Franqueada para substituir computador onde originalmente esteja instalado o sistema SARA_AGF para manutenção/conserto.', '', 0),
(11806, 'anexo', 265, NULL, 1, '2', 'Taxa para vistoria de adequação de equipamentos as configurações estabelecidas nos Guias e Especificações Técnicas e para instalação do SARA_AGF em equipamentos adicionais autorizados pelos Correios.', 'TAXAS DE VISTORIA VERIFICAÇÃO DE CONFIGURAÇÃO E INSTALAÇÃO DE SISTEMAS EM EQUIPAMENTOS ADICIONAIS AUTORIZADOS PELOS CORREIOS\nVistoria de configuração e adequação aos Guias e Especificações Técnicas, pelos Correios, em equipamentos adicionais da AGF.	520 PCC (*)\nInstalação de Sistema de Atendimento autorizado pelos Correios em equipamentos adicionais na AGF (por equipamento adicional).	100 PCC (*)\n(*) PPC – Primeiro Porte da Carta', 1),
(11807, 'anexo', 265, NULL, 1, '3', 'Quantitativos limites de equipamentos backups que podem ser autorizados pelos Correios para aquisição e utilização em AGF:', 'Quantidade de guichês com o SARA_AGF 	Quantidade de equipamentos backup que poderão ser permitidos\n1 a 6	1\n7 a 12	2\n13 a 18	3\nA partir de 19	4', 2),
(11808, 'anexo', 265, NULL, 1, '4', 'Guias e Especificações Técnicas dos Correios são as orientações disponibilizadas pelos Correios para as Franqueadas de forma a direcionar, entre outras coisas a aquisição de equipamentos e periféricos de informática, nos quais irão ter instalados o sistema SARA_AGF.', '', 3),
(11809, 'anexo', 265, NULL, 1, '5', 'O preenchimento da planilha de controle de liberação de equipamentos backup é obrigatória e deve ser atualizada todas as vezes em que o computador for utilizado ou substituído.', '* * * * *', 4),
(11810, 'anexo', 267, NULL, 1, '1', 'PREMISSAS PARA LIBERAÇÃO', '', 0),
(11811, 'anexo', 267, 11810, 2, '1.1', 'A solicitação de ajuste no quantitativo de guichês de expedição é opcional.', '', 1),
(11812, 'anexo', 267, 11810, 2, '1.2', 'A instalação de guichê de expedição adicional ocorrerá mediante pagamento de taxas.', '', 2),
(11813, 'anexo', 267, 11810, 2, '1.3', 'O requisitante deverá comprovar o pagamento das seguintes taxas:', 'Função da taxa	Valores em PPC*\nVistoria técnica - nas situações onde não há necessidade de alteração de leiaute	520\nInstalação do SARA nos equipamentos adicionais - por equipamento	100\n*PPC - Primeiro Porte da Carta', 3),
(11814, 'anexo', 267, 11810, 2, '1.4', 'Os equipamentos nos quais serão instalados o Sara_Expedição devem contemplar as configurações contidas nos guias e as especificações técnicas do edital de licitação.', '', 4),
(11815, 'anexo', 267, 11810, 2, '1.5', 'A franqueada é responsável por todos os investimentos, custos operacionais e administrativos decorrentes dos procedimentos referentes à alteração de leiaute para instalação do Guichê de Expedição Adicional, aquisição de equipamentos etc.', '', 5),
(11816, 'anexo', 267, 11810, 2, '1.6', 'A instalação do guichê de expedição adicional gerará, para a AGF, a obrigatoriedade da leitura dos objetos qualificados um a um.', '', 6),
(11817, 'anexo', 267, 11810, 2, '1.7', 'O(s) guichê(s) de expedição adicional(is) poderá(ao) ser utilizado(s) unicamente para as atividades que estão autorizadas para o mesmo, quais sejam:', '', 7),
(11818, 'anexo', 267, 11817, 4, 'a', 'expedição de objetos postais;', '', 8),
(11819, 'anexo', 267, 11817, 4, 'b', 'digitação de telegramas;', '', 9),
(11820, 'anexo', 267, 11817, 4, 'c', 'utilização de recursos/acesso a informações disponibilizados em site ou página dos Correios, tais como: Tabelas de Preços, SCPP (Sistema de Cálculo de Preços e Prazos de Entrega), Helpdesk, SIGA, WebPedido.', 'NOTA: é vedada a transferência do guichê de expedição da AGF, de instalação obrigatória na unidade, para área acessória sob gestão da agência.', 10),
(11821, 'anexo', 267, 11810, 2, '1.8', 'A utilização indevida/não autorizada do guichê de expedição adicional, pela AGF, será considerada descumprimento do Contrato de Franquia Postal, cuja comprovação, acarretará o acréscimo de 50 (cinquenta) pontos no histórico da unidade e aplicação de sanções, quando cabível.', '', 11),
(11822, 'anexo', 267, 11810, 2, '1.9', 'A AGF não poderá estar enquadrada em nenhuma das vedações abaixo:', '', 12),
(11823, 'anexo', 267, 11822, 4, 'a', 'processo administrativo, em andamento, para apuração de irregularidade prevista no Anexo 4 do CFP, que poderá gerar rescisão do Contrato de Franquia Postal (CFP);', '', 13),
(11824, 'anexo', 267, 11822, 4, 'b', 'histórico de irregularidades que representam mais de 70% da pontuação máxima prevista no Anexo 4 do Contrato de Franquia Postal (CFP), nos últimos 6 (seis) meses;', '', 14),
(11825, 'anexo', 267, 11822, 4, 'c', 'débito não negociado ou inadimplemento de obrigações financeiras perante os Correios;', '', 15),
(11826, 'anexo', 267, 11822, 4, 'd', 'registro de desinstalação de guichê de expedição adicional, devido à utilização indevida do equipamento, nos 6 (seis) meses anteriores ao pedido de instalação.', '', 16),
(11827, 'anexo', 267, 11810, 2, '1.10', 'As autorizações fundamentadas no volume de expedição deverão ser reavaliadas, ao final do primeiro trimestre de cada ano, com base nos dados do ano anterior, a fim de verificar se permanece a necessidade da manutenção do guichê de expedição adicional.', '', 17),
(11828, 'anexo', 267, 11810, 2, '1.11', 'O ajuste do quantitativo de guichês de expedição, ampliação ou redução, será realizado por meio de apostilamento, devendo sua realização ser anotada em planilha específica para viabilizar o controle da concessão e do uso.', '', 18),
(11829, 'anexo', 267, 11810, 2, '1.12', 'Não será necessária a elaboração do projeto de alteração de leiaute para análise da engenharia, quando:', '', 19),
(11830, 'anexo', 267, 11829, 4, 'a', 'da instalação de 1 (um) guichê de expedição adicional, no imóvel principal, ou em área acessória contígua;', '', 20),
(11831, 'anexo', 267, 11829, 4, 'b', 'a AGF estiver atuando no regime de migração antecipada. Neste caso, os projetos de Implantação da unidade deverão ser alterados e analisados considerando o quantitativo total dos guichês de expedição, incluindo os adicionais.', '', 21),
(11832, 'anexo', 267, 11810, 2, '1.13', 'Havendo necessidade de alteração do projeto de instalação da AGF, deverão ser observadas as diretrizes do edital de licitação, com relação à qualificação do profissional que elaborará e executará o projeto de alteração de leiaute, bem como do fluxo de avaliação e vistoria do projeto e o pagamento das taxas correlatas.', '', 22),
(11833, 'anexo', 267, 11810, 2, '1.14', 'Como será realizada a análise:', '', 23),
(11834, 'anexo', 267, 11833, 4, 'a', 'a realização da análise da solicitação de ajuste no quantitativo de guichês de expedição só ocorrerá quando a AGF não estiver enquadrada nas vedações.', '', 24),
(11835, 'anexo', 267, 11833, 4, 'b', 'poderá ser autorizada a instalação de guichê de expedição adicional de forma automática, quando a unidade:', '', 25),
(11836, 'anexo', 267, 11833, 4, 'c', 'operar com até 2 (dois) guichês de atendimento e ainda não dispuser de guichê de Expedição;', '', 26),
(11837, 'anexo', 267, 11833, 4, 'd', 'operar com área acessória não contígua (andar diferente daquele onde são realizadas as postagens) ou em outra edificação/imóvel distinto.', '', 27),
(11838, 'anexo', 267, 11833, 4, 'e', 'quando a unidade já dispuser de guichê de expedição, deverá ser verificada a média diária de objetos qualificados (com obrigatoriedade de expedição), a qual será comparada à tabela de concessão de guichê de expedição, conforme a seguir:', '', 28),
(11839, 'anexo', 267, 11833, 4, 'f', 'o coeficiente de produtividade esperada é de 1.036 (um mil e trinta e seis) objetos dia;', '', 29),
(11840, 'anexo', 267, 11833, 4, 'g', 'será considerado para o cálculo da média o período de 3 (três) meses anteriores à solicitação, com a possibilidade de incluir a projeção de crescimento de postagens dos clientes atuais e/ou o acréscimo de novos clientes, no trimestre seguinte a solicitação.', '', 30),
(11841, 'anexo', 267, NULL, 1, '2', 'TABELA DA BASE DE CÁLCULO', '2.1 Tabela de concessão de guichês de expedição.\nObjetos Expedidos por Dia	Nº Guichês que podem ser autorizados\nDe	Até\n0	1036	1\n1037	2072	2\n2073	3108	3\n3109	4144	4\n4145	5180	5\nA partir de 5181	6\n* * * * *', 31),
(11842, 'anexo', 269, NULL, 1, '1', 'INSTRUÇÕES PARA O PROCESSO DE RESCISÃO CONTRATUAL', '', 0),
(11843, 'anexo', 269, 11842, 2, '1.1', 'A instrução e demais procedimentos relativos ao processo administrativo de rescisão contratual deverá observar, obrigatoriamente, o disposto na Cláusula Décima Sétima - da Extinção da Franquia e no Anexo 4 - Quadro de Ocorrência de Descumprimento Contratual do Contrato de Franquia Postal - CFP.', '', 1),
(11844, 'anexo', 269, 11842, 2, '1.2', 'O processo administrativo deverá ser iniciado no Sistema Eletrônico de Informações - SEI, ou outro que vier a substituí-lo, nas situações descritas a seguir:', '', 2),
(11845, 'anexo', 269, 11844, 4, 'a', 'rescisão unilateral:', 'I - verificado que a contabilização no histórico de pontuação de irregularidades (operacionais ou de gestão ou financeiras) atingiu 200 (duzentos) pontos; ou\nII - finalizado o processo administrativo que comprovar o cometimento de ocorrência de descumprimento contratual relativo a Tabela 6 - Irregularidades que ensejam rescisão unilateral do Anexo 4 do Contrato de Franquia Postal; ou\nIII - seja definido judicialmente.', 3),
(11846, 'anexo', 269, 11844, 4, 'b', 'rescisão de forma amigável, quando houver solicitação por qualquer das partes, Correios ou Franqueada, para promover o encerramento da execução contratual, em data anterior ao prazo final de vigência descrito no Contrato de Franquia Postal; e', '', 4),
(11847, 'anexo', 269, 11844, 4, 'c', 'rescisão decorrente de solicitação voluntária da Franqueada, com o objetivo de encerrar a prestação das atividades postais.', '', 5),
(11848, 'anexo', 269, NULL, 1, '2', 'TRAMITAÇÃO DO PROCESSO ADMINISTRATIVO', '', 6),
(11849, 'anexo', 269, 11848, 2, '2.1', 'incidirá na continuidade do processo administrativo, visando a rescisão do Contrato de Franquia Postal, a ausência de manifestação ou atraso nos prazos de encaminhamento de documentação definidos no CFP e neste capítulo, por parte da Franqueada nas situações a seguir:', '', 7),
(11850, 'anexo', 269, 11849, 4, 'a', 'manifestação, após ter sido recusado, pelos Correios, o pedido de rescisão amigável e proposição para  a modalidade de rescisão decorrente de solicitação voluntária da Franqueada;', '', 8),
(11851, 'anexo', 269, 11849, 4, 'b', 'defesa, após o recebimento de notificação formal do início do processo de rescisão unilateral do contrato;', '', 9),
(11852, 'anexo', 269, 11849, 4, 'c', 'pedido de reconsideração da decisão do Superintendente Estadual de Operações pela rescisão contratual; e', '', 10),
(11853, 'anexo', 269, 11849, 4, 'd', 'recurso administrativo ao Correios Sede, sobre a decisão do Superintendente Estadual de Operações pela rescisão contratual.', '', 11),
(11854, 'anexo', 269, 11848, 2, '2.2', 'No interstício temporal entre o recebimento do pedido de reconsideração ou do recurso administrativo pela autoridade competente e a emissão da sua decisão será aplicado efeito suspensivo ao processo de rescisão contratual.', '', 12),
(11855, 'anexo', 269, 11848, 2, '2.3', 'Os prazos dispostos nesse documento, quando não definidos literalmente que sua contagem é realizada em dias úteis, serão contados em dias corridos.', '', 13),
(11856, 'anexo', 269, 11848, 2, '2.4', 'A área jurídica não compõe, obrigatoriamente, o fluxo procedimental do processo administrativo de rescisão contratual, devendo ser acionada pelo órgão regional de gestão de canais de atendimento terceirizados e/ou Superintendente Estadual de Operações, somente para sanar dúvidas relativas ao correto cumprimento das fases obrigatórias e, garantir a segurança da análise do conteúdo documental acostado ao processo.', '', 14),
(11857, 'anexo', 269, NULL, 1, '3', 'METODOLOGIAS DE COMUNICAÇÃO', '3.1	Durante a tramitação do processo de rescisão do CFP, a comunicação poderá ser realizada conforme a seguir:', 15),
(11858, 'anexo', 269, 11857, 4, 'a', 'preferencialmente, por comunicação eletrônica gerada no Sistema Eletrônico de Informações - SEI, ou por outro que vier a substituí-lo;', '', 16),
(11859, 'anexo', 269, 11857, 4, 'b', 'por carta com aviso de recebimento ou telegrama com pedido de confirmação de entrega, a fim de registrar a data de cientificação da unidade;', '', 17),
(11860, 'anexo', 269, 11857, 4, 'c', 'em mãos na unidade Franqueada, com recibo em 2ª via; ou', '', 18),
(11861, 'anexo', 269, 11857, 4, 'd', 'por comunicação eletrônica nos moldes dispostos no Contrato de Franquia Postal.', '', 19),
(11862, 'anexo', 269, NULL, 3, '3.1.1', 'Nos casos de comunicação realizada pelos meios descritos nas alíneas “b”, “c” ou “d”, a cópia do documento devidamente assinado pelo representante legal da AGF e do respectivo recibo deverá ser digitalizado e anexado ao processo no SEI.', '', 20),
(11863, 'anexo', 269, NULL, 3, '3.1.2', 'Nos casos de comunicação digital ou física encaminhada por meio de Sistema Eletrônico de Informações - SEI, será considerada como recebida pela Franqueada a partir de sua manifestação confirmando o recebimento ou após 72 (setenta e duas) horas do horário do seu envio, o que ocorrer primeiro.', '', 21),
(11864, 'anexo', 269, 11857, 2, '3.2', 'A Franqueada deverá utilizar os mesmos meios de comunicação que o órgão regional de gestão de canais de atendimento terceirizados durante a tramitação do processo administrativo.', '', 22),
(11865, 'anexo', 269, 11864, 3, '3.2.1', 'O cadastramento da Franqueada para acesso ao Sistema Eletrônico de Informações - SEI, quando não houver sido realizado anteriormente, deverá ocorrer conforme orientações presentes no endereço eletrônico: http://www.correios.com.br/sobre-os-correios/sei-protocolo-eletronico, sendo as eventuais dúvidas sanadas pelo órgão regional de gestão dos canais de atendimento terceirizados, junto ao gestor do sistema e posteriormente, prestadas orientações à Franqueada.', '', 23),
(11866, 'anexo', 269, 11857, 2, '3.3', 'É indispensável que a cada etapa do processo administrativo o órgão regional de gestão dos canais de atendimento terceirizados comunique formalmente à Franqueada sobre:', '', 24),
(11867, 'anexo', 269, 11866, 4, 'a', 'a abertura do processo administrativo e a respectiva motivação;', '', 25),
(11868, 'anexo', 269, 11866, 4, 'b', 'a tomada de decisão relativa à etapa finalizada;', '', 26),
(11869, 'anexo', 269, 11866, 4, 'c', 'a próxima etapa do processo (defesa, contraditório, pedido de reconsideração, recurso administrativo etc.);', '', 27),
(11870, 'anexo', 269, 11866, 4, 'd', 'o prazo e a forma para apresentação de documentação pela AGF; e', '', 28),
(11871, 'anexo', 269, 11866, 4, 'e', 'a ação que será adotada se não houver apresentação de documentação pela AGF no prazo e forma definidos na alínea “d” acima.', '', 29),
(11872, 'anexo', 269, NULL, 1, '4', 'CONTEÚDO DO RELATÓRIO TÉCNICO OU DA NOTA TÉCNICA', '', 30),
(11873, 'anexo', 269, 11872, 2, '4.1', 'O órgão regional de gestão dos canais de atendimento terceirizados iniciará processo administrativo no Sistema Eletrônico de Informações - SEI e emitirá Relatório Técnico ou Nota Técnica relativa ao processo de rescisão contratual, que deverá conter no mínimo os seguintes elementos:', '', 31),
(11874, 'anexo', 269, 11873, 4, 'a', 'Referência Documental: listar os documentos e/ou processos correlacionados, que ensejaram a necessidade de instruir o processo de rescisão do Contrato de Franquia Postal;', 'NOTA: anexar os documentos referenciados, conforme descrito na alínea “a” ao processo administrativo em ordem cronológica e com os respectivos nomes.', 32),
(11875, 'anexo', 269, 11873, 4, 'b', 'motivação: dispor o motivo da instrução do processo de rescisão do Contrato de Franquia Postal;', '', 33),
(11876, 'anexo', 269, 11873, 4, 'c', 'contextualização: descrever de forma sucinta as situações e datas das notificações emitidas pelo órgão regional de gestão dos canais de atendimento terceirizados e o embasamento contratual de cada uma delas, conforme a seguir:', 'I - as argumentações e os documentos apresentados pela Franqueada;\nII - a motivação para não acatamento (falta de documentos comprobatórios, defesa apresentada após a data estabelecida; ausência de defesa etc.); e\nIII - data e quantitativo de pontos contabilizados no histórico de pontuação de irregularidades.', 34),
(11877, 'anexo', 269, 11873, 4, 'd', 'impactos com o fechamento da unidade: descrever as consequências da rescisão contratual, quais sejam:', 'I - o quantitativo populacional do município;\nII - a relação dos canais de atendimento próprios e/ou terceirizados instalados na circunvizinhança à região de atendimento, bem como as distâncias entre os canais e a Unidade Franqueada a ser fechada;\nIII - os principais concorrentes presentes na região de atendimento em que está localizada a unidade foco do processo de rescisão;\nIV - o resultado, por período não inferior a 6 (seis) meses, relativos à captação de receita, indicadores de desempenho, existência de multas ou notificações de órgãos competentes por tempo de espera na fila, bem como resultado do receita/despesa (R/D) das unidades de atendimento próprias relacionadas no inciso “II” desta alínea “d”; e\nV - a relação dos clientes que são atendidos pela unidade foco do processo de rescisão.', 35),
(11878, 'anexo', 269, 11873, 4, 'e', 'conclusão: apresentar a conclusão final sobre a rescisão contratual, conforme a seguir:', 'I - explanar de forma concisa sobre todos os elementos que se relacionam aos fatos registrados no Relatório Técnico/Nota Técnica, a fim de que seja possível determinar a existência de motivação para a rescisão contratual; e\nII - descrever o posicionamento do órgão regional de gestão dos canais de atendimento terceirizados, de forma a auxiliar o Superintendente Estadual de Operações quanto a aplicação da penalidade de rescisão contratual.', 36),
(11879, 'anexo', 269, 11873, 4, 'f', 'encaminhamento: encaminhar o processo ao Superintendente Estadual de Operações para conhecimento, análise dos fatos e aprovação ou não sobre a decisão de rescisão contratual; e', '', 37),
(11880, 'anexo', 269, 11873, 4, 'g', 'assinaturas: o Relatório Técnico ou Nota Técnica deverá ser assinado pelo gestor do órgão regional de gestão dos canais de atendimento terceirizados e pelo Gerente da Região de Atendimento e Vendas - REATE, à qual a Agência Franqueada está vinculada.', '4.2 O Superintendente Estadual de Operações poderá dispor a motivação relativa ao deferimento ou indeferimento foco do processo administrativo de rescisão contratual, conforme a seguir:\na)	inserir no próprio relatório técnico ou a nota técnica, devendo conter textualmente a motivação para homologação e autorização, ou não, da rescisão contratual; ou\nb)	emitir um parecer em documento apartado, devendo conter textualmente as análises e disposições, bem como a motivação para homologação e autorização, ou não, da rescisão contratual.', 38),
(11881, 'anexo', 269, NULL, 1, '5', 'DÉBITOS EXISTENTES', '', 39),
(11882, 'anexo', 269, 11881, 2, '5.1', 'Os Termos de Reconhecimento e Parcelamento de Débito - TRPD serão rescindidos como consequência do distrato contratual.', '', 40),
(11883, 'anexo', 269, 11881, 2, '5.2', 'Os valores das parcelas vencidas ou vincendas relativas à TRPD, inadimplementos financeiros, ou débitos originados na operacionalização do contrato deverão ser foco de compensação com os créditos da Franqueada.', '', 41),
(11884, 'anexo', 269, 11883, 3, '5.2.1', 'Inexistindo créditos ou sendo os créditos insuficientes para a quitação dos débitos de que trata o subitem 5.2 deste Anexo, deverá ser comunicado à Franqueada sobre a concessão de prazo de até 10 (dez) dias úteis, contados da data do recebimento da correspondência para a realização das seguintes ações:', '', 42),
(11885, 'anexo', 269, 11884, 4, 'a', 'quitação do montante total do débito pendente, nos termos orientados pela área financeira e encaminhamento do comprovante de pagamento, ao endereço eletrônico, digital ou físico fornecido pelos Correios; ou', '', 43),
(11886, 'anexo', 269, 11884, 4, 'b', 'assinatura de Termo de Reconhecimento de Dívida, o qual será emitido mediante a apresentação de garantia ou garantia real que seja no mínimo igual ou superior ao montante total do débito pendente acrescido da atualização monetária e juros.', '', 44),
(11887, 'anexo', 269, 11883, 3, '5.2.2', 'Não havendo a quitação até o prazo acordado ou não sendo celebrado termo específico deverão ser adotadas providências administrativas e/ou judiciais necessárias para quitação total dos débitos existentes.', '', 45),
(11888, 'anexo', 269, NULL, 1, '6', 'PARCELAMENTO DE DÉBITOS - COBRANÇA JUDICIAL', '6.1 Os parcelamentos de débitos relativos ao Contrato de Franquia Postal, que tenham sido celebrados judicialmente serão mantidos, respeitando o regramento disposto no processo específico.', 46),
(11889, 'anexo', 269, 11888, 2, '6.2', 'Aos parcelamento de débitos em trâmite na justiça, nos termos do Art. 2 da Lei nº 9.469/97, que não tenham sido finalizados, quando possível, devem ser incluídos os valores de que tratam o subitem 5.2.2, deste Anexo.', '* * * * *', 47),
(11890, 'anexo', 270, NULL, 1, '1', 'INFORMAÇÕES DO SUBPROCESSO', '', 0),
(11891, 'anexo', 270, 11890, 2, '1.1', 'As instruções e demais procedimentos relativos ao Processo Administrativo de Rescisão Contratual por solicitação voluntária da AGF, deverá observar, obrigatoriamente, o disposto nos seguintes documentos:', 'a) cláusula décima sétima - da Extinção da Franquia e no Anexo 2 - Tabela de Valores e Taxas, do Contrato de Franquia Postal - CFP;\nb) orientações gerais para o processo de rescisão do Contrato de Franquia Postal, descritas no Anexo 2 do presente Capítulo.', 1),
(11892, 'anexo', 270, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 2),
(11893, 'anexo', 270, 11892, 2, '2.1', 'Procedimentos da Pessoa Jurídica detentora do Contrato de Franquia Postal (AGF)', '', 3),
(11894, 'anexo', 270, 11893, 3, '2.1.1', 'Encaminhar ao órgão regional de gestão dos canais de atendimento terceirizados, com no mínimo 90 (noventa) dias de antecedência, comunicação formal solicitando a instauração de processo administrativo, com vistas à rescisão voluntária do Contrato de Franquia Postal, considerando os seguintes aspectos:', '', 4),
(11895, 'anexo', 270, 11894, 4, 'a', 'nos casos de comunicação eletrônica deverá, obrigatoriamente, constar a assinatura do representante legal da Franqueada, validada por meio de certificação digital, para que os documentos eletrônicos possam ser apensados ao Processo Administrativo;', '', 5),
(11896, 'anexo', 270, 11894, 4, 'b', 'quando ocorrer pelo Sistema Eletrônico de Informações - SEI, seguir rigorosamente as orientações emitidas pelos Correios, disponíveis no endereço: http://www.correios.com.br/sobre-os-correios/sei-protocolo-eletronico, de forma a evitar represamento ou atrasos na comunicação;', '', 6),
(11897, 'anexo', 270, 11894, 4, 'c', 'quando ocorrer via postal - atentar-se às disposições do instrumento jurídico constitutivo da Pessoa Jurídica, quanto à representação legal da empresa para oposição da(s) assinatura(s), de forma a mitigar o risco de recusa do documento por irregularidade quanto a representação.', '', 7),
(11898, 'anexo', 270, 11893, 3, '2.1.2', 'Receber comunicação do órgão regional de gestão dos canais de atendimento terceirizados com o resultado da análise referente à manifestação.', '', 8),
(11899, 'anexo', 270, 11893, 3, '2.1.3', 'Encaminhar pedido de reconsideração sobre a decisão ao Superintendente Estadual de Operações, quando a decisão for pelo indeferimento da manifestação pela rescisão voluntária do Contrato de Franquia Postal.', '2.1.3.1 Acostar documentação complementar àquela anteriormente anexada ao processo, de modo a viabilizar a análise do pedido de reconsideração pelo Superintendente Estatual de Operações.\nNOTA: no interstício temporal entre o recebimento do Pedido de Reconsideração ou do Recurso Administrativo pela autoridade competente e a emissão da sua decisão será aplicado efeito suspensivo ao processo.', 9),
(11900, 'anexo', 270, 11893, 3, '2.1.4', 'Receber, da Superintendência Estadual de Operações, comunicação formal sobre a decisão relativa ao pedido de reconsideração de que trata o item 2.1.3 deste Capítulo.', '', 10),
(11901, 'anexo', 270, 11893, 3, '2.1.5', 'Preparar Recurso Administrativo, em até 10 (dez) dias úteis, caso julgue pertinente, havendo indeferimento do pedido de reconsideração da decisão pela rescisão contratual por solicitação voluntária.', '2.1.5.1 Encaminhar o Recurso Administrativo ao Correios Sede, por meio do Superintendente Estadual de Operações.', 11),
(11902, 'anexo', 270, 11893, 3, '2.1.6', 'Receber comunicação formal do Correios Sede, em relação à decisão pelo indeferimento ou deferimento do recurso administrativo relativo à rescisão do Contrato de Franquia Postal por solicitação voluntária da AGF.', 'NOTA 1: havendo deferimento do pedido de reconsideração ou do recurso administrativo, o processo administrativo de rescisão do Contrato de Franquia Postal por solicitação voluntária da AGF, será arquivado após os trâmites de fechamento da unidade. Contudo, o processo poderá ser reaberto, a qualquer tempo, se comprovada a utilização de documentação ilícita.\nNOTA 2: em caso de indeferimento do recurso administrativo, arquivar o processo administrativo.\n2.1.6.1 Observar e atender, em caso de deferimento do recurso administrativo para a rescisão voluntária, todas as orientações repassadas pelo órgão regional de gestão dos canais de atendimento terceirizados e/ou equipe técnica de fechamento para encerramento das atividades da AGF.', 12),
(11903, 'anexo', 270, 11893, 3, '2.1.7', 'Providenciar o pagamento da indenização devida aos Correios, prevista no Anexo 2 do Contrato de Franquia Postal, com a previsão de redução de 10% do valor, por cada ano completo de execução contratual.', '', 13),
(11904, 'anexo', 270, 11893, 3, '2.1.8', 'Afixar o aviso de encerramento das atividades da AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), quando houver, conforme modelo Anexo 8 deste Capítulo, em local de fácil visualização por parte dos clientes, com no mínimo 10 (dez) dias de antecedência da data prevista para o fechamento.', '', 14),
(11905, 'anexo', 270, 11893, 3, '2.1.9', 'Informar, sobre o encerramento das atividades da AGF, aos clientes de Caixa Postal, conforme modelo disposto no Anexo 7 deste Capítulo, bem como aos clientes de entrega interna e atendidos por contrato, com no mínimo 10 (dez) dias de antecedência da data prevista para o fechamento da unidade.', '', 15),
(11906, 'anexo', 270, 11893, 3, '2.1.10', 'Receber a equipe técnica de fechamento da AGF na data marcada para o encerramento das atividades da unidade.', '2.1.10.1 Providenciar o cumprimento das orientações recebidas pelo órgão regional de gestão dos canais de atendimento terceirizados e/ou da equipe técnica de fechamento da AGF quanto às providências a serem adotadas para viabilizar o encerramento das atividades da unidade.\n2.1.10.2 Acompanhar os procedimentos de encerramento das atividades da AGF e/ou área acessória, pela equipe técnica de fechamento da AGF.', 16),
(11907, 'anexo', 270, 11893, 3, '2.1.11', 'Emitir as notas fiscais de devolução de produtos, etiquetas e formulários geradores de receitas e outros documentos controlados, conforme as orientações emitidas pelos Correios, observando as instruções apresentadas nos Anexo 5 e 6 deste Capítulo.', '', 17),
(11908, 'anexo', 270, 11893, 3, '2.1.12', 'Assinar o Termo de Encerramento das Atividades da AGF e/ou área acessória, em conformidade com o Anexo 9 deste Capítulo.', '2.1.12.1 Ter ciência de que verificada a existência de itens avariados, ausentes ou inoperantes, por ventura cedidos, de forma onerosa ou não, pelos Correios, o valor relativo à sua substituição ou conserto será debitado na última prestação de contas, e quando não for possível, será cobrado a posteriori.', 18),
(11909, 'anexo', 270, 11893, 3, '2.1.13', 'Providenciar a descaracterização da AGF e, quando houver, das áreas acessórias, inclusive no que tange à comunicação visual, ou qualquer particularidade que remeta a marcas e patentes de propriedade dos Correios, conforme orientação recebida dos Correios sobre a matéria.', '', 19),
(11910, 'anexo', 270, 11892, 2, '2.2', 'Procedimentos do Órgão Regional de Gestão dos Canais de Atendimento Terceirizados', '', 20),
(11911, 'anexo', 270, 11910, 3, '2.2.1', 'Iniciar processo administrativo no Sistema Eletrônico de Informações - SEI, ou outro que vier a substituí-lo, observando o subitem 1.2 do Anexo 2 deste Capítulo.', '2.2.1.1 Observar na instrução e condução do processo administrativo de rescisão contratual as disposições presentes no Anexo 2 deste Capítulo.', 21),
(11912, 'anexo', 270, 11910, 3, '2.2.2', 'Elaborar relatório técnico ou nota técnica, em conformidade com o Anexo 2 deste Capítulo.', '', 22),
(11913, 'anexo', 270, 11910, 3, '2.2.3', 'Comunicar, formalmente, à Franqueada, mediante carta ou telegrama, sobre a abertura de processo administrativo com a finalidade de rescindir o instrumento contratual, devendo conter no aviso a motivação e as próximas fases do processo.', '', 23),
(11914, 'anexo', 270, 11910, 3, '2.2.4', 'Entregar a comunicação formal, à Franqueada, seguindo o regramento apresentado no subitem 3.1 do Anexo 2 deste Capítulo.', '', 24),
(11915, 'anexo', 270, 11910, 3, '2.2.5', 'Solicitar ao órgão de gestão financeira dos canais de atendimento terceirizados informação sobre a situação de adimplemento, ou não, das obrigações financeiras da AGF em relação aos Correios.', '2.2.5.1 Solicitar ao órgão de gestão financeira dos canais de atendimento terceirizados o cálculo do valor da indenização devida aos Correios, prevista no Anexo 2 do Contrato de Franquia Postal, com a previsão de redução de 10% do valor, por cada ano completo de execução contratual.\n2.2.5.2  Solicitar ao órgão de gestão financeira dos canais de atendimento terceirizados, a verificação da existência de Termo(s) de Reconhecimento e Parcelamento de Débitos - TRPD, quando houver, bem como faturas vencidas ou a vencer.', 25),
(11916, 'anexo', 270, 11910, 3, '2.2.6', 'Receber, do órgão de gestão financeira dos canais de atendimento terceirizados, a informação e orientações sobre os procedimentos relativos à situação financeira da AGF para realizar a rescisão do Contrato de Franquia Postal.', '', 26),
(11917, 'anexo', 270, 11910, 3, '2.2.7', 'Solicitar, caso necessário, apoio técnico da área jurídica para esclarecer dúvidas relacionadas ao Contrato/Edital de Licitação e/ou, outros assuntos de natureza jurídica.', 'NOTA: a área jurídica não compõe, obrigatoriamente, procedimento previsto neste Capítulo, devendo ser acionada somente para garantir a segurança da análise por parte do órgão regional de gestão de canais de atendimento terceirizados.', 27);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(11918, 'anexo', 270, 11910, 3, '2.2.8', 'Receber da Franqueada a manifestação/defesa, em caso de indeferimento do pedido voluntário de rescisão contratual, analisar e encaminhar relatório técnico consubstanciado ao Superintendente Estadual de Operações com solicitação de autorização para realizar as seguintes ações:', '', 28),
(11919, 'anexo', 270, 11918, 4, 'a', 'dar continuidade ao processo de rescisão contratual por solicitação voluntária, quando verificado existência de fatos e/ou documentos na manifestação que fundamentem a instauração do processo administrativo de rescisão contratual; e', '', 29),
(11920, 'anexo', 270, 11918, 4, 'b', 'finalizar e arquivar o processo, quando indeferida a rescisão por solicitação voluntária da pessoa jurídica detentora do Contrato de Franquia Postal (AGF).', 'NOTA: o interstício temporal para comunicar à Franqueada sobre o resultado da análise da manifestação é de até 10 (dez) dias úteis após o recebimento da documentação. Se o Superintendente Estadual de Operações necessitar de prazo maior, a AGF deverá ser informada.', 30),
(11921, 'anexo', 270, 11910, 3, '2.2.9', 'Receber o resultado da análise do Superintendente Estadual de Operações sobre o deferimento ou indeferimento da manifestação do pedido de reconsideração, conforme a seguir:', '', 31),
(11922, 'anexo', 270, 11921, 4, 'a', 'sendo acatado o pedido de reconsideração, dar continuidade ao processo de rescisão contratual por solicitação voluntária, conforme previsto no item 17.1.1, item I do Contrato de Franquia Postal; e', '', 32),
(11923, 'anexo', 270, 11921, 4, 'b', 'se houver indeferimento do pedido de reconsideração, encaminhar comunicação à Franqueada, constando as seguintes orientações:', 'I - informações sobre o prazo de até 10 (dez) dias úteis para apresentação de Recurso Administrativo ao Correios Sede, se houver novas informações e/ou documentos a serem incluídos no processo; e\nII - repercussões, no caso de não apresentação do recurso administrativo em tempo hábil.', 33),
(11924, 'anexo', 270, 11910, 3, '2.2.10', 'Receber o recurso administrativo da AGF, se houver, e encaminhá-lo ao Correios Sede, por intermédio do Superintendente Estadual de Operações.', '', 34),
(11925, 'anexo', 270, 11910, 3, '2.2.11', 'Receber e comunicar à Franqueada sobre a decisão do Correios Sede, em relação ao recurso administrativo.', '', 35),
(11926, 'anexo', 270, 11910, 3, '2.2.12', 'Fazer constar na carta encaminhada à Franqueada, se a decisão final do Correios Sede, for pelo deferimento do recurso, ou seja, anuir pela rescisão do Contrato de Franquia Postal, orientações sobre o pagamento da sanção pecuniária calculada pela área financeira.', 'NOTA: em caso de indeferimento do recurso administrativo pelo Correios Sede, finalizar e arquivar o processo administrativo.', 36),
(11927, 'anexo', 270, 11910, 3, '2.2.13', 'Informar, assim que for tomada decisão pelo fechamento da AGF, ao órgão de suprimento ao qual a unidade está subordinada, para suspender todos os pedidos de suprimento em andamento.', '', 37),
(11928, 'anexo', 270, 11910, 3, '2.2.14', 'Providenciar o distrato dos termos aditivos relativos à área acessória (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), quando houver.', '', 38),
(11929, 'anexo', 270, 11910, 3, '2.2.15', 'Verificar as condições dispostas no Contrato de Franquia Postal relativas à possibilidade de suspensão do direito de participar de licitação e do impedimento de contratar com os Correios e/ou a possibilidade de licitar e adotar as providências de execução dos procedimentos, quando cabível.', '', 39),
(11930, 'anexo', 270, 11910, 3, '2.2.16', 'Informar a área regional de vendas sobre a data prevista para encerramento das atividades na AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), com no mínimo 10 (dez) dias úteis de antecedência, para que haja tempo hábil de cientificar os clientes de contrato.', '', 40),
(11931, 'anexo', 270, 11910, 3, '2.2.17', 'Comunicar à(s) empresa(s) homologada(s) para fornecimento de máquina de franquear, com no mínimo 10 (dez) dias úteis de antecedência, sobre o encerramento das atividades, para que essa(s) adote(m) as providências necessárias quanto aos seguintes procedimentos:', '', 41),
(11932, 'anexo', 270, 11931, 4, 'a', 'finalizar negociações para locação ou fornecimento de máquina de franquear para a AGF;', '', 42),
(11933, 'anexo', 270, 11931, 4, 'b', 'encerrar o fornecimento de crédito para a máquina de franquear, concedendo valores no montante e frequência autorizados pelos Correios, até a data do encerramento das atividades da AGF;', '', 43),
(11934, 'anexo', 270, 11931, 4, 'c', 'interromper, em definitivo, o acesso da conexão da máquina de franquear com a Central de Carga Remota - CCR no dia posterior ao marcado para o encerramento das atividades; e', '', 44),
(11935, 'anexo', 270, 11931, 4, 'd', 'recolher o equipamento e/ou o mecanismo de tarifação, conforme disposições constantes no contrato celebrado entre a empresa homologada e a AGF.', 'NOTA: havendo alteração de data marcada para o encerramento das atividades da AGF ou arquivamento do processo de rescisão, o(s) fornecedor(es) homologado(s) deverá(ão) ser comunicado(s) de modo a mitigar a descontinuidade dos serviços postais.', 45),
(11936, 'anexo', 270, 11910, 3, '2.2.18', 'Interagir com o órgão regional de operações a fim de informar:', '', 46),
(11937, 'anexo', 270, 11936, 4, 'a', 'com no mínimo 10 (dez) dias úteis de antecedência, a data prevista para encerramento das atividades da AGF;', '', 47),
(11938, 'anexo', 270, 11936, 4, 'b', 'a definição, realizada de forma conjunta, da unidade de atendimento para qual será redirecionada a carga postal de entrega interna e caixa postal, considerando as regras vigentes, a estrutura instalada e a capacidade produtiva da unidade de destino dos objetos postais;', '', 48),
(11939, 'anexo', 270, 11936, 4, 'c', 'sobre a  exclusão da faixa de CEP da AGF e das áreas acessórias, da numeração do(s) Bloco(s) de Caixa(s) Postal(is), existente(s) no Diretório Nacional de Endereços - DNE e dos sistemas correlatos à coleta e ao encaminhamento de carga.', '', 49),
(11940, 'anexo', 270, 11910, 3, '2.2.19', 'Interagir com o órgão regional de operações, com a antecedência necessária, para viabilizar a retirada da(s) caixa(s) de coleta interna, bem como da(s) caixa(s) externa(s) afixada(s) na parede da unidade ou em frente à edificação, caso houver, na data marcada para o fechamento da unidade.', '2.2.19.1  Solicitar ao órgão regional de operações, a exclusão da faixa de CEP e das informações da AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal) no Diretório Nacional de Endereços - DNE.', 50),
(11941, 'anexo', 270, 11910, 3, '2.2.20', 'Solicitar ao órgão regional de gestão de patrimônio, com no mínimo 10 (dez) dias úteis de antecedência, o recolhimento de equipamentos e/ou mobiliário que sejam de propriedade dos Correios e que tenham sido cedidos pelos Correios, de forma onerosa ou não, para operacionalização da AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).', '2.2.20.1 Identificar no Termo de Encerramento das Atividades da AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), Anexo 9 deste Capítulo, a existência de itens cedidos com avaria ou que não estejam funcionando, os quais necessitarão de conserto ou substituição.\n2.2.20.2 Informar ao órgão de gestão financeira para que realize a cobrança relativa à substituição ou conserto do item cedido na prestação de contas final da AGF.', 51),
(11942, 'anexo', 270, 11910, 3, '2.2.21', 'Cientificar, com no mínimo 10 (dez) dias úteis de antecedência, os demais órgãos da estrutura dos Correios correlacionados à execução contratual das Agências de Correios Franqueadas para adoção das providências cabíveis no seu âmbito de atuação.', '', 52),
(11943, 'anexo', 270, 11910, 3, '2.2.22', 'Definir, por meio de portaria, os profissionais que irão compor a equipe técnica de fechamento da AGF, a qual deverá ser composta de profissionais que tenham conhecimento e habilidades para acompanhar as tratativas de finalização das atividades.', '2.2.22.1 Viabilizar junto aos órgãos regionais correlatos o suporte fundamental para o desempenho das atribuições da equipe técnica de fechamento da AGF, a exemplo de veículo (s) administrativo(s)/operacional(is), diárias, hospedagens, etc.\n2.2.22.2 Interagir com o órgão regional de tecnologia da informação para disponibilizar profissional para compor a equipe técnica de fechamento da AGF, quando não for possível fazê-lo por meio remoto, de modo que, encerrados os procedimentos, sejam desabilitados dos equipamentos da unidade, o sistema de automação do atendimento e outros disponibilizados pelos Correios.', 53),
(11944, 'anexo', 270, 11910, 3, '2.2.23', 'Receber comunicação da equipe técnica de fechamento da AGF sobre situações de impedimento de acesso à AGF e/ou área acessória, se houver.', '2.2.23.1 Consultar a área jurídica sobre as providências a serem adotadas e orientar a equipe técnica de fechamento da AGF.', 54),
(11945, 'anexo', 270, 11910, 3, '2.2.24', 'Solicitar ao órgão corporativo de gestão de cadastro de órgãos, conforme fluxo correspondente, a mudança de status da unidade no ERP de “2 - Criada e Instalada” para “3 - Fechada Temporariamente”. Após 90 (noventa) dias, vencidas todas as etapas e possíveis repercussões, solicitar a mudança para o status “4 - Fechada Definitivamente”.', '', 55),
(11946, 'anexo', 270, 11910, 3, '2.2.25', 'Providenciar publicação nos informativos estaduais e no Site de Informações e Gestão do Atendimento - SIGA, bem como solicitar a atualização no site dos Correios sobre o fechamento da AGF e/ou área acessória.', '', 56),
(11947, 'anexo', 270, 11910, 3, '2.2.26', 'Emitir o termo de distrato, convocando a Franqueada para a assinatura.', 'NOTA: Se o representante legal da Franqueada não comparecer, emitir carta (modelo apresentado no Anexo 10 deste Capítulo) comunicando a rescisão do contrato por solicitação voluntária da AGF.', 57),
(11948, 'anexo', 270, 11910, 3, '2.2.27', 'Providenciar a publicação resumida do termo de distrato ou da Carta no Diário Oficial da União - DOU, em até 5 (cinco) dias úteis do mês seguinte ao de sua assinatura, a qual a critério do órgão competente poderá ocorrer no prazo de até 20 (vinte) dias, conforme legislação pertinente.', '2.3	Procedimentos da Equipe Técnica de Fechamento da AGF\n2.3.1	Encaminhar à Franqueada uma comunicação, digital ou física, informando a data e o horário do comparecimento da equipe técnica de fechamento na AGF e/ou nas áreas acessória (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), assim como da necessidade de execução dos seguintes procedimentos:\na)	regularizar pendências do Sistema de Proteção de Receita - Proter;\nb)	realizar a quitação de faturas e/ou outras pendências financeiras;\nc)	realizar a conexão da máquina de franquear no dia anterior ao definido para o encerramento das atividades;\nd)	realizar a postagem e a expedição de todos os objetos captados no dia anterior ao definido para o fechamento;\ne)	providenciar o recolhimento de todas as etiquetas de registro e/ou insumos/materiais de consumo que tenham sido cedidos a clientes;\nf)	separar os produtos (caixas, envelopes, selos etc.) que estejam aptos para comercialização e separa-los em unidades de fornecimento, para viabilizar a conferência e a emissão de nota fiscal de devolução, com atenção aos aspectos a seguir:\nI - os produtos que não estejam fisicamente adequados para comercialização (molhado, rasgado, manchado etc.) devem ser baixados no sistema como vendidos, até a data anterior ao fechamento da AGF, a fim de serem excluídos do sistema; e\nII - os Correios não receberão, em devolução, os produtos cujas condições físicas inviabilizam sua comercialização em outras unidades.\ng)	providenciar retirada da comunicação visual interna e externa que contenham a marca e/ ou patente dos Correios, em até 30 (trinta) dias após o encerramento das atividades na unidade; e\nh)	estar presente na unidade o representante legal, procurador e/ou proprietário da unidade para acompanhar as atividades de encerramento da AGF.\n2.3.2	Encaminhar à agência, com antecedência mínima de 10 (dez) dias úteis, o aviso de informações aos clientes para afixação na AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), quando houver.\nNOTA: o cartaz deverá detalhar as informações à população sobre o fechamento da AGF e agências mais próximas, conforme modelo de aviso de encerramento das atividades da AGF, disponibilizado no Anexo 8 deste Capítulo.\n2.3.3	Comparecer à AGF na data e horário programados para realização das ações de fechamento.\nNOTA: Todos os profissionais deverão estar portando o crachá funcional para possibilitar a sua identificação.\n2.3.3.1	Lavrar boletim de ocorrência nas situações em que houver impedimento da entrada dos profissionais dos Correios na AGF e/ou área acessória, por representante legal ou empregado da Franqueada.\n2.3.3.2	Comunicar ao órgão regional de gestão dos canais de atendimento terceirizados, quando se configurar a situação disposta no subitem 2.3.3.1 deste Anexo ou se a unidade estiver fechada.\n2.3.3.3	Aguardar orientação do órgão regional de gestão dos canais de atendimento terceirizados sobre os procedimentos a serem adotados.\n2.3.4	Recolher os insumos/materiais de consumo que tenham sido fornecidos pelos Correios para operacionalização da AGF, conforme orientações descritas no Anexo 6 deste Capítulo.\n2.3.4.1	Direcionar os insumos/materiais de consumo recolhidos da AGF que não atinjam o quantitativo de unidades de fornecimento para agência própria dos Correios definida anteriormente pelo órgão regional de gestão dos canais de atendimento terceirizados dos Correios.\n2.3.5	Acompanhar a emissão do relatório de conexão da máquina de franquear, conforme orientações do MANCAT 13.\n2.3.6	Retirar e alijar a borracha de todos os carimbos de uso no serviço postal, relacionando a quantidade e a identificação.\nNOTA: preferencialmente, o alijamento deverá ocorrer na presença do representante legal da Franqueada.\n2.3.7	Orientar, conferir e acompanhar a emissão de nota fiscal de devolução pela Franqueada, conforme orientações constantes do Anexo 6 deste Capítulo, das etiquetas de código de barras físicas (etiquetas de registro), formulários geradores de receita e outros materiais com utilização controlada (comprovante etc.).\n2.3.8	Catalogar as etiquetas de registro e os formulários geradores de receita que constem em estoque no sistema e não estejam fisicamente na unidade, para análise e adoção de providências posteriores.\n2.3.8.1	Assinar e coletar a assinatura do representante legal da Franqueada ou do profissional designado por esta para acompanhar as atividades, nas páginas do catálogo dos insumos descritos no subitem 2.3.8 deste Anexo.\n2.3.9	Conferir os produtos comercializáveis a serem recolhidos e acompanhar:\na)	a emissão da nota fiscal de devolução pela Franqueada, respeitando as unidades de fornecimento de cada produto e demais orientações contempladas no Anexo 5 deste Capítulo;\nb)	o fechamento do objeto postal endereçado ao órgão de suprimento correlato por meio de PAC administrativo.\n2.3.10	Relacionar e recolher objetos postais que estejam sob guarda da unidade para entrega interna e/ou caixa postal, de modo a transferi-los à unidade mais próxima. A unidade que receber os objetos redirecionados deverá emitir novo aviso de chegada para cada objeto.\n2.3.11	Verificar a existência de objetos postais captados pela agência e:\na)	 identificar sua contabilização e o respectivo encaminhamento, solicitando ao responsável legal/proprietário/empregado da AGF que estiver acompanhando os procedimentos de encerramento que providencie a regularização dos objetos não contabilizados e não expedidos; e\nb)	solicitar coleta ao órgão regional de operações.\n2.3.12	Retirar todos os cartazes dos quadros de avisos existentes na unidade, descartando aqueles que estejam fora da vigência de exposição.\n2.3.13	Registrar todas as ações ocorridas, concluir o termo de encerramento das atividades da AGF e/ou área acessória, anexando toda a documentação.\n2.3.13.1	 Colher a assinatura da equipe técnica de fechamento da AGF bem como do responsável legal da AGF no termo de encerramento das atividades, conforme Anexo 9 deste Capítulo, rubricando as demais páginas do documento.\n2.3.13.2	Disponibilizar à Franqueada uma via do termo de encerramento das atividades da AGF, conforme Anexo 9 deste Capítulo.\n2.3.13.3	Inserir cópia do termo de encerramento das atividades da AGF e a documentação correspondente no processo de rescisão do Contrato de Franquia Postal disposto no sistema eletrônico de informações.', 58),
(11949, 'anexo', 270, 11892, 2, '2.4', 'Procedimentos do Superintendente Estadual de Operações', '', 59),
(11950, 'anexo', 270, 11949, 3, '2.4.1', 'Receber relatório técnico ou nota técnica emitida pelo órgão regional de gestão dos canais de atendimento terceirizados, constando a motivação para instauração do processo de rescisão do Contrato de Franquia Postal por solicitação voluntária.', '', 60),
(11951, 'anexo', 270, 11949, 3, '2.4.2', 'Analisar o relatório técnico/nota técnica e autorizar/homologar, ou não, os procedimentos para rescisão contratual na modalidade voluntária.', '', 61),
(11952, 'anexo', 270, 11949, 3, '2.4.3', 'Solicitar ao órgão regional de gestão dos canais de atendimento terceirizados, caso necessário, outros subsídios para viabilizar a análise.', '2.4.3.1 Formalizar a decisão sobre a rescisão contratual em até 10 (dez) dias úteis, contados da data do recebimento do processo administrativo.', 62),
(11953, 'anexo', 270, 11949, 3, '2.4.4', 'Receber o relatório técnico/nota técnica do órgão regional de gestão dos canais de atendimento terceirizados relativo à análise do pedido de reconsideração, se houver, bem como a documentação comprobatória encaminhado pela Franqueada objeto do processo de rescisão contratual na modalidade voluntária.', '2.4.4.1 Analisar a documentação correlata e emitir parecer de deferimento ou indeferimento relativo ao pedido de reconsideração emitido pela Franqueada.\n2.4.1.1 Comunicar ao órgão regional de gestão dos canais de atendimento terceirizados sobre o resultado da análise, e orientar para que cientifique à Franqueada.', 63),
(11954, 'anexo', 270, 11949, 3, '2.4.5', 'Receber, do órgão regional de gestão dos canais de atendimento terceirizados, recurso administrativo interposto pela Franqueada, se cabível.', '2.4.5.1 Encaminhar ao Correios Sede, para análise e emissão de parecer final o recurso administrativo contra a decisão de rescisão voluntária do Contrato de Franquia Postal emitido no âmbito estadual, sendo que:', 64),
(11955, 'anexo', 270, 11954, 4, 'a', 'o encaminhamento do processo ao Correios Sede, deve ser precedido da emissão de relatório técnico/nota técnica, o(a) qual deve contemplar parecer consubstanciado e conclusivo da Superintendência Estadual de Operações; e', '', 65),
(11956, 'anexo', 270, 11954, 4, 'b', 'o recurso administrativo impetrado pela Franqueada tem efeito suspensivo em relação aos procedimentos de rescisão do Contrato de Franquia Postal.', '', 66),
(11957, 'anexo', 270, 11949, 3, '2.4.6', 'Receber, do Correios Sede, a decisão final em relação ao processo de rescisão do Contrato de Franquia Postal por solicitação voluntária da Franqueada.', '2.4.1.2 Informar ao órgão regional de gestão dos canais de atendimento terceirizados sobre o posicionamento do Correios Sede, assim como em relação à continuidade dos procedimentos correlatos ao parecer recebido.', 67),
(11958, 'anexo', 270, 11949, 3, '2.4.2', 'Assinar o termo de distrato e/ou documento de formalização de rescisão contratual, quando aplicável.', '', 68),
(11959, 'anexo', 270, 11892, 2, '2.5', 'Procedimentos do Órgão de Gestão Financeira dos Canais de Atendimento Terceirizados', '', 69),
(11960, 'anexo', 270, 11959, 3, '2.5.1', 'Prestar apoio profissional quando solicitado pelo órgão regional de gestão dos canais de atendimento terceirizados, quanto à análise da situação financeira da AGF.', '', 70),
(11961, 'anexo', 270, 11959, 3, '2.5.2', 'Receber comunicação do órgão regional de gestão dos canais de atendimento terceirizados sobre a rescisão do Contrato de Franquia Postal por solicitação voluntária da Franqueada.', '', 71),
(11962, 'anexo', 270, 11959, 3, '2.5.3', 'Rescindir o(s) Termo(s) de Reconhecimento e Parcelamento de Débitos - TRPD, quando houver.', '', 72),
(11963, 'anexo', 270, 11959, 3, '2.5.4', 'Verificar a existência de faturas vencidas e/ou a vencer, de forma a viabilizar, quando cabível, sua quitação na última prestação de contas.', '', 73),
(11964, 'anexo', 270, 11959, 3, '2.5.5', 'Orientar o órgão regional de gestão dos canais de atendimento terceirizados e/ou a equipe técnica de fechamento da AGF quanto aos procedimentos financeiros de encerramento da agência.', '', 74),
(11965, 'anexo', 270, 11959, 3, '2.5.6', 'Receber, do órgão de suprimento, informações quanto ao recebimento dos produtos comercializáveis em devolução, conforme Anexo 5 deste Capítulo.', '2.5.6.1 Viabilizar o ressarcimento dos créditos relativos aos produtos devolvidos.', 75),
(11966, 'anexo', 270, 11959, 3, '2.5.7', 'Receber, do órgão regional de gestão dos canais de atendimento terceirizados, as informações sobre a necessidade de debitar na última prestação de contas, os valores relativos à substituição e/ou consertos de itens cedidos pelos Correios à Franqueada para operacionalização do objeto do Contrato de Franquia Postal.', '2.5.7.1 Providenciar a inclusão do débito de que trata o item 2.4.13 deste Anexo e efetuar a devida cobrança.\n2.5.7.2 Receber a solicitação de parcelamento de débito da pessoa jurídica detentora do Contrato de Franquia Postal (AGF), se houver, avaliando a possibilidade de parcelamento dos débitos por meio de cobrança administrativa, conforme Anexo 2 deste Capítulo.', 76),
(11967, 'anexo', 270, 11892, 2, '2.6', 'Procedimentos do Órgão Jurídico Regional', '', 77),
(11968, 'anexo', 270, 11967, 3, '2.6.1', 'Receber a solicitação de apoio técnico do órgão regional de gestão dos canais de atendimento terceirizados e/ou Superintendente Estadual de Operações.', '', 78),
(11969, 'anexo', 270, 11967, 3, '2.6.2', 'Prestar apoio jurídico quando solicitado pelo órgão regional de gestão dos canais de atendimento terceirizados e/ou Superintendente Estadual de Operações, quanto à análise dos documentos apresentados pela Franqueada, assim como do Contrato de Franquia Postal, edital de licitação e outros documentos necessários.', '', 79),
(11970, 'anexo', 270, 11967, 3, '2.6.3', 'Responder formalmente em até 5(cinco) dias úteis contados da data subsequente ao recebimento da consulta.', 'NOTA: poderá ser encaminhada resposta eletrônica com a assinatura do gestor ou do responsável pela área consultada.', 80),
(11971, 'anexo', 270, 11967, 3, '2.6.4', 'Receber solicitação de orientação quanto aos procedimentos a serem adotados pelo órgão regional de gestão dos canais de atendimento terceirizados quando:', '', 81),
(11972, 'anexo', 270, 11971, 4, 'a', 'houver impedimento de acesso da Equipe Técnica de Fechamento da AGF na unidade; e', '', 82),
(11973, 'anexo', 270, 11971, 4, 'b', 'a agência e/ou áreas acessórias estiverem fechadas e não houver nenhum responsável na unidade para receber a equipe técnica de fechamento da AGF.', '2.6.4.1 Orientar o órgão regional de gestão dos canais de atendimento terceirizados e/ou Superintendente Estadual de Operações, e adotar as providências jurídicas cabíveis.', 83),
(11974, 'anexo', 270, 11892, 2, '2.7', 'Procedimentos do Órgão Regional de Vendas', '', 84),
(11975, 'anexo', 270, 11974, 3, '2.7.1', 'Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF e/ou das áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).', '', 85),
(11976, 'anexo', 270, 11974, 3, '2.7.2', 'Informar aos clientes que utilizam o respectivo canal de atendimento sobre o iminente fechamento da Agência de Correios Franqueada foco do processo de rescisão contratual.', '', 86),
(11977, 'anexo', 270, 11974, 3, '2.7.3', 'Interagir com os clientes de perfil industrial para definir as unidades habilitadas para atendê-los.', '', 87),
(11978, 'anexo', 270, 11892, 2, '2.8', 'Procedimentos do Órgão de Suprimento', '', 88),
(11979, 'anexo', 270, 11978, 3, '2.8.1', 'Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF.', '', 89),
(11980, 'anexo', 270, 11978, 3, '2.8.2', 'Suspender os procedimentos de suprimento em andamento para a Franqueada.', '', 90),
(11981, 'anexo', 270, 11978, 3, '2.8.3', 'Providenciar o bloqueio dos usuários aos sistemas de suprimento.', '', 91),
(11982, 'anexo', 270, 11978, 3, '2.8.4', 'Orientar o órgão regional de gestão dos canais de atendimento terceirizados sobre os procedimentos para devolução e/ou descarte dos itens estocáveis que se encontrem na AGF e estejam aptos para uso ou comercialização por outras unidades.', 'NOTA: os produtos que não estejam fisicamente aptos para comercialização (molhado, rasgado, manchado etc.) devem ser baixados no sistema como vendidos, até a data anterior ao fechamento da AGF, a fim de serem excluídos do sistema.', 92),
(11983, 'anexo', 270, 11978, 3, '2.8.5', 'Receber, conferir os produtos devolvidos pela AGF e informar ao órgão de gestão financeira e ao órgão regional de gestão dos canais de atendimento terceirizados sobre o valor venal correspondente.', '', 93),
(11984, 'anexo', 270, 11978, 3, '2.8.6', 'Comunicar ao órgão regional de gestão dos canais de atendimento terceirizados e ao órgão de gestão financeira quanto ao recebimento dos itens devolvidos e a conclusão dos procedimentos internos.', '', 94),
(11985, 'anexo', 270, 11892, 2, '2.9', 'Procedimentos do Órgão Regional de Operações', '', 95),
(11986, 'anexo', 270, 11985, 3, '2.9.1', 'Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF e/ou das áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).', '', 96),
(11987, 'anexo', 270, 11985, 3, '2.9.2', 'Disponibilizar veículo de apoio à equipe técnica de fechamento da AGF, bem como para:', '', 97),
(11988, 'anexo', 270, 11987, 4, 'a', 'transferência de objetos postais destinados para entrega interna e/ou caixa postal, da AGF que será fechada para a(s) unidade(s) de atendimento pré-definida(s);', '', 98),
(11989, 'anexo', 270, 11987, 4, 'b', 'coleta de objetos postais captados pela AGF.', '', 99),
(11990, 'anexo', 270, 11985, 3, '2.9.3', 'Reorganizar a distribuição dos objetos de entrega interna e o fluxo de coleta a ser implantado na data posterior ao fechamento da unidade.', '', 100),
(11991, 'anexo', 270, 11985, 3, '2.9.4', 'Providenciar a exclusão da faixa de CEP e das informações da AGF e/ou das áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal) no Diretório Nacional de Endereços - DNE e demais sistemas corporativos de gestão de encaminhamento e coleta.', '', 101),
(11992, 'anexo', 270, 11892, 2, '2.10', 'Procedimentos do Órgão Regional de Gestão Patrimonial', '', 102),
(11993, 'anexo', 270, 11992, 3, '2.10.1', 'Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF e/ou das áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).', '', 103),
(11994, 'anexo', 270, 11992, 3, '2.10.2', 'Providenciar, quando cabível, na data marcada para o fechamento da unidade, o recolhimento dos equipamentos e/ou mobiliários, que tenham sido cedidos pelos Correios à AGF e/ou áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), para a operacionalização do objeto do Contrato de Franquia Postal.', '', 104),
(11995, 'anexo', 270, 11992, 3, '2.10.3', 'Verificar as condições de integridade estrutural e de funcionamento dos itens cedidos pelos Correios à Franqueada antes de seu recolhimento.', '2.10.3.1 Solicitar à Equipe Técnica de Fechamento da AGF que faça constar no termo de encerramento das atividades da unidade, conforme Anexo 9 deste Capítulo, as condições identificadas nos itens cedidos.', 105),
(11996, 'anexo', 270, 11892, 2, '2.11', 'Procedimentos do Correios Sede', '', 106),
(11997, 'anexo', 270, 11996, 3, '2.11.1', 'Receber o recurso administrativo da franqueada encaminhado por intermédio do Superintendente Estadual de Operações.', '2.11.1.1 Analisar o processo de rescisão do Contrato de Franquia Postal, por solicitação voluntária da AGF, no prazo de 10 (dez) dias úteis, contados da data de seu recebimento.\n2.11.1.2 Solicitar informações adicionais à Superintendência Estadual de Operações, quando pertinente.\n2.11.1.3 Informar à Superintendência Estadual de Operações quando houver a necessidade de prazo adicional para viabilizar a análise.', 107),
(11998, 'anexo', 270, 11996, 3, '2.11.2', 'Encaminhar a resposta à Superintendência Estadual de Operações relativa à análise de Recurso Administrativo.', '* * * * *', 108),
(11999, 'anexo', 271, NULL, 1, '1', 'INFORMAÇÕES DO SUBPROCESSO', '', 0),
(12000, 'anexo', 271, 11999, 2, '1.1', 'As instruções e demais procedimentos relativos ao processo administrativo de rescisão contratual de forma amigável, deverá observar, obrigatoriamente, o disposto nos seguintes documentos:', 'a) cláusula décima sétima - da extinção da franquia do Contrato de Franquia Postal; e\nb) orientações gerais para o processo de rescisão do Contrato de Franquia Postal, descritas no Anexo 2 do presente Capítulo.', 1),
(12001, 'anexo', 271, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 2),
(12002, 'anexo', 271, 12001, 2, '2.1', 'Procedimentos da Pessoa Jurídica detentora do Contrato de Franquia Postal (AGF)', '', 3),
(12003, 'anexo', 271, 12002, 3, '2.1.1', 'Receber, do órgão regional de gestão dos canais de atendimento terceirizados, notificação formal sobre a instauração de processo administrativo com vistas à rescisão do Contrato de Franquia Postal de forma amigável.', '', 4),
(12004, 'anexo', 271, 12002, 3, '2.1.2', 'Encaminhar no prazo de 10 (dez) dias úteis, contados do recebimento da notificação, manifestação favorável à rescisão amigável do Contrato de Franquia Postal.', '2.1.2.1	Utilizar os mesmos meios de comunicação, para interagir com o órgão regional de gestão de canais de atendimento terceirizados, conforme a seguir:', 5),
(12005, 'anexo', 271, 12004, 4, 'a', 'nos casos de comunicação eletrônica deverá, obrigatoriamente, constar a assinatura do representante legal da Franqueada, validada por meio de certificação digital, para que os documentos eletrônicos possam ser apensados ao processo administrativo;', '', 6),
(12006, 'anexo', 271, 12004, 4, 'b', 'quando ocorrer pelo Sistema Eletrônico de Informações - SEI, seguir rigorosamente as orientações emitidas pelos Correios, disponíveis no endereço http://www.correios.com.br/sobre-os-correios/sei-protocolo-eletronico, de forma a evitar represamento ou atrasos na comunicação; e', '', 7),
(12007, 'anexo', 271, 12004, 4, 'c', 'quando ocorrer via postal - atentar-se às disposições do instrumento jurídico constitutivo da pessoa jurídica, quanto à representação legal da empresa para aposição da(s) assinatura(s), de forma a mitigar o risco de recusa do documento por irregularidade.', '', 8),
(12008, 'anexo', 271, 12002, 3, '2.1.3', 'Encaminhar solicitação de parcelamento de débitos do Contrato de Franquia Postal por meio de cobrança administrativa ao órgão regional de gestão regional dos canais de atendimento terceirizados, se houver.', '', 9),
(12009, 'anexo', 271, 12001, 2, '2.2', 'Procedimentos do Órgão Regional de Gestão dos Canais de Atendimento Terceirizados', '', 10),
(12010, 'anexo', 271, 12009, 3, '2.2.1', 'Iniciar Processo Administrativo no Sistema Eletrônico de Informações - SEI, ou outro que vier a substituí-lo, observando o subitem 1.2 do Anexo 2 deste Capítulo.', '2.2.1.1 Observar na instrução e condução do processo administrativo de rescisão contratual as disposições presentes no Anexo 2 deste Capítulo.', 11),
(12011, 'anexo', 271, 12009, 3, '2.2.2', 'Elaborar relatório técnico ou nota técnica em conformidade com o Anexo 2 deste Capítulo.', '', 12),
(12012, 'anexo', 271, 12009, 3, '2.2.3', 'Comunicar formalmente à Franqueada mediante carta ou telegrama, sobre a abertura de processo administrativo com a finalidade de rescindir o instrumento contratual, devendo conter no aviso a motivação e as próximas fases do processo.', '', 13),
(12013, 'anexo', 271, 12009, 3, '2.2.4', 'Entregar a comunicação formal, à Franqueada, seguindo o regramento apresentado no subitem 3.1 do Anexo 2 deste Capítulo.', '', 14),
(12014, 'anexo', 271, 12009, 3, '2.2.5', 'Solicitar ao órgão de gestão financeira dos canais de atendimento terceirizados informação sobre a situação de adimplemento, ou não, das obrigações financeiras da AGF em relação aos Correios.', '2.2.5.1 Solicitar ao órgão de gestão financeira dos canais de atendimento terceirizados a verificação da existência de Termo(s) de Reconhecimento e Parcelamento de Débitos - TRPD, quando houver, bem como faturas vencidas ou a vencer.', 15),
(12015, 'anexo', 271, 12009, 3, '2.2.6', 'Receber, do órgão de gestão financeira dos canais de atendimento terceirizados, a informação e orientações sobre os procedimentos relativos à situação financeira da AGF para realizar a rescisão do Contrato de Franquia Postal.', '', 16),
(12016, 'anexo', 271, 12009, 3, '2.2.7', 'Solicitar, caso necessário, apoio técnico da área jurídica para esclarecer dúvidas relacionadas ao contrato/edital de licitação e/ou, outros assuntos de natureza jurídica.', 'NOTA: a área jurídica não compõe, obrigatoriamente, procedimento previsto neste capítulo, devendo ser acionada somente para garantir a segurança da análise por parte do órgão regional de gestão de canais de atendimento terceirizados.', 17),
(12017, 'anexo', 271, 12009, 3, '2.2.8', 'Receber, da Franqueada, a manifestação/defesa, analisar e encaminhar relatório técnico consubstanciado ao Superintendente Estadual de Operações com solicitação de autorização para realizar as seguintes ações:', '', 18),
(12018, 'anexo', 271, 12017, 4, 'a', 'dar continuidade ao processo de rescisão contratual de forma amigável, quando verificada manifestação favorável da pessoa jurídica detentora do Contrato de Franquia Postal (AGF) para rescisão contratual; e', '', 19),
(12019, 'anexo', 271, 12017, 4, 'b', 'finalizar e arquivar o processo, quando indeferida a rescisão amigável pela pessoa jurídica detentora do Contrato de Franquia Postal (AGF).', '', 20),
(12020, 'anexo', 271, 12009, 3, '2.2.9', 'Receber, da pessoa jurídica detentora do Contrato de Franquia Postal (AGF), o pedido de parcelamento de débitos, se houver, por meio de cobrança administrativa.', '2.2.9.1 Analisar a documentação apresentada e encaminhar parecer ao órgão de gestão financeira dos canais de atendimento terceirizados de modo a subsidiar a tomada de decisão do mesmo.', 21),
(12021, 'anexo', 271, 12009, 3, '2.2.10', 'Receber o resultado da análise efetuada pelo órgão de gestão financeira e comunicar à Franqueada sobre o deferimento ou indeferimento do pedido de parcelamento de débito do Contrato de Franquia Postal por meio de cobrança administrativa, conforme a seguir:', '', 22),
(12022, 'anexo', 271, 12021, 4, 'a', 'sendo acatado o pedido de parcelamento, dar continuidade ao processo de rescisão contratual de forma amigável, conforme previsto no item 17.1.1, item II do Contrato de Franquia Postal; e', '', 23),
(12023, 'anexo', 271, 12021, 4, 'b', 'se houver indeferimento do pedido de parcelamento, encaminhar comunicação à Franqueada.', '', 24),
(12024, 'anexo', 271, 12009, 3, '2.2.11', 'Informar, assim que for tomada decisão pelo fechamento da AGF, ao órgão de suprimento ao qual a unidade está subordinada para suspender todos os pedidos de suprimento em andamento.', '', 25),
(12025, 'anexo', 271, 12009, 3, '2.2.12', 'Providenciar o distrato dos termos aditivos relativos à área acessória (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), quando houver.', '', 26),
(12026, 'anexo', 271, 12009, 3, '2.2.13', 'Verificar as condições dispostas no Contrato de Franquia Postal relativas à possibilidade de suspensão do direito de participar de licitação e do impedimento de contratar com os Correios e/ou a possibilidade de licitar e adotar as providências de execução dos procedimentos, quando cabível.', '', 27),
(12027, 'anexo', 271, 12009, 3, '2.2.14', 'Informar a área regional de vendas sobre a data prevista para encerramento das atividades na AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), com no mínimo 10 (dez) dias úteis de antecedência, para que haja tempo hábil de cientificar os clientes de contrato.', '', 28),
(12028, 'anexo', 271, 12009, 3, '2.2.15', 'Comunicar à(s) empresa(s) homologada(s) para fornecimento de máquina de franquear, com no mínimo 10 (dez) dias úteis de antecedência, sobre o encerramento das atividades, para que essa(s) adote(m) as providências necessárias quanto aos seguintes procedimentos:', '', 29),
(12029, 'anexo', 271, 12028, 4, 'a', 'finalizar negociações para locação ou fornecimento de máquina de franquear para a AGF;', '', 30),
(12030, 'anexo', 271, 12028, 4, 'b', 'encerrar o fornecimento de crédito para a máquina de franquear, concedendo valores no montante e frequência autorizados pelos Correios, até a data do encerramento das atividades da AGF;', '', 31),
(12031, 'anexo', 271, 12028, 4, 'c', 'interromper em definitivo, o acesso da conexão da máquina de franquear com a Central de Carga Remota - CCR no dia posterior ao marcado para o encerramento das atividades; e', '', 32),
(12032, 'anexo', 271, 12028, 4, 'd', 'recolher o equipamento e/ou o mecanismo de tarifação, conforme disposições constantes no contrato celebrado entre a empresa homologada e a AGF.', 'NOTA: havendo alteração de data marcada para o encerramento das atividades da AGF ou arquivamento do processo de rescisão, o(s) fornecedor(es) homologado(s) deverá(ão) ser comunicado(s) de modo a mitigar a descontinuidade dos serviços postais.', 33),
(12033, 'anexo', 271, 12009, 3, '2.2.16', 'Interagir com o órgão regional de operações a fim de informar:', '', 34),
(12034, 'anexo', 271, 12033, 4, 'a', 'com no mínimo 10 (dez) dias úteis de antecedência, a data prevista para encerramento das atividades da AGF;', '', 35),
(12035, 'anexo', 271, 12033, 4, 'b', 'a definição, realizada de forma conjunta, da unidade de atendimento para qual será redirecionada a carga postal de entrega interna e caixa postal, considerando as regras vigentes, a estrutura instalada e a capacidade produtiva da unidade de destino dos objetos postais;', '', 36),
(12036, 'anexo', 271, 12033, 4, 'c', 'sobre a  exclusão da faixa de CEP da AGF e das áreas acessórias, da numeração do(s) bloco(s) de caixa(s) postal(is), existente(s) no Diretório Nacional de Endereços - DNE e dos sistemas correlatos à coleta e ao encaminhamento de carga.', '2.2.16.1 Interagir com o órgão competente na regional, com antecedência necessária, para viabilizar a retirada da(s) caixa(s) de coleta interna, bem como das caixas externas afixada(s) na parede da unidade ou em frente à edificação, caso houver, na data marcada para o fechamento da unidade.', 37),
(12037, 'anexo', 271, 12009, 3, '2.2.17', 'Solicitar ao órgão regional de gestão de patrimônio, com no mínimo 10 (dez) dias úteis de antecedência, o recolhimento de equipamentos e/ou mobiliário que sejam de propriedade dos Correios e que tenham sido cedidos pelos Correios, de forma onerosa ou não, para operacionalização da AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).', '', 38),
(12038, 'anexo', 271, 12009, 3, '2.2.18', 'Cientificar, com no mínimo 10 (dez) dias úteis de antecedência, os demais órgãos da estrutura dos Correios correlacionados à execução contratual das Agências de Correios Franqueadas, para adoção das providências cabíveis no seu âmbito de atuação.', '', 39),
(12039, 'anexo', 271, 12009, 3, '2.2.19', 'Definir, por meio de portaria, os profissionais que irão compor a equipe técnica de fechamento da AGF, a qual deverá ser composta de profissionais que tenham conhecimento e habilidades para acompanhar as tratativas de finalização das atividades.', '2.2.19.1 Viabilizar junto aos órgãos regionais correlatos o suporte fundamental para o desempenho das atribuições da equipe técnica de fechamento da AGF, a exemplo de veículo (s) administrativo(s)/operacional(is), diárias, hospedagens, etc.\n2.2.19.2 Interagir com o órgão regional de tecnologia da informação para disponibilizar profissional para compor a equipe técnica de fechamento da AGF, quando não for possível fazê-lo por meio remoto, de modo que, encerrados os procedimentos, sejam desabilitados dos equipamentos da unidade, o sistema de automação do atendimento e outros disponibilizados pelos Correios.', 40),
(12040, 'anexo', 271, 12009, 3, '2.2.20', 'Receber comunicação da equipe técnica de fechamento da AGF sobre situações de impedimento de acesso à AGF e/ou área acessória, se houver.', '', 41),
(12041, 'anexo', 271, 12009, 3, '2.2.21', 'Consultar a área jurídica sobre as providências a serem adotadas e orientar a equipe técnica de fechamento da AGF.', '2.2.21.1 Identificar no termo de encerramento das atividades da AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), Anexo 9 deste Capítulo, a existência de itens cedidos com avaria ou que não estejam funcionando, os quais necessitarão de conserto ou substituição.\n2.2.21.2 Informar ao órgão de gestão financeira para que realize a cobrança relativa à substituição ou conserto do item cedido na prestação de contas final da AGF.', 42),
(12042, 'anexo', 271, 12009, 3, '2.2.22', 'Elaborar e encaminhar ao Superintendente Estadual de Operações, para validação e assinatura, a solicitação de emissão de portaria de fechamento definitivo da AGF e/ou área acessória.', '', 43),
(12043, 'anexo', 271, 12009, 3, '2.2.23', 'Solicitar ao órgão corporativo de gestão de cadastro de órgãos, conforme fluxo correspondente, a mudança de status da unidade no ERP de “2 - Criada e Instalada” para “3 - Fechada Temporariamente”.', '2.2.23.1 Após 90 (noventa) dias, vencidas todas as etapas e possíveis repercussões, solicitar a mudança para o status “4 - Fechada Definitivamente”.', 44),
(12044, 'anexo', 271, 12009, 3, '2.2.24', 'Providenciar publicação nos informativos estaduais e no Site de Informações e Gestão do Atendimento - SIGA, bem como solicitar a atualização no site dos Correios sobre o fechamento da AGF e/ou área acessória.', '', 45),
(12045, 'anexo', 271, 12009, 3, '2.2.25', 'Emitir o termo de distrato, comunicando e informando à Franqueada para a assinatura.', '', 46);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(12046, 'anexo', 271, 12009, 3, '2.2.26', 'Providenciar a publicação resumida do termo de distrato ou da carta no Diário Oficial da União - DOU, em até 5 (cinco) dias úteis do mês seguinte ao de sua assinatura, a qual a critério do órgão competente poderá ocorrer no prazo de até 20 (vinte) dias, conforme legislação pertinente.', '2.3	Procedimentos da Equipe Técnica de Fechamento da AGF\n2.3.1	Encaminhar à Franqueada uma comunicação, digital ou física, informando a data e o horário do comparecimento da equipe técnica de fechamento na AGF e/ou nas áreas acessória (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), assim como da necessidade de execução dos seguintes procedimentos:\na)	regularizar pendências do Sistema de Proteção de Receita - Proter;\nb)	realizar a quitação de faturas e/ou outras pendências financeiras;\nc)	realizar a conexão da máquina de franquear no dia anterior ao definido para o encerramento das atividades;\nd)	realizar a postagem e a expedição de todos os objetos captados no dia anterior ao definido para o fechamento;\ne)	providenciar o recolhimento de todas as etiquetas de registro e/ou insumos/materiais de consumo que tenham sido cedidos a clientes;\nf)	separar os produtos (caixas, envelopes, selos etc.) que estejam adequados para comercialização e separa-los os mesmos em unidades de fornecimento, para viabilizar a conferência e a emissão de nota fiscal de devolução, com atenção aos aspectos a seguir:\nI - os produtos que não estejam fisicamente adequados para comercialização (molhado, rasgado, manchado etc.) devem ser baixados no sistema como vendidos, até a data anterior ao fechamento da AGF, a fim de serem excluídos do sistema; e\nII - os Correios não receberão, em devolução, os produtos cujas condições físicas inviabilizam sua comercialização em outras unidades.\ng)	providenciar retirada da comunicação visual interna e externa que contenham a marca e/ou patente dos Correios, em até 30 (trinta) dias após o encerramento das atividades na unidade; e\nh)	estar presente na unidade o representante legal, procurador e/ou o proprietário da unidade para acompanhar as atividades de encerramento da AGF.\n2.3.2	Encaminhar à agência, com antecedência mínima de 10 (dez) dias úteis, o aviso de informações aos clientes, para afixação na AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal), quando houver.\nNOTA: o cartaz deverá detalhar as informações à população sobre o fechamento da AGF e agências mais próximas, conforme modelo de aviso de encerramento das atividades da AGF, disponibilizado no Anexo 8 deste Capítulo.\n2.3.3	Comparecer à AGF na data e horário programados para realização das ações de fechamento.\nNOTA: todos os profissionais deverão estar portando o crachá funcional, para possibilitar a sua identificação.\n2.3.3.1	Lavrar Boletim de Ocorrência nas situações em que houver impedimento da entrada dos profissionais dos Correios na AGF e/ou área acessória, por representante legal ou empregado da Franqueada.\n2.3.3.2	Comunicar ao órgão regional de gestão dos canais de atendimento terceirizados, quando se configurar a situação disposta no subitem 2.3.3.1 deste Anexo ou se a unidade estiver fechada.\n2.3.3.3	Aguardar orientação do órgão regional de gestão dos canais de atendimento terceirizados sobre os procedimentos a serem adotados.\n2.3.4	Recolher insumos/material de consumo que tenham sido fornecidos pelos Correios para operacionalização da AGF, conforme orientações descritas no Anexo 6 deste capítulo.\n2.3.4.1	Direcionar os insumos/materiais de consumo recolhidos da AGF que não atinjam o quantitativo de unidades de fornecimento para a Agência Própria dos Correios definida anteriormente pelo órgão regional de gestão dos canais de atendimento terceirizados dos Correios.\n2.3.5	Verificar o relatório de conexão da máquina de franquear, não tendo ocorrido conforme as orientações, acompanhar sua realização e a emissão do relatório correspondente.\n2.3.6	Retirar e alijar a borracha de todos os carimbos de uso no serviço postal, relacionando a quantidade e a identificação.\nNOTA: preferencialmente, o alijamento deverá ocorrer na presença do representante legal da Franqueada.\n2.3.7	Orientar, conferir e acompanhar a emissão de nota fiscal de devolução pela Franqueada, conforme orientações constantes do Anexo 6 deste Capítulo, das etiquetas de código de barras físicas (etiquetas de registro), formulários geradores de receita e outros materiais com utilização controlada (comprovante etc.).\n2.3.8	Catalogar as etiquetas de registro e os formulários geradores de receita que constem em estoque no sistema e não estejam fisicamente na unidade, para análise e adoção de providências posteriores.\n2.3.8.1	Assinar e coletar a assinatura do representante legal da Franqueada ou do profissional designado por esta para acompanhar as atividades, nas páginas do catálogo dos insumos descritos no subitem 2.3.8 deste Anexo.\n2.3.9	Conferir os produtos comercializáveis a serem recolhidos e acompanhar:\na)	a emissão da nota fiscal de devolução pela Franqueada, respeitando as unidades de fornecimento de cada produto e demais orientações contempladas no Anexo 5 deste Capítulo; e\nb)	o fechamento do objeto postal endereçado ao órgão de suprimento correlato por meio de PAC administrativo.\n2.3.10	Relacionar e recolher objetos postais que estejam sob guarda da unidade para entrega interna e/ou para caixa postal, de modo a transferi-los à unidade mais próxima. A unidade que receber os objetos redirecionados deverá emitir novo aviso de chegada para cada objeto.\n2.3.11	Verificar a existência de objetos postais captados pela agência e:\na)	identificar sua contabilização e o respectivo encaminhamento, não constando, solicitando ao responsável legal/proprietário/empregado da AGF que estiver acompanhando os procedimentos de encerramento que providencie a regularização dos objetos não contabilizados e não expedidos; e\nb)	solicitar coleta ao órgão regional de operações.\n2.3.12	Retirar todos os cartazes dos quadros de avisos existentes na unidade, descartando aqueles que estejam fora da vigência de exposição.\n2.3.13	Registrar todas as ações ocorridas, concluir o termo de encerramento das atividades da AGF e/ou área acessória, anexando toda a documentação.\n2.3.13.1	 Colher a assinatura da equipe técnica de fechamento da AGF bem como do responsável legal da AGF no termo de encerramento das atividades, conforme Anexo 9 deste capítulo, rubricando as demais páginas do documento.\n2.3.13.2	Disponibilizar à Franqueada uma via do termo de encerramento das atividades da AGF, conforme Anexo 9 deste Capítulo.\n2.3.13.3	Inserir cópia do termo de encerramento das atividades da franqueada e a documentação correspondente no sistema eletrônico de informações, no respectivo processo de rescisão do Contrato de Franquia Postal.', 47),
(12047, 'anexo', 271, 12001, 2, '2.4', 'Procedimento do Superintendente Estadual de Operações', '', 48),
(12048, 'anexo', 271, 12047, 3, '2.4.1', 'Receber relatório técnico ou nota técnica emitida pelo órgão regional de gestão dos canais de atendimento terceirizados, constando a motivação para instauração do processo de rescisão do Contrato de Franquia Postal de forma amigável.', '', 49),
(12049, 'anexo', 271, 12047, 3, '2.4.2', 'Analisar o relatório técnico/nota técnica e autorizar/homologar, ou não, os procedimentos para rescisão contratual de forma amigável.', '', 50),
(12050, 'anexo', 271, 12047, 3, '2.4.3', 'Solicitar, caso necessário, ao órgão regional de gestão dos canais de atendimento terceirizados, outros subsídios para viabilizar a análise.', '', 51),
(12051, 'anexo', 271, 12047, 3, '2.4.4', 'Responder ao Correios Sede, sobre a manifestação da pessoa jurídica detentora do Contrato de Franquia Postal (AGF), em até 10 (dez) dias contados do recebimento da mesma.', '2.4.4.1 Encaminhar ao Correios Sede, para análise e emissão de parecer final sobre a rescisão do Contrato de Franquia Postal de forma amigável, emitido no âmbito estadual, sendo que:', 52),
(12052, 'anexo', 271, 12051, 4, 'a', 'o encaminhamento do processo ao Correios Sede deve ser precedido da emissão de relatório técnico complementar ao emitido para abertura do processo de rescisão do Contrato de Franquia Postal; e', '', 53),
(12053, 'anexo', 271, 12051, 4, 'b', 'o relatório técnico deve contemplar parecer consubstanciado e conclusivo da Superintendência Estadual de Operações.', '', 54),
(12054, 'anexo', 271, 12047, 3, '2.4.5', 'Receber, do Correios Sede, a decisão final em relação ao processo de rescisão do Contrato de Franquia Postal de forma amigável.', '2.4.5.1 Orientar o órgão regional de gestão dos canais de atendimento terceirizados sobre a comunicação à Franqueada quanto ao posicionamento dos Correios e continuidade dos procedimentos correlatos ao parecer recebido.', 55),
(12055, 'anexo', 271, 12047, 3, '2.4.6', 'Assinar o termo de distrato e/ou documento de formalização de rescisão contratual, quando aplicável.', '', 56),
(12056, 'anexo', 271, 12001, 2, '2.5', 'Procedimentos do Órgão de Gestão Financeira dos Canais de Atendimento Terceirizados', '', 57),
(12057, 'anexo', 271, 12056, 3, '2.5.1', 'Prestar apoio profissional quando solicitado pelo órgão regional de gestão dos canais de atendimento terceirizados, quanto à análise da situação financeira da AGF.', '', 58),
(12058, 'anexo', 271, 12056, 3, '2.5.2', 'Receber comunicação do órgão regional de gestão dos canais de atendimento terceirizados sobre a rescisão do Contrato de Franquia Postal de forma amigável.', '', 59),
(12059, 'anexo', 271, 12056, 3, '2.5.3', 'Rescindir o(s) termo(s) de reconhecimento e parcelamento de débitos, quando houver.', '', 60),
(12060, 'anexo', 271, 12056, 3, '2.5.4', 'Verificar a existência de faturas vencidas e/ou a vencer, de forma a viabilizar, quando cabível, sua quitação na última prestação de contas.', '', 61),
(12061, 'anexo', 271, 12056, 3, '2.5.5', 'Orientar o órgão regional de gestão dos canais de atendimento terceirizados e/ou a equipe técnica de fechamento da AGF quanto aos procedimentos financeiros de encerramento da agência.', '', 62),
(12062, 'anexo', 271, 12056, 3, '2.5.6', 'Receber, do órgão de suprimento, informações quanto ao recebimentos dos produtos comercializáveis em devolução, conforme Anexo 5 deste Capítulo.', '2.5.6.1 Viabilizar o ressarcimento dos créditos relativos aos produtos devolvidos.', 63),
(12063, 'anexo', 271, 12056, 3, '2.5.7', 'Receber, do órgão regional de gestão dos canais de atendimento terceirizados, as informações sobre a necessidade de debitar, na última prestação de contas, os valores relativos à substituição e/ou consertos de itens cedidos pelos Correios à Franqueada para operacionalização do objeto do Contrato de Franquia Postal.', '2.5.7.1 Providenciar a inclusão do débito de que trata o subitem 2.5.7 deste Anexo e efetuar a devida cobrança.', 64),
(12064, 'anexo', 271, 12056, 3, '2.5.8', 'Receber a solicitação de parcelamento de débito da pessoa jurídica detentora do Contrato de Franquia Postal (AGF), se houver, avaliando a possibilidade de parcelamento dos débitos por meio de cobrança administrativa, conforme Anexo 2 deste Capítulo.', '', 65),
(12065, 'anexo', 271, 12001, 2, '2.6', 'Procedimentos do Órgão Jurídico Regional', '', 66),
(12066, 'anexo', 271, 12065, 3, '2.6.1', 'Receber a solicitação de apoio técnico do órgão regional de gestão dos canais de atendimento terceirizados e/ou do Superintendente Estadual de Operações.', '', 67),
(12067, 'anexo', 271, 12065, 3, '2.6.2', 'Prestar apoio jurídico quando solicitado pelo órgão regional de gestão dos canais de atendimento terceirizados, quanto à análise dos documentos apresentados pela Franqueada, assim como do Contrato de Franquia Postal, edital de licitação e outros documentos necessários.', '', 68),
(12068, 'anexo', 271, 12065, 3, '2.6.3', 'Responder, formalmente, em até 5 (cinco) dias úteis contados da data subsequente ao recebimento da consulta.', 'NOTA: poderá ser encaminhada resposta eletrônica com a assinatura do gestor ou do responsável pela área consultada.', 69),
(12069, 'anexo', 271, 12065, 3, '2.6.4', 'Receber solicitação de orientação quanto aos procedimentos a serem adotados pelo órgão regional de gestão dos canais de atendimento terceirizados quando:', '', 70),
(12070, 'anexo', 271, 12069, 4, 'a', 'houver impedimento de acesso da equipe técnica de fechamento da AGF entrar na unidade; e', '', 71),
(12071, 'anexo', 271, 12069, 4, 'b', 'a agência e/ou áreas acessórias estiverem fechadas e/ou não houver nenhum responsável na unidade para receber a equipe técnica de fechamento da AGF.', '2.6.4.1 Orientar o órgão regional de gestão dos canais de atendimento terceirizados e/ou Superintendente Estadual de Operações, e adotar as providências jurídicas cabíveis.', 72),
(12072, 'anexo', 271, 12001, 2, '2.7', 'Procedimentos do Órgão Regional de Vendas', '', 73),
(12073, 'anexo', 271, 12072, 3, '2.7.1', 'Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF e/ou das áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).', '', 74),
(12074, 'anexo', 271, 12072, 3, '2.7.2', 'Informar aos clientes que utilizam o respectivo canal de atendimento sobre o iminente fechamento da Agência de Correios Franqueada foco do processo de rescisão contratual.', '', 75),
(12075, 'anexo', 271, 12072, 3, '2.7.3', 'Interagir com os clientes de perfil industrial para definir as unidades habilitadas para atendê-los.', '', 76),
(12076, 'anexo', 271, 12001, 2, '2.8', 'Procedimentos do Órgão de Suprimento', '', 77),
(12077, 'anexo', 271, 12076, 3, '2.8.1', 'Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF.', '', 78),
(12078, 'anexo', 271, 12076, 3, '2.8.2', 'Suspender os procedimentos de suprimento em andamento para a Franqueada.', '', 79),
(12079, 'anexo', 271, 12076, 3, '2.8.3', 'Providenciar o bloqueio dos usuários aos sistemas de suprimento.', '', 80),
(12080, 'anexo', 271, 12076, 3, '2.8.4', 'Orientar o órgão regional de gestão dos canais de atendimento terceirizados sobre os procedimentos para devolução e/ou descarte dos itens estocáveis que se encontrem na AGF e estejam aptos para uso ou comercialização por outras unidades.', 'NOTA: os produtos que não estejam fisicamente aptos para comercialização (molhado, rasgado, manchado etc.) devem ser baixados no sistema como vendidos, até a data anterior ao fechamento da AGF, a fim de serem excluídos do sistema.', 81),
(12081, 'anexo', 271, 12076, 3, '2.8.5', 'Receber, conferir os produtos devolvidos pela AGF e informar ao órgão de gestão financeira e ao órgão regional de gestão dos canais de atendimento terceirizados sobre o valor venal correspondente.', '', 82),
(12082, 'anexo', 271, 12076, 3, '2.8.6', 'Comunicar ao órgão regional de gestão dos canais de atendimento terceirizados e ao órgão de gestão financeira quanto ao recebimento dos itens devolvidos e a conclusão dos procedimentos internos.', '', 83),
(12083, 'anexo', 271, 12001, 2, '2.9', 'Procedimentos do Órgão Regional de Operações', '2.9.1	Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).\n2.9.2	Disponibilizar veículo de apoio à equipe técnica de fechamento da AGF, bem como para:\na)	transferência de objetos postais destinados para entrega interna e/ou caixa postal, da AGF que será fechada, para a(s) unidade(s) de atendimento pré-definida(s); e\nb)	coleta de objetos postais captados pela AGF.\n2.9.3	Reorganizar a distribuição dos objetos de entrega interna e o fluxo de coleta a ser implantado na data posterior ao fechamento da unidade.\n2.9.4	Providenciar a exclusão da faixa de CEP e das informações da AGF e/ou das áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal) no Diretório Nacional de Endereços - DNE e demais sistemas corporativos de gestão de encaminhamento e coleta.\n2.10	Procedimentos do Órgão Regional de Gestão Patrimonial\n2.10.1	Receber informação do órgão regional de gestão dos canais de atendimento terceirizados sobre o fechamento da AGF e/ou das áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal).\n2.10.2	Providenciar, quando cabível, o recolhimento na data marcada para o fechamento da unidade, dos equipamentos e/ou mobiliários que tenham sido cedidos pelos Correios à AGF e/ou nas áreas acessórias (Guichê Avançado de Atendimento Contingencial - GAC e Guichê Avançado de Atendimento Sazonal) para a operacionalização do objeto do Contrato de Franquia Postal.\n2.10.3	Verificar as condições de integridade estrutural e de funcionamento dos itens cedidos pelos Correios à Franqueada antes de seu recolhimento.\n2.10.3.1	Solicitar à equipe técnica de fechamento da AGF que faça constar no termo de encerramento das atividades da unidade, conforme Anexo 9 deste Capítulo, as condições identificadas nos itens cedidos.', 84),
(12084, 'anexo', 271, 12001, 2, '2.11', 'Procedimentos do Correios Sede', '', 85),
(12085, 'anexo', 271, 12084, 3, '2.11.1', 'Receber o processo de rescisão do Contrato de Franquia Postal de forma amigável, encaminhado por intermédio do Superintendente Estadual de Operações, em conformidade com o Anexo 2 deste Capítulo.', '2.11.1.1 Analisar o processo de rescisão do Contrato de Franquia Postal de forma amigável no prazo de 10 (dez) dias úteis, contados da data de seu recebimento.\n2.11.1.2 Solicitar informações adicionais à Superintendência Estadual de Operações, quando pertinente.\n2.11.1.3 Informar à Superintendência Estadual de Operações quando houver a necessidade de prazo adicional para viabilizar a análise.', 86),
(12086, 'anexo', 271, 12084, 3, '2.11.2', 'Encaminhar a resposta à Superintendência Estadual de Operações.', '* * * * *', 87),
(12087, 'anexo', 272, NULL, 1, '1', 'INFORMAÇÕES DO SUBPROCESSO', '1.1	As instruções e demais procedimentos relativos ao recolhimento de produtos incluem, obrigatoriamente, as seguintes disposições:', 0),
(12088, 'anexo', 272, 12087, 4, 'a', 'cláusula terceira - item 3.7.1, alínea “f” do Contrato de Franquia Postal - CFP;', '', 1),
(12089, 'anexo', 272, 12087, 4, 'b', 'MANSUP 2/3/2 - 3.1 e 3.2, a saber:', 'I - item 3.1: “A devolução de produto somente se aplica aos casos de itens em consignação, itens de terceiros ou nas situações definidas em demais Módulos(s) específico(s) do MANSUP.”\nII - item 3.2: “No caso de itens próprios consignados às AGFs, a devolução ao Centro de Logística Integrada - CLI deve obedecer ao mesmo tipo de unidade de fornecimento, exceção aos casos de devolução de produtos danificados.”', 2),
(12090, 'anexo', 272, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '', 3),
(12091, 'anexo', 272, 12090, 2, '2.1', 'Procedimentos da Pessoa Jurídica Detentora do Contrato de Franquia Postal (AGF)', '', 4),
(12092, 'anexo', 272, 12091, 3, '2.1.1', 'Separar os produtos por tipo, para conferência e verificação das condições de comercialização.', '', 5),
(12093, 'anexo', 272, 12091, 3, '2.1.2', 'Emitir nota fiscal de devolução de produtos para o CLI ao qual a unidade está vinculada, utilizando os seguintes parâmetros fiscais:', 'a) CFOP (Código Fiscal de Operações e Prestações): agência e CLI estabelecidos no mesmo Estado: 5.202 (devolução de compra para comercialização);\nb) agência e CLI estabelecidos em Estados diferentes: 6.202 (devolução de compra para comercialização); e\nc) CST (Código de Situação Tributária): o valor dos itens e o valor do Imposto sobre Circulação de Mercadorias e Serviços - ICMS deverão ser idênticos aos informados na nota emitida pelo CLI na ocasião do último suprimento realizado à unidade.', 6),
(12094, 'anexo', 272, 12091, 3, '2.1.3', 'Referenciar na nota fiscal de devolução de produtos o número da(s) nota(s) fiscal(is) de fornecimento relativo aos produtos devolvidos.', '', 7),
(12095, 'anexo', 272, 12091, 3, '2.1.4', 'Encaminhar ao gestor estadual do contrato de franquia postal o Documento Auxiliar da Nota Fiscal Eletrônica - DANFE e o arquivo XML, via e-mail.', '', 8),
(12096, 'anexo', 272, 12090, 2, '2.2', 'Procedimentos da Equipe Técnica de Fechamento Da AGF', '', 9),
(12097, 'anexo', 272, 12096, 3, '2.2.1', 'Emitir orientação à agência que será fechada, com fluxo de procedimentos que viabilizarão a devolução de produtos.', '', 10),
(12098, 'anexo', 272, 12096, 3, '2.2.2', 'Conferir as condições de comercialização dos produtos.', '', 11),
(12099, 'anexo', 272, 12096, 3, '2.2.3', 'Contar os produtos e verificar o quantitativo de unidades por cada tipo de produto.', '', 12),
(12100, 'anexo', 272, 12096, 3, '2.2.4', 'Separar os itens em condições de uso, por categoria (exemplo: aerogramas, selos, embalagens etc), devidamente identificados.', '', 13),
(12101, 'anexo', 272, 12096, 3, '2.2.5', 'Orientar e acompanhar quanto ao correto acondicionamento dos produtos que podem ser recolhidos em caixas, fechá-las e utilizar etiqueta de encomenda PAC Administrativo.', '', 14),
(12102, 'anexo', 272, 12096, 3, '2.2.6', 'Os itens de diferentes categorias poderão ser acondicionados numa mesma caixa, desde que devidamente separados e identificados.', '', 15),
(12103, 'anexo', 272, 12096, 3, '2.2.7', 'Orientar sobre a emissão da nota fiscal de devolução dos produtos, nas quantidades correspondentes ao recolhimento, bem como, na indicação correta dos valores no documento fiscal, observando-se o desconto fornecido.', '', 16),
(12104, 'anexo', 272, 12096, 3, '2.2.8', 'Providenciar o encaminhamento dos produtos acompanhados da nota fiscal de devolução ao CLI, utilizando rotulagem para os volumes, conforme modelo a seguir:', 'Ao\nCentro de Logística Integrada - CLI CD Leste\nEndereço: Av Dr. Antonio João Abdalla, 2727, Vila Nova.\n07750-981 - Cajamar/SP\nREF.: DEVOLUÇÃO DE PRODUTOS - ENCERRAMENTO (Nome da unidade)\nNF de Devolução nº.:_____\nOu\nAo\nCentro de Logística Integrada - CLI CD Oeste\nEndereço: SGCV Sul Lote 16 a 18, SOF Sul.\n71215-100 - Brasília/DF\nREF.: DEVOLUÇÃO DE PRODUTOS - ENCERRAMENTO (Nome da unidade)\nNF de Devolução nº.:_____', 17),
(12105, 'anexo', 272, NULL, 1, '3', 'PROCEDIMENTOS DO ÓRGÃO REGIONAL DE GESTÃO DOS CANAIS DE ATENDIMENTO TERCEIRIZADOS', '3.1 Receber o DANFE e o arquivo XML encaminhado via e-mail pela AGF.\n3.2 Postar o arquivo XML no repositório dos Correios por meio do link http://app.correiosnet.int/dfe/inicio/inicio.jsf\n3.3 Encaminhar o DANFE via e-mail ao Correios Sede, ao órgão de gestão financeira e ao respectivo Centro de Logística Integrada - CLI (CD Oeste recebimentogecdoeste@correios.com.br ou CD Leste GECDLESTEPROD@correios.com.br) (idem)', 18),
(12106, 'anexo', 272, NULL, 1, '4', 'PROCEDIMENTOS DO CORREIOS SEDE', '4.1 Emitir memorando circular no qual documentará o fato ocorrido ao órgão de gestão financeira, anexando o DANFE recebido e solicitando que providencie o ajuste das etiquetas constantes na NF no PROTER e realize os ajustes tributários pertinentes.', 19),
(12107, 'anexo', 272, NULL, 1, '5', 'PROCEDIMENTOS DO ÓRGÃO DE GESTÃO FINANCEIRA', '', 20),
(12108, 'anexo', 272, 12107, 2, '5.1', 'Providenciar o ressarcimento dos valores relativos aos produtos devolvidos com fatura quitada.', '', 21),
(12109, 'anexo', 272, 12107, 2, '5.2', 'Providenciar os ajustes tributários necessários nos livros contábeis.', '', 22),
(12110, 'anexo', 272, NULL, 1, '6', 'PROCEDIMENTOS DO CENTRO DE LOGÍSTICA INTEGRADA - CLI', '', 23),
(12111, 'anexo', 272, 12110, 2, '6.1', 'Receber a carga identificada.', '', 24),
(12112, 'anexo', 272, 12110, 2, '6.2', 'Conferir os produtos recebidos, confrontando com a nota fiscal de devolução.', '', 25),
(12113, 'anexo', 272, 12110, 2, '6.3', 'Efetuar os ajustes no sistema de controle de estoque.', '', 26),
(12114, 'anexo', 272, 12110, 2, '6.4', 'Dar entrada do produto no sistema ERP, de acordo com o tipo de pedido realizado anteriormente pela AGF.', '', 27),
(12115, 'anexo', 272, 12110, 2, '6.5', 'Informar o recebimento dos produtos ao órgão de gestão financeira, quando o ajuste contábil não for processado automaticamente.', '* * * * *', 28),
(12116, 'anexo', 273, NULL, 1, '1', 'INFORMAÇÕES DO SUBPROCESSO', '1. 1	As instruções e demais procedimentos relativos ao recolhimento de insumos/materiais de consumo incluem, obrigatoriamente, as seguintes disposições:', 0),
(12117, 'anexo', 273, 12116, 4, 'a', 'cláusula terceira - Item 3.7.1, alínea “f” do Contrato de Franquia Postal - CPF;', '', 1),
(12118, 'anexo', 273, 12116, 4, 'b', 'MANSUP 2/3 e seus anexos.', '', 2),
(12119, 'anexo', 273, NULL, 1, '2', 'DESCRIÇÃO DO SUBPROCESSO', '2.1 Procedimentos da Pessoa Jurídica Detentora do Contrato de Franquia Postal (AGF)\n2.1.1	Devolução de Insumos/Materiais de Consumo\n2.1.1.1	Havendo encerramento das atividades na unidade de atendimento terceirizada, os materiais (insumos/materiais de consumo) deverão ser devolvidos ao órgão regional de gestão dos canais de atendimento terceirizados em unidades de fornecimento fechadas, conforme suprido pelo Centro de Logística Integrada - CLI por Guia de Remessa de Material - GRM.\n2.1.1.2 Separar os materiais por tipo, para conferência e verificação das condições de uso.\n2.1.1.3 Itens obsoletos deverão ser alijados na própria agência conforme orientações do órgão regional de gestão dos canais de atendimento terceirizados\n2.1.2 Devolução de Etiquetas\n2.1.2.1 As etiquetas deverão ser devolvidas ao CLI supridor da AGF, em caixas fechadas em sequência numérica única (faixa única).\n2.1.2.2 Separar as etiquetas por tipo, para conferência e verificação das condições de uso.\n2.1.2.3 Emitir relatório de estoque de etiquetas do Sistema de Automação da Rede de Atendimento - SARA.\n2.1.2.4 Emitir nota fiscal de remessa dos materiais para o CLI a qual a unidade está vinculada, utilizando os seguintes parâmetros fiscais:\na) CFOP (Código Fiscal de Operações e Prestações): agência e CLI estabelecidos no mesmo Estado: 5.949;\nb) CFOP (Código Fiscal de Operações e Prestações): agência e CLI estabelecidos em Estados diferentes: 6.949;\nc) CST (Código de Situação Tributária): o valor dos itens e o valor do Imposto sobre Circulação de Mercadorias e Serviços - ICMS deverão ser idênticos aos informados na nota emitida pelo CLI na ocasião do último suprimento realizado à unidade.\n2.1.2.5 Referenciar na nota fiscal de devolução, o número da nota(s) fiscal(is) de origem da última remessa realizada pelo CLI supridor.\n2.1.2.6 Encaminhar ao gestor regional do Contrato de Franquia Postal o Documento Auxiliar da Nota Fiscal Eletrônica - Danfe e o arquivo XML via e-mail.\n2.1.2.7 Alijar as etiquetas obsoletas na própria agência, conforme orientações fornecidas pelo órgão regional de gestão dos canais de atendimento terceirizados\n2.2 Procedimentos da Equipe Técnica de Fechamento da AGF\n2.2.1 Emitir orientação à agência que será fechada com fluxo de procedimentos que viabilizarão a devolução de materiais.\n2.2.2 Emitir, via SARA, o relatório com o estoque de etiquetas.\n2.2.3 Conferir as etiquetas físicas, confrontando com o relatório emitido pelo SARA.\n2.2.4 Orientar e acompanhar quanto ao correto acondicionamento dos materiais que podem ser recolhidos em caixas, fechá-las e utilizar etiqueta de encomenda PAC administrativo.\n2.2.5 Orientar sobre a emissão da nota fiscal de remessa dos materiais nas quantidades correspondentes ao recolhimento, bem como na indicação correta dos valores no documento fiscal.\n2.2.6 Providenciar o encaminhamento dos materiais acompanhados da nota fiscal de remessa ao CLI, utilizando rotulagem para os volumes conforme modelo a seguir:\nAo\nCentro de Logística Integrada - CLI CD Leste\nEndereço: Av Dr. Antonio João Abdalla, 2727, Vila Nova.\n07750-981 - Cajamar/SP\nREF.: DEVOLUÇÃO DE MATERIAIS - ENCERRAMENTO (Nome da unidade)\nNF de Devolução nº.:_____\nOu\nAo\nCentro de Logística Integrada - CLI CD Oeste\nEndereço: SGCV Sul Lote 16 a 18, SOF Sul.\n71215-100 - Brasília/DF\nREF.: DEVOLUÇÃO DE MATERIAIS - ENCERRAMENTO (Nome da unidade)\nNF de Devolução nº.:_____\n2.3 Procedimentos do Órgão Regional de Gestão dos Canais de Atendimento Terceirizados\n2.3.1 Receber o DANFE e o arquivo XML encaminhado via e-mail pela AGF.\n2.3.2 Postar o arquivo XML no repositório dos Correios por meio do link: http://app.correiosnet.int/dfe/inicio/inicio.jsf\n2.3.3 Encaminhar o DANFE via e-mail ao Correios Sede, ao órgão de gestão financeira e ao respectivo Centro de Logística Integrada - CLI (CD Oeste recebimentogecdoeste@correios.com.br ou CD Leste GECDLESTEPROD@correios.com.br', 3),
(12120, 'anexo', 273, NULL, 1, '3', 'PROCEDIMENTOS DO CORREIOS SEDE', '3.1	Emitir memorando circular no qual documentará o fato ocorrido ao órgão de gestão financeira, anexando o DANFE recebido e solicitando que providencie o ajuste das etiquetas constantes na NF no PROTER e realize os ajustes tributários pertinentes.', 4),
(12121, 'anexo', 273, NULL, 1, '4', 'PROCEDIMENTOS DO ÓRGÃO DE GESTÃO FINANCEIRA', '', 5),
(12122, 'anexo', 273, 12121, 2, '4.1', 'Ajustar o Sistema de Proteção de Receita - PROTER com base nas informações recebidas.', '', 6),
(12123, 'anexo', 273, 12121, 2, '4.2', 'Cadastrar a sequência no PROTER, caso o controle de receitas esteja centralizado, ou repassar a sequência ao gestor regional do contrato para proceder ao referido cadastro no sistema.', '', 7),
(12124, 'anexo', 273, 12121, 2, '4.3', 'Providenciar os ajustes tributários nos livros contábeis, se necessário.', '', 8),
(12125, 'anexo', 273, NULL, 1, '5', 'PROCEDIMENTOS DO CENTRO DE LOGÍSTICA INTEGRADA - CLI', '', 9),
(12126, 'anexo', 273, 12125, 2, '5.1', 'Receber a carga de materiais identificada.', '', 10),
(12127, 'anexo', 273, 12125, 2, '5.2', 'Conferir as etiquetas recebidas com a nota fiscal de remessa.', '', 11),
(12128, 'anexo', 273, 12125, 2, '5.3', 'Efetuar os ajustes no sistema de controle de estoque.', '', 12),
(12129, 'anexo', 273, 12125, 2, '5.4', 'Informar o recebimento das etiquetas ao órgão de gestão financeira quando o ajuste contábil não for realizado automaticamente.', '* * * * *', 13),
(12130, 'anexo', 276, NULL, 1, '1', 'Na tabela abaixo deverão ser descritas as ocorrências ou pendências relativas aos procedimentos identificados durante as atividades de fechamento da AGF, tais como:', '', 0),
(12131, 'anexo', 276, 12130, 4, 'a', 'ausência de etiquetas e/ou formulários, quando comparadas ao relatório de estoque;', '', 1),
(12132, 'anexo', 276, 12130, 4, 'b', 'objetos postais não contabilizados e/ou não expedidos segundo as normas previstas no MANCAT;', '', 2),
(12133, 'anexo', 276, 12130, 4, 'c', 'necessidade de solicitar coleta para carga postal acumulada;', '', 3),
(12134, 'anexo', 276, 12130, 4, 'd', 'objetos de entrega interna e/ou caixa postal com invólucro danificado ou com aparência de espoliado;', '', 4),
(12135, 'anexo', 276, 12130, 4, 'e', 'ausência e/ou dano em equipamentos e/ou imóveis cedidos pelos Correios', '', 5),
(12136, 'anexo', 276, 12130, 4, 'f', 'atividades preliminares não realizadas (produtos não separados, agência com movimento aberto, não realização de conexão de máquina de franquear etc.).', 'ITEM	DESCRIÇÃO DE OCORRÊNCIAS OU PENDÊNCIAS\n 	 \n 	 \n 	 \n 	 \n 	 \n 	 \n 	 \nCidade/UF,          de                                   de 20......\nRepresentantes dos Correios\nNome Completo: ______________________________________________________\nMatrícula: ____________________\nNome Completo: ______________________________________________________\nMatrícula: ____________________\nRepresentante(s) Legal(is) da Franqueada/AGF\nNome Completo: ______________________________________________________\nCPF: ____________________\nNome Completo: ______________________________________________________\nCPF: ____________________\nObservação: as páginas deste documento deverão ser rubricadas pelos representantes dos Correios e da Franqueada.\n* * * * *', 6),
(12137, 'anexo', 278, NULL, 1, '1', 'APLICABILIDADE DA PENALIDADE DE SUSPENSÃO TEMPORÁRIA DE PARTICIPAÇÃO EM LICITAÇÃO E IMPEDIMENTO DE CONTRATAR COM OS CORREIOS', '', 0),
(12138, 'anexo', 278, 12137, 2, '1.1', 'Concomitantemente à aplicação da penalidade de suspensão temporária de participação em licitação e impedimento de contratar com os Correios poderá ser necessária a adoção das providências para viabilizar a interposição de declaração de inidoneidade para licitar ou contratar com a Administração pública pelos órgãos competentes, nos termos dos artigos 155 e 155 da Lei 14.133/2021.', '', 1),
(12139, 'anexo', 278, 12137, 2, '1.2', 'A abrangência das penalidades restritivas do direito de licitar e contratar será conferida, para fins de verificação da situação das pessoas jurídicas contratadas detentoras de contratos para instalação e operação de canais de atendimento terceirizados penalizados por outros entes da administração pública, a partir das seguintes premissas:', '', 2),
(12140, 'anexo', 278, 12139, 4, 'a', 'quando o ente sancionador for os Correios, qualquer que seja o teor, fundamento legal ou origem da contratação, a abrangência da penalidade alcançará todas as estruturas dos Correios;', '', 3),
(12141, 'anexo', 278, 12139, 4, 'b', 'deve ser verificado no instrumento contratual a fim de identificar a amplitude do alcance da penalidade em relação a outra unidade do mesmo modelo ou de outro modelo de canal de atendimento que esteja sobre a gestão da pessoa jurídica contratada', '', 4),
(12142, 'anexo', 278, 12139, 4, 'c', 'quando o ente sancionar for órgão ou entidade da administração pública, prevalecem a fundamentação legal e a extensão conferida pelo aplicador da penalidade;', 'Nota: a penalidade de impedimento de licitar e contratar prevista pelo art. 7° da Lei nº 10.520/2002 abrange os Correios, desde que o ente aplicador seja da esfera federal.', 5),
(12143, 'anexo', 278, 12139, 4, 'd', 'as penalidades de suspensão temporária de participação em licitação e impedimento de contratar previstas no art. 87, inciso III, da Lei nº 8.666/1993 e no art. 83, inciso III da Lei nº 13.303/2016 não abrangem os Correios, quando aplicadas por outros entes.', '', 6),
(12144, 'anexo', 278, 12137, 2, '1.3', 'A penalidade aplicada à empresa matriz abrange a empresa filial e vice versa, principalmente, quando o órgão aplicador for da esfera federal ou judicial.', '', 7),
(12145, 'anexo', 278, 12137, 2, '1.4', 'A aplicação da suspensão temporária para participar em licitação e impedimento de contratar com os Correios deverá ser aplicada conforme estabelecido no instrumento contratual e na legislação aplicável:', '', 8),
(12146, 'anexo', 278, 12145, 4, 'a', 'rescisão/revogação unilateral do instrumento contratual pelos Correios, em razão de inexecução total ou parcial do contrato, antes do início da instalação e operação do canal de atendimento contratual;', 'I - dar causa à inexecução parcial do contrato;\nII - dar causa à inexecução parcial do contrato que cause grave dano à Administração, ao funcionamento dos serviços públicos ou ao interesse coletivo;\nIII - dar causa à inexecução total do contrato;\nIV - deixar de entregar a documentação exigida para o certame;\nV - não manter a proposta, salvo em decorrência de fato superveniente devidamente justificado;\nVI - não celebrar o contrato ou não entregar a documentação exigida para a contratação, quando convocado dentro do prazo de validade de sua proposta;\nVII- ensejar o retardamento da execução ou da entrega do objeto da licitação sem motivo justificado;\nVIII - apresentar declaração ou documentação falsa exigida para o certame ou prestar declaração falsa durante a licitação ou a execução do contrato;\nIX - fraudar a licitação ou praticar ato fraudulento na execução do contrato;\nX - comportar-se de modo inidôneo ou cometer fraude de qualquer natureza;\nXI - praticar atos ilícitos com vistas a frustrar os objetivos da licitação;\nXII - praticar ato lesivo previsto no art. 5º da Lei nº 12.846, de 1º de agosto de 2013.\nNota: nos termos do artigo 156 da lei 14.133/2021 será extensiva à Administração Pública a aplicação da penalidade de suspensão temporária de licitar e contratar na comprovação de quaisquer das ocorrências descritas nos incisos II, III, IV, V, VI e VII.', 9),
(12147, 'anexo', 278, 12145, 4, 'b', 'rescisão/revogação unilateral do instrumento contratual pelos Correios, em razão da inexecução total ou parcial do contrato, após o início das atividades do canal de atendimento terceirizado:', 'I - há de verificar-se a responsabilidade da pessoa jurídica contratada, seus sócios, representantes legais, contratados ou empregados na ocorrência de inexecução do contrato;\nII - a permanência em situação de inadimplemento junto aos Correios será considerado como inexecução parcial do contrato, quando esse perdurar por 6 (seis) meses ou mais, até a data da instrução do processo administrativo de apuração da irregularidade;\nIII - não quitar as parcelas de Termo de Negociação e Parcelamento de débitos por mais de 90 (noventa) dias ou mais, contados a partir do primeiro dia de atraso, até a data da instrução do processo administrativo de apuração da irregularidade, será considerada como inexecução parcial do contrato;\nIV - a unidade/agência não prestar atendimento postal, por 30 (trinta) dias, consecutivos ou mais, sem anuência dos Correios, será considerado como inexecução total;\nNota: a inexecução contratual de que trata o inciso IV, será isenta da aplicação de penalidade de licitar e contratar com os Correios nas situações em que o fechamento da unidade/agência se deu em razão de caso fortuito ou de força maior correlacionado ao imóvel, a exemplo de enchente, deslizamentos, destruição causada por terceiro etc.', 10),
(12148, 'anexo', 278, 12145, 4, 'c', 'apresentação de documentos falsos;', '', 11),
(12149, 'anexo', 278, 12145, 4, 'd', 'cometimento de fraude na execução do objeto do contrato, a exemplo de:', 'I - adquirir, estocar, utilizar e/ou comercializar na AGF, produtos, selos ou outras formas de tarifação de objetos postais, que sejam identificados falsos ou inidôneo, será considerado como fraude, mesmo que a pessoa jurídica contratada, seus sócios ou representantes legais não sejam o articulador da ação criminosa;\nII - fraudar ou violar os mecanismos da máquina de franquear;\nIII - apresentar-se a terceiros como dirigente, preposto ou empregado dos Correios.', 12),
(12150, 'anexo', 278, 12145, 4, 'e', 'condenação, mesmo que em primeira instância, pela pratica dolosa de fraude fiscal no recolhimento de quaisquer tributos;', '', 13),
(12151, 'anexo', 278, 12145, 4, 'f', 'condenação pela prática de atos ilícitos, visando a frustrar os objetivos da contratação;', '', 14),
(12152, 'anexo', 278, 12145, 4, 'g', 'demonstração de inidoneidade para contratar com a Administração Pública.', '', 15),
(12153, 'anexo', 278, 12137, 2, '1.5', 'Observar na legislação aplicável e no instrumento contratual as situações em que a aplicabilidade da penalidade deve ser extensiva à administração pública direta e indireta.', '', 16),
(12154, 'anexo', 278, NULL, 1, '2', 'REABILITAÇÃO', '', 17),
(12155, 'anexo', 278, 12154, 2, '2.1', 'É admitida a reabilitação da pessoa jurídica contratada perante os Correios, exigidos, cumulativamente:', '', 18),
(12156, 'anexo', 278, 12155, 4, 'a', 'reparação integral do dano causado aos Correios e a  Administração Pública, quando aplicável;', '', 19),
(12157, 'anexo', 278, 12155, 4, 'b', 'pagamento da multa, prevista contratualmente;', '', 20),
(12158, 'anexo', 278, 12155, 4, 'c', 'transcurso do prazo mínimo de 1 (um) ano da aplicação da penalidade;', '', 21),
(12159, 'anexo', 278, 12155, 4, 'd', 'cumprimento das condições de reabilitação definidas no processo administrativo que estabeleceu a aplicação da penalidade;', '', 22),
(12160, 'anexo', 278, 12155, 4, 'e', 'análise jurídica prévia, com posicionamento conclusivo quanto ao cumprimento dos requisitos definidos pelo instrumento contratual ou na legislação aplicável.', '', 23),
(12161, 'anexo', 278, NULL, 1, '3', 'DOSIMETRIA DA PENALIDADE DE SUSPENSÃO TEMPORÁRIA DE PARTICIPAÇÃO EM LICITAÇÃO E IMPEDIMENTO DE CONTRATAR', '', 24),
(12162, 'anexo', 278, 12161, 2, '3.1', 'Na aplicação da penalidade de suspensão temporária de licitar e impedimento de contratar com os Correios serão considerados:', '', 25),
(12163, 'anexo', 278, 12162, 4, 'a', 'a natureza e a gravidade da infração cometida;', '', 26),
(12164, 'anexo', 278, 12162, 4, 'b', 'as peculiaridades do caso concreto;', '', 27),
(12165, 'anexo', 278, 12162, 4, 'c', 'as circunstâncias agravantes ou atenuantes;', '', 28),
(12166, 'anexo', 278, 12162, 4, 'd', 'os danos que dela provierem para a Administração Pública;', '', 29),
(12167, 'anexo', 278, 12162, 4, 'e', 'a implantação ou o aperfeiçoamento de programa de integridade, conforme normas e orientações dos órgãos de controle.', '', 30),
(12168, 'anexo', 278, 12161, 2, '3.2', 'Aplicar os prazos indicados abaixo para impedimento de licitar e contratar com a administração pública.', 'Penalidade	Prazo	Agravante 	Atenuante\nInexecução parcial	 6 meses	Ampliar a penalidade em 3 meses\nInexecução total\n12 meses	Ampliar a penalidade em 6 meses	Reduzir o prazo da penalidade em 6 meses.\nNão manter condição de habilitação	18 meses		Reduzir o prazo da penalidade em 6 meses, se não houver responsabilidade definida.\nNão manter condição de habilitação 	18 meses		Reduzir o prazo em 9 meses se houver quitação de débitos existentes antes do registro da penalidade.\nApresentação de documento falso	24 meses\nCometimento de fraude	24 meses\nFraude Fiscal no recolhimento de tributos	24 meses\nPratica de atos ilícitos para frustrar os objetivos da licitação	24 meses\nDemonstrar idoneidade para contratar	24 meses', 31),
(12169, 'anexo', 278, 12161, 2, '3.3', 'Será considerado como agravante as situações em que for identificada a responsabilidade objetiva da pessoa jurídica contratada, ou, ainda, de sócio(s), de representante(s) legal(is), de contratado(s) ou de empregado(s) na ocorrência de descumprimento contratual que ensejou a aplicação da penalidade de impedimento de licitar e contratar com os Correios e/ou com a administração pública', '', 32),
(12170, 'anexo', 278, 12161, 2, '3.4', 'Será considerado como atenuante as situações em que for identificado que não houve responsabilidade objetiva ou dolo da pessoa jurídica contratada, ou, ainda, de sócio(s), de representante(s) legal(is), de contratado(s) ou de empregado(s) na ocorrência de descumprimento contratual que ensejou a aplicação da penalidade de impedimento de licitar e contratar com os Correios e/ou com a administração pública.', '', 33),
(12171, 'anexo', 278, 12161, 2, '3.5', 'As irregularidades cujo prazo de penalidade seja de 24 (vinte e quatro) meses também são extensivas à impedimento de licitar e contratar com a administração pública.', '* * * * *', 34),
(12172, 'anexo', 279, NULL, 4, 'a', 'Planejamento de Encontro de Negócios na Administração Central:', '', 0),
(12173, 'anexo', 279, NULL, 4, 'b', 'Planejamento de Encontro de Negócios nas Diretorias Regionais:', '', 1),
(12174, 'anexo', 279, NULL, 4, 'c', 'Execução do Planejamento de Encontro de Negócios na Administração Central:', '', 2),
(12175, 'anexo', 279, NULL, 4, 'd', 'Execução do Planejamento de Encontro de Negócios nas Diretorias Regionais:', '*****', 3),
(12176, 'anexo', 282, NULL, 1, '1', 'FLUXO DO SUBPROCESSO', '* * * * *', 0),
(12177, 'anexo', 283, NULL, 1, '1', 'FLUXOS DE VENDAS (NÍVEL 1)', '1.1 Fluxo de Definir Estratégia de Vendas (Nível 2)\n1.1.1 Fluxo de Consolidar Dados para Planejamento de Vendas (Nível 3)\n1.1.2 Fluxo de Elaborar Plano de Ações de Vendas (Nível 3)\n1.2 Fluxo Executar Vendas (Nível 2)\n1.2.1 Fluxo Gerir Leads (Nível 3)\n1.2.2 Fluxo Realizar Negociação (Nível 3)\n1.2.3 Fluxo Formalizar Documento (Nível 3)\n1.2.4 Fluxo Cadastrar Contrato (Nível 3)\n1.3 Fluxo Definir Atuação da Força de Vendas (Nível 2)\n1.3.1 Fluxo Reconhecer Resultados de Campanhas e Ações de Incentivo a Vendas (Nível 3)\n1.3.2 Fluxo Planejar Atuação da Força de Vendas (Nível 3)\n1.3.3 Fluxo Coordenar Atuação da Força de Vendas (Nível 3)\n1.4 Fluxo Medir Efetividade de Vendas (Nível 2)\n1.4.1 Fluxo Realizar Acompanhamento Conjunto de Resultados (Nível 3)\n* * * * *', 0);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(12178, 'anexo', 284, NULL, 1, '1', 'DETALHAMENTO DO PROCESSO ', '1.1 O processo de nível 2 da Cadeia de Valor dos Correios Executar vendas possui os processos descritos a seguir.\n1.1.1 Definir plano de ação: a força de vendas deve elaborar o plano de ação necessário para cumprimento do plano de ação de vendas.\n1.1.2 Gerir leads: identificar dados de potencial cliente que demonstram interesse em contratar os serviços/produtos dos Correios, contatando em ordem de prioridade e acompanhando até a concretização ou não da venda, conforme as seguintes etapas:\na) incluir e/ou atualizar base de mailings: manter atualizada a base de clientes potenciais e dados para contato (telefone, e-mail e endereço), a partir de importação e/ou atualização de mailings (Receita Federal, ciclo Micro e Pequenas Empresas - MPE, eventos diversos, fornecedores dos Correios, clientes com contratos cancelados, entidades que não conseguiram finalizar a contratação pelo portal do termo de adesão);\nb) aplicar filtro de estratégia: selecionar os segmentos de mercado (Classificação Nacional de Atividade Econômica - CNAE) mais aderentes aos serviços de Correios e classificar os clientes com maior potencial de compra;\nc) aquecer mailing: a partir de um mailing selecionado, o responsável pela prospecção deve interagir com o contato, verificando seu interesse e disponibilidade financeira para posterior registro no sistema de Prospecção de Negócios - PRONEG;\nd) cadastrar dados do interessado quando há solicitação de contato dos Correios por meio de telefone/site: o operador da central de atendimento deve registrar informações no sistema de Prospecção de Negócios - PRONEG, conforme dados cadastrados no site dos Correios ou recebidos por telefone;\ne) cadastrar dados do cliente potencial quando há oportunidade identificada na postagem à vista: o gestor de relacionamento da agência deve registrar informações no sistema de Prospecção de Negócios - PRONEG, conforme dados coletados no momento da postagem;\nf) contatar cliente para identificar oportunidade: interagir com o cliente, verificando seu interesse e disponibilidade financeira para posterior registro no sistema de Prospecção de Negócios - PRONEG.\n1.1.3 Realizar negociação: realizar negociação com o cliente ou prospect de forma a concretizar as ações de vendas de produtos/serviços, para postagem à vista ou por meio de contrato, conforme os seguintes processos:\n1.1.3.1 Realizar Gestão Competitiva: obter dados relevantes para oferta de soluções aos clientes categorizados, segundo a Política Comercial dos Correios, como Ouro a Infinite, conforme as seguintes etapas:\na) identificar necessidades do cliente;\nb) mapear células de negócio:\nI - atribuir segmento de negócio às necessidades do cliente: correlacionar um segmento de negócio para cada necessidade do cliente identificada;\nII - identificar abrangência da célula: identificar a abrangência geográfica da necessidade (Local, Estadual, Nacional e Internacional);\nIII - valorar potencial da célula: identificar os valores despendidos pelos clientes com a necessidade correlacionada aos serviços dos Correios;\nIV - identificar concorrentes e participação, se houver: identificar empresas concorrentes que prestam serviços no cliente;\nV - mapear produtos enviados pelo cliente: identificar todos os produtos do cliente relacionados à necessidade;\nVI - selecionar produto dos Correios: selecionar produto/serviço dos Correios relacionados ao segmento de negócios identificado para atendimento à necessidade do cliente;\nVII - identificar se necessita customização: selecionar se a solução será customizada ou não;\nVIII - mapear fatores chaves de sucesso: identificar os fatores, sob a ótica do cliente, que determinam a concretização da negociação;\nIX - atribuir notas para todos os players para cada fator chave de sucesso: registrar as notas sob a ótica do cliente para cada player (Correios e concorrentes) em todos os fator chave de sucesso identificados;\nX - mapear barreiras de entrada: identificar fatores que impedem a participação nos negócios do cliente relacionados à sua necessidade;\nXI - atribuir grau de atratividade: analisar a célula e indicar grau de atratividade, considerando seu potencial de negócios.\nc) registrar oportunidades e ameaças:\nI - descrever oportunidades e ameaças: descrever de forma sucinta as oportunidades e ameaças identificadas (oportunidade: ocasião propícia para fechar negócios. Ameaça: risco de perda de algo conquistado);\nII - estimar datas de impacto e conclusão: inserir data em que a oportunidade ou ameaça foi detectada e a respectiva previsão de impacto;\nIII - avaliar existência de barreiras específicas: selecionar barreiras à concretização da oportunidade/mitigação da ameaça (barreiras: obstáculos a serem superados para adoção das medidas necessárias visando o atingimento dos objetivos desejados);\nIV - mapear valores e quantidades: estimar quantidade de objetos e receita relacionados à oportunidade/ameaça e selecionar a origem da oportunidade (concorrentes, estrutura do cliente, novos mercados e contratos de outros clientes) ou ameaça (contratos, à vista rede franqueada ou rede própria);\nd) cadastrar atividade no plano de ação de vendas: descrever a atividade a ser executada, relacionando ações estratégicas quando necessário;\ne) cadastrar ações planejadas: detalhar as ações que serão executadas, definindo datas de início e fim e responsáveis (matrícula).\n1.1.3.2 Submeter para análise de viabilidade: solicitar modelagem de solução customizada para as oportunidades de novos negócios com cliente ou prospect para atendimento às necessidades que não são atendidas por soluções do portfólio dos Correios.\n1.1.3.3 Efetuar negociação: enviar proposta comercial ao cliente, interagir com o cliente para esclarecimento da proposta, apresentação de contra argumentos às objeções, revisão da proposta apresentada com vista à conclusão da negociação.\n1.1.3.4 Registrar resultado da negociação: registrar o resultado da negociação no sistema de gestão de relacionamento com clientes.\n1.1.3.5 Identificar clientes com maior possibilidade de geração de negócio: priorizar aderência às estratégias de rentabilização de clientes Prata e Bronze definidas no plano de ações de vendas do varejo.\n1.1.3.6 Participar de campanha de incentivo a vendas: a força de vendas e gestores devem seguir o regulamento das campanhas e/ou ações de incentivo a vendas, ofertando soluções dos Correios para estarem aptos para premiações.\n1.1.4 Formalizar documento: formalizar instrumento contratual de acordo com a negociação com o cliente.\n1.1.5 Cadastrar contrato: realizar cadastro do contrato no ERP.\n1.1.6 Acompanhar início da prestação de serviço/ fornecimento do produto: a força de vendas deve garantir que no contrato do cliente estejam cadastrados os serviços/produtos negociados. \n* * * * *', 0),
(12179, 'anexo', 285, NULL, 1, '1', 'DETALHAMENTO DO PROCESSO ', '1.1 O processo de nível 2 da Cadeia de Valor dos Correios Definir atuação da força de vendas possui os seguintes processos.\n1.1.1 Reconhecer resultados de campanhas e ações de incentivo a vendas: promover a premiação aos empregados em reconhecimento dos resultados de campanhas e ações de incentivo a vendas, conforme regulamento publicado.\n1.1.2 Planejar atuação da força de vendas: definir moldes de atuação da força de vendas, a partir dos seguintes processos:\na) definir modelo de meritocracia: criar regras de acesso, ascensão e decesso da força de vendas com critérios que permitam a clareza e igualdade de condições aos empregados da empresa, por meio das seguintes etapas:\nI - consultar funções existentes;\nII - definir regras de ascensão e de decesso na carreira da força de vendas;\nIII - definir indicadores que serão avaliados no modelo de meritocracia;\nIV - definir método de avaliação.\nb) definir atividades da força de vendas: a partir da Política Comercial dos Correios, detalhar as atribuições definidas ao nível de atividade, considerando a natureza de atuação dos ocupantes das funções da força de vendas e especialistas de negócios logísticos/ internacionais;\nc) definir perfil da força de vendas: definir os Conhecimentos, Habilidades e Atitudes - CHA, grau de escolaridade, experiência e/ou outros requisitos necessários para atuação das funções;\nd) elaborar plano de capacitação: definir ações de educação e temas priorizados com objetivo de disseminar conhecimentos que contribuam para o desenvolvimento das competências necessárias para ocupantes das funções da força de vendas;\ne) elaborar plano de trabalho padrão: definir plano de trabalho padrão dos ocupantes das funções da força de vendas e sugerir o plano de trabalho dos respectivos gestores, apresentando as metas e competências a serem cumpridas no ciclo avaliativo do Gerenciamento de Competências e Resultados - GCR;\nf) definir critérios para composição de carteiras: definir critérios para inclusão de clientes na carteira de cada empregado da força de vendas;\ng) dimensionar força de venda: a partir da quantidade de clientes, definir o quantitativo de posição de funções da força de vendas necessário para realizar os processos de vendas e de relacionamento com o cliente, conforme Política Comercial dos Correios;\nh) definir modelo de acompanhamento de resultados: definir meios que permitam o acompanhamento sistemático dos resultados comerciais e de desempenho da força de vendas e suas respectivas supervisões/coordenações/gerências.\n1.1.3 Coordenar atuação da força de vendas: coordenar a execução da força de vendas sob sua gestão, conforme os seguintes processos:\na) monitorar execução de vendas: o gestor da força de vendas deve acompanhar sistematicamente resultados comerciais, conforme as ações e metodologia disponibilizadas no plano de ação de vendas;\nb) realizar avaliação de desempenho: o gestor da força de vendas deve avaliar as metas e competências da respectiva equipe de vendas, conforme plano de trabalho definido;\nc) compor carteira de clientes: o gestor da força de vendas deve avaliar a capacidade de atendimento da força de vendas e distribuir os clientes para sua equipe, conforme definição da área de planejamento de vendas;\nd) alocar força de vendas: preencher as posições de funções da força de vendas, conforme as seguintes etapas:\nI - aplicar modelo de meritocracia;\nII - identificar quantidade de funções vagas;\nIII - designar força de vendas habilitada pelo modelo de meritocracia;\nIV - solicitar processo de recrutamento e seleção para preenchimento das funções vagas, caso não tenham habilitados pelo modelo de meritocracia.\ne) aplicar modelo de incentivo a vendas: acompanhar campanhas/ações de incentivo a vendas, direcionando a equipe para o atingimento das metas de receita.\n \n* * * * *', 0),
(12180, 'anexo', 286, NULL, 1, '1', 'DETALHAMENTO DO PROCESSO', '', 0),
(12181, 'anexo', 286, NULL, 1, '1', 'O processo de nível 2 da Cadeia de Valor dos Correios Medir efetividade de vendas possui os seguintes processos.', '1.1. Acompanhamento da taxa de conversão de leads:\na) gerar informações: a área de planejamento de vendas deve acompanhar a quantidade de conversões de prospecção a partir do sistema de Prospecção de Negócios - PRONEG;\nb) disponibilizar para as áreas interessadas: a área de planejamento de vendas deve divulgar as informações da performance das conversões de prospecção para todos envolvidos no processo de prospecção;\nc) avaliar efetividade de conversão de leads: a área de planejamento de vendas deve monitorar a taxa de conversão com o objetivo de rever estratégias de prospecção.\n1.2 Acompanhamento de resultados comerciais:\n‘\na) obter informações dos clientes: a força de vendas deve identificar informações que justifiquem os resultados comerciais do cliente;\nb) identificar causas e contramedidas: a força de vendas deve analisar as informações obtidas junto ao cliente para detectar as causas da sua performance e quais as contramedidas que serão adotadas para recuperar a receita perdida;\nc) apresentar resultados, causas e contramedidas: os gestores da força de vendas devem consolidar as informações da sua equipe e realizar a apresentação dos resultados, causas e contramedidas aos órgãos superiores de gestão;\nd) análise conjunta de resultados: as áreas corporativas de vendas e atendimento devem avaliar as informações apresentadas pela Superintendência Estadual - SE;\ne) acompanhar execução de contramedidas: os gestores da força de vendas devem acompanhar e garantir o cumprimento das contramedidas estipuladas.\n1.3 Acompanhamento do plano de ação de vendas: os gestores da força de vendas devem acompanhar a execução das ações do plano de ação de vendas.\n* * * * *', 1),
(12182, 'anexo', 287, NULL, 1, '1', 'FLUXOS DE GERIR CLIENTES (NÍVEL 1)', '1.1 Fluxo Gerir Clientes (Nível 2)\n1.1.1 Fluxo Atender Demandas de Pós-vendas (Nível 3)\n1.1.2 Fluxo Gerir Contas (Nível 3)\n1.1.3 Fluxo Gerir Retenção de Clientes (Nível 3)\n* * * * *', 0),
(12183, 'anexo', 288, NULL, 1, '1', 'DETALHAMENTO DO PROCESSO', '1.1 O processo de nível 2 da Cadeia de Valor dos Correios gerir clientes possui os seguintes processos:\na) atender demandas de pós-vendas: atender demandas de pós-vendas dos clientes, por meio da Central de Atendimento ao Cliente ou da interação realizada junto ao gestor de relacionamento:\nI - atendimento por meio da Central de Atendimento ao Cliente - CAC: serão disponibilizados canais de atendimento ao cliente para recebimento, tratamento e indenização de manifestações;\nII - atendimento por meio dos gestores de relacionamento: os gestores responsáveis pelo atendimento ao cliente deverão avaliar/acompanhar as demandas de pós vendas relacionadas às questões tecnológicas, financeiras, operacionais, comerciais e administrativas.\nb) gerir contas: a gestão da conta do cliente é realizada, por meio do seu gestor de relacionamento, a partir dos seguintes processos:\nI - atualizar informações do cliente: inserir informações confiáveis e atualizadas nos sistemas de gestão do cliente;\nII - ajustar grupos de clientes: promover ajustes na composição e gestão dos grupos de cliente, por meio de transferência, agrupamento e exclusão de CNPJ;\nIII - monitorar faturamento do cliente: acompanhar sistemas de faturamento para verificar o cumprimento das contrapartidas contratadas e os resultados comerciais dos clientes sob sua gestão, analisando evolução ou declínio comparado ao mercado que ele está inserido, ao histórico de faturamento e à meta proposta.\nNota 1: a força de vendas deverá analisar o perfil da carga dos clientes sob sua gestão, identificando mudanças e respectivas causas, relacionando-as com os resultados financeiros, para compor diagnóstico que subsidie a tomada de decisões.\nNota 2: os gestores regionais devem monitorar mensalmente junto à força de vendas sob sua coordenação o acompanhamento da receita dos clientes e, em casos de variações relevantes de postagem (queda ou aumento), deverá ser validado junto ao cliente as razões dessas variações, emitindo alerta à área de operações e à área de segurança, quando necessário.\nNota 3: sempre que viável, deve ser priorizada a oferta de postagem nos centros operacionais aos clientes de mensagem com grandes volumes de postagens.\nc) gerir retenção de clientes: promover ações que visam a retenção do cliente a partir dos seguintes processos:\nI - monitorar o período de expiração contratual: atuar na renovação contratual, monitorando o período de expiração contratual, informando o cliente sobre os procedimentos para renovação e negociar a renovação do contrato\nII - mitigar ameaças: o gestor de relacionamento deve identificar ameaças de perda de receitas ou ruptura contratual e apresentar ao cliente argumentos de vendas, destacando as vantagens e benefícios dos Correios;\nIII - identificar oportunidade: o gestor de relacionamento deve monitorar a execução do contrato a fim de identificar potencial do cliente utilizar serviços/ produtos que ainda não utiliza, para posterior negociação.\n* * * * *', 0),
(12184, 'anexo', 289, NULL, 1, '1', 'FLUXO DE CRIAÇÃO DO GUIA DE ATUAÇÃO', '* * * * *', 0),
(12185, 'anexo', 290, NULL, 1, '1', 'DESCRIÇÃO DAS ATIVIDADES', '1.1 Descrever as atividades do gestor de relacionamento comercial Key Account Manager - KAM (Gestor de Grandes Contas responsável pelos clientes com categoria institucional Infinite):', 0),
(12186, 'anexo', 290, 12185, 4, 'a', 'acompanhar os clientes em visitas técnicas nos Correios;', '', 1),
(12187, 'anexo', 290, 12185, 4, 'b', 'acompanhar taxa de conversão das prospecções realizadas e resultados comerciais dos clientes sob sua gestão, analisando evolução ou declínio com relação ao mercado que ele está inserido, ao histórico de faturamento e à meta proposta;', '', 2),
(12188, 'anexo', 290, 12185, 4, 'c', 'apresentar proposta comercial aos clientes sob sua gestão e/ou prospects, conforme padrão disponibilizado pelas áreas competentes;', '', 3),
(12189, 'anexo', 290, 12185, 4, 'd', 'avaliar e propor ajustes das metas de vendas dos clientes sob sua gestão, quando aplicável;', '', 4),
(12190, 'anexo', 290, 12185, 4, 'e', 'conhecer regras atualizadas de produtos/serviços, cadeia produtiva dos Correios e dos clientes sob sua gestão;', '', 5),
(12191, 'anexo', 290, 12185, 4, 'f', 'direcionar demandas tecnológicas de 2º nível, que envolvem a utilização de sistemas/ferramentas providas pelos Correios, caso não tenha sido solucionada em 1º nível nas ações negociais;', '', 6),
(12192, 'anexo', 290, 12185, 4, 'g', 'elaborar contramedidas a partir de causas identificadas de desvio negativo, com o objetivo de atingir as metas de receitas estabelecidas;', '', 7),
(12193, 'anexo', 290, 12185, 4, 'h', 'elaborar e executar o plano de ação com o objetivo de atingir as metas estabelecidas no plano de vendas e/ou outras oportunidades identificadas;', '', 8),
(12194, 'anexo', 290, 12185, 4, 'i', 'elaborar e realizar apresentações personalizadas de acordo com as necessidades dos clientes;', '', 9),
(12195, 'anexo', 290, 12185, 4, 'j', 'elaborar relatórios e/ou diagnósticos diversos dos clientes sob sua gestão relacionados ao desempenho comercial;', '', 10),
(12196, 'anexo', 290, 12185, 4, 'k', 'encaminhar dúvidas sobre processos e regras de negócios dos produtos relacionadas para formatadores, quando a informação não for localizada nos repositórios de informações;', '', 11),
(12197, 'anexo', 290, 12185, 4, 'l', 'executar ações de vendas visando ao incremento e geração de novas receitas, prospecção de novos negócios, prospecção de novos clientes, manutenção e satisfação do cliente, a partir do plano de vendas e potencial do cliente;', '', 12),
(12198, 'anexo', 290, 12185, 4, 'm', 'identificar datas comemorativas de clientes sob sua gestão, promovendo produtos de conveniência, realizando network, fortalecendo imagem Correios x Cliente, dentre outros;', '', 13),
(12199, 'anexo', 290, 12185, 4, 'n', 'identificar e avaliar os indicadores de desempenho dos clientes sob sua gestão e/ou Key Performance Indicators - KPI, sob a ótica do mercado, visando subsidiar a alta direção dos Correios na tomada de decisões;', '', 14),
(12200, 'anexo', 290, 12185, 4, 'o', 'interagir com as áreas para a implantação de novos serviços e produtos, direcionando a demanda para acompanhamento do Key Account Desk - KAD quando a utilização do serviço for iniciada;', '', 15),
(12201, 'anexo', 290, 12185, 4, 'p', 'manter atualizadas as informações dos leads e prospects em sistema/ferramenta para gestão da prospecção;', '', 16),
(12202, 'anexo', 290, 12185, 4, 'q', 'manter relacionamento com as áreas do cliente que tenham os Correios na condição de contratado;', '', 17),
(12203, 'anexo', 290, 12185, 4, 'r', 'orientar os clientes sob sua gestão acerca dos canais de atendimento das demandas administrativas contratuais (contrato/termos aditivos/apostilamento), monitorando a conclusão da demanda pelas áreas responsáveis;', '', 18),
(12204, 'anexo', 290, 12185, 4, 's', 'participar de eventos relacionados ao mercado do cliente, para manter-se atualizado às tendências e atuação da concorrência, buscando as melhores oportunidades de negócio;', '', 19),
(12205, 'anexo', 290, 12185, 4, 't', 'participar e/ou promover reuniões com os clientes, assistente comercial de tecnologia, assistente de comércio exterior e/ou áreas dos Correios a fim de realizar pontos de controle sobre indicadores de desempenho dos clientes e demandas apresentadas, com proposição de melhorias e o devido registro em ata;', '', 20),
(12206, 'anexo', 290, 12185, 4, 'u', 'prestar informações das regras de negócios dos Correios, de produtos e serviços do portfólio da Empresa para os clientes sob sua gestão;', '', 21),
(12207, 'anexo', 290, 12185, 4, 'v', 'promover ações que visam ampliar os níveis de acesso e fortalecimento da relação com o cliente e conquistas de novos negócios, por meio de eventos patrocinados ou organizados pelos Correios, entrega de materiais de relacionamento, dentre outros;', '', 22),
(12208, 'anexo', 290, 12185, 4, 'w', 'promover/participar de reuniões com os clientes sob sua gestão, para tratativas/esclarecimentos a respeito dos aspectos operacionais e/ou proposição de melhorias, solicitando a participação do Key Account Desk - KAD e/ou Especialista em Operações, quando necessário;', '', 23),
(12209, 'anexo', 290, 12185, 4, 'x', 'propor e participar, quando for o caso, das melhorias dos processos internos dos Correios aplicáveis aos clientes sob sua gestão, considerando o desempenho financeiro, jornada e experiência do cliente, dentre outros fatores;', '', 24),
(12210, 'anexo', 290, 12185, 4, 'y', 'propor negócios customizados ao cliente, alinhados às estratégias e diretrizes da área de vendas, visando atender necessidades que não são supridas pelos serviços de prateleira dos Correios, com o respectivo acompanhamento do andamento do processo;', '', 25),
(12211, 'anexo', 290, 12185, 4, 'z', 'monitorar o faturamento do cliente visando assegurar a utilização do valor mínimo do pacote contratado, promovendo interações junto ao cliente para ajuste no pacote contratado, quando necessário;', 'aa) realizar a gestão competitiva dos clientes sob sua gestão, por meio da coleta de informações (matriz SWOT, identificação de fatores-chaves de sucesso, segmento de atuação, atuação de concorrentes, potencial de mercado, balancetes financeiros, quarters reporters, investimentos, dentre outros), registrando e mantendo as informações atualizadas nos sistemas corporativos dos Correios ou outras ferramentas disponibilizadas para gestão do cliente;\nbb) realizar atendimento de 1º nível para demandas tecnológicas, prestando informações para clientes sob sua gestão nas ações negociais sobre: características e funcionalidades dos sistemas/ferramentas, links de acesso, obtenção de usuário e senha e local de disponibilização de manuais;\ncc) realizar tratativas junto ao cliente nos processos de negociação para contratação/renovação de contratos/termos aditivos/apostilamentos, conforme procedimentos geridos pela área de apoio a vendas, acompanhando a geração da minuta contratual;\ndd) registrar e manter atualizadas as informações dos clientes sob sua gestão nos sistemas corporativos dos Correios ou em outras ferramentas disponibilizadas para gestão do cliente;\nee) representar os Correios em reuniões, encontros de negócios, palestras, workshops sobre assuntos referentes aos clientes sob sua gestão, registrando as informações conforme orientações da área de vendas;\nff) representar os Correios nas reuniões com a área de tecnologia dos clientes para esclarecimento de dúvidas ou internalização para posterior resposta.\n1.2 Descrever as atividades do gestor de relacionamento comercial Key Account Desk - KAD (Gestor de Contas Backoffice responsável pelos clientes com categoria institucional Infinite):', 26),
(12212, 'anexo', 290, 12185, 4, 'a', 'acompanhar os clientes em visitas técnicas nos Correios, solicitando a participação do Especialista em Operações, quando necessário;', '', 27),
(12213, 'anexo', 290, 12185, 4, 'b', 'analisar o perfil da carga dos clientes sob sua gestão, identificando mudanças e respectivas causas, relacionando-as com os resultados financeiros, para compor diagnóstico que subsidie a tomada de decisões;', '', 28),
(12214, 'anexo', 290, 12185, 4, 'c', 'apoiar o atendimento das demandas administrativas diversas, tais como, solucionar erros de cadastro (código de serviço, unidade de vinculação, número de cartão de postagem), atender as solicitações referentes aos cartões de postagem e malotes, entre outras, encaminhando e acompanhando o atendimento ao cliente junto à área responsável;', '', 29),
(12215, 'anexo', 290, 12185, 4, 'd', 'atender demandas financeiras do cliente, informando os canais de atendimento disponíveis para questões fora da sua alçada de atuação;', '', 30),
(12216, 'anexo', 290, 12185, 4, 'e', 'bloquear objetos para a entrega por meio do sistema SEIN, quando o cliente não conseguir efetuar o cancelamento no sistema;', '', 31),
(12217, 'anexo', 290, 12185, 4, 'f', 'comunicar aos clientes alterações e ocorrências que impactam no processo operacional, tais como: alterações de endereço e local de postagem dos objetos; atualização dos planos de triagem, dentre outros;', '', 32),
(12218, 'anexo', 290, 12185, 4, 'g', 'comunicar as informações que impactem os negócios do clientes;', '', 33),
(12219, 'anexo', 290, 12185, 4, 'h', 'conhecer regras atualizadas de produtos/serviços, cadeia produtiva dos Correios e dos clientes sob sua gestão;', '', 34),
(12220, 'anexo', 290, 12185, 4, 'i', 'contribuir na elaboração de contramedidas dos clientes sob sua gestão, a partir de causas identificadas de desvio negativo, com o objetivo de atingir as metas de receitas estabelecidas;', '', 35),
(12221, 'anexo', 290, 12185, 4, 'j', 'contribuir na elaboração do plano de ação a partir de causas identificadas ou do plano de vendas, com o objetivo de atingir as metas de receitas estabelecidas;', '', 36),
(12222, 'anexo', 290, 12185, 4, 'k', 'direcionar as demandas de viabilidade e implantação de serviços ao Especialista em Operações, realizando o acompanhamento e respectiva notificação ao cliente, quando for o caso;', '', 37),
(12223, 'anexo', 290, 12185, 4, 'l', 'direcionar e monitorar as demandas apresentadas pelos clientes sob sua gestão, referentes a suprimentos de insumos operacionais, fornecimento de formulário AR e etiquetas, regularização de arquivos de postagem, coletas, corte de carga, carga retida, não entrega de objetos, devolução de AR, dentre outras;', '', 38),
(12224, 'anexo', 290, 12185, 4, 'm', 'direcionar demandas tecnológicas de 2º nível, que envolvem a utilização de sistemas/ferramentas providas pelos Correios, caso não tenha sido solucionada em 1º nível nas ações de pós-vendas;', '', 39),
(12225, 'anexo', 290, 12185, 4, 'n', 'direcionar necessidades identificadas nos clientes sob sua gestão sobre demandas administrativas, financeiras e operacionais para as áreas internas dos Correios, adotando os procedimentos de formalização conforme orientação da área de vendas e suporte a vendas, acompanhando para que o atendimento seja realizado de forma tempestiva;', '', 40),
(12226, 'anexo', 290, 12185, 4, 'o', 'disponibilizar esclarecimentos/informações ao Especialista em Operações sobre os contratos, intermediando o diálogo entre as áreas e o cliente;', '', 41),
(12227, 'anexo', 290, 12185, 4, 'p', 'elaborar relatórios e/ou diagnósticos diversos dos clientes sob sua gestão, exceto àqueles relacionados ao desempenho comercial;', '', 42),
(12228, 'anexo', 290, 12185, 4, 'q', 'informar ao Especialista em Operações sobre operações pontuais, especiais ou promocionais realizadas pelos clientes sob sua gestão, com indicação do volume, data e duração previstos, para garantir a viabilidade operacional;', '', 43),
(12229, 'anexo', 290, 12185, 4, 'r', 'interagir com as áreas responsáveis para esclarecimento de dúvidas sobre os procedimentos operacionais dos clientes sob sua gestão, com o respectivo retorno ao cliente;', '', 44),
(12230, 'anexo', 290, 12185, 4, 's', 'monitorar a qualidade operacional dos Correios e nível de serviço dos clientes sob sua gestão, direcionando as inconsistências operacionais identificadas para a área de operações;', '', 45),
(12231, 'anexo', 290, 12185, 4, 't', 'orientar o cliente para realização de rastreamento em lote por meio do sistema SRO;', '', 46),
(12232, 'anexo', 290, 12185, 4, 'u', 'orientar os clientes sobre débitos em aberto para evitar a interrupção da prestação dos serviços contratados devido à suspensão contratual por inadimplência;', '', 47),
(12233, 'anexo', 290, 12185, 4, 'v', 'participar e/ou promover reuniões com os clientes, assistente comercial de tecnologia, assistente de comércio exterior e/ou áreas dos Correios a fim de realizar pontos de controle sobre indicadores de desempenho dos clientes e demandas apresentadas, com proposição de melhorias e o devido registro em ata;', '', 48),
(12234, 'anexo', 290, 12185, 4, 'w', 'prestar informações ao cliente com contrato sobre o atendimento das demandas administrativas, tais como: canais de atendimento para acesso a sistemas/ferramentas, geração de etiquetas, utilização do SEI, contrato, renovação contratual, entre outros;', '', 49),
(12235, 'anexo', 290, 12185, 4, 'x', 'prestar informações às áreas demandantes dos Correios, relativas aos segmentos de mercado, nos quais estão inseridos os clientes sob sua gestão;', '', 50),
(12236, 'anexo', 290, 12185, 4, 'y', 'prestar informações das regras de negócios dos Correios, de produtos e serviços do portfólio da Empresa para os clientes sob sua gestão;', '', 51),
(12237, 'anexo', 290, 12185, 4, 'z', 'prestar orientações aos clientes nos casos de classificação de objetos, layouts de listas de postagem e arquivos de pré-postagem, dentre outros;', 'aa) promover/participar de reuniões com os clientes sob sua gestão, para tratativas/esclarecimentos a respeito dos aspectos operacionais e/ou proposição de melhorias, quando necessário;\nbb) propor e participar, quando for o caso, das melhorias dos processos internos dos Correios aplicáveis aos clientes sob sua gestão, considerando o desempenho financeiro, jornada e experiência do cliente, dentre outros fatores;\ncc) realizar a Avaliação Técnica Comercial - ATC e direcionar a atividade de validação da Avaliação Técnica Operacional - ATO para o Especialista em Operações, acompanhando o resultado da homologação;\ndd) realizar análise das indenizações pagas aos clientes sob sua gestão, identificando as unidades ofensoras para atuação das áreas responsáveis;\nee) realizar apoio administrativo para as demandas negociais nas ações de rentabilização ou prospecção de clientes;\nff) realizar atendimento de 1º nível para demandas tecnológicas, prestando informações para clientes sob sua gestão nas ações de pós-vendas sobre: características e funcionalidades dos sistemas/ferramentas, links de acesso, obtenção de usuário e senha e local de disponibilização de manuais;\ngg) realizar contato, quando necessário, com os fornecedores dos clientes sob sua gestão (gráficas, agências de publicidade, dentre outros), para esclarecer dúvidas, propor melhorias, dar ciência de inconformidades nas postagens, dentre outras necessidades que possam surgir;\nhh) receber as demandas de abertura de PI extemporâneo e indenizações por fraude de remessa expressa, instruir o processo SEI e encaminhar para a área responsável, com acompanhamento para posicionamento ao cliente;\nii) registrar e manter atualizadas as informações dos clientes sob sua gestão nos sistemas corporativos dos Correios ou em outras ferramentas disponibilizadas para gestão do cliente;\njj) solicitar para a área de apoio a vendas a geração de usuário e senha nos sistemas/ferramentas, para produtos e serviços implantados.\n1.3 Descrever as atividades do gestor de relacionamento comercial Key Account Manager - KAM (Gestor de Grandes Contas responsável pelos clientes com categoria institucional Diamante):', 52),
(12238, 'anexo', 290, 12185, 4, 'a', 'acompanhar os clientes em visitas técnicas nos Correios, centros operacionais, dentre outros;', '', 53),
(12239, 'anexo', 290, 12185, 4, 'b', 'acompanhar taxa de conversão das prospecções realizadas e resultados comerciais dos clientes sob sua gestão, analisando evolução ou declínio com relação ao mercado que ele está inserido, ao histórico de faturamento e à meta proposta;', '', 54),
(12240, 'anexo', 290, 12185, 4, 'c', 'apresentar proposta comercial aos clientes sob sua gestão e/ou prospects, conforme padrão disponibilizado pelas áreas competentes;', '', 55),
(12241, 'anexo', 290, 12185, 4, 'd', 'avaliar e propor ajustes das metas de vendas dos clientes sob sua gestão, quando aplicável;', '', 56),
(12242, 'anexo', 290, 12185, 4, 'e', 'direcionar demandas tecnológicas de 2º nível, que envolvem a utilização de sistemas/ferramentas providas pelos Correios, caso não tenha sido solucionada em 1º nível nas ações negociais;', '', 57),
(12243, 'anexo', 290, 12185, 4, 'f', 'elaborar contramedidas a partir de causas identificadas de desvio negativo, com o objetivo de atingir as metas de receitas estabelecidas;', '', 58),
(12244, 'anexo', 290, 12185, 4, 'g', 'elaborar e executar o plano de ação com o objetivo de atingir as metas estabelecidas no plano de vendas e/ou outras oportunidades identificadas;', '', 59),
(12245, 'anexo', 290, 12185, 4, 'h', 'elaborar e realizar apresentações personalizadas de acordo com as necessidades dos clientes;', '', 60),
(12246, 'anexo', 290, 12185, 4, 'i', 'elaborar relatórios e/ou diagnósticos diversos dos clientes sob sua gestão relacionados ao desempenho comercial;', '', 61),
(12247, 'anexo', 290, 12185, 4, 'j', 'encaminhar dúvidas sobre processos e regras de negócios dos produtos relacionadas para formatadores, quando a informação não for localizada nos repositórios de informações;', '', 62),
(12248, 'anexo', 290, 12185, 4, 'k', 'executar ações de vendas visando ao incremento e geração de novas receitas, prospecção de novos negócios, prospecção de novos clientes, manutenção e satisfação do cliente, a partir do plano de vendas e potencial do cliente;', '', 63),
(12249, 'anexo', 290, 12185, 4, 'l', 'identificar datas comemorativas de clientes sob sua gestão, promovendo produtos de conveniência, realizando network, fortalecendo imagem Correios x Cliente, dentre outros;', '', 64),
(12250, 'anexo', 290, 12185, 4, 'm', 'identificar e avaliar os indicadores de desempenho dos clientes sob sua gestão e/ou Key Performance Indicators - KPI, sob a ótica do mercado, visando subsidiar a alta direção dos Correios na tomada de decisões;', '', 65),
(12251, 'anexo', 290, 12185, 4, 'n', 'interagir com as áreas para a implantação de novos serviços e produtos, direcionando a demanda para acompanhamento do Key Account Desk - KAD quando a utilização do serviço for iniciada;', '', 66),
(12252, 'anexo', 290, 12185, 4, 'o', 'manter atualizadas as informações dos leads e prospects em sistema/ferramenta para gestão da prospecção;', '', 67),
(12253, 'anexo', 290, 12185, 4, 'p', 'manter relacionamento com as áreas do cliente que tenham os Correios na condição de contratado;', '', 68),
(12254, 'anexo', 290, 12185, 4, 'q', 'orientar os clientes sob sua gestão acerca dos canais de atendimento das demandas administrativas contratuais (contrato/termos aditivos/apostilamento), monitorando a conclusão da demanda pelas áreas responsáveis;', '', 69),
(12255, 'anexo', 290, 12185, 4, 'r', 'monitorar o faturamento do cliente visando assegurar a utilização do valor mínimo do pacote contratado, promovendo interações junto ao cliente para ajuste no pacote contratado, quando necessário;', '', 70),
(12256, 'anexo', 290, 12185, 4, 's', 'participar de eventos relacionados ao mercado do cliente, para manter-se atualizado às tendências e atuação da concorrência, buscando as melhores oportunidades de negócio;', '', 71),
(12257, 'anexo', 290, 12185, 4, 't', 'participar e/ou promover reuniões com os clientes, assistente comercial de tecnologia, assistente de comércio exterior e/ou áreas dos Correios a fim de realizar pontos de controle sobre indicadores de desempenho dos clientes e demandas apresentadas, com proposição de melhorias e o devido registro em ata;', '', 72),
(12258, 'anexo', 290, 12185, 4, 'u', 'prestar informações aos prospects sobre os procedimentos para efetivação do contrato comercial;', '', 73),
(12259, 'anexo', 290, 12185, 4, 'v', 'prestar informações às áreas demandantes dos Correios, relativas aos segmentos de mercado, nos quais estão inseridos os clientes sob sua gestão;', '', 74),
(12260, 'anexo', 290, 12185, 4, 'w', 'prestar informações das regras de negócios dos Correios, de produtos e serviços do portfólio da Empresa para os clientes sob sua gestão;', '', 75),
(12261, 'anexo', 290, 12185, 4, 'x', 'promover ações que visam ampliar os níveis de acesso e fortalecimento da relação com o cliente e conquistas de novos negócios, por meio de eventos patrocinados ou organizados pelos Correios, entrega de materiais de relacionamento, dentre outros;', '', 76),
