(12287, 'anexo', 290, 12185, 4, 'x', 'promover/participar de reuniões com os clientes sob sua gestão, para tratativas/esclarecimentos a respeito dos aspectos operacionais e/ou proposição de melhorias, quando necessário;', '', 102),
(12288, 'anexo', 290, 12185, 4, 'y', 'propor e participar, quando for o caso, das melhorias dos processos internos dos Correios aplicáveis aos clientes sob sua gestão, considerando o desempenho financeiro, jornada e experiência do cliente, dentre outros fatores;', '', 103),
(12289, 'anexo', 290, 12185, 4, 'z', 'realizar análise das indenizações pagas aos clientes sob sua gestão, identificando as unidades ofensoras para atuação das áreas responsáveis;', 'aa) realizar apoio administrativo para as demandas negociais nas ações de rentabilização ou prospecção de clientes;\nbb) realizar atendimento de 1º nível para demandas tecnológicas, prestando informações para clientes sob sua gestão nas ações de pós-vendas sobre: características e funcionalidades dos sistemas/ferramentas, links de acesso, obtenção de usuário e senha e local de disponibilização de manuais;\ncc) realizar contato, quando necessário, com os fornecedores dos clientes sob sua gestão (gráficas, agências de publicidade, dentre outros), para esclarecer dúvidas, propor melhorias, dar ciência de inconformidades nas postagens, dentre outras necessidades que possam surgir;\ndd) receber as demandas de abertura de PI extemporâneo e indenizações por fraude de remessa expressa, instruir o processo SEI e encaminhar para a área responsável, com acompanhamento para posicionamento ao cliente;\nee) registrar e manter atualizadas as informações dos clientes sob sua gestão nos sistemas corporativos dos Correios ou em outras ferramentas disponibilizadas para gestão do cliente;\nff) solicitar para a área de apoio a vendas a geração de usuário e senha nos sistemas/ferramentas, para produtos e serviços implantados.\n1.5 Descrever as atividades do gestor de relacionamento comercial responsável pelos clientes com categoria institucional Platinum e Ouro):', 104),
(12290, 'anexo', 290, 12185, 4, 'a', 'acompanhar os clientes em visitas técnicas nos Correios;', '', 105),
(12291, 'anexo', 290, 12185, 4, 'b', 'acompanhar taxa de conversão das prospecções realizadas e resultados comerciais dos clientes sob sua gestão, analisando evolução ou declínio com relação ao mercado que ele está inserido, ao histórico de faturamento e à meta proposta;', '', 106),
(12292, 'anexo', 290, 12185, 4, 'c', 'analisar o perfil da carga dos clientes sob sua gestão, identificando mudanças e respectivas causas, relacionando-as com os resultados financeiros, para compor diagnóstico que subsidie a tomada de decisões;', '', 107),
(12293, 'anexo', 290, 12185, 4, 'd', 'apoiar o atendimento das demandas administrativas diversas, tais como, solucionar erros de cadastro (código de serviço, unidade de vinculação, número de cartão de postagem), atender as solicitações referentes aos cartões de postagem e malotes, entre outras, encaminhando e acompanhando o atendimento ao cliente junto à área responsável;', '', 108),
(12294, 'anexo', 290, 12185, 4, 'e', 'apoiar tecnicamente na preparação e homologação de arquivos de faturamento, arquivo/lista de previsão de postagem, realizar o atesto na Avaliação Técnica Comercial -ATC e acompanhar validação da Avaliação Técnica Operacional - ATO pela Operação, realizar a análise de classificação de objetos, dentre outros;', '', 109),
(12295, 'anexo', 290, 12185, 4, 'f', 'apresentar proposta comercial aos clientes sob sua gestão e/ou prospects, conforme padrão disponibilizado pelas áreas competentes;', '', 110),
(12296, 'anexo', 290, 12185, 4, 'g', 'atender demandas financeiras do cliente, informando os canais de atendimento disponíveis para questões fora da sua alçada de atuação;', '', 111),
(12297, 'anexo', 290, 12185, 4, 'h', 'avaliar e propor ajustes das metas de vendas dos clientes sob sua gestão, quando aplicável;', '', 112),
(12298, 'anexo', 290, 12185, 4, 'i', 'bloquear objetos para a entrega por meio do sistema SEIN, quando o cliente não conseguir efetuar o cancelamento no sistema;', '', 113),
(12299, 'anexo', 290, 12185, 4, 'j', 'comunicar aos clientes alterações e ocorrências que impactam no processo operacional, tais como: alterações de endereço e local de postagem dos objetos; atualização dos planos de triagem, dentre outros;', '', 114),
(12300, 'anexo', 290, 12185, 4, 'k', 'comunicar as informações que impactem os negócios do clientes;', '', 115),
(12301, 'anexo', 290, 12185, 4, 'l', 'conhecer regras atualizadas de produtos/serviços, cadeia produtiva dos Correios e dos clientes sob sua gestão;', '', 116),
(12302, 'anexo', 290, 12185, 4, 'm', 'direcionar e monitorar as demandas apresentadas pelos clientes sob sua gestão, referentes a suprimentos de insumos operacionais, fornecimento de formulário AR e etiquetas, regularização de arquivos de postagem, coletas, corte de carga, carga retida, não entrega de objetos, devolução de Aviso de Recebimento - AR, dentre outras;', '', 117);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(12303, 'anexo', 290, 12185, 4, 'n', 'direcionar demandas tecnológicas de 2º nível, que envolvem a utilização de sistemas/ferramentas providas pelos Correios, caso não tenha sido solucionada em 1º nível nas ações negociais e de pós vendas;', '', 118),
(12304, 'anexo', 290, 12185, 4, 'o', 'direcionar necessidades identificadas nos clientes sob sua gestão sobre demandas administrativas, financeiras e operacionais para as áreas internas dos Correios, adotando os procedimentos de formalização conforme orientação da área de vendas e suporte a vendas, acompanhando para que o atendimento seja realizado de forma tempestiva;', '', 119),
(12305, 'anexo', 290, 12185, 4, 'p', 'elaborar contramedidas a partir de causas identificadas de desvio negativo, com o objetivo de atingir as metas de receitas estabelecidas;', '', 120),
(12306, 'anexo', 290, 12185, 4, 'q', 'elaborar e executar o plano de ação com o objetivo de atingir as metas estabelecidas no plano de vendas e/ou outras oportunidades identificadas;', '', 121),
(12307, 'anexo', 290, 12185, 4, 'r', 'elaborar e realizar apresentações personalizadas de acordo com as necessidades dos clientes;', '', 122),
(12308, 'anexo', 290, 12185, 4, 's', 'elaborar relatórios e/ou diagnósticos diversos dos clientes sob sua gestão;', '', 123),
(12309, 'anexo', 290, 12185, 4, 't', 'encaminhar dúvidas sobre processos e regras de negócios dos produtos relacionadas para formatadores, quando a informação não for localizada nos repositórios de informações;', '', 124),
(12310, 'anexo', 290, 12185, 4, 'u', 'executar ações de vendas visando ao incremento e geração de novas receitas, prospecção de novos negócios, prospecção de novos clientes, manutenção e satisfação do cliente, a partir do plano de vendas e potencial do cliente;', '', 125),
(12311, 'anexo', 290, 12185, 4, 'v', 'identificar datas comemorativas de clientes sob sua gestão, promovendo produtos de conveniência, realizando network, fortalecendo imagem Correios x Cliente, dentre outros;', '', 126),
(12312, 'anexo', 290, 12185, 4, 'w', 'identificar e avaliar os indicadores de desempenho dos clientes sob sua gestão e/ou Key Performance Indicators - KPI, sob a ótica do mercado, visando subsidiar a alta direção dos Correios na tomada de decisões;', '', 127),
(12313, 'anexo', 290, 12185, 4, 'x', 'interagir com as áreas para a implantação de novos serviços e produtos;', '', 128),
(12314, 'anexo', 290, 12185, 4, 'y', 'interagir com as áreas responsáveis para esclarecimento de dúvidas sobre os procedimentos operacionais dos clientes sob sua gestão, com o respectivo retorno ao cliente;', '', 129),
(12315, 'anexo', 290, 12185, 4, 'z', 'manter atualizadas as informações dos leads e prospects em sistema/ferramenta para gestão da prospecção;', 'aa) manter relacionamento com as áreas do cliente que tenham os Correios na condição de contratado;\nbb) monitorar a qualidade operacional dos Correios e nível de serviço dos clientes sob sua gestão, direcionando as inconsistências operacionais identificadas para a área de operações;\ncc) monitorar o faturamento do cliente visando assegurar a utilização do valor mínimo do pacote contratado, promovendo interações junto ao cliente para ajuste no pacote contratado, quando necessário;\ndd)  orientar o cliente para realização de rastreamento em lote por meio do sistema SRO;\nee) orientar os clientes sob sua gestão acerca dos canais de atendimento das demandas administrativas contratuais (contrato/termos aditivos/apostilamento), monitorando a conclusão da demanda pelas áreas responsáveis;\nff) orientar os clientes sobre débitos em aberto para evitar a interrupção da prestação dos serviços contratados devido à suspensão contratual por inadimplência;\ngg) participar de eventos relacionados ao mercado do cliente, para manter-se atualizado às tendências e atuação da concorrência, buscando as melhores oportunidades de negócio;\nhh) participar e/ou promover reuniões com os clientes, assistente comercial de tecnologia, assistente de comércio exterior e/ou áreas dos Correios a fim de realizar pontos de controle sobre indicadores de desempenho dos clientes e demandas apresentadas, com proposição de melhorias e o devido registro em ata;\nii) prestar informações ao cliente com contrato sobre o atendimento das demandas administrativas, tais como: canais de atendimento para acesso a sistemas/ferramentas, geração de etiquetas, utilização do SEI, contrato, renovação contratual, entre outros;\njj) prestar informações aos prospects sobre os procedimentos para efetivação do contrato comercial;\nkk) prestar informações às áreas demandantes dos Correios, relativas aos segmentos de mercado, nos quais estão inseridos os clientes sob sua gestão;\nll) prestar informações das regras de negócios dos Correios, de produtos e serviços do portfólio da Empresa para os clientes sob sua gestão;\nmm) prestar orientações aos clientes nos casos de classificação de objetos, layouts de listas de postagem e arquivos de pré-postagem, dentre outros;\nnn) promover ações que visam ampliar os níveis de acesso e fortalecimento da relação com o cliente e conquistas de novos negócios, por meio de eventos patrocinados ou organizados pelos Correios, entrega de materiais de relacionamento, dentre outros;\noo) propor e participar, quando for o caso, das melhorias dos processos internos dos Correios aplicáveis aos clientes sob sua gestão, considerando o desempenho financeiro, jornada e experiência do cliente, dentre outros fatores;\npp) propor negócios customizados ao cliente, alinhados às estratégias e diretrizes da área de vendas, visando atender necessidades que não são supridas pelos serviços de prateleira dos Correios, com o respectivo acompanhamento do andamento do processo;\nqq) realizar a gestão competitiva dos clientes sob sua gestão, por meio da coleta de informações (matriz SWOT, identificação de fatores-chaves de sucesso, segmento de atuação, atuação de concorrentes, potencial de mercado, balancetes financeiros, quarters reporters, investimentos, dentre outros), registrando e mantendo as informações atualizadas nos sistemas corporativos dos Correios ou outras ferramentas disponibilizadas para gestão do cliente;\nrr) realizar atendimento de 1º nível para demandas tecnológicas, prestando informações para ações negociais e de pós-vendas: características e funcionalidades dos sistemas/ferramentas, links de acesso, obtenção de usuário e senha e local de disponibilização de manuais;\nss) realizar contato, quando necessário, com os fornecedores dos clientes sob sua gestão (gráficas, agências de publicidade, dentre outros), para esclarecer dúvidas, propor melhorias, dar ciência de inconformidades nas postagens, dentre outras necessidades que possam surgir;\ntt) realizar tratativas junto ao cliente nos processos de negociação para contratação/renovação de contratos/termos aditivos/apostilamentos, conforme procedimentos geridos pela área de apoio a vendas, acompanhando a geração da minuta contratual;\nuu) receber as demandas de abertura de PI extemporâneo e indenizações por fraude de remessa expressa, instruir o processo SEI e encaminhar para a área responsável, com acompanhamento para posicionamento ao cliente;\nvv) registrar e manter atualizadas as informações dos clientes sob sua gestão nos sistemas corporativos dos Correios ou em outras ferramentas disponibilizadas para gestão do cliente;\nww) representar os Correios em reuniões, encontros de negócios, palestras, workshops sobre assuntos referentes aos clientes sob sua gestão, registrando as informações conforme orientações da área de vendas;\nxx) representar os Correios nas reuniões com a área de tecnologia dos clientes para esclarecimento de dúvidas ou internalização para posterior resposta;\nyy) solicitar para a área de apoio a vendas a geração de usuário e senha nos sistemas/ferramentas, para produtos e serviços implantados.\n1.6 Descrever as atividades do gestor de relacionamento comercial responsável pelas demais categorias institucionais):', 130),
(12316, 'anexo', 290, 12185, 4, 'a', 'acompanhar taxa de conversão das prospecções realizadas e resultados comerciais dos clientes sob sua gestão, analisando evolução ou declínio com relação ao mercado que ele está inserido, ao histórico de faturamento e à meta proposta;', '', 131),
(12317, 'anexo', 290, 12185, 4, 'b', 'apoiar o atendimento das demandas administrativas diversas, tais como, solucionar erros de cadastro (código de serviço, unidade de vinculação, número de cartão de postagem), atender as solicitações referentes aos cartões de postagem e malotes, entre outras, encaminhando e acompanhando o atendimento ao cliente junto à área responsável;', '', 132),
(12318, 'anexo', 290, 12185, 4, 'c', 'apresentar proposta comercial aos clientes sob sua gestão e/ou prospects, conforme padrão disponibilizado pelas áreas competentes;', '', 133),
(12319, 'anexo', 290, 12185, 4, 'd', 'atender demandas financeiras do cliente, informando os canais de atendimento disponíveis para questões fora da sua alçada de atuação;', '', 134),
(12320, 'anexo', 290, 12185, 4, 'e', 'avaliar e propor ajustes das metas de vendas dos clientes sob sua gestão, quando aplicável;', '', 135),
(12321, 'anexo', 290, 12185, 4, 'f', 'bloquear objetos para a entrega por meio do sistema SEIN, quando o cliente não conseguir efetuar o cancelamento no sistema;', '', 136),
(12322, 'anexo', 290, 12185, 4, 'g', 'comunicar aos clientes alterações e ocorrências que impactam no processo operacional, tais como: alterações de endereço e local de postagem dos objetos; atualização dos planos de triagem, dentre outros;', '', 137),
(12323, 'anexo', 290, 12185, 4, 'h', 'comunicar as informações que impactem os negócios do clientes;', '', 138),
(12324, 'anexo', 290, 12185, 4, 'i', 'conhecer regras atualizadas de produtos/serviços, cadeia produtiva dos Correios e dos clientes sob sua gestão;', '', 139),
(12325, 'anexo', 290, 12185, 4, 'j', 'direcionar demandas tecnológicas de 2º nível, que envolvem a utilização de sistemas/ferramentas providas pelos Correios, caso não tenha sido solucionada em 1º nível nas ações negociais e de pós vendas;', '', 140),
(12326, 'anexo', 290, 12185, 4, 'k', 'direcionar necessidades identificadas nos clientes sob sua gestão sobre demandas administrativas, financeiras e operacionais para as áreas internas dos Correios, adotando os procedimentos de formalização conforme orientação da área de vendas e suporte a vendas, acompanhando para que o atendimento seja realizado de forma tempestiva;', '', 141),
(12327, 'anexo', 290, 12185, 4, 'l', 'direcionar negociações customizadas para a força de vendas da SE de localização do CNPJ nas ações de prospecção de novos clientes;', '', 142),
(12328, 'anexo', 290, 12185, 4, 'm', 'elaborar contramedidas a partir de causas identificadas de desvio negativo, com o objetivo de atingir as metas de receitas estabelecidas;', '', 143),
(12329, 'anexo', 290, 12185, 4, 'n', 'elaborar e executar o plano de ação com o objetivo de atingir as metas estabelecidas no plano de vendas e/ou outras oportunidades identificadas;', '', 144),
(12330, 'anexo', 290, 12185, 4, 'o', 'encaminhar dúvidas sobre processos e regras de negócios dos produtos relacionadas para formatadores, quando a informação não for localizada nos repositórios de informações;', '', 145),
(12331, 'anexo', 290, 12185, 4, 'p', 'executar ações de vendas visando ao incremento e geração de novas receitas, prospecção de novos negócios, prospecção de novos clientes, manutenção e satisfação do cliente, a partir do plano de vendas e potencial do cliente;', '', 146),
(12332, 'anexo', 290, 12185, 4, 'q', 'identificar datas comemorativas de clientes sob sua gestão, promovendo produtos de conveniência, realizando network, fortalecendo imagem Correios x Cliente, dentre outros;', '', 147),
(12333, 'anexo', 290, 12185, 4, 'r', 'direcionar as demandas apresentadas pelos clientes sob sua gestão, referentes a suprimentos de insumos operacionais, fornecimento de formulário AR e etiquetas, regularização de arquivos de postagem, coletas, corte de carga, carga retida, não entrega de objetos, devolução de AR, dentre outras;', '', 148),
(12334, 'anexo', 290, 12185, 4, 's', 'interagir com as áreas para a implantação de novos serviços e produtos;', '', 149),
(12335, 'anexo', 290, 12185, 4, 't', 'manter atualizadas as informações dos leads e prospects em sistema/ferramenta para gestão da prospecção;', '', 150),
(12336, 'anexo', 290, 12185, 4, 'u', 'monitorar o faturamento do cliente visando assegurar a utilização do valor mínimo do pacote contratado, promovendo interações junto ao cliente para ajuste no pacote contratado, quando necessário;', '', 151),
(12337, 'anexo', 290, 12185, 4, 'v', 'orientar o cliente sobre os canais de atendimento para as demandas de abertura de PI extemporâneo e indenizações por fraude de remessa expressa;', '', 152),
(12338, 'anexo', 290, 12185, 4, 'w', 'orientar o cliente para realização de rastreamento em lote por meio do sistema SRO;', '', 153),
(12339, 'anexo', 290, 12185, 4, 'x', 'orientar os clientes sob sua gestão acerca dos canais de atendimento das demandas administrativas contratuais (contrato/termos aditivos/apostilamento), monitorando a conclusão da demanda pelas áreas responsáveis;', '', 154),
(12340, 'anexo', 290, 12185, 4, 'y', 'participar e/ou promover reuniões com os clientes, assistente comercial de tecnologia, assistente de comércio exterior e/ou áreas dos Correios a fim de realizar pontos de controle sobre indicadores de desempenho dos clientes e demandas apresentadas, com proposição de melhorias e o devido registro em ata;', '', 155),
(12341, 'anexo', 290, 12185, 4, 'z', 'prestar informações ao cliente com contrato sobre o atendimento das demandas administrativas, tais como: canais de atendimento para acesso a sistemas/ferramentas, geração de etiquetas, utilização do SEI, contrato, renovação contratual, entre outros;', 'aa) prestar informações aos prospects sobre os procedimentos para efetivação do contrato comercial;\nbb) prestar informações às áreas demandantes dos Correios, relativas aos segmentos de mercado, nos quais estão inseridos os clientes sob sua gestão;\ncc) prestar informações das regras de negócios dos Correios, de produtos e serviços do portfólio da Empresa para os clientes sob sua gestão;\ndd) promover ações que visam ampliar os níveis de acesso e fortalecimento da relação com o cliente e conquistas de novos negócios, por meio de eventos patrocinados ou organizados pelos Correios, entrega de materiais de relacionamento, dentre outros;\nee) propor e participar, quando for o caso, das melhorias dos processos internos dos Correios aplicáveis aos clientes sob sua gestão, considerando o desempenho financeiro, jornada e experiência do cliente, dentre outros fatores;\nff) prospectar novos clientes a partir das ações de vendas previstas no plano de vendas;\ngg) realizar atendimento de 1º nível para demandas tecnológicas, prestando informações para ações negociais e de pós-vendas: características e funcionalidades dos sistemas/ferramentas, links de acesso, obtenção de usuário e senha e local de disponibilização de manuais;\nhh) realizar tratativas junto ao cliente nos processos de negociação para contratação/renovação de contratos/termos aditivos/apostilamentos, conforme procedimentos geridos pela área de apoio a vendas, acompanhando a geração da minuta contratual;\nii) registrar e manter atualizadas as informações dos clientes sob sua gestão nos sistemas corporativos dos Correios ou em outras ferramentas disponibilizadas para gestão do cliente;\njj) representar os Correios em reuniões sobre assuntos referentes aos clientes sob sua gestão, registrando as informações conforme orientações da área de vendas;\nkk) solicitar apoio da Superintendência Estadual - SE gestora do cliente para viabilizar visitas técnicas nos Correios, conforme necessidade identificada;\nll) solicitar para a área de apoio a vendas a geração de usuário e senha nos sistemas/ferramentas, para produtos e serviços implantados.', 156),
(12342, 'anexo', 290, NULL, 1, '2', 'INDICAÇÃO DAS FUNÇÕES DOS GESTORES DE RELACIONAMENTO COMERCIAL', '2.1 Indicar as funções do gestor de relacionamento comercial:', 157),
(12343, 'anexo', 290, 12342, 4, 'a', 'responsável pelos clientes com categoria institucional Infinite: as atividades serão desempenhadas preferencialmente pelo Gerente de Contas Especiais - GCE;', '', 158),
(12344, 'anexo', 290, 12342, 4, 'b', 'responsável pelos clientes com categoria institucional Diamante: as atividades serão desempenhadas preferencialmente pelo Assistente Comercial - ACOM I;', '', 159),
(12345, 'anexo', 290, 12342, 4, 'c', 'responsável pelos clientes com categoria institucional Platinum e Ouro: as atividades serão desempenhadas preferencialmente pelo Assistente Comercial - ACOM II ou ACOM III;', '', 160),
(12346, 'anexo', 290, 12342, 4, 'd', 'responsável pelas demais categorias institucionais: as atividades serão desempenhadas preferencialmente pelo Operador de Teleatendimento da Central de Atendimento ao Cliente.', '', 161),
(12347, 'anexo', 290, NULL, 1, '3', 'DEFINIÇÃO DE LOTAÇÃO E LOCALIZAÇÃO DOS PROFISSIONAIS', '3.1 Definir a lotação e localização do gestor de relacionamento comercial:', 162),
(12348, 'anexo', 290, 12347, 4, 'a', 'responsável pelos clientes com categoria institucional Infinite, Diamante, Platinum ou Ouro: será lotado na localidade sede da Superintendência Estadual - SE gestora do cliente, mas poderá ser localizado em outra cidade de acordo com a localização dos responsáveis pela tomada de decisões ou das operações do cliente, conforme definição da SE;', '', 163),
(12349, 'anexo', 290, 12347, 4, 'b', 'responsável pelos clientes das demais categorias institucionais: será lotado e localizado na unidade de vendas à distância responsável pela gestão dos clientes com contrato.', '', 164),
(12350, 'anexo', 290, NULL, 1, '4', 'COMUNICAR ALTERAÇÕES DA GESTÃO DE CLIENTES', '4.1 Comunicar ao cliente as alterações da gestão do seu contrato e apresentar o novo gestor, por escrito (carta/ofício) e pessoalmente, por interação à distância ou presencial, conforme o caso.\n* * * * *', 165),
(12351, 'anexo', 291, NULL, 1, '1', 'ESCOPO DE ATUALÇÃO', '1.1 Descrever os níveis de atendimento do suporte tecnológico:', 0),
(12352, 'anexo', 291, 12351, 4, 'a', '1º nível: gestor de relacionamento comercial;', '', 1),
(12353, 'anexo', 291, 12351, 4, 'b', '2º nível: assistente comercial de tecnologia;', '', 2),
(12354, 'anexo', 291, 12351, 4, 'c', '3º nível:  gestores funcionais dos sistemas/ferramentas e time de desenvolvimento na área de tecnologia.', '', 3),
(12355, 'anexo', 291, NULL, 1, '2', 'DESCRIÇÃO DAS ATIVIDADES', '2.1 Atendimento em 1º Nível - Operador de Teleatendimento e Gestor de Relacionamento Comercial\n2.1.1 Consultar MANCAT 27/13 anexo 02 para consultar as atividades de operadores de teleatendimento e gestores de relacionamento comercial.\n2.2 Descrever as atividades do profissional de atendimento em 2º Nível - Assistente Comercial de Tecnologia:', 4),
(12356, 'anexo', 291, 12355, 4, 'a', 'atuar proativamente na detecção de oportunidades de melhorias dos sistemas/ferramentas tecnológicas dos Correios utilizados pelos clientes com contrato;', '', 5),
(12357, 'anexo', 291, 12355, 4, 'b', 'atuar no suporte de 2º nível, quando necessário, nas reuniões com as áreas tecnológicas dos clientes de contrato de todas as categorias e com os integradores que não possuem contrato com os Correios, de forma presencial ou remota;', '', 6),
(12358, 'anexo', 291, 12355, 4, 'c', 'demandar o gestor funcional (PO) do sistema/ferramenta para resolução de problemas que não possam ser solucionados no 2º nível, monitorando retorno para resposta ao cliente com contrato;', '', 7),
(12359, 'anexo', 291, 12355, 4, 'd', 'disponibilizar scripts para atendimento de 1º e 2º nível, conforme informações obtidas por meio dos gestores dos sistemas/ferramentas mantidos pelos Correios;', '', 8),
(12360, 'anexo', 291, 12355, 4, 'e', 'identificar falhas nos arquivos postados pelo cliente com contrato, caso não tenha sido detectado o erro a partir das orientações da Central de Atendimento ao Cliente ou dos gestores de relacionamento, interagindo com os órgãos gestores funcionais do sistema/ferramenta, se for o caso;', '', 9),
(12361, 'anexo', 291, 12355, 4, 'f', 'interagir com o gestor funcional (PO) do sistema/ferramenta para consultar as questões omissas das orientações de utilização dos sistemas/ferramentas mantidos pelos Correios (2º Nível de atendimento);', '', 10),
(12362, 'anexo', 291, 12355, 4, 'g', 'interagir com gestor funcional (PO) do sistema/ferramenta quando identificada inconsistência na utilização do sistema ou consulta de dados, monitorando a resolução (3º nível);', '', 11),
(12363, 'anexo', 291, 12355, 4, 'h', 'interagir com os clientes com contrato para suporte de 2º nível, bem como integradores que não possuem contratos com os Correios, viabilizando a implantação, integração ou solução de problemas com sistemas/ferramentas mantidos pelos Correios, com resposta no Fale Conosco, se for o caso;', '', 12),
(12364, 'anexo', 291, 12355, 4, 'i', 'monitorar a operacionalização dos sistemas/ferramentas dos Correios utilizados pelos clientes com contrato, interagindo com o gestor funcional (PO) da ferramenta/sistema para garantir a disponibilidade da plataforma (2º nível);', '', 13),
(12365, 'anexo', 291, 12355, 4, 'j', 'propor aos gestores funcionais dos sistemas/ferramentas tecnológicas alterações para atendimento de demandas específicas de clientes com contrato;', '', 14),
(12366, 'anexo', 291, 12355, 4, 'k', 'recepcionar demandas do gestor de relacionamento com o cliente com contrato e da Central de Atendimento ao Cliente para solução de problemas de implantação, integração ou de utilização de sistemas/ferramentas mantidos pelos Correios (2º nível);', '', 15),
(12367, 'anexo', 291, 12355, 4, 'l', 'verificar falhas relatadas pelos clientes com contrato na correção de planilha para macro rastreamento, interagindo com o gestor funcional (PO) do sistema quando necessário.', '2.3 Descrever as atividades do profissional de Atendimento em 3º Nível - Gestor Funcional (PO):', 16),
(12368, 'anexo', 291, 12355, 4, 'a', 'atuar proativamente na detecção de oportunidades de melhorias dos sistemas/ferramentas tecnológicas dos Correios utilizadas pelos clientes com contrato;', '', 17),
(12369, 'anexo', 291, 12355, 4, 'b', 'interagir com o Time de Desenvolvimento para avaliação técnica e intervenção tecnológica nos sistemas/ferramentas dos Correios para solucionar os problemas apresentados e possibilitar o uso pelos clientes; ', '', 18),
(12370, 'anexo', 291, 12355, 4, 'c', 'propor alterações nos sistemas/ferramentas tecnológicas dos Correios para atendimento de demandas específicas de clientes com contrato;', '', 19),
(12371, 'anexo', 291, 12355, 4, 'd', 'responder as demandas apresentadas pelo Assistente Comercial de Tecnologia, após parecer das unidades consultadas em 3º nível, se for o caso.', '2.4 Descrever as atividades do profissional de Atendimento em 3º Nível - Time de Desenvolvimento:\n ', 20),
(12372, 'anexo', 291, 12355, 4, 'a', 'providenciar intervenções técnicas e outras ações necessárias para viabilizar a utilização dos sistemas/ferramentas dos Correios pelos clientes com contrato;', '', 21),
(12373, 'anexo', 291, 12355, 4, 'b', 'reportar ao demandante de 3º nível as soluções disponibilizadas para viabilizar a utilização dos sistemas/ferramentas dos Correios pelos clientes com contrato.', '', 22),
(12374, 'anexo', 291, NULL, 1, '3', 'INDICAÇÃO DAS FUNÇÕES', '3.1 Indicar a função de Assistente Comercial III para atendimento de demandas tecnológicas de 2º nível.\nNota 1: o atendimento tecnológico em 1º nível será desempenhado por profissionais designados conforme MANCAT 27/3, anexo 2.\nNota 2: o atendimento tecnológico em 3º nível será desempenhado por profissionais designados pela área de tecnologia.', 23),
(12375, 'anexo', 291, NULL, 1, '4', 'DEFINIÇÃO DE LOTAÇÃO E LOCALIZAÇÃO DOS PROFISSIONAIS', '4.1 Definir a lotação e localização dos profissionais, conforme o nível de atendimento:', 24),
(12376, 'anexo', 291, 12375, 4, 'a', 'atendimento em 1º nível: o profissional será lotado e localizado na área comercial ou conforme necessidade dos Correios;', '', 25),
(12377, 'anexo', 291, 12375, 4, 'b', 'atendimento em 2º nível: o profissional será lotado e localizado nas áreas gestoras funcionais, ou conforme necessidade dos Correios;', '', 26),
(12378, 'anexo', 291, 12375, 4, 'c', 'atendimento em 3º nível: o profissional será lotado e localizado na área de tecnologia ou conforme necessidade dos Correios.', '* * * * *', 27),
(12379, 'anexo', 292, NULL, 1, '1', 'ESCOPO DE ATUAÇÃO', '1.1 A atuação neste segmento requer conhecimentos aprofundados em normas e procedimentos específicos acerca de negócios internacionais.', 0),
(12380, 'anexo', 292, 12379, 2, '1.2', 'A consultoria de negócios internacionais será desempenhada pelo Assistente de Comercio Exterior - ACOMEX, de acordo com sua região de atendimento.', '', 1),
(12381, 'anexo', 292, NULL, 1, '2', 'DESCRIÇÃO DAS ATIVIDADES', '2.1 Descrever as atividades do profissional de consultoria especializada nos negócios internacionais - Assistente de Comercio Exterior - ACOMEX:', 2),
(12382, 'anexo', 292, 12381, 4, 'a', 'acompanhar a implantação e a gestão dos negócios internacionais;', '', 3),
(12383, 'anexo', 292, 12381, 4, 'b', 'acompanhar os resultados dos serviços internacionais e movimentos relevantes do mercado que possam impactar nos negócios, propondo ajustes no Plano de Ação, se necessário;', '', 4),
(12384, 'anexo', 292, 12381, 4, 'c', 'analisar a lista de leads disponibilizada pelo Departamento gestor, com os potenciais clientes dos produtos e soluções internacionais;', '', 5),
(12385, 'anexo', 292, 12381, 4, 'd', 'apoiar o gestor do relacionamento na negociação do termo de confidencialidade com cada cliente, se aplicável;', '', 6),
(12386, 'anexo', 292, 12381, 4, 'e', 'apoiar o gestor do relacionamento para o registro de informações qualitativas sobre a operação do cliente nos sistemas/ferramentas corporativas;', '', 7),
(12387, 'anexo', 292, 12381, 4, 'f', 'apoiar, com informações técnicas, a elaboração de conteúdos e treinamentos de produtos e/ou soluções internacionais;', '', 8),
(12388, 'anexo', 292, 12381, 4, 'g', 'apresentar as soluções e/ou produtos internacionais dos Correios em encontros de negócios com clientes e instituições, de acordo com as estratégias comerciais;', '', 9),
(12389, 'anexo', 292, 12381, 4, 'h', 'apresentar relatório das atividades realizadas ao respectivo gestor local e/ou Departamento gestor de produtos e soluções internacionais;', '', 10),
(12390, 'anexo', 292, 12381, 4, 'i', 'conhecer a cadeia produtiva do cliente, propondo soluções e/ou produtos internacionais que otimizem o processo produtivo;', '', 11),
(12391, 'anexo', 292, 12381, 4, 'j', 'definir, em conjunto com o gestor imediato, a lista de leads prioritários para ação comercial;', '', 12),
(12392, 'anexo', 292, 12381, 4, 'k', 'disseminar os principais negócios definidos pelo Departamento gestor, conforme área de atuação de sua SE;', '', 13),
(12393, 'anexo', 292, 12381, 4, 'l', 'elaborar e validar com o cliente a proposta comercial, em conjunto com o gestor do relacionamento do cliente;', '', 14),
(12394, 'anexo', 292, 12381, 4, 'm', 'elaborar, em conjunto com o gestor do relacionamento do cliente, o plano de ação comercial;', '', 15),
(12395, 'anexo', 292, 12381, 4, 'n', 'elaborar, em conjunto com o gestor do relacionamento do cliente, proposta técnica de melhoria do processo do cliente, se aplicável;', '', 16),
(12396, 'anexo', 292, 12381, 4, 'o', 'emitir consulta contendo subsídios necessários às esferas superiores de acordo com o fluxo de comunicação, para viabilizar negócios internacionais;', '', 17),
(12397, 'anexo', 292, 12381, 4, 'p', 'executar o plano de ação, em alinhamento ao Plano de Vendas da Empresa;', '', 18),
(12398, 'anexo', 292, 12381, 4, 'q', 'identificar, em conjunto com o gestor do relacionamento do cliente, oportunidades junto aos clientes e ao mercado realizando ações de prospecção de novos negócios;', '', 19),
(12399, 'anexo', 292, 12381, 4, 'r', 'manter-se atualizado com informações atinentes a sua área de atuação;', '', 20),
(12400, 'anexo', 292, 12381, 4, 's', 'monitorar a atuação de outros operadores e disponibilizar informações qualitativas do mercado ao Departamento gestor;', '', 21),
(12401, 'anexo', 292, 12381, 4, 't', 'participar das reuniões de acompanhamento de resultados;', '', 22),
(12402, 'anexo', 292, 12381, 4, 'u', 'participar de reuniões junto às áreas envolvidas nos processos que visem atender às necessidades dos clientes referentes aos produtos e/ou soluções internacionais;', '', 23),
(12403, 'anexo', 292, 12381, 4, 'v', 'participar e/ou promover workshops (interno e externo) para disseminar os negócios internacionais, conforme diretrizes comerciais;', '', 24),
(12404, 'anexo', 292, 12381, 4, 'w', 'propor melhorias no âmbito de sua atuação, que agreguem valor ao cliente, otimizando o processo produtivo dos Correios;', '', 25),
(12405, 'anexo', 292, 12381, 4, 'x', 'realizar apresentações, conforme modelos definidos pelo Departamento gestor, sobre as negociações de serviços e/ou produtos para abordagem aos clientes;', '', 26),
(12406, 'anexo', 292, 12381, 4, 'y', 'realizar visitas técnicas, em conjunto com o gestor do relacionamento, para mapeamento dos processos dos clientes, aderentes aos negócios internacionais dos Correios;', '', 27),
(12407, 'anexo', 292, 12381, 4, 'z', 'realizar, em conjunto com o gestor do relacionamento, visita técnica aos leads prioritários;', 'aa) sugerir a participação em eventos e participar do planejamento de encontros de negócios com os clientes de negócios internacionais, visando a manutenção dos contratos existentes e conquista de novos clientes;\nbb) validar a proposta técnico-operacional, em conjunto com o Departamento gestor e do relacionamento do cliente, se aplicável.', 28),
(12408, 'anexo', 292, NULL, 1, '3', 'INDICAÇÃO DAS FUNÇÕES', '3.1 Indicar a função de Assistente de Comercio Exterior - ACOMEX para atendimento de demandas acerca de negócios internacionais.', 29),
(12409, 'anexo', 292, NULL, 1, '4', 'DEFINIÇÃO DE LOTAÇÃO E LOCALIZAÇÃO DOS PROFISSIONAIS', '4.1 O Assistente de Comercio Exterior - ACOMEX será lotado e localizado nos Órgãos de Vendas de maior potencial de negócios ou conforme a necessidade dos Correios.\n4.2 A definição de localização de cada profissional especializado em negócios internacionais será a critério dos Correios, conforme necessidade do atendimento dos clientes sob sua gestão e realização de consultoria.\n* * * * *', 30),
(12410, 'anexo', 293, NULL, 1, '1', 'GESTÃO DOS INSTRUMENTOS CONTRATUAIS', '', 0),
(12411, 'anexo', 293, 12410, 2, '1.1', 'Sistema Correios Fácil', '1.2 Sistema Eletrônico de Informações - SEI\n* * * * *', 1),
(12412, 'anexo', 294, NULL, 1, '1', 'Os contratos devem ser redigidos com fonte não inferior a fonte tamanho 12 (doze) de acordo com a Lei nº 8.078/90 (Código Defesa do Consumidor).', '', 0),
(12413, 'anexo', 294, 12412, 2, '1.1', 'O contrato deve ser composto por: preâmbulo, corpo do contrato, fechamento, anexos, termos e condições, ficha técnica, termo aditivo contratual e apostilamento.', '', 1),
(12414, 'anexo', 294, 12412, 2, '1.2', 'Do preâmbulo deverão constar:', '', 2),
(12415, 'anexo', 294, 12414, 4, 'a', 'a identificação das partes: nome, CNPJ/MF, endereço etc;', '', 3),
(12416, 'anexo', 294, 12414, 4, 'b', 'os representantes legais das partes e respectivas identificações;', '', 4),
(12417, 'anexo', 294, 12414, 4, 'c', 'a finalidade.', 'Nota: em casos específicos, devidamente chancelados pela área jurídica, poderão ser dispensadas as alíneas “a” e “b”.', 5),
(12418, 'anexo', 294, 12412, 2, '1.3', 'Do corpo do contrato deverão constar as cláusulas essenciais:', '', 6),
(12419, 'anexo', 294, 12418, 4, 'a', 'objeto;', '', 7),
(12420, 'anexo', 294, 12418, 4, 'b', 'obrigações das partes;', '', 8),
(12421, 'anexo', 294, 12418, 4, 'c', 'preços e reajuste;', '', 9),
(12422, 'anexo', 294, 12418, 4, 'd', 'condições de pagamento;', '', 10),
(12423, 'anexo', 294, 12418, 4, 'e', 'prazo de vigência;', '', 11),
(12424, 'anexo', 294, 12418, 4, 'f', 'inadimplemento;', '', 12),
(12425, 'anexo', 294, 12418, 4, 'g', 'rescisão;', '', 13),
(12426, 'anexo', 294, 12418, 4, 'h', 'disposições gerais; e', '', 14),
(12427, 'anexo', 294, 12418, 4, 'i', 'foro.', 'Nota 1: deve sempre ser eleito o Foro da Justiça Federal, seção da Capital do respectivo Estado, para dirimir as questões oriundas do contrato. Pode ser eleito Foro da Justiça Federal em outra localidade desde que nessa haja estrutura jurídica dos Correios.\nNota 2: os contratos comerciais celebrados com órgãos públicos conterão as cláusulas indicadas no 1.3, as cláusulas específicas de dotação orçamentária e dispensa ou inexigibilidade de licitação, além de outras pré-chanceladas pela área jurídica.', 15),
(12428, 'anexo', 294, 12412, 2, '1.4', 'Do fechamento deverão constar:', '', 16),
(12429, 'anexo', 294, 12428, 4, 'a', 'o texto padronizado de fechamento;', '', 17),
(12430, 'anexo', 294, 12428, 4, 'b', 'a data; e', '', 18),
(12431, 'anexo', 294, 12428, 4, 'c', 'as assinaturas das partes.', '', 19),
(12432, 'anexo', 294, 12412, 2, '1.5', 'Por instrumentos e documentos congêneres de contratação entendem-se: contratos comerciais, termos aditivos, apostilamentos, fichas resumo/técnica, dentre outros.', '', 20),
(12433, 'anexo', 294, 12412, 2, '1.6', 'O idioma oficial dos instrumentos contratuais e documentos congêneres é o português.', '', 21),
(12434, 'anexo', 294, 12433, 3, '1.6.1', 'Documentos emitidos por países estrangeiros, para produzirem efeitos no Brasil, precisam ter a tradução juramentada para a língua portuguesa (deverá ser providenciada pelo cliente) e devem ser validados, ou seja, legalizados/consularizados unicamente junto às repartições Consulares (Embaixada ou Consulado) do Brasil no exterior, que possuem jurisdição sobre a localidade em que os documentos foram emitidos.', '', 22),
(12435, 'anexo', 294, 12433, 3, '1.6.2', 'A validação também ocorrerá por meio de apostilamento dos documentos estrangeiros, em casos em que a contratante for sediada em país signatário da Convenção de Haia.', '', 23),
(12436, 'anexo', 294, NULL, 1, '2', 'CONTRATO MÚLTIPLO E SUAS REGRAS', '', 24),
(12437, 'anexo', 294, 12436, 2, '2.1', 'O contrato comercial é constituído de uma minuta principal que consente a adesão a pacotes de serviços, termos de condições e anexos de produtos e/ou serviços específicos que o cliente venha a contratar.', '', 25),
(12438, 'anexo', 294, 12436, 2, '2.2', 'Os contratos comerciais, via de regra, são formalizados por minutas avaliadas e aprovadas previamente pela área jurídica, denominadas como contratos padrões.', '', 26),
(12439, 'anexo', 294, 12438, 3, '2.2.1', 'Na apresentação da minuta de contrato ao cliente, deverá sempre ser ofertada a versão padrão, pré-aprovada pela área jurídica.', '', 27),
(12440, 'anexo', 294, 12436, 2, '2.3', 'Os pacotes de serviço contemplam os principais produtos e serviços dos Correios destinados às pessoas jurídicas.', '', 28),
(12441, 'anexo', 294, 12440, 3, '2.3.1', 'Os produtos e serviços disponíveis em cada pacote podem ser consultados nos Termos de Condições Comerciais, no portal dos Correios.', '', 29),
(12442, 'anexo', 294, 12436, 2, '2.4', 'Os pacotes de serviços serão vinculados aos respectivos contratos a partir da escolha do cliente, observando as condições e prazos indicados neste módulo e as previstas nos Termos de Condições Comerciais.', '', 30),
(12443, 'anexo', 294, 12436, 2, '2.5', 'Os Termos de Condições são parte integrante da minuta contratual e elencam os produtos e serviços que fazem parte do objeto do contrato, estabelecendo as regras para comercialização, operacionalização e categorização dos clientes de contrato comercial dos Correios.', '', 31),
(12444, 'anexo', 294, 12443, 3, '2.5.1', 'Nos Termos de Condições devem conter:', '', 32),
(12445, 'anexo', 294, 12444, 4, 'a', 'condições comerciais: informações referentes às regras comerciais que devem ser obedecidas pelas partes quando da utilização dos serviços;', '', 33),
(12446, 'anexo', 294, 12444, 4, 'b', 'condições operacionais: procedimentos operacionais para a prestação e execução dos serviços que devem ser observados pelas partes;', '', 34),
(12447, 'anexo', 294, 12444, 4, 'c', 'manifestação e indenização: regras referentes a registro de manifestação e condições para eventual indenização.', '', 35),
(12448, 'anexo', 294, 12436, 2, '2.6', 'Os Termos não são apensados ao corpo da minuta contratual, sendo possível a sua consulta por meio do portal dos Correios ou cartório de registro especificado em cláusula contratual.', '', 36),
(12449, 'anexo', 294, 12436, 2, '2.7', 'O anexo corresponde às condições técnicas/operacionais específicas de um serviço e, quando utilizado, é parte integrante do contrato.', '', 37),
(12450, 'anexo', 294, 12436, 2, '2.8', 'Os anexos de produtos/serviços específicos devem ser assinados e incluídos no corpo da minuta contratual ou incluído no contrato por meio de termo aditivo/apostilamento.', '', 38),
(12451, 'anexo', 294, 12436, 2, '2.9', 'A ficha técnica apresenta as informações específicas para a operacionalização do serviço e, quando utilizada, é considerada parte complementar do contrato.', '', 39),
(12452, 'anexo', 294, 12436, 2, '2.10', 'O termo aditivo contratual é um complemento ao contrato assinado, que promove alterações que precisam ser acordadas entre as partes.', '', 40),
(12453, 'anexo', 294, 12452, 3, '2.10.1', 'Esse instrumento:', '', 41),
(12454, 'anexo', 294, 12453, 4, 'a', 'inclui, altera ou exclui informações no contrato;', '', 42),
(12455, 'anexo', 294, 12453, 4, 'b', 'indica que houve alteração em alguma cláusula que altere direitos e obrigações das partes e, por esse motivo, deve ser documentado;', '', 43),
(12456, 'anexo', 294, 12453, 4, 'c', 'requer aprovação jurídica prévia à assinatura das partes.', '', 44),
(12457, 'anexo', 294, 12436, 2, '2.11', 'Apostilamento é um complemento ao contrato assinado, que promove alterações previstas no referido instrumento ou em regras para sua operacionalização.', '', 45),
(12458, 'anexo', 294, NULL, 1, '3', 'CLÁUSULAS ALTERNATIVAS PARA CONTRATOS MÚLTIPLOS', '', 46),
(12459, 'anexo', 294, 12458, 2, '3.1', 'A área de vendas pode valer-se das cláusulas alternativas quando julgar pertinente, desde que haja solicitação prévia do cliente.', '', 47),
(12460, 'anexo', 294, 12459, 3, '3.1.1', 'As cláusulas alternativas são regras contratuais inseridas nos instrumentos após solicitação dos clientes, considerando suas particularidades. Nesse sentido, nem sempre se aplicam a todos os contratantes, motivo pelo qual só são incluídas mediante manifestação de necessidade do contratante.', '', 48),
(12461, 'anexo', 294, 12458, 2, '3.2', 'As referidas cláusulas alternativas estão dispostas em servidor específico de acesso livre para as áreas interessadas.', '', 49),
(12462, 'anexo', 294, 12461, 3, '3.2.1', 'A utilização das cláusulas alternativas não descaracteriza a minuta do padrão, uma vez que todas as cláusulas alternativas foram analisadas e aprovadas pela área jurídica.', '', 50),
(12463, 'anexo', 294, NULL, 1, '4', 'PRORROGAÇÃO DE VIGÊNCIA E RENOVAÇÃO CONTRATUAL', '', 51),
(12464, 'anexo', 294, 12463, 2, '4.1', 'A repactuação/renovação de contratos comerciais de prestação de serviços de produtos e serviços (contrato sucedâneo) é entendida como a substituição do contrato firmado anteriormente, sem interrupção de vigência.', '', 52),
(12465, 'anexo', 294, 12464, 3, '4.1.1', 'A manutenção do número do contrato está condicionada à celebração de um novo instrumento, cuja vigência inicial deverá ser de até 1 (um) dia após a data de encerramento da vigência do instrumento contratual que o precede.', '', 53),
(12466, 'anexo', 294, 12464, 3, '4.1.2', 'Embora assinado um novo instrumento contratual, para o sistema corporativo trata-se de uma continuidade da relação comercial, com emissão de fatura única referente ao consumo para o ciclo definido.', '', 54),
(12467, 'anexo', 294, 12463, 2, '4.2', 'No caso de termos aditivos de prorrogação de vigência de contratos a assinatura deve ocorrer antes do final da vigência contratual.', '', 55),
(12468, 'anexo', 294, NULL, 1, '5', 'REGRAS PARA CONTRATO ESPECIAL/CUSTOMIZADO', '', 56),
(12469, 'anexo', 294, 12468, 2, '5.1', 'Para os casos de qualquer alteração/inclusão/exclusão de cláusulas, subitens e redação, a minuta torna-se customizada, sendo necessária a realização dos procedimentos apresentados no MANCAT 28/1 - 2.5.4.', '', 57),
(12470, 'anexo', 294, 12468, 2, '5.2', 'Alterações contratuais que envolvam eventual ajuste de escopo necessitam, obrigatoriamente, de aprovação por meio de novo Relatório de Customização de Negócios – RCN.', '', 58),
(12471, 'anexo', 294, 12468, 2, '5.3', 'Prestar serviços por meio da celebração de contratos para negócios customizados é uma alternativa para atender à solicitação de clientes de customização de produtos e serviços já existentes no portfólio ou desenvolvimento de um novo produto/serviço.', '', 59),
(12472, 'anexo', 294, 12468, 2, '5.4', 'O órgão formatador deverá definir as condições comerciais e operacionais para subsidiar a elaboração do correspondente instrumento contratual para pactuação do produto/serviço customizado.', '', 60),
(12473, 'anexo', 294, 12468, 2, '5.5', 'No caso de renovação e reajuste de contratos customizados, o órgão gestor de produtos e serviços deverá encaminhar, ao departamento de precificação, em até 45 (quarenta e cinco) dias antes do vencimento, para a análise e elaboração da proposta da estratégia de precificação e posterior submissão aos órgãos competentes para aprovação.', '', 61),
(12474, 'anexo', 294, 12473, 3, '5.5.1', 'Obrigatoriamente, a demanda deve vir acompanhada dos subsídios necessários para revisão e reajuste de preços, observando o previsto no MANNEG 7/1 - 2.1.3.', '', 62),
(12475, 'anexo', 294, 12468, 2, '5.6', 'A análise realizada pela área jurídica é materializada por meio de nota jurídica.', '', 63),
(12476, 'anexo', 294, 12468, 2, '5.7', 'O processo SEI que detém o instrumento contratual customizado, pactuado entre as partes, não poderá ser tramitado nas demais áreas internas.', '', 64),
(12477, 'anexo', 294, 12476, 3, '5.7.1', 'Caso necessária consulta a outras áreas internas, a gerência de suporte comercial deverá providenciar a abertura de outro processo para as tratativas complementares.', '', 65),
(12478, 'anexo', 294, NULL, 1, '6', 'REGRAS GERAIS PARA FORMALIZAÇÃO DE INSTRUMENTOS CONTRATUAIS NOS SISTEMAS DE CADASTRO DA EMPRESA', '', 66),
(12479, 'anexo', 294, 12478, 2, '6.1', 'Estabelecer a vigência inicial do instrumento contratual após assinatura das partes, quando necessário, considerando a data da última assinatura.', '', 67),
(12480, 'anexo', 294, 12479, 3, '6.1.1', 'Os instrumentos contratuais somente possuem validade após assinatura de todos os representantes legais das partes envolvidas, com exceção do apostilamento.', '', 68),
(12481, 'anexo', 294, 12479, 3, '6.1.2', 'Quando o instrumento contratual estabelece que a vigência inicial ocorrerá a partir de uma data definida, todas as assinaturas deverão ocorrer até essa data.', '', 69),
(12482, 'anexo', 294, 12479, 3, '6.1.3', 'Não é permitida retroatividade para vigência do instrumento contratual.', '', 70),
(12483, 'anexo', 294, 12478, 2, '6.2', 'Solicitar os registros nos sistemas corporativos dos Correios, de forma a viabilizar a operacionalização dos instrumentos contratuais.', '', 71),
(12484, 'anexo', 294, 12483, 3, '6.2.1', 'O cadastro dos contratos efetivados pelos Correios Fácil será integralmente viabilizado pela plataforma.', '', 72),
(12485, 'anexo', 294, 12478, 2, '6.3', 'Disponibilizar o cartão de postagem para todos os clientes que celebrarem contrato via SEI ou sempre que solicitado pelo cliente.', '', 73),
(12486, 'anexo', 294, 12485, 3, '6.3.1', 'O cartão de postagem virtual ficará disponível no perfil do cliente Correios Fácil após a conclusão do cadastro do contrato.', '', 74),
(12487, 'anexo', 294, NULL, 1, '7', 'CENTRO DE CUSTOS', '', 75),
(12488, 'anexo', 294, 12487, 2, '7.1', 'Poderão ser criados centros de custos com raiz de CNPJ diferente da contratante nos casos expressamente autorizados e devidamente fundamentados pela área de gestão dos contratos comerciais, conforme modalidades abaixo:', 'a) centralizado: fatura única; e\nb) descentralizado: fatura separada por centro de custo.\n* * * * *', 76),
(12489, 'anexo', 296, NULL, 1, '1', 'PRAZOS E FUNDAMENTAÇÃO LEGAL', '1.1 O processo de prorrogação de vigência ou a renovação dos contratos comerciais observará a previsão legal e terá início por meio de comunicação formal (carta ou ofício), com antecedência mínima de:\na) 60 (sessenta) dias para empresa privada, nos casos de renovação;\nb) 120 (cento e vinte) dias para órgão público ou qualquer instituição cujas contratações sejam regidas pela Lei nº 8.666/93, nº 14.133/21, nº 13.303/16, nos casos de prorrogação de vigência ou renovação contratual.\n1.2 A comunicação formal a que se refere o subitem anterior poderá iniciar-se com maior antecedência, a critério da área gestora do cliente ou da área de apoio a vendas.\n* * * * *', 0),
(12490, 'anexo', 298, NULL, 1, '1', 'Para a realização do encontro da força de vendas, deve ser elaborado pelo Departamento de Vendas e pela Diretoria Regional um projeto básico que contemple todos os pontos destacados abaixo:', 'a) nome - o encontro da força de vendas deve ter um nome que traduza o escopo do evento;\nb) temas - devem ser abordados temas de relevância para a força de vendas participante e que estejam alinhados às politicas comerciais e/ou ao planejamento estratégico da ECT:\nI - por meio de painéis e palestras deverão ser abordados/debatidos temas referentes a políticas de gestão de vendas e da força de vendas e ao relacionamento com os clientes, de forma a garantir os resultados comerciais da ECT;\nII - os temas específicos poderão ser tratados em palestras por profissionais de renome nacional e de reconhecida performance e/ou por profissionais da ECT, conforme a necessidade verificada. Todos os nomes dos palestrantes deverão ser validados pelo Departamento de Vendas;\nIII - os jogos empresariais e as dinâmicas de grupos deverão trabalhar as questões comportamentais e reforçar, de forma lúdica, os temas tratados nas palestras.\nc) objetivos do evento - devem estar relacionados diretamente aos objetivos definidos no subitem 4.2. deste capítulo;\nd) data - deverá ser definida, preferencialmente, nos períodos de baixa temporada, visando à redução dos custos para realização do evento. Caso não seja possível realização nesse período, deve ser verificada possibilidade de redução na tarifa de hospedagem no período do encontro da força de vendas;\ne) duração - a programação efetiva deve ser limitada a 3 (três) dias, a contar da cerimônia de abertura até a de encerramento, sem considerar o período para deslocamento;\nf) local - preferencialmente em hotel localizado em uma cidade com infra-estrutura adequada, com capacidade e know how para realização de convenções, com a distância limitada a 300 km da sede da Diretoria Regional que sediará o encontro, de forma a propiciar a imersão dos participantes durante todo o período de permanência no local. Além de comportar a quantidade de participantes, deverá dispor de área livre para realização de dinâmicas de grupos e atividades de inter-relacionamento;\ng) programação - A programação deverá contemplar palestras, dinâmicas vivenciais, atividades de integração, atividades motivacionais e outras, desde que relacionadas aos objetivos do encontro:\nI - deverão ser estabelecidos momentos para apresentação/discussão de informações da ECT, como por exemplo assuntos de interesse da força de vendas e que impactam na atuação desses profissionais, informações sobre planejamento estratégico da empresa e informações comerciais. Esses espaços, denominados “Momentos Correios”, serão conduzidos por representantes dos departamentos normativos da ECT, após análise e validação do Departamento de Vendas.\nh) recursos materiais e operacionais necessários - equipamentos de informáticas e audiovisuais (exemplo: computadores, notebooks e impressoras modernos, data show, telão, controles remotos, apontadores a laser, microfones, mesa de som, caixas de som, mastros para bandeiras, bandeiras, flip chart, máquinas fotográficas, filmadoras), os materiais de escritório/papelaria em geral (exemplo: blocos de anotações, canetas, pastas, papéis, pincéis, crachás), os materiais promocionais (exemplo: banners, folders, display), necessários à realização do evento.\ni) Orçamento - todas as despesas previstas com atividades e ações destinadas à realização do encontro da força de vendas deverão ser alocadas nas contas definidas no MANCAT, mód 1, cap 3, subitem 8.1.2. Para o registro orçamentário, devem ser obedecidos todos os dispositivos legais;\nj) responsáveis - definição dos profissionais e dos órgãos responsáveis pela realização do encontro da força de vendas, tanto da Administração Central como da Diretoria Regional, e definição de um gestor para acompanhamento geral do encontro;\nl) plano de ação - relação de todas as ações a serem executadas para a realização efetiva do evento na data prevista, com responsáveis por cada ação e prazo para conclusão.\n* * * * *', 0);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(12491, 'anexo', 299, NULL, 1, '1', 'Tipos de Encontros da Força de Vendas', 'a) Convenção de vendas: Encontro com Força de Vendas e Gestores com desempenhos destacados nas campanhas de vendas e no alcance das metas definidas pela empresa.\nb) Encontro de GCEs: Encontro de Gerentes de Contas Especiais em âmbito nacional.\nc) Encontro de ACOMs: Encontro de Assistentes Comerciais I, II e III, realizado por Região.\nd) Encontro de REVENs: Encontro de Gerentes das Regiões de Vendas.\ne) Encontro da Área de Suporte às Vendas: Encontro de Profissionais da Área de Suporte à Vendas\n1.1 De acordo com a programação anual do Departamento de Vendas, outros encontros poderão ser estabelecidas, conforme objetivos definidos neste capítulo.\n* * * * *', 0),
(12492, 'anexo', 300, NULL, 1, '1', 'REGRAS GERAIS', '1.1 De acordo com as normas postais, o objeto pertence ao remetente até a entrega ao destinatário.\n1.2 Conforme consta da Lei nº 6.538, de 22 de junho de 1978, os serviços postais são regidos por convenções e acordos internacionais ratificados e aprovados pelo Brasil.\n1.3 Os países membros da União Postal Universal - UPU e os operadores designados não aceitarão qualquer responsabilidade por declarações alfandegárias ou por decisões tomadas pela autoridade aduaneira no exame de itens submetidos ao controle alfandegário.\n1.3.1 Somente serão aceitas reclamações de objetos efetivamente recebidos pelos Correios.\n1.4 Prazos de aceitação da reclamação:', 0),
(12493, 'anexo', 300, 12492, 4, 'a', 'até 120 (cento e vinte) dias corridos para os serviços Documento Internacional Expresso, Exporta Fácil Expresso e Express Mail Service - EMS, contados a partir da data de postagem do objeto;', '', 1),
(12494, 'anexo', 300, 12492, 4, 'b', 'até 6 (seis) meses para os serviços Documento Internacional Standard, Exporta Fácil Standard, Exporta Fácil Econômico, Colis Postaux, Petit Paquet Registrado - PPR, Prime Exprés e Tracked, contados a partir da data de postagem do objeto;', '', 2),
(12495, 'anexo', 300, 12492, 4, 'c', 'até 90 (noventa) dias corridos para o serviço Correios Packet, contados a partir do dia seguinte à data prevista de entrega ou à data da efetiva entrega ou, na falta dessas, da data do evento postado.', '1.5 Para as reclamações de objetos da plataforma da UPU recebidas via operador designado, após o prazo definido para aceitação, não caberá qualquer tipo de indenização se o sinistro não tiver ocorrido em trâmite postal no Brasil.\n1.5.1 A reclamação deverá ser respondida de acordo com status do evento do rastreamento e das informações dos sistemas internacionais.\n1.6 Quando a reclamação for procedente e o serviço tiver previsão de indenização ou ressarcimento, estes caberão:', 3),
(12496, 'anexo', 300, 12492, 4, 'a', 'ao remetente no Brasil, referente aos objetos de exportação - Documento Internacional e Exporta Fácil;', 'b) à contratante, referente aos objetos de importação Correios Packet;\nc) ao responsável pela geração do pedido de pagamento dos tributos (Imposto de Importação e ICMS), logado ao ID Correios, mas a entrega foi realizada em endereço diferente do declarado;', 4),
(12497, 'anexo', 300, 12492, 4, 'd', 'ao operador designado do país de origem, via contas internacionais, para objetos de importação da plataforma UPU.', '1.6.1 A indenização ou o ressarcimento a serem pagos não deverão considerar perdas indiretas, como perda de receita ou danos morais.\n1.7 Indenização de Serviços Internacionais\n1.7.1 Motivos passíveis de indenização:', 5),
(12498, 'anexo', 300, 12492, 4, 'a', 'avaria e/ou espoliação;', '', 6),
(12499, 'anexo', 300, 12492, 4, 'b', 'devolução ou entrega indevidas;', '', 7),
(12500, 'anexo', 300, 12492, 4, 'c', 'extravio;', '', 8),
(12501, 'anexo', 300, 12492, 4, 'd', 'roubo.', '1.7.2 A apuração sobre avaria ou espoliação depois da efetiva entrega do objeto ao destinatário ou remetente só poderá ser considerada procedente se houver informações nos sistemas e mediante documento informando sobre a situação do objeto antes da entrega, seja por emissão de Boletim de Verificação - BV, Auto de Irregularidade - AI ou Termo de Constatação - TC ou nas situações em que o recebedor comprove que o dano não ocorreu após o recebimento.\n1.7.3 Caso o cliente remetente pleiteie indenização por avaria ou espoliação de um objeto, se for devida, será sempre pelo valor total e o objeto deverá ser retido pelos Correios.\n1.7.3.1 Para o destinatário, não caberá qualquer indenização nos casos de avaria total ou espoliação (subtração de conteúdo).\n1.7.4 Os objetos internacionais de importação localizados e reintegrados no fluxo postal após a comunicação do seu sinistro (roubo, extravio, avaria ou espoliação) e com análise de procedência para indenização, serão encaminhados para refugo e não haverá recuperação de receita.\n1.7.4.1 A exceção para ser realizada a recuperação de receita será para objetos de exportação postados a faturar e para encomenda Correios Packet com valores provisionados pelo contratante para o pagamento de impostos antecipadamente, ou seja, as postagens realizadas e recebidas no Programa Remessa Conforme - PRC.\n1.7.5 Quando objetos internacionais de exportação forem localizados e reintegrados ao fluxo postal após a comunicação do seu sinistro, roubo, extravio, avaria ou espoliação) e análise de procedência para indenização, o processo de indenização deverá ser cancelado, caso ela ainda não tenha sido paga ao cliente.\n1.7.6 Para objetos internacionais de exportação destinados aos Estados Unidos e com procedência para indenização, deverão ser devolvidos, também, os valores cobrados a título de desembaraço aduaneiro no destino, se houver.\n1.7.6.1 Remessas de exportação destinadas aos Estados Unidos possuem cobrança adicional específica, em função da legislação daquele país ter condicionado o envio ao recolhimento antecipado dos tributos aplicáveis e da necessidade de cobrir os custos do desembaraço aduaneiro naquele país.\n1.7.7 Não caberá indenização caso um objeto postal internacional se perder, for danificado, devolvido ou entregue de forma errônea ou com atraso em razão de circunstâncias fora do controle dos Correios, como nas situações abaixo:', 9),
(12502, 'anexo', 300, 12492, 4, 'a', 'caso fortuito ou de força maior, tais como: terremoto, ciclone, tempestade, inundação, guerra, queda de aeronave, embargo, condições climáticas inapropriadas, greves, atos ou omissões de autoridades públicas, ou similares que ocorrerem sem que haja culpa dos Correios;', '', 10),
(12503, 'anexo', 300, 12492, 4, 'b', 'qualquer ato ou omissão do remetente (declaração incorreta de conteúdo, mal acondicionamento ou endereço insuficiente), do destinatário ou de um terceiro;', '', 11),
(12504, 'anexo', 300, 12492, 4, 'c', 'qualquer ato ou omissão de um profissional de alfândega e de outros oficiais governamentais;', '', 12),
(12505, 'anexo', 300, 12492, 4, 'd', 'danos de natureza elétrica, magnética ou por perda ou avaria de imagens, gravações eletrônicas, fotográficas ou de filmagens;', '', 13),
(12506, 'anexo', 300, 12492, 4, 'e', 'devolução do objeto tenha sido ocasionada por erro do remetente ou por órgão de fiscalização;', '', 14),
(12507, 'anexo', 300, 12492, 4, 'f', 'envio de conteúdo proibido ou que apresentem indícios que o enquadre em alguma restrição ao transporte.', '1.7.7.1 Não haverá indenização parcial nos casos de avaria ou espoliação ocorrida no trâmite postal no Brasil.\n1.7.8 Os valores referentes à aplicação de multa por descumprimento das regras previstas no regulamento aduaneiro não serão indenizados.\n1.8 Ressarcimento de Serviços Internacionais de Importação\n1.8.1 Motivos passíveis de ressarcimento:', 15),
(12508, 'anexo', 300, 12492, 4, 'a', 'alteração do regime de tributação em função de falha pelos Correios, que resultar em cobrança a maior do que o devido;', '', 16),
(12509, 'anexo', 300, 12492, 4, 'b', 'geração do pedido de pagamento dos tributos realizado fora do ambiente “Minhas Importações” ou em outra chave Pix dos Correios;', '', 17),
(12510, 'anexo', 300, 12492, 4, 'c', 'geração de pedido de pagamento dos tributos para CPF do cliente logado ao ID Correios, mas a entrega foi realizada em endereço diferente do declarado;', '', 18),
(12511, 'anexo', 300, 12492, 4, 'd', 'pagamento de tributos em duplicidade.', '1.8.2 Não caberá ressarcimento caso um objeto postal internacional de importação se perder, for danificado, devolvido ou entregue de forma errônea ou com atraso em razão de circunstâncias fora do controle dos Correios, como nas situações abaixo:', 19),
(12512, 'anexo', 300, 12492, 4, 'a', 'caso fortuito ou de força maior, tais como: terremoto, ciclone, tempestade, inundação, guerra, queda de aeronave, embargo, condições climáticas inapropriadas, greves, atos ou omissões de autoridades públicas, ou similares que ocorrerem sem que haja culpa dos Correios;', '', 20),
(12513, 'anexo', 300, 12492, 4, 'b', 'qualquer ato ou omissão do remetente (declaração incorreta de conteúdo, mal acondicionamento ou endereço insuficiente), do destinatário, de um terceiro, de um profissional de alfândega e de outros oficiais governamentais;', '', 21),
(12514, 'anexo', 300, 12492, 4, 'c', 'danos de natureza elétrica, magnética ou por perda ou avaria de imagens, gravações eletrônicas, fotográficas ou de filmagens;', '', 22),
(12515, 'anexo', 300, 12492, 4, 'd', 'devolução do objeto tenha sido ocasionada por erro do remetente ou por órgão de fiscalização;', '', 23),
(12516, 'anexo', 300, 12492, 4, 'e', 'envio de conteúdo proibido ou que apresentem indícios que as enquadrem em alguma restrição ao transporte.', '1.8.2.1 Não haverá indenização parcial nos casos de avaria ou espoliação ocorrida no trâmite postal no Brasil\n1.9 Ressarcimento de Serviços Internacionais de Exportação\n1.9.1 Caberá ressarcimento parcial do valor da postagem e integral do valor pago a título de ad valorem (se contratado o adicional de Valor Declarado) na suspensão da entrega da remessa de exportação, solicitada pelo cliente no portal Correios, e quando do cancelamento da exportação por circunstâncias que inviabilizem o envio da remessa ao exterior e estejam fora do controle dos Correios, desde que a remessa de exportação com registro tenha seu fluxo interrompido antes da apresentação à companhia aérea para envio internacional, como nas situações a seguir:', 24),
(12517, 'anexo', 300, 12492, 4, 'a', 'caso fortuito ou de força maior, tais como: terremoto, ciclone, tempestade, inundação, guerra, queda de aeronave, embargo, condições climáticas inapropriadas, greves, atos ou omissões de autoridades públicas, ou similares que ocorrerem sem que haja culpa dos Correios;', '', 25),
(12518, 'anexo', 300, 12492, 4, 'b', 'qualquer ato ou omissão do cliente (declaração incorreta de conteúdo, mal acondicionamento ou endereço insuficiente), do destinatário, de um terceiro, de um profissional de alfândega e de outros oficiais governamentais;', '', 26),
(12519, 'anexo', 300, 12492, 4, 'c', 'danos de natureza elétrica, magnética ou por perda ou avaria de imagens, gravações eletrônicas, fotográficas ou de filmagens;', '', 27),
(12520, 'anexo', 300, 12492, 4, 'd', 'devolução do objeto que tenha sido ocasionada por erro do cliente ou por órgão de fiscalização;', '', 28),
(12521, 'anexo', 300, 12492, 4, 'e', 'envio de conteúdo proibido ou que apresentem indícios que as enquadrem em alguma restrição ao transporte;', '', 29),
(12522, 'anexo', 300, 12492, 4, 'f', 'efetivação da suspensão da entrega, após solicitação formal do cliente por meio da funcionalidade de Suspensão de Entrega de Objetos, no portal dos Correios.', '1.9.2 Para análise da procedência do ressarcimento parcial do valor da postagem e integral do ad valorem, deve haver solicitação formal do cliente, com abertura de manifestação no Fale Conosco.\n1.9.3 São passíveis de ressarcimento os serviços de exportação registrados:', 30),
(12523, 'anexo', 300, 12492, 4, 'a', 'Exporta Fácil Expresso;', '', 31),
(12524, 'anexo', 300, 12492, 4, 'b', 'Exporta Fácil Standard;', '', 32),
(12525, 'anexo', 300, 12492, 4, 'c', 'Exporta Fácil Econômico;', '', 33),
(12526, 'anexo', 300, 12492, 4, 'd', 'Documento Internacional Expresso;', '', 34),
(12527, 'anexo', 300, 12492, 4, 'e', 'Documento Internacional Standard com adicional de registro.', '1.9.4 Não serão ressarcidos valores relativos a embalagens, etiquetas de registro ou outros produtos dos Correios que tenham valor próprio.\n1.9.5 Nos casos de registros de manifestação referentes a objetos destinados aos Estados Unidos, serão considerados os mesmos critérios para ressarcimento dos serviços postais (postagem e ad valorem) e consideradas regras específicas para devolução dos valores eventualmente pagos pelo cliente no ato da postagem para desembaraço aduaneiro naquele país.\n1.10 Ao final do processo, a área responsável pela apuração deverá enviar resposta ao solicitante, com informação conclusiva a respeito do objeto reclamado.', 35),
(12528, 'anexo', 300, NULL, 1, '2', 'REGRAS PARA O TRATAMENTO DAS MANIFESTAÇÕES DOS OBJETOS INTERNACIONAIS DE EXPORTAÇÃO', '2.1 Para a apuração, deverão ser consultados todos os sistemas disponíveis para obtenção das informações sobre a situação do objeto reclamado e/ou de seus dados de expedição (incluindo, mas não se limitando ao Sistema de Rastreamento - SRO, ao International Postal System - IPS, EMS Smart Tracking e Global Customer Care Service - GCSS).\n2.1.1 As unidades envolvidas no tratamento do objeto reclamado deverão ser consultadas com o objetivo de localizá-lo, caso não haja comprovação da sua saída do Brasil.\n2.2 A indenização por extravio, descrita no subitem 1.7.1, também é devida quando um objeto registrado em devolução ao remetente não for recebido no Brasil após 3 (três) meses do operador designado de destino registrar o evento de saída do exterior.\n2.3 Para objetos com evento “Expedido” ao exterior, deverão ser considerados os seguintes prazos em dias corridos, a partir da data do evento, para consulta ao país de destino:', 36),
(12529, 'anexo', 300, 12528, 4, 'a', 'Documento Internacional Expresso e Exporta Fácil Expresso: 15 (quinze) dias;', '', 37),
(12530, 'anexo', 300, 12528, 4, 'b', 'Documento Internacional Standard, Exporta Fácil Standard e Exporta Fácil Econômico: após o prazo previsto de entrega, de acordo com o país.', '2.4 Para objetos que não tiverem o evento “Expedido” para o exterior, deverão ser considerados os seguintes prazos, em dias corridos, a partir da data da postagem, para consulta ao país de destino:', 38),
(12531, 'anexo', 300, 12528, 4, 'a', 'Documento Internacional Expresso, Exporta Fácil Expresso e Exporta Fácil Standard: 15 (quinze) dias;', '', 39),
(12532, 'anexo', 300, 12528, 4, 'b', 'Documento Internacional Standard e Exporta Fácil Econômico: 30 (trinta) dias.', '2.5 Deverão ser solicitados esclarecimentos junto à área responsável do Centro Internacional pela expedição do objeto, antes de enviar a consulta ao operador designado de destino.\n2.6 A consulta para o operador designado de destino deverá ser enviada preferencialmente via sistema de atendimento ou via formulário CN 08, devidamente preenchido, por e-mail.\n2.6.1 Se for por meio de correspondência, deverá ser utilizado o serviço administrativo na modalidade Standard com registro.\n2.7 O formulário CN 08 deverá ser preenchido com todos os dados solicitados, incluindo as informações obrigatórias sobre os valores pagos.\n2.8 Um único CN 08 pode conter mais de um objeto, desde que sejam do mesmo remetente e enviados para o mesmo endereço de destino.\n2.9 Se for enviado via postal, o formulário CN 08 deve ser respondido pelo operador designado, em até 2 (dois) meses a contar da data inicial.\n2.10 Se for enviado por meio eletrônico, o formulário CN 08 deve ser respondido pelo operador designado, no prazo de 30 (trinta) dias da data de envio.\n2.11 Se operador designado não responder nos prazos especificados nos subitens 2.9 e 2.10, a área responsável pelo processo de pós-venda deverá registrar o objeto como “Extraviado” e prosseguir com a indenização.\n2.12 Quando o objeto for encaminhado para o destino e envolver mais de um operador designado, via trânsito entre os países, o primeiro operador designado deverá ser consultado.\n2.12.1 Caso os Correios não recebam retorno em até 10 (dez) dias, o segundo operador designado deverá ser consultado.\n2.13 Caso o operador designado de destino registre o evento de entrega do objeto ao destino e depois houver a reclamação de que o objeto está avariado ou espoliado, a reclamação deverá ser formalizada no país de destino, para apuração das condições de recebimento e entrega.\n2.14 Caso seja registrado o evento de entrega, mas houver reclamação de que o destinatário não recebeu o objeto, o operador designado de destino poderá fornecer, em até 30 (trinta) dias:', 40),
(12533, 'anexo', 300, 12528, 4, 'a', 'a confirmação da entrega do objeto, via carta, aviso de entrega CN 07 ou outro meio, assinado pelo destinatário; ou', '', 41),
(12534, 'anexo', 300, 12528, 4, 'b', 'uma cópia de uma assinatura de aceitação ou outra forma de prova de recebimento do destinatário.', '2.14.1 Não caberá indenização pela não entrega ainda que não seja possível comprovar quem foi o recebedor do objeto.\n2.15 Para objetos postados como Documento Internacional Expresso ou Exporta Fácil Expresso, enviar consulta para o operador designado de destino, preferencialmente via sistema de atendimento a reclamações, ou enviar o formulário E-03 por e-mail.\n2.15.1 No caso de consulta pelo operador designado, as respostas devem ser realizadas pelo mesmo meio que foi feita a consulta.\n2.16 As informações constantes do sistema Fale Conosco e do processo aberto no Sistema de Reclamação Internacional - SRI serão a base para a análise da procedência e definição do montante a ser indenizado/ressarcido ao cliente.\n2.17 Todas as ações que envolverem processos externos ao sistema Fale Conosco, como contatos por e-mail e consultas a operadores pelo sistema de atendimento a reclamações, durante a apuração das manifestações internacionais deverão ser registradas no sistema Fale Conosco no campo “Ocorrência”.\n2.18 Os arquivos necessários à análise de procedência e/ou definição de valores a serem pagos ao cliente deverão ser anexados ao sistema SRI, sendo o executor da atividade responsável pela inclusão e veracidade de cada informação anexada e/ou incluída no processo.\n2.19 Expirado o prazo de entrega do objeto reclamado e o prazo de tratamento da reclamação, em não havendo solução nem justificativa para a não conformidade do serviço contratado pelo cliente, a área de pós-vendas deverá registrar o objeto como “Extraviado” e iniciar o processo de indenização.\n2.20 Para os serviços Documento Internacional Expresso, Exporta Fácil Econômico, Exporta Fácil Standard, Exporta Fácil Expresso que tiverem como últimos eventos “Extravio” ou “Roubo” no Brasil no sistema de rastreamento, deverá ser iniciado o processo de indenização.\n2.21 Quando a reclamação referente à avaria total, extravio ou roubo for procedente, a indenização ao titular do direito de recebê-la será paga como segue:', 42),
(12535, 'anexo', 300, 12528, 4, 'a', 'sem valor declarado: devolução do valor de postagem do serviço principal e dos serviços adicionais, quando contratados, vigentes na data da postagem, e do valor referente à indenização automática, se houver para o serviço, exceto embalagem;', '', 43),
(12536, 'anexo', 300, 12528, 4, 'b', 'com valor declarado: devolução do valor de postagem do serviço principal e dos serviços adicionais, quando contratados, exceto ad valorem e embalagem.', '2.22 Ao receber resposta do operador designado de destino, deverá ser realizada a baixa da reclamação no SRI e Fale Conosco.\n2.23 Ressarcimento de Remessas de Exportação\n2.23.1 Para os casos de serviços de exportação registrados não concluídos, que se enquadrem nos critérios do subitem 1.9 deste Anexo, caberá ressarcimento dos preços de postagem ao cliente, observando-se os seguintes percentuais de valores a serem retidos e, por consequência, a serem pagos:\nServiço	Retenção	Ressarcimento\nExporta Fácil\n(Expresso, Standard ou Econômico)	24,6%	75,4%\nDocumento Internacional\n(Expresso ou Standard com Registro)	34,9%	65,1%\n2.23.2 O registro do ressarcimento parcial deverá ser efetuado na conta contábil 31198.010001 - Receitas Canceladas.\n2.23.3 O ressarcimento deverá ser calculado, exclusivamente, sobre o valor pago no ato da postagem.\n2.23.4 O valor pago como ad valorem na contratação do adicional Valor Declarado deverá ser ressarcido integralmente, caso não tenha ocorrido sinistro com o objeto.\n2.23.5 Quando se tratar de ressarcimento de postagem destinada aos Estados Unidos, deverão ser acrescidos na devolução os valores integrais pagos pelo cliente no ato da postagem para desembaraço aduaneiro nos EUA, se houver.\n2.23.5.1 O ressarcimento dos valores mencionados no subitem 2.23.5 e a devolução dos valores citados no subitem 1.7.6 deverão ser feitos na conta contábil 21202.160009 - Imposto de Exportação.\n2.23.6 Não deverão constar do cálculo do ressarcimento valores relativos a embalagens, etiquetas de registro ou outros produtos dos Correios que tenham valor próprio.\n2.23.7 A procedência do pedido de ressarcimento deverá levar em consideração a necessidade de o objeto estar com o evento finalizador “Distribuído ao Remetente” ou “Entregue” em endereço do Brasil, tendo como anteriores eventos que denotam interrupção do fluxo de exportação, incluindo, mas não se limitando, a:', 44),
(12537, 'anexo', 300, 12528, 4, 'a', 'FC-14 - Envio cancelado - embargo no exterior;', '', 45),
(12538, 'anexo', 300, 12528, 4, 'b', 'BD-81 - Exportação Cancelada;', '', 46),
(12539, 'anexo', 300, 12528, 4, 'c', 'FC-42 - Objeto contém produto não permitido;', '', 47),
(12540, 'anexo', 300, 12528, 4, 'd', 'BD-62 - Objeto em devolução à origem - Determinação da Receita Federal;', '', 48),
(12541, 'anexo', 300, 12528, 4, 'e', 'FC 52 - Objeto com conteúdo restrito ou tem limitação de transporte aéreo.', '2.23.8 As alíneas do subitem 2.23.7 não são exaustivas.\n2.23.8.1 Considerando o dinamismo do fluxo operacional, todos os eventos que denotarem interrupção do fluxo de exportação antes da expedição para o país de destino podem ser incluídos nas automações conduzidas pelo pós-venda.\n2.23.9 O motivo interno a ser utilizado no Fale Conosco será o 241 - \"Objeto não saiu do Brasil\".', 49),
(12542, 'anexo', 300, NULL, 1, '3', 'REGRAS PARA O TRATAMENTO DAS MANIFESTAÇÕES DOS OBJETOS INTERNACIONAIS DE IMPORTAÇÃO DA PLATAFORMA UPU VIA OPERADORES DESIGNADOS', '3.1 Para os serviços Carta Registrada, EMS, Colis Postaux, Petit Paquet Registrado - PPR e Petit Paquet Simples - PPS, caso seja cabível indenização, os valores serão repassados ao operador designado de origem, via contas internacionais, exceto para valores referentes aos tributos (Imposto de Importação e Imposto Estadual) e serviços postais em que a indenização é realizada para o importador/destinatário ou ao responsável pela geração do pedido de pagamento via ID Correios.\n3.1.1 Será necessária a formalização da reclamação do operador designado do país de origem para que seja realizada abertura do processo de apuração.\n3.1.2 Não caberá indenização ao destinatário de valor referente a despesa de envio do objeto para o Brasil.\n3.1.2.1 Quando do recebimento de consulta de operador designado, deverá ser verificado no sistema Fale Conosco se já houve reclamação e processo de indenização referente à cobrança de tributos (Imposto de Importação e Imposto Estadual) e serviços postais.\n3.1.2.1.1 Se sim, as informações da apuração deverão ser utilizadas para responder ao país de origem.\n3.2 Após o recebimento do formulário CN08, E-03 ou reclamações enviadas por meio de sistema de atendimento a reclamações dos operadores designados de origem, deverá ser observado o prazo de aceitação e o preenchimento das informações.\n3.2.1 Em caso de não cumprimento do prazo e/ou se houver problemas no preenchimento que impeçam as apurações, o formulário deverá ser devolvido ao operador designado de origem.\n3.3 Os sistemas disponíveis deverão ser consultados para obtenção das informações sobre a situação do objeto reclamado e/ou de seus dados de expedição e também o SRI para verificação da existência de reclamação formalizada no país de origem do objeto.\n3.4 Todas as unidades envolvidas deverão ser consultadas se não houver comprovação de recebimento no Brasil, comprovação de entrega ao destinatário ou justificativa para a desconformidade da prestação do serviço.\n3.5 Caso o objeto tenha chegado ao Brasil, consultar a unidade operacional e considerar a resposta recebida para definir se a manifestação é procedente, para ressarcimento ao operador designado via contas internacionais.\n3.6 Em caso de constatação de desconformidade no serviço prestado em âmbito nacional, reconhecer a responsabilidade dos Correios junto ao operador designado de origem por meio de envio de formulário CN08 ou E03 ou comunicação via sistema de atendimento a reclamações com as informações sobre o objeto.\n3.7 Se houver informação sobre a entrega do objeto no sistema de rastreamento, ela deverá ser enviada ao correio de origem como prova de entrega, conforme previsto nos regulamentos de serviços da Convenção Postal Universal.\n3.8 Não caberá indenização para a avaria ou espólio que ultrapasse o valor segurado aceito pelo Correio Brasileiro no Compêndio Postal, no Compêndio de Encomendas e no Guia Operacional EMS.\n3.9 Regras para considerar objetos de importação UPU como extraviados:', 50),
(12543, 'anexo', 300, 12542, 4, 'a', 'objetos EMS que tiverem como último evento “Conferido - Recebido no Brasil” num período de 10 (dez) dias corridos;', '', 51),
(12544, 'anexo', 300, 12542, 4, 'b', 'objetos Prime Exprés, Tracked e Colis Postaux que tiverem como último evento “Conferido - Recebido no Brasil” num período de 30 (trinta) dias;', '', 52),
(12545, 'anexo', 300, 12542, 4, 'c', 'objeto EMS que tiver como último evento “Objeto em trânsito para unidade” num período superior a 7 (sete) dias corridos da data prevista para entrega;', '', 53),
(12546, 'anexo', 300, 12542, 4, 'd', 'objetos Prime Exprés, Tracked e Colis Postaux que tiverem como último evento “Objeto em trânsito para a unidade” num período superior a 10 (dez) dias corridos da data prevista para entrega', 'Nota: a unidade de destino deverá confirmar o não encaminhamento e/ou a não entrega do objeto e lançar o evento de extravio no sistema de rastreamento.', 54),
(12547, 'anexo', 300, 12542, 4, 'e', 'os objetos Petit Paquet Registrado - PPR, Petit Paquet Simples - PPS e Carta Registrada Internacional que tiverem como último evento no sistema de rastreamento como “Recebido no Brasil” ou “Pagamento confirmado” ou “Objeto expedido” num período superior a data prevista de entrega de 15 (quinze) dias úteis;', 'Nota: a unidade de destino deverá confirmar o não encaminhamento ou a não entrega do objeto e lançar o registro do evento de extravio no sistema de rastreamento.', 55),
(12548, 'anexo', 300, 12542, 4, 'f', 'objetos na modalidade expressa que tiverem como último evento “Pagamento confirmado” num período superior a 10 (dez) dias corridos;', '', 56),
(12549, 'anexo', 300, 12542, 4, 'g', 'objetos na modalidade Standard que tiverem como último evento “Pagamento confirmado” num período superior a 20 (vinte) dias corridos.', '3.10 Caso não haja o lançamento do evento de extravio pela unidade, e o cliente não tenha registrado a reclamação dentro do prazo previsto, será permitido o registro de Manifestação Extemporânea em função de falha operacional com o repasse da despesa para a unidade que contribuiu para a perda de prazo.\n3.11 Para objeto de importação da plataforma UPU que tiver como último evento “Roubo” ou “Extravio”, se tiver consulta do operador designado sobre este objeto, deverá ser providenciado a informação ao operador designado de origem, e se a reclamação for dada como procedente e houver previsão para indenização, esta ocorrerá para o remetente via acerto de contas.\n3.12 O ressarcimento será devido quando ocorrer alteração do regime de tributação em função de falha dos Correios.\n3.12.1 Nesse caso, será devolvida a diferença dos valores cobrados a maior em relação ao efetivamente devido, considerando as alíquotas vigentes.\n3.12.2 Para as situações abaixo, será devido o ressarcimento do valor pago pelo cliente, seja via boleto ou via Pix, após a confirmação do recebimento pelos Correios, no Sistema de Serviços Internacionais de Importação - SSII e PagFácil e do recebimento do valor do Pix pelo Departamento Financeiro:', 57),
(12550, 'anexo', 300, 12542, 4, 'a', 'quando da geração do pedido de pagamento dos tributos (Imposto de Importação e Imposto Estadual) realizado fora do ambiente “Minhas Importações” ou em outra chave Pix dos Correios;', '', 58),
(12551, 'anexo', 300, 12542, 4, 'b', 'quando ocorrer a vinculação para pagamento ao CPF do cliente logado ao ID Correios, mas a entrega foi realizada em endereço diferente do declarado;', '', 59),
(12552, 'anexo', 300, 12542, 4, 'c', 'quando ocorrer o pagamento dos tributos em duplicidade.', '3.13 O ressarcimento ao cliente será realizado por meio de geração de voucher com débito em conta contábil específica.\n3.14 Se for comprovada falha operacional ou de sistemas corporativos ou alteração do status do objeto em função de decisão de autoridade aduaneira, após apuração pela área responsável, deverá ser providenciado a devolução dos valores dos tributos (Imposto de Importação e Imposto Estadual).', 60),
(12553, 'anexo', 300, NULL, 1, '4', 'REGRAS PARA O TRATAMENTO DAS MANIFESTAÇÕES DOS OBJETOS INTERNACIONAIS DE IMPORTAÇÃO - CORREIOS PACKET', '4.1 Motivos passíveis de indenização:', 61),
(12554, 'anexo', 300, 12553, 4, 'a', 'avaria/espoliação;', '', 62),
(12555, 'anexo', 300, 12553, 4, 'b', 'devolução ou entrega indevida;', '', 63),
(12556, 'anexo', 300, 12553, 4, 'c', 'extravio;', '', 64),
(12557, 'anexo', 300, 12553, 4, 'd', 'roubo.', '4.2 Por se se tratar de prazos previstos de entrega, não haverá indenização por atraso\n4.2.1 Encomendas constantes nas malas transportadas entre o aeroporto (zona primária) e o Centro Internacional (zona secundária) somente serão passíveis de indenização quando houver constatação de extravio da mala em sua totalidade.\n4.3 As regras para tratamento e distribuição do serviço Correios Packet, após a sua nacionalização, serão as mesmas previstas para os serviços de encomendas nacionais:', 65),
(12558, 'anexo', 300, 12553, 4, 'a', 'Correios Packet Express: de acordo com as regras de tratamento, distribuição e prazos estabelecidos para o serviço de encomenda nacional SEDEX;', '', 66),
(12559, 'anexo', 300, 12553, 4, 'b', 'Correios Packet Standard: de acordo com as regras de tratamento, distribuição e os prazos estabelecidos para o serviço de encomenda nacional PAC.', '4.4 Regras para considerar uma encomenda Correios Packet como extraviada:', 67),
(12560, 'anexo', 300, 12553, 4, 'a', 'encomenda com o último evento “Conferido - Recebido/Brasil” num período superior a 60 (sessenta) dias corridos;', '', 68),
(12561, 'anexo', 300, 12553, 4, 'b', 'encomenda da modalidade expressa que tiver como último evento “Objeto em trânsito para unidade” num período superior a 7 (sete) dias corridos da data prevista para entrega;', '', 69),
(12562, 'anexo', 300, 12553, 4, 'c', 'encomenda da modalidade Standard que tiver como último evento “Objeto em trânsito para a unidade” num período superior a 10 (dez) dias corridos da data prevista para entrega;', '', 70),
(12563, 'anexo', 300, 12553, 4, 'd', 'encomenda da modalidade expressa que tiver como último evento “Pagamento confirmado” num período superior a 10 (dez) dias corridos da data prevista para entrega;', '', 71),
(12564, 'anexo', 300, 12553, 4, 'e', 'encomenda da modalidade Standard que tiver como último evento “Pagamento confirmado” num período superior a 20 (vinte) dias corridos da data prevista para entrega.', '4.5 A encomenda Correios Packet que for acompanhada na apuração de Nível de Serviço Padrão - NSP poderá ter prazo diferenciado para lançamento do evento de extravio.\n4.6 Toda encomenda considerada extraviada deverá ter o bloqueio de entrega.\n4.7 A contratante do serviço, o destinatário da encomenda ou o responsável pela geração do pedido de pagamento dos tributos poderão registrar reclamação.\n4.8 Quando a reclamação referente à avaria total, extravio ou roubo for procedente, a indenização ao titular do direito de recebê-la será paga como segue:', 72),
(12565, 'anexo', 300, 12553, 4, 'a', 'Correios Packet Express: devolução do valor de postagem do serviço principal vigente na data da postagem e do valor referente a indenização automática;', '', 73),
(12566, 'anexo', 300, 12553, 4, 'b', 'Correios Packet Standard: devolução do valor de postagem do serviço principal vigente na data da postagem e do valor referente a indenização automática.', '', 74),
(12567, 'anexo', 300, 12553, 4, 'c', 'Serviço de desembaraço: devolução dos valores do serviço de desembaraço das encomendas recebidas no Brasil e/ou dos valores de tributos (Imposto de Importação e Imposto Estadual) se houver a saída do Centro Internacional e antes da entrega ou a retirada pela Contratante.', '4.9 Encomenda Correios Packet com valores provisionados pela contratante para o pagamento antecipado dos tributos (Imposto de Importação e Imposto Estadual) serão passíveis de recuperação de receita conforme critérios abaixo:', 75),
(12568, 'anexo', 300, 12553, 4, 'a', 'encomenda constante na fila para pagamento de indenização reintegrada no fluxo postal deverá ter a alteração do motivo para \"serviços postais não prestados\" e com o pagamento somente dos preços postais;', '', 76),
(12569, 'anexo', 300, 12553, 4, 'b', 'após o pagamento da indenização, se a encomenda for reintegrada ao fluxo postal e tiver o evento \"Distribuído ao Remetente\" deverão ser recuperados os valores da indenização automática e tributos (Imposto de Importação e Imposto Estadual);', '', 77),
(12570, 'anexo', 300, 12553, 4, 'c', 'após o pagamento da indenização, se a encomenda for reintegrada e tiver o evento \"Entregue no Destino\", a contratante deverá ser consultada para a recuperação de todos os valores pagos a título de indenização — preços postais, indenização automática e tributos (Imposto de Importação e Imposto Estadual).', '4.10 O ressarcimento será devido quando ocorrer alteração do regime de tributação em função de falha dos Correios.\n4.10.1 Nesse caso, será devolvida a diferença dos valores cobrados a maior em relação ao efetivamente devido, considerando as alíquotas vigentes e análise se houve indenização da encomenda.\n4.10.2 Para as situações abaixo, será devido o ressarcimento do valor pago pelo cliente seja via boleto ou via Pix, após a confirmação do recebimento pelos Correios, nos sistemas (SSII e PagFácil) e do recebimento do valor do Pix pelo Departamento Financeiro:', 78),
(12571, 'anexo', 300, 12553, 4, 'a', 'quando da geração do pedido de pagamento dos tributos (Imposto de Importação e Imposto Estadual) realizado fora do ambiente Minhas Importações ou em outra chave Pix dos Correios;', '', 79),
(12572, 'anexo', 300, 12553, 4, 'b', 'quando ocorrer a vinculação para pagamento ao CPF do cliente logado ao ID Correios, mas a entrega foi realizada em endereço diferente do declarado;', '', 80),
(12573, 'anexo', 300, 12553, 4, 'c', 'quando ocorrer o pagamento dos tributos em duplicidade.', '4.11 O ressarcimento ao cliente será realizado por meio de geração de voucher com débito em conta contábil específica.\n4.12 Se for comprovado falha operacional ou de sistemas corporativos ou alteração do status do objeto em função de decisão de autoridade aduaneira, após apuração pela área responsável, deverá ser providenciado a devolução do valor dos preços postais vigentes na data da postagem e os valores dos tributos (Imposto de Importação e Imposto Estadual).', 81),
(12574, 'anexo', 300, NULL, 1, '5', 'PROCEDIMENTOS PÓS-INDENIZAÇÃO', '5.1 A alocação de custos da despesa relativa à indenização de objeto internacional de exportação será da unidade que comprovadamente deu causa à indenização.\n5.2 Se não for possível identificar a unidade responsável, dividir o montante igualitariamente entre as unidades expedidora e receptora do objeto, se o último evento registrado no sistema de rastreamento seja de “Expedido”, em situações de extravio ou roubo.\n5.3 Se o último evento registrado no sistema de rastreamento for diferente de “Expedido”, em situações de extravio ou roubo, alocar na última unidade pela qual passou o objeto.\n5.4 Se ocorreu espólio ou avaria no trâmite postal no Brasil, alocar na última unidade pela qual passou o objeto.\n5.5 Para objetos de exportação, quando a responsabilidade pela indenização recair sobre a companhia aérea contratada, o operador logístico ou o operador designado de destino, a alocação de custos da despesa relativa à indenização deverá ser no MCU do Departamento de Gestão de Produtos Internacionais.\n5.6 Para objetos de importação, efetuar alocação de custos da despesa relativa à indenização na unidade que comprovadamente deu causa à indenização.\n5.7 Se não for possível identificar a unidade responsável, dividir o montante igualitariamente entre as unidades expedidora e receptora do objeto, se o último evento registrado no sistema de rastreamento seja “Expedido”, em situações de extravio, roubo avaria total.\n5.8 Caso o último evento registrado no sistema de rastreamento seja diferente de “Expedido” e não constar a unidade de destino e para as situações de extravio, roubo ou avaria total alocar na última unidade pela qual o objeto passou.\n* * * * *', 82),
(12575, 'anexo', 303, NULL, 1, '1', 'FLUXO GERAL', '1.1 Fluxo do Subprocesso Armazenagem dos Produtos\n1.2 Fluxo do Subprocesso Atendimento de Pedidos dos Produtos\n1.3 Fluxo do Subprocesso Tratamento da Expedição dos Produtos\n1.4 Fluxo do Subprocesso Atendimento de Devolução dos Produtos\n* * * * *', 0),
(12576, 'anexo', 305, NULL, 1, '1', 'FLUXO GERAL DO SERVIÇO CORREIOS LOG SUPRI', '', 0),
(12577, 'anexo', 305, 12576, 2, '1.1', 'Fluxo do Subprocesso Recebimento de Carga', '', 1),
(12578, 'anexo', 305, 12576, 2, '1.2', 'Fluxo do Subprocesso Conferência Exaustiva', '', 2),
(12579, 'anexo', 305, 12576, 2, '1.3', 'Fluxo do Subprocesso Armazenagem', '', 3),
(12580, 'anexo', 305, 12576, 2, '1.4', 'Fluxo do Subprocesso Atendimento de Pedidos', '* * * * *', 4),
(12581, 'anexo', 306, NULL, 1, '1', 'DEFINIÇÃO', '', 0),
(12582, 'anexo', 306, 12581, 2, '1.1', 'O Log Supri é o serviço de gestão e distribuição de suprimentos, que consiste no recebimento da carga, conferência exaustiva, armazenagem, separação e atendimento de pedidos, montagem de kits, expedição, distribuição e tratamento de devolução de materiais de consumo, escritório, mobiliário e permanente dos clientes pelos Correios.', '', 1),
(12583, 'anexo', 306, 12582, 3, '1.1.1', 'Para a modalidade In House do Log Supri, os Correios executam as atividades de intralogística dentro do armazém do cliente, em qualquer munícipio do Brasil.', '', 2),
(12584, 'anexo', 306, 12581, 2, '1.2', 'Atividades contempladas no Correios Log Supri:', '', 3),
(12585, 'anexo', 306, 12584, 4, 'a', 'intralogística: consiste no recebimento dos itens, conferência exaustiva, armazenagem, separação e atendimento de pedidos, montagem de kits, expedição e atividades correlatas. A intralogística poderá ser executada no armazém dos Correios ou no armazém do cliente (modalidade In house);', '', 4),
(12586, 'anexo', 306, 12584, 4, 'b', 'distribuição: é o encaminhamento do objeto ao destino final, conforme definido pelo cliente;', '', 5),
(12587, 'anexo', 306, 12584, 4, 'c', 'tratamento de devolução: consiste no recebimento dos objetos devolvidos, identificação dos motivos de não entrega, incorporação da carga ao estoque e repasse das informações ao cliente.', '', 6),
(12588, 'anexo', 306, NULL, 1, '2', 'PÚBLICO-ALVO', '', 7),
(12589, 'anexo', 306, 12588, 2, '2.1', 'Órgãos públicos e empresas privadas que necessitem de solução logística na cadeia de suprimentos, considerando desde o recebimento e armazenagem de materiais até a distribuição e o atendimento de pedidos nos Centros de Logística Integrada dos Correios.', '', 8),
(12590, 'anexo', 306, 12589, 3, '2.1.1', 'Clientes que desejam terceirizar operações mercantis dentro de suas instalações poderão utilizar a modalidade In House.', '', 9),
(12591, 'anexo', 306, NULL, 1, '3', 'ABRANGÊNCIA', '', 10),
(12592, 'anexo', 306, 12591, 2, '3.1', 'As atividades de intralogística serão executadas nos Centros de Logística Integrada - CLIs dos Correios, instalados nas seguintes localidades:', '', 11),
(12593, 'anexo', 306, 12592, 4, 'a', 'Belo Horizonte/MG;', '', 12),
(12594, 'anexo', 306, 12592, 4, 'b', 'Brasília/DF;', '', 13),
(12595, 'anexo', 306, 12592, 4, 'c', 'Região Metropolitana de São Paulo/SP;', '', 14),
(12596, 'anexo', 306, 12592, 4, 'd', 'Rio do Janeiro/RJ.', '', 15),
(12597, 'anexo', 306, 12592, 3, '3.1.1', 'Na modalidade In House as atividades de intralogística serão executadas nas instalações do cliente, em qualquer munícipio do território brasileiro.', '', 16),
(12598, 'anexo', 306, 12591, 2, '3.2', 'A etapa de distribuição é realizada em âmbito nacional.', '', 17),
(12599, 'anexo', 306, NULL, 1, '4', 'ETAPAS DO SERVIÇO', '', 18),
(12600, 'anexo', 306, 12599, 2, '4.1', 'O Correios Log Supri está estruturado em 4 (quatro) etapas:', '', 19),
(12601, 'anexo', 306, 12600, 4, 'a', 'gestão de armazenagem: compreendendo a conferência, o recebimento da carga proveniente dos clientes, a sua incorporação ao estoque e a alocação estratégica dos itens nos diversos espaços do armazém;', '', 20),
(12602, 'anexo', 306, 12600, 4, 'b', 'processamento de pedidos: é o processo de realização das atividades de impressão de pedidos ou notas fiscais, etiquetagem e montagem de caixa. Durante este processo os pedidos recebidos são coletados no armazém, conferidos e agrupados de acordo com as instruções do cliente. Os itens são preparados para o envio, com etiquetas de identificação e rastreamento, sendo embalados de forma adequada para garantir a integridade dos produtos;', '', 21),
(12603, 'anexo', 306, 12600, 4, 'c', 'tratamento de devolução: envolve procedimentos para lidar com as devoluções de materiais de acordo com as diretrizes do cliente, incluindo a conferência dos itens devolvidos e o tratamento para armazenamento ou destinação final;', '', 22),
(12604, 'anexo', 306, 12600, 4, 'd', 'expedição e distribuição: realizada após a separação dos pedidos ou montagem dos kits. Os itens serão distribuídos conforme as diretrizes previamente acordadas entre as partes. O cliente possui a autonomia para escolher a modalidade de distribuição inerente ao seu contrato, conforme Política Comercial, ou utilizar as modalidades Urgente e Não Urgente, disponíveis no Correios Log Supri. No caso da modalidade In House, o cliente também têm a responsabilidade de definir a abrangência e os horários de geração de pedidos, garantindo uma sincronia eficaz com suas operações internas.', '', 23),
(12605, 'anexo', 306, NULL, 1, '5', 'ESPECIFICIDADES', '', 24),
(12606, 'anexo', 306, 12605, 2, '5.1', 'Todas as especificidades essenciais para a correta execução do serviço estão minuciosamente detalhadas no Guia de Execução Operacional do Correios Log Supri, disponível no Espaço do Consultor, na Intranet, servindo como referência abrangente e abordando desde os procedimentos de armazenagem, processamento de pedidos, tratamento de devolução, até a distribuição.', '', 25),
(12607, 'anexo', 306, 12606, 3, '5.1.1', 'Para uma compreensão completa e precisa das práticas e diretrizes, recomenda-se a consulta ao Guia de Execução Operacional como recurso indispensável, pois foi elaborado com vistas a garantir que cada etapa seja executada com excelência, em conformidade com os padrões estabelecidos, assegurando a eficácia e qualidade das operações logísticas.', '', 26),
(12608, 'anexo', 306, NULL, 1, '6', 'PRECIFICAÇÃO', '', 27),
(12609, 'anexo', 306, 12608, 2, '6.1', 'É realizada por um dos dois modelos distintos: modalidade padrão ou modalidade In House.', '', 28),
(12610, 'anexo', 306, 12609, 3, '6.1.1', 'Cada modelo contempla diferentes critérios de precificação, com base nas atividades realizadas no processo logístico.', '', 29),
(12611, 'anexo', 306, 12608, 2, '6.2', 'A modalidade padrão do Correios Log Supri é precificada por execução das seguintes atividades:', '', 30),
(12612, 'anexo', 306, 12611, 4, 'a', 'recebimento (por palete);', '', 31),
(12613, 'anexo', 306, 12611, 4, 'b', 'armazenagem (por palete);', '', 32),
(12614, 'anexo', 306, 12611, 4, 'c', 'conferência exaustiva (por item);', '', 33),
(12615, 'anexo', 306, 12611, 4, 'd', 'separação (nº. de SKU por pedido);', '', 34),
(12616, 'anexo', 306, 12611, 4, 'e', 'agrupamento de itens (por kit);', '', 35),
(12617, 'anexo', 306, 12611, 4, 'f', 'expedição (por objeto).', '', 36),
(12618, 'anexo', 306, 12608, 2, '6.3', 'Na Modalidade In House a precificação do Correios Log Supri é customizada de acordo com o pacote operacional escolhido pelo cliente. Cada pacote operacional possui um preço fixo mensal e leva em consideração a alocação de recursos de acordo com a demanda.', '', 37),
(12619, 'anexo', 306, 12618, 3, '6.3.1', 'Os pacotes operacionais incluem uma combinação das atividades mencionadas acima, e o cliente deve informar os parâmetros relevantes, como: quantidade diária de paletes, itens para conferência, SKU por pedido, dentre outros.', '', 38),
(12620, 'anexo', 306, 12618, 3, '6.3.2', 'É importante observar que, na Modalidade In House, a infraestrutura de segurança, certificações, alvarás e demais requisitos legais são de responsabilidade do cliente. Além disto, não estão inclusos nos pacotes operacionais os profissionais específicos e outros custos adicionais, que devem ser acordados separadamente.', '', 39),
(12621, 'anexo', 306, 12608, 2, '6.4', 'Para detalhes adicionais sobre a estrutura de precificação, deve-se consultar o Guia de Execução Operacional, onde estão dispostas as modalidades de precificação, bem como os critérios específicos que regem cada atividade, garantindo uma compreensão completa e precisa dos custos envolvidos no serviço.', '* * * * *', 40),
(12622, 'anexo', 308, NULL, 1, '1', 'Anexar junto a solicitação:', '', 0),
(12623, 'anexo', 308, 12622, 4, 'a', 'cópia da cédula de identidade e do CPF dos profissionais;', '', 1),
(12624, 'anexo', 308, 12622, 4, 'b', 'cópia da Carteira de Trabalho e Previdência Social - CTPS, das folhas de identificação e do registro funcional da permissionária ou do Contrato de Prestação de Serviço;', '', 2),
(12625, 'anexo', 308, 12622, 4, 'c', 'cópia dos certificados emitidos pelos Correios, quando o profissional tiver experiência profissional em serviço postal nos últimos dois anos;', '', 3),
(12626, 'anexo', 308, 12622, 4, 'd', 'comprovante do pagamento de hora/aula, quando definido pelos Correios.', '* * * * *', 4),
(12627, 'anexo', 309, NULL, 1, '1', 'POSIÇÃO DE TRABALHO CONFIGURAÇÕES', '', 0),
(12628, 'anexo', 309, 12627, 2, '1.1', 'Preencha na coluna “Atendido” com o termo “sim” ou “não” conforme a análise da vistoria de adequação aos requisitos mínimos.', '', 1),
(12629, 'anexo', 309, NULL, 1, '1', 'ESTAÇÃO DE ATENDIMENTO CONFIGURAÇÃO MÍNIMA	Qtd.	Atendido', '1.1	 PLACA PRINCIPAL\n1.1.1	Com arquitetura micro ATX, pico BTX, micro BTX, BTX, pico ITX, mini ITX ou ITX.	 	 \n1.1.2	Depois de configurado, o equipamento deve disponibilizar pelo menos 1 (um) slot livre no padrão PCI 2.3 ou PCI Express 2.0 ou superior.	 	 \n1.2	BIOS\n1.2.1	Tipo flash memory, utilizando memória não volátil e reprogramável.	 	 \n1.2.2	Compatível com o padrão “Plug and Play”.	 	 \n1.2.3	Suporte à data superior ao ano 2000 e com data de revisão ou atualização a partir de 2015.	 	 \n1.2.4	Com suporte ao padrão ACPI (Advanced Configuration and Power Interface) 2.0 ou superior.	 	 \n1.2.5	Com suporte habilitado às tecnologias S.M.A.R.T. (Self-Monitoring, Analysis and Reporting Technology) e AHCI (Advanced Host Controller Interface).	 	 \n1.3	 PROCESSADOR\n1.3.1	Com pelo menos 2 (dois) núcleos (cores) reais de processamento e 04 threads ou com 4 (quatro) núcleos (cores) reais de processamento.	 	 \n1.3.2	Com clock básico mínimo de 2,5 GHz sem nenhum tipo de modificação (overclock).	 	 \n1.3.3	Compatível com a memória RAM solicitada.	 	 \n1.3.4	Com suporte à Arquitetura de 64 bits, ao conjunto de instruções AES (Advanced Encryption Standard), instruções do padrão SSE4 ou superior ou padrão AVX e Extensões de Virtualização.	 	 \n1.3.5	Com controle automático do nível de desempenho, ajustando dinamicamente a frequência e a voltagem, de acordo com o processamento realizado no momento.	 	 \n1.4	MEMÓRIA\n1.4.1	Possuir no mínimo, 8 GB de memória RAM padrão DDR-3 SDRAM 1.866MHz ou superior.	 	 \n1.4.2	Não será aceito nenhum tipo de modificação (overclok) para o funcionamento da memória.	 	 \n1.5	UNIDADE DE ARMAZENAMENTO\n1.5.1	Pelo menos 1 (uma) unidade de disco rígido interna com capacidade mínima de 500 GB, com interface tipo Serial ATA – 300 MB/s ou superior.	 	 \n1.5.2	Velocidade de rotação de, no mínimo, 7.200 RPMs.	 	 \n1.5.3	Memória cache buffer de, no mínimo, 16 MB.	 	 \n1.5.4	Com suporte às tecnologias de pré-falha S.M.A.R.T (Self-Monitoring, Analysis and Reporting Technology) e NCQ (Native Command Queuing).	 	 ', 2);
INSERT INTO `itens` (`id`, `doc_tipo`, `doc_id`, `pai_id`, `nivel`, `numero`, `titulo`, `conteudo`, `ordem`) VALUES
(12630, 'anexo', 309, NULL, 1, '2', 'CONECTIVIDADE E INTERFACES', '2.1	Uma interface Serial ATA de 300 MB/s ou superior que permita gerenciar a(s) unidade(s) de disco rígido especificada(s).	 	 \n2.2	Uma interface controladora de vídeo compatível com o monitor de vídeo.	 	 \n2.3	Uma interface de rede compatível, no mínimo, com os padrões Ethernet e Fast-Ethernet, autosense, full-duplex e plug-and-play, configurável totalmente por software.	 	 \n2.4	Mínimo de 6 (seis) interfaces USB 2.0 ou superior, integradas à placa principal, não sendo aceito nenhum tipo de adaptação.	 	 \n2.5	Possuir 1 (uma) interface exclusiva para Mouse e 1 (uma) interface exclusiva para teclado com conector do tipo PS/2 na parte traseira do equipamento ou USB, ambas integradas à placa principal.	 	 ', 3),
(12631, 'anexo', 309, NULL, 1, '3', 'ACESSÓRIOS, CABOS E PERIFÉRICOS', '3.1	TECLADO\n3.1.1	Padrão AT do tipo estendido de 104 teclas, com todos os caracteres da língua portuguesa.	 	 \n3.1.2	Deve atender ao padrão ABNT-2.	 	 \n3.1.3	Com ajuste de inclinação.	 	 \n3.2	MOUSE\n3.2.1	Mouse óptico, com três botões (incluindo tecla de rolagem), com formato ergonômico e conformação ambidestra.	 	 \n3.2.2	Resolução mínima de 1000 dpi.	 	 \n3.3	CABOS E DEMAIS ACESSÓRIOS\n3.3.1	Deverão ser fornecidos todos os cabos e acessórios necessários ao uso e funcionamento do equipamento completo, inclusive para os periféricos que o acompanham.	 	 \n3.3.1.1	Acessórios e periféricos do tipo wireless devem ser acompanhados de seus respectivos adaptadores, conectores e drivers quando necessários ao seu funcionamento.	 	 ', 4),
(12632, 'anexo', 309, NULL, 1, '4', 'DISPLAY E RESOLUÇÃO', '4.1	Monitor de tela 100% plana de LCD ou LED de no mínimo 18.5” widescreen.	 	 \n4.2	Com conectores de entrada compatíveis com o cabo e a interface controladora de vídeo.	 	 \n4.3	Com suporte a, no mínimo, uma ou mais resoluções do padrão “WXGA”.	 	 \n4.4	Deve possuir taxa de atualização de 60 Hz ou superior.	 	 \n4.5	Deve aceitar tensões de 100/240 VAc ±10% de forma automática.	 	 ', 5),
(12633, 'anexo', 309, NULL, 1, '5', 'ENERGIA', '5.1	A fonte de alimentação de energia elétrica do equipamento principal ofertado deverá suportar todos os dispositivos internos na configuração máxima admitida pelos componentes do equipamento, bem como a utilização de todas as interfaces USB presentes no equipamento montado, inclusive simultaneamente.	 	 \n5.2	O equipamento ofertado deve possuir fonte de alimentação de energia elétrica bi-volt (110VAc, 220VAc) ou full-range, com tensão de entrada de 100/240 VAc ±10%.	 	 ', 6),
(12634, 'anexo', 309, NULL, 1, '6', 'CARACTERÍSTICAS, DESEMPENHO E FUNCIONALIDADES', '6.1	 Deve possuir tecnologia de controle automático de temperatura para evitar aquecimento excessivo de componentes, incluindo controle da temperatura através de cooler apropriado ao processador ou tecnologia de ajuste dinâmico do consumo de energia que dispense o uso de cooler.	 	 ', 7),
(12635, 'anexo', 309, NULL, 1, '7', 'COMPATIBILIDADE E CONFORMIDADE', '7.1	O equipamento ofertado, bem como todos os dispositivos de hardware, além de seus drivers e outros softwares fornecidos com o equipamento devem ser compatíveis com os seguintes sistemas operacionais: Microsoft Windows 7 Pro, Microsoft Windows 10 Pro.	 	 \n7.2	Incluir licenças para o sistema operacional Microsoft Windows 7 Pro ou Microsoft Windows 10 Pro, em Português do Brasil, para cada equipamento, de forma a garantir o acesso às atualizações disponibilizadas pelo fabricante do sistema operacional especificado.	 	 ', 8),
(12636, 'anexo', 309, NULL, 1, '8', 'IMPRESSORA TÉRMICA', '8.1	MARCA/MODELO	Fabricante	Qtd.	Atendido\n8.1.1	4051	PERTO	 	 \n8.1.2	F94JX001 (compatível com NFC-e) 	PERTO	 	 \n8.1.3	F94P2002 (compatível com NFC-e)	PERTO	 	 \n8.1.4	TM-20	EPSON	 	 ', 9),
(12637, 'anexo', 309, NULL, 1, '9', 'BALANÇA	Qtd.	Atendido', '9.1	Capacidade máxima real de pesagem de 30 kg;	 	 \n9.2	Precisão mínima de leitura: 2 gramas com peso até 6 kg;	 	 \n9.3	Display digital, com iluminação interna, para exibição do peso aferido;	 	 \n9.4	Capacidade de alternância automática entre as faixas de precisão do peso, de acordo com o objeto pesado;	 	 \n9.5	Teclado de fácil digitação, com material isolante, minimizando efeitos eletrostáticos;	 	 \n9.6	Interface USB ou sem fio, para envio de dados de pesagem para a Solução de Atendimento dos Correios. Em caso de utilização de interface sem fio, a impressora deve vir com todos os componentes físicos e de software necessários para sua correta utilização;	 	 \n9.7	Gabinete em ABS ou material semelhante, resistente a impactos;	 	 \n9.8	Alimentação: bi-volt;	 	 \n9.9	Certificada pelo INMETRO, conforme Portaria nº 236 de 22 de dezembro de 1994 e suas atualizações;	 	 \n9.10	Driver compatível com o sistema operacional selecionado para a Estação de Trabalho PDV, conforme descrito na Tabela 1.	 	 ', 10),
(12638, 'anexo', 309, NULL, 1, '10', 'LEITOR ÓTICO', '10.1	 INTERFACES\n10.2	USB compatível com a versão 2.0+ ou superior, com alimentação elétrica pelo mesmo cabo.	 	 \n10.3	FUNCIONALIDADES: LEITURA DE CÓDIGO DE BARRAS\n10.4	Em múltiplas densidades e cores.	 	 \n10.5	A uma luminosidade ambiente igual ou superior a 350 lux	 	 \n10.6	Em condições de contraste e reflexão mínimos de 35%	 	 \n10.7	Com baixa qualidade e através de visor plástico.	 	 \n10.8	Formatos de códigos de barras: UPC/EAN e EAN com suplementos, EAN 128, código 39, código 39 ASCII completo, código 93, intercalado 2 de 5, Code 128 A/B/C, PDF417 e Datamatrix ECC 200.	 	 \n10.9	Programação para leitura do código intercalado 2 de 5 (ITF) com tamanho de 46 posições ou maior, em conformidade com o padrão utilizado pela rede bancária/comercial (FEBRABAN).	 	 \n10.10	Leitura dos códigos de barras tipo 1D:	 	 \n10.11	Com densidade entre 6 mils e 30 mils;	 	 \n10.12	Com larguras entre 2,0 e 25 cm (inclusive). 1.2.4.3. a uma distância de 0,7 cm até 26 cm (inclusive)	 	 \n10.13	Leitura dos códigos de barras tipo Datamatrix:	 	 \n10.14	Padrão ECC 200;	 	 \n10.15	Com densidade mínima de impressão de 200 dpi, com dimensão do módulo X maior ou igual a 0,35 mm, com zona de silêncio em torno do código de, no mínimo, 3 mm e qualidade de Impressão mínima de classificação 2 (ISO/IEC 15415).	 	 \n10.16	Com densidade mínima de impressão de 240 dpi, com dimensão do módulo X maior ou igual a 0,25 mm, com zona de silêncio em torno do código de, no mínimo, 3 mm e qualidade de Impressão mínima de classificação 2 (ISO/IEC 15415);	 	 \n10.17	Instalação sem necessidade de qualquer tipo de software (aplicativo, driver, etc.) para o seu funcionamento.	 	 \n10.18	Configuração de inserção do caractere “ENTER” após a leitura.	 	 \n10.19	Deve possuir indicação luminosa e sonora de funcionamento ou erros ocorridos nas leituras.	 	 \n10.20	Carcaça em material rígido, resistente a quedas de até 1,2m sem comprometer o funcionamento do equipamento.	 	 ', 11),
(12639, 'anexo', 309, NULL, 1, '11', 'COMPATIBILIDADE', '11.1	O equipamento deverá ser compatível com o sistema operacional definido para a Estação de Trabalho PDV prevista.	 	 ', 12),
(12640, 'anexo', 309, NULL, 1, '2', 'COMUNICAÇÃO VISUAL', '', 13),
(12641, 'anexo', 309, 12640, 2, '2.1', 'Preencha na coluna “Atendido” com o termo “sim” ou “não” conforme a análise da vistoria de adequação aos requisitos mínimos.', '12.	COMUNICAÇÃO VISUAL	Qtd.	Atendido\n12.1	 IINTERNA\n12.1.1	Acessibilidade\n12.1.2	Cartaz menu serviços\n12.1.3	Display de piso menu serviços e/ou\n12.1.4	Placa pendural menu serviços e/ou\n12.2	EXTERNA\n12.2.1	Totem	 	 \n12.2.2	Bandeira	 	 ', 14),
(12642, 'anexo', 309, NULL, 1, '3', 'INSTALAÇÕES INTERNAS', '', 15),
(12643, 'anexo', 309, 12642, 2, '3.1', 'Preencha na coluna “Atendido” com o termo “sim” ou “não” conforme a análise da vistoria de adequação aos requisitos mínimos.', '15.	MEDIDAS	Atendido\n15.1	MÓDULO DE ATENDIMENTO\n15.1.1	O módulo de atendimento está instalado.\n15.1.2	Distância mínima de 70cm entre a parte de trás do módulo de atendimento (simples/complementar) e a parede/armário ou qualquer elemento detrás do móvel.\n15.1.3	Área à frente do módulo de atendimento dispõe de espaço de no mínimo 1,20m (um metro e vinte centímetros) sem obstáculo.\n15.1.4	Área paralela à frente do módulo de atendimento dispõe de espaço que permite o deslocamento do cliente de no mínimo 1,50m (um metro e cinquenta centímetros)\n15.2	ÁREA DE APOIO\n15.2.1	Metragem mínima para área de apoio (5m²) módulo simples\n15.2.2	Área de apoio em local apartado da área de atendimento\n15.2.3	Área de apoio é parte integrante do estabelecimento comercial, está em local coberto e protegido de eventos da natureza.\n15.3	ACESSO DOS CLIENTES\n15.3.1	O imóvel permite o acesso irrestrito de pessoas em qualquer época do ando, sem exigências de cadastramento prévio, crachás ou outro procedimento ou sistema de controle de acesso', 16),
(12644, 'anexo', 309, NULL, 1, '4', 'CRITÉRIOS ESTABELECIDAS NO PROCESSO DE SELEÇÃO DO CMD', '', 17),
(12645, 'anexo', 309, 12644, 2, '4.1', 'Preencha na coluna “Critério Atendido” com um “X” conforme verificação dos critérios de habilitação na vistoria de conformidade.', '', 18),
(12646, 'anexo', 309, 12644, 2, '4.2', 'A coluna “Critério Pontuado” deverá ser preenchida antes da realização da visita técnica.', 'CRITÉRIO 01 – MAIOR VISIBILIDADE E POSICIONAMENTO PARA ATENDIMENTO AO PÚBLICO\nDESCRIÇÃO DOS ITEMS PONTUADOS	CRITERIO\nPONTUADO 	CRITÉRIO\nATENDIDO\nLocalizado em esquina de via de grande circulação (arterial* ou coletora**) ou, no caso de estabelecimento em shopping center/galeria comercial, com distância máxima de até 30 metros da entrada principal do shopping center/galeria comercial\nLocalizado em via de grande circulação (arterial* ou coletora**) ou em esquina de via local***. No caso de shopping center/galeria comercial, se estiver localizado fora do subsolo ou de corredor isolado ou área sem saída.\nFora de via de grande circulação (arterial* ou coletora**) ou de esquina de via local***. No caso de shopping center/galeria comercial, se estiver localizado em subsolo ou corredor isolado ou área sem saída.\nCRITÉRIO 02 – MAIOR DISPONIBILIZAÇÃO DE EQUIPAMENTOS DE SEGURANÇA\nDESCRIÇÃO DOS ITEMS PONTUADOS	CRITERIO\nPONTUADO 	CRITÉRIO\nATENDIDO\nSistema de alarme, circuito fechado de televisão (CFTV) e serviço de vigilância durante o horário de atendimento.\nDois dos itens de segurança dentre os descritos acima.\nUm item de segurança dentre os descritos acima.\nCRITÉRIO 03 – DISPONIBILIDADE E MENOR DISTÂNCIA DO ESTABELECIMENTO EM RELAÇÃO À ÁREA DE CARGA E DESCARGA DE VEÍCULO\nDESCRIÇÃO DOS ITEMS PONTUADOS	CRITERIO\nPONTUADO 	CRITÉRIO\nATENDIDO\nPossui área para carga e descarga em distância de até 10m (dez metros) da entrada principal do estabelecimento.\nPossui área para carga e descarga em distância entre 11m (onze metros) e 25m (vinte e cinco metros) da entrada principal do estabelecimento.\nPossui área para carga e descarga em distância superior a 25m (vinte e cinco metros) da entrada principal do estabelecimento.\nCRITÉRIO 04 – DISPONIBILIDADE DE ESTACIONAMENTO E MENOR DISTÂNCIA DO ESTABELECIMENTO\nDESCRIÇÃO DOS ITEMS PONTUADOS	CRITERIO\nPONTUADO 	CRITÉRIO\nATENDIDO\nPossui estacionamento próprio adjacente ao estabelecimento.\nPossui estacionamento não adjacente ao estabelecimento, mas\nem uma distância de até 45m do estabelecimento.\nPossui estacionamento não adjacente ao estabelecimento a uma distância superior a 45m do estabelecimento.\nCRITÉRIO 05 – HORÁRIO E FREQUÊNCIA DE FUNCIONAMENTO DO COMÉRCIO\nDESCRIÇÃO DOS ITEMS PONTUADOS	CRITERIO\nPONTUADO 	CRITÉRIO\nATENDIDO\nAcima de 64 horas por semana, distribuídas no mínimo, por cinco dias por semana.\nEntre 45 e 64 horas por semana, distribuídas no mínimo, por cinco dias por semana.\nEntre 40 e 44 horas por semana, distribuídas no mínimo, por cinco dias por semana.\nCRITÉRIO 06 – CLIMATIZAÇÃO E ISOLAMENTO TÉRMICO\nDESCRIÇÃO DOS ITEMS PONTUADOS	CRITERIO\nPONTUADO 	CRITÉRIO\nATENDIDO\nEstabelecimento comercial com climatização através de ar condicionado ou aquecedor ou similar.\nClimatização através de ar condicionado ou aquecedor ou similar restrita à área de atendimento do CMD\nEstabelecimento com climatização através de ventilador ou similar.\nCRITÉRIO 07 – USO DE MECANISMOS DE SUSTENTABILIDADE\nDESCRIÇÃO DOS ITEMS PONTUADOS	CRITERIO\nPONTUADO 	CRITÉRIO\nATENDIDO\nPossui estrutura de coleta seletiva, reuso de água e utilização de energia solar.\nDois dos itens de sustentabilidade dentre os descritos acima.\nUm item de sustentabilidade dentre os descritos acima.', 19),
(12647, 'anexo', 309, NULL, 1, '5', 'RESULTADO DA VISTORIA DE ADEQUAÇÃO AOS REQUISITOS MÍNIMOS E DE COMPROVAÇÃO DOS CRITÉRIOS DE HABILITAÇÃO DO CMD.', '', 20),
(12648, 'anexo', 309, 12647, 2, '5.1', 'Conforme verificado, nesta data, e consoante as informações registradas neste documento o CMD_____________ (colocar o nome da Unidade) foi ____________ (aprovado/reprovado) na Vistoria de Adequação aos Requisitos Mínimos.', 'ITEM OU\nCRITÉRIO 	DESCRIÇÃO DO MOTIVO DA REPROVAÇÃO\n 	 \n 	 \n 	 \n 	 \n 	 \n 	 \n 	 \n 	 \n*Preencher apenas se houver inconsistência em algum item ou critério, não havendo passar um risco.\nCidade - UF ......./........... de 20......\nRepresentantes dos Correios\n_______________________________\nNome Completo\nMatrícula:\n_______________________________\nNome Completo\nMatrícula:\nRepresentante(s) Legal(is) da Permissionária\n_______________________________\nNome Completo\nCPF:\n_______________________________\nNome Completo\nCPF:', 21),
(12649, 'anexo', 309, NULL, 1, '6', 'ORIENTAÇÕES GERAIS:', '', 22),
(12650, 'anexo', 309, 12649, 2, '6.1', 'Recomenda-se que o(a) permissionário(a) realize uma auto avaliação, antes de solicitar a visita técnica dos Correios, mitigando a possibilidade de reprovação, e consequentemente, cobrança da taxa prevista no Anexo 2 do Contrato de Permissão para essa finalidade.', '', 23),
(12651, 'anexo', 309, 12649, 2, '6.2', 'É fator condicionante para a realização da vistoria a presença de no mínimo um representante legal da permissionária durante todo o processo de verificação dos itens que compõe esse documento.', '', 24),
(12652, 'anexo', 309, 12649, 2, '6.3', 'As páginas desse documento deverão ser rubricadas pelos representantes dos Correios e da permissionária.', '* * * * *', 25);
