INSERT INTO `regras` (`id`, `item_id`, `doc_tipo`, `doc_id`, `servico`, `tipo`, `descricao`, `valor_numerico`, `unidade`, `contexto`, `fonte`, `criado_em`) VALUES
(1, 3750, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...convenientemente dobrada, adquire a forma de um envelope. É destinado a outros países, podendo ser aceito no regime interno, se for...', NULL, NULL, 'Aerograma internacional: documento prioritário pré-selado, apresenta-se em forma de uma folha de papel que, convenientemente dobrada, adquire a forma de um envelope. É destinado a outros países, podendo ser aceito no regime interno, se for do interesse do remetente.', 'Módulo 1 › Cap. 1 › 2.5', '2026-06-22 19:42:50'),
(2, 3756, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...a de Correios Comunitária - AGC: é a unidade de atendimento destinada a viabilizar, no mínimo, a prestação de serviços postais bási...', NULL, NULL, 'Agência de Correios Comunitária - AGC: é a unidade de atendimento destinada a viabilizar, no mínimo, a prestação de serviços postais básicos, em pequenas localidades com população superior a quinhentos habitantes, bem como em áreas urbanas onde predomine o interesse social e a exploração econômica de serviços postais não se mostre viável.', 'Módulo 1 › Cap. 1 › 2.11', '2026-06-22 19:42:50'),
(3, 3773, 'capitulo', 1, NULL, 'volume', 'Volume mínimo: 20 un — Amostra FAC: objeto extraído de forma aleatória, de diversas partes da carga, considerando a quantidade informada pelo S', 20.0000, 'un', 'Amostra FAC: objeto extraído de forma aleatória, de diversas partes da carga, considerando a quantidade informada pelo Sistema CIFWEB, correspondente a 2% do total de objetos postados, limitando-se o mínimo de 20 (vinte) objetos e ao máximo de 200 (duzentos), para conferência com as informações individuais constantes do Relatório de Postagem Eletrônico.', 'Módulo 1 › Cap. 1 › 2.28', '2026-06-22 19:42:50'),
(4, 3801, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...to, onde é informado ao cliente que a encomenda se encontra disponível para retirada interna. ...', NULL, NULL, 'Aviso de chegada: é o aviso emitido por uma unidade dos Correios e encaminhado ao destinatário de um objeto, onde é informado ao cliente que a encomenda se encontra disponível para retirada interna.', 'Módulo 1 › Cap. 1 › 2.56', '2026-06-22 19:42:50'),
(5, 3826, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...e coleta: é o receptáculo instalado em logradouros públicos destinados ao atendimento do usuário por meio de depósito de correspondê...', NULL, NULL, 'Caixa de coleta: é o receptáculo instalado em logradouros públicos destinados ao atendimento do usuário por meio de depósito de correspondência previamente franqueada.', 'Módulo 1 › Cap. 1 › 2.77', '2026-06-22 19:42:50'),
(6, 3833, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ... material resistente, com formato adequado ao empilhamento, destinado ao acondicionamento de objetos simples ou registrados, de for...', NULL, NULL, 'Caixeta: unitizador de material resistente, com formato adequado ao empilhamento, destinado ao acondicionamento de objetos simples ou registrados, de formato normal ou semi-embaraçoso.', 'Módulo 1 › Cap. 1 › 2.84', '2026-06-22 19:42:50'),
(7, 3839, 'capitulo', 1, 'PAC', 'prazo', 'Prazo formal: 8 horas — Capacidade Produtiva de um Empregado - CPE: é o tempo real de efetiva ocupação do empregado com seu trabalho, sendo cons', 8.0000, 'horas', 'Capacidade Produtiva de um Empregado - CPE: é o tempo real de efetiva ocupação do empregado com seu trabalho, sendo considerada em condições normais uma ocupação real de 90% da jornada diária de 8 (oito) horas, o que equivale a 432 (quatrocentos e trinta e dois) minutos.', 'Módulo 1 › Cap. 1 › 2.90', '2026-06-22 19:42:50'),
(8, 3883, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...se também cecograma o material impresso para uso dos cegos. Disponível para envio nacional e internacional ...', NULL, NULL, 'Cecograma: objeto de correspondência impresso em relevo, para uso dos cegos. Considera-se também cecograma o material impresso para uso dos cegos. Disponível para envio nacional e internacional', 'Módulo 1 › Cap. 1 › 2.122', '2026-06-22 19:42:50'),
(9, 3884, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ... é o espaço físico capaz de comportar móveis e equipamentos destinados ao suporte das atividades desenvolvidas no guichê de retaguar...', NULL, NULL, 'Célula de mobiliários e equipamentos a compartilhar: é o espaço físico capaz de comportar móveis e equipamentos destinados ao suporte das atividades desenvolvidas no guichê de retaguarda, cuja utilização é opcional e pode ser partilhada com outros guichês de retaguarda e/ou para apoiar as atividades dos guichês de atendimento.', 'Módulo 1 › Cap. 1 › 2.123', '2026-06-22 19:42:50'),
(10, 3886, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...DD;\nb) 0800-725-7282: demais localidades;\nc) 0800-725-0100: exclusivo para o registro de reclamações, elogios e sugestões....', NULL, NULL, 'Central de Atendimento dos Correios - CAC: canal de atendimento responsável pela captação de manifestações dos clientes dos Correios por telefone, que atende por intermédio dos seguintes números: a) 3003-0100: capitais, regiões metropolitanas e cidades-sedes de DDD;\nb) 0800-725-7282: demais localidades;\nc) 0800-725-0100: exclusivo para o registro de reclamações, elogios e sugestões.', 'Módulo 1 › Cap. 1 › 2.125', '2026-06-22 19:42:50'),
(11, 3934, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...: é toda mensagem escrita, na forma impressa ou eletrônica, destinada a uma pessoa ou grupo de pessoas. ...', NULL, NULL, 'Comunicação dirigida: é toda mensagem escrita, na forma impressa ou eletrônica, destinada a uma pessoa ou grupo de pessoas.', 'Módulo 1 › Cap. 1 › 2.172', '2026-06-22 19:42:50'),
(12, 3947, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...Contas em condições especiais: são contas prioritariamente destinadas a menores, proponentes incapazes, não alfabetizados, contas a...', NULL, NULL, 'Contas em condições especiais: são contas prioritariamente destinadas a menores, proponentes incapazes, não alfabetizados, contas abertas com procuração, deficientes visuais/auditivos e tituladas por falecidos (espólio).', 'Módulo 1 › Cap. 1 › 2.185', '2026-06-22 19:42:50'),
(13, 3961, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...Correios Entrega Direta - CED: serviço exclusivo para entrega, em âmbito nacional, de publicações periódicas, em ...', NULL, NULL, 'Correios Entrega Direta - CED: serviço exclusivo para entrega, em âmbito nacional, de publicações periódicas, em domicílio. Destina-se ao cliente que precisa distribuir e gerenciar a entrega de suas publicações, da postagem à entrega. Por meio da web, são disponibilizadas informações da performance da entrega, motivos de não entrega e possibilidades de reenvio, de modo a que o cliente tenha respostas rápidas e confiáveis para os recebedores de suas publicações.', 'Módulo 1 › Cap. 1 › 2.197', '2026-06-22 19:42:50'),
(14, 3979, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...espersonalização: é o ato de separar o Selo-Base da vinheta destinada ao cliente, por meio de corte manual nos picotes que unem as ...', NULL, NULL, 'Despersonalização: é o ato de separar o Selo-Base da vinheta destinada ao cliente, por meio de corte manual nos picotes que unem as peças.', 'Módulo 1 › Cap. 1 › 2.215', '2026-06-22 19:42:50'),
(15, 3986, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...nal de Endereços - Básico - e-DNE Básico: Modalidade do DNE destinada a qualquer pessoa física ou jurídica que na condição de usuár...', NULL, NULL, 'Diretório Nacional de Endereços - Básico - e-DNE Básico: Modalidade do DNE destinada a qualquer pessoa física ou jurídica que na condição de usuária final trabalhe com as seguintes aplicações:', 'Módulo 1 › Cap. 1 › 2.222', '2026-06-22 19:42:50'),
(16, 3997, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...nal de Endereços - Master - e-DNE Master: modalidade do DNE destinada a qualquer pessoa física ou jurídica que trabalhe com as segu...', NULL, NULL, 'Diretório Nacional de Endereços - Master - e-DNE Master: modalidade do DNE destinada a qualquer pessoa física ou jurídica que trabalhe com as seguintes aplicações:', 'Módulo 1 › Cap. 1 › 2.223', '2026-06-22 19:42:50'),
(17, 4048, 'capitulo', 1, 'SEDEX', 'elegibilidade', 'Elegibilidade: ...o saco, com ilustrações alusivas aos serviços dos Correios, destinado ao acondicionamento de objetos a serem postados na modalidade...', NULL, NULL, 'Envelope SEDEX estadual pré-franqueado: envelope específico pré-franqueado, tipo saco, com ilustrações alusivas aos serviços dos Correios, destinado ao acondicionamento de objetos a serem postados na modalidade SEDEX Estadual Pré-Franqueado do Serviço de Encomenda Expressa.', 'Módulo 1 › Cap. 1 › 2.257', '2026-06-22 19:42:50'),
(18, 4055, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...Espaço Qualidade de Vida - EQV: É o local destinado a lazer, descanso, leitura e estudo dos empregados lotados na...', NULL, NULL, 'Espaço Qualidade de Vida - EQV: É o local destinado a lazer, descanso, leitura e estudo dos empregados lotados nas agências.', 'Módulo 1 › Cap. 1 › 2.264', '2026-06-22 19:42:50'),
(19, 4064, 'capitulo', 1, 'REMESSA', 'peso', 'Limite de peso: 30 kg — Exporta Fácil +: Solução de logística de exportação para o envio de remessas de grandes volumes, com peso a partir de 30', 30.0000, 'kg', 'Exporta Fácil +: Solução de logística de exportação para o envio de remessas de grandes volumes, com peso a partir de 30 kg ou com dimensões que extrapolem as dimensões aceitas pelo meio postal, para o exterior.', 'Módulo 1 › Cap. 1 › 2.273', '2026-06-22 19:42:50'),
(20, 4125, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...o anúncios, matérias pagas, matérias especiais e similares, destinado a promover a divulgação e o desenvolvimento das vendas de um ...', NULL, NULL, 'Impresso Especial - IE: objeto obtido por meio de impressão gráfica, em vários exemplares idênticos, constituído de uma ou mais folhas, contendo anúncios, matérias pagas, matérias especiais e similares, destinado a promover a divulgação e o desenvolvimento das vendas de um determinado produto ou serviço, a prestar informações, a divulgar eventos culturais, políticos, religiosos, esportivos e assemelhados.', 'Módulo 1 › Cap. 1 › 2.330', '2026-06-22 19:42:50'),
(21, 4173, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ..., anúncios e outro tipo de informação de interesse público, destinado a um grupo de pessoas. ...', NULL, NULL, 'Jornais segmentados: publicação periódica constituída por uma série de folhas grandes de papel, dobradas em caderno, onde foram impressas notícias, reportagens, crônicas, entrevistas, anúncios e outro tipo de informação de interesse público, destinado a um grupo de pessoas.', 'Módulo 1 › Cap. 1 › 2.349', '2026-06-22 19:42:50'),
(22, 4194, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...spedada: serviço de hospedagem de loja virtual dos Correios destinado a varejistas que desejam iniciar sua operação na internet. Ut...', NULL, NULL, 'Loja hospedada: serviço de hospedagem de loja virtual dos Correios destinado a varejistas que desejam iniciar sua operação na internet. Utilizando a estrutura tecnológica fornecida pelo CorreiosNet Shopping para montagem e operacionalização de loja virtual. Disponibilizando diversas formas de pagamento, carrinho de compras e quantidade ilimitada de produtos cadastrados.', 'Módulo 1 › Cap. 1 › 2.370', '2026-06-22 19:42:50'),
(23, 4197, 'capitulo', 1, 'SEDEX', 'elegibilidade', 'Elegibilidade: ...ulada Âncora: é o mesmo serviço de vínculo de loja virtual, destinado aos clientes corporativos do serviço e-SEDEX de renome nacion...', NULL, NULL, 'Loja vinculada Âncora: é o mesmo serviço de vínculo de loja virtual, destinado aos clientes corporativos do serviço e-SEDEX de renome nacional no comércio eletrônico.', 'Módulo 1 › Cap. 1 › 2.373', '2026-06-22 19:42:50'),
(24, 4209, 'capitulo', 1, NULL, 'valor', 'Valor (R$): 3.50 r$ — Mala Direta Postal - MDP: é o serviço de envio e distribuição em grande quantidade de peças exclusivamente promocionais,', 3.5000, 'r$', 'Mala Direta Postal - MDP: é o serviço de envio e distribuição em grande quantidade de peças exclusivamente promocionais, endereçadas, personalizadas ou não, que requer investimento mensal de valor fixo, atualmente em R$ 3.500,00/mês, segundo a tarifa comercial dos Correios, contempla o pagamento a faturar, por meio de contrato.', 'Módulo 1 › Cap. 1 › 2.378', '2026-06-22 19:42:50'),
(25, 4210, 'capitulo', 1, NULL, 'peso', 'Limite de peso: 300 g — Mala Direta Postal Domiciliária - MDPD: é o serviço de envio e distribuição de peças exclusivamente promocionais, não en', 300.0000, 'g', 'Mala Direta Postal Domiciliária - MDPD: é o serviço de envio e distribuição de peças exclusivamente promocionais, não endereçadas, de até 300g, com pagamento a faturar ou à vista, por meio de contrato.', 'Módulo 1 › Cap. 1 › 2.379', '2026-06-22 19:42:50'),
(26, 4212, 'capitulo', 1, 'REMESSA', 'elegibilidade', 'Elegibilidade: ...Mala M: remessa internacional destinada ao envio de impressos de um único remetente, endereçados a um...', NULL, NULL, 'Mala M: remessa internacional destinada ao envio de impressos de um único remetente, endereçados a um só destinatário.', 'Módulo 1 › Cap. 1 › 2.381', '2026-06-22 19:42:50'),
(27, 4229, 'capitulo', 1, NULL, 'elegibilidade', 'Elegibilidade: ...é um componente da Máquina de Franquear que permite a carga somente por processo remoto, via modem. Armazena e gerencia créditos, c...', NULL, NULL, 'Medidor da máquina de franquear: é um componente da Máquina de Franquear que permite a carga somente por processo remoto, via modem. Armazena e gerencia créditos, controlando o uso da postagem. É o mecanismo de registro das operações da Máquina de Franquear.', 'Módulo 1 › Cap. 1 › 2.393', '2026-06-22 19:42:50'),
(28, 4291, 'capitulo', 1, NULL, 'prazo', 'Prazo formal: 90 dias — fim: até 90 (noventa) dias da postagem.', 90.0000, 'dias', 'fim: até 90 (noventa) dias da postagem.', 'Módulo 1 › Cap. 1 › b', '2026-06-22 19:42:50'),
