(426, 9055, 'anexo', 178, 'PAC', 'prazo', 'Prazo formal: 7 dias corridos — prazo de 7 (sete) dias corridos: Correios Packet;', 7.0000, 'dias corridos', 'prazo de 7 (sete) dias corridos: Correios Packet;', 'Módulo 11 › Anx. 9 › d', '2026-06-22 19:42:50'),
(427, 9056, 'anexo', 178, 'PAC', 'prazo', 'Prazo formal: 30 dias corridos — prazo de 30 (trinta) dias corridos: objeto endereçado a Caixa Postal.', 30.0000, 'dias corridos', 'prazo de 30 (trinta) dias corridos: objeto endereçado a Caixa Postal. Nota: exceto para encomenda Correios Packet nacionalizada em devolução que não pode ser endereçada para unidade dos Correios.\nExemplo: Caixa Postal ou Posta Restante Pedida.\n* * * * *', 'Módulo 11 › Anx. 9 › e', '2026-06-22 19:42:50'),
(428, 9074, 'anexo', 180, 'PAC', 'peso', 'Limite de peso: 30 kg — LIMITES DE PESO', 30.0000, 'kg', 'LIMITES DE PESO 6.1 Os limites máximos permitidos para o peso físico é de até 30kg para o Correios Packet Express e Standard.', 'Módulo 11 › Anx. 2 › 6', '2026-06-22 19:42:50'),
(429, 9082, 'anexo', 180, NULL, 'dimensao', 'Dimensão: 10 cm — dimensões mínimas (C x D): 10 cm x 5 cm;', 10.0000, 'cm', 'dimensões mínimas (C x D): 10 cm x 5 cm;', 'Módulo 11 › Anx. 2 › a', '2026-06-22 19:42:50'),
(430, 9083, 'anexo', 180, NULL, 'dimensao', 'Dimensão: 90 cm — dimensões máximas (C x D): 90 cm x 30 cm;', 90.0000, 'cm', 'dimensões máximas (C x D): 90 cm x 30 cm;', 'Módulo 11 › Anx. 2 › b', '2026-06-22 19:42:50'),
(431, 9101, 'anexo', 181, 'REMESSA', 'restricao', 'Restrição: ...É vedado à pessoa jurídica, o envio de remessas enquadradas como pre...', NULL, NULL, 'É vedado à pessoa jurídica, o envio de remessas enquadradas como presente, sendo permitido apenas a pessoas físicas. Para tanto, é permitido à pessoa jurídica o envio de brindes ou amostras, os quais devem ser acompanhados por nota fiscal para o devido encaminhamento ao destino.', 'Módulo 12 › Anx. 2 › 2.1.4', '2026-06-22 19:42:50'),
(432, 9148, 'anexo', 181, NULL, 'elegibilidade', 'Elegibilidade: ...forma de garantir a indenização do valor total do bem. Está disponível para os seguintes serviços: ...', NULL, NULL, 'O serviço adicional Valor Declarado - VD pode ser contratado no momento no envio de mercadorias como forma de garantir a indenização do valor total do bem. Está disponível para os seguintes serviços:', 'Módulo 12 › Anx. 2 › 7.3.1', '2026-06-22 19:42:50'),
(433, 9155, 'anexo', 181, NULL, 'peso', 'Limite de peso: 2 kg — O limite máximo de peso físico para o envio de documento, obtido da balança, é 2 kg para Documento Internacional Express', 2.0000, 'kg', 'O limite máximo de peso físico para o envio de documento, obtido da balança, é 2 kg para Documento Internacional Expresso e Standard.', 'Módulo 12 › Anx. 2 › 8.1', '2026-06-22 19:42:50'),
(434, 9157, 'anexo', 181, NULL, 'peso', 'Limite de peso: 30 kg — 30 kg para Exporta Fácil Expresso e Standard;', 30.0000, 'kg', '30 kg para Exporta Fácil Expresso e Standard;', 'Módulo 12 › Anx. 2 › a', '2026-06-22 19:42:50'),
(435, 9158, 'anexo', 181, NULL, 'peso', 'Limite de peso: 2 kg — 2 kg para Exporta Fácil Econômico.', 2.0000, 'kg', '2 kg para Exporta Fácil Econômico.', 'Módulo 12 › Anx. 2 › b', '2026-06-22 19:42:50'),
