(446, 9266, 'anexo', 182, NULL, 'dimensao', 'Dimensão: 9 cm — mínimas: 9 cm × 14 cm ou rolo: comprimento + 2× o diâmetro = 17 cm (maior dimensão não inferior a 10 cm);', 9.0000, 'cm', 'mínimas: 9 cm × 14 cm ou rolo: comprimento + 2× o diâmetro = 17 cm (maior dimensão não inferior a 10 cm);', 'Módulo 12 › Anx. 3 › a', '2026-06-22 19:42:50'),
(447, 9267, 'anexo', 182, NULL, 'peso', 'Limite de peso: 30 kg — máximas: comprimento + largura + espessura = 90 cm (maior dimensão exceder 60 cm) ou rolo: comprimento + 2× o diâmetro =', 30.0000, 'kg', 'máximas: comprimento + largura + espessura = 90 cm (maior dimensão exceder 60 cm) ou rolo: comprimento + 2× o diâmetro = 104 cm (maior dimensão não pode exceder 90 cm). 1.3.2 Peso: até 30 kg.\n1.3.3 Modalidade: econômica.\n1.3.4 Serviços adicionais: não oferece o registro para esse serviço.\n1.3.5 Forma de pagamento: a faturar.\n1.3.6 Outras considerações:', 'Módulo 12 › Anx. 3 › b', '2026-06-22 19:42:50'),
(448, 9269, 'anexo', 182, NULL, 'peso', 'Limite de peso: 30 kg — os objetos serão acondicionados, desde a sua postagem até a sua entrega, em única embalagem postal com peso máximo de 30', 30.0000, 'kg', 'os objetos serão acondicionados, desde a sua postagem até a sua entrega, em única embalagem postal com peso máximo de 30 kg, conforme aceitação do país de destino;', 'Módulo 12 › Anx. 3 › b', '2026-06-22 19:42:50'),
