(488, 9675, 'anexo', 192, NULL, 'elegibilidade', 'Elegibilidade: ...Não é prevista a entrega de aviso de chegada para objetos destinados ao Locker e Clique e Retire ou que estejam mal endereçados. ...', NULL, NULL, 'Não é prevista a entrega de aviso de chegada para objetos destinados ao Locker e Clique e Retire ou que estejam mal endereçados.', 'Módulo 16 › Anx. 2 › 26.2.1', '2026-06-22 19:42:50'),
(489, 9691, 'anexo', 192, NULL, 'prazo', 'Prazo formal: 3 dias corridos — A encomenda encaminhada para entrega em Ponto de Coleta é disponibilizada para retirada durante 3 (três) dias corridos.', 3.0000, 'dias corridos', 'A encomenda encaminhada para entrega em Ponto de Coleta é disponibilizada para retirada durante 3 (três) dias corridos.', 'Módulo 16 › Anx. 2 › 27.5', '2026-06-22 19:42:50'),
(490, 9697, 'anexo', 192, 'LOGÍSTICA REVERSA', 'elegibilidade', 'Elegibilidade: ...ncomenda postada por meio do serviço de Logística Reversa e destinada ao Clique e Retire são aplicadas as regras de cobrança estabe...', NULL, NULL, 'Encomenda postada por meio do serviço de Logística Reversa e destinada ao Clique e Retire são aplicadas as regras de cobrança estabelecidas para a Posta Restante Pedida.', 'Módulo 16 › Anx. 2 › 28.1.2', '2026-06-22 19:42:50'),
(491, 9722, 'anexo', 192, NULL, 'elegibilidade', 'Elegibilidade: ...serviço adicional de Checklist e/ou múltiplos objetos não é elegível para o Locker. ...', NULL, NULL, 'O e-ticket que possuir o serviço adicional de Checklist e/ou múltiplos objetos não é elegível para o Locker.', 'Módulo 16 › Anx. 2 › 31.2.2', '2026-06-22 19:42:50'),
(492, 9733, 'anexo', 192, NULL, 'elegibilidade', 'Elegibilidade: ...r e-mail, SMS e/ou App Correios, quando a encomenda estiver disponível para retirada. ...', NULL, NULL, 'O destinatário é notificado por e-mail, SMS e/ou App Correios, quando a encomenda estiver disponível para retirada.', 'Módulo 16 › Anx. 2 › 31.5.2', '2026-06-22 19:42:50'),
(493, 9738, 'anexo', 192, NULL, 'elegibilidade', 'Elegibilidade: ...Para encomenda destinada ao Locker não é fornecido recibo de entrega. ...', NULL, NULL, 'Para encomenda destinada ao Locker não é fornecido recibo de entrega.', 'Módulo 16 › Anx. 2 › 31.8', '2026-06-22 19:42:50'),
(494, 9741, 'anexo', 192, NULL, 'prazo', 'Prazo formal: 7 dias corridos — na entrega ao destinatário:', 7.0000, 'dias corridos', 'na entrega ao destinatário: I -  72h: encomenda destinada ao Locker, após o envio da notificação de disponibilidade;\nII -  7 (sete) dias corridos: encomenda para entrega interna, Posta Restante Caída ou Posta Restante Pedida;\nIII -  30 (trinta) dias corridos: encomenda endereçada a Caixa Postal.', 'Módulo 16 › Anx. 2 › a', '2026-06-22 19:42:50'),
(495, 9741, 'anexo', 192, NULL, 'prazo', 'Prazo formal: 30 dias corridos — na entrega ao destinatário:', 30.0000, 'dias corridos', 'na entrega ao destinatário: I -  72h: encomenda destinada ao Locker, após o envio da notificação de disponibilidade;\nII -  7 (sete) dias corridos: encomenda para entrega interna, Posta Restante Caída ou Posta Restante Pedida;\nIII -  30 (trinta) dias corridos: encomenda endereçada a Caixa Postal.', 'Módulo 16 › Anx. 2 › a', '2026-06-22 19:42:50'),
(496, 9741, 'anexo', 192, NULL, 'elegibilidade', 'Elegibilidade: ...na entrega ao destinatário: I -  72h: encomenda destinada ao Locker, após o envio da notificação de disponibilidade;\nII...', NULL, NULL, 'na entrega ao destinatário: I -  72h: encomenda destinada ao Locker, após o envio da notificação de disponibilidade;\nII -  7 (sete) dias corridos: encomenda para entrega interna, Posta Restante Caída ou Posta Restante Pedida;\nIII -  30 (trinta) dias corridos: encomenda endereçada a Caixa Postal.', 'Módulo 16 › Anx. 2 › a', '2026-06-22 19:42:50'),
(497, 9742, 'anexo', 192, 'SEDEX HOJE', 'prazo', 'Prazo formal: 7 dias corridos — na devolução ao remetente:', 7.0000, 'dias corridos', 'na devolução ao remetente: I -  7 (sete) dias corridos: encomenda em devolução interna, Posta Restante Caída ou Posta Restante Pedida;\nII -  30 (trinta) dias corridos: encomenda endereçada a Caixa Postal.\nNota: não há prazo de guarda para entrega de SEDEX Hoje, tendo em vista que o serviço não prevê entrega interna.', 'Módulo 16 › Anx. 2 › b', '2026-06-22 19:42:50'),
(498, 9742, 'anexo', 192, 'SEDEX HOJE', 'prazo', 'Prazo formal: 30 dias corridos — na devolução ao remetente:', 30.0000, 'dias corridos', 'na devolução ao remetente: I -  7 (sete) dias corridos: encomenda em devolução interna, Posta Restante Caída ou Posta Restante Pedida;\nII -  30 (trinta) dias corridos: encomenda endereçada a Caixa Postal.\nNota: não há prazo de guarda para entrega de SEDEX Hoje, tendo em vista que o serviço não prevê entrega interna.', 'Módulo 16 › Anx. 2 › b', '2026-06-22 19:42:50'),
(499, 9744, 'anexo', 192, NULL, 'prazo', 'Prazo formal: 90 dias corridos — O Pedido de Informação - PI poderá ser apresentado por clientes com e sem contrato, por meio da Central de Atendimento d', 90.0000, 'dias corridos', 'O Pedido de Informação - PI poderá ser apresentado por clientes com e sem contrato, por meio da Central de Atendimento dos Correios - CAC ou do Portal Correios, a partir do dia seguinte ao vencimento do prazo de entrega previsto para o serviço contratado e até 90 (noventa) dias corridos a partir da entrega ou da expectativa de entrega do objeto.', 'Módulo 16 › Anx. 2 › 33.1', '2026-06-22 19:42:50'),
(500, 9773, 'anexo', 192, 'SEDEX', 'prazo', 'Prazo formal: 3 dias úteis — SEDEX:', 3.0000, 'dias úteis', 'SEDEX: I -  de 1 (um) a 3 (três) dias úteis de atraso: 5% do valor da postagem;\nII -  de 4 (quatro) a 5 (cinco) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 5 (cinco) dias úteis de atraso: 15% do valor da postagem.', 'Módulo 16 › Anx. 2 › e', '2026-06-22 19:42:50'),
(501, 9773, 'anexo', 192, 'SEDEX', 'prazo', 'Prazo formal: 5 dias úteis — SEDEX:', 5.0000, 'dias úteis', 'SEDEX: I -  de 1 (um) a 3 (três) dias úteis de atraso: 5% do valor da postagem;\nII -  de 4 (quatro) a 5 (cinco) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 5 (cinco) dias úteis de atraso: 15% do valor da postagem.', 'Módulo 16 › Anx. 2 › e', '2026-06-22 19:42:50'),
(502, 9773, 'anexo', 192, 'SEDEX', 'prazo', 'Prazo formal: 5 dias úteis — SEDEX:', 5.0000, 'dias úteis', 'SEDEX: I -  de 1 (um) a 3 (três) dias úteis de atraso: 5% do valor da postagem;\nII -  de 4 (quatro) a 5 (cinco) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 5 (cinco) dias úteis de atraso: 15% do valor da postagem.', 'Módulo 16 › Anx. 2 › e', '2026-06-22 19:42:50'),
(503, 9774, 'anexo', 192, 'PAC', 'prazo', 'Prazo formal: 5 dias úteis — PAC:', 5.0000, 'dias úteis', 'PAC: I -  de 1 (um) a 5 (cinco) dias úteis de atraso: 5% do valor da postagem;\nII -  de 6 (seis) a 10 (dez) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 10 (dez) dias úteis de atraso: 15% do valor da postagem.', 'Módulo 16 › Anx. 2 › f', '2026-06-22 19:42:50'),
(504, 9774, 'anexo', 192, 'PAC', 'prazo', 'Prazo formal: 10 dias úteis — PAC:', 10.0000, 'dias úteis', 'PAC: I -  de 1 (um) a 5 (cinco) dias úteis de atraso: 5% do valor da postagem;\nII -  de 6 (seis) a 10 (dez) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 10 (dez) dias úteis de atraso: 15% do valor da postagem.', 'Módulo 16 › Anx. 2 › f', '2026-06-22 19:42:50'),
(505, 9774, 'anexo', 192, 'PAC', 'prazo', 'Prazo formal: 10 dias úteis — PAC:', 10.0000, 'dias úteis', 'PAC: I -  de 1 (um) a 5 (cinco) dias úteis de atraso: 5% do valor da postagem;\nII -  de 6 (seis) a 10 (dez) dias úteis de atraso: 10% do valor da postagem;\nIII -  acima de 10 (dez) dias úteis de atraso: 15% do valor da postagem.', 'Módulo 16 › Anx. 2 › f', '2026-06-22 19:42:50'),
(506, 9782, 'anexo', 192, NULL, 'elegibilidade', 'Elegibilidade: ...o objeto reclamado, sem a tentativa de entrega domiciliar e destinado a município com CEP único, deve existir consulta junto a unid...', NULL, NULL, 'para o objeto reclamado, sem a tentativa de entrega domiciliar e destinado a município com CEP único, deve existir consulta junto a unidade responsável pela distribuição de encomendas, para identificação de atendimento ao art. 11 da Portaria nº 15.441/2024 do Ministério das Comunicações. Nota: para os endereços em conformidade com a referida legislação, cabe indenização pela não tentativa de entrega domiciliar. Para os endereços desconformes, não cabe indenização, restando esclarecer ao reclaman', 'Módulo 16 › Anx. 2 › c', '2026-06-22 19:42:50'),
(507, 9827, 'anexo', 193, NULL, 'prazo', 'Prazo formal: 7 dias corridos — O objeto deve permanecer disponível para ser retirado na agência por até 7 (sete) dias corridos, sendo devolvido ao reme', 7.0000, 'dias corridos', 'O objeto deve permanecer disponível para ser retirado na agência por até 7 (sete) dias corridos, sendo devolvido ao remetente após esse prazo.', 'Módulo 16 › Anx. 3 › 8.2', '2026-06-22 19:42:50'),
(508, 9827, 'anexo', 193, NULL, 'elegibilidade', 'Elegibilidade: ...O objeto deve permanecer disponível para ser retirado na agência por até 7 (sete) dias corridos, sen...', NULL, NULL, 'O objeto deve permanecer disponível para ser retirado na agência por até 7 (sete) dias corridos, sendo devolvido ao remetente após esse prazo.', 'Módulo 16 › Anx. 3 › 8.2', '2026-06-22 19:42:50'),
(509, 9881, 'anexo', 194, 'REMESSA', 'restricao', 'Restrição: ...ada mais de uma postagem no fluxo postal, no mesmo dia.\n6.5 É proibida a Remessa Agrupada.\n6.6 No interior da embalagem deverão co...', NULL, NULL, 'Após o desembaraço alfandegário de produto controlado pelo Exército. Nota: o serviço de importação efetuado pelos Correios será somente de peças de arma de fogo, por pessoas físicas e jurídicas autorizadas pelo Comando da Região Militar.\n6.3 A encomenda deverá ser postada fechada, em embalagem resistente, com total responsabilidade do remetente e sem qualquer indicação externa de conteúdo.\n6.4 É limitada a postagem de 2 (duas) unidades por encomenda, sendo ainda vedada mais de uma postagem no fl', 'Módulo 16 › Anx. 5 › 6.2.4', '2026-06-22 19:42:50'),
(510, 9883, 'anexo', 194, 'REMESSA', 'restricao', 'Restrição: ...ncher o campo “Controle do Cliente” com as letras “EE”.\n6.9 Não é permitida a postagem de munições, explosivos, armações e chassis de a...', NULL, NULL, 'Nota Fiscal - NF ou documento de liberação da alfândega. 6.7 A postagem de retorno ao fabricante ou comércio especializado somente poderá ser realizada através do serviço de Logística Reversa em Agência.\n6.8 Na etiqueta de endereçamento deverão constar os serviços adicionais de Aviso de Recebimento - AR e Produto Controlado - EE. No caso do serviço adicional EE, não é possível sua solicitação via Logística Reversa em Agência, não sendo possível sua indicação na etiqueta de endereçamento, por iss', 'Módulo 16 › Anx. 5 › b', '2026-06-22 19:42:50'),
(511, 9886, 'anexo', 194, NULL, 'prazo', 'Prazo formal: 7 dias corridos — ENTREGA', 7.0000, 'dias corridos', 'ENTREGA 9.1 A entrega interna é realizada em dias úteis, de segunda-feira a sábado, na Agência dos Correios mais próxima do endereço do destinatário.\n9.2 O objeto ficará disponível na agência, para retirada por parte do destinatário, pelo prazo máximo de 7 (sete) dias corridos. Após este prazo o objeto será devolvido imediatamente ao remetente.\n9.3 Quando da chegada do objeto, a agência deverá emitir o Aviso de Chegada ao destinatário da encomenda.\n9.4 A encomenda poderá ser retirada mesmo sem a', 'Módulo 16 › Anx. 5 › 9', '2026-06-22 19:42:50'),
(512, 9901, 'anexo', 196, NULL, 'dimensao', 'Dimensão: 114 mm — postar a encomenda acompanhada do envelope que será utilizado na devolução do documento, do canhoto ou da via de Nota Fi', 114.0000, 'mm', 'postar a encomenda acompanhada do envelope que será utilizado na devolução do documento, do canhoto ou da via de Nota Fiscal, o qual deverá ter o leiaute também definido pelos Correios: I -  o envelope a ser utilizado deverá ser, preferencialmente, o do tipo comum, nas seguintes medidas: 114 mm x 162 mm ou 114 mm x 229 mm (Recomendado Pelos Correios – RPC), padronizados segundo as normas da Associação Brasileira de Normas Técnicas – ABNT.', 'Módulo 16 › Anx. 8 › d', '2026-06-22 19:42:50'),
(513, 9901, 'anexo', 196, NULL, 'dimensao', 'Dimensão: 114 mm — postar a encomenda acompanhada do envelope que será utilizado na devolução do documento, do canhoto ou da via de Nota Fi', 114.0000, 'mm', 'postar a encomenda acompanhada do envelope que será utilizado na devolução do documento, do canhoto ou da via de Nota Fiscal, o qual deverá ter o leiaute também definido pelos Correios: I -  o envelope a ser utilizado deverá ser, preferencialmente, o do tipo comum, nas seguintes medidas: 114 mm x 162 mm ou 114 mm x 229 mm (Recomendado Pelos Correios – RPC), padronizados segundo as normas da Associação Brasileira de Normas Técnicas – ABNT.', 'Módulo 16 › Anx. 8 › d', '2026-06-22 19:42:50'),
(514, 9912, 'anexo', 197, NULL, 'elegibilidade', 'Elegibilidade: ...O GF está disponível para os serviços de encomendas da seguinte forma: ...', NULL, NULL, 'O GF está disponível para os serviços de encomendas da seguinte forma:', 'Módulo 16 › Anx. 9 › 2.1', '2026-06-22 19:42:50'),
(515, 9965, 'anexo', 198, NULL, 'elegibilidade', 'Elegibilidade: ...O serviço está disponível para clientes com contrato e será habilitado no contrato após re...', NULL, NULL, 'O serviço está disponível para clientes com contrato e será habilitado no contrato após realização de análise de viabilidade comercial, atendidas às exigências da Política Comercial vigente, especialmente no que se refere à contrapartida atual, na qual a revenda de serviços dos Correios não deve constituir a principal atividade do contratante.', 'Módulo 16 › Anx. 10 › 3.2', '2026-06-22 19:42:50'),
(516, 9981, 'anexo', 198, NULL, 'prazo', 'Prazo formal: 7 dias úteis — O prazo máximo para retirada da carga é de 7 (sete) dias úteis, contabilizados a partir da disponibilidade da carga pela', 7.0000, 'dias úteis', 'O prazo máximo para retirada da carga é de 7 (sete) dias úteis, contabilizados a partir da disponibilidade da carga pela unidade operacional de destino, em dias úteis e respectivo horário de atendimento ao público.', 'Módulo 16 › Anx. 10 › 8.3', '2026-06-22 19:42:50'),
(517, 9985, 'anexo', 198, NULL, 'prazo', 'Prazo formal: 7 dias úteis — A carga em devolução terá o prazo máximo para retirada de 7 (sete) dias úteis.', 7.0000, 'dias úteis', 'A carga em devolução terá o prazo máximo para retirada de 7 (sete) dias úteis. 8.3.4.1 Após este prazo, a unidade operacional de destino classificará a carga como refugo e irá providenciar os tramites previstos no MANDIS 9/3.', 'Módulo 16 › Anx. 10 › 8.3.4', '2026-06-22 19:42:50'),
(518, 9990, 'anexo', 198, NULL, 'elegibilidade', 'Elegibilidade: ...Empresa - CEM. Nota: as postagens realizadas pelos CLIs são destinadas aos clientes que possuem estoque junto aos Correios (ex.: Cor...', NULL, NULL, 'Considerando as dimensões e o peso estabelecidos para o produto, as unidades de postagem são: Centros de Logística Integrada - CLI, Gerência de Controle e Capitação de Postagens - GCCAP e Unidade Correios Empresa - CEM. Nota: as postagens realizadas pelos CLIs são destinadas aos clientes que possuem estoque junto aos Correios (ex.: Correios Log+ e Correios Log Supri) e necessitam realizar a transferência de carga entre as unidades.', 'Módulo 16 › Anx. 10 › 10.1', '2026-06-22 19:42:50'),
(519, 10000, 'anexo', 198, NULL, 'peso', 'Limite de peso: 350 kg — peso máximo: até 350kg;', 350.0000, 'kg', 'peso máximo: até 350kg;', 'Módulo 16 › Anx. 10 › b', '2026-06-22 19:42:50'),
(520, 10089, 'anexo', 199, NULL, 'elegibilidade', 'Elegibilidade: ...xemplo: pessoa jurídica que vende, exclusivamente, sementes destinadas ao uso doméstico. Enquadramento de isenção: Decreto nº 10.586...', NULL, NULL, 'Os Correios não possuem competência técnica para avaliar se um determinado cliente se enquadra nos casos previstos de isenção do Renasem, conforme regulamentos vigentes. Cabe ao cliente assegurar e indicar que está isento da referida obrigação, apontando o seu enquadramento na legislação aplicável, tendo em vista que o Mapa não emite documento específico de isenção. Exemplo: pessoa jurídica que vende, exclusivamente, sementes destinadas ao uso doméstico. Enquadramento de isenção: Decreto nº 10.5', 'Módulo 16 › Anx. 11 › 6.7', '2026-06-22 19:42:50'),
(521, 10104, 'anexo', 199, NULL, 'restricao', 'Restrição: ...sementes classificadas como nocivas e proibidas, conforme Instrução Normativa Mapa nº 46, de 24 de setembr...', NULL, NULL, 'sementes classificadas como nocivas e proibidas, conforme Instrução Normativa Mapa nº 46, de 24 de setembro de 2013.', 'Módulo 16 › Anx. 11 › d', '2026-06-22 19:42:50'),
(522, 10122, 'anexo', 199, NULL, 'restricao', 'Restrição: ...abelece a relação de espécies de sementes nocivas toleradas e proibidas na produção, na comercialização e no transporte; ...', NULL, NULL, 'Instrução Normativa Mapa nº 46/2013: estabelece a relação de espécies de sementes nocivas toleradas e proibidas na produção, na comercialização e no transporte;', 'Módulo 16 › Anx. 11 › h', '2026-06-22 19:42:50'),
(523, 10148, 'anexo', 201, 'LOGÍSTICA REVERSA', 'elegibilidade', 'Elegibilidade: ...ealizar a prestação do serviço, cuja área de cobertura está disponível para consulta: ...', NULL, NULL, 'A logística reversa com coleta tem abrangência restrita às localidades que possuem viabilidade comercial e operacional para realizar a prestação do serviço, cuja área de cobertura está disponível para consulta:', 'Módulo 16 › Anx. 2 › 3.5', '2026-06-22 19:42:50'),
(524, 10153, 'anexo', 201, 'LOGÍSTICA REVERSA', 'elegibilidade', 'Elegibilidade: ...O serviço Logística Reversa é prestado somente por contrato, sendo, em todos os casos, um serviço a faturar. ...', NULL, NULL, 'O serviço Logística Reversa é prestado somente por contrato, sendo, em todos os casos, um serviço a faturar.', 'Módulo 16 › Anx. 2 › 4.1', '2026-06-22 19:42:50'),
(525, 10181, 'anexo', 201, NULL, 'prazo', 'Prazo formal: 30 dias corridos — O prazo para a realização da 1º tentativa de coleta é o 1º dia útil seguinte ao da data de solicitação, porém a contrata', 30.0000, 'dias corridos', 'O prazo para a realização da 1º tentativa de coleta é o 1º dia útil seguinte ao da data de solicitação, porém a contratante poderá agendar seu pedido de coleta para até 30 (trinta) dias corridos da data de solicitação.', 'Módulo 16 › Anx. 2 › 7.1.4', '2026-06-22 19:42:50'),
(526, 10182, 'anexo', 201, NULL, 'prazo', 'Prazo formal: 1 dia útil — Quando o pedido de coleta envolver aquisição de embalagem, ao prazo de coleta será acrescido 1 (um) dia útil.', 1.0000, 'dia útil', 'Quando o pedido de coleta envolver aquisição de embalagem, ao prazo de coleta será acrescido 1 (um) dia útil.', 'Módulo 16 › Anx. 2 › 7.1.5', '2026-06-22 19:42:50'),
(527, 10326, 'anexo', 206, 'LOGÍSTICA REVERSA', 'prazo', 'Prazo formal: 10 dias — a postagem do objeto de ida deverá ser realizada em até 10 dias a contar da emissão.', 10.0000, 'dias', 'a postagem do objeto de ida deverá ser realizada em até 10 dias a contar da emissão. 2.3 SIGEPWEB\n2.3.1 Conforme manual do SIGEPWEB, realizar a pré-postagem do objeto de ida com simultânea, vinculando a autorização de postagem ou a coleta reversa.\n2.3.2 O Rótulo de endereçamento da Logística Reversa Simultânea - LRS deverá ser emitido e afixado no objeto de ida.\n2.3.3 A etiqueta verde da logística reversa simultânea deverá ser afixada ao lado do Rótulo de Endereçamento do objeto de ida.\n2.3.4 A ', 'Módulo 16 › Anx. 7 › d', '2026-06-22 19:42:50'),
(528, 10326, 'anexo', 206, 'LOGÍSTICA REVERSA', 'prazo', 'Prazo formal: 10 dias — a postagem do objeto de ida deverá ser realizada em até 10 dias a contar da emissão.', 10.0000, 'dias', 'a postagem do objeto de ida deverá ser realizada em até 10 dias a contar da emissão. 2.3 SIGEPWEB\n2.3.1 Conforme manual do SIGEPWEB, realizar a pré-postagem do objeto de ida com simultânea, vinculando a autorização de postagem ou a coleta reversa.\n2.3.2 O Rótulo de endereçamento da Logística Reversa Simultânea - LRS deverá ser emitido e afixado no objeto de ida.\n2.3.3 A etiqueta verde da logística reversa simultânea deverá ser afixada ao lado do Rótulo de Endereçamento do objeto de ida.\n2.3.4 A ', 'Módulo 16 › Anx. 7 › d', '2026-06-22 19:42:50'),
(529, 10328, 'anexo', 206, 'LOGÍSTICA REVERSA', 'dimensao', 'Dimensão: 40 mm — ETIQUETA VERDE IDENTIFICADORA DA LOGÍSTICA REVERSA SIMULTÂNEA', 40.0000, 'mm', 'ETIQUETA VERDE IDENTIFICADORA DA LOGÍSTICA REVERSA SIMULTÂNEA 4.1 A etiqueta da Logística Reversa Simultânea possui cor verde, dimensões 40 mm x 40 mm e código 752402897.\nNota: essa etiqueta na cor verde deverá ser colada ao lado do rótulo de endereçamento.\n* * * * *', 'Módulo 16 › Anx. 7 › 4', '2026-06-22 19:42:50'),
